window.BOOK={"slug": "matthew", "name": "Matthew", "testament": "NT", "orig_label": "Greek · SBLGNT", "rtl": false, "translations": [{"id": "kjv", "label": "KJV (1611)"}, {"id": "web", "label": "WEB (modern)"}, {"id": "bsb", "label": "Berean Standard"}, {"id": "asv", "label": "ASV (1901)"}, {"id": "ylt", "label": "Young's Literal"}, {"id": "tyndale", "label": "Tyndale (1526)"}, {"id": "dra", "label": "Douay-Rheims"}, {"id": "bbe", "label": "Basic English"}, {"id": "geneva", "label": "Geneva (1599)"}, {"id": "wycliffe", "label": "Wycliffe (1382)"}, {"id": "rotherham", "label": "Rotherham Emph."}, {"id": "weymouth", "label": "Weymouth NT"}, {"id": "darby", "label": "Darby"}, {"id": "twenty", "label": "20th Century NT"}, {"id": "acv", "label": "A Conservative Version"}, {"id": "anderson", "label": "Anderson NT (1864)"}, {"id": "haweis", "label": "Haweis NT (1795)"}, {"id": "noyes", "label": "Noyes NT (1869)"}, {"id": "webster", "label": "Webster (1833)"}, {"id": "vulgate", "label": "Vulgate · Latin"}], "books": [{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}], "chapters": [{"c": 1, "verses": [{"v": 1, "ref": "1:1", "o": "Βίβλος γενέσεως Ἰησοῦ χριστοῦ υἱοῦ Δαυὶδ υἱοῦ Ἀβραάμ.", "en": {"kjv": "The book of the generation of Jesus Christ, the son of David, the son of Abraham.", "web": "The book of the genealogy of Jesus Christ, the son of David, the son of Abraham.", "bsb": "This is the record of the genealogy of Jesus Christ, the son of David, the son of Abraham:", "asv": "The book of the generation of Jesus Christ, the son of David, the son of Abraham.", "ylt": "A roll of the birth of Jesus Christ, son of David, son of Abraham.", "tyndale": "This is the boke of the generacion of Iesus Christ the sonne of Dauid, the sonne also of Abraham.", "dra": "The book of the generation of Jesus Christ, the son of David, the son of Abraham:", "bbe": "The book of the generations of Jesus Christ, the son of David, the son of Abraham.", "geneva": "The booke of the generation of Jesus Christ the sonne of Dauid, the sonne of Abraham.", "wycliffe": "The book of the generacioun of Jhesu Crist, the sone of Dauid, the sone of Abraham.", "rotherham": "The Lineage Roll of Jesus Christ,—Son of David, Son of Abraham.", "weymouth": "The Genealogy of Jesus Christ, the son of David, the son of Abraham.", "darby": "Book of the generation of Jesus Christ, Son of David, Son of Abraham.", "twenty": "A genealogy of Jesus Christ, a descendant of David and Abraham.", "acv": "A book of a genealogy of Jesus Christ, the son of David, the son of Abraham.", "anderson": "The book of the genealogy of Jesus Christ, the son of David, the son of Abraham.", "haweis": "THE book of the genealogy of Jesus Christ, the son of David, the son of Abraham.", "noyes": "The genealogy of Jesus Christ, son of David, son of Abraham.", "webster": "The book of the generation of Jesus Christ, the son of David, the son of Abraham.", "vulgate": "liber generationis Iesu Christi filii David filii Abraham;"}}, {"v": 2, "ref": "1:2", "o": "Ἀβραὰμ ἐγέννησεν τὸν Ἰσαάκ, Ἰσαὰκ δὲ ἐγέννησεν τὸν Ἰακώβ, Ἰακὼβ δὲ ἐγέννησεν τὸν Ἰούδαν καὶ τοὺς ἀδελφοὺς αὐτοῦ,", "en": {"kjv": "Abraham begat Isaac; and Isaac begat Jacob; and Jacob begat Judas and his brethren;", "web": "Abraham became the father of Isaac. Isaac became the father of Jacob. Jacob became the father of Judah and his brothers.", "bsb": "Abraham was the father of Isaac, Isaac the father of Jacob, and Jacob the father of Judah and his brothers.", "asv": "Abraham begat Isaac; and Isaac begat Jacob; and Jacob begat Judah and his brethren;", "ylt": "Abraham begat Isaac, and Isaac begat Jacob, and Jacob begat Judah and his brethren,", "tyndale": "Abraham begat Isaac: Isaac begat Iacob: Iacob begat Iudas and his brethren:", "dra": "Abraham begot Isaac. And Isaac begot Jacob. And Jacob begot Judas and his brethren.", "bbe": "The son of Abraham was Isaac; and the son of Isaac was Jacob; and the sons of Jacob were Judah and his brothers;", "geneva": "Abraham begate Isaac. And Isaac begate Iacob. And Iacob begat Iudas and his brethren.", "wycliffe": "Abraham bigat Isaac. Isaac bigat Jacob. Jacob bigat Judas and hise britheren.", "rotherham": "Abraham begat Isaac, and Isaac begat Jacob, and Jacob, begat Judah and his brethren;", "weymouth": "Abraham was the father of Isaac; Isaac of Jacob; Jacob of Judah and his brothers.", "darby": "Abraham begat Isaac; and Isaac begat Jacob, and Jacob begat Juda and his brethren;", "twenty": "Abraham was the father of Isaac, Isaac of Jacob, Jacob of Judah and his brothers,", "acv": "Abraham begot Isaac, and Isaac begot Jacob, and Jacob begot Judah and his brothers,", "anderson": "Abraham begot Isaac: Isaac begot Jacob: Jacob begot Judah and his brothers:", "haweis": "Abraham begat Isaac, and Isaac begat Jacob, and Jacob begat Judas and his brethren,", "noyes": "Abraham begat Isaac; and Isaac begat Jacob; and Jacob begat Judah and his brothers.", "webster": "Abraham begat Isaac; and Isaac begat Jacob; and Jacob begat Judah and his brethren;", "vulgate": "Abraham genuit Isaac Isaac autem genuit Iacob Iacob autem genuit Iudam et fratres eius;"}}, {"v": 3, "ref": "1:3", "o": "Ἰούδας δὲ ἐγέννησεν τὸν Φαρὲς καὶ τὸν Ζάρα ἐκ τῆς Θαμάρ, Φαρὲς δὲ ἐγέννησεν τὸν Ἑσρώμ, Ἑσρὼμ δὲ ἐγέννησεν τὸν Ἀράμ,", "en": {"kjv": "And Judas begat Phares and Zara of Thamar; and Phares begat Esrom; and Esrom begat Aram;", "web": "Judah became the father of Perez and Zerah by Tamar. Perez became the father of Hezron. Hezron became the father of Ram.", "bsb": "Judah was the father of Perez and Zerah by Tamar, Perez the father of Hezron, and Hezron the father of Ram.", "asv": "and Judah begat Perez and Zerah of Tamar; and Perez begat Hezron; and Hezron begat Ram;", "ylt": "and Judah begat Pharez and Zarah of Tamar, and Pharez begat Hezron, and Hezron begat Ram,", "tyndale": "Iudas begat Phares and zaram of Thamar: Phares begat Hesrom: Hesrom begat Aram:", "dra": "And Judas begot Phares and Zara of Thamar. And Phares begot Esron. And Esron begot Aram.", "bbe": "And the sons of Judah were Perez and Zerah by Tamar; and the son of Perez was Hezron; and the son of Hezron was Ram;", "geneva": "And Iudas begate Phares, and Zara of Thamar. And Phares begate Esrom. And Esrom begate Aram.", "wycliffe": "Judas bigat Fares and Zaram, of Tamar. Fares bigat Esrom.", "rotherham": "And Judah begat Perez and Zarah of Tamah, and Perez begat Hezron, and Hezron begat Ram;", "weymouth": "Judah was the father (by Tamar) of Perez and Zerah; Perez of Hezron; Hezron of Ram;", "darby": "and Juda begat Phares and Zara of Thamar; and Phares begat Esrom, and Esrom begat Aram,", "twenty": "Judah of Perez and Zerah, whose mother was Tamar, Perez of Hezron, Hezron of Ram,", "acv": "and Judah begot Perez and Zerah from Tamar, and Perez begot Hezron, and Hezron begot Ram,", "anderson": "Judah begot Phares and Zarah of Thamar: Phares begot Hezron: Hezron begot Aram:", "haweis": "and Judas begat Phares, and Zara of Thamar, and Phares begat Esrom, and Esrom begat Aram;", "noyes": "And Judah begat Pharez and Zarah, by Tamar. And Pharez begat Hezron; and Hezron begat Ram;", "webster": "And Judah begat Phares and Zara of Thamar; and Phares begat Esrom; and Esrom begat Aram;", "vulgate": "Iudas autem genuit Phares et Zara de Thamar Phares autem genuit Esrom Esrom autem genuit Aram;"}}, {"v": 4, "ref": "1:4", "o": "Ἀρὰμ δὲ ἐγέννησεν τὸν Ἀμιναδάβ, Ἀμιναδὰβ δὲ ἐγέννησεν τὸν Ναασσών, Ναασσὼν δὲ ἐγέννησεν τὸν Σαλμών,", "en": {"kjv": "And Aram begat Aminadab; and Aminadab begat Naasson; and Naasson begat Salmon;", "web": "Ram became the father of Amminadab. Amminadab became the father of Nahshon. Nahshon became the father of Salmon.", "bsb": "Ram was the father of Amminadab, Amminadab the father of Nahshon, and Nahshon the father of Salmon.", "asv": "and Ram begat Amminadab; and Amminadab begat Nahshon; and Nahshon begat Salmon;", "ylt": "and Ram begat Amminadab, and Amminadab begat Nahshon, and Nahshon begat Salmon,", "tyndale": "Aram begat Aminadab: Aminadab begat Naasson: Naasson begat Salmon:", "dra": "And Aram begot Aminadab. And Aminadab begot Naasson. And Naasson begot Salmon.", "bbe": "And the son of Ram was Amminadab; and the son of Amminadab was Nahshon; and the son of Nahshon was Salmon;", "geneva": "And Aram begate Aminadab. And Aminadab begate Naasson. And Naasson begat Salmon.", "wycliffe": "Esrom bigat Aram. Aram bigat Amynadab. Amynadab bigat Naason. Naason bigat Salmon.", "rotherham": "And Ram begat Amminadab, and Amminadab begat Nashon, and Nashon begat Salmon;", "weymouth": "Ram of Amminadab; Amminadab of Nahshon; Nahshon of Salmon;", "darby": "and Aram begat Aminadab, and Aminadab begat Naasson, and Naasson begat Salmon,", "twenty": "Ram of Amminadab, Amminadab of Nashon, Nashon of Salmon,", "acv": "and Ram begot Amminadab, and Amminadab begot Nahshon, and Nahshon begot Salmon,", "anderson": "Aram begot Aminidab: Aminidab begot Nahshon: Nahshon begot Salmon:", "haweis": "and Aram begat Amminadab, and Amminadab begat Naasson, and Naasson begat Salmon,", "noyes": "and Ram begat Amminadab; and Amminadab begat Nahshon; and Nahshon begat Salmon;", "webster": "And Aram begat Aminadab; and Aminadab begat Naasson; and Naasson begat Salmon;", "vulgate": "Aram autem genuit Aminadab Aminadab autem genuit Naasson Naasson autem genuit Salmon;"}}, {"v": 5, "ref": "1:5", "o": "Σαλμὼν δὲ ἐγέννησεν τὸν ⸂Βόες ἐκ τῆς Ῥαχάβ, Βόες⸃ δὲ ἐγέννησεν τὸν ⸂Ἰωβὴδ ἐκ τῆς Ῥούθ, Ἰωβὴδ⸃ δὲ ἐγέννησεν τὸν Ἰεσσαί,", "en": {"kjv": "And Salmon begat Booz of Rachab; and Booz begat Obed of Ruth; and Obed begat Jesse;", "web": "Salmon became the father of Boaz by Rahab. Boaz became the father of Obed by Ruth. Obed became the father of Jesse.", "bsb": "Salmon was the father of Boaz by Rahab, Boaz the father of Obed by Ruth, Obed the father of Jesse,", "asv": "and Salmon begat Boaz of Rahab; and Boaz begat Obed of Ruth; and Obed begat Jesse;", "ylt": "and Salmon begat Boaz of Rahab, and Boaz begat Obed of Ruth, and Obed begat Jesse,", "tyndale": "Salmon begat Boos of Rahab: Boos begat Obed of Ruth: Obed begat Iesse:", "dra": "And Salmon begot Booz of Rahab. And Booz begot Obed of Ruth. And Obed begot Jesse.", "bbe": "And the son of Salmon by Rahab was Boaz; and the son of Boaz by Ruth was Obed; and the son of Obed was Jesse;", "geneva": "And Salmon begate Booz of Rachab. And Booz begat Obed of Ruth. and Obed begat Iesse.", "wycliffe": "Salmon bigat Booz, of Raab. Booz bigat Obeth, of Ruth. Obeth bigat Jesse. Jesse bigat Dauid the king.", "rotherham": "And Salmon begat Boaz of Rahab, and Boaz begat Obed of Ruth, and Obed begat Jesse;", "weymouth": "Salmon (by Rahab) of Boaz; Boaz (by Ruth) of Obed; Obed of Jesse;", "darby": "and Salmon begat Booz of Rachab; and Booz begat Obed of Ruth; and Obed begat Jesse,", "twenty": "Salmon of Boaz, whose mother was Rahab, Boaz of Obed, whose mother was Ruth, Obed of Jesse,", "acv": "and Salmon begot Boaz from Rahab, and Boaz begot Obed from Ruth, and Obed begot Jesse,", "anderson": "Salmon begot Boa of Rachab: Boaz begot Obed of Ruth: Obed begot Jesse:", "haweis": "and Salmon begat Boaz of Rachab, and Boaz begat Obed of Ruth, and Obed begat Jesse,", "noyes": "and Salmon begat Boaz by Rahab. And Boaz begat Obed by Ruth. And Obed begat Jesse;", "webster": "And Salmon begat Booz of Rachab; and Booz begat Obed of Ruth; and Obed begat Jesse;", "vulgate": "Salmon autem genuit Booz de Rachab Booz autem genuit Obed ex Ruth Obed autem genuit Iesse Iesse autem genuit David regem;"}}, {"v": 6, "ref": "1:6", "o": "Ἰεσσαὶ δὲ ἐγέννησεν τὸν Δαυὶδ τὸν βασιλέα. Δαυὶδ ⸀δὲ ἐγέννησεν τὸν Σολομῶνα ἐκ τῆς τοῦ Οὐρίου,", "en": {"kjv": "And Jesse begat David the king; and David the king begat Solomon of her that had been the wife of Urias;", "web": "Jesse became the father of King David. David became the father of Solomon by her who had been the wife of Uriah.", "bsb": "and Jesse the father of David the king. Next: David was the father of Solomon by Uriah’s wife,", "asv": "and Jesse begat David the king. And David begat Solomon of her that had been the wife of Uriah;", "ylt": "and Jesse begat David the king. And David the king begat Solomon, of her who had been Uriah's,", "tyndale": "Iesse begat Dauid the kynge: Dauid the kynge begat Salomon, of her that was the wyfe of Vry:", "dra": "And Jesse begot David the king. And David the king begot Solomon, of her that had been the wife of Urias.", "bbe": "And the son of Jesse was David the king; and the son of David was Solomon by her who had been the wife of Uriah;", "geneva": "And Iesse begate Dauid the King. And Dauid the King begate Salomon of her that was the wife of Vrias.", "wycliffe": "Dauid the king bigat Salamon, of hir that was Vries wijf.", "rotherham": "And Jesse begat David the King. And David begat Solomon of her [that had been the wife] of Uriah;", "weymouth": "Jesse of David--the King. David (by Uriah's widow) was the father of Solomon;", "darby": "and Jesse begat David the king. And David begat Solomon, of her [that had been the wife] of Urias;", "twenty": "Jesse of David the King. David was the father of Solomon, whose mother was Uriah’s widow,", "acv": "and Jesse begot David the king. And David begot Solomon from the widow of Uriah,", "anderson": "Jesse begot David the king: David the king begot Solomon of her who had been the wife of Uriah:", "haweis": "and Jesse begat David the king, and David the king begat Solomon of her that had been the wife of Urias,", "noyes": "and Jesse begat David the king. And David begat Solomon by the wife of Uriah.", "webster": "And Jesse begat David the king; and David the king begat Solomon of her [that had been the wife] of Uriah;", "vulgate": "David autem rex genuit Salomonem ex ea quae fuit Uriae;"}}, {"v": 7, "ref": "1:7", "o": "Σολομὼν δὲ ἐγέννησεν τὸν Ῥοβοάμ, Ῥοβοὰμ δὲ ἐγέννησεν τὸν Ἀβιά, Ἀβιὰ δὲ ἐγέννησεν τὸν ⸂Ἀσάφ,", "en": {"kjv": "And Solomon begat Roboam; and Roboam begat Abia; and Abia begat Asa;", "web": "Solomon became the father of Rehoboam. Rehoboam became the father of Abijah. Abijah became the father of Asa.", "bsb": "Solomon the father of Rehoboam, Rehoboam the father of Abijah, and Abijah the father of Asa.", "asv": "and Solomon begat Rehoboam; and Rehoboam begat Abijah; and Abijah begat Asa;", "ylt": "and Solomon begat Rehoboam, and Rehoboam begat Abijah, and Abijah begat Asa,", "tyndale": "Salomon begat Roboam: Roboam begat Abia: Abia begat Asa:", "dra": "And Solomon begot Roboam. And Roboam begot Abia. And Abia begot Asa.", "bbe": "And the son of Solomon was Rehoboam; and the son of Rehoboam was Abijah; and the son of Abijah was Asa;", "geneva": "And Salomon begate Roboam. And Roboam begate Abia. And Abia begate Asa.", "wycliffe": "Salomon bigat Roboam. Roboam bigat Abias.", "rotherham": "And Solomon begat Rehoboam, and Rehoboam begat Abijah, and Abijah begat Asa;", "weymouth": "Solomon of Rehoboam; Rehoboam of Abijah; Abijah of Asa;", "darby": "and Solomon begat Roboam, and Roboam begat Abia, and Abia begat Asa,", "twenty": "Solomon of Rehoboam, Rehoboam of Abijah, Abijah of Asa,", "acv": "and Solomon begot Rehoboam, and Rehoboam begot Abijah, and Abijah begot Asa,", "anderson": "Solomon begot Rehoboam: Rehoboam begot Abia: Abia begot Asa:", "haweis": "and Solomon begat Roboam, and Roboam begat Abia, and Abia begat Asa,", "noyes": "And Solomon begat Rehoboam; and Rehoboam begat Abijah; and Abijah begat Asa;", "webster": "And Solomon begat Roboam; and Roboam begat Abia; and Abia begat Asa;", "vulgate": "Salomon autem genuit Roboam Roboam autem genuit Abiam Abia autem genuit Asa;"}}, {"v": 8, "ref": "1:8", "o": "Ἀσὰφ⸃ δὲ ἐγέννησεν τὸν Ἰωσαφάτ, Ἰωσαφὰτ δὲ ἐγέννησεν τὸν Ἰωράμ, Ἰωρὰμ δὲ ἐγέννησεν τὸν Ὀζίαν,", "en": {"kjv": "And Asa begat Josaphat; and Josaphat begat Joram; and Joram begat Ozias;", "web": "Asa became the father of Jehoshaphat. Jehoshaphat became the father of Joram. Joram became the father of Uzziah.", "bsb": "Asa was the father of Jehoshaphat, Jehoshaphat the father of Joram, and Joram the father of Uzziah.", "asv": "and Asa begat Jehoshaphat; and Jehoshaphat begat Joram; and Joram begat Uzziah;", "ylt": "and Asa begat Jehoshaphat, and Jehoshaphat begat Joram, and Joram begat Uzziah,", "tyndale": "Asa begat Iosaphat: Iosaphat begat Ioram: Ioram begat Osias:", "dra": "And Asa begot Josaphat. And Josaphat begot Joram. And Joram begot Ozias.", "bbe": "And the son of Asa was Jehoshaphat; and the son of Jehoshaphat was Joram; and the son of Joram was Uzziah;", "geneva": "And Asa begate Iosaphat. And Iosaphat begate Ioram. And Ioram begate Hozias.", "wycliffe": "Abias bigat Asa. Asa bigat Josaphath. Josaphath bigat Joram. Joram bigat", "rotherham": "And Asa begat Jehoshaphat, and Jehoshaphat begat Joram, and Joram begat Uzziah;", "weymouth": "Asa of Jehoshaphat; Jehoshaphat of Jehoram; Jehoram of Uzziah;", "darby": "and Asa begat Josaphat, and Josaphat begat Joram, and Joram begat Ozias,", "twenty": "Asa of Jehoshaphat, Jehoshaphat of Jehoram, Jehoram of Uzziah,", "acv": "and Asa begot Jehoshaphat, and Jehoshaphat begot Joram, and Joram begot Uzziah,", "anderson": "Asa begot Jehosaphat: Jehosaphat begot Jehoram: Jehoram begot Uzziah:", "haweis": "and Asa begat Josaphat, and Josaphat begat Joram, and Joram begat Ozias,", "noyes": "and Asa begat Jehoshaphat; and Jehoshaphat begat Joram; and Joram begat Uzziah;", "webster": "And Asa begat Josaphat; and Josaphat begat Joram; and Joram begat Ozias;", "vulgate": "Asa autem genuit Iosaphat Iosaphat autem genuit Ioram Ioram autem genuit Oziam;"}}, {"v": 9, "ref": "1:9", "o": "Ὀζίας δὲ ἐγέννησεν τὸν Ἰωαθάμ, Ἰωαθὰμ δὲ ἐγέννησεν τὸν Ἀχάζ, Ἀχὰζ δὲ ἐγέννησεν τὸν Ἑζεκίαν,", "en": {"kjv": "And Ozias begat Joatham; and Joatham begat Achaz; and Achaz begat Ezekias;", "web": "Uzziah became the father of Jotham. Jotham became the father of Ahaz. Ahaz became the father of Hezekiah.", "bsb": "Uzziah was the father of Jotham, Jotham the father of Ahaz, and Ahaz the father of Hezekiah.", "asv": "and Uzziah begat Jotham; and Jotham begat Ahaz; and Ahaz begat Hezekiah;", "ylt": "and Uzziah begat Jotham, and Jotham begat Ahaz, and Ahaz begat Hezekiah,", "tyndale": "Osias begat Ioatham: Ioatham begat Achas: Achas begat Ezechias:", "dra": "And Ozias begot Joatham. And Joatham begot Achaz. And Achaz begot Ezechias.", "bbe": "And the son of Uzziah was Jotham; and the son of Jotham was Ahaz; and the son of Ahaz was Hezekiah;", "geneva": "And Hozias begat Ioatham. And Ioatham begate Achaz. And Achaz begate Ezekias.", "wycliffe": "Osias. Osias bigat Joathan. Joathan bigat Achaz. Achaz bigat Ezechie.", "rotherham": "And Uzziah begat Jotham, and Jotham begat Ahaz, and Ahaz begat Hezekiah:", "weymouth": "Uzziah of Jotham; Jotham of Ahaz; Ahaz of Hezekiah;", "darby": "and Ozias begat Joatham, and Joatham begat Achaz, and Achaz begat Ezekias,", "twenty": "Uzziah of Jotham, Jotham of Ahaz, Ahaz of Hezekiah,", "acv": "and Uzziah begot Jotham, and Jotham begot Ahaz, and Ahaz begot Hezekiah,", "anderson": "Uzziah begot Jotham: Jotham begot Ahaz: Ahaz begot Hezekiah:", "haweis": "and Ozias begat Joatham, and Joatham begat Ahaz, and Ahaz begat Hezekias,", "noyes": "and Uzziah begat Jotham; and Jotham begat Ahaz; and Ahaz begat Hezekiah;", "webster": "And Ozias begat Joatham; and Joatham begat Achaz; and Achaz begat Ezekias;", "vulgate": "Ozias autem genuit Ioatham Ioatham autem genuit Achaz Achaz autem genuit Ezechiam;"}}, {"v": 10, "ref": "1:10", "o": "Ἑζεκίας δὲ ἐγέννησεν τὸν Μανασσῆ, Μανασσῆς δὲ ἐγέννησεν τὸν ⸂Ἀμώς, Ἀμὼς⸃ δὲ ἐγέννησεν τὸν Ἰωσίαν,", "en": {"kjv": "And Ezekias begat Manasses; and Manasses begat Amon; and Amon begat Josias;", "web": "Hezekiah became the father of Manasseh. Manasseh became the father of Amon. Amon became the father of Josiah.", "bsb": "Hezekiah was the father of Manasseh, Manasseh the father of Amon, Amon the father of Josiah,", "asv": "and Hezekiah begat Manasseh; and Manasseh begat Amon; and Amon begat Josiah;", "ylt": "and Hezekiah begat Manasseh, and Manasseh begat Amon, and Amon begat Josiah,", "tyndale": "Ezechias begat Manasses: Manasses begat Amon: Amon begat Iosias:", "dra": "And Ezechias begot Manasses. And Manasses begot Amon. And Amon begot Josias.", "bbe": "And the son of Hezekiah was Manasseh; and the son of Manasseh was Amon; and the son of Amon was Josiah;", "geneva": "And Ezekias begate Manasses. And Manasses begate Amon. And Amon begate Iosias.", "wycliffe": "Ezechie bigat Manasses. Manasses bigat Amon.", "rotherham": "And Hezekiah begat Manasseh, and Manasseh begat Amon, and Amon begat Josiah;", "weymouth": "Hezekiah of Manasseh; Manasseh of Amon; Amon of Josiah;", "darby": "and Ezekias begat Manasses, and Manasses begat Amon, and Amon begat Josias,", "twenty": "Hezekiah of Manasseh, Manasseh of Ammon, Ammon of Josiah,", "acv": "and Hezekiah begot Manasseh, and Manasseh begot Amon, and Amon begot Josiah,", "anderson": "Hezekiah begot Manasseh: Manasseh begot Amon: Amon begot Josiah:", "haweis": "and Hezekias begat Manasses, and Manasses begat Amon, and Amon begat Josias,", "noyes": "and Hezekiah begat Manasseh; and Manasseh begat Amon; and Amon begat Josiah;", "webster": "And Ezekias begat Manasses; and Manasses begat Amon; and Amon begat Josias;", "vulgate": "Ezechias autem genuit Manassen Manasses autem genuit Amon Amon autem genuit Iosiam;"}}, {"v": 11, "ref": "1:11", "o": "Ἰωσίας δὲ ἐγέννησεν τὸν Ἰεχονίαν καὶ τοὺς ἀδελφοὺς αὐτοῦ ἐπὶ τῆς μετοικεσίας Βαβυλῶνος.", "en": {"kjv": "And Josias begat Jechonias and his brethren, about the time they were carried away to Babylon:", "web": "Josiah became the father of Jechoniah and his brothers, at the time of the exile to Babylon.", "bsb": "and Josiah the father of Jeconiah and his brothers at the time of the exile to Babylon.", "asv": "and Josiah begat Jechoniah and his brethren, at the time of the carrying away to Babylon.", "ylt": "and Josiah begat Jeconiah and his brethren, at the Babylonian removal.", "tyndale": "Iosias begat Iechonias and his brethren aboute ye tyme they were caryed awaye to Babylon.", "dra": "And Josias begot Jechonias and his brethren in the transmigration of Babylon.", "bbe": "And the sons of Josiah were Jechoniah and his brothers, at the time of the taking away to Babylon.", "geneva": "And Iosias begate Iakim. And Iakim begate Iechonias and his brethren about the time they were caried away to Babylon.", "wycliffe": "Amon bigat Josias. Josias bigat Jeconyas and his britheren, in to the transmygracioun of Babiloyne.", "rotherham": "And Josiah begat Jechoniah, and his brethren,—upon the removal to Babylon.", "weymouth": "Josiah of Jeconiah and his brothers at the period of the Removal to Babylon.", "darby": "and Josias begat Jechonias and his brethren, at the time of the carrying away of Babylon.", "twenty": "Josiah of Jeconiah and his brothers, at the time of the Exile to Babylon.", "acv": "and Josiah begot Jechoniah and his brothers during the Babylonian exile.", "anderson": "Josiah begot Jeconiah and his brothers, about the time of the removal to Babylon.", "haweis": "and Josias begat Jechonias and his brethren, about the time they were carried away to Babylon,", "noyes": "and Josiah begat Jeconiah and his brothers, at the time of the removal to Babylon.", "webster": "And Josias begat Jechonias and his brethren, about the time they were carried away to Babylon:", "vulgate": "Iosias autem genuit Iechoniam et fratres eius in transmigratione Babylonis;"}}, {"v": 12, "ref": "1:12", "o": "Μετὰ δὲ τὴν μετοικεσίαν Βαβυλῶνος Ἰεχονίας ἐγέννησεν τὸν Σαλαθιήλ, Σαλαθιὴλ δὲ ἐγέννησεν τὸν Ζοροβαβέλ,", "en": {"kjv": "And after they were brought to Babylon, Jechonias begat Salathiel; and Salathiel begat Zorobabel;", "web": "After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel.", "bsb": "After the exile to Babylon: Jeconiah was the father of Shealtiel, Shealtiel the father of Zerubbabel,", "asv": "And after the carrying away to Babylon, Jechoniah begat Shealtiel; and Shealtiel begat Zerubbabel;", "ylt": "And after the Babylonian removal, Jeconiah begat Shealtiel, and Shealtiel begat Zerubbabel,", "tyndale": "And after they were brought to Babylon, Iechonias begat Salathiel: Salathiel begat zorobabel:", "dra": "And after the transmigration of Babylon, Jechonias begot Salathiel. And Salathiel begot Zorobabel.", "bbe": "And after the taking away to Babylon, Jechoniah had a son Shealtiel; and Shealtiel had Zerubbabel;", "geneva": "And after they were caried away into Babylon, Iechonias begate Salathiel. And Salathiel begate Zorobabel.", "wycliffe": "And aftir the transmygracioun of Babiloyne, Jeconyas bigat Salatiel. Salatiel bigat Zorobabel.", "rotherham": "And, after the removal to Babylon, Jechoniah begat Shealtiel, and Shealtiel begat Zerubbabel;", "weymouth": "After the Removal to Babylon Jeconiah had a son Shealtiel; Shealtiel was the father of Zerubbabel;", "darby": "And after the carrying away of Babylon, Jechonias begat Salathiel, and Salathiel begat Zorobabel,", "twenty": "After the Exile to Babylon — Jeconiah was the father of Shealtiel, Shealtiel of Zerubbabel,", "acv": "And after the Babylonian exile, Jechoniah begot Shealtiel, and Shealtiel begot Zerubbabel,", "anderson": "And after the removal to Babylon, Jeconiah begot Shealtiel: Shealtiel begot Zerubbabel:", "haweis": "and after they were brought to Babylon, Jechonias begat Salathiel, and Salathiel begat Zorobabel,", "noyes": "And after the removal to Babylon, Jeconiah begat Shealtiel; and Shealtiel begat Zerubbabel;", "webster": "And after they were brought to Babylon, Jechonias begat Salathiel; and Salathiel begat Zorobabel;", "vulgate": "et post transmigrationem Babylonis Iechonias genuit Salathihel Salathihel autem genuit Zorobabel;"}}, {"v": 13, "ref": "1:13", "o": "Ζοροβαβὲλ δὲ ἐγέννησεν τὸν Ἀβιούδ, Ἀβιοὺδ δὲ ἐγέννησεν τὸν Ἐλιακίμ, Ἐλιακὶμ δὲ ἐγέννησεν τὸν Ἀζώρ,", "en": {"kjv": "And Zorobabel begat Abiud; and Abiud begat Eliakim; and Eliakim begat Azor;", "web": "Zerubbabel became the father of Abiud. Abiud became the father of Eliakim. Eliakim became the father of Azor.", "bsb": "Zerubbabel the father of Abiud, Abiud the father of Eliakim, and Eliakim the father of Azor.", "asv": "and Zerubbabel begat Abiud; and Abiud begat Eliakim; and Eliakim begat Azor;", "ylt": "and Zerubbabel begat Abiud, and Abiud begat Eliakim, and Eliakim begat Azor,", "tyndale": "zorobabel begat Abiud: Abiud begat Eliachim: Eliachim begat Azor:", "dra": "And Zorobabel begot Abiud. And Abiud begot Eliacim. And Eliacim begot Azor.", "bbe": "And Zerubbabel had Abiud; and Abiud had Eliakim; and Eliakim had Azor;", "geneva": "And Zorobabel begate Abiud. And Abiud begate Eliacim. And Eliacim begate Azor.", "wycliffe": "Zorobabel bigat Abyut. Abyut bigat Eliachym. Eliachym bigat Asor.", "rotherham": "And Zerubbabel begat Abiud, and Abiud begat Eliakim, and Eliakim begat Azor;", "weymouth": "Zerubbabel of Abiud; Abiud of Eliakim; Eliakim of Azor;", "darby": "and Zorobabel begat Abiud, and Abiud begat Eliakim, and Eliakim begat Azor,", "twenty": "Zerubbabel of Abiud, Abiud of Eliakim, Eliakim of Azor,", "acv": "and Zerubbabel begot Abiud, and Abiud begot Eliakim, and Eliakim begot Azor,", "anderson": "Zerubbabel begot Abiud: Abiud begot Eliakim: Eliakim begot Azor:", "haweis": "and Zorobabel begat Abiud, and Abiud begat Eliakim, and Eliakim begat Azor,", "noyes": "and Zerubbabel begat Abiud; and Abiud begat Eliakim; and Eliakim begat Azor;", "webster": "And Zorobabel begat Abiud; and Abiud begat Eliakim; and Eliakim begat Azor;", "vulgate": "Zorobabel autem genuit Abiud Abiud autem genuit Eliachim Eliachim autem genuit Azor;"}}, {"v": 14, "ref": "1:14", "o": "Ἀζὼρ δὲ ἐγέννησεν τὸν Σαδώκ, Σαδὼκ δὲ ἐγέννησεν τὸν Ἀχίμ, Ἀχὶμ δὲ ἐγέννησεν τὸν Ἐλιούδ,", "en": {"kjv": "And Azor begat Sadoc; and Sadoc begat Achim; and Achim begat Eliud;", "web": "Azor became the father of Zadok. Zadok became the father of Achim. Achim became the father of Eliud.", "bsb": "Azor was the father of Zadok, Zadok the father of Achim, and Achim the father of Eliud.", "asv": "and Azor begat Sadoc; and Sadoc begat Achim; and Achim begat Eliud;", "ylt": "and Azor begat Sadok, and Sadok begat Achim, and Achim begat Eliud,", "tyndale": "Azor begat Sadoc: Sadoc begat Achin: Achin begat Eliud:", "dra": "And Azor begot Sadoc. And Sadoc begot Achim. And Achim begot Eliud.", "bbe": "And Azor had Zadok; and Zadok had Achim; and Achim had Eliud;", "geneva": "And Azor begate Sadoc. And Sadoc begate Achim. And Achim begate Eliud.", "wycliffe": "Asor bigat Sadoc. Sadoc bigat Achym.", "rotherham": "And Azor begat Sadoc, and Sadoc begat Achim, and Achim begat Eliud;", "weymouth": "Azor of Zadok; Zadok of Achim; Achim of Eliud;", "darby": "and Azor begat Sadoc, and Sadoc begat Achim, and Achim begat Eliud,", "twenty": "Azor of Zadok, Zadok of Achim, Achim of Eliud,", "acv": "and Azor begot Zadoc, and Zadoc begot Achim, and Achim begot Eliud,", "anderson": "Azor begot Sadok: Sadok begot Achim: Achim begot Eliud:", "haweis": "and Azor begat Sadoc, and Sadoc begat Achim, and Achim begat Eliud,", "noyes": "and Azor begat Zadok; and Zadok begat Achim; and Achim begat Eliud;", "webster": "And Azor begat Sadoc; and Sadoc begat Achim; and Achim begat Eliud;", "vulgate": "Azor autem genuit Saddoc Saddoc autem genuit Achim Achim autem genuit Eliud;"}}, {"v": 15, "ref": "1:15", "o": "Ἐλιοὺδ δὲ ἐγέννησεν τὸν Ἐλεάζαρ, Ἐλεάζαρ δὲ ἐγέννησεν τὸν Ματθάν, Ματθὰν δὲ ἐγέννησεν τὸν Ἰακώβ,", "en": {"kjv": "And Eliud begat Eleazar; and Eleazar begat Matthan; and Matthan begat Jacob;", "web": "Eliud became the father of Eleazar. Eleazar became the father of Matthan. Matthan became the father of Jacob.", "bsb": "Eliud was the father of Eleazar, Eleazar the father of Matthan, Matthan the father of Jacob,", "asv": "and Eliud begat Eleazar; and Eleazar begat Matthan; and Matthan begat Jacob;", "ylt": "and Eliud begat Eleazar, and Eleazar begat Matthan, and Matthan begat Jacob,", "tyndale": "Eliud begat Eleasar: Eleasar begat Matthan: Matthan begat Iacob:", "dra": "And Eliud begot Eleazar. And Eleazar begot Mathan. And Mathan begot Jacob.", "bbe": "And Eliud had Eleazar; and Eleazar had Matthan; and Matthan had Jacob;", "geneva": "And Eliud begate Eleazar. And Eleazar begate Matthan. And Matthan begate Iacob.", "wycliffe": "Achym bigat Elyut. Elyut bigat Eleasar. Eleasar bigat Mathan.", "rotherham": "And Eliud begat Eleazar, and Eleazar begat Matthan, and Matthan begat Jacob;—", "weymouth": "Eliud of Eleazar; Eleazar of Matthan; Matthan of Jacob;", "darby": "and Eliud begat Eliazar, and Eliazar begat Matthan, and Matthan begat Jacob,", "twenty": "Eliud of Eleazar, Eleazar of Matthan, Matthan of Jacob,", "acv": "and Eliud begot Eleazar, and Eleazar begot Matthan, and Matthan begot Jacob,", "anderson": "Eliud begot Eleazar: Eleazar begot Matthan: Matthan begot Jacob:", "haweis": "and Eliud begat Eleazar, and Eleazar begat Matthan, and Matthan begat Jacob,", "noyes": "and Eliud begat Eleazar; and Eleazar begat Matthan; and Matthan begat Jacob;", "webster": "And Eliud begat Eleazar; and Eleazar begat Matthan; and Matthan begat Jacob;", "vulgate": "Eliud autem genuit Eleazar Eleazar autem genuit Matthan Matthan autem genuit Iacob;"}}, {"v": 16, "ref": "1:16", "o": "Ἰακὼβ δὲ ἐγέννησεν τὸν Ἰωσὴφ τὸν ἄνδρα Μαρίας, ἐξ ἧς ἐγεννήθη Ἰησοῦς ὁ λεγόμενος χριστός.", "en": {"kjv": "And Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "web": "Jacob became the father of Joseph, the husband of Mary, from whom was born Jesus, who is called Christ.", "bsb": "and Jacob the father of Joseph, the husband of Mary, of whom was born Jesus, who is called Christ.", "asv": "and Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "ylt": "and Jacob begat Joseph, the husband of Mary, of whom was begotten Jesus, who is named Christ.", "tyndale": "Iacob begat Ioseph the husbande of Mary, of which was boren that Iesus, that is called Christ. ⹐", "dra": "And Jacob begot Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "bbe": "And the son of Jacob was Joseph the husband of Mary, who gave birth to Jesus, whose name is Christ.", "geneva": "And Iacob begat Ioseph ye husband of Mary, of whom was borne Jesus, that is called Christ.", "wycliffe": "Mathan bigat Jacob. Jacob bigat Joseph, the hosebonde of Marye, of whom Jhesus was borun, that is clepid Christ.", "rotherham": "And Jacob begat Joseph, the husband of Mary, of whom was born Jesus,—who is called Christ.", "weymouth": "and Jacob of Joseph the husband of Mary, who was the mother of JESUS who is called CHRIST.", "darby": "and Jacob begat Joseph, the husband of Mary, of whom was born Jesus, who is called Christ.", "twenty": "Jacob of Joseph, the husband of Mary, who was the mother of Jesus, who is called ‘Christ’.", "acv": "and Jacob begot Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "anderson": "Jacob begot Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "haweis": "and Jacob begat Joseph, the husband of Mary, of whom is born Jesus, who is called Christ.", "noyes": "and Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "webster": "And Jacob begat Joseph the husband of Mary, of whom was born Jesus, who is called Christ.", "vulgate": "Iacob autem genuit Ioseph virum Mariae de qua natus est Iesus qui vocatur Christus;"}}, {"v": 17, "ref": "1:17", "o": "Πᾶσαι οὖν αἱ γενεαὶ ἀπὸ Ἀβραὰμ ἕως Δαυὶδ γενεαὶ δεκατέσσαρες, καὶ ἀπὸ Δαυὶδ ἕως τῆς μετοικεσίας Βαβυλῶνος γενεαὶ δεκατέσσαρες, καὶ ἀπὸ τῆς μετοικεσίας Βαβυλῶνος ἕως τοῦ χριστοῦ γενεαὶ δεκατέσσαρες.", "en": {"kjv": "So all the generations from Abraham to David are fourteen generations; and from David until the carrying away into Babylon are fourteen generations; and from the carrying away into Babylon unto Christ are fourteen generations.", "web": "So all the generations from Abraham to David are fourteen generations; from David to the exile to Babylon fourteen generations; and from the carrying away to Babylon to the Christ, fourteen generations.", "bsb": "In all, then, there were fourteen generations from Abraham to David, fourteen from David to the exile to Babylon, and fourteen from the exile to the Christ.", "asv": "So all the generations from Abraham unto David are fourteen generations; and from David unto the carrying away to Babylon fourteen generations; and from the carrying away to Babylon unto the Christ fourteen generations.", "ylt": "All the generations, therefore, from Abraham unto David are fourteen generations, and from David unto the Babylonian removal fourteen generations, and from the Babylonian removal unto the Christ, fourteen generations.", "tyndale": "All the generacions from Abraham to David are fowretene generacions. And from David vnto the captivite of Babylon, are fowretene generacions. And from the captivite of Babylon vnto Christ, are also fowrtene generacions.", "dra": "So all the generations from Abraham to David, are fourteen generations. And from David to the transmigration of Babylon, are fourteen generations: and from the transmigration of Babylon to Christ are fourteen generations.", "bbe": "So all the generations from Abraham to David are fourteen generations; and from David to the taking away to Babylon, fourteen generations; and from the taking away to Babylon to the coming of Christ, fourteen generations.", "geneva": "So all the generations from Abraham to Dauid, are fourtene generations. And from Dauid vntil they were caried away into Babylon, fourtene generations: and after they were caried away into Babylon vntill Christ, fourteene generations.", "wycliffe": "And so alle generaciouns fro Abraham to Dauid ben fourtene generacions, and fro Dauid to the transmygracioun of Babiloyne ben fourtene generaciouns, and fro the transmygracioun of Babiloyne to Crist ben fourtene generaciouns.", "rotherham": "So then, all the generations from Abraham unto David, are, fourteen, generations, and, from David unto the removal to Babylon, fourteen, generations; and, from the removal to Babylon unto the Christ, fourteen, generations.", "weymouth": "There are therefore, in all, fourteen generations from Abraham to David; fourteen from David to the Removal to Babylon; and fourteen from the Removal to Babylon to the Christ.", "darby": "All the generations, therefore, from Abraham to David [were] fourteen generations; and from David until the carrying away of Babylon, fourteen generations; and from the carrying away of Babylon unto the Christ, fourteen generations.", "twenty": "So the whole number of generations from Abraham to David is fourteen; from David to the Exile to Babylon fourteen; and from the Exile to Babylon to the Christ fourteen.", "acv": "So all the generations from Abraham to David are fourteen generations, and from David to the Babylonian exile fourteen generations, and from the Babylonian exile to the Christ fourteen generations.", "anderson": "So all the generations from Abraham till David are fourteen generations: and from David till the removal to Babylon are fourteen generations: and from the removal to Babylon till the Christ are fourteen generations.", "haweis": "So all the generations from Abraham to David are fourteen generations, and from David to the carrying away into Babylon fourteen generations, and from the carrying away into Babylon unto Christ fourteen generations.", "noyes": "So all the generations from Abraham to David are fourteen generations; and from David to the removal to Babylon are fourteen generations; and from the removal to Babylon unto Christ are fourteen generations.", "webster": "So all the generations from Abraham to David [are] fourteen generations; and from David until the carrying away into Babylon [are] fourteen generations; and from the carrying away into Babylon to Christ [are] fourteen generations.", "vulgate": "omnes ergo generationes ab Abraham usque ad David generationes quattuordecim et a David usque ad transmigrationem Babylonis generationes quattuordecim et a transmigratione Babylonis usque ad Christum generationes quattuordecim;"}}, {"v": 18, "ref": "1:18", "o": "Τοῦ δὲ ⸀Ἰησοῦ χριστοῦ ἡ ⸀γένεσις οὕτως ἦν. ⸀μνηστευθείσης τῆς μητρὸς αὐτοῦ Μαρίας τῷ Ἰωσήφ, πρὶν ἢ συνελθεῖν αὐτοὺς εὑρέθη ἐν γαστρὶ ἔχουσα ἐκ πνεύματος ἁγίου.", "en": {"kjv": "Now the birth of Jesus Christ was on this wise: When as his mother Mary was espoused to Joseph, before they came together, she was found with child of the Holy Ghost.", "web": "Now the birth of Jesus Christ was like this; for after his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit.", "bsb": "This is how the birth of Jesus Christ came about: His mother Mary was pledged in marriage to Joseph, but before they came together, she was found to be with child through the Holy Spirit.", "asv": "Now the birth of Jesus Christ was on this wise: When his mother Mary had been betrothed to Joseph, before they came together she was found with child of the Holy Spirit.", "ylt": "And of Jesus Christ, the birth was thus: For his mother Mary having been betrothed to Joseph, before their coming together she was found to have conceived from the Holy Spirit,", "tyndale": "✠ The byrthe of Iesus Christ was on thys wyse. When hys mother Mary was betrouthed to Ioseph, before they came to dwell to gedder, she was founde with chylde by ye holy goost.", "dra": "Now the generation of Christ was in this wise. When as his mother Mary was espoused to Joseph, before they came together, she was found with child, of the Holy Ghost.", "bbe": "Now the birth of Jesus Christ was in this way: when his mother Mary was going to be married to Joseph, before they came together the discovery was made that she was with child by the Holy Spirit.", "geneva": "Nowe the birth of Jesus Christ was thus, When as his mother Mary was betrothed to Ioseph, before they came together, shee was found with childe of the holy Ghost.", "wycliffe": "But the generacioun of Crist was thus. Whanne Marie, the modir of Jhesu, was spousid to Joseph, bifore thei camen togidere, she was foundun hauynge of the Hooli Goost in the wombe.", "rotherham": "Now the birth, of [Jesus] Christ, was, thus: His mother Mary having been betrothed to Joseph,—before they came together, she was found with child by [the] Holy Spirit.", "weymouth": "The circumstances of the birth of Jesus Christ were these. After his mother Mary was betrothed to Joseph, before they were united in marriage, she was found to be with child through the Holy Spirit.", "darby": "Now the birth of Jesus Christ was thus: His mother, Mary, that is, having been betrothed to Joseph, before they came together, she was found to be with child of [the] Holy Spirit.", "twenty": "The birth of Jesus Christ took place as follows: His mother Mary was betrothed to Joseph, but, before the marriage took place, she found herself to be with child by the power of the Holy Spirit.", "acv": "Now the birth of Jesus Christ was this way. For his mother Mary, who was betrothed to Joseph, before they came together she was found having in her womb from the Holy Spirit.", "anderson": "But Jesus Christ was begotten thus: After his mother Mary had been betrothed to Joseph, before they had come together, she was found to be with child of the Holy Spirit.", "haweis": "Now the generation of Jesus Christ was attended with these circumstances: His mother Mary being betrothed to Joseph, before they cohabited together, she was found with child from the Holy Spirit.", "noyes": "Now the birth of Jesus Christ was in this manner. When his mother Mary had been betrothed to Joseph, before they came together, she was found to be with child by the Holy Spirit.", "webster": "Now the birth of Jesus Christ was in this manner: When his mother Mary was espoused to Joseph, before they came together, she was found with child by the Holy Spirit.", "vulgate": "Christi autem generatio sic erat cum esset desponsata mater eius Maria Ioseph antequam convenirent inventa est in utero habens de Spiritu Sancto;"}}, {"v": 19, "ref": "1:19", "o": "Ἰωσὴφ δὲ ὁ ἀνὴρ αὐτῆς, δίκαιος ὢν καὶ μὴ θέλων αὐτὴν ⸀δειγματίσαι, ἐβουλήθη λάθρᾳ ἀπολῦσαι αὐτήν.", "en": {"kjv": "Then Joseph her husband, being a just man, and not willing to make her a publick example, was minded to put her away privily.", "web": "Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly.", "bsb": "Because Joseph her husband was a righteous man and was unwilling to disgrace her publicly, he resolved to divorce her quietly.", "asv": "And Joseph her husband, being a righteous man, and not willing to make her a public example, was minded to put her away privily.", "ylt": "and Joseph her husband being righteous, and not willing to make her an example, did wish privately to send her away.", "tyndale": "Then Ioseph her husbande beinge a perfect man and loth to make an ensample of hir, was mynded to put her awaye secretely. ✠", "dra": "Whereupon Joseph her husband, being a just man, and not willing publicly to expose her, was minded to put her away privately.", "bbe": "And Joseph, her husband, being an upright man, and not desiring to make her a public example, had a mind to put her away privately.", "geneva": "Then Ioseph her husband being a iust man, and not willing to make her a publike example, was minded to put her away secretly.", "wycliffe": "And Joseph, hir hosebonde, for he was riytful, and wolde not puplische hir, he wolde priueli haue left hir.", "rotherham": "Moreover, Joseph her husband, being, righteous, and yet unwilling to expose her,—intended, privately, to divorce her.", "weymouth": "But Joseph her husband, being a kind-hearted man and unwilling publicly to disgrace her, had determined to release her privately from the betrothal.", "darby": "But Joseph, her husband, being [a] righteous [man], and unwilling to expose her publicly, purposed to have put her away secretly;", "twenty": "Her husband, Joseph, was a religious man and, being unwilling to expose her to contempt, resolved to put an end to their betrothal privately.", "acv": "But Joseph her husband, being a righteous man, and not wanting to expose her to public disgrace, intended to dismiss her privately.", "anderson": "Then Joseph her husband, being a just man, and not choosing to make an example of her, intended to put her away privately.", "haweis": "Then Joseph her husband being a just man, and not willing to expose her publicly, designed to put her away privately.", "noyes": "Then Joseph her husband, being righteous, and not willing to expose her to shame, purposed to put her away privately.", "webster": "Then Joseph her husband, being a just [man], and not willing to make her a public example, purposed to put her away privately.", "vulgate": "Ioseph autem vir eius cum esset iustus et nollet eam traducere voluit occulte dimittere eam;"}}, {"v": 20, "ref": "1:20", "o": "ταῦτα δὲ αὐτοῦ ἐνθυμηθέντος ἰδοὺ ἄγγελος κυρίου κατ’ ὄναρ ἐφάνη αὐτῷ λέγων· Ἰωσὴφ υἱὸς Δαυίδ, μὴ φοβηθῇς παραλαβεῖν ⸀Μαρίαν τὴν γυναῖκά σου, τὸ γὰρ ἐν αὐτῇ γεννηθὲν ἐκ πνεύματός ἐστιν ἁγίου·", "en": {"kjv": "But while he thought on these things, behold, the angel of the Lord appeared unto him in a dream, saying, Joseph, thou son of David, fear not to take unto thee Mary thy wife: for that which is conceived in her is of the Holy Ghost.", "web": "But when he thought about these things, behold, an angel of the Lord appeared to him in a dream, saying, “Joseph, son of David, don’t be afraid to take to yourself Mary, your wife, for that which is conceived in her is of the Holy Spirit.", "bsb": "But after he had pondered these things, an angel of the Lord appeared to him in a dream and said, “Joseph, son of David, do not be afraid to embrace Mary as your wife, for the One conceived in her is from the Holy Spirit.", "asv": "But when he thought on these things, behold, an angel of the Lord appeared unto him in a dream, saying, Joseph, thou son of David, fear not to take unto thee Mary thy wife: for that which is conceived in her is of the Holy Spirit.", "ylt": "And on his thinking of these things, lo, a messenger of the Lord in a dream appeared to him, saying, `Joseph, son of David, thou mayest not fear to receive Mary thy wife, for that which in her was begotten is of the Holy Spirit,", "tyndale": "Whill he thus thought, behold ye angell of ye Lorde appered vnto him in a dreame, saynge: Ioseph ye sonne of David, feare not to take vnto ye, Mary thy wyfe. For that which is conceaved in her is of the holy goost.", "dra": "But while he thought on these things, behold the Angel of the Lord appeared to him in his sleep, saying: Joseph, son of David, fear not to take unto thee Mary thy wife, for that which is conceived in her, is of the Holy Ghost.", "bbe": "But when he was giving thought to these things, an angel of the Lord came to him in a dream, saying, Joseph, son of David, have no fear of taking Mary as your wife; because that which is in her body is of the Holy Spirit.", "geneva": "But whiles he thought these things, behold, the Angel of the Lord appeared vnto him in a dreame, saying, Ioseph, the sonne of Dauid, feare not to take Mary thy wife: for that which is conceiued in her, is of the holy Ghost.", "wycliffe": "But while he thouyte thes thingis, lo! the aungel of the Lord apperide `in sleep to hym, and seide, Joseph, the sone of Dauid, nyle thou drede to take Marie, thi wijf; for that thing that is borun in hir is of the Hooli Goost.", "rotherham": "But, when, these things, he had pondered, lo! a messenger of the Lord, by dream, appeared to him, saying,—Joseph, son of David! do not fear to take unto thee Mary thy wife, for, that which, in her, hath been begotten, is of [the], Holy, Spirit.", "weymouth": "But while he was contemplating this step, an angel of the Lord appeared to him in a dream and said, \"Joseph, son of David, do not be afraid to bring home your wife Mary, for she is with child through the Holy Spirit.", "darby": "but while he pondered on these things, behold, an angel of [the] Lord appeared to him in a dream, saying, Joseph, son of David, fear not to take to [thee] Mary, thy wife, for that which is begotten in her is of [the] Holy Spirit.", "twenty": "He had been dwelling upon this, when an angel of the Lord appeared to him in a dream. “Joseph, son of David,” the angel said, “do not be afraid to take Mary for your wife, for her child has been conceived by the power of the Holy Spirit.", "acv": "But while he considered these things, behold, an agent of the Lord appeared to him in a dream, saying, Joseph, thou son of David, fear not to take Mary to be thy wife, for that which was begotten in her is from the Holy Spirit.", "anderson": "But while he was thinking of these things, behold, an angel of the Lord appeared to him in a dream, saying: Joseph, son of David, fear not to take home Mary your wife; for that which is begotten in her is of the Holy Spirit.", "haweis": "And as he was revolving the matter in his mind, behold, an angel of the Lord in a dream appeared unto him, saying, Joseph, son of David, fear not to take Mary for thy wife, for that which is conceived in her is from the Holy Spirit.", "noyes": "But while he thought on these things, lo! an angel of the Lord appeared to him in a dream, saying, Joseph, son of David, fear not to take to thee Mary thy wife; for that which is conceived in her is by the Holy Spirit.", "webster": "But while he thought on these things, the angel of the Lord appeared to him in a dream, saying, Joseph, thou son of David, fear not to take to thee Mary thy wife: for that which is conceived in her is by the Holy Spirit.", "vulgate": "haec autem eo cogitante ecce angelus Domini in somnis apparuit ei dicens Ioseph fili David noli timere accipere Mariam coniugem tuam quod enim in ea natum est de Spiritu Sancto est;"}}, {"v": 21, "ref": "1:21", "o": "τέξεται δὲ υἱὸν καὶ καλέσεις τὸ ὄνομα αὐτοῦ Ἰησοῦν, αὐτὸς γὰρ σώσει τὸν λαὸν αὐτοῦ ἀπὸ τῶν ἁμαρτιῶν αὐτῶν.", "en": {"kjv": "And she shall bring forth a son, and thou shalt call his name JESUS: for he shall save his people from their sins.", "web": "She shall give birth to a son. You shall call his name Jesus, for it is he who shall save his people from their sins.”", "bsb": "She will give birth to a Son, and you are to give Him the name Jesus, because He will save His people from their sins.”", "asv": "And she shall bring forth a son; and thou shalt call his name JESUS; for it is he that shall save his people from their sins.", "ylt": "and she shall bring forth a son, and thou shalt call his name Jesus, for he shall save his people from their sins.'", "tyndale": "She shall brynge forthe a sonne, and thou shalt call his name Iesus. For he shall save his peple from their synnes.", "dra": "And she shall bring forth a son: and thou shalt call his name Jesus. For he shall save his people from their sins.", "bbe": "And she will give birth to a son; and you will give him the name Jesus; for he will give his people salvation from their sins.", "geneva": "And she shall bring foorth a sonne, and thou shalt call his name JESUS: for hee shall saue his people from their sinnes.", "wycliffe": "And she shal bere a sone, and thou shalt clepe his name Jhesus; for he schal make his puple saaf fro her synnes.", "rotherham": "Moreover she shall bring forth a son, and thou shalt call his name Jesus,—for, he, will save his people from their sins.", "weymouth": "She will give birth to a Son, and you are to call His name JESUS for He it is who will save His People from their sins.\"", "darby": "And she shall bring forth a son, and thou shalt call his name Jesus, for he shall save his people from their sins.", "twenty": "She shall give birth to a son; and you shall give him the name Jesus, for it is he who shall save his people from their sins.”", "acv": "And she will bring forth a son, and thou shall call his name JESUS, for he will save his people from their sins.", "anderson": "And she will bear a son, and you shall call his name Jesus; for he will save his people from their sins.", "haweis": "And she shall bring forth a son, and thou shalt call his name Jesus, for he shall save his people from their sins.", "noyes": "And she will bear a son, and thou shalt call his name Jesus; for he will save his people from their sins.", "webster": "And she shall bring forth a son, and thou shalt call his name JESUS: for he shall save his people from their sins.", "vulgate": "pariet autem filium et vocabis nomen eius Iesum ipse enim salvum faciet populum suum a peccatis eorum;"}}, {"v": 22, "ref": "1:22", "o": "τοῦτο δὲ ὅλον γέγονεν ἵνα πληρωθῇ τὸ ῥηθὲν ⸀ὑπὸ κυρίου διὰ τοῦ προφήτου λέγοντος·", "en": {"kjv": "Now all this was done, that it might be fulfilled which was spoken of the Lord by the prophet, saying,", "web": "Now all this has happened, that it might be fulfilled which was spoken by the Lord through the prophet, saying,", "bsb": "All this took place to fulfill what the Lord had said through the prophet:", "asv": "Now all this is come to pass, that it might be fulfilled which was spoken by the Lord through the prophet, saying,", "ylt": "And all this hath come to pass, that it may be fulfilled that was spoken by the Lord through the prophet, saying,", "tyndale": "All this was done to fulfill yt which was spoken of the Lorde by the Prophet, saynge:", "dra": "Now all this was done that it might be fulfilled which the Lord spoke by the prophet, saying:", "bbe": "Now all this took place so that the word of the Lord by the prophet might come true,", "geneva": "And al this was done that it might be fulfilled, which is spoken of the Lord by ye Prophet, saying,", "wycliffe": "For al this thing was don, that it schulde be fulfillid, that was seid of the Lord bi a prophete, seiynge, Lo!", "rotherham": "But, all this, hath come to pass, that it might be fulfilled which was spoken by the Lord, through the prophet, saying:", "weymouth": "All this took place in fulfilment of what the Lord had spoken through the Prophet,", "darby": "Now all this came to pass that that might be fulfilled which was spoken by [the] Lord, through the prophet, saying,", "twenty": "All this happened in fulfilment of these words of the Lord in the Prophet, where he says —", "acv": "Now all this has come to pass, so that what was spoken by the Lord through the prophet might be fulfilled, which says,", "anderson": "Now all this was done, that the word might be fulfilled, which was spoken by the Lord through the prophet, saying:", "haweis": "Now the whole of this was done, that what was spoken of the Lord, by the prophet, might be fulfilled, saying,", "noyes": "Now all this took place, that it might be fulfilled which was spoken by the Lord through the prophet, saying,", "webster": "Now all this was done, that it might be fulfilled which was spoken from the Lord by the prophet, saying,", "vulgate": "hoc autem totum factum est ut adimpleretur id quod dictum est a Domino per prophetam dicentem;"}}, {"v": 23, "ref": "1:23", "o": "Ἰδοὺ ἡ παρθένος ἐν γαστρὶ ἕξει καὶ τέξεται υἱόν, καὶ καλέσουσιν τὸ ὄνομα αὐτοῦ Ἐμμανουήλ· ὅ ἐστιν μεθερμηνευόμενον Μεθ’ ἡμῶν ὁ θεός.", "en": {"kjv": "Behold, a virgin shall be with child, and shall bring forth a son, and they shall call his name Emmanuel, which being interpreted is, God with us.", "web": "“Behold, the virgin shall be with child, and shall give birth to a son. They shall call his name Immanuel”; which is, being interpreted, “God with us.”", "bsb": "“Behold, the virgin will be with child and will give birth to a son, and they will call Him Immanuel” (which means, “God with us”).", "asv": "Behold, the virgin shall be with child, and shall bring forth a son, And they shall call his name Immanuel; which is, being interpreted, God with us.", "ylt": "`Lo, the virgin shall conceive, and she shall bring forth a son, and they shall call his name Emmanuel,' which is, being interpreted `With us he is God.'", "tyndale": "Beholde a mayde shall be with chylde, and shall brynge forthe a sonne, and they shall call his name Emanuel, which is by interpretacion, God with vs. ⹐", "dra": "Behold a virgin shall be with child, and bring forth a son, and they shall call his name Emmanuel, which being interpreted is, God with us.", "bbe": "See, the virgin will be with child, and will give birth to a son, and they will give him the name Immanuel, that is, God with us.", "geneva": "Behold, a virgine shalbe with childe, and shall beare a sonne, and they shall call his name Emmanuel, which is by interpretation, God with vs.", "wycliffe": "a virgyn shal haue in wombe, and she schal bere a sone, and thei schulen clepe his name Emanuel, that is to seie, God with vs.", "rotherham": "Lo! a Virgin, shall be with child, and shall bring forth a son,—and they shall call his name Emmanuel; which is, being translated, God with us.", "weymouth": "\"Mark! The maiden will be with child and will give birth to a son, and they will call His name Immanuel\" --a word which signifies `God with us'.", "darby": "Behold, the virgin shall be with child, and shall bring forth a son, and they shall call his name Emmanuel, which is, being interpreted, 'God with us.'", "twenty": "‘Behold! the virgin shall be with child and shall give birth to a son, and they will give him the name Immanuel’ — a word which means ‘God is with us.’", "acv": "Behold, the virgin will have in her womb, and will bring forth a son. And they will call his name Immanuel, which is, being interpreted, God with us.", "anderson": "Behold, a virgin shall be with child, and shall bear a son, and his name shall be called Immanuel, which, when translated, is, God with us.", "haweis": "“A virgin shall be with child and shall bring forth a son, and they shall call his name Immanuel,” which is being interpreted, God with us.", "noyes": "\"Behold, the virgin shall be with child, and shall bear a son, and they shall call his name Immanuel;\" that is, when interpreted, God-is with-us.", "webster": "Behold, a virgin shall be with child, and shall bring forth a son, and they shall call his name Emmanuel, which being interpreted is, God with us.", "vulgate": "ecce virgo in utero habebit et pariet filium et vocabunt nomen eius Emmanuhel quod est interpretatum Nobiscum Deus;"}}, {"v": 24, "ref": "1:24", "o": "⸀ἐγερθεὶς δὲ ὁ Ἰωσὴφ ἀπὸ τοῦ ὕπνου ἐποίησεν ὡς προσέταξεν αὐτῷ ὁ ἄγγελος κυρίου καὶ παρέλαβεν τὴν γυναῖκα αὐτοῦ·", "en": {"kjv": "Then Joseph being raised from sleep did as the angel of the Lord had bidden him, and took unto him his wife:", "web": "Joseph arose from his sleep, and did as the angel of the Lord commanded him, and took his wife to himself;", "bsb": "When Joseph woke up, he did as the angel of the Lord had commanded him, and embraced Mary as his wife.", "asv": "And Joseph arose from his sleep, and did as the angel of the Lord commanded him, and took unto him his wife;", "ylt": "And Joseph, having risen from the sleep, did as the messenger of the Lord directed him, and received his wife,", "tyndale": "And Ioseph assone as he awoke out of slepe, did as the angell of the Lorde bade hym, and toke hys wyfe vnto hym,", "dra": "And Joseph rising up from sleep, did as the angel of the Lord had commanded him, and took unto him his wife.", "bbe": "And Joseph did as the angel of the Lord had said to him, and took her as his wife;", "geneva": "Then Ioseph, being raised from sleepe, did as the Angel of the Lord had inioyned him, and tooke his wife.", "wycliffe": "And Joseph roos fro sleepe, and dide as the aungel of the Lord comaundide hym, and took Marie, his wijf;", "rotherham": "And Joseph, awaking, from his sleep, did as the messenger of the Lord directed him,—and took unto him his wife;", "weymouth": "When Joseph awoke, he did as the angel of the Lord had commanded, and brought home his wife,", "darby": "But Joseph, having awoke up from his sleep, did as the angel of [the] Lord had enjoined him, and took to [him] his wife,", "twenty": "When Joseph awoke from his sleep, he did as the angel of the Lord had directed him.", "acv": "And Joseph, being roused from his sleep, did as the agent of the Lord ordered him. And he took his wife,", "anderson": "And Joseph awoke from his sleep, and did as the angel of the Lord had commanded him; and he took home his wife,", "haweis": "Then Joseph when arisen from sleep, did as the angel of the Lord commanded him, and took his wife;", "noyes": "Then Joseph, on waking up from sleep, did as the angel of the Lord had bidden him, and took to him his wife;", "webster": "Then Joseph, being raised from sleep, did as the angel of the Lord had bidden him, and took to him his wife:", "vulgate": "exsurgens autem Ioseph a somno fecit sicut praecepit ei angelus Domini et accepit coniugem suam;"}}, {"v": 25, "ref": "1:25", "o": "καὶ οὐκ ἐγίνωσκεν αὐτὴν ἕως οὗ ἔτεκεν ⸀υἱόν· καὶ ἐκάλεσεν τὸ ὄνομα αὐτοῦ Ἰησοῦν.", "en": {"kjv": "And knew her not till she had brought forth her firstborn son: and he called his name JESUS.", "web": "and didn’t know her sexually until she had given birth to her firstborn son. He named him Jesus.", "bsb": "But he had no union with her until she gave birth to a Son. And he gave Him the name Jesus.", "asv": "and knew her not till she had brought forth a son: and he called his name JESUS.", "ylt": "and did not know her till she brought forth her son--the first-born, and he called his name Jesus.", "tyndale": "and knewe her not tyll she had brought forth hir fyrst sonne, and called hys name Iesus.", "dra": "And he knew her not, till she brought forth her first born son: and he called his name Jesus.", "bbe": "And he had no connection with her till she had given birth to a son; and he gave him the name Jesus.", "geneva": "But he knew her not, til she had broght forth her first borne sonne, and he called his name JESUS.", "wycliffe": "and he knew her not, til she hadde borun her firste bigete sone, and clepide his name Jhesus.", "rotherham": "and knew her not, until she had brought forth a son,—and he called his name Jesus.", "weymouth": "but did not live with her until she had given birth to a son. The child's name he called JESUS.", "darby": "and knew her not until she had brought forth her firstborn son: and he called his name Jesus.", "twenty": "He made Mary his wife, but did not live with her as her husband until after the birth of her son; and to this son he gave the name Jesus.", "acv": "and knew her not until she brought forth her son, the firstborn. And he called his name JESUS.", "anderson": "and knew her not till she had brought forth her first-born son. And he called his name Jesus.", "haweis": "and he knew her not, until she had brought forth her son, the first begotten, and he called his name Jesus.", "noyes": "and he knew her not till she had brought forth a son: and he called his name Jesus.", "webster": "And knew her not till she had brought forth her first-born son: and he called his name JESUS.", "vulgate": "et non cognoscebat eam donec peperit filium suum primogenitum et vocavit nomen eius Iesum;"}}]}, {"c": 2, "verses": [{"v": 1, "ref": "2:1", "o": "Τοῦ δὲ Ἰησοῦ γεννηθέντος ἐν Βηθλέεμ τῆς Ἰουδαίας ἐν ἡμέραις Ἡρῴδου τοῦ βασιλέως, ἰδοὺ μάγοι ἀπὸ ἀνατολῶν παρεγένοντο εἰς Ἱεροσόλυμα", "en": {"kjv": "Now when Jesus was born in Bethlehem of Judea in the days of Herod the king, behold, there came wise men from the east to Jerusalem,", "web": "Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying,", "bsb": "After Jesus was born in Bethlehem in Judea, during the time of King Herod, Magi from the east arrived in Jerusalem,", "asv": "Now when Jesus was born in Bethlehem of Judæa in the days of Herod the king, behold, Wise-men from the east came to Jerusalem, saying,", "ylt": "And Jesus having been born in Beth-Lehem of Judea, in the days of Herod the king, lo, mages from the east came to Jerusalem,", "tyndale": "When Iesus was borne at Bethleem in Iury, in the tyme of Herode the kynge. Beholde, there came wyse men from the eest to Ierusalem", "dra": "When Jesus therefore was born in Bethlehem of Juda, in the days of king Herod, behold, there came wise men from the East to Jerusalem,", "bbe": "Now when the birth of Jesus took place in Beth-lehem of Judaea, in the days of Herod the king, there came wise men from the east to Jerusalem,", "geneva": "When Jesus then was borne at Bethleem in Iudea, in the dayes of Herod the King, beholde, there came Wisemen from the East to Hierusalem,", "wycliffe": "Therfor whanne Jhesus was borun in Bethleem of Juda, in the daies of king Eroude, lo! astromyenes camen fro the eest to Jerusalem,", "rotherham": "Now, when, Jesus, was born in Bethlehem of Judaea, in the days of Herod the king, lo! wise men from eastern parts, came into Jerusalem:", "weymouth": "Now after the birth of Jesus, which took place at Bethlehem in Judaea in the reign of King Herod, excitement was produced in Jerusalem by the arrival of certain Magi from the east,", "darby": "Now Jesus having been born in Bethlehem of Judaea, in the days of Herod the king, behold magi from the east arrived at Jerusalem, saying,", "twenty": "After the birth of Jesus at Bethlehem in Judea, in the reign of King Herod, some Astrologers from the East arrived in Jerusalem, asking:", "acv": "Now Jesus having been born in Bethlehem of Judea in the days of Herod the king, behold, wise men from the east came to Jerusalem, saying,", "anderson": "Now after Jesus was born in Bethlehem of Judea, in the days of Herod the king, behold, Magi from the east came to Jerusalem,", "haweis": "NOW when Jesus was born in Bethlehem of Judea in the days of Herod the king, lo! Magians from the East came to Jerusalem,", "noyes": "Now when Jesus had been born in Bethlehem of Judaea, in the days of Herod the king, lo! there came magians from the East to Jerusalem,", "webster": "Now, after Jesus was born in Bethlehem of Judea in the days of Herod the king, behold, there came wise men from the east to Jerusalem,", "vulgate": "cum ergo natus esset Iesus in Bethleem Iudaeae in diebus Herodis regis ecce magi ab oriente venerunt Hierosolymam;"}}, {"v": 2, "ref": "2:2", "o": "λέγοντες· Ποῦ ἐστιν ὁ τεχθεὶς βασιλεὺς τῶν Ἰουδαίων; εἴδομεν γὰρ αὐτοῦ τὸν ἀστέρα ἐν τῇ ἀνατολῇ καὶ ἤλθομεν προσκυνῆσαι αὐτῷ.", "en": {"kjv": "Saying, Where is he that is born King of the Jews? for we have seen his star in the east, and are come to worship him.", "web": "“Where is he who is born King of the Jews? For we saw his star in the east, and have come to worship him.”", "bsb": "asking, “Where is the One who has been born King of the Jews? We saw His star in the east and have come to worship Him.”", "asv": "Where is he that is born King of the Jews? for we saw his star in the east, and are come to worship him.", "ylt": "saying, `Where is he who was born king of the Jews? for we saw his star in the east, and we came to bow to him.'", "tyndale": "saynge: Where is he yt is borne kynge of ye Iues? We have sene his starre in ye eest, and are come to worship him.", "dra": "Saying: Where is he that is born king of the Jews? For we have seen his star in the East, and are come to adore him.", "bbe": "Saying, Where is the King of the Jews whose birth has now taken place? We have seen his star in the east and have come to give him worship.", "geneva": "Saying, Where is that King of the Iewes that is borne? for wee haue seene his starre in the East, and are come to worship him.", "wycliffe": "and seiden, Where is he, that is borun king of Jewis? for we han seyn his sterre in the eest, and we comen to worschipe him.", "rotherham": "saying—Where is he that hath been born king of the Jews? for we saw his star in the east, and have come to bow down to him.", "weymouth": "inquiring, \"Where is the newly born king of the Jews? For we have seen his Star in the east, and have come here to do him homage.\"", "darby": "Where is the king of the Jews that has been born? for we have seen his star in the east, and have come to do him homage.", "twenty": "“Where is the new-born King of the Jews? for we saw his star in the east, and have come to do homage to him.”", "acv": "Where is he who is born king of the Jews? For we saw his star in the east, and have come to worship him.", "anderson": "saying: Where is he that is born king of the Jews? For we have seen his star in the east, and have come to do him homage.", "haweis": "saying, Where is he that is born king of the Jews? for we have seen his star in the East, and are come to pay him homage.", "noyes": "saying, Where is the king of the Jews that hath been born? for we saw his star in the East, and came to do him homage.", "webster": "Saying, Where is he that is born king of the Jews? for we have seen his star in the east, and have come to worship him.", "vulgate": "dicentes ubi est qui natus est rex Iudaeorum vidimus enim stellam eius in oriente et venimus adorare eum;"}}, {"v": 3, "ref": "2:3", "o": "ἀκούσας δὲ ⸂ὁ βασιλεὺς Ἡρῴδης⸃ ἐταράχθη καὶ πᾶσα Ἱεροσόλυμα μετ’ αὐτοῦ,", "en": {"kjv": "When Herod the king had heard these things, he was troubled, and all Jerusalem with him.", "web": "When King Herod heard it, he was troubled, and all Jerusalem with him.", "bsb": "When King Herod heard this, he was disturbed, and all Jerusalem with him.", "asv": "And when Herod the king heard it, he was troubled, and all Jerusalem with him.", "ylt": "And Herod the king having heard, was stirred, and all Jerusalem with him,", "tyndale": "When Herode ye kynge had herde thys, he was troubled, and all Ierusalem with hym,", "dra": "And king Herod hearing this, was troubled, and all Jerusalem with him.", "bbe": "And when it came to the ears of Herod the king, he was troubled, and all Jerusalem with him.", "geneva": "When King Herod heard this, he was troubled, and all Hierusalem with him.", "wycliffe": "But king Eroude herde, and was trublid, and al Jerusalem with hym.", "rotherham": "But, when King Herod heard, he was troubled, and all Jerusalem with him;", "weymouth": "Reports of this soon reached the king, and greatly agitated not only him but all the people of Jerusalem.", "darby": "But Herod the king having heard [of it], was troubled, and all Jerusalem with him;", "twenty": "When King Herod heard of this, he was much troubled, and so, too, was all Jerusalem.", "acv": "And Herod the king having heard it, he was troubled, and all Jerusalem with him.", "anderson": "When Herod the king heard these things, he was troubled, and all Jerusalem with him.", "haweis": "Now when Herod the king heard this, he was much agitated, and all Jerusalem with him.", "noyes": "But when Herod the king heard of these things, he was troubled, and all Jerusalem with him;", "webster": "When Herod the king had heard [these things], he was troubled, and all Jerusalem with him.", "vulgate": "audiens autem Herodes rex turbatus est et omnis Hierosolyma cum illo;"}}, {"v": 4, "ref": "2:4", "o": "καὶ συναγαγὼν πάντας τοὺς ἀρχιερεῖς καὶ γραμματεῖς τοῦ λαοῦ ἐπυνθάνετο παρ’ αὐτῶν ποῦ ὁ χριστὸς γεννᾶται.", "en": {"kjv": "And when he had gathered all the chief priests and scribes of the people together, he demanded of them where Christ should be born.", "web": "Gathering together all the chief priests and scribes of the people, he asked them where the Christ would be born.", "bsb": "And when he had assembled all the chief priests and scribes of the people, he asked them where the Christ was to be born.", "asv": "And gathering together all the chief priests and scribes of the people, he inquired of them where the Christ should be born.", "ylt": "and having gathered all the chief priests and scribes of the people, he was inquiring from them where the Christ is born.", "tyndale": "and he gathered all ye chefe Prestes and Scribes of the people, and axed of them where Christ shulde be borne.", "dra": "And assembling together all the chief priests and the scribes of the people, he inquired of them where Christ should be born.", "bbe": "And he got together all the chief priests and scribes of the people, questioning them as to where the birth-place of the Christ would be.", "geneva": "And gathering together all the chiefe Priestes and Scribes of the people, hee asked of them, where Christ should be borne.", "wycliffe": "And he gaderide to gidre alle the prynces of prestis, and scribis of the puple, and enqueride of hem, where Crist shulde be borun.", "rotherham": "and, assembling all the high-priests and scribes of the people, he was enquiring of them—Where is, the Christ, to be born?", "weymouth": "So he assembled all the High Priests and Scribes of the people, and anxiously asked them where the Christ was to be born.", "darby": "and, assembling all the chief priests and scribes of the people, he inquired of them where the Christ should be born.", "twenty": "He called together all the Chief Priests and Teachers of the Law in the nation, and questioned them as to where the Christ was to be born.", "acv": "And having gathered together all the chief priests and scholars of the people, he inquired of them where the Christ is born.", "anderson": "And when he had assembled all the chief priests and scribes of the people, he inquired of them where the Christ should be born.", "haweis": "And assembling all the chief priests and scribes of the people, he enquired of them, where the Messiah should be born.", "noyes": "and assembling all the chief priests and scribes of the people, he inquired of them where the Christ was to be born.", "webster": "And when he had assembled all the chief priests and scribes of the people, he inquired of them where Christ should be born.", "vulgate": "et congregans omnes principes sacerdotum et scribas populi sciscitabatur ab eis ubi Christus nasceretur;"}}, {"v": 5, "ref": "2:5", "o": "οἱ δὲ εἶπαν αὐτῷ· Ἐν Βηθλέεμ τῆς Ἰουδαίας· οὕτως γὰρ γέγραπται διὰ τοῦ προφήτου·", "en": {"kjv": "And they said unto him, In Bethlehem of Judea: for thus it is written by the prophet,", "web": "They said to him, “In Bethlehem of Judea, for this is written through the prophet,", "bsb": "“In Bethlehem in Judea,” they replied, “for this is what the prophet has written:", "asv": "And they said unto him, In Bethlehem of Judæa: for thus it is written through the prophet,", "ylt": "And they said to him, `In Beth-Lehem of Judea, for thus it hath been written through the prophet,", "tyndale": "And they sayde vnto hym: at Bethleem in Iury. For thus it is written by the Prophet.", "dra": "But they said to him: In Bethlehem of Juda. For so it is written by the prophet:", "bbe": "And they said to him, In Beth-lehem of Judaea; for so it is said in the writings of the prophet,", "geneva": "And they saide vnto him, At Beth-leem in Iudea: for so it is written by the Prophet,", "wycliffe": "And thei seiden to hym, In Bethleem of Juda; for so it is writun bi a profete,", "rotherham": "And, they, said to him, In Bethlehem of Judaea,—for, so, is it written through the prophet:", "weymouth": "\"At Bethlehem in Judaea,\" they replied; \"for so it stands written in the words of the Prophet,", "darby": "And they said to him, In Bethlehem of Judaea; for thus it is written through the prophet:", "twenty": "“At Bethlehem in Judea,” was their answer; “for it is said in the Prophet —", "acv": "And they said to him, In Bethlehem of Judea. For thus it is written through the prophet,", "anderson": "And they said to him: In Bethlehem of Judea; for thus it is written by the prophet:", "haweis": "Then they answered him, In Bethlehem of Judea, for so it is written by the prophet,", "noyes": "And they said to him, In Bethlehem of Judaea; for thus it is written by the prophet:", "webster": "And they said to him, In Bethlehem of Judea: for thus it is written by the prophet,", "vulgate": "at illi dixerunt ei in Bethleem Iudaeae sic enim scriptum est per prophetam;"}}, {"v": 6, "ref": "2:6", "o": "Καὶ σύ, Βηθλέεμ γῆ Ἰούδα, οὐδαμῶς ἐλαχίστη εἶ ἐν τοῖς ἡγεμόσιν Ἰούδα· ἐκ σοῦ γὰρ ἐξελεύσεται ἡγούμενος, ὅστις ποιμανεῖ τὸν λαόν μου τὸν Ἰσραήλ.", "en": {"kjv": "And thou Bethlehem, in the land of Juda, art not the least among the princes of Juda: for out of thee shall come a Governor, that shall rule my people Israel.", "web": "‘You Bethlehem, land of Judah, are in no way least among the princes of Judah: for out of you shall come a governor, who shall shepherd my people, Israel.’”", "bsb": "‘But you, Bethlehem, in the land of Judah, are by no means least among the rulers of Judah, for out of you will come a ruler who will be the shepherd of My people Israel.’”", "asv": "And thou Bethlehem, land of Judah, Art in no wise least among the princes of Judah: For out of thee shall come forth a governor, Who shall be shepherd of my people Israel.", "ylt": "And thou, Beth-Lehem, the land of Judah, thou art by no means the least among the leaders of Judah, for out of thee shall come one leading, who shall feed My people Israel.'", "tyndale": "And thou Bethleem in the londe of Iury, art not the leest concernynge the Princes of Iuda. For out of the shall come the captayne, that shall govern my people Israhel.", "dra": "And thou Bethlehem the land of Juda art not the least among the princes of Juda: for out of thee shall come forth the captain that shall rule my people Israel.", "bbe": "You Beth-lehem, in the land of Judah, are not the least among the chiefs of Judah: out of you will come a ruler, who will be the keeper of my people Israel.", "geneva": "And thou Beth-leem in the lande of Iuda, art not the least among the Princes of Iuda: For out of thee shall come the gouernour that shall feede that my people Israel.", "wycliffe": "And thou, Bethleem, the lond of Juda, art not the leest among the prynces of Juda; for of thee a duyk schal go out, that schal gouerne my puple of Israel.", "rotherham": "And, thou, Bethlehem, land of Judah, by no means least, art thou, among the governors of Judah,—For, out of thee, shall one come forth to govern, Who shall shepherd my people Israel.", "weymouth": "\"`And thou, Bethlehem in the land of Judah, by no means the least honorable art thou among princely places in Judah! For from thee shall come a prince--one who shall be the Shepherd of My People Israel.'\"", "darby": "And thou Bethlehem, land of Juda, art in no wise the least among the governors of Juda; for out of thee shall go forth a leader who shall shepherd my people Israel.", "twenty": "‘And thou, Bethlehem in Judah’s land, art in no way least among the chief cities of Judah; for out of thee will come a Chieftain — one who will shepherd my people Israel.’”", "acv": "And thou Bethlehem, land of Judah, are in no way least among the rulers of Judah, for out of thee will come forth a man who rules, who will tend my people Israel.", "anderson": "And thou, Bethlehem, city of Judah, art by no means the least among the chiefs of Judah; for out of thee shall come a leader, that shall be a shepherd to my people Israel.", "haweis": "“And thou Bethlehem, land of Judah, art in no respect the least amongst the princes of Judah, for from thee shall go forth the Ruler, who shall conduct my people Israel.”", "noyes": "\"And thou Bethlehem, land of Judah, art by no means least among the princes of Judah; for out of thee shall come a ruler, who shall feed my people Israel.\"", "webster": "And thou Bethlehem, [in] the land of Judah, art not the least among the princes of Judah: for out of thee shall come a Governor, that shall rule my people Israel.", "vulgate": "et tu Bethleem terra Iuda nequaquam minima es in principibus Iuda ex te enim exiet dux qui reget populum meum Israhel;"}}, {"v": 7, "ref": "2:7", "o": "Τότε Ἡρῴδης λάθρᾳ καλέσας τοὺς μάγους ἠκρίβωσεν παρ’ αὐτῶν τὸν χρόνον τοῦ φαινομένου ἀστέρος,", "en": {"kjv": "Then Herod, when he had privily called the wise men, enquired of them diligently what time the star appeared.", "web": "Then Herod secretly called the wise men, and learned from them exactly what time the star appeared.", "bsb": "Then Herod called the Magi secretly and learned from them the exact time the star had appeared.", "asv": "Then Herod privily called the Wise-men, and learned of them exactly what time the star appeared.", "ylt": "Then Herod, privately having called the mages, did inquire exactly from them the time of the appearing star,", "tyndale": "Then Herod prevely called the wyse men, and dyligently enquyred of them, ye tyme of the starre that appered,", "dra": "Then Herod, privately calling the wise men learned diligently of them the time of the star which appeared to them;", "bbe": "Then Herod sent for the wise men privately, and put questions to them about what time the star had been seen.", "geneva": "Then Herod priuily called the Wisemen, and diligently inquired of them the time of the starre that appeared,", "wycliffe": "Thanne Eroude clepide pryueli the astromyens, and lernyde bisili of hem the tyme of the sterre that apperide to hem.", "rotherham": "Then Herod, privately, calling the wise men, ascertained from them the time of the appearing star;", "weymouth": "Thereupon Herod sent privately for the Magi and ascertained from them the exact time of the star's appearing.", "darby": "Then Herod, having secretly called the magi, inquired of them accurately the time of the star that was appearing;", "twenty": "Then Herod secretly sent for the Astrologers, and ascertained from them the date of the appearance of the star;", "acv": "Then Herod having called the wise men privately, ascertained from them what time the star appeared.", "anderson": "Then Herod, when he had secretly called the Magi, inquired of them strictly at what time the star, then visible, first made its appearance:", "haweis": "Thereupon Herod secretly calling to him the Magians, enquired very particularly of them the time of the star’s appearing,", "noyes": "Then Herod, having privately called the magians ascertained from them exactly the time when the star appeared.", "webster": "Then Herod, when he had privately called the wise men, inquired of them diligently what time the star appeared.", "vulgate": "tunc Herodes clam vocatis magis diligenter didicit ab eis tempus stellae quae apparuit eis;"}}, {"v": 8, "ref": "2:8", "o": "καὶ πέμψας αὐτοὺς εἰς Βηθλέεμ εἶπεν· Πορευθέντες ⸂ἐξετάσατε ἀκριβῶς⸃ περὶ τοῦ παιδίου· ἐπὰν δὲ εὕρητε, ἀπαγγείλατέ μοι, ὅπως κἀγὼ ἐλθὼν προσκυνήσω αὐτῷ.", "en": {"kjv": "And he sent them to Bethlehem, and said, Go and search diligently for the young child; and when ye have found him, bring me word again, that I may come and worship him also.", "web": "He sent them to Bethlehem, and said, “Go and search diligently for the young child. When you have found him, bring me word, so that I also may come and worship him.”", "bsb": "And sending them to Bethlehem, he said: “Go and search carefully for the Child, and when you find Him, report to me, so that I too may go and worship Him.”", "asv": "And he sent them to Bethlehem, and said, Go and search out exactly concerning the young child; and when ye have found him, bring me word, that I also may come and worship him.", "ylt": "and having sent them to Beth-Lehem, he said, `Having gone--inquire ye exactly for the child, and whenever ye may have found, bring me back word, that I also having come may bow to him.'", "tyndale": "and sent them to Bethleem saynge: Goo and searche dyligently for ye chylde. And when ye have founde hym, bringe me worde, yt I maye come and worshippe hym also.", "dra": "And sending them into Bethlehem, said: Go and diligently inquire after the child, and when you have found him, bring me word again, that I also may come and adore him.", "bbe": "And he sent them to Beth-lehem and said, Go and make certain where the young child is; and when you have seen him, let me have news of it, so that I may come and give him worship.", "geneva": "And sent them to Beth-leem, saying, Goe, and searche diligently for the babe: and when ye haue founde him, bring mee worde againe, that I may come also, and worship him.", "wycliffe": "And he sente hem in to Bethleem, and seide, Go ye, and axe ye bisili of the child, and whanne yee han foundun, telle ye it to me, that Y also come, and worschipe hym.", "rotherham": "and sending them to Bethlehem, said—Go search out accurately concerning the child,—and, as soon as ye find it, bring report unto me, that, I also, may come and bow myself down to it.", "weymouth": "He then directed them to go to Bethlehem, adding, \"Go and make careful inquiry about the child, and when you have found him, bring me word, that I too may come and do him homage.\"", "darby": "and having sent them to Bethlehem, said, Go, search out accurately concerning the child, and when ye shall have found [him] bring me back word, so that I also may come and do him homage.", "twenty": "and, sending them to Bethlehem, he said: “Go and make careful inquiries about the child, and, as soon as you have found him, bring me word, that I, too, may go and do homage to him.”", "acv": "And having sent them to Bethlehem, he said, After going, search diligently about the child. And when ye find him, report to me, so that I also having come, may worship him.", "anderson": "and sending them to Bethlehem, he said: Go, make strict inquiry for the young child: and when you have found him, bring me word, that I also may go and do him homage.", "haweis": "and sending them to Bethlehem said, Go, and procure the most exact information respecting this child; and when you have found him, bring me intelligence, that I may come, and pay him homage also.", "noyes": "And he sent them to Bethlehem, and said, Go and search carefully for the child; and when ye have found him, bring me word, that I also may go and do him homage.", "webster": "And he sent them to Bethlehem, and said, Go, and search diligently for the young child; and when ye have found [him], bring me word again, that I may come and worship him also.", "vulgate": "et mittens illos in Bethleem dixit ite et interrogate diligenter de puero et cum inveneritis renuntiate mihi ut et ego veniens adorem eum;"}}, {"v": 9, "ref": "2:9", "o": "οἱ δὲ ἀκούσαντες τοῦ βασιλέως ἐπορεύθησαν, καὶ ἰδοὺ ὁ ἀστὴρ ὃν εἶδον ἐν τῇ ἀνατολῇ προῆγεν αὐτούς, ἕως ἐλθὼν ⸀ἐστάθη ἐπάνω οὗ ἦν τὸ παιδίον.", "en": {"kjv": "When they had heard the king, they departed; and, lo, the star, which they saw in the east, went before them, till it came and stood over where the young child was.", "web": "They, having heard the king, went their way; and behold, the star, which they saw in the east, went before them, until it came and stood over where the young child was.", "bsb": "After they had heard the king, they went on their way, and the star they had seen in the east went ahead of them until it stood over the place where the Child was.", "asv": "And they, having heard the king, went their way; and lo, the star, which they saw in the east, went before them, till it came and stood over where the young child was.", "ylt": "And they, having heard the king, departed, and lo, the star, that they did see in the east, did go before them, till, having come, it stood over where the child was.", "tyndale": "When they had heard the kynge, they departed: and lo the starre which they sawe in ye eeste, went before them, tyll it came and stode over the place where the chylde was.", "dra": "Who having heard the king, went their way; and behold the star which they had seen in the East, went before them, until it came and stood over where the child was.", "bbe": "And after hearing the king, they went on their way; and the star which they saw in the east went before them, till it came to rest over the place where the young child was.", "geneva": "So when they had heard the King, they departed: and loe, the starre which they had seene in the East, went before them, till it came and stoode ouer the place where the babe was.", "wycliffe": "And whanne thei hadden herd the kyng, thei wenten forth. And lo! the sterre, that thei siyen in the eest, wente bifore hem, til it cam, and stood aboue, where the child was.", "rotherham": "Now, they, hearing the king, went, and lo! the star which they had seen in the east, was going before them, until it went and stood over where the child was;", "weymouth": "After hearing what the king said, they went to Bethlehem, while, strange to say, the star they had seen in the east led them on until it came and stood over the place where the babe was.", "darby": "And they having heard the king went their way; and lo, the star, which they had seen in the east, went before them until it came and stood over the place where the little child was.", "twenty": "The Astrologers heard what the King had to say, and then continued their journey. And the star which they had seen in the east led them on, until it reached, and stood over, the place where the child was.", "acv": "And when they heard the king, they departed. And lo, the star that they saw in the east went before them until, having come, it stood over where the child was.", "anderson": "When they had heard the king, they departed; and lo, the star, which they had seen in the east, went before them, till it came and stood over the place where the young child was.", "haweis": "So having heard the king, they went on; and lo, the star, which they had seen in the East, had gone before them, till it came and stood over the place where the infant was.", "noyes": "When they had heard the king, they departed. And lo! the star, which they had seen in the East, went before them, till it came and stood over where the child was.", "webster": "When they had heard the king, they departed; and lo, the star, which they saw in the east, went before them, till it came and stood over where the young child was.", "vulgate": "qui cum audissent regem abierunt et ecce stella quam viderant in oriente antecedebat eos usque dum veniens staret supra ubi erat puer;"}}, {"v": 10, "ref": "2:10", "o": "ἰδόντες δὲ τὸν ἀστέρα ἐχάρησαν χαρὰν μεγάλην σφόδρα.", "en": {"kjv": "When they saw the star, they rejoiced with exceeding great joy.", "web": "When they saw the star, they rejoiced with exceedingly great joy.", "bsb": "When they saw the star, they rejoiced with great delight.", "asv": "And when they saw the star, they rejoiced with exceeding great joy.", "ylt": "And having seen the star, they rejoiced with exceeding great joy,", "tyndale": "When they sawe the starre, they were marvelously glad:", "dra": "And seeing the star they rejoiced with exceeding great joy.", "bbe": "And when they saw the star they were full of joy.", "geneva": "And when they sawe the starre, they reioyced with an exceeding great ioy,", "wycliffe": "And thei siyen the sterre, and ioyeden with a ful greet ioye.", "rotherham": "and, seeing the star, they rejoiced with exceeding great joy;", "weymouth": "When they saw the star, the sight filled them with intense joy.", "darby": "And when they saw the star they rejoiced with exceeding great joy.", "twenty": "At the sight of the star they were filled with joy.", "acv": "And when they saw the star, they rejoiced with exceedingly great joy.", "anderson": "And when they saw the star, they rejoiced with very great joy.", "haweis": "And when they saw the star, they were exceedingly transported with joy.", "noyes": "When they saw the star, they rejoiced with exceeding great joy;", "webster": "When they saw the star, they rejoiced with exceeding great joy.", "vulgate": "videntes autem stellam gavisi sunt gaudio magno valde;"}}, {"v": 11, "ref": "2:11", "o": "καὶ ἐλθόντες εἰς τὴν οἰκίαν εἶδον τὸ παιδίον μετὰ Μαρίας τῆς μητρὸς αὐτοῦ, καὶ πεσόντες προσεκύνησαν αὐτῷ, καὶ ἀνοίξαντες τοὺς θησαυροὺς αὐτῶν προσήνεγκαν αὐτῷ δῶρα, χρυσὸν καὶ λίβανον καὶ σμύρναν.", "en": {"kjv": "And when they were come into the house, they saw the young child with Mary his mother, and fell down, and worshipped him: and when they had opened their treasures, they presented unto him gifts; gold, and frankincense, and myrrh.", "web": "They came into the house and saw the young child with Mary, his mother, and they fell down and worshiped him. Opening their treasures, they offered to him gifts: gold, frankincense, and myrrh.", "bsb": "On coming to the house, they saw the Child with His mother Mary, and they fell down and worshiped Him. Then they opened their treasures and presented Him with gifts of gold and frankincense and myrrh.", "asv": "And they came into the house and saw the young child with Mary his mother; and they fell down and worshipped him; and opening their treasures they offered unto him gifts, gold and frankincense and myrrh.", "ylt": "and having come to the house, they found the child with Mary his mother, and having fallen down they bowed to him, and having opened their treasures, they presented to him gifts, gold, and frankincense, and myrrh,", "tyndale": "and went into the house, and found the chylde with Mary hys mother, and kneled doune and worshipped hym, and opened their treasures, and offred vnto hym gyftes, gold, franckynsence and myrre.", "dra": "And entering into the house, they found the child with Mary his mother, and falling down they adored him: and opening their treasures, they offered him gifts; gold, frankincense, and myrrh.", "bbe": "And they came into the house, and saw the young child with Mary, his mother; and falling down on their faces they gave him worship; and from their store they gave him offerings of gold, perfume, and spices.", "geneva": "And went into the house, and founde the babe with Mary his mother, and fell downe, and worshipped him, and opened their treasures, and presented vnto him giftes, euen golde, and frankincense, and myrrhe.", "wycliffe": "And thei entriden in to the hous, and founden the child with Marie, his modir; and thei felden doun, and worschipiden him. And whanne thei hadden openyd her tresouris, thei offryden to hym yiftis, gold, encense, and myrre.", "rotherham": "and, coming into the house, they saw the child, with Mary its mother,—and, falling down, prostrated themselves unto it, and, opening their treasures, offered unto it gifts—gold and frankincense and myrrh;", "weymouth": "So they entered the house; and when they saw the babe with His mother Mary, they prostrated themselves and did Him homage, and opening their treasure-chests offered gifts to Him--gold, frankincense, and myrrh.", "darby": "And having come into the house they saw the little child with Mary his mother, and falling down did him homage. And having opened their treasures, they offered to him gifts, gold, and frankincense, and myrrh.", "twenty": "Entering the house, they saw the child with his mother, Mary, and fell at his feet and did homage to him. Then they unpacked their treasures, and offered to the child presents of gold, frankincense, and myrrh.", "acv": "And having come into the house, they saw the child with Mary his mother, and having fallen down, they worshiped him. And having opened their treasures, they brought to him gifts, gold and frankincense and myrrh.", "anderson": "And having come into the house, they saw the young child with Mary his mother; and falling down, they did him homage. And when they had opened their treasures, they offered to him gifts, gold, frankincense, and myrrh.", "haweis": "And coming into the house, they found the infant with Mary his mother, and falling prostrate, they paid their homage to him. And opening their treasures, they made their offerings to him, gold, and frankincense, and myrrh.", "noyes": "and when they had come into the house, they saw the child with Mary his mother, and fell down, and did homage to him; and opening their treasures, they presented him gifts, gold and frankincense and myrrh.", "webster": "And when they had come into the house, they saw the young child with Mary his mother, and fell down, and worshiped him: and when they had opened their treasures, they presented to him gifts; gold, and frankincense, and myrrh.", "vulgate": "et intrantes domum invenerunt puerum cum Maria matre eius et procidentes adoraverunt eum et apertis thesauris suis obtulerunt ei munera aurum tus et murram;"}}, {"v": 12, "ref": "2:12", "o": "καὶ χρηματισθέντες κατ’ ὄναρ μὴ ἀνακάμψαι πρὸς Ἡρῴδην δι’ ἄλλης ὁδοῦ ἀνεχώρησαν εἰς τὴν χώραν αὐτῶν.", "en": {"kjv": "And being warned of God in a dream that they should not return to Herod, they departed into their own country another way.", "web": "Being warned in a dream that they shouldn’t return to Herod, they went back to their own country another way.", "bsb": "And having been warned in a dream not to return to Herod, they withdrew to their country by another route.", "asv": "And being warned of God in a dream that they should not return to Herod, they departed into their own country another way.", "ylt": "and having been divinely warned in a dream not to turn back unto Herod, through another way they withdrew to their own region.", "tyndale": "And after they were warned of God in a dreame, that they shuld not go ageyne to Herod, they retourned into their awne countre another waye. ⹐", "dra": "And having received an answer in sleep that they should not return to Herod, they went back another way into their country.", "bbe": "And it was made clear to them by God in a dream that they were not to go back to Herod; so they went into their country by another way.", "geneva": "And after they were warned of God in a dreame, that they should not go againe to Herod, they returned into their countrey another way.", "wycliffe": "And whanne thei hadden take an aunswere in sleep, that thei schulden not turne ayen to Eroude, thei turneden ayen bi anothir weie in to her cuntrey.", "rotherham": "and, being instructed by dream, not to return unto Herod, by another way, retired they unto their own country.", "weymouth": "But being forbidden by God in a dream to return to Herod, they went back to their own country by a different route.", "darby": "And being divinely instructed in a dream not to return to Herod, they departed into their own country another way.", "twenty": "But afterwards, having been warned in a dream not to go back to Herod, they returned to their own country by another road.", "acv": "And divinely warned in a dream not to return to Herod, they departed into their own country by another way.", "anderson": "And having been warned in a dream not to return to Herod, they departed into their own country by another way.", "haweis": "And having received warning in a dream not to go back to Herod, they departed into their own country by another road.", "noyes": "And having been warned by God in a dream not to return to Herod, they went back to their own country another way.", "webster": "And being warned by God in a dream that they should not return to Herod, they departed into their own country another way.", "vulgate": "et responso accepto in somnis ne redirent ad Herodem per aliam viam reversi sunt in regionem suam;"}}, {"v": 13, "ref": "2:13", "o": "Ἀναχωρησάντων δὲ αὐτῶν ἰδοὺ ἄγγελος κυρίου ⸂φαίνεται κατ’ ὄναρ⸃ τῷ Ἰωσὴφ λέγων· Ἐγερθεὶς παράλαβε τὸ παιδίον καὶ τὴν μητέρα αὐτοῦ καὶ φεῦγε εἰς Αἴγυπτον, καὶ ἴσθι ἐκεῖ ἕως ἂν εἴπω σοι· μέλλει γὰρ Ἡρῴδης ζητεῖν τὸ παιδίον τοῦ ἀπολέσαι αὐτό.", "en": {"kjv": "And when they were departed, behold, the angel of the Lord appeareth to Joseph in a dream, saying, Arise, and take the young child and his mother, and flee into Egypt, and be thou there until I bring thee word: for Herod will seek the young child to destroy him.", "web": "Now when they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying, “Arise and take the young child and his mother, and flee into Egypt, and stay there until I tell you, for Herod will seek the young child to destroy him.”", "bsb": "When the Magi had gone, an angel of the Lord appeared to Joseph in a dream. “Get up!” he said. “Take the Child and His mother and flee to Egypt. Stay there until I tell you, for Herod is going to search for the Child to kill Him.”", "asv": "Now when they were departed, behold, an angel of the Lord appeareth to Joseph in a dream, saying, Arise and take the young child and his mother, and flee into Egypt, and be thou there until I tell thee: for Herod will seek the young child to destroy him.", "ylt": "And on their having withdrawn, lo, a messenger of the Lord doth appear in a dream to Joseph, saying, `Having risen, take the child and his mother, and flee to Egypt, and be thou there till I may speak to thee, for Herod is about to seek the child to destroy him.'", "tyndale": "When they were departed: beholde the angell of the Lorde appered to Ioseph in dreame sayinge: aryse, and take the chylde and his mother, and flye into Egypte, and abyde there tyll I brynge the worde. For Herod will seke the chylde to destroye hym.", "dra": "And after they were departed, behold an angel of the Lord appeared in sleep to Joseph, saying: Arise, and take the child and his mother, and fly into Egypt: and be there until I shall tell thee. For it will come to pass that Herod will seek the child to destroy him.", "bbe": "And when they had gone, an angel of the Lord came to Joseph in a dream, saying, Get up and take the young child and his mother, and go into Egypt, and do not go from there till I give you word; for Herod will be searching for the young child to put him to death.", "geneva": "After their departure, behold, the Angel of the Lord appeareth to Ioseph in a dreame, saying, Arise, and take the babe and his mother, and flee into Egypt, and be there til I bring thee word: for Herod will seeke the babe, to destroy him.", "wycliffe": "And whanne thei weren goon, lo! the aungel of the Lord apperide to Joseph in sleep, and seide, Rise vp, and take the child and his modir, and fle in to Egipt, and be thou there, til that I seie to thee; for it is to come, that Eroude seke the child, to destrie hym.", "rotherham": "Now, when they had retired, lo! a messenger of the Lord, appeareth by dream unto Joseph, saying, Arise, take unto thee the child and its mother, and flee into Egypt, and be there, until I tell thee,—for Herod is about to seek the child, to destroy it.", "weymouth": "When they were gone, and angel of the Lord appeared to Joseph in a dream and said, \"Rise: take the babe and His mother and escape to Egypt, and remain there till I bring you word. For Herod is about to make search for the child in order to destroy Him.\"", "darby": "Now, they having departed, behold, an angel of [the] Lord appears in a dream to Joseph, saying, Arise, take to [thee] the little child and his mother, and flee into Egypt, and be there until I shall tell thee; for Herod will seek the little child to destroy it.", "twenty": "After they had left, an angel of the Lord appeared to Joseph in a dream, and said: “Awake, take the child and his mother, and seek refuge in Egypt; and stay there until I bid you return, for Herod is about to search for the child, to put him to death.”", "acv": "Now after they departed, behold, an agent of the Lord appears to Joseph in a dream, saying, After rising, take the child and his mother, and flee into Egypt, and thou be there until I tell thee, for Herod is going to seek the child to destroy it.", "anderson": "When they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying: Arise, and take the young child and his mother, and flee into Egypt, and be there till I bring you word; for Herod is about to seek for the young child, to destroy him.", "haweis": "Now when they were gone, behold an angel of the Lord appeared unto Joseph in a dream, saying, Arise, and take the infant and his mother by night, and flee into Egypt, and stay there, till I speak to thee, for Herod will search for the infant to destroy it.", "noyes": "And when they had gone, lo! an angel of the Lord appeareth to Joseph in a dream, saying, Arise, and take the child and his mother, and flee into Egypt, and remain there until I speak to thee; for Herod will seek the child, to destroy him.", "webster": "And when they had departed, behold, the angel of the Lord appeareth to Joseph in a dream, saying, Arise, and take the young child and his mother, and flee into Egypt, and be thou there until I bring thee word: for Herod will seek the young child to destroy him.", "vulgate": "qui cum recessissent ecce angelus Domini apparuit in somnis Ioseph dicens surge et accipe puerum et matrem eius et fuge in Aegyptum et esto ibi usque dum dicam tibi futurum est enim ut Herodes quaerat puerum ad perdendum eum;"}}, {"v": 14, "ref": "2:14", "o": "ὁ δὲ ἐγερθεὶς παρέλαβε τὸ παιδίον καὶ τὴν μητέρα αὐτοῦ νυκτὸς καὶ ἀνεχώρησεν εἰς Αἴγυπτον,", "en": {"kjv": "When he arose, he took the young child and his mother by night, and departed into Egypt:", "web": "He arose and took the young child and his mother by night, and departed into Egypt,", "bsb": "So he got up, took the Child and His mother by night, and withdrew to Egypt,", "asv": "And he arose and took the young child and his mother by night, and departed into Egypt;", "ylt": "And he, having risen, took the child and his mother by night, and withdrew to Egypt,", "tyndale": "Then he arose, and toke the chylde and his mother by night, and departed into Egypte,", "dra": "Who arose, and took the child and his mother by night, and retired into Egypt: and he was there until the death of Herod:", "bbe": "So he took the young child and his mother by night, and went into Egypt;", "geneva": "So he arose and tooke the babe and his mother by night, and departed into Egypt,", "wycliffe": "And Joseph roos, and took the child and his modir bi nyyt, and wente in to Egipt,", "rotherham": "And, he, arising, took unto him the child and its mother, by night, and retired into Egypt;", "weymouth": "So Joseph roused himself and took the babe and His mother by night and departed into Egypt.", "darby": "And, having arisen, he took to [him] the little child and his mother by night, and departed into Egypt.", "twenty": "Joseph awoke, and taking the child and his mother by night, went into Egypt,", "acv": "And having awakened, he took the child and his mother by night, and departed into Egypt.", "anderson": "And he arose and took the young child and his mother by night, and departed into Egypt,", "haweis": "So rising up, he took the babe and his mother by night, and retired into Egypt,", "noyes": "And he arose, and took the child and his mother by night, and went to Egypt;", "webster": "When he arose, he took the young child and his mother by night, and departed into Egypt:", "vulgate": "qui consurgens accepit puerum et matrem eius nocte et recessit in Aegyptum;"}}, {"v": 15, "ref": "2:15", "o": "καὶ ἦν ἐκεῖ ἕως τῆς τελευτῆς Ἡρῴδου· ἵνα πληρωθῇ τὸ ῥηθὲν ⸀ὑπὸ κυρίου διὰ τοῦ προφήτου λέγοντος· Ἐξ Αἰγύπτου ἐκάλεσα τὸν υἱόν μου.", "en": {"kjv": "And was there until the death of Herod: that it might be fulfilled which was spoken of the Lord by the prophet, saying, Out of Egypt have I called my son.", "web": "and was there until the death of Herod; that it might be fulfilled which was spoken by the Lord through the prophet, saying, “Out of Egypt I called my son.”", "bsb": "where he stayed until the death of Herod. This fulfilled what the Lord had spoken through the prophet: “Out of Egypt I called My Son.”", "asv": "and was there until the death of Herod: that it might be fulfilled which was spoken by the Lord through the prophet, saying, Out of Egypt did I call my son.", "ylt": "and he was there till the death of Herod, that it might be fulfilled that was spoken by the Lord through the prophet, saying, `Out of Egypt I did call My Son.'", "tyndale": "and was there vnto ye deeth of Herod, to fulfill that which was spoken of the Lorde, by ye Prophet which sayeth, out of Egypte haue I called my sonne.", "dra": "That it might be fulfilled which the Lord spoke by the prophet, saying: Out of Egypt have I called my son.", "bbe": "And was there till the death of Herod; so that the word of the Lord through the prophet might come true, Out of Egypt have I sent for my son.", "geneva": "And was there vnto the death of Herod, that that might be fulfilled, which is spoken of the Lord by the Prophet, saying, Out of Egypt haue I called my sonne.", "wycliffe": "and he was there to the deeth of Eroude; that it schulde be fulfillid, that was seid of the Lord bi the profete, seiynge, Fro Egipt Y haue clepid my sone.", "rotherham": "and was there, until the death of Herod,—that it might be fulfilled which was spoken by the Lord through the prophet, saying, Out of Egypt, called I my son.", "weymouth": "There he remained till Herod's death, that what the Lord had said through the Prophet might be fulfilled, \"Out of Egypt I called My Son.\"", "darby": "And he was there until the death of Herod, that that might be fulfilled which was spoken by [the] Lord through the prophet, saying, Out of Egypt have I called my son.", "twenty": "and there he stayed until Herod’s death; in fulfilment of these words of the Lord in the Prophet, where he says — ‘Out of Egypt I called my Son.’", "acv": "And he was there until the end of Herod, so that what was spoken by the Lord through the prophet might be fulfilled, which says, Out of Egypt I called my Son.", "anderson": "and was there till the death of Herod; that the word might be fulfilled which was spoken by the Lord through his prophet, saying: Out of Egypt have I called my Son.", "haweis": "and was there till the death of Herod; that what was spoken of the Lord by the prophet, might be fulfilled, saying, “Out of Egypt have I called my son.”", "noyes": "and was there until the death of Herod; that it might be fulfilled which was spoken by the Lord through the prophet, saying, \"I called my son out of Egypt.\"", "webster": "And was there until the death of Herod: that it might be fulfilled which was spoken from the Lord by the prophet, saying, Out of Egypt have I called my son.", "vulgate": "et erat ibi usque ad obitum Herodis ut adimpleretur quod dictum est a Domino per prophetam dicentem ex Aegypto vocavi filium meum;"}}, {"v": 16, "ref": "2:16", "o": "Τότε Ἡρῴδης ἰδὼν ὅτι ἐνεπαίχθη ὑπὸ τῶν μάγων ἐθυμώθη λίαν, καὶ ἀποστείλας ἀνεῖλεν πάντας τοὺς παῖδας τοὺς ἐν Βηθλέεμ καὶ ἐν πᾶσι τοῖς ὁρίοις αὐτῆς ἀπὸ διετοῦς καὶ κατωτέρω, κατὰ τὸν χρόνον ὃν ἠκρίβωσεν παρὰ τῶν μάγων.", "en": {"kjv": "Then Herod, when he saw that he was mocked of the wise men, was exceeding wroth, and sent forth, and slew all the children that were in Bethlehem, and in all the coasts thereof, from two years old and under, according to the time which he had diligently enquired of the wise men.", "web": "Then Herod, when he saw that he was mocked by the wise men, was exceedingly angry, and sent out, and killed all the male children who were in Bethlehem and in all the surrounding countryside, from two years old and under, according to the exact time which he had learned from the wise men.", "bsb": "When Herod saw that he had been outwitted by the Magi, he was filled with rage. Sending orders, he put to death all the boys in Bethlehem and its vicinity who were two years old and under, according to the time he had learned from the Magi.", "asv": "Then Herod, when he saw that he was mocked of the Wise-men, was exceeding wroth, and sent forth, and slew all the male children that were in Bethlehem, and in all the borders thereof, from two years old and under, according to the time which he had exactly learned of the Wise-men.", "ylt": "Then Herod, having seen that he was deceived by the mages, was very wroth, and having sent forth, he slew all the male children in Beth-Lehem, and in all its borders, from two years and under, according to the time that he inquired exactly from the mages.", "tyndale": "Then Herod perceavynge yt he was moocked of the wyse men, was excedynge wroth, and sent forth and slue all the chyldren that were in Bethleem, and in all the costes there of, as many as were two yere olde and vnder, accordynge to the tyme which he had diligently searched oute of the wyse men.", "dra": "Then Herod perceiving that he was deluded by the wise men, was exceeding angry: and sending killed all the menchildren that were in Bethlehem, and in all the borders thereof, from two years old and under, according to the time which he had diligently inquired of the wise men.", "bbe": "Then Herod, when he saw that he had been tricked by the wise men, was very angry; and he sent out, and put to death all the male children in Beth-lehem and in all the parts round about it, from two years old and under, acting on the knowledge which he had got with care from the wise men.", "geneva": "Then Herod, seeing that he was mocked of the Wisemen, was exceeding wroth, and sent foorth, and slew all the male children that were in Beth-leem, and in all the coasts thereof, from two yeere old and vnder, according to the time which he had diligently searched out of the Wisemen.", "wycliffe": "Thanne Eroude seynge that he was disseyued of the astromyens, was ful wrooth; and he sente, and slowe alle the children, that weren in Bethleem, and in alle the coostis therof, fro two yeer age and with inne, aftir the tyme that he had enquerid of the astromyens.", "rotherham": "Then Herod, seeing that he had been mocked by the wise men, was exceedingly enraged,—and sent and slew all the male children that were in Bethlehem, and in all its bounds, from two years old and under, according to the time which he had ascertained from the wise men.", "weymouth": "Then Herod, finding that the Magi had trifled with him, was furious, and sent and massacred all the boys under two years of age, in Bethlehem and all its neighbourhood, according to the date he had so carefully ascertained from the Magi.", "darby": "Then Herod, seeing that he had been mocked by the magi, was greatly enraged; and sent and slew all the boys which [were] in Bethlehem, and in all its borders, from two years and under, according to the time which he had accurately inquired from the magi.", "twenty": "When Herod found that he had been trifled with by the Astrologers, he was very angry. He sent and put to death all the boys in Bethlehem and the whole of that neighbourhood, who were two years old or under, guided by the date which he had ascertained from the Astrologers.", "acv": "Then Herod, when he saw that he was scorned by the wise men, was exceedingly angry, and having sent forth, he killed all the boys in Bethlehem, and in all the borders of it, from two years old and under, according to the time that he had ascertained from the wise men.", "anderson": "Then Herod, when he saw that he was deceived by the Magi, was greatly enraged, and sent out and slew all the male children that were in Bethlehem and in all its borders, from the age of two years and under, according to the time which he had strictly inquired of the Magi.", "haweis": "Then Herod, perceiving that he was treated delusively by the Magians, was greatly exasperated, and he sent and slew all the male infants, that were in Bethlehem, and in all its territories, from their entering their second year and all under it, according to the time, which he had accurately enquired from the Magians.", "noyes": "Then Herod, when he saw that he had been deceived by the magians, was greatly enraged; and sent forth, and slew all the male children that were in Bethlehem, and in all its borders, from two years old and under, according to the time which he had ascertained from the magians.", "webster": "Then Herod, when he saw that he was mocked by the wise men, was exceeding wroth, and sent forth, and slew all the children that were in Bethlehem, and in all its borders, from two years old and under, according to the time which he had diligently inquired of the wise men.", "vulgate": "tunc Herodes videns quoniam inlusus esset a magis iratus est valde et mittens occidit omnes pueros qui erant in Bethleem et in omnibus finibus eius a bimatu et infra secundum tempus quod exquisierat a magis;"}}, {"v": 17, "ref": "2:17", "o": "τότε ἐπληρώθη τὸ ῥηθὲν ⸀διὰ Ἰερεμίου τοῦ προφήτου λέγοντος·", "en": {"kjv": "Then was fulfilled that which was spoken by Jeremy the prophet, saying,", "web": "Then that which was spoken by Jeremiah the prophet was fulfilled, saying,", "bsb": "Then what was spoken through the prophet Jeremiah was fulfilled:", "asv": "Then was fulfilled that which was spoken through Jeremiah the prophet, saying,", "ylt": "Then was fulfilled that which was spoken by Jeremiah the prophet, saying,", "tyndale": "Then was fulfilled yt which was spoken by the Prophet Ieremy sayinge:", "dra": "Then was fulfilled that which was spoken by Jeremias the prophet, saying:", "bbe": "Then the word of Jeremiah the prophet came true,", "geneva": "Then was that fulfilled which is spoken by the Prophet Ieremias, saying,", "wycliffe": "Thanne `it was fulfillid, that was seid bi Jeremye, the profete,", "rotherham": "Then was fulfilled, that which was spoken through Jeremiah the prophet, saying:", "weymouth": "Then were these words, spoken by the Prophet Jeremiah, fulfilled,", "darby": "Then was fulfilled that which was spoken through Jeremias the prophet, saying,", "twenty": "Then were fulfilled these words spoken in the Prophet Jeremiah, where he says —", "acv": "Then that which was spoken through Jeremiah the prophet was fulfilled, which says,", "anderson": "Then was fulfilled that which was spoken by Jeremiah the prophet, saying:", "haweis": "Then was fulfilled what was spoken by Jeremiah the prophet, saying,", "noyes": "Then was fulfilled that which was spoken through Jeremiah the prophet, saying,", "webster": "Then was fulfilled that which was spoken by Jeremiah the prophet, saying,", "vulgate": "tunc adimpletum est quod dictum est per Hieremiam prophetam dicentem;"}}, {"v": 18, "ref": "2:18", "o": "Φωνὴ ἐν Ῥαμὰ ⸀ἠκούσθη, κλαυθμὸς καὶ ὀδυρμὸς πολύς· Ῥαχὴλ κλαίουσα τὰ τέκνα αὐτῆς, καὶ οὐκ ἤθελεν παρακληθῆναι ὅτι οὐκ εἰσίν.", "en": {"kjv": "In Rama was there a voice heard, lamentation, and weeping, and great mourning, Rachel weeping for her children, and would not be comforted, because they are not.", "web": "“A voice was heard in Ramah, lamentation, weeping and great mourning, Rachel weeping for her children; she wouldn’t be comforted, because they are no more.”", "bsb": "“A voice is heard in Ramah, weeping and great mourning, Rachel weeping for her children, and refusing to be comforted, because they are no more.”", "asv": "A voice was heard in Ramah, Weeping and great mourning, Rachel weeping for her children; And she would not be comforted, because they are not.", "ylt": "`A voice in Ramah was heard--lamentation and weeping and much mourning--Rachel weeping for her children, and she would not be comforted because they are not.'", "tyndale": "On the hilles was a voyce herde, mornynge, wepynge, and greate lamentacion: Rachel wepynge for her chyldren, and wolde not be conforted, because they were not. ⹐", "dra": "A voice in Rama was heard, lamentation and great mourning; Rachel bewailing her children, and would not be comforted, because they are not.", "bbe": "In Ramah there was a sound of weeping and great sorrow, Rachel weeping for her children, and she would not be comforted for their loss.", "geneva": "In Rhama was a voyce heard, mourning, and weeping, and great howling: Rachel weeping for her children, and would not be comforted, because they were not.", "wycliffe": "seiynge, A vois was herd an hiy, wepynge and moche weilyng, Rachel biwepynge hir sones, and she wolde not be coumfortid, for thei ben noyt.", "rotherham": "A voice, in Ramah, was heard, weeping and great mourning,—Rachel weeping for her children, and would not be comforted,—because they are not.", "weymouth": "\"A voice was heard in Ramah, wailing and bitter lamentation: It was Rachel bewailing her children, and she refused to be comforted because there were no more.\"", "darby": "A voice has been heard in Rama, weeping, and great lamentation: Rachel weeping [for] her children, and would not be comforted, because they are not.", "twenty": "‘A voice was heard in Ramah, weeping and much lamentation; Rachel, weeping for her children, refused all comfort because they were not.’", "acv": "A voice was heard in Ramah, lamentation, and weeping, and great mourning, Rachel weeping for her children. And she did not want to be comforted, because they are not.", "anderson": "A voice was heard in Ramah, wailing and weeping, and great mourning; Rachel weeping for her children, and refusing to be comforted because they are no more.", "haweis": "“A cry was heard at Ramah, lamentation, and wailing, and bitter moaning, Rachel weeping for her children, and will not be comforted, because they are no more.”", "noyes": "\"A voice was heard in Ramah, weeping, and great mourning; Rachel weeping for her children, and refusing to be comforted, because they were no more.\"", "webster": "In Rama was there a voice heard, lamentation, and weeping, and great mourning, Rachel weeping [for] her children, and would not be comforted, because they are not.", "vulgate": "vox in Rama audita est ploratus et ululatus multus Rachel plorans filios suos et noluit consolari quia non sunt;"}}, {"v": 19, "ref": "2:19", "o": "Τελευτήσαντος δὲ τοῦ Ἡρῴδου ἰδοὺ ἄγγελος κυρίου ⸂φαίνεται κατ’ ὄναρ⸃ τῷ Ἰωσὴφ ἐν Αἰγύπτῳ", "en": {"kjv": "But when Herod was dead, behold, an angel of the Lord appeareth in a dream to Joseph in Egypt,", "web": "But when Herod was dead, behold, an angel of the Lord appeared in a dream to Joseph in Egypt, saying,", "bsb": "After Herod died, an angel of the Lord appeared in a dream to Joseph in Egypt.", "asv": "But when Herod was dead, behold, an angel of the Lord appeareth in a dream to Joseph in Egypt, saying,", "ylt": "And Herod having died, lo, a messenger of the Lord in a dream doth appear to Joseph in Egypt,", "tyndale": "✠ When Herode was deed: beholde, an angell of ye Lorde appered in a dreame to Ioseph in Egypte", "dra": "But when Herod was dead, behold an angel of the Lord appeared in sleep to Joseph in Egypt,", "bbe": "But when Herod was dead, an angel of the Lord came in a dream to Joseph in Egypt,", "geneva": "And whe Herod was dead, behold, an Angel of the Lord appeareth in a dreame to Ioseph in Egypt,", "wycliffe": "But whanne Eroude was deed, loo! the aungel of the Lord apperide to Joseph in sleep in Egipt,", "rotherham": "But, when Herod was, dead, lo! a messenger of the Lord, appeareth by dream unto Joseph in Egypt;", "weymouth": "But after Herod's death an angel of the Lord appeared in a dream to Joseph in Egypt, and said to him,", "darby": "But Herod having died, behold, an angel of [the] Lord appears in a dream to Joseph in Egypt, saying,", "twenty": "But, on the death of Herod, an angel of the Lord appeared in a dream to Joseph in Egypt, and said:", "acv": "But when Herod perished, behold, an agent of the Lord appears in a dream to Joseph in Egypt, saying,", "anderson": "But when Herod was dead, behold, an angel of the Lord appeared in a dream to Joseph in Egypt,", "haweis": "Now when Herod was dead, behold, the angel of the Lord appeared in a dream to Joseph in Egypt,", "noyes": "But when Herod was dead, lo! an angel of the Lord appeareth in a dream to Joseph in Egypt,", "webster": "But when Herod was dead, behold, an angel of the Lord appeareth in a dream to Joseph in Egypt,", "vulgate": "defuncto autem Herode ecce apparuit angelus Domini in somnis Ioseph in Aegypto;"}}, {"v": 20, "ref": "2:20", "o": "λέγων· Ἐγερθεὶς παράλαβε τὸ παιδίον καὶ τὴν μητέρα αὐτοῦ καὶ πορεύου εἰς γῆν Ἰσραήλ, τεθνήκασιν γὰρ οἱ ζητοῦντες τὴν ψυχὴν τοῦ παιδίου.", "en": {"kjv": "Saying, Arise, and take the young child and his mother, and go into the land of Israel: for they are dead which sought the young child’s life.", "web": "“Arise and take the young child and his mother, and go into the land of Israel, for those who sought the young child’s life are dead.”", "bsb": "“Get up!” he said. “Take the Child and His mother and go to the land of Israel, for those seeking the Child’s life are now dead.”", "asv": "Arise and take the young child and his mother, and go into the land of Israel: for they are dead that sought the young child’s life.", "ylt": "saying, `Having risen, take the child and his mother, and be going to the land of Israel, for they have died--those seeking the life of the child.'", "tyndale": "sayinge: arise and take ye chylde and his mother, and go into ye londe of Israel. For they are deed which sought ye chyldes life.", "dra": "Saying: Arise, and take the child and his mother, and go into the land of Israel. For they are dead that sought the life of the child.", "bbe": "Saying, Get up and take the young child and his mother, and go into the land of Israel: because they who were attempting to take the young child's life are dead.", "geneva": "Saying, Arise, and take the babe and his mother, and goe into the land of Israel: for they are dead which sought the babes life.", "wycliffe": "and seide, Ryse vp, and take the child and his modir, and go in to the lond of Israel; for thei that souyten the lijf of the chijld ben deed.", "rotherham": "saying—Arise! and take unto thee the child and its mother, and be journeying into the land of Israel,—for they are dead, who were seeking the life of the child.", "weymouth": "\"Rise from sleep, and take the child and His mother, and go into the land of Israel, for those who were seeking the child's life are dead.\"", "darby": "Arise, take to [thee] the little child and its mother, and go into the land of Israel: for they who sought the life of the little child are dead.", "twenty": "“Awake, take the child and his mother, and go into the Land of Israel, for those who sought to take the child’s life are dead.”", "acv": "After rising, take the child and his mother, and go into the land of Israel, for those seeking the child's life have died.", "anderson": "saying: Arise and take the young child and his mother, and go into the land of Israel; for they are dead who sought the young child’s life.", "haweis": "saying, Arise, and take the little boy and his mother, and go into the land of Israel: for they who sought the life of the infant are dead.", "noyes": "saying, Arise, and take the child and his mother, and go to the land of Israel; for they who sought the child’s life are dead.", "webster": "Saying, Arise, and take the young child and his mother, and go into the land of Israel: for they are dead who sought the young child's life.", "vulgate": "dicens surge et accipe puerum et matrem eius et vade in terram Israhel defuncti sunt enim qui quaerebant animam pueri;"}}, {"v": 21, "ref": "2:21", "o": "ὁ δὲ ἐγερθεὶς παρέλαβε τὸ παιδίον καὶ τὴν μητέρα αὐτοῦ καὶ ⸀εἰσῆλθεν εἰς γῆν Ἰσραήλ.", "en": {"kjv": "And he arose, and took the young child and his mother, and came into the land of Israel.", "web": "He arose and took the young child and his mother, and came into the land of Israel.", "bsb": "So Joseph got up, took the Child and His mother, and went to the land of Israel.", "asv": "And he arose and took the young child and his mother, and came into the land of Israel.", "ylt": "And he, having risen, took the child and his mother, and came to the land of Israel,", "tyndale": "Then he arose vp, and toke ye chylde and his mother, and cam into the londe of Israhel.", "dra": "Who arose, and took the child and his mother, and came into the land of Israel.", "bbe": "And he got up, and took the young child and his mother, and came into the land of Israel.", "geneva": "Then he arose vp and tooke the babe and his mother, and came into the land of Israel.", "wycliffe": "Joseph roos, and took the child and his modir, and cam in to the loond of Israel.", "rotherham": "And, he, arising, took unto him the child and its mother, and entered into the land of Israel.", "weymouth": "So he roused himself and took the child and His mother and came into the land of Israel.", "darby": "And he arose and took to [him] the little child and its mother, and came into the land of Israel;", "twenty": "And he awoke, and taking the child and his mother, went into the Land of Israel.", "acv": "And having awaken, he took the child and his mother, and came into the land of Israel.", "anderson": "And he arose and took the young child and his mother, and came into the land of Israel.", "haweis": "So he arose, and took the child and his mother, and came unto the land of Israel.", "noyes": "And he arose, and took the child and his mother, and came into the land of Israel.", "webster": "And he arose, and took the young child and his mother, and came into the land of Israel.", "vulgate": "qui surgens accepit puerum et matrem eius et venit in terram Israhel;"}}, {"v": 22, "ref": "2:22", "o": "ἀκούσας δὲ ὅτι Ἀρχέλαος ⸀βασιλεύει τῆς Ἰουδαίας ἀντὶ ⸂τοῦ πατρὸς αὐτοῦ Ἡρῴδου⸃ ἐφοβήθη ἐκεῖ ἀπελθεῖν· χρηματισθεὶς δὲ κατ’ ὄναρ ἀνεχώρησεν εἰς τὰ μέρη τῆς Γαλιλαίας,", "en": {"kjv": "But when he heard that Archelaus did reign in Judea in the room of his father Herod, he was afraid to go thither: notwithstanding, being warned of God in a dream, he turned aside into the parts of Galilee:", "web": "But when he heard that Archelaus was reigning over Judea in the place of his father, Herod, he was afraid to go there. Being warned in a dream, he withdrew into the region of Galilee,", "bsb": "But when he learned that Archelaus was reigning in Judea in place of his father Herod, he was afraid to go there. And having been warned in a dream, he withdrew to the district of Galilee,", "asv": "But when he heard that Archelaus was reigning over Judæa in the room of his father Herod, he was afraid to go thither; and being warned of God in a dream, he withdrew into the parts of Galilee,", "ylt": "and having heard that Archelaus doth reign over Judea instead of Herod his father, he was afraid to go thither, and having been divinely warned in a dream, he withdrew to the parts of Galilee,", "tyndale": "But when he hearde yt Archelaus did raygne in Iury, in ye roume of his father Herode, he was afrayde to goo thither. Not withstondynge after he was warned of god in a dreame, he turned a syde into ye parties of Galile,", "dra": "But hearing that Archclaus reigned in Judea in the room of Herod his father, he was afraid to go thither: and being warned in sleep retired into the quarters of Galilee.", "bbe": "But when it came to his ears that Archelaus was ruling over Judaea in the place of his father Herod, he was in fear of going there; and God having given him news of the danger in a dream, he went out of the way into the country parts of Galilee.", "geneva": "But whe he heard that Archelaus did reigne in Iudea in stead of his father Herod, he was afraide to go thither: yet after he was warned of God in a dreame, he turned aside into the parts of Galile,", "wycliffe": "And he herde that Archilaus regnede in Judee for Eroude, his fadir, and dredde to go thidir. And he was warned in sleep, and wente in to the parties of Galilee;", "rotherham": "Hearing, however, that, Archelaus, was reigning over Judaea instead of his father Herod, he was afraid, thither, to go,—and so, being instructed by dream, he retired into the parts of Galilee;", "weymouth": "But hearing that Archelaus had succeeded his father Herod on the throne of Judaea, he was afraid to go there; and being instructed by God in a dream he withdrew into Galilee,", "darby": "but having heard that 'Archelaus reigns over Judaea, instead of Herod his father,' he was afraid to go there; and having been divinely instructed in a dream, he went away into the parts of Galilee,", "twenty": "But, hearing that Archelaus had succeeded his father Herod as King of Judea, he was afraid to go back there; and having been warned in a dream, he went into the part of the country called Galilee.", "acv": "But when he heard that Archelaus was reigning over Judea in place of his father Herod, he was afraid to go there. And divinely warned in a dream, he withdrew into the parts of Galilee.", "anderson": "But when he heard that Archelaus was reigning in Judea in place of Herod his father, he was afraid to go thither. But being warned in a dream, he withdrew into the regions of Galilee,", "haweis": "But hearing that Archelaus reigned in Judea in the stead of Herod his father, he was afraid to go thither. And being divinely warned in a dream, he retired into the country of Galilee,", "noyes": "But when he heard that Archelaus was reigning in Judaea in the place of his father Herod, he was afraid to go thither; and being warned by God in a dream, he withdrew into the parts of Galilee,", "webster": "But when he heard that Archelaus reigned in Judea in the room of his father Herod, he was afraid to go thither: notwithstanding, being warned by God in a dream, he turned aside into the parts of Galilee:", "vulgate": "audiens autem quod Archelaus regnaret in Iudaea pro Herode patre suo timuit illo ire et admonitus in somnis secessit in partes Galilaeae;"}}, {"v": 23, "ref": "2:23", "o": "καὶ ἐλθὼν κατῴκησεν εἰς πόλιν λεγομένην Ναζαρέτ, ὅπως πληρωθῇ τὸ ῥηθὲν διὰ τῶν προφητῶν ὅτι Ναζωραῖος κληθήσεται.", "en": {"kjv": "And he came and dwelt in a city called Nazareth: that it might be fulfilled which was spoken by the prophets, He shall be called a Nazarene.", "web": "and came and lived in a city called Nazareth; that it might be fulfilled which was spoken through the prophets: “He will be called a Nazarene.”", "bsb": "and he went and lived in a town called Nazareth. So was fulfilled what was spoken through the prophets: “He will be called a Nazarene.”", "asv": "and came and dwelt in a city called Nazareth; that it might be fulfilled which was spoken through the prophets, that he should be called a Nazarene.", "ylt": "and coming, he dwelt in a city named Nazareth, that it might be fulfilled that was spoken through the prophets, that `A Nazarene he shall be called.'", "tyndale": "and went and dwelt in a cite called Nazareth, to fulfill yt which was spoken by ye Prophetes: he shalbe called a Nazarite ⹐", "dra": "And coming he dwelt in a city called Nazareth: that it might be fulfilled which was said by the prophets: That he shall be called a Nazarene.", "bbe": "And he came and was living in a town named Nazareth: so that the word of the prophets might come true, He will be named a Nazarene.", "geneva": "And went and dwelt in a citie called Nazareth, that it might be fulfilled which was spoken by the Prophets, which was, That hee should be called a Nazarite.", "wycliffe": "and cam, and dwelte in a citee, that ys clepid Nazareth, that it shulde be fulfillid, that was seid bi profetis, For he shal be clepid a Nazarey.", "rotherham": "and came and fixed his dwelling in a city called Nazareth,—that it might be fulfilled which was spoken through the prophets—A Nazarene, shall he be called.", "weymouth": "and went and settled in a town called Nazareth, in order that these words spoken through the Prophets might be fulfilled, \"He shall be called a Nazarene.\"", "darby": "and came and dwelt in a town called Nazareth; so that that should be fulfilled which was spoken through the prophets, He shall be called a Nazaraene.", "twenty": "And there he settled in the town of Nazareth, in fulfilment of these words in the Prophets — ‘He will be called a Nazarene.’", "acv": "And having come, he dwelt in a city called Nazareth, so that what was spoken through the prophets might be fulfilled, that he will be called a Nazarene.", "anderson": "and came and dwelt in a city called Nazareth, that the word might be fulfilled which was spoken by the prophets: He shall be called a Nazarene.", "haweis": "and came and dwelt in a city called Nazareth: that what was said by the prophets might be fulfilled, that he shall be called a Nazarean.", "noyes": "and came and took up his abode in a city called Nazareth; that it might be fulfilled which was spoken through the prophets, \"He will be called a Nazarene,\"", "webster": "And he came and dwelt in a city called Nazareth: that it might be fulfilled which was spoken by the prophets, He shall be called a Nazarene.", "vulgate": "et veniens habitavit in civitate quae vocatur Nazareth ut adimpleretur quod dictum est per prophetas quoniam Nazareus vocabitur;"}}]}, {"c": 3, "verses": [{"v": 1, "ref": "3:1", "o": "Ἐν δὲ ταῖς ἡμέραις ἐκείναις παραγίνεται Ἰωάννης ὁ βαπτιστὴς κηρύσσων ἐν τῇ ἐρήμῳ τῆς Ἰουδαίας", "en": {"kjv": "In those days came John the Baptist, preaching in the wilderness of Judea,", "web": "In those days, John the Baptizer came, preaching in the wilderness of Judea, saying,", "bsb": "In those days John the Baptist came, preaching in the wilderness of Judea", "asv": "And in those days cometh John the Baptist, preaching in the wilderness of Judæa, saying,", "ylt": "And in those days cometh John the Baptist, proclaiming in the wilderness of Judea,", "tyndale": "In those dayes Ihon the Baptyst came and preached in the wildernes of Iury", "dra": "And in those days cometh John the Baptist preaching in the desert of Judea.", "bbe": "And in those days John the Baptist came preaching in the waste land of Judaea,", "geneva": "And in those dayes, Iohn the Baptist came and preached in the wildernes of Iudea,", "wycliffe": "In tho daies Joon Baptist cam, and prechide in the desert of Judee,", "rotherham": "Now, in those days, came John the Immerser, proclaiming in the wilderness of Judaea;", "weymouth": "About this time John the Baptist made his appearance, preaching in the Desert of Judaea.", "darby": "Now in those days comes John the baptist, preaching in the wilderness of Judaea,", "twenty": "About that time John the Baptist first appeared, proclaiming in the Wilderness of Judea:", "acv": "And in those days John the immerser comes, preaching in the wilderness of Judea, and saying,", "anderson": "In those days came John the Immerser, preaching in the wilderness of Judea,", "haweis": "THEN in those days came John the Baptist, preaching in the desert country of Judea,", "noyes": "In those days came John the Baptist, preaching in the wilderness of Judaea,", "webster": "In those days came John the Baptist, preaching in the wilderness of Judea,", "vulgate": "in diebus autem illis venit Iohannes Baptista praedicans in deserto Iudaeae;"}}, {"v": 2, "ref": "3:2", "o": "⸀καὶ λέγων· Μετανοεῖτε, ἤγγικεν γὰρ ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "And saying, Repent ye: for the kingdom of heaven is at hand.", "web": "“Repent, for the Kingdom of Heaven is at hand!”", "bsb": "and saying, “Repent, for the kingdom of heaven is near.”", "asv": "Repent ye; for the kingdom of heaven is at hand.", "ylt": "and saying, `Reform, for come nigh hath the reign of the heavens,'", "tyndale": "saynge; Repet the kyngdome of heue is at honde.", "dra": "And saying: Do penance: for the kingdom of heaven is at hand.", "bbe": "Saying, Let your hearts be turned from sin; for the kingdom of heaven is near.", "geneva": "And said, Repent: for the kingdome of heauen is at hand.", "wycliffe": "and seide, Do ye penaunce, for the kyngdom of heuenes shal neiye.", "rotherham": "saying, Repent ye,—for the kingdom of the heavens hath drawn near.", "weymouth": "\"Repent,\" he said, \"for the Kingdom of the Heavens is now close at hand.\"", "darby": "and saying, Repent, for the kingdom of the heavens has drawn nigh.", "twenty": "“Repent, for the Kingdom of Heaven is at hand.”", "acv": "Repent ye, for the kingdom of the heavens has approached.", "anderson": "and saying: Repent, for the kingdom of heaven is at hand.", "haweis": "and saying, Repent, for the kingdom of heaven is nigh.", "noyes": "saying, Repent, for the kingdom of heaven is at hand.", "webster": "And saying, Repent ye: for the kingdom of heaven is at hand.", "vulgate": "et dicens paenitentiam agite adpropinquavit enim regnum caelorum;"}}, {"v": 3, "ref": "3:3", "o": "οὗτος γάρ ἐστιν ὁ ῥηθεὶς ⸀διὰ Ἠσαΐου τοῦ προφήτου λέγοντος· Φωνὴ βοῶντος ἐν τῇ ἐρήμῳ· Ἑτοιμάσατε τὴν ὁδὸν κυρίου, εὐθείας ποιεῖτε τὰς τρίβους αὐτοῦ.", "en": {"kjv": "For this is he that was spoken of by the prophet Esaias, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight.", "web": "For this is he who was spoken of by Isaiah the prophet, saying, “The voice of one crying in the wilderness, make ready the way of the Lord. Make his paths straight.”", "bsb": "This is he who was spoken of through the prophet Isaiah: “A voice of one calling in the wilderness, ‘Prepare the way for the Lord, make straight paths for Him.’”", "asv": "For this is he that was spoken of through Isaiah the prophet, saying, The voice of one crying in the wilderness, Make ye ready the way of the Lord, Make his paths straight.", "ylt": "for this is he who was spoken of by Isaiah the prophet, saying, `A voice of one crying in the wilderness, Prepare ye the way of the Lord, straight make ye His paths.'", "tyndale": "This is he of whom it is spoken by the Prophet Esay which sayeth: The voyce of a cryer in wyldernes prepare the Lordes waye and make hys pathes strayght.", "dra": "For this is he that was spoken of by Isaias the prophet, saying: A voice of one crying in the desert, Prepare ye the way of the Lord, make straight his paths.", "bbe": "For this is he of whom Isaiah the prophet said, The voice of one crying in the waste land, Make ready the way of the Lord, make his roads straight.", "geneva": "For this is he of whome it is spoken by the Prophet Esaias, saying, The voyce of him that crieth in the wildernes, Prepare ye the way of the Lord: make his pathes straight.", "wycliffe": "For this is he, of whom it is seid bi Ysaie, the prophete, seyinge, A vois of a crier in desert, Make ye redi the weies of the Lord; make ye riyt the pathis of hym.", "rotherham": "For, this, is he who was spoken of through Isaiah the prophet, saying, A voice, of one crying aloud! In the wilderness, prepare ye the way of the Lord, straight, be making his paths.", "weymouth": "He it is who was spoken of through the Prophet Isaiah when he said, \"The voice of one crying aloud, `In the desert prepare ye a road for the Lord: make His highway straight.'\"", "darby": "For this is he who has been spoken of through Esaias the prophet, saying, Voice of him that crieth in the wilderness: prepare ye the way of [the] Lord, make straight his paths.", "twenty": "This is he who was spoken of in the Prophet Isaiah, where he says — ‘The voice of one crying aloud in the Wilderness: “Make ready the way of the Lord, make his paths straight.”’", "acv": "For this is he who was spoken of by Isaiah the prophet, saying, The voice of a man crying in the wilderness: Prepare ye the way of the Lord. Make his paths straight.", "anderson": "For this is he that was spoken of by Isaiah the prophet, saying: The voice of one crying in the wilderness, Prepare the way of the Lord, make his paths straight.", "haweis": "For this is the person spoken of by Isaiah the prophet, saying, “The voice of one crying aloud in the wilderness, Prepare the way of the Lord, make his paths strait.”", "noyes": "For this is he that was spoken of through Isaiah the prophet, saying, \"The voice of one crying in the wilderness, Prepare the way of the Lord, make straight his paths!\"", "webster": "For this is he that was spoken of by the prophet Isaiah, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight.", "vulgate": "hic est enim qui dictus est per Esaiam prophetam dicentem vox clamantis in deserto parate viam Domini rectas facite semitas eius;"}}, {"v": 4, "ref": "3:4", "o": "αὐτὸς δὲ ὁ Ἰωάννης εἶχεν τὸ ἔνδυμα αὐτοῦ ἀπὸ τριχῶν καμήλου καὶ ζώνην δερματίνην περὶ τὴν ὀσφὺν αὐτοῦ, ἡ δὲ τροφὴ ⸂ἦν αὐτοῦ⸃ ἀκρίδες καὶ μέλι ἄγριον.", "en": {"kjv": "And the same John had his raiment of camel’s hair, and a leathern girdle about his loins; and his meat was locusts and wild honey.", "web": "Now John himself wore clothing made of camel’s hair, with a leather belt around his waist. His food was locusts and wild honey.", "bsb": "John wore a garment of camel’s hair, with a leather belt around his waist. His food was locusts and wild honey.", "asv": "Now John himself had his raiment of camel’s hair, and a leathern girdle about his loins; and his food was locusts and wild honey.", "ylt": "And this John had his clothing of camel's hair, and a girdle of skin round his loins, and his nourishment was locusts and honey of the field.", "tyndale": "This Iho had hys garmet of camels heer and a gerdell of a skynne aboute his loynes. Hys meate was locustes and wylde hony.", "dra": "And the same John had his garment of camel's hair, and a leathern girdle about his loins: and his meat was locusts and wild honey.", "bbe": "Now John was clothed in camel's hair, with a leather band about him; and his food was locusts and honey.", "geneva": "And this Iohn had his garment of camels heare, and a girdle of a skinne about his loynes: his meate was also locusts and wilde hony.", "wycliffe": "And this Joon hadde clothing of camels heeris, and a girdil of skynne aboute hise leendis; and his mete was honysoukis, and hony of the wode.", "rotherham": "But John, himself, had his raiment of camel’s hair, and a leathern girdle about his loins,—while, his food, was locusts and wild honey.", "weymouth": "This man John wore a garment of camel's hair, and a loincloth of leather; and he lived upon locusts and wild honey.", "darby": "And John himself had his garment of camel's hair, and a leathern girdle about his loins, and his nourishment was locusts and wild honey.", "twenty": "John wore clothing made of camels’ hair, with a belt of leather round his waist, and his food was locusts and wild honey.", "acv": "Now John himself had his raiment of camel's hair, and a leather belt about his waist. And his food was locusts and wild honey.", "anderson": "But the same John had his clothing of camel’s hair, and a girdle of leather around his loins, and his food was locusts and wild honey.", "haweis": "Now this John had his garment made of camel’s hair, and a girdle of leather about his loins, and his food was locusts and wild honey.", "noyes": "And John himself had his raiment of camel’s hair, and a leathern girdle about his loins; and his food was locusts and wild honey.", "webster": "And the same John had his raiment of camel's hair, and a leathern girdle about his loins; and his food was locusts and wild honey.", "vulgate": "ipse autem Iohannes habebat vestimentum de pilis camelorum et zonam pelliciam circa lumbos suos esca autem eius erat lucustae et mel silvestre;"}}, {"v": 5, "ref": "3:5", "o": "τότε ἐξεπορεύετο πρὸς αὐτὸν Ἱεροσόλυμα καὶ πᾶσα ἡ Ἰουδαία καὶ πᾶσα ἡ περίχωρος τοῦ Ἰορδάνου,", "en": {"kjv": "Then went out to him Jerusalem, and all Judea, and all the region round about Jordan,", "web": "Then people from Jerusalem, all of Judea, and all the region around the Jordan went out to him.", "bsb": "People went out to him from Jerusalem and all Judea and the whole region around the Jordan.", "asv": "Then went out unto him Jerusalem, and all Judæa, and all the region round about the Jordan;", "ylt": "Then were going forth unto him Jerusalem, and all Judea, and all the region round about the Jordan,", "tyndale": "The went oute to hym Ierusalem and all Iury and all ye regio roude aboute Iorda", "dra": "Then went out to him Jerusalem and all Judea, and all the country about Jordan:", "bbe": "Then Jerusalem and all Judaea went out to him, and all the people from near Jordan;", "geneva": "Then went out to him Ierusalem and all Iudea, and all the region rounde about Iordan.", "wycliffe": "Thanne Jerusalem wente out to hym, and al Judee, and al the cuntre aboute Jordan;", "rotherham": "Then, were going forth unto him—Jerusalem, and all Judaea, and all the country round about the Jordan:", "weymouth": "Then large numbers of people went out to him--people from Jerusalem and from all Judaea, and from the whole of the Jordan valley--", "darby": "Then went out to him Jerusalem, and all Judaea, and all the country round the Jordan,", "twenty": "At that time Jerusalem, and all Judea, as well as the whole district of the Jordan, went out to him", "acv": "Then Jerusalem, and all Judea, and all the region of the Jordan went out to him,", "anderson": "Then went out to him Jerusalem, and all Judea, and all the region round about the Jordan,", "haweis": "Then went out to him Jerusalem and all Judea, and all the regions about Jordan,", "noyes": "Then went out to him Jerusalem, and all Judaea, and all the country about the Jordan;", "webster": "Then went out to him Jerusalem, and all Judea, and all the region about Jordan,", "vulgate": "tunc exiebat ad eum Hierosolyma et omnis Iudaea et omnis regio circa Iordanen;"}}, {"v": 6, "ref": "3:6", "o": "καὶ ἐβαπτίζοντο ἐν τῷ Ἰορδάνῃ ⸀ποταμῷ ὑπ’ αὐτοῦ ἐξομολογούμενοι τὰς ἁμαρτίας αὐτῶν.", "en": {"kjv": "And were baptized of him in Jordan, confessing their sins.", "web": "They were baptized by him in the Jordan, confessing their sins.", "bsb": "Confessing their sins, they were baptized by him in the Jordan River.", "asv": "and they were baptized of him in the river Jordan, confessing their sins.", "ylt": "and they were baptized in the Jordan by him, confessing their sins.", "tyndale": "and were baptised of him in Iorda cofessynge their synnes.", "dra": "And were baptized by him in the Jordan, confessing their sins.", "bbe": "And they were given baptism by him in the river Jordan, saying openly that they had done wrong.", "geneva": "And they were baptized of him in Iordan, confessing their sinnes.", "wycliffe": "and thei weren waischun of hym in Jordan, `and knowlechiden her synnes.", "rotherham": "and were being immersed in the Jordan river, by him, openly confessing their sins.", "weymouth": "and were baptized by him in the Jordan, making full confession of their sins.", "darby": "and were baptised by him in the Jordan, confessing their sins.", "twenty": "and were baptized by him in the river Jordan, confessing their sins.", "acv": "and they were immersed by him in the Jordan, confessing their sins.", "anderson": "and were immersed by him in the Jordan, confessing their sins.", "haweis": "and were baptized by him in Jordan, on making confession of their sins.", "noyes": "and were baptized by him in the river Jordan, confessing their sins.", "webster": "And were baptized by him in Jordan, confessing their sins.", "vulgate": "et baptizabantur in Iordane ab eo confitentes peccata sua;"}}, {"v": 7, "ref": "3:7", "o": "Ἰδὼν δὲ πολλοὺς τῶν Φαρισαίων καὶ Σαδδουκαίων ἐρχομένους ἐπὶ τὸ βάπτισμα ⸀αὐτοῦ εἶπεν αὐτοῖς· Γεννήματα ἐχιδνῶν, τίς ὑπέδειξεν ὑμῖν φυγεῖν ἀπὸ τῆς μελλούσης ὀργῆς;", "en": {"kjv": "But when he saw many of the Pharisees and Sadducees come to his baptism, he said unto them, O generation of vipers, who hath warned you to flee from the wrath to come?", "web": "But when he saw many of the Pharisees and Sadducees coming for his baptism, he said to them, “You offspring of vipers, who warned you to flee from the wrath to come?", "bsb": "But when John saw many of the Pharisees and Sadducees coming to his place of baptism, he said to them, “You brood of vipers, who warned you to flee from the coming wrath?", "asv": "But when he saw many of the Pharisees and Sadducees coming to his baptism, he said unto them, Ye offspring of vipers, who warned you to flee from the wrath to come?", "ylt": "And having seen many of the Pharisees and Sadducees coming about his baptism, he said to them, `Brood of vipers! who did shew you to flee from the coming wrath?", "tyndale": "When he sawe many of ye Pharises and of ye Saduces come to hys baptim he sayde vnto the: O generacio of vipers who hath taught you to fle fro the vengeauce to come?", "dra": "And seeing many of the Pharisees and Sadducees coming to his baptism, he said to them: Ye brood of vipers, who hath shewed you to flee from the wrath to come?", "bbe": "But when he saw a number of the Pharisees and Sadducees coming to his baptism, he said to them, Offspring of snakes, at whose word are you going in flight from the wrath to come?", "geneva": "Now when he sawe many of the Pharises, and of the Sadduces come to his baptisme, he said vnto them, O generations of vipers, who hath forewarned you to flee from the anger to come?", "wycliffe": "But he siy manye of the Farysees and of Saduceis comynge to his baptym, and seide to hem, Generaciouns of eddris, who shewide to you to fle fro the wraththe that is to come?", "rotherham": "But, seeing, many of the Pharisees and Sadducees, coming unto his immersion, he said to them,—Broods of vipers! who suggested to you, to be fleeing from the coming wrath?", "weymouth": "But when he saw many of the Pharisees and Sadducees coming for baptism, he exclaimed, \"O vipers' brood, who has warned you to flee from the coming wrath?", "darby": "But seeing many of the Pharisees and Sadducees coming to his baptism, he said to them, Offspring of vipers, who has forewarned you to flee from the coming wrath?", "twenty": "When, however, John saw many of the Pharisees and Sadducees coming to receive his baptism, he said to them: “You brood of vipers! Who has prompted you to seek refuge from the coming judgment?", "acv": "But when he saw many of the Pharisees and Sadducees coming to his immersion, he said to them, Ye offspring of vipers, who showed you to flee from the coming wrath?", "anderson": "But when he saw many of the Pharisees and Sadducees coming to his immersion, he said to them: Generation of vipers, who has warned you to flee from the coining wrath?", "haweis": "But when he saw many of the Pharisees and of the Sadducees coming to his baptism, he said to them, O ye broods of vipers! who hath warned you to flee from the wrath to come?", "noyes": "But seeing many of the Pharisees and Sadducees coming to be baptized, he said to them, Brood of vipers, who warned you to flee from the coming wrath?", "webster": "But when he saw many of the Pharisees and Sadducees come to his baptism, he said to them, O generation of vipers, who hath warned you to flee from the wrath to come?", "vulgate": "videns autem multos Pharisaeorum et Sadducaeorum venientes ad baptismum suum dixit eis progenies viperarum quis demonstravit vobis fugere a futura ira;"}}, {"v": 8, "ref": "3:8", "o": "ποιήσατε οὖν καρπὸν ἄξιον τῆς μετανοίας", "en": {"kjv": "Bring forth therefore fruits meet for repentance:", "web": "Therefore produce fruit worthy of repentance!", "bsb": "Produce fruit, then, in keeping with repentance.", "asv": "Bring forth therefore fruit worthy of repentance:", "ylt": "bear, therefore, fruits worthy of the reformation,", "tyndale": "Brynge forth therfore the frutes belongynge to repentauce.", "dra": "Bring forth therefore fruit worthy of penance.", "bbe": "Let your change of heart be seen in your works:", "geneva": "Bring foorth therefore fruite worthy amendment of life.", "wycliffe": "Therfor do ye worthi fruyte of penaunce,", "rotherham": "Bring forth, therefore, fruit worthy of repentance;", "weymouth": "Therefore let your lives prove your change of heart;", "darby": "Produce therefore fruit worthy of repentance.", "twenty": "Let your life, then, prove your repentance;", "acv": "Therefore produce fruit worthy of repentance.", "anderson": "Bring forth, therefore, fruit worthy of repentance:", "haweis": "Produce then worthy fruits of repentance:", "noyes": "Bring forth therefore fruit worthy of repentance,", "webster": "Bring forth therefore fruits meet for repentance:", "vulgate": "facite ergo fructum dignum paenitentiae;"}}, {"v": 9, "ref": "3:9", "o": "καὶ μὴ δόξητε λέγειν ἐν ἑαυτοῖς· Πατέρα ἔχομεν τὸν Ἀβραάμ, λέγω γὰρ ὑμῖν ὅτι δύναται ὁ θεὸς ἐκ τῶν λίθων τούτων ἐγεῖραι τέκνα τῷ Ἀβραάμ.", "en": {"kjv": "And think not to say within yourselves, We have Abraham to our father: for I say unto you, that God is able of these stones to raise up children unto Abraham.", "web": "Don’t think to yourselves, ‘We have Abraham for our father,’ for I tell you that God is able to raise up children to Abraham from these stones.", "bsb": "And do not presume to say to yourselves, ‘We have Abraham as our father.’ For I tell you that out of these stones God can raise up children for Abraham.", "asv": "and think not to say within yourselves, We have Abraham to our father: for I say unto you, that God is able of these stones to raise up children unto Abraham.", "ylt": "and do not think to say in yourselves, A father we have--Abraham, for I say to you, that God is able out of these stones to raise children to Abraham,", "tyndale": "And se that ye ons thynke not to saye in your selues we haue Abraham to oure father. For I saye vnto you that God is able of these stones to rayse vp chyldern vnto Abraha.", "dra": "And think not to say within yourselves, We have Abraham for our father. For I tell you that God is able of these stones to raise up children to Abraham.", "bbe": "And say not to yourselves, We have Abraham for our father; because I say to you that God is able from these stones to make children for Abraham.", "geneva": "And thinke not to say with your selues, We haue Abraham to our father: for I say vnto you, that God is able euen of these stones to raise vp children vnto Abraham.", "wycliffe": "and nyle ye seie with ynne you, We han Abraham to fadir; for Y seie to you, that God is myyti to reise vp of these stoones the sones of Abraham.", "rotherham": "and think not to be saying within yourselves,—As our father, we have, Abraham; for, I say unto you, that God is able, out of these stones, to raise up children unto Abraham.", "weymouth": "and do not imagine that you can say to yourselves, `We have Abraham as our forefather,' for I tell you that God can raise up descendants for Abraham from these stones.", "darby": "And do not think to say within yourselves, We have Abraham for [our] father; for I say unto you, thatGod is able of these stones to raise up children to Abraham.", "twenty": "and do not think that you can say among yourselves ‘Abraham is our ancestor,’ for I tell you that out of these very stones God is able to raise descendants for Abraham!", "acv": "And think not to say within yourselves, We have a father, Abraham. For I say to you, that God is able from these stones to raise up children to Abraham.", "anderson": "and think not to say within yourselves, We have Abraham for our father; for I say to you that God is able from these stones to raise up children to Abraham.", "haweis": "and think not to say in yourselves, We have Abraham for our father: for I say unto you, that God is able out of these stones to raise up children to Abraham.", "noyes": "and think not to say within yourselves, We have Abraham for our father; for I say to you, that God is able out of these stones to raise up children to Abraham.", "webster": "And think not to say within yourselves, We have Abraham for [our] father: for I say to you, that God is able of these stones to raise up children to Abraham.", "vulgate": "et ne velitis dicere intra vos patrem habemus Abraham dico enim vobis quoniam potest Deus de lapidibus istis suscitare filios Abrahae;"}}, {"v": 10, "ref": "3:10", "o": "ἤδη ⸀δὲ ἡ ἀξίνη πρὸς τὴν ῥίζαν τῶν δένδρων κεῖται· πᾶν οὖν δένδρον μὴ ποιοῦν καρπὸν καλὸν ἐκκόπτεται καὶ εἰς πῦρ βάλλεται.", "en": {"kjv": "And now also the axe is laid unto the root of the trees: therefore every tree which bringeth not forth good fruit is hewn down, and cast into the fire.", "web": "“Even now the ax lies at the root of the trees. Therefore every tree that doesn’t produce good fruit is cut down, and cast into the fire.", "bsb": "The axe lies ready at the root of the trees, and every tree that does not produce good fruit will be cut down and thrown into the fire.", "asv": "And even now the axe lieth at the root of the trees: every tree therefore that bringeth not forth good fruit is hewn down, and cast into the fire.", "ylt": "and now also, the axe unto the root of the trees is laid, every tree therefore not bearing good fruit is hewn down, and to fire is cast.", "tyndale": "Euenowe is ye axe put vnto ye rote of ye trees: soo that every tree which bringeth not forthe goode frute is hewe doune and cast into ye fyre.", "dra": "For now the axe is laid to the root of the trees. Every tree therefore that doth not yield good fruit, shall be cut down, and cast into the fire.", "bbe": "And even now the axe is put to the root of the trees; every tree then which does not give good fruit is cut down, and put into the fire.", "geneva": "And now also is the axe put to the roote of the trees: therfore euery tree which bringeth not forth good fruit, is hewen downe, and cast into ye fire.", "wycliffe": "And now the ax is put to the roote of the tree; therfore euery tree that makith not good fruyt, shal be kit doun, and shal be cast in to the fier.", "rotherham": "Already also, the axe, unto the root of the trees, is being laid,—every tree, therefore, not bringing forth good fruit, is to be hewn down, and, into fire, to be cast.", "weymouth": "And already the axe is lying at the root of the trees, so that every tree which does not produce good fruit will quickly be hewn down and thrown into the fire.", "darby": "And already the axe is applied to the root of the trees; every tree therefore not producing good fruit is cut down and cast into the fire.", "twenty": "Already the axe is lying at the root of the trees. Therefore every tree that fails to bear good fruit will be cut down and thrown into the fire.", "acv": "And even now the axe is laid at the root of the trees. Every tree therefore not producing good fruit is cut down, and cast into the fire.", "anderson": "Even now the ax is lying at the root of the trees: therefore, every tree that does not bring forth good fruit is cut down and thrown into the fire.", "haweis": "And now also the ax is laid to the root of the trees: every tree therefore which produceth not good fruit, is hewing down, and casting into the fire.", "noyes": "And already is the axe lying at the root of the trees; every tree therefore that beareth not good fruit is to be cut down, and cast into the fire.", "webster": "And now also the ax is laid to the root of the trees: therefore every tree which bringeth not forth good fruit is hewn down, and cast into the fire.", "vulgate": "iam enim securis ad radicem arborum posita est omnis ergo arbor quae non facit fructum bonum exciditur et in ignem mittitur;"}}, {"v": 11, "ref": "3:11", "o": "Ἐγὼ μὲν ⸂ὑμᾶς βαπτίζω⸃ ἐν ὕδατι εἰς μετάνοιαν· ὁ δὲ ὀπίσω μου ἐρχόμενος ἰσχυρότερός μού ἐστιν, οὗ οὐκ εἰμὶ ἱκανὸς τὰ ὑποδήματα βαστάσαι· αὐτὸς ὑμᾶς βαπτίσει ἐν πνεύματι ἁγίῳ ⸂καὶ πυρί⸃·", "en": {"kjv": "I indeed baptize you with water unto repentance: but he that cometh after me is mightier than I, whose shoes I am not worthy to bear: he shall baptize you with the Holy Ghost, and with fire:", "web": "I indeed baptize you in water for repentance, but he who comes after me is mightier than I, whose shoes I am not worthy to carry. He will baptize you in the Holy Spirit.", "bsb": "I baptize you with water for repentance, but after me will come One more powerful than I, whose sandals I am not worthy to carry. He will baptize you with the Holy Spirit and with fire.", "asv": "I indeed baptize you in water unto repentance: but he that cometh after me is mightier than I, whose shoes I am not worthy to bear: he shall baptize you in the Holy Spirit and in fire:", "ylt": "`I indeed do baptize you with water to reformation, but he who after me is coming is mightier than I, of whom I am not worthy to bear the sandals, he shall baptize you with the Holy Spirit and with fire,", "tyndale": "I baptise you in water in toke of repentauce: but he ye cometh after me is myghtier then I whose shues I am not worthy to beare. He shall baptise you with ye holy gost and with fyre:", "dra": "I indeed baptize you in water unto penance, but he that shall come after me, is mightier than I, whose shoes I am not worthy to bear: he shall baptize you in the Holy Ghost and fire.", "bbe": "Truly, I give baptism with water to those of you whose hearts are changed; but he who comes after me is greater than I, whose shoes I am not good enough to take up: he will give you baptism with the Holy Spirit and with fire:", "geneva": "In deede I baptize you with water to amendment of life, but he that commeth after me, is mightier then I, whose shoes I am not worthie to beare: hee will baptize you with the holy Ghost, and with fire.", "wycliffe": "Y waische you in water, in to penaunce; but he that shal come after me is strongere than Y, whos schoon Y am not worthi to bere; he shal baptise you in the Hooli Goost and fier.", "rotherham": "I, indeed, am immersing you, in water, unto repentance,—but, he who, after me, cometh is, mightier than I, whose, sandals, I am not worthy to bear, he, will immerse you, in Holy Spirit and fire:", "weymouth": "I indeed am baptizing you in water on a profession of repentance; but He who is coming after me is mightier than I: His sandals I am not worthy to carry for a moment; He will baptize you in the Holy Spirit and in fire.", "darby": "I indeed baptise you with water to repentance, but he that comes after me is mightier than I, whose sandals I am not fit to bear; he shall baptise you with [the] Holy Spirit and fire;", "twenty": "I, indeed, baptize you with water to teach repentance; but he who is coming after me is more powerful than I, and I am not fit even to carry his sandals. He will baptize you with the Holy Spirit and with fire.", "acv": "I indeed immerse you in water for repentance, but he who comes after me is mightier than I, whose shoes I am not worthy to bear. He will immerse you in the Holy Spirit.", "anderson": "I immerse you in water, in order to repentance; but he that comes after me is mightier than I, whose sandals I am not worthy to carry. He will immerse you in the Holy Spirit and in fire:", "haweis": "I indeed baptize you with water unto repentance: but he that is coming after me is mightier than I, whose sandals I am not worthy to carry: he shall baptize you with the Holy Spirit, and with fire:", "noyes": "I indeed baptize you in water, for repentance; but he that cometh after me is mightier than I, whose sandals I am not worthy to bear; he will baptize you in the Holy Spirit and in fire.", "webster": "I indeed baptize you with water to repentance: but he that cometh after me is mightier than I, whose shoes I am not worthy to bear: he shall baptize you with the Holy Spirit, and [with] fire:", "vulgate": "ego quidem vos baptizo in aqua in paenitentiam qui autem post me venturus est fortior me est cuius non sum dignus calciamenta portare ipse vos baptizabit in Spiritu Sancto et igni;"}}, {"v": 12, "ref": "3:12", "o": "οὗ τὸ πτύον ἐν τῇ χειρὶ αὐτοῦ, καὶ διακαθαριεῖ τὴν ἅλωνα αὐτοῦ καὶ συνάξει τὸν σῖτον αὐτοῦ εἰς τὴν ⸀ἀποθήκην, τὸ δὲ ἄχυρον κατακαύσει πυρὶ ἀσβέστῳ.", "en": {"kjv": "Whose fan is in his hand, and he will throughly purge his floor, and gather his wheat into the garner; but he will burn up the chaff with unquenchable fire.", "web": "His winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor. He will gather his wheat into the barn, but the chaff he will burn up with unquenchable fire.”", "bsb": "His winnowing fork is in His hand to clear His threshing floor and to gather His wheat into the barn; but He will burn up the chaff with unquenchable fire.”", "asv": "whose fan is in his hand, and he will thoroughly cleanse his threshing-floor; and he will gather his wheat into the garner, but the chaff he will burn up with unquenchable fire.", "ylt": "whose fan is in his hand, and he will thoroughly cleanse his floor, and will gather his wheat to the storehouse, but the chaff he will burn with fire unquenchable.'", "tyndale": "which hath also his fan in his hod and will pourge his floure and gadre ye wheet into his garner and will burne ye chaffe with vnquecheable fyre", "dra": "Whose fan is in his hand, and he will thoroughly cleanse his floor and gather his wheat into the barn; but the chaff he will burn with unquenchable fire.", "bbe": "In whose hand is the instrument with which he will make clean his grain; he will put the good grain in his store, but the waste will be burned up in the fire which will never be put out.", "geneva": "Which hath his fanne in his hand, and wil make cleane his floore, and gather his wheate into his garner, but will burne vp the chaffe with vnquenchable fire.", "wycliffe": "Whos wynewing cloth is in his hoond, and he shal fulli clense his corn flore, and shal gadere his whete in to his berne; but the chaffe he shal brenne with fier that mai not be quenchid.", "rotherham": "Whose fan is in his hand, and he will clear out his threshing-floor,—and will gather his wheat into the granary, but, the chaff, will he burn up with fire unquenchable.", "weymouth": "His winnowing-shovel is in His hand, and He will make a thorough clearance of His threshing-floor, gathering His wheat into the storehouse, but burning up the chaff in unquenchable fire.\"", "darby": "whose winnowing fan [is] in his hand, and he shall thoroughly purge his threshing-floor, and shall gather his wheat into the garner, but the chaff he will burn with fire unquenchable.", "twenty": "His winnowing-fan is in his hand, and he will clear his threshing-floor, and store his grain in the barn, but the chaff he will burn with inextinguishable fire.”", "acv": "Whose winnowing fork is in his hand, and he will thoroughly cleanse his threshing floor. And he will gather his wheat into the storehouse, but he will burn the chaff with unquenchable fire.", "anderson": "whose winnowing-shovel is in his hand, and he will thoroughly cleanse his thrashing-floor, and gather his grain into his granary; but the chaff he will burn with unquenchable fire.", "haweis": "whose winnowing fan is in his hand, and he will thoroughly cleanse his threshing floor, and will collect the wheat into his granary; but the chaff will he burn up with fire unquenchable.", "noyes": "His winnowing-shovel is in his hand, and he will thoroughly cleanse his threshing-floor, and gather his wheat into the garner; but the chaff he will burn up with unquenchable fire.", "webster": "Whose fan [is] in his hand, and he will thoroughly cleanse his floor, and gather his wheat into the granary; but he will burn the chaff with unquenchable fire.", "vulgate": "cuius ventilabrum in manu sua et permundabit aream suam et congregabit triticum suum in horreum paleas autem conburet igni inextinguibili;"}}, {"v": 13, "ref": "3:13", "o": "Τότε παραγίνεται ὁ Ἰησοῦς ἀπὸ τῆς Γαλιλαίας ἐπὶ τὸν Ἰορδάνην πρὸς τὸν Ἰωάννην τοῦ βαπτισθῆναι ὑπ’ αὐτοῦ.", "en": {"kjv": "Then cometh Jesus from Galilee to Jordan unto John, to be baptized of him.", "web": "Then Jesus came from Galilee to the Jordan to John, to be baptized by him.", "bsb": "At that time Jesus came from Galilee to the Jordan to be baptized by John.", "asv": "Then cometh Jesus from Galilee to the Jordan unto John, to be baptized of him.", "ylt": "Then cometh Jesus from Galilee upon the Jordan, unto John to be baptized by him,", "tyndale": "Then cam Iesus from Galile to Iordan vnto Ihon to be baptised of hym.", "dra": "Then cometh Jesus from Galilee to the Jordan, unto John, to be baptized by him.", "bbe": "Then Jesus came from Galilee to John at the Jordan, to be given baptism by him.", "geneva": "Then came Iesus from Galile to Iordan vnto Iohn, to be baptized of him.", "wycliffe": "Thanne Jhesus cam fro Galilee in to Jordan to Joon, to be baptised of hym.", "rotherham": "Then, cometh Jesus, from Galilee to the Jordan, unto John,—to be immersed by him.", "weymouth": "Just at that time Jesus, coming from Galilee to the Jordan, presents Himself to John to be baptized by him.", "darby": "Then comes Jesus from Galilee to the Jordan to John, to be baptised of him;", "twenty": "Then Jesus came from Galilee to the Jordan, to John, to be baptized by him.", "acv": "Then Jesus comes from Galilee to the Jordan to John to be immersed by him.", "anderson": "Then came Jesus from Galilee to the Jordan to John, to be immersed by him.", "haweis": "Then came Jesus from Galilee unto Jordan to John, that he might be baptized by him.", "noyes": "Then cometh Jesus from Galilee to the Jordan to John, to be baptized by him.", "webster": "Then cometh Jesus from Galilee to Jordan to John, to be baptized by him.", "vulgate": "tunc venit Iesus a Galilaea in Iordanen ad Iohannem ut baptizaretur ab eo;"}}, {"v": 14, "ref": "3:14", "o": "ὁ δὲ ⸀Ἰωάννης διεκώλυεν αὐτὸν λέγων· Ἐγὼ χρείαν ἔχω ὑπὸ σοῦ βαπτισθῆναι, καὶ σὺ ἔρχῃ πρός με;", "en": {"kjv": "But John forbad him, saying, I have need to be baptized of thee, and comest thou to me?", "web": "But John would have hindered him, saying, “I need to be baptized by you, and you come to me?”", "bsb": "But John tried to prevent Him, saying, “I need to be baptized by You, and do You come to me?”", "asv": "But John would have hindered him, saying, I have need to be baptized of thee, and comest thou to me?", "ylt": "but John was forbidding him, saying, `I have need by thee to be baptized--and thou dost come unto me!'", "tyndale": "But Ihon forbade hym saynge: I ought to be baptysed of the: and comest thou to me?", "dra": "But John stayed him, saying: I ought to be baptized by thee, and comest thou to me?", "bbe": "But John would have kept him back, saying, It is I who have need of baptism from you, and do you come to me?", "geneva": "But Iohn earnestly put him backe, saying, I haue neede to be baptized of thee, and commest thou to me?", "wycliffe": "And Joon forbede him, and seide, Y owe to be baptisid of thee, and thou comest to me?", "rotherham": "But, he, would have hindered him, saying—I, have, need, by thee, to be immersed,—and dost, thou, come unto me?", "weymouth": "John protested. \"It is I,\" he said, \"who have need to be baptized by you, and do you come to me?\"", "darby": "but John urgently forbad him, saying, I have need to be baptised of thee; and comest thou to me?", "twenty": "But John tried to prevent him. “It is I,” he said, “who need to be baptized by you; why then do you come to me?”", "acv": "But John was preventing him, saying, I have need to be immersed by thee, and thou come to me?", "anderson": "But John forbade him, saying: I have need to be immersed by thee, and comest thou to me?", "haweis": "But John earnestly withheld him, saying, I have need to be baptized of thee, and comest thou to me?", "noyes": "But John opposed him, saying, I have need to be baptized by thee, and dost thou come to me?", "webster": "But John forbad him, saying, I have need to be baptized by thee, and comest thou to me?", "vulgate": "Iohannes autem prohibebat eum dicens ego a te debeo baptizari et tu venis ad me;"}}, {"v": 15, "ref": "3:15", "o": "ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν ⸂πρὸς αὐτόν⸃· Ἄφες ἄρτι, οὕτως γὰρ πρέπον ἐστὶν ἡμῖν πληρῶσαι πᾶσαν δικαιοσύνην. τότε ἀφίησιν αὐτόν.", "en": {"kjv": "And Jesus answering said unto him, Suffer it to be so now: for thus it becometh us to fulfil all righteousness. Then he suffered him.", "web": "But Jesus, answering, said to him, “Allow it now, for this is the fitting way for us to fulfill all righteousness.” Then he allowed him.", "bsb": "“Let it be so now,” Jesus replied. “It is fitting for us to fulfill all righteousness in this way.” Then John permitted Him.", "asv": "But Jesus answering said unto him, Suffer it now: for thus it becometh us to fulfil all righteousness. Then he suffereth him.", "ylt": "But Jesus answering said to him, `Suffer now, for thus it is becoming to us to fulfil all righteousness,' then he doth suffer him.", "tyndale": "Iesus answered and sayd to hym: Let it be so now. For thus it becommeth vs to fulfyll all rightwesnes. Then he suffred hym.", "dra": "And Jesus answering, said to him: Suffer it to be so now. For so it becometh us to fulfil all justice. Then he suffered him.", "bbe": "But Jesus made answer, saying to him, Let it be so now: because so it is right for us to make righteousness complete. Then he gave him baptism.", "geneva": "Then Iesus answering, saide to him, Let be nowe: for thus it becommeth vs to fulfill all righteousnes. So he suffered him.", "wycliffe": "But Jhesus answeride, and seide to hym, Suffre nowe, for thus it fallith to vs to fulfille al riytfulnesse.", "rotherham": "But Jesus answering, said unto him, Suffer [me] even now,—for, thus, it becometh us, to fulfil, all righteousness; then, he suffered him.", "weymouth": "\"Let it be so on this occasion,\" Jesus replied; \"for so we ought to fulfil every religious duty.\" Then he consented;", "darby": "But Jesus answering said to him, Suffer [it] now; for thus it becometh us to fulfil all righteousness. Then he suffers him.", "twenty": "“Let it be so for the present,” Jesus answered, “since it is fitting for us thus to satisfy every claim of religion.” Upon this, John consented.", "acv": "But having answered, Jesus said to him, Allow it now, for thus it is fitting for us to fulfill all righteousness. Then he allows him.", "anderson": "But Jesus answering said to him: Permit it now; for thus it becomes us to perform fully every righteous act. Then he permitted him.", "haweis": "But Jesus answering said unto him, Permit it to be so now, for thus it becometh us to fulfil all righteousness. Then he permitted him.", "noyes": "And Jesus answering said to him, Suffer it now; for thus it becometh us to fulfill all righteousness. Then he suffered him.", "webster": "And Jesus answering said to him, Suffer [it to be so] now: for thus it becometh us to fulfill all righteousness. Then he suffered him.", "vulgate": "respondens autem Iesus dixit ei sine modo sic enim decet nos implere omnem iustitiam tunc dimisit eum;"}}, {"v": 16, "ref": "3:16", "o": "⸂βαπτισθεὶς δὲ⸃ ὁ Ἰησοῦς ⸂εὐθὺς ἀνέβη⸃ ἀπὸ τοῦ ὕδατος· καὶ ἰδοὺ ⸀ἠνεῴχθησαν οἱ οὐρανοί, καὶ εἶδεν ⸀πνεῦμα θεοῦ καταβαῖνον ὡσεὶ ⸀περιστερὰν ἐρχόμενον ἐπ’ αὐτόν·", "en": {"kjv": "And Jesus, when he was baptized, went up straightway out of the water: and, lo, the heavens were opened unto him, and he saw the Spirit of God descending like a dove, and lighting upon him:", "web": "Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him.", "bsb": "As soon as Jesus was baptized, He went up out of the water. Suddenly the heavens were opened, and He saw the Spirit of God descending like a dove and resting on Him.", "asv": "And Jesus, when he was baptized, went up straightway from the water: and lo, the heavens were opened unto him, and he saw the Spirit of God descending as a dove, and coming upon him;", "ylt": "And having been baptized, Jesus went up immediately from the water, and lo, opened to him were the heavens, and he saw the Spirit of God descending as a dove, and coming upon him,", "tyndale": "And Iesus assone as he was baptised came strayght out of ye water. And lo heue was ope over hym: and Ihon sawe the spirite of God descende lyke a doue and lyght vpon hym.", "dra": "And Jesus being baptized, forthwith came out of the water: and lo, the heavens were opened to him: and he saw the Spirit of God descending as a dove, and coming upon him.", "bbe": "And Jesus, having been given baptism, straight away went up from the water; and, the heavens opening, he saw the Spirit of God coming down on him as a dove;", "geneva": "And Iesus when hee was baptized, came straight out of the water. And lo, the heaues were opened vnto him, and Iohn saw the Spirit of God descending like a doue, and lighting vpon him.", "wycliffe": "Thanne Joon suffride hym. And whanne Jhesus was baptisid, anoon he wente up fro the watir; and lo! heuenes weren openyd to hym, and he saie the Spirit of God comynge doun as a dowue, and comynge on hym; and loo!", "rotherham": "And Jesus, having been immersed, straightway, went up from the water,—and lo! the heavens were opened and he saw the Spirit of God, descending like a dove coming upon him;", "weymouth": "and Jesus was baptized, and immediately went up from the water. At that moment the heavens opened, and he saw the Spirit of God descending like a dove and alighting upon Him,", "darby": "And Jesus, having been baptised, went up straightway from the water, and lo, the heavens were opened to him, and he saw the Spirit ofGod descending as a dove, and coming upon him:", "twenty": "After the baptism of Jesus, and just as he came up from the water, the heavens opened, and he saw the Spirit of God descending, like a dove, and alighting upon him,", "acv": "And when Jesus was immersed, he went up straightaway out of the water. And lo, the heavens were opened to him, and he saw the Spirit of God descending like a dove, and coming upon him.", "anderson": "And after Jesus was immersed, he came up immediately from the water; and lo, the heavens were opened to him, and he saw the Spirit of God descending like a dove, and coming upon him.", "haweis": "And Jesus, after his baptism, came straight from the water: and lo! the heavens were opened for him, and he saw the Spirit of God descending as it were a dove, and coming upon him:", "noyes": "And Jesus, as soon as he was baptized, went up from the water; and, lo! the heavens were opened, and he saw the Spirit of God, descending like a dove, coming upon him.", "webster": "And Jesus, when he was baptized, went up immediately out of the water: and lo, the heavens were opened to him, and he saw the Spirit of God descending like a dove, and lighting upon him:", "vulgate": "baptizatus autem confestim ascendit de aqua et ecce aperti sunt ei caeli et vidit Spiritum Dei descendentem sicut columbam venientem super se;"}}, {"v": 17, "ref": "3:17", "o": "καὶ ἰδοὺ φωνὴ ἐκ τῶν οὐρανῶν λέγουσα· Οὗτός ἐστιν ὁ υἱός μου ὁ ἀγαπητός, ἐν ᾧ εὐδόκησα.", "en": {"kjv": "And lo a voice from heaven, saying, This is my beloved Son, in whom I am well pleased.", "web": "Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”", "bsb": "And a voice from heaven said, “This is My beloved Son, in whom I am well pleased!”", "asv": "and lo, a voice out of the heavens, saying, This is my beloved Son, in whom I am well pleased.", "ylt": "and lo, a voice out of the heavens, saying, `This is My Son--the Beloved, in whom I did delight.'", "tyndale": "And lo there came a voyce from heven sayng: Thys ys that my beloved sonne in whom is my delyte.", "dra": "And behold a voice from heaven saying: This is my beloved Son, in whom I am well pleased.", "bbe": "And a voice came out of heaven, saying, This is my dearly loved Son, with whom I am well pleased.", "geneva": "And loe, a voyce came from heauen, saying, This is my beloued Sonne, in whome I am well pleased.", "wycliffe": "a vois fro heuenes, seiynge, This is my louyd sone, in which Y haue plesid to me.", "rotherham": "and lo! a voice out of the heavens,—saying, This, is my Son, the Beloved, in whom I delight.", "weymouth": "while a voice came from Heaven, saying, \"This is My Son, the dearly loved, in whom is My delight.\"", "darby": "and behold, a voice out of the heavens saying, This is my beloved Son, in whom I have found my delight.", "twenty": "and from the heavens there came a voice which said: “This is my son, the Beloved, in whom I delight.”", "acv": "And lo, a voice out of the heavens, saying, This is my beloved Son, in whom I am well pleased.", "anderson": "And lo, a voice from heaven, saying: This is my beloved Son, in whom I delight.", "haweis": "and lo! a voice from the heavens, saying, This is my Son, the beloved, in whom is my delight.", "noyes": "And lo! a voice from the heavens, saying, \"This is my beloved Son, with whom I am well pleased.\"", "webster": "And lo, a voice from heaven, saying, This is my beloved Son, in whom I am well pleased.", "vulgate": "et ecce vox de caelis dicens hic est Filius meus dilectus in quo mihi conplacui;"}}]}, {"c": 4, "verses": [{"v": 1, "ref": "4:1", "o": "Τότε ὁ Ἰησοῦς ἀνήχθη εἰς τὴν ἔρημον ὑπὸ τοῦ πνεύματος, πειρασθῆναι ὑπὸ τοῦ διαβόλου.", "en": {"kjv": "Then was Jesus led up of the Spirit into the wilderness to be tempted of the devil.", "web": "Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil.", "bsb": "Then Jesus was led by the Spirit into the wilderness to be tempted by the devil.", "asv": "Then was Jesus led up of the Spirit into the wilderness to be tempted of the devil.", "ylt": "Then Jesus was led up to the wilderness by the Spirit, to be tempted by the Devil,", "tyndale": "Then was Iesus ledd awaye of ye spirite into wildernes to be tempted of ye devyll.", "dra": "Then Jesus was led by the spirit into the desert, to be tempted by the devil.", "bbe": "Then Jesus was sent by the Spirit into the waste land to be tested by the Evil One.", "geneva": "Then was Iesus led aside of the Spirit into the wildernes, to be tempted of the deuil.", "wycliffe": "Thanne Jhesus was led of a spirit in to desert, to be temptid of the feend.", "rotherham": "Then, Jesus was led up into the wilderness, by the Spirit, to be tempted by the adversary;", "weymouth": "At that time Jesus was led up by the Spirit into the Desert in order to be tempted by the Devil.", "darby": "Then Jesus was carried up into the wilderness by the Spirit to be tempted of the devil:", "twenty": "Then Jesus was led up into the Wilderness by the Spirit to be tempted by the Devil.", "acv": "Then Jesus was led by the Spirit into the wilderness to be tempted by the devil.", "anderson": "Then was Jesus led up by the Spirit into the wilderness, to be tempted by the devil.", "haweis": "THEN was Jesus led away by the spirit into the wilderness, to be tempted by the devil.", "noyes": "Then was Jesus led up by the Spirit into the wilderness, to be tempted by the Devil.", "webster": "Then was Jesus led by the Spirit into the wilderness, to be tempted by the devil.", "vulgate": "tunc Iesus ductus est in desertum ab Spiritu ut temptaretur a diabolo;"}}, {"v": 2, "ref": "4:2", "o": "καὶ νηστεύσας ἡμέρας τεσσεράκοντα καὶ νύκτας τεσσεράκοντα ὕστερον ἐπείνασεν.", "en": {"kjv": "And when he had fasted forty days and forty nights, he was afterward an hungred.", "web": "When he had fasted forty days and forty nights, he was hungry afterward.", "bsb": "After fasting forty days and forty nights, He was hungry.", "asv": "And when he had fasted forty days and forty nights, he afterward hungered.", "ylt": "and having fasted forty days and forty nights, afterwards he did hunger.", "tyndale": "And when he had fasted fourtye dayes and fourtye nightes he was afterward an hungred.", "dra": "And when he had fasted forty days and forty nights, afterwards he was hungry.", "bbe": "And after going without food for forty days and forty nights, he was in need of it.", "geneva": "And when he had fasted fourtie dayes, and fourtie nights, he was afterward hungrie.", "wycliffe": "And whanne he hadde fastid fourti daies and fourti nyytis, aftirward he hungride.", "rotherham": "and, fasting forty days and forty nights,—afterwards, he hungered.", "weymouth": "There He fasted for forty days and nights; and after that He suffered from hunger.", "darby": "and having fasted forty days and forty nights, afterwards he hungered.", "twenty": "And, after he had fasted for forty days and forty nights, he became hungry.", "acv": "And having fasted forty days and forty nights, afterward he was hungry.", "anderson": "And when he had fasted forty days and forty nights, he was afterward hungry.", "haweis": "And when he had fasted forty days and forty nights, afterwards he became hungry.", "noyes": "And when he had tasted forty days and forty nights, he was afterward hungry.", "webster": "And when he had fasted forty days and forty nights, he was afterward hungry.", "vulgate": "et cum ieiunasset quadraginta diebus et quadraginta noctibus postea esuriit;"}}, {"v": 3, "ref": "4:3", "o": "καὶ προσελθὼν ⸂ὁ πειράζων εἶπεν αὐτῷ⸃· Εἰ υἱὸς εἶ τοῦ θεοῦ, εἰπὲ ἵνα οἱ λίθοι οὗτοι ἄρτοι γένωνται.", "en": {"kjv": "And when the tempter came to him, he said, If thou be the Son of God, command that these stones be made bread.", "web": "The tempter came and said to him, “If you are the Son of God, command that these stones become bread.”", "bsb": "The tempter came to Him and said, “If You are the Son of God, tell these stones to become bread.”", "asv": "And the tempter came and said unto him, If thou art the Son of God, command that these stones become bread.", "ylt": "And the Tempter having come to him said, `If Son thou art of God--speak that these stones may become loaves.'", "tyndale": "Then came to hym the tempter and sayde: yf thou be the sonne of God commaunde that these stones be made breed.", "dra": "And the tempter coming said to him: If thou be the Son of God, command that these stones be made bread.", "bbe": "And the Evil One came and said to him, If you are the Son of God, give the word for these stones to become bread.", "geneva": "Then came to him the tempter, and said, If thou be the Sonne of God, commande that these stones be made bread.", "wycliffe": "And the tempter cam nyy, and seide to hym, If thou art Goddis sone, seie that thes stoones be maad looues.", "rotherham": "And, coming near, the tempter said to him,—If thou art God’s, Son, speak! that, these stones, may become, loaves.", "weymouth": "So the Tempter came and said, \"If you are the Son of God, command these stones to turn into loaves.\"", "darby": "And the tempter coming up to him said, If thou be Son ofGod, speak, that these stones may become loaves of bread.", "twenty": "And the Tempter came to him, and said: “If you are God’s Son, tell these stones to become loaves of bread.”", "acv": "And after he who tempts came, he said to him, If thou are the Son of God, speak so that these stones may become bread.", "anderson": "And the tempter came to him and said: If you are the Son of God, command that these stones become bread.", "haweis": "And the tempter coming to him said, If thou art the Son of God, command that these stones be made loaves.", "noyes": "And the tempter came and said to him, If thou art the Son of God, command that these stones become loaves of bread.", "webster": "And when the tempter came to him, he said, If thou art the son of God, command that these stones be made bread.", "vulgate": "et accedens temptator dixit ei si Filius Dei es dic ut lapides isti panes fiant;"}}, {"v": 4, "ref": "4:4", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Γέγραπται· Οὐκ ἐπ’ ἄρτῳ μόνῳ ζήσεται ⸀ὁ ἄνθρωπος, ἀλλ’ ⸀ἐπὶ παντὶ ῥήματι ἐκπορευομένῳ διὰ στόματος θεοῦ.", "en": {"kjv": "But he answered and said, It is written, Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God.", "web": "But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of the mouth of God.’”", "bsb": "But Jesus answered, “It is written: ‘Man shall not live on bread alone, but on every word that comes from the mouth of God.’”", "asv": "But he answered and said, It is written, Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God.", "ylt": "But he answering said, `It hath been written, Not upon bread alone doth man live, but upon every word coming forth from the mouth of God.'", "tyndale": "He answered and sayde: yt is wrytten man shall not lyve by brede onlye but by every worde yt proceadeth out of the mouth of God.", "dra": "Who answered and said: It is written, Not in bread alone doth man live, but in every word that proceedeth from the mouth of God.", "bbe": "But he made answer and said, It is in the Writings, Bread is not man's only need, but every word which comes out of the mouth of God.", "geneva": "But he answering said, It is written, Man shall not liue by bread onely, but by euery worde that proceedeth out of the mouth of God.", "wycliffe": "Which answeride, and seide to hym, It is writun, Not oonli in breed luyeth man, but in ech word that cometh of Goddis mouth.", "rotherham": "But, he, answering, said, It is written,—Not on bread alone, shall man live, but on every declaration coming forth through the mouth of God.", "weymouth": "\"It is written,\" replied Jesus, \"`It is not on bread alone that a man shall live, but on whatsoever God shall appoint.'\"", "darby": "But he answering said, It is written, Man shall not live by bread alone, but by every word which goes out throughGod's mouth.", "twenty": "But Jesus answered: “Scripture says — ‘It is not on bread alone that man is to live, but on every word that comes from the mouth of God.’”", "acv": "But having answered, he said, It is written, Man will not live on bread alone, but on every word coming out through the mouth of God.", "anderson": "But he answered and said: It is written, Man shall not live by bread alone, but by every word that comes forth from the mouth of God.", "haweis": "But he answering said, It is written, “Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God.”", "noyes": "But he answered and said, It is written, \"Man shall not live on bread alone, but on every word that proceedeth from the mouth of God.\"", "webster": "But he answered and said, It is written, Man shall not live by bread alone, but by every word that proceedeth out of the mouth of God.", "vulgate": "qui respondens dixit scriptum est non in pane solo vivet homo sed in omni verbo quod procedit de ore Dei;"}}, {"v": 5, "ref": "4:5", "o": "Τότε παραλαμβάνει αὐτὸν ὁ διάβολος εἰς τὴν ἁγίαν πόλιν, καὶ ⸀ἔστησεν αὐτὸν ἐπὶ τὸ πτερύγιον τοῦ ἱεροῦ,", "en": {"kjv": "Then the devil taketh him up into the holy city, and setteth him on a pinnacle of the temple,", "web": "Then the devil took him into the holy city. He set him on the pinnacle of the temple,", "bsb": "Then the devil took Him to the holy city and set Him on the pinnacle of the temple.", "asv": "Then the devil taketh him into the holy city; and he set him on the pinnacle of the temple,", "ylt": "Then doth the Devil take him to the holy city, and doth set him on the pinnacle of the temple,", "tyndale": "Then the devyll tooke hym vp into ye holy cite and set hym on a pynacle of the teple", "dra": "Then the devil took him up into the holy city, and set him upon the pinnacle of the temple,", "bbe": "Then the Evil One took him to the holy town; and he put him on the highest point of the Temple and said to him,", "geneva": "Then the deuil tooke him vp into the holy Citie, and set him on a pinacle of the temple,", "wycliffe": "Thanne the feend took hym in to the hooli citee, and settide hym on the pynacle of the temple,", "rotherham": "Then, the adversary taketh him with him, unto the holy city,—and he set him upon the pinnacle of the temple;", "weymouth": "Then the Devil took Him to the Holy City and caused Him to stand on the roof of the Temple,", "darby": "Then the devil takes him to the holy city, and sets him upon the edge of the temple,", "twenty": "Then the Devil took him to the Holy City, and, placing him on the parapet of the temple, said to him:", "acv": "Then the devil takes him into the holy city, and stands him on the pinnacle of the temple.", "anderson": "Then the devil took him into the holy city, and placed him on the pinnacle of the temple,", "haweis": "Then the devil taketh him up into the holy city, and placed him on a wing of the temple,", "noyes": "Then the Devil taketh him into the holy city, and setteth him on the pinnacle of the temple;", "webster": "Then the devil taketh him up into the holy city, and setteth him on a pinnacle of the temple,", "vulgate": "tunc adsumit eum diabolus in sanctam civitatem et statuit eum supra pinnaculum templi;"}}, {"v": 6, "ref": "4:6", "o": "καὶ λέγει αὐτῷ· Εἰ υἱὸς εἶ τοῦ θεοῦ, βάλε σεαυτὸν κάτω· γέγραπται γὰρ ὅτι Τοῖς ἀγγέλοις αὐτοῦ ἐντελεῖται περὶ σοῦ καὶ ἐπὶ χειρῶν ἀροῦσίν σε, μήποτε προσκόψῃς πρὸς λίθον τὸν πόδα σου.", "en": {"kjv": "And saith unto him, If thou be the Son of God, cast thyself down: for it is written, He shall give his angels charge concerning thee: and in their hands they shall bear thee up, lest at any time thou dash thy foot against a stone.", "web": "and said to him, “If you are the Son of God, throw yourself down, for it is written, ‘He will put his angels in charge of you.’ and, ‘On their hands they will bear you up, so that you don’t dash your foot against a stone.’”", "bsb": "“If You are the Son of God,” he said, “throw Yourself down. For it is written: ‘He will command His angels concerning You, and they will lift You up in their hands, so that You will not strike Your foot against a stone.’”", "asv": "and saith unto him, If thou art the Son of God, cast thyself down: for it is written, He shall give his angels charge concerning thee: and, On their hands they shall bear thee up, Lest haply thou dash thy foot against a stone.", "ylt": "and saith to him, `If Son thou art of God--cast thyself down, for it hath been written, that, His messengers He shall charge concerning thee, and on hands they shall bear thee up, that thou mayest not dash on a stone thy foot.'", "tyndale": "and sayd vnto hym: yf thou be the sonne of God cast thy sylfe doune. For it is wrytte he shall geve his angels charge over the and with their handes they shall holde yt vp that thou dashe not thy fote agaynst a stone.", "dra": "And said to him: If thou be the Son of God, cast thyself down, for it is written: That he hath given his angels charge over thee, and in their hands shall they bear thee up, lest perhaps thou dash thy foot against a stone.", "bbe": "If you are the Son of God, let yourself go down; for it is in the Writings, He will give his angels care over you; and, In their hands they will keep you up, so that your foot may not be crushed against a stone.", "geneva": "And said vnto him, If thou be the Sonne of God, cast thy selfe downe: for it is written, that he wil giue his Angels charge ouer thee, and with their hands they shall lift thee vp, lest at any time thou shouldest dash thy foote against a stone.", "wycliffe": "and seide to hym, If thou art Goddis sone, sende thee adoun; for it is writun, That to hise aungels he comaundide of thee, and thei schulen take thee in hondis, lest perauenture thou hirte thi foot at a stoon.", "rotherham": "and saith to him—If thou art God’s, Son, cast thyself down,—for it is written, To his messengers, will he give charge concerning thee; and, on hands, will they bear thee up, lest once thou strike, against a stone, thy foot.", "weymouth": "and said, \"If you are God's Son, throw yourself down; for it is written, \"`To His angels He will give orders concerning thee, and on their hands they shall bear thee up, lest at any moment thou shouldst strike thy foot against a stone.'\"", "darby": "and says to him, If thou be Son ofGod cast thyself down; for it is written, He shall give charge to his angels concerning thee, and on [their] hands shall they bear thee, lest in anywise thou strike thy foot against a stone.", "twenty": "“If you are God’s Son, throw yourself down, for Scripture says — ‘He will give his angels commands about thee, and on their hands they will upbear thee, lest ever thou shouldst strike thy foot against a stone.’”", "acv": "And he says to him, If thou are the Son of God, cast thyself down, for it is written, He will command his agents about thee, and, They will take thee up in their hands, lest thou dash thy foot against a stone.", "anderson": "and said to him: If you are the Son of God, throw yourself down, for it is written: He will give his angels charge concerning you; and in their hands shall they take you up, lest you strike your foot against a stone.", "haweis": "and saith to him, If thou be the Son of God, cast thyself down: for it is written, “that he shall give his angels a charge concerning thee: and in their hands shall they hold thee up, lest at any time thou dash thy foot against a stone.”", "noyes": "and saith to him, If thou art the Son of God, cast thyself down; for it is written, \"He will give his angels charge concerning thee; and in their hands they will bear thee up, that thou mayst not dash thy foot against a stone.\"", "webster": "And saith to him, If thou art the Son of God, cast thyself down, for it is written, He shall give his angels charge concerning thee: and in [their] hands they shall uphold thee, lest at any time thou dash thy foot against a stone.", "vulgate": "et dixit ei si Filius Dei es mitte te deorsum scriptum est enim quia angelis suis mandabit de te et in manibus tollent te ne forte offendas ad lapidem pedem tuum;"}}, {"v": 7, "ref": "4:7", "o": "ἔφη αὐτῷ ὁ Ἰησοῦς· Πάλιν γέγραπται· Οὐκ ἐκπειράσεις κύριον τὸν θεόν σου.", "en": {"kjv": "Jesus said unto him, It is written again, Thou shalt not tempt the Lord thy God.", "web": "Jesus said to him, “Again, it is written, ‘You shall not test the Lord, your God.’”", "bsb": "Jesus replied, “It is also written: ‘Do not put the Lord your God to the test.’”", "asv": "Jesus said unto him, Again it is written, Thou shalt not make trial of the Lord thy God.", "ylt": "Jesus said to him again, `It hath been written, Thou shalt not tempt the Lord thy God.'", "tyndale": "And Iesus sayde to hym it ys wrytten also: Thou shalt not tempte thy Lorde God.", "dra": "Jesus said to him: It is written again: Thou shalt not tempt the Lord thy God.", "bbe": "Jesus said to him, Again it is in the Writings, You may not put the Lord your God to the test.", "geneva": "Iesus saide vnto him, It is written againe, Thou shalt not tempt the Lord thy God.", "wycliffe": "Eftsoone Jhesus seide to hym, It is writun, Thou shalt not tempte thi Lord God.", "rotherham": "Jesus said to him, Again, it is written,—Thou shalt not put to the test, the Lord thy God.", "weymouth": "\"Again it is written,\" replied Jesus, \"`Thou shalt not put the Lord thy God to the proof.'\"", "darby": "Jesus said to him, It is again written, Thou shalt not tempt [the] Lord thyGod.", "twenty": "“Scripture also says,” answered Jesus, “Thou shalt not tempt the Lord thy God.’”", "acv": "Jesus said to him, Again it is written, Thou shall not challenge the Lord thy God.", "anderson": "Jesus said to him: It is again written, You shall not put the Lord your God to the proof.", "haweis": "Jesus said unto him, It is written again, “Thou shalt not tempt the Lord thy God.”", "noyes": "Jesus said to him, Again it is written, \"Thou shalt not make trial of the Lord thy God.\"", "webster": "Jesus said to him, It is written again, Thou shalt not tempt the Lord thy God.", "vulgate": "ait illi Iesus rursum scriptum est non temptabis Dominum Deum tuum;"}}, {"v": 8, "ref": "4:8", "o": "Πάλιν παραλαμβάνει αὐτὸν ὁ διάβολος εἰς ὄρος ὑψηλὸν λίαν, καὶ δείκνυσιν αὐτῷ πάσας τὰς βασιλείας τοῦ κόσμου καὶ τὴν δόξαν αὐτῶν", "en": {"kjv": "Again, the devil taketh him up into an exceeding high mountain, and sheweth him all the kingdoms of the world, and the glory of them;", "web": "Again, the devil took him to an exceedingly high mountain, and showed him all the kingdoms of the world, and their glory.", "bsb": "Again, the devil took Him to a very high mountain and showed Him all the kingdoms of the world and their glory.", "asv": "Again, the devil taketh him unto an exceeding high mountain, and showeth him all the kingdoms of the world, and the glory of them;", "ylt": "Again doth the Devil take him to a very high mount, and doth shew to him all the kingdoms of the world and the glory of them,", "tyndale": "The devyll toke hym vp agayne and ledde hym in to an excedynge hye mountayne and shewed hym all the kyngdomes of ye worlde and all ye glorie of them", "dra": "Again the devil took him up into a very high mountain, and shewed him all the kingdoms of the world, and the glory of them,", "bbe": "Again, the Evil One took him up to a very high mountain, and let him see all the kingdoms of the world and the glory of them;", "geneva": "Againe the deuil tooke him vp into an exceeding hie mountaine, and shewed him all the kingdomes of the world, and the glory of them,", "wycliffe": "Eftsoone the feend took hym in to a ful hiy hil, and schewide to hym alle the rewmes of the world, and the ioye of hem;", "rotherham": "Again, the adversary taketh him with him, into an exceeding high mountain,—and pointeth out to him all the kingdoms of the world, and their glory;", "weymouth": "Then the Devil took Him to the top of an exceedingly lofty mountain, from which he caused Him to see all the Kingdoms of the world and their splendour,", "darby": "Again the devil takes him to a very high mountain, and shews him all the kingdoms of the world, and their glory,", "twenty": "The third time, the Devil took Jesus to a very high mountain, and, showing him all the kingdoms of the world and their splendour, said to him:", "acv": "Again, the devil takes him onto an exceedingly high mountain, and shows him all the kingdoms of the world, and the glory of them.", "anderson": "Again, the devil took him to a very high mountain, and showed him all the kingdoms of the world and the glory of them,", "haweis": "Again the devil taketh him unto an exceeding high mountain, and sheweth him all the kingdoms of the world, and their glory;", "noyes": "Again, the Devil taketh him m an exceeding high mountain, and showeth him all the kingdoms of the world, and their glory;", "webster": "Again, the devil taketh him up upon an exceeding high mountain, and showeth him all the kingdoms of the world, and the glory of them,", "vulgate": "iterum adsumit eum diabolus in montem excelsum valde et ostendit ei omnia regna mundi et gloriam eorum;"}}, {"v": 9, "ref": "4:9", "o": "καὶ ⸀εἶπεν αὐτῷ· Ταῦτά ⸂σοι πάντα⸃ δώσω, ἐὰν πεσὼν προσκυνήσῃς μοι.", "en": {"kjv": "And saith unto him, All these things will I give thee, if thou wilt fall down and worship me.", "web": "He said to him, “I will give you all of these things, if you will fall down and worship me.”", "bsb": "“All this I will give You,” he said, “if You will fall down and worship me.”", "asv": "and he said unto him, All these things will I give thee, if thou wilt fall down and worship me.", "ylt": "and saith to him, `All these to thee I will give, if falling down thou mayest bow to me.'", "tyndale": "and sayde to hym: all these will I geue ye if thou wilt faull doune and worship me.", "dra": "And said to him: All these will I give thee, if falling down thou wilt adore me.", "bbe": "And he said to him, All these things will I give you, if you will go down on your face and give me worship.", "geneva": "And sayd to him, All these will I giue thee, if thou wilt fall downe, and worship me.", "wycliffe": "and seide to hym, Alle these `Y schal yyue to thee, if thou falle doun and worschipe me.", "rotherham": "and said to him, All these things, will I give thee,—if thou wilt fall down and worship me.", "weymouth": "and said to Him, \"All this I will give you, if you will kneel down and do me homage.\"", "darby": "and says to him, All these things will I give thee if, falling down, thou wilt do me homage.", "twenty": "“All these I will give you, if you will fall at my feet and do homage to me.”", "acv": "And he says to him, All these things I give thee, if after falling down, thou will worship me.", "anderson": "and said to him: All these things will I give you, if you will fall down and worship me.", "haweis": "and saith unto him, All these things will I give thee, if thou wilt fall prostrate and worship me.", "noyes": "and said to him, All these things will I give thee, if thou wilt fall down and worship me.", "webster": "And saith to him, All these things will I give thee, if thou wilt fall down and worship me.", "vulgate": "et dixit illi haec tibi omnia dabo si cadens adoraveris me;"}}, {"v": 10, "ref": "4:10", "o": "τότε λέγει αὐτῷ ὁ Ἰησοῦς· ⸀Ὕπαγε, Σατανᾶ· γέγραπται γάρ· Κύριον τὸν θεόν σου προσκυνήσεις καὶ αὐτῷ μόνῳ λατρεύσεις.", "en": {"kjv": "Then saith Jesus unto him, Get thee hence, Satan: for it is written, Thou shalt worship the Lord thy God, and him only shalt thou serve.", "web": "Then Jesus said to him, “Get behind me,Satan! For it is written, ‘You shall worship the Lord your God, and you shall serve him only.’”", "bsb": "“Away from Me, Satan!” Jesus declared. “For it is written: ‘Worship the Lord your God and serve Him only.’”", "asv": "Then saith Jesus unto him, Get thee hence, Satan: for it is written, Thou shalt worship the Lord thy God, and him only shalt thou serve.", "ylt": "Then saith Jesus to him, `Go--Adversary, for it hath been written, The Lord thy God thou shalt bow to, and Him only thou shalt serve.'", "tyndale": "Then sayde Iesus vnto hym. Avoyd Satan. For it is writte thou shalt worshyp ye Lorde thy God and hym only shalt thou serve.", "dra": "Then Jesus saith to him: Begone, Satan: for it is written: The Lord thy God shalt thou adore, and him only shalt thou serve.", "bbe": "Then said Jesus to him, Away, Satan: for it is in the Writings, Give worship to the Lord your God and be his servant only.", "geneva": "Then sayd Iesus vnto him, Auoyde Satan: for it is written, Thou shalt worship the Lord thy God, and him onely shalt thou serue.", "wycliffe": "Thanne Jhesus seide to hym, Goo, Sathanas; for it is writun, Thou schalt worschipe thi Lord God, and to hym aloone thou shalt serue.", "rotherham": "Then saith Jesus unto him, Withdraw, Satan! for it is written,—The Lord thy God, shalt thou worship, and, to him alone, render divine service.", "weymouth": "\"Begone, Satan!\" Jesus replied; \"for it is written, `To the Lord thy God thou shalt do homage, and to Him alone shalt thou render worship.'\"", "darby": "Then says Jesus to him, Get thee away, Satan, for it is written, Thou shalt do homage to [the] Lord thyGod, and him alone shalt thou serve.", "twenty": "Then Jesus said to him: “Begone, Satan! for Scripture says — ‘Thou shalt do homage to the Lord thy God, and worship him only.’”", "acv": "Then Jesus says to him, Get thee behind me, Satan, for it is written, Thou shall worship the Lord thy God, and him only thou shall serve.", "anderson": "Then Jesus said to him: Get behind me, Satan, for it is written: You shall worship the Lord your God, and him only shall you serve.", "haweis": "Then saith Jesus unto him, Avaunt Satan! for it is written, “Thou shalt worship the Lord thy God, and to him only thou pay divine adoration.”", "noyes": "Then saith Jesus to him, Be gone, Satan! for it is written, \"Thou shalt worship the Lord thy God, and him only shalt thou serve.\"", "webster": "Then saith Jesus to him, Be gone, Satan: for it is written, Thou shalt worship the Lord thy God, and him only shalt thou serve.", "vulgate": "tunc dicit ei Iesus vade Satanas scriptum est Dominum Deum tuum adorabis et illi soli servies;"}}, {"v": 11, "ref": "4:11", "o": "τότε ἀφίησιν αὐτὸν ὁ διάβολος, καὶ ἰδοὺ ἄγγελοι προσῆλθον καὶ διηκόνουν αὐτῷ.", "en": {"kjv": "Then the devil leaveth him, and, behold, angels came and ministered unto him.", "web": "Then the devil left him, and behold, angels came and served him.", "bsb": "Then the devil left Him, and angels came and ministered to Him.", "asv": "Then the devil leaveth him; and behold, angels came and ministered unto him.", "ylt": "Then doth the Devil leave him, and lo, messengers came and were ministering to him.", "tyndale": "Then the dyvell left hym and beholde the angels came and ministred vnto hym.", "dra": "Then the devil left him; and behold angels came and ministered to him.", "bbe": "Then the Evil One went away from him, and angels came and took care of him.", "geneva": "Then the deuill left him: and beholde, the Angels came, and ministred vnto him.", "wycliffe": "Thanne the feend lafte hym; and lo! aungels camen nyy, and serueden to hym.", "rotherham": "Then, the adversary leaveth him,—and lo! messengers came near, and began ministering unto him.", "weymouth": "Thereupon the Devil left Him, and angels at once came and ministered to Him.", "darby": "Then the devil leaves him, and behold, angels came and ministered to him.", "twenty": "Then the Devil left him alone, and angels came and ministered to him.", "acv": "Then the devil leaves him, and behold, agents came and served him.", "anderson": "Then the devil left him, and behold, angels came and ministered to him.", "haweis": "Then the devil leaveth him, and lo! angels came and ministered unto him.", "noyes": "Then the Devil leaveth him; and lo! angels came and ministered to him.", "webster": "Then the devil leaveth him, and behold, angels came and ministered to him.", "vulgate": "tunc reliquit eum diabolus et ecce angeli accesserunt et ministrabant ei;"}}, {"v": 12, "ref": "4:12", "o": "Ἀκούσας ⸀δὲ ὅτι Ἰωάννης παρεδόθη ἀνεχώρησεν εἰς τὴν Γαλιλαίαν.", "en": {"kjv": "Now when Jesus had heard that John was cast into prison, he departed into Galilee;", "web": "Now when Jesus heard that John was delivered up, he withdrew into Galilee.", "bsb": "When Jesus heard that John had been imprisoned, He withdrew to Galilee.", "asv": "Now when he heard that John was delivered up, he withdrew into Galilee;", "ylt": "And Jesus having heard that John was delivered up, did withdraw to Galilee,", "tyndale": "When Iesus had hearde yt Ihon was taken he departed into Galile", "dra": "And when Jesus had heard that John was delivered up, he retired into Galilee:", "bbe": "Now when it came to his ears that John had been put in prison, he went away to Galilee;", "geneva": "And when Iesus had heard that Iohn was committed to prison, he returned into Galile.", "wycliffe": "But whanne Jhesus hadde herd that Joon was takun, he wente in to Galilee.", "rotherham": "And, hearing that, John, had been delivered up, he retired into Galilee;", "weymouth": "Now when Jesus heard that John was thrown into prison, He withdrew into Galilee,", "darby": "But having heard that John was delivered up, he departed into Galilee:", "twenty": "When Jesus heard that John had been committed to prison, he retired to Galilee.", "acv": "Now when Jesus heard that John was delivered up, he departed into Galilee.", "anderson": "Now when Jesus heard that John was delivered up; he withdrew into Galilee;", "haweis": "But when Jesus heard that John was cast into prison, he retired into Galilee;", "noyes": "Now when Jesus heard that John had been cast into prison, he withdrew into Galilee.", "webster": "Now when Jesus had heard that John was cast into prison, he departed into Galilee.", "vulgate": "cum autem audisset quod Iohannes traditus esset secessit in Galilaeam;"}}, {"v": 13, "ref": "4:13", "o": "καὶ καταλιπὼν τὴν Ναζαρὰ ἐλθὼν κατῴκησεν εἰς Καφαρναοὺμ τὴν παραθαλασσίαν ἐν ὁρίοις Ζαβουλὼν καὶ Νεφθαλίμ·", "en": {"kjv": "And leaving Nazareth, he came and dwelt in Capernaum, which is upon the sea coast, in the borders of Zabulon and Nephthalim:", "web": "Leaving Nazareth, he came and lived in Capernaum, which is by the sea, in the region of Zebulun and Naphtali,", "bsb": "Leaving Nazareth, He went and lived in Capernaum, which is by the sea in the region of Zebulun and Naphtali,", "asv": "and leaving Nazareth, he came and dwelt in Capernaum, which is by the sea, in the borders of Zebulun and Naphtali:", "ylt": "and having left Nazareth, having come, he dwelt at Capernaum that is by the sea, in the borders of Zebulun and Naphtalim,", "tyndale": "and left Nazareth and went and dwelte in Capernaum which is a cite apon the see in ye coostes of zabulon and Neptalim", "dra": "And leaving the city Nazareth, he came and dwelt in Capharnaum on the sea coast, in the borders of Zabulon and of Nephthalim;", "bbe": "And going away from Nazareth, he came and made his living-place in Capernaum, which is by the sea, in the country of Zebulun and Naphtali:", "geneva": "And leauing Nazareth, went and dwelt in Capernaum, which is neere the sea in the borders of Zabulon and Nephthalim,", "wycliffe": "And he lefte the citee of Nazareth, and cam, and dwelte in the citee of Cafarnaum, biside the see, in the coostis of Zabulon and Neptalym,", "rotherham": "and, forsaking Nazareth, he came and fixed his dwelling in Capernaum, which was by the lake,—within the bounds of Zebulun and Naphtali:", "weymouth": "and leaving Nazareth He went and settled at Capernaum, a town by the Lake on the frontiers of Zebulun and Naphtali,", "darby": "and having left Nazareth, he went and dwelt at Capernaum, which is on the sea-side in the borders of Zabulon and Nepthalim,", "twenty": "Afterwards, leaving Nazareth, he went and settled at Capernaum, which is by the side of the Sea, within the borders of Zebulun and Naphtali;", "acv": "And having left Nazareth behind, after coming, he dwelt in Capernaum by the sea in the regions of Zebulun and Naphtali,", "anderson": "and, leaving Nazareth, he went and dwelt in Capernaum, which is upon the sea, in the borders of Zebulon and Naphtali,", "haweis": "and leaving Nazareth, he came and resided at Capernaum, a maritime city, on the confines of Zebulun and Nephthali:", "noyes": "And leaving Nazara, he came and dwelt in Capernaum, on the shore of the lake, in the borders of Zebulun and Naphtali;", "webster": "And leaving Nazareth, he came and dwelt in Capernaum, which is upon the sea coast, in the borders of Zabulon and Nephthalim;", "vulgate": "et relicta civitate Nazareth venit et habitavit in Capharnaum maritimam in finibus Zabulon et Nepthalim;"}}, {"v": 14, "ref": "4:14", "o": "ἵνα πληρωθῇ τὸ ῥηθὲν διὰ Ἠσαΐου τοῦ προφήτου λέγοντος·", "en": {"kjv": "That it might be fulfilled which was spoken by Esaias the prophet, saying,", "web": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "bsb": "to fulfill what was spoken through the prophet Isaiah:", "asv": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "ylt": "that it might be fulfilled that was spoken through Isaiah the prophet, saying,", "tyndale": "to fulfill that whiche was spoken by Esay the Prophet sayinge:", "dra": "That it might be fulfilled which was said by Isaias the prophet:", "bbe": "So that the word of the prophet Isaiah might come true,", "geneva": "That it might be fulfilled which was spoken by Esaias the Propet, saying,", "wycliffe": "that it shulde be fulfillid, that was seid by Ysaie, the profete, seiynge,", "rotherham": "that it might be fulfilled, which was spoken through Isaiah the prophet, saying:", "weymouth": "in order that these words, spoken through the Prophet Isaiah, might be fulfilled,", "darby": "that that might be fulfilled which was spoken through Esaias the prophet, saying,", "twenty": "in fulfilment of these words in the Prophet Isaiah —", "acv": "so that what was spoken through Isaiah the prophet might be fulfilled, which says,", "anderson": "that the word might be fulfilled which was spoken by Isaiah the prophet, saying:", "haweis": "that what was spoken by the prophet Isaiah might be fulfilled, saying,", "noyes": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "webster": "That it might be fulfilled which was spoken by Isaiah the prophet, saying,", "vulgate": "ut adimpleretur quod dictum est per Esaiam prophetam;"}}, {"v": 15, "ref": "4:15", "o": "Γῆ Ζαβουλὼν καὶ γῆ Νεφθαλίμ, ὁδὸν θαλάσσης, πέραν τοῦ Ἰορδάνου, Γαλιλαία τῶν ἐθνῶν,", "en": {"kjv": "The land of Zabulon, and the land of Nephthalim, by the way of the sea, beyond Jordan, Galilee of the Gentiles;", "web": "“The land of Zebulun and the land of Naphtali, toward the sea, beyond the Jordan, Galilee of the Gentiles,", "bsb": "“Land of Zebulun and land of Naphtali, the Way of the Sea, beyond the Jordan, Galilee of the Gentiles—", "asv": "The land of Zebulun and the land of Naphtali, Toward the sea, beyond the Jordan, Galilee of the Gentiles,", "ylt": "`Land of Zebulun and land of Naphtali, way of the sea, beyond the Jordan, Galilee of the nations! --", "tyndale": "The londe of zabulon and Neptalim the waye of the see beyonde Iordan Galile of the Gentyls", "dra": "Land of Zabulon and land of Nephthalim, the way of the sea beyond the Jordan, Galilee of the Gentiles:", "bbe": "The land of Zebulun and the land of Naphtali, by the way of the sea, the other side of Jordan, Galilee of the Gentiles,", "geneva": "The land of Zabulon, and the land of Nephthalim by the way of the sea, beyond Iordan, Galile of the Gentiles:", "wycliffe": "The lond of Sabulon and the lond of Neptalym, the weie of the see ouer Jordan, of Galilee of hethen men,", "rotherham": "Land of Zebulun, and land of Naphtali, the lake-way across the Jordan,—Galilee of the nations,", "weymouth": "\"Zebulun's land and Naphtali's land; the road by the Lake; the country beyond the Jordan; Galilee of the Nations!", "darby": "Land of Zabulon and land of Nepthalim, way of [the] sea beyond the Jordan, Galilee of the nations:", "twenty": "‘The land of Zebulun and the land of Naphtali, the land of the Road by the Sea, and beyond the Jordan, with Galilee of the Gentiles —", "acv": "The land of Zebulun and the land of Naphtali, way of the sea, beyond the Jordan, Galilee of the Gentiles,", "anderson": "The land of Zebulon, and the land of Naphtali, toward the sea beyond the Jordan, Galilee of the Gentiles;", "haweis": "“The land of Zabulun, and the land of Naphthali, the road to the sea, beyond Jordan, Galilee of the Gentiles;", "noyes": "\"The land of Zebulun, and the land of Naphtali, by the way of the lake beyond the Jordan, Galilee of the Gentiles,", "webster": "The land of Zabulon, and the land of Nephthalim, [by] the way of the sea, beyond Jordan, Galilee of the Gentiles:", "vulgate": "terra Zabulon et terra Nepthalim via maris trans Iordanen Galilaeae gentium;"}}, {"v": 16, "ref": "4:16", "o": "ὁ λαὸς ὁ καθήμενος ἐν ⸀σκοτίᾳ ⸂φῶς εἶδεν⸃ μέγα, καὶ τοῖς καθημένοις ἐν χώρᾳ καὶ σκιᾷ θανάτου φῶς ἀνέτειλεν αὐτοῖς.", "en": {"kjv": "The people which sat in darkness saw great light; and to them which sat in the region and shadow of death light is sprung up.", "web": "the people who sat in darkness saw a great light, to those who sat in the region and shadow of death, to them light has dawned.”", "bsb": "the people living in darkness have seen a great light; on those living in the land of the shadow of death, a light has dawned.”", "asv": "The people that sat in darkness Saw a great light, And to them that sat in the region and shadow of death, To them did light spring up.", "ylt": "the people that is sitting in darkness saw a great light, and to those sitting in a region and shadow of death--light arose to them.'", "tyndale": "ye people which sat in darknes sawe greate lyght and to them which sate in the region and shadowe of deeth lyght is begone to shyne.", "dra": "The people that sat in darkness, hath seen great light: and to them that sat in the region of the shadow of death, light is sprung up.", "bbe": "The people who were in the dark saw a great light, and to those in the land of the shade of death did the dawn come up.", "geneva": "The people which sate in darkenes, sawe great light: and to them which sate in the region, and shadowe of death, light is risen vp.", "wycliffe": "the puple that walkide in derknessis saye greet liyt, and while men satten in the cuntre of shadewe of deth, liyt aroos to hem.", "rotherham": "The people that was sitting in darkness, a great light, beheld,—and, on them who were sitting in land and shade of death, Light rose on them.", "weymouth": "The people who were dwelling in darkness have seen a brilliant light; and on those who were dwelling in the region of the shadow of death, on them light has dawned.\"", "darby": "— the people sitting in darkness has seen a great light, and to those sitting in [the] country and shadow of death, to them has light sprung up.", "twenty": "The people who were dwelling in darkness have seen a great Light, and, for those who were dwelling in the shadow-land of Death, a Light has risen!’", "acv": "the people who dwell in darkness saw a great light, and to those who dwell in the region and shadow of death, light sprang up to them.", "anderson": "the people that sat in darkness saw great light; and upon those who sat in the region and shadow of death light has risen.", "haweis": "the people who sat in darkness saw a great light; and on those who sat in the region and shadow of death, even on them hath the light arisen.”", "noyes": "the people that sat in darkness, saw a great light; and upon those who sat in the region and shadow of death, light arose.\"", "webster": "The people who sat in darkness, saw great light; and to them who sat in the region and shades of death, light hath arisen.", "vulgate": "populus qui sedebat in tenebris lucem vidit magnam et sedentibus in regione et umbra mortis lux orta est eis;"}}, {"v": 17, "ref": "4:17", "o": "Ἀπὸ τότε ἤρξατο ὁ Ἰησοῦς κηρύσσειν καὶ λέγειν· Μετανοεῖτε, ἤγγικεν γὰρ ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "From that time Jesus began to preach, and to say, Repent: for the kingdom of heaven is at hand.", "web": "From that time, Jesus began to preach, and to say, “Repent! For the Kingdom of Heaven is at hand.”", "bsb": "From that time on Jesus began to preach, “Repent, for the kingdom of heaven is near.”", "asv": "From that time began Jesus to preach, and to say, Repent ye; for the kingdom of heaven is at hand.", "ylt": "From that time began Jesus to proclaim and to say, `Reform ye, for come nigh hath the reign of the heavens.'", "tyndale": "From yt tyme Iesus begane to preache and to saye: repet for ye kigdome of heve is at hode.", "dra": "From that time Jesus began to preach, and to say: Do penance, for the kingdom of heaven is at hand.", "bbe": "From that time Jesus went about preaching and saying, Let your hearts be turned from sin, for the kingdom of heaven is near.", "geneva": "From that time Iesus began to preach, and to say, Amende your liues: for the kingdome of heauen is at hand.", "wycliffe": "Fro that tyme Jhesus bigan to preche, and seie, Do ye penaunce, for the kyngdom of heuenes schal come niy.", "rotherham": "From that time, began Jesus to be making proclamation, and saying,—Repent ye, for the kingdom of the heavens hath drawn near.", "weymouth": "From that time Jesus began to preach. \"Repent,\" He said, \"for the Kingdom of the Heavens is now close at hand.\"", "darby": "From that time began Jesus to preach and to say, Repent, for the kingdom of the heavens has drawn nigh.", "twenty": "At that time Jesus began to proclaim — “Repent, for the Kingdom of Heaven is at hand.”", "acv": "From that time Jesus began to preach, and to say, Repent ye, for the kingdom of the heavens has approached.", "anderson": "From that time Jesus began to preach and to say: Repent, for the kingdom of heaven is at hand.", "haweis": "From that time Jesus began to preach, and to say, Repent, for the kingdom of heaven is approaching.", "noyes": "From that time Jesus began to preach, and to say, Repent; for the kingdom of heaven is at hand.", "webster": "From that time Jesus began to preach, and to say, Repent: for the kingdom of heaven is at hand.", "vulgate": "exinde coepit Iesus praedicare et dicere paenitentiam agite adpropinquavit enim regnum caelorum;"}}, {"v": 18, "ref": "4:18", "o": "Περιπατῶν δὲ παρὰ τὴν θάλασσαν τῆς Γαλιλαίας εἶδεν δύο ἀδελφούς, Σίμωνα τὸν λεγόμενον Πέτρον καὶ Ἀνδρέαν τὸν ἀδελφὸν αὐτοῦ, βάλλοντας ἀμφίβληστρον εἰς τὴν θάλασσαν, ἦσαν γὰρ ἁλιεῖς·", "en": {"kjv": "And Jesus, walking by the sea of Galilee, saw two brethren, Simon called Peter, and Andrew his brother, casting a net into the sea: for they were fishers.", "web": "Walking by the sea of Galilee, he saw two brothers: Simon, who is called Peter, and Andrew, his brother, casting a net into the sea; for they were fishermen.", "bsb": "As Jesus was walking beside the Sea of Galilee, He saw two brothers, Simon called Peter and his brother Andrew. They were casting a net into the sea, for they were fishermen.", "asv": "And walking by the sea of Galilee, he saw two brethren, Simon who is called Peter, and Andrew his brother, casting a net into the sea; for they were fishers.", "ylt": "And Jesus, walking by the sea of Galilee, saw two brothers, Simon named Peter and Andrew his brother, casting a drag into the sea--for they were fishers--", "tyndale": "As Iesus walked by the see of Galile he sawe two brethren: Simon which was called Peter and Andrew his brother castynge a neet into the see for they were fisshers", "dra": "And Jesus walking by the sea of Galilee, saw two brethren, Simon who is called Peter, and Andrew his brother, casting a net into the sea (for they were fishers).", "bbe": "And when he was walking by the sea of Galilee, he saw two brothers, Simon, whose other name was Peter, and Andrew, his brother, who were putting a net into the sea; for they were fishermen.", "geneva": "And Iesus walking by the sea of Galile, sawe two brethren, Simon, which was called Peter, and Andrew his brother, casting a net into the sea (for they were fishers.)", "wycliffe": "And Jhesus walkide bisidis the see of Galilee, and saye twei britheren, Symount, that is clepid Petre, and Andrewe, his brothir, castynge nettis in to the see; for thei weren fischeris.", "rotherham": "And, walking round beside the sea of Galilee, he saw two brethren—Simon who is called Peter, and Andrew his brother,—casting a large fishing-net into the sea, for they were fishers;", "weymouth": "And walking along the shore of the Lake of Galilee He saw two brothers--Simon called Peter and his brother Andrew--throwing a drag-net into the Lake; for they were fishers.", "darby": "And walking by the sea of Galilee, he saw two brothers, Simon called Peter, and Andrew his brother, casting a net into the sea, for they were fishers;", "twenty": "As Jesus was walking along the shore of the Sea of Galilee, he saw two brothers — Simon, also known as Peter, and his brother Andrew — casting a net into the Sea; for they were fishermen.", "acv": "And walking by the sea of Galilee, he saw two brothers, Simon who is called Peter, and Andrew his brother, casting a net into the sea, for they were fishermen.", "anderson": "And as he was walking by the sea of Galilee, he saw two brothers, Simon who is called Peter, and Andrew his brother, throwing a net into the sea, for they were fishers.", "haweis": "And as Jesus was walking by the sea of Galilee, he saw two brothers, Simon who is called Peter, and Andrew his brother, casting a net into the sea, for they were fishermen.", "noyes": "And while walking by the lake of Galilee, he saw two brothers, Simon called Peter, and Andrew his brother, casting a net into the lake; for they were fishers.", "webster": "And Jesus, walking by the sea of Galilee, saw two brethren, Simon called Peter, and Andrew his brother, casting a net into the sea: for they were fishers.", "vulgate": "ambulans autem iuxta mare Galilaeae vidit duos fratres Simonem qui vocatur Petrus et Andream fratrem eius mittentes rete in mare erant enim piscatores;"}}, {"v": 19, "ref": "4:19", "o": "καὶ λέγει αὐτοῖς· Δεῦτε ὀπίσω μου, καὶ ποιήσω ὑμᾶς ἁλιεῖς ἀνθρώπων.", "en": {"kjv": "And he saith unto them, Follow me, and I will make you fishers of men.", "web": "He said to them, “Come after me, and I will make you fishers for men.”", "bsb": "“Come, follow Me,” Jesus said, “and I will make you fishers of men.”", "asv": "And he saith unto them, Come ye after me, and I will make you fishers of men.", "ylt": "and he saith to them, `Come ye after me, and I will make you fishers of men,'", "tyndale": "and he sayde vnto them folowe me and I will make you fisshers of men.", "dra": "And he saith to them: Come ye after me, and I will make you to be fishers of men.", "bbe": "And he said to them, Come after me, and I will make you fishers of men.", "geneva": "And he sayd vnto them, Follow me, and I will make you fishers of men.", "wycliffe": "And he seide to hem, Come ye aftir me, and Y shal make you to be maad fisscheris of men.", "rotherham": "and he saith unto them, Come after me,—and I will make you fishers, of men.", "weymouth": "And He said to them, \"Come and follow me, and I will make you fishers of men.\"", "darby": "and he says to them, Come after me, and I will make you fishers of men.", "twenty": "“Come and follow me,” Jesus said, “and I will set you to fish for men.”", "acv": "And he says to them, Come behind me, and I will make you fishermen of men.", "anderson": "And he said to them: Come after me, and I will make you fishers of men.", "haweis": "And he saith to them, Follow me, and I will make you fishers of men.", "noyes": "And he saith to them, Come after me, and I will make you fishers of men.", "webster": "And he saith to them, Follow me, and I will make you fishers of men.", "vulgate": "et ait illis venite post me et faciam vos fieri piscatores hominum;"}}, {"v": 20, "ref": "4:20", "o": "οἱ δὲ εὐθέως ἀφέντες τὰ δίκτυα ἠκολούθησαν αὐτῷ.", "en": {"kjv": "And they straightway left their nets, and followed him.", "web": "They immediately left their nets and followed him.", "bsb": "And at once they left their nets and followed Him.", "asv": "And they straightway left the nets, and followed him.", "ylt": "and they, immediately, having left the nets, did follow him.", "tyndale": "And they strayght waye lefte their nettes and folowed hym.", "dra": "And they immediately leaving their nets, followed him.", "bbe": "And straight away they let go the nets and went after him.", "geneva": "And they straightway leauing the nets, folowed him.", "wycliffe": "And anoon thei leften the nettis, and sueden hym.", "rotherham": "And, they, straightway, leaving the nets, followed him.", "weymouth": "So they immediately left their nets and followed Him. As He went further on,", "darby": "And they, having left their trawl-nets, immediately followed him.", "twenty": "The two men left their nets at once and followed him.", "acv": "And straightaway having left the nets, they followed him.", "anderson": "And they immediately left their nets and followed him.", "haweis": "Then immediately quitting their nets they followed him.", "noyes": "And they immediately left their nets, and followed him.", "webster": "And they immediately left [their] nets, and followed him.", "vulgate": "at illi continuo relictis retibus secuti sunt eum;"}}, {"v": 21, "ref": "4:21", "o": "Καὶ προβὰς ἐκεῖθεν εἶδεν ἄλλους δύο ἀδελφούς, Ἰάκωβον τὸν τοῦ Ζεβεδαίου καὶ Ἰωάννην τὸν ἀδελφὸν αὐτοῦ, ἐν τῷ πλοίῳ μετὰ Ζεβεδαίου τοῦ πατρὸς αὐτῶν καταρτίζοντας τὰ δίκτυα αὐτῶν, καὶ ἐκάλεσεν αὐτούς.", "en": {"kjv": "And going on from thence, he saw other two brethren, James the son of Zebedee, and John his brother, in a ship with Zebedee their father, mending their nets; and he called them.", "web": "Going on from there, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. He called them.", "bsb": "Going on from there, He saw two other brothers, James son of Zebedee and his brother John. They were in a boat with their father Zebedee, mending their nets. Jesus called them,", "asv": "And going on from thence he saw two other brethren, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets; and he called them.", "ylt": "And having advanced thence, he saw other two brothers, James of Zebedee, and John his brother, in the boat with Zebedee their father, refitting their nets, and he called them,", "tyndale": "And he went forthe from thence and sawe other twoo brethren Iames the sonne of zebede and Ihon his brother in the shippe with zebede their father mendynge their nettes and called them.", "dra": "And going on from thence, he saw other two brethren, James the son of Zebedee, and John his brother, in a ship with Zebedee their father, mending their nets: and he called them.", "bbe": "And going on from there he saw two other brothers, James, the son of Zebedee, and John, his brother, in the boat with their father, stitching up their nets; and he said, Come.", "geneva": "And when he was gone forth from thence, he saw other two brethren, Iames the sonne of Zebedeus, and Iohn his brother in a ship with Zebedeus their father, mending their nets, and he called them.", "wycliffe": "And he yede forth fro that place, and saie tweyne othere britheren, James of Zebede, and Joon, his brother, in a schip with Zebede, her fadir, amendynge her nettis, and he clepide hem.", "rotherham": "And, going forward from thence, he saw other two brethren—James the son of Zebedee, and John his brother—in the boat with Zebedee their father, putting in order their nets,—and he called them.", "weymouth": "He saw two other brothers, James the son of Zabdi and his brother John, in the boat with their father Zabdi mending their nets; and He called them.", "darby": "And going on thence he saw other two brothers, James the [son] of Zebedee and John his brother, in the ship with Zebedee their father, mending their trawl-nets, and he called them;", "twenty": "Going further on, he saw two other men who were also brothers, James, Zebediah’s son, and his brother John, in their boat with their father, mending their nets. Jesus called them,", "acv": "And having gone on from there he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. And he called them.", "anderson": "And going on thence, he saw other two brothers, James the son of Zebedee, and John his brother, in the ship with Zebedee their father, mending their nets; and he called them.", "haweis": "And going on from thence, he saw two other brothers, James son of Zebedee, and John his brother, in a boat with Zebedee their father, mending their nets; and he called them.", "noyes": "And going on from thence, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets; and he called them.", "webster": "And going on from thence, he saw other two brethren, James [the son] of Zebedee, and John his brother, in a boat with Zebedee their father, mending their nets: and he called them.", "vulgate": "et procedens inde vidit alios duos fratres Iacobum Zebedaei et Iohannem fratrem eius in navi cum Zebedaeo patre eorum reficientes retia sua et vocavit eos;"}}, {"v": 22, "ref": "4:22", "o": "οἱ δὲ εὐθέως ἀφέντες τὸ πλοῖον καὶ τὸν πατέρα αὐτῶν ἠκολούθησαν αὐτῷ.", "en": {"kjv": "And they immediately left the ship and their father, and followed him.", "web": "They immediately left the boat and their father, and followed him.", "bsb": "and immediately they left the boat and their father and followed Him.", "asv": "And they straightway left the boat and their father, and followed him.", "ylt": "and they, immediately, having left the boat and their father, did follow him.", "tyndale": "And they with out taryinge lefte the shyp and their father and folowed hym.", "dra": "And they forthwith left their nets and father, and followed him.", "bbe": "And they went straight from the boat and their father and came after him.", "geneva": "And they without tarying, leauing the ship, and their father, folowed him.", "wycliffe": "And anoon thei leften the nettis and the fadir, and sueden hym.", "rotherham": "And, they, straightway, leaving the boat and their father, followed him.", "weymouth": "And they at once left the boat and their father, and followed Him.", "darby": "and they, having left the ship and their father, immediately followed him.", "twenty": "and they at once left their boat and their father, and followed him.", "acv": "And straightaway having left the boat and their father, they followed him.", "anderson": "And they immediately left the ship and their father, and followed him.", "haweis": "Then they instantly quitting the ship and their father, followed him.", "noyes": "And they immediately left the boat and their father, and followed him.", "webster": "And they immediately left the boat, and their father, and followed him.", "vulgate": "illi autem statim relictis retibus et patre secuti sunt eum;"}}, {"v": 23, "ref": "4:23", "o": "Καὶ περιῆγεν ⸂ἐν ὅλῃ τῇ Γαλιλαίᾳ⸃, διδάσκων ἐν ταῖς συναγωγαῖς αὐτῶν καὶ κηρύσσων τὸ εὐαγγέλιον τῆς βασιλείας καὶ θεραπεύων πᾶσαν νόσον καὶ πᾶσαν μαλακίαν ἐν τῷ λαῷ.", "en": {"kjv": "And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of sickness and all manner of disease among the people.", "web": "Jesus went about in all Galilee, teaching in their synagogues, preaching the Good News of the Kingdom, and healing every disease and every sickness among the people.", "bsb": "Jesus went throughout Galilee, teaching in their synagogues, preaching the gospel of the kingdom, and healing every disease and sickness among the people.", "asv": "And Jesus went about in all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of disease and all manner of sickness among the people.", "ylt": "And Jesus was going about all Galilee teaching in their synagogues, and proclaiming the good news of the reign, and healing every disease, and every malady among the people,", "tyndale": "And Iesus went aboute all Galile teachyng in their synagoges and preachynge ye gospell of the kyngdome and healed all maner of sicknes and all maner dyseases amoge ye people.", "dra": "And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom: and healing all manner of sickness and every infirmity, among the people.", "bbe": "And Jesus went about in all Galilee, teaching in their Synagogues and preaching the good news of the kingdom, and making well those who were ill with any disease among the people.", "geneva": "So Iesus went about all Galile, teaching in their Synagogues, and preaching the Gospel of the kingdome, and healing euery sicknesse and euery disease among the people.", "wycliffe": "And Jhesus yede aboute al Galilee, techynge in the synagogis of hem, and prechynge the gospel of the kyngdom, and heelynge euery languor and eche sekenesse among the puple.", "rotherham": "And Jesus was going round throughout all Galilee, teaching in their synagogues, and proclaiming the glad-message of the kingdom,—and curing every disease, and every infirmity, among the people.", "weymouth": "Then Jesus travelled through all Galilee, teaching in their synagogues and proclaiming the Good News of the Kingdom, and curing every kind of disease and infirmity among the people.", "darby": "And [Jesus] went round the whole [of] Galilee, teaching in their synagogues, and preaching the glad tidings of the kingdom, and healing every disease and every bodily weakness among the people.", "twenty": "And Jesus went all through Galilee, teaching in their Synagogues, proclaiming the Good News of the Kingdom, and curing every kind of disease and every kind of sickness among the people;", "acv": "And Jesus went around all Galilee, teaching in their synagogues, and preaching the good news of the kingdom, and healing every sickness and every disease among the people.", "anderson": "And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and curing every disease, and every kind of sickness among the people.", "haweis": "And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and healing every disease and every malady among the people.", "noyes": "And he went round the whole of Galilee, teaching in their synagogues, and preaching the glad tidings of the kingdom, and healing every sickness and every disease among the people.", "webster": "And Jesus went about all Galilee, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of sickness, and all manner of disease among the people.", "vulgate": "et circumibat Iesus totam Galilaeam docens in synagogis eorum et praedicans evangelium regni et sanans omnem languorem et omnem infirmitatem in populo;"}}, {"v": 24, "ref": "4:24", "o": "καὶ ἀπῆλθεν ἡ ἀκοὴ αὐτοῦ εἰς ὅλην τὴν Συρίαν· καὶ προσήνεγκαν αὐτῷ πάντας τοὺς κακῶς ἔχοντας ποικίλαις νόσοις καὶ βασάνοις ⸀συνεχομένους, δαιμονιζομένους καὶ σεληνιαζομένους καὶ παραλυτικούς, καὶ ἐθεράπευσεν αὐτούς.", "en": {"kjv": "And his fame went throughout all Syria: and they brought unto him all sick people that were taken with divers diseases and torments, and those which were possessed with devils, and those which were lunatick, and those that had the palsy; and he healed them.", "web": "The report about him went out into all Syria. They brought to him all who were sick, afflicted with various diseases and torments, possessed with demons, epileptics, and paralytics; and he healed them.", "bsb": "News about Him spread all over Syria, and people brought to Him all who were ill with various diseases, those suffering acute pain, the demon-possessed, those having seizures, and the paralyzed—and He healed them.", "asv": "And the report of him went forth into all Syria: and they brought unto him all that were sick, holden with divers diseases and torments, possessed with demons, and epileptic, and palsied; and he healed them.", "ylt": "and his fame went forth to all Syria, and they brought to him all having ailments, pressed with manifold sicknesses and pains, and demoniacs, and lunatics, and paralytics, and he healed them.", "tyndale": "And his fame spreed abroode through oute all Siria. And they brought vnto hym all sicke people that were taken with divers diseases and gripinges and them yt were possessed with devils and those which were lunatyke and those that had the palsie: and he healed the.", "dra": "And his fame went throughout all Syria, and they presented to him all sick people that were taken with divers diseases and torments, and such as were possessed by devils, and lunatics, and those that had the palsy, and he cured them:", "bbe": "And news of him went out through all Syria; and they took to him all who were ill with different diseases and pains, those having evil spirits and those who were off their heads, and those who had no power of moving. And he made them well.", "geneva": "And his fame spread abroad through all Syria: and they brought vnto him all sicke people, that were taken with diuers diseases and torments, and them that were possessed with deuils, and those which were lunatike, and those that had the palsey: and he healed them.", "wycliffe": "And his fame wente in to al Sirie; and thei brouyten to hym alle that weren at male ese, and that weren take with dyuerse languores and turmentis, and hem that hadden feendis, and lunatike men, and men in palesy, and he heelide hem.", "rotherham": "And forth went the report of him into all Syria; and they brought unto him all who were sick, with divers diseases and tortures, distressed, demonized and lunatic and paralyzed,—and he cured them.", "weymouth": "Thus His fame spread through all Syria; and they brought all the sick to Him, the people who were suffering from various diseases and pains--demoniacs, epileptics, paralytics; and He cured them.", "darby": "And his fame went out into the whole [of] Syria, and they brought to him all that were ill, suffering under various diseases and pains, and those possessed by demons, and lunatics, and paralytics; and he healed them.", "twenty": "and his fame spread all through Syria. They brought to him all who were ill with any form of disease, or who were suffering pain — any who were either possessed by demons, or were lunatic, or paralysed; and he cured them.", "acv": "And his fame went forth into all Syria. And they brought to him all those faring badly with various diseases, and gripped with pain, and being demon-possessed, and being lunatic, and paralyzed. And he healed them.", "anderson": "And his fame went abroad into all Syria. And they brought to him all that were sick, those who were afflicted with various diseases and pains, and those who were possessed with demons, and lunatics, and paralytics; and he cured them.", "haweis": "And there went out a report of him into all Syria: and they brought unto him all who had illness, the afflicted with various diseases and painful complaints, and the demoniacs, and lunatics, and paralytics; and he healed them.", "noyes": "And his fame went forth into all Syria; and they brought to him all that were sick, afflicted with various diseases and torments, and those who were possessed by demons, and lunatics, and those who were struck with palsy; and he healed them.", "webster": "And his fame spread throughout all Syria: and they brought to him all sick people that were taken with diverse diseases and torments, and those who were possessed with demons, and those who were lunatic, and those that had the palsy; and he healed them.", "vulgate": "et abiit opinio eius in totam Syriam et obtulerunt ei omnes male habentes variis languoribus et tormentis conprehensos et qui daemonia habebant et lunaticos et paralyticos et curavit eos;"}}, {"v": 25, "ref": "4:25", "o": "καὶ ἠκολούθησαν αὐτῷ ὄχλοι πολλοὶ ἀπὸ τῆς Γαλιλαίας καὶ Δεκαπόλεως καὶ Ἱεροσολύμων καὶ Ἰουδαίας καὶ πέραν τοῦ Ἰορδάνου.", "en": {"kjv": "And there followed him great multitudes of people from Galilee, and from Decapolis, and from Jerusalem, and from Judea, and from beyond Jordan.", "web": "Great multitudes from Galilee, Decapolis, Jerusalem, Judea and from beyond the Jordan followed him.", "bsb": "The large crowds that followed Him came from Galilee, the Decapolis, Jerusalem, Judea, and beyond the Jordan.", "asv": "And there followed him great multitudes from Galilee and Decapolis and Jerusalem and Judæa and from beyond the Jordan.", "ylt": "And there followed him many multitudes from Galilee, and Decapolis, and Jerusalem, and Judea, and beyond the Jordan.", "tyndale": "And ther folowed hym a greate nombre of people from Galile and from the ten cyties and from Ierusalem and from Iury and from ye regions that lye beyonde Iordan.", "dra": "And much people followed him from Galilee, and from Decapolis, and from Jerusalem, and from Judea, and from beyond the Jordan.", "bbe": "And there went after him great numbers from Galilee and Decapolis and Jerusalem and Judaea and from the other side of Jordan.", "geneva": "And there folowed him great multitudes out of Galile, and Decapolis, and Hierusalem, and Iudea, and from beyond Iordan.", "wycliffe": "And ther sueden hym myche puple of Galile, and of Decapoli, and of Jerusalem, and of Judee, and of biyende Jordan.", "rotherham": "And there followed him large multitudes—from Galilee, and Decapolis, and Jerusalem, and Judaea, and across the Jordan.", "weymouth": "And great crowds followed Him, coming from Galilee, from the Ten Towns, from Jerusalem, and from beyond the district on the other side of the Jordan.", "darby": "And great crowds followed him from Galilee, and Decapolis, and Jerusalem, and Judaea, and beyond the Jordan.", "twenty": "And he was followed by large crowds from Galilee, the district of the Ten Towns, Jerusalem, Judea, and from beyond the Jordan.", "acv": "And many multitudes from Galilee and Decapolis and Jerusalem and Judea and beyond the Jordan followed him.", "anderson": "And many multitudes followed him from Galilee, and Decapolis, and Jerusalem, and Judea, and from beyond the Jordan.", "haweis": "And great multitudes followed him from Galilee, and Decapolis, and Jerusalem, and Judea, and from beyond Jordan.", "noyes": "And great multitudes followed him from Galilee and Decapolis and Jerusalem and Judaea, and from beyond the Jordan.", "webster": "And there followed him great multitudes of people from Galilee, and [from] Decapolis, and [from] Jerusalem, and [from] Judea, and [from] beyond Jordan.", "vulgate": "et secutae sunt eum turbae multae de Galilaea et Decapoli et Hierosolymis et Iudaea et de trans Iordanen;"}}]}, {"c": 5, "verses": [{"v": 1, "ref": "5:1", "o": "Ἰδὼν δὲ τοὺς ὄχλους ἀνέβη εἰς τὸ ὄρος· καὶ καθίσαντος αὐτοῦ προσῆλθαν αὐτῷ οἱ μαθηταὶ αὐτοῦ·", "en": {"kjv": "And seeing the multitudes, he went up into a mountain: and when he was set, his disciples came unto him:", "web": "Seeing the multitudes, he went up onto the mountain. When he had sat down, his disciples came to him.", "bsb": "When Jesus saw the crowds, He went up on the mountain and sat down. His disciples came to Him,", "asv": "And seeing the multitudes, he went up into the mountain: and when he had sat down, his disciples came unto him:", "ylt": "And having seen the multitudes, he went up to the mount, and he having sat down, his disciples came to him,", "tyndale": "When he sawe the people he went vp into a mountayne and when he was set his disciples came to hym", "dra": "And seeing the multitudes, he went up into a mountain, and when he was set down, his disciples came unto him.", "bbe": "And seeing great masses of people he went up into the mountain; and when he was seated his disciples came to him.", "geneva": "And when he sawe the multitude, he went vp into a mountaine: and when he was set, his disciples came to him.", "wycliffe": "And Jhesus, seynge the puple, wente vp in to an hil; and whanne he was set, hise disciplis camen to hym.", "rotherham": "But, seeing the multitudes, he went up into a mountain,—and, when he had taken a seat, his disciples came unto him;", "weymouth": "Seeing the multitude of people, Jesus went up the Hill. There He seated Himself, and when His disciples came to Him,", "darby": "But seeing the crowds, he went up into the mountain, and having sat down, his disciples came to him;", "twenty": "On seeing the crowds of People, Jesus went up the hill; and, when he had taken his seat, his disciples came up to him;", "acv": "And having seen the multitudes, he went up onto the mountain. And when he sat down, his disciples came to him.", "anderson": "And seeing the multitudes, he went up into the mountain; and when he had sat down, his disciples came to him;", "haweis": "THEN seeing the multitudes, he went up into the mountain: and seating himself, his disciples came to him:", "noyes": "And seeing the multitudes, he went up into the mountain; and when he had sat down, his disciples came to him.", "webster": "And seeing the multitudes, he ascended a mountain: and when he was seated, his disciples came to him.", "vulgate": "videns autem turbas ascendit in montem et cum sedisset accesserunt ad eum discipuli eius;"}}, {"v": 2, "ref": "5:2", "o": "καὶ ἀνοίξας τὸ στόμα αὐτοῦ ἐδίδασκεν αὐτοὺς λέγων·", "en": {"kjv": "And he opened his mouth, and taught them, saying,", "web": "He opened his mouth and taught them, saying,", "bsb": "and He began to teach them, saying:", "asv": "and he opened his mouth and taught them, saying,", "ylt": "and having opened his mouth, he was teaching them, saying:", "tyndale": "and he opened hys mouthe and taught them sayinge:", "dra": "And opening his mouth he taught them, saying:", "bbe": "And with these words he gave them teaching, saying,", "geneva": "And he opened his mouth and taught them, saying,", "wycliffe": "And he openyde his mouth, and tauyte hem, and seide,", "rotherham": "and, opening his mouth, he began teaching them, saying:—", "weymouth": "He proceeded to teach them, and said:", "darby": "and, having opened his mouth, he taught them, saying,", "twenty": "and he began to teach them as follows:", "acv": "And having opened his mouth, he taught them, saying,", "anderson": "and he opened his mouth and taught them, saying:", "haweis": "and opening his mouth, he taught them, saying,", "noyes": "And he opened his mouth, and taught them, saying:—", "webster": "And he opened his mouth, and taught them, saying,", "vulgate": "et aperiens os suum docebat eos dicens;"}}, {"v": 3, "ref": "5:3", "o": "Μακάριοι οἱ πτωχοὶ τῷ πνεύματι, ὅτι αὐτῶν ἐστιν ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "Blessed are the poor in spirit: for theirs is the kingdom of heaven.", "web": "“Blessed are the poor in spirit, for theirs is the Kingdom of Heaven.", "bsb": "“Blessed are the poor in spirit, for theirs is the kingdom of heaven.", "asv": "Blessed are the poor in spirit: for theirs is the kingdom of heaven.", "ylt": "`Happy the poor in spirit--because theirs is the reign of the heavens.", "tyndale": "Blessed are the povre in sprete: for theirs is the kyngdome of heven.", "dra": "Blessed are the poor in spirit: for theirs is the kingdom of heaven.", "bbe": "Happy are the poor in spirit: for the kingdom of heaven is theirs.", "geneva": "Blessed are the poore in spirit, for theirs is the kingdome of heauen.", "wycliffe": "Blessed ben pore men in spirit, for the kyngdom of heuenes is herne.", "rotherham": "Happy, the destitute, in spirit; for, theirs, is the kingdom of the heavens;", "weymouth": "\"Blessed are the poor in spirit, for to them belongs the Kingdom of the Heavens.", "darby": "Blessed [are] the poor in spirit, for theirs is the kingdom of the heavens.", "twenty": "“Blessed are the poor in spirit, for theirs is the Kingdom of Heaven.", "acv": "Blessed are the poor in spirit, because the kingdom of the heavens is theirs.", "anderson": "Blessed are the poor in spirit; for theirs is the kingdom of heaven.", "haweis": "Blessed are the poor in spirit, for their’s is the kingdom of heaven.", "noyes": "Blessed are the poor in spirit; for theirs is the kingdom of heaven.", "webster": "Blessed [are] the poor in spirit: for theirs is the kingdom of heaven.", "vulgate": "beati pauperes spiritu quoniam ipsorum est regnum caelorum;"}}, {"v": 4, "ref": "5:4", "o": "μακάριοι οἱ πενθοῦντες, ὅτι αὐτοὶ παρακληθήσονται.", "en": {"kjv": "Blessed are they that mourn: for they shall be comforted.", "web": "Blessed are those who mourn, for they shall be comforted.", "bsb": "Blessed are those who mourn, for they will be comforted.", "asv": "Blessed are they that mourn: for they shall be comforted.", "ylt": "`Happy the mourning--because they shall be comforted.", "tyndale": "Blessed are they that morne: for they shalbe conforted.", "dra": "Blessed are the meek: for they shall possess the land.", "bbe": "Happy are those who are sad: for they will be comforted.", "geneva": "Blessed are they that mourne: for they shall be comforted.", "wycliffe": "Blessid ben mylde men, for thei schulen welde the erthe.", "rotherham": "Happy, they who mourn; for, they, shall be comforted:", "weymouth": "\"Blessed are the mourners, for they shall be comforted.", "darby": "Blessed they that mourn, for they shall be comforted.", "twenty": "Blessed are the mourners, for they shall be comforted.", "acv": "Blessed are those who mourn, because they will be comforted.", "anderson": "Blessed are they that mourn; for they shall be comforted.", "haweis": "Blessed are they that mourn: for they shall be comforted.", "noyes": "Blessed are the meek; for they will inherit the earth.", "webster": "Blessed [are] they that mourn: for they shall be comforted.", "vulgate": "beati mites quoniam ipsi possidebunt terram;"}}, {"v": 5, "ref": "5:5", "o": "μακάριοι οἱ πραεῖς, ὅτι αὐτοὶ κληρονομήσουσι τὴν γῆν.", "en": {"kjv": "Blessed are the meek: for they shall inherit the earth.", "web": "Blessed are the gentle, for they shall inherit the earth.", "bsb": "Blessed are the meek, for they will inherit the earth.", "asv": "Blessed are the meek: for they shall inherit the earth.", "ylt": "`Happy the meek--because they shall inherit the land.", "tyndale": "Blessed are the meke: for they shall inheret the erth.", "dra": "Blessed are they that mourn: for they shall be comforted.", "bbe": "Happy are the gentle: for the earth will be their heritage.", "geneva": "Blessed are the meeke: for they shall inherite the earth.", "wycliffe": "Blessid ben thei that mornen, for thei schulen be coumfortid.", "rotherham": "Happy, the meek; for, they, shall inherit the earth:", "weymouth": "\"Blessed are the meek, for they as heirs shall obtain possession of the earth.", "darby": "Blessed the meek, for they shall inherit the earth.", "twenty": "Blessed are the gentle, for they shall inherit the earth.", "acv": "Blessed are the meek, because they will inherit the earth.", "anderson": "Blessed are the meek; for they shall inherit the earth.", "haweis": "Blessed are the meek: for they shall inherit the earth.", "noyes": "Blessed are they who mourn; for they will be comforted.", "webster": "Blessed [are] the meek: for they shall inherit the earth.", "vulgate": "beati qui lugent quoniam ipsi consolabuntur;"}}, {"v": 6, "ref": "5:6", "o": "μακάριοι οἱ πεινῶντες καὶ διψῶντες τὴν δικαιοσύνην, ὅτι αὐτοὶ χορτασθήσονται.", "en": {"kjv": "Blessed are they which do hunger and thirst after righteousness: for they shall be filled.", "web": "Blessed are those who hunger and thirst after righteousness, for they shall be filled.", "bsb": "Blessed are those who hunger and thirst for righteousness, for they will be filled.", "asv": "Blessed are they that hunger and thirst after righteousness: for they shall be filled.", "ylt": "`Happy those hungering and thirsting for righteousness--because they shall be filled.", "tyndale": "Blessed are they which honger and thurst for rightewesnes: for they shalbe filled.", "dra": "Blessed are they that hunger and thirst after justice: for they shall have their fill.", "bbe": "Happy are those whose heart's desire is for righteousness: for they will have their desire.", "geneva": "Blessed are they which hunger and thirst for righteousnes: for they shalbe filled.", "wycliffe": "Blessid ben thei that hungren and thristen riytwisnesse, for thei schulen be fulfillid.", "rotherham": "Happy, they who hunger and thirst for righteousness; for, they, shall be filled:", "weymouth": "\"Blessed are those who hunger and thirst for righteousness, for they shall be completely satisfied.", "darby": "Blessed they who hunger and thirst after righteousness, for they shall be filled.", "twenty": "Blessed are those who hunger and thirst for righteousness, for they shall be satisfied.", "acv": "Blessed are those who hunger and thirst for righteousness, because they will be filled.", "anderson": "Blessed are they that hunger and thirst for righteousness; for they shall be filled.", "haweis": "Blessed are they who hunger and thirst after righteousness: for they shall be fed to the full.", "noyes": "Blessed are they who hunger and thirst after righteousness; for they will be filled.", "webster": "Blessed [are] they who hunger and thirst for righteousness: for they shall be filled.", "vulgate": "beati qui esuriunt et sitiunt iustitiam quoniam ipsi saturabuntur;"}}, {"v": 7, "ref": "5:7", "o": "μακάριοι οἱ ἐλεήμονες, ὅτι αὐτοὶ ἐλεηθήσονται.", "en": {"kjv": "Blessed are the merciful: for they shall obtain mercy.", "web": "Blessed are the merciful, for they shall obtain mercy.", "bsb": "Blessed are the merciful, for they will be shown mercy.", "asv": "Blessed are the merciful: for they shall obtain mercy.", "ylt": "`Happy the kind--because they shall find kindness.", "tyndale": "Blessed are ye mercifull: for they shall obteyne mercy.", "dra": "Blessed are the merciful: for they shall obtain mercy.", "bbe": "Happy are those who have mercy: for they will be given mercy.", "geneva": "Blessed are the mercifull: for they shall obteine mercie.", "wycliffe": "Blessid ben merciful men, for thei schulen gete merci.", "rotherham": "Happy, the merciful; for, they, shall receive mercy:", "weymouth": "\"Blessed are the compassionate, for they shall receive compassion.", "darby": "Blessed the merciful, for they shall find mercy.", "twenty": "Blessed are the merciful, for they shall find mercy.", "acv": "Blessed are the merciful, because they will obtain mercy.", "anderson": "Blessed are the merciful; for they shall receive mercy.", "haweis": "Blessed are the merciful for they shall obtain mercy.", "noyes": "Blessed are the merciful; for they will obtain mercy.", "webster": "Blessed [are] the merciful: for they shall obtain mercy.", "vulgate": "beati misericordes quia ipsi misericordiam consequentur;"}}, {"v": 8, "ref": "5:8", "o": "μακάριοι οἱ καθαροὶ τῇ καρδίᾳ, ὅτι αὐτοὶ τὸν θεὸν ὄψονται.", "en": {"kjv": "Blessed are the pure in heart: for they shall see God.", "web": "Blessed are the pure in heart, for they shall see God.", "bsb": "Blessed are the pure in heart, for they will see God.", "asv": "Blessed are the pure in heart: for they shall see God.", "ylt": "`Happy the clean in heart--because they shall see God.", "tyndale": "Blessed are the pure in herte: for they shall se God.", "dra": "Blessed are the clean of heart: they shall see God.", "bbe": "Happy are the clean in heart: for they will see God.", "geneva": "Blessed are the pure in heart: for they shall see God.", "wycliffe": "Blessid ben thei that ben of clene herte, for thei schulen se God.", "rotherham": "Happy, the pure, in heart; for, they, shall, see God:", "weymouth": "\"Blessed are the pure in heart, for they shall see God.", "darby": "Blessed the pure in heart, for they shall seeGod.", "twenty": "Blessed are the pure in heart, for they shall see God.", "acv": "Blessed are the pure in heart, because they will see God.", "anderson": "Blessed are the pure in heart; for they shall see God.", "haweis": "Blessed are the pure in heart: for they shall see God.", "noyes": "Blessed are the pure in heart; for they will see God.", "webster": "Blessed [are] the pure in heart: for they shall see God.", "vulgate": "beati mundo corde quoniam ipsi Deum videbunt;"}}, {"v": 9, "ref": "5:9", "o": "μακάριοι οἱ εἰρηνοποιοί, ὅτι αὐτοὶ υἱοὶ θεοῦ κληθήσονται.", "en": {"kjv": "Blessed are the peacemakers: for they shall be called the children of God.", "web": "Blessed are the peacemakers, for they shall be called children of God.", "bsb": "Blessed are the peacemakers, for they will be called sons of God.", "asv": "Blessed are the peacemakers: for they shall be called sons of God.", "ylt": "`Happy the peacemakers--because they shall be called Sons of God.", "tyndale": "Blessed are the peacemakers: for they shalbe called the chyldren of God.", "dra": "Blessed are the peacemakers: for they shall be called the children of God.", "bbe": "Happy are the peacemakers: for they will be named sons of God.", "geneva": "Blessed are the peace makers: for they shall be called the children of God.", "wycliffe": "Blessid ben pesible men, for thei schulen be clepid Goddis children.", "rotherham": "Happy, the peacemakers; for, they, shall be, called sons of God:", "weymouth": "\"Blessed are the peacemakers, for it is they who will be recognized as sons of God.", "darby": "Blessed the peace-makers, for they shall be called sons ofGod.", "twenty": "Blessed are the peacemakers, for they shall be called Sons of God.", "acv": "Blessed are the peacemakers, because they will be called sons of God.", "anderson": "Blessed are the peacemakers; for they shall be called sons of God.", "haweis": "Blessed are the peacemakers: for they shall be called the children of God.", "noyes": "Blessed are the peace-makers; for they will be called sons of God.", "webster": "Blessed [are] the peace-makers: for they shall be called children of God.", "vulgate": "beati pacifici quoniam filii Dei vocabuntur;"}}, {"v": 10, "ref": "5:10", "o": "μακάριοι οἱ δεδιωγμένοι ἕνεκεν δικαιοσύνης, ὅτι αὐτῶν ἐστιν ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "Blessed are they which are persecuted for righteousness’ sake: for theirs is the kingdom of heaven.", "web": "Blessed are those who have been persecuted for righteousness’ sake, for theirs is the Kingdom of Heaven.", "bsb": "Blessed are those who are persecuted because of righteousness, for theirs is the kingdom of heaven.", "asv": "Blessed are they that have been persecuted for righteousness’ sake: for theirs is the kingdom of heaven.", "ylt": "`Happy those persecuted for righteousness' sake--because theirs is the reign of the heavens.", "tyndale": "Blessed are they which suffre persecucio for rightwesnes sake: for theirs ys the kyngdome of heuen.", "dra": "Blessed are they that suffer persecution for justice' sake: for theirs is the kingdom of heaven.", "bbe": "Happy are those who are attacked on account of righteousness: for the kingdom of heaven will be theirs.", "geneva": "Blessed are they which suffer persecution for righteousnes sake: for theirs is the kingdome of heauen.", "wycliffe": "Blessid ben thei that suffren persecusioun for riytfulnesse, for the kingdam of heuenes is herne.", "rotherham": "Happy, they who have been persecuted for righteousness’ sake; for, theirs, is the kingdom of the heavens.", "weymouth": "\"Blessed are those who have borne persecution in the cause of Righteousness, for to them belongs the Kingdom of the Heavens.", "darby": "Blessed they who are persecuted on account of righteousness, for theirs is the kingdom of the heavens.", "twenty": "Blessed are those who have been persecuted in the cause of righteousness, for theirs is the Kingdom of Heaven.", "acv": "Blessed are those who have been persecuted because of righteousness, because the kingdom of the heavens is theirs.", "anderson": "Blessed are they that are persecuted on account of righteousness; for theirs is the kingdom of heaven.", "haweis": "Blessed are they who are persecuted for righteousness sake: for their’s is the kingdom in heaven.", "noyes": "Blessed are they who are persecuted for righteousness’ sake; for theirs is the kingdom of heaven.", "webster": "Blessed [are] they who are persecuted for righteousness' sake: for theirs is the kingdom of heaven.", "vulgate": "beati qui persecutionem patiuntur propter iustitiam quoniam ipsorum est regnum caelorum;"}}, {"v": 11, "ref": "5:11", "o": "μακάριοί ἐστε ὅταν ὀνειδίσωσιν ὑμᾶς καὶ διώξωσιν καὶ εἴπωσιν πᾶν ⸀πονηρὸν καθ’ ὑμῶν ψευδόμενοι ἕνεκεν ἐμοῦ.", "en": {"kjv": "Blessed are ye, when men shall revile you, and persecute you, and shall say all manner of evil against you falsely, for my sake.", "web": "“Blessed are you when people reproach you, persecute you, and say all kinds of evil against you falsely, for my sake.", "bsb": "Blessed are you when people insult you, persecute you, and falsely say all kinds of evil against you because of Me.", "asv": "Blessed are ye when men shall reproach you, and persecute you, and say all manner of evil against you falsely, for my sake.", "ylt": "`Happy are ye whenever they may reproach you, and may persecute, and may say any evil thing against you falsely for my sake--", "tyndale": "Blessed are ye when men reuyle you and persecute you and shall falsly say all manner of yvell saynges agaynst you for my sake.", "dra": "Blessed are ye when they shall revile you, and persecute you, and speak all that is evil against you, untruly, for my sake:", "bbe": "Happy are you when men give you a bad name, and are cruel to you, and say all evil things against you falsely, because of me.", "geneva": "Blessed shall ye be when men reuile you, and persecute you, and say all maner of euill against you for my sake, falsely.", "wycliffe": "`Ye schulen be blessid, whanne men schulen curse you, and schulen pursue you, and shulen seie al yuel ayens you liynge, for me.", "rotherham": "Happy, are ye, whensoever they may reproach you and persecute you, and say every evil thing against you, falsely, for my sake:", "weymouth": "\"Blessed are you when they have insulted and persecuted you, and have said every cruel thing about you falsely for my sake.", "darby": "Blessed are ye when they may reproach and persecute you, and say every wicked thing against you, lying, for my sake.", "twenty": "Blessed are you when people taunt you, and persecute you, and say everything evil about you — untruly, and on my account.", "acv": "Blessed are ye when they revile you, and persecute you, and say every evil word, being deceitful against you because of me.", "anderson": "Blessed are you, when they shall reproach you, and persecute you, and say every evil thing against you, falsely, on my account.", "haweis": "Blessed are ye, when they shall revile and persecute you, and lying, speak every thing evil against you for my sake.", "noyes": "Blessed are ye, when men revile you, and persecute you, and say every thing that is bad against you, falsely, for my sake.", "webster": "Blessed are ye when men shall revile you, and persecute [you], and shall say all manner of evil against you falsely, for my sake.", "vulgate": "beati estis cum maledixerint vobis et persecuti vos fuerint et dixerint omne malum adversum vos mentientes propter me;"}}, {"v": 12, "ref": "5:12", "o": "χαίρετε καὶ ἀγαλλιᾶσθε, ὅτι ὁ μισθὸς ὑμῶν πολὺς ἐν τοῖς οὐρανοῖς· οὕτως γὰρ ἐδίωξαν τοὺς προφήτας τοὺς πρὸ ὑμῶν.", "en": {"kjv": "Rejoice, and be exceeding glad: for great is your reward in heaven: for so persecuted they the prophets which were before you.", "web": "Rejoice, and be exceedingly glad, for great is your reward in heaven. For that is how they persecuted the prophets who were before you.", "bsb": "Rejoice and be glad, because great is your reward in heaven; for in the same way they persecuted the prophets before you.", "asv": "Rejoice, and be exceeding glad: for great is your reward in heaven: for so persecuted they the prophets that were before you.", "ylt": "rejoice ye and be glad, because your reward is great in the heavens, for thus did they persecute the prophets who were before you.", "tyndale": "Reioyce and be glad for greate is youre rewarde in heven. + For so persecuted they ye Prophetes which were before youre dayes.", "dra": "Be glad and rejoice for your reward is very great in heaven. For so they persecuted the prophets that were before you.", "bbe": "Be glad and full of joy; for great is your reward in heaven: for so were the prophets attacked who were before you.", "geneva": "Reioyce and be glad, for great is your reward in heauen: for so persecuted they the Prophets which were before you.", "wycliffe": "Ioie ye, and be ye glad, for youre meede is plenteuouse in heuenes; for so thei han pursued `also profetis that weren bifor you.", "rotherham": "Rejoice and exult, because, your reward, is great in the heavens; for, so, persecuted they the prophets who were before you.", "weymouth": "Be joyful and triumphant, because your reward is great in the Heavens; for so were the Prophets before you persecuted.", "darby": "Rejoice and exult, for your reward is great in the heavens; for thus have they persecuted the prophets who were before you.", "twenty": "Be glad and rejoice, because your reward in Heaven will be great; for so men persecuted the Prophets who lived before you.", "acv": "Rejoice, and be exceedingly glad, because your reward is great in the heavens, for so they persecuted the prophets before you.", "anderson": "Rejoice, and leap for joy; for great is your reward in heaven: for so did they persecute the prophets who were before you.", "haweis": "Rejoice and exult; for plenteous is your reward in the heavens: for just so they persecuted the prophets who went before you.", "noyes": "Rejoice, and be exceeding glad; for great is your reward in heaven; for so did they persecute the prophets that were before you.", "webster": "Rejoice, and be exceeding glad: for great [is] your reward in heaven: for so they persecuted the prophets who were before you.", "vulgate": "gaudete et exultate quoniam merces vestra copiosa est in caelis sic enim persecuti sunt prophetas qui fuerunt ante vos;"}}, {"v": 13, "ref": "5:13", "o": "Ὑμεῖς ἐστε τὸ ἅλας τῆς γῆς· ἐὰν δὲ τὸ ἅλας μωρανθῇ, ἐν τίνι ἁλισθήσεται; εἰς οὐδὲν ἰσχύει ἔτι εἰ μὴ ⸂βληθὲν ἔξω⸃ καταπατεῖσθαι ὑπὸ τῶν ἀνθρώπων.", "en": {"kjv": "Ye are the salt of the earth: but if the salt have lost his savour, wherewith shall it be salted? it is thenceforth good for nothing, but to be cast out, and to be trodden under foot of men.", "web": "“You are the salt of the earth, but if the salt has lost its flavor, with what will it be salted? It is then good for nothing, but to be cast out and trodden under the feet of men.", "bsb": "You are the salt of the earth. But if the salt loses its savor, how can it be made salty again? It is no longer good for anything, except to be thrown out and trampled by men.", "asv": "Ye are the salt of the earth: but if the salt have lost its savor, wherewith shall it be salted? it is thenceforth good for nothing, but to be cast out and trodden under foot of men.", "ylt": "`Ye are the salt of the land, but if the salt may lose savour, in what shall it be salted? for nothing is it good henceforth, except to be cast without, and to be trodden down by men.", "tyndale": "ye are ye salt of the erthe: but and yf ye salt have lost hir saltnes what can be salted ther with? It is thence forthe good for nothynge but to be cast oute and to be troade vnder fote of men.", "dra": "You are the salt of the earth. But if the salt lose its savour, wherewith shall it be salted? It is good for nothing anymore but to be cast out, and to be trodden on by men.", "bbe": "You are the salt of the earth; but if its taste goes from the salt, how will you make it salt again? it is then good for nothing but to be put out and crushed under foot by men.", "geneva": "Ye are the salt of the earth: but if the salt haue lost his sauour, wherewith shall it be salted? It is thenceforth good for nothing, but to be cast out, and to be troden vnder foote of men.", "wycliffe": "Ye ben salt of the erthe; that if the salt vanysche awey, whereynne schal it be saltid? To no thing it is worth ouere, no but that it be cast out, and be defoulid of men.", "rotherham": "Ye, are the salt of the earth; but, if the salt become tasteless, wherewith shall it be salted? it is good, for nothing, any more, save, being cast out, to be trampled on by men.", "weymouth": "\"*You* are the salt of the earth; but if salt has become tasteless, in what way can it regain its saltness? It is no longer good for anything but to be thrown away and trodden on by the passers by.", "darby": "Ye are the salt of the earth; but if the salt have become insipid, wherewith shall it be salted? It is no longer fit for anything but to be cast out and to be trodden under foot by men.", "twenty": "It is you who are the salt of the earth; but, if the salt should lose its strength, what will you use to restore its saltiness? It is no longer good for anything, but is thrown away, and trampled underfoot.", "acv": "Ye are the salt material of the earth. But if the salt material becomes ineffective, by what will it be salted? It is potent for nothing further, except to be cast outside and to be trodden down by men.", "anderson": "You are the salt of the earth: but if the salt has become tasteless, by what means shall it become salt again? It is then good for nothing but to be thrown out and trod upon by men.", "haweis": "Ye are the salt of the earth: but if the salt become insipid, with what can it be salted? it is of no farther use for any purpose, but to be cast out, and trodden under foot of men.", "noyes": "Ye are the salt of the earth. But if the salt have lost its savor, wherewith shall itself be salted? It is thenceforth good for nothing, but to be cast out, and to be trodden under foot by men.", "webster": "Ye are the salt of the earth: but if the salt hath lost its savor, with what shall it be salted? it is thenceforth good for nothing, but to be cast out, and to be trodden under foot by men.", "vulgate": "vos estis sal terrae quod si sal evanuerit in quo sallietur ad nihilum valet ultra nisi ut mittatur foras et conculcetur ab hominibus;"}}, {"v": 14, "ref": "5:14", "o": "Ὑμεῖς ἐστε τὸ φῶς τοῦ κόσμου. οὐ δύναται πόλις κρυβῆναι ἐπάνω ὄρους κειμένη·", "en": {"kjv": "Ye are the light of the world. A city that is set on an hill cannot be hid.", "web": "You are the light of the world. A city located on a hill can’t be hidden.", "bsb": "You are the light of the world. A city on a hill cannot be hidden.", "asv": "Ye are the light of the world. A city set on a hill cannot be hid.", "ylt": "`Ye are the light of the world, a city set upon a mount is not able to be hid;", "tyndale": "Ye are ye light of the worlde. A cite yt is set on an hill cannot be hid", "dra": "You are the light of the world. A city seated on a mountain cannot be hid.", "bbe": "You are the light of the world. A town put on a hill may be seen by all.", "geneva": "Ye are the light of the world. A citie that is set on an hill, cannot be hid.", "wycliffe": "Ye ben liyt of the world; a citee set on an hil may not be hid;", "rotherham": "Ye, are the light of the world: it is impossible for a city to be hid, on the top of a mountain, lying.", "weymouth": "*You* are the light of the world; a town cannot be hid if built on a hill-top.", "darby": "Ye are the light of the world: a city situated on the top of a mountain cannot be hid.", "twenty": "It is you who are the Light of the world. A town that stands on a hill cannot be hidden.", "acv": "Ye are the light of the world. A city setting on a hill cannot be hid,", "anderson": "You are the light of the world: a city that lies upon a mountain can not be hid:", "haweis": "Ye are the light of the world. A city cannot be hid that is situated on an eminence.", "noyes": "Ye are the light of the world. A city that is set on a hill cannot be hid;", "webster": "Ye are the light of the world. A city that is set on a hill cannot be hid.", "vulgate": "vos estis lux mundi non potest civitas abscondi supra montem posita;"}}, {"v": 15, "ref": "5:15", "o": "οὐδὲ καίουσιν λύχνον καὶ τιθέασιν αὐτὸν ὑπὸ τὸν μόδιον ἀλλ’ ἐπὶ τὴν λυχνίαν, καὶ λάμπει πᾶσιν τοῖς ἐν τῇ οἰκίᾳ.", "en": {"kjv": "Neither do men light a candle, and put it under a bushel, but on a candlestick; and it giveth light unto all that are in the house.", "web": "Neither do you light a lamp, and put it under a measuring basket, but on a stand; and it shines to all who are in the house.", "bsb": "Neither do people light a lamp and put it under a basket. Instead, they set it on a stand, and it gives light to everyone in the house.", "asv": "Neither do men light a lamp, and put it under the bushel, but on the stand; and it shineth unto all that are in the house.", "ylt": "nor do they light a lamp, and put it under the measure, but on the lamp-stand, and it shineth to all those in the house;", "tyndale": "nether do men lyght a cadell and put it vnder a busshell but on a candelstick and it lighteth all that are in the house.", "dra": "Neither do men light a candle and put it under a bushel, but upon a candlestick, that it may shine to all that are in the house.", "bbe": "And a burning light is not put under a vessel, but on its table; so that its rays may be shining on all who are in the house.", "geneva": "Neither doe men light a candel, and put it vnder a bushel, but on a candlesticke, and it giueth light vnto all that are in the house.", "wycliffe": "ne me teendith not a lanterne, and puttith it vndur a busschel, but on a candilstike, that it yyue liyt to alle that ben in the hous.", "rotherham": "Neither light they a lamp, and place it under the measure; but upon the lampstand, and it giveth light to all that are in the house.", "weymouth": "Nor is a lamp lighted to be put under a bushel, but on the lampstand; and then it gives light to all in the house.", "darby": "Nor do [men] light a lamp and put it under the bushel, but upon the lamp-stand, and it shines for all who are in the house.", "twenty": "Men do not light a lamp and put it under the corn-measure, but on the lamp-stand, where it gives light to every one in the house.", "acv": "nor do they light a lamp, and put it under the bushel, but on the lampstand, and it shines to all in the house.", "anderson": "neither do men light a lamp and place it under the measure, but on the lamp-stand, and it gives light to all that are in the house.", "haweis": "Neither do men burn a lamp, and set it under a bushel, but on its stand; and it sheds light on all that are in the house.", "noyes": "nor do men light a lamp, and put it under the bushel, but on the lamp-stand; and it giveth light to all that are in the house.", "webster": "Neither do men light a candle, and put it under a close vessel, but on a candlestick: and it giveth light to all that are in the house.", "vulgate": "neque accendunt lucernam et ponunt eam sub modio sed super candelabrum ut luceat omnibus qui in domo sunt;"}}, {"v": 16, "ref": "5:16", "o": "οὕτως λαμψάτω τὸ φῶς ὑμῶν ἔμπροσθεν τῶν ἀνθρώπων, ὅπως ἴδωσιν ὑμῶν τὰ καλὰ ἔργα καὶ δοξάσωσιν τὸν πατέρα ὑμῶν τὸν ἐν τοῖς οὐρανοῖς.", "en": {"kjv": "Let your light so shine before men, that they may see your good works, and glorify your Father which is in heaven.", "web": "Even so, let your light shine before men; that they may see your good works, and glorify your Father who is in heaven.", "bsb": "In the same way, let your light shine before men, that they may see your good deeds and glorify your Father in heaven.", "asv": "Even so let your light shine before men; that they may see your good works, and glorify your Father who is in heaven.", "ylt": "so let your light shine before men, that they may see your good works, and may glorify your Father who is in the heavens.", "tyndale": "Let youre light so shyne before men yt they maye se youre good workes and glorify youre father which is in heven.", "dra": "So let your light shine before men, that they may see your good works, and glorify your Father who is in heaven.", "bbe": "Even so let your light be shining before men, so that they may see your good works and give glory to your Father in heaven.", "geneva": "Let your light so shine before men, that they may see your good workes, and glorifie your Father which is in heauen.", "wycliffe": "So schyne youre liyt befor men, that thei se youre goode werkis, and glorifie youre fadir that is in heuenes.", "rotherham": "In like manner, let your light shine before men,—that they may see your good works,—and glorify your Father who is in the heavens.", "weymouth": "Just so let your light shine before all men, in order that they may see your holy lives and may give glory to your Father who is in Heaven.", "darby": "Let your light thus shine before men, so that they may see your upright works, and glorify your Father who is in the heavens.", "twenty": "Let your light so shine before the eyes of your fellow men, that, seeing your good actions, they may praise your Father who is in Heaven.", "acv": "Thus your light should shine before men, so that they may see your good works, and glorify your Father in the heavens.", "anderson": "In this way let your light shine before men, that they may see your good works, and glorify your Father who is in heaven.", "haweis": "Just so let your light shine before men, that they may see your good works, and glorify your Father who is in the heavens.", "noyes": "In like manner let your light shine before men, that they may see your good works, and glorify your Father who is in heaven.", "webster": "Let your light so shine before men, that they may see your good works, and glorify your Father who is in heaven.", "vulgate": "sic luceat lux vestra coram hominibus ut videant vestra bona opera et glorificent Patrem vestrum qui in caelis est;"}}, {"v": 17, "ref": "5:17", "o": "Μὴ νομίσητε ὅτι ἦλθον καταλῦσαι τὸν νόμον ἢ τοὺς προφήτας· οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι·", "en": {"kjv": "Think not that I am come to destroy the law, or the prophets: I am not come to destroy, but to fulfil.", "web": "“Don’t think that I came to destroy the law or the prophets. I didn’t come to destroy, but to fulfill.", "bsb": "Do not think that I have come to abolish the Law or the Prophets. I have not come to abolish them, but to fulfill them.", "asv": "Think not that I came to destroy the law or the prophets: I came not to destroy, but to fulfil.", "ylt": "`Do not suppose that I came to throw down the law or the prophets--I did not come to throw down, but to fulfil;", "tyndale": "Thinke not yt I am come to destroye the lawe or the Prophets: no I am nott come to destroye them but to fulfyll them.", "dra": "Do not think that I am come to destroy the law, or the prophets. I am not come to destroy, but to fulfil.", "bbe": "Let there be no thought that I have come to put an end to the law or the prophets. I have not come for destruction, but to make complete.", "geneva": "Think not that I am come to destroy the Lawe, or the Prophets. I am not come to destroy them, but to fulfill them.", "wycliffe": "Nil ye deme, that Y cam to vndo the lawe, or the profetis; Y cam not to vndo the lawe, but to fulfille.", "rotherham": "Do not think, that I came to pull down the law, or the prophets,—I came not to pull down, but to fulfil.", "weymouth": "\"Do not for a moment suppose that I have come to abrogate the Law or the Prophets: I have not come to abrogate them but to give them their completion.", "darby": "Think not that I am come to make void the law or the prophets; I am not come to make void, but to fulfil.", "twenty": "Do not think that I have come to do away with the Law or the Prophets; I have not come to do away with them, but to complete them.", "acv": "Think not that I came to abolish the law or the prophets. I came not to abolish, but to fulfill.", "anderson": "Think not that I have come to make the law or the prophets of no effect. I have not come to make them of no effect, but to give them their full efficiency.", "haweis": "Think not that I am come to destroy the law and the prophets: I came not to destroy, but to fulfil.", "noyes": "Think not that I came to destroy the Law or the Prophets: I came not to destroy, but to fulfill.", "webster": "Think not that I am come to destroy the law, or the prophets: I am not come to destroy, but to fulfill.", "vulgate": "nolite putare quoniam veni solvere legem aut prophetas non veni solvere sed adimplere;"}}, {"v": 18, "ref": "5:18", "o": "ἀμὴν γὰρ λέγω ὑμῖν, ἕως ἂν παρέλθῃ ὁ οὐρανὸς καὶ ἡ γῆ, ἰῶτα ἓν ἢ μία κεραία οὐ μὴ παρέλθῃ ἀπὸ τοῦ νόμου, ἕως ἂν πάντα γένηται.", "en": {"kjv": "For verily I say unto you, Till heaven and earth pass, one jot or one tittle shall in no wise pass from the law, till all be fulfilled.", "web": "For most certainly, I tell you, until heaven and earth pass away, not even one smallest letteror one tiny pen stroke shall in any way pass away from the law, until all things are accomplished.", "bsb": "For I tell you truly, until heaven and earth pass away, not a single jot, not a stroke of a pen, will disappear from the Law until everything is accomplished.", "asv": "For verily I say unto you, Till heaven and earth pass away, one jot or one tittle shall in no wise pass away from the law, till all things be accomplished.", "ylt": "for, verily I say to you, till that the heaven and the earth may pass away, one iota or one tittle may not pass away from the law, till that all may come to pass.", "tyndale": "For truely I saye vnto you till heven and erth perisshe one iott or one tytle of the lawe shall not scape tyll all be fulfilled.", "dra": "For amen I say unto you, till heaven and earth pass, one jot, or one tittle shall not pass of the law, till all be fulfilled.", "bbe": "Truly I say to you, Till heaven and earth come to an end, not the smallest letter or part of a letter will in any way be taken from the law, till all things are done.", "geneva": "For truely I say vnto you, Till heauen, and earth perish, one iote or one title of the Law shall not scape, till all things be fulfilled.", "wycliffe": "Forsothe Y seie to you, til heuene and erthe passe, o lettir or o titel shal not passe fro the lawe, til alle thingis be doon.", "rotherham": "For, verily, I say unto you, until the heaven and the earth shall pass away, one least letter, or one point, may in nowise pass away from the law, till all be accomplished.", "weymouth": "Solemnly I tell you that until Heaven and earth pass away, not one iota or smallest detail will pass away from the Law until all has taken place.", "darby": "For verily I say unto you, Until the heaven and the earth pass away, one iota or one tittle shall in no wise pass from the law till all come to pass.", "twenty": "For I tell you, until the heavens and the earth disappear, not even the smallest letter, nor one stroke of a letter, shall disappear from the Law until all is done.", "acv": "For truly I say to you, until the heaven and the earth pass away, one iota or one tittle will, no, not pass away from the law, until all things come to pass.", "anderson": "For verily I say to you, Till heaven and earth pass away, one yod or one point shall in no way pass from the law till all be fulfilled.", "haweis": "For I tell you assuredly, that till heaven and earth pass away, not one iota, or the smallest stroke of a letter, shall pass from the law, until all things shall be accomplished.", "noyes": "For truly do I say to you, Not till heaven and earth pass away, shall one jot or one tittle pass from the Law, till all be fulfilled.", "webster": "For verily I say to you, Till heaven and earth shall pass away, one jot or one tittle shall in no wise pass from the law, till all be fulfilled.", "vulgate": "amen quippe dico vobis donec transeat caelum et terra iota unum aut unus apex non praeteribit a lege donec omnia fiant;"}}, {"v": 19, "ref": "5:19", "o": "ὃς ἐὰν οὖν λύσῃ μίαν τῶν ἐντολῶν τούτων τῶν ἐλαχίστων καὶ διδάξῃ οὕτως τοὺς ἀνθρώπους, ἐλάχιστος κληθήσεται ἐν τῇ βασιλείᾳ τῶν οὐρανῶν· ὃς δ’ ἂν ποιήσῃ καὶ διδάξῃ, οὗτος μέγας κληθήσεται ἐν τῇ βασιλείᾳ τῶν οὐρανῶν.", "en": {"kjv": "Whosoever therefore shall break one of these least commandments, and shall teach men so, he shall be called the least in the kingdom of heaven: but whosoever shall do and teach them, the same shall be called great in the kingdom of heaven.", "web": "Whoever, therefore, shall break one of these least commandments, and teach others to do so, shall be called least in the Kingdom of Heaven; but whoever shall do and teach them shall be called great in the Kingdom of Heaven.", "bsb": "So then, whoever breaks one of the least of these commandments and teaches others to do likewise will be called least in the kingdom of heaven; but whoever practices and teaches them will be called great in the kingdom of heaven.", "asv": "Whosoever therefore shall break one of these least commandments, and shall teach men so, shall be called least in the kingdom of heaven: but whosoever shall do and teach them, he shall be called great in the kingdom of heaven.", "ylt": "`Whoever therefore may loose one of these commands--the least--and may teach men so, least he shall be called in the reign of the heavens, but whoever may do and may teach them , he shall be called great in the reign of the heavens.", "tyndale": "Whosoever breaketh one of these lest commaundmentes and teacheth men so he shalbe called the leest in the kyngdome of heve. But whosoever obserueth and teacheth ye same shal be called greate in the kyngdome of heven.", "dra": "He therefore that shall break one of these least commandments, and shall so teach men shall be called the least in the kingdom of heaven. But he that shall do and teach, he shall be called great in the kingdom of heaven.", "bbe": "Whoever then goes against the smallest of these laws, teaching men to do the same, will be named least in the kingdom of heaven; but he who keeps the laws, teaching others to keep them, will be named great in the kingdom of heaven.", "geneva": "Whosoeuer therefore shall breake one of these least commandements, and teach men so, he shall be called the least in the kingdome of heauen: but whosoeuer shall obserue and teach them, the same shall be called great in the kingdome of heauen.", "wycliffe": "Therfor he that brekith oon of these leeste maundementis, and techith thus men, schal be clepid the leste in the rewme of heuenes; `but he that doith, and techith, schal be clepid greet in the kyngdom of heuenes.", "rotherham": "Whosoever, therefore, shall relax one of these commandments, the least, and teach men so, shall be called, least, in the kingdom of the heavens; but, whosoever shall do and teach, the same, shall be called, great, in the kingdom of the heavens.", "weymouth": "Whoever therefore breaks one of these least commandments and teaches others to break them, will be called the least in the Kingdom of the Heavens; but whoever practises them and teaches them, he will be acknowledged as great in the Kingdom of the Heavens.", "darby": "Whosoever then shall do away with one of these least commandments, and shall teach men so, shall be called least in the kingdom of the heavens; but whosoever shall practise and teach [them], he shall be called great in the kingdom of the heavens.", "twenty": "Whoever, therefore, breaks one of these commandments, even the least of them, and teaches others to do so, will be the least-esteemed in the Kingdom of Heaven; but whoever keeps them, and teaches others to do so, will be esteemed great in the Kingdom of Heaven.", "acv": "Whoever therefore may relax one of these least commandments, and may teach men so, he will be called least in the kingdom of the heavens. But whoever may do and may teach them, this man will be called great in the kingdom of the heavens.", "anderson": "Whoever, therefore, shall make void one of the least of these commandments, and shall teach men so, shall be called least in the kingdom of heaven. But whoever shall do and teach, he shall be called great in the kingdom of heaven.", "haweis": "Whosoever therefore shall break one of the least of these commandments, and teach men so, he shall be accounted the least in the kingdom of heaven: but whosoever shall practise, and teach them, he shall be reckoned great in the kingdom of heaven.", "noyes": "Whoever therefore shall break one of these least commandments, and shall teach men so, will be called the least in the kingdom of heaven; but whoever shall do and teach them, he will be called great in the kingdom of heaven.", "webster": "Whoever therefore shall break one of these least commandments, and shall teach men so, he shall be called the least in the kingdom of heaven: but whoever shall do, and teach [them], the same shall be called great in the kingdom of heaven.", "vulgate": "qui ergo solverit unum de mandatis istis minimis et docuerit sic homines minimus vocabitur in regno caelorum qui autem fecerit et docuerit hic magnus vocabitur in regno caelorum;"}}, {"v": 20, "ref": "5:20", "o": "λέγω γὰρ ὑμῖν ὅτι ἐὰν μὴ περισσεύσῃ ⸂ὑμῶν ἡ δικαιοσύνη⸃ πλεῖον τῶν γραμματέων καὶ Φαρισαίων, οὐ μὴ εἰσέλθητε εἰς τὴν βασιλείαν τῶν οὐρανῶν.", "en": {"kjv": "For I say unto you, That except your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no case enter into the kingdom of heaven.", "web": "For I tell you that unless your righteousness exceeds that of the scribes and Pharisees, there is no way you will enter into the Kingdom of Heaven.", "bsb": "For I tell you that unless your righteousness exceeds that of the scribes and Pharisees, you will never enter the kingdom of heaven.", "asv": "For I say unto you, that except your righteousness shall exceed the righteousness of the scribes and Pharisees, ye shall in no wise enter into the kingdom of heaven.", "ylt": "`For I say to you, that if your righteousness may not abound above that of the scribes and Pharisees, ye may not enter to the reign of the heavens.", "tyndale": "For I saye vnto you except youre rightewesnes excede the righetewesnes of ye Scribes and Pharises ye canot entre into ye kyngdome of heven.", "dra": "For I tell you, that unless your justice abound more than that of the scribes and Pharisees, you shall not enter into the kingdom of heaven.", "bbe": "For I say to you, If your righteousness is not greater than the righteousness of the scribes and Pharisees, you will never go into the kingdom of heaven.", "geneva": "For I say vnto you, except your righteousnes exceede the righteousnes of the Scribes and Pharises, ye shall not enter into the kingdome of heauen.", "wycliffe": "And Y seie to you, that but your riytfulnesse be more plenteuouse than of scribis and of Farisees, ye schulen not entre into the kyngdom of heuenes.", "rotherham": "For I say unto you, that, unless your righteousness exceed that of the Scribes and Pharisees, in nowise, may ye enter into the kingdom of the heavens.", "weymouth": "For I assure you that unless your righteousness greatly surpasses that of the Scribes and the Pharisees, you will certainly not find entrance into the Kingdom of the Heavens.", "darby": "For I say unto you, that unless your righteousness surpass [that] of the scribes and Pharisees, ye shall in no wise enter into the kingdom of the heavens.", "twenty": "Indeed I tell you that, unless your religion is above that of the Teachers of the Law, and Pharisees, you will never enter the Kingdom of Heaven.", "acv": "For I say to you, that unless your righteousness abounds more than of the scholars and Pharisees, ye will, no, not enter into the kingdom of the heavens.", "anderson": "For I say to you, That, unless your righteousness excel that of the scribes and Pharisees, you can by no means enter into the kingdom of heaven.", "haweis": "For I say unto you, That except your righteousness abounds more than that of the scribes and Pharisees, ye shall in no wise enter into the kingdom of heaven.", "noyes": "For I say to you, Unless your righteousness shall exceed that of the scribes and Pharisees, ye will not enter the kingdom of heaven.", "webster": "For I say to you, That except your righteousness shall exceed [the righteousness] of the scribes and Pharisees, ye shall in no case enter into the kingdom of heaven.", "vulgate": "dico enim vobis quia nisi abundaverit iustitia vestra plus quam scribarum et Pharisaeorum non intrabitis in regnum caelorum;"}}, {"v": 21, "ref": "5:21", "o": "Ἠκούσατε ὅτι ἐρρέθη τοῖς ἀρχαίοις· Οὐ φονεύσεις· ὃς δ’ ἂν φονεύσῃ, ἔνοχος ἔσται τῇ κρίσει.", "en": {"kjv": "Ye have heard that it was said by them of old time, Thou shalt not kill; and whosoever shall kill shall be in danger of the judgment:", "web": "“You have heard that it was said to the ancient ones, ‘You shall not murder;’ and ‘Whoever shall murder shall be in danger of the judgment.’", "bsb": "You have heard that it was said to the ancients, ‘Do not murder’ and ‘Anyone who murders will be subject to judgment.’", "asv": "Ye have heard that it was said to them of old time, Thou shalt not kill; and whosoever shall kill shall be in danger of the judgment:", "ylt": "`Ye heard that it was said to the ancients: Thou shalt not kill, and whoever may kill shall be in danger of the judgment;", "tyndale": "Ye have herde howe it was sayd vnto the of ye olde tyme: Thou shalt not kyll. For whoso ever kylleth shall be in daunger of iudgemet.", "dra": "You have heard that it was said to them of old: Thou shalt not kill. And whosoever shall kill, shall be in danger of the judgment.", "bbe": "You have knowledge that it was said in old times, You may not put to death; and, Whoever puts to death will be in danger of being judged:", "geneva": "Ye haue heard that it was sayd vnto them of the olde time, Thou shalt not kill: for whosoeuer killeth shalbe culpable of iudgement.", "wycliffe": "Ye han herd that it was seid to elde men, Thou schalt not slee; and he that sleeth, schal be gilti to doom.", "rotherham": "Ye have heard, that it was said, to them of olden time,—Thou shalt not commit murder, and, whosoever shall commit murder, shall be, liable, to judgment.", "weymouth": "\"You have heard that it was said to the ancients, `Thou shalt not commit murder', and whoever commits murder will be answerable to the magistrate.", "darby": "Ye have heard that it was said to the ancients, Thou shalt not kill; but whosoever shall kill shall be subject to the judgment.", "twenty": "You have heard that to our ancestors it was said — ‘Thou shalt not commit murder,’ and ‘Whoever commits murder shall be liable to answer for it to the Court.’", "acv": "Ye have heard that it was said to them in old times, Thou shall not murder, and whoever murders will be liable to the judgment.", "anderson": "You have heard that it was said to the ancients: You shall not kill; and whoever shall kill, shall be liable to the sentence of the judges.", "haweis": "Ye have heard that it was said to the men of antient times, “Thou shalt do no murder;” and whosoever shall commit murder, shall be liable to the judgment:", "noyes": "Ye have heard that it was said to them of old time, \"Thou shalt not kill; and whoever shall kill, shall be in danger of the Judges.\"", "webster": "Ye have heard that it was said to them of old time, Thou shalt not kill; and whoever shall kill, shall be in danger of the judgment:", "vulgate": "audistis quia dictum est antiquis non occides qui autem occiderit reus erit iudicio;"}}, {"v": 22, "ref": "5:22", "o": "ἐγὼ δὲ λέγω ὑμῖν ὅτι πᾶς ὁ ὀργιζόμενος τῷ ἀδελφῷ ⸀αὐτοῦ ἔνοχος ἔσται τῇ κρίσει· ὃς δ’ ἂν εἴπῃ τῷ ἀδελφῷ αὐτοῦ· Ῥακά, ἔνοχος ἔσται τῷ συνεδρίῳ· ὃς δ’ ἂν εἴπῃ· Μωρέ, ἔνοχος ἔσται εἰς τὴν γέενναν τοῦ πυρός.", "en": {"kjv": "But I say unto you, That whosoever is angry with his brother without a cause shall be in danger of the judgment: and whosoever shall say to his brother, Raca, shall be in danger of the council: but whosoever shall say, Thou fool, shall be in danger of hell fire.", "web": "But I tell you, that everyone who is angry with his brother without a cause shall be in danger of the judgment; and whoever shall say to his brother, ‘Raca!’ shall be in danger of the council; and whoever shall say, ‘You fool!’ shall be in danger of the fire of Gehenna.", "bsb": "But I tell you that anyone who is angry with his brother will be subject to judgment. Again, anyone who says to his brother, ‘Raca,’ will be subject to the Sanhedrin. But anyone who says, ‘You fool!’ will be subject to the fire of hell.", "asv": "but I say unto you, that every one who is angry with his brother shall be in danger of the judgment; and whosoever shall say to his brother, Raca, shall be in danger of the council; and whosoever shall say, Thou fool, shall be in danger of the hell of fire.", "ylt": "but I--I say to you, that every one who is angry at his brother without cause, shall be in danger of the judgment, and whoever may say to his brother, Empty fellow! shall be in danger of the sanhedrim, and whoever may say, Rebel! shall be in danger of the gehenna of the fire.", "tyndale": "But I say vnto you whosoever is angre with hys brother shalbe in daunger of iudgement. Whosoeuer sayeth vnto his brother Racha shalbe in dauger of a cousell. But whosoeuer sayeth thou fole shalbe in dauger of hell fyre.", "dra": "But I say to you, that whosoever is angry with his brother, shall be in danger of the judgment. And whosoever shall say to his brother, Raca, shall be in danger of the council. And whosoever shall say, Thou fool, shall be in danger of hell fire.", "bbe": "But I say to you that everyone who is angry with his brother will be in danger of being judged; and he who says to his brother, Raca, will be in danger from the Sanhedrin; and whoever says, You foolish one, will be in danger of the hell of fire.", "geneva": "But I say vnto you, whosoeuer is angry with his brother vnaduisedly, shalbe culpable of iudgment. And whosoeuer sayth vnto his brother, Raca, shalbe worthy to be punished by the Councill. And whosoeuer shall say, Foole, shalbe worthy to be punished with hell fire.", "wycliffe": "But Y seie to you, that ech man that is wrooth to his brothir, schal be gilti to doom; and he that seith to his brother, Fy! schal be gilti to the counseil; but he that seith, Fool, schal be gilti to the fier of helle.", "rotherham": "But, I, say unto you, that, every one who is angry with his brother, shall be, liable, to judgment,—and, whosoever shall say to his brother, Worthless one!, shall be, liable, to the high council; and, whosoever shall say, Rebel!, shall be, liable, unto the fiery gehenna.", "weymouth": "But I say to you that every one who becomes angry with his brother shall be answerable to the magistrate; that whoever says to his brother `Raca,' shall be answerable to the Sanhedrin; and that whoever says, `You fool!' shall be liable to the Gehenna of Fire.", "darby": "But I say unto you, that every one that is lightly angry with his brother shall be subject to the judgment; but whosoever shall say to his brother, Raca, shall be subject to [be called before] the sanhedrim; but whosoever shall say, Fool, shall be subject to the penalty of the hell of fire.", "twenty": "I, however, say to you that any one who cherishes anger against his brother shall be liable to answer for it to the Court; and whoever pours contempt upon his brother shall be liable to answer for it to the High Council, while whoever calls down curses upon him shall be liable to answer for it in the fiery Pit.", "acv": "But I say to you, that every man who is angry at his brother without cause will be liable to the judgment, and whoever speaks an insult to his brother will be liable to the council, and whoever says, Foolish man, will be liable to the hell of fire.", "anderson": "But I say to you, Whoever is angry with his brother without a cause, shall be liable to the sentence of the judges. And whoever shall say to his brother, Worthless fellow, shall be liable to the sentence of the Sanhedrin. But who ever shall say, Impious wretch, shall be in danger of hell-fire.", "haweis": "but I say unto you, That every man who is angry with his brother without cause, shall be liable to the judgment: and whosoever shall say to his brother, Raca, shall be liable to the sanhedrim: but whosever shall say, Thou fool, shall be liable to be cast into hell fire.", "noyes": "But I say to you, that whoever is angry with his brother shall be in danger of the Judges; and whoever shall say to his brother, Simpleton! shall be in danger of the Council; and whoever shall say, Fool! shall be in danger of hell-fire.", "webster": "But I say to you, That whoever is angry with his brother without a cause, shall be in danger of the judgment: and whoever shall say to his brother, Raca, shall be in danger of the council: but whoever shall say, Thou fool, shall be in danger of hell-fire.", "vulgate": "ego autem dico vobis quia omnis qui irascitur fratri suo reus erit iudicio qui autem dixerit fratri suo racha reus erit concilio qui autem dixerit fatue reus erit gehennae ignis;"}}, {"v": 23, "ref": "5:23", "o": "ἐὰν οὖν προσφέρῃς τὸ δῶρόν σου ἐπὶ τὸ θυσιαστήριον κἀκεῖ μνησθῇς ὅτι ὁ ἀδελφός σου ἔχει τι κατὰ σοῦ,", "en": {"kjv": "Therefore if thou bring thy gift to the altar, and there rememberest that thy brother hath ought against thee;", "web": "“If therefore you are offering your gift at the altar, and there remember that your brother has anything against you,", "bsb": "So if you are offering your gift at the altar and there remember that your brother has something against you,", "asv": "If therefore thou art offering thy gift at the altar, and there rememberest that thy brother hath aught against thee,", "ylt": "`If, therefore, thou mayest bring thy gift to the altar, and there mayest remember that thy brother hath anything against thee,", "tyndale": "Therfore whe thou offrest thy gifte at the altare and their remembrest that thy brother hath ought agaynst the:", "dra": "If therefore thou offer thy gift at the altar, and there thou remember that thy brother hath anything against thee;", "bbe": "If then you are making an offering at the altar and there it comes to your mind that your brother has something against you,", "geneva": "If then thou bring thy gift to the altar, and there remembrest that thy brother hath ought against thee,", "wycliffe": "Therfor if thou offrist thi yifte `at the auter, and ther thou bithenkist, that thi brothir hath sum what ayens thee,", "rotherham": "If, therefore, thou be bearing thy gift towards the altar, and, there, shouldst remember that, thy brother, hath aught against thee,", "weymouth": "If therefore when you are offering your gift upon the altar, you remember that your brother has a grievance against you,", "darby": "If therefore thou shouldest offer thy gift at the altar, and there shouldest remember that thy brother has something against thee,", "twenty": "Therefore, when presenting your gift at the altar, if even there you remember that your brother has some grievance against you,", "acv": "If therefore thou should bring thy gift to the altar, and remember there that thy brother has anything against thee,", "anderson": "If, therefore, you bring your gift to the altar, and there remember that your brother has any thing against you,", "haweis": "If therefore thou bring thy gift to the altar, and there rememberest that thy brother hath ought against thee;", "noyes": "Therefore, if thou bring thy gift to the altar, and there remember that thy brother hath aught against thee,", "webster": "Therefore if thou shalt bring thy gift to the altar, and there remember that thy brother hath aught against thee;", "vulgate": "si ergo offeres munus tuum ad altare et ibi recordatus fueris quia frater tuus habet aliquid adversum te;"}}, {"v": 24, "ref": "5:24", "o": "ἄφες ἐκεῖ τὸ δῶρόν σου ἔμπροσθεν τοῦ θυσιαστηρίου καὶ ὕπαγε πρῶτον διαλλάγηθι τῷ ἀδελφῷ σου, καὶ τότε ἐλθὼν πρόσφερε τὸ δῶρόν σου.", "en": {"kjv": "Leave there thy gift before the altar, and go thy way; first be reconciled to thy brother, and then come and offer thy gift.", "web": "leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift.", "bsb": "leave your gift there before the altar. First go and be reconciled to your brother; then come and offer your gift.", "asv": "leave there thy gift before the altar, and go thy way, first be reconciled to thy brother, and then come and offer thy gift.", "ylt": "leave there thy gift before the altar, and go--first be reconciled to thy brother, and then having come bring thy gift.", "tyndale": "leue there thyne offrynge before the altre and go thy waye first and be reconcyled to thy brother and then come and offre thy gyfte.", "dra": "Leave there thy offering before the altar, and go first to be reconciled to thy brother, and then coming thou shalt offer thy gift.", "bbe": "While your offering is still before the altar, first go and make peace with your brother, then come and make your offering.", "geneva": "Leaue there thine offring before the altar, and goe thy way: first be reconciled to thy brother, and then come and offer thy gift.", "wycliffe": "leeue there thi yifte bifor the auter, and go first to be recounselid to thi brothir, and thanne thou schalt come, and schalt offre thi yifte.", "rotherham": "leave, there, thy gift before the altar, and withdraw,—first, be reconciled unto thy brother, and, then, coming, be offering thy gift.", "weymouth": "leave your gift there before the altar, and go and make friends with your brother first, and then return and proceed to offer your gift.", "darby": "leave there thy gift before the altar, and first go, be reconciled to thy brother, and then come and offer thy gift.", "twenty": "leave your gift there, before the altar, go and be reconciled to your brother, first, then come and present your gift.", "acv": "leave there thy gift before the altar, and go. First be reconciled to thy brother, and then, after coming, bring thy gift.", "anderson": "leave your gift there before the altar, and go, first be reconciled to your brother, and then come and offer your gift.", "haweis": "leave there thy gift before the altar, and go: first be reconciled to thy brother, and then come and offer thy gift.", "noyes": "leave there thy gift before the altar, and go away; first be reconciled to thy brother, and then come and offer thy gift.", "webster": "Leave there thy gift before the altar, and go thy way; first be reconciled to thy brother, and then come and offer thy gift.", "vulgate": "relinque ibi munus tuum ante altare et vade prius reconciliare fratri tuo et tunc veniens offers munus tuum;"}}, {"v": 25, "ref": "5:25", "o": "ἴσθι εὐνοῶν τῷ ἀντιδίκῳ σου ταχὺ ἕως ὅτου εἶ ⸂μετ’ αὐτοῦ ἐν τῇ ὁδῷ⸃, μήποτέ σε παραδῷ ὁ ἀντίδικος τῷ κριτῇ, καὶ ὁ ⸀κριτὴς τῷ ὑπηρέτῃ, καὶ εἰς φυλακὴν βληθήσῃ·", "en": {"kjv": "Agree with thine adversary quickly, whiles thou art in the way with him; lest at any time the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.", "web": "Agree with your adversary quickly, while you are with him on the way; lest perhaps the prosecutor deliver you to the judge, and the judge deliver you to the officer, and you be cast into prison.", "bsb": "Reconcile quickly with your adversary, while you are still on the way to court. Otherwise, he may hand you over to the judge, and the judge may hand you over to the officer, and you may be thrown into prison.", "asv": "Agree with thine adversary quickly, while thou art with him in the way; lest haply the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.", "ylt": "`Be agreeing with thy opponent quickly, while thou art in the way with him, that the opponent may not deliver thee to the judge, and the judge may deliver thee to the officer, and to prison thou mayest be cast,", "tyndale": "Agre with thyne adversary quicklye whyles thou arte in ye waye with hym lest that adversary deliver ye to ye iudge and ye iudge delivre ye to ye minister and the thou be cast into preson.", "dra": "Be at agreement with thy adversary betimes, whilst thou art in the way with him: lest perhaps the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.", "bbe": "Come to an agreement quickly with him who has a cause against you at law, while you are with him on the way, for fear that he may give you up to the judge and the judge may give you to the police and you may be put into prison.", "geneva": "Agree with thine aduersarie quickly, whiles thou art in the way with him, lest thine aduersarie deliuer thee to the Iudge, and the Iudge deliuer thee to ye sergeant, and thou be cast into prison.", "wycliffe": "Be thou consentynge to thin aduersarie soone, while thou art in the weie with hym, lest perauenture thin aduersarie take thee to the domesman, and the domesman take thee to the mynystre, and thou be sent in to prisoun.", "rotherham": "Be making agreement with thine adversary, quickly, while thou art with him, in the way,—lest once thine adversary deliver thee up unto the judge, and the judge, unto the officer, and, into prison, thou be cast.", "weymouth": "Come to terms without delay with your opponent while you are yet with him on the way to the court; for fear he should obtain judgement from the magistrate against you, and the magistrate should give you in custody to the officer and you be thrown into prison.", "darby": "Make friends with thine adverse party quickly, whilst thou art in the way with him; lest some time the adverse party deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.", "twenty": "Be ready to make friends with your opponent, even when you meet him on your way to the court; for fear that he should hand you over to the judge, and the judge to his officer, and you should be thrown into prison.", "acv": "Be agreeing with thine opponent quickly, while thou are with him on the way, lest the opponent deliver thee to the judge, and the judge deliver thee to the subordinate, and thou will be cast into prison.", "anderson": "Come to an agreement with your opponent at law quickly, while you are on the road with him, lest your opponent at law deliver you to the judge, and the judge deliver you to the officer, and you be thrown into prison.", "haweis": "Be disposed to agree with thy prosecutor speedily, whilst thou art in the way with him to the bar; lest the prosecutor deliver thee up to the judge, and the judge commit thee to the officer, and thou be cast into prison.", "noyes": "Agree with thine adversary at law quickly, while thou art on the road with him; lest the adversary deliver thee to the judge, and the judge to the officer, and thou be cast into prison.", "webster": "Agree with thy adversary quickly, while thou art in the way with him; lest at any time the adversary deliver thee to the judge, and the judge deliver thee to the officer, and thou be cast into prison.", "vulgate": "esto consentiens adversario tuo cito dum es in via cum eo ne forte tradat te adversarius iudici et iudex tradat te ministro et in carcerem mittaris;"}}, {"v": 26, "ref": "5:26", "o": "ἀμὴν λέγω σοι, οὐ μὴ ἐξέλθῃς ἐκεῖθεν ἕως ἂν ἀποδῷς τὸν ἔσχατον κοδράντην.", "en": {"kjv": "Verily I say unto thee, Thou shalt by no means come out thence, till thou hast paid the uttermost farthing.", "web": "Most certainly I tell you, you shall by no means get out of there, until you have paid the last penny.", "bsb": "Truly I tell you, you will not get out until you have paid the last penny.", "asv": "Verily I say unto thee, Thou shalt by no means come out thence, till thou have paid the last farthing.", "ylt": "verily I say to thee, thou mayest not come forth thence till that thou mayest pay the last farthing.", "tyndale": "I say vnto ye verely: thou shalt not come out thece till thou have payed ye utmost farthige.", "dra": "Amen I say to thee, thou shalt not go out from thence till thou repay the last farthing.", "bbe": "Truly I say to you, You will not come out from there till you have made payment of the very last farthing.", "geneva": "Verely I say vnto thee, thou shalt not come out thence, till thou hast payed the vtmost farthing.", "wycliffe": "Treuli Y seie to thee, thou shalt not go out fro thennus, til thou yelde the last ferthing.", "rotherham": "Verily, I say unto thee, In nowise, mayest thou come out from thence, until thou pay the last halfpenny.", "weymouth": "I solemnly tell you that you will certainly not be released till you have paid the very last farthing.", "darby": "Verily I say to thee, Thou shalt in no wise come out thence till thou hast paid the last farthing.", "twenty": "I tell you, you will not come out until you have paid the last penny.", "acv": "Truly I say to thee, thou will, no, not come out from there, until thou have paid the last quadran.", "anderson": "Verily, I say to you, You shall by no means come out thence, till you have paid the last farthing.", "haweis": "Verily I say unto thee, Thou shalt in no wise come out from thence, till thou hast paid the last farthing.", "noyes": "Truly do I say to thee, Thou wilt not come out thence, till thou hast paid the last farthing.", "webster": "Verily, I say to thee, thou shalt by no means come out thence, till thou hast paid the uttermost farthing.", "vulgate": "amen dico tibi non exies inde donec reddas novissimum quadrantem;"}}, {"v": 27, "ref": "5:27", "o": "Ἠκούσατε ὅτι ἐρρέθη· Οὐ μοιχεύσεις.", "en": {"kjv": "Ye have heard that it was said by them of old time, Thou shalt not commit adultery:", "web": "“You have heard that it was said, ‘You shall not commit adultery;’", "bsb": "You have heard that it was said, ‘Do not commit adultery.’", "asv": "Ye have heard that it was said, Thou shalt not commit adultery:", "ylt": "`Ye heard that it was said to the ancients: Thou shalt not commit adultery;", "tyndale": "Ye haue hearde howe it was sayde to the of olde tyme: Thou shalt not comitt advoutrie.", "dra": "You have heard that it was said to them of old: Thou shalt not commit adultery.", "bbe": "You have knowledge that it was said, You may not have connection with another man's wife:", "geneva": "Ye haue heard that it was sayd to them of olde time, Thou shalt not commit adulterie.", "wycliffe": "Ye han herd that it was seid to elde men, Thou schalt `do no letcherie.", "rotherham": "Ye have heard, that it was said, Thou shalt not commit adultery:", "weymouth": "\"You have heard that it was said, `Thou shalt not commit adultery.'", "darby": "Ye have heard that it has been said, Thou shalt not commit adultery.", "twenty": "You have heard that it was said — ‘Thou shalt not commit adultery.’", "acv": "Ye have heard that it was said, Thou shall not commit adultery.", "anderson": "You have heard that it was said: You shall not commit adultery.", "haweis": "Ye have heard that it was said to those of old, “Thou shalt not commit adultery:”", "noyes": "Ye have heard that it was said, \"Thou shalt not commit adultery.\"", "webster": "Ye have heard that it was said to them of old time, Thou shalt not commit adultery:", "vulgate": "audistis quia dictum est antiquis non moechaberis;"}}, {"v": 28, "ref": "5:28", "o": "ἐγὼ δὲ λέγω ὑμῖν ὅτι πᾶς ὁ βλέπων γυναῖκα πρὸς τὸ ἐπιθυμῆσαι αὐτὴν ἤδη ἐμοίχευσεν αὐτὴν ἐν τῇ καρδίᾳ αὐτοῦ.", "en": {"kjv": "But I say unto you, That whosoever looketh on a woman to lust after her hath committed adultery with her already in his heart.", "web": "but I tell you that everyone who gazes at a woman to lust after her has committed adultery with her already in his heart.", "bsb": "But I tell you that anyone who looks at a woman to lust after her has already committed adultery with her in his heart.", "asv": "but I say unto you, that every one that looketh on a woman to lust after her hath committed adultery with her already in his heart.", "ylt": "but I--I say to you, that every one who is looking on a woman to desire her, did already commit adultery with her in his heart.", "tyndale": "But I say vnto you that whosoeuer looketh on a wyfe lustynge after her hathe comitted advoutrie with hir alredy in his hert.", "dra": "But I say to you, that whosoever shall look on a woman to lust after her, hath already committed adultery with her in his heart.", "bbe": "But I say to you that everyone whose eyes are turned on a woman with desire has had connection with her in his heart.", "geneva": "But I say vnto you, that whosoeuer looketh on a woman to lust after her, hath committed adulterie with her already in his heart.", "wycliffe": "But Y seie to you, that euery man that seeth a womman for to coueite hir, hath now do letcherie bi hir in his herte.", "rotherham": "But, I, say unto you, that, Every one who looketh on a woman so as to covet her, already, hath committed adultery with her, in his heart.", "weymouth": "But I tell you that whoever looks at a woman and cherishes lustful thoughts has already in his heart become guilty with regard to her.", "darby": "But I say unto you, that every one who looks upon a woman to lust after her has already committed adultery with her in his heart.", "twenty": "I, however, say to you that any one who looks at a woman with an impure intention has already committed adultery with her in his heart.", "acv": "But I say to you, that every man who looks on a woman to crave her has already committed adultery with her in his heart.", "anderson": "But I say to you, Whoever looks upon a woman to cherish desire for her, has already committed adultery with her in his heart.", "haweis": "but I say unto you, That every one who looketh upon a woman to lust after her, hath already committed adultery with her in his heart.", "noyes": "But I say to you, that whoever looketh on a woman to lust after her, hath committed adultery with her already in his heart.", "webster": "But I say to you, That whoever looketh on a woman to lust after her, hath committed adultery with her already in his heart.", "vulgate": "ego autem dico vobis quoniam omnis qui viderit mulierem ad concupiscendum eam iam moechatus est eam in corde suo;"}}, {"v": 29, "ref": "5:29", "o": "εἰ δὲ ὁ ὀφθαλμός σου ὁ δεξιὸς σκανδαλίζει σε, ἔξελε αὐτὸν καὶ βάλε ἀπὸ σοῦ, συμφέρει γάρ σοι ἵνα ἀπόληται ἓν τῶν μελῶν σου καὶ μὴ ὅλον τὸ σῶμά σου βληθῇ εἰς γέενναν.", "en": {"kjv": "And if thy right eye offend thee, pluck it out, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.", "web": "If your right eye causes you to stumble, pluck it out and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna.", "bsb": "If your right eye causes you to sin, gouge it out and throw it away. It is better for you to lose one part of your body than for your whole body to be thrown into hell.", "asv": "And if thy right eye causeth thee to stumble, pluck it out, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not thy whole body be cast into hell.", "ylt": "`But, if thy right eye doth cause thee to stumble, pluck it out and cast from thee, for it is good to thee that one of thy members may perish, and not thy whole body be cast to gehenna.", "tyndale": "Wherfore yf thy right eye offende ye plucke hym out and caste him from the. Better it is for the yt one of thy membres perisshe then that thy hole bodye shuld be cast into hell.", "dra": "And if thy right eye scandalize thee, pluck it out and cast it from thee. For it is expedient for thee that one of thy members should perish, rather than thy whole body be cast into hell.", "bbe": "And if your right eye is a cause of trouble to you, take it out and put it away from you; because it is better to undergo the loss of one part, than for all your body to go into hell.", "geneva": "Wherefore if thy right eye cause thee to offend, plucke it out, and cast it from thee: for better it is for thee, that one of thy members perish, then that thy whole body should be cast into hell.", "wycliffe": "That if thi riyt iye sclaundre thee, pulle hym out, and caste fro thee; for it spedith to thee, that oon of thi membris perische, than that al thi bodi go in to helle.", "rotherham": "And, if, thy right eye, is causing thee to stumble, pluck it out, and cast it from thee,—for it profiteth thee, that, one of thy members, should perish, and not, thy whole body, be cast into gehenna.", "weymouth": "If therefore your eye, even the right eye, is a snare to you, tear it out and away with it; it is better for you that one member should be destroyed rather than that your whole body should be thrown into Gehenna.", "darby": "But if thy right eye be a snare to thee, pluck it out and cast it from thee: for it is profitable for thee that one of thy members perish, and not thy whole body be cast into hell.", "twenty": "If your right eye is a snare to you, take it out and throw it away. It would be best for you to lose one part of your body, and not to have the whole of it thrown into the Pit.", "acv": "And if thy right eye causes thee to stumble, remove it and cast it from thee, for it is advantageous for thee that one of thy body-parts should perish, and not thy whole body be cast into hell.", "anderson": "If, then, your right eye ensnare you, tear it out, and throw it from you; for it is profitable for you that one of your members should perish, and not that your whole body should be thrown into hell.", "haweis": "If then thine eye, the right, leads thee to offend, pluck it out, and cast it from thee: for it is highly for thy advantage, that one of thy members be destroyed, and not that thy whole body should be cast into hell.", "noyes": "And if thy right eye cause thee to offend, pluck it out, and cast it from thee; for it is better for thee that one of thy members should perish, than that thy whole body should be cast into hell.", "webster": "And if thy right eye shall cause thee to sin, pluck it out, and cast [it] from thee: for [it] is profitable for thee that one of thy members should perish, and not [that] thy whole body should be cast into hell.", "vulgate": "quod si oculus tuus dexter scandalizat te erue eum et proice abs te expedit enim tibi ut pereat unum membrorum tuorum quam totum corpus tuum mittatur in gehennam;"}}, {"v": 30, "ref": "5:30", "o": "καὶ εἰ ἡ δεξιά σου χεὶρ σκανδαλίζει σε, ἔκκοψον αὐτὴν καὶ βάλε ἀπὸ σοῦ, συμφέρει γάρ σοι ἵνα ἀπόληται ἓν τῶν μελῶν σου καὶ μὴ ὅλον τὸ σῶμά σου ⸂εἰς γέενναν ἀπέλθῃ⸃.", "en": {"kjv": "And if thy right hand offend thee, cut it off, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not that thy whole body should be cast into hell.", "web": "If your right hand causes you to stumble, cut it off, and throw it away from you. For it is more profitable for you that one of your members should perish, than for your whole body to be cast into Gehenna.", "bsb": "And if your right hand causes you to sin, cut it off and throw it away. It is better for you to lose one part of your body than for your whole body to depart into hell.", "asv": "And if thy right hand causeth thee to stumble, cut it off, and cast it from thee: for it is profitable for thee that one of thy members should perish, and not thy whole body go into hell.", "ylt": "`And, if thy right hand doth cause thee to stumble, cut it off, and cast from thee, for it is good to thee that one of thy members may perish, and not thy whole body be cast to gehenna.", "tyndale": "Also if thy right honde offend ye cut hym of and caste hym from the. Better yt ys that one of thy membres perisshe then that all thy body shulde be caste in to hell.", "dra": "And if thy right hand scandalize thee, cut it off, and cast it from thee: for it is expedient for thee that one of thy members should perish, rather than that thy whole body go into hell.", "bbe": "And if your right hand is a cause of trouble to you, let it be cut off and put it away from you; because it is better to undergo the loss of one part, than for all your body to go into hell.", "geneva": "Also if thy right hand make thee to offend, cut it off, and cast it from thee: for better it is for thee that one of thy members perish, then that thy whole body should be cast into hell.", "wycliffe": "And if thi riyt hond sclaundre thee, kitte hym aweye, and caste fro thee; for it spedith to thee that oon of thi membris perische, than that al thi bodi go in to helle.", "rotherham": "And, if, thy right hand, is causing thee to stumble, cut it off, and cast it from thee,—for it profiteth thee, that, one of thy members, should perish, and not, thy whole body, into gehenna, depart.", "weymouth": "And if your right hand is a snare to you, cut it off and away with it; it is better for you that one member should be destroyed rather than that your whole body should go into Gehenna.", "darby": "And if thy right hand be a snare to thee, cut it off and cast it from thee: for it is profitable for thee that one of thy members perish, and not thy whole body be cast into hell.", "twenty": "And, if your right hand is a snare to you, cut it off and throw it away. It would be best for you to lose one part of your body, and not to have the whole of it go down to the Pit.", "acv": "And if thy right hand causes thee to stumble, cut it off and cast it from thee, for it is advantageous for thee that one of thy body-parts should perish, and not thy whole body be cast into hell.", "anderson": "And if your right hand ensnare you, cut it off, and throw it from you; for it is profitable for you that one of your members should perish, and not that your whole body should be thrown into hell.", "haweis": "And if thy right hand leads thee to offend, cut it off, and cast it from thee: for it is highly thy interest that one of thy members should be destroyed, and not that thy whole body should be cast into hell.", "noyes": "And if thy right hand cause thee to offend, cut it off, and cast it from thee; for it is better for thee that one of thy members should perish, than that thy whole body should go away into hell.", "webster": "And if thy right hand shall cause thee to sin, cut it off, and cast [it] from thee: for it is profitable for thee that one of thy members should perish, and not [that] thy whole body should be cast into hell.", "vulgate": "et si dextera manus tua scandalizat te abscide eam et proice abs te expedit tibi ut pereat unum membrorum tuorum quam totum corpus tuum eat in gehennam;"}}, {"v": 31, "ref": "5:31", "o": "Ἐρρέθη ⸀δέ· Ὃς ἂν ἀπολύσῃ τὴν γυναῖκα αὐτοῦ, δότω αὐτῇ ἀποστάσιον.", "en": {"kjv": "It hath been said, Whosoever shall put away his wife, let him give her a writing of divorcement:", "web": "“It was also said, ‘Whoever shall put away his wife, let him give her a writing of divorce,’", "bsb": "It has also been said, ‘Whoever divorces his wife must give her a certificate of divorce.’", "asv": "It was said also, Whosoever shall put away his wife, let him give her a writing of divorcement:", "ylt": "`And it was said, That whoever may put away his wife, let him give to her a writing of divorce;", "tyndale": "It ys sayd whosoever put awaye his wyfe let hym geve her a testymonyall also of the devorcement.", "dra": "And it hath been said, Whosoever shall put away his wife, let him give her a bill of divorce.", "bbe": "Again, it was said, Whoever puts away his wife has to give her a statement in writing for this purpose:", "geneva": "It hath bene sayd also, Whosoeuer shall put away his wife, let him giue her a bill of diuorcement.", "wycliffe": "And it hath be seyd, Who euere leeueth his wijf, yyue he to hir a libel of forsakyng.", "rotherham": "It was said, moreover, Whosoever shall divorce his wife, let him give her a writing of divorcement;", "weymouth": "\"It was also said, `If any man puts away his wife, let him give her a written notice of divorce.'", "darby": "It has been said too, Whosoever shall put away his wife, let him give her a letter of divorce.", "twenty": "It was also said — ‘Let any one who divorces his wife serve her with a notice of separation.’", "acv": "And it was said, Whoever may divorce his wife, let him give her a divorce certificate.", "anderson": "It has been said: Whoever will put away his wife, let him give her a bill of divorce.", "haweis": "It hath been said indeed, That whosoever will put away his wife, let him give her a bill of divorce:", "noyes": "And it was said, \"Whoever shall put away his wife, let him give her a writing of divorcement.\"", "webster": "It hath been said, Whoever shall put away his wife, let him give her a writing of divorcement:", "vulgate": "dictum est autem quicumque dimiserit uxorem suam det illi libellum repudii;"}}, {"v": 32, "ref": "5:32", "o": "ἐγὼ δὲ λέγω ὑμῖν ὅτι ⸂πᾶς ὁ ἀπολύων⸃ τὴν γυναῖκα αὐτοῦ παρεκτὸς λόγου πορνείας ποιεῖ αὐτὴν ⸀μοιχευθῆναι, καὶ ὃς ἐὰν ἀπολελυμένην γαμήσῃ μοιχᾶται.", "en": {"kjv": "But I say unto you, That whosoever shall put away his wife, saving for the cause of fornication, causeth her to commit adultery: and whosoever shall marry her that is divorced committeth adultery.", "web": "but I tell you that whoever puts away his wife, except for the cause of sexual immorality, makes her an adulteress; and whoever marries her when she is put away commits adultery.", "bsb": "But I tell you that anyone who divorces his wife, except for sexual immorality, brings adultery upon her. And he who marries a divorced woman commits adultery.", "asv": "but I say unto you, that every one that putteth away his wife, saving for the cause of fornication, maketh her an adulteress: and whosoever shall marry her when she is put away committeth adultery.", "ylt": "but I--I say to you, that whoever may put away his wife, save for the matter of whoredom, doth make her to commit adultery; and whoever may marry her who hath been put away doth commit adultery.", "tyndale": "But I say vnto you: whosoever put awaye his wyfe (except it be for fornicacion) causeth her to breake matrymony. And whosoever maryeth her that is devorsed breaketh wedlocke.", "dra": "But I say to you, that whosoever shall put away his wife, excepting the cause of fornication, maketh her to commit adultery: and he that shall marry her that is put away, committeth adultery.", "bbe": "But I say to you that everyone who puts away his wife for any other cause but the loss of her virtue, makes her false to her husband; and whoever takes her as his wife after she is put away, is no true husband to her.", "geneva": "But I say vnto you, whosoeuer shall put away his wife (except it be for fornication) causeth her to commit adulterie: and whosoeuer shall marrie her that is diuorced, committeth adulterie.", "wycliffe": "But Y seie to you, that euery man that leeueth his wijf, outtakun cause of fornycacioun, makith hir to do letcherie, and he that weddith the forsakun wijf, doith auowtrye.", "rotherham": "But, I, say unto you, that, Everyone who divorceth his wife—saving for unfaithfulness, causeth her to be made an adulteress,—[and, whosoever shall marry a divorced woman, committeth adultery].", "weymouth": "But I tell you that every man who puts away his wife except on the ground of unfaithfulness causes her to commit adultery, and whoever marries her when so divorced commits adultery.", "darby": "But I say unto you, that whosoever shall put away his wife, except for cause of fornication, makes her commit adultery, and whosoever marries one that is put away commits adultery.", "twenty": "I, however, say to you that any one who divorces his wife, except on the ground of her unchastity, leads to her committing adultery; while any one who marries her after her divorce is guilty of adultery.", "acv": "But I say to you, that whoever may divorce his wife apart from a matter of fornication, disposes her to commit adultery, and whoever may marry her who has been divorced commits adultery.", "anderson": "But I say to you, Whoever shall put away his wife, unless on account of lewdness, causes her to commit adultery: and whoever marries her that is divorced, commits adultery.", "haweis": "But I say unto you, Whosoever shall put away his wife, except on account of whoredom, causeth her to commit adultery: and whosoever shall marry her that is put away, committeth adultery.", "noyes": "But I say to you, that whoever putteth away his wife, unless it be on account of fornication, causeth her to commit adultery; and whoever shall marry her when put away, committeth adultery.", "webster": "But I say to you, That whoever shall put away his wife, saving for the cause of lewdness, causeth her to commit adultery: and whoever shall marry her that is divorced, committeth adultery.", "vulgate": "ego autem dico vobis quia omnis qui dimiserit uxorem suam excepta fornicationis causa facit eam moechari et qui dimissam duxerit adulterat;"}}, {"v": 33, "ref": "5:33", "o": "Πάλιν ἠκούσατε ὅτι ἐρρέθη τοῖς ἀρχαίοις· Οὐκ ἐπιορκήσεις, ἀποδώσεις δὲ τῷ κυρίῳ τοὺς ὅρκους σου.", "en": {"kjv": "Again, ye have heard that it hath been said by them of old time, Thou shalt not forswear thyself, but shalt perform unto the Lord thine oaths:", "web": "“Again you have heard that it was said to them of old time, ‘You shall not make false vows, but shall perform to the Lord your vows,’", "bsb": "Again, you have heard that it was said to the ancients, ‘Do not break your oath, but fulfill your vows to the Lord.’", "asv": "Again, ye have heard that it was said to them of old time, Thou shalt not forswear thyself, but shalt perform unto the Lord thine oaths:", "ylt": "`Again, ye heard that it was said to the ancients: Thou shalt not swear falsely, but thou shalt pay to the Lord thine oaths;", "tyndale": "Agayne ye haue hearde how it was sayd to the of olde tyme thou shalt not forsuere thy selfe but shalt performe thyne othe to God.", "dra": "Again you have heard that it was said to them of old, thou shalt not forswear thyself: but thou shalt perform thy oaths to the Lord.", "bbe": "Again, you have knowledge that it was said in old times, Do not take false oaths, but give effect to your oaths to the Lord:", "geneva": "Againe, ye haue heard that it was sayd to them of old time, Thou shalt not forsweare thy selfe, but shalt performe thine othes to the Lord.", "wycliffe": "Eftsoone ye han herd, that it was seid to elde men, Thou schalt not forswere, but thou schalt yelde thin othis to the Lord.", "rotherham": "Again, ye have heard that it was said, to them of olden time, Thou shalt not swear falsely,—but shalt render unto the Lord, thine oaths.", "weymouth": "\"Again, you have heard that it was said to the ancients, `Thou shalt not swear falsely, but shalt perform thy vows to the Lord.'", "darby": "Again, ye have heard that it has been said to the ancients, Thou shalt not forswear thyself, but shalt render to the Lord what thou hast sworn.", "twenty": "Again, you have heard that to our ancestors it was said — ‘Thou shalt not break an oath, but thou shall keep thine oaths as a debt due to the Lord.’", "acv": "Again, ye have heard that it was said to them in old times, Thou shall not swear falsely, but shall render to the Lord thine oaths.", "anderson": "Again, you have heard that it was said to the ancients: You shall not swear falsely, but shall pay to the Lord your vows.", "haweis": "Again ye have heard that it was said to those of old, “Thou shalt not perjure thyself, but shalt perform to the Lord thine oaths:”", "noyes": "Again ye have heard that it was said to them of old time, \"Thou shalt not swear falsely, but shalt perform to the Lord thine oaths.\"", "webster": "Again, ye have heard that it hath been said to them of old time, Thou shalt not forswear thyself, but shalt perform to the Lord thy oaths:", "vulgate": "iterum audistis quia dictum est antiquis non peierabis reddes autem Domino iuramenta tua;"}}, {"v": 34, "ref": "5:34", "o": "ἐγὼ δὲ λέγω ὑμῖν μὴ ὀμόσαι ὅλως· μήτε ἐν τῷ οὐρανῷ, ὅτι θρόνος ἐστὶν τοῦ θεοῦ·", "en": {"kjv": "But I say unto you, Swear not at all; neither by heaven; for it is God’s throne:", "web": "but I tell you, don’t swear at all: neither by heaven, for it is the throne of God;", "bsb": "But I tell you not to swear at all: either by heaven, for it is God’s throne;", "asv": "but I say unto you, Swear not at all; neither by the heaven, for it is the throne of God;", "ylt": "but I--I say to you, not to swear at all; neither by the heaven, because it is the throne of God,", "tyndale": "But I saye vnto you swere not at all nether by heue for it ys Goddes seate:", "dra": "But I say to you not to swear at all, neither by heaven for it is the throne of God:", "bbe": "But I say to you, Take no oaths at all: not by the heaven, because it is the seat of God;", "geneva": "But I say vnto you, Sweare not at all, neither by heauen, for it is the throne of God:", "wycliffe": "But Y seie to you, that ye swere not `for ony thing; nethir bi heuene, for it is the trone of God;", "rotherham": "But, I, tell you—not to swear, at all: Neither by heaven, because it is the, throne of God,—", "weymouth": "But I tell you not to swear at all; neither by Heaven, for it is God's throne;", "darby": "But I say unto you, Do not swear at all; neither by the heaven, because it is [the] throne ofGod;", "twenty": "I, however, say to you that you must not swear at all, either by Heaven, since that is God’s throne,", "acv": "But I say to you, not to swear at all, neither by heaven, because it is the throne of God,", "anderson": "But I say to you, Swear not at all: neither by heaven, for it is the throne of God;", "haweis": "But I say to thee, Swear not at all; neither by the heaven; for it is the throne of God:", "noyes": "But I say to you, Swear not at all; neither by heaven, for it is the throne of God;", "webster": "But I say to you, Swear not at all: neither by heaven; for it is God's throne:", "vulgate": "ego autem dico vobis non iurare omnino neque per caelum quia thronus Dei est;"}}, {"v": 35, "ref": "5:35", "o": "μήτε ἐν τῇ γῇ, ὅτι ὑποπόδιόν ἐστιν τῶν ποδῶν αὐτοῦ· μήτε εἰς Ἱεροσόλυμα, ὅτι πόλις ἐστὶν τοῦ μεγάλου βασιλέως·", "en": {"kjv": "Nor by the earth; for it is his footstool: neither by Jerusalem; for it is the city of the great King.", "web": "nor by the earth, for it is the footstool of his feet; nor by Jerusalem, for it is the city of the great King.", "bsb": "or by the earth, for it is His footstool; or by Jerusalem, for it is the city of the great King.", "asv": "nor by the earth, for it is the footstool of his feet; nor by Jerusalem, for it is the city of the great King.", "ylt": "nor by the earth, because it is His footstool, nor by Jerusalem, because it is a city of a great king,", "tyndale": "nor yet by the erth for it is his fote stole: nether by Ierusalem for it ys ye cyte of yt greate kynge:", "dra": "Nor by the earth, for it is his footstool: nor by Jerusalem, for it is the city of the great king:", "bbe": "Or by the earth, because it is the resting-place for his foot; or by Jerusalem, because it is the town of the great King.", "geneva": "Nor yet by the earth: for it is his footestoole: neither by Hierusalem: for it is the citie of the great King.", "wycliffe": "nether bi the erthe, for it is the stole of his feet; nether bi Jerusalem, for it is the citee of a greet kyng; nether thou shalt not swere bi thin heed,", "rotherham": "Nor by the earth, because it is his, footstool; nor by Jerusalem, because, it is the, city, of the Great King;", "weymouth": "nor by the earth, for it is the footstool under His feet; nor by Jerusalem, for it is the City of the Great King.", "darby": "nor by the earth, because it is [the] footstool of his feet; nor by Jerusalem, because it is [the] city of the great King.", "twenty": "or by the earth, since that is his footstool, or by Jerusalem, since that is the city of the Great King.", "acv": "nor by the earth, because it is the footstool of his feet, nor by Jerusalem, because it is the city of the great King.", "anderson": "nor by the earth, for it is his footstool; nor by Jerusalem, for it is the city of the great King:", "haweis": "nor by the earth; for it is the footstool of his feet: nor by Jerusalem; for it is the city of the great King:", "noyes": "nor by the earth, for it is his footstool; nor by Jerusalem, for it is the city of the Great King;", "webster": "Nor by the earth; for it is his footstool: neither by Jerusalem; for it is the city of the great King,", "vulgate": "neque per terram quia scabillum est pedum eius neque per Hierosolymam quia civitas est magni Regis;"}}, {"v": 36, "ref": "5:36", "o": "μήτε ἐν τῇ κεφαλῇ σου ὀμόσῃς, ὅτι οὐ δύνασαι μίαν τρίχα λευκὴν ⸂ποιῆσαι ἢ μέλαιναν⸃.", "en": {"kjv": "Neither shalt thou swear by thy head, because thou canst not make one hair white or black.", "web": "Neither shall you swear by your head, for you can’t make one hair white or black.", "bsb": "Nor should you swear by your head, for you cannot make a single hair white or black.", "asv": "Neither shalt thou swear by thy head, for thou canst not make one hair white or black.", "ylt": "nor by thy head mayest thou swear, because thou art not able one hair to make white or black;", "tyndale": "nether shalt thou sweare by thy heed because thou canst not make one white heer or blacke:", "dra": "Neither shalt thou swear by thy head, because thou canst not make one hair white or black.", "bbe": "You may not take an oath by your head, because you are not able to make one hair white or black.", "geneva": "Neither shalt thou sweare by thine head, because thou canst not make one heare white or blacke.", "wycliffe": "for thou maist not make oon heere white, ne blacke;", "rotherham": "Nor, by thine own head, mayest thou swear, because thou art not able to make, one hair, white or black.", "weymouth": "And do not swear by your head, for you cannot make one hair white or black.", "darby": "Neither shalt thou swear by thy head, because thou canst not make one hair white or black.", "twenty": "Nor should you swear by your head, since you cannot make a single hair either white or black.", "acv": "Neither shall thou swear by thy head, because thou cannot make one hair white or black.", "anderson": "neither shall you swear by your head, for you can not make one hair white or black.", "haweis": "neither shalt thou swear by thy head, for thou canst not make one hair white or black.", "noyes": "nor shalt thou swear by thy head, for thou canst not make one hair white or black.", "webster": "Neither shalt thou swear by thy head, because thou canst not make one hair white or black.", "vulgate": "neque per caput tuum iuraveris quia non potes unum capillum album facere aut nigrum;"}}, {"v": 37, "ref": "5:37", "o": "ἔστω δὲ ὁ λόγος ὑμῶν ναὶ ναί, οὒ οὔ· τὸ δὲ περισσὸν τούτων ἐκ τοῦ πονηροῦ ἐστιν.", "en": {"kjv": "But let your communication be, Yea, yea; Nay, nay: for whatsoever is more than these cometh of evil.", "web": "But let your ‘Yes’ be ‘Yes’ and your ‘No’ be ‘No.’ Whatever is more than these is of the evil one.", "bsb": "Simply let your ‘Yes’ be ‘Yes,’ and your ‘No,’ ‘No.’ Anything more comes from the evil one.", "asv": "But let your speech be, Yea, yea; Nay, nay: and whatsoever is more than these is of the evil one.", "ylt": "but let your word be, Yes, Yes, No, No, and that which is more than these is of the evil.", "tyndale": "But your comunicacion shalbe ye ye: nay nay. For whatsoeuer is more then yt cometh of yvell.", "dra": "But let your speech be yea, yea: no, no: and that which is over and above these, is of evil.", "bbe": "But let your words be simply, Yes or No: and whatever is more than these is of the Evil One.", "geneva": "But let your communication be Yea, yea: Nay, nay. For whatsoeuer is more then these, commeth of euill.", "wycliffe": "but be youre word, Yhe, yhe; Nay, nay; and that that is more than these, is of yuel.", "rotherham": "But let your word be, Yea, yea,—Nay, nay; and, what goeth beyond these, is, of evil.", "weymouth": "But let your language be, `Yes, yes,' or `No, no.' Anything in excess of this comes from the Evil one.", "darby": "But let your word be Yea, yea; Nay, nay; but what is more than these is from evil.", "twenty": "Let your words be simply ‘Yes’ or ‘No’; anything beyond this comes from what is wrong.", "acv": "But let your word be, Yes, yes, No, no. And anything beyond these is from evil.", "anderson": "But let your word be, Yes, yes; No, no; for whatever is more than these is of the Evil One.", "haweis": "But let your discourse be, Yea, yea; No, no: for all addition to these is from the wicked one.", "noyes": "But let your language be, Yea, yea; Nay; nay; for whatever is more than these cometh of evil.", "webster": "But let your communication be, Yea, yea, Nay, nay: for whatever [is] more than these cometh of evil.", "vulgate": "sit autem sermo vester est est non non quod autem his abundantius est a malo est;"}}, {"v": 38, "ref": "5:38", "o": "Ἠκούσατε ὅτι ἐρρέθη· Ὀφθαλμὸν ἀντὶ ὀφθαλμοῦ καὶ ὀδόντα ἀντὶ ὀδόντος.", "en": {"kjv": "Ye have heard that it hath been said, An eye for an eye, and a tooth for a tooth:", "web": "“You have heard that it was said, ‘An eye for an eye, and a tooth for a tooth.’", "bsb": "You have heard that it was said, ‘Eye for eye and tooth for tooth.’", "asv": "Ye have heard that it was said, An eye for an eye, and a tooth for a tooth:", "ylt": "`Ye heard that it was said: Eye for eye, and tooth for tooth;", "tyndale": "Ye have hearde how it ys sayd an eye for an eye: a tothe for a tothe.", "dra": "You have heard that it hath been said: An eye for an eye, and a tooth for a tooth.", "bbe": "You have knowledge that it was said, An eye for an eye, and a tooth for a tooth:", "geneva": "Ye haue heard that it hath bene sayd, An eye for an eye, and a tooth for a tooth.", "wycliffe": "Ye han herd that it hath be seid, Iye for iye, and tothe for tothe.", "rotherham": "Ye have heard, that it was said,—Eye for eye, and tooth for tooth.", "weymouth": "\"You have heard that it was said, `Eye for eye, tooth for tooth.'", "darby": "Ye have heard that it has been said, Eye for eye and tooth for tooth.", "twenty": "You have heard that it was said — ‘An eye for an eye and a tooth for a tooth.’", "acv": "Ye have heard that it was said, An eye for an eye, and a tooth for a tooth.", "anderson": "You have heard that it was said: An eye for an eye, and a tooth for a tooth.", "haweis": "Ye have heard that it was said, “Eye for eye, and tooth for tooth:”", "noyes": "Ye have heard that it was said, \"An eye for an eye, and a tooth for a tooth.\"", "webster": "Ye have heard that it hath been said, An eye for an eye, and a tooth for a tooth.", "vulgate": "audistis quia dictum est oculum pro oculo et dentem pro dente;"}}, {"v": 39, "ref": "5:39", "o": "ἐγὼ δὲ λέγω ὑμῖν μὴ ἀντιστῆναι τῷ πονηρῷ· ἀλλ’ ὅστις σε ⸀ῥαπίζει ⸀εἰς τὴν δεξιὰν ⸀σιαγόνα, στρέψον αὐτῷ καὶ τὴν ἄλλην·", "en": {"kjv": "But I say unto you, That ye resist not evil: but whosoever shall smite thee on thy right cheek, turn to him the other also.", "web": "But I tell you, don’t resist him who is evil; but whoever strikes you on your right cheek, turn to him the other also.", "bsb": "But I tell you not to resist an evil person. If someone slaps you on your right cheek, turn to him the other also;", "asv": "but I say unto you, Resist not him that is evil: but whosoever smiteth thee on thy right cheek, turn to him the other also.", "ylt": "but I--I say to you, not to resist the evil, but whoever shall slap thee on thy right cheek, turn to him also the other;", "tyndale": "But I saye to you that ye resist not wroge. But whosoever geve the a blowe on thy right cheke tourne to him the other.", "dra": "But I say to you not to resist evil: but if one strike thee on thy right cheek, turn to him also the other:", "bbe": "But I say to you, Do not make use of force against an evil man; but to him who gives you a blow on the right side of your face let the left be turned.", "geneva": "But I say vnto you, Resist not euill: but whosoeuer shall smite thee on thy right cheeke, turne to him the other also.", "wycliffe": "But Y seie to you, that ye ayenstonde not an yuel man; but if ony smyte thee in the riyt cheke, schewe to him also the tothir;", "rotherham": "But, I, tell you, not to resist evil,—Nay, whoever is smiting thee on the right cheek, turn to him, the other also;", "weymouth": "But I tell you not to resist a wicked man, but if any one strikes you on the right cheek, turn the other to him as well.", "darby": "But I say unto you, not to resist evil; but whoever shall strike thee on thy right cheek, turn to him also the other;", "twenty": "I, however, say to you that you must not resist wrong; but, if any one strikes you on the right cheek, turn the other to him also;", "acv": "But I say to you, not to resist what is troublesome, but whoever will strike thee on thy right cheek, turn to him the other also.", "anderson": "But I say to you, Resist not the injurious. But whoever will smite you on your right cheek, turn to him the other also.", "haweis": "but I say unto you, Resist not an injurious act; but whosoever shall smite thee on the right cheek, turn to him also the other.", "noyes": "But I say to you, that ye resist not the evil-doer; but whoever smiteth thee on the right cheek, turn to him the other also;", "webster": "But I say to you, That ye resist not evil: but whoever shall strike thee on thy right cheek, turn to him the other also.", "vulgate": "ego autem dico vobis non resistere malo sed si quis te percusserit in dextera maxilla tua praebe illi et alteram;"}}, {"v": 40, "ref": "5:40", "o": "καὶ τῷ θέλοντί σοι κριθῆναι καὶ τὸν χιτῶνά σου λαβεῖν, ἄφες αὐτῷ καὶ τὸ ἱμάτιον·", "en": {"kjv": "And if any man will sue thee at the law, and take away thy coat, let him have thy cloke also.", "web": "If anyone sues you to take away your coat, let him have your cloak also.", "bsb": "if someone wants to sue you and take your tunic, let him have your cloak as well;", "asv": "And if any man would go to law with thee, and take away thy coat, let him have thy cloak also.", "ylt": "and whoever is willing to take thee to law, and thy coat to take--suffer to him also the cloak.", "tyndale": "And yf eny man will sue the at the lawe and take awaye thy coote let hym have thy cloocke also.", "dra": "And if a man will contend with thee in judgment, and take away thy coat, let go thy cloak also unto him.", "bbe": "And if any man goes to law with you and takes away your coat, do not keep back your robe from him.", "geneva": "And if any man wil sue thee at the law, and take away thy coate, let him haue thy cloke also.", "wycliffe": "and to hym that wole stryue with thee in doom, and take awey thi coote, leeue thou `to him also thi mantil;", "rotherham": "And, him who is desiring thee to be judged, and to take, thy tunic, let him have, thy mantle also.", "weymouth": "If any one wishes to go to law with you and to deprive you of your under garment, let him take your outer one also.", "darby": "and to him that would go to law with thee and take thy body coat, leave him thy cloak also.", "twenty": "and, when any one wants to go to law with you, to take your coat, let him have your cloak as well;", "acv": "And to the man who wants to sue thee, and take away thy coat, thou shall leave him thy cloak also.", "anderson": "And to him that will go to law with you, and take away your coat, give your mantle also.", "haweis": "And if a man will prosecute thee, and take thy coat, let him have thy cloak also.", "noyes": "and if any one intends to sue thee at the law, and take thy coat, give up to him thy cloak also;", "webster": "And if any man will sue thee at the law, and take away thy coat, let him have [thy] cloke also.", "vulgate": "et ei qui vult tecum iudicio contendere et tunicam tuam tollere remitte ei et pallium;"}}, {"v": 41, "ref": "5:41", "o": "καὶ ὅστις σε ἀγγαρεύσει μίλιον ἕν, ὕπαγε μετ’ αὐτοῦ δύο.", "en": {"kjv": "And whosoever shall compel thee to go a mile, go with him twain.", "web": "Whoever compels you to go one mile, go with him two.", "bsb": "and if someone forces you to go one mile, go with him two miles.", "asv": "And whosoever shall compel thee to go one mile, go with him two.", "ylt": "`And whoever shall impress thee one mile, go with him two,", "tyndale": "And whosoever wyll copell the to goo a myle goo wyth him twayne.", "dra": "And whosoever will force thee one mile, go with him other two.", "bbe": "And whoever makes you go one mile, go with him two.", "geneva": "And whosoeuer will compell thee to goe a mile, goe with him twaine.", "wycliffe": "and who euer constreyneth thee a thousynde pacis, go thou with hym othir tweyne.", "rotherham": "And, whoever shall impress thee one mile, go with him two:", "weymouth": "And whoever shall compel you to convey his goods one mile, go with him two.", "darby": "And whoever will compel thee to go one mile, go with him two.", "twenty": "and, if any one compels you to go one mile, go two miles with him.", "acv": "And whoever will draft thee for one mile, go thou with him two.", "anderson": "And whoever will compel you to go one mile, go with him two.", "haweis": "And whosoever shall press thee for one mile, go with him two.", "noyes": "and whoever shall compel thee to go one mile, go with him two.", "webster": "And whoever shall constrain thee [to go] one mile, go with him two.", "vulgate": "et quicumque te angariaverit mille passus vade cum illo alia duo;"}}, {"v": 42, "ref": "5:42", "o": "τῷ αἰτοῦντί σε ⸀δός, καὶ τὸν θέλοντα ἀπὸ σοῦ δανίσασθαι μὴ ἀποστραφῇς.", "en": {"kjv": "Give to him that asketh thee, and from him that would borrow of thee turn not thou away.", "web": "Give to him who asks you, and don’t turn away him who desires to borrow from you.", "bsb": "Give to the one who asks you, and do not turn away from the one who wants to borrow from you.", "asv": "Give to him that asketh thee, and from him that would borrow of thee turn not thou away.", "ylt": "to him who is asking of thee be giving, and him who is willing to borrow from thee thou mayest not turn away.", "tyndale": "Geve to him that axeth and fro him that wolde borowe tourne not awaye.", "dra": "Give to him that asketh of thee, and from him that would borrow of thee turn not away.", "bbe": "Give to him who comes with a request, and keep not your property from him who would for a time make use of it.", "geneva": "Giue to him that asketh, and from him that would borowe of thee, turne not away.", "wycliffe": "Yyue thou to hym that axith of thee, and turne not awey fro hym that wole borewe of thee.", "rotherham": "To him who is asking thee, give; and, him who is desiring from thee to borrow, do not thou turn away.", "weymouth": "To him who asks, give: from him who would borrow, turn not away.", "darby": "To him that asks of thee give, and from him that desires to borrow of thee turn not away.", "twenty": "Give to him who asks of you; and, from him who wants to borrow from you, do not turn away.", "acv": "Give to him who asks thee, and turn thou not away from him who wants to borrow from thee.", "anderson": "Give to him that asks of you; and from him that would borrow of you, turn not away.", "haweis": "Give to him that asketh thee; and from him who wants to borrow of thee, turn not away.", "noyes": "Give to him that asketh of thee; and from him that would borrow of thee, turn not away.", "webster": "Give to him that asketh thee, and from him that would borrow of thee, turn not thou away.", "vulgate": "qui petit a te da ei et volenti mutuari a te ne avertaris;"}}, {"v": 43, "ref": "5:43", "o": "Ἠκούσατε ὅτι ἐρρέθη· Ἀγαπήσεις τὸν πλησίον σου καὶ μισήσεις τὸν ἐχθρόν σου.", "en": {"kjv": "Ye have heard that it hath been said, Thou shalt love thy neighbour, and hate thine enemy.", "web": "“You have heard that it was said, ‘You shall love your neighbor, and hate your enemy.’", "bsb": "You have heard that it was said, ‘Love your neighbor’ and ‘Hate your enemy.’", "asv": "Ye have heard that it was said, Thou shalt love thy neighbor, and hate thine enemy:", "ylt": "`Ye heard that it was said: Thou shalt love thy neighbour, and shalt hate thine enemy;", "tyndale": "Ye have hearde how it is sayde: thou shalt love thyne neghbour and hate thine enimy.", "dra": "You have heard that it hath been said, Thou shalt love thy neighbour, and hate thy enemy.", "bbe": "You have knowledge that it was said, Have love for your neighbour, and hate for him who is against you:", "geneva": "Ye haue heard that it hath bin said, Thou shalt loue thy neighbour, and hate your enemie.", "wycliffe": "Ye han herd that it was seid, Thou shalt loue thi neiybore, and hate thin enemye.", "rotherham": "Ye have heard, that it was said, Thou shalt love thy neighbour, and hate thine enemy.", "weymouth": "\"You have heard that it was said, `Thou shalt love thy neighbour and hate thine enemy.'", "darby": "Ye have heard that it has been said, Thou shalt love thy neighbour and hate thine enemy.", "twenty": "You have heard that it was said — ‘Thou shalt love thy neighbour and hate thy enemy.’", "acv": "Ye have heard that it was said, Thou shall love thy neighbor, and hate thine enemy.", "anderson": "You have heard that it was said: You shall love your neighbor, and hate your enemy.", "haweis": "Ye have heard that it hath been said, “Thou shalt love thy neighbour, and hate thine enemy.”", "noyes": "Ye have heard that it was said, \"Thou shalt love thy neighbor, and hate thine enemy.\"", "webster": "Ye have heard that it hath been said, Thou shalt love thy neighbor, and hate thy enemy:", "vulgate": "audistis quia dictum est diliges proximum tuum et odio habebis inimicum tuum;"}}, {"v": 44, "ref": "5:44", "o": "ἐγὼ δὲ λέγω ὑμῖν, ἀγαπᾶτε τοὺς ἐχθροὺς ⸀ὑμῶν καὶ προσεύχεσθε ὑπὲρ ⸀τῶν διωκόντων ὑμᾶς·", "en": {"kjv": "But I say unto you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you;", "web": "But I tell you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who mistreat you and persecute you,", "bsb": "But I tell you, love your enemies and pray for those who persecute you,", "asv": "but I say unto you, Love your enemies, and pray for them that persecute you;", "ylt": "but I--I say to you, Love your enemies, bless those cursing you, do good to those hating you, and pray for those accusing you falsely, and persecuting you,", "tyndale": "But I saye vnto you love youre enimies. Blesse the that coursse you. Do good to them that hate you. Praye for them which doo you wronge and persecute you", "dra": "But I say to you, Love your enemies: do good to them that hate you: and pray for them that persecute and calumniate you:", "bbe": "But I say to you, Have love for those who are against you, and make prayer for those who are cruel to you;", "geneva": "But I say vnto you, Loue your enemies: blesse them that curse you: doe good to them that hate you, and pray for them which hurt you, and persecute you,", "wycliffe": "But Y seie to you, loue ye youre enemyes, do ye wel to hem that hatiden you, and preye ye for hem that pursuen, and sclaundren you;", "rotherham": "But, I, say unto you, Be loving your enemies, and praying for them who are persecuting you:", "weymouth": "But I command you all, love your enemies, and pray for your persecutors;", "darby": "But I say unto you, Love your enemies, [bless those who curse you,] do good to those who hate you, and pray for those who [insult you and] persecute you,", "twenty": "I, however, say to you — Love your enemies, and pray for those who persecute you,", "acv": "But I say to you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who mistreat you and persecute you,", "anderson": "But I say to you, Love your enemies: bless those who curse you, do good to those who hate you, and pray for those who insult you and persecute you:", "haweis": "But I say unto you, Love your enemies, bless those who curse you, do good to those who hate you, and pray for those who treat you insolently, and persecute you;", "noyes": "But I say to you, Love your enemies, and pray for those who persecute you;", "webster": "But I say to you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them who despitefully use you, and persecute you;", "vulgate": "ego autem dico vobis diligite inimicos vestros benefacite his qui oderunt vos et orate pro persequentibus et calumniantibus vos;"}}, {"v": 45, "ref": "5:45", "o": "ὅπως γένησθε υἱοὶ τοῦ πατρὸς ὑμῶν τοῦ ⸀ἐν οὐρανοῖς, ὅτι τὸν ἥλιον αὐτοῦ ἀνατέλλει ἐπὶ πονηροὺς καὶ ἀγαθοὺς καὶ βρέχει ἐπὶ δικαίους καὶ ἀδίκους.", "en": {"kjv": "That ye may be the children of your Father which is in heaven: for he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust.", "web": "that you may be children of your Father who is in heaven. For he makes his sun to rise on the evil and the good, and sends rain on the just and the unjust.", "bsb": "that you may be sons of your Father in heaven. He causes His sun to rise on the evil and the good, and sends rain on the righteous and the unrighteous.", "asv": "that ye may be sons of your Father who is in heaven: for he maketh his sun to rise on the evil and the good, and sendeth rain on the just and the unjust.", "ylt": "that ye may be sons of your Father in the heavens, because His sun He doth cause to rise on evil and good, and He doth send rain on righteous and unrighteous.", "tyndale": "that ye maye be ye chyldern of youre father that is in heauen: for he maketh his sunne to aryse on ye yvell and on the good and sendeth his reyn on the iuste and vniuste.", "dra": "That you may be the children of your Father who is in heaven, who maketh his sun to rise upon the good, and bad, and raineth upon the just and the unjust.", "bbe": "So that you may be the sons of your Father in heaven; for his sun gives light to the evil and to the good, and he sends rain on the upright man and on the sinner.", "geneva": "That ye may be the children of your father that is in heauen: for he maketh his sunne to arise on the euill, and the good, and sendeth raine on the iust, and vniust.", "wycliffe": "that ye be the sones of your fadir that is in heuenes, that makith his sunne to rise vpon goode `and yuele men, and reyneth on iust men and vniuste.", "rotherham": "That ye may become sons of your Father who is in the heavens: because, his sun, he maketh arise on evil and good, and sendeth rain, on just and unjust.", "weymouth": "that so you may become true sons of your Father in Heaven; for He causes His sun to rise on the wicked as well as the good, and sends rain upon those who do right and those who do wrong.", "darby": "that ye may be [the] sons of your Father who is in [the] heavens; for he makes his sun rise on evil and good, and sends rain on just and unjust.", "twenty": "that you may become Sons of your Father who is in Heaven; for he causes his sun to rise upon bad and good alike, and sends rain upon the righteous and upon the unrighteous.", "acv": "so that ye may become sons of your Father in the heavens, because he makes his sun to rise on the evil and the good, and makes rain on the righteous and the unrighteous.", "anderson": "that you may be the sons of your Father who is in heaven; for he makes his sun to rise upon the evil and the good, and causes it to rain on the just and on the unjust.", "haweis": "that ye may be the children of your Father who is in heaven: for he causeth his sun to rise on the evil and on the good, and tendeth rain on the just and on the unjust.", "noyes": "that ye may become sons of your Father who is in heaven; for he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust.", "webster": "That ye may be the children of your Father who [is] in heaven: for he maketh his sun to rise on the evil and on the good, and sendeth rain on the just and on the unjust.", "vulgate": "ut sitis filii Patris vestri qui in caelis est qui solem suum oriri facit super bonos et malos et pluit super iustos et iniustos;"}}, {"v": 46, "ref": "5:46", "o": "ἐὰν γὰρ ἀγαπήσητε τοὺς ἀγαπῶντας ὑμᾶς, τίνα μισθὸν ἔχετε; οὐχὶ καὶ οἱ τελῶναι ⸂τὸ αὐτὸ⸃ ποιοῦσιν;", "en": {"kjv": "For if ye love them which love you, what reward have ye? do not even the publicans the same?", "web": "For if you love those who love you, what reward do you have? Don’t even the tax collectors do the same?", "bsb": "If you love those who love you, what reward will you get? Do not even tax collectors do the same?", "asv": "For if ye love them that love you, what reward have ye? do not even the publicans the same?", "ylt": "`For, if ye may love those loving you, what reward have ye? do not also the tax-gatherers the same?", "tyndale": "For yf ye love them which love you: what rewarde shall ye have? Doo not the Publicans euen so?", "dra": "For if you love them that love you, what reward shall you have? do not even the publicans this?", "bbe": "For if you have love for those who have love for you, what credit is it to you? do not the tax-farmers the same?", "geneva": "For if ye loue them, which loue you, what rewarde shall you haue? Doe not the Publicanes euen the same?", "wycliffe": "For if ye louen hem that louen you, what mede schulen ye han? whether pupplicans doon not this?", "rotherham": "For, if ye love them that love you, what reward have ye? are not, even the tax-collectors, the same thing, doing?", "weymouth": "For if you love only those who love you, what reward have you earned? Do not even the tax-gatherers do that?", "darby": "For if ye should love those who love you, what reward have ye? Do not also the tax-gatherers the same?", "twenty": "For, if you love only those who love you, what reward will you have? Even the tax-gatherers do this!", "acv": "For if ye love those who love you, what reward have ye? Do not even the tax collectors the same?", "anderson": "For if you love those who love you, what reward have you? Do not even the publicans the same?", "haweis": "For if ye love those who love you, what reward have you? do not even the publicans the same thing?", "noyes": "For if ye love those who love you, what reward have ye? Do not even the publicans the same?", "webster": "For if ye love them who love you, what reward have ye? do not even the publicans the same?", "vulgate": "si enim diligatis eos qui vos diligunt quam mercedem habebitis nonne et publicani hoc faciunt;"}}, {"v": 47, "ref": "5:47", "o": "καὶ ἐὰν ἀσπάσησθε τοὺς ⸀ἀδελφοὺς ὑμῶν μόνον, τί περισσὸν ποιεῖτε; οὐχὶ καὶ οἱ ⸀ἐθνικοὶ ⸂τὸ αὐτὸ⸃ ποιοῦσιν;", "en": {"kjv": "And if ye salute your brethren only, what do ye more than others? do not even the publicans so?", "web": "If you only greet your friends, what more do you do than others? Don’t even the tax collectors do the same?", "bsb": "And if you greet only your brothers, what are you doing more than others? Do not even Gentiles do the same?", "asv": "And if ye salute your brethren only, what do ye more than others? do not even the Gentiles the same?", "ylt": "and if ye may salute your brethren only, what do ye abundant? do not also the tax-gatherers so?", "tyndale": "", "dra": "And if you salute your brethren only, what do you more? do not also the heathens this?", "bbe": "And if you say, Good day, to your brothers only, what do you do more than others? do not even the Gentiles the same?", "geneva": "And if ye be friendly to your brethren onely, what singular thing doe ye? doe not euen the Publicanes likewise?", "wycliffe": "And if ye greten youre britheren oonli, what schulen ye do more? ne doon not hethene men this?", "rotherham": "And, if ye salute your brethren only, what, more than common, are ye doing? are not, even the nations, the same thing, doing?", "weymouth": "And if you salute only your near relatives, what praise is due to you? Do not even the Gentiles do the same?", "darby": "And if ye should salute your brethren only, what do ye extraordinary? Do not also the Gentiles the same?", "twenty": "And, if you show courtesy to your brothers only, what are you doing more than others? Even the Gentiles do this!", "acv": "And if ye only greet your friends, what do ye extra? Do not even the tax collectors this way?", "anderson": "And if you salute your brethren only, in what do you excel? Do not even the publicans so?", "haweis": "And if ye embrace your brethren only, what do ye extraordinary? do not even the publicans so?", "noyes": "And if ye salute your brethren only, what do ye that excelleth? Do not even the heathen the same?", "webster": "And if ye salute your brethren only, what do ye more [than others]? do not even the publicans so?", "vulgate": "et si salutaveritis fratres vestros tantum quid amplius facitis nonne et ethnici hoc faciunt;"}}, {"v": 48, "ref": "5:48", "o": "Ἔσεσθε οὖν ὑμεῖς τέλειοι ⸀ὡς ὁ πατὴρ ὑμῶν ὁ ⸀οὐράνιος τέλειός ἐστιν.", "en": {"kjv": "Be ye therefore perfect, even as your Father which is in heaven is perfect.", "web": "Therefore you shall be perfect, just as your Father in heaven is perfect.", "bsb": "Be perfect, therefore, as your heavenly Father is perfect.", "asv": "Ye therefore shall be perfect, as your heavenly Father is perfect.", "ylt": "ye shall therefore be perfect, as your Father who is in the heavens is perfect.", "tyndale": "And yf ye be frendly to youre brethren onlye: what singuler thynge doo ye? Do not the Publicans lyke wyse? ye shall therfore be perfecte eve as youre father which is in heauen is perfecte.", "dra": "Be you therefore perfect, as also your heavenly Father is perfect.", "bbe": "Be then complete in righteousness, even as your Father in heaven is complete.", "geneva": "Ye shall therefore be perfit, as your Father which is in heauen, is perfite.", "wycliffe": "Therfore be ye parfit, as youre heuenli fadir is parfit.", "rotherham": "Ye, therefore, shall become, perfect: as, your heavenly Father, is perfect.", "weymouth": "You however are to be complete in goodness, as your Heavenly Father is complete.", "darby": "Be ye therefore perfect as your heavenly Father is perfect.", "twenty": "You, then, must become perfect — as your heavenly Father is perfect.", "acv": "Ye therefore shall be perfect, even as your Father in the heavens is perfect.", "anderson": "Be you therefore perfect, as your Father who is in heaven is perfect.", "haweis": "Be ye therefore perfect, as your Father who is in heaven is perfect.", "noyes": "Be ye therefore perfect, as your heavenly Father is perfect.", "webster": "Be ye therefore perfect, even as your Father who is in heaven is perfect.", "vulgate": "estote ergo vos perfecti sicut et Pater vester caelestis perfectus est;"}}]}, {"c": 6, "verses": [{"v": 1, "ref": "6:1", "o": "Προσέχετε ⸀δὲ τὴν ⸀δικαιοσύνην ὑμῶν μὴ ποιεῖν ἔμπροσθεν τῶν ἀνθρώπων πρὸς τὸ θεαθῆναι αὐτοῖς· εἰ δὲ μή γε, μισθὸν οὐκ ἔχετε παρὰ τῷ πατρὶ ὑμῶν τῷ ἐν τοῖς οὐρανοῖς.", "en": {"kjv": "Take heed that ye do not your alms before men, to be seen of them: otherwise ye have no reward of your Father which is in heaven.", "web": "“Be careful that you don’t do your charitable giving before men, to be seen by them, or else you have no reward from your Father who is in heaven.", "bsb": "“Be careful not to perform your righteous acts before men to be seen by them. If you do, you will have no reward from your Father in heaven.", "asv": "Take heed that ye do not your righteousness before men, to be seen of them: else ye have no reward with your Father who is in heaven.", "ylt": "`Take heed your kindness not to do before men, to be seen by them, and if not--reward ye have not from your Father who is in the heavens;", "tyndale": "Take hede to youre almes. That ye geve it not in the syght of men to the intent that ye wolde be sene of them. Or els ye get no rewarde of youre father which is in heve.", "dra": "Take heed that you do not your justice before men, to be seen by them: otherwise you shall not have a reward of your Father who is in heaven.", "bbe": "Take care not to do your good works before men, to be seen by them; or you will have no reward from your Father in heaven.", "geneva": "Take heede that ye giue not your almes before men, to be seene of them, or els ye shall haue no reward of your Father which is in heaue.", "wycliffe": "Takith hede, that ye do not youre riytwisnesse bifor men, to be seyn of hem, ellis ye schulen haue no meede at youre fadir that is in heuenes.", "rotherham": "[But] take heed, that ye do not, your righteousness, before men, to be gazed at by them,—otherwise at least, reward, have ye none, with your Father who is in the heavens.", "weymouth": "\"But beware of doing your good actions in the sight of men, in order to attract their gaze; if you do, there is no reward for you with your Father who is in Heaven.", "darby": "Take heed not to do your alms before men to be seen of them, otherwise ye have no reward with your Father who is in the heavens.", "twenty": "Take care not to perform your religious duties in public in order to be seen by others; if you do, your Father who is in Heaven has no reward for you.", "acv": "Be careful not to do your charity before men in order to be seen by them, otherwise ye have no reward from your Father in the heavens.", "anderson": "Beware of doing your charitable deeds before men, to be seen by them; otherwise you have no reward with your Father who is in heaven.", "haweis": "TAKE heed that ye do not your alms before men, in order to catch their eye: for otherwise ye have no reward from your Father who is in heaven.", "noyes": "But take heed that ye do not your righteousness before men, to be seen by them; otherwise ye have no reward with your Father who is in heaven.", "webster": "Take heed that ye do not your alms before men, to be seen by them: otherwise ye have no reward from your Father who is in heaven.", "vulgate": "adtendite ne iustitiam vestram faciatis coram hominibus ut videamini ab eis alioquin mercedem non habebitis apud Patrem vestrum qui in caelis est;"}}, {"v": 2, "ref": "6:2", "o": "Ὅταν οὖν ποιῇς ἐλεημοσύνην, μὴ σαλπίσῃς ἔμπροσθέν σου, ὥσπερ οἱ ὑποκριταὶ ποιοῦσιν ἐν ταῖς συναγωγαῖς καὶ ἐν ταῖς ῥύμαις, ὅπως δοξασθῶσιν ὑπὸ τῶν ἀνθρώπων· ἀμὴν λέγω ὑμῖν, ἀπέχουσιν τὸν μισθὸν αὐτῶν.", "en": {"kjv": "Therefore when thou doest thine alms, do not sound a trumpet before thee, as the hypocrites do in the synagogues and in the streets, that they may have glory of men. Verily I say unto you, They have their reward.", "web": "Therefore when you do merciful deeds, don’t sound a trumpet before yourself, as the hypocrites do in the synagogues and in the streets, that they may get glory from men. Most certainly I tell you, they have received their reward.", "bsb": "So when you give to the needy, do not sound a trumpet before you, as the hypocrites do in the synagogues and on the streets, to be honored by men. Truly I tell you, they already have their full reward.", "asv": "When therefore thou doest alms, sound not a trumpet before thee, as the hypocrites do in the synagogues and in the streets, that they may have glory of men. Verily I say unto you, They have received their reward.", "ylt": "whenever, therefore, thou mayest do kindness, thou mayest not sound a trumpet before thee as the hypocrites do, in the synagogues, and in the streets, that they may have glory from men; verily I say to you--they have their reward!", "tyndale": "Whe soever therfore thou gevest thine almes thou shalt not make a tropet to be blowe before the as ye ypocrites do in the synagogis and in the stretis for to be preysed of men. Verely I say vnto you they have their rewarde.", "dra": "Therefore when thou dost an alms-deed, sound not a trumpet before thee, as the hypocrites do in the synagogues and in the streets, that they may be honoured by men. Amen I say to you, they have received their reward.", "bbe": "When then you give money to the poor, do not make a noise about it, as the false-hearted men do in the Synagogues and in the streets, so that they may have glory from men. Truly, I say to you, They have their reward.", "geneva": "Therefore when thou giuest thine almes, thou shalt not make a trumpet to be blowen before thee, as the hypocrites doe in the Synagogues and in the streetes, to be praysed of men. Verely I say vnto you, they haue their rewarde.", "wycliffe": "Therfore whanne thou doist almes, nyle thou trumpe tofore thee, as ypocritis doon in synagogis and stretis, that thei be worschipid of men; sotheli Y seie to you, they han resseyued her meede.", "rotherham": "When, therefore, thou mayest be doing an alms, do not sound a trumpet before thee, just as, the hypocrites, do in the synagogues and in the streets—that they may be glorified by men,—Verily, I say unto you, they are getting back their reward.", "weymouth": "`When you give in charity, never blow a trumpet before you as the hypocrites do in the synagogues and streets in order that their praises may be sung by men. I solemnly tell you that they already have their reward.", "darby": "When therefore thou doest alms, sound not a trumpet before thee, as the hypocrites do in the synagogues and in the streets, so that they may have glory from men. Verily I say unto you, They have their reward.", "twenty": "Therefore, when you do acts of charity, do not have a trumpet blown in front of you, as hypocrites do in the Synagogues and in the streets, that they may be praised by others. There, I tell you, is their reward!", "acv": "When therefore thou do charity, do not sound a trumpet before thee, as the hypocrites do in the synagogues and in the streets, so that they may have glory by men. Truly I say to you, they have their reward.", "anderson": "When, therefore, you do a charitable deed, do not cause a trumpet to be sounded before you, as the hypocrites do, in the synagogues and in the streets, that they may be glorified by men. Verily, I say to you, They have their reward.", "haweis": "Therefore when thou givest alms, sound not a trumpet before thee, as the hypocrites do, in the synagogues, and in the streets, that they may have glory from men. Verily I say unto you, They receive their reward.", "noyes": "Therefore when thou doest alms, do not sound a trumpet before thee, as the hypocrites do in the synagogues and in the streets, that they may have glory of men. Truly do I say to you, They have received their reward.", "webster": "Therefore, when thou doest [thy] alms, do not sound a trumpet before thee, as the hypocrites do, in the synagogues, and in the streets, that they may have glory from men. Verily, I say to you, they have their reward.", "vulgate": "cum ergo facies elemosynam noli tuba canere ante te sicut hypocritae faciunt in synagogis et in vicis ut honorificentur ab hominibus amen dico vobis receperunt mercedem suam;"}}, {"v": 3, "ref": "6:3", "o": "σοῦ δὲ ποιοῦντος ἐλεημοσύνην μὴ γνώτω ἡ ἀριστερά σου τί ποιεῖ ἡ δεξιά σου,", "en": {"kjv": "But when thou doest alms, let not thy left hand know what thy right hand doeth:", "web": "But when you do merciful deeds, don’t let your left hand know what your right hand does,", "bsb": "But when you give to the needy, do not let your left hand know what your right hand is doing,", "asv": "But when thou doest alms, let not thy left hand know what thy right hand doeth:", "ylt": "`But thou, doing kindness, let not thy left hand know what thy right hand doth,", "tyndale": "But whe thou doest thine almes let not thy lyfte had knowe what thy righte had doth", "dra": "But when thou dost alms, let not thy left hand know what thy right hand doth.", "bbe": "But when you give money, let not your left hand see what your right hand does:", "geneva": "But when thou doest thine almes, let not thy left hand knowe what thy right hand doeth,", "wycliffe": "But whanne thou doist almes, knowe not thi left hond what thi riyt hond doith, that thin almes be in hidils,", "rotherham": "But, thou, when doing an alms, let not, thy left hand, know what thy right hand is doing;", "weymouth": "But when you are giving in charity, let not your left hand perceive what your right hand is doing,", "darby": "But thou, when thou doest alms, let not thy left hand know what thy right hand does;", "twenty": "But, when you do acts of charity, do not let your left hand know what your right hand is doing,", "acv": "But when thou do charity, let not thy left hand know what thy right hand does,", "anderson": "But when you do a charitable deed, let not your left hand know what your right hand does;", "haweis": "But when thou givest alms, let not thy right hand know what thy left is doing:", "noyes": "But when thou doest alms, let not thy left hand know what thy right hand doeth;", "webster": "But when thou doest alms, let not thy left hand know what thy right hand doeth:", "vulgate": "te autem faciente elemosynam nesciat sinistra tua quid faciat dextera tua;"}}, {"v": 4, "ref": "6:4", "o": "ὅπως ᾖ σου ἡ ἐλεημοσύνη ἐν τῷ κρυπτῷ· καὶ ὁ πατήρ σου ὁ βλέπων ἐν τῷ ⸀κρυπτῷ ἀποδώσει ⸀σοι.", "en": {"kjv": "That thine alms may be in secret: and thy Father which seeth in secret himself shall reward thee openly.", "web": "so that your merciful deeds may be in secret, then your Father who sees in secret will reward you openly.", "bsb": "so that your giving may be in secret. And your Father, who sees what is done in secret, will reward you.", "asv": "that thine alms may be in secret: and thy Father who seeth in secret shall recompense thee.", "ylt": "that thy kindness may be in secret, and thy Father who is seeing in secret Himself shall reward thee manifestly.", "tyndale": "yt thine almes may be secret: and thy father which seith in secret shall rewarde ye opely.", "dra": "That thy alms may be in secret, and thy Father who seeth in secret will repay thee.", "bbe": "So that your giving may be in secret; and your Father, who sees in secret, will give you your reward.", "geneva": "That thine almes may be in secret, and thy Father that seeth in secret, hee will rewarde thee openly.", "wycliffe": "and thi fadir that seeth in hiddils, schal quyte thee.", "rotherham": "that thine alms may be in secret,—and, thy Father, who seeth in secret, will give it back to thee.", "weymouth": "that your charities may be in secret; and then your Father--He who sees in secret--will recompense you.", "darby": "so that thine alms may be in secret, and thy Father who sees in secret will render [it] to thee.", "twenty": "so that your charity may be secret; and your Father, who sees what is in secret, will recompense you.", "acv": "so that thy charity may be in secret. And thy Father who sees in secret will himself reward thee in the open.", "anderson": "that your charitable deeds may be in secret; and your Father, who sees in secret, himself will reward you openly.", "haweis": "that thine alms may be in secret: and thy Father who seeth in secret, will himself reward thee openly.", "noyes": "that thine alms may be in secret; and thy Father, who seeth in secret, will reward thee.", "webster": "That thy alms may be in secret; and thy Father who seeth in secret, himself will reward thee openly.", "vulgate": "ut sit elemosyna tua in abscondito et Pater tuus qui videt in abscondito reddet tibi;"}}, {"v": 5, "ref": "6:5", "o": "Καὶ ὅταν ⸂προσεύχησθε, οὐκ ἔσεσθε ὡς⸃ οἱ ὑποκριταί· ὅτι φιλοῦσιν ἐν ταῖς συναγωγαῖς καὶ ἐν ταῖς γωνίαις τῶν πλατειῶν ἑστῶτες προσεύχεσθαι, ⸀ὅπως φανῶσιν τοῖς ἀνθρώποις· ἀμὴν λέγω ⸀ὑμῖν, ἀπέχουσι τὸν μισθὸν αὐτῶν.", "en": {"kjv": "And when thou prayest, thou shalt not be as the hypocrites are: for they love to pray standing in the synagogues and in the corners of the streets, that they may be seen of men. Verily I say unto you, They have their reward.", "web": "“When you pray, you shall not be as the hypocrites, for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen by men. Most certainly, I tell you, they have received their reward.", "bsb": "And when you pray, do not be like the hypocrites. For they love to pray standing in the synagogues and on the street corners to be seen by men. Truly I tell you, they already have their full reward.", "asv": "And when ye pray, ye shall not be as the hypocrites: for they love to stand and pray in the synagogues and in the corners of the streets, that they may be seen of men. Verily I say unto you, They have received their reward.", "ylt": "`And when thou mayest pray, thou shalt not be as the hypocrites, because they love in the synagogues, and in the corners of the broad places--standing--to pray, that they may be seen of men; verily I say to you, that they have their reward.", "tyndale": "And when thou prayest thou shalt not be as ye ypocrytes are. For they love to stond and praye in the synagoges and in the corners of ye stretes because they wolde be sene of men. Verely I saye vnto you they haue their rewarde.", "dra": "And when ye pray, you shall not be as the hypocrites, that love to stand and pray in the synagogues and corners of the streets, that they may be seen by men: Amen I say to you, they have received their reward.", "bbe": "And when you make your prayers, be not like the false-hearted men, who take pleasure in getting up and saying their prayers in the Synagogues and at the street turnings so that they may be seen by men. Truly I say to you, They have their reward.", "geneva": "And when thou prayest, be not as the hypocrites: for they loue to stand, and pray in the Synagogues, and in the corners of the streetes, because they would be seene of men. Verely I say vnto you, they haue their rewarde.", "wycliffe": "And whanne ye preyen, ye schulen not be as ipocritis, that louen to preye stondynge in synagogis and corneris of stretis, to be seyn of men; treuli Y seie to you, thei han resseyued her meede.", "rotherham": "And, when ye may be praying, ye shall not be as the hypocrites, because they love, in the synagogues, and at the corners of the broad ways, to take their stand and pray, that they may shine before men; Verily, I say unto you, they are getting back their reward.", "weymouth": "\"And when praying, you must not be like the hypocrites. They are fond of standing and praying in the synagogues or at the corners of the wider streets, in order that men may see them. I solemnly tell you that they already have their reward.", "darby": "And when thou prayest, thou shalt not be as the hypocrites; for they love to pray standing in the synagogues and in the corners of the streets so that they should appear to men. Verily I say unto you, They have their reward.", "twenty": "And, when you pray, you are not to behave as hypocrites do. They like to pray standing in the Synagogues and at the corners of the streets, that they may be seen by men. There, I tell you, is their reward!", "acv": "And when thou pray, thou shall not be as the hypocrites, because they love to pray having stood in the synagogues and in the corners of the thoroughfares, so that they may be seen by men. Truly I say to you, they have their reward.", "anderson": "And when you pray, you shall not be like the hypocrites; for they love to pray standing in the synagogues, and in the corners of the streets, that they may be seen by men. Verily, I say to you, They have their reward.", "haweis": "And when thou prayest, be not as the hypocrites: for they love standing in the synagogues and at the corners of the streets, to pray, that they may make a shew to men. Verily I say unto you, That they have their reward.", "noyes": "And when ye pray, ye shall not be as the hypocrites are; for they love to pray standing in the synagogues and in the corners of the streets, that they may be seen by men. Truly do I say to you, They have received their reward.", "webster": "And when thou prayest, thou shalt not be as the hypocrites [are]: for they love to pray standing in the synagogues, and in the corners of the streets, that they may be seen by men. Verily, I say to you, they have their reward.", "vulgate": "et cum oratis non eritis sicut hypocritae qui amant in synagogis et in angulis platearum stantes orare ut videantur ab hominibus amen dico vobis receperunt mercedem suam;"}}, {"v": 6, "ref": "6:6", "o": "σὺ δὲ ὅταν προσεύχῃ, εἴσελθε εἰς τὸ ταμεῖόν σου καὶ κλείσας τὴν θύραν σου πρόσευξαι τῷ πατρί σου τῷ ἐν τῷ κρυπτῷ· καὶ ὁ πατήρ σου ὁ βλέπων ἐν τῷ κρυπτῷ ἀποδώσει ⸀σοι.", "en": {"kjv": "But thou, when thou prayest, enter into thy closet, and when thou hast shut thy door, pray to thy Father which is in secret; and thy Father which seeth in secret shall reward thee openly.", "web": "But you, when you pray, enter into your inner room, and having shut your door, pray to your Father who is in secret, and your Father who sees in secret will reward you openly.", "bsb": "But when you pray, go into your inner room, shut your door, and pray to your Father, who is unseen. And your Father, who sees what is done in secret, will reward you.", "asv": "But thou, when thou prayest, enter into thine inner chamber, and having shut thy door, pray to thy Father who is in secret, and thy Father who seeth in secret shall recompense thee.", "ylt": "`But thou, when thou mayest pray, go into thy chamber, and having shut thy door, pray to thy Father who is in secret, and thy Father who is seeing in secret, shall reward thee manifestly.", "tyndale": "But when thou prayest entre into thy chamber and shut thy dore to the and praye to thy father which ys in secrete: and thy father which seith in secret shall rewarde the openly.", "dra": "But thou when thou shalt pray, enter into thy chamber, and having shut the door, pray to thy Father in secret, and thy father who seeth in secret will repay thee.", "bbe": "But when you make your prayer, go into your private room, and, shutting the door, say a prayer to your Father in secret, and your Father, who sees in secret, will give you your reward.", "geneva": "But when thou prayest, enter into thy chamber and when thou hast shut thy doore, pray vnto thy Father which is in secret, and thy Father which seeth in secret, shall rewarde thee openly.", "wycliffe": "But whanne thou schalt preye, entre in to thi couche, and whanne the dore is schet, preye thi fadir in hidils, and thi fadir that seeth in hidils, schal yelde to thee.", "rotherham": "But, thou, when thou wouldest pray, enter into thy closet, and, fastening thy door, pray unto thy Father who is in secret,—and, thy Father who seeth in secret, will reward thee.", "weymouth": "But you, whenever you pray, go into your own room and shut the door: then pray to your Father who is in secret, and your Father--He who sees in secret--will recompense you.", "darby": "But thou, when thou prayest, enter into thy chamber, and having shut thy door, pray to thy Father who is in secret, and thy Father who sees in secret will render [it] to thee.", "twenty": "But, when one of you prays, let him go into his own room, shut the door, and pray to his Father who dwells in secret; and his Father, who sees what is secret, will recompense him.", "acv": "But thou, when thou pray, enter into thy private room, and having shut thy door, pray to thy Father in secret, and thy Father who sees in secret will reward thee in the open.", "anderson": "But do you, when you pray, go into your closet, and when you have closed the door, pray to your Father who is in secret: and your Father who sees in secret will reward you openly.", "haweis": "But when thou prayest, enter into thy closet, and shut thy door, to pray to thy Father who is in secret; and thy Father who seeth in secret shall reward thee openly.", "noyes": "But do thou, when thou prayest, enter into thy closet, and, when thou hast shut thy door, pray to thy Father who is in secret; and thy Father, who seeth in secret, will reward thee.", "webster": "But thou, when thou prayest, enter into thy closet, and when thou hast shut thy door, pray to thy Father who is in secret, and thy Father who seeth in secret, will reward thee openly.", "vulgate": "tu autem cum orabis intra in cubiculum tuum et cluso ostio tuo ora Patrem tuum in abscondito et Pater tuus qui videt in abscondito reddet tibi;"}}, {"v": 7, "ref": "6:7", "o": "Προσευχόμενοι δὲ μὴ βατταλογήσητε ὥσπερ οἱ ἐθνικοί, δοκοῦσιν γὰρ ὅτι ἐν τῇ πολυλογίᾳ αὐτῶν εἰσακουσθήσονται·", "en": {"kjv": "But when ye pray, use not vain repetitions, as the heathen do: for they think that they shall be heard for their much speaking.", "web": "In praying, don’t use vain repetitions, as the Gentiles do; for they think that they will be heard for their much speaking.", "bsb": "And when you pray, do not babble on like pagans, for they think that by their many words they will be heard.", "asv": "And in praying use not vain repetitions, as the Gentiles do: for they think that they shall be heard for their much speaking.", "ylt": "`And--praying--ye may not use vain repetitions like the nations, for they think that in their much speaking they shall be heard,", "tyndale": "And whe ye praye bable not moche as the hethe do: for they thincke that they shalbe herde for their moche bablynges sake.", "dra": "And when you are praying, speak not much, as the heathens. For they think that in their much speaking they may be heard.", "bbe": "And in your prayer do not make use of the same words again and again, as the Gentiles do: for they have the idea that God will give attention to them because of the number of their words.", "geneva": "Also when ye pray, vse no vaine repetitions as the Heathen: for they thinke to be heard for their much babbling.", "wycliffe": "But in preiyng nyle yee speke myche, as hethene men doon, for thei gessen that thei ben herd in her myche speche.", "rotherham": "And, being at prayer, use not vain repetitions, just like the nations,—for they think, that, in their much speaking, they shall be hoard;", "weymouth": "\"And when praying, do not use needless repetitions as the Gentiles do, for they expect to be listened to because of their multitude of words.", "darby": "But when ye pray, use not vain repetitions, as those who are of the nations: for they think they shall be heard through their much speaking.", "twenty": "When praying, do not repeat the same words over and over again, as is done by the Gentiles, who think that by using many words they will obtain a hearing.", "acv": "And while praying do not use vain repetitions as the heathen do, for they think that they will be heard by their much speaking.", "anderson": "But when you pray, do not use vain repetitions, as the heathen do: for they think that they will be heard for their many words.", "haweis": "And when thou art at prayer, use not vain repetitions, like the heathen: for they imagine that they shall be heard for their much speaking.", "noyes": "But when ye pray, use not vain repetitions, as the heathen do; for they think that they shall be heard for the multitude of their words.", "webster": "But when ye pray, use not vain repetitions, as the heathen do: for they think that they shall be heard for their much speaking.", "vulgate": "orantes autem nolite multum loqui sicut ethnici putant enim quia in multiloquio suo exaudiantur;"}}, {"v": 8, "ref": "6:8", "o": "μὴ οὖν ὁμοιωθῆτε αὐτοῖς, οἶδεν γὰρ ⸀ὁ πατὴρ ὑμῶν ὧν χρείαν ἔχετε πρὸ τοῦ ὑμᾶς αἰτῆσαι αὐτόν.", "en": {"kjv": "Be not ye therefore like unto them: for your Father knoweth what things ye have need of, before ye ask him.", "web": "Therefore don’t be like them, for your Father knows what things you need, before you ask him.", "bsb": "Do not be like them, for your Father knows what you need before you ask Him.", "asv": "Be not therefore like unto them: for your Father knoweth what things ye have need of, before ye ask him.", "ylt": "be ye not therefore like to them, for your Father doth know those things that ye have need of before your asking him;", "tyndale": "Be ye not lyke them therfore. For youre father knoweth wherof ye haue neade before ye axe of him.", "dra": "Be not you therefore like to them for your Father knoweth what is needful for you, before you ask him.", "bbe": "So be not like them; because your Father has knowledge of your needs even before you make your requests to him.", "geneva": "Be ye not like them therefore: for your Father knoweth whereof ye haue neede, before ye aske of him.", "wycliffe": "Therfor nyle ye be maad lich to hem, for your fadir woot what is nede to you, bifore that ye axen hym.", "rotherham": "do not, therefore, make yourselves like them, for [God] your Father knoweth of what things ye have, need, before ye ask him.", "weymouth": "Do not, however, imitate them; for your Father knows what things you need before ever you ask Him.", "darby": "Be not ye therefore like them, for your Father knows of what things ye have need before ye beg [anything] of him.", "twenty": "Do not imitate them; for God, your Father, knows what you need before you ask him.", "acv": "Be not therefore like them, for your Father knows what things ye have need of before ye ask him.", "anderson": "Be not, therefore, like them; for your Father knows what things you need before you ask him.", "haweis": "Be not ye therefore like them: for your Father knoweth of what things ye have need, before you ask him.", "noyes": "Be not ye therefore like them; for your Father knoweth what things ye have need of, before ye ask him.", "webster": "Therefore be ye not like them: for your Father knoweth what things ye need before ye ask him.", "vulgate": "nolite ergo adsimilari eis scit enim Pater vester quibus opus sit vobis antequam petatis eum;"}}, {"v": 9, "ref": "6:9", "o": "Οὕτως οὖν προσεύχεσθε ὑμεῖς· Πάτερ ἡμῶν ὁ ἐν τοῖς οὐρανοῖς· ἁγιασθήτω τὸ ὄνομά σου,", "en": {"kjv": "After this manner therefore pray ye: Our Father which art in heaven, Hallowed be thy name.", "web": "Pray like this: ‘Our Father in heaven, may your name be kept holy.", "bsb": "So then, this is how you should pray: ‘Our Father in heaven, hallowed be Your name.", "asv": "After this manner therefore pray ye: Our Father who art in heaven, Hallowed be thy name.", "ylt": "thus therefore pray ye: `Our Father who art in the heavens! hallowed be Thy name.", "tyndale": "After thys maner therfore praye ye. O oure father which arte in heve halowed be thy name.", "dra": "Thus therefore shall you pray: Our Father who art in heaven, hallowed be thy name.", "bbe": "Let this then be your prayer: Our Father in heaven, may your name be kept holy.", "geneva": "After this maner therefore pray ye, Our father which art in heauen, halowed be thy name.", "wycliffe": "And thus ye schulen preye, Oure fadir that art in heuenes, halewid be thi name;", "rotherham": "Thus, therefore pray, ye: Our Father, who art in the heavens,—Hallowed be thy name,", "weymouth": "\"In this manner therefore pray: `Our Father who art in Heaven, may Thy name be kept holy;", "darby": "Thus therefore pray ye: Our Father who art in the heavens, let thy name be sanctified,", "twenty": "You, therefore, should pray thus — ‘Our Father, who art in Heaven, may thy name be held holy,", "acv": "Pray ye therefore this way: Our Father in the heavens, hallowed be thy name.", "anderson": "In this manner, therefore, pray you: Our Father who art in heaven, hallowed be thy name.", "haweis": "Thus then pray ye: Our Father, which art in heaven, hallowed be thy name.", "noyes": "After this manner therefore pray ye:—Our Father, who art in heaven, hallowed be thy name;", "webster": "After this manner therefore pray ye: Our Father who art in heaven, Hallowed be thy name.", "vulgate": "sic ergo vos orabitis Pater noster qui in caelis es sanctificetur nomen tuum;"}}, {"v": 10, "ref": "6:10", "o": "ἐλθέτω ἡ βασιλεία σου, γενηθήτω τὸ θέλημά σου, ὡς ἐν οὐρανῷ καὶ ⸀ἐπὶ γῆς·", "en": {"kjv": "Thy kingdom come. Thy will be done in earth, as it is in heaven.", "web": "Let your Kingdom come. Let your will be done, as in heaven, so on earth.", "bsb": "Your kingdom come, Your will be done, on earth as it is in heaven.", "asv": "Thy kingdom come. Thy will be done, as in heaven, so on earth.", "ylt": "`Thy reign come: Thy will come to pass, as in heaven also on the earth.", "tyndale": "Let thy kyngdome come. Thy wyll be fulfilled as well in erth as it ys in heven.", "dra": "Thy kingdom come. Thy will be done on earth as it is in heaven.", "bbe": "Let your kingdom come. Let your pleasure be done, as in heaven, so on earth.", "geneva": "Thy Kingdome come. Thy will be done euen in earth, as it is in heauen.", "wycliffe": "thi kyngdoom come to; be thi wille don `in erthe as in heuene;", "rotherham": "Come may thy kingdom,—Accomplished be thy will, as in heaven, also on earth:", "weymouth": "let Thy kingdom come; let Thy will be done, as in Heaven so on earth;", "darby": "let thy kingdom come, let thy will be done as in heaven so upon the earth;", "twenty": "thy Kingdom come, thy will be done — on earth, as in Heaven.", "acv": "May thy kingdom come. May thy will happen on the earth as also in heaven.", "anderson": "Thy kingdom come. Thy will be done on earth, as it is done in heaven.", "haweis": "Thy kingdom come. Thy will be done in earth, as it is in heaven.", "noyes": "thy kingdom come; thy will be done on earth as it is in heaven;", "webster": "Thy kingdom come. Thy will be done on earth as [it is] in heaven.", "vulgate": "veniat regnum tuum fiat voluntas tua sicut in caelo et in terra;"}}, {"v": 11, "ref": "6:11", "o": "τὸν ἄρτον ἡμῶν τὸν ἐπιούσιον δὸς ἡμῖν σήμερον·", "en": {"kjv": "Give us this day our daily bread.", "web": "Give us today our daily bread.", "bsb": "Give us this day our daily bread.", "asv": "Give us this day our daily bread.", "ylt": "`Our appointed bread give us to-day.", "tyndale": "Geve vs this daye oure dayly breede.", "dra": "Give us this day our supersubstantial bread.", "bbe": "Give us this day bread for our needs.", "geneva": "Giue vs this day our dayly bread.", "wycliffe": "yyue to vs this dai oure `breed ouer othir substaunce;", "rotherham": "Our needful bread, give us, this day;", "weymouth": "give us to-day our bread for the day;", "darby": "give us to-day our needed bread,", "twenty": "Give us to-day the bread that we shall need;", "acv": "Give us this day the bread sufficient for us.", "anderson": "Give us this day the bread for our support.", "haweis": "Give us this day our daily bread.", "noyes": "give us this day our daily bread;", "webster": "Give us this day our daily bread.", "vulgate": "panem nostrum supersubstantialem da nobis hodie;"}}, {"v": 12, "ref": "6:12", "o": "καὶ ἄφες ἡμῖν τὰ ὀφειλήματα ἡμῶν, ὡς καὶ ἡμεῖς ⸀ἀφήκαμεν τοῖς ὀφειλέταις ἡμῶν·", "en": {"kjv": "And forgive us our debts, as we forgive our debtors.", "web": "Forgive us our debts, as we also forgive our debtors.", "bsb": "And forgive us our debts, as we also have forgiven our debtors.", "asv": "And forgive us our debts, as we also have forgiven our debtors.", "ylt": "`And forgive us our debts, as also we forgive our debtors.", "tyndale": "And forgeve vs oure treaspases eve as we forgeve oure trespacers.", "dra": "And forgive us our debts, as we also forgive our debtors.", "bbe": "And make us free of our debts, as we have made those free who are in debt to us.", "geneva": "And forgiue vs our dettes, as we also forgiue our detters.", "wycliffe": "and foryyue to vs oure dettis, as we foryyuen to oure dettouris; and lede vs not in to temptacioun,", "rotherham": "And forgive us our debts, as, we also, have forgiven our debtors;", "weymouth": "and forgive us our shortcomings, as we also have forgiven those who have failed in their duty towards us;", "darby": "and forgive us our debts, as we also forgive our debtors,", "twenty": "and forgive us our wrong-doings, as we have forgiven those who have wronged us;", "acv": "And forgive us our debts as we also forgive our debtors.", "anderson": "And forgive us our debts, as we also forgive our debtors.", "haweis": "And forgive us our debts, as we forgive our debtors.", "noyes": "and forgive us our debts, as we also have forgiven our debtors;", "webster": "And forgive us our debts, as we forgive our debtors.", "vulgate": "et dimitte nobis debita nostra sicut et nos dimisimus debitoribus nostris;"}}, {"v": 13, "ref": "6:13", "o": "καὶ μὴ εἰσενέγκῃς ἡμᾶς εἰς πειρασμόν, ἀλλὰ ῥῦσαι ἡμᾶς ἀπὸ τοῦ ⸀πονηροῦ.", "en": {"kjv": "And lead us not into temptation, but deliver us from evil: For thine is the kingdom, and the power, and the glory, for ever. Amen.", "web": "Bring us not into temptation, but deliver us from the evil one. For yours is the Kingdom, the power, and the glory forever. Amen. ’", "bsb": "And lead us not into temptation, but deliver us from the evil one.’", "asv": "And bring us not into temptation, but deliver us from the evil one.", "ylt": "`And mayest Thou not lead us to temptation, but deliver us from the evil, because Thine is the reign, and the power, and the glory--to the ages. Amen.", "tyndale": "And leade vs not into teptacion: but delyver vs fro evell. For thyne is ye kyngedome and ye power and ye glorye for ever. Amen.", "dra": "And lead us not into temptation. But deliver us from evil. Amen.", "bbe": "And let us not be put to the test, but keep us safe from the Evil One.", "geneva": "And leade vs not into tentation, but deliuer vs from euill: for thine is the kingdome, and the power, and the glorie for euer. Amen.", "wycliffe": "but delyuere vs fro yuel.", "rotherham": "And bring us not into temptation, but rescue us from the evil one.", "weymouth": "and bring us not into temptation, but rescue us from the Evil one.'", "darby": "and lead us not into temptation, but save us from evil.", "twenty": "and take us not into temptation, but deliver us from Evil.’", "acv": "And bring us not into temptation, but deliver us from evil, because from thee is the kingdom and the power and the glory into the ages. Truly.", "anderson": "And lead us not into temptation, but deliver us from the Evil One.", "haweis": "And lead us not into temptation; but deliver us from evil: for thine is the kingdom, and the power, and the glory, for ever and ever. Amen!", "noyes": "and lead us not into temptation, but deliver us from evil.", "webster": "And lead us not into temptation, but deliver us from evil. For thine is the kingdom, and the power, and the glory, for ever. Amen.", "vulgate": "et ne inducas nos in temptationem sed libera nos a malo;"}}, {"v": 14, "ref": "6:14", "o": "ἐὰν γὰρ ἀφῆτε τοῖς ἀνθρώποις τὰ παραπτώματα αὐτῶν, ἀφήσει καὶ ὑμῖν ὁ πατὴρ ὑμῶν ὁ οὐράνιος·", "en": {"kjv": "For if ye forgive men their trespasses, your heavenly Father will also forgive you:", "web": "“For if you forgive men their trespasses, your heavenly Father will also forgive you.", "bsb": "For if you forgive men their trespasses, your heavenly Father will also forgive you.", "asv": "For if ye forgive men their trespasses, your heavenly Father will also forgive you.", "ylt": "`For, if ye may forgive men their trespasses He also will forgive you--your Father who is in the heavens;", "tyndale": "For and yf ye shall forgeve other men their treaspases youre hevenly father shall also forgeve you.", "dra": "For if you will forgive men their offences, your heavenly Father will forgive you also your offences.", "bbe": "For if you let men have forgiveness for their sins, you will have forgiveness from your Father in heaven.", "geneva": "For if ye doe forgiue men their trespasses, your heauenly Father will also forgiue you.", "wycliffe": "Amen. For if ye foryyuen to men her synnes, youre heuenli fadir schal foryyue to you youre trespassis.", "rotherham": "For, if ye forgive men their faults, Your Father who is in the heavens, will forgive, even you;", "weymouth": "\"For if you forgive others their offences, your Heavenly Father will forgive you also;", "darby": "For if ye forgive men their offences, your heavenly Father also will forgive you [yours],", "twenty": "For, if you forgive others their offences, your heavenly Father will forgive you also;", "acv": "For if ye forgive men their trespasses, your heavenly Father will also forgive you.", "anderson": "For if you forgive men their offenses, your heavenly Father will also forgive you.", "haweis": "For if ye forgive men their offences, your heavenly Father will also forgive you:", "noyes": "For if ye forgive men their trespasses, your heavenly Father will also forgive you;", "webster": "For, if ye forgive men their trespasses, your heavenly Father will also forgive you:", "vulgate": "si enim dimiseritis hominibus peccata eorum dimittet et vobis Pater vester caelestis delicta vestra;"}}, {"v": 15, "ref": "6:15", "o": "ἐὰν δὲ μὴ ἀφῆτε τοῖς ⸀ἀνθρώποις, οὐδὲ ὁ πατὴρ ὑμῶν ἀφήσει τὰ παραπτώματα ὑμῶν.", "en": {"kjv": "But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.", "web": "But if you don’t forgive men their trespasses, neither will your Father forgive your trespasses.", "bsb": "But if you do not forgive men their trespasses, neither will your Father forgive yours.", "asv": "But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.", "ylt": "but if ye may not forgive men their trespasses, neither will your Father forgive your trespasses.", "tyndale": "But and ye wyll not forgeve men their trespases nomore shall youre father forgeve youre treaspases.", "dra": "But if you will not forgive men, neither will your Father forgive you your offences.", "bbe": "But if you do not let men have forgiveness for their sins, you will not have forgiveness from your Father for your sins.", "geneva": "But if ye do not forgiue men their trespasses,, no more will your father forgiue you your trespaces.", "wycliffe": "Sotheli if ye foryyuen not to men, nether youre fadir schal foryyue to you youre synnes.", "rotherham": "But, if ye forgive not men [their faults], neither will your Father forgive, your faults.", "weymouth": "but if you do not forgive others their offences, neither will your Father forgive yours.", "darby": "but if ye do not forgive men their offences, neither will your Father forgive your offences.", "twenty": "but, if you do not forgive others their offences, not even your Father will forgive your offences.", "acv": "But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.", "anderson": "But if you forgive not men their offenses, neither will your Father forgive your offenses.", "haweis": "but if ye forgive not to men their offences, neither will your Father forgive your offences.", "noyes": "but if ye do not forgive men, neither will your Father forgive your trespasses.", "webster": "But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.", "vulgate": "si autem non dimiseritis hominibus nec Pater vester dimittet peccata vestra;"}}, {"v": 16, "ref": "6:16", "o": "Ὅταν δὲ νηστεύητε, μὴ γίνεσθε ⸀ὡς οἱ ὑποκριταὶ σκυθρωποί, ἀφανίζουσιν γὰρ τὰ πρόσωπα αὐτῶν ὅπως φανῶσιν τοῖς ἀνθρώποις νηστεύοντες· ἀμὴν λέγω ⸀ὑμῖν, ἀπέχουσιν τὸν μισθὸν αὐτῶν.", "en": {"kjv": "Moreover when ye fast, be not, as the hypocrites, of a sad countenance: for they disfigure their faces, that they may appear unto men to fast. Verily I say unto you, They have their reward.", "web": "“Moreover when you fast, don’t be like the hypocrites, with sad faces. For they disfigure their faces, that they may be seen by men to be fasting. Most certainly I tell you, they have received their reward.", "bsb": "When you fast, do not be somber like the hypocrites, for they disfigure their faces to show men they are fasting. Truly I tell you, they already have their full reward.", "asv": "Moreover when ye fast, be not, as the hypocrites, of a sad countenance: for they disfigure their faces, that they may be seen of men to fast. Verily I say unto you, They have received their reward.", "ylt": "`And when ye may fast, be ye not as the hypocrites, of sour countenances, for they disfigure their faces, that they may appear to men fasting; verily I say to you, that they have their reward.", "tyndale": "Moreoure when ye faste be not sad as ye ypocrytes are. For they disfigure their faces that they myght be sene of me how they faste. Verely I say vnto you they have their rewarde.", "dra": "And when you fast, be not as the hypocrites, sad. For they disfigure their faces, that they may appear unto men to fast. Amen I say to you, they have received their reward.", "bbe": "And when you go without food, be not sad-faced as the false-hearted are. For they go about with changed looks, so that men may see that they are going without food. Truly I say to you, They have their reward.", "geneva": "Moreouer, when ye fast, looke not sowre as the hypocrites: for they disfigure their faces, that they might seeme vnto men to fast. Verely I say vnto you, that they haue their rewarde.", "wycliffe": "But whanne ye fasten, nyle ye be maad as ypocritis sorewful, for thei defacen hem silf, to seme fastyng to men; treuli Y seie to you, they han resseyued her meede.", "rotherham": "And, when ye may he fasting, become not ye, as the hypocrites, of sullen countenance,—for they darken their looks, that they may appear, unto men, to be fasting: Verily, I say unto you, they are getting back their reward.", "weymouth": "\"When any of you fast, never assume gloomy looks as the hypocrites do; for they disfigure their faces in order that it may be evident to men that they are fasting. I solemnly tell you that they already have their reward.", "darby": "And when ye fast, be not as the hypocrites, downcast in countenance; for they disfigure their faces, so that they may appear fasting to men: verily I say unto you, They have their reward.", "twenty": "And, when you fast, do not put on gloomy looks, as hypocrites do who disfigure their faces that they may be seen by men to be fasting. That, I tell you, is their reward!", "acv": "And when ye fast, become not like the gloomy looking hypocrites, for they make their faces unsightly, so that they may appear fasting to men. Truly I say to you, they have their reward.", "anderson": "And when you fast, do not put on a sad countenance, as the hypocrites do; for they disfigure their faces, that they may appear to men to be fasting. Verily, I say to you, They have their reward.", "haweis": "And when ye fast, be not as the hypocrites, affecting a gloomy look: for they disfigure their visages, that they may make a shew of fasting to men. Verily I say unto you, That they have their reward.", "noyes": "Moreover, when ye fast, be not, as the hypocrites, of a sad countenance; for they disfigure their faces, that they may appear to men to be fasting. Truly do I say to you, They have received their reward.", "webster": "Moreover, when ye fast, be not as the hypocrites, of a sad countenance: for they disfigure their faces, that they may appear to men to fast. Verily, I say to you, they have their reward.", "vulgate": "cum autem ieiunatis nolite fieri sicut hypocritae tristes demoliuntur enim facies suas ut pareant hominibus ieiunantes amen dico vobis quia receperunt mercedem suam;"}}, {"v": 17, "ref": "6:17", "o": "σὺ δὲ νηστεύων ἄλειψαί σου τὴν κεφαλὴν καὶ τὸ πρόσωπόν σου νίψαι,", "en": {"kjv": "But thou, when thou fastest, anoint thine head, and wash thy face;", "web": "But you, when you fast, anoint your head, and wash your face;", "bsb": "But when you fast, anoint your head and wash your face,", "asv": "But thou, when thou fastest, anoint thy head, and wash thy face;", "ylt": "`But thou, fasting, anoint thy head, and wash thy face,", "tyndale": "But thou whe thou fastest annoynte thyne heed and washe thy face", "dra": "But thou, when thou fastest anoint thy head, and wash thy face;", "bbe": "But when you go without food, put oil on your head and make your face clean;", "geneva": "But when thou fastest, anoint thine head, and wash thy face,", "wycliffe": "But whanne thou fastist, anoynte thin heed, and waische thi face,", "rotherham": "But, when, thou, art fasting, anoint thy head, and, thy face, wash,—", "weymouth": "But, whenever you fast, pour perfume on your hair and wash your face,", "darby": "But thou, [when] fasting, anoint thy head and wash thy face,", "twenty": "But, when one of you fasts, let him anoint his head and wash his face,", "acv": "But when thou fast, anoint thy head, and wash thy face,", "anderson": "But do you, when you fast, anoint your head and wash your face;", "haweis": "But when thou keepest a fast, anoint thine head, and wash thy face;", "noyes": "But do thou, when thou fastest, anoint thy head, and wash thy face;", "webster": "But thou, when thou fastest, anoint thy head, and wash thy face;", "vulgate": "tu autem cum ieiunas ungue caput tuum et faciem tuam lava;"}}, {"v": 18, "ref": "6:18", "o": "ὅπως μὴ φανῇς τοῖς ἀνθρώποις νηστεύων ἀλλὰ τῷ πατρί σου τῷ ἐν τῷ ⸀κρυφαίῳ· καὶ ὁ πατήρ σου ὁ βλέπων ἐν τῷ ⸁κρυφαίῳ ἀποδώσει σοι.", "en": {"kjv": "That thou appear not unto men to fast, but unto thy Father which is in secret: and thy Father, which seeth in secret, shall reward thee openly.", "web": "so that you are not seen by men to be fasting, but by your Father who is in secret, and your Father, who sees in secret, will reward you.", "bsb": "so that your fasting will not be obvious to men, but only to your Father, who is unseen. And your Father, who sees what is done in secret, will reward you.", "asv": "that thou be not seen of men to fast, but of thy Father who is in secret: and thy Father, who seeth in secret, shall recompense thee.", "ylt": "that thou mayest not appear to men fasting, but to thy Father who is in secret, and thy Father, who is seeing in secret, shall reward thee manifestly.", "tyndale": "that it appere not vnto men howe that thou fastest: but vnto thy father which is in secrete: and thy father which seeth in secret shall rewarde the openly.", "dra": "That thou appear not to men to fast, but to thy Father who is in secret: and thy Father who seeth in secret, will repay thee.", "bbe": "So that no one may see that you are going without food, but your Father in secret; and your Father, who sees in secret, will give you your reward.", "geneva": "That thou seeme not vnto men to fast, but vnto thy Father which is in secret: and thy Father which seeth in secret, will rewarde thee openly.", "wycliffe": "that thou be not seen fastynge to men, but to thi fadir that is in hidlis, and thi fadir that seeth in priuey, shal yelde to thee.", "rotherham": "that thou do not appear, unto men, to be fasting, but to thy Father who is in secret,—and, thy Father who seeth in secret, will reward thee.", "weymouth": "that it may not be apparent to men that you are fasting, but to your Father who is in secret; and your Father--He who sees in secret--will recompense you.", "darby": "so that thou mayest not appear fasting unto men, but to thy Father who is in secret; and thy Father who sees in secret shall render [it] to thee.", "twenty": "that he may not be seen by men to be fasting, but by his Father who dwells in secret; and his Father, who sees what is secret, will recompense him.", "acv": "so that thou may not appear fasting to men, but to thy Father in secret. And thy Father, who sees in secret, will reward thee.", "anderson": "that you may not appear to men to be fasting, but to your Father who is in secret. And your Father who sees in secret will reward you.", "haweis": "that thou mayest not make a shew of fasting to men, but to thy Father who is in secret: and thy Father who seeth in secret shall reward thee openly.", "noyes": "that thou appear not to men to be fasting, but to thy Father who is in secret; and thy Father, who seeth in secret, will reward thee.", "webster": "That thou mayest not appear to men to fast, but to thy Father, who is in secret: and thy Father, who seeth in secret, shall reward thee openly.", "vulgate": "ne videaris hominibus ieiunans sed Patri tuo qui est in abscondito et Pater tuus qui videt in abscondito reddet tibi;"}}, {"v": 19, "ref": "6:19", "o": "Μὴ θησαυρίζετε ὑμῖν θησαυροὺς ἐπὶ τῆς γῆς, ὅπου σὴς καὶ βρῶσις ἀφανίζει, καὶ ὅπου κλέπται διορύσσουσιν καὶ κλέπτουσιν·", "en": {"kjv": "Lay not up for yourselves treasures upon earth, where moth and rust doth corrupt, and where thieves break through and steal:", "web": "“Don’t lay up treasures for yourselves on the earth, where moth and rust consume, and where thieves break through and steal;", "bsb": "Do not store up for yourselves treasures on earth, where moth and rust destroy, and where thieves break in and steal.", "asv": "Lay not up for yourselves treasures upon the earth, where moth and rust consume, and where thieves break through and steal:", "ylt": "`Treasure not up to yourselves treasures on the earth, where moth and rust disfigure, and where thieves break through and steal,", "tyndale": "Se that ye gaddre you not treasure vpon ye erth where rust and mothes corrupte and where theves breake through and steale.", "dra": "Lay not up to yourselves treasures on earth: where the rust, and moth consume, and where thieves break through, and steal.", "bbe": "Make no store of wealth for yourselves on earth, where it may be turned to dust by worms and weather, and where thieves may come in by force and take it away.", "geneva": "Lay not vp treasures for your selues vpon the earth, where the mothe and canker corrupt, and where theeues digge through and steale.", "wycliffe": "Nile ye tresoure to you tresouris in erthe, where ruste and mouyte destrieth, and where theues deluen out and stelen;", "rotherham": "Be not laying up for yourselves treasures upon the earth, where, moth and rust, do tarnish, and where, thieves, dig through and steal;", "weymouth": "\"Do not lay up stores of wealth for yourselves on earth, where the moth and wear-and-tear destroy, and where thieves break in and steal.", "darby": "Lay not up for yourselves treasures upon the earth, where moth and rust spoils, and where thieves dig through and steal;", "twenty": "Do not store up treasures for yourselves on earth, where moth and rust destroy, and where thieves break in and steal.", "acv": "Lay not up for yourselves treasures upon the earth, where moth and rust deteriorates, and where thieves break through and steal,", "anderson": "Lay not up for yourselves treasures on earth, where moths and rust consume, and where thieves break through and steal.", "haweis": "Lay not up for yourselves treasures upon earth, where the rust and canker spoil, and where thieves dig through and steal:", "noyes": "Lay not up for yourselves treasures on earth, where the moth and rust consume, and where thieves break through and steal;", "webster": "Lay not up for yourselves treasures upon earth, where moth and rust doth corrupt, and where thieves break through and steal:", "vulgate": "nolite thesaurizare vobis thesauros in terra ubi erugo et tinea demolitur ubi fures effodiunt et furantur;"}}, {"v": 20, "ref": "6:20", "o": "θησαυρίζετε δὲ ὑμῖν θησαυροὺς ἐν οὐρανῷ, ὅπου οὔτε σὴς οὔτε βρῶσις ἀφανίζει, καὶ ὅπου κλέπται οὐ διορύσσουσιν οὐδὲ κλέπτουσιν·", "en": {"kjv": "But lay up for yourselves treasures in heaven, where neither moth nor rust doth corrupt, and where thieves do not break through nor steal:", "web": "but lay up for yourselves treasures in heaven, where neither moth nor rust consume, and where thieves don’t break through and steal;", "bsb": "But store up for yourselves treasures in heaven, where moth and rust do not destroy, and where thieves do not break in and steal.", "asv": "but lay up for yourselves treasures in heaven, where neither moth nor rust doth consume, and where thieves do not break through nor steal:", "ylt": "but treasure up to yourselves treasures in heaven, where neither moth nor rust doth disfigure, and where thieves do not break through nor steal,", "tyndale": "But gaddre ye treasure togeder in heve where nether rust nor mothes corrupte and where theves nether breake vp nor yet steale.", "dra": "But lay up to yourselves treasures in heaven: where neither the rust nor moth doth consume, and where thieves do not break through, nor steal.", "bbe": "But make a store for yourselves in heaven, where it will not be turned to dust and where thieves do not come in to take it away:", "geneva": "But lay vp treasures for your selues in heauen, where neither the mothe nor canker corrupteth, and where theeues neither digge through, nor steale.", "wycliffe": "but gadere to you tresouris in heuene, where nether ruste ne mouyte distrieth, and where theues deluen not out, ne stelen.", "rotherham": "but be laying up or yourselves treasures in heaven, where, neither moth nor rust, doth tarnish, and where, thieves, dig not through nor steal:", "weymouth": "But amass wealth for yourselves in Heaven, where neither the moth nor wear-and-tear destroys, and where thieves do not break in and steal.", "darby": "but lay up for yourselves treasures in heaven, where neither moth nor rust spoils, and where thieves do not dig through nor steal;", "twenty": "But store up treasures for yourselves in Heaven, where neither moth nor rust destroys, and where thieves do not break in or steal.", "acv": "but lay up for yourselves treasures in heaven, where neither moth nor rust deteriorates, and where thieves do not break through nor steal.", "anderson": "But lay up for yourselves treasures in heaven, where neither moth nor rust consumes, and where thieves do not break through, nor steal.", "haweis": "but lay up for yourselves treasures in heaven, where neither rust nor canker spoil, and where thieves do not dig through and steal;", "noyes": "but lay up for yourselves treasures in heaven, where neither moth nor rust consumeth, and where thieves do not break through nor steal.", "webster": "But lay up for yourselves treasures in heaven, where neither moth nor rust doth corrupt, and where thieves do not break through nor steal.", "vulgate": "thesaurizate autem vobis thesauros in caelo ubi neque erugo neque tinea demolitur et ubi fures non effodiunt nec furantur;"}}, {"v": 21, "ref": "6:21", "o": "ὅπου γάρ ἐστιν ὁ θησαυρός ⸀σου, ἐκεῖ ἔσται καὶ ἡ καρδία ⸁σου.", "en": {"kjv": "For where your treasure is, there will your heart be also.", "web": "for where your treasure is, there your heart will be also.", "bsb": "For where your treasure is, there your heart will be also.", "asv": "for where thy treasure is, there will thy heart be also.", "ylt": "for where your treasure is, there will be also your heart.", "tyndale": "For where soever youre treasure ys there will youre hertes be also.", "dra": "For where thy treasure is, there is thy heart also.", "bbe": "For where your wealth is, there will your heart be.", "geneva": "For where your treasure is, there will your heart be also.", "wycliffe": "For where thi tresoure is, there also thin herte is.", "rotherham": "for, where, thy treasure, is, there, will be, thy heart [also].", "weymouth": "For where your wealth is, there also will your heart be.", "darby": "for where thy treasure is, there will be also thy heart.", "twenty": "For where your treasure is, there will your heart be also.", "acv": "For where your treasure is, there will your heart be also.", "anderson": "For where your treasure is, there will your heart be also.", "haweis": "for where your treasure is, there will your heart be also.", "noyes": "For where thy treasure is, there will thy heart be also.", "webster": "For where your treasure is, there will your heart be also.", "vulgate": "ubi enim est thesaurus tuus ibi est et cor tuum;"}}, {"v": 22, "ref": "6:22", "o": "Ὁ λύχνος τοῦ σώματός ἐστιν ὁ ὀφθαλμός. ἐὰν οὖν ⸂ᾖ ὁ ὀφθαλμός σου ἁπλοῦς⸃, ὅλον τὸ σῶμά σου φωτεινὸν ἔσται·", "en": {"kjv": "The light of the body is the eye: if therefore thine eye be single, thy whole body shall be full of light.", "web": "“The lamp of the body is the eye. If therefore your eye is sound, your whole body will be full of light.", "bsb": "The eye is the lamp of the body. If your eyes are good, your whole body will be full of light.", "asv": "The lamp of the body is the eye: if therefore thine eye be single, thy whole body shall be full of light.", "ylt": "`The lamp of the body is the eye, if, therefore, thine eye may be perfect, all thy body shall be enlightened,", "tyndale": "The light of the body is thyne eye. Wher fore if thyne eye besyngle all thy body shalbe full of light.", "dra": "The light of thy body is thy eye. If thy eye be single, thy whole body shall be lightsome.", "bbe": "The light of the body is the eye; if then your eye is true, all your body will be full of light.", "geneva": "The light of the body is the eye: if then thine eye be single, thy whole body shall be light.", "wycliffe": "The lanterne of thi bodi is thin iye; if thin iye be symple, al thi bodi shal be liytful;", "rotherham": "The lamp of the body, is the eye: if therefore thine eye be single, thy whole body, shall be, lighted up;", "weymouth": "\"The eye is the lamp of the body. If then your eyesight is good, your whole body will be well lighted;", "darby": "The lamp of the body is the eye; if therefore thine eye be single, thy whole body will be light:", "twenty": "The lamp of the body is the eye. If your eye is unclouded, your whole body will be lit up;", "acv": "The light of the body is the eye. If therefore thine eye is sound, thy whole body will be bright.", "anderson": "The lamp of the body is the eye: if, therefore, your eye be sound, your whole body will be light:", "haweis": "The lamp of the body is the eye: if therefore thine eye be transparent, thy whole body shall be enlightened.", "noyes": "The eye is the lamp of the body. If thine eye he clear, thy whole body will be in light;", "webster": "The light of the body is the eye: if therefore thy eye be single, thy whole body will be full of light.", "vulgate": "lucerna corporis est oculus si fuerit oculus tuus simplex totum corpus tuum lucidum erit;"}}, {"v": 23, "ref": "6:23", "o": "ἐὰν δὲ ὁ ὀφθαλμός σου πονηρὸς ᾖ, ὅλον τὸ σῶμά σου σκοτεινὸν ἔσται. εἰ οὖν τὸ φῶς τὸ ἐν σοὶ σκότος ἐστίν, τὸ σκότος πόσον.", "en": {"kjv": "But if thine eye be evil, thy whole body shall be full of darkness. If therefore the light that is in thee be darkness, how great is that darkness!", "web": "But if your eye is evil, your whole body will be full of darkness. If therefore the light that is in you is darkness, how great is the darkness!", "bsb": "But if your eyes are bad, your whole body will be full of darkness. If then the light within you is darkness, how great is that darkness!", "asv": "But if thine eye be evil, thy whole body shall be full of darkness. If therefore the light that is in thee be darkness, how great is the darkness!", "ylt": "but if thine eye may be evil, all thy body shall be dark; if, therefore, the light that is in thee is darkness--the darkness, how great!", "tyndale": "But and if thyne eye be wycked then all thy body shalbe full of derckenes. Wherfore yf the light that is in the be darckenes: how greate is that darckenes.", "dra": "But if thy eye be evil thy whole body shall be darksome. If then the light that is in thee, be darkness: the darkness itself how great shall it be!", "bbe": "But if your eye is evil, all your body will be dark. If then the light which is in you is dark, how dark it will be!", "geneva": "But if thine eye be wicked, then all thy body shalbe darke. Wherefore if the light that is in thee, be darkenes, howe great is that darkenesse?", "wycliffe": "but if thin iye be weiward, al thi bodi shal be derk. If thanne the liyt that is in thee be derknessis, how grete schulen thilk derknessis be?", "rotherham": "But, if thine eye be, evil, thy whole body, shall be, in the dark;—if therefore, the light which is in thee, is, darkness, the darkness, how great!", "weymouth": "but if your eyesight is bad, your whole body will be dark. If however the very light within you is darkness, how dense must the darkness be!", "darby": "but if thine eye be wicked, thy whole body will be dark. If therefore the light that is in thee be darkness, how great the darkness!", "twenty": "but, if your eye is diseased, your whole body will be darkened. And, if the inner light is darkness, how intense must that darkness be!", "acv": "But if thine eye is bad, thy whole body will be dark. If therefore the light that is in thee is darkness, how great is the darkness!", "anderson": "But if your eye be diseased, your whole body will be dark. If therefore, the light that is in you is darkness, how great is that darkness!", "haweis": "But if thine eye be vitiated, thy whole body will be darkened. If therefore the light which is in thee be darkness, how great is that darkness!", "noyes": "but if thine eye be disordered, thy whole body will be in darkness. If then the light that is within thee is darkness, how great that darkness!", "webster": "But if thy eye be evil, thy whole body will be full of darkness. If therefore the light that is in thee is darkness, how great [is] that darkness!", "vulgate": "si autem oculus tuus nequam fuerit totum corpus tuum tenebrosum erit si ergo lumen quod in te est tenebrae sunt tenebrae quantae erunt;"}}, {"v": 24, "ref": "6:24", "o": "Οὐδεὶς δύναται δυσὶ κυρίοις δουλεύειν· ἢ γὰρ τὸν ἕνα μισήσει καὶ τὸν ἕτερον ἀγαπήσει, ἢ ἑνὸς ἀνθέξεται καὶ τοῦ ἑτέρου καταφρονήσει. οὐ δύνασθε θεῷ δουλεύειν καὶ μαμωνᾷ.", "en": {"kjv": "No man can serve two masters: for either he will hate the one, and love the other; or else he will hold to the one, and despise the other. Ye cannot serve God and mammon.", "web": "“No one can serve two masters, for either he will hate the one and love the other; or else he will be devoted to one and despise the other. You can’t serve both God and Mammon.", "bsb": "No one can serve two masters: Either he will hate the one and love the other, or he will be devoted to the one and despise the other. You cannot serve both God and money.", "asv": "No man can serve two masters: for either he will hate the one, and love the other; or else he will hold to one, and despise the other. Ye cannot serve God and mammon.", "ylt": "`None is able to serve two lords, for either he will hate the one and love the other, or he will hold to the one, and despise the other; ye are not able to serve God and Mammon.", "tyndale": "No ma can serve two masters. For ether he shall hate the one and love the other: or els he shall lene to ye one and despise ye other: ye can not serve God and mammon.", "dra": "No man can serve two masters. For either he will hate the one, and love the other: or he will sustain the one, and despise the other. You cannot serve God and mammon.", "bbe": "No man is able to be a servant to two masters: for he will have hate for the one and love for the other, or he will keep to one and have no respect for the other. You may not be servants of God and of wealth.", "geneva": "No man can serue two masters: for eyther he shall hate the one, and loue the other, or els he shall leane to the one, and despise the other. Ye cannot serue God and riches.", "wycliffe": "No man may serue tweyn lordis, for ethir he schal hate `the toon, and loue the tother; ethir he shal susteyne `the toon, and dispise the tothir. Ye moun not serue God and richessis.", "rotherham": "No one, unto two masters, can be in service; for either, the one, he will hate, and, the other ,love, or, one, he will hold to, and, the other, despise: Ye cannot be in service, unto God, and, unto Riches.", "weymouth": "\"No man can be the bondservant of two masters; for either he will dislike one and like the other, or he will attach himself to one and think slightingly of the other. You cannot be the bondservants both of God and of gold.", "darby": "No one can serve two masters; for either he will hate the one and will love the other, or he will hold to the one and despise the other. Ye cannot serveGod and mammon.", "twenty": "No one can serve two masters, for either he will hate one and love the other, or else he will attach himself to one and despise the other. You cannot serve both God and Money.", "acv": "No man can serve two masters, for either he will hate the one, and love the other, or he will hold to one, and disparage the other. Ye cannot serve God and mammon.", "anderson": "No one can serve two masters: for he will either hate the one and love the other; or he will hold to the one, and neglect the other. You can not serve God and riches.", "haweis": "No man can serve two masters: for he will either hate the one, and love the other; or he will adhere to the one, and disregard the other. Ye cannot serve God and mammon.", "noyes": "No one can serve two masters; for either he will hate one, and love the other; or else he will cleave to one, and despise the other. Ye cannot serve God and mammon.", "webster": "No man can serve two masters: for either he will hate the one, and love the other; or else he will hold to the one, and despise the other. Ye cannot serve God and mammon.", "vulgate": "nemo potest duobus dominis servire aut enim unum odio habebit et alterum diliget aut unum sustinebit et alterum contemnet non potestis Deo servire et mamonae;"}}, {"v": 25, "ref": "6:25", "o": "Διὰ τοῦτο λέγω ὑμῖν· μὴ μεριμνᾶτε τῇ ψυχῇ ὑμῶν τί ⸀φάγητε, μηδὲ τῷ σώματι ὑμῶν τί ἐνδύσησθε· οὐχὶ ἡ ψυχὴ πλεῖόν ἐστι τῆς τροφῆς καὶ τὸ σῶμα τοῦ ἐνδύματος;", "en": {"kjv": "Therefore I say unto you, Take no thought for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than meat, and the body than raiment?", "web": "Therefore I tell you, don’t be anxious for your life: what you will eat, or what you will drink; nor yet for your body, what you will wear. Isn’t life more than food, and the body more than clothing?", "bsb": "Therefore I tell you, do not worry about your life, what you will eat or drink; or about your body, what you will wear. Is not life more than food, and the body more than clothes?", "asv": "Therefore I say unto you, Be not anxious for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than the food, and the body than the raiment?", "ylt": "`Because of this I say to you, be not anxious for your life, what ye may eat, and what ye may drink, nor for your body, what ye may put on. Is not the life more than the nourishment, and the body than the clothing?", "tyndale": "Therfore I saye vnto you be not carefull for your lyfe what ye shall eate or what ye shall drincke nor yet for youre body what ye shall put on. ys not ye lyfe more worth then meate and the body more of value then raymeut?", "dra": "Therefore I say to you, be not solicitous for your life, what you shall eat, nor for your body, what you shall put on. Is not the life more than the meat: and the body more than the raiment?", "bbe": "So I say to you, Take no thought for your life, about food or drink, or about clothing for your body. Is not life more than food, and the body more than its clothing?", "geneva": "Therefore I say vnto you, be not carefull for your life, what ye shall eate, or what ye shall drinke: nor yet for your body, what ye shall put on. Is not the life more worth then meate? and the bodie then raiment?", "wycliffe": "Therfor I seie to you, that ye be not bisi to youre lijf, what ye schulen ete; nether to youre bodi, with what ye schulen be clothid. Whether lijf is not more than meete, and the bodie more than cloth?", "rotherham": "For this cause, I say unto you: Be not anxious for your life, what ye shall eat [or what ye shall drink],—or for your body, what ye shall put on: Is not, the life, more than, the food? And, the body, than, the raiment?", "weymouth": "For this reason I charge you not to be over-anxious about your lives, inquiring what you are to eat or what you are to drink, nor yet about your bodies, inquiring what clothes you are to put on. Is not the life more precious than its food, and the body than its clothing?", "darby": "For this cause I say unto you, Do not be careful about your life, what ye should eat and what ye should drink; nor for your body what ye should put on. Is not the life more than food, and the body than raiment?", "twenty": "That is why I say to you, Do not be anxious about your life here — what you can get to eat or drink; nor yet about your body — what you can get to wear. Is not life more than food, and the body than its clothing?", "acv": "Because of this I say to you, be not anxious about your life, what ye may eat, or what ye may drink, nor yet for your body, what ye may wear. Is not the life more than the food, and the body than the clothing?", "anderson": "For this reason I say to you, Be not anxious for your life, what you shall eat, and what you shall drink; nor for your body, what you shall put on. Is not your life a greater gift than food, and your body than clothing?", "haweis": "For this cause I tell you, Be not anxious about your life, what ye shall eat, or what ye shall drink; nor for your body, what ye shall put on. Is not the life of more value than meat, and the body than raiment?", "noyes": "Therefore I say to you, Be not anxious for your life, what ye shall eat; nor yet for your body, what ye shall put on. Is not the life more than food, and the body than raiment?", "webster": "Therefore I say to you, Be not anxious for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than food, and the body than raiment?", "vulgate": "ideo dico vobis ne solliciti sitis animae vestrae quid manducetis neque corpori vestro quid induamini nonne anima plus est quam esca et corpus plus est quam vestimentum;"}}, {"v": 26, "ref": "6:26", "o": "ἐμβλέψατε εἰς τὰ πετεινὰ τοῦ οὐρανοῦ ὅτι οὐ σπείρουσιν οὐδὲ θερίζουσιν οὐδὲ συνάγουσιν εἰς ἀποθήκας, καὶ ὁ πατὴρ ὑμῶν ὁ οὐράνιος τρέφει αὐτά· οὐχ ὑμεῖς μᾶλλον διαφέρετε αὐτῶν;", "en": {"kjv": "Behold the fowls of the air: for they sow not, neither do they reap, nor gather into barns; yet your heavenly Father feedeth them. Are ye not much better than they?", "web": "See the birds of the sky, that they don’t sow, neither do they reap, nor gather into barns. Your heavenly Father feeds them. Aren’t you of much more value than they?", "bsb": "Look at the birds of the air: They do not sow or reap or gather into barns—and yet your heavenly Father feeds them. Are you not much more valuable than they?", "asv": "Behold the birds of the heaven, that they sow not, neither do they reap, nor gather into barns; and your heavenly Father feedeth them. Are not ye of much more value than they?", "ylt": "look to the fowls of the heaven, for they do not sow, nor reap, nor gather into storehouses, and your heavenly Father doth nourish them; are not ye much better than they?", "tyndale": "Beholde the foules of ye ayer: for they sowe not nether reepe nor yet cary into ye barnes: and yet youre hevely father fedeth the. Are ye not moche better the they?", "dra": "Behold the birds of the air, for they neither sow, nor do they reap, nor gather into barns: and your heavenly Father feedeth them. Are not you of much more value than they?", "bbe": "See the birds of heaven; they do not put seeds in the earth, they do not get in grain, or put it in store-houses; and your Father in heaven gives them food. Are you not of much more value than they?", "geneva": "Behold the foules of the heauen: for they sowe not, neither reape, nor carie into the barnes: yet your heauenly Father feedeth them. Are ye not much better then they?", "wycliffe": "Biholde ye the foulis of the eire, for thei sowen not, nethir repen, nethir gaderen in to bernes; and youre fadir of heuene fedith hem. Whether ye ben not more worthi than thei?", "rotherham": "Observe intently, the birds of the heaven,—that they neither sow, nor reap, nor gather into barns, and yet, your heavenly Father, feedeth, them: Are no, ye, much better than, they?", "weymouth": "Look at the birds which fly in the air: they do not sow or reap or store up in barns, but your Heavenly Father feeds them: are not you of much greater value than they?", "darby": "Look at the birds of the heaven, that they sow not, nor reap, nor gather into granaries, and your heavenly Father nourishes them. Are ye not much more excellent than they?", "twenty": "Look at the wild birds — they neither sow, nor reap, nor gather into barns; and yet your heavenly Father feeds them! And are not you more precious than they?", "acv": "Look to the birds of the sky, because they sow not, nor do they reap, nor gather into barns, and your heavenly Father feeds them. Are ye not more valuable then they?", "anderson": "Observe the birds of the air, that they neither sow, nor reap, nor gather into granaries. Yet your heavenly Father feeds them. Are you not much better than they?", "haweis": "Look on the birds of the air: for they neither sow, nor reap, nor gather into barns; yet your heavenly Father feedeth them. Are you not of more value than they?", "noyes": "Behold the birds of the air, that they sow not, nor reap, nor gather into barns; and your heavenly Father feedeth them. Are not ye of much greater value than they?", "webster": "Behold the fowls of the air: for they sow not, neither do they reap, nor gather into barns; yet your heavenly Father feedeth them. Are ye not much better than they?", "vulgate": "respicite volatilia caeli quoniam non serunt neque metunt neque congregant in horrea et Pater vester caelestis pascit illa nonne vos magis pluris estis illis;"}}, {"v": 27, "ref": "6:27", "o": "τίς δὲ ἐξ ὑμῶν μεριμνῶν δύναται προσθεῖναι ἐπὶ τὴν ἡλικίαν αὐτοῦ πῆχυν ἕνα;", "en": {"kjv": "Which of you by taking thought can add one cubit unto his stature?", "web": "“Which of you, by being anxious, can add one momentto his lifespan?", "bsb": "Who of you by worrying can add a single hour to his life?", "asv": "And which of you by being anxious can add one cubit unto the measure of his life?", "ylt": "`And who of you, being anxious, is able to add to his age one cubit?", "tyndale": "Which of you (though he toke thought therfore) coulde put one cubit vnto his stature?", "dra": "And which of you by taking thought, can add to his stature one cubit?", "bbe": "And which of you by taking thought is able to make himself a cubit taller?", "geneva": "Which of you by taking care is able to adde one cubite vnto his stature?", "wycliffe": "But who of you thenkynge mai putte to his stature o cubit?", "rotherham": "But who from among you, being anxious, can add to his stature one cubit?", "weymouth": "Which of you by being over-anxious can add a single foot to his height?", "darby": "But which of you by carefulness can add to his growth one cubit?", "twenty": "But which of you, by being anxious, can prolong his life a single moment?", "acv": "And which man of you by being anxious can add one cubit to his life span?", "anderson": "Which of you, by his anxiety, can add one span to his life?", "haweis": "But which of you, by his cares, can add one cubit to his stature?", "noyes": "But who of you by anxious thought can add to his life one cubit?", "webster": "Which of you by anxious care can add one cubit to his stature?", "vulgate": "quis autem vestrum cogitans potest adicere ad staturam suam cubitum unum;"}}, {"v": 28, "ref": "6:28", "o": "καὶ περὶ ἐνδύματος τί μεριμνᾶτε; καταμάθετε τὰ κρίνα τοῦ ἀγροῦ πῶς ⸂αὐξάνουσιν· οὐ κοπιῶσιν οὐδὲ νήθουσιν⸃·", "en": {"kjv": "And why take ye thought for raiment? Consider the lilies of the field, how they grow; they toil not, neither do they spin:", "web": "Why are you anxious about clothing? Consider the lilies of the field, how they grow. They don’t toil, neither do they spin,", "bsb": "And why do you worry about clothes? Consider how the lilies of the field grow: They do not labor or spin.", "asv": "And why are ye anxious concerning raiment? Consider the lilies of the field, how they grow; they toil not, neither do they spin:", "ylt": "and about clothing why are ye anxious? consider well the lilies of the field; how do they grow? they do not labour, nor do they spin;", "tyndale": "And why care ye then for raymet? Considre ye lylies of ye felde how they growe. They labour not nether spynne.", "dra": "And for raiment why are you solicitous? Consider the lilies of the field, how they grow: they labour not, neither do they spin.", "bbe": "And why are you troubled about clothing? See the flowers of the field, how they come up; they do no work, they make no thread:", "geneva": "And why care ye for raiment? Learne howe the lilies of the fielde doe growe: they are not wearied, neither spinne:", "wycliffe": "And of clothing what ben ye bisye? Biholde ye the lilies of the feeld, how thei wexen. Thei trauelen not, nether spynnen;", "rotherham": "And, about clothing, why are ye anxious? Consider well the lilies of the field, how they grow,—they toil not neither do they spin;", "weymouth": "And why be anxious about clothing? Learn a lesson from the wild lilies. Watch their growth. They neither toil nor spin,", "darby": "And why are ye careful about clothing? Observe with attention the lilies of the field, how they grow: they toil not, neither do they spin;", "twenty": "And why be anxious about clothing? Study the wild lilies, and how they grow. They neither toil nor spin;", "acv": "And why are ye anxious about clothing? Consider the lilies of the field, how they grow. They toil not, nor do they spin,", "anderson": "And why are you anxious about clothing? Consider the lilies of the field how they grow: they toil not, nor do they spin.", "haweis": "And why are ye anxious about clothing? Contemplate the lilies of the field, how they grow; they toil not, nor spin:", "noyes": "And why are ye anxious about raiment? Consider the lilies of the field, how they grow. They toil not, neither do they spin;", "webster": "And why are ye anxious for raiment? Consider the lilies of the field how they grow? they toil not, neither do they spin?", "vulgate": "et de vestimento quid solliciti estis considerate lilia agri quomodo crescunt non laborant nec nent;"}}, {"v": 29, "ref": "6:29", "o": "λέγω δὲ ὑμῖν ὅτι οὐδὲ Σολομὼν ἐν πάσῃ τῇ δόξῃ αὐτοῦ περιεβάλετο ὡς ἓν τούτων.", "en": {"kjv": "And yet I say unto you, That even Solomon in all his glory was not arrayed like one of these.", "web": "yet I tell you that even Solomon in all his glory was not dressed like one of these.", "bsb": "Yet I tell you that not even Solomon in all his glory was adorned like one of these.", "asv": "yet I say unto you, that even Solomon in all his glory was not arrayed like one of these.", "ylt": "and I say to you, that not even Solomon in all his glory was arrayed as one of these.", "tyndale": "And yet for all yt I saye vnto you yt eue Salomon in all his royalte was not arayed lyke vnto one of these.", "dra": "But I say to you, that not even Solomon in all his glory was arrayed as one of these.", "bbe": "But I say to you that even Solomon in all his glory was not clothed like one of these.", "geneva": "Yet I say vnto you, that euen Salomon in all his glorie was not arayed like one of these.", "wycliffe": "and Y seie to you, Salomon in al his glorie was not keuered as oon of these.", "rotherham": "And yet, I say unto you, not even Solomon, in all his glory, was arrayed like, one of these!", "weymouth": "and yet I tell you that not even Solomon in all his magnificence could array himself like one of these.", "darby": "but I say unto you, that not even Solomon in all his glory was clothed as one of these.", "twenty": "yet I tell you that even Solomon in all his splendour was not robed like one of these.", "acv": "yet I say to you, that not even Solomon in all his glory was arrayed like one of these.", "anderson": "But I say to you, That Solomon, in all his glory, was not clothed like one of these.", "haweis": "yet I tell you, Not even Solomon in all his glory was arrayed as one of these.", "noyes": "and yet I say to you, that not even Solomon in all his glory was arrayed like one of these.", "webster": "And yet I say to you, that even Solomon in all his glory was not arrayed like one of these.", "vulgate": "dico autem vobis quoniam nec Salomon in omni gloria sua coopertus est sicut unum ex istis;"}}, {"v": 30, "ref": "6:30", "o": "εἰ δὲ τὸν χόρτον τοῦ ἀγροῦ σήμερον ὄντα καὶ αὔριον εἰς κλίβανον βαλλόμενον ὁ θεὸς οὕτως ἀμφιέννυσιν, οὐ πολλῷ μᾶλλον ὑμᾶς, ὀλιγόπιστοι;", "en": {"kjv": "Wherefore, if God so clothe the grass of the field, which to day is, and to morrow is cast into the oven, shall he not much more clothe you, O ye of little faith?", "web": "But if God so clothes the grass of the field, which today exists, and tomorrow is thrown into the oven, won’t he much more clothe you, you of little faith?", "bsb": "If that is how God clothes the grass of the field, which is here today and tomorrow is thrown into the furnace, will He not much more clothe you, O you of little faith?", "asv": "But if God doth so clothe the grass of the field, which to-day is, and to-morrow is cast into the oven, shall he not much more clothe you, O ye of little faith?", "ylt": "`And if the herb of the field, that to-day is, and to-morrow is cast to the furnace, God doth so clothe--not much more you, O ye of little faith?", "tyndale": "Wherfore yf God so clothe the grasse which ys to daye in the felde and to morowe shalbe caste in to the fournace: shall he not moche more do the same vnto you o ye of lytle fayth?", "dra": "And if the grass of the field, which is to day, and to morrow is cast into the oven, God doth so clothe: how much more you, O ye of little faith?", "bbe": "But if God gives such clothing to the grass of the field, which is here today and tomorrow is put into the oven, will he not much more give you clothing, O you of little faith?", "geneva": "Wherefore if God so clothe the grasse of the fielde which is to day, and to morowe is cast into the ouen, shall he not doe much more vnto you, O ye of litle faith?", "wycliffe": "And if God clothith thus the hei of the feeld, that to day is, and to morewe is cast in to an ouen, hou myche more you of litel feith?", "rotherham": "Now, if the grass of the field—which to-day, is, and, to-morrow, into an oven, is cast—God thus adorneth, not much rather, you, little of faith?", "weymouth": "And if God so clothes the wild herbage which to-day flourishes and to-morrow is thrown into the oven, is it not much more certain that He will clothe you, you men of little faith?", "darby": "But ifGod so clothe the herbage of the field, which is to-day, and to-morrow is cast into [the] oven, will he not much rather you, O [ye] of little faith?", "twenty": "If God so clothes even the grass of the field, which is living to-day and to-morrow will be thrown into the oven, will not he much more clothe you, O men of little faith?", "acv": "And if God so clothes the grass of the field, which today is, and tomorrow is cast into an oven, will he not much more you, O ye of little faith?", "anderson": "If then, God so clothes the herb of the field, which to-day is, and to-morrow is thrown into the oven, will he not much more clothe you, O you of little faith?", "haweis": "If God then so clothe a vegetable of the field, which to-day is, in beauty, and tomorrow is cast into the furnace, shall he not much more clothe you, O ye of little faith?", "noyes": "And if God so clothes the herbage of the field, which today is, and tomorrow is cast into an oven, will he not much more clothe you, O ye of little faith?", "webster": "Wherefore, if God so clotheth the grass of the field, which to-day is, and to-morrow is cast into the oven, [will he] not much more [clothe] you, O ye of little faith?", "vulgate": "si autem faenum agri quod hodie est et cras in clibanum mittitur Deus sic vestit quanto magis vos minimae fidei;"}}, {"v": 31, "ref": "6:31", "o": "μὴ οὖν μεριμνήσητε λέγοντες· Τί φάγωμεν; ἤ· Τί πίωμεν; ἤ· Τί περιβαλώμεθα;", "en": {"kjv": "Therefore take no thought, saying, What shall we eat? or, What shall we drink? or, Wherewithal shall we be clothed?", "web": "“Therefore don’t be anxious, saying, ‘What will we eat?’, ‘What will we drink?’ or, ‘With what will we be clothed?’", "bsb": "Therefore do not worry, saying, ‘What shall we eat?’ or ‘What shall we drink?’ or ‘What shall we wear?’", "asv": "Be not therefore anxious, saying, What shall we eat? or, What shall we drink? or, Wherewithal shall we be clothed?", "ylt": "therefore ye may not be anxious, saying, What may we eat? or, What may we drink? or, What may we put round?", "tyndale": "Therfore take no thought sayinge: what shall we eate or what shall we drincke or wherwt shall we be clothed?", "dra": "Be not solicitous therefore, saying: What shall we eat: or what shall we drink, or wherewith shall we be clothed?", "bbe": "Then do not be full of care, saying, What are we to have for food or drink? or, With what may we be clothed?", "geneva": "Therefore take no thought, saying, What shall we eate? or what shall we drinke? or where with shall we be clothed?", "wycliffe": "Therfor nyle ye be bisi, seiynge, What schulen we ete? or, What schulen we drinke? or, With what thing schulen we be keuered?", "rotherham": "Do not then be anxious saying, What shall we eat? or What shall we drink? or Wherewithal shall we be arrayed?", "weymouth": "Do not be over-anxious, therefore, asking `What shall we eat?' or `What shall we drink?' or `What shall we wear?'", "darby": "Be not therefore careful, saying, What shall we eat? or What shall we drink? or What shall we put on?", "twenty": "Do not then ask anxiously ‘What can we get to eat?’ or ‘What can we get to drink?’ or ‘What can we get to wear?’", "acv": "Be not therefore anxious, saying, What may we eat? or, What may we drink? or, What may we wear?", "anderson": "Therefore, be not anxious, saying: What shall we eat? or, what shall we drink? or, with what shall we be clothed?", "haweis": "Wherefore be under no anxiety, saying, What shall we eat? or, What shall we drink? or, With what shall we be clothed?", "noyes": "Therefore be not anxious, saying, What shall we eat, or what shall we drink, or wherewith shall we he clothed?", "webster": "Therefore be not anxious, saying, What shall we eat? or what shall we drink? or, with what shall we be clothed?", "vulgate": "nolite ergo solliciti esse dicentes quid manducabimus aut quid bibemus aut quo operiemur;"}}, {"v": 32, "ref": "6:32", "o": "πάντα γὰρ ταῦτα τὰ ἔθνη ⸀ἐπιζητοῦσιν· οἶδεν γὰρ ὁ πατὴρ ὑμῶν ὁ οὐράνιος ὅτι χρῄζετε τούτων ἁπάντων.", "en": {"kjv": "(For after all these things do the Gentiles seek:) for your heavenly Father knoweth that ye have need of all these things.", "web": "For the Gentiles seek after all these things; for your heavenly Father knows that you need all these things.", "bsb": "For the Gentiles strive after all these things, and your heavenly Father knows that you need them.", "asv": "For after all these things do the Gentiles seek; for your heavenly Father knoweth that ye have need of all these things.", "ylt": "for all these do the nations seek for, for your heavenly Father doth know that ye have need of all these;", "tyndale": "After all these thynges seke the getyls. For youre hevely father knoweth that ye have neade of all these thynges.", "dra": "For after all these things do the heathens seek. For your Father knoweth that you have need of all these things.", "bbe": "Because the Gentiles go in search of all these things: for your Father in heaven has knowledge that you have need of all these things:", "geneva": "(For after all these things seeke the Gentiles) for your heauenly Father knoweth, that ye haue neede of all these things.", "wycliffe": "For hethene men seken alle these thingis; and youre fadir woot, that ye han nede to alle these thingis.", "rotherham": "For, all these things, the nations, seek after,—for your heavenly Father, knoweth, that ye are needing, all these things.", "weymouth": "For all these are questions that Gentiles are always asking; but your Heavenly Father knows that you need these things--all of them.", "darby": "for all these things the nations seek after; for your heavenly Father knows that ye have need of all these things.", "twenty": "All these are the things for which the nations are seeking, and your heavenly Father knows that you need them all.", "acv": "For the Gentiles seek after all these things, for your heavenly Father knows that ye need all these things.", "anderson": "For after all these things do the Gentiles seek: for your heavenly Father knows that you need all these things.", "haweis": "(for after all these things the heathen seek:) and your heavenly Father knoweth that ye have need of them all.", "noyes": "For after all these things do the gentiles seek; for your heavenly Father knoweth that ye have need of all these things.", "webster": "(For after all these things do the Gentiles seek) for your heavenly Father knoweth that ye have need of all these things.", "vulgate": "haec enim omnia gentes inquirunt scit enim Pater vester quia his omnibus indigetis;"}}, {"v": 33, "ref": "6:33", "o": "ζητεῖτε δὲ πρῶτον τὴν ⸀βασιλείαν καὶ τὴν δικαιοσύνην αὐτοῦ, καὶ ταῦτα πάντα προστεθήσεται ὑμῖν.", "en": {"kjv": "But seek ye first the kingdom of God, and his righteousness; and all these things shall be added unto you.", "web": "But seek first God’s Kingdom, and his righteousness; and all these things will be given to you as well.", "bsb": "But seek first the kingdom of God and His righteousness, and all these things will be added unto you.", "asv": "But seek ye first his kingdom, and his righteousness; and all these things shall be added unto you.", "ylt": "but seek ye first the reign of God and His righteousness, and all these shall be added to you.", "tyndale": "But rather seke ye fyrst the kyngdome of heuen and the rightwisnes therof and all these thynges shalbe ministred vnto you.", "dra": "Seek ye therefore first the kingdom of God, and his justice, and all these things shall be added unto you.", "bbe": "But let your first care be for his kingdom and his righteousness; and all these other things will be given to you in addition.", "geneva": "But seeke ye first the kingdome of God, and his righteousnesse, and all these things shall be ministred vnto you.", "wycliffe": "Therfor seke ye first the kyngdom of God, and his riytfulnesse, and alle these thingis shulen be cast to you.", "rotherham": "But be seeking first, the kingdom and its righteousness,—and, all these things, shall be added unto you.", "weymouth": "But make His Kingdom and righteousness your chief aim, and then these things shall all be given you in addition.", "darby": "But seek ye first the kingdom ofGod and his righteousness, and all these things shall be added unto you.", "twenty": "But first seek his Kingdom and the righteousness that he requires, and then all these things shall be added for you.", "acv": "But seek ye first the kingdom of God and his righteousness, and all these things will be added to you.", "anderson": "But seek first the kingdom of God, and his righteousness, and all these things shall be given to you in addition.", "haweis": "But seek ye, in the first place, the kingdom of God, and his righteousness; and all these things shall be given you over.", "noyes": "But seek first his kingdom, and his righteousness; and all these things will also be given you.", "webster": "But seek ye first the kingdom of God, and his righteousness, and all these things shall be added to you.", "vulgate": "quaerite autem primum regnum et iustitiam eius et omnia haec adicientur vobis;"}}, {"v": 34, "ref": "6:34", "o": "μὴ οὖν μεριμνήσητε εἰς τὴν αὔριον, ἡ γὰρ αὔριον μεριμνήσει ⸀αὑτῆς· ἀρκετὸν τῇ ἡμέρᾳ ἡ κακία αὐτῆς.", "en": {"kjv": "Take therefore no thought for the morrow: for the morrow shall take thought for the things of itself. Sufficient unto the day is the evil thereof.", "web": "Therefore don’t be anxious for tomorrow, for tomorrow will be anxious for itself. Each day’s own evil is sufficient.", "bsb": "Therefore do not worry about tomorrow, for tomorrow will worry about itself. Today has enough trouble of its own.", "asv": "Be not therefore anxious for the morrow: for the morrow will be anxious for itself. Sufficient unto the day is the evil thereof.", "ylt": "Be not therefore anxious for the morrow, for the morrow shall be anxious for its own things; sufficient for the day is the evil of it.", "tyndale": "Care not then for the morow but let ye morow care for it selfe: for the daye present hath ever ynough of his awne trouble.", "dra": "Be not therefore solicitous for to morrow; for the morrow will be solicitous for itself. Sufficient for the day is the evil thereof.", "bbe": "Then have no care for tomorrow: tomorrow will take care of itself. Take the trouble of the day as it comes.", "geneva": "Care not then for the morowe: for the morowe shall care for it selfe: the day hath ynough with his owne griefe.", "wycliffe": "Therfor nyle ye be bisy in to the morew, for the morew shal be bisi to `hym silf; for it suffisith to the dai his owen malice.", "rotherham": "Do not, then, be anxious for the morrow; for the morrow, will be anxious, for itself: Sufficient for the day, is the evil thereof.", "weymouth": "Do not be over-anxious, therefore, about to-morrow, for to-morrow will bring its own cares. Enough for each day are its own troubles.", "darby": "Be not careful therefore for the morrow, for the morrow shall be careful about itself. Sufficient to the day [is] its own evil.", "twenty": "Therefore do not be anxious about to-morrow, for to-morrow will bring its own anxieties. Every day has trouble enough of its own.", "acv": "Be not therefore anxious for the morrow, for the morrow will be anxious about things of itself. Sufficient for the day is the evil of it.", "anderson": "Therefore, be not anxious about the morrow, for the morrow will have anxieties of its own. Sufficient for the day is its own evil.", "haweis": "Be not therefore anxious about to-morrow: for tomorrow will provide for its own wants. Sufficient for the day is the evil thereof.", "noyes": "Be not then anxious about the morrow; for the morrow will be anxious about itself. Sufficient for the day is the evil thereof.", "webster": "Therefore be not anxious for the morrow: for the morrow will be solicitous for the things of itself. Sufficient to the day [is] its own evil.", "vulgate": "nolite ergo esse solliciti in crastinum crastinus enim dies sollicitus erit sibi ipse sufficit diei malitia sua;"}}]}, {"c": 7, "verses": [{"v": 1, "ref": "7:1", "o": "Μὴ κρίνετε, ἵνα μὴ κριθῆτε·", "en": {"kjv": "Judge not, that ye be not judged.", "web": "“Don’t judge, so that you won’t be judged.", "bsb": "“Do not judge, or you will be judged.", "asv": "Judge not, that ye be not judged.", "ylt": "`Judge not, that ye may not be judged,", "tyndale": "Iudge not that ye be not iudged.", "dra": "Judge not, that you may not be judged.", "bbe": "Be not judges of others, and you will not be judged.", "geneva": "Judge not, that ye be not iudged.", "wycliffe": "Nile ye deme, `that ye be not demed; for in what doom ye demen,", "rotherham": "Judge not, that ye be not judged;—", "weymouth": "\"Judge not, that you may not be judged;", "darby": "Judge not, that ye may not be judged;", "twenty": "Do not judge, that you may not be judged.", "acv": "Do not criticize, that ye may not be criticized.", "anderson": "Judge not, that you may not be judged:", "haweis": "JUDGE not, that ye be not judged.", "noyes": "Judge not, that ye be not judged.", "webster": "Judge not, that ye be not judged.", "vulgate": "nolite iudicare ut non iudicemini;"}}, {"v": 2, "ref": "7:2", "o": "ἐν ᾧ γὰρ κρίματι κρίνετε κριθήσεσθε, καὶ ἐν ᾧ μέτρῳ μετρεῖτε μετρηθήσεται ὑμῖν.", "en": {"kjv": "For with what judgment ye judge, ye shall be judged: and with what measure ye mete, it shall be measured to you again.", "web": "For with whatever judgment you judge, you will be judged; and with whatever measure you measure, it will be measured to you.", "bsb": "For with the same judgment you pronounce, you will be judged; and with the measure you use, it will be measured to you.", "asv": "For with what judgment ye judge, ye shall be judged: and with what measure ye mete, it shall be measured unto you.", "ylt": "for in what judgment ye judge, ye shall be judged, and in what measure ye measure, it shall be measured to you.", "tyndale": "For as ye iudge so shall ye be iudged. And wt what mesure ye mete wt the same shall it be mesured to you agayne.", "dra": "For with what judgment you judge, you shall be judged: and with what measure you mete, it shall be measured to you again.", "bbe": "For as you have been judging, so you will be judged, and with your measure will it be measured to you.", "geneva": "Eor with what iudgement ye iudge, ye shall be iudged, and with what measure ye mete, it shall be measured to you againe.", "wycliffe": "ye schulen be demed, and in what mesure ye meten, it schal be meten ayen to you.", "rotherham": "For, with what judgment ye judge, shall ye be judged,—and, with what measure ye mete, shall it be measured unto you.", "weymouth": "for your own judgement will be dealt--and your own measure meted--to yourselves.", "darby": "for with what judgment ye judge, ye shall be judged; and with what measure ye mete, it shall be measured to you.", "twenty": "For, just as you judge others, you will yourselves be judged, and the measure that you mete will be meted out to you.", "acv": "For by what criticism ye criticize, ye will be criticized, and by what measure ye measure, it will be measured to you.", "anderson": "for with what judgment you judge, you shall be judged: and with what measure you measure, it shall be measured to you.", "haweis": "For with the same judgment ye judge others, shall ye be judged: and with the measure ye mete, shall it be measured to you again.", "noyes": "For with what judgment ye judge, ye will be judged; and with what measure ye mete, it will be measured to you.", "webster": "For with what judgment ye judge, ye shall be judged: and the measure which ye give, shall be measured to you again.", "vulgate": "in quo enim iudicio iudicaveritis iudicabimini et in qua mensura mensi fueritis metietur vobis;"}}, {"v": 3, "ref": "7:3", "o": "τί δὲ βλέπεις τὸ κάρφος τὸ ἐν τῷ ὀφθαλμῷ τοῦ ἀδελφοῦ σου, τὴν δὲ ἐν τῷ σῷ ὀφθαλμῷ δοκὸν οὐ κατανοεῖς;", "en": {"kjv": "And why beholdest thou the mote that is in thy brother’s eye, but considerest not the beam that is in thine own eye?", "web": "Why do you see the speck that is in your brother’s eye, but don’t consider the beam that is in your own eye?", "bsb": "Why do you look at the speck in your brother’s eye, but fail to notice the beam in your own eye?", "asv": "And why beholdest thou the mote that is in thy brother’s eye, but considerest not the beam that is in thine own eye?", "ylt": "`And why dost thou behold the mote that is in thy brother's eye, and the beam that is in thine own eye dost not consider?", "tyndale": "Why seist thou a moote in thy brothers eye and perceavest not the beame yt ys yn thyne awne eye.", "dra": "And why seest thou the mote that is in thy brother's eye; and seest not the beam that is in thy own eye?", "bbe": "And why do you take note of the grain of dust in your brother's eye, but take no note of the bit of wood which is in your eye?", "geneva": "And why seest thou the mote, that is in thy brothers eye, and perceiuest not the beame that is in thine owne eye?", "wycliffe": "But what seest thou a litil mote in the iye of thi brother, and seest not a beem in thin owne iye?", "rotherham": "Why, moreover, beholdest thou the mote, in the eye of thy brother,—while, the beam in thine own eye, thou dost not consider?", "weymouth": "And why do you look at the splinter in your brother's eye, and not notice the beam which is in your own eye?", "darby": "But why lookest thou on the mote that is in the eye of thy brother, but observest not the beam that is in thine eye?", "twenty": "And why do you look at the straw in your brother’s eye, while you pay no attention at all to the beam in yours?", "acv": "And why do thou see the speck in thy brother's eye, but do not notice the beam in thine own eye?", "anderson": "And why do you look at the splinter that is in your brother’s eye, but perceive not the beam that is in your own eye?", "haweis": "And why spiest thou out the mote which is in thy brother’s eye, yet payest no attention to the beam which is in thine own eye?", "noyes": "And why dost thou look at the mote that is in thy brother’s eye, and not perceive the beam in thine own eye?", "webster": "And why beholdest thou the mote that is in thy brother's eye, but considerest not the beam that is in thy own eye?", "vulgate": "quid autem vides festucam in oculo fratris tui et trabem in oculo tuo non vides;"}}, {"v": 4, "ref": "7:4", "o": "ἢ πῶς ἐρεῖς τῷ ἀδελφῷ σου· Ἄφες ἐκβάλω τὸ κάρφος ⸀ἐκ τοῦ ὀφθαλμοῦ σου, καὶ ἰδοὺ ἡ δοκὸς ἐν τῷ ὀφθαλμῷ σοῦ;", "en": {"kjv": "Or how wilt thou say to thy brother, Let me pull out the mote out of thine eye; and, behold, a beam is in thine own eye?", "web": "Or how will you tell your brother, ‘Let me remove the speck from your eye;’ and behold, the beam is in your own eye?", "bsb": "How can you say to your brother, ‘Let me take the speck out of your eye,’ while there is still a beam in your own eye?", "asv": "Or how wilt thou say to thy brother, Let me cast out the mote out of thine eye; and lo, the beam is in thine own eye?", "ylt": "or, how wilt thou say to thy brother, Suffer I may cast out the mote from thine eye, and lo, the beam is in thine own eye?", "tyndale": "Or why sayest thou to thy brother: suffre me to plucke oute the moote oute of thyne eye and behold a beame is in thyne awne eye.", "dra": "Or how sayest thou to thy brother: Let me cast the mote out of thy eye; and behold a beam is in thy own eye?", "bbe": "Or how will you say to your brother, Let me take out the grain of dust from your eye, when you yourself have a bit of wood in your eye?", "geneva": "Or howe sayest thou to thy brother, Suffer me to cast out the mote out of thine eye, and beholde, a beame is in thine owne eye?", "wycliffe": "Or hou seist thou to thi brothir, Brothir, suffre I schal do out a mote fro thin iye, and lo! a beem is in thin owne iye?", "rotherham": "Or how wilt thou say unto thy brother, Let me cast the mote out of thine eye,—when lo! a beam, is in thine own eye?", "weymouth": "Or how say to your brother, `Allow me to take the splinter out of your eye,' while the beam is in your own eye?", "darby": "Or how wilt thou say to thy brother, Allow [me], I will cast out the mote from thine eye; and behold, the beam is in thine eye?", "twenty": "How will you say to your brother ‘Let me take out the straw from your eye,’ when all the time there is a beam in your own?", "acv": "Or how will thou say to thy brother, Let me take out the speck from thine eye, and behold, the beam in thine own eye?", "anderson": "Or, how will you say to your brother, Let me pull out the splinter from your eye: and lo; a beam is in your own eye?", "haweis": "Or how wilt thou say to thy brother, Suffer me to take the mote off from thine eye: and behold there is a beam in thine own eye?", "noyes": "Or how wilt thou say to thy brother, Let me take the mote out of thine eye; when, lo! the beam is in thine own eye?", "webster": "Or how wilt thou say to thy brother, Let me pull out the mote out of thy eye; and behold, a beam [is] in thy own eye?", "vulgate": "aut quomodo dicis fratri tuo sine eiciam festucam de oculo tuo et ecce trabis est in oculo tuo;"}}, {"v": 5, "ref": "7:5", "o": "ὑποκριτά, ἔκβαλε πρῶτον ⸂ἐκ τοῦ ὀφθαλμοῦ σοῦ τὴν δοκόν⸃, καὶ τότε διαβλέψεις ἐκβαλεῖν τὸ κάρφος ἐκ τοῦ ὀφθαλμοῦ τοῦ ἀδελφοῦ σου.", "en": {"kjv": "Thou hypocrite, first cast out the beam out of thine own eye; and then shalt thou see clearly to cast out the mote out of thy brother’s eye.", "web": "You hypocrite! First remove the beam out of your own eye, and then you can see clearly to remove the speck out of your brother’s eye.", "bsb": "You hypocrite! First take the beam out of your own eye, and then you will see clearly to remove the speck from your brother’s eye.", "asv": "Thou hypocrite, cast out first the beam out of thine own eye; and then shalt thou see clearly to cast out the mote out of thy brother’s eye.", "ylt": "Hypocrite, cast out first the beam out of thine own eye, and then thou shalt see clearly to cast out the mote out of thy brother's eye.", "tyndale": "Ypocryte fyrst cast oute the beame oute of thyne awne eye and then shalte thou se clearly to plucke oute the moote out of thy brothers eye.", "dra": "Thou hypocrite, cast out first the beam out of thy own eye, and then shalt thou see to cast out the mote out of thy brother's eye.", "bbe": "You false one, first take out the bit of wood from your eye, then will you see clearly to take out the grain of dust from your brother's eye.", "geneva": "Hypocrite, first cast out that beame out of thine owne eye, and then shalt thou see clearely to cast out the mote out of thy brothers eye.", "wycliffe": "Ipocrite, `do thou out first the beem of thin iye, and thanne thou schalt se to do out the mote of the iye of thi brothir.", "rotherham": "Hypocrite! cast first, out of thine own eye, the beam,—and, then, shalt thou see clearly to cast the mote, out of the eye of thy brother.", "weymouth": "Hypocrite, first take the beam out of your own eye, and then you will see clearly how to remove the splinter from your brother's eye.", "darby": "Hypocrite, cast out first the beam out of thine eye, and then thou wilt see clearly to cast out the mote out of the eye of thy brother.", "twenty": "Hypocrite! Take out the beam from your own eye first, and then you will see clearly how to take out the straw from your brother’s.", "acv": "Thou hypocrite, first take out the beam from thine own eye, and then thou will see clearly to take out the speck from thy brother's eye.", "anderson": "Hypocrite! first pull the beam out of your own eye, and then you will see clearly to pull the splinter out of your brother’s eye.", "haweis": "Thou hypocrite, take first the beam out of thine own eye and then shalt thou see clearly to take off the mote from thy brother’s eye.", "noyes": "Hypocrite! first cast the beam out of thine own eye; and then wilt thou see clearly to take the mote out of thy brother’s eye.", "webster": "Thou hypocrite, first cast out the beam out of thy own eye; and then shalt thou see clearly to cast out the mote out of thy brother's eye.", "vulgate": "hypocrita eice primum trabem de oculo tuo et tunc videbis eicere festucam de oculo fratris tui;"}}, {"v": 6, "ref": "7:6", "o": "Μὴ δῶτε τὸ ἅγιον τοῖς κυσίν, μηδὲ βάλητε τοὺς μαργαρίτας ὑμῶν ἔμπροσθεν τῶν χοίρων, μήποτε ⸀καταπατήσουσιν αὐτοὺς ἐν τοῖς ποσὶν αὐτῶν καὶ στραφέντες ῥήξωσιν ὑμᾶς.", "en": {"kjv": "Give not that which is holy unto the dogs, neither cast ye your pearls before swine, lest they trample them under their feet, and turn again and rend you.", "web": "“Don’t give that which is holy to the dogs, neither throw your pearls before the pigs, lest perhaps they trample them under their feet, and turn and tear you to pieces.", "bsb": "Do not give dogs what is holy; do not throw your pearls before swine. If you do, they may trample them under their feet, and then turn and tear you to pieces.", "asv": "Give not that which is holy unto the dogs, neither cast your pearls before the swine, lest haply they trample them under their feet, and turn and rend you.", "ylt": "`Ye may not give that which is holy to the dogs, nor cast your pearls before the swine, that they may not trample them among their feet, and having turned--may rend you.", "tyndale": "Geve not that which is holy to dogges nether cast ye youre pearles before swyne lest they treade them vnder their fete and ye other tourne agayne and all to rent you.", "dra": "Give not that which is holy to dogs; neither cast ye your pearls before swine, lest perhaps they trample them under their feet, and turning upon you, they tear you.", "bbe": "Do not give that which is holy to the dogs, or put your jewels before pigs, for fear that they will be crushed under foot by the pigs whose attack will then be made against you.", "geneva": "Giue ye not that which is holy, to dogges, neither cast ye your pearles before swine, lest they treade them vnder their feete, and turning againe, all to rent you.", "wycliffe": "Nile ye yyue hooli thing to houndis, nethir caste ye youre margaritis bifore swyne, lest perauenture thei defoulen hem with her feet, and the houndis be turned, and al to-tere you.", "rotherham": "Do not give what is holy unto dogs, neither cast ye your pearls before swine,—lest once they trample, them, down with their feet, and, turning, tear, you.", "weymouth": "\"Give not that which is holy to the dogs, nor throw your pearls to the swine; otherwise they will trample them under their feet and then turn and attack you.", "darby": "Give not that which is holy to the dogs, nor cast your pearls before the swine, lest they trample them with their feet, and turning round rend you.", "twenty": "Do not give what is sacred to dogs; nor yet throw your pearls before pigs, lest they should trample them under their feet, and then turn and attack you.", "acv": "Do not give what is holy to the dogs, nor cast your pearls before the swine, lest they trample them by their feet, and having turn back may lacerate you.", "anderson": "Give not that which is holy to dogs, nor throw your pearls before swine, lest they trample them under their feet, and turn again and tear you.", "haweis": "Give not that which is holy to dogs, nor cast pearls before swine; lest they tread them under foot, and turning round tear you.", "noyes": "Give not that which is holy to dogs, neither cast ye your pearls before swine; lest they trample them under their feet, and turn upon you and rend you.", "webster": "Give not that which [is] holy to dogs, neither cast ye your pearls before swine, lest they trample them under their feet, and turn again and rend you.", "vulgate": "nolite dare sanctum canibus neque mittatis margaritas vestras ante porcos ne forte conculcent eas pedibus suis et conversi disrumpant vos;"}}, {"v": 7, "ref": "7:7", "o": "Αἰτεῖτε, καὶ δοθήσεται ὑμῖν· ζητεῖτε, καὶ εὑρήσετε· κρούετε, καὶ ἀνοιγήσεται ὑμῖν.", "en": {"kjv": "Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you:", "web": "“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you.", "bsb": "Ask, and it will be given to you; seek, and you will find; knock, and the door will be opened to you.", "asv": "Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you:", "ylt": "`Ask, and it shall be given to you; seek, and ye shall find; knock, and it shall be opened to you;", "tyndale": "Axe and it shalbe geven you. Seke and ye shall fynd. knocke and it shalbe opened vnto you.", "dra": "Ask, and it shall be given you: seek, and you shall find: knock, and it shall be opened to you.", "bbe": "Make a request, and it will be answered; what you are searching for you will get; give the sign, and the door will be open to you:", "geneva": "Aske, and it shall be giuen you: seeke, and ye shall finde: knocke, and it shall be opened vnto you.", "wycliffe": "Axe ye, and it schal be youun to you; seke ye, and ye schulen fynde; knocke ye, and it schal be openyd to you.", "rotherham": "Be asking, and it shall be given you, Be seeking, and ye shall find,—Be knocking, and it shall be opened unto you.", "weymouth": "\"Ask, and it will be given to you; seek, and you will find; knock, and the door will be opened to you.", "darby": "Ask, and it shall be given to you. Seek, and ye shall find. Knock, and it shall be opened to you.", "twenty": "Ask, and your prayer shall be granted; search, and you shall find; knock, and the door shall be opened to you.", "acv": "Ask, and it will be given you. Seek, and ye will find. Knock, and it will be opened to you.", "anderson": "Ask, and it shall be given you; seek, and you shall find; knock, and it shall be opened to you.", "haweis": "Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you:", "noyes": "Ask, and it will be given you; seek, and ye will find; knock, and the door will be opened to you.", "webster": "Ask, and it shall be given you; seek, and ye shall find; knock, and the door shall be opened to you:", "vulgate": "petite et dabitur vobis quaerite et invenietis pulsate et aperietur vobis;"}}, {"v": 8, "ref": "7:8", "o": "πᾶς γὰρ ὁ αἰτῶν λαμβάνει καὶ ὁ ζητῶν εὑρίσκει καὶ τῷ κρούοντι ⸀ἀνοιγήσεται.", "en": {"kjv": "For every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.", "web": "For everyone who asks receives. He who seeks finds. To him who knocks it will be opened.", "bsb": "For everyone who asks receives; he who seeks finds; and to him who knocks, the door will be opened.", "asv": "for every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.", "ylt": "for every one who is asking doth receive, and he who is seeking doth find, and to him who is knocking it shall be opened.", "tyndale": "For whosoever axeth receaveth and he yt seketh fyndeth and to hym that knocketh it shalbe opened.", "dra": "For every one that asketh, receiveth: and he that seeketh, findeth: and to him that knocketh, it shall be opened.", "bbe": "Because to everyone who makes a request, it will be given; and he who is searching will get his desire, and to him who gives the sign, the door will be open.", "geneva": "For whosoeuer asketh, receiueth: and he, that seeketh, findeth: and to him that knocketh, it shall be opened.", "wycliffe": "For ech that axith, takith; and he that sekith, fyndith; and it schal be openyd to hym, that knockith.", "rotherham": "For, whosoever asketh, receiveth, and, he that seeketh, findeth,—and, to him that knocketh, shall it be opened.", "weymouth": "For it is always he who asks that receives, he who seeks that finds, and he who knocks that has the door opened to him.", "darby": "For every one that asks receives; and he that seeks finds; and to him that knocks it shall be opened.", "twenty": "For he that asks receives, he that searches finds, and to him that knocks the door shall be opened.", "acv": "For every man who asks receives, and he who seeks finds, and to him who knocks it will be opened.", "anderson": "For every one that asks, receives; and he that seeks, finds; and to him that knocks, it shall be opened.", "haweis": "for every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.", "noyes": "For every one that asketh, receiveth; and he that seeketh, findeth; and to him that knocketh, the door will be opened.", "webster": "For every one that asketh, receiveth; and he that seeketh, findeth; and to him that knocketh, the door shall be opened.", "vulgate": "omnis enim qui petit accipit et qui quaerit invenit et pulsanti aperietur;"}}, {"v": 9, "ref": "7:9", "o": "ἢ τίς ⸀ἐστιν ἐξ ὑμῶν ἄνθρωπος, ὃν ⸀αἰτήσει ὁ υἱὸς αὐτοῦ ἄρτον— μὴ λίθον ἐπιδώσει αὐτῷ;", "en": {"kjv": "Or what man is there of you, whom if his son ask bread, will he give him a stone?", "web": "Or who is there among you, who, if his son asks him for bread, will give him a stone?", "bsb": "Which of you, if his son asks for bread, will give him a stone?", "asv": "Or what man is there of you, who, if his son shall ask him for a loaf, will give him a stone;", "ylt": "`Or what man is of you, of whom, if his son may ask a loaf--a stone will he present to him?", "tyndale": "Ys there eny man amoge you which if his sonne axed hym bread wolde offer him astone?", "dra": "Or what man is there among you, of whom if his son shall ask bread, will he reach him a stone?", "bbe": "Or which of you, if his son makes a request for bread, will give him a stone?", "geneva": "For what man is there among you, which if his sonne aske him bread, woulde giue him a stone?", "wycliffe": "What man of you is, that if his sone axe hym breed, whethir he wole take hym a stoon?", "rotherham": "Or what man, from among yourselves, whom his son shall ask for a loaf,—a stone, will give him?", "weymouth": "What man is there among you, who if his son shall ask him for bread will offer him a stone?", "darby": "Or what man is there of you who, if his son shall ask of him a loaf of bread, will give him a stone;", "twenty": "Who among you, when his son asks him for a loaf, will give him a stone,", "acv": "Or what man is there of you, who, if his son may ask for bread, will give him a stone,", "anderson": "What man is there of you, of whom if his son ask bread, will he give him a stone?", "haweis": "What man is there of you, of whom if his son ask a loaf, will he give him a stone?", "noyes": "Or what man is there of you, who, if his son ask for bread, will give him a stone?", "webster": "Or what man is there of you, who, if his son shall ask bread, will give him a stone?", "vulgate": "aut quis est ex vobis homo quem si petierit filius suus panem numquid lapidem porriget ei;"}}, {"v": 10, "ref": "7:10", "o": "⸀ἢ καὶ ⸂ἰχθὺν αἰτήσει⸃— μὴ ὄφιν ἐπιδώσει αὐτῷ;", "en": {"kjv": "Or if he ask a fish, will he give him a serpent?", "web": "Or if he asks for a fish, who will give him a serpent?", "bsb": "Or if he asks for a fish, will give him a snake?", "asv": "or if he shall ask for a fish, will give him a serpent?", "ylt": "and if a fish he may ask--a serpent will he present to him?", "tyndale": "Or if he axed fysshe wolde he proffer hym a serpet?", "dra": "Or if he shall ask him a fish, will he reach him a serpent?", "bbe": "Or if he makes a request for a fish, will give him a snake?", "geneva": "Or if he aske fish, wil he giue him a serpent?", "wycliffe": "Or if he axe fische, whether he wole take hym an edder?", "rotherham": "Or, a fish also, shall ask,—a serpent, will give him?", "weymouth": "Or if the son shall ask him for a fish will offer him a snake?", "darby": "and if he ask a fish, will give him a serpent?", "twenty": "or when he asks for a fish, will give him a snake?", "acv": "and if he may ask for a fish, will give him a serpent?", "anderson": "And if he ask a fish, will he give him a serpent?", "haweis": "or if he ask a fish, will he give him a serpent?", "noyes": "or, if he ask for a fish, will give him a serpent?", "webster": "Or if he shall ask a fish, will he give him a serpent?", "vulgate": "aut si piscem petet numquid serpentem porriget ei;"}}, {"v": 11, "ref": "7:11", "o": "εἰ οὖν ὑμεῖς πονηροὶ ὄντες οἴδατε δόματα ἀγαθὰ διδόναι τοῖς τέκνοις ὑμῶν, πόσῳ μᾶλλον ὁ πατὴρ ὑμῶν ὁ ἐν τοῖς οὐρανοῖς δώσει ἀγαθὰ τοῖς αἰτοῦσιν αὐτόν.", "en": {"kjv": "If ye then, being evil, know how to give good gifts unto your children, how much more shall your Father which is in heaven give good things to them that ask him?", "web": "If you then, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him!", "bsb": "So if you who are evil know how to give good gifts to your children, how much more will your Father in heaven give good things to those who ask Him!", "asv": "If ye then, being evil, know how to give good gifts unto your children, how much more shall your Father who is in heaven give good things to them that ask him?", "ylt": "if, therefore, ye being evil, have known good gifts to give to your children, how much more shall your Father who is in the heavens give good things to those asking him?", "tyndale": "Yf ye then which are evyll cane geve to youre chyldren good gyftes: how moche moore shall youre father which is in heve geve good thynges to them yt axe hym?", "dra": "If you then being evil, know how to give good gifts to your children: how much more will your Father who is in heaven, give good things to them that ask him?", "bbe": "If you, then, being evil, are able to give good things to your children, how much more will your Father in heaven give good things to those who make requests to him?", "geneva": "If ye then, which are euill, can giue to your children good giftes, howe much more shall your Father which is in heauen, giue good thinges to them that aske him?", "wycliffe": "Therfor if ye, whanne ye ben yuele men, kunnen yyue good yiftis to youre sones, hou myche more youre fadir that is in heuenes schal yyue good thingis to men that axen hym?", "rotherham": "If then, ye, being, evil, know how, good gifts, to be giving unto your children, how much more, will, your Father who is in the heavens, give good things to them that ask, him?", "weymouth": "If you then, imperfect as you are, know how to give good gifts to your children, how much more will your Father in Heaven give good things to those who ask Him!", "darby": "If therefore ye, being wicked, know [how] to give good gifts to your children, how much rather shall your Father who is in the heavens give good things to them that ask of him?", "twenty": "If you, then, wicked though you are, know how to give good gifts to your children, how much more will your Father who is in Heaven give what is good to those that ask him!", "acv": "If ye therefore, being evil, know to give good gifts to your children, how much more your Father in the heavens will give good things to those who ask him?", "anderson": "If then you, being evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to those who ask him?", "haweis": "If ye then, evil as ye are, know how to bestow good gifts on your children; how much more will your Father who is in heaven, bestow good things on those who ask him?", "noyes": "If ye then, though evil, know how to give good gifts to your children, how much more will your Father who is in heaven give good things to them that ask him!", "webster": "If ye then being evil know [how] to give good gifts to your children, how much more shall your Father who is in heaven give good things to them that ask him?", "vulgate": "si ergo vos cum sitis mali nostis bona dare filiis vestris quanto magis Pater vester qui in caelis est dabit bona petentibus se;"}}, {"v": 12, "ref": "7:12", "o": "Πάντα οὖν ὅσα ⸀ἐὰν θέλητε ἵνα ποιῶσιν ὑμῖν οἱ ἄνθρωποι, οὕτως καὶ ὑμεῖς ποιεῖτε αὐτοῖς· οὗτος γάρ ἐστιν ὁ νόμος καὶ οἱ προφῆται.", "en": {"kjv": "Therefore all things whatsoever ye would that men should do to you, do ye even so to them: for this is the law and the prophets.", "web": "Therefore whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets.", "bsb": "In everything, then, do to others as you would have them do to you. For this is the essence of the Law and the Prophets.", "asv": "All things therefore whatsoever ye would that men should do unto you, even so do ye also unto them: for this is the law and the prophets.", "ylt": "`All things, therefore, whatever ye may will that men may be doing to you, so also do to them, for this is the law and the prophets.", "tyndale": "Therfore whatsoever ye wolde that men shulde do to you even so do ye to them. This ys the lawe and the Prophettes.", "dra": "All things therefore whatsoever you would that men should do to you, do you also to them. For this is the law and the prophets.", "bbe": "All those things, then, which you would have men do to you, even so do you to them: because this is the law and the prophets.", "geneva": "Therefore whatsoeuer ye woulde that men should doe to you, euen so doe ye to them: for this is the Lawe and the Prophets.", "wycliffe": "Therfor alle thingis, what euere thingis ye wolen that men do to you, do ye to hem, for this is the lawe and the prophetis.", "rotherham": "Whatsoever things, therefore, ye would, that men be doing unto you, so, be, ye also, doing, unto them,—for, this, is the law and the prophets.", "weymouth": "Everything, therefore, be it what it may, that you would have men do to you, do you also the same to them; for in this the Law and the Prophets are summed up.", "darby": "Therefore all things whatever ye desire that men should do to you, thus do ye also do to them; for this is the law and the prophets.", "twenty": "Do to others whatever you would wish them to do to you; for that is the teaching of both the Law and the Prophets.", "acv": "All things therefore, as many as ye may want that men should do to you, so also do ye to them, for this is the law and the prophets.", "anderson": "All things, therefore, whatever you would that men should do to you, even so do you to them: for this is the law and the prophets.", "haweis": "All things therefore whatsoever ye would be willing that men should do to you, just so do ye to them: for this is the law and the prophets.", "noyes": "All things, then, whatever ye would that men should do to you, do ye also so to them; for this is the Law and the Prophets.", "webster": "Therefore all things whatever ye would that men should do to you, do ye even so to them: for this is the law and the prophets.", "vulgate": "omnia ergo quaecumque vultis ut faciant vobis homines et vos facite eis haec est enim lex et prophetae;"}}, {"v": 13, "ref": "7:13", "o": "Εἰσέλθατε διὰ τῆς στενῆς πύλης· ὅτι πλατεῖα ⸂ἡ πύλη⸃ καὶ εὐρύχωρος ἡ ὁδὸς ἡ ἀπάγουσα εἰς τὴν ἀπώλειαν, καὶ πολλοί εἰσιν οἱ εἰσερχόμενοι δι’ αὐτῆς·", "en": {"kjv": "Enter ye in at the strait gate: for wide is the gate, and broad is the way, that leadeth to destruction, and many there be which go in thereat:", "web": "“Enter in by the narrow gate; for wide is the gate and broad is the way that leads to destruction, and many are those who enter in by it.", "bsb": "Enter through the narrow gate. For wide is the gate and broad is the way that leads to destruction, and many enter through it.", "asv": "Enter ye in by the narrow gate: for wide is the gate, and broad is the way, that leadeth to destruction, and many are they that enter in thereby.", "ylt": "`Go ye in through the strait gate, because wide is the gate, and broad the way that is leading to the destruction, and many are those going in through it;", "tyndale": "Enter in at the strayte gate: for wyde is ye gate and broade is the waye that leadeth to destruccion: and many ther be which goo yn therat.", "dra": "Enter ye in at the narrow gate: for wide is the gate, and broad is the way that leadeth to destruction, and many there are who go in thereat.", "bbe": "Go in by the narrow door; for wide is the door and open is the way which goes to destruction, and great numbers go in by it.", "geneva": "Enter in at the streight gate: for it is the wide gate, and broade way that leadeth to destruction: and many there be which goe in thereat,", "wycliffe": "Entre ye bi the streyt yate; for the yate that ledith to perdicioun is large, and the weie is broode, and there ben many that entren bi it.", "rotherham": "Enter ye in at, the narrow gate; because broad and roomy is the way that leadeth unto destruction,—and, many, are they who enter thereby:", "weymouth": "\"Enter by the narrow gate; for wide is the gate and broad the road which leads to ruin, and many there are who enter by it;", "darby": "Enter in through the narrow gate, for wide the gate and broad the way that leads to destruction, and many are they who enter in through it.", "twenty": "Go in by the small gate. Broad and spacious is the road that leads to destruction, and those that go in by it are many;", "acv": "Enter ye in by the narrow gate, because wide is the gate, and broad is the way, that leads to destruction, and many are they who enter through it.", "anderson": "Enter in through the strait gate: for wide is the gate, and broad is the way, that leads to destruction; and many there are that go in through it.", "haweis": "Enter in through the strait gate: for wide is the gate, and spacious the road, which leadeth to perdition, and they are many who enter that way:", "noyes": "Enter in at the strait gate; for wide is the gate, and broad is the way, that leadeth to destruction; and many are they who go in thereat.", "webster": "Enter ye in at the strait gate; for wide [is] the gate, and broad [is] the way, that leadeth to destruction, and many there are who go in by it.", "vulgate": "intrate per angustam portam quia lata porta et spatiosa via quae ducit ad perditionem et multi sunt qui intrant per eam;"}}, {"v": 14, "ref": "7:14", "o": "⸀ὅτι στενὴ ἡ πύλη καὶ τεθλιμμένη ἡ ὁδὸς ἡ ἀπάγουσα εἰς τὴν ζωήν, καὶ ὀλίγοι εἰσὶν οἱ εὑρίσκοντες αὐτήν.", "en": {"kjv": "Because strait is the gate, and narrow is the way, which leadeth unto life, and few there be that find it.", "web": "Hownarrow is the gate, and restricted is the way that leads to life! Few are those who find it.", "bsb": "But small is the gate and narrow the way that leads to life, and only a few find it.", "asv": "For narrow is the gate, and straitened the way, that leadeth unto life, and few are they that find it.", "ylt": "how strait is the gate, and compressed the way that is leading to the life, and few are those finding it!", "tyndale": "But strayte is the gate and narowe ys the waye which leadeth vnto lyfe: and feawe there be that fynde it.", "dra": "How narrow is the gate, and strait is the way that leadeth to life: and few there are that find it!", "bbe": "For narrow is the door and hard the road to life, and only a small number make discovery of it.", "geneva": "Because the gate is streight, and the way narowe that leadeth vnto life, and fewe there be that finde it.", "wycliffe": "Hou streit is the yate, and narwy the weye, that ledith to lijf, and ther ben fewe that fynden it.", "rotherham": "Because, narrow, is the gate, and, confined, the way, that leadeth unto life,—and, few, are they who find, it.", "weymouth": "because narrow is the gate and contracted the road which leads to Life, and few are those who find it.", "darby": "For narrow the gate and straitened the way that leads to life, and they are few who find it.", "twenty": "for small is the gate, and narrow the road, that leads to Life, and those that find it are few.", "acv": "How narrow is the gate, and restricted the way, that leads to life, and few are those who find it.", "anderson": "How strait is the gate, and how narrow the way, that leads to life! and few there are that find it.", "haweis": "because strait is the gate, and narrow the road, which leadeth to life, and they are but a few who find it.", "noyes": "For strait is the gate, and narrow the way, that leadeth to life; and few are they who find it.", "webster": "Because strait [is] the gate, and narrow [is] the way, which leadeth to life, and few there are that find it.", "vulgate": "quam angusta porta et arta via quae ducit ad vitam et pauci sunt qui inveniunt eam;"}}, {"v": 15, "ref": "7:15", "o": "⸀Προσέχετε ἀπὸ τῶν ψευδοπροφητῶν, οἵτινες ἔρχονται πρὸς ὑμᾶς ἐν ἐνδύμασι προβάτων ἔσωθεν δέ εἰσιν λύκοι ἅρπαγες.", "en": {"kjv": "Beware of false prophets, which come to you in sheep’s clothing, but inwardly they are ravening wolves.", "web": "“Beware of false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves.", "bsb": "Beware of false prophets. They come to you in sheep’s clothing, but inwardly they are ravenous wolves.", "asv": "Beware of false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves.", "ylt": "`But, take heed of the false prophets, who come unto you in sheep's clothing, and inwardly are ravening wolves.", "tyndale": "Beware of false Prophetes which come to you in shepes clothinge but inwardly they are ravenynge wolves.", "dra": "Beware of false prophets, who come to you in the clothing of sheep, but inwardly they are ravening wolves.", "bbe": "Be on the watch for false prophets, who come to you in sheep's clothing, but inside they are cruel wolves.", "geneva": "Beware of false prophets, which come to you, in sheepes clothing, but inwardly they are rauening wolues.", "wycliffe": "Be ye war of fals prophetis, that comen to you in clothingis of scheep, but withynneforth thei ben as wolues of raueyn;", "rotherham": "Beware of false prophets, who come unto you in clothing of sheep,—while, within, they are ravening wolves.", "weymouth": "\"Beware of the false teachers--men who come to you in sheep's fleeces, but beneath that disguise they are ravenous wolves.", "darby": "But beware of false prophets, which come to you in sheep's clothing, but within are ravening wolves.", "twenty": "Beware of false Teachers — men who come to you in the guise of sheep, but at heart they are ravenous wolves.", "acv": "But beware of false prophets, who come to you in sheep's clothing, but inwardly are predatory wolves.", "anderson": "But beware of false prophets, who come to you in sheep’s clothing, but within are ravenous wolves.", "haweis": "Take heed then of false prophets, who come to you in the garb of sheep, but inwardly they are ravening wolves.", "noyes": "Beware of the false prophets, who come to you in sheep’s clothing, but inwardly are ravening wolves.", "webster": "Beware of false prophets, who come to you in sheep's clothing, but inwardly they are ravening wolves.", "vulgate": "adtendite a falsis prophetis qui veniunt ad vos in vestimentis ovium intrinsecus autem sunt lupi rapaces;"}}, {"v": 16, "ref": "7:16", "o": "ἀπὸ τῶν καρπῶν αὐτῶν ἐπιγνώσεσθε αὐτούς. μήτι συλλέγουσιν ἀπὸ ἀκανθῶν ⸀σταφυλὰς ἢ ἀπὸ τριβόλων σῦκα;", "en": {"kjv": "Ye shall know them by their fruits. Do men gather grapes of thorns, or figs of thistles?", "web": "By their fruits you will know them. Do you gather grapes from thorns, or figs from thistles?", "bsb": "By their fruit you will recognize them. Are grapes gathered from thornbushes, or figs from thistles?", "asv": "By their fruits ye shall know them. Do men gather grapes of thorns, or figs of thistles?", "ylt": "From their fruits ye shall know them; do men gather from thorns grapes? or from thistles figs?", "tyndale": "Ye shall knowe them by their frutes. Do men gaddre grapes of thornes? or figges of bryres?", "dra": "By their fruits you shall know them. Do men gather grapes of thorns, or figs of thistles?", "bbe": "By their fruits you will get knowledge of them. Do men get grapes from thorns or figs from thistles?", "geneva": "Ye shall know them by their fruites. Doe men gather grapes of thornes? or figges of thistles?", "wycliffe": "of her fruytis ye schulen knowe hem. Whether men gaderen grapis of thornes, or figus of breris?", "rotherham": "By their fruits, shall ye find, them, out,—unless perhaps men gather—from thorns, grapes! or, from thistles, figs!", "weymouth": "By their fruits you will easily recognize them. Are grapes gathered from thorns or figs from brambles?", "darby": "By their fruits ye shall know them. Do [men] gather a bunch of grapes from thorns, or from thistles figs?", "twenty": "By the fruit of their lives you will know them. Do people gather grapes from thorn bushes, or figs from thistles?", "acv": "From their fruits ye will know them. Do they gather grapes from thorns, or figs from thistles?", "anderson": "By their fruits you will know them. Are grapes gathered from thorns, or figs from thistles?", "haweis": "By their fruits ye shall know them. Do men gather a bunch of grapes from thorns, or figs from thistles?", "noyes": "Ye may know them by their fruits. Do men gather grapes of thorns, or figs of thistles?", "webster": "Ye shall know them by their fruits: Do men gather grapes from thorns, or figs from thistles:", "vulgate": "a fructibus eorum cognoscetis eos numquid colligunt de spinis uvas aut de tribulis ficus;"}}, {"v": 17, "ref": "7:17", "o": "οὕτως πᾶν δένδρον ἀγαθὸν καρποὺς καλοὺς ποιεῖ, τὸ δὲ σαπρὸν δένδρον καρποὺς πονηροὺς ποιεῖ·", "en": {"kjv": "Even so every good tree bringeth forth good fruit; but a corrupt tree bringeth forth evil fruit.", "web": "Even so, every good tree produces good fruit; but the corrupt tree produces evil fruit.", "bsb": "Likewise, every good tree bears good fruit, but a bad tree bears bad fruit.", "asv": "Even so every good tree bringeth forth good fruit; but the corrupt tree bringeth forth evil fruit.", "ylt": "so every good tree doth yield good fruits, but the bad tree doth yield evil fruits.", "tyndale": "Euen soo every good tree bryngeth forthe good frute. But a corrupte tree bryngethe forthe evyll frute.", "dra": "Even so every good tree bringeth forth good fruit, and the evil tree bringeth forth evil fruit.", "bbe": "Even so, every good tree gives good fruit; but the bad tree gives evil fruit.", "geneva": "So euery good tree bringeth foorth good fruite, and a corrupt tree bringeth forth euill fruite.", "wycliffe": "So euery good tre makith good fruytis; but an yuel tre makith yuel fruytis.", "rotherham": "So, every good tree, fine fruit, produceth,—whereas, the worthless tree, evil fruit, produceth:", "weymouth": "Just so every good tree produces good fruit, but a poisonous tree produces bad fruit.", "darby": "So every good tree produces good fruits, but the worthless tree produces bad fruits.", "twenty": "So, too, every sound tree bears good fruit, while a worthless tree bears bad fruit.", "acv": "Likewise every good tree produces good fruits, but the corrupt tree produces bad fruits.", "anderson": "So every good tree produces goodly fruit: but an unsound tree produces diseased fruit.", "haweis": "So every good tree beareth good fruits; but every bad tree in kind, produceth bad fruits.", "noyes": "So every good tree beareth good fruit; but a bad tree beareth bad fruit.", "webster": "Even so every good tree bringeth forth good fruit; but a corrupt tree bringeth forth evil fruit.", "vulgate": "sic omnis arbor bona fructus bonos facit mala autem arbor fructus malos facit;"}}, {"v": 18, "ref": "7:18", "o": "οὐ δύναται δένδρον ἀγαθὸν καρποὺς πονηροὺς ⸀ποιεῖν, οὐδὲ δένδρον σαπρὸν καρποὺς καλοὺς ποιεῖν.", "en": {"kjv": "A good tree cannot bring forth evil fruit, neither can a corrupt tree bring forth good fruit.", "web": "A good tree can’t produce evil fruit, neither can a corrupt tree produce good fruit.", "bsb": "A good tree cannot bear bad fruit, and a bad tree cannot bear good fruit.", "asv": "A good tree cannot bring forth evil fruit, neither can a corrupt tree bring forth good fruit.", "ylt": "A good tree is not able to yield evil fruits, nor a bad tree to yield good fruits.", "tyndale": "A good tree canot brynge forthe bad frute: nor yet a bad tree can bringe forthe good frute.", "dra": "A good tree cannot bring forth evil fruit, neither can an evil tree bring forth good fruit.", "bbe": "It is not possible for a good tree to give bad fruit, and a bad tree will not give good fruit.", "geneva": "A good tree can not bring forth euil fruite: neither can a corrupt tree bring forth good fruite.", "wycliffe": "A good tre may not make yuel fruytis, nethir an yuel tre make good fruytis.", "rotherham": "It is, impossible, for a, good tree, to be bearing, evil fruit, neither doth, a worthless tree, produce, fine fruit.", "weymouth": "A good tree cannot bear bad fruit, nor a poisonous tree good fruit.", "darby": "A good tree cannot produce bad fruits, nor a worthless tree produce good fruits.", "twenty": "A sound tree cannot produce bad fruit, nor can a worthless tree bear good fruit.", "acv": "A good tree cannot produce bad fruits, nor a corrupt tree produce good fruits.", "anderson": "A good tree can not produce diseased fruit; nor can an unsound tree produce goodly fruit.", "haweis": "A good tree cannot produce bad fruits, neither can a tree bad in kind produce good fruits.", "noyes": "A good tree cannot bear bad fruit, nor call a bad tree bear good fruit.", "webster": "A good tree cannot bring forth evil fruit, neither [can] a corrupt tree bring forth good fruit.", "vulgate": "non potest arbor bona fructus malos facere neque arbor mala fructus bonos facere;"}}, {"v": 19, "ref": "7:19", "o": "πᾶν δένδρον μὴ ποιοῦν καρπὸν καλὸν ἐκκόπτεται καὶ εἰς πῦρ βάλλεται.", "en": {"kjv": "Every tree that bringeth not forth good fruit is hewn down, and cast into the fire.", "web": "Every tree that doesn’t grow good fruit is cut down, and thrown into the fire.", "bsb": "Every tree that does not bear good fruit is cut down and thrown into the fire.", "asv": "Every tree that bringeth not forth good fruit is hewn down, and cast into the fire.", "ylt": "Every tree not yielding good fruit is cut down and is cast to fire:", "tyndale": "Every tree that bryngethe not forthe good frute shalbe hewe doune and cast into the fyre.", "dra": "Every tree that bringeth not forth good fruit, shall be cut down, and shall be cast into the fire.", "bbe": "Every tree which does not give good fruit is cut down and put in the fire.", "geneva": "Euery tree that bringeth not forth good fruite, is hewen downe, and cast into the fire.", "wycliffe": "Euery tre that makith not good fruyt, schal be kyt doun, and schal be cast in to the fier.", "rotherham": "Every tree that beareth not fine fruit, is hewn down, and, into fire, is cast.", "weymouth": "Every tree which does not yield good fruit is cut down and thrown aside for burning.", "darby": "Every tree not producing good fruit is cut down and cast into the fire.", "twenty": "Every tree that fails to bear good fruit is cut down and thrown into the fire.", "acv": "Every tree not producing good fruit is cut down, and thrown into the fire.", "anderson": "Every tree that does not produce goodly fruit, is cut down and thrown into the fire.", "haweis": "Every tree that beareth not good fruit, is cut down, and cast into the fire.", "noyes": "Every tree that beareth not good fruit is cut down, and cast into the fire.", "webster": "Every tree that bringeth not forth good fruit is hewn down, and cast into the fire.", "vulgate": "omnis arbor quae non facit fructum bonum exciditur et in ignem mittitur;"}}, {"v": 20, "ref": "7:20", "o": "ἄρα γε ἀπὸ τῶν καρπῶν αὐτῶν ἐπιγνώσεσθε αὐτούς.", "en": {"kjv": "Wherefore by their fruits ye shall know them.", "web": "Therefore by their fruits you will know them.", "bsb": "So then, by their fruit you will recognize them.", "asv": "Therefore by their fruits ye shall know them.", "ylt": "therefore from their fruits ye shall know them.", "tyndale": "Wherfore by their frutes ye shall knowe the.", "dra": "Wherefore by their fruits you shall know them.", "bbe": "So by their fruits you will get knowledge of them.", "geneva": "Therefore by their fruites ye shall knowe them.", "wycliffe": "Therfor of her fruytis ye schulen knowe hem.", "rotherham": "After all then, by their fruits, shall ye find, them, out.", "weymouth": "So by their fruits at any rate, you will easily recognize them.", "darby": "By their fruits then surely ye shall know them.", "twenty": "Hence it is by the fruit of their lives that you will know such men.", "acv": "So then from their fruits ye will know them.", "anderson": "Therefore, by their fruits you shall know them.", "haweis": "Well then! by their fruits ye shall know them.", "noyes": "So then ye may know them by their fruits.", "webster": "Wherefore by their fruits ye shall know them,", "vulgate": "igitur ex fructibus eorum cognoscetis eos;"}}, {"v": 21, "ref": "7:21", "o": "Οὐ πᾶς ὁ λέγων μοι· Κύριε κύριε εἰσελεύσεται εἰς τὴν βασιλείαν τῶν οὐρανῶν, ἀλλ’ ὁ ποιῶν τὸ θέλημα τοῦ πατρός μου τοῦ ἐν ⸀τοῖς οὐρανοῖς.", "en": {"kjv": "Not every one that saith unto me, Lord, Lord, shall enter into the kingdom of heaven; but he that doeth the will of my Father which is in heaven.", "web": "Not everyone who says to me, ‘Lord, Lord,’ will enter into the Kingdom of Heaven; but he who does the will of my Father who is in heaven.", "bsb": "Not everyone who says to Me, ‘Lord, Lord,’ will enter the kingdom of heaven, but only he who does the will of My Father in heaven.", "asv": "Not every one that saith unto me, Lord, Lord, shall enter into the kingdom of heaven; but he that doeth the will of my Father who is in heaven.", "ylt": "`Not every one who is saying to me Lord, lord, shall come into the reign of the heavens; but he who is doing the will of my Father who is in the heavens.", "tyndale": "Not all they that saye vnto me Master Master shall enter in to the kyngdome of heven: but he that dothe my fathers will which ys in heven.", "dra": "Not every one that saith to me, Lord, Lord, shall enter into the kingdom of heaven: but he that doth the will of my Father who is in heaven, he shall enter into the kingdom of heaven.", "bbe": "Not everyone who says to me, Lord, Lord, will go into the kingdom of heaven; but he who does the pleasure of my Father in heaven.", "geneva": "Not euery one that sayeth vnto me, Lord, Lord, shall enter into the kingdome of heauen, but he that doeth my Fathers will which is in heauen.", "wycliffe": "Not ech man that seith to me, Lord, Lord, schal entre in to the kyngdom of heuenes; but he that doith the wille of my fadir that is in heuenes, he schal entre in to the kyngdoom of heuenes.", "rotherham": "Not every one that saith unto me, Lord! Lord! shall enter into the kingdom of the heavens,—but he that doeth the will of my Father who is in the heavens.", "weymouth": "\"Not every one who says to me, `Master, Master,' will enter the Kingdom of the Heavens, but only those who are obedient to my Father who is in Heaven.", "darby": "Not every one who says to me, Lord, Lord, shall enter into the kingdom of the heavens, but he that does the will of my Father who is in the heavens.", "twenty": "Not every one who says to me ‘Master! Master!’ will enter the Kingdom of Heaven, but only he who does the will of my Father who is in Heaven.", "acv": "Not every man who says to me, Lord, Lord, will enter into the kingdom of the heavens, but he who does the will of my Father in the heavens.", "anderson": "Not every one that says to me, Lord, Lord, shall enter into the kingdom of heaven; but he that does the will of my Father who is in heaven.", "haweis": "Not every one who saith to me, Lord, Lord! shall enter into the kingdom of heaven; but he that doeth the will of my Father who is in heaven.", "noyes": "Not every one that saith to me, Lord, Lord, will enter into the kingdom of heaven; but he that doeth the will of my Father who is in heaven.", "webster": "Not every one that saith to me, Lord, Lord, shall enter into the kingdom of heaven; but he that doeth the will of my Father who is in heaven.", "vulgate": "non omnis qui dicit mihi Domine Domine intrabit in regnum caelorum sed qui facit voluntatem Patris mei qui in caelis est ipse intrabit in regnum caelorum;"}}, {"v": 22, "ref": "7:22", "o": "πολλοὶ ἐροῦσίν μοι ἐν ἐκείνῃ τῇ ἡμέρᾳ· Κύριε κύριε, οὐ τῷ σῷ ὀνόματι ἐπροφητεύσαμεν, καὶ τῷ σῷ ὀνόματι δαιμόνια ἐξεβάλομεν, καὶ τῷ σῷ ὀνόματι δυνάμεις πολλὰς ἐποιήσαμεν;", "en": {"kjv": "Many will say to me in that day, Lord, Lord, have we not prophesied in thy name? and in thy name have cast out devils? and in thy name done many wonderful works?", "web": "Many will tell me in that day, ‘Lord, Lord, didn’t we prophesy in your name, in your name cast out demons, and in your name do many mighty works?’", "bsb": "Many will say to Me on that day, ‘Lord, Lord, did we not prophesy in Your name, and in Your name drive out demons and perform many miracles?’", "asv": "Many will say to me in that day, Lord, Lord, did we not prophesy by thy name, and by thy name cast out demons, and by thy name do many mighty works?", "ylt": "Many will say to me in that day, Lord, lord, have we not in thy name prophesied? and in thy name cast out demons? and in thy name done many mighty things?", "tyndale": "Many will saye to me in that daye Master master have we not in thy name prophesied? And in thy name have caste oute devyls? And in thy name have done many miracles?", "dra": "Many will say to me in that day: Lord, Lord, have not we prophesied in thy name, and cast out devils in thy name, and done many miracles in thy name?", "bbe": "A great number will say to me on that day, Lord, Lord, were we not prophets in your name, and did we not by your name send out evil spirits, and by your name do works of power?", "geneva": "Many will say to me in that day, Lord, Lord, haue we not by thy Name prophecied? and by thy name cast out deuils? and by thy name done many great workes?", "wycliffe": "Many schulen seie to me in that dai, Lord, Lord, whether we han not prophesied in thi name, and han caste out feendis in thi name, and han doon many vertues in thi name?", "rotherham": "Many, will say unto me, in, that, day, Lord! Lord! did we not, in thy name, prophesy, and, in thy name, cast, demons, out,—and, in thy name, many works of power, perform?", "weymouth": "Many will say to me on that day, \"`Master, Master, have we not prophesied in Thy name, and in Thy name expelled demons, and in Thy name performed many mighty works?'", "darby": "Many shall say to me in that day, Lord, Lord, have we not prophesied through thy name, and through thy name cast out demons, and through thy name done many works of power?", "twenty": "On ‘That Day’ many will say to me ‘Master, Master, was not it in your name that we taught, and in your name that we drove out demons, and in your name that we did many miracles?’", "acv": "Many will say to me in that day, Lord, Lord, did we not prophesy by thy name, and by thy name cast out demons, and by thy name do many mighty works?", "anderson": "Many will say to me in that day, Lord, Lord, have we not prophesied in thy name, and in thy name cast out demons, and in thy name done many mighty works?", "haweis": "Many will say unto me in that day, Lord, Lord, have we not prophesied in thy name? and in thy name have we not cast out devils? and in thy name done many miracles?", "noyes": "Many will say to me in that day, Lord, Lord, did we not prophesy in thy name, and in thy name cast out demons, and in thy name work many miracles?", "webster": "Many will say to me in that day, Lord, Lord, have we not prophesied in thy name? and in thy name have cast out demons? and in thy name done many wonderful works?", "vulgate": "multi dicent mihi in illa die Domine Domine nonne in nomine tuo prophetavimus et in tuo nomine daemonia eiecimus et in tuo nomine virtutes multas fecimus;"}}, {"v": 23, "ref": "7:23", "o": "καὶ τότε ὁμολογήσω αὐτοῖς ὅτι Οὐδέποτε ἔγνων ὑμᾶς· ἀποχωρεῖτε ἀπ’ ἐμοῦ οἱ ἐργαζόμενοι τὴν ἀνομίαν.", "en": {"kjv": "And then will I profess unto them, I never knew you: depart from me, ye that work iniquity.", "web": "Then I will tell them, ‘I never knew you. Depart from me, you who work iniquity.’", "bsb": "Then I will tell them plainly, ‘I never knew you; depart from Me, you workers of lawlessness!’", "asv": "And then will I profess unto them, I never knew you: depart from me, ye that work iniquity.", "ylt": "and then I will acknowledge to them, that--I never knew you, depart from me ye who are working lawlessness.", "tyndale": "And then will I knowlege vnto them that I never knewe them. Departe from me ye workers of iniquite.", "dra": "And then will I profess unto them, I never knew you: depart from me, you that work iniquity.", "bbe": "And then will I say to them, I never had knowledge of you: go from me, you workers of evil.", "geneva": "And then will I professe to them, I neuer knewe you: depart from me, ye that worke iniquitie.", "wycliffe": "And thanne Y schal knouleche to hem, That Y knewe you neuere; departe awei fro me, ye that worchen wickidnesse.", "rotherham": "And, then, will I confess unto them, Never, have I acknowledged you,—Depart from me, ye workers of lawlessness!", "weymouth": "\"And then I will tell them plainly, \"`I never knew you: begone from me, you doers of wickedness.'", "darby": "and then will I avow unto them, I never knew you. Depart from me, workers of lawlessness.", "twenty": "And then I shall say to them plainly ‘I never knew you. Go from my presence, you who live in sin.’", "acv": "And then I will profess to them, I never acknowledged you. Depart from me, ye who work lawlessness.", "anderson": "And then will I profess to them, I never knew you: depart from me, you that work iniquity.", "haweis": "And then will I profess unto them, that I never knew you: depart from me, ye workers of iniquity.", "noyes": "And then will I declare to them, I never knew you: depart from me, ye that work iniquity.", "webster": "And then will I profess to them, I never knew you: depart from me, ye that work iniquity.", "vulgate": "et tunc confitebor illis quia numquam novi vos discedite a me qui operamini iniquitatem;"}}, {"v": 24, "ref": "7:24", "o": "Πᾶς οὖν ὅστις ἀκούει μου τοὺς λόγους τούτους καὶ ποιεῖ αὐτούς, ⸀ὁμοιωθήσεται ἀνδρὶ φρονίμῳ, ὅστις ᾠκοδόμησεν ⸂αὐτοῦ τὴν οἰκίαν⸃ ἐπὶ τὴν πέτραν.", "en": {"kjv": "Therefore whosoever heareth these sayings of mine, and doeth them, I will liken him unto a wise man, which built his house upon a rock:", "web": "“Everyone therefore who hears these words of mine, and does them, I will liken him to a wise man, who built his house on a rock.", "bsb": "Therefore everyone who hears these words of Mine and acts on them is like a wise man who built his house on the rock.", "asv": "Every one therefore that heareth these words of mine, and doeth them, shall be likened unto a wise man, who built his house upon the rock:", "ylt": "`Therefore, every one who doth hear of me these words, and doth do them, I will liken him to a wise man who built his house upon the rock;", "tyndale": "Whosoever heareth of me these sayinges and doethe the same I wyll lyken hym vnto a wyse man which bylt hys housse on a rocke:", "dra": "Every one therefore that heareth these my words, and doth them, shall be likened to a wise man that built his house upon a rock,", "bbe": "Everyone, then, to whom my words come and who does them, will be like a wise man who made his house on a rock;", "geneva": "Whosoeuer then heareth of mee these words, and doeth the same, I will liken him to a wise man, which hath builded his house on a rock:", "wycliffe": "Therfor ech man that herith these my wordis, and doith hem, schal be maad lijk to a wise man, that hath bildid his hous on a stoon.", "rotherham": "Every one, therefore, who heareth [these] my words, and doeth them, shall be likened to a prudent man, who built his house upon the rock;", "weymouth": "\"Every one who hears these my teachings and acts upon them will be found to resemble a wise man who builds his house upon rock;", "darby": "Whoever therefore hears these my words and does them, I will liken him to a prudent man, who built his house upon the rock;", "twenty": "Everyone, therefore, that listens to this teaching of mine and acts upon it may be compared to a prudent man, who built his house upon the rock.", "acv": "Therefore every man, whoever hears these sayings of mine, and does them, I will compare him to a wise man who built his house upon the rock.", "anderson": "Therefore, whoever hears these words of mine and does them, I will liken him to a wise man, who built his house on the rock:", "haweis": "Every man therefore who is hearing from me these words, and puts them in practice, I will compare him to the intelligent man, who erected his house upon a rock:", "noyes": "Every one then that heareth these sayings of mine, and doeth them, shall be likened to a wise man, who built his house upon a rock;", "webster": "Therefore whoever heareth these sayings of mine, and doeth them, I will liken him to a wise man, who built his house upon a rock:", "vulgate": "omnis ergo qui audit verba mea haec et facit ea adsimilabitur viro sapienti qui aedificavit domum suam supra petram;"}}, {"v": 25, "ref": "7:25", "o": "καὶ κατέβη ἡ βροχὴ καὶ ἦλθον οἱ ποταμοὶ καὶ ἔπνευσαν οἱ ἄνεμοι καὶ προσέπεσαν τῇ οἰκίᾳ ἐκείνῃ, καὶ οὐκ ἔπεσεν, τεθεμελίωτο γὰρ ἐπὶ τὴν πέτραν.", "en": {"kjv": "And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell not: for it was founded upon a rock.", "web": "The rain came down, the floods came, and the winds blew, and beat on that house; and it didn’t fall, for it was founded on the rock.", "bsb": "The rain fell, the torrents raged, and the winds blew and beat against that house; yet it did not fall, because its foundation was on the rock.", "asv": "and the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell not: for it was founded upon the rock.", "ylt": "and the rain did descend, and the streams came, and the winds blew, and they beat on that house, and it fell not, for it had been founded on the rock.", "tyndale": "and aboundance of rayne descended and the fluddes came and the wyndes blewe and bet vpon that same housse and it fell not because it was grounded on the rocke.", "dra": "And the rain fell, and the floods came, and the winds blew, and they beat upon that house, and it fell not, for it was founded on a rock.", "bbe": "And the rain came down and there was a rush of waters and the winds were driving against that house, but it was not moved; because it was based on the rock.", "geneva": "And the raine fell, and the floods came, and the windes blewe, and beat vpon that house, and it fell not: for it was grounded on a rocke.", "wycliffe": "And reyn felde doun, and flodis camen, and wyndis blewen, and russchiden `in to that hous; and it felde not doun, for it was foundun on a stoon.", "rotherham": "And the rain descended, and the streams came, and the winds blew, and rushed against that house, and it fell not; for it had been founded upon the rock.", "weymouth": "and the heavy rain falls, the swollen torrents come, and the winds blow and beat against the house; yet it does not fall, for its foundation is on rock.", "darby": "and the rain came down, and the streams came, and the winds blew and fell upon that house, and it did not fall, for it had been founded upon the rock.", "twenty": "The rain poured down, the rivers rose, the winds blew and beat upon that house, but it did not fall, for its foundations were upon the rock.", "acv": "And the rain descended, and the torrents came, and the winds blew, and beat upon that house, and it fell not, for it had been founded upon the rock.", "anderson": "and the rain descended, and the torrents came, and the winds blew, and they beat against that house, and it fell not: for it was founded on the rock.", "haweis": "and the rain descended, and the rivers rushed, and the winds blew, and they beat against that house, and it fell not; for it was founded on a rock.", "noyes": "and the rain descended, and the streams came, and the winds blew, and beat upon that house; and it fell not; for it was founded upon a rock.", "webster": "And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell not: for it was founded upon a rock.", "vulgate": "et descendit pluvia et venerunt flumina et flaverunt venti et inruerunt in domum illam et non cecidit fundata enim erat super petram;"}}, {"v": 26, "ref": "7:26", "o": "καὶ πᾶς ὁ ἀκούων μου τοὺς λόγους τούτους καὶ μὴ ποιῶν αὐτοὺς ὁμοιωθήσεται ἀνδρὶ μωρῷ, ὅστις ᾠκοδόμησεν ⸂αὐτοῦ τὴν οἰκίαν⸃ ἐπὶ τὴν ἄμμον.", "en": {"kjv": "And every one that heareth these sayings of mine, and doeth them not, shall be likened unto a foolish man, which built his house upon the sand:", "web": "Everyone who hears these words of mine, and doesn’t do them will be like a foolish man, who built his house on the sand.", "bsb": "But everyone who hears these words of Mine and does not act on them is like a foolish man who built his house on sand.", "asv": "And every one that heareth these words of mine, and doeth them not, shall be likened unto a foolish man, who built his house upon the sand:", "ylt": "`And every one who is hearing of me these words, and is not doing them, shall be likened to a foolish man who built his house upon the sand;", "tyndale": "And whosoever heareth of me these sayinges and doth the not shalbe lykened vnto a folysh man which bilt hys housse apo the sondes:", "dra": "And every one that heareth these my words and doth them not, shall be like a foolish man that built his house upon the sand,", "bbe": "And everyone to whom my words come and who does them not, will be like a foolish man who made his house on sand;", "geneva": "But whosoeuer heareth these my wordes, and doeth them not, shall be likened vnto a foolish man, which hath builded his house vpon the sand:", "wycliffe": "And euery man that herith these my wordis, and doith hem not, is lijk to a fool, that hath bildid his hous on grauel.", "rotherham": "And every one who heareth these my words, and doeth them not, shall be likened unto a foolish man, who built his house upon the sand;", "weymouth": "And every one who hears these my teachings and does not act upon them will be found to resemble a fool who builds his house upon sand.", "darby": "And every one who hears these my words and does not do them, he shall be likened to a foolish man, who built his house upon the sand;", "twenty": "And every one that listens to this teaching of mine and does not act upon it may be compared to a foolish man, who built his house on the sand.", "acv": "And every man who hears these sayings of mine, and does not do them, will be compared to a foolish man who built his house upon the sand.", "anderson": "And every one that hears these words of mine, and does them not, shall be likened to a foolish man, who built his house upon the sand.", "haweis": "And every man who is hearing these sayings of mine, and doth not practise them, he will resemble the foolish man, who built his house upon the sand:", "noyes": "And every one that heareth these sayings of mine, and doeth them not, shall be likened to a foolish man, who built his house upon the sand;", "webster": "And every one that heareth these sayings of mine, and doeth them not, shall be likened to a foolish man, who built his house upon the sand:", "vulgate": "et omnis qui audit verba mea haec et non facit ea similis erit viro stulto qui aedificavit domum suam supra harenam;"}}, {"v": 27, "ref": "7:27", "o": "καὶ κατέβη ἡ βροχὴ καὶ ἦλθον οἱ ποταμοὶ καὶ ἔπνευσαν οἱ ἄνεμοι καὶ προσέκοψαν τῇ οἰκίᾳ ἐκείνῃ, καὶ ἔπεσεν, καὶ ἦν ἡ πτῶσις αὐτῆς μεγάλη.", "en": {"kjv": "And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell: and great was the fall of it.", "web": "The rain came down, the floods came, and the winds blew, and beat on that house; and it fell—and great was its fall.”", "bsb": "The rain fell, the torrents raged, and the winds blew and beat against that house, and it fell—and great was its collapse!”", "asv": "and the rain descended, and the floods came, and the winds blew, and smote upon that house; and it fell: and great was the fall thereof.", "ylt": "and the rain did descend, and the streams came, and the winds blew, and they beat on that house, and it fell, and its fall was great.'", "tyndale": "and abundauce of rayne descended and the fluddes came and ye wyndes blewe and beet vpon that housse and it fell and great was the fall of it.", "dra": "And the rain fell, and the floods came, and the winds blew, and they beat upon that house, and it fell, and great was the fall thereof.", "bbe": "And the rain came down and there was a rush of waters and the winds were driving against that house; and it came down and great was its fall.", "geneva": "And the raine fell, and the floods came, and the windes blewe, and beat vpon that house, and it fell, and the fall thereof was great.", "wycliffe": "And reyn cam doun, and floodis camen, and wyndis blewen, and thei hurliden ayen that hous; and it felde doun, and the fallyng doun therof was greet.", "rotherham": "And the rain descended, and the streams came, and the winds blew, and dashed against that house, and it fell; and, the fall thereof, was, great.", "weymouth": "The heavy rain descends, the swollen torrents come, and the winds blow and burst upon the house, and it falls; and disastrous is the fall.\"", "darby": "and the rain came down, and the streams came, and the winds blew and beat upon that house, and it fell, and its fall was great.", "twenty": "The rain poured down, the rivers rose, the winds blew and struck against that house, and it fell; and great was its downfall.”", "acv": "And the rain descended, and the torrents came, and the winds blew, and beat upon that house, and it fell. And great was the fall of it.", "anderson": "And the rain descended, and the torrents came, and the winds blew, and beat upon that house, and it fell: and great was its fall.", "haweis": "and the rain descended, and the rivers rushed, and the winds blew, and set against that house, and it fell; and the fall of it was great.", "noyes": "and the rain descended, and the streams came, and the winds blew, and beat upon that house; and it fell; and great was its fall.", "webster": "And the rain descended, and the floods came, and the winds blew, and beat upon that house; and it fell, and great was the fall of it.", "vulgate": "et descendit pluvia et venerunt flumina et flaverunt venti et inruerunt in domum illam et cecidit et fuit ruina eius magna;"}}, {"v": 28, "ref": "7:28", "o": "Καὶ ἐγένετο ὅτε ⸀ἐτέλεσεν ὁ Ἰησοῦς τοὺς λόγους τούτους, ἐξεπλήσσοντο οἱ ὄχλοι ἐπὶ τῇ διδαχῇ αὐτοῦ·", "en": {"kjv": "And it came to pass, when Jesus had ended these sayings, the people were astonished at his doctrine:", "web": "When Jesus had finished saying these things, the multitudes were astonished at his teaching,", "bsb": "When Jesus had finished saying these things, the crowds were astonished at His teaching,", "asv": "And it came to pass, when Jesus had finished these words, the multitudes were astonished at his teaching:", "ylt": "And it came to pass, when Jesus ended these words, the multitudes were astonished at his teaching,", "tyndale": "And it came to passe that when Iesus had ended these saynges the people were astonnyed at hys doctryne.", "dra": "And it came to pass when Jesus had fully ended these words, the people were in admiration at his doctrine.", "bbe": "And it came about, when Jesus had come to the end of these words, that the people were surprised at his teaching,", "geneva": "And it came to passe, when Iesus had ended these wordes, the people were astonied at his doctrine.", "wycliffe": "And it was doon, whanne Jhesus hadde endid these wordis, the puple wondride on his techyng;", "rotherham": "And it came to pass, when Jesus ended these words, with astonishment were the multitudes being struck at his teaching;", "weymouth": "When Jesus had concluded this discourse, the crowds were filled with amazement at His teaching,", "darby": "And it came to pass, when Jesus had finished these words, the crowds were astonished at his doctrine,", "twenty": "By the time that Jesus had finished speaking, the crowd was filled with amazement at his teaching.", "acv": "And it came to pass, when Jesus finished these sayings, the multitudes were astonished at his teaching,", "anderson": "And it came to pass when Jesus had ended these words, that the multitudes were astonished at his teaching:", "haweis": "And it was so, that when Jesus had concluded all these sayings, the multitudes were exceedingly struck with his teaching:", "noyes": "And it came to pass, when Jesus had ended these sayings, that the multitudes were astonished at his teaching.", "webster": "And it came to pass when Jesus had ended these sayings, the people were astonished at his doctrine.", "vulgate": "et factum est cum consummasset Iesus verba haec admirabantur turbae super doctrinam eius;"}}, {"v": 29, "ref": "7:29", "o": "ἦν γὰρ διδάσκων αὐτοὺς ὡς ἐξουσίαν ἔχων καὶ οὐχ ὡς οἱ γραμματεῖς ⸀αὐτῶν.", "en": {"kjv": "For he taught them as one having authority, and not as the scribes.", "web": "for he taught them with authority, and not like the scribes.", "bsb": "because He taught as one who had authority, and not as their scribes.", "asv": "for he taught them asonehaving authority, and not as their scribes.", "ylt": "for he was teaching them as having authority, and not as the scribes.", "tyndale": "For he taught them as one havynge power and not as the Scribes.", "dra": "For he was teaching them as one having power, and not as the scribes and Pharisees.", "bbe": "for he was teaching as one having authority, and not as their scribes.", "geneva": "For he taught them as one hauing authoritie, and not as the Scribes.", "wycliffe": "for he tauyte hem, as he that hadde power, and not as the scribis `of hem, and the Farisees.", "rotherham": "for he was teaching them as one having, authority, and not as their Scribes.", "weymouth": "for He had been teaching them as one who had authority, and not as their Scribes taught.", "darby": "for he taught them as having authority, and not as their scribes.", "twenty": "For he taught them like one who had authority, and not like their Teachers of the Law.", "acv": "for he was teaching them as having authority, and not as their scholars.", "anderson": "for he taught them as one that had authority, and not as the scribes.", "haweis": "for he taught them as having authority, and not as the scribes.", "noyes": "For he taught them as having authority, and not as their scribes.", "webster": "For he taught them as [one] having authority, and not as the scribes.", "vulgate": "erat enim docens eos sicut potestatem habens non sicut scribae eorum et Pharisaei;"}}]}, {"c": 8, "verses": [{"v": 1, "ref": "8:1", "o": "⸂Καταβάντος δὲ αὐτοῦ⸃ ἀπὸ τοῦ ὄρους ἠκολούθησαν αὐτῷ ὄχλοι πολλοί.", "en": {"kjv": "When he was come down from the mountain, great multitudes followed him.", "web": "When he came down from the mountain, great multitudes followed him.", "bsb": "When Jesus came down from the mountain, large crowds followed Him.", "asv": "And when he was come down from the mountain, great multitudes followed him.", "ylt": "And when he came down from the mount, great multitudes did follow him,", "tyndale": "When he was come downe from the moutayne moch people folowed him.", "dra": "And when he was come down from the mountain, great multitudes followed him:", "bbe": "And when he had come down from the mountain, great numbers of people came after him.", "geneva": "Nowe when he was come downe from the mountaine, great multitudes followed him.", "wycliffe": "But whanne Jhesus was come doun fro the hil, mych puple suede hym.", "rotherham": "And when he came down from the mountain, there followed him large multitudes.", "weymouth": "Upon descending from the hill country He was followed by immense crowds.", "darby": "And when he had come down from the mountain, great crowds followed him.", "twenty": "When Jesus had come down from the hill, great crowds followed him.", "acv": "And upon his coming down from the mountain, many multitudes followed him.", "anderson": "And when he had come down from the mountain, many multitudes followed him.", "haweis": "NOW when he descended from the mount, great multitudes followed him.", "noyes": "When he had come down from the mountain, great multitudes followed him.", "webster": "When he had come down from the mountain, great multitudes followed him.", "vulgate": "cum autem descendisset de monte secutae sunt eum turbae multae;"}}, {"v": 2, "ref": "8:2", "o": "καὶ ἰδοὺ λεπρὸς ⸀προσελθὼν προσεκύνει αὐτῷ λέγων· Κύριε, ἐὰν θέλῃς δύνασαί με καθαρίσαι.", "en": {"kjv": "And, behold, there came a leper and worshipped him, saying, Lord, if thou wilt, thou canst make me clean.", "web": "Behold, a leper came to him and worshiped him, saying, “Lord, if you want to, you can make me clean.”", "bsb": "Suddenly a leper came and knelt before Him, saying, “Lord, if You are willing, You can make me clean.”", "asv": "And behold, there came to him a leper and worshipped him, saying, Lord, if thou wilt, thou canst make me clean.", "ylt": "and lo, a leper having come, was bowing to him, saying, `Sir, if thou art willing, thou art able to cleanse me;'", "tyndale": "And lo ther came a lepre and worsheped him sayinge: Master if thou wylt thou canst make me clene.", "dra": "And behold a leper came and adored him, saying: Lord, if thou wilt, thou canst make me clean.", "bbe": "And a leper came and gave him worship, saying, Lord, if it is your pleasure, you have power to make me clean.", "geneva": "And loe, there came a Leper and worshipped him, saying, Master, if thou wilt, thou canst make me cleane.", "wycliffe": "And loo! a leprouse man cam, and worschipide hym, and seide, Lord, if thou wolt, thou maist make me clene.", "rotherham": "And lo! a leper, coming near, began to bow down to him saying,—Lord! if thou be willing, thou canst cleanse me.", "weymouth": "And a leper came to Him, and throwing himself at His feet, said, \"Sir, if only you are willing you are able to cleanse me.\"", "darby": "And behold, a leper came up to [him] and did him homage, saying, Lord, if thou wilt, thou art able to cleanse me.", "twenty": "And he saw a leper who came up, and bowed to the ground before him, and said: “Master, if only you are willing, you are able to make me clean.”", "acv": "And behold, a leper who came, worshiped him, saying, Lord, if thou will, thou can cleanse me.", "anderson": "And behold, a leper came and did him homage, saying: Lord, if thou wilt, thou canst make me clean.", "haweis": "And lo! a leper came and worshipped him, saying, Lord, if thou wilt, thou canst make me clean.", "noyes": "And lo! there came a leper and bowed down before him, saying, Lord, if thou wilt, thou canst cleanse me.", "webster": "And behold, there came a leper and worshiped him, saying, Lord, if thou wilt, thou canst make me clean.", "vulgate": "et ecce leprosus veniens adorabat eum dicens Domine si vis potes me mundare;"}}, {"v": 3, "ref": "8:3", "o": "καὶ ἐκτείνας τὴν χεῖρα ἥψατο ⸀αὐτοῦ λέγων· Θέλω, καθαρίσθητι· καὶ εὐθέως ἐκαθαρίσθη αὐτοῦ ἡ λέπρα.", "en": {"kjv": "And Jesus put forth his hand, and touched him, saying, I will; be thou clean. And immediately his leprosy was cleansed.", "web": "Jesus stretched out his hand, and touched him, saying, “I want to. Be made clean.” Immediately his leprosy was cleansed.", "bsb": "Jesus reached out His hand and touched the man. “I am willing,” He said. “Be clean!” And immediately his leprosy was cleansed.", "asv": "And he stretched forth his hand, and touched him, saying, I will; be thou made clean. And straightway his leprosy was cleansed.", "ylt": "and having stretched forth the hand, Jesus touched him, saying, `I will, be thou cleansed,' and immediately his leprosy was cleansed.", "tyndale": "And Iesus put forthe hys hond and touched hym sayinge: I wyll be thou clene and immediatly hys leprosie was clensed.", "dra": "And Jesus stretching forth his hand, touched him, saying: I will, be thou made clean. And forthwith his leprosy was cleansed.", "bbe": "And he put his hand on him, saying, It is my pleasure; be clean. And straight away he was made clean.", "geneva": "And Iesus putting foorth his hand, touched him, saying, I will, be thou cleane: and immediatly his leprosie was clensed.", "wycliffe": "And Jhesus helde forth the hoond, and touchide hym, and seide, Y wole, be thou maad cleene. And anoon the lepre of him was clensid.", "rotherham": "And, stretching forth the hand, he touched him, saying,—I am willing, be cleansed! And, straightway, cleansed was his leprosy.", "weymouth": "So Jesus put out His hand and touched him, and said, \"I am willing: be cleansed.\" Instantly he was cleansed from his leprosy;", "darby": "And he stretched out his hand and touched him, saying, I will; be cleansed. And immediately his leprosy was cleansed.", "twenty": "Stretching out his hand, Jesus touched him, saying as he did so: “I am willing; become clean.” Instantly he was made clean from his leprosy;", "acv": "And having reached out his hand, Jesus touched him, saying, I will, be thou cleansed. And straightaway his leprosy was cleansed.", "anderson": "And Jesus stretched out his hand and touched him, saying: I will; be clean. And immediately his leprosy was cleansed.", "haweis": "And stretching out his hand, Jesus touched him, saying, I will; be thou clean. And instantly the leprosy was cleansed.", "noyes": "And he put forth his hand, and touched him, saying, I will; be thou cleansed. And immediately his leprosy was cleansed.", "webster": "And Jesus put forth [his] hand, and touched him, saying, I will; be thou clean. And immediately his leprosy was cleansed.", "vulgate": "et extendens manum tetigit eum Iesus dicens volo mundare et confestim mundata est lepra eius;"}}, {"v": 4, "ref": "8:4", "o": "καὶ λέγει αὐτῷ ὁ Ἰησοῦς· Ὅρα μηδενὶ εἴπῃς, ἀλλὰ ὕπαγε σεαυτὸν δεῖξον τῷ ἱερεῖ, καὶ προσένεγκον τὸ δῶρον ὃ προσέταξεν Μωϋσῆς εἰς μαρτύριον αὐτοῖς.", "en": {"kjv": "And Jesus saith unto him, See thou tell no man; but go thy way, shew thyself to the priest, and offer the gift that Moses commanded, for a testimony unto them.", "web": "Jesus said to him, “See that you tell nobody, but go, show yourself to the priest, and offer the gift that Moses commanded, as a testimony to them.”", "bsb": "Then Jesus instructed him, “See that you don’t tell anyone. But go, show yourself to the priest and offer the gift prescribed by Moses, as a testimony to them.”", "asv": "And Jesus saith unto him, See thou tell no man; but go, show thyself to the priest, and offer the gift that Moses commanded, for a testimony unto them.", "ylt": "And Jesus saith to him, `See, thou mayest tell no one, but go, thyself shew to the priest, and bring the gift that Moses commanded for a testimony to them.'", "tyndale": "And Iesus sayde vnto him. Se thou tell no man but go and shewe thy selfe to the preste and offer the gyfte that Moses comaunded in witnes to them.", "dra": "And Jesus saith to him: See thou tell no man: but go, shew thyself to the priest, and offer the gift which Moses commanded, for a testimony unto them.", "bbe": "And Jesus said to him, See that you say nothing about this to anyone; but go and let the priest see you and make the offering which was ordered by Moses, for a witness to them.", "geneva": "Then Iesus saide vnto him, See thou tell no man, but goe, and shewe thy selfe vnto the Priest, and offer the gift that Moses commanded, for a witnesse to them.", "wycliffe": "And Jhesus seide to hym, Se, seie thou to no man; but go, shewe thee to the prestis, and offre the yift that Moyses comaundide, in witnessyng to hem.", "rotherham": "And Jesus saith unto him, Mind! tell, no one,—but withdraw, thyself, shew to the priest, and offer the gift which Moses directed, for a witness unto them.", "weymouth": "and Jesus said to him, \"Be careful to tell no one, but go and show yourself to the priest, and offer the gift which Moses appointed as evidence for them.\"", "darby": "And Jesus says to him, See thou tell no man, but go, shew thyself to the priest, and offer the gift which Moses ordained, for a testimony to them.", "twenty": "and then Jesus said to him: “Be careful not to say a word to any one, but go and show yourself to the Priest, and offer the gift directed by Moses, as evidence of your cure.”", "acv": "And Jesus says to him, See thou speak to no man, but go, show thyself to the priest, and bring the gift that Moses commanded for a testimony to them.", "anderson": "And Jesus said to him: See that you tell no one. But go, show yourself to the priest, and offer the gift that Moses commanded, for a testimony to them.", "haweis": "And Jesus said to him, See thou tell no man; but go, shew thyself to the priest, and offer the gift which Moses commanded for a testimony unto them.", "noyes": "And Jesus saith to him, See thou tell no one; but go, show thyself to the priest, and offer the gift that Moses commanded, for a testimony to them.", "webster": "And Jesus saith to him, See thou tell no man; but go, show thyself to the priest, and offer the gift that Moses commanded, for a testimony to them.", "vulgate": "et ait illi Iesus vide nemini dixeris sed vade ostende te sacerdoti et offer munus quod praecepit Moses in testimonium illis;"}}, {"v": 5, "ref": "8:5", "o": "⸂Εἰσελθόντος δὲ αὐτοῦ⸃ εἰς Καφαρναοὺμ προσῆλθεν αὐτῷ ἑκατόνταρχος παρακαλῶν αὐτὸν", "en": {"kjv": "And when Jesus was entered into Capernaum, there came unto him a centurion, beseeching him,", "web": "When he came into Capernaum, a centurion came to him, asking him,", "bsb": "When Jesus had entered Capernaum, a centurion came and pleaded with Him,", "asv": "And when he was entered into Capernaum, there came unto him a centurion, beseeching him,", "ylt": "And Jesus having entered into Capernaum, there came to him a centurion calling upon him,", "tyndale": "When Iesus was entred into Capernau ther came vnto him a certayne Centurion and besought hym", "dra": "And when he had entered into Capharnaum, there came to him a centurion, beseeching him,", "bbe": "And when Jesus was come into Capernaum, a certain captain came to him with a request,", "geneva": "When Iesus was entred into Capernaum, there came vnto him a Centurion, beseeching him,", "wycliffe": "And whanne he hadde entrid in to Cafarnaum, `the centurien neiyede to him, and preiede him,", "rotherham": "And, when he entered into Capernaum, there came near unto him a centurion, beseeching him,", "weymouth": "After His entry into Capernaum a Captain came to Him, and entreated Him.", "darby": "And when he had entered into Capernaum, a centurion came to him, beseeching him,", "twenty": "After Jesus had entered Capernaum, a Captain in the Roman army came up to him, entreating his help.", "acv": "And upon his entering into Capernaum, a centurion came to him, beseeching him,", "anderson": "And when he entered Capernaum, there came to him a centurion, beseeching him,", "haweis": "Then as Jesus was entering into Capernaum, there met him a centurion, intreating him,", "noyes": "And when he had entered into Capernaum, there came to him a centurion, beseeching him,", "webster": "And when Jesus had entered into Capernaum, there came to him a centurion, beseeching him,", "vulgate": "cum autem introisset Capharnaum accessit ad eum centurio rogans eum;"}}, {"v": 6, "ref": "8:6", "o": "καὶ λέγων· Κύριε, ὁ παῖς μου βέβληται ἐν τῇ οἰκίᾳ παραλυτικός, δεινῶς βασανιζόμενος.", "en": {"kjv": "And saying, Lord, my servant lieth at home sick of the palsy, grievously tormented.", "web": "and saying, “Lord, my servant lies in the house paralyzed, grievously tormented.”", "bsb": "“Lord, my servant lies at home, paralyzed and in terrible agony.”", "asv": "and saying, Lord, my servant lieth in the house sick of the palsy, grievously tormented.", "ylt": "and saying, `Sir, my young man hath been laid in the house a paralytic, fearfully afflicted,'", "tyndale": "sayinge: Master my seruaunt lyeth sicke at home of ye palsye and ys greuously payned.", "dra": "And saying, Lord, my servant lieth at home sick of the palsy, and is grievously tormented.", "bbe": "Saying, Lord, my servant is ill in bed at the house, with no power in his body, and in great pain.", "geneva": "And saide, Master, my seruant lieth sicke at home of the palsie, and is grieuously pained.", "wycliffe": "and seide, Lord, my childe lijth in the hous sijk on the palesie, and is yuel turmentid.", "rotherham": "and saying, Lord! my servant, is laid prostrate in the house, a paralytic, fearfully tortured.", "weymouth": "\"Sir,\" he said, \"my servant at home is lying ill with paralysis, and is suffering great pain.\"", "darby": "and saying, Lord, my servant lies paralytic in the house, suffering grievously.", "twenty": "“Sir,” he said, “my manservant is lying ill at my house with a stroke of paralysis, and is suffering terribly.”", "acv": "and saying, Lord, my boy has been laid down in the house, paralyzed, extremely tormented.", "anderson": "and saying: Lord, my servant lies in my house, palsied, fearfully afflicted.", "haweis": "and saying, My servant is lying in the house paralytic, terribly tormented with pain.", "noyes": "and saying, Lord, my servant lieth at home palsied, sorely tormented.", "webster": "And saying, Lord, my servant lieth at home sick with the palsy, grievously tormented.", "vulgate": "et dicens Domine puer meus iacet in domo paralyticus et male torquetur;"}}, {"v": 7, "ref": "8:7", "o": "⸀καὶ λέγει ⸀αὐτῷ· Ἐγὼ ἐλθὼν θεραπεύσω αὐτόν.", "en": {"kjv": "And Jesus saith unto him, I will come and heal him.", "web": "Jesus said to him, “I will come and heal him.”", "bsb": "“I will go and heal him,” Jesus replied.", "asv": "And he saith unto him, I will come and heal him.", "ylt": "and Jesus saith to him, `I, having come, will heal him.'", "tyndale": "And Iesus sayd vnto hym: I will come and heale him.", "dra": "And Jesus saith to him: I will come and heal him.", "bbe": "And he said to him, I will come and make him well.", "geneva": "And Iesus saide vnto him, I will come and heale him.", "wycliffe": "And Jhesus seide to him, Y schal come, and schal heele him.", "rotherham": "He saith unto him, I, will come and cure him.", "weymouth": "\"I will come and cure him,\" said Jesus.", "darby": "And Jesus says to him, I will come and heal him.", "twenty": "“I will come and cure him,” answered Jesus.", "acv": "And Jesus says to him, after coming I will heal him.", "anderson": "And Jesus said to him: I will go and cure him.", "haweis": "And Jesus said unto him, I will come and heal him.", "noyes": "He saith to him, I will come and heal him.", "webster": "And Jesus saith to him, I will come and heal him.", "vulgate": "et ait illi Iesus ego veniam et curabo eum;"}}, {"v": 8, "ref": "8:8", "o": "⸂καὶ ἀποκριθεὶς⸃ ὁ ἑκατόνταρχος ἔφη· Κύριε, οὐκ εἰμὶ ἱκανὸς ἵνα μου ὑπὸ τὴν στέγην εἰσέλθῃς· ἀλλὰ μόνον εἰπὲ λόγῳ, καὶ ἰαθήσεται ὁ παῖς μου·", "en": {"kjv": "The centurion answered and said, Lord, I am not worthy that thou shouldest come under my roof: but speak the word only, and my servant shall be healed.", "web": "The centurion answered, “Lord, I’m not worthy for you to come under my roof. Just say the word, and my servant will be healed.", "bsb": "The centurion answered, “Lord, I am not worthy to have You come under my roof. But just say the word, and my servant will be healed.", "asv": "And the centurion answered and said, Lord, I am not worthy that thou shouldest come under my roof; but only say the word, and my servant shall be healed.", "ylt": "And the centurion answering said, `Sir, I am not worthy that thou mayest enter under my roof, but only say a word, and my servant shall be healed;", "tyndale": "The Centurio answered and sayde: Syr I am not worthy yt thou shuldest come vnder my rofe but speake ye worde only and my servaut shalbe healed.", "dra": "And the centurion, making answer, said: Lord, I am not worthy that thou shouldst enter under my roof; but only say the word, and my servant shall be healed.", "bbe": "And the captain in answer said, Lord, I am not good enough for you to come under my roof; but only say the word, and my servant will be made well.", "geneva": "But the Centurion answered, saying, Master, I am not worthy that thou shouldest come vnder my roofe: but speake the worde onely, and my seruant shall be healed.", "wycliffe": "And the centurien answeride, and seide to hym, Lord, Y am not worthi, that thou entre vndur my roof; but oonli seie thou bi word, and my childe shal be heelid.", "rotherham": "But the centurion, answering, said, Lord! I am of no consideration, that, under my roof, thou shouldest enter,—but, only say with a word, and healed shall be my servant.", "weymouth": "\"Sir,\" replied the Captain, \"I am not a fit person to receive you under my roof: merely say the word, and my servant will be cured.", "darby": "And the centurion answered and said, Lord, I am not fit that thou shouldest enter under my roof; but only speak a word, and my servant shall be healed.", "twenty": "“Sir,” the Captain went on, “I am unworthy to receive you under my roof; but only speak, and my manservant will be cured.", "acv": "And having answered, the centurion said, Lord, I am not worthy that thou should come under my roof, but only speak the word, and my boy will be healed.", "anderson": "And the centurion answering, said: Lord, I am not worthy that thou shouldst come under my roof; but say in a word only, and my servant shall be restored to health.", "haweis": "And the centurion said, I am not a fit person, that thou shouldest come under my roof: but only speak a word, and my servant be cured.", "noyes": "But the centurion answered and said, Lord, I am not worthy that thou shouldst come under my roof; but only command with a word, and my servant will be made well.", "webster": "The centurion answered and said, Lord, I am not worthy that thou shouldst come under my roof: but speak the word only, and my servant will be healed.", "vulgate": "et respondens centurio ait Domine non sum dignus ut intres sub tectum meum sed tantum dic verbo et sanabitur puer meus;"}}, {"v": 9, "ref": "8:9", "o": "καὶ γὰρ ἐγὼ ἄνθρωπός εἰμι ὑπὸ ⸀ἐξουσίαν, ἔχων ὑπ’ ἐμαυτὸν στρατιώτας, καὶ λέγω τούτῳ· Πορεύθητι, καὶ πορεύεται, καὶ ἄλλῳ· Ἔρχου, καὶ ἔρχεται, καὶ τῷ δούλῳ μου· Ποίησον τοῦτο, καὶ ποιεῖ.", "en": {"kjv": "For I am a man under authority, having soldiers under me: and I say to this man, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.", "web": "For I am also a man under authority, having under myself soldiers. I tell this one, ‘Go,’ and he goes; and tell another, ‘Come,’ and he comes; and tell my servant, ‘Do this,’ and he does it.”", "bsb": "For I myself am a man under authority, with soldiers under me. I tell one to go, and he goes; and another to come, and he comes. I tell my servant to do something, and he does it.”", "asv": "For I also am a man under authority, having under myself soldiers: and I say to this one, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.", "ylt": "for I also am a man under authority, having under myself soldiers, and I say to this one, Go, and he goeth, and to another, Be coming, and he cometh, and to my servant, Do this, and he doth it .'", "tyndale": "For I also my selfe am a man vndre power and have sowdiers vndre me and I saye to one go and he goeth and to anothre come and he cometh: and to my seruaut do this and he doeth it.", "dra": "For I also am a man subject to authority, having under me soldiers; and I say to this, Go, and he goeth, and to another Come, and he cometh, and to my servant, Do this, and he doeth it.", "bbe": "Because I myself am a man under authority, having under me fighting men; and I say to this one, Go, and he goes; and to another, Come, and he comes; and to my servant, Do this, and he does it.", "geneva": "For I am a man also vnder the authoritie of an other, and haue souldiers vnder me: and I say to one, Goe, and he goeth: and to another, Come, and he commeth: and to my seruant, Doe this, and he doeth it.", "wycliffe": "For whi Y am a man ordeyned vndur power, and haue knyytis vndir me; and Y seie to this, Go, and he goith; and to another, Come, and he cometh; and to my seruaunt, Do this, and he doith it.", "rotherham": "For, I also, am a man [set] under authority, having under myself, soldiers,—and I say to this one, Go! and he goeth, and to another, Come! and he cometh, and, to my servant, Do this! and he doeth it.", "weymouth": "For I myself am also under authority, and have soldiers under me. To one I say `Go,' and he goes, to another `Come,' and he comes, and to my slave `Do this or that,' and he does it.\"", "darby": "For I also am a man under authority, having under me soldiers, and I say to this [one], Go, and he goes; and to another, Come, and he comes; and to my bondman, Do this, and he does it.", "twenty": "For I myself am a man under the orders of others, with soldiers under me; and, if I say to one of them ‘Go,’ he goes, and to another ‘Come,’ he comes, and to my slave ‘Do this,’ he does it.”", "acv": "For I also am a man under authority, having soldiers under myself. And I say to this man, Go, and he goes, and to another, Come, and he comes, and to my bondman, Do this, and he does it.", "anderson": "For I am a man under authority, having soldiers under me; and I say to this one, Go, and he goes; and to another, Come, and he comes; and to my servant, Do this, and he does it.", "haweis": "For I also am a man under authority, having under my command soldiers and I say to this soldier, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.", "noyes": "For even I am a man under authority, having soldiers under me; and I say to this one, Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth it.", "webster": "For I am a man under authority, having soldiers under me: and I say to this [man], Go, and he goeth; and to another, Come, and he cometh; and to my servant, Do this, and he doeth [it].", "vulgate": "nam et ego homo sum sub potestate habens sub me milites et dico huic vade et vadit et alio veni et venit et servo meo fac hoc et facit;"}}, {"v": 10, "ref": "8:10", "o": "ἀκούσας δὲ ὁ Ἰησοῦς ἐθαύμασεν καὶ εἶπεν τοῖς ἀκολουθοῦσιν· Ἀμὴν λέγω ὑμῖν, ⸂παρ’ οὐδενὶ τοσαύτην πίστιν ἐν τῷ Ἰσραὴλ⸃ εὗρον.", "en": {"kjv": "When Jesus heard it, he marvelled, and said to them that followed, Verily I say unto you, I have not found so great faith, no, not in Israel.", "web": "When Jesus heard it, he marveled, and said to those who followed, “Most certainly I tell you, I haven’t found so great a faith, not even in Israel.", "bsb": "When Jesus heard this, He marveled and said to those following Him, “Truly I tell you, I have not found anyone in Israel with such great faith.", "asv": "And when Jesus heard it, he marvelled, and said to them that followed, Verily I say unto you, I have not found so great faith, no, not in Israel.", "ylt": "And Jesus having heard, did wonder, and said to those following, `Verily I say to you, not even in Israel so great faith have I found;", "tyndale": "When Iesus hearde yt he marveled and sayd to them yt folowed hym. Derely I say vnto you I have not foude so great fayth: no not in Israel.", "dra": "And Jesus hearing this, marvelled; and said to them that followed him. Amen I say to you, I have not found so great faith in Israel.", "bbe": "And when these words came to the ears of Jesus he was surprised, and said to those who came after him, Truly I say to you, I have not seen such great faith, no, not in Israel.", "geneva": "When Iesus heard that, he marueiled, and said to them that folowed him, Verely, I say vnto you, I haue not found so great faith, euen in Israel.", "wycliffe": "And Jhesus herde these thingis, and wondride, and seide to men `that sueden him, Treuli Y seie to you, Y foond not so greet feith in Israel.", "rotherham": "Now Jesus, hearing, marveled, and said to them that followed,—Verily, I say unto you, With no one in Israel, such faith as this, have I found.", "weymouth": "Jesus listened to this reply, and was astonished, and said to the people following Him, \"I solemnly tell you that in no Israelite have I found faith as great as this.", "darby": "And when Jesus heard it, he wondered, and said to those who followed, Verily I say unto you, Not even in Israel have I found so great faith.", "twenty": "Jesus was surprised to hear this, and said to those who were following him: “Never I tell you, in any Israelite have I met with such faith as this!", "acv": "And when Jesus heard it, he marveled, and said to those who followed, Truly I say to you, not even in Israel have I found such great faith.", "anderson": "And when Jesus heard it, he was filled with admiration, and said to those who followed him: Verily I say to you, not even in Israel have I found so great faith.", "haweis": "And Jesus hearing him, marvelled, and said to those who were following, Verily I say unto you, not even in Israel have I found so great faith.", "noyes": "When Jesus heard this, he marveled, and said to those who followed, Truly do I say to you, Not even in Israel have I found such faith.", "webster": "When Jesus heard [it], he marveled, and said to them that followed, Verily I say to you, I have not found so great faith, no, not in Israel.", "vulgate": "audiens autem Iesus miratus est et sequentibus se dixit amen dico vobis non inveni tantam fidem in Israhel;"}}, {"v": 11, "ref": "8:11", "o": "λέγω δὲ ὑμῖν ὅτι πολλοὶ ἀπὸ ἀνατολῶν καὶ δυσμῶν ἥξουσιν καὶ ἀνακλιθήσονται μετὰ Ἀβραὰμ καὶ Ἰσαὰκ καὶ Ἰακὼβ ἐν τῇ βασιλείᾳ τῶν οὐρανῶν·", "en": {"kjv": "And I say unto you, That many shall come from the east and west, and shall sit down with Abraham, and Isaac, and Jacob, in the kingdom of heaven.", "web": "I tell you that many will come from the east and the west, and will sit down with Abraham, Isaac, and Jacob in the Kingdom of Heaven,", "bsb": "I say to you that many will come from the east and the west to share the banquet with Abraham, Isaac, and Jacob in the kingdom of heaven.", "asv": "And I say unto you, that many shall come from the east and the west, and shall sit down with Abraham, and Isaac, and Jacob, in the kingdom of heaven:", "ylt": "and I say to you, that many from east and west shall come and recline (at meat) with Abraham, and Isaac, and Jacob, in the reign of the heavens,", "tyndale": "I say therfore vnto you that many shall come fro the eest and weest and shall rest wt Abraham Isaac and Iacob in the kingdome of heve:", "dra": "And I say to you that many shall come from the east and the west, and shall sit down with Abraham, and Isaac and Jacob in the kingdom of heaven:", "bbe": "And I say to you that numbers will come from the east and the west, and will take their seats with Abraham and Isaac and Jacob, in the kingdom of heaven:", "geneva": "But I say vnto you, that many shall come from the East and West, and shall sit downe with Abraham, and Isaac, and Iacob, in the kingdome of heauen.", "wycliffe": "And Y seie to you, that many schulen come fro the eest and the west, and schulen reste with Abraham and Ysaac and Jacob in the kyngdom of heuenes;", "rotherham": "But I say unto you, Many from east and west, will have come, and shall recline with Abraham and Isaac and Jacob, in the kingdom of the heavens;", "weymouth": "And I tell you that many will come from the east and from the west and will recline at table with Abraham, Isaac and Jacob in the Kingdom of the Heavens,", "darby": "But I say unto you, that many shall come from [the] rising and setting [sun], and shall lie down at table with Abraham, and Isaac, and Jacob in the kingdom of the heavens;", "twenty": "Yes, and many will come in from East and West and take their places beside Abraham, Isaac, and Jacob, in the Kingdom of Heaven;", "acv": "And I say to you, that many will come from east and west, and will sit down with Abraham, and Isaac, and Jacob, in the kingdom of the heavens,", "anderson": "I also say to you, That many shall come from the east and the west, and shall recline with Abraham, and Isaac, and Jacob in the kingdom of heaven;", "haweis": "And I say unto you, That many shall come from the east and from the west, and shall sit down with Abraham, and Isaac, and Jacob, in the kingdom of heaven.", "noyes": "And I say to you, that many will come from the east and the west, and recline at table with Abraham and Isaac and Jacob in the kingdom of heaven.", "webster": "And I say to you, that many shall come from the east and the west, and shall sit down with Abraham, and Isaac, and Jacob in the kingdom of heaven.", "vulgate": "dico autem vobis quod multi ab oriente et occidente venient et recumbent cum Abraham et Isaac et Iacob in regno caelorum;"}}, {"v": 12, "ref": "8:12", "o": "οἱ δὲ υἱοὶ τῆς βασιλείας ἐκβληθήσονται εἰς τὸ σκότος τὸ ἐξώτερον· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "But the children of the kingdom shall be cast out into outer darkness: there shall be weeping and gnashing of teeth.", "web": "but the children of the Kingdom will be thrown out into the outer darkness. There will be weeping and gnashing of teeth.”", "bsb": "But the sons of the kingdom will be thrown into the outer darkness, where there will be weeping and gnashing of teeth.”", "asv": "but the sons of the kingdom shall be cast forth into the outer darkness: there shall be the weeping and the gnashing of teeth.", "ylt": "but the sons of the reign shall be cast forth to the outer darkness--there shall be the weeping and the gnashing of the teeth.'", "tyndale": "and the chyldren of ye kyngdome shalbe cast out in to vtter darcknes: there shalbe wepinge and gnasshing of tethe.", "dra": "But the children of the kingdom shall be cast out into the exterior darkness: there shall be weeping and gnashing of teeth.", "bbe": "But the sons of the kingdom will be put out into the dark, and there will be weeping and cries of pain.", "geneva": "And the children of the kingdome shall be cast out into vtter darkenes: there shalbe weeping and gnashing of teeth.", "wycliffe": "but the sones of the rewme schulen be cast out in to vtmer derknessis; there schal be wepyng, and grynting of teeth.", "rotherham": "Whereas, the sons of the kingdom, shall be cast forth into the darkness outside,—There, will be wailing and gnashing of teeth.", "weymouth": "while the natural heirs of the Kingdom will be driven out into the darkness outside: there will be the weeping aloud and the gnashing of teeth.\"", "darby": "but the sons of the kingdom shall be cast out into the outer darkness: there shall be the weeping and the gnashing of teeth.", "twenty": "while the heirs to the Kingdom will be ‘banished into the darkness’ outside; there, there will be weeping and grinding of teeth.”", "acv": "but the sons of the kingdom will be cast out into the outer darkness. There will be the weeping and the gnashing of teeth.", "anderson": "but the sons of the kingdom shall be cast into the darkness that is without. There shall be weeping and gnashing of teeth.", "haweis": "But the children of the kingdom shall be cast into the outer darkness: there shall be wailing and gnashing of teeth.", "noyes": "But the sons of the kingdom will go out into the outer darkness; there will be wailing and gnashing of teeth.", "webster": "But the children of the kingdom shall be cast out into utter darkness: there shall be weeping and gnashing of teeth.", "vulgate": "filii autem regni eicientur in tenebras exteriores ibi erit fletus et stridor dentium;"}}, {"v": 13, "ref": "8:13", "o": "καὶ εἶπεν ὁ Ἰησοῦς τῷ ἑκατοντάρχῃ· Ὕπαγε, ⸀ὡς ἐπίστευσας γενηθήτω σοι· καὶ ἰάθη ὁ ⸀παῖς ἐν τῇ ὥρᾳ ἐκείνῃ.", "en": {"kjv": "And Jesus said unto the centurion, Go thy way; and as thou hast believed, so be it done unto thee. And his servant was healed in the selfsame hour.", "web": "Jesus said to the centurion, “Go your way. Let it be done for you as you have believed.” His servant was healed in that hour.", "bsb": "Then Jesus said to the centurion, “Go! As you have believed, so will it be done for you.” And his servant was healed at that very hour.", "asv": "And Jesus said unto the centurion, Go thy way; as thou hast believed, so be it done unto thee. And the servant was healed in that hour.", "ylt": "And Jesus said to the centurion, `Go, and as thou didst believe let it be to thee;' and his young man was healed in that hour.", "tyndale": "The Iesus sayd vnto ye Centurion go thy waye and as thou belevest so be it vnto the. And his servaunt was healed the selfe houre.", "dra": "And Jesus said to the centurion: Go, and as thou hast believed, so be it done to thee. And the servant was healed at the same hour.", "bbe": "And Jesus said to the captain, Go in peace; as your faith is, so let it be done to you. And the servant was made well in that hour.", "geneva": "Then Iesus saide vnto the Centurion, Goe thy way, and as thou hast beleeued, so be it vnto thee, And his seruant was healed the same houre.", "wycliffe": "And Jhesus seide to the centurioun, Go, and as thou hast bileuyd, be it doon to thee. And the child was heelid fro that hour.", "rotherham": "And Jesus said unto the centurion, Withdraw! and, as thou hast believed, be it done for thee. And healed was the servant in that hour.", "weymouth": "And Jesus said to the Captain, \"Go, and just as you have believed, so be it for you.\" And the servant recovered precisely at that time.", "darby": "And Jesus said to the centurion, Go, and as thou hast believed, be it to thee. And his servant was healed in that hour.", "twenty": "Then Jesus said to the Captain: “Go now, and it shall be according to your faith.” And the man was cured that very hour.", "acv": "And Jesus said to the centurion, Go thou. And as thou have believed, be it done to thee. And his boy was healed in that hour.", "anderson": "And Jesus said to the centurion: Go, and as you have believed, so be it to you. And his servant was restored to health in that hour.", "haweis": "And Jesus said to the centurion, Go; and as thou hast believed, be it to thee. And his servant was cured at that very hour.", "noyes": "And Jesus said to the centurion, Go thy way; as thou hast believed, so be it done to thee. And the servant was made well in that hour.", "webster": "And Jesus said to the centurion, Depart; and as thou hast believed, so be it done to thee. And his servant was healed in the same hour.", "vulgate": "et dixit Iesus centurioni vade et sicut credidisti fiat tibi et sanatus est puer in hora illa;"}}, {"v": 14, "ref": "8:14", "o": "Καὶ ἐλθὼν ὁ Ἰησοῦς εἰς τὴν οἰκίαν Πέτρου εἶδεν τὴν πενθερὰν αὐτοῦ βεβλημένην καὶ πυρέσσουσαν·", "en": {"kjv": "And when Jesus was come into Peter’s house, he saw his wife’s mother laid, and sick of a fever.", "web": "When Jesus came into Peter’s house, he saw his wife’s mother lying sick with a fever.", "bsb": "When Jesus arrived at Peter’s house, He saw Peter’s mother-in-law sick in bed with a fever.", "asv": "And when Jesus was come into Peter’s house, he saw his wife’s mother lying sick of a fever.", "ylt": "And Jesus having come into the house of Peter, saw his mother-in-law laid, and fevered,", "tyndale": "And then Iesus went to Peters housse and sawe hys wyves mother lyinge sicke of a fevre", "dra": "And when Jesus was come into Peter's house, he saw his wife's mother lying, and sick of a fever;", "bbe": "And when Jesus had come into Peter's house, he saw his wife's mother in bed, very ill.", "geneva": "And when Iesus came to Peters house, he sawe his wiues mother layed downe, and sicke of a feuer.", "wycliffe": "And whanne Jhesus was comun in to the hous of Symount Petre, he say his wyues modir liggynge, and shakun with feueris.", "rotherham": "And Jesus, coming into the house of Peter, saw his mother-in-law laid prostrate and in a fever,", "weymouth": "After this Jesus went to the house of Peter, whose mother-in-law he found ill in bed with fever.", "darby": "And when Jesus had come to Peter's house, he saw his mother-in-law laid down and in a fever;", "twenty": "When Jesus went into Peter’s house, he saw Peter’s mother-in-law prostrated with fever.", "acv": "And when Jesus came into Peter's house, he saw his mother-in-law, having been laid down, and feverish.", "anderson": "And when Jesus had come into Peter’s house, he saw his mother-in-law lying, and ill of a fever.", "haweis": "And when Jesus was come into the house of Peter, he saw his mother-in-law laid on a bed, and in a fever.", "noyes": "And when Jesus had come into Peter’s house, he saw his wife’s mother lying sick of a fever.", "webster": "And when Jesus had come into Peter's house, he saw his wife's mother laid, and sick with a fever.", "vulgate": "et cum venisset Iesus in domum Petri vidit socrum eius iacentem et febricitantem;"}}, {"v": 15, "ref": "8:15", "o": "καὶ ἥψατο τῆς χειρὸς αὐτῆς, καὶ ἀφῆκεν αὐτὴν ὁ πυρετός, καὶ ἠγέρθη καὶ διηκόνει αὐτῷ.", "en": {"kjv": "And he touched her hand, and the fever left her: and she arose, and ministered unto them.", "web": "He touched her hand, and the fever left her. She got up and served him.", "bsb": "So He touched her hand, and the fever left her, and she got up and began to serve Him.", "asv": "And he touched her hand, and the fever left her; and she arose, and ministered unto him.", "ylt": "and he touched her hand, and the fever left her, and she arose, and was ministering to them.", "tyndale": "and touched her hande and the fevre left hir: and she arose and ministred vnto them.", "dra": "And he touched her hand, and the fever left her, and she arose and ministered to them.", "bbe": "And he put his hand on hers and the disease went from her, and she got up and took care of his needs.", "geneva": "And he touched her hande, and the feuer left her: so she arose, and ministred vnto them.", "wycliffe": "And he touchide hir hoond, and the feuer lefte hir; and she roos, and seruede hem.", "rotherham": "and he touched her hand, and the fever left her,—and she arose, and began ministering unto him.", "weymouth": "He touched her hand and the fever left her: and then she rose and waited upon Him.", "darby": "and he touched her hand, and the fever left her, and she arose and served him.", "twenty": "On his taking her hand, the fever left her, and she rose and began to wait upon him.", "acv": "And he touched her hand, and the fever left her. And she was raised up, and served him.", "anderson": "And he touched her hand, and the fever left her: and she arose and ministered to him.", "haweis": "And he touched her hand, and the fever left her: and she arose, and waited upon them.", "noyes": "And he touched her hand, and the fever left her; and she arose, and waited on him.", "webster": "And he touched her hand, and the fever left her: and she arose, and ministered to them.", "vulgate": "et tetigit manum eius et dimisit eam febris et surrexit et ministrabat eis;"}}, {"v": 16, "ref": "8:16", "o": "Ὀψίας δὲ γενομένης προσήνεγκαν αὐτῷ δαιμονιζομένους πολλούς· καὶ ἐξέβαλεν τὰ πνεύματα λόγῳ, καὶ πάντας τοὺς κακῶς ἔχοντας ἐθεράπευσεν·", "en": {"kjv": "When the even was come, they brought unto him many that were possessed with devils: and he cast out the spirits with his word, and healed all that were sick:", "web": "When evening came, they brought to him many possessed with demons. He cast out the spirits with a word, and healed all who were sick;", "bsb": "When evening came, many who were demon-possessed were brought to Jesus, and He drove out the spirits with a word and healed all the sick.", "asv": "And when even was come, they brought unto him many possessed with demons: and he cast out the spirits with a word, and healed all that were sick:", "ylt": "And evening having come, they brought to him many demoniacs, and he did cast out the spirits with a word, and did heal all who were ill,", "tyndale": "When the eue was come they brought vn to him many yt were possessed with devyllis. And he cast out ye spirites with a worde and healed all yt were sicke", "dra": "And when evening was come, they brought to him many that were possessed with devils: and he cast out the spirits with his word: and all that were sick he healed:", "bbe": "And in the evening, they took to him a number of people who had evil spirits; and he sent the spirits out of them with a word, and made well all who were ill;", "geneva": "When the Euen was come, they brought vnto him many that were possessed with deuils: and he cast out the spirits with his worde, and healed all that were sicke,", "wycliffe": "And whanne it was euen, thei brouyten to hym manye that hadden deuelis, and he castide out spiritis bi word, and heelide alle that weren yuel at ese;", "rotherham": "But, when, evening, came, they brought unto him many demonized,—and he cast out the spirits with a word, and, all who were sick, he cured:", "weymouth": "In the evening many demoniacs were brought to Him, and with a word He expelled the demons; and He cured all the sick,", "darby": "And when the evening was come, they brought to him many possessed by demons, and he cast out the spirits with a word, and healed all that were ill;", "twenty": "In the evening the people brought to Jesus many who were possessed by demons; and he drove out the spirits with a word, and cured all who were ill,", "acv": "And having become evening, they brought to him many being demon possessed. And he cast out the spirits by word, and healed all those faring badly,", "anderson": "When the evening had come, they brought to him many that were possessed with demons: and he cast out the spirits with his word, and cured all that were sick;", "haweis": "And when evening was come, they brought him many possessed by devils: and he cast out the spirits by a word, and all who had illnesses he cured:", "noyes": "And when evening came, they brought to him many that were possessed by demons; and he cast out the spirits with a word, and healed all that were sick;", "webster": "When the evening was come, they brought to him many that were possessed with demons: and he cast out the spirits with [his] word, and healed all that were sick;", "vulgate": "vespere autem facto obtulerunt ei multos daemonia habentes et eiciebat spiritus verbo et omnes male habentes curavit;"}}, {"v": 17, "ref": "8:17", "o": "ὅπως πληρωθῇ τὸ ῥηθὲν διὰ Ἠσαΐου τοῦ προφήτου λέγοντος· Αὐτὸς τὰς ἀσθενείας ἡμῶν ἔλαβεν καὶ τὰς νόσους ἐβάστασεν.", "en": {"kjv": "That it might be fulfilled which was spoken by Esaias the prophet, saying, Himself took our infirmities, and bare our sicknesses.", "web": "that it might be fulfilled which was spoken through Isaiah the prophet, saying: “He took our infirmities, and bore our diseases.”", "bsb": "This was to fulfill what was spoken through the prophet Isaiah: “He took on our infirmities and carried our diseases.”", "asv": "that it might be fulfilled which was spoken through Isaiah the prophet, saying, Himself took our infirmities, and bare our diseases.", "ylt": "that it might be fulfilled that was spoken through Isaiah the prophet, saying, `Himself took our infirmities, and the sicknesses he did bear.'", "tyndale": "to fulfill yt which was spoke by Esayas ye Prophet sayinge. He toke on him oure infirmities and bare oure sickneses.", "dra": "That it might be fulfilled, which was spoken by the prophet Isaias, saying: He took our infirmities, and bore our diseases.", "bbe": "So that the word of Isaiah the prophet might come true: He himself took our pains and our diseases.", "geneva": "That it might be fulfilled, which was spoken by Esaias the Prophet, saying, He tooke our infirmities, and bare our sickenesses.", "wycliffe": "that it were fulfillid, that was seid by Ysaie, the profete, seiynge, He took oure infirmytees, and bar oure siknessis.", "rotherham": "that it might be fulfilled, which was spoken through Isaiah the prophet, saying,—Himself, our weaknesses, took, and, diseases, bare.", "weymouth": "in order that this prediction of the Prophet Isaiah might be fulfilled, \"He took on Him our weaknesses, and bore the burden of our diseases.\"", "darby": "so that that should be fulfilled which was spoken through Esaias the prophet, saying, Himself took our infirmities and bore our diseases.", "twenty": "in fulfilment of these words in the Prophet Isaiah — ‘He took our infirmities on himself, and bore the burden of our diseases.’", "acv": "so that what was spoken through Isaiah the prophet might be fulfilled, which says, He himself took our infirmities, and bore our diseases.", "anderson": "that the word might be fulfilled which was spoken by Isaiah the prophet, saying: He himself took our infirmities, and bore our diseases.", "haweis": "that it might be fulfilled what was spoken by the prophet, “Himself he took our infirmities, and bore our diseases.”", "noyes": "that it might be fulfilled which was spoken through Isaiah the prophet, saying, \"He himself took our infirmities, and bore our diseases.\"", "webster": "That it might be fulfilled which was spoken by Isaiah the prophet, saying, He himself took our infirmities, and bore [our] sicknesses.", "vulgate": "ut adimpleretur quod dictum est per Esaiam prophetam dicentem ipse infirmitates nostras accepit et aegrotationes portavit;"}}, {"v": 18, "ref": "8:18", "o": "Ἰδὼν δὲ ὁ Ἰησοῦς ⸂πολλοὺς ὄχλους⸃ περὶ αὐτὸν ἐκέλευσεν ἀπελθεῖν εἰς τὸ πέραν.", "en": {"kjv": "Now when Jesus saw great multitudes about him, he gave commandment to depart unto the other side.", "web": "Now when Jesus saw great multitudes around him, he gave the order to depart to the other side.", "bsb": "When Jesus saw a large crowd around Him, He gave orders to cross to the other side of the sea.", "asv": "Now when Jesus saw great multitudes about him, he gave commandment to depart unto the other side.", "ylt": "And Jesus having seen great multitudes about him, did command to depart to the other side;", "tyndale": "Whe Iesus sawe moche people about him he comaunded to go over ye water.", "dra": "And Jesus seeing great multitudes about him, gave orders to pass over the water.", "bbe": "Now when Jesus saw a great mass of people about him, he gave an order to go to the other side.", "geneva": "And when Iesus sawe great multitudes of people about him, he commanded them to goe ouer the water.", "wycliffe": "And Jhesus say myche puple aboute him, and bade hise disciplis go ouer the watir.", "rotherham": "Now Jesus, seeing a multitude about him, gave orders to depart unto the other side.", "weymouth": "Seeing great crowds about Him Jesus had given directions to cross to the other side of the Lake,", "darby": "And Jesus, seeing great crowds around him, commanded to depart to the other side.", "twenty": "Seeing a crowd round him, Jesus gave orders to go across.", "acv": "Now when Jesus saw many multitudes around him, he commanded to depart to the other side.", "anderson": "But when Jesus saw many multitudes about him, he gave orders to depart to the other side.", "haweis": "Now when Jesus saw great multitudes about him, he gave orders to pass to the other side.", "noyes": "And Jesus, seeing great multitudes about him, gave orders to depart to the other side.", "webster": "Now when Jesus saw great multitudes about him, he gave commandment to depart to the other side.", "vulgate": "videns autem Iesus turbas multas circum se iussit ire trans fretum;"}}, {"v": 19, "ref": "8:19", "o": "καὶ προσελθὼν εἷς γραμματεὺς εἶπεν αὐτῷ· Διδάσκαλε, ἀκολουθήσω σοι ὅπου ἐὰν ἀπέρχῃ.", "en": {"kjv": "And a certain scribe came, and said unto him, Master, I will follow thee whithersoever thou goest.", "web": "A scribe came, and said to him, “Teacher, I will follow you wherever you go.”", "bsb": "And one of the scribes came to Him and said, “Teacher, I will follow You wherever You go.”", "asv": "And there came a scribe, and said unto him, Teacher, I will follow thee whithersoever thou goest.", "ylt": "and a certain scribe having come, said to him, `Teacher, I will follow thee wherever thou mayest go;'", "tyndale": "And ther came a scribe and sayd vnto hym: master I wyll folowe ye whyther so ever thou goest.", "dra": "And a certain scribe came and said to him: Master, I will follow thee whithersoever thou shalt go.", "bbe": "And there came a scribe and said to him, Master, I will come after you wherever you go.", "geneva": "Then came there a certaine Scribe, and said vnto him, Master, I will follow thee whithersoeuer thou goest.", "wycliffe": "And a scribe neiyede, and seide to hym, Maistir, Y shal sue thee, whidir euer thou schalt go.", "rotherham": "And a certain scribe, coming near, said unto him,—Teacher; I will follow thee, whithersoever Thou goest.", "weymouth": "when a Scribe came and said to Him, \"Teacher, I will follow you wherever you go.\"", "darby": "And a scribe came up and said to him, Teacher, I will follow thee whithersoever thou mayest go.", "twenty": "And a Teacher of the Law came up to him, and said: “Teacher, I will follow you wherever you go.”", "acv": "And a certain scholar having come, he said to him, Teacher, I will follow thee wherever thou may go.", "anderson": "And a certain scribe came and said to him: Teacher, I will follow thee wherever thou goest.", "haweis": "And a certain scribe came, and said unto him, Master, I will follow thee whithersoever thou goest.", "noyes": "And a certain scribe came and said to him, Teacher, I will follow thee wherever thou goest.", "webster": "And a certain scribe came, and said to him, Master, I will follow thee whithersoever thou goest.", "vulgate": "et accedens unus scriba ait illi magister sequar te quocumque ieris;"}}, {"v": 20, "ref": "8:20", "o": "καὶ λέγει αὐτῷ ὁ Ἰησοῦς· Αἱ ἀλώπεκες φωλεοὺς ἔχουσιν καὶ τὰ πετεινὰ τοῦ οὐρανοῦ κατασκηνώσεις, ὁ δὲ υἱὸς τοῦ ἀνθρώπου οὐκ ἔχει ποῦ τὴν κεφαλὴν κλίνῃ.", "en": {"kjv": "And Jesus saith unto him, The foxes have holes, and the birds of the air have nests; but the Son of man hath not where to lay his head.", "web": "Jesus said to him, “The foxes have holes, and the birds of the sky have nests, but the Son of Man has nowhere to lay his head.”", "bsb": "Jesus replied, “Foxes have dens and birds of the air have nests, but the Son of Man has no place to lay His head.”", "asv": "And Jesus saith unto him, The foxes have holes, and the birds of the heaven have nests; but the Son of man hath not where to lay his head.", "ylt": "and Jesus saith to him, `The foxes have holes, and the birds of the heaven places of rest, but the Son of Man hath not where he may lay the head.'", "tyndale": "And Iesus sayd vnto him: the foxes have holes and the bryddes of the ayer have nestes but ye sonne of the man hath not whero to rest his heede.", "dra": "And Jesus saith to him: The foxes have holes, and the birds of the air nests; but the Son of man hath not where to lay his head.", "bbe": "And Jesus said to him, The foxes have holes, and the birds of heaven have a resting-place; but the Son of man has nowhere to put his head.", "geneva": "But Iesus saide vnto him, The foxes haue holes, and the birdes of the heauen haue nestes, but the Sonne of man hath not whereon to rest his head.", "wycliffe": "And Jhesus seide to hym, Foxis han dennes, and briddis of heuene han nestis, but mannus sone hath not where `he schal reste his heed.", "rotherham": "And Jesus saith unto him: The foxes, have, dens, and, the birds of the heavens, nests,—but, the Son of Man, hath not where, his head he may recline.", "weymouth": "\"Foxes have holes,\" replied Jesus, \"and birds have nests; but the Son of Man has nowhere to lay His head.\"", "darby": "And Jesus says to him, The foxes have holes, and the birds of the heaven roosting-places; but the Son of man has not where he may lay his head.", "twenty": "“Foxes have holes,” answered Jesus, “and wild birds their roosting-places, but the Son of Man has nowhere to lay his head.”", "acv": "And Jesus says to him, The foxes have holes, and the birds of the sky, nests, but the Son of man has nowhere he may lay his head.", "anderson": "And Jesus said to him: The foxes have dens, and the birds of the air have roosts; but the Son of man has not where to lay his head.", "haweis": "And Jesus said unto him, The foxes have holes, and the birds of the air have nests; but the Son of man hath not where he can lay his head.", "noyes": "And Jesus saith to him, The foxes have holes, and the birds of the air have lodging-places; but the Son of man hath not where to lay his head.", "webster": "And Jesus saith to him, The foxes have holes, and the birds of the air [have] nests; but the Son of man hath not where to lay [his] head.", "vulgate": "et dicit ei Iesus vulpes foveas habent et volucres caeli tabernacula Filius autem hominis non habet ubi caput reclinet;"}}, {"v": 21, "ref": "8:21", "o": "ἕτερος δὲ τῶν ⸀μαθητῶν εἶπεν αὐτῷ· Κύριε, ἐπίτρεψόν μοι πρῶτον ἀπελθεῖν καὶ θάψαι τὸν πατέρα μου.", "en": {"kjv": "And another of his disciples said unto him, Lord, suffer me first to go and bury my father.", "web": "Another of his disciples said to him, “Lord, allow me first to go and bury my father.”", "bsb": "Another of His disciples requested, “Lord, first let me go and bury my father.”", "asv": "And another of the disciples said unto him, Lord, suffer me first to go and bury my father.", "ylt": "And another of his disciples said to him, `Sir, permit me first to depart and to bury my father;'", "tyndale": "A nothre yt was one of hys disciples sayd vnto hym: master suffre me fyrst to go and burye my father.", "dra": "And another of his disciples said to him: Lord, suffer me first to go and bury my father.", "bbe": "And another of the disciples said to him, Lord, let me first go and give the last honours to my father.", "geneva": "And another of his disciples saide vnto him, Master, suffer me first to goe, and burie my father.", "wycliffe": "Anothir of his disciplis seide to him, Lord, suffre me to go first, and birie my fader.", "rotherham": "And, another of the disciples, saith unto him,—Lord! suffer me, first, to depart, and bury my father.", "weymouth": "Another of the disciples said to Him, \"Sir, allow me first to go and bury my father.\"", "darby": "But another of his disciples said to him, Lord, suffer me first to go away and bury my father.", "twenty": "“Master,” said another, who was a disciple, “let me first go and bury my father.”", "acv": "And another of his disciples said to him, Lord, allow me first to go and bury my father.", "anderson": "And another of his disciples said to him: Lord, permit me first to go and bury my father.", "haweis": "And another of his disciples said unto him, Permit me first to go and bury my father.", "noyes": "And another of the disciples said to him, Lord, suffer me first to go and bury my father.", "webster": "And another of his disciples said to him, Lord, suffer me first to go and bury my father.", "vulgate": "alius autem de discipulis eius ait illi Domine permitte me primum ire et sepelire patrem meum;"}}, {"v": 22, "ref": "8:22", "o": "ὁ δὲ Ἰησοῦς ⸀λέγει αὐτῷ· Ἀκολούθει μοι, καὶ ἄφες τοὺς νεκροὺς θάψαι τοὺς ἑαυτῶν νεκρούς.", "en": {"kjv": "But Jesus said unto him, Follow me; and let the dead bury their dead.", "web": "But Jesus said to him, “Follow me, and leave the dead to bury their own dead.”", "bsb": "But Jesus told him, “Follow Me, and let the dead bury their own dead.”", "asv": "But Jesus saith unto him, Follow me; and leave the dead to bury their own dead.", "ylt": "and Jesus said to him, `Follow me, and suffer the dead to bury their own dead.'", "tyndale": "But Iesus sayd vnto him: folowe me and let the deed burie their deed.", "dra": "But Jesus said to him: Follow me, and let the dead bury their dead.", "bbe": "But Jesus said to him, Come after me; and let the dead take care of their dead.", "geneva": "But Iesus said vnto him, Followe me, and let the dead burie their dead.", "wycliffe": "But Jhesus seide to hym, Sue thou me, and lete deed men birie her deede men.", "rotherham": "But, Jesus, saith unto him,—Be following me, and leave, the dead, to bury, their own dead.", "weymouth": "\"Follow me,\" said Jesus, \"and leave the dead to bury their own dead.\"", "darby": "But Jesus said to him, Follow me, and leave the dead to bury their own dead.", "twenty": "But Jesus answered: “Follow me, and leave the dead to bury their dead.”", "acv": "But Jesus said to him, Follow me, and leave the dead to bury their own dead.", "anderson": "But Jesus said to him: Follow me, and let the dead bury their own dead.", "haweis": "And Jesus said unto him, Follow me; and let the dead bury their own dead.", "noyes": "But he saith to him, Follow me, and let the dead bury their own dead.", "webster": "But Jesus said to him, Follow me; and let the dead bury their dead.", "vulgate": "Iesus autem ait illi sequere me et dimitte mortuos sepelire mortuos suos;"}}, {"v": 23, "ref": "8:23", "o": "Καὶ ἐμβάντι αὐτῷ ⸀εἰς πλοῖον ἠκολούθησαν αὐτῷ οἱ μαθηταὶ αὐτοῦ.", "en": {"kjv": "And when he was entered into a ship, his disciples followed him.", "web": "When he got into a boat, his disciples followed him.", "bsb": "When He got into the boat, His disciples followed Him.", "asv": "And when he was entered into a boat, his disciples followed him.", "ylt": "And when he entered into the boat his disciples did follow him,", "tyndale": "And he entred in to a shyppe and his disciples folowed him.", "dra": "And when he entered into the boat, his disciples followed him:", "bbe": "And when he had got into a boat, his disciples went after him.", "geneva": "And when he was entred into ye ship, his disciples followed him.", "wycliffe": "And whanne he was goon vp in to a litil schip, his disciplis sueden hym.", "rotherham": "And, when he, entered, into a boat, his disciples followed him.", "weymouth": "Then He went on board a fishing-boat, and His disciples followed Him.", "darby": "And he went on board ship and his disciples followed him;", "twenty": "Then he got into the boat, followed by his disciples.", "acv": "And upon his entering into the boat, his disciples followed him.", "anderson": "And when he had entered the ship, his disciples followed him.", "haweis": "And going on board a vessel, his disciples followed him.", "noyes": "And when he had gone on board the boat, his disciples followed him.", "webster": "And when he had entered into a boat, his disciples followed him.", "vulgate": "et ascendente eo in navicula secuti sunt eum discipuli eius;"}}, {"v": 24, "ref": "8:24", "o": "καὶ ἰδοὺ σεισμὸς μέγας ἐγένετο ἐν τῇ θαλάσσῃ, ὥστε τὸ πλοῖον καλύπτεσθαι ὑπὸ τῶν κυμάτων, αὐτὸς δὲ ἐκάθευδεν.", "en": {"kjv": "And, behold, there arose a great tempest in the sea, insomuch that the ship was covered with the waves: but he was asleep.", "web": "Behold, a violent storm came up on the sea, so much that the boat was covered with the waves, but he was asleep.", "bsb": "Suddenly a violent storm came up on the sea, so that the boat was engulfed by the waves; but Jesus was sleeping.", "asv": "And behold, there arose a great tempest in the sea, insomuch that the boat was covered with the waves: but he was asleep.", "ylt": "and lo, a great tempest arose in the sea, so that the boat was being covered by the waves, but he was sleeping,", "tyndale": "And beholde there arose a a greate tepest in ye see in so moche yt the shippe was covered wt waves and he was a slepe.", "dra": "And behold a great tempest arose in the sea, so that the boat was covered with waves, but he was asleep.", "bbe": "And there came up a great storm in the sea, so that the boat was covered with the waves: but he was sleeping.", "geneva": "And beholde, there arose a great tempest in the sea, so that the ship was couered with waues: but he was a sleepe.", "wycliffe": "And loo! a greet stiring was maad in the see, so that the schip was hilid with wawes; but he slepte.", "rotherham": "And lo! a great squall, arose in the sea, so that, the boat, was being covered, by the waves,—but, he, was sleeping.", "weymouth": "But suddenly there arose a great storm on the Lake, so that the waves threatened to engulf the boat; but He was asleep.", "darby": "and behold, [the water] became very agitated on the sea, so that the ship was covered by the waves; but he slept.", "twenty": "Suddenly so great a storm came on upon the Sea, that the waves broke right over the boat. But Jesus was asleep;", "acv": "And behold, a great tempest developed in the sea, so as for the boat to be covered by the waves, but he was sleeping.", "anderson": "And behold, there was a great tempest in the sea, so that the ship was covered by the waves: but he was asleep.", "haweis": "And, behold, there was a great tempest in the sea, so that the vessel was hid by the waves; but he was asleep.", "noyes": "And, lo! a great tempest arose on the lake, so that the boat was almost covered by the waves; but he was sleeping.", "webster": "And behold, there arose a great tempest in the sea, insomuch that the boat was covered with the waves: but he was asleep.", "vulgate": "et ecce motus magnus factus est in mari ita ut navicula operiretur fluctibus ipse vero dormiebat;"}}, {"v": 25, "ref": "8:25", "o": "καὶ ⸀προσελθόντες ἤγειραν αὐτὸν λέγοντες· Κύριε, ⸀σῶσον, ἀπολλύμεθα.", "en": {"kjv": "And his disciples came to him, and awoke him, saying, Lord, save us: we perish.", "web": "They came to him, and woke him up, saying, “Save us, Lord! We are dying!”", "bsb": "The disciples went and woke Him, saying, “Lord, save us! We are perishing!”", "asv": "And they came to him, and awoke him, saying, Save, Lord; we perish.", "ylt": "and his disciples having come to him, awoke him, saying, `Sir, save us; we are perishing.'", "tyndale": "And his disciples came vn to him and awoke hym sayinge: master save vs we perishe.", "dra": "And they came to him, and awaked him, saying: Lord, save us, we perish.", "bbe": "And they came to him, and, awaking him, said, Help, Lord; destruction is near.", "geneva": "Then his disciples came, and awoke him, saying, Master, saue vs: we perish.", "wycliffe": "And hise disciplis camen to hym, and reysiden hym, and seiden, Lord, saue vs; we perischen.", "rotherham": "And, coming near, they aroused him, saying, Master! save, we perish!", "weymouth": "So they came and woke Him, crying, \"Master, save us, we are drowning!\"", "darby": "And the disciples came and awoke him, saying, Lord save: we perish.", "twenty": "and the disciples came and roused him. “Master,” they cried, “save us; we are lost!”", "acv": "And the disciples having approached, they awoke him, saying, Save us, Lord, we are perishing.", "anderson": "And his disciples came to him, and awoke him, saying: Lord, save us; we perish.", "haweis": "And his disciples coming, awoke him, saying, Lord, save us: we are perishing!", "noyes": "And they came and awoke him, saying, Lord, save! we are perishing.", "webster": "And his disciples came to [him], and awoke him, saying, Lord, save us: we perish.", "vulgate": "et accesserunt et suscitaverunt eum dicentes Domine salva nos perimus;"}}, {"v": 26, "ref": "8:26", "o": "καὶ λέγει αὐτοῖς· Τί δειλοί ἐστε, ὀλιγόπιστοι; τότε ἐγερθεὶς ἐπετίμησεν τοῖς ἀνέμοις καὶ τῇ θαλάσσῃ, καὶ ἐγένετο γαλήνη μεγάλη.", "en": {"kjv": "And he saith unto them, Why are ye fearful, O ye of little faith? Then he arose, and rebuked the winds and the sea; and there was a great calm.", "web": "He said to them, “Why are you fearful, O you of little faith?” Then he got up, rebuked the wind and the sea, and there was a great calm.", "bsb": "“You of little faith,” Jesus replied, “why are you so afraid?” Then He got up and rebuked the winds and the sea, and it was perfectly calm.", "asv": "And he saith unto them, Why are ye fearful, O ye of little faith? Then he arose, and rebuked the winds and the sea; and there was a great calm.", "ylt": "And he saith to them, `Why are ye fearful, O ye of little faith?' Then having risen, he rebuked the winds and the sea, and there was a great calm;", "tyndale": "And he sayd vnto them: why are ye fearfull o ye of lytell faithe? Then he arose and rebuked ye wyndes and the see and ther folowed a greate calme.", "dra": "And Jesus saith to them: Why are you fearful, O ye of little faith? Then rising up, he commanded the winds, and the sea, and there came a great calm.", "bbe": "And he said to them, Why are you full of fear, O you of little faith? Then he got up and gave orders to the winds and the sea; and there was a great calm.", "geneva": "And he said vnto them, Why are ye fearefull, O ye of litle faith? Then he arose, and rebuked the winds and the sea: and so there was a great calme.", "wycliffe": "And Jhesus seide to hem, What ben ye of litil feith agaste? Thanne he roos, and comaundide to the wyndis and the see, and a greet pesibilnesse was maad.", "rotherham": "And he saith unto them, Why, are ye, fearful, little of faith? Then, aroused, he rebuked the winds and the sea,—and it became a great calm.", "weymouth": "\"Why are you so easily frightened,\" He replied, \"you men of little faith?\" Then He rose and reproved the winds and the waves, and there was a perfect calm;", "darby": "And he says to them, Why are ye fearful, O ye of little faith? Then, having arisen, he rebuked the winds and the sea, and there was a great calm.", "twenty": "“Why are you so timid?” he said. “O men of little faith!” Then Jesus rose and rebuked the winds and the sea, and a great calm followed.", "acv": "And he says to them, Why are ye cowardly, O ye of little faith? Then after rising, he rebuked the winds and the sea, and there became a great calm.", "anderson": "And he said to them: Why are you fearful, O you of little faith? Then he arose, and rebuked the winds and the sea: and there was a great calm.", "haweis": "And he said unto them, Why are ye fearful, O ye of little faith? Then arising, he issued his mandate to the winds, and to the sea; and there was a great calm.", "noyes": "And he saith to them, Why are ye fearful, ye of little faith? Then he arose, and rebuked the winds and the waves; and there was a great calm.", "webster": "And he saith to them, Why are ye fearful, O ye of little faith? Then he arose, and rebuked the winds and the sea; and there was a great calm.", "vulgate": "et dicit eis quid timidi estis modicae fidei tunc surgens imperavit ventis et mari et facta est tranquillitas magna;"}}, {"v": 27, "ref": "8:27", "o": "οἱ δὲ ἄνθρωποι ἐθαύμασαν λέγοντες· Ποταπός ἐστιν οὗτος ὅτι καὶ οἱ ἄνεμοι καὶ ἡ θάλασσα ⸂αὐτῷ ὑπακούουσιν⸃;", "en": {"kjv": "But the men marvelled, saying, What manner of man is this, that even the winds and the sea obey him!", "web": "The men marveled, saying, “What kind of man is this, that even the wind and the sea obey him?”", "bsb": "The men were amazed and asked, “What kind of man is this? Even the winds and the sea obey Him!”", "asv": "And the men marvelled, saying, What manner of man is this, that even the winds and the sea obey him?", "ylt": "and the men wondered, saying, `What kind--is this, that even the wind and the sea do obey him?'", "tyndale": "And the men marveyled and sayd: what man is this that bothe wyndes and see obey hym?", "dra": "But the men wondered, saying: What manner of man is this, for the winds and the sea obey him?", "bbe": "And the men were full of wonder, saying, What sort of man is this, that even the winds and the sea do his orders?", "geneva": "And the men marueiled, saying, What man is this, that both the windes and the sea obey him!", "wycliffe": "And men wondriden, and seiden, What maner man is he this, for the wyndis and the see obeischen to him?", "rotherham": "But, the men, marveled, saying, Whence is this one,—that, both the winds and the sea, unto him, give ear?", "weymouth": "and the men, filled with amazement, exclaimed, \"What kind of man is this? for the very winds and waves obey him!\"", "darby": "But the men were astonished, saying, What sort [of man] is this, that even the winds and the sea obey him?", "twenty": "The men were amazed, and exclaimed: “What kind of man is this, that even the winds and the sea obey him!”", "acv": "But the men marveled, saying, What kind of man is this, that even the winds and the sea obey him?", "anderson": "But the men were astonished, and said: What man is this, that even the winds and the sea obey him!", "haweis": "And the men marvelled, saying, What a wondrous man is this, that even the winds and the sea obey him!", "noyes": "And the men marveled, saying, What manner of man is this, that even the winds and the waves obey him?", "webster": "But the men marveled, saying, What manner of man is this, that even the winds and the sea obey him!", "vulgate": "porro homines mirati sunt dicentes qualis est hic quia et venti et mare oboediunt ei;"}}, {"v": 28, "ref": "8:28", "o": "Καὶ ⸂ἐλθόντος αὐτοῦ⸃ εἰς τὸ πέραν εἰς τὴν χώραν τῶν ⸀Γαδαρηνῶν ὑπήντησαν αὐτῷ δύο δαιμονιζόμενοι ἐκ τῶν μνημείων ἐξερχόμενοι, χαλεποὶ λίαν ὥστε μὴ ἰσχύειν τινὰ παρελθεῖν διὰ τῆς ὁδοῦ ἐκείνης.", "en": {"kjv": "And when he was come to the other side into the country of the Gergesenes, there met him two possessed with devils, coming out of the tombs, exceeding fierce, so that no man might pass by that way.", "web": "When he came to the other side, into the country of the Gergesenes, two people possessed by demons met him there, coming out of the tombs, exceedingly fierce, so that nobody could pass that way.", "bsb": "When Jesus arrived on the other side in the region of the Gadarenes, He was met by two demon-possessed men coming from the tombs. They were so violent that no one could pass that way.", "asv": "And when he was come to the other side into the country of the Gadarenes, there met him two possessed with demons, coming forth out of the tombs, exceeding fierce, so that no man could pass by that way.", "ylt": "And he having come to the other side, to the region of the Gergesenes, there met him two demoniacs, coming forth out of the tombs, very fierce, so that no one was able to pass over by that way,", "tyndale": "And when he was come to ye other syde in to ye coutre of ye Gergesites ther met him two possessed of devylles which came out of the graves and were out of measure fearce so yt no ma myght go by that waye.", "dra": "And when he was come on the other side of the water, into the country of the Gerasens, there met him two that were possessed with devils, coming out of the sepulchres, exceeding fierce, so that none could pass by that way.", "bbe": "And when he had come to the other side, to the country of the Gadarenes, there came out to him from the place of the dead, two who had evil spirits, so violent that no man was able to go that way.", "geneva": "And when he was come to the other side into ye countrey of the Gergesenes, there met him two possessed with deuils, which came out of the graues very fierce, so that no man might goe by that way.", "wycliffe": "And whanne Jhesus was comun ouer the watir in to the cuntre of men of Gerasa, twey men metten hym, that hadden deuelis, and camen out of graues, ful woode, so that noo man myyte go bi that weie.", "rotherham": "And, when he, came, unto the other side, into the country of the Gadarenes, there met him, two men demonized, out of the tombs, coming forth,—fierce exceedingly, so that no one could pass that way;", "weymouth": "On His arrival at the other side, in the country of the Gadarenes, there met Him two men possessed by demons, coming from among the tombs: they were so dangerously fierce that no one was able to pass that way.", "darby": "And there met him, when he came to the other side, to the country of the Gergesenes, two possessed by demons, coming out of the tombs, exceeding dangerous, so that no one was able to pass by that way.", "twenty": "And on getting to the other side — the country of the Gadarenes — Jesus met two men who were possessed by demons, coming out of the tombs. They were so violent that no one was able to pass that way.", "acv": "And upon his coming to the other side, into the country of the Gergesenes, two men being demon possessed met him, coming out of the sepulchers, exceedingly fierce, so that no man could pass by that way.", "anderson": "And when he had come to the opposite side, into the country of the Gadarenes, there met him two men, coming out of the tombs, possessed with demons, very fierce, so that no one could pass that way.", "haweis": "And when he came to the other side, into the region of the Girgasenes, there met him two demoniacs, coming from the sepulchres; exceeding fierce, so that no person was able to pass by that road.", "noyes": "And when he had come to the other side, into the country of the Gadarenes, there met him two men possessed by demons, coming out of the tombs, exceedingly fierce, so that no one could pass by that way.", "webster": "And when he had come to the other side, into the country of the Gergesenes, there met him two possessed with demons, coming out of the tombs, exceeding fierce, so that no man might pass by that way.", "vulgate": "et cum venisset trans fretum in regionem Gerasenorum occurrerunt ei duo habentes daemonia de monumentis exeuntes saevi nimis ita ut nemo posset transire per viam illam;"}}, {"v": 29, "ref": "8:29", "o": "καὶ ἰδοὺ ἔκραξαν λέγοντες· Τί ἡμῖν καὶ ⸀σοί, υἱὲ τοῦ θεοῦ; ἦλθες ὧδε πρὸ καιροῦ βασανίσαι ἡμᾶς;", "en": {"kjv": "And, behold, they cried out, saying, What have we to do with thee, Jesus, thou Son of God? art thou come hither to torment us before the time?", "web": "Behold, they cried out, saying, “What do we have to do with you, Jesus, Son of God? Have you come here to torment us before the time?”", "bsb": "“What do You want with us, Son of God?” they shouted. “Have You come here to torture us before the appointed time?”", "asv": "And behold, they cried out, saying, What have we to do with thee, thou Son of God? art thou come hither to torment us before the time?", "ylt": "and lo, they cried out, saying, `What--to us and to thee, Jesus, Son of God? didst thou come hither, before the time, to afflict us?'", "tyndale": "And behold they cryed out sayinge: O Iesu the sonne of God what have we to do with the? Art thou come hyther to tormet vs before the tyme be come?", "dra": "And behold they cried out, saying: What have we to do with thee, Jesus Son of God? art thou come hither to torment us before the time?", "bbe": "And they gave a loud cry, saying, What have we to do with you, you Son of God? Have you come here to give us punishment before the time?", "geneva": "And beholde, they cryed out, saying, Iesus the sonne of God, what haue we to do with thee? Art thou come hither to tormet vs before ye time?", "wycliffe": "And lo! thei crieden, and seiden, What to vs and to thee, Jhesu, the sone of God? `art thou comun hidir bifore the tyme to turmente vs?", "rotherham": "and lo! they cried aloud, saying, What have we in common with thee, O Son of God? Hast thou come hither, before the right time, to torment us?", "weymouth": "They cried aloud, \"What hast Thou to do with us, Thou Son of God? Hast Thou come here to torment us before the time?\"", "darby": "And behold, they cried out, saying, What have we to do with thee, Son ofGod? hast thou come here before the time to torment us?", "twenty": "Suddenly they shrieked out: “What do you want with us, Son of God? Have you come here to torment us before our time?”", "acv": "And behold, they cried out, saying, What is with us and thee, Jesus, Son of God? Did thou come here before the time to torment us?", "anderson": "And behold, they cried out, saying: What have we to do with thee, Jesus, Son of God? Hast thou come hither to torment us before the time?", "haweis": "And lo! they cried out, saying, What have we to do with thee, Jesus, thou Son of God? art thou come hither before the time to torment us?", "noyes": "And lo! they cried out, saying, What have we to do with thee, Son of God? Didst thou come here to torment us before the time?", "webster": "And behold, they cried out, saying, What have we [to do] with thee, Jesus, [thou] Son of God? art thou come hither to torment us before the time?", "vulgate": "et ecce clamaverunt dicentes quid nobis et tibi Fili Dei venisti huc ante tempus torquere nos;"}}, {"v": 30, "ref": "8:30", "o": "ἦν δὲ μακρὰν ἀπ’ αὐτῶν ἀγέλη χοίρων πολλῶν βοσκομένη.", "en": {"kjv": "And there was a good way off from them an herd of many swine feeding.", "web": "Now there was a herd of many pigs feeding far away from them.", "bsb": "In the distance a large herd of pigs was feeding.", "asv": "Now there was afar off from them a herd of many swine feeding.", "ylt": "And there was far off from them a herd of many swine feeding,", "tyndale": "And ther was a good waye of fro them a greate heerd of swyne fedinge.", "dra": "And there was, not far from them, a herd of many swine feeding.", "bbe": "Now there was, some distance away, a great herd of pigs taking their food.", "geneva": "Nowe there was, afarre off from them, a great heard of swine feeding.", "wycliffe": "And not fer fro hem was a flocke of many swyne lesewynge.", "rotherham": "Now there was, far from them, a herd of many swine, feeding;", "weymouth": "Now at some distance from them a vast herd of swine were feeding.", "darby": "Now there was, a great way off from them, a herd of many swine feeding;", "twenty": "A long way off, there was a drove of many pigs, feeding;", "acv": "Now there was afar off from them a herd of many swine feeding.", "anderson": "Now there was, at a distance from them, a herd of many swine, feeding.", "haweis": "And at a considerable distance, there was a great herd of swine feeding.", "noyes": "Now there was at a distance from them a herd of many swine feeding.", "webster": "And there was a good way off from them a herd of many swine, feeding.", "vulgate": "erat autem non longe ab illis grex porcorum multorum pascens;"}}, {"v": 31, "ref": "8:31", "o": "οἱ δὲ δαίμονες παρεκάλουν αὐτὸν λέγοντες· Εἰ ἐκβάλλεις ἡμᾶς, ⸂ἀπόστειλον ἡμᾶς⸃ εἰς τὴν ἀγέλην τῶν χοίρων.", "en": {"kjv": "So the devils besought him, saying, If thou cast us out, suffer us to go away into the herd of swine.", "web": "The demons begged him, saying, “If you cast us out, permit us to go away into the herd of pigs.”", "bsb": "So the demons begged Jesus, “If You drive us out, send us into the herd of pigs.”", "asv": "And the demons besought him, saying, If thou cast us out, send us away into the herd of swine.", "ylt": "and the demons were calling on him, saying, `If thou dost cast us forth, permit us to go away to the herd of the swine;'", "tyndale": "Then ye devyles besought him sayinge: if thou cast vs out suffre vs to go oure waye in to the heerd of swyne.", "dra": "And the devils besought him, saying: If thou cast us out hence, send us into the herd of swine.", "bbe": "And the evil spirits made strong prayers to him, saying, If you send us out, let us go into the herd of pigs.", "geneva": "And the deuils besought him, saying, If thou cast vs out, suffer vs to goe into the heard of swine.", "wycliffe": "And the deuelis preyeden hym, and seiden, If thou castist out vs fro hennes, sende vs in to the droue of swyne.", "rotherham": "and, the demons, began to beseech him, saying, If thou dost cast us out, send us away, into the herd of swine.", "weymouth": "So the demons entreated Him. \"If Thou drivest us out,\" they said, \"send us into the herd of swine.\"", "darby": "and the demons besought him, saying, If thou cast us out, send us away into the herd of swine.", "twenty": "and the foul spirits began begging Jesus: “If you drive us out, send us into the drove of pigs.”", "acv": "And the demons besought him, saying, If thou cast us out, allow us to go away into the herd of swine.", "anderson": "And the demons besought him, saying: If thou cast us out, permit us to go away into the herd of swine.", "haweis": "Then the devils besought him, saying, If thou cast us out, permit us to go into the herd of swine.", "noyes": "And the demons besought him, saying, If thou cast us out, send us into the herd of swine.", "webster": "So the demons besought him, saying, If thou expellest us, suffer us to go away into the herd of swine.", "vulgate": "daemones autem rogabant eum dicentes si eicis nos mitte nos in gregem porcorum;"}}, {"v": 32, "ref": "8:32", "o": "καὶ εἶπεν αὐτοῖς· Ὑπάγετε. οἱ δὲ ἐξελθόντες ἀπῆλθον εἰς ⸂τοὺς χοίρους⸃· καὶ ἰδοὺ ὥρμησεν πᾶσα ἡ ⸀ἀγέλη κατὰ τοῦ κρημνοῦ εἰς τὴν θάλασσαν, καὶ ἀπέθανον ἐν τοῖς ὕδασιν.", "en": {"kjv": "And he said unto them, Go. And when they were come out, they went into the herd of swine: and, behold, the whole herd of swine ran violently down a steep place into the sea, and perished in the waters.", "web": "He said to them, “Go!” They came out, and went into the herd of pigs: and behold, the whole herd of pigs rushed down the cliff into the sea, and died in the water.", "bsb": "“Go!” He told them. So they came out and went into the pigs, and the whole herd rushed down the steep bank into the sea and died in the waters.", "asv": "And he said unto them, Go. And they came out, and went into the swine: and behold, the whole herd rushed down the steep into the sea, and perished in the waters.", "ylt": "and he saith to them, `Go.' And having come forth, they went to the herd of the swine, and lo, the whole herd of the swine rushed down the steep, to the sea, and died in the waters,", "tyndale": "And he sayd vnto the: go youre wayes. Then wet they out and departed into ye heerd of swyne And beholde ye whoale heerd of swyne was caryed wt violence hedlinge in to the see and perisshed in ye water.", "dra": "And he said to them: Go. But they going out went into the swine, and behold the whole herd ran violently down a steep place into the sea: and they perished in the waters.", "bbe": "And he said to them, Go. And they came out, and went into the pigs; and the herd went rushing down a sharp slope into the sea and came to their end in the water.", "geneva": "And he said vnto them, Go. So they went out and departed into the heard of swine: and beholde, the whole heard of swine ranne headlong into the sea, and died in the water.", "wycliffe": "And he seide to hem, Go ye. And thei yeden out, and wenten in to the swyne; and loo! in a greet bire al the droue wente heedlyng in to the see, and thei weren deed in the watris.", "rotherham": "And he said unto them, Withdraw! So, they, going out, departed into the swine,—and lo! all the herd rushed down the cliff, into the sea, and died in the waters.", "weymouth": "\"Go,\" He replied. Then they came out from the men and went into the swine, whereupon the entire herd instantly rushed down the cliff into the Lake and perished in the water.", "darby": "And he said to them, Go. And they, going out, departed into the herd of swine; and lo, the whole herd [of swine] rushed down the steep slope into the sea, and died in the waters.", "twenty": "“Go,” he said. The spirits came out, and entered the pigs; and the whole drove rushed down the steep slope into the Sea, and died in the water.", "acv": "And he said to them, Go. And having come out, they went into the herd of swine. And behold, the whole herd of the swine stampeded down the slope into the sea, and perished in the waters.", "anderson": "And he said to them: Go. And when they had come out, they went away into the herd of swine. And behold, the whole herd of swine rushed down a steep place into the sea, and perished in the waters.", "haweis": "And he said to them, Go. Then they going forth out of him, entered into the herd of swine: and lo! the whole herd of the swine rushed down a precipice into the sea, and perished in the waters.", "noyes": "And he said to them, Go. And they came out, and went into the swine. And lo! the whole herd rushed down the steep into the lake, and perished in the waters.", "webster": "And he said to them, Go. And when they had come out, they went into the herd of swine: and behold, the whole herd of swine ran violently down a steep place into the sea, and perished in the waters.", "vulgate": "et ait illis ite at illi exeuntes abierunt in porcos et ecce impetu abiit totus grex per praeceps in mare et mortui sunt in aquis;"}}, {"v": 33, "ref": "8:33", "o": "οἱ δὲ βόσκοντες ἔφυγον, καὶ ἀπελθόντες εἰς τὴν πόλιν ἀπήγγειλαν πάντα καὶ τὰ τῶν δαιμονιζομένων.", "en": {"kjv": "And they that kept them fled, and went their ways into the city, and told every thing, and what was befallen to the possessed of the devils.", "web": "Those who fed them fled, and went away into the city, and told everything, including what happened to those who were possessed with demons.", "bsb": "Those tending the pigs ran off into the town and reported all this, including the account of the demon-possessed men.", "asv": "And they that fed them fled, and went away into the city, and told everything, and what was befallen to them that were possessed with demons.", "ylt": "and those feeding did flee, and, having gone to the city, they declared all, and the matter of the demoniacs.", "tyndale": "Then ye heerdme fleed and wet their ways in to ye cyte and tolde every thinge and what had fortuned vnto the possessed of the devyls.", "dra": "And they that kept them fled: and coming into the city, told every thing, and concerning them that had been possessed by the devils.", "bbe": "And their keepers went in flight to the town and gave an account of everything, and of the men who had the evil spirits.", "geneva": "Then the heardmen fled: and when they were come into the citie, they tolde all things, and what was become of them that were possessed with the deuils.", "wycliffe": "And the hirdis fledden awey, and camen in to the citee, and telden alle these thingis, and of hem that hadden the feendis.", "rotherham": "And, they who were feeding them, fled,—and, departing into the city, reported all things, and what concerned them who had been demonized.", "weymouth": "The swineherds fled, and went and told the whole story in the town, including what had happened to the demoniacs.", "darby": "But they that fed them fled, and went away into the city and related everything, and what had happened as to those possessed by demons.", "twenty": "At this the men who tended them ran away and went to the town, carrying the news of all that had occurred, and of what had happened to the possessed men.", "acv": "And those who tended them fled, and having gone into the city, they told everything, also the things of the men being demon possessed.", "anderson": "And those who fed them fled, and went into the city, and told every thing, and what had happened to those who had been possessed with the demons.", "haweis": "But they who fed them fled, and going away into the city, reported all things, and what had happened to the demoniacs.", "noyes": "And the herdsmen fled, and went away into the city, and told everything, and what had happened to the men possessed by demons.", "webster": "And they that kept them, fled, and went into the city, and told every thing; and what had befallen to the possessed with demons.", "vulgate": "pastores autem fugerunt et venientes in civitatem nuntiaverunt omnia et de his qui daemonia habuerant;"}}, {"v": 34, "ref": "8:34", "o": "καὶ ἰδοὺ πᾶσα ἡ πόλις ἐξῆλθεν εἰς ⸀ὑπάντησιν τῷ Ἰησοῦ, καὶ ἰδόντες αὐτὸν παρεκάλεσαν ὅπως μεταβῇ ἀπὸ τῶν ὁρίων αὐτῶν.", "en": {"kjv": "And, behold, the whole city came out to meet Jesus: and when they saw him, they besought him that he would depart out of their coasts.", "web": "Behold, all the city came out to meet Jesus. When they saw him, they begged that he would depart from their borders.", "bsb": "Then the whole town went out to meet Jesus. And when they saw Him, they begged Him to leave their region.", "asv": "And behold, all the city came out to meet Jesus: and when they saw him, they besought him that he would depart from their borders.", "ylt": "And lo, all the city came forth to meet Jesus, and having seen him, they called on him that he might depart from their borders.", "tyndale": "And beholde all the cyte came out and met Iesus. And when they sawe hym they besought hym to departe oute of their costes.", "dra": "And behold the whole city went out to meet Jesus, and when they saw him, they besought him that he would depart from their coast.", "bbe": "And all the town came out to Jesus; and seeing him they made request that he would go away from their part of the country.", "geneva": "And beholde, all ye citie came out to meete Iesus: and when they sawe him, they besought him to depart out of their coastes.", "wycliffe": "And lo! al the citee wente out ayens Jhesu; and whanne thei hadden seyn hym, thei preieden, that he wolde passe fro her coostis.", "rotherham": "And lo! all the city, came out to meet Jesus,—and, seeing him, they besought that he would pass on from their bounds.", "weymouth": "So at once the whole population came out to meet Jesus; and when they saw Him, they besought Him to leave their country.", "darby": "And behold, the whole city went out to meet Jesus; and when they saw him, they begged [him] to go away out of their coasts.", "twenty": "At the news the whole town went out to meet Jesus, and, when they saw him, they entreated him to go away from their neighbourhood.", "acv": "And behold, the whole city came out to a meeting with Jesus. And having seen him, they besought him that he would depart from their regions.", "anderson": "And, behold, all the city came out to meet Jesus. And when they saw him, they besought him to depart out of their borders.", "haweis": "And, behold, all the city came out to meet him: and when they saw him, they besought him to depart from their territories.", "noyes": "And lo! the whole city came out to meet Jesus; and when they saw him, they besought him to depart from their borders.", "webster": "And behold, the whole city came out to meet Jesus: and when they saw him, they besought him that he would depart out of their borders.", "vulgate": "et ecce tota civitas exiit obviam Iesu et viso eo rogabant ut transiret a finibus eorum;"}}]}, {"c": 9, "verses": [{"v": 1, "ref": "9:1", "o": "Καὶ ⸀ἐμβὰς ⸀εἰς πλοῖον διεπέρασεν καὶ ἦλθεν εἰς τὴν ἰδίαν πόλιν.", "en": {"kjv": "And he entered into a ship, and passed over, and came into his own city.", "web": "He entered into a boat, and crossed over, and came into his own city.", "bsb": "Jesus got into a boat, crossed over, and came to His own town.", "asv": "And he entered into a boat, and crossed over, and came into his own city.", "ylt": "And having gone to the boat, he passed over, and came to his own city,", "tyndale": "Then he entred in to a shippe and passed over and came in to his awne cite.", "dra": "And entering into a boat, he passed over the water and came into his own city.", "bbe": "And he got into a boat and went across and came to his town.", "geneva": "Then hee entred into a shippe, and passed ouer, and came into his owne citie.", "wycliffe": "And Jhesus wente vp in to a boot, and passide ouer the watir, and cam in to his citee.", "rotherham": "And, entering into a boat, he crossed over, and came into his own city.", "weymouth": "Accordingly He went on board, and crossing over came to His own town.", "darby": "And going on board the ship, he passed over and came to his own city.", "twenty": "Afterwards Jesus got into a boat, and, crossing over, came to his own city.", "acv": "And after entering into the boat, he passed over, and came into his own city.", "anderson": "And he entered the ship, and passed over, and came into his own city.", "haweis": "AND going on board the vessel, he passed over, and came to his own city.", "noyes": "And going on board a boat, he crossed over, and came to his own city.", "webster": "And he entered into a boat, and passed over, and came into his own city.", "vulgate": "et ascendens in naviculam transfretavit et venit in civitatem suam;"}}, {"v": 2, "ref": "9:2", "o": "Καὶ ἰδοὺ προσέφερον αὐτῷ παραλυτικὸν ἐπὶ κλίνης βεβλημένον. καὶ ἰδὼν ὁ Ἰησοῦς τὴν πίστιν αὐτῶν εἶπεν τῷ παραλυτικῷ· Θάρσει, τέκνον· ⸀ἀφίενταί ⸂σου αἱ ἁμαρτίαι⸃.", "en": {"kjv": "And, behold, they brought to him a man sick of the palsy, lying on a bed: and Jesus seeing their faith said unto the sick of the palsy; Son, be of good cheer; thy sins be forgiven thee.", "web": "Behold, they brought to him a man who was paralyzed, lying on a bed. Jesus, seeing their faith, said to the paralytic, “Son, cheer up! Your sins are forgiven you.”", "bsb": "Just then some men brought to Him a paralytic lying on a mat. When Jesus saw their faith, He said to the paralytic, “Take courage, son; your sins are forgiven.”", "asv": "And behold, they brought to him a man sick of the palsy, lying on a bed: and Jesus seeing their faith said unto the sick of the palsy, Son, be of good cheer; thy sins are forgiven.", "ylt": "and lo, they were bringing to him a paralytic, laid upon a couch, and Jesus having seen their faith, said to the paralytic, `Be of good courage, child, thy sins have been forgiven thee.'", "tyndale": "And lo they brought to him a ma sicke of ye palsie lyinge in his bed. And when Iesus sawe ye faith of the he sayd to the sicke of ye palsie: sonne be of good chere thy sinnes be forgeve the.", "dra": "And behold they brought to him one sick of the palsy lying in a bed. And Jesus, seeing their faith, said to the man sick of the palsy: Be of good heart, son, thy sins are forgiven thee.", "bbe": "And they took to him a man stretched on a bed who had no power of moving; and Jesus, seeing their faith, said to the man who was ill, Son, take heart; you have forgiveness for your sins.", "geneva": "And loe, they brought to him a man sicke of the palsie, laid on a bed. And Iesus seeing their faith, saide to the sicke of the palsie, Sonne, be of good comfort: thy sinnes are forgiuen thee.", "wycliffe": "And lo! thei brouyten to hym a man sike in palesie, liggynge in a bed. And Jhesus saw the feith of hem, and seide to the man sike in palesye, Sone, haue thou trist; thi synnes ben foryouun to thee.", "rotherham": "And lo! they were bringing unto him a paralytic, on a couch, laid prostrate; and Jesus, seeing, their faith, said to the paralytic,—Take courage! child, forgiven are thy sins.", "weymouth": "Here they brought to Him a paralytic lying on a bed. Seeing their faith Jesus said to the paralytic, \"Take courage, my child; your sins are pardoned.\"", "darby": "And behold, they brought to him a paralytic, laid upon a bed; and Jesus, seeing their faith, said to the paralytic, Be of good courage, child; thy sins are forgiven.", "twenty": "And there some people brought to him a paralysed man on a bed. When Jesus saw their faith, he said to the man: “Courage, Child! Your sins are forgiven.”", "acv": "And behold, they brought to him a paralyzed man who was placed on a bed. And having seen their faith Jesus said to the paralyzed man, Cheer up, child, thy sins have been forgiven thee.", "anderson": "And behold, they brought to him a man sick of the palsy, lying on a bed. And Jesus, seeing their faith, said to the palsied man: Son, be of good courage; your sins are forgiven you.", "haweis": "And lo! they brought him a paralytic stretched on a bed: and Jesus seeing their faith said to the paralytic, Be of good cheer, son; thy sins are forgiven thee.", "noyes": "And lo! they brought to him a man that was palsied, lying on a bed. And Jesus, seeing their faith, said to the palsied man, Be of good cheer, son; thy sins are forgiven.", "webster": "And behold, they brought to him a man sick with the palsy, lying on a bed: and Jesus, seeing their faith, said to the sick of the palsy, Son, be of good cheer; thy sins are forgiven thee.", "vulgate": "et ecce offerebant ei paralyticum iacentem in lecto et videns Iesus fidem illorum dixit paralytico confide fili remittuntur tibi peccata tua;"}}, {"v": 3, "ref": "9:3", "o": "καὶ ἰδού τινες τῶν γραμματέων εἶπαν ἐν ἑαυτοῖς· Οὗτος βλασφημεῖ.", "en": {"kjv": "And, behold, certain of the scribes said within themselves, This man blasphemeth.", "web": "Behold, some of the scribes said to themselves, “This man blasphemes.”", "bsb": "On seeing this, some of the scribes said to themselves, “This man is blaspheming!”", "asv": "And behold, certain of the scribes said within themselves, This man blasphemeth.", "ylt": "And lo, certain of the scribes said within themselves, `This one doth speak evil.'", "tyndale": "And beholde certeyne of ye scribes sayd in the selves this ma blasphemeth.", "dra": "And behold some of the scribes said within themselves: He blasphemeth.", "bbe": "And some of the scribes said among themselves, This man has no respect for God.", "geneva": "And beholde, certaine of the Scribes saide with themselues, This man blasphemeth.", "wycliffe": "And lo! summe of the scribis seiden withynne hem silf, This blasfemeth.", "rotherham": "And lo! certain of the scribes, said within themselves,—This man, speaketh profanely!", "weymouth": "\"Such language is impious,\" said some of the Scribes among themselves.", "darby": "And behold, certain of the scribes said to themselves, This [man] blasphemes.", "twenty": "Then some of the teachers of the Law said to themselves: “This man is blaspheming!”", "acv": "And behold, some of the scholars said within themselves, This man blasphemes.", "anderson": "And behold, some of the scribes said within themselves: This man talks impiously.", "haweis": "And lo! some of the scribes said within themselves, This man blasphemeth.", "noyes": "And lo! some of the scribes said within themselves, This man is blaspheming.", "webster": "And behold, certain of the scribes said within themselves, This [man] blasphemeth.", "vulgate": "et ecce quidam de scribis dixerunt intra se hic blasphemat;"}}, {"v": 4, "ref": "9:4", "o": "καὶ ⸀εἰδὼς ὁ Ἰησοῦς τὰς ἐνθυμήσεις αὐτῶν εἶπεν· ⸀Ἱνατί ἐνθυμεῖσθε πονηρὰ ἐν ταῖς καρδίαις ὑμῶν;", "en": {"kjv": "And Jesus knowing their thoughts said, Wherefore think ye evil in your hearts?", "web": "Jesus, knowing their thoughts, said, “Why do you think evil in your hearts?", "bsb": "But Jesus knew what they were thinking and said, “Why do you harbor evil in your hearts?", "asv": "And Jesus knowing their thoughts said, Wherefore think ye evil in your hearts?", "ylt": "And Jesus, having known their thoughts, said, `Why think ye evil in your hearts?", "tyndale": "And whe Iesus sawe their thoughtes he sayd: wherfore thinke ye evill in youre hertes?", "dra": "And Jesus seeing their thoughts, said: Why do you think evil in your hearts?", "bbe": "And Jesus, having knowledge of what was in their minds, said, Why are your thoughts evil?", "geneva": "But when Iesus saw their thoughts, he said, Wherefore thinke yee euil things in your hearts?", "wycliffe": "And whanne Jhesus hadde seyn her thouytis, he seide, Wherto thenken ye yuele thingis in youre hertis?", "rotherham": "And Jesus, knowing, their inward thoughts, said,—To what end are ye cherishing evil thoughts within your hearts?", "weymouth": "Knowing their thoughts Jesus said, \"Why are you cherishing evil thoughts in your hearts?", "darby": "And Jesus, seeing their thoughts, said, Why do ye think evil things in your hearts?", "twenty": "Knowing their thoughts, Jesus exclaimed: “Why do your cherish such wicked thoughts?", "acv": "And having known their thoughts Jesus said, Why think ye evil in your hearts?", "anderson": "And Jesus, perceiving their thoughts, said: Why do evil thoughts arise in your hearts?", "haweis": "And Jesus, seeing their thoughts, said, wherefore do ye imagine evil things in your hearts?", "noyes": "And Jesus seeing their thoughts, said, Wherefore have ye evil thoughts in your hearts?", "webster": "And Jesus, knowing their thoughts, said, Why think ye evil in your hearts?", "vulgate": "et cum vidisset Iesus cogitationes eorum dixit ut quid cogitatis mala in cordibus vestris;"}}, {"v": 5, "ref": "9:5", "o": "τί γάρ ἐστιν εὐκοπώτερον, εἰπεῖν· ⸀Ἀφίενταί σου αἱ ἁμαρτίαι, ἢ εἰπεῖν· ⸀Ἔγειρε καὶ περιπάτει;", "en": {"kjv": "For whether is easier, to say, Thy sins be forgiven thee; or to say, Arise, and walk?", "web": "For which is easier, to say, ‘Your sins are forgiven;’ or to say, ‘Get up, and walk?’", "bsb": "Which is easier: to say, ‘Your sins are forgiven,’ or to say, ‘Get up and walk?’", "asv": "For which is easier, to say, Thy sins are forgiven; or to say, Arise, and walk?", "ylt": "for which is easier? to say, The sins have been forgiven to thee; or to say, Rise, and walk?", "tyndale": "Whether ys esyer to saye thy synnes be forgeven ye or to saye: arise and walke?", "dra": "Whether is easier, to say, Thy sins are forgiven thee: or to say, Arise, and walk?", "bbe": "For which is the simpler, to say, You have forgiveness for your sins; or to say, Get up and go?", "geneva": "For whether is it easier to say, Thy sinnes are forgiuen thee, or to say, Arise, and walke?", "wycliffe": "What is liytere to seye, Thi synnes ben foryouun to thee, ethir `to seie, Rise thou, and walke?", "rotherham": "For which is easier—To say, Forgiven are thy sins,—or to say, Rise and be walking!", "weymouth": "Why, which is easier? --to say, `Your sins are pardoned,' or to say `Rise up and walk'?", "darby": "For which is easier: to say, Thy sins are forgiven; or to say, Rise up and walk?", "twenty": "Which, I ask, is the easier? — to say ‘Your sins are forgiven’? or to say ‘Get up, and walk about’?", "acv": "For which is easier, to say, Thy sins have been forgiven thee, or to say, Arise and walk?", "anderson": "For, which is easier, to say, Your sins are forgiven; or to say, Arise, and walk?", "haweis": "For which is the easier, to say, Thy sins are forgiven thee; or to say, Arise, and walk?", "noyes": "For which is easier? to say, Thy sins are forgiven? or to say, Arise, and walk?", "webster": "For which is easier, to say, Thy sins are forgiven thee; or to say, Arise, and walk?", "vulgate": "quid est facilius dicere dimittuntur tibi peccata aut dicere surge et ambula;"}}, {"v": 6, "ref": "9:6", "o": "ἵνα δὲ εἰδῆτε ὅτι ἐξουσίαν ἔχει ὁ υἱὸς τοῦ ἀνθρώπου ἐπὶ τῆς γῆς ἀφιέναι ἁμαρτίας— τότε λέγει τῷ παραλυτικῷ· ⸀Ἐγερθεὶς ἆρόν σου τὴν κλίνην καὶ ὕπαγε εἰς τὸν οἶκόν σου.", "en": {"kjv": "But that ye may know that the Son of man hath power on earth to forgive sins, (then saith he to the sick of the palsy,) Arise, take up thy bed, and go unto thine house.", "web": "But that you may know that the Son of Man has authority on earth to forgive sins...” (then he said to the paralytic), “Get up, and take up your mat, and go up to your house.”", "bsb": "But so that you may know that the Son of Man has authority on earth to forgive sins...” Then He said to the paralytic, “Get up, pick up your mat, and go home.”", "asv": "But that ye may know that the Son of man hath authority on earth to forgive sins (then saith he to the sick of the palsy), Arise, and take up thy bed, and go unto thy house.", "ylt": "`But, that ye may know that the Son of Man hath power upon the earth to forgive sins--(then saith he to the paralytic) --having risen, take up thy couch, and go to thy house.'", "tyndale": "That ye maye knowe that ye sonne of ma hath power to forgeve sinnes in erth then sayd he vnto ye sicke of ye palsye: arise take vp thy beed and go home to thine housse.", "dra": "But that you may know that the Son of man hath power on earth to forgive sins, (then said he to the man sick of the palsy,) Arise, take up thy bed, and go into thy house.", "bbe": "But so that you may see that on earth the Son of man has authority for the forgiveness of sins, (then said he to the man who was ill,) Get up, and take up your bed, and go to your house.", "geneva": "And that ye may knowe that the Sonne of man hath authoritie in earth to forgiue sinnes, (then saide he vnto the sicke of the palsie,) Arise, take vp thy bed, and goe to thine house.", "wycliffe": "But that ye wite that mannus sone hath power to foryyue synnes in erthe, thanne he seide to the sijk man in palesie, Rise vp; take thi bed, and go in to thin hous.", "rotherham": "But, that ye may know, that the Son of Man hath, authority, upon the earth, to be forgiving sins, then, saith he to the paralytic,—Rise! take up thy couch, and withdraw unto thy house.", "weymouth": "But, to prove to you that the Son of Man has authority on earth to pardon sins\" --He then says to the paralytic, \"Rise, and take up your bed and go home.\"", "darby": "But that ye may know that the Son of man has power on earth to forgive sins, (then he says to the paralytic,) Rise up, take up thy bed and go to thy house.", "twenty": "But, that you may know that the Son of Man has power on earth to forgive sins” — then he said to the paralysed man — “Get up, take up your bed, and return to your home.”", "acv": "But that ye may know that the Son of man has authority on earth to forgive sins (then he says to the paralyzed man), After rising, take up thy bed, and go to thy house.", "anderson": "But that you may know that the Son of man on earth has authority to forgive sins (then he said to the palsied man): Arise, take up your bed, and go to your house.", "haweis": "But that ye may know that the Son of man hath authority upon earth to forgive sins, (then he saith to the paralytic,) Arise, take up thy bed, and go into thy house.", "noyes": "But that ye may know that the Son of Man hath authority on earth to forgive sins,—then he saith to the palsied man,—Arise, take up thy bed, and go to thy house.", "webster": "But that ye may know that the Son of man hath power on earth to forgive sins, (then saith he to the sick with the palsy,) Arise, take up thy bed, and go to thy house.", "vulgate": "ut sciatis autem quoniam Filius hominis habet potestatem in terra dimittendi peccata tunc ait paralytico surge tolle lectum tuum et vade in domum tuam;"}}, {"v": 7, "ref": "9:7", "o": "καὶ ἐγερθεὶς ἀπῆλθεν εἰς τὸν οἶκον αὐτοῦ.", "en": {"kjv": "And he arose, and departed to his house.", "web": "He arose and departed to his house.", "bsb": "And the man got up and went home.", "asv": "And he arose, and departed to his house.", "ylt": "And he, having risen, went to his house,", "tyndale": "And he arose and departed to his awne housse.", "dra": "And he arose, and went into his house.", "bbe": "And he got up and went away to his house.", "geneva": "And hee arose, and departed to his owne house.", "wycliffe": "And he roos, and wente in to his hous.", "rotherham": "And, rising, he departed unto his house.", "weymouth": "And he got up, and went off home.", "darby": "And he rose up and went to his house.", "twenty": "The man got up and went to his home.", "acv": "And after rising, he departed to his house.", "anderson": "And he arose, and departed to his house.", "haweis": "And he arose, and went to his house.", "noyes": "And he arose, and went away to his house.", "webster": "And he arose, and departed to his house.", "vulgate": "et surrexit et abiit in domum suam;"}}, {"v": 8, "ref": "9:8", "o": "ἰδόντες δὲ οἱ ὄχλοι ⸀ἐφοβήθησαν καὶ ἐδόξασαν τὸν θεὸν τὸν δόντα ἐξουσίαν τοιαύτην τοῖς ἀνθρώποις.", "en": {"kjv": "But when the multitudes saw it, they marvelled, and glorified God, which had given such power unto men.", "web": "But when the multitudes saw it, they marveled and glorified God, who had given such authority to men.", "bsb": "When the crowds saw this, they were filled with awe and glorified God, who had given such authority to men.", "asv": "But when the multitudes saw it, they were afraid, and glorified God, who had given such authority unto men.", "ylt": "and the multitudes having seen, wondered, and glorified God, who did give such power to men.", "tyndale": "And when ye people sawe it they marveyled and glorified god which had geve suche power to me.", "dra": "And the multitude seeing it, feared, and glorified God that gave such power to men.", "bbe": "But when the people saw it they were full of fear, and gave glory to God who had given such authority to men.", "geneva": "So when the multitude sawe it, they marueiled, and glorified God, which had giuen such authoritie to men.", "wycliffe": "And the puple seynge dredde, and glorifiede God, that yaf suche power to men.", "rotherham": "Now the multitudes, seeing, were struck with fear, and glorified the God who had given authority, such as this, unto men.", "weymouth": "And the crowds were awe-struck when they saw it, and ascribed the glory to God who had entrusted such power to a man.", "darby": "But the crowds seeing [it], were in fear, and glorifiedGod who gave such power to men.", "twenty": "When the crowd saw this, they were awe-struck, and praised God for giving such power to men.", "acv": "But when the multitudes saw it, they marveled, and glorified God, who gave such authority to men.", "anderson": "And when the multitude saw it, they were astonished, and glorified God, who had given such authority to men.", "haweis": "But when the multitude saw it, they were astonished, and glorified God, who had given such power unto men.", "noyes": "And when the multitudes saw it, they were struck with fear, and gave glory to God, who had given such power to men.", "webster": "But when the multitude saw [it], they marveled, and glorified God, who had given such power to men.", "vulgate": "videntes autem turbae timuerunt et glorificaverunt Deum qui dedit potestatem talem hominibus;"}}, {"v": 9, "ref": "9:9", "o": "Καὶ παράγων ὁ Ἰησοῦς ἐκεῖθεν εἶδεν ἄνθρωπον καθήμενον ἐπὶ τὸ τελώνιον, Μαθθαῖον λεγόμενον, καὶ λέγει αὐτῷ· Ἀκολούθει μοι· καὶ ἀναστὰς ἠκολούθησεν αὐτῷ.", "en": {"kjv": "And as Jesus passed forth from thence, he saw a man, named Matthew, sitting at the receipt of custom: and he saith unto him, Follow me. And he arose, and followed him.", "web": "As Jesus passed by from there, he saw a man called Matthew sitting at the tax collection office. He said to him, “Follow me.” He got up and followed him.", "bsb": "As Jesus went on from there, He saw a man named Matthew sitting at the tax booth. “Follow Me,” He told him, and Matthew got up and followed Him.", "asv": "And as Jesus passed by from thence, he saw a man, called Matthew, sitting at the place of toll: and he saith unto him, Follow me. And he arose, and followed him.", "ylt": "And Jesus passing by thence, saw a man sitting at the tax-office, named Matthew, and saith to him, `Be following me,' and he, having risen, did follow him.", "tyndale": "And as Iesus passed forth fro thence he sawe a ma syt a receyuinge of custome named Mathew and sayd to him: folowe me.", "dra": "And when Jesus passed on from thence, he saw a man sitting in the custom house, named Matthew; and he saith to him: Follow me. And he arose up and followed him.", "bbe": "And when Jesus was going from there, he saw a man whose name was Matthew, seated at the place where taxes were taken; and he said to him, Come after me. And he got up and went after him.", "geneva": "And as Iesus passed foorth from thence, hee sawe a man sitting at the custome, named Matthewe, and saide to him, Followe me. And he arose, and followed him.", "wycliffe": "And whanne Jhesus passide fro thennus, he say a man, Matheu bi name, sittynge in a tolbothe. And he seide to hym, Sue thou me.", "rotherham": "And Jesus, passing aside from thence, saw a man presiding over the tax-office, called, Matthew, and saith unto him,—Be following me. And, arising, he followed him.", "weymouth": "Passing on thence Jesus saw a man called Matthew sitting at the Toll Office, and said to him, \"Follow me.\" And he arose, and followed Him.", "darby": "And Jesus, passing on thence, saw a man sitting at the tax-office, called Matthew, and says to him, Follow me. And he rose up and followed him.", "twenty": "As Jesus went along, he saw a man, called Matthew, sitting in the tax-office, and said to him: “Follow me.” Matthew got up and followed him.", "acv": "And passing forth from there, Jesus saw a man named Matthew sitting at the tax office. And he says to him, Follow me. And after rising, he followed him.", "anderson": "And as Jesus passed by from that place, he saw a man named Matthew, sitting at the custom-house; and he said to him: Follow me. And he arose and followed him.", "haweis": "And Jesus passing from thence, saw a man sitting at the custom house, called Matthew: and saith unto him, Follow me. And he arose and followed him.", "noyes": "And as Jesus passed on from thence, he saw a man, named Matthew, sitting at the custom-house; and he saith to him, Follow me. And he arose and followed him.", "webster": "And as Jesus was passing from thence, he saw a man named Matthew, sitting at the receipt of custom: and he saith to him, Follow me. And he arose, and followed him.", "vulgate": "et cum transiret inde Iesus vidit hominem sedentem in teloneo Mattheum nomine et ait illi sequere me et surgens secutus est eum;"}}, {"v": 10, "ref": "9:10", "o": "Καὶ ἐγένετο αὐτοῦ ἀνακειμένου ἐν τῇ οἰκίᾳ, ⸀καὶ ἰδοὺ πολλοὶ τελῶναι καὶ ἁμαρτωλοὶ ἐλθόντες συνανέκειντο τῷ Ἰησοῦ καὶ τοῖς μαθηταῖς αὐτοῦ.", "en": {"kjv": "And it came to pass, as Jesus sat at meat in the house, behold, many publicans and sinners came and sat down with him and his disciples.", "web": "As he sat in the house, behold, many tax collectors and sinners came and sat down with Jesus and his disciples.", "bsb": "Later, as Jesus was dining at Matthew’s house, many tax collectors and sinners came and ate with Him and His disciples.", "asv": "And it came to pass, as he sat at meat in the house, behold, many publicans and sinners came and sat down with Jesus and his disciples.", "ylt": "And it came to pass, he reclining (at meat) in the house, that lo, many tax-gatherers and sinners having come, were lying (at meat) with Jesus and his disciples,", "tyndale": "And he arose and folowed him. And it came to passe as he sat at meate in the housse: beholde many publicans and synners came and sate downe also with Iesus and hys disciples.", "dra": "And it came to pass as he was sitting at meat in the house, behold many publicans and sinners came, and sat down with Jesus and his disciples.", "bbe": "And it came about, when he was in the house taking food, that a number of tax-farmers and sinners came and took their places with Jesus and his disciples.", "geneva": "And it came to passe, as Iesus sate at meate in his house, beholde, many Publicanes and sinners, that came thither, sate downe at the table with Iesus and his disciples.", "wycliffe": "And he roos, and folewide hym. And it was don, the while he sat `at the mete in the hous, lo! many pupplicans and synful men camen, and saten `at the mete with Jhesu and hise disciplis.", "rotherham": "And it came to pass, as he was reclining in the house, that lo! many tax-collectors and sinners, came, and were reclining together with Jesus and his disciples.", "weymouth": "And while He was reclining at table, a large number of tax-gathers and notorious sinners were of the party with Jesus and His disciples.", "darby": "And it came to pass, as he lay at table in the house, that behold, many tax-gatherers and sinners came and lay at table with Jesus and his disciples.", "twenty": "And, later on, when he was at table in the house, a number of tax-gatherers and outcasts came in and took their places at table with Jesus and his disciples.", "acv": "And it came to pass while he relaxed in the house, and behold, many tax collectors and sinners having come, they were sitting with Jesus and his disciples.", "anderson": "And it came to pass that, while Jesus was reclining at table in his house, behold, many publicans and sinners came and reclined at table with him and his disciples.", "haweis": "And it came to pass, as he sat in his house, many tax-gatherers and sinners came, and sat down at table with Jesus and his disciples.", "noyes": "And it came to pass, as he was reclining at table in the house, lo! many publicans and sinners came and reclined with Jesus and his disciples.", "webster": "And it came to pass, as Jesus sat at table in the house, behold, many publicans and sinners came and sat down with him and his disciples.", "vulgate": "et factum est discumbente eo in domo ecce multi publicani et peccatores venientes discumbebant cum Iesu et discipulis eius;"}}, {"v": 11, "ref": "9:11", "o": "καὶ ἰδόντες οἱ Φαρισαῖοι ⸀ἔλεγον τοῖς μαθηταῖς αὐτοῦ· Διὰ τί μετὰ τῶν τελωνῶν καὶ ἁμαρτωλῶν ἐσθίει ὁ διδάσκαλος ὑμῶν;", "en": {"kjv": "And when the Pharisees saw it, they said unto his disciples, Why eateth your Master with publicans and sinners?", "web": "When the Pharisees saw it, they said to his disciples, “Why does your teacher eat with tax collectors and sinners?”", "bsb": "When the Pharisees saw this, they asked His disciples, “Why does your Teacher eat with tax collectors and sinners?”", "asv": "And when the Pharisees saw it, they said unto his disciples, Why eateth your Teacher with the publicans and sinners?", "ylt": "and the Pharisees having seen, said to his disciples, `Wherefore with the tax-gatherers and sinners doth your teacher eat?'", "tyndale": "When the Pharises sawe that they sayd to hys disciples: why eateth youre master wt publicans and synners?", "dra": "And the Pharisees seeing it, said to his disciples: Why doth your master eat with publicans and sinners?", "bbe": "And when the Pharisees saw it, they said to his disciples, Why does your Master take food with tax-farmers and sinners?", "geneva": "And when the Pharises sawe that, they saide to his disciples, Why eateth your master with Publicanes and sinners?", "wycliffe": "And Farisees sien, and seiden to hise disciplis, Whi etith youre maister with pupplicans and synful men?", "rotherham": "And, the Pharisees, observing it, began to say unto his disciples,—Wherefore, with tax-collectors and sinners, doth your Teacher eat?", "weymouth": "The Pharisees noticed this, and they inquired of His disciples, \"Why does your Teacher eat with the tax-gatherers and notorious sinners?\"", "darby": "And the Pharisees seeing [it], said to his disciples, Why does your teacher eat with tax-gatherers and sinners?", "twenty": "When the Pharisees saw this, they said to his disciples: “Why does your Teacher eat in the company of tax-gatherers and outcasts?”", "acv": "And when the Pharisees saw it, they said to his disciples, Why does your teacher eat with the tax collectors and sinners?", "anderson": "And when the Pharisees saw it, they said to his disciples: Why does your teacher eat with publicans and sinners?", "haweis": "And the Pharisees observing it, said to his disciples, How is this, that your Master eateth with publicans and sinners?", "noyes": "And when the Pharisees saw it, they said to his disciples, Why doth your teacher eat with the publicans and sinners?", "webster": "And when the Pharisees saw [it], they said to his disciples, Why eateth your Master with publicans and sinners?", "vulgate": "et videntes Pharisaei dicebant discipulis eius quare cum publicanis et peccatoribus manducat magister vester;"}}, {"v": 12, "ref": "9:12", "o": "ὁ ⸀δὲ ἀκούσας ⸀εἶπεν· Οὐ χρείαν ἔχουσιν οἱ ἰσχύοντες ἰατροῦ ἀλλὰ οἱ κακῶς ἔχοντες.", "en": {"kjv": "But when Jesus heard that, he said unto them, They that be whole need not a physician, but they that are sick.", "web": "When Jesus heard it, he said to them, “Those who are healthy have no need for a physician, but those who are sick do.", "bsb": "On hearing this, Jesus said, “It is not the healthy who need a doctor, but the sick.", "asv": "But when he heard it, he said, They that are whole have no need of a physician, but they that are sick.", "ylt": "And Jesus having heard, said to them, `They who are whole have no need of a physician, but they who are ill;", "tyndale": "When Iesus herde that he sayde vnto them: The whole neade not the phisicion but they that are sicke.", "dra": "But Jesus hearing it, said: They that are in health need not a physician, but they that are ill.", "bbe": "But on hearing this he said, Those who are well have no need of a medical man, but those who are ill.", "geneva": "Nowe when Iesus heard it, hee sayde vnto them, The whole neede not a Physition, but they that are sicke.", "wycliffe": "And Jhesus herde, and seide, A leche is not nedeful to men that faren wel, but to men that ben yuel at ese.", "rotherham": "And, he, hearing it, said,—No need have the strong, of a physician, but they who are sick.", "weymouth": "He heard the question and replied, \"It is not men in good health who require a doctor, but the sick.", "darby": "But [Jesus] hearing it, said, They that are strong have not need of a physician, but those that are ill.", "twenty": "On hearing this, Jesus said: “It is not those who are in health that need a doctor, but those who are ill.", "acv": "But Jesus having heard it, he said to them, Those who are strong have no need of a physician, but those who fare badly.", "anderson": "When Jesus heard it, he said to them: Those who are in health have no need of a physician, but those who are sick.", "haweis": "But Jesus hearing it, said unto them, They who are in the vigour of health have no need of the physician, but they who have illness.", "noyes": "But when he heard that, he said, They who are well do not need a physician, but they who are sick.", "webster": "But when Jesus heard [that], he said to them, They that are in health need not a physician, but they that are sick.", "vulgate": "at Iesus audiens ait non est opus valentibus medico sed male habentibus;"}}, {"v": 13, "ref": "9:13", "o": "πορευθέντες δὲ μάθετε τί ἐστιν· Ἔλεος θέλω καὶ οὐ θυσίαν· οὐ γὰρ ἦλθον καλέσαι δικαίους ἀλλὰ ⸀ἁμαρτωλούς.", "en": {"kjv": "But go ye and learn what that meaneth, I will have mercy, and not sacrifice: for I am not come to call the righteous, but sinners to repentance.", "web": "But you go and learn what this means: ‘I desire mercy, and not sacrifice,’for I came not to call the righteous, but sinners to repentance.”", "bsb": "But go and learn what this means: ‘I desire mercy, not sacrifice.’ For I have not come to call the righteous, but sinners.”", "asv": "But go ye and learn what this meaneth, I desire mercy, and not sacrifice: for I came not to call the righteous, but sinners.", "ylt": "but having gone, learn ye what is, Kindness I will, and not sacrifice, for I did not come to call righteous men, but sinners, to reformation.'", "tyndale": "Goo and learne what that meaneth: I have pleasure in mercy and not in offerynge. For I am not come to call the rightewes but the synners to repentaunce.", "dra": "Go then and learn what this meaneth, I will have mercy and not sacrifice. For I am not come to call the just, but sinners.", "bbe": "But go and take to heart the sense of these words, My desire is for mercy, not offerings: for I have come not to get the upright, but sinners.", "geneva": "But goe yee and learne what this is, I will haue mercie, and not sacrifice: for I am not come to call the righteous, but the sinners to repentance.", "wycliffe": "But go ye, and lerne what it is, Y wole merci, and not sacrifice; for I cam, not to clepe riytful men, but synful men.", "rotherham": "But go ye, and learn what this meaneth,—Mercy, I desire, and not, sacrifice; For I came, not to call the righteous, but sinners.", "weymouth": "But go and learn what this means, `It is mercy that I desire, not sacrifice'; for I did not come to appeal to the righteous, but to sinners.\"", "darby": "But go and learn what [that] is — I will have mercy and not sacrifice; for I have not come to call righteous [men] but sinners.", "twenty": "Go and learn what this means — ‘I desire mercy, and not sacrifice’; for I did not come to call the religious, but the outcast.”", "acv": "But after going, learn what this means, I desire mercy, and not sacrifice, for I came not to call the righteous, but sinners for repentance.", "anderson": "But go and learn what this means: I desire mercy, and not sacrifice. For I came not to call righteous men, but sinners to repentance.", "haweis": "Go then, and learn what is said, “I require mercy and not sacrifice:” for I am not come to call the righteous, but sinners to repentance.", "noyes": "But go ye and learn what this meaneth: \"I desire mercy, and not sacrifice.\" For I came not to call righteous men, but sinners.", "webster": "But go ye and learn what [that] meaneth, I will have mercy, and not sacrifice: for I am not come to call the righteous, but sinners to repentance.", "vulgate": "euntes autem discite quid est misericordiam volo et non sacrificium non enim veni vocare iustos sed peccatores;"}}, {"v": 14, "ref": "9:14", "o": "Τότε προσέρχονται αὐτῷ οἱ μαθηταὶ Ἰωάννου λέγοντες· Διὰ τί ἡμεῖς καὶ οἱ Φαρισαῖοι νηστεύομεν ⸀πολλά, οἱ δὲ μαθηταί σου οὐ νηστεύουσιν;", "en": {"kjv": "Then came to him the disciples of John, saying, Why do we and the Pharisees fast oft, but thy disciples fast not?", "web": "Then John’s disciples came to him, saying, “Why do we and the Pharisees fast often, but your disciples don’t fast?”", "bsb": "At that time John’s disciples came to Jesus and asked, “Why is it that we and the Pharisees fast so often, but Your disciples do not fast?”", "asv": "Then come to him the disciples of John, saying, Why do we and the Pharisees fast oft, but thy disciples fast not?", "ylt": "Then come to him do the disciples of John, saying, `Wherefore do we and the Pharisees fast much, and thy disciples fast not?'", "tyndale": "Then came ye disciples of Ihon to hym sayinge: why do we and the Pharises fast ofte: but thy disciples fast not?", "dra": "Then came to him the disciples of John, saying: Why do we and the Pharisees, fast often, but thy disciples do not fast?", "bbe": "Then the disciples of John came to him, saying, Why do we and the Pharisees frequently go without food, but your disciples do not?", "geneva": "Then came the disciples of Iohn to him, saying, Why doe we and the Pharises fast oft, and thy disciples fast not?", "wycliffe": "Thanne the disciplis of Joon camen to hym, and seiden, Whi we and Farisees fasten ofte, but thi disciplis fasten not?", "rotherham": "Then come near unto him the disciples of John, saying,—Wherefore do, we, and the Pharisees, fast, whereas, thy disciples, fast not?", "weymouth": "At that time John's disciples came and asked Jesus, \"Why do we and the Pharisees fast, but your disciples do not?\"", "darby": "Then come to him the disciples of John, saying, Why do we and the Pharisees often fast, but thy disciples fast not?", "twenty": "Then John’s disciples came to Jesus, and asked: “Why do we and the Pharisees fast while your disciples do not?”", "acv": "Then the disciples of John come to him, saying, Why do we and the Pharisees fast much, but thy disciples fast not?", "anderson": "Then came to him the disciples of John, saying: Why do we and the Pharisees fast often, but your disciples fast not?", "haweis": "Then came unto him disciples of John, saying, Why do we and the Pharisees keep many fasts, but thy disciples fast not?", "noyes": "Then came to him the disciples of John, saying, Why do we and the Pharisees fast, and thy disciples fast not?", "webster": "Then came to him the disciples of John, saying, Why do we and the Pharisees fast often, but thy disciples fast not?", "vulgate": "tunc accesserunt ad eum discipuli Iohannis dicentes quare nos et Pharisaei ieiunamus frequenter discipuli autem tui non ieiunant;"}}, {"v": 15, "ref": "9:15", "o": "καὶ εἶπεν αὐτοῖς ὁ Ἰησοῦς· Μὴ δύνανται οἱ υἱοὶ τοῦ νυμφῶνος πενθεῖν ἐφ’ ὅσον μετ’ αὐτῶν ἐστιν ὁ νυμφίος; ἐλεύσονται δὲ ἡμέραι ὅταν ἀπαρθῇ ἀπ’ αὐτῶν ὁ νυμφίος, καὶ τότε νηστεύσουσιν.", "en": {"kjv": "And Jesus said unto them, Can the children of the bridechamber mourn, as long as the bridegroom is with them? but the days will come, when the bridegroom shall be taken from them, and then shall they fast.", "web": "Jesus said to them, “Can the friends of the bridegroom mourn, as long as the bridegroom is with them? But the days will come when the bridegroom will be taken away from them, and then they will fast.", "bsb": "Jesus replied, “How can the guests of the bridegroom mourn while He is with them? But the time will come when the bridegroom will be taken from them; then they will fast.", "asv": "And Jesus said unto them, Can the sons of the bridechamber mourn, as long as the bridegroom is with them? but the days will come, when the bridegroom shall be taken away from them, and then will they fast.", "ylt": "And Jesus said to them, `Can the sons of the bride-chamber mourn, so long as the bridegroom is with them? but days shall come when the bridegroom may be taken from them, and then they shall fast.", "tyndale": "And Iesus sayde vnto them: Can ye weddynge chyldren morne as longe as ye bridegrome is wt them? The tyme will come whe the bridegrome shalbe take fro them and then shall they faste.", "dra": "And Jesus said to them: Can the children of the bridegroom mourn, as long as the bridegroom is with them? But the days will come, when the bridegroom shall be taken away from them, and then they shall fast.", "bbe": "And Jesus said to them, Will the friends of the newly-married man be sad as long as he is with them? But the days will come when he will be taken away from them, and then will they go without food.", "geneva": "And Iesus saide vnto them, Can the children of the marriage chamber mourne as long as the bridegrome is with them? But the daies will come, when the bridegrome shall be taken from them, and then shall they fast.", "wycliffe": "And Jhesus seide to hem, Whether the sones of the spouse moun morne, as long as the spouse is with hem? But daies schulen come, whanne the spouse schal be takun a wei fro hem, and thanne thei schulen faste.", "rotherham": "And Jesus said unto them,—Can, the sons of the bridechamber, mourn, so long as, the bridegroom, is, with them? But days will come, when the bridegroom, shall be taken from them, and, then, will they fast.", "weymouth": "\"Can the bridegroom's party mourn,\" He replied, \"as long as the bridegroom is with them? But other days will come (when the Bridegroom has been taken from them) and then they will fast.", "darby": "And Jesus said to them, Can the sons of the bridechamber mourn so long as the bridegroom is with them? But days will come when the bridegroom will have been taken away from them, and then they will fast.", "twenty": "Jesus answered: “Can the bridegroom’s friends mourn as long as the bridegroom is with them? But the days will come, when the bridegroom will be parted from them, and they will fast then.", "acv": "And Jesus said to them, The sons of the wedding hall cannot mourn as long as the bridegroom is with them. But the days will come when the bridegroom will be taken away from them, and then they will fast.", "anderson": "And Jesus said to them: Can the sons of the bride-chamber mourn while the bridegroom is with them? But the days will come, when the bridegroom shall be taken from them, and then will they fast.", "haweis": "And Jesus said unto them, Can the children of the bridechamber weep, whilst the bridegroom is with them? but the days will come, when the bridegroom shall be taken away from them, and then will they fast.", "noyes": "And Jesus said to them, Can the companions of the bridegroom mourn, as long as the bridegroom is with them? But the days will come, when the bridegroom will be taken from them, and then will they fast.", "webster": "And Jesus said to them, Can the children of the bride-chamber mourn, as long as the bridegroom is with them? but the days will come, when the bridegroom shall be taken from them, and then they will fast.", "vulgate": "et ait illis Iesus numquid possunt filii sponsi lugere quamdiu cum illis est sponsus venient autem dies cum auferetur ab eis sponsus et tunc ieiunabunt;"}}, {"v": 16, "ref": "9:16", "o": "οὐδεὶς δὲ ἐπιβάλλει ἐπίβλημα ῥάκους ἀγνάφου ἐπὶ ἱματίῳ παλαιῷ· αἴρει γὰρ τὸ πλήρωμα αὐτοῦ ἀπὸ τοῦ ἱματίου, καὶ χεῖρον σχίσμα γίνεται.", "en": {"kjv": "No man putteth a piece of new cloth unto an old garment, for that which is put in to fill it up taketh from the garment, and the rent is made worse.", "web": "No one puts a piece of unshrunk cloth on an old garment; for the patch would tear away from the garment, and a worse hole is made.", "bsb": "No one sews a patch of unshrunk cloth on an old garment. For the patch will pull away from the garment, and a worse tear will result.", "asv": "And no man putteth a piece of undressed cloth upon an old garment; for that which should fill it up taketh from the garment, and a worse rent is made.", "ylt": "`And no one doth put a patch of undressed cloth on an old garment, for its filling up doth take from the garment, and a worse rent is made.", "tyndale": "Noo man peceth and olde garment with a pece of newe cloothe. For then taketh he awaye ye pece agayne from the garmet and the rent ys made greater.", "dra": "And nobody putteth a piece of raw cloth unto an old garment. For it taketh away the fulness thereof from the garment, and there is made a greater rent.", "bbe": "And no man puts a bit of new cloth on an old coat, for by pulling away from the old, it makes a worse hole.", "geneva": "Moreouer no man pieceth an olde garment with a piece of newe cloth: for that that should fill it vp, taketh away from the garment, and the breach is worse.", "wycliffe": "And no man putteth a clout of buystous clothe in to an elde clothing; for it doith awey the fulnesse of the cloth, and a wers breking is maad.", "rotherham": "Howbeit, no one, layeth on a patch of unshrunk cloth, upon an old garment,—for the shrinking of it teareth away from the garment, and, a worse rent, is made.", "weymouth": "No one ever mends an old cloak with a patch of newly woven cloth. Otherwise, the patch put on would tear away some of the old, and a worse hole would be made.", "darby": "But no one puts a patch of new cloth on an old garment, for its filling up takes from the garment and a worse rent takes place.", "twenty": "No man ever puts a piece of unshrunk cloth on an old garment; for such a patch tears away from the garment, and a worse rent is made.", "acv": "And no man puts a patch of new cloth upon an old garment, for the patch of it pulls from the garment, and a tear becomes worse.", "anderson": "No one puts a patch of new cloth on an old garment; for that which is put in to fill it up, takes from the garment, and a worse rent is made.", "haweis": "But no man ingrafts a patch of undressed cloth into an old garment, for the piece supplied taketh from the garment, and the rent becomes worse.", "noyes": "No one putteth a patch of undressed cloth on an old garment; for the piece that filleth in teareth away from the garment, and a worse rent is made.", "webster": "No man putteth a piece of new cloth to an old garment: for that which is put in to fill it up, taketh from the garment, and the rent is made worse.", "vulgate": "nemo autem inmittit commissuram panni rudis in vestimentum vetus tollit enim plenitudinem eius a vestimento et peior scissura fit;"}}, {"v": 17, "ref": "9:17", "o": "οὐδὲ βάλλουσιν οἶνον νέον εἰς ἀσκοὺς παλαιούς· εἰ δὲ μή γε, ῥήγνυνται οἱ ἀσκοί, καὶ ὁ οἶνος ἐκχεῖται καὶ οἱ ἀσκοὶ ⸀ἀπόλλυνται· ἀλλὰ βάλλουσιν οἶνον νέον εἰς ἀσκοὺς καινούς, καὶ ἀμφότεροι συντηροῦνται.", "en": {"kjv": "Neither do men put new wine into old bottles: else the bottles break, and the wine runneth out, and the bottles perish: but they put new wine into new bottles, and both are preserved.", "web": "Neither do people put new wine into old wine skins, or else the skins would burst, and the wine be spilled, and the skins ruined. No, they put new wine into fresh wine skins, and both are preserved.”", "bsb": "Neither do men pour new wine into old wineskins. If they do, the skins will burst, the wine will spill, and the wineskins will be ruined. Instead, they pour new wine into new wineskins, and both are preserved.”", "asv": "Neither do men put new wine into old wine-skins: else the skins burst, and the wine is spilled, and the skins perish: but they put new wine into fresh wine-skins, and both are preserved.", "ylt": "`Nor do they put new wine into old skins, and if not--the skins burst, and the wine doth run out, and the skins are destroyed, but they put new wine into new skins, and both are preserved together.'", "tyndale": "Nether do men put newe wyne into olde vessels for then the vessels breake and the wyne runneth oute and the vessels perysshe. But they powre newe wyne into newe vessels and so are both saved togeder.", "dra": "Neither do they put new wine into old bottles. Otherwise the bottles break, and the wine runneth out, and the bottles perish. But new wine they put into new bottles: and both are preserved.", "bbe": "And men do not put new wine into old wine-skins; or the skins will be burst and the wine will come out, and the skins are of no more use: but they put new wine into new wine-skins, and so the two will be safe.", "geneva": "Neither doe they put newe wine into olde vessels: for then the vessels would breake, and the wine woulde be spilt, and the vessels shoulde perish: but they put new wine into newe vessels, and so are both preserued.", "wycliffe": "Nethir men putten newe wyne in to elde botelis, ellis the botels ben to-broke, and distried, and the wyn sched out. But men putten newe wyne in to newe botels, and bothe ben kept.", "rotherham": "Neither pour they new wine into old skins: otherwise at least, the skins are burst, and, the wine, runneth out, and, the skins, are spoiled,—but they pour new wine into unused skins, and, both, are together preserved.", "weymouth": "Nor do people pour new wine into old wineskins. Otherwise, the skins would split, the wine would escape, and the skins be destroyed. But they put new wine into fresh skins, and both are saved.\"", "darby": "Nor do men put new wine into old skins, otherwise the skins burst and the wine is poured out, and the skins will be destroyed; but they put new wine into new skins, and both are preserved together.", "twenty": "Nor do people put new wine into old wine-skins; for, if they do, the skins burst, and the wine runs out, and the skins are lost; but they put new wine into fresh skins, and so both are preserved.”", "acv": "Neither do they put new wine into old wineskins. Otherwise the wineskins burst, and the wine is spilled, and the wineskins will perish. But they put new wine into fresh wineskins, and both are preserved.", "anderson": "Nor do men put new wine into old bottles; if so, the bottles burst, and the wine runs out, and the bottles are lost. But they put new wine into new bottles, and both are preserved.", "haweis": "Nor do they put new wine into old bottles: but if they do, the bottles burst, and the wine is spilt, and the bottles are destroyed: but they put new wine into new bottles, and both are preserved.", "noyes": "Nor do men put new wine into old skins; else the skins burst, and the wine runneth out, and the skins are spoilt. But they put new wine into new skins, and both are preserved together.", "webster": "Neither do men put new wine into old bottles: else the bottles break, and the wine runneth out, and the bottles perish: but they put new wine into new bottles, and both are preserved.", "vulgate": "neque mittunt vinum novum in utres veteres alioquin rumpuntur utres et vinum effunditur et utres pereunt sed vinum novum in utres novos mittunt et ambo conservantur;"}}, {"v": 18, "ref": "9:18", "o": "Ταῦτα αὐτοῦ λαλοῦντος αὐτοῖς ἰδοὺ ἄρχων εἷς ⸀ἐλθὼν προσεκύνει αὐτῷ λέγων ὅτι Ἡ θυγάτηρ μου ἄρτι ἐτελεύτησεν· ἀλλὰ ἐλθὼν ἐπίθες τὴν χεῖρά σου ἐπ’ αὐτήν, καὶ ζήσεται.", "en": {"kjv": "While he spake these things unto them, behold, there came a certain ruler, and worshipped him, saying, My daughter is even now dead: but come and lay thy hand upon her, and she shall live.", "web": "While he told these things to them, behold, a ruler came and worshiped him, saying, “My daughter has just died, but come and lay your hand on her, and she will live.”", "bsb": "While Jesus was saying these things, a synagogue leader came and knelt before Him. “My daughter has just died,” he said. “But come and place Your hand on her, and she will live.”", "asv": "While he spake these things unto them, behold, there came a ruler, and worshipped him, saying, My daughter is even now dead: but come and lay thy hand upon her, and she shall live.", "ylt": "While he is speaking these things to them, lo, a ruler having come, was bowing to him, saying that `My daughter just now died, but, having come, lay thy hand upon her, and she shall live.'", "tyndale": "Whyls he thus spake vnto the beholde ther came a certayne ruler and worshipped him sayinge: my doghter is euen now deceased but come and lay thy honde on her and she shall live.", "dra": "As he was speaking these things unto them, behold a certain ruler came up, and adored him, saying: Lord, my daughter is even now dead; but come, lay thy hand upon her, and she shall live.", "bbe": "While he was saying these things to them, there came a ruler and gave him worship, saying, My daughter is even now dead; but come and put your hand on her, and she will come back to life.", "geneva": "While hee thus spake vnto them, beholde, there came a certaine ruler, and worshipped him, saying, My daughter is nowe deceased, but come and laie thine hande on her, and shee shall liue.", "wycliffe": "Whiles that Jhesus spak thes thingis to hem, lo! a prince cam, and worschipide hym, and seide, Lord, my douyter is now deed; but come thou, and putte thin hond on hir, and she schal lyue.", "rotherham": "While, these things, he was speaking unto them, lo! a [certain] ruler, came, and began bowing down to him, saying,—My daughter, just now died! But come, and lay thy hand upon, her, and she shall live.", "weymouth": "While He was thus speaking, a Ruler came up and profoundly bowing said, \"My daughter is just dead; but come and put your hand upon her and she will return to life.\"", "darby": "As he spoke these things to them, behold, a ruler coming in did homage to him, saying, My daughter has by this died; but come and lay thy hand upon her and she shall live.", "twenty": "While Jesus was saying this, a President of a Synagogue came up and bowed to the ground before him. “My daughter,” he said, “Has just died; but come and place your hand on her, and she will be restored to life.”", "acv": "While he spoke these things to them, behold, one ruler who came worshiped him, saying, My daughter has just now perished, but after coming, lay thy hand upon her, and she will live.", "anderson": "While he was speaking these things to them, behold, a certain ruler came and did him homage, saying: My daughter is already dead; but come, lay thy hand upon her, and she shall live.", "haweis": "As he was speaking these things to them, behold, there came a ruler, and prostrated himself before him, saying, My daughter hath just now died: but come and lay thine hand upon her, and she shall live.", "noyes": "While he was thus speaking to them, lo! a certain ruler came in and bowed down before him, saying, My daughter just now died; but come and lay thy hand upon her, and she will live.", "webster": "While he was speaking these things to them, behold, there came a certain ruler, and worshiped him, saying, My daughter is even now dead: but come and lay thy hand upon her, and she will live.", "vulgate": "haec illo loquente ad eos ecce princeps unus accessit et adorabat eum dicens filia mea modo defuncta est sed veni inpone manum super eam et vivet;"}}, {"v": 19, "ref": "9:19", "o": "καὶ ἐγερθεὶς ὁ Ἰησοῦς ⸀ἠκολούθει αὐτῷ καὶ οἱ μαθηταὶ αὐτοῦ.", "en": {"kjv": "And Jesus arose, and followed him, and so did his disciples.", "web": "Jesus got up and followed him, as did his disciples.", "bsb": "So Jesus got up and went with him, along with His disciples.", "asv": "And Jesus arose, and followed him, and so did his disciples.", "ylt": "And Jesus having risen, did follow him, also his disciples,", "tyndale": "And Iesus arose and folowed hym with hys disciples.", "dra": "And Jesus rising up followed him, with his disciples.", "bbe": "And Jesus got up and went after him, and so did his disciples.", "geneva": "And Iesus arose and followed him with his disciples.", "wycliffe": "And Jhesus roos, and `hise disciplis, and sueden hym.", "rotherham": "And Jesus, arising, was following him, also his disciples.", "weymouth": "And Jesus rose and followed him, as did also His disciples.", "darby": "And Jesus rose up and followed him, and [so did] his disciples.", "twenty": "So Jesus rose and followed him, and his disciples went also.", "acv": "And having risen, Jesus followed him, also his disciples.", "anderson": "And Jesus and his disciples arose and followed him.", "haweis": "And Jesus arose, and followed him, and his disciples also.", "noyes": "And Jesus arose and followed him, with his disciples.", "webster": "And Jesus arose, and followed him, and [so did] his disciples.", "vulgate": "et surgens Iesus sequebatur eum et discipuli eius;"}}, {"v": 20, "ref": "9:20", "o": "Καὶ ἰδοὺ γυνὴ αἱμορροοῦσα δώδεκα ἔτη προσελθοῦσα ὄπισθεν ἥψατο τοῦ κρασπέδου τοῦ ἱματίου αὐτοῦ·", "en": {"kjv": "And, behold, a woman, which was diseased with an issue of blood twelve years, came behind him, and touched the hem of his garment:", "web": "Behold, a woman who had an issue of blood for twelve years came behind him, and touched the fringe of his garment;", "bsb": "Suddenly a woman who had suffered from bleeding for twelve years came up behind Him and touched the fringe of His cloak.", "asv": "And behold, a woman, who had an issue of blood twelve years, came behind him, and touched the border of his garment:", "ylt": "and lo, a woman having an issue of blood twelve years, having come to him behind, did touch the fringe of his garments,", "tyndale": "And beholde a woman which was diseased wt an yssue of bloude .xii. yeres came behynde hym and toched ye hem of hys vesture.", "dra": "And behold a woman who was troubled with an issue of blood twelve years, came behind him, and touched the hem of his garment.", "bbe": "And a woman, who for twelve years had had a flow of blood, came after him, and put her hand on the edge of his robe:", "geneva": "(And beholde, a woman which was diseased with an issue of blood twelue yeres, came behinde him, and touched the hemme of his garment.", "wycliffe": "And lo! a womman, that hadde the blodi flux twelue yere, neiyede bihynde, and touchide the hem of his cloth.", "rotherham": "And lo! a woman, having a flow of blood twelve years, coming near behind, touched the fringe of his mantle.", "weymouth": "But a woman who for twelve years had been afflicted with haemorrhage came behind Him and touched the tassel of His cloak;", "darby": "And behold, a woman, who had had a bloody flux [for] twelve years, came behind and touched the hem of his garment;", "twenty": "But meanwhile a woman, who had been suffering from haemorrhage for twelve years, came up behind and touched the tassel of his cloak.", "acv": "And behold, a woman having an issue of blood twelve years, after coming from behind, touched the edge of his garment.", "anderson": "And behold, a woman that had been diseased with an issue of blood for twelve years, came behind him, and touched the fringe of his mantle.", "haweis": "And, behold, a woman, who had an haemorrage twelve years, came behind, and touched the fringe of his garment:", "noyes": "And, lo! a woman, who had had an issue of blood for twelve years, came up behind, and touched the fringe of his garment.", "webster": "(And behold, a woman who was diseased with an issue of blood twelve years, came behind [him], and touched the hem of his garment.", "vulgate": "et ecce mulier quae sanguinis fluxum patiebatur duodecim annis accessit retro et tetigit fimbriam vestimenti eius;"}}, {"v": 21, "ref": "9:21", "o": "ἔλεγεν γὰρ ἐν ἑαυτῇ· Ἐὰν μόνον ἅψωμαι τοῦ ἱματίου αὐτοῦ σωθήσομαι.", "en": {"kjv": "For she said within herself, If I may but touch his garment, I shall be whole.", "web": "for she said within herself, “If I just touch his garment, I will be made well.”", "bsb": "She said to herself, “If only I touch His cloak, I will be healed.”", "asv": "for she said within herself, If I do but touch his garment, I shall be made whole.", "ylt": "for she said within herself, `If only I may touch his garment, I shall be saved.'", "tyndale": "For she sayd in her silfe: yf I maye toche but even his vesture only I shalbe safe.", "dra": "For she said within herself: If I shall touch only his garment, I shall be healed.", "bbe": "Because, she said to herself, if I may but put my hand on his robe, I will be made well.", "geneva": "For shee saide in her selfe, If I may touche but his garment onely, I shalbe whole.", "wycliffe": "For sche seide with ynne hir self, Yif Y touche oonli the cloth of hym, Y schal be saaf.", "rotherham": "For she kept saying within herself,—If only I touch his mantle, I shall be made well!", "weymouth": "for she said to herself, \"If I but touch His cloak, I shall be cured.\"", "darby": "for she said within herself, If I should only touch his garment I shall be healed.", "twenty": "“If I only touch his cloak,” she said to herself, “I shall get well.”", "acv": "For she said within herself, If only I may touch his garment, I will be healed.", "anderson": "For she said within herself: If I may only touch his mantle, I shall be saved.", "haweis": "for she said within herself, If I only touch his garment, I shall be cured.", "noyes": "For she said within herself, If I only touch his garment, I shall be made well.", "webster": "For she said within herself, If I may but touch his garment, I shall be whole.", "vulgate": "dicebat enim intra se si tetigero tantum vestimentum eius salva ero;"}}, {"v": 22, "ref": "9:22", "o": "ὁ δὲ Ἰησοῦς ⸀στραφεὶς καὶ ἰδὼν αὐτὴν εἶπεν· Θάρσει, θύγατερ· ἡ πίστις σου σέσωκέν σε. καὶ ἐσώθη ἡ γυνὴ ἀπὸ τῆς ὥρας ἐκείνης.", "en": {"kjv": "But Jesus turned him about, and when he saw her, he said, Daughter, be of good comfort; thy faith hath made thee whole. And the woman was made whole from that hour.", "web": "But Jesus, turning around and seeing her, said, “Daughter, cheer up! Your faith has made you well.” And the woman was made well from that hour.", "bsb": "Jesus turned and saw her. “Take courage, daughter,” He said, “your faith has healed you.” And the woman was cured from that very hour.", "asv": "But Jesus turning and seeing her said, Daughter, be of good cheer; thy faith hath made thee whole. And the woman was made whole from that hour.", "ylt": "And Jesus having turned about, and having seen her, said, `Be of good courage, daughter, thy faith hath saved thee,' and the woman was saved from that hour.", "tyndale": "Then Iesus tourned him about and behelde her sayinge: Doughter be of good conforte thy faith hath made the safe. And she was made whole even that same houre.", "dra": "But Jesus turning and seeing her, said: Be of good heart, daughter, thy faith hath made thee whole. And the woman was made whole from that hour.", "bbe": "But Jesus, turning and seeing her, said, Daughter, take heart; your faith has made you well. And the woman was made well from that hour.", "geneva": "Then Iesus turned him about, and seeing her, did say, Daughter, be of good comfort: thy faith hath made thee whole. And the woman was made whole at that same moment.)", "wycliffe": "And Jhesus turnede, and say hir, and seide, Douytir, haue thou trist; thi feith hath maad thee saaf. And the womman was hool fro that our.", "rotherham": "And, Jesus, turning and seeing her, said,—Take courage! daughter, Thy faith, hath made thee well. And the woman was made well, from that hour.", "weymouth": "And Jesus turned and saw her, and said, \"Take courage, daughter; your faith has cured you.\" And the woman was restored to health from that moment.", "darby": "But Jesus turning and seeing her, said, Be of good courage, daughter; thy faith has healed thee. And the woman was healed from that hour.", "twenty": "Turning and seeing her, Jesus said: “Courage, Daughter! your faith has delivered you.” And the woman was delivered from her malady from that very hour.", "acv": "But having turned around and seen her, Jesus said, Cheer up, daughter, thy faith has healed thee. And the woman was healed from that hour.", "anderson": "But Jesus turned, and saw her, and said: Daughter, be of good courage; your faith has saved you. And the woman was saved from that hour.", "haweis": "Then Jesus, turning about and beholding her, said, Be encouraged, daughter; thy faith hath saved thee. And the woman was cured from that hour.", "noyes": "And he turned round, and seeing her, said, Be of good cheer, daughter; thy faith hath made thee well. And the woman was made well from that hour.", "webster": "But Jesus turned himself about, and when he saw her, he said, Daughter, be of good comfort; thy faith hath made thee whole. And the woman was made whole from that hour.)", "vulgate": "at Iesus conversus et videns eam dixit confide filia fides tua te salvam fecit et salva facta est mulier ex illa hora;"}}, {"v": 23, "ref": "9:23", "o": "καὶ ἐλθὼν ὁ Ἰησοῦς εἰς τὴν οἰκίαν τοῦ ἄρχοντος καὶ ἰδὼν τοὺς αὐλητὰς καὶ τὸν ὄχλον θορυβούμενον", "en": {"kjv": "And when Jesus came into the ruler’s house, and saw the minstrels and the people making a noise,", "web": "When Jesus came into the ruler’s house, and saw the flute players, and the crowd in noisy disorder,", "bsb": "When Jesus entered the house of the synagogue leader, He saw the flute players and the noisy crowd.", "asv": "And when Jesus came into the ruler’s house, and saw the flute-players, and the crowd making a tumult,", "ylt": "And Jesus having come to the house of the ruler, and having seen the minstrels and the multitude making tumult,", "tyndale": "And when Iesus came into ye rulers housse and sawe the minstrels and the people raginge", "dra": "And when Jesus was come into the house of the ruler, and saw the minstrels and the multitude making a rout,", "bbe": "And when Jesus came into the ruler's house and saw the players with their instruments and the people making a noise,", "geneva": "Nowe when Iesus came into the Rulers house, and saw the minstrels and the multitude making noise,", "wycliffe": "And whanne Jhesus cam in to the hous of the prince, and say mynstrallis, and the puple makynge noise,", "rotherham": "And, Jesus, coming, into the house of the ruler, and seeing the flute-players and the multitude in confusion, was saying:", "weymouth": "Entering the Ruler's house, Jesus saw the flute-players and the crowd loudly wailing,", "darby": "And when Jesus was come to the house of the ruler, and saw the flute-players and the crowd making a tumult,", "twenty": "When Jesus reached the President’s house, seeing the flute players, and a number of people all in confusion,", "acv": "And Jesus having come into the ruler's house, and having seen the minstrels, and the crowd making a commotion,", "anderson": "And when Jesus came into the house of the ruler, and saw the minstrels and the multitude making lamentation,", "haweis": "And when Jesus was come into the ruler’s house, and saw the flute-players, and a multitude confusedly lamenting,", "noyes": "And Jesus coming into the ruler’s house, and seeing the minstrels, and the crowd making a noise,", "webster": "And when Jesus came into the ruler's house, and saw the minstrels and the people making a noise,", "vulgate": "et cum venisset Iesus in domum principis et vidisset tibicines et turbam tumultuantem;"}}, {"v": 24, "ref": "9:24", "o": "⸀ἔλεγεν· Ἀναχωρεῖτε, οὐ γὰρ ἀπέθανεν τὸ κοράσιον ἀλλὰ καθεύδει· καὶ κατεγέλων αὐτοῦ.", "en": {"kjv": "He said unto them, Give place: for the maid is not dead, but sleepeth. And they laughed him to scorn.", "web": "he said to them, “Make room, because the girl isn’t dead, but sleeping.” They were ridiculing him.", "bsb": "“Go away,” He told them. “The girl is not dead, but asleep.” And they laughed at Him.", "asv": "he said, Give place: for the damsel is not dead, but sleepeth. And they laughed him to scorn.", "ylt": "he saith to them, `Withdraw, for the damsel did not die, but doth sleep,' and they were deriding him;", "tyndale": "he sayde vnto them: Get you hence for ye mayde is not deed but slepeth. And they laughed hym to scorne.", "dra": "He said: Give place, for the girl is not dead, but sleepeth. And they laughed him to scorn.", "bbe": "He said, Make room; for the girl is not dead, but sleeping. And they were laughing at him.", "geneva": "He said vnto them, Get you hence: for the maid is not dead, but sleepeth. And they laughed him to scorne.", "wycliffe": "he seide, Go ye a wei, for the damysel is not deed, but slepith. And thei scornyden hym.", "rotherham": "Give place! for the maiden died not, but is sleeping. And they began to deride him.", "weymouth": "and He said, \"Go out of the room; the little girl is not dead, but asleep.\" And they laughed at Him.", "darby": "he said, Withdraw, for the damsel is not dead, but sleeps. And they derided him.", "twenty": "he said: “Go away, the little girl is not dead; she is asleep.” They began to laugh at him;", "acv": "he says to them, Depart, for the little girl did not die, but sleeps. And they ridiculed him.", "anderson": "he said to them: Depart; for the maid is not dead, but sleeps. And they derided him.", "haweis": "he saith to them, Retire; for the little girl is not dead, but sleeping. And they derided him.", "noyes": "said, Withdraw; for the girl is not dead, but is sleeping. And they laughed him to scorn.", "webster": "He said to them, Give place: for the maid is not dead, but sleepeth. And they derided him.", "vulgate": "dicebat recedite non est enim mortua puella sed dormit et deridebant eum;"}}, {"v": 25, "ref": "9:25", "o": "ὅτε δὲ ἐξεβλήθη ὁ ὄχλος, εἰσελθὼν ἐκράτησεν τῆς χειρὸς αὐτῆς, καὶ ἠγέρθη τὸ κοράσιον.", "en": {"kjv": "But when the people were put forth, he went in, and took her by the hand, and the maid arose.", "web": "But when the crowd was put out, he entered in, took her by the hand, and the girl arose.", "bsb": "After the crowd had been put outside, Jesus went in and took the girl by the hand, and she got up.", "asv": "But when the crowd was put forth, he entered in, and took her by the hand; and the damsel arose.", "ylt": "but, when the multitude was put forth, having gone in, he took hold of her hand, and the damsel arose,", "tyndale": "Assone as ye people were put forthe he went in and toke her by ye hond and the mayde arose.", "dra": "And when the multitude was put forth, he went in, and took her by the hand. And the maid arose.", "bbe": "But when the people were sent out, he went in and took her by the hand; and the girl got up.", "geneva": "And when the multitude were put foorth, hee went in and tooke her by the hande, and the maide arose.", "wycliffe": "And whanne the folc was put out, he wente in, and helde hir hond; and the damysel roos.", "rotherham": "But, when the multitude had been put forth, he went in, and grasped her hand,—and the maiden arose.", "weymouth": "When however the place was cleared of the crowd, Jesus went in, and on His taking the little girl by the hand, she rose up.", "darby": "But when the crowd had been put out, he went in and took her hand; and the damsel rose up.", "twenty": "but, when the people had been sent out, Jesus went in, and took the little girl’s hand, and she rose.", "acv": "But when the crowd was put out, having entered in, he took her hand, and the little girl arose.", "anderson": "But when the multitude had been sent out, he went in, and took the maiden by the hand, and she arose.", "haweis": "So when the multitude was put out, he went in, and took her by the hand, and the little girl arose.", "noyes": "But when the crowd had been put out, he went in, and took hold of her hand; and the girl arose.", "webster": "But when the people were put forth, he went in, and took her by the hand, and the maid arose.", "vulgate": "et cum eiecta esset turba intravit et tenuit manum eius et surrexit puella;"}}, {"v": 26, "ref": "9:26", "o": "καὶ ἐξῆλθεν ἡ φήμη αὕτη εἰς ὅλην τὴν γῆν ἐκείνην.", "en": {"kjv": "And the fame hereof went abroad into all that land.", "web": "The report of this went out into all that land.", "bsb": "And the news about this spread throughout that region.", "asv": "And the fame hereof went forth into all that land.", "ylt": "and the fame of this went forth to all the land.", "tyndale": "And this was noysed through out all that lande.", "dra": "And the fame hereof went abroad into all that country.", "bbe": "And the news of it went out into all that land.", "geneva": "And this bruite went throughout all that lande.", "wycliffe": "And this fame wente out in to al that loond.", "rotherham": "And forth went this report, into the whole of that land.", "weymouth": "And the report of this spread throughout all that district.", "darby": "And the fame of it went out into all that land.", "twenty": "The report of this spread through all that part of the country.", "acv": "And this report went forth into all that land.", "anderson": "And the fame of this went abroad in all that land.", "haweis": "And the fame of it went forth into all that country.", "noyes": "And the report of this went abroad into all that country.", "webster": "And the fame of this went abroad into all that land.", "vulgate": "et exiit fama haec in universam terram illam;"}}, {"v": 27, "ref": "9:27", "o": "Καὶ παράγοντι ἐκεῖθεν τῷ Ἰησοῦ ἠκολούθησαν ⸀αὐτῷ δύο τυφλοὶ κράζοντες καὶ λέγοντες· Ἐλέησον ἡμᾶς, ⸀υἱὲ Δαυίδ.", "en": {"kjv": "And when Jesus departed thence, two blind men followed him, crying, and saying, Thou Son of David, have mercy on us.", "web": "As Jesus passed by from there, two blind men followed him, calling out and saying, “Have mercy on us, son of David!”", "bsb": "As Jesus went on from there, two blind men followed Him, crying out, “Have mercy on us, Son of David!”", "asv": "And as Jesus passed by from thence, two blind men followed him, crying out, and saying, Have mercy on us, thou son of David.", "ylt": "And Jesus passing on thence, two blind men followed him, calling and saying, `Deal kindly with us, Son of David.'", "tyndale": "And as Iesus departed thence two blynde men folowed hym crying and saying: O thou sonne of David have mercy on vs.", "dra": "And as Jesus passed from thence, there followed him two blind men crying out and saying, Have mercy on us, O Son of David.", "bbe": "And when Jesus went on from there, two blind men came after him, crying out, Have mercy on us, you Son of David.", "geneva": "And as Iesus departed thence, two blinde men followed him, crying, and saying, O sonne of Dauid, haue mercie vpon vs.", "wycliffe": "And whanne Jhesus passide fro thennus, twei blynde men criynge sueden hym, and seiden, Thou sone of Dauid, haue merci on vs.", "rotherham": "And, as Jesus, was passing aside from thence, there followed him, two blind men, crying aloud and saying,—Have mercy on us, O Son of David!", "weymouth": "As Jesus passed on, two blind men followed Him, shouting and saying, \"Pity us, Son of David.\"", "darby": "And as Jesus passed on thence, two blind [men] followed him, crying and saying, Have mercy on us, Son of David.", "twenty": "As Jesus was passing on from there, he was followed by two blind men, who kept calling out: “Take pity on us, Son of David!”", "acv": "And when Jesus departed from there, two blind men followed him, crying out, and saying, Be merciful to us, thou son of David.", "anderson": "And as Jesus was departing thence, two blind men followed him, crying out and saying: Son of David, have mercy on us.", "haweis": "And as Jesus departed thence, two blind men followed him, crying out, and saying, Have mercy on us, son of David!", "noyes": "And as Jesus passed on from thence, two blind men followed him, crying out and saying, Have pity on us, Son of David!", "webster": "And when Jesus departed thence, two blind men followed him, crying, and saying, [Thou] son of David, have mercy on us.", "vulgate": "et transeunte inde Iesu secuti sunt eum duo caeci clamantes et dicentes miserere nostri Fili David;"}}, {"v": 28, "ref": "9:28", "o": "ἐλθόντι δὲ εἰς τὴν οἰκίαν προσῆλθον αὐτῷ οἱ τυφλοί, καὶ λέγει αὐτοῖς ὁ Ἰησοῦς· Πιστεύετε ὅτι δύναμαι τοῦτο ποιῆσαι; λέγουσιν αὐτῷ· Ναί, κύριε.", "en": {"kjv": "And when he was come into the house, the blind men came to him: and Jesus saith unto them, Believe ye that I am able to do this? They said unto him, Yea, Lord.", "web": "When he had come into the house, the blind men came to him. Jesus said to them, “Do you believe that I am able to do this?” They told him, “Yes, Lord.”", "bsb": "After Jesus had entered the house, the blind men came to Him. “Do you believe that I am able to do this?” He asked. “Yes, Lord,” they answered.", "asv": "And when he was come into the house, the blind men came to him: and Jesus saith unto them, Believe ye that I am able to do this? They say unto him, Yea, Lord.", "ylt": "And he having come to the house, the blind men came to him, and Jesus saith to them, `Believe ye that I am able to do this?' They say to him, `Yes, sir.'", "tyndale": "And when he was come to housse the blynd came to hym And Iesus sayde vnto them: Beleve ye that I am able to do thys? And they sayde vnto hym: ye Lorde.", "dra": "And when he was come to the house, the blind men came to him. And Jesus saith to them, Do you believe, that I can do this unto you? They say to him, Yea, Lord.", "bbe": "And when he had come into the house, the blind men came to him; and Jesus said to them, Have you faith that I am able to do this? They said to him, Yes, Lord.", "geneva": "And when hee was come into the house, the blinde came to him, and Iesus saide vnto them, Beleeue yee that I am able to doe this? And they sayd vnto him, Yea, Lord.", "wycliffe": "And whanne he cam in to the hous, the blynde men camen to hym; and Jhesus seide to hem, What wolen ye, that I do to you? And thei seiden, Lord, that oure iyen be opened. And Jhesus seide, Bileuen ye, that Y mai do this thing to you? Thei seien to him, Yhe, Lord.", "rotherham": "And, when he entered the house, the blind men came unto him,—and Jesus saith unto them, Believe ye, that I can, do this? They say unto him, Yea, Lord!", "weymouth": "And when He had gone indoors, they came to Him. \"Do you believe that I can do this?\" He asked them. \"Yes, Sir,\" they replied.", "darby": "And when he was come to the house, the blind [men] came to him. And Jesus says to them, Do ye believe that I am able to do this? They say to him, Yea, Lord.", "twenty": "When he had gone indoors, the blind men came up to him; and Jesus asked them: “Do you believe that I am able to do this?” “Yes, Master!” they answered.", "acv": "And when he came into the house, the blind men came to him. And Jesus says to them, Believe ye that I am able to do this? They say to him, Yes, Lord.", "anderson": "And when he had entered the house, the blind men came to him. And Jesus said to them: Do you believe that I am able to do this? They said to him, Yes, Lord.", "haweis": "So when he came into the house, the blind men came to him: and Jesus said to them, Believe ye that I am able to do this? They said unto him, Yes, Lord.", "noyes": "And when he had come into the house, the blind men came to him; and Jesus saith to them, Do ye believe that I am able to do this? They say to him, Yea, Lord.", "webster": "And when he had come into the house, the blind men came to him: and Jesus saith to them, Believe ye that I am able to do this? They said to him, Yes, Lord.", "vulgate": "cum autem venisset domum accesserunt ad eum caeci et dicit eis Iesus creditis quia possum hoc facere vobis dicunt ei utique Domine;"}}, {"v": 29, "ref": "9:29", "o": "τότε ἥψατο τῶν ὀφθαλμῶν αὐτῶν λέγων· Κατὰ τὴν πίστιν ὑμῶν γενηθήτω ὑμῖν.", "en": {"kjv": "Then touched he their eyes, saying, According to your faith be it unto you.", "web": "Then he touched their eyes, saying, “According to your faith be it done to you.”", "bsb": "Then He touched their eyes and said, “According to your faith will it be done to you.”", "asv": "Then touched he their eyes, saying, According to your faith be it done unto you.", "ylt": "Then touched he their eyes, saying, `According to your faith let it be to you,'", "tyndale": "Then touched he their eyes saying: acordynge to youre faythe be it vnto you.", "dra": "Then he touched their eyes, saying, According to your faith, be it done unto you.", "bbe": "Then he put his hand on their eyes, saying, As your faith is, let it be done to you.", "geneva": "Then touched he their eyes, saying, According to your faith be it vnto you.", "wycliffe": "Thanne he touchide her iyen, and seide, Aftir youre feith be it doon to you.", "rotherham": "Then touched he their eyes, saying, According to your faith, be it done unto you.", "weymouth": "So He touched their eyes and said, \"According to your faith let it be to you.\"", "darby": "Then he touched their eyes, saying, According to your faith, be it unto you.", "twenty": "Upon that he touched their eyes, and said: “It shall be according to your faith.”", "acv": "Then he touched their eyes, saying, According to your faith may it happen to you.", "anderson": "Then he touched their eyes, and said: According to your faith, be it to you.", "haweis": "Then he touched their eyes, saying, According to your faith be it unto you.", "noyes": "Then he touched their eyes, saying, According to your faith be it done to you.", "webster": "Then he touched their eyes, saying, According to your faith, be it to you.", "vulgate": "tunc tetigit oculos eorum dicens secundum fidem vestram fiat vobis;"}}, {"v": 30, "ref": "9:30", "o": "καὶ ἠνεῴχθησαν αὐτῶν οἱ ὀφθαλμοί. καὶ ⸀ἐνεβριμήθη αὐτοῖς ὁ Ἰησοῦς λέγων· Ὁρᾶτε μηδεὶς γινωσκέτω·", "en": {"kjv": "And their eyes were opened; and Jesus straitly charged them, saying, See that no man know it.", "web": "Their eyes were opened. Jesus strictly commanded them, saying, “See that no one knows about this.”", "bsb": "And their eyes were opened. Jesus warned them sternly, “See that no one finds out about this!”", "asv": "And their eyes were opened. And Jesus strictly charged them, saying, See that no man know it.", "ylt": "and their eyes were opened, and Jesus strictly charged them, saying, `See, let no one know;'", "tyndale": "And their eyes were opened. And Iesus charged the saying: Se yt no man knowe of it.", "dra": "And their eyes were opened, and Jesus strictly charged them, saying, See that no man know this.", "bbe": "And their eyes were made open. And Jesus said to them sharply, Let no man have knowledge of it.", "geneva": "And their eyes were opened, and Iesus gaue them great charge, saying, See that no man knowe it.", "wycliffe": "And the iyen of hem were opened. And Jhesus thretenede hem, and seide, Se ye, that no man wite.", "rotherham": "And their eyes were opened. And Jesus, sternly charged them, saying, Mind! let no one know!", "weymouth": "Then their eyes were opened. And assuming a stern tone Jesus said to them, \"Be careful to let no one know.\"", "darby": "And their eyes were opened; and Jesus charged them sharply, saying, See, let no man know it.", "twenty": "Then their eyes were opened. Jesus sternly cautioned them. “See that no one knows of it,” he said.", "acv": "And their eyes were opened. And Jesus strictly warned them, saying, See that no man knows it.", "anderson": "And their eyes were opened; and Jesus strictly charged them, saying: See that no one know it,", "haweis": "And their eyes were opened; and Jesus strictly charged them, saying, Take care that no person know it.", "noyes": "And their eyes were opened. And Jesus sternly charged them, saying, See that no one know it.", "webster": "And their eyes were opened; and Jesus strictly charged them, saying, See [that] no man know [it].", "vulgate": "et aperti sunt oculi illorum et comminatus est illis Iesus dicens videte ne quis sciat;"}}, {"v": 31, "ref": "9:31", "o": "οἱ δὲ ἐξελθόντες διεφήμισαν αὐτὸν ἐν ὅλῃ τῇ γῇ ἐκείνῃ.", "en": {"kjv": "But they, when they were departed, spread abroad his fame in all that country.", "web": "But they went out and spread abroad his fame in all that land.", "bsb": "But they went out and spread the news about Him throughout the land.", "asv": "But they went forth, and spread abroad his fame in all that land.", "ylt": "but they, having gone forth, did spread his fame in all that land.", "tyndale": "But they assone as they were departed spreed abroade his name through oute all the londe.", "dra": "But they going out, spread his fame abroad in all that country.", "bbe": "But they went out and gave news of him in all that land.", "geneva": "But when they were departed, they spread abroad his fame throughout all that land.", "wycliffe": "But thei yeden out, and diffameden hym thorou al that lond.", "rotherham": "They, however, going forth, made him known throughout the whole of that land.", "weymouth": "But they went out and published His fame in all that district.", "darby": "But they, when they were gone out, spread his name abroad in all that land.", "twenty": "But the men went out, and spread the news about him through all that part of the country.", "acv": "But having departed, they widely proclaimed him in all that land.", "anderson": "But they went out and spread his fame abroad in all that land.", "haweis": "But they going forth, blazoned his fame through all that country.", "noyes": "But they went out, and spread abroad his fame in all that country.", "webster": "But they, when they had departed, spread abroad his fame in all that country.", "vulgate": "illi autem exeuntes diffamaverunt eum in tota terra illa;"}}, {"v": 32, "ref": "9:32", "o": "Αὐτῶν δὲ ἐξερχομένων ἰδοὺ προσήνεγκαν αὐτῷ ⸀ἄνθρωπον κωφὸν δαιμονιζόμενον·", "en": {"kjv": "As they went out, behold, they brought to him a dumb man possessed with a devil.", "web": "As they went out, behold, a mute man who was demon possessed was brought to him.", "bsb": "As they were leaving, a demon-possessed man who was mute was brought to Jesus.", "asv": "And as they went forth, behold, there was brought to him a dumb man possessed with a demon.", "ylt": "And as they are coming forth, lo, they brought to him a man dumb, a demoniac,", "tyndale": "As they went out beholde they brought to hym a dome ma possessed af a devyll.", "dra": "And when they were gone out, behold they brought him a dumb man, possessed with a devil.", "bbe": "And while they were going away, there came to him a man without the power of talking, and with an evil spirit.", "geneva": "And as they went out, beholde, they brought to him a domme man possessed with a deuill.", "wycliffe": "And whanne thei weren gon out, loo! thei brouyten to hym a doumbe man, hauynge a deuel.", "rotherham": "And, as, they, were going forth, lo! there was brought to him, a dumb man, demonized.", "weymouth": "And as they were leaving His presence a dumb demoniac was brought to Him.", "darby": "But as these were going out, behold, they brought to him a dumb man possessed by a demon.", "twenty": "Just as they were going out, some people brought up to Jesus a dumb man who was possessed by a demon;", "acv": "And after they departed, behold, they brought to him a mute man possessed with a demon.", "anderson": "And as they were going out, behold, they brought to him a dumb man possessed with a demon.", "haweis": "And when they were coming out, behold, they brought unto him a man, dumb, a demoniac.", "noyes": "And as they were going out, lo! they brought to him a dumb man, possessed by a demon.", "webster": "As thy went out, behold, they brought to him a dumb man possessed with a demon.", "vulgate": "egressis autem illis ecce obtulerunt ei hominem mutum daemonium habentem;"}}, {"v": 33, "ref": "9:33", "o": "καὶ ἐκβληθέντος τοῦ δαιμονίου ἐλάλησεν ὁ κωφός. καὶ ἐθαύμασαν οἱ ὄχλοι λέγοντες· Οὐδέποτε ἐφάνη οὕτως ἐν τῷ Ἰσραήλ.", "en": {"kjv": "And when the devil was cast out, the dumb spake: and the multitudes marvelled, saying, It was never so seen in Israel.", "web": "When the demon was cast out, the mute man spoke. The multitudes marveled, saying, “Nothing like this has ever been seen in Israel!”", "bsb": "And when the demon had been driven out, the man began to speak. The crowds were amazed and said, “Nothing like this has ever been seen in Israel!”", "asv": "And when the demon was cast out, the dumb man spake: and the multitudes marvelled, saying, It was never so seen in Israel.", "ylt": "and the demon having been cast out, the dumb spake, and the multitude did wonder, saying that `It was never so seen in Israel:'", "tyndale": "And as sone as the devyll was cast oute the domme spake: And the people merveled sayinge: it was never so sene in Israel.", "dra": "And after the devil was cast out, the dumb man spoke, and the multitudes wondered, saying, Never was the like seen in Israel.", "bbe": "And when the evil spirit had been sent out, the man had the power of talking: and they were all surprised, saying, Such a thing has never been seen in Israel.", "geneva": "And when the deuill was cast out, the domme spake: then the multitude marueiled, saying, The like was neuer seene in Israel.", "wycliffe": "And whanne the deuel was cast out, the doumb man spak. And the puple wondride, and seide, It hath not be say thus in Israel.", "rotherham": "And, the demon being cast out, the dumb man spoke; and the multitudes marvelled, saying,—Never, was it seen thus, in Israel.", "weymouth": "When the demon was expelled, the dumb man could speak. And the crowds exclaimed in astonishment, \"Never was such a thing seen in Israel.\"", "darby": "And the demon having been cast out, the dumb spake. And the crowds were astonished, saying, It has never been seen thus in Israel.", "twenty": "and, as soon as the demon had been driven out, the dumb man spoke. The people were astonished at this, and exclaimed: “Nothing like this has ever been seen in Israel!”", "acv": "And when the demon was cast out, the mute man spoke. And the multitudes marveled, saying, It was never so seen in Israel.", "anderson": "And after the demon had been cast out, the dumb man spoke. And the multitudes were astonished, and said: Never was it seen thus in Israel.", "haweis": "And when the devil was cast out, the dumb man spoke: and the multitudes marvelled, saying, Never at any time was the like to this seen in Israel.", "noyes": "And when the demon was cash out, the dumb man spoke. And the multitudes marveled, saying, Never was the like seen in Israel.", "webster": "And when the demon was cast out, the dumb spoke: and the multitudes marveled, saying, It was never so seen in Israel.", "vulgate": "et eiecto daemone locutus est mutus et miratae sunt turbae dicentes numquam paruit sic in Israhel;"}}, {"v": 34, "ref": "9:34", "o": "οἱ δὲ Φαρισαῖοι ἔλεγον· Ἐν τῷ ἄρχοντι τῶν δαιμονίων ἐκβάλλει τὰ δαιμόνια.", "en": {"kjv": "But the Pharisees said, He casteth out devils through the prince of the devils.", "web": "But the Pharisees said, “By the prince of the demons, he casts out demons.”", "bsb": "But the Pharisees said, “It is by the prince of demons that He drives out demons.”", "asv": "But the Pharisees said, By the prince of the demons casteth he out demons.", "ylt": "but the Pharisees said, `By the ruler of the demons he doth cast out the demons.'", "tyndale": "But the Pharises sayde: he casteth oute devyls by the power of the chefe devyll.", "dra": "But the Pharisees said, By the prince of devils he casteth out devils.", "bbe": "But the Pharisees said, By the ruler of evil spirits, he sends evil spirits out of men.", "geneva": "But the Pharises saide, He casteth out deuils, through the prince of deuils.", "wycliffe": "But the Farisees seiden, In the prince of deuelis he castith out deuelis.", "rotherham": "[But, the Pharisees, beg to say, In the ruler of the demons, is he casting out the demons.]", "weymouth": "But the Pharisees maintained, \"It is by the power of the Prince of the demons that he drives out the demons.\"", "darby": "But the Pharisees said, He casts out the demons through the prince of the demons.", "twenty": "But the Pharisees said: “He drives out the demons by the help of the chief of the demons.”", "acv": "But the Pharisees said, By the ruler of the demons he casts out demons.", "anderson": "But the Pharisees said: He casts out the demons by the prince of the demons.", "haweis": "But the Pharisees said, By the prince of the devils doth he cast the devils out.", "noyes": "But the Pharisees said, He casteth out the demons through the prince of the demons.", "webster": "But the Pharisees said, He casteth out demons, through the prince of the demons.", "vulgate": "Pharisaei autem dicebant in principe daemoniorum eicit daemones;"}}, {"v": 35, "ref": "9:35", "o": "Καὶ περιῆγεν ὁ Ἰησοῦς τὰς πόλεις πάσας καὶ τὰς κώμας, διδάσκων ἐν ταῖς συναγωγαῖς αὐτῶν καὶ κηρύσσων τὸ εὐαγγέλιον τῆς βασιλείας καὶ θεραπεύων πᾶσαν νόσον καὶ πᾶσαν ⸀μαλακίαν.", "en": {"kjv": "And Jesus went about all the cities and villages, teaching in their synagogues, and preaching the gospel of the kingdom, and healing every sickness and every disease among the people.", "web": "Jesus went about all the cities and the villages, teaching in their synagogues, and preaching the Good News of the Kingdom, and healing every disease and every sickness among the people.", "bsb": "Jesus went through all the towns and villages, teaching in their synagogues, preaching the gospel of the kingdom, and healing every disease and sickness.", "asv": "And Jesus went about all the cities and the villages, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of disease and all manner of sickness.", "ylt": "And Jesus was going up and down all the cities and the villages, teaching in their synagogues, and proclaiming the good news of the reign, and healing every sickness and every malady among the people.", "tyndale": "And Iesus went about all cities and tounes teachynge in their synagoges and preachyng the glad tidinges of ye kyngdome and healinge all maner sicknes and desease amoge ye people.", "dra": "And Jesus went about all the cities and towns, teaching in their synagogues, and preaching the gospel of the kingdom, and healing every disease, and every infirmity.", "bbe": "And Jesus went about all the towns and small places, teaching in their Synagogues and preaching the good news of the kingdom and making well all sorts of disease and pain.", "geneva": "And Iesus went about all cities and townes, teaching in their Synagogues, and preaching the Gospel of the kingdome, and healing euery sickenesse and euery disease among the people.", "wycliffe": "And Jhesus wente `aboute alle the `citees and castels, techinge in the synagogis of hem, and prechynge the gospel of the kyngdom, and helynge euery langour and euery sijknesse.", "rotherham": "And Jesus was going round all the cities and the villages, teaching in their synagogues, and proclaiming the glad-message of the kingdom,—and curing every disease, and every infirmity.", "weymouth": "And Jesus continued His circuits through all the towns and the villages, teaching in their synagogues and proclaiming the Good News of the Kingdom, and curing every kind of disease and infirmity.", "darby": "And Jesus went round all the cities and the villages, teaching in their synagogues, and preaching the glad tidings of the kingdom, and healing every disease and every bodily weakness.", "twenty": "Jesus went round all the towns and the villages, teaching in their Synagogues, proclaiming the Good News of the Kingdom, and curing every kind of disease and every kind of sickness.", "acv": "And Jesus went about all the cities and the villages, teaching in their synagogues, and preaching the good news of the kingdom, and healing every sickness and every disease among the people.", "anderson": "And Jesus went through all the cities and villages, teaching in their synagogues, and preaching the gospel of the kingdom, and curing every disease and every infirmity.", "haweis": "And Jesus took a circuit through all the cities and villages, teaching in their synagogues, and preaching the gospel of the kingdom, and healing all manner of disease, and every malady among the people.", "noyes": "And Jesus went round all the cities and villages, teaching in their synagogues, and preaching the glad tidings of the kingdom, and healing every sickness and every disease.", "webster": "And Jesus went about all the cities and villages, teaching in their synagogues, and preaching the gospel of the kingdom, and healing every sickness, and every disease among the people.", "vulgate": "et circumibat Iesus civitates omnes et castella docens in synagogis eorum et praedicans evangelium regni et curans omnem languorem et omnem infirmitatem;"}}, {"v": 36, "ref": "9:36", "o": "Ἰδὼν δὲ τοὺς ὄχλους ἐσπλαγχνίσθη περὶ αὐτῶν ὅτι ἦσαν ἐσκυλμένοι καὶ ἐρριμμένοι ⸀ὡσεὶ πρόβατα μὴ ἔχοντα ποιμένα.", "en": {"kjv": "But when he saw the multitudes, he was moved with compassion on them, because they fainted, and were scattered abroad, as sheep having no shepherd.", "web": "But when he saw the multitudes, he was moved with compassion for them, because they were harassed and scattered, like sheep without a shepherd.", "bsb": "When He saw the crowds, He was moved with compassion for them, because they were harassed and helpless, like sheep without a shepherd.", "asv": "But when he saw the multitudes, he was moved with compassion for them, because they were distressed and scattered, as sheep not having a shepherd.", "ylt": "And having seen the multitudes, he was moved with compassion for them, that they were faint and cast aside, as sheep not having a shepherd,", "tyndale": "But when he sawe the people he had copassion on the because they were pyned awaye and scattered abroade eve as shepe havige no shepherd.", "dra": "And seeing the multitudes, he had compassion on them: because they were distressed, and lying like sheep that have no shepherd.", "bbe": "But when he saw all the people he was moved with pity for them, because they were troubled and wandering like sheep without a keeper.", "geneva": "But when he saw the multitude, he had compassion vpon them, because they were dispersed, and scattered abroade, as sheepe hauing no shepheard.", "wycliffe": "And he siy the puple, and hadde reuthe on hem; for thei weren trauelid, and liggynge as scheep not hauynge a scheepherde.", "rotherham": "But, seeing the multitudes, he was moved with compassion concerning them, because they were torn and thrown down, like sheep hating no shepherd.", "weymouth": "And when He saw the crowds He was touched with pity for them, because they were distressed and were fainting on the ground like sheep which have no shepherd.", "darby": "But when he saw the crowds he was moved with compassion for them, because they were harassed, and cast away as sheep not having a shepherd.", "twenty": "But, when he saw the crowds, his heart was moved with compassion for them, because they were distressed and harassed, ‘like sheep without a shepherd’;", "acv": "But when he saw the multitudes, he felt compassion for them, because they were troubled and dejected, as sheep having no shepherd.", "anderson": "And when he saw the multitudes, he was moved with compassion for them, because they were troubled and scattered as sheep that had no shepherd.", "haweis": "And beholding the multitudes, he was moved with compassion for them, because they were fainting, and lying here and there, as sheep that had no shepherd.", "noyes": "And seeing the multitudes, he was moved with compassion for them, because they were harassed and scattered about, as sheep having no shepherd.", "webster": "But when he saw the multitudes, he was moved with compassion on them, because they fainted, and were scattered abroad, as sheep having no shepherd.", "vulgate": "videns autem turbas misertus est eis quia erant vexati et iacentes sicut oves non habentes pastorem;"}}, {"v": 37, "ref": "9:37", "o": "τότε λέγει τοῖς μαθηταῖς αὐτοῦ· Ὁ μὲν θερισμὸς πολύς, οἱ δὲ ἐργάται ὀλίγοι·", "en": {"kjv": "Then saith he unto his disciples, The harvest truly is plenteous, but the labourers are few;", "web": "Then he said to his disciples, “The harvest indeed is plentiful, but the laborers are few.", "bsb": "Then He said to His disciples, “The harvest is plentiful, but the workers are few.", "asv": "Then saith he unto his disciples, The harvest indeed is plenteous, but the laborers are few.", "ylt": "then saith he to his disciples, `The harvest indeed is abundant, but the workmen few;", "tyndale": "Then sayde he to hys disciples: the hervest is greate but the laborers are feawe.", "dra": "Then he saith to his disciples, The harvest indeed is great, but the labourers are few.", "bbe": "Then he said to his disciples, There is much grain but not enough men to get it in.", "geneva": "Then saide he to his disciples, Surely the haruest is great, but the labourers are fewe.", "wycliffe": "Thanne he seide to hise disciplis, Sotheli there is myche ripe corn, but fewe werk men.", "rotherham": "Then, saith he unto his disciples, The harvest, indeed, is great, but, the labourers, few;", "weymouth": "Then He said to His disciples, \"The harvest is abundant, but the reapers are few;", "darby": "Then saith he to his disciples, The harvest [is] great and the workmen [are] few;", "twenty": "and he said to his disciples: “The harvest is abundant, but the labourers are few.", "acv": "Then he says to his disciples, The harvest truly is plentiful, but the workmen are few.", "anderson": "Then he said to his disciples: The harvest is abundant, but the laborers are few.", "haweis": "Then said he to his disciples, The harvest indeed is abundant, but the labourers are few;", "noyes": "Then he saith to his disciples, The harvest indeed is great, but the laborers are few.", "webster": "Then saith he to his disciples, The harvest truly [is] plentiful, but the laborers [are] few.", "vulgate": "tunc dicit discipulis suis messis quidem multa operarii autem pauci;"}}, {"v": 38, "ref": "9:38", "o": "δεήθητε οὖν τοῦ κυρίου τοῦ θερισμοῦ ὅπως ἐκβάλῃ ἐργάτας εἰς τὸν θερισμὸν αὐτοῦ.", "en": {"kjv": "Pray ye therefore the Lord of the harvest, that he will send forth labourers into his harvest.", "web": "Pray therefore that the Lord of the harvest will send out laborers into his harvest.”", "bsb": "Ask the Lord of the harvest, therefore, to send out workers into His harvest.”", "asv": "Pray ye therefore the Lord of the harvest, that he send forth laborers into his harvest.", "ylt": "beseech ye therefore the Lord of the harvest, that he may put forth workmen to His harvest.'", "tyndale": "Wherfore praye the Lorde of the harvest to sende forthe laborers into hys harvest.", "dra": "Pray ye therefore the Lord of the harvest, that he send forth labourers into his harvest.", "bbe": "Make prayer, then, to the Lord of the grain-fields, that he may send out workers to get in his grain.", "geneva": "Wherefore pray the Lord of the haruest, that he woulde sende foorth labourers into his haruest.", "wycliffe": "Therfor preye ye the lord of the ripe corn, that he sende werke men in to his ripe corn.", "rotherham": "Beg ye, therefore, of the Lord of the harvest,—That he would thrust forth labourers, into his harvest.", "weymouth": "therefore entreat the Owner of the Harvest to send out reapers into His fields.\"", "darby": "supplicate therefore the Lord of the harvest, that he send forth workmen unto his harvest.", "twenty": "Therefore pray to the Owner of the harvest to send labourers to gather in his harvest.”", "acv": "Pray ye therefore the Lord of the harvest, that he will send forth workmen into his harvest.", "anderson": "Therefore pray the Lord of the harvest to send out laborers into his harvest.", "haweis": "entreat therefore the Lord of the harvest, that he would send forth workmen for his harvest.", "noyes": "Pray therefore the Lord of the harvest to send forth laborers for his harvest.", "webster": "Pray ye therefore the Lord of the harvest, that he will send forth laborers into his harvest.", "vulgate": "rogate ergo dominum messis ut eiciat operarios in messem suam;"}}]}, {"c": 10, "verses": [{"v": 1, "ref": "10:1", "o": "Καὶ προσκαλεσάμενος τοὺς δώδεκα μαθητὰς αὐτοῦ ἔδωκεν αὐτοῖς ἐξουσίαν πνευμάτων ἀκαθάρτων ὥστε ἐκβάλλειν αὐτὰ καὶ θεραπεύειν πᾶσαν νόσον καὶ πᾶσαν μαλακίαν.", "en": {"kjv": "And when he had called unto him his twelve disciples, he gave them power against unclean spirits, to cast them out, and to heal all manner of sickness and all manner of disease.", "web": "He called to himself his twelve disciples, and gave them authority over unclean spirits, to cast them out, and to heal every disease and every sickness.", "bsb": "And calling His twelve disciples to Him, Jesus gave them authority over unclean spirits, so that they could drive them out and heal every disease and sickness.", "asv": "And he called unto him his twelve disciples, and gave them authority over unclean spirits, to cast them out, and to heal all manner of disease and all manner of sickness.", "ylt": "And having called to him his twelve disciples, he gave to them power over unclean spirits, so as to be casting them out, and to be healing every sickness, and every malady.", "tyndale": "And he called his .xii. disciples vnto hym and gave them power over vnclene sprites to cast them oute and to heale all maner of sicknesses and all maner of deseases.", "dra": "And having called his twelve disciples together, he gave them power over unclean spirits, to cast them out, and to heal all manner of diseases, and all manner of infirmities.", "bbe": "And he got together his twelve disciples and gave them the power of driving out unclean spirits, and of making well all sorts of disease and pain.", "geneva": "And hee called his twelue disciples vnto him, and gaue them power against vncleane spirits, to cast them out, and to heale euery sickenesse, and euery disease.", "wycliffe": "And whanne his twelue disciplis weren clepid togidere, he yaf to hem powere of vnclene spiritis, to caste hem out of men, and to heele eueri langour, and sijknesse.", "rotherham": "And, calling near his twelve disciples, he gave them authority over impure spirits,—so as to be casting them out, and curing every disease and every infirmity.", "weymouth": "Then He called to Him His twelve disciples and gave them authority over foul spirits, to drive them out; and to cure every kind of disease and infirmity.", "darby": "And having called to [him] his twelve disciples, he gave them power over unclean spirits, so that they should cast them out, and heal every disease and every bodily weakness.", "twenty": "Calling his twelve Disciples to him, Jesus gave them authority over foul spirits, so that they could drive them out, as well as the power of curing every kind of disease and every kind of sickness.", "acv": "And having called in his twelve disciples, he gave them authority over unclean spirits, so as to cast them out, and to heal every sickness and every disease.", "anderson": "And he called to him his twelve disciples, and gave them authority over unclean spirits, so that they might cast them out, and care every disease and every infirmity.", "haweis": "AND having called unto him his twelve disciples, he gave them authority over unclean spirits, to cast them out, and to cure every disease, and every malady.", "noyes": "And he called to him his twelve disciples, and gave them power over unclean spirits, to cast them out, and to heal every sickness and every disease.", "webster": "And when he had called to [him] his twelve disciples, he gave them power [against] unclean spirits, to cast them out, and to heal all manner of sickness, and all manner of disease.", "vulgate": "et convocatis duodecim discipulis suis dedit illis potestatem spirituum inmundorum ut eicerent eos et curarent omnem languorem et omnem infirmitatem;"}}, {"v": 2, "ref": "10:2", "o": "τῶν δὲ δώδεκα ἀποστόλων τὰ ὀνόματά ἐστιν ταῦτα· πρῶτος Σίμων ὁ λεγόμενος Πέτρος καὶ Ἀνδρέας ὁ ἀδελφὸς ⸀αὐτοῦ, Ἰάκωβος ὁ τοῦ Ζεβεδαίου καὶ Ἰωάννης ὁ ἀδελφὸς αὐτοῦ,", "en": {"kjv": "Now the names of the twelve apostles are these; The first, Simon, who is called Peter, and Andrew his brother; James the son of Zebedee, and John his brother;", "web": "Now the names of the twelve apostles are these. The first, Simon, who is called Peter; Andrew, his brother; James the son of Zebedee; John, his brother;", "bsb": "These are the names of the twelve apostles: first Simon, called Peter, and his brother Andrew; James son of Zebedee, and his brother John;", "asv": "Now the names of the twelve apostles are these: The first, Simon, who is called Peter, and Andrew his brother; James thesonof Zebedee, and John his brother;", "ylt": "And of the twelve apostles the names are these: first, Simon, who is called Peter, and Andrew his brother; James of Zebedee, and John his brother;", "tyndale": "The names of the .xii. Apostles are these. The fyrst Simon called also Peter: and Andrew his brother. Iames the sonne of zebede aud Ihon his brother.", "dra": "And the names of the twelve Apostles are these: The first, Simon who is called Peter, and Andrew his brother,", "bbe": "Now the names of the twelve are these: The first, Simon, who is named Peter, and Andrew, his brother; James, the son of Zebedee, and John, his brother;", "geneva": "Nowe the names of the twelue Apostles are these. The first is Simon, called Peter, and Andrew his brother: Iames the sonne of Zebedeus, and Iohn his brother.", "wycliffe": "And these ben the names of the twelue apostlis; the firste, Symount, that is clepid Petre, and Andrew, his brothir; James of Zebede, and Joon, his brothir; Filip, and Bartholomeu;", "rotherham": "Now, the twelve apostles’ names, are these:—first Simon, who is called Peter, and Andrew his brother,—and James, the son of Zebedee, and John, his brother;", "weymouth": "Now the names of the twelve Apostles were these: first, Simon called Peter, and his brother Andrew; James the son of Zabdi, and his brother John;", "darby": "Now the names of the twelve apostles are these: first, Simon, who was called Peter, and Andrew his brother; James the [son] of Zebedee, and John his brother;", "twenty": "The names of the twelve Apostles are these: First Simon, also known as Peter, and his brother Andrew; James the son of Zebediah, and his brother John;", "acv": "Now the names of the twelve apostles are these: First, Simon, who is called Peter, and Andrew his brother, James the son of Zebedee, and John his brother,", "anderson": "Now these are the names of the twelve apostles: the first, Simon, who is called Peter, and Andrew his brother; James the son of Zebedee, and John his brother;", "haweis": "Now these are the names of the twelve apostles; The first, Simon, who is called Peter, and Andrew his brother; James son of Zebedee, and John his brother;", "noyes": "Now the names of the twelve apostles are these: first, Simon, who is called Peter, and Andrew his brother, and James the son of Zebedee, and John his brother;", "webster": "Now the names of the twelve apostles are these; The first, Simon, who is called Peter, and Andrew his brother; James [the son] of Zebedee, and John his brother;", "vulgate": "duodecim autem apostolorum nomina sunt haec primus Simon qui dicitur Petrus et Andreas frater eius;"}}, {"v": 3, "ref": "10:3", "o": "Φίλιππος καὶ Βαρθολομαῖος, Θωμᾶς καὶ Μαθθαῖος ὁ τελώνης, Ἰάκωβος ὁ τοῦ Ἁλφαίου καὶ ⸀Θαδδαῖος,", "en": {"kjv": "Philip, and Bartholomew; Thomas, and Matthew the publican; James the son of Alpheus, and Lebbeus, whose surname was Thaddeus;", "web": "Philip; Bartholomew; Thomas; Matthew the tax collector; James the son of Alphaeus; Lebbaeus, who was also called Thaddaeus;", "bsb": "Philip and Bartholomew; Thomas and Matthew the tax collector; James son of Alphaeus, and Thaddaeus;", "asv": "Philip, and Bartholomew; Thomas, and Matthew the publican; James the son of Alphæus, and Thaddæus;", "ylt": "Philip, and Bartholomew; Thomas, and Matthew the tax-gatherer; James of Alpheus, and Lebbeus who was surnamed Thaddeus;", "tyndale": "Philip and Bartlemew. Thomas and Mathew the Publican. Iames the sonne of Alphe and Lebbeus otherwyse called Taddeus.", "dra": "James the son of Zebedee, and John his brother, Philip and Bartholomew, Thomas and Matthew the publican, and James the son of Alpheus, and Thaddeus,", "bbe": "Philip and Bartholomew; Thomas and Matthew, the tax-farmer; James, the son of Alphaeus, and Thaddaeus;", "geneva": "Philippe and Bartlemewe: Thomas, and Matthewe that Publicane: Iames the sonne of Alpheus, and Lebbeus whose surname was Thaddeus:", "wycliffe": "Thomas, and Matheu, pupplican; and James Alfey, and Tadee;", "rotherham": "Philip, and Bartholomew,—Thomas, and Matthew, the tax-collector; James, the son of Alphaeus, and Thadaeus;", "weymouth": "Philip and Bartholomew, Thomas and Matthew the tax-gatherer, James the son of Alphaeus, and Thaddaeus;", "darby": "Philip and Bartholomew; Thomas, and Matthew the tax-gatherer; James the [son] of Alphaeus, and Lebbaeus, who was surnamed Thaddaeus;", "twenty": "Philip and Bartholomew; Thomas and Matthew the tax-gather; James the son of Alphaeus, and Thaddaeus;", "acv": "Philip, and Bartholomew, Thomas, and Matthew the tax collector, James the son of Alphaeus, and Lebbaeus who was surnamed Thaddaeus,", "anderson": "Philip and Bartholomew, Thomas, and Matthew the publican; James the son of Alphæus, and Lebbæus, who was surnamed Thaddæus;", "haweis": "Philip, and Bartholomew; Thomas, and Matthew the tax-gatherer; James son of Alpheus, and Lebbeus, whose surname is Thaddeus;", "noyes": "Philip and Bartholomew; Thomas and Matthew the publican; James the son of Alphaeus, and Lebbaeus;", "webster": "Philip, and Bartholomew; Thomas, and Matthew the publican; James [the son] of Alpheus, and Lebbeus, whose surname was Thaddeus;", "vulgate": "Iacobus Zebedaei et Iohannes frater eius Philippus et Bartholomeus Thomas et Mattheus publicanus et Iacobus Alphei et Thaddeus;"}}, {"v": 4, "ref": "10:4", "o": "Σίμων ὁ ⸀Καναναῖος καὶ Ἰούδας ⸀ὁ Ἰσκαριώτης ὁ καὶ παραδοὺς αὐτόν.", "en": {"kjv": "Simon the Canaanite, and Judas Iscariot, who also betrayed him.", "web": "Simon the Canaanite; and Judas Iscariot, who also betrayed him.", "bsb": "Simon the Zealot, and Judas Iscariot, who betrayed Jesus.", "asv": "Simon the Cananæan, and Judas Iscariot, who also betrayed him.", "ylt": "Simon the Cananite, and Judas Iscariot, who did also deliver him up.", "tyndale": "Simon of Cane and Iudas Iscarioth which also betrayed hym.", "dra": "Simon the Cananean, and Judas Iscariot, who also betrayed him.", "bbe": "Simon the Zealot, and Judas Iscariot, who was false to him.", "geneva": "Simon the Cananite, and Iudas Iscariot, who also betraied him.", "wycliffe": "Symount Chananee, and Judas Scarioth, that bitrayede Crist.", "rotherham": "Simon, the zealot, and Judas Iscariot, who also delivered him up.", "weymouth": "Simon the Cananaean, and Judas the Iscariot, who also betrayed Him.", "darby": "Simon the Cananaean, and Judas the Iscariote, who also delivered him up.", "twenty": "Simon the Zealot, and Judas Iscariot — the Apostle who betrayed him.", "acv": "Simon the Canaanite, and Judas Iscariot, who also betrayed him.", "anderson": "Simon the Canaanite, and Judas Iscariot, who also delivered him up.", "haweis": "Simon the Cananite, and Judas Iscariot, who also betrayed him.", "noyes": "Simon of Cana, and Judas Iscariot, he who betrayed him.", "webster": "Simon the Canaanite, and Judas Iscariot, who also betrayed him.", "vulgate": "Simon Cananeus et Iudas Scariotes qui et tradidit eum;"}}, {"v": 5, "ref": "10:5", "o": "Τούτους τοὺς δώδεκα ἀπέστειλεν ὁ Ἰησοῦς παραγγείλας αὐτοῖς λέγων· Εἰς ὁδὸν ἐθνῶν μὴ ἀπέλθητε καὶ εἰς πόλιν Σαμαριτῶν μὴ εἰσέλθητε·", "en": {"kjv": "These twelve Jesus sent forth, and commanded them, saying, Go not into the way of the Gentiles, and into any city of the Samaritans enter ye not:", "web": "Jesus sent these twelve out, and commanded them, saying, “Don’t go among the Gentiles, and don’t enter into any city of the Samaritans.", "bsb": "These twelve Jesus sent out with the following instructions: “Do not go onto the road of the Gentiles or enter any town of the Samaritans.", "asv": "These twelve Jesus sent forth, and charged them, saying, Go not into any way of the Gentiles, and enter not into any city of the Samaritans:", "ylt": "These twelve did Jesus send forth, having given command to them, saying, `To the way of the nations go not away, and into a city of the Samaritans go not in,", "tyndale": "These .xii. sent Iesus and comaunded them sayinge: Go not in to ye wayes yt leade to the gentyls and in to ye cities of ye Samaritans enter ye not.", "dra": "These twelve Jesus sent: commanding them, saying: Go ye not into the way of the Gentiles, and into the city of the Samaritans enter ye not.", "bbe": "These twelve Jesus sent out and gave them orders, saying, Do not go among the Gentiles, or into any town of Samaria,", "geneva": "These twelue did Iesus send forth, and commanded them, saying, Goe not into the way of of the Gentiles, and into the cities of the Samaritans enter yee not:", "wycliffe": "Jhesus sente these twelue, and comaundide hem, and seide, Go ye not `in to the weie of hethene men, and entre ye not in to the citees of Samaritans;", "rotherham": "These twelve, Jesus sent forth, charging them, saying:—Into any way to the nations, do not depart,—and, into any city of Samaritans, do not enter;", "weymouth": "These twelve Jesus sent on a mission, after giving them their instructions: \"Go not,\" He said, \"among the Gentiles, and enter no Samaritan town;", "darby": "These twelve Jesus sent out when he had charged them, saying, Go not off into [the] way of [the] nations, and into a city of Samaritans enter ye not;", "twenty": "These twelve Jesus sent out as his Messengers, after giving them these instructions — “Do not go to the Gentiles, nor enter any Samaritan town,", "acv": "These twelve Jesus sent forth, having ordered them, saying, Go not into a way of the Gentiles, and enter not into a city of the Samaritans,", "anderson": "These twelve Jesus sent forth after he had charged them, saying: Go not into the road that leads to the Gentiles, and enter not a city of the Samaritans.", "haweis": "These twelve did Jesus send forth, commanding them, saying, Go not into the way of the Gentiles, and into any city of the Samaritans enter not:", "noyes": "These twelve Jesus sent forth, when he had charged them, saying, Go not away to gentiles, and enter not any city of the Samaritans;", "webster": "These twelve Jesus sent forth, and commanded them, saying, Go not into the way of the Gentiles, and enter ye not into [any] city of the Samaritans.", "vulgate": "hos duodecim misit Iesus praecipiens eis et dicens in viam gentium ne abieritis et in civitates Samaritanorum ne intraveritis;"}}, {"v": 6, "ref": "10:6", "o": "πορεύεσθε δὲ μᾶλλον πρὸς τὰ πρόβατα τὰ ἀπολωλότα οἴκου Ἰσραήλ.", "en": {"kjv": "But go rather to the lost sheep of the house of Israel.", "web": "Rather, go to the lost sheep of the house of Israel.", "bsb": "Go rather to the lost sheep of Israel.", "asv": "but go rather to the lost sheep of the house of Israel.", "ylt": "and be going rather unto the lost sheep of the house of Israel.", "tyndale": "But go rather to ye lost shepe of the housse of Israel.", "dra": "But go ye rather to the lost sheep of the house of Israel.", "bbe": "But go to the wandering sheep of the house of Israel,", "geneva": "But goe rather to the lost sheepe of the house of Israel.", "wycliffe": "but rather go ye to the scheep of the hous of Israel, that han perischid.", "rotherham": "But be going, rather, unto the lost sheep of the house of Israel.", "weymouth": "but, instead of that, go to the lost sheep of Israel's race.", "darby": "but go rather to the lost sheep of the house of Israel.", "twenty": "but make your way rather to the lost sheep of Israel.", "acv": "but go rather to the lost sheep of the house of Israel.", "anderson": "But go rather to the lost sheep of the house of Israel.", "haweis": "but go rather to the sheep that are lost of the house of Israel.", "noyes": "but go rather to the lost sheep of the house of Israel.", "webster": "But go rather to the lost sheep of the house of Israel.", "vulgate": "sed potius ite ad oves quae perierunt domus Israhel;"}}, {"v": 7, "ref": "10:7", "o": "πορευόμενοι δὲ κηρύσσετε λέγοντες ὅτι Ἤγγικεν ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "And as ye go, preach, saying, The kingdom of heaven is at hand.", "web": "As you go, preach, saying, ‘The Kingdom of Heaven is at hand!’", "bsb": "As you go, preach this message: ‘The kingdom of heaven is near.’", "asv": "And as ye go, preach, saying, The kingdom of heaven is at hand.", "ylt": "`And, going on, proclaim saying that, the reign of the heavens hath come nigh;", "tyndale": "Go and preach sayinge: yt the kyngdome of heve is at hande.", "dra": "And going, preach, saying: The kingdom of heaven is at hand.", "bbe": "And, on your way, say, The kingdom of heaven is near.", "geneva": "And as ye goe, preach, saying, The kingdome of heauen is at hand.", "wycliffe": "And go ye, and preche ye, and seie, that the kyngdam of heuenes shal neiye;", "rotherham": "And, as ye go, proclaim, saying, The kingdom of the heavens hath drawn near!", "weymouth": "And as you go, preach and say, `The Kingdom of the Heavens is close at hand.'", "darby": "And as ye go, preach, saying, The kingdom of the heavens has drawn nigh.", "twenty": "And on your way proclaim that the Kingdom of Heaven is at hand.", "acv": "And while going, preach, saying, The kingdom of the heavens has come near.", "anderson": "And as you go, preach, saying: The kingdom of heaven is at hand.", "haweis": "And as ye go, preach, saying, The kingdom of heaven is approaching.", "noyes": "And, as ye go, proclaim, saying, The kingdom of heaven is at hand.", "webster": "And as ye go, proclaim, saying, The kingdom of heaven is at hand.", "vulgate": "euntes autem praedicate dicentes quia adpropinquavit regnum caelorum;"}}, {"v": 8, "ref": "10:8", "o": "ἀσθενοῦντας θεραπεύετε, ⸂νεκροὺς ἐγείρετε⸃, λεπροὺς καθαρίζετε, δαιμόνια ἐκβάλλετε· δωρεὰν ἐλάβετε, δωρεὰν δότε.", "en": {"kjv": "Heal the sick, cleanse the lepers, raise the dead, cast out devils: freely ye have received, freely give.", "web": "Heal the sick, cleanse the lepers, and cast out demons. Freely you received, so freely give.", "bsb": "Heal the sick, raise the dead, cleanse the lepers, drive out demons. Freely you have received; freely give.", "asv": "Heal the sick, raise the dead, cleanse the lepers, cast out demons: freely ye received, freely give.", "ylt": "infirm ones be healing, lepers be cleansing, dead be raising, demons be casting out--freely ye did receive, freely give.", "tyndale": "Heale the sicke clense the lepers rayse the deed caste oute the devils. Frely ye have receved frely geve agayne.", "dra": "Heal the sick, raise the dead, cleanse the lepers, cast out devils: freely have you received, freely give.", "bbe": "Make well those who are ill, give life to the dead, make lepers clean, send evil spirits out of men; freely it has been given to you, freely give.", "geneva": "Heale the sicke: cleanse the lepers: raise vp the dead: cast out the deuils. Freely ye haue receiued, freely giue.", "wycliffe": "heele ye sike men, reise ye deede men, clense ye mesels, caste ye out deuelis; freeli ye han takun, freli yyue ye.", "rotherham": "Be curing, the sick, raising, the dead,—cleansing, lepers, casting out, demons: freely, ye have, received, freely, give.", "weymouth": "Cure the sick, raise the dead to life, cleanse lepers, drive out demons: you have received without payment, give without payment.", "darby": "Heal [the] infirm, [raise the dead], cleanse lepers, cast out demons: ye have received gratuitously, give gratuitously.", "twenty": "Cure the sick, raise the dead, make the lepers clean, drive out demons. You have received free of cost, give free of cost.", "acv": "Heal those who are feeble, cleanse the lepers, cast out demons. Freely ye received, freely give.", "anderson": "Cure the sick, cleanse the lepers, cast out demons. Freely you have received, freely give.", "haweis": "Heal the sick, cleanse the lepers, raise the dead, cast out devils: freely ye have received, freely give.", "noyes": "Heal the sick, raise the dead, cleanse lepers, cast out demons; freely ye received, freely give.", "webster": "Heal the sick, cleanse the lepers, raise the dead, cast out demons: freely ye have received, freely give.", "vulgate": "infirmos curate mortuos suscitate leprosos mundate daemones eicite gratis accepistis gratis date;"}}, {"v": 9, "ref": "10:9", "o": "μὴ κτήσησθε χρυσὸν μηδὲ ἄργυρον μηδὲ χαλκὸν εἰς τὰς ζώνας ὑμῶν,", "en": {"kjv": "Provide neither gold, nor silver, nor brass in your purses,", "web": "Don’t take any gold, nor silver, nor brass in your money belts.", "bsb": "Do not carry any gold or silver or copper in your belts.", "asv": "Get you no gold, nor silver, nor brass in your purses;", "ylt": "`Provide not gold, nor silver, nor brass in your girdles,", "tyndale": "Posses not golde nor silver nor brassse yn youre gerdels", "dra": "Do not possess gold, nor silver, nor money in your purses:", "bbe": "Take no gold or silver or copper in your pockets;", "geneva": "Possesse not golde, nor siluer, nor money in your girdels,", "wycliffe": "Nyle ye welde gold, nether siluer, ne money in youre girdlis, not a scrippe in the weie,", "rotherham": "Ye may procure—neither gold, nor silver, nor copper, for your belts,—", "weymouth": "\"Provide no gold, nor even silver nor copper to carry in your pockets;", "darby": "Do not provide yourselves with gold, or silver, or brass, for your belts,", "twenty": "Do not provide yourselves with gold, or silver, or pence in your purses;", "acv": "Acquire no gold, nor silver, nor copper in your belts,", "anderson": "Provide for yourselves neither gold, nor silver, nor brass, to put into your purses,", "haweis": "Provide neither gold, nor silver, nor brass in your purses,", "noyes": "Provide neither gold, nor silver, nor brass, in your girdles;", "webster": "Provide neither gold, nor silver, nor brass in your purses;", "vulgate": "nolite possidere aurum neque argentum neque pecuniam in zonis vestris;"}}, {"v": 10, "ref": "10:10", "o": "μὴ πήραν εἰς ὁδὸν μηδὲ δύο χιτῶνας μηδὲ ὑποδήματα μηδὲ ⸀ῥάβδον· ἄξιος γὰρ ὁ ἐργάτης τῆς τροφῆς ⸀αὐτοῦ.", "en": {"kjv": "Nor scrip for your journey, neither two coats, neither shoes, nor yet staves: for the workman is worthy of his meat.", "web": "Take no bag for your journey, neither two coats, nor shoes, nor staff: for the laborer is worthy of his food.", "bsb": "Take no bag for the road, or second tunic, or sandals, or staff; for the worker is worthy of his provisions.", "asv": "no wallet for your journey, neither two coats, nor shoes, nor staff: for the laborer is worthy of his food.", "ylt": "nor scrip for the way, nor two coats, nor sandals, nor staff--for the workman is worthy of his nourishment.", "tyndale": "nor yet scrip towardes your iorney: nether two cotes nether shues nor yet a staffe. For the workma is worthy to have his meate.", "dra": "Nor scrip for your journey, nor two coats, nor shoes, nor a staff; for the workman is worthy of his meat.", "bbe": "Take no bag for your journey and do not take two coats or shoes or a stick: for the workman has a right to his food.", "geneva": "Nor a scrippe for the iourney, neither two coates, neither shoes, nor a staffe: for the workeman is worthie of his meate.", "wycliffe": "nether twei cootis, nethir shoon, nether a yerde; for a werkman is worthi his mete.", "rotherham": "neither satchel for journey, nor two tunics, nor sandals, nor staff; for, worthy, is the labourer, of his maintenance.", "weymouth": "no bag for your journey, nor change of linen, nor shoes, nor stick; for the labourer deserves his food.", "darby": "nor scrip for the way, nor two body coats, nor sandals, nor a staff: for the workman is worthy of his nourishment.", "twenty": "not even with a bag for the journey, or a change of clothes, or sandals, or even a staff; for the worker is worth his food.", "acv": "no bag for the road, nor two coats, nor shoes, nor staffs, for the workman is worthy of his provision.", "anderson": "nor bag for your journey, nor two coats, nor sandals, nor staffs: for the laborer is worthy of his support.", "haweis": "nor a scrip for the journey, nor two coats, nor sandals, nor stick: for the workman is worthy of his food.", "noyes": "nor bag for the journey, nor two coats, nor sandals, nor a staff. For the laborer is worthy of his living.", "webster": "Nor bag for your journey, neither two coats, neither shoes, nor a staff: for the workman is worthy of his food.", "vulgate": "non peram in via neque duas tunicas neque calciamenta neque virgam dignus enim est operarius cibo suo;"}}, {"v": 11, "ref": "10:11", "o": "εἰς ἣν δ’ ἂν πόλιν ἢ κώμην εἰσέλθητε, ἐξετάσατε τίς ἐν αὐτῇ ἄξιός ἐστιν· κἀκεῖ μείνατε ἕως ἂν ἐξέλθητε.", "en": {"kjv": "And into whatsoever city or town ye shall enter, enquire who in it is worthy; and there abide till ye go thence.", "web": "Into whatever city or village you enter, find out who in it is worthy; and stay there until you go on.", "bsb": "Whatever town or village you enter, find out who is worthy there and stay at his house until you move on.", "asv": "And into whatsoever city or village ye shall enter, search out who in it is worthy; and there abide till ye go forth.", "ylt": "`And into whatever city or village ye may enter, inquire ye who in it is worthy, and there abide, till ye may go forth.", "tyndale": "In to whatsoever cite or toune ye shall come enquyre who ys worthy yn it and there abyde till ye goo thence.", "dra": "And into whatsoever city or town you shall enter, inquire who in it is worthy, and there abide till you go thence.", "bbe": "And into whatever town or small place you go, make search there for someone who is respected, and make his house your resting-place till you go away.", "geneva": "And into whatsoeuer citie or towne ye shall come, enquire who is worthy in it, and there abide till yee goe thence.", "wycliffe": "In to what euere citee or castel ye schulen entre, axe ye who therynne is worthi, and there dwelle ye, til ye go out.", "rotherham": "And, into whatsoever city or village ye enter, search out who in it is, worthy, and, there, abide, till ye go forth.", "weymouth": "\"Whatever town or village you enter, inquire for some good man; and make his house your home till you leave the place.", "darby": "But into whatsoever city or village ye enter, inquire who in it is worthy, and there remain till ye go forth.", "twenty": "Whatever town or village you visit, find out who is worthy in that place, and remain there till you leave.", "acv": "And into whatever city or village ye may enter, inquire who in it is worthy, and there abide until ye go forth.", "anderson": "Whatever city or village you enter, inquire who in it is worthy, and there make your home till you go away.", "haweis": "And into whatsoever city or village ye enter, enquire who in it is worthy; and there abide till ye depart.", "noyes": "And into whatever city or town ye enter, inquire who in it is worthy; and there abide till ye leave the place.", "webster": "And into whatever city or town ye shall enter, inquire who in it is worthy, and there abide till ye go thence.", "vulgate": "in quamcumque civitatem aut castellum intraveritis interrogate quis in ea dignus sit et ibi manete donec exeatis;"}}, {"v": 12, "ref": "10:12", "o": "εἰσερχόμενοι δὲ εἰς τὴν οἰκίαν ἀσπάσασθε αὐτήν·", "en": {"kjv": "And when ye come into an house, salute it.", "web": "As you enter into the household, greet it.", "bsb": "As you enter the home, greet its occupants.", "asv": "And as ye enter into the house, salute it.", "ylt": "And coming to the house salute it,", "tyndale": "And whe ye come in to an housse salute ye same.", "dra": "And when you come into the house, salute it, saying: Peace be to this house.", "bbe": "And when you go in, say, May peace be on this house.", "geneva": "And when yee come into an house, salute the same.", "wycliffe": "And whanne ye goon in to an hous, `grete ye it, and seyn, Pees to this hous.", "rotherham": "And, as ye enter the house, salute it;", "weymouth": "When you enter the house, salute it;", "darby": "And as ye enter into a house salute it.", "twenty": "As you enter the house, greet it.", "acv": "And while entering into the house, salute it.", "anderson": "When you go into a house, salute it:", "haweis": "And when ye come into a family, salute it:", "noyes": "And as ye enter the house, salute it.", "webster": "And when ye come into a house, salute it.", "vulgate": "intrantes autem in domum salutate eam;"}}, {"v": 13, "ref": "10:13", "o": "καὶ ἐὰν μὲν ᾖ ἡ οἰκία ἀξία, ἐλθάτω ἡ εἰρήνη ὑμῶν ἐπ’ αὐτήν· ἐὰν δὲ μὴ ᾖ ἀξία, ἡ εἰρήνη ὑμῶν ⸀πρὸς ὑμᾶς ἐπιστραφήτω.", "en": {"kjv": "And if the house be worthy, let your peace come upon it: but if it be not worthy, let your peace return to you.", "web": "If the household is worthy, let your peace come on it, but if it isn’t worthy, let your peace return to you.", "bsb": "If the home is worthy, let your peace rest on it; but if it is not, let your peace return to you.", "asv": "And if the house be worthy, let your peace come upon it: but if it be not worthy, let your peace return to you.", "ylt": "and if indeed the house be worthy, let your peace come upon it; and if it be not worthy, let your peace turn back to you.", "tyndale": "And yf the housse be worthy youre peace shall come apon it. But yf it be not worthy youre peace shall retourne to you agayne.", "dra": "And if that house be worthy, your peace shall come upon it; but if it be not worthy, your peace shall return to you.", "bbe": "And if the house is good enough, let your peace come on it: but if not, let your peace come back to you.", "geneva": "And if the house be worthy, let your peace come vpon it: but if it be not worthie, let your peace returne to you.", "wycliffe": "And if thilk hous be worthi, youre pees schal come on it; but if that hous be not worthi, youre pees schal turne ayen to you.", "rotherham": "And, if the house be worthy, let your peace come upon it, but, if it be not worthy, let your peace, unto you, return.", "weymouth": "and if the house deserves it, the peace you invoke shall come upon it. If not, your peace shall return to you.", "darby": "And if the house indeed be worthy, let your peace come upon it; but if it be not worthy, let your peace return to you.", "twenty": "Then, if the house is worthy, let your blessing rest upon it, but, if it is unworthy, let your blessing return upon yourselves.", "acv": "And if indeed the house is worthy, let your peace come upon it, but if it is not worthy, let your peace return to you.", "anderson": "and if the house be worthy, your peace shall come upon it; but if it be not worthy, your peace shall return to you.", "haweis": "and if the family shall be deserving, your peace shall come upon it: and if it be not deserving, your peace shall return to you.", "noyes": "And if the house be worthy, let your peace come upon it; but if it be not worthy, let your peace return to you.", "webster": "And if the house be worthy, let your peace come upon it: but if it be not worthy, let your peace return to you.", "vulgate": "et siquidem fuerit domus digna veniat pax vestra super eam si autem non fuerit digna pax vestra ad vos revertatur;"}}, {"v": 14, "ref": "10:14", "o": "καὶ ὃς ⸀ἂν μὴ δέξηται ὑμᾶς μηδὲ ἀκούσῃ τοὺς λόγους ὑμῶν, ἐξερχόμενοι ⸀ἔξω τῆς οἰκίας ἢ τῆς πόλεως ἐκείνης ἐκτινάξατε τὸν κονιορτὸν τῶν ποδῶν ὑμῶν.", "en": {"kjv": "And whosoever shall not receive you, nor hear your words, when ye depart out of that house or city, shake off the dust of your feet.", "web": "Whoever doesn’t receive you, nor hear your words, as you go out of that house or that city, shake off the dust from your feet.", "bsb": "And if anyone will not welcome you or heed your words, shake the dust off your feet when you leave that home or town.", "asv": "And whosoever shall not receive you, nor hear your words, as ye go forth out of that house or that city, shake off the dust of your feet.", "ylt": "`And whoever may not receive you nor hear your words, coming forth from that house or city, shake off the dust of your feet,", "tyndale": "And whosoever shall not receave you nor will heare youre preachynge: when ye departe oute of yt housse or that cite shake of the duste of youre fete.", "dra": "And whosoever shall not receive you, nor hear your words: going forth out of that house or city shake off the dust from your feet.", "bbe": "And whoever will not take you in, or give ear to your words, when you go out from that house or that town, put off its dust from your feet.", "geneva": "And whosoeuer shall not receiue you, nor heare your woordes, when yee depart out of that house, or that citie, shake off the dust of your feete.", "wycliffe": "And who euere resseyueth not you, nethir herith youre wordis, go ye fro that hous or citee, and sprenge of the dust of youre feet.", "rotherham": "And, whosoever shall neither welcome you, nor hear your words, as ye go forth outside that house or city, shake off the dust of your feet:", "weymouth": "And whoever refuses to receive you or even to listen to your Message, as you leave that house or town, shake off the very dust from your feet.", "darby": "And whosoever shall not receive you, nor hear your words, as ye go forth out of that house or city, shake off the dust of your feet.", "twenty": "If no one welcomes you, or listens to what you say, as you leave that house or that town, shake off its dust from your feet.", "acv": "And whoever will not receive you, nor hear your words, while departing that house or that city, shake off the dust of your feet.", "anderson": "And whoever will not receive you, nor hear your words, when you go out of that house or that city, shake off the dust from your feet.", "haweis": "And whosoever shall not receive you, nor attend to your discourses, go out of that house, or city, and shake off the dust of your feet.", "noyes": "And whoever shall not receive you, nor hear your words, when ye go out of that house or city, shake off the dust from your feet.", "webster": "And whoever shall not receive you, nor hear your words, when ye depart from that house, or city, shake off the dust of your feet.", "vulgate": "et quicumque non receperit vos neque audierit sermones vestros exeuntes foras de domo vel de civitate excutite pulverem de pedibus vestris;"}}, {"v": 15, "ref": "10:15", "o": "ἀμὴν λέγω ὑμῖν, ἀνεκτότερον ἔσται γῇ Σοδόμων καὶ Γομόρρων ἐν ἡμέρᾳ κρίσεως ἢ τῇ πόλει ἐκείνῃ.", "en": {"kjv": "Verily I say unto you, It shall be more tolerable for the land of Sodom and Gomorrha in the day of judgment, than for that city.", "web": "Most certainly I tell you, it will be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city.", "bsb": "Truly I tell you, it will be more bearable for Sodom and Gomorrah on the day of judgment than for that town.", "asv": "Verily I say unto you, It shall be more tolerable for the land of Sodom and Gomorrah in the day of judgment, than for that city.", "ylt": "verily I say to you, It shall be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city.", "tyndale": "Truly I say vnto you: it shalbe easier for the londe of zodoma and Gomorra in the daye of iudgement then for that cite.", "dra": "Amen I say to you, it shall be more tolerable for the land of Sodom and Gomorrha in the day of judgment, than for that city.", "bbe": "Truly I say to you, It will be better for the land of Sodom and Gomorrah in the day of God's judging than for that town.", "geneva": "Truely I say vnto you, it shall be easier for them of the lande of Sodom and Gomorrha in the day of iudgement, then for that citie.", "wycliffe": "Treuly Y seie to you, it shal be more suffrable to the loond of men of Sodom and of Gommor in the dai of iugement, than to thilke citee.", "rotherham": "Verily, I say unto you,—More tolerable, will it be, for the land of Sodom and Gomorrha in the day of judgment, than for, that, city!", "weymouth": "I solemnly tell you that it will be more endurable for the land of Sodom and Gomorrah on the day of Judgement than for that town.", "darby": "Verily I say unto you, It shall be more tolerable for the land of Sodom and Gomorrha in judgment-day than for that city.", "twenty": "I tell you, the doom of the land of Sodom and Gomorrah will be more bearable in the ‘Day of Judgment’ than the doom of that town.", "acv": "Truly I say to you, it will be more tolerable for the land of Sodom and Gomorrah in the day of judgment, than for that city.", "anderson": "Verily I say to you, It shall be more tolerable for the land of Sodom and Gomorrah, in the day of judgment, than for that city.", "haweis": "Verily I say unto you, It shall be more tolerable for the land of Sodom and Gomorrah in the day of judgment than for that city.", "noyes": "Truly do I say to you, It will be more tolerable for the land of Sodom and Gomorrah in the day of judgment, than for that city.", "webster": "Verily, I say to you, It shall be more tolerable for the land of Sodom and Gomorrah, in the day of judgment, than for that city.", "vulgate": "amen dico vobis tolerabilius erit terrae Sodomorum et Gomorraeorum in die iudicii quam illi civitati;"}}, {"v": 16, "ref": "10:16", "o": "Ἰδοὺ ἐγὼ ἀποστέλλω ὑμᾶς ὡς πρόβατα ἐν μέσῳ λύκων· γίνεσθε οὖν φρόνιμοι ὡς οἱ ὄφεις καὶ ἀκέραιοι ὡς αἱ περιστεραί.", "en": {"kjv": "Behold, I send you forth as sheep in the midst of wolves: be ye therefore wise as serpents, and harmless as doves.", "web": "“Behold, I send you out as sheep in the midst of wolves. Therefore be wise as serpents, and harmless as doves.", "bsb": "Behold, I am sending you out like sheep among wolves; therefore be as shrewd as snakes and as innocent as doves.", "asv": "Behold, I send you forth as sheep in the midst of wolves: be ye therefore wise as serpents, and harmless as doves.", "ylt": "`Lo, I do send you forth as sheep in the midst of wolves, be ye therefore wise as the serpents, and simple as the doves.", "tyndale": "Beholde I sende you forthe as shepe amoge wolves. Be ye therfore wyse as serpetes and innocent as doves.", "dra": "Behold I send you as sheep in the midst of wolves. Be ye therefore wise as serpents and simple as doves.", "bbe": "See, I send you out as sheep among wolves. Be then as wise as snakes, and as gentle as doves.", "geneva": "Behold, I send you as sheepe in the middes of the wolues: be yee therefore wise as serpents, and innocent as doues.", "wycliffe": "Lo! Y sende you as scheep in the myddil of wolues; therfor be ye sliy as serpentis, and symple as dowues.", "rotherham": "Lo! I, send you forth as sheep amidst wolves; become ye therefore—prudent, as serpents, and simple, as doves.", "weymouth": "\"Remember it is I who am sending you out, as sheep into the midst of wolves; prove yourselves as sagacious as serpents, and as innocent as doves.", "darby": "Behold, I send you as sheep in the midst of wolves; be therefore prudent as the serpents, and guileless as the doves.", "twenty": "Remember, I am sending you out as my Messengers like sheep among wolves. So be as wise as serpents, and as blameless as doves.", "acv": "Behold, I send you forth as sheep in the midst of wolves. Become ye therefore wise as serpents, and innocent as doves.", "anderson": "Behold, I send you forth as sheep in the midst of wolves: be, therefore, wise as serpents, and guileless as doves.", "haweis": "Behold, I send you forth as sheep in the midst of wolves: be ye therefore prudent as serpents, and harmless as doves.", "noyes": "Lo! I send you forth as sheep into the midst of wolves. Be therefore wise as serpents, and harmless as doves.", "webster": "Behold, I send you forth as sheep in the midst of wolves: be ye therefore wise as serpents, and harmless as doves.", "vulgate": "ecce ego mitto vos sicut oves in medio luporum estote ergo prudentes sicut serpentes et simplices sicut columbae;"}}, {"v": 17, "ref": "10:17", "o": "προσέχετε δὲ ἀπὸ τῶν ἀνθρώπων· παραδώσουσιν γὰρ ὑμᾶς εἰς συνέδρια, καὶ ἐν ταῖς συναγωγαῖς αὐτῶν μαστιγώσουσιν ὑμᾶς·", "en": {"kjv": "But beware of men: for they will deliver you up to the councils, and they will scourge you in their synagogues;", "web": "But beware of men: for they will deliver you up to councils, and in their synagogues they will scourge you.", "bsb": "But beware of men; for they will hand you over to their councils and flog you in their synagogues.", "asv": "But beware of men: for they will deliver you up to councils, and in their synagogues they will scourge you;", "ylt": "And, take ye heed of men, for they will give you up to sanhedrims, and in their synagogues they will scourge you,", "tyndale": "Beware of men for they shall deliver you vp to ye cousels and shall scourge you in their synagoges.", "dra": "But beware of men. For they will deliver you up in councils, and they will scourge you in their synagogues.", "bbe": "But be on the watch against men: for they will give you up to the Sanhedrins, and in their Synagogues they will give you blows;", "geneva": "But beware of men, for they will deliuer you vp to the Councils, and will scourge you in their Synagogues.", "wycliffe": "But be ye war of men, for thei schulen take you in counseilis, and thei schulen bete you in her synagogis;", "rotherham": "But beware of men; for they will deliver you up into high-councils, and, in their synagogues, will they scourge you,—", "weymouth": "But beware of men; for they will deliver you up to appear before Sanhedrins, and will flog you in their synagogues;", "darby": "But beware of men; for they will deliver you up to sanhedrims, and scourge you in their synagogues;", "twenty": "Be on your guard against your fellow men, for they will betray you to courts of law, and scourge you in their Synagogues;", "acv": "But beware of men, for they will deliver you up to councils, and they will scourge you in their synagogues,", "anderson": "But beware of men: for they will deliver you to the councils, and scourge you in their synagogues;", "haweis": "But be on your guard against men: for they will deliver you up to the sanhedrim, and scourge you in their synagogues.", "noyes": "But beware of men. For they will deliver you up to the councils, and they will scourge you in their synagogues;", "webster": "But beware of men: for they will deliver you to the councils, and they will scourge you in their synagogues.", "vulgate": "cavete autem ab hominibus tradent enim vos in conciliis et in synagogis suis flagellabunt vos;"}}, {"v": 18, "ref": "10:18", "o": "καὶ ἐπὶ ἡγεμόνας δὲ καὶ βασιλεῖς ἀχθήσεσθε ἕνεκεν ἐμοῦ εἰς μαρτύριον αὐτοῖς καὶ τοῖς ἔθνεσιν.", "en": {"kjv": "And ye shall be brought before governors and kings for my sake, for a testimony against them and the Gentiles.", "web": "Yes, and you will be brought before governors and kings for my sake, for a testimony to them and to the nations.", "bsb": "On My account, you will be brought before governors and kings as witnesses to them and to the Gentiles.", "asv": "yea and before governors and kings shall ye be brought for my sake, for a testimony to them and to the Gentiles.", "ylt": "and before governors and kings ye shall be brought for my sake, for a testimony to them and to the nations.", "tyndale": "And ye shall be brought to the heed rulers and kynges for my sake in witnes to them and to the gentyls.", "dra": "And you shall be brought before governors, and before kings for my sake, for a testimony to them and to the Gentiles:", "bbe": "And you will come before rulers and kings because of me, for a witness to them and to the Gentiles.", "geneva": "And ye shall be brought to the gouernours and Kings for my sake, in witnes to them, and to the Gentiles.", "wycliffe": "and to meyris, or presidentis, and to kyngis, ye schulen be lad for me, in witnessyng to hem, and to the hethen men.", "rotherham": "And, before both governor and kings, shall ye be brought, for my sake—for a witness to them and the nations.", "weymouth": "and you will even be put on trial before governors and kings for my sake, to bear witness to them and to the Gentiles.", "darby": "and ye shall be brought before rulers and kings for my sake, for a testimony to them and to the nations.", "twenty": "and you will be brought before governors and kings for my sake, that you may witness for me before them and the nations.", "acv": "and ye will be brought to governors and even kings because of me, for a witness to them and to the Gentiles.", "anderson": "and you will be brought before governors and kings for my sake, for a testimony against them and the Gentiles.", "haweis": "And ye shall be brought before rulers and kings for my sake, for a testimony against them and the heathen.", "noyes": "and ye will be brought before governors and kings for my sake, that ye may bear testimony to them and to the gentiles.", "webster": "And ye will be brought before governors and kings for my sake, for a testimony against them and the Gentiles.", "vulgate": "et ad praesides et ad reges ducemini propter me in testimonium illis et gentibus;"}}, {"v": 19, "ref": "10:19", "o": "ὅταν δὲ ⸀παραδῶσιν ὑμᾶς, μὴ μεριμνήσητε πῶς ἢ τί λαλήσητε· δοθήσεται γὰρ ὑμῖν ἐν ἐκείνῃ τῇ ὥρᾳ τί ⸀λαλήσητε·", "en": {"kjv": "But when they deliver you up, take no thought how or what ye shall speak: for it shall be given you in that same hour what ye shall speak.", "web": "But when they deliver you up, don’t be anxious how or what you will say, for it will be given you in that hour what you will say.", "bsb": "But when they hand you over, do not worry about how to respond or what to say. In that hour you will be given what to say.", "asv": "But when they deliver you up, be not anxious how or what ye shall speak: for it shall be given you in that hour what ye shall speak.", "ylt": "`And whenever they may deliver you up, be not anxious how or what ye may speak, for it shall be given you in that hour what ye shall speak;", "tyndale": "But when they delyver you vp take no thought how or what ye shall speake for yt shalbe geve you eve in that same houre what ye shall saye.", "dra": "But when they shall deliver you up, take no thought how or what to speak: for it shall be given you in that hour what to speak:", "bbe": "But when you are given up into their hands, do not be troubled about what to say or how to say it: for in that hour what you are to say will be given to you;", "geneva": "But when they deliuer you vp, take no thought howe or what ye shall speake: for it shall be giuen you in that houre, what ye shall say.", "wycliffe": "But whanne thei take you, nyle ye thenke, hou or what thing ye schulen speke, for it shal be youun `to you in that our, what ye schulen speke;", "rotherham": "And, when they deliver you up, be not anxious how or what ye shall speak,—for it shall be given you in that hour what ye shall speak;", "weymouth": "But when they have delivered you up, have no anxiety as to how you shall speak or what you shall say; for at that very time it shall be given you what to say;", "darby": "But when they deliver you up, be not careful how or what ye shall speak; for it shall be given to you in that hour what ye shall speak.", "twenty": "Whenever they betray you, do not be anxious as to how you shall speak or what you shall say, for what you shall say will be given you at the moment;", "acv": "But when they deliver you up, be not anxious how or what ye should speak, for it will be given you in that hour what ye will speak.", "anderson": "But when they deliver you up, be not anxious how or what you shall speak; for that which you shall speak shall be given you in that hour:", "haweis": "But when they shall deliver you up, be under no anxiety what ye shall say; for it shall be given you in that very hour what ye should speak:", "noyes": "But when they deliver you up, be not anxious as to how or What ye shall speak; for it will be given you in that hour what ye shall speak.", "webster": "But when they deliver you up, be not anxious how or what ye shall speak, for it shall be given to you in that same hour what ye shall speak.", "vulgate": "cum autem tradent vos nolite cogitare quomodo aut quid loquamini dabitur enim vobis in illa hora quid loquamini;"}}, {"v": 20, "ref": "10:20", "o": "οὐ γὰρ ὑμεῖς ἐστε οἱ λαλοῦντες ἀλλὰ τὸ πνεῦμα τοῦ πατρὸς ὑμῶν τὸ λαλοῦν ἐν ὑμῖν.", "en": {"kjv": "For it is not ye that speak, but the Spirit of your Father which speaketh in you.", "web": "For it is not you who speak, but the Spirit of your Father who speaks in you.", "bsb": "For it will not be you speaking, but the Spirit of your Father speaking through you.", "asv": "For it is not ye that speak, but the Spirit of your Father that speaketh in you.", "ylt": "for ye are not the speakers, but the Spirit of your Father that is speaking in you.", "tyndale": "For it is not ye that speke but ye sprite of your father which speaketh in you.", "dra": "For it is not you that speak, but the spirit of your Father that speaketh in you.", "bbe": "Because it is not you who say the words, but the Spirit of your Father in you.", "geneva": "For it is not yee that speake, but the spirite of your father which speaketh in you.", "wycliffe": "for it ben not ye that speken, but the spirit of youre fadir, that spekith in you.", "rotherham": "For it is not, ye, who are speaking, but, the Spirit of your Father, that is speaking in you.", "weymouth": "for it is not you who will speak: it will be the Spirit of your Father speaking through you.", "darby": "For ye are not the speakers, but the Spirit of your Father which speaks in you.", "twenty": "for it will not be you who speak, but the Spirit of your Father that speaks within you.", "acv": "For ye are not who speak, but the Spirit of your Father speaking in you.", "anderson": "for it is not you that speak, but it is the Spirit of your Father that speaks in you.", "haweis": "for it is not you who are speaking, but the Spirit of your Father which is speaking in you.", "noyes": "For it is not ye that speak, but the Spirit of your Father that speaketh in you.", "webster": "For it is not ye that speak, but the Spirit of your Father which speaketh in you.", "vulgate": "non enim vos estis qui loquimini sed Spiritus Patris vestri qui loquitur in vobis;"}}, {"v": 21, "ref": "10:21", "o": "παραδώσει δὲ ἀδελφὸς ἀδελφὸν εἰς θάνατον καὶ πατὴρ τέκνον, καὶ ἐπαναστήσονται τέκνα ἐπὶ γονεῖς καὶ θανατώσουσιν αὐτούς.", "en": {"kjv": "And the brother shall deliver up the brother to death, and the father the child: and the children shall rise up against their parents, and cause them to be put to death.", "web": "“Brother will deliver up brother to death, and the father his child. Children will rise up against parents, and cause them to be put to death.", "bsb": "Brother will betray brother to death, and a father his child; children will rise against their parents and have them put to death.", "asv": "And brother shall deliver up brother to death, and the father his child: and children shall rise up against parents, and cause them to be put to death.", "ylt": "`And brother shall deliver up brother to death, and father child, and children shall rise up against parents, and shall put them to death,", "tyndale": "The brother shall betraye the brother to deeth and the father the sonne. And the chyldre shall aryse agaynste their fathers and mothers and shall put them to deethe:", "dra": "The brother also shall deliver up the brother to death, and the father the son; and the children shall rise up against their parents, and shall put them to death.", "bbe": "And brother will give up brother to death, and the father his child: and children will go against their fathers and mothers, and put them to death.", "geneva": "And the brother shall betray the brother to death, and the father the sonne, and the children shall rise against their parents, and shall cause them to die.", "wycliffe": "`And the brother shal take the brother in to deeth, and the fader the sone, and sones schulen rise ayens fadir and modir, and schulen turmente hem bi deeth.", "rotherham": "And, brother, will deliver up, brother, unto death, and, father, child,—and, children, will rise up, against parents, and will put them to death.", "weymouth": "Brother will betray brother to death, and father, child; and children will rise against their own parents and will put them to death.", "darby": "But brother shall deliver up brother to death, and father child; and children shall rise up against parents and shall put them to death;", "twenty": "Brother will betray brother to death, and the father his child; and children will turn against their parents, and cause them to be put to death;", "acv": "And a brother will deliver up a brother to death, and a father a child. And children will rise up against parents, and condemn them to death.", "anderson": "Brother will deliver up brother to death, and the father the child; and children will rise up against their parents, and cause them to be put to death.", "haweis": "Then brother shall surrender brother to death, and the father the son; and children shall rise up against parents, and cause them to be put to death.", "noyes": "And brother will deliver up brother to death, and the father his child; and children will rise up against their parent, and put them to death;", "webster": "And the brother will deliver up the brother to death, and the father the child: and the children will rise up against [their] parents, and cause them to be put to death.", "vulgate": "tradet autem frater fratrem in mortem et pater filium et insurgent filii in parentes et morte eos adficient;"}}, {"v": 22, "ref": "10:22", "o": "καὶ ἔσεσθε μισούμενοι ὑπὸ πάντων διὰ τὸ ὄνομά μου· ὁ δὲ ὑπομείνας εἰς τέλος οὗτος σωθήσεται.", "en": {"kjv": "And ye shall be hated of all men for my name’s sake: but he that endureth to the end shall be saved.", "web": "You will be hated by all men for my name’s sake, but he who endures to the end will be saved.", "bsb": "You will be hated by everyone because of My name, but the one who perseveres to the end will be saved.", "asv": "And ye shall be hated of all men for my name’s sake: but he that endureth to the end, the same shall be saved.", "ylt": "and ye shall be hated by all because of my name, but he who hath endured to the end, he shall be saved.", "tyndale": "and ye shall be hated of all me for my name. But he that endureth to the ende shalbe saved.", "dra": "And you shall be hated by all men for my name's sake: but he that shall persevere unto the end, he shall be saved.", "bbe": "And you will be hated by all men because of my name: but he who is strong to the end will have salvation.", "geneva": "And yee shall be hated of all men for my Name: but he that endureth to the end, he shall be saued.", "wycliffe": "And ye schulen be in hate to alle men for my name; but he that shall dwelle stille in to the ende, shal be saaf.", "rotherham": "And ye will be hated by all, because of my name,—but, he that endureth throughout, the same, shall be saved.", "weymouth": "And you will be objects of universal hatred because you are called by my name; but he who holds out to the End--he will be saved.", "darby": "and ye shall be hated of all on account of my name. But he that has endured to [the] end, he shall be saved.", "twenty": "and you will be hated by every one on account of my Name. Yet the man that endures to the end shall be saved.", "acv": "And ye will be hated by all men because of my name, but he who endures to the end, this man will be saved.", "anderson": "And you will be hated by all men on my account: but he that endures to the end shall be saved.", "haweis": "And ye shall be hated of all men for my name’s sake: but he that endureth to the end, that man shall be saved.", "noyes": "and ye will be hated by all on account of my name. But he that endureth to the end will be saved.", "webster": "And ye will be hated by all [men] for my name's sake: but he that endureth to the end shall be saved.", "vulgate": "et eritis odio omnibus propter nomen meum qui autem perseveraverit in finem hic salvus erit;"}}, {"v": 23, "ref": "10:23", "o": "ὅταν δὲ διώκωσιν ὑμᾶς ἐν τῇ πόλει ταύτῃ, φεύγετε εἰς τὴν ⸀ἑτέραν· ἀμὴν γὰρ λέγω ὑμῖν, οὐ μὴ τελέσητε τὰς πόλεις ⸀τοῦ Ἰσραὴλ ἕως ⸀ἂν ἔλθῃ ὁ υἱὸς τοῦ ἀνθρώπου.", "en": {"kjv": "But when they persecute you in this city, flee ye into another: for verily I say unto you, Ye shall not have gone over the cities of Israel, till the Son of man be come.", "web": "But when they persecute you in this city, flee into the next, for most certainly I tell you, you will not have gone through the cities of Israel, until the Son of Man has come.", "bsb": "When they persecute you in one town, flee to the next. Truly I tell you, you will not reach all the towns of Israel before the Son of Man comes.", "asv": "But when they persecute you in this city, flee into the next: for verily I say unto you, Ye shall not have gone through the cities of Israel, till the Son of man be come.", "ylt": "`And whenever they may persecute you in this city, flee to the other, for verily I say to you, ye may not have completed the cities of Israel till the Son of Man may come.", "tyndale": "When they persecute you in one cite flye in to another. I tell you for a treuth ye shall not fynysshe all yt cities of Israel tyll ye sonne of man be come.", "dra": "And when they shall persecute you in this city, flee into another. Amen I say to you, you shall not finish all the cities of Israel, till the Son of man come.", "bbe": "But when they are cruel to you in one town, go in flight to another: for truly, I say to you, You will not have gone through the towns of Israel before the Son of man comes.", "geneva": "And when they persecute you in this citie, flee into another: for verely I say vnto you, yee shall not goe ouer all the cities of Israel, till the Sonne of man be come.", "wycliffe": "And whanne thei pursuen you in this citee, fle ye in to anothir. Treuli Y seie to you, ye schulen not ende the citees of Israel, to for that mannus sone come.", "rotherham": "And, when they persecute you in this city, flee into another,—for, verily, I say unto you, in nowise shall ye finish the cities of Israel, till, he Son of Man, come.", "weymouth": "Whenever they persecute you in one town, escape to the next; for I solemnly tell you that you will not have gone the round of all the towns of Israel before the Son of Man comes.", "darby": "But when they persecute you in this city, flee to the other; for verily I say to you, Ye shall not have completed the cities of Israel until the Son of man be come.", "twenty": "But, when they persecute you in one town, escape to the next; for, I tell you, you will not have come to the end of the towns of Israel before the Son of Man comes.", "acv": "But when they persecute you in this city, flee into the other, for truly I say to you, ye will, no, not have completed the cities of Israel, until the Son of man comes.", "anderson": "But when they persecute you in this city, flee into another: for verily I say to you, You will not have made the circuit of the cities of Israel before the Son of man shall come.", "haweis": "But when they shall persecute you in one city, flee unto another: for verily I say unto you, Ye shall not complete your circuit through the cities of Israel before the Son of man comes.", "noyes": "And when they persecute you in one city, flee to another. For truly do I say to you, Ye will not have gone over the cities of Israel till the Son of man hath come.", "webster": "But when they persecute you in this city, flee ye into another: for verily I say to you, Ye shall not have gone over the cities of Israel till the Son of man shall have come.", "vulgate": "cum autem persequentur vos in civitate ista fugite in aliam amen enim dico vobis non consummabitis civitates Israhel donec veniat Filius hominis;"}}, {"v": 24, "ref": "10:24", "o": "Οὐκ ἔστιν μαθητὴς ὑπὲρ τὸν διδάσκαλον οὐδὲ δοῦλος ὑπὲρ τὸν κύριον αὐτοῦ.", "en": {"kjv": "The disciple is not above his master, nor the servant above his lord.", "web": "“A disciple is not above his teacher, nor a servant above his lord.", "bsb": "A disciple is not above his teacher, nor a servant above his master.", "asv": "A disciple is not above his teacher, nor a servant above his lord.", "ylt": "`A disciple is not above the teacher, nor a servant above his lord;", "tyndale": "The disciple ys not above hys master: nor yet ye servaut above his lorde.", "dra": "The disciple is not above the master, nor the servant above his lord.", "bbe": "A disciple is not greater than his master, or a servant than his lord.", "geneva": "The disciple is not aboue his master, nor the seruant aboue his Lord.", "wycliffe": "The disciple is not aboue the maistir, ne the seruaunt aboue hys lord;", "rotherham": "A, disciple, is not above, the teacher, nor, a servant, above, his lord:", "weymouth": "\"The learner is never superior to his teacher, and the servant is never superior to his master.", "darby": "The disciple is not above his teacher, nor the bondman above his lord.", "twenty": "A scholar is not above his teacher, nor a servant above his master.", "acv": "A pupil is not above his teacher, nor a bondman above his lord.", "anderson": "The disciple is not above his teacher, nor the servant above his master.", "haweis": "The disciple is not superior to his teacher, nor the servant above his master.", "noyes": "A disciple is not above his teacher, nor a servant above his lord.", "webster": "The disciple is not above [his] teacher, nor the servant above his lord.", "vulgate": "non est discipulus super magistrum nec servus super dominum suum;"}}, {"v": 25, "ref": "10:25", "o": "ἀρκετὸν τῷ μαθητῇ ἵνα γένηται ὡς ὁ διδάσκαλος αὐτοῦ, καὶ ὁ δοῦλος ὡς ὁ κύριος αὐτοῦ. εἰ τὸν οἰκοδεσπότην Βεελζεβοὺλ ⸀ἐπεκάλεσαν, πόσῳ μᾶλλον τοὺς οἰκιακοὺς αὐτοῦ.", "en": {"kjv": "It is enough for the disciple that he be as his master, and the servant as his lord. If they have called the master of the house Beelzebub, how much more shall they call them of his household?", "web": "It is enough for the disciple that he be like his teacher, and the servant like his lord. If they have called the master of the house Beelzebul, how much more those of his household!", "bsb": "It is enough for a disciple to be like his teacher, and a servant like his master. If the head of the house has been called Beelzebul, how much more the members of his household!", "asv": "It is enough for the disciple that he be as his teacher, and the servant as his lord. If they have called the master of the house Beelzebub, how much more them of his household!", "ylt": "sufficient to the disciple that he may be as his teacher, and the servant as his lord; if the master of the house they did call Beelzeboul, how much more those of his household?", "tyndale": "It is ynough for the disciple to be as hys master ys and that the servaunt be as his lorde ys. yf they have called the lorde of the housse beelzebub: how moche more shall they call them of his housholde so?", "dra": "It is enough for the disciple that he be as his master, and the servant as his lord. If they have called the good man of the house Beelzebub, how much more them of his household?", "bbe": "It is enough for the disciple that he may be as his master, and the servant as his lord. If they have given the name Beelzebub to the master of the house, how much more to those of his house!", "geneva": "It is ynough for the disciple to bee as his master is, and the seruaunt as his Lord. If they haue called the master of the house Beel-zebub, howe much more them of his housholde?", "wycliffe": "it is ynowy to the disciple, that he be as his maistir, and to the seruaunt as his lord. If thei han clepid the hosebonde man Belsabub, hou myche more his houshold meyne?", "rotherham": "Sufficient for the disciple, that he become, as his teacher, and, the servant, as, his lord. If, the master of the house, Beelzebul, they called, how much more, the men of his house!", "weymouth": "Enough for the learner to be on a level with his teacher, and for the servant to be on a level with his master. If they have called the master of the house Baal-zebul, how much more will they slander his servants?", "darby": "[It is] sufficient for the disciple that he should become as his teacher, and the bondman as his lord. If they have called the master of the house Beelzebub, how much more those of his household?", "twenty": "It is enough for a scholar to be treated like his teacher, and a servant like his master. If the head of the house has been called Baal-zebub, how much more the members of his household!", "acv": "It is enough for the pupil that he becomes like his teacher, and the bondman like his lord. If they have called the house-ruler Beelzebub, how much more those of his household.", "anderson": "It is enough for the disciple, that he be as his teacher; and for the servant, that he be as his master. If they call the master of the house Beelzebul, how much more those of his household?", "haweis": "It is sufficient if the disciple be as his teacher, and the servant as his master. If they have called the master of the family Beelzebub, how much more his domestics?", "noyes": "It is enough for the disciple to be as his teacher, and the servant as his lord. If they have called the master of the house Beelzebul, how much more will they so call those of his household!", "webster": "It is enough for the disciple that he should be as his teacher, and the servant as his lord: if they have called the master of the house Beelzebub, how much more [will they call] them of his household?", "vulgate": "sufficit discipulo ut sit sicut magister eius et servus sicut dominus eius si patrem familias Beelzebub vocaverunt quanto magis domesticos eius;"}}, {"v": 26, "ref": "10:26", "o": "Μὴ οὖν φοβηθῆτε αὐτούς· οὐδὲν γάρ ἐστιν κεκαλυμμένον ὃ οὐκ ἀποκαλυφθήσεται, καὶ κρυπτὸν ὃ οὐ γνωσθήσεται.", "en": {"kjv": "Fear them not therefore: for there is nothing covered, that shall not be revealed; and hid, that shall not be known.", "web": "Therefore don’t be afraid of them, for there is nothing covered that will not be revealed; and hidden that will not be known.", "bsb": "So do not be afraid of them. For there is nothing concealed that will not be disclosed, and nothing hidden that will not be made known.", "asv": "Fear them not therefore: for there is nothing covered, that shall not be revealed; and hid, that shall not be known.", "ylt": "`Ye may not, therefore, fear them, for there is nothing covered, that shall not be revealed, and hid, that shall not be known;", "tyndale": "Feare the not therfore. There is no thinge so close that shall not be openned and no thinge so hyd that shall not be knowen.", "dra": "Therefore fear them not. For nothing is covered that shall not be revealed: nor hid, that shall not be known.", "bbe": "Have, then, no fear of them: because nothing is covered which will not come to light, or secret which will not be made clear.", "geneva": "Feare them not therefore: for there is nothing couered, that shall not be disclosed, nor hid, that shall not be knowen.", "wycliffe": "Therfor drede ye not hem; for no thing is hid, that schal not be shewid; and no thing is priuey, that schal not be wist.", "rotherham": "Then do not fear them,—for, nothing hath been covered, which shall not be, uncovered, and, hidden, which shall not be, made known.", "weymouth": "Fear them not, however; there is nothing veiled which will not be uncovered, nor secret which will not become known.", "darby": "Fear them not therefore; for there is nothing covered which shall not be revealed, and secret which shall not be known.", "twenty": "Do not, therefore, be afraid of them. There is nothing concealed which will not be revealed, nor anything hidden which will not become known.", "acv": "Fear them not therefore, for there is nothing covered, that will not be revealed, and hid, that will not be known.", "anderson": "Fear them not, therefore; for there is nothing covered that shall not be revealed, nor hidden that shall not be made known.", "haweis": "However, fear them not: for there is nothing concealed, which shall not be discovered; nor hid, which shall not be known.", "noyes": "Fear them not therefore. For there is nothing covered that will not be revealed; and hid, that will not be known.", "webster": "Fear them not therefore: for there is nothing covered, that shall not be revealed; and hid, that shall not be known.", "vulgate": "ne ergo timueritis eos nihil enim opertum quod non revelabitur et occultum quod non scietur;"}}, {"v": 27, "ref": "10:27", "o": "ὃ λέγω ὑμῖν ἐν τῇ σκοτίᾳ, εἴπατε ἐν τῷ φωτί· καὶ ὃ εἰς τὸ οὖς ἀκούετε, κηρύξατε ἐπὶ τῶν δωμάτων.", "en": {"kjv": "What I tell you in darkness, that speak ye in light: and what ye hear in the ear, that preach ye upon the housetops.", "web": "What I tell you in the darkness, speak in the light; and what you hear whispered in the ear, proclaim on the housetops.", "bsb": "What I tell you in the dark, speak in the daylight; what is whispered in your ear, proclaim from the housetops.", "asv": "What I tell you in the darkness, speak ye in the light; and what ye hear in the ear, proclaim upon the house-tops.", "ylt": "that which I tell you in the darkness, speak in the light, and that which you hear at the ear, proclaim on the house-tops.", "tyndale": "What I tell you in dercknes that speake ye in lyght. And what ye heare in the eare that preache ye on the housse toppes.", "dra": "That which I tell you in the dark, speak ye in the light: and that which you hear in the ear, preach ye upon the housetops.", "bbe": "What I say to you in the dark, say in the light: and what comes to your ear secretly, say publicly from the house-tops.", "geneva": "What I tell you in darkenesse, that speake yee in light: and what yee heare in the eare, that preach yee on the houses.", "wycliffe": "That thing that Y seie to you in derknessis, seie ye in the liyt; and preche ye on housis, that thing that ye heeren in the ere.", "rotherham": "What I am saying to you in the darkness, tell ye in the light,—and, what [whispered] into the ear ye are hearing, proclaim ye on the housetops.", "weymouth": "What I tell you in the dark, speak in the light; and what is whispered into your ear, proclaim upon the roofs of the houses.", "darby": "What I say to you in darkness speak in the light, and what ye hear in the ear preach upon the houses.", "twenty": "What I tell you in the dark, say again in the light; and what is whispered in your ear, proclaim upon the housetops.", "acv": "What I tell you in the darkness, speak ye in the light, and what ye hear in the ear, proclaim upon the housetops.", "anderson": "What I tell you in darkness, speak in the light: and what you hear in the ear, preach on the house-tops.", "haweis": "What I say unto you in the dark, publish in the light: and what ye hear whispered into the ear, proclaim upon the roofs.", "noyes": "What I say to you in darkness, speak ye in the light; and what ye hear in the ear, proclaim ye upon the housetops.", "webster": "What I tell you in darkness, [that] speak ye in light: and what ye hear in the ear, [that] publish ye upon the house-tops.", "vulgate": "quod dico vobis in tenebris dicite in lumine et quod in aure auditis praedicate super tecta;"}}, {"v": 28, "ref": "10:28", "o": "καὶ μὴ ⸀φοβεῖσθε ἀπὸ τῶν ἀποκτεννόντων τὸ σῶμα τὴν δὲ ψυχὴν μὴ δυναμένων ἀποκτεῖναι· ⸁φοβεῖσθε δὲ μᾶλλον τὸν δυνάμενον ⸀καὶ ψυχὴν ⸁καὶ σῶμα ἀπολέσαι ἐν γεέννῃ.", "en": {"kjv": "And fear not them which kill the body, but are not able to kill the soul: but rather fear him which is able to destroy both soul and body in hell.", "web": "Don’t be afraid of those who kill the body, but are not able to kill the soul. Rather, fear him who is able to destroy both soul and body in Gehenna.", "bsb": "Do not be afraid of those who kill the body but cannot kill the soul. Instead, fear the One who can destroy both soul and body in hell.", "asv": "And be not afraid of them that kill the body, but are not able to kill the soul: but rather fear him who is able to destroy both soul and body in hell.", "ylt": "`And be not afraid of those killing the body, and are not able to kill the soul, but fear rather Him who is able both soul and body to destroy in gehenna.", "tyndale": "And feare ye not them which kyll the body and be not able to kyll the soule. But rather feare hym which is able to destroye bothe soule and body into hell.", "dra": "And fear ye not them that kill the body, and are not able to kill the soul: but rather fear him that can destroy both soul and body in hell.", "bbe": "And have no fear of those who put to death the body, but are not able to put to death the soul. But have fear of him who has power to give soul and body to destruction in hell.", "geneva": "And feare yee not them which kill the bodie, but are nor able to kill the soule: but rather feare him, which is able to destroy both soule and bodie in hell.", "wycliffe": "And nyle ye drede hem that sleen the bodi; for thei moun not sle the soule; but rather drede ye hym, that mai lese bothe soule and bodi in to helle.", "rotherham": "And be not in fear, by reason of them that are killing the body,—and, the soul, are not able to kill. But fear, rather, him who is able, both soul and body, to destroy in gehenna!", "weymouth": "\"And do not fear those who kill the body, but cannot kill the soul; but rather fear him who is able to destroy both soul and body in Gehenna.", "darby": "And be not afraid of those who kill the body, but cannot kill the soul; but fear rather him who is able to destroy both soul and body in hell.", "twenty": "And do not be afraid of those who kill the body, but are unable to kill the soul; rather be afraid of him who is able to destroy both soul and body in the Pit.", "acv": "And be not afraid of those who kill the body, but are not able to kill the soul. But rather fear him who is able to destroy both soul and body in hell.", "anderson": "And fear not them that kill the body, but are not able to kill the soul. But rather fear him who is able to destroy both soul and body in hell.", "haweis": "And be not afraid of those who kill the body, and cannot kill the soul: but fear him rather who is able to destroy both soul and body in hell.", "noyes": "And fear not those who kill the body, but are not able to kill the soul; but rather fear him who is able to destroy both soul and body in hell.", "webster": "And fear not them who kill the body, but are not able to kill the soul: but rather fear him who is able to destroy both soul and body in hell.", "vulgate": "et nolite timere eos qui occidunt corpus animam autem non possunt occidere sed potius eum timete qui potest et animam et corpus perdere in gehennam;"}}, {"v": 29, "ref": "10:29", "o": "οὐχὶ δύο στρουθία ἀσσαρίου πωλεῖται; καὶ ἓν ἐξ αὐτῶν οὐ πεσεῖται ἐπὶ τὴν γῆν ἄνευ τοῦ πατρὸς ὑμῶν.", "en": {"kjv": "Are not two sparrows sold for a farthing? and one of them shall not fall on the ground without your Father.", "web": "“Aren’t two sparrows sold for an assarion coin? Not one of them falls on the ground apart from your Father’s will,", "bsb": "Are not two sparrows sold for a penny? Yet not one of them will fall to the ground apart from the will of your Father.", "asv": "Are not two sparrows sold for a penny? and not one of them shall fall on the ground without your Father:", "ylt": "`Are not two sparrows sold for an assar? and one of them shall not fall on the ground without your Father;", "tyndale": "Are not two sparowes solde for a farthinge? And none of them dothe lyght on the grounde with out youre father.", "dra": "Are not two sparrows sold for a farthing? and not one of them shall fall on the ground without your Father.", "bbe": "Are not sparrows two a farthing? and not one of them comes to an end without your Father:", "geneva": "Are not two sparrowes sold for a farthing, and one of them shall not fal on the ground without your Father?", "wycliffe": "Whether twei sparewis ben not seeld for an halpeny? and oon of hem shal not falle on the erthe with outen youre fadir.", "rotherham": "Are not, two sparrows, for a farthing, sold? And, one from among them, shall not fall upon the ground, without your Father;", "weymouth": "Do not two sparrows sell for a halfpenny? Yet not one of them will fall to the ground without your Father's leave.", "darby": "Are not two sparrows sold for a farthing? and one of them shall not fall to the ground without your Father;", "twenty": "Are not two sparrows sold for a half-penny? Yet not one of them will fall to the ground without your Father’s knowledge.", "acv": "Are not two sparrows sold for a penny? And not one of them will fall on the ground independent of your Father.", "anderson": "Are not two sparrows sold for a farthing? and yet not one of them shall fall upon the ground with out your Father.", "haweis": "Are not two sparrows sold for a farthing? and one of them shall not fall to the ground without your Father.", "noyes": "Are not two sparrows sold for a penny? and not one of them shall fall to the ground without your Father.", "webster": "Are not two sparrows sold for a farthing? and not one of them shall fall on the ground without your Father.", "vulgate": "nonne duo passeres asse veneunt et unus ex illis non cadet super terram sine Patre vestro;"}}, {"v": 30, "ref": "10:30", "o": "ὑμῶν δὲ καὶ αἱ τρίχες τῆς κεφαλῆς πᾶσαι ἠριθμημέναι εἰσίν.", "en": {"kjv": "But the very hairs of your head are all numbered.", "web": "but the very hairs of your head are all numbered.", "bsb": "And even the very hairs of your head are all numbered.", "asv": "but the very hairs of your head are all numbered.", "ylt": "and of you--even the hairs of the head are all numbered;", "tyndale": "And now are all the heeris of youre heedis numbred.", "dra": "But the very hairs of your head are all numbered.", "bbe": "But the hairs of your head are all numbered.", "geneva": "Yea, and all the heares of your head are nombred.", "wycliffe": "`And alle the heeris of youre heed ben noumbrid. Therfor nyle ye drede; ye ben betere than many sparewis.", "rotherham": "But, even the hairs of, your, head, have all been numbered.", "weymouth": "But as for you, the very hairs on your heads are all numbered.", "darby": "but of you even the hairs of the head are all numbered.", "twenty": "While as for you, the very hairs of your head are numbered.", "acv": "But even the hairs of your head are all numbered.", "anderson": "But even the hairs of your head are all numbered.", "haweis": "But even the hairs of your head are all numbered.", "noyes": "But even the hairs of your head are all numbered.", "webster": "But the very hairs of your head are all numbered.", "vulgate": "vestri autem et capilli capitis omnes numerati sunt;"}}, {"v": 31, "ref": "10:31", "o": "μὴ οὖν ⸀φοβεῖσθε· πολλῶν στρουθίων διαφέρετε ὑμεῖς.", "en": {"kjv": "Fear ye not therefore, ye are of more value than many sparrows.", "web": "Therefore don’t be afraid. You are of more value than many sparrows.", "bsb": "So do not be afraid; you are worth more than many sparrows.", "asv": "Fear not therefore: ye are of more value than many sparrows.", "ylt": "be not therefore afraid, than many sparrows ye are better.", "tyndale": "Feare ye not therfore: ye are of more value then many sparowes.", "dra": "Fear not therefore: better are you than many sparrows.", "bbe": "Then have no fear; you are of more value than a flock of sparrows.", "geneva": "Feare ye not therefore, yee are of more value then many sparowes.", "wycliffe": "Therfor euery man that schal knouleche me bifore men, Y schal knouleche hym bifor my fadir that is in heuenes.", "rotherham": "Then be not in fear—than many sparrows, better are, ye!", "weymouth": "Away then with fear; you are more precious than a multitude of sparrows.", "darby": "Fear not therefore; ye are better than many sparrows.", "twenty": "Do not, therefore, be afraid; you are of more value than many sparrows.", "acv": "Fear not therefore, ye are of worth more than many sparrows.", "anderson": "Fear not, therefore: you are of more value than many sparrows.", "haweis": "Fear not, therefore, ye are of more value than many sparrows.", "noyes": "Fear not therefore; ye are of more value than many sparrows.", "webster": "Fear ye not therefore, ye are of more value than many sparrows.", "vulgate": "nolite ergo timere multis passeribus meliores estis vos;"}}, {"v": 32, "ref": "10:32", "o": "Πᾶς οὖν ὅστις ὁμολογήσει ἐν ἐμοὶ ἔμπροσθεν τῶν ἀνθρώπων, ὁμολογήσω κἀγὼ ἐν αὐτῷ ἔμπροσθεν τοῦ πατρός μου τοῦ ⸀ἐν οὐρανοῖς·", "en": {"kjv": "Whosoever therefore shall confess me before men, him will I confess also before my Father which is in heaven.", "web": "Everyone therefore who confesses me before men, him I will also confess before my Father who is in heaven.", "bsb": "Therefore everyone who confesses Me before men, I will also confess him before My Father in heaven.", "asv": "Every one therefore who shall confess me before men, him will I also confess before my Father who is in heaven.", "ylt": "`Every one, therefore, who shall confess in me before men, I also will confess in him before my Father who is in the heavens;", "tyndale": "Who soever therfore shall knowledge me before men hym will I knowledge also before my father which is in heuen.", "dra": "Every one therefore that shall confess me before men, I will also confess him before my Father who is in heaven.", "bbe": "To everyone, then, who gives witness to me before men, I will give witness before my Father in heaven.", "geneva": "Whosoeuer therefore shall confesse me before men, him will I confesse also before my Father which is in heauen.", "wycliffe": "", "rotherham": "Every one therefore who shall confess me before men, I also, will confess, him, before my Father who is in the heavens;", "weymouth": "\"Every man who acknowledges me before men I also will acknowledge before my Father who is in Heaven.", "darby": "Every one therefore who shall confess me before men, I also will confess him before my Father who is in [the] heavens.", "twenty": "Every one, therefore, who shall acknowledge me before his fellow men, I, too, will acknowledge before my Father who is in Heaven;", "acv": "Therefore every man, whoever will profess in me before men, I also will profess in him before my Father in the heavens.", "anderson": "Whoever, therefore, will confess me before men, him will I also confess before my Father who is in heaven.", "haweis": "Every one therefore who shall make confession of me before men, of him will I also make confession before my Father who is in heaven.", "noyes": "Every one therefore who shall acknowledge me before men, him will I also acknowledge before my Father who is in heaven.", "webster": "Whoever therefore shall confess me before men, him will I also confess before my Father who is in heaven.", "vulgate": "omnis ergo qui confitebitur me coram hominibus confitebor et ego eum coram Patre meo qui est in caelis;"}}, {"v": 33, "ref": "10:33", "o": "ὅστις ⸂δ’ ἂν⸃ ἀρνήσηταί με ἔμπροσθεν τῶν ἀνθρώπων, ἀρνήσομαι ⸂κἀγὼ αὐτὸν⸃ ἔμπροσθεν τοῦ πατρός μου τοῦ ⸀ἐν οὐρανοῖς.", "en": {"kjv": "But whosoever shall deny me before men, him will I also deny before my Father which is in heaven.", "web": "But whoever denies me before men, him I will also deny before my Father who is in heaven.", "bsb": "But whoever denies Me before men, I will also deny him before My Father in heaven.", "asv": "But whosoever shall deny me before men, him will I also deny before my Father who is in heaven.", "ylt": "and whoever shall deny me before men, I also will deny him before my Father who is in the heavens.", "tyndale": "But whoso ever shall denye me before men hym will I also denye before my father which is in heven.", "dra": "But he that shall deny me before men, I will also deny him before my Father who is in heaven.", "bbe": "But if anyone says before men that he has no knowledge of me, I will say that I have no knowledge of him before my Father in heaven.", "geneva": "But whosoeuer shall denie me before me, him will I also denie before my Father which is in heauen.", "wycliffe": "But he that shal denye me bifor men, and I shal denye him bifor my fadir that is in heuenes.", "rotherham": "But, whoever shall deny me before men, I also, will deny, him, before my Father who is in the heavens.", "weymouth": "But whoever disowns me before men I also will disown before my Father who is in Heaven.", "darby": "But whosoever shall deny me before men, him will I also deny before my Father who is in [the] heavens.", "twenty": "but, if any one disowns me before his fellow men, I, too, will disown him before my Father who is in Heaven.", "acv": "But whoever would deny me before men, I also will deny him before my Father in the heavens.", "anderson": "But whoever will deny me before men, him will I also deny before my Father who is in heaven.", "haweis": "But whosoever shall disown me before men, him will I also disown before my Father who is in heaven.", "noyes": "But whoever shall deny me before men, him will I also deny before my Father who is in heaven.", "webster": "But whoever shall deny me before men, him will I also deny before my Father who is in heaven.", "vulgate": "qui autem negaverit me coram hominibus negabo et ego eum coram Patre meo qui est in caelis;"}}, {"v": 34, "ref": "10:34", "o": "Μὴ νομίσητε ὅτι ἦλθον βαλεῖν εἰρήνην ἐπὶ τὴν γῆν· οὐκ ἦλθον βαλεῖν εἰρήνην ἀλλὰ μάχαιραν.", "en": {"kjv": "Think not that I am come to send peace on earth: I came not to send peace, but a sword.", "web": "“Don’t think that I came to send peace on the earth. I didn’t come to send peace, but a sword.", "bsb": "Do not assume that I have come to bring peace to the earth; I have not come to bring peace, but a sword.", "asv": "Think not that I came to send peace on the earth: I came not to send peace, but a sword.", "ylt": "`Ye may not suppose that I came to put peace on the earth; I did not come to put peace, but a sword;", "tyndale": "Thynke not that I am come to sende peace into the erth. I came not to send peace but a swearde.", "dra": "Do not think that I came to send peace upon earth: I came not to send peace, but the sword.", "bbe": "Do not have the thought that I have come to send peace on the earth; I came not to send peace but a sword.", "geneva": "Thinke not that I am come to sende peace into the earth: I came not to send peace, but the sworde.", "wycliffe": "Nile ye deme, that Y cam to sende pees in to erthe; Y cam not to sende pees, but swerd.", "rotherham": "Do not think, that I came to thrust peace upon the earth,—I came not to thrust, peace, but, a sword;", "weymouth": "\"Do not suppose that I came to bring peace to the earth: I did not come to bring peace but a sword.", "darby": "Do not think that I have come to send peace upon the earth: I have not come to send peace, but a sword.", "twenty": "Do not imagine that I have come to bring peace upon the earth. I have come to bring, not peace, but the sword.", "acv": "Think not that I came to spread peace on the earth. I came not to spread peace, but a sword.", "anderson": "Think not that I have come to send peace on the earth. I have not come to send peace, but a sword.", "haweis": "Think not that I am come to bring peace to the earth: I came not to bring peace, but a sword.", "noyes": "Think not that I came to send peace on earth: I came not to send peace, but a sword.", "webster": "Think not that I am come to send peace on earth: I came not to send peace, but a sword.", "vulgate": "nolite arbitrari quia venerim mittere pacem in terram non veni pacem mittere sed gladium;"}}, {"v": 35, "ref": "10:35", "o": "ἦλθον γὰρ διχάσαι ἄνθρωπον κατὰ τοῦ πατρὸς αὐτοῦ καὶ θυγατέρα κατὰ τῆς μητρὸς αὐτῆς καὶ νύμφην κατὰ τῆς πενθερᾶς αὐτῆς,", "en": {"kjv": "For I am come to set a man at variance against his father, and the daughter against her mother, and the daughter in law against her mother in law.", "web": "For I came to set a man at odds against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law.", "bsb": "For I have come to turn ‘a man against his father, a daughter against her mother, a daughter-in-law against her mother-in-law.", "asv": "For I came to set a man at variance against his father, and the daughter against her mother, and the daughter in law against her mother in law:", "ylt": "for I came to set a man at variance against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law,", "tyndale": "For I am come to set a man at varyaunce ageynst hys father and the doughter ageynst hyr mother and the doughterlawe ageynst her motherlawe:", "dra": "For I came to set a man at variance against his father, and the daughter against her mother, and the daughter in law against her mother in law.", "bbe": "For I have come to put a man against his father, and the daughter against her mother, and the daughter-in-law against her mother-in-law:", "geneva": "For I am come to set a man at variance against his father, and the daughter against her mother, and the daughter in law against her mother in lawe.", "wycliffe": "For Y cam to departe a man ayens his fadir, and the douytir ayens hir modir, and the sones wijf ayens the housbondis modir;", "rotherham": "For I came to set at variance—a man, against, his father, and, a daughter, against, her mother, and, a bride, against, her mother-in-law;", "weymouth": "For I came to set a man against his father, a daughter against her mother, and a daughter-in-law against her mother-in-law;", "darby": "For I have come to set a man at variance with his father, and the daughter with her mother, and the daughter-in-law with her mother-in-law;", "twenty": "For I have come to set — ‘a man against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law.", "acv": "For I came to divide a man against his father, and a daughter against her mother, and a daughter-in-law against her mother-in-law.", "anderson": "For I have come to set a man at variance with his father, and the daughter with her mother, and the daughter-in-law with her mother-in-law:", "haweis": "For I came to set a man at variance against his father, and the daughter against her mother, and the daughter-in-law against her mother-in-law.", "noyes": "For I came to set a man at variance with his father, and a daughter with her mother, and a bride with her mother-in-law;", "webster": "For I am come to set a man at variance against his father, and the daughter against her mother, and the daughter-in-law against her mother-in-law.", "vulgate": "veni enim separare hominem adversus patrem suum et filiam adversus matrem suam et nurum adversus socrum suam;"}}, {"v": 36, "ref": "10:36", "o": "καὶ ἐχθροὶ τοῦ ἀνθρώπου οἱ οἰκιακοὶ αὐτοῦ.", "en": {"kjv": "And a man’s foes shall be they of his own household.", "web": "A man’s foes will be those of his own household.", "bsb": "A man’s enemies will be the members of his own household.’", "asv": "and a man’s foes shall be they of his own household.", "ylt": "and the enemies of a man are those of his household.", "tyndale": "And a mannes fooes shalbe they of hys owne housholde.", "dra": "And a man's enemies shall be they of his own household.", "bbe": "And a man will be hated by those of his house.", "geneva": "And a mans enemies shall be they of his owne housholde.", "wycliffe": "and the enemyes of a man ben `thei, that ben homeli with him.", "rotherham": "And, a man foes, are, they of his own house.", "weymouth": "and a man's own family will be his foes.", "darby": "and they of his household [shall be] a man's enemies.", "twenty": "A man’s enemies will be the members of his own household.’", "acv": "And a man's foes, are those of his own household.", "anderson": "and a man’s enemies shall be those of his own household.", "haweis": "And the enemies of a man shall be those of his own house.", "noyes": "and they of a man’s own household will be his foes.", "webster": "And a man's foes [will be] they of his own household.", "vulgate": "et inimici hominis domestici eius;"}}, {"v": 37, "ref": "10:37", "o": "ὁ φιλῶν πατέρα ἢ μητέρα ὑπὲρ ἐμὲ οὐκ ἔστιν μου ἄξιος· καὶ ὁ φιλῶν υἱὸν ἢ θυγατέρα ὑπὲρ ἐμὲ οὐκ ἔστιν μου ἄξιος·", "en": {"kjv": "He that loveth father or mother more than me is not worthy of me: and he that loveth son or daughter more than me is not worthy of me.", "web": "He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me isn’t worthy of me.", "bsb": "Anyone who loves his father or mother more than Me is not worthy of Me; anyone who loves his son or daughter more than Me is not worthy of Me;", "asv": "He that loveth father or mother more than me is not worthy of me; and he that loveth son or daughter more than me is not worthy of me.", "ylt": "`He who is loving father or mother above me, is not worthy of me, and he who is loving son or daughter above me, is not worthy of me,", "tyndale": "He that lovith hys father or mother more then me is not mete for me. And he that loveth his sonne or doughter more then me is not mete for me.", "dra": "He that loveth father or mother more than me, is not worthy of me; and he that loveth son or daughter more than me, is not worthy of me.", "bbe": "He who has more love for his father or mother than for me is not good enough for me; he who has more love for son or daughter than for me is not good enough for me.", "geneva": "He that loueth father or mother more then me, is not worthie of me. And he that loueth sonne, or daughter more then mee, is not worthie of me.", "wycliffe": "He that loueth fadir or modir more than me, is not worthi to me. And he that loueth sone or douyter ouer me, is not worthi to me.", "rotherham": "He that loveth father or mother above me, is not, worthy, of me,—and, he that loveth son or daughter above me, is not, worthy, of me;", "weymouth": "Any one who loves father or mother more than me is not worthy of me, and any one who loves son or daughter more than me is not worthy of me;", "darby": "He who loves father or mother above me is not worthy of me; and he who loves son or daughter above me is not worthy of me.", "twenty": "He who loves father or mother more than me is not worthy of me; and he who loves son or daughter more than me is not worthy of me.", "acv": "He who loves father or mother above me is not worthy of me, and he who loves son or daughter above me is not worthy of me.", "anderson": "He that loves father or mother more than me, is not worthy of me: and he that loves son or daughter more than me, is not worthy of me:", "haweis": "He that loveth father or mother more than me, is not worthy of me: and he that loveth son or daughter more than me, is not worthy of me.", "noyes": "He that loveth father or mother more than me, is not worthy of me; and he that loveth son or daughter more than me, is not worthy of me;", "webster": "He that loveth father or mother more than me, is not worthy of me: and he that loveth son or daughter more than me, is not worthy of me.", "vulgate": "qui amat patrem aut matrem plus quam me non est me dignus et qui amat filium aut filiam super me non est me dignus;"}}, {"v": 38, "ref": "10:38", "o": "καὶ ὃς οὐ λαμβάνει τὸν σταυρὸν αὐτοῦ καὶ ἀκολουθεῖ ὀπίσω μου, οὐκ ἔστιν μου ἄξιος.", "en": {"kjv": "And he that taketh not his cross, and followeth after me, is not worthy of me.", "web": "He who doesn’t take his cross and follow after me, isn’t worthy of me.", "bsb": "and anyone who does not take up his cross and follow Me is not worthy of Me.", "asv": "And he that doth not take his cross and follow after me, is not worthy of me.", "ylt": "and whoever doth not receive his cross and follow after me, is not worthy of me.", "tyndale": "And he yt taketh not his crosse and foloweth me ys not mete for me.", "dra": "And he that taketh not up his cross, and followeth me, is not worthy of me.", "bbe": "And he who does not take his cross and come after me is not good enough for me.", "geneva": "And hee that taketh not his crosse, and followeth after me, is not worthie of me.", "wycliffe": "And he that takith not his croos, and sueth me, is not worthi to me.", "rotherham": "And, he that doth not take his cross and follow after me, is not, worthy, of me.", "weymouth": "and any one who does not take up his cross and follow where I lead is not worthy of me.", "darby": "And he who does not take up his cross and follow after me is not worthy of me.", "twenty": "And the man who does not take his cross and follow in my steps is not worthy of me.", "acv": "And he who does not take his cross and follow behind me, is not worthy of me.", "anderson": "and whoever does not take his cross and follow after me, is not worthy of me.", "haweis": "And he that taketh not up his cross, and followeth after me, is not worthy of me.", "noyes": "and he that doth not take his cross, and follow me, is not worthy of me.", "webster": "And he that taketh not his cross, and followeth me, is not worthy of me.", "vulgate": "et qui non accipit crucem suam et sequitur me non est me dignus;"}}, {"v": 39, "ref": "10:39", "o": "ὁ εὑρὼν τὴν ψυχὴν αὐτοῦ ἀπολέσει αὐτήν, καὶ ὁ ἀπολέσας τὴν ψυχὴν αὐτοῦ ἕνεκεν ἐμοῦ εὑρήσει αὐτήν.", "en": {"kjv": "He that findeth his life shall lose it: and he that loseth his life for my sake shall find it.", "web": "He who seeks his life will lose it; and he who loses his life for my sake will find it.", "bsb": "Whoever finds his life will lose it, and whoever loses his life for My sake will find it.", "asv": "He that findeth his life shall lose it; and he that loseth his life for my sake shall find it.", "ylt": "`He who found his life shall lose it, and he who lost his life for my sake shall find it.", "tyndale": "He that fyndeth hys lyfe shall lose it: and he that losith hys lyfe for my sake shall fynde it.", "dra": "He that findeth his life, shall lose it: and he that shall lose his life for me, shall find it.", "bbe": "He who has the desire to keep his life will have it taken from him, and he who gives up his life because of me will have it given back to him.", "geneva": "He that will finde his life, shall lose it: and he that loseth his life for my sake, shall finde it.", "wycliffe": "He that fyndith his lijf, shal lose it; and he that lesith his lijf for me, shal fynde it.", "rotherham": "He that hath found his life, shall lose it,—and, he that hath lost his life, for my sake, shall find it.", "weymouth": "To save your life is to lose it, and to lose your life for my sake is to save it.", "darby": "He that finds his life shall lose it, and he who has lost his life for my sake shall find it.", "twenty": "He who has found his life will lose it, while he who, for my sake, has lost his life shall find it.", "acv": "He who finds his life will lose it, and he who loses his life because of me will find it.", "anderson": "He that finds his life shall lose it; and he that loses his life for my sake, shall find it.", "haweis": "He that preserveth his life shall lose it: and he that loseth his life for my sake shall preserve it.", "noyes": "He that findeth his life will lose it; and he that loseth his life for my sake will find it.", "webster": "He that findeth his life shall lose it: and he that loseth his life for my sake, shall find it.", "vulgate": "qui invenit animam suam perdet illam et qui perdiderit animam suam propter me inveniet eam;"}}, {"v": 40, "ref": "10:40", "o": "Ὁ δεχόμενος ὑμᾶς ἐμὲ δέχεται, καὶ ὁ ἐμὲ δεχόμενος δέχεται τὸν ἀποστείλαντά με.", "en": {"kjv": "He that receiveth you receiveth me, and he that receiveth me receiveth him that sent me.", "web": "He who receives you receives me, and he who receives me receives him who sent me.", "bsb": "He who receives you receives Me, and he who receives Me receives the One who sent Me.", "asv": "He that receiveth you receiveth me, and he that receiveth me receiveth him that sent me.", "ylt": "`He who is receiving you doth receive me, and he who is receiving me doth receive Him who sent me,", "tyndale": "He that receavith you receavith me: and he that receavith me receavith him that sent me.", "dra": "He that receiveth you, receiveth me: and he that receiveth me, receiveth him that sent me.", "bbe": "He who gives honour to you gives honour to me; and he who gives honour to me gives honour to him who sent me.", "geneva": "He that receiueth you, receiueth me: and hee that receiueth mee, receiueth him that hath sent me.", "wycliffe": "He that resseyueth you, resseyueth me; and he that resseyueth me, resseyueth hym that sente me.", "rotherham": "He that giveth welcome unto you, unto me, giveth welcome, and, he that, unto me, giveth welcome, giveth welcome—unto him that sent me forth.", "weymouth": "\"Whoever receives you receives me, and whoever receives me receives Him who sent me.", "darby": "He that receives you receives me, and he that receives me receives him that sent me.", "twenty": "He who welcomes you is welcoming me; and he who welcomes me is welcoming him who sent me as his Messenger.", "acv": "He who receives you receives me, and he who receives me receives him who sent me.", "anderson": "He that receives you, receives me: and he that receives me, receives him that sent me.", "haweis": "He that receiveth you receiveth me, and he that receiveth me receiveth him that sent me.", "noyes": "He that receiveth you, receiveth me; and he that receiveth me, receiveth him that sent me.", "webster": "He that receiveth you, receiveth me, and he that receiveth me, receiveth him that sent me.", "vulgate": "qui recipit vos me recipit et qui me recipit recipit eum qui me misit;"}}, {"v": 41, "ref": "10:41", "o": "ὁ δεχόμενος προφήτην εἰς ὄνομα προφήτου μισθὸν προφήτου λήμψεται, καὶ ὁ δεχόμενος δίκαιον εἰς ὄνομα δικαίου μισθὸν δικαίου λήμψεται.", "en": {"kjv": "He that receiveth a prophet in the name of a prophet shall receive a prophet’s reward; and he that receiveth a righteous man in the name of a righteous man shall receive a righteous man’s reward.", "web": "He who receives a prophet in the name of a prophet will receive a prophet’s reward. He who receives a righteous man in the name of a righteous man will receive a righteous man’s reward.", "bsb": "Whoever receives a prophet because he is a prophet will receive a prophet’s reward, and whoever receives a righteous man because he is a righteous man will receive a righteous man’s reward.", "asv": "He that receiveth a prophet in the name of a prophet shall receive a prophet’s reward: and he that receiveth a righteous man in the name of a righteous man shall receive a righteous man’s reward.", "ylt": "he who is receiving a prophet in the name of a prophet, shall receive a prophet's reward, and he who is receiving a righteous man in the name of a righteous man, shall receive a righteous man's reward,", "tyndale": "He that receavith a prophet in ye name of a prophet shall receave a prophetes rewarde. And he that receavith a righteous man in the name of a righteous man shall receave the rewarde of a righteous man.", "dra": "He that receiveth a prophet in the name of a prophet, shall receive the reward of a prophet: and he that receiveth a just man in the name of a just man, shall receive the reward of a just man.", "bbe": "He who gives honour to a prophet, in the name of a prophet, will be given a prophet's reward; and he who gives honour to an upright man, in the name of an upright man, will be given an upright man's reward.", "geneva": "Hee that receiueth a Prophet in the name of a Prophet, shall receiue a Prophetes rewarde: and hee that receiueth a righteous man, in the name of a righteous man, shall receiue the rewarde of a righteous man.", "wycliffe": "He that resseyueth a prophete in the name of a prophete, shal take the mede of a prophete. And he that resseyueth a iust man in the name of a iust man, schal take the mede of a iust man.", "rotherham": "He that giveth welcome unto a prophet, in the name of a prophet, the reward of a prophet, shall receive; and, he that giveth welcome unto a righteous man, in the name of a righteous man, the reward of a righteous man, shall receive;—", "weymouth": "Every one who receives a prophet, because he is a prophet, will receive a prophet's reward, and every one who receives a righteous man, because he is a righteous man, will receive a righteous man's reward.", "darby": "He that receives a prophet in the name of a prophet, shall receive a prophet's reward; and he that receives a righteous man in the name of a righteous man, shall receive a righteous man's reward.", "twenty": "He who welcomes a Prophet, because he is a Prophet, shall receive a Prophet’s reward; and he who welcomes a good man, because he is a good man, shall receive a good man’s reward.", "acv": "He who receives a prophet in the name of a prophet will receive a prophet's reward, and he who receives a righteous man in the name of a righteous man will receive a righteous man's reward.", "anderson": "He that receives a prophet because he is a prophet, shall receive a prophet’s reward: and he that receives a righteous man because he is a righteous man, shall receive a righteous man’s reward.", "haweis": "He that receiveth a prophet in the name of a prophet, shall receive the reward of a prophet; and he that receiveth a righteous man in the name of a righteous man, shall receive the reward of a righteous man.", "noyes": "He that receiveth a prophet because he is a prophet, will receive a prophet’s reward, and he that receiveth a righteous man because he is a righteous man, will receive a righteous man’s reward.", "webster": "He that receiveth a prophet in the name of a prophet, shall receive a prophet's reward; and he that receiveth a righteous man in the name of a righteous man, shall receive a righteous man's reward.", "vulgate": "qui recipit prophetam in nomine prophetae mercedem prophetae accipiet et qui recipit iustum in nomine iusti mercedem iusti accipiet;"}}, {"v": 42, "ref": "10:42", "o": "καὶ ὃς ⸀ἂν ποτίσῃ ἕνα τῶν μικρῶν τούτων ποτήριον ψυχροῦ μόνον εἰς ὄνομα μαθητοῦ, ἀμὴν λέγω ὑμῖν, οὐ μὴ ἀπολέσῃ τὸν μισθὸν αὐτοῦ.", "en": {"kjv": "And whosoever shall give to drink unto one of these little ones a cup of cold water only in the name of a disciple, verily I say unto you, he shall in no wise lose his reward.", "web": "Whoever gives one of these little ones just a cup of cold water to drink in the name of a disciple, most certainly I tell you he will in no way lose his reward.”", "bsb": "And if anyone gives even a cup of cold water to one of these little ones because he is My disciple, truly I tell you, he will never lose his reward.”", "asv": "And whosoever shall give to drink unto one of these little ones a cup of cold water only, in the name of a disciple, verily I say unto you he shall in no wise lose his reward.", "ylt": "and whoever may give to drink to one of these little ones a cup of cold water only in the name of a disciple, verily I say to you, he may not lose his reward.'", "tyndale": "And whosoever shall geve vnto one of these lytle ones to drincke a cuppe of colde water only in the name of a disciple: I tel you of a trueth he shall not lose his rewarde.", "dra": "And whosoever shall give to drink to one of these little ones a cup of cold water only in the name of a disciple, amen I say to you he shall not lose his reward.", "bbe": "And whoever gives to one of these little ones a cup of cold water only, in the name of a disciple, truly I say to you, he will not go without his reward.", "geneva": "And whosoeuer shall giue vnto one of these litle ones to drinke a cuppe of colde water onely, in the name of a disciple, verely I say vnto you, he shall not lose his rewarde.", "wycliffe": "And who euer yyueth drynke to oon of these leeste a cuppe of coolde watir oonli in the name of a disciple, treuli Y seie to you, he shal not leese his mede.", "rotherham": "And, whosoever shall give to drink—unto one of these little ones—a cup of cold water only, in the name of a disciple, Verily, I say unto you, in nowise, shall lose his reward!", "weymouth": "And whoever gives one of these little ones even a cup of cold water to drink because he is a disciple, I solemnly tell you that he will not lose his reward.\"", "darby": "And whosoever shall give to drink to one of these little ones a cup of cold [water] only, in the name of a disciple, verily I say unto you, he shall in no wise lose his reward.", "twenty": "And, if any one gives but a cup of cold water to one of these lowly ones because he is a disciple, I tell you that he shall assuredly not lose his reward.”", "acv": "And whoever may give to drink one of these little ones merely a cold cup in the name of a disciple, truly I say to you he will, no, not lose his reward.", "anderson": "And whoever will give one of these little ones only a cup of cold water to drink, because he is a disciple, verily I say to you, he shall not lose his reward.", "haweis": "And whosoever shall give to one of these little ones, if but a cup of cold water to drink, in the name of a disciple, verily I say unto you, he shall in no wise lose his reward.", "noyes": "And whoever shall give to drink only a cup of cold water to one of these little ones because he is a disciple, truly do I say to you, he will by no means lose his reward.", "webster": "And whoever shall give to drink to one of these little ones, a cup of cold [water] only, in the name of a disciple, verily, I say to you, he shall in no wise lose his reward.", "vulgate": "et quicumque potum dederit uni ex minimis istis calicem aquae frigidae tantum in nomine discipuli amen dico vobis non perdet mercedem suam;"}}]}, {"c": 11, "verses": [{"v": 1, "ref": "11:1", "o": "Καὶ ἐγένετο ὅτε ἐτέλεσεν ὁ Ἰησοῦς διατάσσων τοῖς δώδεκα μαθηταῖς αὐτοῦ, μετέβη ἐκεῖθεν τοῦ διδάσκειν καὶ κηρύσσειν ἐν ταῖς πόλεσιν αὐτῶν.", "en": {"kjv": "And it came to pass, when Jesus had made an end of commanding his twelve disciples, he departed thence to teach and to preach in their cities.", "web": "When Jesus had finished directing his twelve disciples, he departed from there to teach and preach in their cities.", "bsb": "After Jesus had finished instructing His twelve disciples, He went on from there to teach and preach in their cities.", "asv": "And it came to pass when Jesus had finished commanding his twelve disciples, he departed thence to teach and preach in their cities.", "ylt": "And it came to pass, when Jesus ended directing his twelve disciples, he departed thence to teach and to preach in their cities.", "tyndale": "And it came to passe when Iesus had made an ende of comaundinge his .xii. disciples that he departed thence to teache and to preache in their cities.", "dra": "And it came to pass, when Jesus had made an end of commanding his twelve disciples, he passed from thence, to teach and to preach in their cities.", "bbe": "And it came about that when Jesus had come to the end of giving these orders to his twelve disciples, he went away from there, teaching and preaching in their towns.", "geneva": "And it came to passe that when Iesus had made an ende of commaunding his twelue disciples, hee departed thence to teache and to preach in their cities.", "wycliffe": "And it was doon, whanne Jhesus hadde endid, he comaundide to hise twelue disciplis, and passide fro thennus to teche and preche in the citees of hem.", "rotherham": "And it came to pass, when Jesus had finished giving instructions to his twelve disciples, he passed on from thence, to be teaching and proclaiming in their cities.", "weymouth": "When Jesus had concluded His instructions to His twelve disciples, He left in order to teach and to proclaim His Message in the neighbouring towns.", "darby": "And it came to pass when Jesus had finished commanding his twelve disciples, he departed thence to teach and preach in their cities.", "twenty": "After Jesus had finished giving directions to his twelve Disciples, he left that place in order to teach and preach in their towns.", "acv": "And it came to pass when Jesus finished directing his twelve disciples, he departed from there to teach and preach in their cities.", "anderson": "And it came to pass, when Jesus had made an end of commanding his twelve disciples, he departed thence to teach and to preach in their cities.", "haweis": "AND it came to pass, when Jesus had finished his injunctions to his twelve disciples, he departed thence to teach and preach in their cities.", "noyes": "And it came to pass, when Jesus had made an end of his charge to his twelve disciples, that he departed thence, to teach and to preach in their cities.", "webster": "And it came to pass when Jesus had made an end of commanding his twelve disciples, he departed thence to teach and to preach in their cities.", "vulgate": "et factum est cum consummasset Iesus praecipiens duodecim discipulis suis transiit inde ut doceret et praedicaret in civitatibus eorum;"}}, {"v": 2, "ref": "11:2", "o": "Ὁ δὲ Ἰωάννης ἀκούσας ἐν τῷ δεσμωτηρίῳ τὰ ἔργα τοῦ χριστοῦ πέμψας ⸀διὰ τῶν μαθητῶν αὐτοῦ", "en": {"kjv": "Now when John had heard in the prison the works of Christ, he sent two of his disciples,", "web": "Now when John heard in the prison the works of Christ, he sent two of his disciples", "bsb": "Meanwhile John heard in prison about the works of Christ, and he sent his disciples", "asv": "Now when John heard in the prison the works of the Christ, he sent by his disciples", "ylt": "And John having heard in the prison the works of the Christ, having sent two of his disciples,", "tyndale": "When Ihon beinge in preson hearde ye workes of Christ he sent two of his disciples", "dra": "Now when John had heard in prison the works of Christ: sending two of his disciples he said to him:", "bbe": "Now when John had news in prison of the works of the Christ, he sent his disciples", "geneva": "And when Iohn heard in the prison the woorkes of Christ, he sent two of his disciples, and sayde vnto him,", "wycliffe": "But whanne Joon in boondis hadde herd the werkis of Crist, he sente tweyne of hise disciplis,", "rotherham": "Now, John, hearing in the prison the works of the Christ, sending through his disciples,", "weymouth": "Now John had heard in prison about the Christ's doings, and he sent some of his disciples to inquire:", "darby": "But John, having heard in the prison the works of the Christ, sent by his disciples,", "twenty": "Now John had heard in prison what the Christ was doing, and he sent a message by his disciples,", "acv": "Now when John heard in the prison the works of the Christ, having sent two of his disciples,", "anderson": "Now when John had heard in the prison of the works of the Christ, he sent two of his disciples,", "haweis": "Then John, having heard in prison the works of Christ, sent two of his disciples,", "noyes": "And John, having heard in the prison of the works of Christ, sent by his disciples,", "webster": "Now when John had heard in the prison the works of Christ, he sent two of his disciples,", "vulgate": "Iohannes autem cum audisset in vinculis opera Christi mittens duos de discipulis suis;"}}, {"v": 3, "ref": "11:3", "o": "εἶπεν αὐτῷ· Σὺ εἶ ὁ ἐρχόμενος ἢ ἕτερον προσδοκῶμεν;", "en": {"kjv": "And said unto him, Art thou he that should come, or do we look for another?", "web": "and said to him, “Are you he who comes, or should we look for another?”", "bsb": "to ask Him, “Are You the One who was to come, or should we look for someone else?”", "asv": "and said unto him, Art thou he that cometh, or look we for another?", "ylt": "said to him, `Art thou He who is coming, or for another do we look?'", "tyndale": "and sayde vnto him. Arte thou he that shall come: or shall we loke for another.", "dra": "Art thou he that art to come, or look we for another?", "bbe": "To say to him, Are you he who is to come, or are we waiting for another?", "geneva": "Art thou he that shoulde come, or shall we looke for another?", "wycliffe": "and seide to him, `Art thou he that schal come, or we abiden another?", "rotherham": "said unto him, Art, thou, the coming one? or, a different one, are we to expect?", "weymouth": "\"Are you the Coming One, or is it a different person that we are to expect?\"", "darby": "and said to him, Art thou the coming [one]? or are we to wait for another?", "twenty": "and asked — ” Are you ‘The Coming One,’ or are we to look for someone else?”", "acv": "he said to him, Are thou he who comes, or do we look for another man?", "anderson": "and said to him: Art thou he that was to come, or must we look for another?", "haweis": "and said unto him, Art thou he that cometh, or should we expect another?", "noyes": "and said to him, Art thou he that is to come, or are we to look for another?", "webster": "And said to him, Art thou he that should come, or do we look for another?", "vulgate": "ait illi tu es qui venturus es an alium expectamus;"}}, {"v": 4, "ref": "11:4", "o": "καὶ ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν αὐτοῖς· Πορευθέντες ἀπαγγείλατε Ἰωάννῃ ἃ ἀκούετε καὶ βλέπετε·", "en": {"kjv": "Jesus answered and said unto them, Go and shew John again those things which ye do hear and see:", "web": "Jesus answered them, “Go and tell John the things which you hear and see:", "bsb": "Jesus replied, “Go back and report to John what you hear and see:", "asv": "And Jesus answered and said unto them, Go and tell John the things which ye hear and see:", "ylt": "And Jesus answering said to them, `Having gone, declare to John the things that ye hear and see,", "tyndale": "Iesus answered and sayde vnto them. Go and shewe Ihon what ye have hearde and sene.", "dra": "And Jesus making answer said to them: Go and relate to John what you have heard and seen.", "bbe": "And Jesus, answering, said to them, Go and give news to John of the things which you are seeing and hearing:", "geneva": "And Iesus answering, said vnto them, Goe, and shewe Iohn, what things ye heare, and see.", "wycliffe": "And Jhesus answeride, and seide `to hem, Go ye, and telle ayen to Joon tho thingis that ye han herd and seyn.", "rotherham": "And, answering, Jesus said unto them—Go report unto John what ye do hear and see:—", "weymouth": "\"Go and report to John what you see and hear,\" replied Jesus;", "darby": "And Jesus answering said to them, Go, report to John what ye hear and see.", "twenty": "The answer of Jesus to the question was — “Go and report to John what you hear and see —", "acv": "And having answered, Jesus said to them, After going, report to John the things that ye hear and see:", "anderson": "And Jesus answered and said to them: Go and tell John what you hear and see.", "haweis": "And Jesus answering said unto them, Go, and tell John what things ye hear and see.", "noyes": "And Jesus answered and said to them, Go and tell John what ye hear and see.", "webster": "Jesus answered and said to them, Go and show John again those things which ye hear and see:", "vulgate": "et respondens Iesus ait illis euntes renuntiate Iohanni quae auditis et videtis;"}}, {"v": 5, "ref": "11:5", "o": "τυφλοὶ ἀναβλέπουσιν καὶ χωλοὶ περιπατοῦσιν, λεπροὶ καθαρίζονται καὶ κωφοὶ ἀκούουσιν, ⸀καὶ νεκροὶ ἐγείρονται καὶ πτωχοὶ εὐαγγελίζονται·", "en": {"kjv": "The blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised up, and the poor have the gospel preached to them.", "web": "the blind receive their sight, the lame walk, the lepers are cleansed, the deaf hear,the dead are raised up, and the poor have good news preached to them.", "bsb": "The blind receive sight, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised, and the good news is preached to the poor.", "asv": "the blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, and the dead are raised up, and the poor have good tidings preached to them.", "ylt": "blind receive sight, and lame walk, lepers are cleansed, and deaf hear, dead are raised, and poor have good news proclaimed,", "tyndale": "The blynd se the halt goo the lepers are clensed: the deef heare the ded ryse ageyne and the glad tidinges is preached to the povre.", "dra": "The blind see, the lame walk, the lepers are cleansed, the deaf hear, the dead rise again, the poor have the gospel preached to them.", "bbe": "The blind see; those who were not able to, are walking; lepers are made clean; those who were without hearing, now have their ears open; the dead come to life again, and the poor have the good news given to them.", "geneva": "The blinde receiue sight, and the halt doe walke: the lepers are clensed, and the deafe heare, the dead are raised vp, and the poore receiue the Gospel.", "wycliffe": "Blynde men seen, crokid men goon, meselis ben maad clene, deefe men heren, deed men rysen ayen, pore men ben takun to `prechyng of the gospel.", "rotherham": "The, blind, recover sight, and, the lame, walk, lepers, are cleansed, and, the deaf, hear,—and, the dead, are raised, and, the destitute, are told the joyful tidings;", "weymouth": "\"blind eyes receive sight, and cripples walk; lepers are cleansed, and deaf ears hear; the dead are raised to life, and the poor have the Good News proclaimed to them;", "darby": "Blind [men] see and lame walk; lepers are cleansed, and deaf hear; and dead are raised, and poor have glad tidings preached to them:", "twenty": "the blind recover their sight and the lame walk, the lepers are made clean and the deaf hear, the dead, too, are raised to life, and the good news is told to the poor.", "acv": "the blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, and the dead are raised up, and the poor are proclaimed good news.", "anderson": "The blind receive their sight, and the lame walk; the lepers are cleansed, and the deaf hear; the dead are raised, and the poor have the gospel preached to them;", "haweis": "The blind receive sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised, and the poor have the gospel preached to them.", "noyes": "The blind receive sight and the lame walk, lepers are cleansed, and the deaf hear, and the dead are raised, and to the poor good tidings are brought;", "webster": "The blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised, and the poor have the gospel preached to them.", "vulgate": "caeci vident claudi ambulant leprosi mundantur surdi audiunt mortui resurgunt pauperes evangelizantur;"}}, {"v": 6, "ref": "11:6", "o": "καὶ μακάριός ἐστιν ὃς ⸀ἐὰν μὴ σκανδαλισθῇ ἐν ἐμοί.", "en": {"kjv": "And blessed is he, whosoever shall not be offended in me.", "web": "Blessed is he who finds no occasion for stumbling in me.”", "bsb": "Blessed is the one who does not fall away on account of Me.”", "asv": "And blessed is he, whosoever shall find no occasion of stumbling in me.", "ylt": "and happy is he who may not be stumbled in me.'", "tyndale": "And happy is he that is not offended by me.", "dra": "And blessed is he that shall not be scandalized in me.", "bbe": "And a blessing will be on him who has no doubts about me.", "geneva": "And blessed is he that shall not be offeded in me.", "wycliffe": "And he is blessid, that shal not be sclaundrid in me.", "rotherham": "And, happy, is he, whosoever shall not find cause of stumbling, in me.", "weymouth": "and blessed is every one who does not stumble and fall because of my claims.\"", "darby": "and blessed is whosoever shall not be offended in me.", "twenty": "And blessed is the man who finds no hindrance in me.”", "acv": "And blessed is he, whoever will not be caused to stumble by me.", "anderson": "and blessed is he that shall find in me no cause of offense.", "haweis": "And blessed is he whosoever shall not be offended at me.", "noyes": "and blessed is he, whoever shall find no occasion of stumbling in me.", "webster": "And blessed is [he] to whom I shall not be the cause of his falling into sin.", "vulgate": "et beatus est qui non fuerit scandalizatus in me;"}}, {"v": 7, "ref": "11:7", "o": "Τούτων δὲ πορευομένων ἤρξατο ὁ Ἰησοῦς λέγειν τοῖς ὄχλοις περὶ Ἰωάννου· Τί ἐξήλθατε εἰς τὴν ἔρημον θεάσασθαι; κάλαμον ὑπὸ ἀνέμου σαλευόμενον;", "en": {"kjv": "And as they departed, Jesus began to say unto the multitudes concerning John, What went ye out into the wilderness to see? A reed shaken with the wind?", "web": "As these went their way, Jesus began to say to the multitudes concerning John, “What did you go out into the wilderness to see? A reed shaken by the wind?", "bsb": "As John’s disciples were leaving, Jesus began to speak to the crowds about John: “What did you go out into the wilderness to see? A reed swaying in the wind?", "asv": "And as these went their way, Jesus began to say unto the multitudes concerning John, What went ye out into the wilderness to behold? a reed shaken with the wind?", "ylt": "And as they are going, Jesus began to say to the multitudes concerning John, `What went ye out to the wilderness to view? --a reed shaken by the wind?", "tyndale": "And as they departed Iesus begane to speake vnto the people of Ihon. What for to se wet ye out in to the wyldernes? wet ye out to se a rede shake with ye wynde?", "dra": "And when they went their way, Jesus began to say to the multitudes concerning John: What went you out into the desert to see? a reed shaken with the wind?", "bbe": "And when they were going away, Jesus, talking of John, said to all the people, What went you out into the waste land to see? a tall stem moving in the wind?", "geneva": "And as they departed, Iesus beganne to speake vnto the multitude, of Iohn, What went ye out into the wildernes to see? A reede shaken with the winde?", "wycliffe": "And whanne thei weren goon awei, Jhesus bigan to seie of Joon to the puple, What thing wenten ye out in to desert to se? a reed wawed with the wynd?", "rotherham": "But, as these were going their way, Jesus began to say unto the multitudes, concerning John,—What went ye forth into the wilderness to gaze at? A reed, by a wind, shaken?", "weymouth": "When the messengers had taken their leave, Jesus proceeded to say to the multitude concerning John, \"What did you go out into the Desert to gaze at? A reed waving in the wind?", "darby": "But as they went [away], Jesus began to say to the crowds concerning John, What went ye out into the wilderness to see? a reed moved about by the wind?", "twenty": "While these men were going back, Jesus began to say to the crowds with reference to John:", "acv": "And while those men departed, Jesus began to say to the multitudes about John, What did ye go out into the wilderness to see? A reed shaken with the wind?", "anderson": "As these were going away, Jesus began to say to the multitudes concerning John: What did you go out into the wilderness to see? A reed shaken by the wind?", "haweis": "And when they were gone, Jesus began to speak to the multitudes concerning John, What went ye out into the wilderness to see? A reed shaken with the wind?", "noyes": "And, as these were going, Jesus began to say to the multitudes concerning John, What went ye out into the wilderness to see? the reeds shaken by the wind?", "webster": "And as they departed, Jesus began to say to the multitudes concerning John, What went ye out into the wilderness to see? a reed shaken with the wind?", "vulgate": "illis autem abeuntibus coepit Iesus dicere ad turbas de Iohanne quid existis in desertum videre harundinem vento agitatam;"}}, {"v": 8, "ref": "11:8", "o": "ἀλλὰ τί ἐξήλθατε ἰδεῖν; ἄνθρωπον ἐν ⸀μαλακοῖς ἠμφιεσμένον; ἰδοὺ οἱ τὰ μαλακὰ φοροῦντες ἐν τοῖς οἴκοις τῶν ⸀βασιλέων ⸀εἰσίν.", "en": {"kjv": "But what went ye out for to see? A man clothed in soft raiment? behold, they that wear soft clothing are in kings’ houses.", "web": "But what did you go out to see? A man in soft clothing? Behold, those who wear soft clothing are in king’s houses.", "bsb": "Otherwise, what did you go out to see? A man dressed in fine clothes? Look, those who wear fine clothing are found in kings’ palaces.", "asv": "But what went ye out to see? a man clothed in soft raiment? Behold, they that wear soft raiment are in kings’ houses.", "ylt": "`But what went ye out to see? --a man clothed in soft garments? lo, those wearing the soft things are in the kings' houses.", "tyndale": "other what wet ye out for to se? A man clothed in soofte raymet:? Beholde they yt weare soofte clothig are in kynges howses.", "dra": "But what went you out to see? a man clothed in soft garments? Behold they that are clothed in soft garments, are in the houses of kings.", "bbe": "But what went you out to see? a man delicately clothed? Those who have fair robes are in kings' houses.", "geneva": "But what went ye out to see? A man clothed in soft raiment? Behold, they that weare soft clothing, are in Kings houses.", "wycliffe": "Or what thing wenten ye out to see? a man clothid with softe clothis? Lo! thei that ben clothid with softe clothis ben in the housis of kyngis.", "rotherham": "But what went ye forth to see? A man, in soft clothing, arrayed? Lo! they who soft clothing do wear, are in the houses of kings.", "weymouth": "But what did you go out to see? A man luxuriously dressed? Those who wear luxurious clothes are to be found in kings' palaces.", "darby": "But what went ye out to see? a man clothed in delicate raiment? behold, those who wear delicate things are in the houses of kings.", "twenty": "“What did you go out into the Wilderness to look at? A reed waving in the wind? If not, what did you go out to see? A man richly dressed? Why, those who wear rich things are to be found in the courts of kings!", "acv": "But what did ye go out to see? A man clothed in delicate clothes? Behold, those wearing delicate things are in king's houses.", "anderson": "But what did you go out to see? A man clothed in soft raiment? Behold, those who wear soft clothing are in kings houses.", "haweis": "But what went ye out to see? A man clothed in delicate garments? Lo! they who wear delicate garments are in the houses of kings.", "noyes": "But why did ye go out? to see a man clothed in soft raiment? Lo! they that wear soft clothing are in kings’ houses.", "webster": "But what went ye out to see? A man clothed in soft raiment? Behold, they that wear soft [clothing] are in kings' houses.", "vulgate": "sed quid existis videre hominem mollibus vestitum ecce qui mollibus vestiuntur in domibus regum sunt;"}}, {"v": 9, "ref": "11:9", "o": "ἀλλὰ τί ἐξήλθατε⸂; προφήτην ἰδεῖν⸃; ναί, λέγω ὑμῖν, καὶ περισσότερον προφήτου.", "en": {"kjv": "But what went ye out for to see? A prophet? yea, I say unto you, and more than a prophet.", "web": "But why did you go out? To see a prophet? Yes, I tell you, and much more than a prophet.", "bsb": "What then did you go out to see? A prophet? Yes, I tell you, and more than a prophet.", "asv": "But wherefore went ye out? to see a prophet? Yea, I say unto you, and much more than a prophet.", "ylt": "`But what went ye out to see? --a prophet? yes, I say to you, and more than a prophet,", "tyndale": "But what wet ye oute for to se? A prophete? Ye I saye to you and more the a prophete.", "dra": "But what went you out to see? A prophet? Yea I tell you, and more than a prophet.", "bbe": "But why did you go out? to see a prophet? Yes, I say to you, and more than a prophet.", "geneva": "But what went ye out to see? A Prophet? Yea, I say vnto you, and more then a Prophet.", "wycliffe": "But what thing wenten ye out to se? a prophete? Yhe, Y seie to you, and more than a prophete.", "rotherham": "But why went ye forth? A prophet, to see? Yea, I say unto you, and much more than a prophet.", "weymouth": "But why did you go out? To see a prophet? Yes, I tell you, and far more than a prophet.", "darby": "But what went ye out to see? a prophet? Yea, I say to you, and more than a prophet:", "twenty": "What, then, did you go for? To see a Prophet? Yes, I tell you, and far more than a Prophet.", "acv": "But what did ye go out to see? A prophet? Yea, I say to you, and more than a prophet.", "anderson": "But what did you go out to see? A prophet? Yes, I say to you, and more than a prophet.", "haweis": "Yet what went ye out to see? A prophet? Yes, I tell you, and abundantly more than a prophet.", "noyes": "But why did ye go out? to see a prophet? Yea, I say to you, and more than a prophet.", "webster": "But what went ye out to see? A prophet? yes, I say to you, and more than a prophet.", "vulgate": "sed quid existis videre prophetam etiam dico vobis et plus quam prophetam;"}}, {"v": 10, "ref": "11:10", "o": "⸀οὗτός ἐστιν περὶ οὗ γέγραπται· Ἰδοὺ ἐγὼ ἀποστέλλω τὸν ἄγγελόν μου πρὸ προσώπου σου, ὃς κατασκευάσει τὴν ὁδόν σου ἔμπροσθέν σου.", "en": {"kjv": "For this is he, of whom it is written, Behold, I send my messenger before thy face, which shall prepare thy way before thee.", "web": "For this is he, of whom it is written, ‘Behold, I send my messenger before your face, who will prepare your way before you.’", "bsb": "This is the one about whom it is written: ‘Behold, I will send My messenger ahead of You, who will prepare Your way before You.’", "asv": "This is he, of whom it is written, Behold, I send my messenger before thy face, Who shall prepare thy way before thee.", "ylt": "for this is he of whom it hath been written, Lo, I do send My messenger before thy face, who shall prepare thy way before thee.", "tyndale": "For this is he of who it is wrytte. Beholde I sende my messenger before thy face which shall prepare thy waye before ye.", "dra": "For this is he of whom it is written: Behold I send my angel before my face, who shall prepare thy way before thee.", "bbe": "This is he of whom it has been said, See, I send my servant before your face, who will make ready your way before you.", "geneva": "For this is he of whom it is written, Beholde, I send my messenger before thy face, which shall prepare thy way before thee.", "wycliffe": "For this is he, of whom it is writun, Lo! Y sende myn aungel bifor thi face, that shal make redi thi weye bifor thee.", "rotherham": "This, is he, concerning whom it is written,—Lo! I, send my messenger before thy face, who shall make ready thy way before thee!", "weymouth": "This is he of whom it is written, \"`See I am sending My messenger before Thy face, and he will make Thy road ready before Thee.'", "darby": "this is he of whom it is written, Behold, I send my messenger before thy face, who shall prepare thy way before thee.", "twenty": "This is the man of whom Scripture says — ‘Behold, I am myself sending my Messenger before thy face, and he shall prepare thy way before thee.’", "acv": "For this is he about whom it is written, Behold, I send my agent before thy face who will prepare thy way before thee.", "anderson": "For this is he of whom it is written: Behold, I send my messenger before thy face, who shall prepare thy way before thee.", "haweis": "For this is he of whom it is written, “Behold, I send my messenger before thy face, who shall prepare thy way before thee.”", "noyes": "For this is he of whom it is written: \"Lo! I send my messenger before thy face, who shall prepare thy way before thee.\"", "webster": "For this is [he] concerning whom it is written, Behold, I send my messenger before thy face, who shall prepare thy way before thee.", "vulgate": "hic enim est de quo scriptum est ecce ego mitto angelum meum ante faciem tuam qui praeparabit viam tuam ante te;"}}, {"v": 11, "ref": "11:11", "o": "ἀμὴν λέγω ὑμῖν, οὐκ ἐγήγερται ἐν γεννητοῖς γυναικῶν μείζων Ἰωάννου τοῦ βαπτιστοῦ· ὁ δὲ μικρότερος ἐν τῇ βασιλείᾳ τῶν οὐρανῶν μείζων αὐτοῦ ἐστιν.", "en": {"kjv": "Verily I say unto you, Among them that are born of women there hath not risen a greater than John the Baptist: notwithstanding he that is least in the kingdom of heaven is greater than he.", "web": "Most certainly I tell you, among those who are born of women there has not arisen anyone greater than John the Baptizer; yet he who is least in the Kingdom of Heaven is greater than he.", "bsb": "Truly I tell you, among those born of women there has risen no one greater than John the Baptist. Yet even the least in the kingdom of heaven is greater than he.", "asv": "Verily I say unto you, Among them that are born of women there hath not arisen a greater than John the Baptist: yet he that is but little in the kingdom of heaven is greater than he.", "ylt": "Verily I say to you, there hath not risen, among those born of women, a greater than John the Baptist, but he who is least in the reign of the heavens is greater than he.", "tyndale": "Verely I saye vnto you amonge ye chyldren of wemen arose there not a gretter then Ihon the baptist. Notwithstondinge he that ys lesse in the kyngdome of heven ys gretter then he.", "dra": "Amen I say to you, there hath not risen among them that are born of women a greater than John the Baptist: yet he that is the lesser in the kingdom of heaven is greater than he.", "bbe": "Truly I say to you, Among the sons of women there has not been a greater than John the Baptist: but he who is least in the kingdom of heaven is greater than he.", "geneva": "Verely I say vnto you, among them which are begotten of women, arose there not a greater then Iohn Baptist: notwithstanding, he that is the least in the kingdome of heauen, is greater then he.", "wycliffe": "Treuli Y seie to you, ther roos noon more than Joon Baptist among the children of wymmen; but he that is lesse in the kyngdom of heuenes, is more than he.", "rotherham": "Verily, I say unto you—There hath not arisen, among such as are born of women, a greater than John the Immerser,—yet, he that is less in the kingdom of the heavens, is, greater than he.", "weymouth": "\"I solemnly tell you that among all of woman born no greater has ever been raised up than John the Baptist; yet one who is of lower rank in the Kingdom of the Heavens is greater than he.", "darby": "Verily I say to you, that there is not arisen among [the] born of women a greater than John the baptist. But he who is a little one in the kingdom of the heavens is greater than he.", "twenty": "I tell you, no one born of a woman has yet appeared who is greater than John the Baptist; and yet the lowliest in the Kingdom of Heaven is greater than he.", "acv": "Truly I say to you, among men born of women there has not been raised a greater than John the immerser. Yet the smaller in the kingdom of the heavens is greater than he.", "anderson": "Verily, I say to you, Among those born of women, there has not risen a greater than John the Immerser. But the least in the kingdom of heaven is greater than he.", "haweis": "Verily I say unto you, There hath not arisen, from those born of women, a greater than John the Baptist: yet he that is the least in the kingdom of God is greater than he.", "noyes": "Truly do I say to you, Among those born of women there hath not risen a greater than John the Baptist. But he that is least in the kingdom of heaven is greater than he.", "webster": "Verily, I say to you, among them that are born of women, there hath not risen a greater than John the Baptist: notwithstanding, he that is least in the kingdom of heaven, is greater than he.", "vulgate": "amen dico vobis non surrexit inter natos mulierum maior Iohanne Baptista qui autem minor est in regno caelorum maior est illo;"}}, {"v": 12, "ref": "11:12", "o": "ἀπὸ δὲ τῶν ἡμερῶν Ἰωάννου τοῦ βαπτιστοῦ ἕως ἄρτι ἡ βασιλεία τῶν οὐρανῶν βιάζεται, καὶ βιασταὶ ἁρπάζουσιν αὐτήν.", "en": {"kjv": "And from the days of John the Baptist until now the kingdom of heaven suffereth violence, and the violent take it by force.", "web": "From the days of John the Baptizer until now, the Kingdom of Heaven suffers violence, and the violent take it by force.", "bsb": "From the days of John the Baptist until now, the kingdom of heaven has been subject to violence, and the violent lay claim to it.", "asv": "And from the days of John the Baptist until now the kingdom of heaven suffereth violence, and men of violence take it by force.", "ylt": "`And, from the days of John the Baptist till now, the reign of the heavens doth suffer violence, and violent men do take it by force,", "tyndale": "From the tyme of Ihon Baptist hytherto ye kyngdome of heve suffreth violence and they that go to it with violence pluck it vnto them.", "dra": "And from the days of John the Baptist until now, the kingdom of heaven suffereth violence, and the violent bear it away.", "bbe": "And from the days of John the Baptist till now, the kingdom of heaven is forcing its way in, and men of force take it.", "geneva": "And from the time of Iohn Baptist hitherto, the kingdome of heauen suffereth violence, and the violent take it by force.", "wycliffe": "And fro the daies of Joon Baptist til now the kyngdom of heuenes suffrith violence, and violent men rauyschen it.", "rotherham": "But, from the days of John the Immerser, until even now, the kingdom of the heavens, is being invaded, and, invaders, are, seizing upon it.", "weymouth": "But from the time of John the Baptist till now, the Kingdom of the Heavens has been suffering violent assault, and the violent have been seizing it by force.", "darby": "But from the days of John the baptist until now, the kingdom of the heavens is taken by violence, and [the] violent seize on it.", "twenty": "From the time of John the Baptist to this very hour, the Kingdom of Heaven has been taken by force, and men using force have been seizing it.", "acv": "And from the days of John the immerser until now the kingdom of the heavens is treated aggressively, and aggressors seize it.", "anderson": "From the days of John the Immerser till now, the kingdom of heaven is taken by violence, and men of violence seize upon it eagerly.", "haweis": "But from the days of John the Baptist unto the present, the kingdom of heaven is assaulted by violence, and the invaders forcibly seize upon it.", "noyes": "And from the days of John the Baptist until now, the kingdom of heaven suffereth violence, and the violent seize upon it.", "webster": "And from the days of John the Baptist, until now, the kingdom of heaven suffereth violence, and the violent take it by force.", "vulgate": "a diebus autem Iohannis Baptistae usque nunc regnum caelorum vim patitur et violenti rapiunt illud;"}}, {"v": 13, "ref": "11:13", "o": "πάντες γὰρ οἱ προφῆται καὶ ὁ νόμος ἕως Ἰωάννου ἐπροφήτευσαν·", "en": {"kjv": "For all the prophets and the law prophesied until John.", "web": "For all the prophets and the law prophesied until John.", "bsb": "For all the Prophets and the Law prophesied until John.", "asv": "For all the prophets and the law prophesied until John.", "ylt": "for all the prophets and the law till John did prophesy,", "tyndale": "For all the prophetes and the lawe prophesyed vnto to the tyme of Ihon.", "dra": "For all the prophets and the law prophesied until John:", "bbe": "For all the prophets and the law were in force till John.", "geneva": "For all the Prophetes and the Lawe prophecied vnto Iohn.", "wycliffe": "For alle prophetis and the lawe `til to Joon prophecieden; and if ye wolen resseyue,", "rotherham": "For, all the prophets and the law, until John, did prophesy;", "weymouth": "For all the Prophets and the Law taught until John.", "darby": "For all the prophets and the law have prophesied unto John.", "twenty": "For the teaching of all the Prophets and of the Law continued till the time of John;", "acv": "For all the prophets and the law prophesied until John.", "anderson": "For all the prophets and the law prophesied till John;", "haweis": "For all the prophets and the law until John, foretold this.", "noyes": "For all the Prophets and the Law, until John, prophesied.", "webster": "For all the prophets and the law prophesied until John.", "vulgate": "omnes enim prophetae et lex usque ad Iohannem prophetaverunt;"}}, {"v": 14, "ref": "11:14", "o": "καὶ εἰ θέλετε δέξασθαι, αὐτός ἐστιν Ἠλίας ὁ μέλλων ἔρχεσθαι.", "en": {"kjv": "And if ye will receive it, this is Elias, which was for to come.", "web": "If you are willing to receive it, this is Elijah, who is to come.", "bsb": "And if you are willing to accept it, he is the Elijah who was to come.", "asv": "And if ye are willing to receive it, this is Elijah, that is to come.", "ylt": "and if ye are willing to receive it , he is Elijah who was about to come;", "tyndale": "Also yf ye wyll receave it this is Helyas which shuld come.", "dra": "And if you will receive it, he is Elias that is to come.", "bbe": "And if you are able to see it, this is Elijah who was to come.", "geneva": "And if ye will receiue it, this is that Elias, which was to come.", "wycliffe": "he is Elie that is to come.", "rotherham": "And, if ye are willing to accept it, he, is Elijah—the one destined to come.", "weymouth": "And (if you are willing to receive it) he is the Elijah who was to come.", "darby": "And if ye will receive it, this is Elias, who is to come.", "twenty": "and — if you are ready to accept it — John is himself the Elijah who was destined to come.", "acv": "And if ye are willing to receive it, he is Elijah who is going to come.", "anderson": "and if you are willing to receive it, he is Elijah that was to come.", "haweis": "And if ye will receive it, this is Elias who was to come.", "noyes": "And if ye are willing to receive it, he is the Elijah who was to come.", "webster": "And if ye will receive [it], this is Elijah who was to come.", "vulgate": "et si vultis recipere ipse est Helias qui venturus est;"}}, {"v": 15, "ref": "11:15", "o": "ὁ ἔχων ⸀ὦτα ἀκουέτω.", "en": {"kjv": "He that hath ears to hear, let him hear.", "web": "He who has ears to hear, let him hear.", "bsb": "He who has ears, let him hear.", "asv": "He that hath ears to hear, let him hear.", "ylt": "he who is having ears to hear--let him hear.", "tyndale": "He yt hathe eares to heare let him heare.", "dra": "He that hath ears to hear, let him hear.", "bbe": "He who has ears, let him give ear.", "geneva": "He that hath eares to heare, let him heare.", "wycliffe": "He that hath eris of heryng, here he.", "rotherham": "He that hath ears, let him hear!", "weymouth": "Listen, every one who has ears!", "darby": "He that has ears to hear, let him hear.", "twenty": "Let him who has ears hear.", "acv": "He who has ears to hear, let him hear.", "anderson": "He that has ears to hear, let him hear.", "haweis": "He that hath ears to hear, let him hear.", "noyes": "He that hath ears, let him hear.", "webster": "He that hath ears to hear, let him hear.", "vulgate": "qui habet aures audiendi audiat;"}}, {"v": 16, "ref": "11:16", "o": "Τίνι δὲ ὁμοιώσω τὴν γενεὰν ταύτην; ὁμοία ἐστὶν παιδίοις ⸂καθημένοις ἐν ταῖς ἀγοραῖς ἃ προσφωνοῦντα τοῖς ἑτέροις⸃", "en": {"kjv": "But whereunto shall I liken this generation? It is like unto children sitting in the markets, and calling unto their fellows,", "web": "“But to what shall I compare this generation? It is like children sitting in the marketplaces, who call to their companions", "bsb": "To what can I compare this generation? They are like children sitting in the marketplaces and calling out to others:", "asv": "But whereunto shall I liken this generation? It is like unto children sitting in the marketplaces, who call unto their fellows", "ylt": "`And to what shall I liken this generation? it is like little children in market-places, sitting and calling to their comrades,", "tyndale": "But wher vnto shall I lyken this generacion? It ys lyke vnto chyldre which syt in the market and call vnto their felowes", "dra": "But whereunto shall I esteem this generation to be like? It is like to children sitting in the market place.", "bbe": "But what comparison may I make of this generation? It is like children seated in the market-places, crying out to one another,", "geneva": "But whereunto shall I liken this generation? It is like vnto litle children which sit in the markets, and call vnto their fellowes,", "wycliffe": "But to whom schal Y gesse this generacioun lijk? It is lijk to children sittynge in chepyng, that crien to her peeris,", "rotherham": "But, unto what, shall I liken this generation? It is, like, unto children, sitting the market-places, who, calling unto the others,", "weymouth": "\"But to what shall I compare the present generation? It is like children sitting in the open places, who call to their playmates.", "darby": "But to whom shall I liken this generation? It is like children sitting in the markets, which, calling to their companions,", "twenty": "But to what shall I compare the present generation? It is like little children sitting in the market-places and calling out to their playmates —", "acv": "But to what shall I compare this generation? It is like children sitting in the marketplaces, calling to their companions,", "anderson": "But to what shall I liken this generation? It is like children sitting in the markets, and calling to their companions,", "haweis": "But to whom shall I resemble this generation? it is like little boys sitting in the places of concourse, and calling to their companions,", "noyes": "But to what shall I liken this generation? It is like children sitting in the markets, who call to their fellows,", "webster": "But to what shall I liken this generation? It is like to children sitting in the markets, and calling to their fellows,", "vulgate": "cui autem similem aestimabo generationem istam similis est pueris sedentibus in foro qui clamantes coaequalibus;"}}, {"v": 17, "ref": "11:17", "o": "⸀λέγουσιν· Ηὐλήσαμεν ὑμῖν καὶ οὐκ ὠρχήσασθε· ⸀ἐθρηνήσαμεν καὶ οὐκ ἐκόψασθε·", "en": {"kjv": "And saying, We have piped unto you, and ye have not danced; we have mourned unto you, and ye have not lamented.", "web": "and say, ‘We played the flute for you, and you didn’t dance. We mourned for you, and you didn’t lament.’", "bsb": "‘We played the flute for you, and you did not dance; we sang a dirge, and you did not mourn.’", "asv": "and say, We piped unto you, and ye did not dance; we wailed, and ye did not mourn.", "ylt": "and saying, We piped unto you, and ye did not dance, we lamented to you, and ye did not smite the breast.", "tyndale": "and saye: we have pyped vnto you and ye have not daunsed? We have morned vnto you and ye have not sorowed.", "dra": "Who crying to their companions say: We have piped to you, and you have not danced: we have lamented, and you have not mourned.", "bbe": "We made music for you and you did not take part in the dance; we gave cries of sorrow and you made no signs of grief.", "geneva": "And say, We haue piped vnto you, and ye haue not daunced, we haue mourned vnto you, and ye haue not lamented.", "wycliffe": "and seien, We han songun to you, and ye han not daunsid; we han morned to you, and ye han not weilid.", "rotherham": "say, We played the flute to you, and ye danced not,—we sang a lament, and ye beat not the breast.", "weymouth": "\"`We have played the flute to you,' they say, `and you have not danced: we have sung dirges, and you have not beaten your breasts.'", "darby": "say, We have piped to you, and ye have not danced: we have mourned to you, and ye have not wailed.", "twenty": "‘We have played the flute for you, but you have not danced; We have wailed, but you have not mourned.’", "acv": "and saying, We piped to you, and ye did not dance, we mourned to you, and ye did not beat the breast.", "anderson": "and saying: We have played on the pipe for you, and you have not danced; we have wailed for you, and you have not lamented.", "haweis": "and saying, We have piped to you, and ye have not danced; we have sung mournful ditties to you, and ye have not beat your breasts.", "noyes": "and say, We piped to you, and ye did not dance; we sung a dirge, and ye did not lament.", "webster": "And saying, We have piped to you, and ye have not danced; We have mourned to you, and ye have not lamented.", "vulgate": "dicunt cecinimus vobis et non saltastis lamentavimus et non planxistis;"}}, {"v": 18, "ref": "11:18", "o": "ἦλθεν γὰρ Ἰωάννης μήτε ἐσθίων μήτε πίνων, καὶ λέγουσιν· Δαιμόνιον ἔχει·", "en": {"kjv": "For John came neither eating nor drinking, and they say, He hath a devil.", "web": "For John came neither eating nor drinking, and they say, ‘He has a demon.’", "bsb": "For John came neither eating nor drinking, and they say, ‘He has a demon!’", "asv": "For John came neither eating nor drinking, and they say, He hath a demon.", "ylt": "`For John came neither eating nor drinking, and they say, He hath a demon;", "tyndale": "For Ihon came nether eatinge nor drinkinge and they saye he hath the devyll.", "dra": "For John came neither eating nor drinking; and they say: He hath a devil.", "bbe": "For John came, taking no food or drink, and they say, He has an evil spirit.", "geneva": "For Iohn came neither eating nor drinking, and they say, He hath a deuill.", "wycliffe": "For Joon cam nether etynge ne drynkynge, and thei seien, He hath a deuel.", "rotherham": "For, John, came, neither eating nor drinking, and they say—A demon, he hath!", "weymouth": "\"For John came neither eating nor drinking, and they say, `He has a demon.'", "darby": "For John has come neither eating nor drinking, and they say, He has a demon.", "twenty": "For, when John came, neither eating nor drinking, men said ‘He has a demon in him’;", "acv": "For John came neither eating nor drinking, and they say, He has a demon.", "anderson": "For John came, neither eating nor drinking, and they say: He has a demon.", "haweis": "For John came neither eating nor drinking, and they say, He hath a devil:", "noyes": "For John came neither eating nor drinking; and they say, He hath a demon.", "webster": "For John came neither eating nor drinking, and they say, He hath a demon.", "vulgate": "venit enim Iohannes neque manducans neque bibens et dicunt daemonium habet;"}}, {"v": 19, "ref": "11:19", "o": "ἦλθεν ὁ υἱὸς τοῦ ἀνθρώπου ἐσθίων καὶ πίνων, καὶ λέγουσιν· Ἰδοὺ ἄνθρωπος φάγος καὶ οἰνοπότης, τελωνῶν φίλος καὶ ἁμαρτωλῶν. καὶ ἐδικαιώθη ἡ σοφία ἀπὸ τῶν ⸀ἔργων αὐτῆς.", "en": {"kjv": "The Son of man came eating and drinking, and they say, Behold a man gluttonous, and a winebibber, a friend of publicans and sinners. But wisdom is justified of her children.", "web": "The Son of Man came eating and drinking, and they say, ‘Behold, a gluttonous man and a drunkard, a friend of tax collectors and sinners!’ But wisdom is justified by her children.”", "bsb": "The Son of Man came eating and drinking, and they say, ‘Look at this glutton and drunkard, a friend of tax collectors and sinners!’ But wisdom is vindicated by her actions.”", "asv": "The Son of man came eating and drinking, and they say, Behold, a gluttonous man and a winebibber, a friend of publicans and sinners! And wisdom is justified by her works.", "ylt": "the Son of Man came eating and drinking, and they say, Lo, a man, a glutton, and a wine-drinker, a friend of tax-gatherers and sinners, and wisdom was justified of her children.'", "tyndale": "The sonne of man came eatinge and drinkinge and they saye beholde a glutton and drynker of wyne and a frend vnto publicas and synners. Never the later wysdome ys iustified of hir children.", "dra": "The Son of man came eating and drinking, and they say: Behold a man that is a glutton and a wine drinker, a friend of publicans and sinners. And wisdom is justified by her children.", "bbe": "The Son of man has come feasting, and they say, See, a lover of food and wine, a friend of tax-farmers and sinners! And wisdom is judged to be right by her works.", "geneva": "The sonne of man came eating and drinking, and they say, Beholde a glutton and a drinker of wine, a friend vnto Publicanes and sinners: but wisedome is iustified of her children.", "wycliffe": "The sone of man cam etynge and drynkynge, and thei seien, Lo! a man a glotoun, and a drinkere of wijne, and a freend of pupplicans and of synful men. And wisdom is iustified of her sones.", "rotherham": "The Son of Man, came, eating and drinking, and they say, Lo! a gluttonous man and a wine-drinker! a friend of, tax-collectors, and sinners! And yet wisdom hath been justified by her works.", "weymouth": "The Son of Man came eating and drinking, and they exclaim, `See this man! --given to gluttony and tippling, and a friend of tax-gatherers and notorious sinners!' And yet Wisdom is vindicated by her actions.\"", "darby": "The Son of man has come eating and drinking, and they say, Behold, a man [that is] eating and wine-drinking, a friend of tax-gatherers, and of sinners: — and wisdom has been justified by her children.", "twenty": "and now that the Son of Man has come, eating and drinking, they are saying ‘Here is a glutton and a wine-drinker, a friend of tax-gatherers and outcasts!’ And yet Wisdom is vindicated by her actions.”", "acv": "The Son of man came eating and drinking, and they say, Behold the man, a glutton and a drunkard, a friend of tax collectors and sinners! And wisdom is justified from her children.", "anderson": "The Son of man has come eating and drinking, and they say: Behold, a glutton, and a drinker of wine, a friend of publicans and sinners. Yet wisdom is vindicated by her children.", "haweis": "the Son of man is come eating and drinking, and they say, Behold, what a man! a glutton and a wine-bibber, a friend of publicans and sinners: though wisdom hath been justified by her children.", "noyes": "The Son of man came eating and drinking; and they say, Behold, a glutton and a wine-bibber, a friend of publicans and sinners! But wisdom is justified by her works.", "webster": "The Son of man came eating and drinking, and they say, Behold, a man gluttonous, and a wine-bibber, a friend of publicans and sinners. But wisdom is justified by her children.", "vulgate": "venit Filius hominis manducans et bibens et dicunt ecce homo vorax et potator vini publicanorum et peccatorum amicus et iustificata est sapientia a filiis suis;"}}, {"v": 20, "ref": "11:20", "o": "Τότε ⸀ἤρξατο ὀνειδίζειν τὰς πόλεις ἐν αἷς ἐγένοντο αἱ πλεῖσται δυνάμεις αὐτοῦ, ὅτι οὐ μετενόησαν·", "en": {"kjv": "Then began he to upbraid the cities wherein most of his mighty works were done, because they repented not:", "web": "Then he began to denounce the cities in which most of his mighty works had been done, because they didn’t repent.", "bsb": "Then Jesus began to denounce the cities in which most of His miracles had been performed, because they did not repent.", "asv": "Then began he to upbraid the cities wherein most of his mighty works were done, because they repented not.", "ylt": "Then began he to reproach the cities in which were done most of his mighty works, because they did not reform.", "tyndale": "Then bega he to vpbrayd the cities in which most of his miracles were done because they meded not.", "dra": "Then began he to upbraid the cities wherein were done the most of his miracles, for that they had not done penance.", "bbe": "Then he went on to say hard things to the towns where most of his works of power were done, because they had not been turned from their sins.", "geneva": "Then began he to vpbraide the cities, wherein most of his great workes were done, because they repented not.", "wycliffe": "Thanne Jhesus bigan to seye repreef to citees, in whiche ful manye vertues of him weren doon, for thei diden not penaunce.", "rotherham": "Then, began he to upbraid the cities, in which had been done his noblest mighty works; because they repented not:—", "weymouth": "Then began He to upbraid the towns where most of His mighty works had been done--because they had not repented.", "darby": "Then began he to reproach the cities in which most of his works of power had taken place, because they had not repented.", "twenty": "Then Jesus began to reproach the towns in which most of his miracles had been done, because they had not repented:", "acv": "Then he began to upbraid the cities in which most of his mighty works occurred, because they did not repent.", "anderson": "Then he began to reprove the cities in which most of his mighty works had been done, because they did not repent.", "haweis": "Then began he to upbraid the cities in which the chief of his miracles had been wrought, because they repented not:", "noyes": "Then he began to upbraid the cities wherein most of his miracles were done, because they did not repent.", "webster": "Then he began to upbraid the cities in which most of his mighty works had been done, because they repented not.", "vulgate": "tunc coepit exprobrare civitatibus in quibus factae sunt plurimae virtutes eius quia non egissent paenitentiam;"}}, {"v": 21, "ref": "11:21", "o": "Οὐαί σοι, Χοραζίν· οὐαί σοι, Βηθσαϊδά· ὅτι εἰ ἐν Τύρῳ καὶ Σιδῶνι ἐγένοντο αἱ δυνάμεις αἱ γενόμεναι ἐν ὑμῖν, πάλαι ἂν ἐν σάκκῳ καὶ σποδῷ μετενόησαν.", "en": {"kjv": "Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works, which were done in you, had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "web": "“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes.", "bsb": "“Woe to you, Chorazin! Woe to you, Bethsaida! For if the miracles that were performed in you had been performed in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "asv": "Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes.", "ylt": "`Woe to thee, Chorazin! woe to thee, Bethsaida! because, if in Tyre and Sidon had been done the mighty works that were done in you, long ago in sackcloth and ashes they had reformed;", "tyndale": "Wo be to ye Chorasin. Wo be to ye Betzaida: for if the miracles which were shewd in you had bene done in Tyre and Sidon they had repented longe agone in sackcloth and asshes.", "dra": "Woe thee, Corozain, woe to thee, Bethsaida: for if in Tyre and Sidon had been wrought the miracles that have been wrought in you, they had long ago done penance in sackcloth and ashes.", "bbe": "Unhappy are you, Chorazin! Unhappy are you, Beth-saida! For if the works of power which were done in you had been done in Tyre and Sidon, they would have been turned from their sins in days gone by, clothing themselves in haircloth and putting dust on their heads.", "geneva": "Woe be to thee, Chorazin: Woe be to thee, Bethsaida: for if ye great workes, which were done in you, had bene done in Tyrus and Sidon, they had repented long agone in sackecloth and ashes.", "wycliffe": "Wo to thee! Corosaym, woo to thee! Bethsaida; for if the vertues that ben doon in you hadden be doon in Tyre and Sidon, sumtyme thei hadden don penaunce in heyre and aische.", "rotherham": "Alas for thee, Chorazin! Alas for thee, Bethsaida! Because, if, in Tyre and Zidon, had been done the works of power, which were done in you, of old, in sackcloth and ashes, had they repented.", "weymouth": "\"Alas for thee, Chorazin!\" He cried. \"Alas for thee, Bethsaida! For had the mighty works been done in Tyre and Sidon which have been done in both of you, they would long ere now have repented, covered with sackcloth and ashes.", "darby": "Woe to thee, Chorazin! woe to thee Bethsaida! for if the works of power which have taken place in you, had taken place in Tyre and Sidon, they had long ago repented in sackcloth and ashes.", "twenty": "“Alas for you, Chorazin! Alas for you, Bethsaida! For, if the miracles which were done in you had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "acv": "Woe to thee, Chorazin! Woe to thee, Bethsaida! Because if the mighty works that occurred in you occurred in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "anderson": "Alas for thee, Chorazin! alas for thee, Bethsaida! for if the mighty works which have been clone in you had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "haweis": "Wo unto thee, Chorazin! wo unto thee, Bethsaida! for if the miracles which had been wrought in you had been done in Tyre and Sidon, long since would they have repented in sack-cloth and ashes.", "noyes": "Woe to thee, Chorazin! woe to thee, Bethsaida! for if the miracles that were done in you had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "webster": "Woe to thee, Chorazin; woe to thee, Bethsaida: for if the mighty works which have been done in you had been done in Tyre and Sidon, they would have repented long ago in sackcloth and ashes.", "vulgate": "vae tibi Corazain vae tibi Bethsaida quia si in Tyro et Sidone factae essent virtutes quae factae sunt in vobis olim in cilicio et cinere paenitentiam egissent;"}}, {"v": 22, "ref": "11:22", "o": "πλὴν λέγω ὑμῖν, Τύρῳ καὶ Σιδῶνι ἀνεκτότερον ἔσται ἐν ἡμέρᾳ κρίσεως ἢ ὑμῖν.", "en": {"kjv": "But I say unto you, It shall be more tolerable for Tyre and Sidon at the day of judgment, than for you.", "web": "But I tell you, it will be more tolerable for Tyre and Sidon on the day of judgment than for you.", "bsb": "But I tell you, it will be more bearable for Tyre and Sidon on the day of judgment than for you.", "asv": "But I say unto you, it shall be more tolerable for Tyre and Sidon in the day of judgment, than for you.", "ylt": "but I say to you, to Tyre and Sidon it shall be more tolerable in a day of judgment than for you.", "tyndale": "Neverthelesse I say to you: it shall be esier for Tyre and Sidon at the day of iudgemet then for you.", "dra": "But I say unto you, it shall be more tolerable for Tyre and Sidon in the day of judgment, than for you.", "bbe": "But I say to you, It will be better for Tyre and Sidon in the day of judging, than for you.", "geneva": "But I say to you, It shalbe easier for Tyrus and Sidon at the day of iudgement, then for you.", "wycliffe": "Netheles Y seie to you, it schal be lesse peyne to Tire and Sidon in the dai of doom, than to you.", "rotherham": "Moreover, I say unto you, For Tyre and Zidon, more tolerable, will it be, in the day of judgment, than for you.", "weymouth": "Only I tell you that it will be more endurable for Tyre and Sidon on the day of Judgement than for you.", "darby": "But I say to you, that it shall be more tolerable for Tyre and Sidon in judgment-day than for you.", "twenty": "Yet, I tell you, the doom of Tyre and Sidon will be more bearable in the ‘Day of Judgment’ than yours.", "acv": "Nevertheless I say to you, it will be more tolerable for Tyre and Sidon in the day of judgment than for you.", "anderson": "But I say to you, It will be more tolerable for Tyre and Sidon, in the day of judgment, than for you.", "haweis": "Wherefore I say unto you, It shall be more tolerable for Tyre and Sidon in the day of judgment than for you.", "noyes": "But I say to you, It will be more tolerable for Tyre and Sidon at the day of judgment, than for you.", "webster": "But I say to you, It shall be more tolerable for Tyre and Sidon at the day of judgment, than for you.", "vulgate": "verumtamen dico vobis Tyro et Sidoni remissius erit in die iudicii quam vobis;"}}, {"v": 23, "ref": "11:23", "o": "καὶ σύ, Καφαρναούμ, ⸂μὴ ἕως οὐρανοῦ ὑψωθήσῃ⸃; ἕως ᾅδου ⸀καταβήσῃ· ὅτι εἰ ἐν Σοδόμοις ⸀ἐγενήθησαν αἱ δυνάμεις αἱ γενόμεναι ἐν σοί, ⸀ἔμεινεν ἂν μέχρι τῆς σήμερον.", "en": {"kjv": "And thou, Capernaum, which art exalted unto heaven, shalt be brought down to hell: for if the mighty works, which have been done in thee, had been done in Sodom, it would have remained until this day.", "web": "You, Capernaum, who are exalted to heaven, you will go down to Hades. For if the mighty works had been done in Sodom which were done in you, it would have remained until this day.", "bsb": "And you, Capernaum, will you be lifted up to heaven? No, you will be brought down to Hades! For if the miracles that were performed in you had been performed in Sodom, it would have remained to this day.", "asv": "And thou, Capernaum, shalt thou be exalted unto heaven? thou shalt go down unto Hades: for if the mighty works had been done in Sodom which were done in thee, it would have remained until this day.", "ylt": "`And thou, Capernaum, which unto the heaven wast exalted, unto hades shalt be brought down, because if in Sodom had been done the mighty works that were done in thee, it had remained unto this day;", "tyndale": "And thou Capernau which art lift vp vnto heve shalt be brought doune to hell. For if the miracles which have bene done in the had bene shewed in zodom: they had remayned to this daye.", "dra": "And thou Capharnaum, shalt thou be exalted up to heaven? thou shalt go down even unto hell. For if in Sodom had been wrought the miracles that have been wrought in thee, perhaps it had remained unto this day.", "bbe": "And you, Capernaum, were you not to be lifted up to heaven? you will go down into hell: for if the works of power which were done in you had been done in Sodom, it would have been here to this day.", "geneva": "And thou, Capernaum, which art lifted vp vnto heauen, shalt be brought downe to hell: for if the great workes, which haue bin done in thee, had bene done among them of Sodom, they had remained to this day.", "wycliffe": "And thou, Cafarnaum, whethir thou schalt be arerid vp in to heuene? Thou shalt go doun in to helle. For if the vertues that ben don in thee, hadden be don in Sodom, perauenture thei schulden haue dwellid `in to this dai.", "rotherham": "And, thou, Capernaum! Unto heaven, shalt thou be uplifted? Unto hades, thou shall be brought down; because, if, in Sodom, had been done the works of power, which were done in thee, it would, in that case, have remained until this day.", "weymouth": "And thou, Capernaum, shalt thou be exalted even to Heaven? Even to Hades shalt thou descend. For had the mighty works been done in Sodom which have been done in thee, it would have remained until now.", "darby": "And thou, Capernaum, who hast been raised up to heaven, shalt be brought down even to hades. For if the works of power which have taken place in thee, had taken place in Sodom, it had remained until this day.", "twenty": "And you, Capernaum! Will you ‘exalt yourself to Heaven’? ‘You shall go down to the Place of Death.’ For, if the miracles which have been done in you had been done in Sodom, it would have been standing to this day.", "acv": "And thou, Capernaum, which was exalted as far as the sky. Thou will be brought down as far as Hades, because if the mighty works had occurred in Sodom that occurred in thee, it would have remained until this day.", "anderson": "And thou, Capernaum, that hast been exalted to heaven, shalt be brought down to hades. For if the mighty works which have been done in thee had been done in Sodom, it would have remained till this day.", "haweis": "And thou, Capernaum, who hast been exalted unto heaven, shalt be cast down to hell: for if the miracles which have been wrought in thee had been done in Sodom, it had remained unto this day.", "noyes": "And thou, Capernaum! shalt thou be exalted to heaven? Thou shalt be brought down to the underworld; for if the miracles which were done in thee had been done in Sodom, it would have remained until this day.", "webster": "And thou, Capernaum, which art exalted to heaven, shalt be brought down to hell: for if the mighty works which have been done in thee, had been done in Sodom, it would have remained until this day.", "vulgate": "et tu Capharnaum numquid usque in caelum exaltaberis usque in infernum descendes quia si in Sodomis factae fuissent virtutes quae factae sunt in te forte mansissent usque in hunc diem;"}}, {"v": 24, "ref": "11:24", "o": "πλὴν λέγω ὑμῖν ὅτι γῇ Σοδόμων ἀνεκτότερον ἔσται ἐν ἡμέρᾳ κρίσεως ἢ σοί.", "en": {"kjv": "But I say unto you, That it shall be more tolerable for the land of Sodom in the day of judgment, than for thee.", "web": "But I tell you that it will be more tolerable for the land of Sodom, on the day of judgment, than for you.”", "bsb": "But I tell you that it will be more bearable for Sodom on the day of judgment than for you.”", "asv": "But I say unto you that it shall be more tolerable for the land of Sodom in the day of judgment, than for thee.", "ylt": "but I say to you, to the land of Sodom it shall be more tolerable in a day of judgment than to thee.'", "tyndale": "Neverthelesse I saye vnto you: it shalbe easiar for ye londe of zodo in the daye of iudgemet the for ye.", "dra": "But I say unto you, that it shall be more tolerable for the land of Sodom in the day of judgment than for thee.", "bbe": "But I say to you that it will be better for the land of Sodom in the day of judging, than for you.", "geneva": "But I say vnto you, that it shall be easier for them of the land of Sodom in the day of iudgement, then for thee.", "wycliffe": "Netheles Y seie to you, that to the lond of Sodom it schal be `lesse peyne in the dai of doom, than to thee.", "rotherham": "Moreover, I say unto you—For the land of Sodom, more tolerable, will it be in a day of judgment, than, for thee.", "weymouth": "Only I tell you all, that it will be more endurable for the land of Sodom on the day of Judgement than for thee.\"", "darby": "But I say to you, that it shall be more tolerable for [the] land of Sodom in judgment-day than for thee.", "twenty": "Yet, I tell you, the doom of Sodom will be more bearable in the ‘Day of Judgment’ than yours.”", "acv": "Nevertheless I say to you that it will be more tolerable for the land of Sodom in the day of judgment, than for thee.", "anderson": "But I say to you, It shall be more tolerable for the land of Sodom, in the day of judgment, than for thee.", "haweis": "Wherefore I say unto you, That it shall be more tolerable for the land of Sodom in the day of judgment than for thee.", "noyes": "But I say to you, that it will be more tolerable for the land of Sodom in the day of judgment, than for thee.", "webster": "But I say to you, that it shall be more tolerable for the land of Sodom, in the day of judgment, than for thee.", "vulgate": "verumtamen dico vobis quia terrae Sodomorum remissius erit in die iudicii quam tibi;"}}, {"v": 25, "ref": "11:25", "o": "Ἐν ἐκείνῳ τῷ καιρῷ ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν· Ἐξομολογοῦμαί σοι, πάτερ κύριε τοῦ οὐρανοῦ καὶ τῆς γῆς, ὅτι ⸀ἔκρυψας ταῦτα ἀπὸ σοφῶν καὶ συνετῶν, καὶ ἀπεκάλυψας αὐτὰ νηπίοις·", "en": {"kjv": "At that time Jesus answered and said, I thank thee, O Father, Lord of heaven and earth, because thou hast hid these things from the wise and prudent, and hast revealed them unto babes.", "web": "At that time, Jesus answered, “I thank you, Father, Lord of heaven and earth, that you hid these things from the wise and understanding, and revealed them to infants.", "bsb": "At that time Jesus declared, “I praise You, Father, Lord of heaven and earth, because You have hidden these things from the wise and learned, and revealed them to little children.", "asv": "At that season Jesus answered and said, I thank thee, O Father, Lord of heaven and earth, that thou didst hide these things from the wise and understanding, and didst reveal them unto babes:", "ylt": "At that time Jesus answering said, `I do confess to Thee, Father, Lord of the heavens and of the earth, that thou didst hide these things from wise and understanding ones, and didst reveal them to babes.", "tyndale": "At yt tyme Iesus answered and sayd: I prayse ye o father lorde of heve and erth because thou hast hid these thinges fro the wyse and prudet and hast opened the vnto babes:", "dra": "At that time Jesus answered and said: I confess to thee, O Father, Lord of Heaven and earth, because thou hast hid these things from the wise and prudent, and hast revealed them to little ones.", "bbe": "At that time Jesus made answer and said, I give praise to you, O Father, Lord of heaven and earth, because you have kept these things secret from the wise and the men of learning, and have made them clear to little children.", "geneva": "At that time Iesus answered, and saide, I giue thee thankes, O Father, Lord of heauen and earth, because thou hast hid these things from the wise and men of vnderstanding, and hast opened them vnto babes.", "wycliffe": "In thilke tyme Jhesus answeride, and seide, Y knowleche to thee, fadir, lord of heuene and of erthe, for thou hast hid these thingis fro wijse men, and redi, and hast schewid hem to litle children;", "rotherham": "In that season, answered Jesus, and said—I openly give praise unto thee, Father, Lord of heaven and earth,—in that thou hast hid these things from the wise and discerning, and hast revealed them unto babes;", "weymouth": "About that time Jesus exclaimed, \"I heartily praise Thee, Father, Lord of Heaven and of earth, that Thou hast hidden these things from sages and men of discernment, and hast unveiled them to babes.", "darby": "At that time, Jesus answering said, I praise thee, Father, Lord of the heaven and of the earth, that thou hast hid these things from the wise and prudent, and hast revealed them to babes.", "twenty": "At that same time Jesus uttered the words: “I thank thee, Father, Lord of Heaven and earth, that, though thou hast hidden these things from the wise and learned, thou hast revealed them to the child-like!", "acv": "Jesus having responded at that time, said, I extol thee, O Father, Lord of the heaven and the earth, because thou hid these things from the wise and intelligent, and revealed them to the childlike.", "anderson": "At that time Jesus answered and said: I thank thee, Father, Lord of heaven and of earth, because thou hast hid these things from the wise and prudent, and hast revealed them to babes.", "haweis": "At that time Jesus spake and said, I thank thee, O Father, Lord of heaven and earth, that thou hast hid these things from the wise and the intelligent, and hast revealed them to babes:", "noyes": "At that time Jesus answered and said, I thank thee, O Father, Lord of heaven and earth, that, though thou didst hide these things from the wise and discerning, thou didst reveal them to babes.", "webster": "At that time Jesus answered and said, I thank thee, O Father, Lord of heaven and earth, because thou hast hid these things from the wise and prudent, and hast revealed them to babes.", "vulgate": "in illo tempore respondens Iesus dixit confiteor tibi Pater Domine caeli et terrae quia abscondisti haec a sapientibus et prudentibus et revelasti ea parvulis;"}}, {"v": 26, "ref": "11:26", "o": "ναί, ὁ πατήρ, ὅτι οὕτως ⸂εὐδοκία ἐγένετο⸃ ἔμπροσθέν σου.", "en": {"kjv": "Even so, Father: for so it seemed good in thy sight.", "web": "Yes, Father, for so it was well-pleasing in your sight.", "bsb": "Yes, Father, for this was well-pleasing in Your sight.", "asv": "yea, Father, for so it was well-pleasing in thy sight.", "ylt": "Yes, Father, because so it was good pleasure before Thee.", "tyndale": "eve so father for so it pleased ye.", "dra": "Yea, Father: for so hath it seemed good in thy sight.", "bbe": "Yes, Father, for so it was pleasing in your eyes.", "geneva": "It is so, O Father, because thy good pleasure was such.", "wycliffe": "so, fadir, for so it was plesynge tofore thee.", "rotherham": "Yea, O Father! That, so, it hath become, a delight, before thee.", "weymouth": "Yes, Father, for such has been Thy gracious will.", "darby": "Yea, Father, for thus has it been well-pleasing in thy sight.", "twenty": "Yes, Father, I thank thee that this has seemed good to thee.", "acv": "Yea, Father, because this way it was done pleasing in thy sight.", "anderson": "Even so, Father, for so it seemed good in thy sight.", "haweis": "yes, Father! since such is thy good pleasure.", "noyes": "Yea, Father, for so it seemed good in thy sight.", "webster": "Even so, Father, for so it seemed good in thy sight.", "vulgate": "ita Pater quoniam sic fuit placitum ante te;"}}, {"v": 27, "ref": "11:27", "o": "Πάντα μοι παρεδόθη ὑπὸ τοῦ πατρός μου, καὶ οὐδεὶς ἐπιγινώσκει τὸν υἱὸν εἰ μὴ ὁ πατήρ, οὐδὲ τὸν πατέρα τις ἐπιγινώσκει εἰ μὴ ὁ υἱὸς καὶ ᾧ ἐὰν βούληται ὁ υἱὸς ἀποκαλύψαι.", "en": {"kjv": "All things are delivered unto me of my Father: and no man knoweth the Son, but the Father; neither knoweth any man the Father, save the Son, and he to whomsoever the Son will reveal him.", "web": "All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son, and he to whom the Son desires to reveal him.", "bsb": "All things have been entrusted to Me by My Father. No one knows the Son except the Father, and no one knows the Father except the Son and those to whom the Son chooses to reveal Him.", "asv": "All things have been delivered unto me of my Father: and no one knoweth the Son, save the Father; neither doth any know the Father, save the Son, and he to whomsoever the Son willeth to reveal him.", "ylt": "`All things were delivered to me by my Father, and none doth know the Son, except the Father, nor doth any know the Father, except the Son, and he to whom the Son may wish to reveal Him .", "tyndale": "All thinges are geve vnto me of my father. And noma knoweth ye sonne but ye father: nether knoweth eny ma ye father save ye sonne and he to whome ye sonne will ope him.", "dra": "All things are delivered to me by my Father. And no one knoweth the Son but the Father: neither doth any one know the Father, but the Son, and he to whom it shall please the Son to reveal him.", "bbe": "All things have been given to me by my Father; and no one has knowledge of the Son, but the Father; and no one has knowledge of the Father, but the Son, and he to whom the Son will make it clear.", "geneva": "All things are giuen vnto me of my Father: and no man knoweth the Sonne, but ye Father: neither knoweth any man ye Father, but the Sonne, and he to whom ye Sonne will reueile him.", "wycliffe": "Alle thingis ben youune to me of my fadir; and no man knewe the sone, but the fadir, nethir ony man knewe the fadir, but the sone, and to whom the sone wolde schewe.", "rotherham": "All things, unto me, have been delivered up by my Father; and, no one, fully knoweth the Son, save the rather, neither doth any one fully know, the Father, save, the Son, and he to whomsoever the Son, may be minded, to reveal, him.", "weymouth": "\"All things have been handed over to me by my Father, and no one fully knows the Son except the Father, nor does any one fully know the Father except the Son and all to whom the Son chooses to reveal Him.", "darby": "All things have been delivered to me by my Father, and no one knows the Son but the Father, nor does any one know the Father, but the Son, and he to whom the Son may be pleased to reveal [him].", "twenty": "Everything has been committed to me by my Father; nor does any one fully know the Son, except the Father, or fully know the Father, except the Son and those to whom the Son may choose to reveal him.", "acv": "All things were delivered to me by my Father. And no man knows the Son, except the Father, nor does any man know the Father, except the Son, and he to whomever the Son wants to reveal him.", "anderson": "All things have been delivered to me by my Father; and no one knows the Son, but the Father; nor does any one know the Father, but the Son, and he to whom the Son will reveal him.", "haweis": "All things are delivered up to me by my Father: and no person knoweth the Son but the Father; neither knoweth any person the Father but the Son, and he to whom the Son is pleased to reveal him.", "noyes": "All things were delivered to me by my Father; and no one knoweth the Son but the Father; nor doth any one know the Father, but the Son, and he to whom it is the will of the Son to reveal him.", "webster": "All things are delivered to me by my Father; and no man knoweth the Son, but the Father; neither knoweth any man the Father, save the Son, and [he] to whomsoever the Son will reveal [him].", "vulgate": "omnia mihi tradita sunt a Patre meo et nemo novit Filium nisi Pater neque Patrem quis novit nisi Filius et cui voluerit Filius revelare;"}}, {"v": 28, "ref": "11:28", "o": "Δεῦτε πρός με πάντες οἱ κοπιῶντες καὶ πεφορτισμένοι, κἀγὼ ἀναπαύσω ὑμᾶς.", "en": {"kjv": "Come unto me, all ye that labour and are heavy laden, and I will give you rest.", "web": "“Come to me, all you who labor and are heavily burdened, and I will give you rest.", "bsb": "Come to Me, all you who are weary and burdened, and I will give you rest.", "asv": "Come unto me, all ye that labor and are heavy laden, and I will give you rest.", "ylt": "`Come unto me, all ye labouring and burdened ones, and I will give you rest,", "tyndale": "Come vnto me all ye that laboure and are laden and I wyll ease you.", "dra": "Come to me all you that labor and are burdened, and I will refresh you.", "bbe": "Come to me, all you who are troubled and weighted down with care, and I will give you rest.", "geneva": "Come vnto me, all ye that are wearie and laden, and I will ease you.", "wycliffe": "Alle ye that traueilen, and ben chargid, come to me, and Y schal fulfille you.", "rotherham": "Come unto me! all ye that toil and are burdened, and, I, will give you rest:", "weymouth": "\"Come to me, all you toiling and burdened ones, and *I* will give you rest.", "darby": "Come to me, all ye who labour and are burdened, and I will give you rest.", "twenty": "Come to me, all you who toil and are burdened, and I will give you rest!", "acv": "Come to me, all ye who labor and have been burdened, and I will give you rest.", "anderson": "Come to me, all you that are weary, and heavily burdened, and I will give you rest.", "haweis": "Come to me, all who labour hard, and sustain heavy burdens, and I will give you relief.", "noyes": "Come to me, all ye that labor and are heavy laden, and I will give you rest.", "webster": "Come to me, all [ye] that labor, and are heavy laden, and I will give you rest.", "vulgate": "venite ad me omnes qui laboratis et onerati estis et ego reficiam vos;"}}, {"v": 29, "ref": "11:29", "o": "ἄρατε τὸν ζυγόν μου ἐφ’ ὑμᾶς καὶ μάθετε ἀπ’ ἐμοῦ, ὅτι πραΰς εἰμι καὶ ταπεινὸς τῇ καρδίᾳ, καὶ εὑρήσετε ἀνάπαυσιν ταῖς ψυχαῖς ὑμῶν·", "en": {"kjv": "Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.", "web": "Take my yoke upon you, and learn from me, for I am gentle and lowly in heart; and you will find rest for your souls.", "bsb": "Take My yoke upon you and learn from Me; for I am gentle and humble in heart, and you will find rest for your souls.", "asv": "Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.", "ylt": "take up my yoke upon you, and learn from me, because I am meek and humble in heart, and ye shall find rest to your souls,", "tyndale": "Take my yoke on you and lerne of me for I am meke and lowly in herte: and ye shall fynd rest vnto youre soules.", "dra": "Take up my yoke upon you, and learn of me, because I am meek, and humble of heart: And you shall find rest to your souls.", "bbe": "Take my yoke on you and become like me, for I am gentle and without pride, and you will have rest for your souls;", "geneva": "Take my yoke on you, and learne of me that I am meeke and lowly in heart: and ye shall finde rest vnto your soules.", "wycliffe": "Take ye my yok on you, and lerne ye of me, for Y am mylde and meke in herte; and ye schulen fynde reste to youre soulis.", "rotherham": "Take my yoke upon you, and learn of me,—because, meek, am I and lowly, in heart, and ye shall find rest unto your souls;", "weymouth": "Take my yoke upon you and learn from me; for I am gentle and lowly in heart, and you will find rest for your souls.", "darby": "Take my yoke upon you, and learn from me; for I am meek and lowly in heart; and ye shall find rest to your souls;", "twenty": "Take my yoke upon you, and learn from me, for I am gentle and lowly-minded, and ‘you shall find rest for your souls’;", "acv": "Take my yoke upon you, and learn from me, because I am meek and lowly in heart, and ye will find rest for your souls.", "anderson": "Take my yoke upon you, and learn from me; for I am meek and lowly in heart; and you shall find rest for your souls.", "haweis": "Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest to your souls.", "noyes": "Take my yoke upon you, and learn from me; for I am meek and lowly in heart; and ye shall find rest for your souls.", "webster": "Take my yoke upon you, and learn from me: for I am meek and lowly in heart; and ye shall find rest to your souls.", "vulgate": "tollite iugum meum super vos et discite a me quia mitis sum et humilis corde et invenietis requiem animabus vestris;"}}, {"v": 30, "ref": "11:30", "o": "ὁ γὰρ ζυγός μου χρηστὸς καὶ τὸ φορτίον μου ἐλαφρόν ἐστιν.", "en": {"kjv": "For my yoke is easy, and my burden is light.", "web": "For my yoke is easy, and my burden is light.”", "bsb": "For My yoke is easy and My burden is light.”", "asv": "For my yoke is easy, and my burden is light.", "ylt": "for my yoke is easy, and my burden is light.'", "tyndale": "For my yoke is easy and my burden is light.", "dra": "For my yoke is sweet and my burden light.", "bbe": "For my yoke is good, and the weight I take up is not hard.", "geneva": "For my yoke is easie, and my burden light.", "wycliffe": "`For my yok is softe, and my charge liyt.", "rotherham": "For, my yoke, is easy, and, my burden, light.", "weymouth": "For it is good to bear my yoke, and my burden is light.\"", "darby": "for my yoke is easy, and my burden is light.", "twenty": "for my yoke is easy, and my burden is light.”", "acv": "For my yoke is befitting, and my burden is light.", "anderson": "For my yoke is easy, and my burden is light.", "haweis": "For my yoke is easy, and my burden is light.", "noyes": "For my yoke is easy, and my burden is light.", "webster": "For my yoke [is] easy, and my burden is light.", "vulgate": "iugum enim meum suave est et onus meum leve est;"}}]}, {"c": 12, "verses": [{"v": 1, "ref": "12:1", "o": "Ἐν ἐκείνῳ τῷ καιρῷ ἐπορεύθη ὁ Ἰησοῦς τοῖς σάββασιν διὰ τῶν σπορίμων· οἱ δὲ μαθηταὶ αὐτοῦ ἐπείνασαν καὶ ἤρξαντο τίλλειν στάχυας καὶ ἐσθίειν.", "en": {"kjv": "At that time Jesus went on the sabbath day through the corn; and his disciples were an hungred, and began to pluck the ears of corn, and to eat.", "web": "At that time, Jesus went on the Sabbath day through the grain fields. His disciples were hungry and began to pluck heads of grain and to eat.", "bsb": "At that time Jesus went through the grainfields on the Sabbath. His disciples were hungry and began to pick the heads of grain and eat them.", "asv": "At that season Jesus went on the sabbath day through the grainfields; and his disciples were hungry and began to pluck ears and to eat.", "ylt": "At that time did Jesus go on the sabbaths through the corn, and his disciples were hungry, and they began to pluck ears, and to eat,", "tyndale": "In that tyme went Iesus on the Sabot dayes thorow the corne and his disciples were anhogred and begane to plucke the eares of coorne and to eate.", "dra": "At that time Jesus went through the corn on the sabbath: and his disciples being hungry, began to pluck the ears, and to eat.", "bbe": "At that time Jesus went through the fields on the Sabbath day; and his disciples, being in need of food, were taking the heads of grain.", "geneva": "At that time Iesus went on a Sabbath day through ye corne, and his disciples were an hungred, and bega to plucke ye eares of corne and to eate.", "wycliffe": "In that tyme Jhesus wente bi cornes in the sabot day; and hise disciplis hungriden, and bigunnen to plucke the eris of corn, and to ete.", "rotherham": "In that season, went Jesus, on, the sabbath, through the cornfields,—and, his disciples, hungered, and began to pluck ears of corn, and to eat.", "weymouth": "About that time Jesus passed on the Sabbath through the wheatfields; and His disciples became hungry, and began to gather ears of wheat and eat them.", "darby": "At that time Jesus went on the sabbath through the cornfields; and his disciples were hungry, and began to pluck the ears and to eat.", "twenty": "About the same time Jesus walked through the corn-fields one Sabbath. His disciples were hungry, and began to pick some ears of wheat and eat them.", "acv": "At that time Jesus went through the grain fields on the sabbath, and his disciples were hungry and began to pluck ears, and to eat.", "anderson": "At that time Jesus was going, on the Sabbath, through the fields of grain; and his disciples were hungry, and began to pull the ears of grain, and to eat.", "haweis": "AT that time Jesus walked through corn-fields on a sabbath-day; and his disciples were hungry, and began to pluck the ears of corn, and to eat.", "noyes": "At that time Jesus went on the sabbath through the grain-fields; and his disciples were hungry, and began to pluck the ears of grain, and to eat.", "webster": "At that time Jesus went on the sabbath through the corn, and his disciples were hungry, and began to pluck the ears of corn, and to eat.", "vulgate": "in illo tempore abiit Iesus sabbato per sata discipuli autem eius esurientes coeperunt vellere spicas et manducare;"}}, {"v": 2, "ref": "12:2", "o": "οἱ δὲ Φαρισαῖοι ἰδόντες εἶπαν αὐτῷ· Ἰδοὺ οἱ μαθηταί σου ποιοῦσιν ὃ οὐκ ἔξεστιν ποιεῖν ἐν σαββάτῳ.", "en": {"kjv": "But when the Pharisees saw it, they said unto him, Behold, thy disciples do that which is not lawful to do upon the sabbath day.", "web": "But the Pharisees, when they saw it, said to him, “Behold, your disciples do what is not lawful to do on the Sabbath.”", "bsb": "When the Pharisees saw this, they said to Him, “Look, Your disciples are doing what is unlawful on the Sabbath.”", "asv": "But the Pharisees, when they saw it, said unto him, Behold, thy disciples do that which it is not lawful to do upon the sabbath.", "ylt": "and the Pharisees having seen, said to him, `Lo, thy disciples do that which it is not lawful to do on a sabbath.'", "tyndale": "When ye pharises sawe that they sayde vnto him: Beholde thy disciples do that which is not lawfull to do apon ye saboth daye.", "dra": "And the Pharisees seeing them, said to him: Behold thy disciples do that which is not lawful to do on the sabbath days.", "bbe": "But the Pharisees, when they saw it, said to him, See, your disciples do that which it is not right to do on the Sabbath.", "geneva": "And when the Pharises sawe it, they saide vnto him, Beholde, thy disciples doe that which is not lawfull to doe vpon the Sabbath.", "wycliffe": "And Fariseis, seynge, seiden to hym, Lo! thi disciplis don that thing that is not leueful to hem to do in sabatis.", "rotherham": "But, the Pharisees, observing it, said unto him, Lo! thy disciples, are doing what is not allowed to do, on sabbath.", "weymouth": "But the Pharisees saw it and said to Him, \"Look! your disciples are doing what the Law forbids them to do on the Sabbath.\"", "darby": "But the Pharisees, seeing [it], said to him, Behold, thy disciples are doing what is not lawful to do on sabbath.", "twenty": "But, when the Pharisees saw this, they said: “Look! your disciples are doing what it is not allowable to do on a Sabbath!”", "acv": "But the Pharisees, when they saw it, said to him, Behold, thy disciples do what is not permitted to do upon the sabbath.", "anderson": "But when the Pharisees saw it, they said to him: Behold, your disciples are doing what it is not lawful to do on the Sabbath.", "haweis": "But when the Pharisees saw it, they said to him, Behold, thy disciples do a thing that it is not lawful to do on the sabbath.", "noyes": "But the Pharisees, seeing it, said to him, Lo! thy disciples are doing that which it is not lawful to do on the sabbath.", "webster": "But when the Pharisees saw it, they said to him, Behold, thy disciples do that which it is not lawful to do on the sabbath.", "vulgate": "Pharisaei autem videntes dixerunt ei ecce discipuli tui faciunt quod non licet eis facere sabbatis;"}}, {"v": 3, "ref": "12:3", "o": "ὁ δὲ εἶπεν αὐτοῖς· Οὐκ ἀνέγνωτε τί ἐποίησεν Δαυὶδ ὅτε ⸀ἐπείνασεν καὶ οἱ μετ’ αὐτοῦ;", "en": {"kjv": "But he said unto them, Have ye not read what David did, when he was an hungred, and they that were with him;", "web": "But he said to them, “Haven’t you read what David did, when he was hungry, and those who were with him;", "bsb": "Jesus replied, “Have you not read what David did when he and his companions were hungry?", "asv": "But he said unto them, Have ye not read what David did, when he was hungry, and they that were with him;", "ylt": "And he said to them, `Did ye not read what David did, when he was hungry, himself and those with him--", "tyndale": "He sayde vnto the: Haue ye not reed what David did whe he was anhougered and they also which were with him?", "dra": "But he said to them: Have you not read what David did when he was hungry, and they that were with him:", "bbe": "But he said to them, Have you no knowledge of what David did when he had need of food, and those who were with him?", "geneva": "But he said vnto them, Haue ye not read what Dauid did when he was an hungred, and they that were with him?", "wycliffe": "And he seide to hem, Whether ye han not red, what Dauid dide, whanne he hungride, and thei that weren with hym?", "rotherham": "And he said unto them, have ye never read what, David, did, when he hungered, and they who were with him? how", "weymouth": "\"Have you never read,\" He replied, \"what David did when he and his men were hungry?", "darby": "But he said to them, Have ye not read what David did when he was hungry, and they that were with him?", "twenty": "“Have not you read,” replied Jesus, “what David did, when he and his companions were hungry —", "acv": "But he said to them, Have ye not read what David did when he was hungry, he and those with him,", "anderson": "But he said to them: Have you not read what David did, when he and those who were with him were hungry?", "haweis": "And he said unto them, Have ye not read what David did, when he was hungry, and they who were with him?", "noyes": "But he said to them, Have ye not read what David did, when he and those who were with him were hungry?", "webster": "But he said to them, Have ye not read what David did when he was hungry, and they that were with him;", "vulgate": "at ille dixit eis non legistis quid fecerit David quando esuriit et qui cum eo erant;"}}, {"v": 4, "ref": "12:4", "o": "πῶς εἰσῆλθεν εἰς τὸν οἶκον τοῦ θεοῦ καὶ τοὺς ἄρτους τῆς προθέσεως ⸂ἔφαγον, ὃ⸃ οὐκ ἐξὸν ἦν αὐτῷ φαγεῖν οὐδὲ τοῖς μετ’ αὐτοῦ, εἰ μὴ τοῖς ἱερεῦσιν μόνοις;", "en": {"kjv": "How he entered into the house of God, and did eat the shewbread, which was not lawful for him to eat, neither for them which were with him, but only for the priests?", "web": "how he entered into God’s house, and ate the show bread, which was not lawful for him to eat, neither for those who were with him, but only for the priests?", "bsb": "He entered the house of God, and he and his companions ate the consecrated bread, which was not lawful for them to eat, but only for the priests.", "asv": "how he entered into the house of God, and ate the showbread, which it was not lawful for him to eat, neither for them that were with him, but only for the priests?", "ylt": "how he went into the house of God, and the loaves of the presentation did eat, which it is not lawful to him to eat, nor to those with him, except to the priests alone?", "tyndale": "How he entred into the housse of God and ate ye halowed loves which were not lawfull for him to eate nether for the which were wt him but only for ye prestes.", "dra": "How he entered into the house of God, and did eat the loaves of proposition, which it was not lawful for him to eat, nor for them that were with him, but for the priests only?", "bbe": "How he went into the house of God and took for food the holy bread which it was not right for him or for those who were with him to take, but only for the priests?", "geneva": "Howe he entred into ye house of God, and did eate the shewe bread, which was not lawfull for him to eate, neither for them which were with him, but onely for the Priestes?", "wycliffe": "hou he entride in to the hous of God, and eet looues of proposicioun, whiche looues it was not leueful to hym to ete, nether to hem that weren with hym, but to prestis aloone?", "rotherham": "he entered into the house of God and, the presence-bread, did eat, which it was not, allowable, for him to eat, nor for them who were with him,—save for the priests, alone?", "weymouth": "how he entered the House of God and ate the Presented Loaves, which it was not lawful for him or his men to eat, nor for any except the priests?", "darby": "How he entered into the house ofGod, and ate the shewbread, which it was not lawful for him to eat, nor for those with him, but for the priests only?", "twenty": "how he went into the House of God, and how they ate the consecrated bread, through it was not allowable for him or his companions to eat it, but only for the priests?", "acv": "how he entered into the house of God, and ate the loaves of the presentation, which was not permitted for him to eat, nor for those with him, except only for the priests?", "anderson": "how he entered the house of God, and ate the loaves of the presence, which it was not lawful for him to eat, nor for those who were with him, but for the priests only?", "haweis": "how they went into the house of God, and did eat the loaves of shew-bread, of which it was not lawful for him or those who were with him to eat, but for the priests alone?", "noyes": "how he went into the house of God, and they ate the show-bread, which it was not lawful for him to eat, nor for those who were with him, but for the priests alone?", "webster": "How he entered into the house of God, and ate the show-bread, which it was not lawful for him to eat, neither for them who were with him, but only for the priests?", "vulgate": "quomodo intravit in domum Dei et panes propositionis comedit quos non licebat ei edere neque his qui cum eo erant nisi solis sacerdotibus;"}}, {"v": 5, "ref": "12:5", "o": "ἢ οὐκ ἀνέγνωτε ἐν τῷ νόμῳ ὅτι τοῖς σάββασιν οἱ ἱερεῖς ἐν τῷ ἱερῷ τὸ σάββατον βεβηλοῦσιν καὶ ἀναίτιοί εἰσιν;", "en": {"kjv": "Or have ye not read in the law, how that on the sabbath days the priests in the temple profane the sabbath, and are blameless?", "web": "Or have you not read in the law, that on the Sabbath day, the priests in the temple profane the Sabbath, and are guiltless?", "bsb": "Or haven’t you read in the Law that on the Sabbath the priests in the temple break the Sabbath and yet are innocent?", "asv": "Or have ye not read in the law, that on the sabbath day the priests in the temple profane the sabbath, and are guiltless?", "ylt": "`Or did ye not read in the Law, that on the sabbaths the priests in the temple do profane the sabbath, and are blameless?", "tyndale": "Or have ye not reed in ye lawe how that ye prestes in ye temple breake the saboth daye and yet are blamlesse?", "dra": "Or have ye not read in the law, that on the sabbath days the priests in the temple break the sabbath, and are without blame?", "bbe": "Or is it not said in the law, how the Sabbath is broken by the priests in the Temple and they do no wrong?", "geneva": "Or haue ye not read in the Lawe, how that on the Sabbath dayes the Priestes in the Temple breake the Sabbath, and are blameles?", "wycliffe": "Or whether ye han not red in the lawe, that in sabotis prestis in the temple defoulen the sabotis, and thei ben with oute blame?", "rotherham": "Or have ye not read, in the law, that, on the sabbaths, the priests, in the temple, the sabbath, profane, and are, blameless?", "weymouth": "And have you not read in the Law how on the Sabbath the priests in the Temple break the Sabbath without incurring guilt?", "darby": "Or have ye not read in the law that on the sabbaths the priests in the temple profane the sabbath, and are blameless?", "twenty": "And have not you read in the law that, on the Sabbath, the priest in the Temple break the Sabbath and yet are not guilty?", "acv": "Or have ye not read in the law, that on the sabbath the priests in the temple profane the sabbath, and are guiltless?", "anderson": "Or, have you not read in the law that on the Sabbath-days the priests in the temple profane the Sabbath, and are blameless?", "haweis": "Or have ye not read in the law, that on the sabbaths the priests in the temple profane the sabbath, and are not culpable?", "noyes": "Or have ye not read in the Law, that on the sabbaths the priests in the temple profane the sabbath, and are blameless?", "webster": "Or have ye not read in the law, that on the sabbath the priests in the temple profane the sabbath, and are blameless?", "vulgate": "aut non legistis in lege quia sabbatis sacerdotes in templo sabbatum violant et sine crimine sunt;"}}, {"v": 6, "ref": "12:6", "o": "λέγω δὲ ὑμῖν ὅτι τοῦ ἱεροῦ μεῖζόν ἐστιν ὧδε.", "en": {"kjv": "But I say unto you, That in this place is one greater than the temple.", "web": "But I tell you that one greater than the temple is here.", "bsb": "But I tell you that something greater than the temple is here.", "asv": "But I say unto you, that one greater than the temple is here.", "ylt": "and I say to you, that a greater than the temple is here;", "tyndale": "But I saye vnto you: that here is one greater then ye teple.", "dra": "But I tell you that there is here a greater than the temple.", "bbe": "But I say to you that a greater thing than the Temple is here.", "geneva": "But I say vnto you, that here is one greater then the Temple.", "wycliffe": "And Y seie to you, that here is a gretter than the temple.", "rotherham": "But I say unto you,—Something greater than the Temple, is here!", "weymouth": "But I tell you that there is here that which is greater than the Temple.", "darby": "But I say unto you, that there is here what is greater than the temple.", "twenty": "Here, however, I tell you, there is something greater than the Temple!", "acv": "But I say to you, that a greater than the temple is here.", "anderson": "But I say to you, that something greater than the temple is here.", "haweis": "Now I tell you, That one greater than the temple is here.", "noyes": "But I say to you, that something greater than the temple is here.", "webster": "But I say to you, that in this place is [one] greater than the temple.", "vulgate": "dico autem vobis quia templo maior est hic;"}}, {"v": 7, "ref": "12:7", "o": "εἰ δὲ ἐγνώκειτε τί ἐστιν· Ἔλεος θέλω καὶ οὐ θυσίαν, οὐκ ἂν κατεδικάσατε τοὺς ἀναιτίους.", "en": {"kjv": "But if ye had known what this meaneth, I will have mercy, and not sacrifice, ye would not have condemned the guiltless.", "web": "But if you had known what this means, ‘I desire mercy, and not sacrifice,’you would not have condemned the guiltless.", "bsb": "If only you had known the meaning of ‘I desire mercy, not sacrifice,’ you would not have condemned the innocent.", "asv": "But if ye had known what this meaneth, I desire mercy, and not sacrifice, ye would not have condemned the guiltless.", "ylt": "and if ye had known what is: Kindness I will, and not sacrifice--ye had not condemned the blameless,", "tyndale": "Wherfore yf ye had wist what this sayinge meneth: I require mercy and not sacrifice: ye wold never have condened innocetes.", "dra": "And if you knew what this meaneth: I will have mercy, and not sacrifice: you would never have condemned the innocent.", "bbe": "But if these words had been in your minds, My desire is for mercy and not for offerings, you would not have been judging those who have done no wrong.", "geneva": "Wherefore if ye knewe what this is, I will haue mercie, and not sacrifice, ye would not haue condemned the innocents.", "wycliffe": "And if ye wisten, what it is, Y wole merci, and not sacrifice, ye schulden neuer haue condempned innocentis.", "rotherham": "If, however, ye had known what this meaneth—Mercy, I desire, and not, sacrifice, ye would not have condemned the blameless;", "weymouth": "And if you knew what this means, `It is mercy I desire, not sacrifice', you would not have condemned those who are without guilt.", "darby": "But if ye had known what is: I will have mercy and not sacrifice, ye would not have condemned the guiltless.", "twenty": "And had you learned the meaning of the words — ‘I desire mercy, and not sacrifice,’ you would not have condemned those who are not guilty.", "acv": "But if ye had known what this means, I desire mercy, and not sacrifice, ye would not have condemned the innocent.", "anderson": "But if you had known what this means―I desire mercy, and not sacrifice―you would not have condemned the blameless.", "haweis": "But if ye had known what that meant, I desire mercy and not sacrifice; ye would not have condemned the innocent.", "noyes": "But if ye had known what this meaneth, \"I desire mercy and not sacrifice,\" ye would not have condemned the guiltless.", "webster": "But if ye had known what [this] meaneth, I will have mercy, and not sacrifice, ye would not have condemned the guiltless.", "vulgate": "si autem sciretis quid est misericordiam volo et non sacrificium numquam condemnassetis innocentes;"}}, {"v": 8, "ref": "12:8", "o": "κύριος γάρ ἐστιν τοῦ σαββάτου ὁ υἱὸς τοῦ ἀνθρώπου.", "en": {"kjv": "For the Son of man is Lord even of the sabbath day.", "web": "For the Son of Man is Lord of the Sabbath.”", "bsb": "For the Son of Man is Lord of the Sabbath.”", "asv": "For the Son of man is lord of the sabbath.", "ylt": "for the son of man is lord even of the sabbath.'", "tyndale": "For ye sonne of man is lord even of ye saboth daye.", "dra": "For the Son of man is Lord even of the sabbath.", "bbe": "For the Son of man is lord of the Sabbath.", "geneva": "For the sonne of man is Lord, euen of the Sabbath.", "wycliffe": "For mannus Sone is lord, yhe, of the sabat.", "rotherham": "For, the Son of Man, is, Lord of the Sabbath.", "weymouth": "For the Son of Man is the Lord of the Sabbath.\"", "darby": "For the Son of man is Lord of the sabbath.", "twenty": "For the Son of Man is lord of the Sabbath.”", "acv": "For the Son of man is Lord of the sabbath.", "anderson": "For the Son of man is Lord of the Sabbath.", "haweis": "For the Son of man is Lord also of the sabbath.", "noyes": "For the Son of man is lord of the sabbath.", "webster": "For the Son of man is Lord even of the sabbath.", "vulgate": "dominus est enim Filius hominis etiam sabbati;"}}, {"v": 9, "ref": "12:9", "o": "Καὶ μεταβὰς ἐκεῖθεν ἦλθεν εἰς τὴν συναγωγὴν αὐτῶν·", "en": {"kjv": "And when he was departed thence, he went into their synagogue:", "web": "He departed there, and went into their synagogue.", "bsb": "Moving on from there, Jesus entered their synagogue,", "asv": "And he departed thence, and went into their synagogue:", "ylt": "And having departed thence, he went to their synagogue,", "tyndale": "And he departed thence and went into their synagoge:", "dra": "And when he had passed from thence, he came into their synagogues.", "bbe": "And he went from there into their Synagogue:", "geneva": "And he departed thence, and went into their Synagogue:", "wycliffe": "And whanne he passide fro thennus, he cam in to the synagoge of hem.", "rotherham": "And, passing on from thence, he came into their synagogue;", "weymouth": "Departing thence He went to their synagogue,", "darby": "And, going away from thence, he came into their synagogue.", "twenty": "Passing on, Jesus went into their Synagogue,", "acv": "And having departed from there, he went into their synagogue.", "anderson": "And he departed thence, and went into their synagogue.", "haweis": "And going on from thence, he came into their synagogue;", "noyes": "And departing thence, he went into their synagogue.", "webster": "And when he had departed thence, he went into their synagogue.", "vulgate": "et cum inde transisset venit in synagogam eorum;"}}, {"v": 10, "ref": "12:10", "o": "καὶ ἰδοὺ ⸀ἄνθρωπος χεῖρα ἔχων ξηράν. καὶ ἐπηρώτησαν αὐτὸν λέγοντες· Εἰ ἔξεστι τοῖς σάββασιν ⸀θεραπεύειν; ἵνα κατηγορήσωσιν αὐτοῦ.", "en": {"kjv": "And, behold, there was a man which had his hand withered. And they asked him, saying, Is it lawful to heal on the sabbath days? that they might accuse him.", "web": "And behold there was a man with a withered hand. They asked him, “Is it lawful to heal on the Sabbath day?” that they might accuse him.", "bsb": "and a man with a withered hand was there. In order to accuse Jesus, they asked Him, “Is it lawful to heal on the Sabbath?”", "asv": "and behold, a man having a withered hand. And they asked him, saying, Is it lawful to heal on the sabbath day? that they might accuse him.", "ylt": "and lo, there was a man having the hand withered, and they questioned him, saying, `Is it lawful to heal on the sabbaths?' that they might accuse him.", "tyndale": "and beholde ther was a man whiche had his hande dryed vp. And they axed him sayinge: ys it lawfull to heale apon ye saboth dayes? because they myght acuse him.", "dra": "And behold there was a man who had a withered hand, and they asked him, saying: Is it lawful to heal on the sabbath days? that they might accuse him.", "bbe": "And there was a man with a dead hand. And they put a question to him, saying, Is it right to make a man well on the Sabbath day? so that they might have something against him.", "geneva": "And beholde, there was a man which had his hand dried vp. And they asked him, saying, Is it lawfull to heale vpon a Sabbath day? that they might accuse him.", "wycliffe": "And lo! a man that hadde a drye hoond. And thei axiden hym, and seiden, Whether it be leueful to hele in the sabot? that thei schulden acuse hym.", "rotherham": "and lo! a man having, a withered hand, and they questioned him, saying, Is it allowable, on the sabbath, to heal? that they might accuse him.", "weymouth": "where there was a man with a shrivelled arm. And they questioned Him, \"Is it right to cure people on the Sabbath?\" Their intention was to bring a charge against Him.", "darby": "And behold, there was a man having his hand withered. And they asked him, saying, Is it lawful to heal on the sabbath? that they might accuse him.", "twenty": "and there he saw a man with a withered hand. Some people asked Jesus whether it was allowable to work a cure on the Sabbath — so that they might have a charge to bring against him.", "acv": "And behold, there was a man having a withered hand. And they interrogated him, asking if it is permitted to heal on the sabbath, so that they might accuse him.", "anderson": "And behold, a man was there that had a withered hand. And they asked him, saying: Is it lawful to cure on the Sabbath-days? that they might accuse him.", "haweis": "and, behold a man was there who had a withered hand. And they asked him, saying, Is it lawful to heal on sabbath days? that they might accuse him.", "noyes": "And, lo! there was a man having a withered hand. And they asked him, saying, Is it lawful to heal on the sabbath? that they might accuse him.", "webster": "And behold, there was a man who had [his] hand withered. And they asked him, saying, Is it lawful to heal on the sabbath? that they might accuse him.", "vulgate": "et ecce homo manum habens aridam et interrogabant eum dicentes si licet sabbatis curare ut accusarent eum;"}}, {"v": 11, "ref": "12:11", "o": "ὁ δὲ εἶπεν αὐτοῖς· Τίς ⸀ἔσται ἐξ ὑμῶν ἄνθρωπος ὃς ἕξει πρόβατον ἕν, καὶ ἐὰν ἐμπέσῃ τοῦτο τοῖς σάββασιν εἰς βόθυνον, οὐχὶ κρατήσει αὐτὸ καὶ ἐγερεῖ;", "en": {"kjv": "And he said unto them, What man shall there be among you, that shall have one sheep, and if it fall into a pit on the sabbath day, will he not lay hold on it, and lift it out?", "web": "He said to them, “What man is there among you, who has one sheep, and if this one falls into a pit on the Sabbath day, won’t he grab on to it, and lift it out?", "bsb": "He replied, “If one of you has a sheep and it falls into a pit on the Sabbath, will he not take hold of it and lift it out?", "asv": "And he said unto them, What man shall there be of you, that shall have one sheep, and if this fall into a pit on the sabbath day, will he not lay hold on it, and lift it out?", "ylt": "And he said to them, `What man shall be of you, who shall have one sheep, and if this may fall on the sabbaths into a ditch, will not lay hold on it and raise it ?", "tyndale": "And he sayde vnto the: whiche of you wolde it be yf he had a shepe fallen into a pitte on ye saboth daye that wolde not take him and lyft him out?", "dra": "But he said to them: What man shall there be among you, that hath one sheep: and if the same fall into a pit on the sabbath day, will he not take hold on it and lift it up?", "bbe": "And he said to them, Which of you, having a sheep, if it gets into a hole on the Sabbath day, will not put out a helping hand and get it back?", "geneva": "And he said vnto the, What man shall there be among you, that hath a sheepe, and if it fal on a Sabbath day into a pit, doth not take it and lift it out?", "wycliffe": "And he seide to hem, What man of you schal be, that hath o scheep, and if it falle in to a diche in the sabotis, whether he shal not holde, and lifte it vp?", "rotherham": "And said unto them, What man, from among yourselves, [shall there be],—Who shall have one sheep, and, if this should fall, on the sabbath, into a pit, will not lay hold of it, and raise it?", "weymouth": "\"Which of you is there,\" He replied, \"who, if he has but a single sheep and it falls into a hole on the Sabbath, will not lay hold of it and lift it out?", "darby": "But he said to them, What man shall there be of you who has one sheep, and if this fall into a pit on the sabbath, will not lay hold of it and raise [it] up?", "twenty": "But Jesus said to them: “Which of you, if he had only one sheep, and that sheep fell into a pit on the Sabbath, would not lay hold of it and pull it out?", "acv": "And he said to them, What man of you will there be, who will have one sheep, and if this falls into a pit on the sabbath, will he not grasp it, and lift it out?", "anderson": "And he said to them: What man shall there be among you, that shall have one sheep, and if this fall into a pit on the Sabbath-day, will he not lay hold on it and lift it out?", "haweis": "Then he said to them; What man of you is there who hath one sheep, and if it fall into a pit on the sabbath, doth he not lay hold on him, and lift him out?", "noyes": "And he said to them, Who of you that owneth one sheep, if it fall into a pit on the sabbath, will not lay hold of it, and lift it out?", "webster": "And he said to them, What man shall there be among you, that shall have one sheep, and if it shall fall into a pit on the sabbath, will he not lay hold on it, and lift [it] out?", "vulgate": "ipse autem dixit illis quis erit ex vobis homo qui habeat ovem unam et si ceciderit haec sabbatis in foveam nonne tenebit et levabit eam;"}}, {"v": 12, "ref": "12:12", "o": "πόσῳ οὖν διαφέρει ἄνθρωπος προβάτου. ὥστε ἔξεστιν τοῖς σάββασιν καλῶς ποιεῖν.", "en": {"kjv": "How much then is a man better than a sheep? Wherefore it is lawful to do well on the sabbath days.", "web": "Of how much more value then is a man than a sheep! Therefore it is lawful to do good on the Sabbath day.”", "bsb": "How much more valuable is a man than a sheep! Therefore it is lawful to do good on the Sabbath.”", "asv": "How much then is a man of more value than a sheep! Wherefore it is lawful to do good on the sabbath day.", "ylt": "How much better, therefore, is a man than a sheep? --so that it is lawful on the sabbaths to do good.'", "tyndale": "And how moche is a man better the a shepe? Wherfore it is lefull to do a good dede on the saboth dayes.", "dra": "How much better is a man than a sheep? Therefore it is lawful to do a good deed on the sabbath days.", "bbe": "Of how much more value is a man than a sheep! For this reason it is right to do good on the Sabbath day.", "geneva": "How much more then is a man better then a sheepe? therefore, it is lawfull to doe well on a Sabbath day.", "wycliffe": "How myche more is a man better than a scheep? Therfor it is leueful to do good in the sabatis.", "rotherham": "How much better, then, a man, than, a sheep? So that it is allowable, on the sabbath, nobly, to act.", "weymouth": "Is not a man, however, far superior to a sheep? Therefore it is right to do good on the Sabbath.\"", "darby": "How much better then is a man than a sheep! So that it is lawful to do well on the sabbath.", "twenty": "And how much more precious a man is than a sheep! Therefore it is allowable to do good on the Sabbath.”", "acv": "How much therefore a man is superior to a sheep. So then it is permitted to do good on the sabbath.", "anderson": "How much better, then, is a man than a sheep! So it is lawful to do well on the Sabbath-days.", "haweis": "Of how much more value then is a man than a sheep? Wherefore it is lawful to do good on the sabbath days.", "noyes": "Of how much more worth now is a man than a sheep! So then it is lawful to do well on the sabbath.", "webster": "How much then is a man better than a sheep? wherefore it is lawful to do well on the sabbath days.", "vulgate": "quanto magis melior est homo ove itaque licet sabbatis benefacere;"}}, {"v": 13, "ref": "12:13", "o": "τότε λέγει τῷ ἀνθρώπῳ· Ἔκτεινόν ⸂σου τὴν χεῖρα⸃· καὶ ἐξέτεινεν, καὶ ἀπεκατεστάθη ὑγιὴς ὡς ἡ ἄλλη.", "en": {"kjv": "Then saith he to the man, Stretch forth thine hand. And he stretched it forth; and it was restored whole, like as the other.", "web": "Then he told the man, “Stretch out your hand.” He stretched it out; and it was restored whole, just like the other.", "bsb": "Then Jesus said to the man, “Stretch out your hand.” So he stretched it out, and it was restored to full use, just like the other.", "asv": "Then saith he to the man, Stretch forth thy hand. And he stretched it forth; and it was restored whole, as the other.", "ylt": "Then saith he to the man, `Stretch forth thy hand,' and he stretched it forth, and it was restored whole as the other.", "tyndale": "Then sayde he to ye ma: stretch forth thy had. And he stretched it forthe. And it was made whole agayne lyke vnto ye other.", "dra": "Then he saith to the man: Stretch forth thy hand; and he stretched it forth, and it was restored to health even as the other.", "bbe": "Then said he to the man, Put out your hand. And he put it out, and it was made as well as the other.", "geneva": "Then said he to the man, Stretch forth thine hand. And he stretched it foorth, and it was made whole as the other.", "wycliffe": "Thanne he seide to the man, Stretche forth thin hoond. And he strauyte forth; and it was restorid to heelthe as the tothir.", "rotherham": "Then saith he unto the man, Stretch forth thy hand! And he stretched it forth,—and it was restored, whole, as the other.", "weymouth": "Then He said to the man, \"Stretch out your arm.\" And he stretched it out, and it was restored quite sound like the other.", "darby": "Then he says to the man, Stretch out thy hand. And he stretched [it] out, and it was restored sound as the other.", "twenty": "Then he said to the man. “Stretch out your hand.” The man stretched it out; and it had become as sound as the other.", "acv": "Then he says to the man, Stretch forth thy hand. And he stretched it forth, and it was restored whole, as the other.", "anderson": "Then he said to the man: Stretch forth your hand. And he stretched it forth; and it was restored to soundness, like the other.", "haweis": "Then saith he to the man, Stretch out thy hand; and he stretched it out, and it was restored, sound as the other.", "noyes": "Then saith he to the man, Stretch forth thy hand. And he stretched it forth; and it was restored sound as the other.", "webster": "Then saith he to the man, Stretch out thy hand. And he stretched [it] out; and [it] was restored to a sound state like the other.", "vulgate": "tunc ait homini extende manum tuam et extendit et restituta est sanitati sicut altera;"}}, {"v": 14, "ref": "12:14", "o": "⸂ἐξελθόντες δὲ οἱ Φαρισαῖοι συμβούλιον ἔλαβον κατ’ αὐτοῦ⸃ ὅπως αὐτὸν ἀπολέσωσιν.", "en": {"kjv": "Then the Pharisees went out, and held a council against him, how they might destroy him.", "web": "But the Pharisees went out, and conspired against him, how they might destroy him.", "bsb": "But the Pharisees went out and plotted how they might kill Jesus.", "asv": "But the Pharisees went out, and took counsel against him, how they might destroy him.", "ylt": "And the Pharisees having gone forth, held a consultation against him, how they might destroy him,", "tyndale": "Then ye Pharyses wet out and helde a cousell agaynst hym how they myght destroye hym.", "dra": "And the Pharisees going out made a consultation against him, how they might destroy him.", "bbe": "But the Pharisees went out and made designs against him, how they might put him to death.", "geneva": "Then the Pharises went out, and consulted against him, howe they might destroy him.", "wycliffe": "And the Farisees wenten out, and maden a counsel ayens hym, hou thei schulden distrie hym.", "rotherham": "And the Pharisees, going forth, took, counsel, against him, to the end that, him, they might destroy.", "weymouth": "But the Pharisees after leaving the synagogue consulted together against Him, how they might destroy Him.", "darby": "But the Pharisees, having gone out, took counsel against him, how they might destroy him.", "twenty": "On coming out, the Pharisees plotted against Jesus, to put him to death.", "acv": "But when they went out, the Pharisees held a consultation against him, how they might destroy him.", "anderson": "But the Pharisees went out and took counsel against him, that they might destroy him.", "haweis": "Then the Pharisees went out, and held a consultation against him, how they might make away with him.", "noyes": "Then the Pharisees went out, and consulted together against him, how they might destroy him.", "webster": "Then the Pharisees went out, and held a council against him, how they might destroy him.", "vulgate": "exeuntes autem Pharisaei consilium faciebant adversus eum quomodo eum perderent;"}}, {"v": 15, "ref": "12:15", "o": "Ὁ δὲ Ἰησοῦς γνοὺς ἀνεχώρησεν ἐκεῖθεν. καὶ ἠκολούθησαν ⸀αὐτῷ πολλοί, καὶ ἐθεράπευσεν αὐτοὺς πάντας,", "en": {"kjv": "But when Jesus knew it, he withdrew himself from thence: and great multitudes followed him, and he healed them all;", "web": "Jesus, perceiving that, withdrew from there. Great multitudes followed him; and he healed them all,", "bsb": "Aware of this, Jesus withdrew from that place. Large crowds followed Him, and He healed them all,", "asv": "And Jesus perceivingitwithdrew from thence: and many followed him; and he healed them all,", "ylt": "and Jesus having known, withdrew thence, and there followed him great multitudes, and he healed them all,", "tyndale": "When Iesus knewe yt he departed thece and moche people folowed him and he healed the all", "dra": "But Jesus knowing it, retired from thence: and many followed him, and he healed them all.", "bbe": "And Jesus, having knowledge of this, went away from there, and a great number went after him; and he made them all well,", "geneva": "But whe Iesus knew it, he departed thece, and great multitudes folowed him, and he healed the al,", "wycliffe": "And Jhesus knewe it, and wente awei fro thennus; and many sueden hym, and he helide hem alle.", "rotherham": "But, Jesus, taking note, retired from thence,—and many followed him, and he cured them all;", "weymouth": "Aware of this, Jesus departed elsewhere; and a great number of people followed Him, all of whom He cured.", "darby": "But Jesus knowing [it], withdrew thence, and great crowds followed him; and he healed them all:", "twenty": "Jesus, however, became aware of it, and went away from that place. A number of people followed him, and he cured them all;", "acv": "And having known it Jesus withdrew from there, and many multitudes followed him, and he healed them all.", "anderson": "But Jesus perceived it, and withdrew from that place. And many multitudes followed him, and he cured them all.", "haweis": "But Jesus knew it, and retired from thence, and great multitudes followed him, and he healed them all,", "noyes": "But Jesus, knowing it, withdrew from thence; and many followed him; and he healed them all,", "webster": "But when Jesus knew [it], he withdrew himself from thence: and great multitudes followed him, and he healed them all.", "vulgate": "Iesus autem sciens recessit inde et secuti sunt eum multi et curavit eos omnes;"}}, {"v": 16, "ref": "12:16", "o": "καὶ ἐπετίμησεν αὐτοῖς ἵνα μὴ φανερὸν αὐτὸν ποιήσωσιν,", "en": {"kjv": "And charged them that they should not make him known:", "web": "and commanded them that they should not make him known:", "bsb": "warning them not to make Him known.", "asv": "and charged them that they should not make him known:", "ylt": "and did charge them that they might not make him manifest,", "tyndale": "and charged the that they shuld not make him knowe:", "dra": "And he charged them that they should not make him known.", "bbe": "Ordering them not to give people word of him:", "geneva": "And charged them in threatning wise, that they should not make him knowen,", "wycliffe": "And he comaundide to hem, that thei schulden not make hym knowun;", "rotherham": "and straitly charged them, lest they should make him, manifest:", "weymouth": "But He gave them strict injunctions not to blaze abroad His doings,", "darby": "and charged them strictly that they should not make him publicly known:", "twenty": "but he warned them not to make him known,", "acv": "And he chided them so that they would not make him known,", "anderson": "And he charged them not to make him known;", "haweis": "and charged them that they should not make him known.", "noyes": "and strictly charged them not to make him known;", "webster": "And charged them that they should not make him known:", "vulgate": "et praecepit eis ne manifestum eum facerent;"}}, {"v": 17, "ref": "12:17", "o": "⸀ἵνα πληρωθῇ τὸ ῥηθὲν διὰ Ἠσαΐου τοῦ προφήτου λέγοντος·", "en": {"kjv": "That it might be fulfilled which was spoken by Esaias the prophet, saying,", "web": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "bsb": "This was to fulfill what was spoken through the prophet Isaiah:", "asv": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "ylt": "that it might be fulfilled that was spoken through Isaiah the prophet, saying,", "tyndale": "to fulfyll that which was spoden by Esay ye Prophet which sayeth.", "dra": "That it might be fulfilled which was spoken by Isaias the prophet, saying:", "bbe": "So that what was said by Isaiah the prophet might come true,", "geneva": "That it might be fulfilled, which was spoken by Esaias the Prophet, saying,", "wycliffe": "that that thing were fulfillid, that was seid by Isaie, the prophete, seiynge, Lo!", "rotherham": "that it might be fulfilled, which was spoken through Isaiah the prophet, saying:—", "weymouth": "that those words of the Prophet Isaiah might be fulfilled,", "darby": "that that might be fulfilled which was spoken through Esaias the prophet, saying,", "twenty": "in fulfilment of these words in the Prophet Isaiah —", "acv": "so that what was spoken through Isaiah the prophet might be fulfilled, which says,", "anderson": "that the word might be fulfilled which was spoken by Isaiah the prophet, saying:", "haweis": "That what was spoken by Isaiah the prophet might be fulfilled, saying,", "noyes": "that it might be fulfilled which was spoken through Isaiah the prophet, saying,", "webster": "That it might be fulfilled which was spoken by Isaiah the prophet, saying,", "vulgate": "ut adimpleretur quod dictum est per Esaiam prophetam dicentem;"}}, {"v": 18, "ref": "12:18", "o": "Ἰδοὺ ὁ παῖς μου ὃν ᾑρέτισα, ὁ ἀγαπητός μου ⸂εἰς ὃν⸃ εὐδόκησεν ἡ ψυχή μου· θήσω τὸ πνεῦμά μου ἐπ’ αὐτόν, καὶ κρίσιν τοῖς ἔθνεσιν ἀπαγγελεῖ.", "en": {"kjv": "Behold my servant, whom I have chosen; my beloved, in whom my soul is well pleased: I will put my spirit upon him, and he shall shew judgment to the Gentiles.", "web": "“Behold, my servant whom I have chosen; my beloved in whom my soul is well pleased: I will put my Spirit on him. He will proclaim justice to the nations.", "bsb": "“Here is My Servant, whom I have chosen, My beloved, in whom My soul delights. I will put My Spirit on Him, and He will proclaim justice to the nations.", "asv": "Behold, my servant whom I have chosen; My beloved in whom my soul is well pleased: I will put my Spirit upon him, And he shall declare judgment to the Gentiles.", "ylt": "`Lo, My servant, whom I did choose, My beloved, in whom My soul did delight, I will put My Spirit upon him, and judgment to the nations he shall declare,", "tyndale": "Beholde my chylde who I have chosen my beloved in who my soule deliteth. I wyll put my sprete on hym and he shall shewe iudgemet to ye gentyls.", "dra": "Behold my servant whom I have chosen, my beloved in whom my soul hath been well pleased. I will put my spirit upon him, and he shall shew judgment to the Gentiles.", "bbe": "See my servant, the man of my selection, my loved one in whom my soul is well pleased: I will put my Spirit on him, and he will make my decision clear to the Gentiles.", "geneva": "Behold my seruant whom I haue chosen, my beloued in whom my soule deliteth: I wil put my Spirit on him, and he shall shewe iudgement to the Gentiles.", "wycliffe": "my child, whom Y haue chosun, my derling, in whom it hath wel plesid to my soule; Y shal put my spirit on him, and he shal telle dom to hethen men.", "rotherham": "Lo! my servant, whom I have chosen, My beloved, in whom, my soul, delighteth,—I will put my Spirit upon him, and, justice, unto the nations, will he report:", "weymouth": "\"This is My servant whom I have chosen, My dearly loved One in whom My soul takes pleasure. I will put My spirit upon Him, and He will announce justice to the nations.", "darby": "Behold my servant, whom I have chosen, my beloved, in whom my soul has found its delight. I will put my Spirit upon him, and he shall shew forth judgment to the nations.", "twenty": "‘Behold! the Servant of my Choice, My Beloved, in whom my heart delights! I will breathe my spirit upon him, and he shall announce a time of judgment to the Gentiles.", "acv": "Behold, my Boy whom I chose, my beloved in whom my soul is well pleased. I will put my Spirit upon him, and he will declare justice to the Gentiles.", "anderson": "Be hold, my servant whom I have chosen; my beloved, in whom my soul delights. I will put my Spirit upon him, and he shall declare law to the Gentiles.", "haweis": "“Behold, my servant, whom I have chosen, my beloved, in whom my soul delighteth: I will put my Spirit upon him, and he shall proclaim judgment for the heathen.", "noyes": "\"Behold my servant, whom I chose; my beloved, with whom my soul is well pleased; I will put my Spirit upon him, and he will declare judgment to the nations.", "webster": "Behold, my servant, whom I have chosen; my beloved, in whom my soul is well pleased: I will put my spirit upon him, and he shall show judgment to the Gentiles.", "vulgate": "ecce puer meus quem elegi dilectus meus in quo bene placuit animae meae ponam spiritum meum super eum et iudicium gentibus nuntiabit;"}}, {"v": 19, "ref": "12:19", "o": "οὐκ ἐρίσει οὐδὲ κραυγάσει, οὐδὲ ἀκούσει τις ἐν ταῖς πλατείαις τὴν φωνὴν αὐτοῦ.", "en": {"kjv": "He shall not strive, nor cry; neither shall any man hear his voice in the streets.", "web": "He will not strive, nor shout; neither will anyone hear his voice in the streets.", "bsb": "He will not quarrel or cry out; no one will hear His voice in the streets.", "asv": "He shall not strive, nor cry aloud; Neither shall any one hear his voice in the streets.", "ylt": "he shall not strive nor cry, nor shall any hear in the broad places his voice,", "tyndale": "He shall not stryve he shall not crye nether shall eny man heare his voyce in ye streetes", "dra": "He shall not contend, nor cry out, neither shall any man hear his voice in the streets.", "bbe": "His coming will not be with fighting or loud cries; and his voice will not be lifted up in the streets.", "geneva": "He shall not striue, nor crie, neither shall any man heare his voyce in the streetes.", "wycliffe": "He shal not stryue, ne crye, nethir ony man shal here his voice in stretis.", "rotherham": "He will not strive, nor will he cry out, nor shall any hear, in the broadways, his voice:", "weymouth": "He will not wrangle or raise His voice, nor will His voice be heard in the broadways.", "darby": "He shall not strive or cry out, nor shall any one hear his voice in the streets;", "twenty": "He shall not contend, nor cry aloud, Neither shall any one hear his voice in the streets;", "acv": "He will not quarrel, nor will he shout, nor will any man hear his voice in the thoroughfares.", "anderson": "He shall not contend, nor cry out; nor shall any one hear his voice in the streets.", "haweis": "He shall not contend, nor be clamorous; neither shall any man in the streets hear his voice.", "noyes": "He will not strive, nor cry aloud, nor will any one hear his voice in the streets.", "webster": "He shall not contend, nor cry; neither shall any man hear his voice in the streets.", "vulgate": "non contendet neque clamabit neque audiet aliquis in plateis vocem eius;"}}, {"v": 20, "ref": "12:20", "o": "κάλαμον συντετριμμένον οὐ κατεάξει καὶ λίνον τυφόμενον οὐ σβέσει, ἕως ἂν ἐκβάλῃ εἰς νῖκος τὴν κρίσιν.", "en": {"kjv": "A bruised reed shall he not break, and smoking flax shall he not quench, till he send forth judgment unto victory.", "web": "He won’t break a bruised reed. He won’t quench a smoking flax, until he leads justice to victory.", "bsb": "A bruised reed He will not break, and a smoldering wick He will not extinguish, till He leads justice to victory.", "asv": "A bruised reed shall he not break, And smoking flax shall he not quench, Till he send forth judgment unto victory.", "ylt": "a bruised reed he shall not break, and smoking flax he shall not quench, till he may put forth judgment to victory,", "tyndale": "a brosed rede shall he not breacke and flaxe that begynneth to burne he shall not queche tyll he sende forth iudgement vnto victory", "dra": "The bruised reed he shall not break: and smoking flax he shall not extinguish: till he send forth judgment unto victory.", "bbe": "The crushed stem will not be broken by him; and the feebly burning light will he not put out, till he has made righteousness overcome all.", "geneva": "A bruised reede shall he not breake, and smoking flaxe shall he not quenche, till he bring forth iudgement vnto victorie.", "wycliffe": "A brisid rehed he shal not breke, and he schal not quenche smokynge flax, til he caste out doom to victorie;", "rotherham": "A bruised cane, will he not break, and, a smoking wick, will he not quench,—until he urge on, justice, to victory,", "weymouth": "A crushed reed He will not utterly break, nor will He quench the still smouldering wick, until He has led on Justice to victory.", "darby": "a bruised reed shall he not break, and smoking flax shall he not quench, until he bring forth judgment unto victory;", "twenty": "a bruised reed he will not break, and a smouldering wick he will not quench, Till he has brought the judgment to a victorious issue,", "acv": "A bruised reed he will not break, and smoldering flax he will not quench, until he sends forth justice for victory.", "anderson": "A bruised reed he shall not break, and a smoking wick he shall not extinguish, till he shall send forth his law for conquest.", "haweis": "A bruised reed shall he not break down, and smoking flax shall he not quench, until he break forth in judgment for victory.", "noyes": "A bruised reed he will not break, and smoking flax he will not quench, till he send forth judgment unto victory.", "webster": "A bruised reed shall he not break, and smoking flax shall he not quench, till he shall send forth judgment to victory.", "vulgate": "harundinem quassatam non confringet et linum fumigans non extinguet donec eiciat ad victoriam iudicium;"}}, {"v": 21, "ref": "12:21", "o": "καὶ τῷ ὀνόματι αὐτοῦ ἔθνη ἐλπιοῦσιν.", "en": {"kjv": "And in his name shall the Gentiles trust.", "web": "In his name, the nations will hope.”", "bsb": "In His name the nations will put their hope.”", "asv": "And in his name shall the Gentiles hope.", "ylt": "and in his name shall nations hope.'", "tyndale": "and in hys name shall the gentyls truste.", "dra": "And in his name the Gentiles shall hope.", "bbe": "And in his name will the Gentiles put their hope.", "geneva": "And in his Name shall the Gentiles trust.", "wycliffe": "and hethene men schulen hope in his name.", "rotherham": "And, in his name, shall nations hope.", "weymouth": "And on His name shall the nations rest their hopes.\"", "darby": "and on his name shall [the] nations hope.", "twenty": "and on his name shall the Gentiles rest their hopes.”", "acv": "And in his name Gentiles will hope.", "anderson": "And in his name shall the Gentiles trust.", "haweis": "And in his name shall the Gentiles hope.”", "noyes": "And in his name will nations hope.\"", "webster": "And in his name shall the Gentiles trust.", "vulgate": "et in nomine eius gentes sperabunt;"}}, {"v": 22, "ref": "12:22", "o": "Τότε ⸂προσηνέχθη αὐτῷ δαιμονιζόμενος τυφλὸς καὶ κωφός⸃· καὶ ἐθεράπευσεν αὐτόν, ὥστε τὸν ⸀κωφὸν λαλεῖν καὶ βλέπειν.", "en": {"kjv": "Then was brought unto him one possessed with a devil, blind, and dumb: and he healed him, insomuch that the blind and dumb both spake and saw.", "web": "Then one possessed by a demon, blind and mute, was brought to him and he healed him, so that the blind and mute man both spoke and saw.", "bsb": "Then a demon-possessed man who was blind and mute was brought to Jesus, and He healed the man so that he could speak and see.", "asv": "Then was brought unto him one possessed with a demon, blind and dumb: and he healed him, insomuch that the dumb man spake and saw.", "ylt": "Then was brought to him a demoniac, blind and dumb, and he healed him, so that the blind and dumb both spake and saw.", "tyndale": "Then was brought to hym one possessed with a devyll which was both blynde and domme: and he healed hym insomoch that he which was blynd and domme both spake and sawe.", "dra": "Then was offered to him one possessed with a devil, blind and dumb: and he healed him, so that he spoke and saw.", "bbe": "Then they took to him one with an evil spirit, who was blind and had no power of talking: and he made him well so that he had the power of talking and seeing.", "geneva": "Then was brought to him one, possessed with a deuill, both blind, and dumme, and he healed him, so that he which was blind and dumme, both spake and saw.", "wycliffe": "Thanne a man blynde and doumbe, that hadde a feend, was brouyt to hym; and he helide hym, so that he spak, and say.", "rotherham": "Then they brought unto him, one demonized, blind and dumb,—and he cured him, so that the dumb did speak and see.", "weymouth": "At that time a demoniac was brought to Him, blind and dumb; and He cured him, so that the dumb man could speak and see.", "darby": "Then was brought to him one possessed by a demon, blind and dumb, and he healed him, so that the dumb [man] spake and saw.", "twenty": "Then some people brought to Jesus a possessed man, who was blind and dumb; and he cured him, so that the man who had been dumb both talked and saw.", "acv": "Then a blind and mute man being demon possessed, was brought to him. And he healed him, so as for the blind and mute man both to speak and to see.", "anderson": "Then was brought to him a demoniac, blind and dumb: and he cured him, so that the blind and dumb man both spoke and saw.", "haweis": "Then was brought to him a demoniac, blind and dumb; and he cured him, so as to enable the blind and dumb both to speak and see.", "noyes": "Then was brought to him one possessed by a demon, blind and dumb; and he healed him, so that the dumb man spoke and saw.", "webster": "Then was brought to him one possessed with a demon, blind and dumb; and he healed him, so that the blind and dumb both spoke and saw.", "vulgate": "tunc oblatus est ei daemonium habens caecus et mutus et curavit eum ita ut loqueretur et videret;"}}, {"v": 23, "ref": "12:23", "o": "καὶ ἐξίσταντο πάντες οἱ ὄχλοι καὶ ἔλεγον· Μήτι οὗτός ἐστιν ὁ υἱὸς Δαυίδ;", "en": {"kjv": "And all the people were amazed, and said, Is not this the son of David?", "web": "All the multitudes were amazed, and said, “Can this be the son of David?”", "bsb": "The crowds were astounded and asked, “Could this be the Son of David?”", "asv": "And all the multitudes were amazed, and said, Can this be the son of David?", "ylt": "And all the multitudes were amazed, and said, `Is this the Son of David?'", "tyndale": "And all the people were amased and sayde: Ys not this that sonne of David?", "dra": "And all the multitudes were amazed, and said: Is not this the son of David?", "bbe": "And all the people were surprised and said, Is not this the Son of David?", "geneva": "And all the people were amased, and saide, Is not this that sonne of Dauid?", "wycliffe": "And al the puple wondride, and seide, Whether this be the sone of Dauid?", "rotherham": "And all the multitudes were beside themselves, and were saying, Can, this one, be, the Son of David?", "weymouth": "And the crowds of people were all filled with amazement and said, \"Can this be the Son of David?\"", "darby": "And all the crowds were amazed and said, Is this [man] the Son of David?", "twenty": "At this all the people were astounded. “Is it possible that this is the son of David?” they exclaimed.", "acv": "And all the multitudes were amazed, and said, Is this not the son of David?", "anderson": "And all the people were amazed, and said: Is not this the son of David?", "haweis": "And all the multitudes were lost in amazement, and they said, Is not this the son of David?", "noyes": "And all the multitudes were amazed, and said, Is this the son of David?", "webster": "And all the people were amazed, and said, Is not this the son of David?", "vulgate": "et stupebant omnes turbae et dicebant numquid hic est Filius David;"}}, {"v": 24, "ref": "12:24", "o": "οἱ δὲ Φαρισαῖοι ἀκούσαντες εἶπον· Οὗτος οὐκ ἐκβάλλει τὰ δαιμόνια εἰ μὴ ἐν τῷ Βεελζεβοὺλ ἄρχοντι τῶν δαιμονίων.", "en": {"kjv": "But when the Pharisees heard it, they said, This fellow doth not cast out devils, but by Beelzebub the prince of the devils.", "web": "But when the Pharisees heard it, they said, “This man does not cast out demons, except by Beelzebul, the prince of the demons.”", "bsb": "But when the Pharisees heard this, they said, “Only by Beelzebul, the prince of demons, does this man drive out demons.”", "asv": "But when the Pharisees heard it, they said, This man doth not cast out demons, but by Beelzebub the prince of the demons.", "ylt": "but the Pharisees having heard, said, `This one doth not cast out demons, except by Beelzeboul, ruler of the demons.'", "tyndale": "But when the Pharises hearde that they sayde: This felow dryveth ye devyls no nother wyse oute but by the helpe of Belzebub ye chefe of the devyls.", "dra": "But the Pharisees hearing it, said: This man casteth not out devils but by Beelzebub the prince of the devils.", "bbe": "But the Pharisees, hearing of it, said, This man only sends evil spirits out of men by Beelzebub, the ruler of evil spirits.", "geneva": "But when the Pharises heard it, they saide, This man casteth the deuils no otherwise out, but through Beelzebub the prince of deuils.", "wycliffe": "But the Farisees herden, and seiden, He this casteth not out feendis, but in Belsabub, prince of feendis.", "rotherham": "But, the Pharisees, hearing it, said, This one, doth not cast out the demons, save in Beelzebul ruler of the demons.", "weymouth": "The Pharisees heard it and said, \"This man only expels demons by the power of Baal-zebul, the Prince of demons.\"", "darby": "But the Pharisees, having heard [it], said, This [man] does not cast out demons, but by Beelzebub, prince of demons.", "twenty": "But the Pharisees heard of it and said: “He drives out demons only by the help of Baal-zebub the chief of the demons.”", "acv": "But when the Pharisees heard it, they said, This man does not cast out demons, except by Beelzebub the ruler of the demons.", "anderson": "But the Pharisees, when they heard it, said: This man does not cast out the demons, unless by Beelzebul, the prince of the demons.", "haweis": "But the Pharisees hearing them, said, This fellow casteth not out devils, but by Beelzebub, the prince of the devils.", "noyes": "But the Pharisees, hearing it, said, This man doth not cast out the demons, except through Beelzebul, the prince of the demons.", "webster": "But when the Pharisees heard [it], they said, This [man] doth not cast out demons, but by Beelzebub the prince of the demons.", "vulgate": "Pharisaei autem audientes dixerunt hic non eicit daemones nisi in Beelzebub principe daemoniorum;"}}, {"v": 25, "ref": "12:25", "o": "εἰδὼς ⸀δὲ τὰς ἐνθυμήσεις αὐτῶν εἶπεν αὐτοῖς· Πᾶσα βασιλεία μερισθεῖσα καθ’ ἑαυτῆς ἐρημοῦται, καὶ πᾶσα πόλις ἢ οἰκία μερισθεῖσα καθ’ ἑαυτῆς οὐ σταθήσεται.", "en": {"kjv": "And Jesus knew their thoughts, and said unto them, Every kingdom divided against itself is brought to desolation; and every city or house divided against itself shall not stand:", "web": "Knowing their thoughts, Jesus said to them, “Every kingdom divided against itself is brought to desolation, and every city or house divided against itself will not stand.", "bsb": "Knowing their thoughts, Jesus said to them, “Every kingdom divided against itself will be laid waste, and every city or household divided against itself will not stand.", "asv": "And knowing their thoughts he said unto them, Every kingdom divided against itself is brought to desolation; and every city or house divided against itself shall not stand:", "ylt": "And Jesus, knowing their thoughts, said to them, `Every kingdom having been divided against itself is desolated, and no city or house having been divided against itself, doth stand,", "tyndale": "But Iesus knewe their thoughtes and sayde to the. Every kingdome devided wt in it sylfe shalbe brought to naught. Nether shall eny cite or housholde devyded agest it sylfe cotynue.", "dra": "And Jesus knowing their thoughts, said to them: Every kingdom divided against itself shall be made desolate: and every city or house divided against itself shall not stand.", "bbe": "And having knowledge of their thoughts he said to them, Every kingdom having division in itself is made waste, and every town or house having division in itself will come to destruction.", "geneva": "But Iesus knew their thoughtes, and said to them, Euery kingdome deuided against it selfe, is brought to nought: and euery citie or house, deuided against it selfe, shall not stand.", "wycliffe": "And Jhesus, witynge her thouytis, seide to hem, Eche kingdom departid ayens it silf, schal be desolatid, and eche cite, or hous, departid ayens it self, schal not stonde.", "rotherham": "And, knowing their inward thoughts, he said unto them, Every kingdom divided against itself, is laid waste,—and, no city or house divided against itself, will stand;", "weymouth": "Knowing their thoughts He said to them, \"Every kingdom in which civil war has raged suffers desolation; and every city or house in which there is internal strife will be brought low.", "darby": "But he, knowing their thoughts, said to them, Every kingdom divided against itself is brought to desolation, and every city or house divided against itself will not subsist.", "twenty": "Jesus, however, was aware of what was passing in their minds, and said to them: “Any kingdom divided against itself becomes a desolation, and any town or household divided against itself will not last.", "acv": "And having known their thoughts Jesus said to them, Every kingdom divided against itself is brought to ruin, and every city or house divided against itself will not stand.", "anderson": "But Jesus, knowing their thoughts, said to them: Every kingdom divided against itself is brought to desolation. And no city or house divided against itself shall stand.", "haweis": "But Jesus knowing their thoughts, said unto them, Every kingdom divided against itself will be desolated; and every city, or family, divided against itself cannot subsist:", "noyes": "And he, knowing their thoughts, said to them, Every kingdom divided against itself is brought to desolation; and no city or house divided against itself will stand.", "webster": "And Jesus knew their thoughts, and said to them, Every kingdom divided against itself, is brought to desolation; and every city or house divided against itself, shall not stand.", "vulgate": "Iesus autem sciens cogitationes eorum dixit eis omne regnum divisum contra se desolatur et omnis civitas vel domus divisa contra se non stabit;"}}, {"v": 26, "ref": "12:26", "o": "καὶ εἰ ὁ Σατανᾶς τὸν Σατανᾶν ἐκβάλλει, ἐφ’ ἑαυτὸν ἐμερίσθη· πῶς οὖν σταθήσεται ἡ βασιλεία αὐτοῦ;", "en": {"kjv": "And if Satan cast out Satan, he is divided against himself; how shall then his kingdom stand?", "web": "If Satan casts out Satan, he is divided against himself. How then will his kingdom stand?", "bsb": "If Satan drives out Satan, he is divided against himself. How then can his kingdom stand?", "asv": "and if Satan casteth out Satan, he is divided against himself; how then shall his kingdom stand?", "ylt": "and if the Adversary doth cast out the Adversary, against himself he was divided, how then doth his kingdom stand?", "tyndale": "So if sata cast out sata the is he devyded agenst him sylfe. How shall then his kyngdome endure?", "dra": "And if Satan cast out Satan, he is divided against himself: how then shall his kingdom stand?", "bbe": "And if Satan sends out Satan, he makes war against himself; how then will he keep his kingdom?", "geneva": "So if Satan cast out Satan, he is deuided against himself: how shall then his kingdom endure?", "wycliffe": "And if Satanas castith out Satanas, he is departid ayens him silf; therfor hou schal his kingdom stonde?", "rotherham": "And, if, Satan, is casting, Satan, out, against himself, hath he become divided,—How then shall, his kingdom, stand?", "weymouth": "And if Satan is expelling Satan, he has begun to make war on himself: how therefore shall his kingdom last?", "darby": "And if Satan casts out Satan, he is divided against himself; how then shall his kingdom subsist?", "twenty": "So, if Satan drives Satan out, he must be divided against himself; and how, then, can his kingdom last?", "acv": "And if Satan casts out Satan, he is divided against himself. How then will his kingdom stand?", "anderson": "And if Satan cast out Satan, he is divided against himself; how then shall his kingdom stand?", "haweis": "so if Satan cast out Satan; he is divided against himself; how then can his kingdom subsist?", "noyes": "And if Satan cast out Satan, he is divided against himself; how then shall his kingdom stand?", "webster": "And if Satan casteth out Satan, he is divided against himself; how then shall his kingdom stand?", "vulgate": "et si Satanas Satanan eicit adversus se divisus est quomodo ergo stabit regnum eius;"}}, {"v": 27, "ref": "12:27", "o": "καὶ εἰ ἐγὼ ἐν Βεελζεβοὺλ ἐκβάλλω τὰ δαιμόνια, οἱ υἱοὶ ὑμῶν ἐν τίνι ἐκβάλλουσιν; διὰ τοῦτο αὐτοὶ ⸂κριταὶ ἔσονται ὑμῶν⸃.", "en": {"kjv": "And if I by Beelzebub cast out devils, by whom do your children cast them out? therefore they shall be your judges.", "web": "If I by Beelzebul cast out demons, by whom do your children cast them out? Therefore they will be your judges.", "bsb": "And if I drive out demons by Beelzebul, by whom do your sons drive them out? So then, they will be your judges.", "asv": "And if I by Beelzebub cast out demons, by whom do your sons cast them out? therefore shall they be your judges.", "ylt": "`And if I, by Beelzeboul, do cast out the demons, your sons--by whom do they cast out? because of this they--they shall be your judges.", "tyndale": "Also if I by ye helpe of Belzebub cast oute devyls: by whose helpe do youre chyldren cast them out? Therfore they shalbe youre iudges.", "dra": "And if I by Beelzebub cast out devils, by whom do your children cast them out? Therefore they shall be your judges.", "bbe": "And if I by Beelzebub send evil spirits out of men, by whom do your sons send them out? So let them be your judges.", "geneva": "Also if I through Beelzebub cast out deuils, by whom doe your children cast them out? Therefore they shall be your iudges.", "wycliffe": "And if Y in Belsabub caste out deuelis, in `whom youre sones casten out? Therfor thei schulen be youre domes men.", "rotherham": "And, if, I, in Beelzebul, am casting out the demons, In whom are, your sons, casting them out? Wherefore, they, shall be, judges of you.", "weymouth": "And if it is by Baal-zebul's power that I expel the demons, by whose power do your disciples expel them? They therefore shall be your judges.", "darby": "And if I cast out demons by Beelzebub, your sons, by whom do they cast [them] out? For this reason they shall be your judges.", "twenty": "And, if it is by Baal-zebub’s help that I drive out demons, by whose help is it that your own sons drive them out? Therefore they shall themselves be your judges.", "acv": "And if I cast out demons by Beelzebub, by whom do your sons cast them out? Because of this they will be your judges.", "anderson": "And if I cast out demons by Beelzebul, by whom do your sons cast them out? For this reason, they shall be your judges.", "haweis": "And if I by Beelzebub cast out devils, by whom do your sons cast them out? therefore shall they be your judges.", "noyes": "And if I cast out the demons through Beelzebul, through whom do your sons cast them out? Therefore shall they be judges of you.", "webster": "And if I by Beelzebub cast out demons, by whom do your children expel [them]? therefore they shall be your judges.", "vulgate": "et si ego in Beelzebub eicio daemones filii vestri in quo eiciunt ideo ipsi iudices erunt vestri;"}}, {"v": 28, "ref": "12:28", "o": "εἰ δὲ ἐν πνεύματι θεοῦ ἐγὼ ἐκβάλλω τὰ δαιμόνια, ἄρα ἔφθασεν ἐφ’ ὑμᾶς ἡ βασιλεία τοῦ θεοῦ.", "en": {"kjv": "But if I cast out devils by the Spirit of God, then the kingdom of God is come unto you.", "web": "But if I by the Spirit of God cast out demons, then the Kingdom of God has come upon you.", "bsb": "But if I drive out demons by the Spirit of God, then the kingdom of God has come upon you.", "asv": "But if I by the Spirit of God cast out demons, then is the kingdom of God come upon you.", "ylt": "`But if I, by the Spirit of God, do cast out the demons, then come already unto you did the reign of God.", "tyndale": "But if I cast out the devyls by the sprite of God: then is the kyngdome of god come on you?", "dra": "But if I by the Spirit of God cast out devils, then is the kingdom of God come upon you.", "bbe": "But if I by the Spirit of God send out evil spirits, then is the kingdom of God come on you.", "geneva": "But if I cast out deuils by ye Spirit of God, then is the kingdome of God come vnto you.", "wycliffe": "But if Y in the Spirit of God caste out feendis, thanne the kyngdom of God is comen in to you.", "rotherham": "But, if, in God’s Spirit, I, am casting out the demons, then doubtless hath come upon you unawares, the kingdom of God!", "weymouth": "But if it is by the power of the Spirit of God that I expel the demons, it is evident that the Kingdom of God has come upon you.", "darby": "But if I by [the] Spirit ofGod cast out demons, then indeed the kingdom ofGod is come upon you.", "twenty": "But, if it is by the help of the Spirit of God that I drive out demons, then the Kingdom of God must already be upon you.", "acv": "But if I cast out demons by the Spirit of God, then the kingdom of God has come near you.", "anderson": "But if I cast out demons by the Spirit of God, then the kingdom of God has already come upon you.", "haweis": "But if I by the Spirit of God cast out the devils, then truly the kingdom of God is come unto you.", "noyes": "But if I cast out the demons through the Spirit of God, then hath the kingdom of God already come to you.", "webster": "But if I cast out demons by the Spirit of God, then the kingdom of God is come to you.", "vulgate": "si autem ego in Spiritu Dei eicio daemones igitur pervenit in vos regnum Dei;"}}, {"v": 29, "ref": "12:29", "o": "ἢ πῶς δύναταί τις εἰσελθεῖν εἰς τὴν οἰκίαν τοῦ ἰσχυροῦ καὶ τὰ σκεύη αὐτοῦ ⸀ἁρπάσαι, ἐὰν μὴ πρῶτον δήσῃ τὸν ἰσχυρόν; καὶ τότε τὴν οἰκίαν αὐτοῦ ⸀διαρπάσει.", "en": {"kjv": "Or else how can one enter into a strong man’s house, and spoil his goods, except he first bind the strong man? and then he will spoil his house.", "web": "Or how can one enter into the house of the strong man, and plunder his goods, unless he first bind the strong man? Then he will plunder his house.", "bsb": "Or again, how can anyone enter a strong man’s house and steal his possessions, unless he first ties up the strong man? Then he can plunder his house.", "asv": "Or how can one enter into the house of the strong man, and spoil his goods, except he first bind the strong man? and then he will spoil his house.", "ylt": "`Or how is one able to go into the house of the strong man, and to plunder his goods, if first he may not bind the strong man? and then his house he will plunder.", "tyndale": "Ether how can a ma enter into a stroge manes housse and violently take awaye his goodes: excepte he fyrst binde ye stroge man and the spoyle his housse?", "dra": "Or how can any one enter into the house of the strong, and rifle his goods, unless he first bind the strong? and then he will rifle his house.", "bbe": "Or how may one go into a strong man's house and take his goods, if he does not first put cords round the strong man? and then he may take his goods.", "geneva": "Els howe can a man enter into a strong mans house and spoyle his goods, except he first bind the strong man, and then spoile his house.", "wycliffe": "Ethir hou may ony man entre in to the hous of a stronge man, and take awey hise vesselis, but `he first bynde the stronge man, and thanne he schal spuyle his hous?", "rotherham": "Or how can one enter the house of the mighty and, seize his goods, unless, first, he bind the mighty one? and, then, his house, he will plunder.", "weymouth": "Again, how can any one enter the house of a strong man and carry off his goods, unless first of all he masters and secures the strong man: then he will ransack his house.", "darby": "Or how can any one enter into the house of the strong [man] and plunder his goods, unless first he bind the strong [man]? and then he will plunder his house.", "twenty": "How, again, can any one get into a strong man’s house and carry off his goods, without first securing him? And not till then will he plunder his house.", "acv": "Or how can any man enter into the house of the strong man, and plunder his goods, unless he first binds the strong man? And then he will plunder his house.", "anderson": "Or, how can any one enter the house of the strong man and spoil his goods, unless he first bind the strong man? and then he will plunder his house.", "haweis": "Else how can one enter into a strong man’s house and plunder his goods, except he first bind the strong man, and then will he plunder his goods?", "noyes": "Or how can one enter into a strong man’s house, and seize upon his goods, unless he first bind the strong man, and then plunder his house?", "webster": "Or else, how can one enter into a strong man's house, and seize his goods, except he shall first bind the strong man? and then he will plunder his house.", "vulgate": "aut quomodo potest quisquam intrare in domum fortis et vasa eius diripere nisi prius alligaverit fortem et tunc domum illius diripiat;"}}, {"v": 30, "ref": "12:30", "o": "ὁ μὴ ὢν μετ’ ἐμοῦ κατ’ ἐμοῦ ἐστιν, καὶ ὁ μὴ συνάγων μετ’ ἐμοῦ σκορπίζει.", "en": {"kjv": "He that is not with me is against me; and he that gathereth not with me scattereth abroad.", "web": "“He who is not with me is against me, and he who doesn’t gather with me, scatters.", "bsb": "He who is not with Me is against Me, and he who does not gather with Me scatters.", "asv": "He that is not with me is against me; and he that gathereth not with me scattereth.", "ylt": "`He who is not with me is against me, and he who is not gathering with me, doth scatter.", "tyndale": "He that is not wt me is agaynst me. And he yt gaddereth not wt me scattereth abrode.", "dra": "He that is not with me, is against me: and he that gathereth not with me, scattereth.", "bbe": "Whoever is not with me is against me; and he who does not take part with me in getting people together, is driving them away.", "geneva": "He that is not with me, is against me: and he that gathereth not with me, scattereth.", "wycliffe": "He that is not with me, is ayens me; and he that gaderith not togidere with me, scaterith abrood.", "rotherham": "He that is no with me, is, against me,—and, he that gathereth not with me, scattereth", "weymouth": "\"The man who is not with me is against me, and he who is not gathering with me is scattering abroad.", "darby": "He that is not with me is against me, and he that gathers not with me scatters.", "twenty": "He who is not with me is against me, and he who does not help me to gather is scattering.", "acv": "He who is not with me is against me, and he who does not gather with me scatters.", "anderson": "He that is not with me, is against me; and he that gathers not with me, scatters.", "haweis": "He that is not with me, is against me; and he that associates not with me, scattereth abroad.", "noyes": "He that is not with me is against me; and he that gathereth not with me scattereth abroad.", "webster": "He that is not with me, is against me; and he that gathereth not with me, scattereth abroad.", "vulgate": "qui non est mecum contra me est et qui non congregat mecum spargit;"}}, {"v": 31, "ref": "12:31", "o": "διὰ τοῦτο λέγω ὑμῖν, πᾶσα ἁμαρτία καὶ βλασφημία ἀφεθήσεται τοῖς ἀνθρώποις, ἡ δὲ τοῦ πνεύματος βλασφημία οὐκ ⸀ἀφεθήσεται.", "en": {"kjv": "Wherefore I say unto you, All manner of sin and blasphemy shall be forgiven unto men: but the blasphemy against the Holy Ghost shall not be forgiven unto men.", "web": "Therefore I tell you, every sin and blasphemy will be forgiven men, but the blasphemy against the Spirit will not be forgiven men.", "bsb": "Therefore I tell you, every sin and blasphemy will be forgiven men, but the blasphemy against the Spirit will not be forgiven.", "asv": "Therefore I say unto you, Every sin and blasphemy shall be forgiven unto men; but the blasphemy against the Spirit shall not be forgiven.", "ylt": "Because of this I say to you, all sin and evil speaking shall be forgiven to men, but the evil speaking of the Spirit shall not be forgiven to men.", "tyndale": "Wherfore I say vnto you all maner of synne and blasphemy shalbe forgeven vnto men: but the blasphemy of ye sprite shall not be forgeven vnto men.", "dra": "Therefore I say to you: Every sin and blasphemy shall be forgiven men, but the blasphemy of the Spirit shall not be forgiven.", "bbe": "So I say to you, Every sin and every evil word against God will have forgiveness; but for evil words against the Spirit there will be no forgiveness.", "geneva": "Wherefore I say vnto you, euery sinne and blasphemie shalbe forgiuen vnto men: but the blasphemie against the holy Ghost shall not be forgiuen vnto men.", "wycliffe": "Therfor I seie to you, al synne and blasfemye shal be foryouun to men, but `the spirit of blasfemye shal not be foryouun.", "rotherham": "Wherefore, I say unto you, All sin and profane speaking, shall be forgiven unto men,—but, the speaking profanely of the Spirit, shall not be forgiven;", "weymouth": "This is why I tell you that men may find forgiveness for every other sin and impious word, but that for impious speaking against the Holy Spirit they shall find no forgiveness.", "darby": "For this reason I say unto you, Every sin and injurious speaking shall be forgiven to men, but speaking injuriously of the Spirit shall not be forgiven to men.", "twenty": "Therefore, I tell you, men will be forgiven every sin and slander; but slander against the Holy Spirit will not be forgiven.", "acv": "Because of this I say to you, every sin and blasphemy will be forgiven to men, but the blasphemy of the Spirit will not be forgiven men.", "anderson": "Therefore I say to you, That every sin and impious speech shad be forgiven men: but the impious speech against the Spirit shall not be forgiven men.", "haweis": "Therefore I say unto you, All sin and blasphemy shall be forgiven to men; but the blasphemy against the Spirit shall not be forgiven to men.", "noyes": "Therefore I say to you, All manner of sin and evil-speaking will be forgiven to men; but blasphemy against the Spirit will not be forgiven.", "webster": "Wherefore I say to you, All manner of sin and blasphemy shall be forgiven to men: but the blasphemy [against] the [Holy] Spirit shall not be forgiven to men.", "vulgate": "ideo dico vobis omne peccatum et blasphemia remittetur hominibus Spiritus autem blasphemia non remittetur;"}}, {"v": 32, "ref": "12:32", "o": "καὶ ὃς ἐὰν εἴπῃ λόγον κατὰ τοῦ υἱοῦ τοῦ ἀνθρώπου, ἀφεθήσεται αὐτῷ· ὃς δ’ ἂν εἴπῃ κατὰ τοῦ πνεύματος τοῦ ἁγίου, οὐκ ἀφεθήσεται αὐτῷ οὔτε ἐν ⸂τούτῳ τῷ⸃ αἰῶνι οὔτε ἐν τῷ μέλλοντι.", "en": {"kjv": "And whosoever speaketh a word against the Son of man, it shall be forgiven him: but whosoever speaketh against the Holy Ghost, it shall not be forgiven him, neither in this world, neither in the world to come.", "web": "Whoever speaks a word against the Son of Man, it will be forgiven him; but whoever speaks against the Holy Spirit, it will not be forgiven him, neither in this age, nor in that which is to come.", "bsb": "Whoever speaks a word against the Son of Man will be forgiven, but whoever speaks against the Holy Spirit will not be forgiven, either in this age or in the one to come.", "asv": "And whosoever shall speak a word against the Son of man, it shall be forgiven him; but whosoever shall speak against the Holy Spirit, it shall not be forgiven him, neither in this world, nor in that which is to come.", "ylt": "And whoever may speak a word against the Son of Man it shall be forgiven to him, but whoever may speak against the Holy Spirit, it shall not be forgiven him, neither in this age, nor in that which is coming.", "tyndale": "And whoso ever speaketh a worde agaynst the sonne of man it shalbe forgeven him. But whosoever speaketh agaynst the holy goost it shall not be forgeven hym: no nether in this worlde nether in the worlde to come.", "dra": "And whosoever shall speak a word against the Son of man, it shall be forgiven him: but he that shall speak against the Holy Ghost, it shall not be forgiven him neither in this world, nor in the world to come.", "bbe": "And whoever says a word against the Son of man, will have forgiveness; but whoever says a word against the Holy Spirit, will not have forgiveness in this life or in that which is to come.", "geneva": "And whosoeuer shall speake a word against the Sonne of man, it shall be forgiuen him: but whosoeuer shall speake against the holy Ghost, it shall not be forgiuen him, neither in this worlde, nor in the worlde to come.", "wycliffe": "And who euere seith a word ayens mannus sone, it shal be foryouun to him; but who that seieth a word ayens the Hooli Goost, it shal not be foryouun to hym, nether in this world, ne in `the tothir.", "rotherham": "And, whosoever shall speak a word against the Son of Man, it shall be forgiven him,—but, whosoever shall speak against the Holy Spirit, it shall not be forgiven him, either in this age, or the coming.", "weymouth": "And whoever shall speak against the Son of Man may obtain forgiveness; but whoever speaks against the Holy Spirit, neither in this nor in the coming age shall he obtain forgiveness.\"", "darby": "And whosoever shall have spoken a word against the Son of man, it shall be forgiven him; but whosoever shall speak against the Holy Spirit, it shall not be forgiven him, neither in this age nor in the coming [one].", "twenty": "Whoever speaks against the Son of Man will be forgiven, but whoever speaks against the Holy Spirit will not be forgiven, either in the present age, or in the age to come.", "acv": "And whoever speaks a word against the Son of man, it will be forgiven him, but whoever speaks against the Holy Spirit, it will not be forgiven him, neither in the present age, nor in the one that is coming.", "anderson": "And whoever shall speak a word against the Son of man, it shall be forgiven him: but whoever shall speak against the Holy Spirit, it shall not be forgiven him, either in the present age, or in that which is to come.", "haweis": "And whosoever may speak a word against the Son of man, it shall be forgiven him: but whosoever shall speak against the Holy Ghost, it shall not be forgiven him, neither in this world, nor in the world to come.", "noyes": "And whoever speaketh a word against the Son of man, it will be forgiven him; but whoever speaketh against the Holy Spirit, it will not be forgiven him, either in this world, or in the world to come.", "webster": "And whoever speaketh a word against the Son of man, it shall be forgiven him: but whoever speaketh against the Holy Spirit, it shall not be forgiven him, neither in this world, neither in the [world] to come.", "vulgate": "et quicumque dixerit verbum contra Filium hominis remittetur ei qui autem dixerit contra Spiritum Sanctum non remittetur ei neque in hoc saeculo neque in futuro;"}}, {"v": 33, "ref": "12:33", "o": "Ἢ ποιήσατε τὸ δένδρον καλὸν καὶ τὸν καρπὸν αὐτοῦ καλόν, ἢ ποιήσατε τὸ δένδρον σαπρὸν καὶ τὸν καρπὸν αὐτοῦ σαπρόν· ἐκ γὰρ τοῦ καρποῦ τὸ δένδρον γινώσκεται.", "en": {"kjv": "Either make the tree good, and his fruit good; or else make the tree corrupt, and his fruit corrupt: for the tree is known by his fruit.", "web": "“Either make the tree good, and its fruit good, or make the tree corrupt, and its fruit corrupt; for the tree is known by its fruit.", "bsb": "Make a tree good and its fruit will be good, or make a tree bad and its fruit will be bad; for a tree is known by its fruit.", "asv": "Either make the tree good, and its fruit good; or make the tree corrupt, and its fruit corrupt: for the tree is known by its fruit.", "ylt": "`Either make the tree good, and its fruit good, or make the tree bad, and its fruit bad, for from the fruit is the tree known.", "tyndale": "Ether make ye tree good and his frute good also: or els make ye tree evyll and his frute evyll also. For ye tree is knowe by his frute.", "dra": "Either make the tree good and its fruit good: or make the tree evil, and its fruit evil. For by the fruit the tree is known.", "bbe": "Make the tree good, and its fruit good; or make the tree bad, and its fruit bad; for by its fruit you will get knowledge of the tree.", "geneva": "Either make the tree good, and his fruite good: or els make the tree euill, and his fruite euil: for the tree is knowen by the fruite.", "wycliffe": "Ethir make ye the tree good, and his fruyt good; ether make ye the tree yuel and his fruyt yuel; for a tree is knowun of the fruyt.", "rotherham": "Either make the tree good, and its fruit good, or make the tree worthless, and its fruit worthless; for, from the fruit, the tree is known.", "weymouth": "\"Either grant the tree to be wholesome and its fruit wholesome, or the tree poisonous and its fruit poisonous; for the tree is known by its fruit.", "darby": "Either make the tree good, and its fruit good; or make the tree corrupt, and its fruit corrupt. For from the fruit the tree is known.", "twenty": "You must assume either that both tree and fruit are good, or that both tree and fruit are worthless; since it is by its fruits that a tree is known.", "acv": "Either make the tree good, and its fruit good, or make the tree corrupt, and its fruit corrupt, for the tree is known by its fruit.", "anderson": "Either make the tree good, and its fruit good; or make the tree unsound, and its fruit unsound. For by the fruit the tree is known.", "haweis": "Either make the tree good, and its fruit good; or make the tree corrupt, and its fruit corrupt: for the tree is known by the fruit.", "noyes": "Either say that the tree is good, and its fruit good; or say that the tree is bad, and its fruit bad; for the tree is known by its fruit. Brood of vipers!", "webster": "Either make the tree good, and its fruit good; or else make the tree corrupt, and its fruit corrupt: for the tree is known by [its] fruit.", "vulgate": "aut facite arborem bonam et fructum eius bonum aut facite arborem malam et fructum eius malum siquidem ex fructu arbor agnoscitur;"}}, {"v": 34, "ref": "12:34", "o": "γεννήματα ἐχιδνῶν, πῶς δύνασθε ἀγαθὰ λαλεῖν πονηροὶ ὄντες; ἐκ γὰρ τοῦ περισσεύματος τῆς καρδίας τὸ στόμα λαλεῖ.", "en": {"kjv": "O generation of vipers, how can ye, being evil, speak good things? for out of the abundance of the heart the mouth speaketh.", "web": "You offspring of vipers, how can you, being evil, speak good things? For out of the abundance of the heart, the mouth speaks.", "bsb": "You brood of vipers, how can you who are evil say anything good? For out of the overflow of the heart, the mouth speaks.", "asv": "Ye offspring of vipers, how can ye, being evil, speak good things? for out of the abundance of the heart the mouth speaketh.", "ylt": "`Brood of vipers! how are ye able to speak good things--being evil? for out of the abundance of the heart doth the mouth speak.", "tyndale": "O generacio of viperes how can ye saye well whe ye youre selves are evyll? For of ye aboundace of the hert ye mouthe speaketh.", "dra": "O generation of vipers, how can you speak good things, whereas you are evil? for out of the abundance of the heart the mouth speaketh.", "bbe": "You offspring of snakes, how are you, being evil, able to say good things? because out of the heart's store come the words of the mouth.", "geneva": "O generations of vipers, howe can you speake good things, when ye are euill? For of the abundance of the heart the mouth speaketh.", "wycliffe": "Ye generacioun of eddris, hou moun ye speke goode thingis, whanne ye ben yuele? For the mouth spekith of plente of the herte.", "rotherham": "Broods of vipers! How can ye speak, good things, being, evil? For, out of the abundance of the heart, the mouth speaketh.", "weymouth": "O vipers' brood, how can you speak what is good when you are evil? For it is from the overflow of the heart that the mouth speaks.", "darby": "Offspring of vipers! how can ye speak good things, being wicked? For of the abundance of the heart the mouth speaks.", "twenty": "You brood of vipers! how can you, evil as you are, say anything good? For what fills the heart will rise to the lips.", "acv": "Ye offspring of vipers, how can ye, being evil, speak good things? For out of the abundance of the heart the mouth speaks.", "anderson": "Generation of vipers, how can you, being evil, speak good things? For out of the abundance of the heart, the mouth speaks.", "haweis": "Ye broods of vipers, how can ye speak good things, yourselves being wicked? for out of the abundance of the heart the mouth speaketh.", "noyes": "How can ye, evil as ye are, speak good things? For out of the abundance of the heart the mouth speaketh.", "webster": "O generation of vipers, how can ye, being evil, speak good things? for out of the abundance of the heart, the mouth speaketh.", "vulgate": "progenies viperarum quomodo potestis bona loqui cum sitis mali ex abundantia enim cordis os loquitur;"}}, {"v": 35, "ref": "12:35", "o": "ὁ ἀγαθὸς ἄνθρωπος ἐκ τοῦ ἀγαθοῦ θησαυροῦ ἐκβάλλει ἀγαθά, καὶ ὁ πονηρὸς ἄνθρωπος ἐκ τοῦ πονηροῦ θησαυροῦ ἐκβάλλει πονηρά.", "en": {"kjv": "A good man out of the good treasure of the heart bringeth forth good things: and an evil man out of the evil treasure bringeth forth evil things.", "web": "The good man out of his good treasure brings out good things, and the evil man out of his evil treasure brings out evil things.", "bsb": "The good man brings good things out of his good store of treasure, and the evil man brings evil things out of his evil store of treasure.", "asv": "The good man out of his good treasure bringeth forth good things: and the evil man out of his evil treasure bringeth forth evil things.", "ylt": "The good man out of the good treasure of the heart doth put forth the good things, and the evil man out of the evil treasure doth put forth evil things.", "tyndale": "A good ma oute of ye good treasure of his hert bringeth forth good thynges. And an evyll man out of his evyll treasure bringeth forth evyll thinges.", "dra": "A good man out of a good treasure bringeth forth good things: and an evil man out of an evil treasure bringeth forth evil things.", "bbe": "The good man out of his good store gives good things; and the evil man out of his evil store gives evil things.", "geneva": "A good man out of the good treasure of his heart bringeth foorth good things: and an euill man out of an euill treasure, bringeth forth euill things.", "wycliffe": "A good man bryngith forth good thingis of good tresoure, and an yuel man bringith forth yuel thingis of yuel tresoure.", "rotherham": "The good man, out of the good treasure, putteth forth, good things; and, the evil man, out of the evil treasure, putteth forth, evil things.", "weymouth": "A good man from his good store produces good things, and a bad man from his bad store produces bad things.", "darby": "The good man out of the good treasure brings forth good things; and the wicked man out of the wicked treasure brings forth wicked things.", "twenty": "A good man, from his good stores, produces good things; while an evil man, from his evil stores, produces evil things.", "acv": "The good man out of his good treasure brings forth good things, and the evil man out of his evil treasure brings forth evil things.", "anderson": "The good man, out of his good treasury, brings forth good things; and the evil man, out of his evil treasury, brings forth evil things.", "haweis": "A good man out of the good treasure of his heart bringeth forth good things: and a wicked man out of the evil treasure of his heart bringeth forth evil things.", "noyes": "The good man, from his good treasure, bringeth out good things; and the evil man, from his evil treasure, bringeth out evil things.", "webster": "A good man, out of the good treasure of the heart, bringeth forth good things: and an evil man, out of the evil treasure, bringeth forth evil things.", "vulgate": "bonus homo de bono thesauro profert bona et malus homo de malo thesauro profert mala;"}}, {"v": 36, "ref": "12:36", "o": "λέγω δὲ ὑμῖν ὅτι πᾶν ῥῆμα ἀργὸν ὃ ⸀λαλήσουσιν οἱ ἄνθρωποι, ἀποδώσουσιν περὶ αὐτοῦ λόγον ἐν ἡμέρᾳ κρίσεως·", "en": {"kjv": "But I say unto you, That every idle word that men shall speak, they shall give account thereof in the day of judgment.", "web": "I tell you that every idle word that men speak, they will give account of it in the day of judgment.", "bsb": "But I tell you that men will give an account on the day of judgment for every careless word they have spoken.", "asv": "And I say unto you, that every idle word that men shall speak, they shall give account thereof in the day of judgment.", "ylt": "`And I say to you, that every idle word that men may speak, they shall give for it a reckoning in a day of judgment;", "tyndale": "But I say vnto you that of every ydell worde that men shall have spoken: they shall geve acountes at the daye of iudgement.", "dra": "But I say unto you, that every idle word that men shall speak, they shall render an account for it in the day of judgment.", "bbe": "And I say to you that in the day when they are judged, men will have to give an account of every foolish word they have said.", "geneva": "But I say vnto you, that of euery idle word that men shall speake, they shall giue account thereof at the day of iudgement.", "wycliffe": "And Y seie to you, that of euery idel word, that men speken, thei schulen yelde resoun therof in the dai of doom;", "rotherham": "But I say unto you, That, every useless expression that men shall utter, they shall render, concerning it, an account, in a day of judgment;", "weymouth": "But I tell you that for every careless word that men shall speak they will be held accountable on the day of Judgement.", "darby": "But I say unto you, that every idle word which men shall say, they shall render an account of it in judgment-day:", "twenty": "I tell you that for every careless thing that men say, they must answer on the ‘Day of Judgment.’", "acv": "But I say to you, that every idle word, whatever men may speak, they will render account about it in the day of judgment.", "anderson": "But I say to you, That for every idle word which men speak, they shall give account in the day of judgment.", "haweis": "But I tell you, That every idle word which men speak, for it shall they give an account in the day of judgment.", "noyes": "And I say to you, that for every idle word that men shall speak, they will give account in the day of judgment.", "webster": "But I say to you, That for every idle word that men shall speak, they shall give account in the day of judgment.", "vulgate": "dico autem vobis quoniam omne verbum otiosum quod locuti fuerint homines reddent rationem de eo in die iudicii;"}}, {"v": 37, "ref": "12:37", "o": "ἐκ γὰρ τῶν λόγων σου δικαιωθήσῃ, καὶ ἐκ τῶν λόγων σου καταδικασθήσῃ.", "en": {"kjv": "For by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "web": "For by your words you will be justified, and by your words you will be condemned.”", "bsb": "For by your words you will be acquitted, and by your words you will be condemned.”", "asv": "For by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "ylt": "for from thy words thou shalt be declared righteous, and from thy words thou shalt be declared unrighteous.'", "tyndale": "For by thy wordes thou shalt be iustifyed: and by thy wordes thou shalt be condemned.", "dra": "For by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "bbe": "For by your words will your righteousness be seen, and by your words you will be judged.", "geneva": "For by thy wordes thou shalt be iustified, and by thy wordes thou shalt be condemned.", "wycliffe": "for of thi wordis thou schalt be iustified, and of thi wordis thou shalt be dampned.", "rotherham": "For, by thy words, shalt thou be, justified, and, by thy words, shalt thou be condemned.", "weymouth": "For each of you by his words shall be justified, or by his words shall be condemned.\"", "darby": "for by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "twenty": "For it is by your words that you will be acquitted, and by your words that you will be condemned.”", "acv": "For from thy words thou will be justified, and from thy words thou will be condemned.", "anderson": "For by your words you shall be justified, and by your words you shall be condemned.", "haweis": "For by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "noyes": "For by thy words thou wilt be justified, and by thy words thou wilt be condemned.", "webster": "For by thy words thou shalt be justified, and by thy words thou shalt be condemned.", "vulgate": "ex verbis enim tuis iustificaberis et ex verbis tuis condemnaberis;"}}, {"v": 38, "ref": "12:38", "o": "Τότε ἀπεκρίθησαν ⸀αὐτῷ τινες τῶν γραμματέων καὶ Φαρισαίων λέγοντες· Διδάσκαλε, θέλομεν ἀπὸ σοῦ σημεῖον ἰδεῖν.", "en": {"kjv": "Then certain of the scribes and of the Pharisees answered, saying, Master, we would see a sign from thee.", "web": "Then certain of the scribes and Pharisees answered, “Teacher, we want to see a sign from you.”", "bsb": "Then some of the scribes and Pharisees said to Him, “Teacher, we want to see a sign from You.”", "asv": "Then certain of the scribes and Pharisees answered him, saying, Teacher, we would see a sign from thee.", "ylt": "Then answered certain of the scribes and Pharisees, saying, `Teacher, we will to see a sign from thee.'", "tyndale": "Then answered certeyne of the scribes and of the Pharises sayinge: Master we wolde fayne se a sygne of ye.", "dra": "Then some of the scribes and Pharisees answered him, saying: Master, we would see a sign from thee.", "bbe": "Then some of the scribes and Pharisees, hearing this, said to him, Master, we are looking for a sign from you.", "geneva": "Then answered certaine of ye Scribes and of the Pharises, saying, Master, we would see a signe of thee.", "wycliffe": "Thanne summe of the scribis and Farisees answeriden to hym, and seiden, Mayster, we wolen se a tokne of thee.", "rotherham": "Then, answered him, certain of the Scribes and Pharisees, saying, Teacher! we desire of thee, a sign, to behold.", "weymouth": "Then He was accosted by some of the Scribes and of the Pharisees who said, \"Teacher, we wish to see a sign given by you.\"", "darby": "Then answered him some of the scribes and Pharisees, saying, Teacher, we desire to see a sign from thee.", "twenty": "At this point, some Teachers of the Law and Pharisees interposed. “Teacher,” they said, “we want to see some sign from you.”", "acv": "Then some of the scholars and Pharisees answered, saying, Teacher, we want to see a sign from thee.", "anderson": "Then some of the scribes and Pharisees answered and said: Teacher, we wish to see a sign from you.", "haweis": "Then certain of the scribes and Pharisees addressed him, saying, Master, we desire to see a sign from thee.", "noyes": "Then some of the scribes and Pharisees answered him, saying, Teacher, we wish to see a sign from thee.", "webster": "Then certain of the scribes and of the Pharisees answered, saying, Master, we would see a sign from thee.", "vulgate": "tunc responderunt ei quidam de scribis et Pharisaeis dicentes magister volumus a te signum videre;"}}, {"v": 39, "ref": "12:39", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν αὐτοῖς· Γενεὰ πονηρὰ καὶ μοιχαλὶς σημεῖον ἐπιζητεῖ, καὶ σημεῖον οὐ δοθήσεται αὐτῇ εἰ μὴ τὸ σημεῖον Ἰωνᾶ τοῦ προφήτου.", "en": {"kjv": "But he answered and said unto them, An evil and adulterous generation seeketh after a sign; and there shall no sign be given to it, but the sign of the prophet Jonas:", "web": "But he answered them, “An evil and adulterous generation seeks after a sign, but no sign will be given it but the sign of Jonah the prophet.", "bsb": "Jesus replied, “A wicked and adulterous generation demands a sign, but none will be given it except the sign of the prophet Jonah.", "asv": "But he answered and said unto them, An evil and adulterous generation seeketh after a sign; and there shall no sign be given to it but the sign of Jonah the prophet:", "ylt": "And he answering said to them, `A generation, evil and adulterous, doth seek a sign, and a sign shall not be given to it, except the sign of Jonah the prophet;", "tyndale": "He answered and sayde to the: The evyll and advoutrous generacio seketh a signe but ther shall no signe be geve to the saue the signe of the Prophete Ionas.", "dra": "Who answering said to them: An evil and adulterous generation seeketh a sign: and a sign shall not be given it, but the sign of Jonas the prophet.", "bbe": "But he, answering, said to them, An evil and false generation is looking for a sign; and no sign will be given to it but the sign of the prophet Jonah:", "geneva": "But he answered and said to them, An euill and adulterous generation seeketh a signe, but no signe shall be giuen vnto it, saue that signe of the Prophet Ionas.", "wycliffe": "Which answeride, and seide to hem, An yuel kynrede and a spouse brekere sekith a tokene, and a tokene shal not be youun to it, but the tokene of Jonas, the prophete.", "rotherham": "But, he, answering, said unto them, A wicked and adulterous generation, a sign, doth seek, and, a sign, will not be, given, it, save the sign of Jonah the prophet.", "weymouth": "\"Wicked and faithless generation!\" He replied, \"they clamour for a sign, but none shall be given to them except the sign of the Prophet Jonah.", "darby": "But he, answering, said to them, A wicked and adulterous generation seeks after a sign, and a sign shall not be given to it save the sign of Jonas the prophet.", "twenty": "“It is a wicked and unfaithful generation,” answered Jesus, “that is asking for a sign, and no sign shall be given it except the sign of the Prophet Jonah.", "acv": "But having answered, he said to them, An evil and adulterous generation seeks after a sign, and no sign will be given to it except the sign of Jonah the prophet.", "anderson": "But he answered and said to them: A wicked and adulterous generation seeks for a sign; and no sign shall be given to it, but the sign of Jonah the prophet.", "haweis": "But he answered and said unto them, A wicked and adulterous generation seeketh a sign; and no sign shall be given it, but the sign of Jonah the prophet:", "noyes": "But he answered and said to them, A wicked and adulterous generation is seeking for a sign; and no sign will be given to it, but the sign of Jonah the prophet.", "webster": "But he answered and said to them, An evil and adulterous generation seeketh for a sign, and there shall no sign be given to it, but the sign of the prophet Jonah.", "vulgate": "qui respondens ait illis generatio mala et adultera signum quaerit et signum non dabitur ei nisi signum Ionae prophetae;"}}, {"v": 40, "ref": "12:40", "o": "ὥσπερ γὰρ ἦν Ἰωνᾶς ἐν τῇ κοιλίᾳ τοῦ κήτους τρεῖς ἡμέρας καὶ τρεῖς νύκτας, οὕτως ἔσται ὁ υἱὸς τοῦ ἀνθρώπου ἐν τῇ καρδίᾳ τῆς γῆς τρεῖς ἡμέρας καὶ τρεῖς νύκτας.", "en": {"kjv": "For as Jonas was three days and three nights in the whale’s belly; so shall the Son of man be three days and three nights in the heart of the earth.", "web": "For as Jonah was three days and three nights in the belly of the whale, so will the Son of Man be three days and three nights in the heart of the earth.", "bsb": "For as Jonah was three days and three nights in the belly of the great fish, so the Son of Man will be three days and three nights in the heart of the earth.", "asv": "for as Jonah was three days and three nights in the belly of the whale; so shall the Son of man be three days and three nights in the heart of the earth.", "ylt": "for, as Jonah was in the belly of the fish three days and three nights, so shall the Son of Man be in the heart of the earth three days and three nights.", "tyndale": "For as Ionas was thre dayes and thre nyghtes in the whales belly: soo shall ye sonne of man be thre dayes and thre nyghtes in ye hert of ye erth.", "dra": "For as Jonas was in the whale's belly three days and three nights: so shall the Son of man be in the heart of the earth three days and three nights.", "bbe": "For as Jonah was three days and three nights in the stomach of the great fish, so will the Son of man be three days and three nights in the heart of the earth.", "geneva": "For as Ionas was three daies and three nights in the whales belly: so shall the Sonne of man be three daies and three nights in ye heart of the earth.", "wycliffe": "For as Jonas was in the wombe of a whal thre daies and thre nyytis, so mannus sone shal be in the herte of the erthe thre daies and thre nyytis.", "rotherham": "For, just as was Jonah in the belly of the sea-monster three days and three nights, so, will be the Son of Man, in the heart of the earth, three days and three nights.", "weymouth": "For just as Jonah was three days in the sea-monster's belly, so will the Son of Man be three days in the heart of the earth.", "darby": "For even as Jonas was in the belly of the great fish three days and three nights, thus shall the Son of man be in the heart of the earth three days and three nights.", "twenty": "For, just as ‘Jonah was inside the sea-monster three days and three nights,’ so shall the Son of Man be three days and three nights in the heart of the earth.", "acv": "For as Jonah was in the belly of the sea-creature three days and three nights, so the Son of man will be in the heart of the earth three days and three nights.", "anderson": "For as Jonah was three days and three nights in the belly of the great fish, so shall the Son of man be three days and three nights in the heart of the earth.", "haweis": "for as Jonah was in the belly of the whale three days and three nights; so shall the Son of man be in the heart of the earth three days and three nights.", "noyes": "For as Jonah was three days and three nights in the belly of the great fish, so will the Son of man be three days and three nights in the heart of the earth.", "webster": "For as Jonah was three days and three nights in the whale's belly: so shall the Son of man be three days and three nights in the heart of the earth.", "vulgate": "sicut enim fuit Ionas in ventre ceti tribus diebus et tribus noctibus sic erit Filius hominis in corde terrae tribus diebus et tribus noctibus;"}}, {"v": 41, "ref": "12:41", "o": "ἄνδρες Νινευῖται ἀναστήσονται ἐν τῇ κρίσει μετὰ τῆς γενεᾶς ταύτης καὶ κατακρινοῦσιν αὐτήν· ὅτι μετενόησαν εἰς τὸ κήρυγμα Ἰωνᾶ, καὶ ἰδοὺ πλεῖον Ἰωνᾶ ὧδε.", "en": {"kjv": "The men of Nineveh shall rise in judgment with this generation, and shall condemn it: because they repented at the preaching of Jonas; and, behold, a greater than Jonas is here.", "web": "The men of Nineveh will stand up in the judgment with this generation, and will condemn it, for they repented at the preaching of Jonah; and behold, someone greater than Jonah is here.", "bsb": "The men of Nineveh will stand at the judgment with this generation and condemn it; for they repented at the preaching of Jonah, and now One greater than Jonah is here.", "asv": "The men of Nineveh shall stand up in the judgment with this generation, and shall condemn it: for they repented at the preaching of Jonah; and behold, a greater than Jonah is here.", "ylt": "`Men of Nineveh shall stand up in the judgment with this generation, and shall condemn it, for they reformed at the proclamation of Jonah, and lo, a greater than Jonah here!", "tyndale": "The men of Ninivie shall rise at the daye of iugdement with this nacion and condemne them: for they amended at ye preachinge of Ionas. And beholde a greater then Ionas is here.", "dra": "The men of Ninive shall rise in judgment with this generation, and shall condemn it: because they did penance at the preaching of Jonas. And behold a greater than Jonas here.", "bbe": "The men of Nineveh will come up in the day of judging and give their decision against this generation: because they were turned from their sins at the preaching of Jonah; and now a greater than Jonah is here.", "geneva": "The men of Nineue shall rise in iudgement with this generation, and condemne it: for they repented at the preaching of Ionas: and behold, a greater then Ionas is here.", "wycliffe": "Men of Nynyue schulen rise in doom with this generacioun, and schulen condempne it; for thei diden penaunce in the prechyng of Jonas, and lo! here a gretter than Jonas.", "rotherham": "Men of Nineveh, will rise up in the judgment, with this generation, and will condemn it,—because they repented into the proclamation of Jonah; and lo! something greater than Jonah, here.", "weymouth": "There will stand up men of Nineveh at the Judgement together with the present generation, and will condemn it; because they repented at the preaching of Jonah, and mark! there is One greater than Jonah here.", "darby": "Ninevites shall stand up in the judgment with this generation, and shall condemn it: for they repented at the preaching of Jonas; and behold, more than Jonas [is] here.", "twenty": "At the Judgment, the men of Nineveh will stand up with this generation, and will condemn it, because they repented at Jonah’s proclamation; and here is more than a Jonah!", "acv": "The men of Nineveh will rise up in the judgment with this generation, and will condemn it, because they repented at the preaching of Jonah, and behold, a greater than Jonah is here.", "anderson": "Tho men of Nineveh shall rise in the judgment with this generation, and condemn it; for they repented in accordance with the preaching of Jonah; and behold, something greater than Jonah is here.", "haweis": "The men of Nineveh shall rise up in judgment against this generation, and condemn it: for they repented on the preaching of Jonah; and behold, a greater than Jonah is here.", "noyes": "The men of Nineveh will stand up in the judgment with this generation, and will condemn it; for they repented at the preaching of Jonah; and, lo! something more than Jonah is here.", "webster": "The men of Nineveh shall rise in judgment with this generation, and shall condemn it: because they repented at the preaching of Jonah; and behold, a greater than Jonah [is] here.", "vulgate": "viri ninevitae surgent in iudicio cum generatione ista et condemnabunt eam quia paenitentiam egerunt in praedicatione Ionae et ecce plus quam Iona hic;"}}, {"v": 42, "ref": "12:42", "o": "βασίλισσα νότου ἐγερθήσεται ἐν τῇ κρίσει μετὰ τῆς γενεᾶς ταύτης καὶ κατακρινεῖ αὐτήν· ὅτι ἦλθεν ἐκ τῶν περάτων τῆς γῆς ἀκοῦσαι τὴν σοφίαν Σολομῶνος, καὶ ἰδοὺ πλεῖον Σολομῶνος ὧδε.", "en": {"kjv": "The queen of the south shall rise up in the judgment with this generation, and shall condemn it: for she came from the uttermost parts of the earth to hear the wisdom of Solomon; and, behold, a greater than Solomon is here.", "web": "The queen of the south will rise up in the judgment with this generation, and will condemn it, for she came from the ends of the earth to hear the wisdom of Solomon; and behold, someone greater than Solomon is here.", "bsb": "The Queen of the South will rise at the judgment with this generation and condemn it; for she came from the ends of the earth to hear the wisdom of Solomon, and now One greater than Solomon is here.", "asv": "The queen of the south shall rise up in the judgment with this generation, and shall condemn it: for she came from the ends of the earth to hear the wisdom of Solomon; and behold, a greater than Solomon is here.", "ylt": "`A queen of the south shall rise up in the judgment with this generation, and shall condemn it, for she came from the ends of the earth to hear the wisdom of Solomon, and lo, a greater than Solomon here!", "tyndale": "The quene of ye south shall ryse at ye daye of iudgement with this generacion and shall condemne the: for she came fro the vtmost parties of the worlde to heare the wysdome of Salomon. And beholde a greater then Salomo is here.", "dra": "The queen of the south shall rise in judgment with this generation, and shall condemn it: because she came from the ends of the earth to hear the wisdom of Solomon, and behold a greater than Solomon here.", "bbe": "The queen of the South will come up in the day of judging and give her decision against this generation: for she came from the ends of the earth to give ear to the wisdom of Solomon; and now a greater than Solomon is here.", "geneva": "The Queene of the South shall rise in iudgement with this generation, and shall condemne it: for she came from the vtmost partes of the earth to heare the wisdome of Salomon: and beholde, a greater then Salomon is here.", "wycliffe": "The queene of the south shal rise in doom with this generacioun, and schal condempne it; for she cam fro the eendis of the erthe to here the wisdom of Salomon, and lo! here a gretter than Salomon.", "rotherham": "The queen of the south, will arise in the judgment with this generation and will condemn it—because she came out of the ends of the earth, to hear the wisdom of Solomon; and lo! something greater than Solomon, here.", "weymouth": "The Queen of the south will awake at the Judgement together with the present generation, and will condemn it; because she came from the ends of the earth to hear the wisdom of Solomon, and mark! there is One greater than Solomon here.", "darby": "A queen of [the] south shall rise up in the judgment with this generation, and shall condemn it; for she came from the ends of the earth to hear the wisdom of Solomon; and behold, more than Solomon [is] here.", "twenty": "At the Judgment the Queen of the South will rise up with the present generation, and will condemn it, because she came from the very ends of the earth to listen to the wisdom of Solomon; and here is more than a Solomon!", "acv": "The queen of the south will rise up in the judgment with this generation, and will condemn it, because she came from the ends of the earth to hear the wisdom of Solomon, and behold, a greater than Solomon is here.", "anderson": "The queen of the south shall rise in the judgment with this generation, and shall condemn it; for she came from the most distant parts of the earth to hear the wisdom of Solomon; and behold, something greater than Solomon is here.", "haweis": "The queen of the South shall rise up in judgment against the men of this generation, and condemn it: for she came from the ends of the earth to hear the wisdom of Solomon; and behold, a greater than Solomon is here.", "noyes": "The queen of the south will rise up in the judgment with this generation, and will condemn it; for she came from the ends of the earth to hear the wisdom of Solomon; and lo! something more than Solomon is here.", "webster": "The queen of the south shall rise up in the judgment with this generation, and shall condemn it: for she came from the uttermost parts of the earth to hear the wisdom of Solomon; and behold, a greater than Solomon [is] here.", "vulgate": "regina austri surget in iudicio cum generatione ista et condemnabit eam quia venit a finibus terrae audire sapientiam Salomonis et ecce plus quam Salomon hic;"}}, {"v": 43, "ref": "12:43", "o": "Ὅταν δὲ τὸ ἀκάθαρτον πνεῦμα ἐξέλθῃ ἀπὸ τοῦ ἀνθρώπου, διέρχεται δι’ ἀνύδρων τόπων ζητοῦν ἀνάπαυσιν, καὶ οὐχ εὑρίσκει.", "en": {"kjv": "When the unclean spirit is gone out of a man, he walketh through dry places, seeking rest, and findeth none.", "web": "But the unclean spirit, when he is gone out of the man, passes through waterless places, seeking rest, and doesn’t find it.", "bsb": "When an unclean spirit comes out of a man, it passes through arid places seeking rest and does not find it.", "asv": "But the unclean spirit, when he is gone out of the man, passeth through waterless places, seeking rest, and findeth it not.", "ylt": "`And, when the unclean spirit may go forth from the man, it doth walk through dry places seeking rest, and doth not find;", "tyndale": "When the vnclene sprite is gone out of a man he walketh throughout dry places seking reest and fyndeth none.", "dra": "And when an unclean spirit is gone out of a man he walketh through dry places seeking rest, and findeth none.", "bbe": "But the unclean spirit, when he is gone out of a man, goes through dry places looking for rest, and getting it not.", "geneva": "Nowe when the vncleane spirit is gone out of a man, he walketh throughout drie places, seeking rest, and findeth none.", "wycliffe": "Whanne an vnclene spirit goith out fro a man, he goith bi drie places, `and sekith rest, and fyndith not.", "rotherham": "But, when the impure spirit goeth out of the man, it passeth through waterless places, seeking rest,—and findeth it not.", "weymouth": "\"No sooner however has the foul spirit gone out of the man, then he roams about in places where there is no water, seeking rest but finding none.", "darby": "But when the unclean spirit has gone out of the man, he goes through dry places, seeking rest, and does not find [it].", "twenty": "No sooner does a foul spirit leave a man, than it passes through places where there is no water, in search of rest, and does not find it.", "acv": "But when the unclean spirit goes forth out of the man, it passes through waterless places, seeking rest, and finds it not.", "anderson": "When the unclean spirit has gone out of a man, he goes through dry places seeking rest, and finds none.", "haweis": "When the unclean spirit is indeed gone out of a man, he traverses through places destitute of water, in search of rest, but cannot find it.", "noyes": "But when the unclean spirit is gone out from a man, it goeth through dry places, seeking rest, and findeth it not.", "webster": "When the unclean spirit is gone out of a man, he walketh through dry places, seeking rest, and he findeth none.", "vulgate": "cum autem inmundus spiritus exierit ab homine ambulat per loca arida quaerens requiem et non invenit;"}}, {"v": 44, "ref": "12:44", "o": "τότε λέγει· ⸂Εἰς τὸν οἶκόν μου ἐπιστρέψω⸃ ὅθεν ἐξῆλθον· καὶ ἐλθὸν ⸀εὑρίσκει ⸀σχολάζοντα σεσαρωμένον καὶ κεκοσμημένον.", "en": {"kjv": "Then he saith, I will return into my house from whence I came out; and when he is come, he findeth it empty, swept, and garnished.", "web": "Then he says, ‘I will return into my house from which I came out,’ and when he has come back, he finds it empty, swept, and put in order.", "bsb": "Then it says, ‘I will return to the house I left.’ On its return, it finds the house vacant, swept clean, and put in order.", "asv": "Then he saith, I will return into my house whence I came out; and when he is come, he findeth it empty, swept, and garnished.", "ylt": "then it saith, I will turn back to my house whence I came forth; and having come, it findeth it unoccupied, swept, and adorned:", "tyndale": "Then he sayeth: I will retourne ageyne into my housse fro whece I came oute. And when he is come he fyndeth the housse empty and swepte and garnisshed.", "dra": "Then he saith: I will return into my house from whence I came out. And coming he findeth it empty, swept, and garnished.", "bbe": "Then he says, I will go back into my house from which I came out; and when he comes, he sees that there is no one in it, but that it has been made fair and clean.", "geneva": "Then he saith, I wil returne into mine house from whence I came: and when he is come, he findeth it emptie, swept and garnished.", "wycliffe": "Thanne he seith, Y shal turne ayen in to myn hous, fro whannys Y wente out. And he cometh, and fyndith it voide, and clensid with besyms, and maad faire.", "rotherham": "Then, it saith, Into my house, will I return whence I came out,—and, coming, findeth it empty [and] swept and adorned.", "weymouth": "Then he says, `I will return to my house that I left;' and he comes and finds it unoccupied, swept clean, and in good order.", "darby": "Then he says, I will return to my house whence I came out; and having come, he finds [it] unoccupied, swept, and adorned.", "twenty": "Then it says ‘I will go back to the home which I left’; but, on coming there, it finds it unoccupied, and swept, and put in order.", "acv": "Then it says, I will return into my house from where I came out. And when it comes, it finds it empty, swept, and put in order.", "anderson": "Then he says: I will return to my house, out of which I came. And he comes and finds it empty, swept, and set in order.", "haweis": "Then he saith, I will return to my mansion, whence I came; and on his arrival, he findeth it unoccupied, swept, and furnished.", "noyes": "Then it saith, I will return to my house whence I came out. And on coming, it findeth it empty, and swept, and put in order.", "webster": "Then he saith, I will return into my house from whence I came out; and when he is come, he findeth [it] empty, swept, and garnished.", "vulgate": "tunc dicit revertar in domum meam unde exivi et veniens invenit vacantem scopis mundatam et ornatam;"}}, {"v": 45, "ref": "12:45", "o": "τότε πορεύεται καὶ παραλαμβάνει μεθ’ ἑαυτοῦ ἑπτὰ ἕτερα πνεύματα πονηρότερα ἑαυτοῦ, καὶ εἰσελθόντα κατοικεῖ ἐκεῖ· καὶ γίνεται τὰ ἔσχατα τοῦ ἀνθρώπου ἐκείνου χείρονα τῶν πρώτων. οὕτως ἔσται καὶ τῇ γενεᾷ ταύτῃ τῇ πονηρᾷ.", "en": {"kjv": "Then goeth he, and taketh with himself seven other spirits more wicked than himself, and they enter in and dwell there: and the last state of that man is worse than the first. Even so shall it be also unto this wicked generation.", "web": "Then he goes, and takes with himself seven other spirits more evil than he is, and they enter in and dwell there. The last state of that man becomes worse than the first. Even so will it be also to this evil generation.”", "bsb": "Then it goes and brings with it seven other spirits more wicked than itself, and they go in and dwell there; and the final plight of that man is worse than the first. So will it be with this wicked generation.”", "asv": "Then goeth he, and taketh with himself seven other spirits more evil than himself, and they enter in and dwell there: and the last state of that man becometh worse than the first. Even so shall it be also unto this evil generation.", "ylt": "then doth it go, and take with itself seven other spirits more evil than itself, and having gone in they dwell there, and the last of that man doth become worse than the first; so shall it be also to this evil generation.'", "tyndale": "Then he goeth his waye and taketh vnto him seven other spretes worsse then himsilfe and so entre they in and dwell there. And the ende of that man is worsse then the beginning. Even so shall it be with this evell nacion.", "dra": "Then he goeth, and taketh with him seven other spirits more wicked than himself, and they enter in and dwell there: and the last state of that man is made worse than the first. So shall it be also to this wicked generation.", "bbe": "Then he goes and takes with him seven other spirits worse than himself, and they go in and make it their living-place: and the last condition of that man is worse than the first. Even so will it be with this evil generation.", "geneva": "Then he goeth, and taketh vnto him seuen other spirites worse then himselfe, and they enter in, and dwell there: and the ende of that man is worse then the beginning. Euen so shall it be with this wicked generation.", "wycliffe": "Thanne he goith, and takith with him seuene othere spiritis worse than hym silf; and thei entren, and dwellen there. And the laste thingis of that man ben maad worse than the formere. So it shal be to this worste generacioun.", "rotherham": "Then, it goeth, and taketh along with itself, seven diverse spirits, more wicked than itself,—and, entering, abideth there; and, the last state of that man, becometh, worse than the first. So, shall it be, with this, wicked, generation.", "weymouth": "Then he goes and brings back with him seven other spirits more wicked than himself, and they come in and dwell there; and in the end that man's condition becomes worse than it was at first. So will it be also with the present wicked generation.\"", "darby": "Then he goes and takes with himself seven other spirits worse than himself, and entering in, they dwell there; and the last condition of that man becomes worse than the first. Thus shall it be to this wicked generation also.", "twenty": "Then it goes and brings with it seven other spirits more wicked than itself, and they go in, and make their home there; and the last state of that man proves to be worse than the first. So, too, will it be with this wicked generation.”", "acv": "Then it goes, and takes with itself seven other spirits more evil than itself, and having enter in, they dwell there. And the last state of that man becomes worse than the first. So it will also be to this evil generation.", "anderson": "Then he goes and takes with himself seven other spirits more wicked than himself; and they enter in and dwell there. And the last state of that man is worse than the first. So shall it be with this wicked generation.", "haweis": "Then goeth he, and taketh with himself seven other spirits more wicked than himself, and they enter in and dwell there: and the last state of that man is worse than the first. So shall it also be with this wicked generation.", "noyes": "Then it goeth and taketh with it seven other spirits more wicked than itself, and they enter in, and dwell there; and the last state of that man becometh worse than the first. So will it be also with this wicked generation.", "webster": "Then goeth he, and taketh with himself seven other spirits more wicked than himself, and they enter in and dwell there: and the last [state] of that man is worse than the first. Even so shall it be also to this wicked generation.", "vulgate": "tunc vadit et adsumit septem alios spiritus secum nequiores se et intrantes habitant ibi et fiunt novissima hominis illius peiora prioribus sic erit et generationi huic pessimae;"}}, {"v": 46, "ref": "12:46", "o": "Ἔτι ⸀δὲ αὐτοῦ λαλοῦντος τοῖς ὄχλοις ἰδοὺ ἡ μήτηρ καὶ οἱ ἀδελφοὶ αὐτοῦ εἱστήκεισαν ἔξω ζητοῦντες αὐτῷ λαλῆσαι.", "en": {"kjv": "While he yet talked to the people, behold, his mother and his brethren stood without, desiring to speak with him.", "web": "While he was yet speaking to the multitudes, behold, his mother and his brothers stood outside, seeking to speak to him.", "bsb": "While Jesus was still speaking to the crowds, His mother and brothers stood outside, wanting to speak to Him.", "asv": "While he was yet speaking to the multitudes, behold, his mother and his brethren stood without, seeking to speak to him.", "ylt": "And while he was yet speaking to the multitudes, lo, his mother and brethren had stood without, seeking to speak to him,", "tyndale": "Whill he yet talked to the people: beholde his mother and his brethren stode without desyringe to speake with him.", "dra": "As he was yet speaking to the multitudes, behold his mother and his brethren stood without, seeking to speak to him.", "bbe": "While he was still talking to the people, his mother and his brothers came, desiring to have talk with him.", "geneva": "While he yet spake to ye multitude, beholde, his mother, and his brethren stood without, desiring to speake with him.", "wycliffe": "Yit whil he spak to the puple, lo! his modir and his bretheren stoden withouteforth, sekynge to speke to hym.", "rotherham": "While yet he was speaking unto the multitudes, lo! his mother and brethren, were standing without, seeking to speak with him.", "weymouth": "While He was still addressing the people His mother and His brothers were standing on the edge of the crowd desiring to speak to Him.", "darby": "But while he was yet speaking to the crowds, behold, his mother and his brethren stood without, seeking to speak to him.", "twenty": "While he was still speaking to the crowds, his mother and brothers were standing outside, asking to speak to him.", "acv": "While he was still speaking to the multitudes, behold, his mother and his brothers had stood outside, seeking to speak to him.", "anderson": "While he was yet speaking to the multitudes, behold, his mother and his brothers stood without, desiring to speak to him.", "haweis": "And while he was yet speaking to the multitudes, behold, his mother and his brethren stood without, desiring to speak to him.", "noyes": "While he was yet speaking to the multitudes, lo! his mother and his brothers were standing without, seeking to speak with him.", "webster": "While he was yet speaking to the people, behold, [his] mother and his brethren stood without, desiring to speak with him.", "vulgate": "adhuc eo loquente ad turbas ecce mater eius et fratres stabant foris quaerentes loqui ei;"}}, {"v": 47, "ref": "12:47", "o": "⸂εἶπεν δέ τις αὐτῷ· Ἰδοὺ ἡ μήτηρ σου καὶ οἱ ἀδελφοί σου ἔξω ἑστήκασιν, ζητοῦντές σοι λαλῆσαι.⸃", "en": {"kjv": "Then one said unto him, Behold, thy mother and thy brethren stand without, desiring to speak with thee.", "web": "One said to him, “Behold, your mother and your brothers stand outside, seeking to speak to you.”", "bsb": "Someone told Him, “Look, Your mother and brothers are standing outside, wanting to speak to You.”", "asv": "And one said unto him, Behold, thy mother and thy brethren stand without, seeking to speak to thee.", "ylt": "and one said to him, `Lo, thy mother and thy brethren do stand without, seeking to speak to thee.'", "tyndale": "Then one sayde vnto hym: beholde thy mother and thy brethre stonde without desiringe to speke wt the.", "dra": "And one said unto him: Behold thy mother and thy brethren stand without, seeking thee.", "bbe": "And one said to him, See, your mother and your brothers are outside, desiring to have talk with you.", "geneva": "Then one said vnto him, Beholde, thy mother and thy brethren stand without, desiring to speake with thee.", "wycliffe": "And a man seide to hym, Lo! thi modir and thi britheren stonden withouteforth, sekynge thee.", "rotherham": "[And one said to him, Lo! thy mother and thy brethren, without, are standing, seeking, to speak, with thee.]", "weymouth": "So some one told Him, \"Your mother and your brothers are standing outside, and desire to speak to you.\"", "darby": "Then one said unto him, Behold, thy mother and thy brethren are standing without, seeking to speak to thee.", "twenty": "Someone told him this, and Jesus replied:", "acv": "And some man said to him, Behold, thy mother and thy brothers stand outside, seeking to speak to thee.", "anderson": "And some one said to him: Behold, your mother and your brothers stand without, desiring to speak to you.", "haweis": "And a person said unto him, Behold, thy mother and thy brethren stand without, desiring to speak to thee.", "noyes": "And one said to him, Behold, thy mother and thy brothers are standing without, seeking to speak with thee.", "webster": "Then one said to him, Behold, thy mother and thy brethren stand without, desiring to speak with thee.", "vulgate": "dixit autem ei quidam ecce mater tua et fratres tui foris stant quaerentes te;"}}, {"v": 48, "ref": "12:48", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν τῷ ⸀λέγοντι αὐτῷ· Τίς ἐστιν ἡ μήτηρ μου, καὶ τίνες εἰσὶν οἱ ἀδελφοί μου;", "en": {"kjv": "But he answered and said unto him that told him, Who is my mother? and who are my brethren?", "web": "But he answered him who spoke to him, “Who is my mother? Who are my brothers?”", "bsb": "But Jesus replied, “Who is My mother, and who are My brothers?”", "asv": "But he answered and said unto him that told him, Who is my mother? and who are my brethren?", "ylt": "And he answering said to him who spake to him, `Who is my mother? and who are my brethren?'", "tyndale": "He answered and sayd to him that tolde hym: Who is my mother? or who are my brethren?", "dra": "But he answering him that told him, said: Who is my mother, and who are my brethren?", "bbe": "But he in answer said to him who gave the news, Who is my mother and who are my brothers?", "geneva": "But he answered, and said to him that told him, Who is my mother? and who are my brethren?", "wycliffe": "He answeride to the man, that spak to hym, and seide, Who is my modir? and who ben my britheren?", "rotherham": "But, he, answering, said unto him that was telling him, Who is my mother? and who are my brethren?", "weymouth": "\"Who is my mother?\" He said to the man; \"and who are my brothers?\"", "darby": "But he answering said to him that spoke to him, Who is my mother, and who are my brethren?", "twenty": "“Who is my mother? and who are my brothers?”", "acv": "But having answered, he said to the man who told him, Who is my mother, and who are my brothers?", "anderson": "But he answered and said to him that told him: Who is my mother? and who are my brothers?", "haweis": "But he answered and said to him that told him, Who is my mother? and who are my brethren?", "noyes": "But he answered and said to him that told him, Who is my mother, and who are my brothers?", "webster": "But he answered and said to him that told him, Who is my mother? and who are my brethren?", "vulgate": "at ipse respondens dicenti sibi ait quae est mater mea et qui sunt fratres mei;"}}, {"v": 49, "ref": "12:49", "o": "καὶ ἐκτείνας τὴν χεῖρα αὐτοῦ ἐπὶ τοὺς μαθητὰς αὐτοῦ εἶπεν· Ἰδοὺ ἡ μήτηρ μου καὶ οἱ ἀδελφοί μου·", "en": {"kjv": "And he stretched forth his hand toward his disciples, and said, Behold my mother and my brethren!", "web": "He stretched out his hand towards his disciples, and said, “Behold, my mother and my brothers!", "bsb": "Pointing to His disciples, He said, “Here are My mother and My brothers.", "asv": "And he stretched forth his hand towards his disciples, and said, Behold, my mother and my brethren!", "ylt": "And having stretched forth his hand toward his disciples, he said, `Lo, my mother and my brethren!", "tyndale": "And he stretched forth his hond over his disciples and sayd: behold my mother and my brethren.", "dra": "And stretching forth his hand towards his disciples, he said: Behold my mother and my brethren.", "bbe": "And he put out his hand to his disciples and said, See, my mother and my brothers!", "geneva": "And he stretched foorth his hand toward his disciples, and said, Beholde my mother and my brethren.", "wycliffe": "And he helde forth his hoond in to hise disciplis, and seide, Lo! my modir and my bretheren;", "rotherham": "And, stretching forth his hand towards his disciples, he said, Lo! my mother and my brethren!", "weymouth": "And pointing to His disciples He added, \"See here are my mother and my brothers.", "darby": "And, stretching out his hand to his disciples, he said, Behold my mother and my brethren;", "twenty": "Then, stretching out his hands towards his disciples, he said: “Here are my mother and my brothers!", "acv": "And having stretched forth his hand towards his disciples, he said, Behold, my mother and my brothers.", "anderson": "And he stretched out his hand toward his disciples, and said: Behold my mother and my brothers.", "haweis": "And stretching out his hand towards his disciples, he said, Behold my mother and my brethren.", "noyes": "And stretching forth his hand toward his disciples, be said, Behold, my mother and my brothers!", "webster": "And he stretched forth his hand towards his disciples, and said, Behold my mother and my brethren!", "vulgate": "et extendens manum in discipulos suos dixit ecce mater mea et fratres mei;"}}, {"v": 50, "ref": "12:50", "o": "ὅστις γὰρ ἂν ποιήσῃ τὸ θέλημα τοῦ πατρός μου τοῦ ἐν οὐρανοῖς, αὐτός μου ἀδελφὸς καὶ ἀδελφὴ καὶ μήτηρ ἐστίν.", "en": {"kjv": "For whosoever shall do the will of my Father which is in heaven, the same is my brother, and sister, and mother.", "web": "For whoever does the will of my Father who is in heaven, he is my brother, and sister, and mother.”", "bsb": "For whoever does the will of My Father in heaven is My brother and sister and mother.”", "asv": "For whosoever shall do the will of my Father who is in heaven, he is my brother, and sister, and mother.", "ylt": "for whoever may do the will of my Father who is in the heavens, he is my brother, and sister, and mother.'", "tyndale": "For whosoever dothe my fathers will which is in heve the same is my brother suster and mother.", "dra": "For whosoever shall do the will of my Father, that is in heaven, he is my brother, and sister, and mother.", "bbe": "For whoever does the pleasure of my Father in heaven, he is my brother, and sister, and mother.", "geneva": "For whosoeuer shall doe my Fathers will which is in heauen, the same is my brother and sister and mother.", "wycliffe": "for who euer doith the wille of my fadir that is in heuenes, he is my brothir, and sistir, and modir.", "rotherham": "For, whosoever shall do the will of my Father who is in the heavens, he, is my, brother, and sister, and mother.", "weymouth": "To obey my Father who is in Heaven--that is to be my brother and my sister and my mother.\"", "darby": "for whosoever shall do the will of my Father who is in [the] heavens, he is my brother, and sister, and mother.", "twenty": "For any one who does the will of my Father who is in Heaven is my brother and sister and mother.”", "acv": "For whoever does the will of my Father in the heavens, he is my brother, and sister, and mother.", "anderson": "For whoever will do the will of my Father who is in heaven, the same is my brother, and sister, and mother.", "haweis": "For whosoever shall do the will of my Father who is in heaven, the same is my brother, and sister, and mother.", "noyes": "For whoever doeth the will of my Father who is in heaven, he is my brother, and sister, and mother.", "webster": "For whoever shall do the will of my Father who is in heaven, the same is my brother, and sister, and mother.", "vulgate": "quicumque enim fecerit voluntatem Patris mei qui in caelis est ipse meus et frater et soror et mater est;"}}]}, {"c": 13, "verses": [{"v": 1, "ref": "13:1", "o": "⸀Ἐν τῇ ἡμέρᾳ ἐκείνῃ ἐξελθὼν ὁ Ἰησοῦς ⸀τῆς οἰκίας ἐκάθητο παρὰ τὴν θάλασσαν·", "en": {"kjv": "The same day went Jesus out of the house, and sat by the sea side.", "web": "On that day Jesus went out of the house, and sat by the seaside.", "bsb": "That same day Jesus went out of the house and sat by the sea.", "asv": "On that day went Jesus out of the house, and sat by the sea side.", "ylt": "And in that day Jesus, having gone forth from the house, was sitting by the sea,", "tyndale": "The same daye wet Iesus out of ye house and sat by the seesyde", "dra": "The same day Jesus going out of the house, sat by the sea side.", "bbe": "On that day Jesus went out of the house and was seated by the seaside.", "geneva": "The same day went Iesus out of the house, and sate by the sea side.", "wycliffe": "In that dai Jhesus yede out of the hous, and sat bisidis the see.", "rotherham": "On that day, Jesus, going out of the house, was sitting near the sea:", "weymouth": "That same day Jesus had left the house and was sitting on the shore of the Lake,", "darby": "And that [same] day Jesus went out from the house and sat down by the sea.", "twenty": "That same day, when Jesus had left the house and was sitting by the Sea,", "acv": "And on that day, having departed from the house, Jesus was sitting beside the sea.", "anderson": "On that day Jesus went out of the house, and sat by the sea.", "haweis": "THEN the same day Jesus going out from the house, sat down near the sea.", "noyes": "The same day Jesus went out of the house, and sat by the shore of the lake;", "webster": "The same day Jesus went out of the house, and sat by the sea side.", "vulgate": "in illo die exiens Iesus de domo sedebat secus mare;"}}, {"v": 2, "ref": "13:2", "o": "καὶ συνήχθησαν πρὸς αὐτὸν ὄχλοι πολλοί, ὥστε αὐτὸν ⸀εἰς πλοῖον ἐμβάντα καθῆσθαι, καὶ πᾶς ὁ ὄχλος ἐπὶ τὸν αἰγιαλὸν εἱστήκει.", "en": {"kjv": "And great multitudes were gathered together unto him, so that he went into a ship, and sat; and the whole multitude stood on the shore.", "web": "Great multitudes gathered to him, so that he entered into a boat, and sat, and all the multitude stood on the beach.", "bsb": "Such large crowds gathered around Him that He got into a boat and sat down, while all the people stood on the shore.", "asv": "And there were gathered unto him great multitudes, so that he entered into a boat, and sat; and all the multitude stood on the beach.", "ylt": "and gathered together unto him were many multitudes, so that he having gone into the boat did sit down, and all the multitude on the beach did stand,", "tyndale": "and moch people resorted vnto him so gretly yt he wet and sat in a shippe and all the people stode on ye shoore.", "dra": "And great multitudes were gathered together unto him, so that he went up into a boat and sat: and all the multitude stood on the shore.", "bbe": "And great numbers of people came together to him, so that he got into a boat; and the people took up their position by the sea.", "geneva": "And great multitudes resorted vnto him, so that he went into a ship, and sate downe: and the whole multitude stoode on the shore.", "wycliffe": "And myche puple was gaderid to hym, so that he wente up in to a boot, and sat; and al the puple stood on the brenke.", "rotherham": "and there were gathered unto him, large multitudes, so that, he, into a boat, entered, and was sitting, and, all the multitude, on the beach was standing.", "weymouth": "when a vast multitude of people crowded round Him. He therefore went on board a boat and sat there, while all the people stood on the shore.", "darby": "And great crowds were gathered together to him, so that going on board ship himself he sat down, and the whole crowd stood on the shore.", "twenty": "such great crowds gathered round him, that he got into a boat, and sat in it, while all the people stood upon the beach.", "acv": "And many multitudes were gathered to him, so as for him (having entered in) to sit in the boat, and all the multitude had stood on the shore.", "anderson": "And many multitudes came together to him, so that he went into a ship and sat; and the whole multitude stood on the shore.", "haweis": "And vast multitudes were gathered together unto him, insomuch that he entered into a vessel to be seated; and all the multitude stood on the beach.", "noyes": "and great multitudes were gathered together to him, so that he went into a boat, and sat down; and all the multitude stood on the beach.", "webster": "And great multitudes were gathered to him, so that he went into a boat, and sat down; and the whole multitude stood on the shore.", "vulgate": "et congregatae sunt ad eum turbae multae ita ut in naviculam ascendens sederet et omnis turba stabat in litore;"}}, {"v": 3, "ref": "13:3", "o": "καὶ ἐλάλησεν αὐτοῖς πολλὰ ἐν παραβολαῖς λέγων· Ἰδοὺ ἐξῆλθεν ὁ σπείρων τοῦ σπείρειν.", "en": {"kjv": "And he spake many things unto them in parables, saying, Behold, a sower went forth to sow;", "web": "He spoke to them many things in parables, saying, “Behold, a farmer went out to sow.", "bsb": "And He told them many things in parables, saying, “A farmer went out to sow his seed.", "asv": "And he spake to them many things in parables, saying, Behold, the sower went forth to sow;", "ylt": "and he spake to them many things in similes, saying: `Lo, the sower went forth to sow,", "tyndale": "And he spake many thynges to the in similitudes sayinge: Beholde ye sower wet forth to sowe.", "dra": "And he spoke to them many things in parables, saying: Behold the sower went forth to sow.", "bbe": "And he gave them teaching in the form of a story, saying, A man went out to put seed in the earth;", "geneva": "Then he spake many things to them in parables, saying, Behold, a sower went forth to sowe.", "wycliffe": "And he spac to hem many thingis in parablis, and seide, Lo! he that sowith, yede out to sowe his seed.", "rotherham": "And he spake unto them many things, in parables, saying: Lo! the sower went forth to sow,—", "weymouth": "He then spoke many things to them in figurative language. \"The sower goes out,\" He said, \"to sow.", "darby": "And he spoke to them many things in parables, saying, Behold, the sower went out to sow:", "twenty": "Then he told them many truths in parables. “The sower,” he began, “went out to sow; and,", "acv": "And he spoke many things to them in parables, saying, Behold, the man who sows went forth to sow.", "anderson": "And he spoke many things to them in parables, saying: Behold, the sower went out to sow.", "haweis": "And he spake unto them many things in parables, saying, Behold, a sower went out to sow:", "noyes": "And he spoke many things to them in parables, saying, Behold, a sower went forth to sow.", "webster": "And he spoke many things to them in parables, saying, Behold, a sower went forth to sow;", "vulgate": "et locutus est eis multa in parabolis dicens ecce exiit qui seminat seminare;"}}, {"v": 4, "ref": "13:4", "o": "καὶ ἐν τῷ σπείρειν αὐτὸν ἃ μὲν ἔπεσεν παρὰ τὴν ὁδόν, καὶ ⸂ἐλθόντα τὰ πετεινὰ⸃ κατέφαγεν αὐτά.", "en": {"kjv": "And when he sowed, some seeds fell by the way side, and the fowls came and devoured them up:", "web": "As he sowed, some seeds fell by the roadside, and the birds came and devoured them.", "bsb": "And as he was sowing, some seed fell along the path, and the birds came and devoured it.", "asv": "and as he sowed, some seeds fell by the way side, and the birds came and devoured them:", "ylt": "and in his sowing, some indeed fell by the way, and the fowls did come and devour them,", "tyndale": "And as he sowed some fell by ye wayessyde and the fowlles came and devoured it vp.", "dra": "And whilst he soweth some fell by the way side, and the birds of the air came and ate them up.", "bbe": "And while he did so, some seeds were dropped by the wayside, and the birds came and took them for food:", "geneva": "And as he sowed, some fell by the way side, and the foules came and deuoured them vp.", "wycliffe": "And while he sowith, summe seedis felden bisidis the weie, and briddis of the eir camen, and eeten hem.", "rotherham": "and, as he sowed, some, indeed, fell by the pathway, and, the birds, came, and devoured it;", "weymouth": "As he sows, some of the seed falls by the way-side, and the birds come and peck it up.", "darby": "and as he sowed, some [grains] fell along the way, and the birds came and devoured them;", "twenty": "as he was sowing, some seed fell along the path, and the birds came and ate it up.", "acv": "And as he sowed, some fell by the wayside, and the birds came and devoured them.", "anderson": "And as he sowed, some seeds fell by the way: and the birds came and ate them up.", "haweis": "and as he was sowing, some seeds fell indeed by the road-side; and the birds came and ate them up:", "noyes": "And as he sowed, some seeds fell by the wayside; and the birds came and devoured them.", "webster": "And when he sowed, some [seeds] fell by the way side, and the fowls came and devoured them:", "vulgate": "et dum seminat quaedam ceciderunt secus viam et venerunt volucres et comederunt ea;"}}, {"v": 5, "ref": "13:5", "o": "ἄλλα δὲ ἔπεσεν ἐπὶ τὰ πετρώδη ὅπου οὐκ εἶχεν γῆν πολλήν, καὶ εὐθέως ἐξανέτειλεν διὰ τὸ μὴ ἔχειν βάθος γῆς,", "en": {"kjv": "Some fell upon stony places, where they had not much earth: and forthwith they sprung up, because they had no deepness of earth:", "web": "Others fell on rocky ground, where they didn’t have much soil, and immediately they sprang up, because they had no depth of earth.", "bsb": "Some fell on rocky ground, where it did not have much soil. It sprang up quickly because the soil was shallow.", "asv": "and others fell upon the rocky places, where they had not much earth: and straightway they sprang up, because they had no deepness of earth:", "ylt": "and others fell upon the rocky places, where they had not much earth, and immediately they sprang forth, through not having depth of earth,", "tyndale": "Some fell apo stony groude where it had not moche erth and a none it sproge vp because it had no depth of erth:", "dra": "And other some fell upon stony ground, where they had not much earth: and they sprung up immediately, because they had no deepness of earth.", "bbe": "And some of the seed went among the stones, where it had not much earth, and straight away it came up because the earth was not deep:", "geneva": "And some fell vpon stony grounde, where they had not much earth, and anon they sprong vp, because they had no depth of earth.", "wycliffe": "But othere seedis felden in to stony places, where thei hadden not myche erthe; and anoon thei sprongen vp, for thei hadden not depnesse of erthe.", "rotherham": "And, some, fell on the rocky places, where it had not much earth,—and, straightway, it sprang up, because if had no depth of earth;", "weymouth": "Some falls on rocky ground, where it has but scanty soil. It quickly shows itself above ground, because it has no depth of earth;", "darby": "and others fell upon the rocky places where they had not much earth, and immediately they sprang up out of [the ground] because of not having [any] depth of earth,", "twenty": "Some fell on rocky places, where it had not much soil, and, having no depth of soil, sprang up at once.", "acv": "But others fell upon the rocky places, where they had not much soil, and straightaway they sprang up because they had no depth of soil.", "anderson": "Others fell on stony places, where they had not much earth; and they immediately sprung up, because they had no depth of earth.", "haweis": "and other seed fell on a rocky soil, where it had not much earth; and immediately it sprang up, because it had no depth of earth:", "noyes": "And others fell upon rocky places, where they had not much earth; and they sprung up immediately, because they had no depth of earth.", "webster": "Some fell upon stony places, where they had not much earth: and forthwith they sprung up, because they had no deepness of earth:", "vulgate": "alia autem ceciderunt in petrosa ubi non habebat terram multam et continuo exorta sunt quia non habebant altitudinem terrae;"}}, {"v": 6, "ref": "13:6", "o": "ἡλίου δὲ ἀνατείλαντος ἐκαυματίσθη καὶ διὰ τὸ μὴ ἔχειν ῥίζαν ἐξηράνθη.", "en": {"kjv": "And when the sun was up, they were scorched; and because they had no root, they withered away.", "web": "When the sun had risen, they were scorched. Because they had no root, they withered away.", "bsb": "But when the sun rose, the seedlings were scorched, and they withered because they had no root.", "asv": "and when the sun was risen, they were scorched; and because they had no root, they withered away.", "ylt": "and the sun having risen they were scorched, and through not having root, they withered,", "tyndale": "and when ye sunne was vp it cauht heet and for lake of rotynge wyddred awaye.", "dra": "And when the sun was up they were scorched: and because they had not root, they withered away.", "bbe": "And when the sun was high, it was burned; and because it had no root it became dry and dead.", "geneva": "And when the sunne was vp, they were parched, and for lacke of rooting, withered away.", "wycliffe": "But whanne the sonne was risun, thei swaliden, and for thei hadden not roote, thei drieden vp.", "rotherham": "and, the sun arising, it was scorched, and, because it had no root, it withered away;", "weymouth": "but when the sun is risen, it is scorched by the heat, and through having no root it withers up.", "darby": "but when the sun rose they were burned up, and because of not having [any] root were dried up;", "twenty": "As soon as the sun had risen, it was scorched, and, having no root, withered away.", "acv": "But when the sun was risen, they were scorched, and because they had no root they withered.", "anderson": "But when the sun was up, they were scorched; and because they had no root, they withered away.", "haweis": "and when the sun arose, it was scorched up; and because it had no root, it withered away.", "noyes": "But when the sun was up, they were scorched; and because they had no root, they withered away.", "webster": "And when the sun had risen, they were scorched; and because they had not root, they withered.", "vulgate": "sole autem orto aestuaverunt et quia non habebant radicem aruerunt;"}}, {"v": 7, "ref": "13:7", "o": "ἄλλα δὲ ἔπεσεν ἐπὶ τὰς ἀκάνθας, καὶ ἀνέβησαν αἱ ἄκανθαι καὶ ⸀ἔπνιξαν αὐτά.", "en": {"kjv": "And some fell among thorns; and the thorns sprung up, and choked them:", "web": "Others fell among thorns. The thorns grew up and choked them.", "bsb": "Other seed fell among thorns, which grew up and choked the seedlings.", "asv": "And others fell upon the thorns; and the thorns grew up and choked them:", "ylt": "and others fell upon the thorns, and the thorns did come up and choke them,", "tyndale": "Some fell amoge thornes and the thornes sproge vp and chooked it.", "dra": "And others fell among thorns: and the thorns grew up and choked them.", "bbe": "And some seeds went among thorns, and the thorns came up and they had no room for growth:", "geneva": "And some fell among thornes, and the thornes sprong vp, and choked them.", "wycliffe": "And other seedis felden among thornes; and thornes woxen vp, and strangeleden hem.", "rotherham": "And, some, fell upon the thorns, and the thorns came up, and choked it;", "weymouth": "Some falls among the thorns; but the thorns spring up and stifle it.", "darby": "and others fell upon the thorns, and the thorns grew up and choked them;", "twenty": "Some, again, fell into the brambles; but the brambles shot up and choked it.", "acv": "And others fell in the thorns, and the thorns grew up and choked them.", "anderson": "Others fell among thorns, and the thorns sprung up and choked them.", "haweis": "And other seeds fell among the thorns; and the thorns sprang up and choked them:", "noyes": "And others fell among thorns; and the thorns grew up, and choked them.", "webster": "And some fell among thorns; and the thorns sprung up, and choked them:", "vulgate": "alia autem ceciderunt in spinas et creverunt spinae et suffocaverunt ea;"}}, {"v": 8, "ref": "13:8", "o": "ἄλλα δὲ ἔπεσεν ἐπὶ τὴν γῆν τὴν καλὴν καὶ ἐδίδου καρπόν, ὃ μὲν ἑκατὸν ὃ δὲ ἑξήκοντα ὃ δὲ τριάκοντα.", "en": {"kjv": "But other fell into good ground, and brought forth fruit, some an hundredfold, some sixtyfold, some thirtyfold.", "web": "Others fell on good soil, and yielded fruit: some one hundred times as much, some sixty, and some thirty.", "bsb": "Still other seed fell on good soil and produced a crop—a hundredfold, sixtyfold, or thirtyfold.", "asv": "and others fell upon the good ground, and yielded fruit, some a hundredfold, some sixty, some thirty.", "ylt": "and others fell upon the good ground, and were giving fruit, some indeed a hundredfold, and some sixty, and some thirty.", "tyndale": "Parte fell in good groud and brought forth good frute: some an hudred fold some sixtie fold some thyrty folde.", "dra": "And others fell upon good ground: and they brought forth fruit, some an hundred fold, some sixty fold, and some thirty fold.", "bbe": "And some, falling on good earth, gave fruit, some a hundred, some sixty, some thirty times as much.", "geneva": "Some againe fel in good ground, and brought forth fruite, one corne an hundreth folde, some sixtie folde, and another thirtie folde.", "wycliffe": "But othere seedis felden in to good lond, and yauen fruyt; summe an hundrid foold, an othir sixti foold, an othir thritti foold.", "rotherham": "But, some, fell upon the good ground, and did yield fruit,—this, indeed a hundred fold, and, that, sixty, and, the other, thirty.", "weymouth": "But a portion falls upon good ground, and gives a return, some a hundred for one, some sixty, some thirty.", "darby": "and others fell upon the good ground, and produced fruit, one a hundred, one sixty, and one thirty.", "twenty": "Some, however, fell on good soil, and yielded a return, sometimes one hundred, sometimes sixty, sometimes thirty fold.", "acv": "But others fell upon the good ground, and yielded fruit, some a hundredfold, some sixty, some thirty.", "anderson": "Others fell upon good ground, and brought forth fruit, some a hundred, some fifty, some thirty.", "haweis": "but others fell on good ground, and produced fruit, some an hundred, some sixty, and some thirty.", "noyes": "And others fell upon good ground; and yielded fruit, some a hundred fold, some Sixty, some thirty fold.", "webster": "But others fell into good ground, and brought forth fruit, some a hundred-fold, some sixty-fold, some thirty-fold.", "vulgate": "alia vero ceciderunt in terram bonam et dabant fructum aliud centesimum aliud sexagesimum aliud tricesimum;"}}, {"v": 9, "ref": "13:9", "o": "ὁ ἔχων ⸀ὦτα ἀκουέτω.", "en": {"kjv": "Who hath ears to hear, let him hear.", "web": "He who has ears to hear, let him hear.”", "bsb": "He who has ears, let him hear.”", "asv": "He that hath ears, let him hear.", "ylt": "He who is having ears to hear--let him hear.'", "tyndale": "Whosoever hath eares to heare let him heare.", "dra": "He that hath ears to hear, let him hear.", "bbe": "He who has ears, let him give ear.", "geneva": "He that hath eares to heare, let him heare.", "wycliffe": "He that hath eris of heryng, here he.", "rotherham": "He that hath ears, let him hear.", "weymouth": "Listen, every one who has ears!\"", "darby": "He that has ears, let him hear.", "twenty": "Let him who has ears hear.”", "acv": "He who has ears, let him hear.", "anderson": "He that has ears to hear, let him hear.", "haweis": "He that hath ears to hear, let him hear.", "noyes": "He that hath ears, let him hear.", "webster": "Who hath ears to hear, let him hear.", "vulgate": "qui habet aures audiendi audiat;"}}, {"v": 10, "ref": "13:10", "o": "Καὶ προσελθόντες οἱ μαθηταὶ εἶπαν αὐτῷ· Διὰ τί ἐν παραβολαῖς λαλεῖς αὐτοῖς;", "en": {"kjv": "And the disciples came, and said unto him, Why speakest thou unto them in parables?", "web": "The disciples came, and said to him, “Why do you speak to them in parables?”", "bsb": "Then the disciples came to Jesus and asked, “Why do You speak to the people in parables?”", "asv": "And the disciples came, and said unto him, Why speakest thou unto them in parables?", "ylt": "And the disciples having come near, said to him, `Wherefore in similes dost thou speak to them?'", "tyndale": "And the disciples came and sayde to him: Why speakest thou to the in parables?", "dra": "And his disciples came and said to him: Why speakest thou to them in parables?", "bbe": "And the disciples came and said to him, Why do you say things to them in the form of stories?", "geneva": "Then the disciples came, and said to him, Why speakest thou to them in parables?", "wycliffe": "And the disciplis camen nyy, and seiden to him, Whi spekist thou in parablis to hem?", "rotherham": "And the disciples, coming near, said to him, Wherefore, in parables, art thou speaking to them?", "weymouth": "(And His disciples came and asked Him, \"Why do you speak to them in figurative language?\"", "darby": "And the disciples came up and said to him, Why speakest thou to them in parables?", "twenty": "Afterwards his disciples came to him, and said: “Why do you speak to them in parables?”", "acv": "And the disciples having come, they said to him, Why do thou speak to them in parables?", "anderson": "And the disciples came and said to him: Why dost thou speak to them in parables?", "haweis": "And when his disciples came, they said to him, Why speakest thou to them in parables?", "noyes": "And the disciples came and said to him, Why dost thou speak to them in parables?", "webster": "And the disciples came, and said to him, Why speakest thou to them in parables?", "vulgate": "et accedentes discipuli dixerunt ei quare in parabolis loqueris eis;"}}, {"v": 11, "ref": "13:11", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν ⸀αὐτοῖς· Ὅτι ὑμῖν δέδοται γνῶναι τὰ μυστήρια τῆς βασιλείας τῶν οὐρανῶν, ἐκείνοις δὲ οὐ δέδοται.", "en": {"kjv": "He answered and said unto them, Because it is given unto you to know the mysteries of the kingdom of heaven, but to them it is not given.", "web": "He answered them, “To you it is given to know the mysteries of the Kingdom of Heaven, but it is not given to them.", "bsb": "He replied, “The knowledge of the mysteries of the kingdom of heaven has been given to you, but not to them.", "asv": "And he answered and said unto them, Unto you it is given to know the mysteries of the kingdom of heaven, but to them it is not given.", "ylt": "And he answering said to them that--`To you it hath been given to know the secrets of the reign of the heavens, and to these it hath not been given,", "tyndale": "He answered and sayde vnto them: it is geve vnto you to knowe ye secretes of the kyngdome of heve but to the it is not geve.", "dra": "Who answered and said to them: Because to you it is given to know the mysteries of the kingdom of heaven: but to them it is not given.", "bbe": "And he said to them in answer, To you is given the knowledge of the secrets of the kingdom of heaven, but to them it is not given.", "geneva": "And he answered, and said vnto them, Because it is giuen vnto you, to know the secretes of the kingdome of heauen, but to the it is not giue.", "wycliffe": "And he answeride, and seide to hem, `For to you it is youun to knowe the priuytees of the kyngdom of heuenes; but it is not youun to hem.", "rotherham": "And, he, answering, said, Because, unto you, hath it been given, to get to know the sacred secrets of the kingdom of the heavens,—whereas, unto them, hath it not been given.", "weymouth": "\"Because,\" He replied, \"while to you it is granted to know the secrets of the Kingdom of the Heavens, to them it is not.", "darby": "And he answering said to them, Because to you it is given to know the mysteries of the kingdom of the heavens, but to them it is not given;", "twenty": "“To you,” answered Jesus, “the knowledge of the hidden truths of the Kingdom of Heaven has been imparted, but not to those.", "acv": "And having answered, he said to them, Because it has been given to you to know the mysteries of the kingdom of the heavens, but to those men it has not been given.", "anderson": "He answered, and said to them: Because it is given to you to know the mysteries of the kingdom of heaven; but to them it is not given.", "haweis": "And he answered and said unto them, Because to you it is given to know the mysteries of the kingdom of heaven, but to them it is not given.", "noyes": "He answered and said, Because to you it hath been given to know the mysteries of the kingdom of heaven; but to them it hath not been given.", "webster": "He answered and said to them, Because it is given to you to know the mysteries of the kingdom of heaven, but to them it is not given.", "vulgate": "qui respondens ait illis quia vobis datum est nosse mysteria regni caelorum illis autem non est datum;"}}, {"v": 12, "ref": "13:12", "o": "ὅστις γὰρ ἔχει, δοθήσεται αὐτῷ καὶ περισσευθήσεται· ὅστις δὲ οὐκ ἔχει, καὶ ὃ ἔχει ἀρθήσεται ἀπ’ αὐτοῦ.", "en": {"kjv": "For whosoever hath, to him shall be given, and he shall have more abundance: but whosoever hath not, from him shall be taken away even that he hath.", "web": "For whoever has, to him will be given, and he will have abundance, but whoever doesn’t have, from him will be taken away even that which he has.", "bsb": "Whoever has will be given more, and he will have an abundance. Whoever does not have, even what he has will be taken away from him.", "asv": "For whosoever hath, to him shall be given, and he shall have abundance: but whosoever hath not, from him shall be taken away even that which he hath.", "ylt": "for whoever hath, it shall be given to him, and he shall have overabundance, and whoever hath not, even that which he hath shall be taken from him.", "tyndale": "For whosoever hath to him shall be geven: and he shall have aboundance. But whosoever hath not: fro hym shalbe takyn awaye even that he hath.", "dra": "For he that hath, to him shall be given, and he shall abound: but he that hath not, from him shall be taken away that also which he hath.", "bbe": "Because whoever has, to him will be given, and he will have more; but from him who has not, even what he has will be taken away.", "geneva": "For whosoeuer hath, to him shalbe giuen, and he shall haue abundance: but whosoeuer hath not, from him shalbe taken away, euen that he hath.", "wycliffe": "For it shal be youun to hym that hath, and he shal haue plente; but if a man hath not, also that thing that he hath shal be takun awei fro hym.", "rotherham": "For, whosoever hath, it shall be given, to him, and he shall be made to abound,—but, whoever hath not, even what he hath, shall be taken from him?", "weymouth": "For whoever has, to him more shall be given, and he shall have abundance; but whoever has not, from him even what he has shall be taken away.", "darby": "for whoever has, to him shall be given, and he shall be caused to be in abundance; but he who has not, even what he has shall be taken away from him.", "twenty": "For, to all who have, more will be given, and they shall have abundance; but, from all who have nothing, even what they have will be taken away.", "acv": "For whoever has, to him will be given, and he will have abundance, but whoever has not, even what he has will be taken away from him.", "anderson": "For whoever has, to him shall be given, and he shall have abundance; but whoever has not, even that which he has shall be taken from him.", "haweis": "For whosoever hath, more shall be given to him, and he shall have abundance: but whosoever hath not, even that he hath shall be taken from him.", "noyes": "For whoever hath, to him will be given, and he will have abundance; but whoever hath not, from him will be taken away even what he hath.", "webster": "For whoever hath, to him shall be given, and he shall have more abundance: but whoever hath not, from him shall be taken away even that which he hath.", "vulgate": "qui enim habet dabitur ei et abundabit qui autem non habet et quod habet auferetur ab eo;"}}, {"v": 13, "ref": "13:13", "o": "διὰ τοῦτο ἐν παραβολαῖς αὐτοῖς λαλῶ, ὅτι βλέποντες οὐ βλέπουσιν καὶ ἀκούοντες οὐκ ἀκούουσιν οὐδὲ συνίουσιν·", "en": {"kjv": "Therefore speak I to them in parables: because they seeing see not; and hearing they hear not, neither do they understand.", "web": "Therefore I speak to them in parables, because seeing they don’t see, and hearing, they don’t hear, neither do they understand.", "bsb": "This is why I speak to them in parables: ‘Though seeing, they do not see; though hearing, they do not hear or understand.’", "asv": "Therefore speak I to them in parables; because seeing they see not, and hearing they hear not, neither do they understand.", "ylt": "`Because of this, in similes do I speak to them, because seeing they do not see, and hearing they do not hear, nor understand,", "tyndale": "Therfore speake I to them in similitudes: for though they se they se not: and hearinge they heare not: nether vnderstonde.", "dra": "Therefore do I speak to them in parables: because seeing they see not, and hearing they hear not, neither do they understand.", "bbe": "For this reason I put things into the form of stories; because they see without seeing, and give ear without hearing, and the sense is not clear to them.", "geneva": "Therefore speake I to them in parables, because they seeing, doe not see: and hearing, they heare not, neither vnderstand.", "wycliffe": "Therfor Y speke to hem in parablis, for thei seynge seen not, and thei herynge heren not, nether vndurstonden;", "rotherham": "For this reason, in parables, unto them, do I speak,—because, seeing, they see not, and, hearing, they hear not,—neither do they understand.", "weymouth": "I speak to them in figurative language for this reason, that while looking they do not see, and while hearing they neither hear nor understand.", "darby": "For this cause I speak to them in parables, because seeing they do not see, and hearing they do not hear nor understand;", "twenty": "That is why I speak to them in parables, because, though they have eyes, they do not see, and though they have ears, they do not hear or understand.", "acv": "Because of this I speak to them in parables, because seeing they see not, and hearing they hear not, nor do they understand.", "anderson": "For this reason I speak to them in parables; because when they see, they see not; and when they hear, they hear not, nor do they understand.", "haweis": "Therefore I speak to them in parables: that seeing, they may not see; and hearing, they may not hear nor understand.", "noyes": "Therefore I speak to them in parables, because seeing they see not, and hearing they hear not, nor understand.", "webster": "Therefore I speak to them in parables: because they seeing see not; and hearing they hear not, neither do they understand.", "vulgate": "ideo in parabolis loquor eis quia videntes non vident et audientes non audiunt neque intellegunt;"}}, {"v": 14, "ref": "13:14", "o": "καὶ ἀναπληροῦται αὐτοῖς ἡ προφητεία Ἠσαΐου ἡ λέγουσα· Ἀκοῇ ἀκούσετε καὶ οὐ μὴ συνῆτε, καὶ βλέποντες βλέψετε καὶ οὐ μὴ ἴδητε.", "en": {"kjv": "And in them is fulfilled the prophecy of Esaias, which saith, By hearing ye shall hear, and shall not understand; and seeing ye shall see, and shall not perceive:", "web": "In them the prophecy of Isaiah is fulfilled, which says, ‘By hearing you will hear, and will in no way understand; Seeing you will see, and will in no way perceive:", "bsb": "In them the prophecy of Isaiah is fulfilled: ‘You will be ever hearing but never understanding; you will be ever seeing but never perceiving.", "asv": "And unto them is fulfilled the prophecy of Isaiah, which saith, By hearing ye shall hear, and shall in no wise understand; And seeing ye shall see, and shall in no wise perceive:", "ylt": "and fulfilled on them is the prophecy of Isaiah, that saith, With hearing ye shall hear, and ye shall not understand, and seeing ye shall see, and ye shall not perceive,", "tyndale": "And in the is fulfilled ye Prophesie of Esayas which prophesie sayth: with the eares ye shall heare and shall not vnderstonde and with the eyes ye shall se and shall not perceave.", "dra": "And the prophecy of Isaias is fulfilled in them, who saith: By hearing you shall hear, and shall not understand: and seeing you shall see, and shall not perceive.", "bbe": "And for them the words of Isaiah have come true, Though you give ear, you will not get knowledge; and seeing, you will see, but the sense will not be clear to you:", "geneva": "So in them is fulfilled the prophecie of Esaias, which prophecie saieth, By hearing, ye shall heare, and shall not vnderstand, and seeing, ye shall see, and shall not perceiue.", "wycliffe": "that the prophesie of Ysaie `seiynge be fulfillid `in hem, With heryng ye schulen here, and ye shulen not vndurstonde; and ye seynge schulen se, and ye shulen not se;", "rotherham": "And, again is being fulfilled in them, the prophecy of Isaiah, which saith,—They shall, surely hear, and yet will not understand, and, surely see, and yet not perceive;", "weymouth": "And in regard to them the prophecy of Isaiah is receiving signal fulfilment: \"`You will hear and hear and by no means understand, and you will look and look and by no means see.", "darby": "and in them is filled up the prophecy of Esaias, which says, Hearing ye shall hear and shall not understand, and beholding ye shall behold and not see;", "twenty": "And in them is being fulfilled that prophecy of Isaiah which says — ‘You will hear with your ears without ever understanding, and, though you have eyes, you will see without ever perceiving,", "acv": "And in them is fulfilled the prophecy of Isaiah, which says, By hearing ye will hear, and will, no, not understand, and seeing ye will see, and will, no, not perceive.", "anderson": "And in them is fulfilled the prophesy of Isaiah, which says: You shall surely hear, and you will not understand; and you shall surely see, and you will not perceive.", "haweis": "And in them is fulfilled the prophecy of Isaiah, which saith, With the hearing ye shall hear, and not understand; and seeing ye shall see, and in no wise perceive:", "noyes": "And in them is fulfilled the prophecy of Isaiah, which saith, \"Ye will hear indeed, and not understand; and ye will see indeed, and not perceive.", "webster": "And in them is fulfilled the prophecy of Isaiah, which saith, By hearing ye shall hear, and shall not understand; and seeing ye shall see, and shall not perceive:", "vulgate": "et adimpletur eis prophetia Esaiae dicens auditu audietis et non intellegetis et videntes videbitis et non videbitis;"}}, {"v": 15, "ref": "13:15", "o": "ἐπαχύνθη γὰρ ἡ καρδία τοῦ λαοῦ τούτου, καὶ τοῖς ὠσὶν βαρέως ἤκουσαν, καὶ τοὺς ὀφθαλμοὺς αὐτῶν ἐκάμμυσαν· μήποτε ἴδωσιν τοῖς ὀφθαλμοῖς καὶ τοῖς ὠσὶν ἀκούσωσιν καὶ τῇ καρδίᾳ συνῶσιν καὶ ἐπιστρέψωσιν, καὶ ἰάσομαι αὐτούς.", "en": {"kjv": "For this people’s heart is waxed gross, and their ears are dull of hearing, and their eyes they have closed; lest at any time they should see with their eyes, and hear with their ears, and should understand with their heart, and should be converted, and I should heal them.", "web": "for this people’s heart has grown callous, their ears are dull of hearing, they have closed their eyes; or else perhaps they might perceive with their eyes, hear with their ears, understand with their heart, and should turn again; and I would heal them.’", "bsb": "For this people’s heart has grown callous; they hardly hear with their ears, and they have closed their eyes. Otherwise they might see with their eyes, hear with their ears, understand with their hearts, and turn, and I would heal them.’", "asv": "For this people’s heart is waxed gross, And their ears are dull of hearing, And their eyes they have closed; Lest haply they should perceive with their eyes, And hear with their ears, And understand with their heart, And should turn again, And I should heal them.", "ylt": "for made gross was the heart of this people, and with the ears they heard heavily, and their eyes they did close, lest they might see with the eyes, and with the ears might hear, and with the heart understand, and turn back, and I might heal them.", "tyndale": "For this peoples hertes are wexed grosse and their eares were dull of herynge and their eyes have they closed lest they shulde se with their eyes and heare with their eares and shuld vnderstonde with their hertes and shuld tourne that I myght heale them.", "dra": "For the heart of this people is grown gross, and with their ears they have been dull of hearing, and their eyes they have shut: lest at any time they should see with their eyes, and hear with their ears, and understand with their heart, and be converted, and I should heal them.", "bbe": "For the heart of this people has become fat and their ears are slow in hearing and their eyes are shut; for fear that they might see with their eyes and give hearing with their ears and become wise in their hearts and be turned again to me, so that I might make them well.", "geneva": "For this peoples heart is waxed fat, and their eares are dull of hearing, and with their eyes they haue winked, lest they should see with their eyes, and heare with their eares, and should vnderstand with their hearts, and should returne, that I might heale them.", "wycliffe": "for the herte of this puple is greetli fattid, and thei herden heuyli with eeris, and thei han closed her iyen, lest sumtime thei seen with iyen, and with eeris heeren, and vndirstonden in herte, and thei be conuertid, and Y heele hem.", "rotherham": "For the heart of this people hath become dense, and, with their ears, heavily have they heard, and, their eyes, have they closed,—lest, once they should see with their eyes, and, with their ears, should hear, and, with their hearts, should understand, and return; when I would certainly heal them.", "weymouth": "For this people's mind is stupefied, their hearing has become dull, and their eyes they have closed; to prevent their ever seeing with their eyes, or hearing with their ears, or understanding with their minds, and turning back, so that I might heal them.'", "darby": "for the heart of this people has grown fat, and they have heard heavily with their ears, and they have closed their eyes as asleep, lest they should see with the eyes, and hear with the ears, and understand with the heart, and should be converted, and I should heal them.", "twenty": "for the mind of this nation has grown dense, and their ears are dull of hearing, their eyes also have they closed; lest some day they should perceive with their eyes, and with their ears they should hear, and in their mind they should understand, and should turn — and I should heal them.’", "acv": "For this people's heart became fat, and their ears hear heavily, and their eyes are shut, lest they should see with their eyes, and hear with their ears, and understand with their heart, and should turn, and I will heal them.", "anderson": "For the heart of this people has become fat; and with their ears they hear heavily; and their eyes they have closed; lest they should see with their eyes, and hear with their ears, and understand with their heart, and should turn to me, and I should give them health.", "haweis": "for the heart of this people is waxed gross, and with their ears they have heard heavily, and their eyes they have closed; lest at any time they should see with the eves, and hear with the ears, and understand with the heart, and be converted, and I should heal them.", "noyes": "For this people’s heart hath become gross, and their ears are dull of hearing, and their eyes they have closed, lest they should see with their eyes, and hear with their ears, and understand with their heart, and turn from their ways, and I should heal them.\"", "webster": "For this people's heart is become gross, and [their] ears are dull of hearing, and their eyes they have closed; lest at any time they should see with [their] eyes, and hear with [their] ears, and should understand with [their] heart, and should be converted, and I should heal them.", "vulgate": "incrassatum est enim cor populi huius et auribus graviter audierunt et oculos suos cluserunt nequando oculis videant et auribus audiant et corde intellegant et convertantur et sanem eos;"}}, {"v": 16, "ref": "13:16", "o": "ὑμῶν δὲ μακάριοι οἱ ὀφθαλμοὶ ὅτι βλέπουσιν, καὶ τὰ ὦτα ὑμῶν ὅτι ⸀ἀκούουσιν.", "en": {"kjv": "But blessed are your eyes, for they see: and your ears, for they hear.", "web": "“But blessed are your eyes, for they see; and your ears, for they hear.", "bsb": "But blessed are your eyes because they see, and your ears because they hear.", "asv": "But blessed are your eyes, for they see; and your ears, for they hear.", "ylt": "`And happy are your eyes because they see, and your ears because they hear,", "tyndale": "But blessed are youre eyes for they se: and youre eares for they heare.", "dra": "But blessed are your eyes, because they see, and your ears, because they hear.", "bbe": "But a blessing be on your eyes, because they see; and on your ears, because they are open.", "geneva": "But blessed are your eyes, for they see: and your eares, for they heare.", "wycliffe": "But youre iyen that seen ben blesside, and youre eeris that heren.", "rotherham": "But happy are, your, eyes, that they see, and your ears, that they hear;", "weymouth": "\"But as for you, blessed are your eyes, for they see, and your ears, for they hear.", "darby": "But blessed are your eyes because they see, and your ears because they hear;", "twenty": "But blessed are your eyes, for they see, and your ears, for they hear;", "acv": "But blessed are your eyes, because they see, and your ears, because they hear.", "anderson": "But blessed are your eyes, for they see; and your ears, for they hear.", "haweis": "But blessed are your eyes; for ye see: and your ears; for ye hear.", "noyes": "But blessed are your eyes, for they see; and your ears, for they hear.", "webster": "But blessed [are] your eyes, for they see: and your ears, for they hear.", "vulgate": "vestri autem beati oculi quia vident et aures vestrae quia audiunt;"}}, {"v": 17, "ref": "13:17", "o": "ἀμὴν γὰρ λέγω ὑμῖν ὅτι πολλοὶ προφῆται καὶ δίκαιοι ἐπεθύμησαν ἰδεῖν ἃ βλέπετε καὶ οὐκ εἶδαν, καὶ ἀκοῦσαι ἃ ἀκούετε καὶ οὐκ ἤκουσαν.", "en": {"kjv": "For verily I say unto you, That many prophets and righteous men have desired to see those things which ye see, and have not seen them; and to hear those things which ye hear, and have not heard them.", "web": "For most certainly I tell you that many prophets and righteous men desired to see the things which you see, and didn’t see them; and to hear the things which you hear, and didn’t hear them.", "bsb": "For truly I tell you, many prophets and righteous men longed to see what you see but did not see it, and to hear what you hear but did not hear it.", "asv": "For verily I say unto you, that many prophets and righteous men desired to see the things which ye see, and saw them not; and to hear the things which ye hear, and heard them not.", "ylt": "for verily I say to you, that many prophets and righteous men did desire to see that which ye look on, and they did not see, and to hear that which ye hear, and they did not hear.", "tyndale": "Verely I say vnto you that many Prophetes and perfaicte me have desired to se tho thinges which ye se and have not sene the: and to heare tho thinges which ye heare and have not herde the.", "dra": "For, amen, I say to you, many prophets and just men have desired to see the things that you see, and have not seen them: and to hear the things that you hear and have not heard them.", "bbe": "For truly, I say to you that prophets and upright men had a desire to see the things which you see, and saw them not; and to have knowledge of the words which have come to your ears, and they had it not.", "geneva": "For verely I say vnto you, that many Prophets, and righteous men haue desired to see those things which ye see, and haue not seene them, and to heare those things which ye heare, and haue not heard them.", "wycliffe": "Forsothe Y seie to you, that manye profetis and iust men coueitiden to se tho thingis that ye seen, and thei sayn not, and to heere tho thingis that ye heren, and thei herden not.", "rotherham": "For, verily, I say unto you—Many prophets and righteous men, have coveted to see what ye see, and have not seen, and to hear what ye hear, and have not heard.", "weymouth": "For I solemnly tell you that many Prophets and holy men have longed to see the sights you see, and have not seen them, and to hear the words you hear, and have not heard them.", "darby": "for verily I say unto you, that many prophets and righteous [men] have desired to see the things which ye behold and did not see [them], and to hear the things which ye hear and did not hear [them].", "twenty": "for I tell you that many Prophets and good men have longed for the sight of the things which you are seeing, yet never saw them, and to hear the things which you are hearing, yet never heard them.", "acv": "For truly I say to you, that many prophets and righteous men longed to see the things that ye see, and did not see them, and to hear the things that ye hear, and did not hear them.", "anderson": "For verily I say to you, Many prophets and righteous men desired to see what you see, and did not see; and to hear what you hear, and did not hear.", "haweis": "For verily I tell you, That many prophets and righteous men have greatly desired to see the things which ye see, and have not seen them; and to hear the things which ye hear, and have not heard them.", "noyes": "Truly do I say to you, that many prophets and righteous men desired to see the things which ye see, and did not see them; and to hear the things which ye hear, and did not hear them.", "webster": "For verily I say to you, That many prophets and righteous [men] have desired to see [the things] which ye see, and have not seen [them]; and to hear [the things] which ye hear, and have not heard [them].", "vulgate": "amen quippe dico vobis quia multi prophetae et iusti cupierunt videre quae videtis et non viderunt et audire quae auditis et non audierunt;"}}, {"v": 18, "ref": "13:18", "o": "Ὑμεῖς οὖν ἀκούσατε τὴν παραβολὴν τοῦ ⸀σπείραντος.", "en": {"kjv": "Hear ye therefore the parable of the sower.", "web": "“Hear, then, the parable of the farmer.", "bsb": "Consider, then, the parable of the sower:", "asv": "Hear then ye the parable of the sower.", "ylt": "`Ye, therefore, hear ye the simile of the sower:", "tyndale": "Heare ye therfore ye similitude of the sower.", "dra": "Hear you therefore the parable of the sower.", "bbe": "Give ear, then, to the story of the man who put the seed in the earth.", "geneva": "Heare ye therefore ye parable of ye sower.", "wycliffe": "Therfor here ye the parable of the sowere.", "rotherham": "Hear, ye, then, the parable of him that sowed:—", "weymouth": "\"To you then I will explain the parable of the Sower.", "darby": "Ye, therefore, hear the parable of the sower.", "twenty": "Listen, then, yourselves to the parable of the Sower.", "acv": "Hear ye then the parable of the man who sows.", "anderson": "Hear you, therefore, the parable of the sower.", "haweis": "Hear ye therefore the parable of the sower.", "noyes": "Hear ye therefore the parable of the sower.", "webster": "Hear ye therefore the parable of the sower.", "vulgate": "vos ergo audite parabolam seminantis;"}}, {"v": 19, "ref": "13:19", "o": "παντὸς ἀκούοντος τὸν λόγον τῆς βασιλείας καὶ μὴ συνιέντος, ἔρχεται ὁ πονηρὸς καὶ ἁρπάζει τὸ ἐσπαρμένον ἐν τῇ καρδίᾳ αὐτοῦ· οὗτός ἐστιν ὁ παρὰ τὴν ὁδὸν σπαρείς.", "en": {"kjv": "When any one heareth the word of the kingdom, and understandeth it not, then cometh the wicked one, and catcheth away that which was sown in his heart. This is he which received seed by the way side.", "web": "When anyone hears the word of the Kingdom, and doesn’t understand it, the evil one comes, and snatches away that which has been sown in his heart. This is what was sown by the roadside.", "bsb": "When anyone hears the message of the kingdom but does not understand it, the evil one comes and snatches away what was sown in his heart. This is the seed sown along the path.", "asv": "When any one heareth the word of the kingdom, and understandeth it not, then cometh the evil one, and snatcheth away that which hath been sown in his heart. This is he that was sown by the way side.", "ylt": "Every one hearing the word of the reign, and not understanding--the evil one doth come, and doth catch that which hath been sown in his heart; this is that sown by the way.", "tyndale": "Whosoever heareth the worde of ye kingdome and vnderstondeth it not ther cometh the evyll ma and catcheth awaye yt which was sowne in his hert. And this is he which was sowne by the wayesyde.", "dra": "When any one heareth the word of the kingdom, and understandeth it not, there cometh the wicked one, and catcheth away that which was sown in his heart: this is he that received the seed by the way side.", "bbe": "When the word of the kingdom comes to anyone, and the sense of it is not clear to him, then the Evil One comes, and quickly takes away that which was put in his heart. He is the seed dropped by the wayside.", "geneva": "Whensoeuer any man heareth the woorde of that kingdome, and vnderstandeth it not, that euil one commeth, and catcheth away that which was sowen in his heart: and this is he which hath receiued the seede by the way side.", "wycliffe": "Ech that herith the word of the rewme, and vndirstondith not, the yuel spirit cometh, and rauyschith that that is sowun in his herte; this it is, that is sowun bisidis the weie.", "rotherham": "When anyone heareth the word of the kingdom, and understandeth it not, the wicked one cometh, and catcheth up that which hath been sown in his heart,—this, is he, by the pathway, sown.", "weymouth": "When a man hears the Message concerning the Kingdom and does not understand it, the Evil one comes and catches away what has been sown in his heart. This is he who has received the seed by the road-side.", "darby": "From every one who hears the word of the kingdom and does not understand [it], the wicked one comes and catches away what was sown in his heart: this is he that is sown by the wayside.", "twenty": "When any one hears the Message of the Kingdom without understanding it, the Evil One comes and snatches away what has been sown in his mind. This is the man meant by the seed which was sown along the path.", "acv": "Of every man who hears the word of the kingdom, and does not understand it, evil comes, and snatches away what was sown in his heart. This is that which was sown by the wayside.", "anderson": "When any one hears the word of the kingdom, and understands it not, the wicked one comes and catches away that which was sown in his heart. This is he that received seed by the wayside.", "haweis": "When any person heareth the word of the kingdom, and doth not understand it, the wicked one cometh, and snatcheth away what was sown on his heart: such is he who is the sown by the road-side.", "noyes": "When any one heareth the word of the kingdom, and understandeth it not, the Evil One cometh, and snatcheth away that which was sown in his heart; this man is what was sown by the wayside.", "webster": "When any one heareth the word of the kingdom, and understandeth [it] not, then cometh the wicked [one], and catcheth away that which was sown in his heart. This is he who received seed by the way side.", "vulgate": "omnis qui audit verbum regni et non intellegit venit malus et rapit quod seminatum est in corde eius hic est qui secus viam seminatus est;"}}, {"v": 20, "ref": "13:20", "o": "ὁ δὲ ἐπὶ τὰ πετρώδη σπαρείς, οὗτός ἐστιν ὁ τὸν λόγον ἀκούων καὶ εὐθὺς μετὰ χαρᾶς λαμβάνων αὐτόν,", "en": {"kjv": "But he that received the seed into stony places, the same is he that heareth the word, and anon with joy receiveth it;", "web": "What was sown on the rocky places, this is he who hears the word, and immediately with joy receives it;", "bsb": "The seed sown on rocky ground is the one who hears the word and at once receives it with joy.", "asv": "And he that was sown upon the rocky places, this is he that heareth the word, and straightway with joy receiveth it;", "ylt": "`And that sown on the rocky places, this is he who is hearing the word, and immediately with joy is receiving it,", "tyndale": "But he yt was sowne in ye stony groude is he which heareth the worde of God and anone wt ioye receaveth it", "dra": "And he that received the seed upon stony ground, is he that heareth the word, and immediately receiveth it with joy.", "bbe": "And that which went on the stones, this is he who, hearing the word, straight away takes it with joy;", "geneva": "And hee that receiued seede in the stonie grounde, is he which heareth the woorde, and incontinently with ioy receiueth it,", "wycliffe": "But this that is sowun on the stony loond, this it is, that herith the word of God, and anoon with ioye takith it.", "rotherham": "And, he on the rocky places sown, the same, is he that, heareth the word, and, straightway, with joy, receiveth it;", "weymouth": "He who has received the seed on the rocky ground is the man who hears the Message and immediately receives it with joy.", "darby": "But he that is sown on the rocky places — this is he who hears the word and immediately receives it with joy,", "twenty": "By the seed which was sown on rocky places is meant the man who hears the Message, and at once accepts it joyfully;", "acv": "And that which was sown upon the rocky places, this is he who hears the word, and straightaway receiving it with joy,", "anderson": "He that received seed on the stony places is he that hears the word, and immediately receives it with joy.", "haweis": "But the sown on the rocky soil, is he who having heard the word, and instantly with joy receiving it,", "noyes": "And what was sown on the rocky places, this is he that heareth the word, and immediately receiveth it with joy,", "webster": "But he that received the seed into stony places, the same is he that heareth the word, and immediately with joy receiveth it;", "vulgate": "qui autem supra petrosa seminatus est hic est qui verbum audit et continuo cum gaudio accipit illud;"}}, {"v": 21, "ref": "13:21", "o": "οὐκ ἔχει δὲ ῥίζαν ἐν ἑαυτῷ ἀλλὰ πρόσκαιρός ἐστιν, γενομένης δὲ θλίψεως ἢ διωγμοῦ διὰ τὸν λόγον εὐθὺς σκανδαλίζεται.", "en": {"kjv": "Yet hath he not root in himself, but dureth for a while: for when tribulation or persecution ariseth because of the word, by and by he is offended.", "web": "yet he has no root in himself, but endures for a while. When oppression or persecution arises because of the word, immediately he stumbles.", "bsb": "But since he has no root, he remains for only a season. When trouble or persecution comes because of the word, he quickly falls away.", "asv": "yet hath he not root in himself, but endureth for a while; and when tribulation or persecution ariseth because of the word, straightway he stumbleth.", "ylt": "and he hath not root in himself, but is temporary, and persecution or tribulation having happened because of the word, immediately he is stumbled.", "tyndale": "yet hath he no rottes in him selfe and therfore dureth but a season: for assone as tribulacion or persecucion aryseth because of the worde by and by he falleth.", "dra": "Yet hath he not root in himself, but is only for a time: and when there ariseth tribulation and persecution because of the word, he is presently scandalized.", "bbe": "But having no root in himself, he goes on for a time; and when trouble comes or pain, because of the word, he quickly becomes full of doubts.", "geneva": "Yet hath he no roote in himselfe, and dureth but a season: for assoone as tribulation or persecution commeth because of the woorde, by and by he is offended.", "wycliffe": "And he hath not roote in hym silf, but is temporal. For whanne tribulacioun and persecucioun is maad for the word, anoon he is sclaundrid.", "rotherham": "yet hath he no root in himself, but is, only for a season,—and, there arising, tribulation or persecution because of the word, straightway, he findeth cause of stumbling.", "weymouth": "It has struck no root, however, within him. He continues for a time, but when suffering comes, or persecution, because of the Message, he at once stumbles and falls.", "darby": "but has no root in himself, but is for a time only; and when tribulation or persecution happens on account of the word, he is immediately offended.", "twenty": "but, as he has no root, he stands for only a short time; and, when trouble or persecution arises on account of the Message, he falls away at once.", "acv": "yet he has no root in himself, instead it is temporary. And when tribulation or persecution develops because of the word, straightaway he is caused to stumble.", "anderson": "Yet he has no root in himself, but endures for a while; and when affliction or persecution arises on account of the word, he immediately takes offense.", "haweis": "hath not really root in himself, but is merely temporary: and when tribulation or persecution ariseth for the word’s sake, immediately he is stumbled.", "noyes": "but, having no root within him, endureth only for a time; and when tribulation or persecution ariseth on account of the word, he immediately falleth away.", "webster": "Yet he hath not root in himself, but endureth for a while: for when tribulation or persecution ariseth because of the word, forthwith he is offended.", "vulgate": "non habet autem in se radicem sed est temporalis facta autem tribulatione et persecutione propter verbum continuo scandalizatur;"}}, {"v": 22, "ref": "13:22", "o": "ὁ δὲ εἰς τὰς ἀκάνθας σπαρείς, οὗτός ἐστιν ὁ τὸν λόγον ἀκούων, καὶ ἡ μέριμνα τοῦ αἰῶνος ⸀τούτου καὶ ἡ ἀπάτη τοῦ πλούτου συμπνίγει τὸν λόγον, καὶ ἄκαρπος γίνεται.", "en": {"kjv": "He also that received seed among the thorns is he that heareth the word; and the care of this world, and the deceitfulness of riches, choke the word, and he becometh unfruitful.", "web": "What was sown among the thorns, this is he who hears the word, but the cares of this age and the deceitfulness of riches choke the word, and he becomes unfruitful.", "bsb": "The seed sown among the thorns is the one who hears the word, but the worries of this life and the deceitfulness of wealth choke the word, and it becomes unfruitful.", "asv": "And he that was sown among the thorns, this is he that heareth the word; and the care of the world, and the deceitfulness of riches, choke the word, and he becometh unfruitful.", "ylt": "`And that sown toward the thorns, this is he who is hearing the word, and the anxiety of this age, and the deceitfulness of the riches, do choke the word, and it becometh unfruitful.", "tyndale": "He yt was sowne amoge thornes is he yt heareth ye worde of God: but the care of this worlde and the dissaytfulnes of ryches choke ye worde and so is he made vnfrutfull.", "dra": "And he that received the seed among thorns, is he that heareth the word, and the care of this world and the deceitfulness of riches choketh up the word, and he becometh fruitless.", "bbe": "And that which was dropped among the thorns, this is he who has the word; and the cares of this life, and the deceits of wealth, put a stop to the growth of the word and it gives no fruit.", "geneva": "And hee that receiued the seede among thornes, is hee that heareth the woorde: but the care of this worlde, and the deceitfulnesse of riches choke the word, and he is made vnfruitfull.", "wycliffe": "But he that is sowun in thornes, is this that heerith the word, and the bisynesse of this world, and the fallace of ritchessis strangulith the word, and it is maad with outen fruyt.", "rotherham": "And, he among the thorns sown, the same, is he that, heareth the word,—and, the anxiety of the age and the deceit of riches, choke up the word, and, unfruitful, it becometh.", "weymouth": "He who has received the seed among the thorns is the man who hears the Message, but the cares of the present age and the delusions of riches quite stifle the Message, and it becomes unfruitful.", "darby": "And he that is sown among the thorns — this is he who hears the word, and the anxious care of this life, and the deceit of riches choke the word, and he becomes unfruitful.", "twenty": "By the seed which was sown among the brambles is meant the man who hears the Message, but the cares of life and the glamour of wealth completely choke the Message, so that it gives no return.", "acv": "And that which was sown in the thorns, this is he who hears the word, and the care of this age, and the deceitfulness of wealth, choke the word, and he becomes unfruitful.", "anderson": "He that received seed among the thorns, is he that hears the word; and the cares of this age, and the deceitfulness of riches choke the word, and it becomes unfruitful.", "haweis": "But the sown among the thorns, is he who heareth the word, and the anxiety about this world and the deceitfulness of riches, choketh the word, and it becometh unfruitful.", "noyes": "And what was sown among the thorns, this is he that heareth the word, but the cares of the world and the deceitfulness of riches choke the word, and he becometh unfruitful.", "webster": "He also that received seed among the thorns is he that heareth the word; and the care of this world, and the deceitfulness of riches choke the word, and he becometh unfruitful.", "vulgate": "qui autem est seminatus in spinis hic est qui verbum audit et sollicitudo saeculi istius et fallacia divitiarum suffocat verbum et sine fructu efficitur;"}}, {"v": 23, "ref": "13:23", "o": "ὁ δὲ ἐπὶ τὴν ⸂καλὴν γῆν⸃ σπαρείς, οὗτός ἐστιν ὁ τὸν λόγον ἀκούων καὶ ⸀συνιείς, ὃς δὴ καρποφορεῖ καὶ ποιεῖ ὃ μὲν ἑκατὸν ὃ δὲ ἑξήκοντα ὃ δὲ τριάκοντα.", "en": {"kjv": "But he that received seed into the good ground is he that heareth the word, and understandeth it; which also beareth fruit, and bringeth forth, some an hundredfold, some sixty, some thirty.", "web": "What was sown on the good ground, this is he who hears the word, and understands it, who most certainly bears fruit, and produces, some one hundred times as much, some sixty, and some thirty.”", "bsb": "But the seed sown on good soil is the one who hears the word and understands it. He indeed bears fruit and produces a crop—a hundredfold, sixtyfold, or thirtyfold.”", "asv": "And he that was sown upon the good ground, this is he that heareth the word, and understandeth it; who verily beareth fruit, and bringeth forth, some a hundredfold, some sixty, some thirty.", "ylt": "`And that sown on the good ground: this is he who is hearing the word, and is understanding, who indeed doth bear fruit, and doth make, some indeed a hundredfold, and some sixty, and some thirty.'", "tyndale": "He which is sowne in ye good grounde is he yt heareth ye worde and vnderstodeth it which also bereth frute and bringeth forth some an.C. folde some sixtie folde and some .xxx. folde.", "dra": "But he that received the seed upon good ground, is he that heareth the word, and understandeth, and beareth fruit, and yieldeth the one an hundredfold, and another sixty, and another thirty.", "bbe": "And the seed which was put in good earth, this is he who gives ear to the word, and gets the sense of it; who gives fruit, some a hundred, some sixty, some thirty times as much.", "geneva": "But he that receiued the seede in the good ground, is he that heareth the worde, and vnderstandeth it, which also beareth fruite, and bringeth foorth, some an hundreth folde, some sixtie folde, and some thirtie folde.", "wycliffe": "But he that is sowun in to good loond, is this that herith the word, and vnderstondeth, and bryngith forth fruyt. And summe makith an hundrid fold, treuli anothir sixti fold, and another thritti fold.", "rotherham": "But, he on the good ground sown, the same, is he who doth hear and understand the word, who, indeed, beareth fruit and produceth,—this, a hundred, and, that, sixty, and, the other, thirty.", "weymouth": "But he who has received the seed on good ground is he who hears and understands. Such hearers give a return, and yield one a hundred for one, another sixty, another thirty.\")", "darby": "But he that is sown upon the good ground — this is he who hears and understands the word, who bears fruit also, and produces, one a hundred, one sixty, and one thirty.", "twenty": "But by the seed which was sown on the good ground is meant the man who hears the Message and understands it, and really yields a return, sometimes one hundred, sometimes sixty, sometimes thirty fold.”", "acv": "But that which was sown upon the good ground, this is he who hears the word, and understands it, who indeed bears fruit, and is productive, some a hundredfold, some sixty, some thirty.", "anderson": "But he that received seed on the good ground, is he that hears the word and understands it; who also produces fruit, and yields, one a hundred; another, sixty; another, thirty.", "haweis": "But the sown upon the good ground, is he who heareth the word, and understandeth it; who truly beareth fruit, and produceth, one an hundred fold, and another sixty, and another thirty.", "noyes": "And what was sown on the good ground, this is he that heareth the word, and understandeth it; who also beareth fruit, and yieldeth, one a hundred fold, another sixty, another thirty fold.", "webster": "But he that receiveth seed into the good ground is he that heareth the word, and understandeth [it]; who also beareth fruit, and bringeth forth, some a hundred fold, some sixty, some thirty.", "vulgate": "qui vero in terra bona seminatus est hic est qui audit verbum et intellegit et fructum adfert et facit aliud quidem centum aliud autem sexaginta porro aliud triginta;"}}, {"v": 24, "ref": "13:24", "o": "Ἄλλην παραβολὴν παρέθηκεν αὐτοῖς λέγων· Ὡμοιώθη ἡ βασιλεία τῶν οὐρανῶν ἀνθρώπῳ ⸀σπείραντι καλὸν σπέρμα ἐν τῷ ἀγρῷ αὐτοῦ.", "en": {"kjv": "Another parable put he forth unto them, saying, The kingdom of heaven is likened unto a man which sowed good seed in his field:", "web": "He set another parable before them, saying, “The Kingdom of Heaven is like a man who sowed good seed in his field,", "bsb": "Jesus put before them another parable: “The kingdom of heaven is like a man who sowed good seed in his field.", "asv": "Another parable set he before them, saying, The kingdom of heaven is likened unto a man that sowed good seed in his field:", "ylt": "Another simile he set before them, saying: `The reign of the heavens was likened to a man sowing good seed in his field,", "tyndale": "Another similitude put he forth vnto the sayinge: The kyngdome of heve is lyke vnto a man which sowed good seed in his felde.", "dra": "Another parable he proposed to them, saying: The kingdom of heaven is likened to a man that sowed good seed in his field.", "bbe": "And he gave them another story, saying, The kingdom of heaven is like a man who put good seed in his field:", "geneva": "Another parable put hee foorth vnto them, saying, The kingdome of heauen is like vnto a man which sowed good seede in his fielde.", "wycliffe": "Anothir parable Jhesus puttide forth to hem, and seide, The kyngdom of heuenes is maad lijk to a man, that sewe good seed in his feld.", "rotherham": "Another parable, put he before them, saying—The kingdom of the heavens hath become like a man sowing good seed in his field;", "weymouth": "Another parable He put before them. \"The Kingdom of the Heavens,\" He said, \"may be compared to a man who has sown good seed in his field,", "darby": "Another parable set he before them, saying, The kingdom of the heavens has become like a man sowing good seed in his field;", "twenty": "Another parable which Jesus told them was this — “The Kingdom of Heaven is compared to a man who sowed good seed in his field.", "acv": "He set forth another parable to them, saying, The kingdom of the heavens is compared to a man sowing good seed in his field.", "anderson": "Another parable he laid before them, saying: The kingdom of heaven is likened to a man that sowed good seed in his field.", "haweis": "Another parable proposed he to them, saying, The kingdom of heaven is like unto a man who sowed good seed in his field:", "noyes": "Another parable he put forth to them, saying, The kingdom of heaven is like a man who sowed good seed in his field.", "webster": "Another parable he proposed to them, saying, The kingdom of heaven is likened to a man who sowed good seed in his field:", "vulgate": "aliam parabolam proposuit illis dicens simile factum est regnum caelorum homini qui seminavit bonum semen in agro suo;"}}, {"v": 25, "ref": "13:25", "o": "ἐν δὲ τῷ καθεύδειν τοὺς ἀνθρώπους ἦλθεν αὐτοῦ ὁ ἐχθρὸς καὶ ⸀ἐπέσπειρεν ζιζάνια ἀνὰ μέσον τοῦ σίτου καὶ ἀπῆλθεν.", "en": {"kjv": "But while men slept, his enemy came and sowed tares among the wheat, and went his way.", "web": "but while people slept, his enemy came and sowed darnel weeds also among the wheat, and went away.", "bsb": "But while everyone was asleep, his enemy came and sowed weeds among the wheat, and slipped away.", "asv": "but while men slept, his enemy came and sowed tares also among the wheat, and went away.", "ylt": "and, while men are sleeping, his enemy came and sowed darnel in the midst of the wheat, and went away,", "tyndale": "But whyll men slepte ther came his foo and sowed tares amoge ye wheate and wet his waye.", "dra": "But while men were asleep, his enemy came and oversowed cockle among the wheat and went his way.", "bbe": "But while men were sleeping, one who had hate for him came and put evil seeds among the grain, and went away.", "geneva": "But while men slept, there came his enemie, and sowed tares among the wheat, and went his waie.", "wycliffe": "And whanne men slepten, his enemy cam, and sewe aboue taris in the myddil of whete, and wente awei.", "rotherham": "and, while men were sleeping, his enemy came, and sowed over darnel, in among the wheat,—and away he went.", "weymouth": "but during the night his enemy comes, and over the first seed he sows darnel among the wheat, and goes away.", "darby": "but while men slept, his enemy came and sowed darnel amongst the wheat, and went away.", "twenty": "But, while every one was asleep, his enemy came and sowed tares among the wheat, and then went away.", "acv": "But while the men slept, his enemy came and sowed tares in the midst of the wheat, and went away.", "anderson": "But while men slept, his enemy came and sowed tares among the wheat, and went away.", "haweis": "and while the men were asleep, his enemy came and sowed zizane among the wheat, and departed.", "noyes": "But while men slept, his enemy came, and sowed tares among the wheat; and went away.", "webster": "But while men slept, his enemy came and sowed tares among the wheat, and departed.", "vulgate": "cum autem dormirent homines venit inimicus eius et superseminavit zizania in medio tritici et abiit;"}}, {"v": 26, "ref": "13:26", "o": "ὅτε δὲ ἐβλάστησεν ὁ χόρτος καὶ καρπὸν ἐποίησεν, τότε ἐφάνη καὶ τὰ ζιζάνια.", "en": {"kjv": "But when the blade was sprung up, and brought forth fruit, then appeared the tares also.", "web": "But when the blade sprang up and produced fruit, then the darnel weeds appeared also.", "bsb": "When the wheat sprouted and bore grain, then the weeds also appeared.", "asv": "But when the blade sprang up and brought forth fruit, then appeared the tares also.", "ylt": "and when the herb sprang up, and yielded fruit, then appeared also the darnel.", "tyndale": "When ye blade was sproge vp and had brought forth frute the appered ye tares also.", "dra": "And when the blade was sprung up, and had brought forth fruit, then appeared also the cockle.", "bbe": "But when the green stem came up and gave fruit, the evil plants were seen at the same time.", "geneva": "And when the blade was sprong vp, and brought forth fruite, then appeared the tares also.", "wycliffe": "But whanne the erbe was growed, and made fruyt, thanne the taris apperiden.", "rotherham": "And, when the blade shot up, and brought forth, fruit, then, appeared, the darnel also.", "weymouth": "But when the blade shoots up and the grain is formed, then appears the darnel also.", "darby": "But when the blade shot up and produced fruit, then appeared the darnel also.", "twenty": "So, when the blades of corn shot up, and came into ear, the tares made their appearance also.", "acv": "And when the blade sprouted and produced fruit, then the tares also appeared.", "anderson": "But when the blade sprung up, and produced fruit, then appeared the tares also.", "haweis": "But when the blade was shot up, and produced fruit, then appeared also the zizane.", "noyes": "But when the blade grew up, and put forth fruit, then appeared the tares also.", "webster": "But when the blade had sprung up, and brought forth fruit, then appeared the tares also.", "vulgate": "cum autem crevisset herba et fructum fecisset tunc apparuerunt et zizania;"}}, {"v": 27, "ref": "13:27", "o": "προσελθόντες δὲ οἱ δοῦλοι τοῦ οἰκοδεσπότου εἶπον αὐτῷ· Κύριε, οὐχὶ καλὸν σπέρμα ⸀ἔσπειρας ἐν τῷ σῷ ἀγρῷ; πόθεν οὖν ἔχει ζιζάνια;", "en": {"kjv": "So the servants of the householder came and said unto him, Sir, didst not thou sow good seed in thy field? from whence then hath it tares?", "web": "The servants of the householder came and said to him, ‘Sir, didn’t you sow good seed in your field? Where did this darnel come from?’", "bsb": "The owner’s servants came to him and said, ‘Sir, didn’t you sow good seed in your field? Where then did the weeds come from?’", "asv": "And the servants of the householder came and said unto him, Sir, didst thou not sow good seed in thy field? whence then hath it tares?", "ylt": "`And the servants of the householder, having come near, said to him, Sir, good seed didst thou not sow in thy field? whence then hath it the darnel?", "tyndale": "The servauntes came to the housholder and sayde vnto him: Syr sowedest not thou good seed in thy closse fro whece the hath it tares?", "dra": "And the servants of the good man of the house coming said to him. Sir, didst thou not sow good seed in thy field? Whence then hath it cockle?", "bbe": "And the servants of the master of the house came and said to him, Sir, did you not put good seed in your field? how then has it evil plants?", "geneva": "Then came the seruaunts of the housholder, and sayd vnto him, Master, sowedst not thou good seede in thy fielde? from whence then hath it tares?", "wycliffe": "And the seruauntis of the hosebonde man camen, and seiden to hym, Lord, whether hast thou not sowun good seed in thi feeld? where of thanne hath it taris?", "rotherham": "And the servants of the householder, coming near, said to him,—Sir! was it not, good seed, thou didst sow in thy field? Whence then hath it, darnel?", "weymouth": "\"So the farmer's men come and ask him, \"`Sir, was it not good seed that you sowed on your land? Where then does the darnel come from?'", "darby": "And the bondmen of the householder came up and said to him, Sir, hast thou not sown good seed in thy field? whence then has it darnel?", "twenty": "On this the owner’s servants came to him, and said ‘Was not it good seed that you sowed in your field? Where, then, do the tares in it come from?’", "acv": "But the bondmen of the house-ruler having come, they said to him, Sir, did thou not sow good seed in thy field? From where then does it have tares?", "anderson": "And the servants of the master of the house came, and said to him, Sir, did you not sow good seed in your field? Whence, then, has it tares?", "haweis": "The servants of the proprietor came, and said to him, Master, didst thou not sow good seed in thy field? whence then hath it the zizane?", "noyes": "So the servants of the householder came and said to him, Sir, didst not thou sow good seed in thy field? Whence then hath it tares?", "webster": "So the servants of the householder came and said to him, Sir, didst thou not sow good seed in thy field? from whence then hath it tares?", "vulgate": "accedentes autem servi patris familias dixerunt ei domine nonne bonum semen seminasti in agro tuo unde ergo habet zizania;"}}, {"v": 28, "ref": "13:28", "o": "ὁ δὲ ἔφη αὐτοῖς· Ἐχθρὸς ἄνθρωπος τοῦτο ἐποίησεν. οἱ δὲ ⸂δοῦλοι αὐτῷ λέγουσιν⸃· Θέλεις οὖν ἀπελθόντες ⸀συλλέξωμεν αὐτά;", "en": {"kjv": "He said unto them, An enemy hath done this. The servants said unto him, Wilt thou then that we go and gather them up?", "web": "“He said to them, ‘An enemy has done this.’ “The servants asked him, ‘Do you want us to go and gather them up?’", "bsb": "‘An enemy did this,’ he replied. So the servants asked him, ‘Do you want us to go and pull them up?’", "asv": "And he said unto them, An enemy hath done this. And the servants say unto him, Wilt thou then that we go and gather them up?", "ylt": "And he saith to them, A man, an enemy, did this; and the servants said to him, Wilt thou, then, that having gone away we may gather it up?", "tyndale": "He sayde to the the envious ma hath done this. Then ye servauntes sayde vnto him: wilt thou then yt we go and gader them?", "dra": "And he said to them: An enemy hath done this. And the servants said to him: Wilt thou that we go and gather it up?", "bbe": "And he said, Someone has done this in hate. And the servants say to him, Is it your pleasure that we go and take them up?", "geneva": "And hee said to them, Some enuious man hath done this. Then the seruants saide vnto him, Wilt thou then that we go and gather them vp?", "wycliffe": "And he seide to hem, An enemy hath do this thing. And the seruauntis seiden to him, `Wolt thou that we goon, and gaderen hem?", "rotherham": "And he said unto them—An enemy, hath, done this. And they say, unto him—Wilt thou, then, that we go and collect it?", "weymouth": "\"`Some enemy has done this,' he said. \"`Shall we go, and collect it?' the men inquire.", "darby": "And he said to them, A man [that is] an enemy has done this. And the bondmen said to him, Wilt thou then that we should go and gather it [up]?", "twenty": "‘An enemy has done this,’ was his answer. ‘Do you wish us, then,’ they asked,’ to go and gather them together?’", "acv": "And he said to them, A hostile man did this. And the bondmen said to him, Do thou desire therefore, after going, we would gather them up?", "anderson": "He said to them, An enemy has done this. The servants said to him, Is it your will, then, that we go and gather them up?", "haweis": "He saith unto them, Some man, an enemy, hath done this. Then the servants said to him, Wilt thou that we go and weed them out?", "noyes": "He said to them, An enemy did this. The servants say to him, Dost thou wish then that we go and gather them up?", "webster": "He said to them, An enemy hath done this. The servants said to him, Wilt thou then that we go and gather them?", "vulgate": "et ait illis inimicus homo hoc fecit servi autem dixerunt ei vis imus et colligimus ea;"}}, {"v": 29, "ref": "13:29", "o": "ὁ δέ ⸀φησιν· Οὔ, μήποτε συλλέγοντες τὰ ζιζάνια ἐκριζώσητε ἅμα αὐτοῖς τὸν σῖτον·", "en": {"kjv": "But he said, Nay; lest while ye gather up the tares, ye root up also the wheat with them.", "web": "“But he said, ‘No, lest perhaps while you gather up the darnel weeds, you root up the wheat with them.", "bsb": "‘No,’ he said, ‘if you pull the weeds now, you might uproot the wheat with them.", "asv": "But he saith, Nay; lest haply while ye gather up the tares, ye root up the wheat with them.", "ylt": "`And he said, No, lest--gathering up the darnel--ye root up with it the wheat,", "tyndale": "But he sayde nay lest whill ye go aboute to wede out ye tares ye plucke vppe also wt them ye wheate by ye rottes:", "dra": "And he said: No, lest perhaps gathering up the cockle, you root up the wheat also together with it.", "bbe": "But he says, No, for fear that by chance while you take up the evil plants, you may be rooting up the grain with them.", "geneva": "But he saide, Nay, lest while yee goe about to gather the tares, yee plucke vp also with them the wheat.", "wycliffe": "And he seide, Nay, lest perauenture ye in gaderynge taris drawen vp with hem the whete bi the roote.", "rotherham": "And, he, saith—Nay! lest, at any time, while collecting the darnel, ye uproot, along with it, the wheat:", "weymouth": "\"`No,' he replied, `for fear that while collecting the darnel you should at the same time root up the wheat with it.", "darby": "But he said, No; lest [in] gathering the darnel ye should root up the wheat with it.", "twenty": "‘No,’ said he, ‘for fear that, while you are gathering the tares, you should root up the wheat as well.", "acv": "But he said, No, lest while gathering up the tares, ye uproot the wheat together with them.", "anderson": "But he said, No; lest while you are gathering the tares, you root up the wheat with them.", "haweis": "he replied, No; lest perhaps in weeding out the zizane, we root up the wheat with them.", "noyes": "But he said, Nay; lest, while ye gather up the tares, ye root up the wheat with them.", "webster": "But he said, No; lest while ye gather the tares, ye root up also the wheat with them.", "vulgate": "et ait non ne forte colligentes zizania eradicetis simul cum eis et triticum;"}}, {"v": 30, "ref": "13:30", "o": "ἄφετε συναυξάνεσθαι ἀμφότερα ⸀μέχρι τοῦ θερισμοῦ· καὶ ἐν καιρῷ τοῦ θερισμοῦ ἐρῶ τοῖς θερισταῖς· Συλλέξατε πρῶτον τὰ ζιζάνια καὶ δήσατε αὐτὰ εἰς δέσμας πρὸς τὸ κατακαῦσαι αὐτά, τὸν δὲ σῖτον ⸀συναγάγετε εἰς τὴν ἀποθήκην μου.", "en": {"kjv": "Let both grow together until the harvest: and in the time of harvest I will say to the reapers, Gather ye together first the tares, and bind them in bundles to burn them: but gather the wheat into my barn.", "web": "Let both grow together until the harvest, and in the harvest time I will tell the reapers, “First, gather up the darnel weeds, and bind them in bundles to burn them; but gather the wheat into my barn.”’”", "bsb": "Let both grow together until the harvest. At that time I will tell the harvesters: First collect the weeds and tie them in bundles to be burned; then gather the wheat into my barn.’”", "asv": "Let both grow together until the harvest: and in the time of the harvest I will say to the reapers, Gather up first the tares, and bind them in bundles to burn them; but gather the wheat into my barn.", "ylt": "suffer both to grow together till the harvest, and in the time of the harvest I will say to the reapers, Gather up first the darnel, and bind it in bundles, to burn it, and the wheat gather up into my storehouse.'", "tyndale": "let bothe growe to gether tyll harvest come and in tyme of harvest I wyll saye to the repers gather ye fyrst ye tares and bind the in sheves to be bret: but gather the wheete into my barne.", "dra": "Suffer both to grow until the harvest, and in the time of the harvest I will say to the reapers: Gather up first the cockle, and bind it into bundles to burn, but the wheat gather ye into my barn.", "bbe": "Let them come up together till the getting in of the grain; and then I will say to the workers, Take up first the evil plants, and put them together for burning: but put the grain into my store-house.", "geneva": "Let both growe together vntill the haruest, and in time of haruest I will say to the reapers, Gather yee first the tares, and binde them in sheaues to burne them: but gather the wheate into my barne.", "wycliffe": "Suffre ye hem bothe to wexe in to repyng tyme; and in the tyme of ripe corne Y shal seie to the reperis, First gadere ye to gidere the taris, and bynde hem to gidere in knytchis to be brent, but gadere ye whete in to my berne.", "rotherham": "Suffer both to grow together until the harvest, and at, harvest time, I will say unto the reapers,—Collect ye first, the darnel, and bind it into bundles, with a view to the burning it up; but, the wheat, be gathering it into my barn.", "weymouth": "Leave both to grow together until the harvest, and at harvest-time I will direct the reapers, Collect the darnel first, and make it up into bundles to burn it, but bring all the wheat into my barn.'\"", "darby": "Suffer both to grow together unto the harvest, and in time of the harvest I will say to the harvestmen, Gather first the darnel, and bind it into bundles to burn it; but the wheat bring together into my granary.", "twenty": "Let both grow side by side till harvest; and then I shall say to the reapers, Gather the tares together first, and tie them in bundles for burning; but bring all the wheat into my barn.’”", "acv": "Allow both to grow together until the harvest. And at the time of the harvest I will say to the reapers, Gather up first the tares, and bind them in bundles in order to burn them, but gather the wheat into my barn.", "anderson": "Let both grow together till the harvest, and in time of harvest I will say to the reapers, Collect first the tares, and bind them into bundles to burn them; but gather the wheat into my granary.", "haweis": "Let them both grow together till the harvest: and at the harvest-time I will say to the reapers, Gather out first the zizane, and bind them in bundles to burn them: but gather the wheat into my barn.", "noyes": "Let both grow together until the harvest; and in the time of harvest I will say to the reapers, Gather up first the tares, and bind them in bundles, to burn them; but gather the wheat into my barn.", "webster": "Let both grow together until the harvest: and in the time of harvest I will say to the reapers, Gather ye first the tares, and bind them in bundles to burn them: but gather the wheat into my barn.", "vulgate": "sinite utraque crescere usque ad messem et in tempore messis dicam messoribus colligite primum zizania et alligate ea fasciculos ad conburendum triticum autem congregate in horreum meum;"}}, {"v": 31, "ref": "13:31", "o": "Ἄλλην παραβολὴν παρέθηκεν αὐτοῖς λέγων· Ὁμοία ἐστὶν ἡ βασιλεία τῶν οὐρανῶν κόκκῳ σινάπεως, ὃν λαβὼν ἄνθρωπος ἔσπειρεν ἐν τῷ ἀγρῷ αὐτοῦ·", "en": {"kjv": "Another parable put he forth unto them, saying, The kingdom of heaven is like to a grain of mustard seed, which a man took, and sowed in his field:", "web": "He set another parable before them, saying, “The Kingdom of Heaven is like a grain of mustard seed, which a man took, and sowed in his field;", "bsb": "He put before them another parable: “The kingdom of heaven is like a mustard seed that a man planted in his field.", "asv": "Another parable set he before them, saying, The kingdom of heaven is like unto a grain of mustard seed, which a man took, and sowed in his field:", "ylt": "Another simile he set before them, saying: `The reign of the heavens is like to a grain of mustard, which a man having taken, did sow in his field,", "tyndale": "Another parable he put forthe vnto the sayinge. The kyngdome of heve is lyke vnto a grayne of mustard seed which a ma taketh and soweth in his felde", "dra": "Another parable he proposed unto them, saying: The kingdom of heaven is like to a grain of mustard seed, which a man took and sowed in his field.", "bbe": "He put another story before them, saying, The kingdom of heaven is like a grain of mustard seed which a man took and put in his field:", "geneva": "Another parable he put foorth vnto them, saying, The kingdome of heauen is like vnto a graine of mustard seede, which a man taketh and soweth in his fielde:", "wycliffe": "Another parable Jhesus puttide forth to hem, and seide, The kyngdom of heuenes is lijk to a corn of seneuey, which a man took, and sewe in his feeld.", "rotherham": "Another parable, put he before them, saying—The kingdom of the heavens is like unto, a grain of mustard seed, which a man took and sowed in his field;", "weymouth": "Another parable He put before them. \"The Kingdom of the Heavens,\" He said, \"is like a mustard-seed, which a man takes and sows in his ground.", "darby": "Another parable set he before them, saying, The kingdom of the heavens is like a grain of mustard [seed] which a man took and sowed in his field;", "twenty": "Another parable which he told them was this — “The Kingdom of Heaven is like a mustard-seed, which a man took and sowed in his field.", "acv": "He set forth another parable to them, saying, The kingdom of the heavens is like a grain of mustard plant, which having taken, a man sowed in his field.", "anderson": "Another parable he laid before them, saying: The kingdom of heaven is like a grain of mustard, that a man took and sowed in his field.", "haweis": "Another parable he proposed to them, saying, The kingdom of heaven is like a grain of mustard, which a man took and sowed in his field:", "noyes": "Another parable he put forth to them, saying, The kingdom of heaven is like a grain of mustard, which a man took and sowed in his field.", "webster": "Another parable he proposed to them, saying, The kingdom of heaven is like a grain of mustard-seed, which a man took, and sowed in his field:", "vulgate": "aliam parabolam proposuit eis dicens simile est regnum caelorum grano sinapis quod accipiens homo seminavit in agro suo;"}}, {"v": 32, "ref": "13:32", "o": "ὃ μικρότερον μέν ἐστιν πάντων τῶν σπερμάτων, ὅταν δὲ αὐξηθῇ μεῖζον τῶν λαχάνων ἐστὶν καὶ γίνεται δένδρον, ὥστε ἐλθεῖν τὰ πετεινὰ τοῦ οὐρανοῦ καὶ κατασκηνοῦν ἐν τοῖς κλάδοις αὐτοῦ.", "en": {"kjv": "Which indeed is the least of all seeds: but when it is grown, it is the greatest among herbs, and becometh a tree, so that the birds of the air come and lodge in the branches thereof.", "web": "which indeed is smaller than all seeds. But when it is grown, it is greater than the herbs, and becomes a tree, so that the birds of the air come and lodge in its branches.”", "bsb": "Although it is the smallest of all seeds, yet it grows into the largest of garden plants and becomes a tree, so that the birds of the air come and nest in its branches.”", "asv": "which indeed is less than all seeds; but when it is grown, it is greater than the herbs, and becometh a tree, so that the birds of the heaven come and lodge in the branches thereof.", "ylt": "which less, indeed, is than all the seeds, but when it may be grown, is greatest of the herbs, and becometh a tree, so that the birds of the heaven do come and rest in its branches.'", "tyndale": "which is ye leest of all seedes. But when it is groune it is the greatest amoge yerbes and it is a tree: so yt the bryddes of the ayer come and bylde in the brauches of it.", "dra": "Which is the least indeed of all seeds; but when it is grown up, it is greater than all herbs, and becometh a tree, so that the birds of the air come, and dwell in the branches thereof.", "bbe": "Which is smaller than all seeds; but when it has come up it is greater than the plants, and becomes a tree, so that the birds of heaven come and make their resting-places in its branches.", "geneva": "Which in deede is the least of all seedes: but when it is growen, it is the greatest among herbes, and it is a tree, so that the birdes of heauen come and builde in the branches thereof.", "wycliffe": "Which is the leeste of alle seedis, but whanne it hath woxen, it is the moste of alle wortis, and is maad a tre; so that briddis of the eir comen, and dwellen in the bowis therof.", "rotherham": "which, indeed, is, less, than all seeds, but, when grown, is greater than garden-plants, and becometh a tree,—so that the birds of heaven come, and lodge among its branches.", "weymouth": "It is the smallest of all seeds, and yet when full-grown it is larger than any herb and forms a tree, so that the birds come and build in its branches.\"", "darby": "which is less indeed than all seeds, but when it is grown is greater than herbs, and becomes a tree, so that the birds of heaven come and roost in its branches.", "twenty": "This seed is smaller than all other seeds, but, when it has grown up, it is larger than the herbs and becomes a tree, so that ‘the wild birds come and roost in its branches.’”", "acv": "Which indeed is smaller than all seeds, but when it is grown, it is greater than the plants, and becomes a tree, so as for the birds of the sky to come and lodge in the branches of it.", "anderson": "It is, indeed, the least of all seeds; but when it is grown it is the largest of garden-plants, and becomes a tree, so that the birds of the air come and roost in its branches.", "haweis": "which indeed is among the smallest of all seeds; but when it is grown, it is among the greatest of herbs, and becomes a tree, so that the birds of the air come and make their nests in the branches of it.", "noyes": "Which is the least indeed of all seeds; but when it is grown, it is greater than the herbs, and becometh a tree, so that the birds of the air come and lodge in its branches.", "webster": "Which indeed is the least of all seeds: but when it is grown, it is the greatest among herbs, and becometh a tree, so that the birds of the air come and lodge on its branches.", "vulgate": "quod minimum quidem est omnibus seminibus cum autem creverit maius est omnibus holeribus et fit arbor ita ut volucres caeli veniant et habitent in ramis eius;"}}, {"v": 33, "ref": "13:33", "o": "Ἄλλην παραβολὴν ἐλάλησεν αὐτοῖς· Ὁμοία ἐστὶν ἡ βασιλεία τῶν οὐρανῶν ζύμῃ, ἣν λαβοῦσα γυνὴ ⸀ἐνέκρυψεν εἰς ἀλεύρου σάτα τρία ἕως οὗ ἐζυμώθη ὅλον.", "en": {"kjv": "Another parable spake he unto them; The kingdom of heaven is like unto leaven, which a woman took, and hid in three measures of meal, till the whole was leavened.", "web": "He spoke another parable to them. “The Kingdom of Heaven is like yeast, which a woman took, and hid in three measuresof meal, until it was all leavened.”", "bsb": "He told them still another parable: “The kingdom of heaven is like leaven that a woman took and mixed into three measures of flour, until all of it was leavened.”", "asv": "Another parable spake he unto them; The kingdom of heaven is like unto leaven, which a woman took, and hid in three measures of meal, till it was all leavened.", "ylt": "Another simile spake he to them: `The reign of the heavens is like to leaven, which a woman having taken, hid in three measures of meal, till the whole was leavened.'", "tyndale": "Another similitude sayde he to them. The kyngdome of heven is lyke vnto leve which a woman taketh and hydeth in .iii. peckes of meele tyll all be levended.", "dra": "Another parable he spoke to them: The kingdom of heaven is like to leaven, which a woman took and hid in three measures of meal, until the whole was leavened.", "bbe": "Another story he gave to them: The kingdom of heaven is like leaven, which a woman took, and put in three measures of meal, till it was all leavened.", "geneva": "Another parable spake hee to them, The kingdome of heauen is like vnto leauen, which a woman taketh and hideth in three pecks of meale, till all be leauened.", "wycliffe": "Another parable Jhesus spac to hem, The kyngdom of heuenes is lijk to sour douy, which a womman took, and hidde in thre mesuris of mele, til it were alle sowrid.", "rotherham": "Another parable, [spake he unto them]:—The kingdom of the heavens is like, unto leaven, which a woman took and hid in three measures of flour until, the whole, was leavened.", "weymouth": "Another parable He spoke to them. \"The Kingdom of the Heavens,\" He said, \"is like yeast which a woman takes and buries in a bushel of flour, for it to work there till the whole mass has risen.\"", "darby": "He spoke another parable to them: The kingdom of the heavens is like leaven, which a woman took and hid in three measures of meal until it had been all leavened.", "twenty": "This was another parable which Jesus related — “The Kingdom of Heaven is like some yeast which a woman took and covered up in three pecks of flour, until the whole had risen.”", "acv": "He spoke another parable to them. The kingdom of the heavens is like leaven, which having taken, a woman hid in three measures of meal until it was all leavened.", "anderson": "He spoke another parable to them: The kingdom of heaven is like leaven which a woman took and hid in three measures of flour, till the whole was leavened.", "haweis": "Another parable spake he to them: The kingdom of heaven is like leaven, which a woman took and covered up in three measures of flour, until the whole was leavened.", "noyes": "Another parable he spoke to them: The kingdom of heaven is like leaven, which a woman took and hid in three measures of meal, till the whole was leavened.", "webster": "Another parable he spoke to them; The kingdom of heaven is like leaven, which a woman took, and hid in three measures of meal, till the whole was leavened.", "vulgate": "aliam parabolam locutus est eis simile est regnum caelorum fermento quod acceptum mulier abscondit in farinae satis tribus donec fermentatum est totum;"}}, {"v": 34, "ref": "13:34", "o": "Ταῦτα πάντα ἐλάλησεν ὁ Ἰησοῦς ἐν παραβολαῖς τοῖς ὄχλοις, καὶ χωρὶς παραβολῆς ⸀οὐδὲν ἐλάλει αὐτοῖς·", "en": {"kjv": "All these things spake Jesus unto the multitude in parables; and without a parable spake he not unto them:", "web": "Jesus spoke all these things in parables to the multitudes; and without a parable, he didn’t speak to them,", "bsb": "Jesus spoke all these things to the crowds in parables. He did not tell them anything without using a parable.", "asv": "All these things spake Jesus in parables unto the multitudes; and without a parable spake he nothing unto them:", "ylt": "All these things spake Jesus in similes to the multitudes, and without a simile he was not speaking to them,", "tyndale": "All these thynge spake Iesus vnto the people by similitudes and with oute similitudes spake he nothinge to them", "dra": "All these things Jesus spoke in parables to the multitudes: and without parables he did not speak to them.", "bbe": "All these things Jesus said to the people in the form of stories; and without a story he said nothing to them:", "geneva": "All these thinges spake Iesus vnto the multitude in parables, and without parables spake he not to them,", "wycliffe": "Jhesus spac alle thes thingis in parablis to the puple, and he spac not to hem with out parablis, that it schulde be fulfillid,", "rotherham": "All these things, spake Jesus in parables, unto the multitudes, and, without a parable, was he speaking, nothing, unto them:", "weymouth": "All this Jesus spoke to the people in figurative language, and except in figurative language He spoke nothing to them,", "darby": "All these things Jesus spoke to the crowds in parables, and without a parable he did not speak to them,", "twenty": "Of all this Jesus spoke to the crowd in parables; indeed to them he used never to speak at all except in parables,", "acv": "Jesus spoke all these things in parables to the multitudes, and he did not speak to them independent of a parable,", "anderson": "All these things Jesus spoke to the multitudes in parables, and without a parable he did not speak to them;", "haweis": "All these things spake Jesus in parables to the multitudes; and without a parable he spake not to them:", "noyes": "All these things Jesus spoke to the multitudes in parables, and without a parable he spoke nothing to them;", "webster": "All these things Jesus spoke to the multitude in parables; and without a parable he spoke not to them:", "vulgate": "haec omnia locutus est Iesus in parabolis ad turbas et sine parabolis non loquebatur eis;"}}, {"v": 35, "ref": "13:35", "o": "ὅπως πληρωθῇ τὸ ῥηθὲν διὰ τοῦ προφήτου λέγοντος· Ἀνοίξω ἐν παραβολαῖς τὸ στόμα μου, ἐρεύξομαι κεκρυμμένα ἀπὸ ⸀καταβολῆς.", "en": {"kjv": "That it might be fulfilled which was spoken by the prophet, saying, I will open my mouth in parables; I will utter things which have been kept secret from the foundation of the world.", "web": "that it might be fulfilled which was spoken through the prophet, saying, “I will open my mouth in parables; I will utter things hidden from the foundation of the world.”", "bsb": "So was fulfilled what was spoken through the prophet: “I will open My mouth in parables; I will utter things hidden since the foundation of the world.”", "asv": "that it might be fulfilled which was spoken through the prophet, saying, I will open my mouth in parables; I will utter things hidden from the foundation of the world.", "ylt": "that it might be fulfilled that was spoken through the prophet, saying, `I will open in similes my mouth, I will utter things having been hidden from the foundation of the world.'", "tyndale": "to fulfyll that which was spoke by the Prophet sayinge: I wyll ope my mouth in similitudes and wyll speake forth thinges which have bene kepte secrete from the begynninge of the worlde.", "dra": "That it might be fulfilled which was spoken by the prophet, saying: I will open my mouth in parables, I will utter things hidden from the foundation of the world.", "bbe": "That it might come true which was said by the prophet, Opening my mouth, I will give out stories; I will give knowledge of things kept secret from before all time.", "geneva": "That it might be fulfilled, which was spoken by the Prophet, saying, I will open my mouth in parables, and will vtter the thinges which haue beene kept secrete from the foundation of the worlde.", "wycliffe": "that is seid bi the prophete, seiynge, Y shal opene my mouth in parablis; Y shal telle out hid thingis fro the makyng of the world.", "rotherham": "that it might be fulfilled, which was spoken through the prophet, saying—I will open, in parables, my mouth, I will bring up things hidden from the foundation!", "weymouth": "in fulfilment of the saying of the Prophet, \"I will open my mouth in figurative language, I will utter things kept hidden since the creation of all things.\"", "darby": "so that that should be fulfilled which was spoken through the prophet, saying, I will open my mouth in parables; I will utter things hidden from [the] world's foundation.", "twenty": "in fulfilment of these words in the Prophet — ‘I will speak to them in parables; I will utter things kept secret since the foundation of the world.’", "acv": "so that what was spoken through the prophet might be fulfilled, which says, I will open my mouth in parables. I will utter things concealed from the foundation of the world.", "anderson": "that the word might be fulfilled which was spoken by the prophet, saying: I will open my mouth in parables; I will utter things that have been kept secret from the foundation of the world.", "haweis": "that it might be fulfilled which was spoken by the prophet, saying, I will open my mouth in parables, I will bring forth things hid from the foundation of the world.", "noyes": "that it might be fulfilled which was spoken through the prophet Isaiah, saying, \"I will open my mouth in parables; I will utter things hidden from the foundation [of the world].\"", "webster": "That it might be fulfilled which was spoken by the prophet, saying, I will open my mouth in parables; I will utter things which have been kept secret from the foundation of the world.", "vulgate": "ut impleretur quod dictum erat per prophetam dicentem aperiam in parabolis os meum eructabo abscondita a constitutione mundi;"}}, {"v": 36, "ref": "13:36", "o": "Τότε ἀφεὶς τοὺς ὄχλους ἦλθεν εἰς τὴν ⸀οἰκίαν. καὶ προσῆλθον αὐτῷ οἱ μαθηταὶ αὐτοῦ λέγοντες· ⸀Διασάφησον ἡμῖν τὴν παραβολὴν τῶν ζιζανίων τοῦ ἀγροῦ.", "en": {"kjv": "Then Jesus sent the multitude away, and went into the house: and his disciples came unto him, saying, Declare unto us the parable of the tares of the field.", "web": "Then Jesus sent the multitudes away, and went into the house. His disciples came to him, saying, “Explain to us the parable of the darnel weeds of the field.”", "bsb": "Then Jesus dismissed the crowds and went into the house. His disciples came to Him and said, “Explain to us the parable of the weeds in the field.”", "asv": "Then he left the multitudes, and went into the house: and his disciples came unto him, saying, Explain unto us the parable of the tares of the field.", "ylt": "Then having let away the multitudes, Jesus came to the house, and his disciples came near to him, saying, `Explain to us the simile of the darnel of the field.'", "tyndale": "Then sent Iesus ye people awaye and came to housse. And his disciples came vnto him sayinge: declare vnto vs the similitude of the tares of the felde.", "dra": "Then having sent away the multitudes, he came into the house, and his disciples came to him, saying: Expound to us the parable of the cockle of the field.", "bbe": "Then he went away from the people, and went into the house; and his disciples came to him, saying, Make clear to us the story of the evil plants in the field.", "geneva": "Then sent Iesus the multitude away, and went into the house. And his disciples came vnto him, saying, Declare vnto vs the parable of the tares of that fielde.", "wycliffe": "Thanne he lefte the puple, and cam in to an hous; and hise disciplis camen to him, and seiden, Expowne to vs the parable of taris of the feeld.", "rotherham": "Then, dismissing the multitudes, he went into the house, and his disciples came near to him, saying—Make quite plain to us the parable of the darnel of the field.", "weymouth": "When He had dismissed the people and had returned to the house, His disciples came to Him with the request, \"Explain to us the parable of the darnel sown in the field.\"", "darby": "Then, having dismissed the crowds, he went into the house; and his disciples came to him, saying, Expound to us the parable of the darnel of the field.", "twenty": "Then Jesus left the crowd, and went into the house. Presently his disciples came to him, and said: “Explain to us the parable of the tares in the field.”", "acv": "Then having sent the multitudes away, Jesus came into the house. And his disciples came to him, saying, Explain to us the parable of the tares of the field.", "anderson": "Then Jesus left the multitudes, and went into the house. And his disciples came to him and said: Explain to us the parable of the tares of the field.", "haweis": "Then Jesus dismissing the multitudes, went into a house; and his disciples came unto him, saying, Explain to us the parable of the zizane of the field.", "noyes": "Then he sent the multitudes away, and went into the house. And his disciples came to him, saying, Explain to us the parable of the tares of the field.", "webster": "Then Jesus sent the multitude away, and went into the house: and his disciples came to him, saying, Declare to us the parable of the tares of the field.", "vulgate": "tunc dimissis turbis venit in domum et accesserunt ad eum discipuli eius dicentes dissere nobis parabolam zizaniorum agri;"}}, {"v": 37, "ref": "13:37", "o": "ὁ δὲ ἀποκριθεὶς ⸀εἶπεν· Ὁ σπείρων τὸ καλὸν σπέρμα ἐστὶν ὁ υἱὸς τοῦ ἀνθρώπου·", "en": {"kjv": "He answered and said unto them, He that soweth the good seed is the Son of man;", "web": "He answered them, “He who sows the good seed is the Son of Man,", "bsb": "He replied, “The One who sows the good seed is the Son of Man.", "asv": "And he answered and said, He that soweth the good seed is the Son of man;", "ylt": "And he answering said to them, `He who is sowing the good seed is the Son of Man,", "tyndale": "Then answered he and sayde to them. He that soweth the good seed is the sonne of man.", "dra": "Who made answer and said to them: He that soweth the good seed is the Son of man.", "bbe": "And he made answer and said, He who puts the good seed in the earth is the Son of man;", "geneva": "Then answered he, and saide to them, He that soweth the good seede, is the Sonne of man.", "wycliffe": "Which answeride, and seide, He that sowith good seed is mannus sone;", "rotherham": "And, he, answering, said—He that soweth the good seed, is the Son of Man;", "weymouth": "\"The sower of the good seed,\" He replied, \"is the Son of Man;", "darby": "But he answering said, He that sows the good seed is the Son of man,", "twenty": "And he answered: “The sower of the good seed is the Son of Man.", "acv": "And having answered, he said to them, He who sows the good seed is the Son of man,", "anderson": "He answered and said to them: He that sows the good seed is the Son of man;", "haweis": "And he replying said to them, He that sowed the good seed, is the Son of man;", "noyes": "He answered and said, He that soweth the good seed is the Son of man.", "webster": "He answered and said to them, He that soweth the good seed is the Son of man;", "vulgate": "qui respondens ait qui seminat bonum semen est Filius hominis;"}}, {"v": 38, "ref": "13:38", "o": "ὁ δὲ ἀγρός ἐστιν ὁ κόσμος· τὸ δὲ καλὸν σπέρμα, οὗτοί εἰσιν οἱ υἱοὶ τῆς βασιλείας· τὰ δὲ ζιζάνιά εἰσιν οἱ υἱοὶ τοῦ πονηροῦ,", "en": {"kjv": "The field is the world; the good seed are the children of the kingdom; but the tares are the children of the wicked one;", "web": "the field is the world; and the good seed, these are the children of the Kingdom; and the darnel weeds are the children of the evil one.", "bsb": "The field is the world, and the good seed represents the sons of the kingdom. The weeds are the sons of the evil one,", "asv": "and the field is the world; and the good seed, these are the sons of the kingdom; and the tares are the sons of the evil one;", "ylt": "and the field is the world, and the good seed, these are the sons of the reign, and the darnel are the sons of the evil one,", "tyndale": "And ye felde is the worlde. And the chyldre of the kingdome they are ye good seed. And the tares are the chyldren of ye wicked.", "dra": "And the field is the world. And the good seed are the children of the kingdom. And the cockle are the children of the wicked one.", "bbe": "And the field is the world; and the good seed is the sons of the kingdom; and the evil seeds are the sons of the Evil One;", "geneva": "And the field is the worlde, and the good seede are the children of the kingdome, and the tares are the children of that wicked one.", "wycliffe": "the feeld is the world; but the good seed, these ben sones of the kyngdom, but taris, these ben yuele children;", "rotherham": "And, the field, is the world, and, the good seed, these are the sons of the kingdom,—and, the darnel seeds, are the sons of the evil one;", "weymouth": "the field is the world; the good seed--these are the sons of the Kingdom; the darnel, the sons of the Evil one.", "darby": "and the field is the world; and the good seed, these are the sons of the kingdom, but the darnel are the sons of the evil [one];", "twenty": "The field is the world. By the good seed is meant the People of the Kingdom. The tares are the wicked,", "acv": "and the field is the world, and the good seed, these are the sons of the kingdom, but the tares are the sons of evil.", "anderson": "the field is the world; the good seed are the sons of the kingdom; the tares are the sons of the Wicked One;", "haweis": "the field is the world: and the good seed are those who are the children of the kingdom; but the zizane are the children of the wicked one;", "noyes": "The field is the world; the good seed is the sons of the kingdom; but the tares are the sons of the Evil One;", "webster": "The field is the world; the good seed are the children of the kingdom; but the tares are the children of the wicked [one];", "vulgate": "ager autem est mundus bonum vero semen hii sunt filii regni zizania autem filii sunt nequam;"}}, {"v": 39, "ref": "13:39", "o": "ὁ δὲ ἐχθρὸς ὁ σπείρας αὐτά ἐστιν ὁ διάβολος· ὁ δὲ θερισμὸς συντέλεια ⸀αἰῶνός ἐστιν, οἱ δὲ θερισταὶ ἄγγελοί εἰσιν.", "en": {"kjv": "The enemy that sowed them is the devil; the harvest is the end of the world; and the reapers are the angels.", "web": "The enemy who sowed them is the devil. The harvest is the end of the age, and the reapers are angels.", "bsb": "and the enemy who sows them is the devil. The harvest is the end of the age, and the harvesters are angels.", "asv": "and the enemy that sowed them is the devil: and the harvest is the end of the world; and the reapers are angels.", "ylt": "and the enemy who sowed them is the devil, and the harvest is a full end of the age, and the reapers are messengers.", "tyndale": "And the enemye that soweth the is ye devell. The harvest is ye end of the worlde. And the repers be ye angels.", "dra": "And the enemy that sowed them, is the devil. But the harvest is the end of the world. And the reapers are the angels.", "bbe": "And he who put them in the earth is Satan; and the getting in of the grain is the end of the world; and those who get it in are the angels.", "geneva": "And the enemie that soweth them, is the deuill, and the haruest is the end of the worlde, and the reapers be the Angels.", "wycliffe": "the enemye that sowith hem is the feend; and the ripe corn is the endyng of the world, the reperis ben aungels.", "rotherham": "And, the enemy that sowed them, is the adversary, and, the harvest, is, the conclusion of an age, and, the reapers, are, messengers.", "weymouth": "The enemy who sows the darnel is *the Devil*; the harvest is the Close of the Age; the reapers are the angels.", "darby": "and the enemy who has sowed it is the devil; and the harvest is [the] completion of [the] age, and the harvestmen are angels.", "twenty": "and the enemy who sowed them is the Devil. The harvest-time is the close of the age, and the reapers are angels.", "acv": "And the enemy who sowed them is the devil, and the harvest is the end of the age, and the reapers are agents.", "anderson": "the enemy that sowed them is the devil; the harvest is the end of the age; and the reapers are angels.", "haweis": "the enemy who sowed them is the devil; the harvest is the end of the world; and the reapers are the angels.", "noyes": "the enemy that sowed them is the Devil; the harvest is the end of the world; and the reapers are angels.", "webster": "The enemy that sowed them is the devil; the harvest is the end of the world; and the reapers are the angels.", "vulgate": "inimicus autem qui seminavit ea est diabolus messis vero consummatio saeculi est messores autem angeli sunt;"}}, {"v": 40, "ref": "13:40", "o": "ὥσπερ οὖν συλλέγεται τὰ ζιζάνια καὶ πυρὶ ⸀καίεται, οὕτως ἔσται ἐν τῇ συντελείᾳ τοῦ ⸀αἰῶνος·", "en": {"kjv": "As therefore the tares are gathered and burned in the fire; so shall it be in the end of this world.", "web": "As therefore the darnel weeds are gathered up and burned with fire; so will it be at the end of this age.", "bsb": "As the weeds are collected and burned in the fire, so will it be at the end of the age.", "asv": "As therefore the tares are gathered up and burned with fire; so shall it be in the end of the world.", "ylt": "`As, then, the darnel is gathered up, and is burned with fire, so shall it be in the full end of this age,", "tyndale": "For eve as the tares are gaddred and bret in ye fyre: so shall it be in ye ende of this worlde.", "dra": "Even as cockle therefore is gathered up, and burnt with fire: so shall it be at the end of the world.", "bbe": "As then the evil plants are got together and burned with fire, so will it be in the end of the world.", "geneva": "As then the tares are gathered and burned in ye fire, so shall it be in the end of this world.", "wycliffe": "Therfor as taris ben gaderid togidere, and ben brent in fier, so it shal be in the endyng of the world.", "rotherham": "Just, therefore, as collected is the darnel, and, with fire is burned, so, will it be in the conclusion of the age:—", "weymouth": "As then the darnel is collected together and burnt up with fire, so will it be at the Close of the Age.", "darby": "As then the darnel is gathered and is burned in the fire, thus it shall be in the completion of the age.", "twenty": "And, just as the tares are gathered and burnt, so it will be at the close of the age.", "acv": "As therefore the tares are gathered up and burned in fire, so it will be at the end of this age.", "anderson": "As, therefore, the tares are collected and burned in fire, so shall it be in the end of this age.", "haweis": "As therefore the zizane are gathered, and burned in the fire; just so shall it be at the end of this world.", "noyes": "As therefore the tares are gathered up and burned with fire, so will it be at the end of the world.", "webster": "As therefore the tares are gathered and burned in the fire; so shall it be in the end of this world.", "vulgate": "sicut ergo colliguntur zizania et igni conburuntur sic erit in consummatione saeculi;"}}, {"v": 41, "ref": "13:41", "o": "ἀποστελεῖ ὁ υἱὸς τοῦ ἀνθρώπου τοὺς ἀγγέλους αὐτοῦ, καὶ συλλέξουσιν ἐκ τῆς βασιλείας αὐτοῦ πάντα τὰ σκάνδαλα καὶ τοὺς ποιοῦντας τὴν ἀνομίαν,", "en": {"kjv": "The Son of man shall send forth his angels, and they shall gather out of his kingdom all things that offend, and them which do iniquity;", "web": "The Son of Man will send out his angels, and they will gather out of his Kingdom all things that cause stumbling, and those who do iniquity,", "bsb": "The Son of Man will send out His angels, and they will weed out of His kingdom every cause of sin and all who practice lawlessness.", "asv": "The Son of man shall send forth his angels, and they shall gather out of his kingdom all things that cause stumbling, and them that do iniquity,", "ylt": "the Son of Man shall send forth his messengers, and they shall gather up out of his kingdom all the stumbling-blocks, and those doing the unlawlessness,", "tyndale": "The sonne of man shall send forth his angels and they shall gather out of his kyngdome all thinges that offende and them which do iniquite", "dra": "The Son of man shall send his angels, and they shall gather out of his kingdom all scandals, and them that work iniquity.", "bbe": "The Son of man will send out his angels, and they will take out of his kingdom everything which is a cause of error, and all those who do wrong,", "geneva": "The Sonne of man shall send forth his Angels, and they shall gather out of his kingdom all things that offend, and them which doe iniquitie,", "wycliffe": "Mannus sone shal sende hise aungels, and thei schulen gadere fro his rewme alle sclaundris, and hem that doon wickidnesse;", "rotherham": "The Son of Man will send forth his messengers, and they will collect, out of his kingdom, all the causes of stumbling, and the doers of lawlessness,", "weymouth": "The Son of Man will commission His angels, and they will gather out of His Kingdom all causes of sin and all who violate His laws;", "darby": "The Son of man shall send his angels, and they shall gather out of his kingdom all offences, and those that practise lawlessness;", "twenty": "The Son of Man will send his angels, and they will gather from his kingdom all that hinders and those who live in sin,", "acv": "The Son of man will send forth his agents, and they will gather out of his kingdom all the stumbling-blocks, and those doing lawlessness,", "anderson": "The Son of man will send forth his angels, and collect out of his kingdom all things that offend, and those who work iniquity,", "haweis": "The Son of man shall send out his angels, and shall gather together out of his kingdom all things offensive, and those who practise iniquity;", "noyes": "The Son of man will send forth his angels, and they will gather out of his kingdom all the stumbling-blocks, and those who do iniquity,", "webster": "The Son of man shall send forth his angels, and they shall gather out of his kingdom all things that offend, and them who do iniquity;", "vulgate": "mittet Filius hominis angelos suos et colligent de regno eius omnia scandala et eos qui faciunt iniquitatem;"}}, {"v": 42, "ref": "13:42", "o": "καὶ βαλοῦσιν αὐτοὺς εἰς τὴν κάμινον τοῦ πυρός· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "And shall cast them into a furnace of fire: there shall be wailing and gnashing of teeth.", "web": "and will cast them into the furnace of fire. There will be weeping and the gnashing of teeth.", "bsb": "And they will throw them into the fiery furnace, where there will be weeping and gnashing of teeth.", "asv": "and shall cast them into the furnace of fire: there shall be the weeping and the gnashing of teeth.", "ylt": "and shall cast them to the furnace of the fire; there shall be the weeping and the gnashing of the teeth.", "tyndale": "and shall cast them into a furnes of fyre. There shalbe waylynge and gnasshing of teth.", "dra": "And shall cast them into the furnace of fire: there shall be weeping and gnashing of teeth.", "bbe": "And will put them into the fire; there will be weeping and cries of sorrow.", "geneva": "And shall cast them into a fornace of fire. There shalbe wailing and gnashing of teeth.", "wycliffe": "and thei schulen sende hem in to the chymney of fier, there shal be weping and betyng to gidere of teeth.", "rotherham": "and will cast them into the furnace of fire: there, will be wailing and gnashing of teeth.", "weymouth": "and these they will throw into the fiery furnace. There will be the weeping aloud and the gnashing of teeth.", "darby": "and they shall cast them into the furnace of fire; there shall be the weeping and the gnashing of teeth.", "twenty": "and ‘will throw them into the fiery furnace,’ where there will be weeping and grinding of teeth.", "acv": "and will cast them into the furnace of fire. There will be the weeping and the gnashing of teeth.", "anderson": "and cast them into the furnace of fire; there shall be weeping and gnashing of teeth.", "haweis": "and will cast them into a furnace of fire; there shall be wailing and gnashing of teeth.", "noyes": "and will cast them into the furnace of fire; there will be wailing and gnashing of teeth.", "webster": "And shall cast them into a furnace of fire: there shall be wailing and gnashing of teeth.", "vulgate": "et mittent eos in caminum ignis ibi erit fletus et stridor dentium;"}}, {"v": 43, "ref": "13:43", "o": "Τότε οἱ δίκαιοι ἐκλάμψουσιν ὡς ὁ ἥλιος ἐν τῇ βασιλείᾳ τοῦ πατρὸς αὐτῶν. ὁ ἔχων ⸀ὦτα ἀκουέτω.", "en": {"kjv": "Then shall the righteous shine forth as the sun in the kingdom of their Father. Who hath ears to hear, let him hear.", "web": "Then the righteous will shine like the sun in the Kingdom of their Father. He who has ears to hear, let him hear.", "bsb": "Then the righteous will shine like the sun in the kingdom of their Father. He who has ears, let him hear.", "asv": "Then shall the righteous shine forth as the sun in the kingdom of their Father. He that hath ears, let him hear.", "ylt": "`Then shall the righteous shine forth as the sun in the reign of their Father. He who is having ears to hear--let him hear.", "tyndale": "Then shall the iuste men shyne as bryght as the sunne in ye kyngdome of their father. Whosoever hath eares to heare let him heare.", "dra": "Then shall the just shine as the sun, in the kingdom of their Father. He that hath ears to hear, let him hear.", "bbe": "Then will the upright be shining as the sun in the kingdom of their Father. He who has ears, let him give ear.", "geneva": "Then shall the iust men shine as ye sunne in the kingdome of their Father. Hee that hath eares to heare, let him heare.", "wycliffe": "Thanne iuste men schulen schyne as the sunne, in the rewme of her fadir. He that hath eeris of heryng, here he.", "rotherham": "Then, the righteous, will shine forth as the sun, in the kingdom of their Father. He that hath ears, let him hear!", "weymouth": "Then will the righteous shine out like the sun in their Father's Kingdom. Listen, every one who has ears!", "darby": "Then the righteous shall shine forth as the sun in the kingdom of their Father. He that has ears, let him hear.", "twenty": "Then shall the righteous shine, like the sun, in the Kingdom of their Father. Let him who has ears hear.", "acv": "Then the righteous will shine forth as the sun in the kingdom of their Father. He who has ears to hear, let him hear.", "anderson": "Then shall the righteous shine forth as the sun, in the kingdom of their Father. He that has ears to hear, let him hear.", "haweis": "Then shall the righteous shine forth as the sun, in the kingdom of their Father. He that hath ears to hear, let him hear.", "noyes": "Then will the righteous shine forth as the sun, in the kingdom of their Father. He that hath ears, let him hear.", "webster": "Then shall the righteous shine as the sun in the kingdom of their Father. Who hath ears to hear, let him hear.", "vulgate": "tunc iusti fulgebunt sicut sol in regno Patris eorum qui habet aures audiat;"}}, {"v": 44, "ref": "13:44", "o": "⸀Ὁμοία ἐστὶν ἡ βασιλεία τῶν οὐρανῶν θησαυρῷ κεκρυμμένῳ ἐν τῷ ἀγρῷ, ὃν εὑρὼν ἄνθρωπος ἔκρυψεν, καὶ ἀπὸ τῆς χαρᾶς αὐτοῦ ὑπάγει καὶ ⸂πωλεῖ πάντα ὅσα ἔχει⸃ καὶ ἀγοράζει τὸν ἀγρὸν ἐκεῖνον.", "en": {"kjv": "Again, the kingdom of heaven is like unto treasure hid in a field; the which when a man hath found, he hideth, and for joy thereof goeth and selleth all that he hath, and buyeth that field.", "web": "“Again, the Kingdom of Heaven is like a treasure hidden in the field, which a man found, and hid. In his joy, he goes and sells all that he has, and buys that field.", "bsb": "The kingdom of heaven is like treasure hidden in a field. When a man found it, he hid it again, and in his joy he went and sold all he had and bought that field.", "asv": "The kingdom of heaven is like unto a treasure hidden in the field; which a man found, and hid; and in his joy he goeth and selleth all that he hath, and buyeth that field.", "ylt": "`Again, the reign of the heavens is like to treasure hid in the field, which a man having found did hide, and from his joy goeth, and all, as much as he hath, he selleth, and buyeth that field.", "tyndale": "Agayne ye kyngdome of heve is lyke vnto treasure hidde in the felde ye which a man fyndeth and hideth: and for ioy therof goeth and selleth all that he hath and byeth that felde.", "dra": "The kingdom of heaven is like unto a treasure hidden in a field. Which a man having found, hid it, and for joy thereof goeth, and selleth all that he hath, and buyeth that field.", "bbe": "The kingdom of heaven is like a secret store of wealth in a field, which a man came across and put back again; and in his joy he goes and gives all he has, to get that field.", "geneva": "Againe, the kingdom of heauen is like vnto a treasure hid in ye field, which when a man hath found, he hideth it, and for ioy thereof departeth and selleth all that he hath, and buieth that field.", "wycliffe": "The kyngdom of heuenes is lijk to tresour hid in a feld, which a man that fyndith, hidith; and for ioye of it he goith, and sillith alle thingis that he hath, and bieth thilk feeld.", "rotherham": "The kingdom of the heavens is like unto, a treasure hid in the field, which a man, finding, hid,—and, by reason of his joy, withdraweth and selleth whatsoever he hath, and buyeth that field.", "weymouth": "\"The Kingdom of the Heavens is like treasure buried in the open country, which a man finds, but buries again, and, in his joy about it, goes and sells all he has and buys that piece of ground.", "darby": "The kingdom of the heavens is like a treasure hid in the field, which a man having found has hid, and for the joy of it goes and sells all whatever he has, and buys that field.", "twenty": "The Kingdom of Heaven is like a treasure hidden in a field, which a man found and hid again, and then, in his delight, went and sold everything that he had, and bought that field.", "acv": "Again the kingdom of the heavens is like a treasure hidden in the field, which a man having found, he hid. And from the joy of it, he goes and sells all, as many things as he has, and buys that field.", "anderson": "Again, the kingdom of heaven is like a treasure hid in a field, which, when a man finds it, he hides; and for the joy it gives, he goes and sells all that he has, and buys that field.", "haweis": "Again, the kingdom of heaven is like a treasure hid in a field: which when a man findeth, he hideth, and for joy thereof, goeth away and selleth all that he hath, and buyeth that field.", "noyes": "The kingdom of heaven is like a treasure hid in a field, which a man found and hid; and for joy thereof he goeth and selleth all that he hath, and buyeth that field.", "webster": "Again, the kingdom of heaven is like treasure hid in a field; which, when a man hath found, he hideth, and for joy thereof goeth and selleth all that he hath, and buyeth that field.", "vulgate": "simile est regnum caelorum thesauro abscondito in agro quem qui invenit homo abscondit et prae gaudio illius vadit et vendit universa quae habet et emit agrum illum;"}}, {"v": 45, "ref": "13:45", "o": "Πάλιν ὁμοία ἐστὶν ἡ βασιλεία τῶν οὐρανῶν ⸀ἀνθρώπῳ ἐμπόρῳ ζητοῦντι καλοὺς μαργαρίτας·", "en": {"kjv": "Again, the kingdom of heaven is like unto a merchant man, seeking goodly pearls:", "web": "“Again, the Kingdom of Heaven is like a man who is a merchant seeking fine pearls,", "bsb": "Again, the kingdom of heaven is like a merchant in search of fine pearls.", "asv": "Again, the kingdom of heaven is like unto a man that is a merchant seeking goodly pearls:", "ylt": "`Again, the reign of the heavens is like to a man, a merchant, seeking goodly pearls,", "tyndale": "Agayne ye kyngdome of heve is lyke vnto a marchaunt that seketh good pearles", "dra": "Again the kingdom of heaven is like to a merchant seeking good pearls.", "bbe": "Again, the kingdom of heaven is like a trader searching for beautiful jewels.", "geneva": "Againe, the kingdome of heauen is like to a marchant man, that seeketh good pearles,", "wycliffe": "Eftsoone the kyngdom of heuenes is lijk to a marchaunt, that sechith good margaritis;", "rotherham": "Again, the kingdom of the heavens is, like, unto, a merchant, seeking beautiful pearls,—", "weymouth": "\"Again the Kingdom of the Heavens is like a jewel merchant who is in quest of choice pearls.", "darby": "Again, the kingdom of the heavens is like a merchant seeking beautiful pearls;", "twenty": "Again, the Kingdom of Heaven is like a merchant in search of choice pearls.", "acv": "Again, the kingdom of the heavens is like a man, a merchant, seeking fine pearls.", "anderson": "Again, the kingdom of heaven is like a merchant seeking goodly pearls.", "haweis": "Again, the kingdom of heaven is like a merchantman in search of beautiful pearls:", "noyes": "Again, the kingdom of heaven is like a merchant seeking goodly pearls.", "webster": "Again, the kingdom of heaven is like a merchant seeking goodly pearls:", "vulgate": "iterum simile est regnum caelorum homini negotiatori quaerenti bonas margaritas;"}}, {"v": 46, "ref": "13:46", "o": "⸂εὑρὼν δὲ⸃ ἕνα πολύτιμον μαργαρίτην ἀπελθὼν πέπρακεν πάντα ὅσα εἶχεν καὶ ἠγόρασεν αὐτόν.", "en": {"kjv": "Who, when he had found one pearl of great price, went and sold all that he had, and bought it.", "web": "who having found one pearl of great price, he went and sold all that he had, and bought it.", "bsb": "When he found one very precious pearl, he went away and sold all he had and bought it.", "asv": "and having found one pearl of great price, he went and sold all that he had, and bought it.", "ylt": "who having found one pearl of great price, having gone away, hath sold all, as much as he had, and bought it.", "tyndale": "which when he had founde one precious pearle wet and solde all that he had and bought it.", "dra": "Who when he had found one pearl of great price, went his way, and sold all that he had, and bought it.", "bbe": "And having come across one jewel of great price, he went and gave all he had in exchange for it.", "geneva": "Who hauing found a pearle of great price, went and solde all that he had, and bought it.", "wycliffe": "but whanne he hath foundun o precious margarite, he wente, and selde alle thingis that he hadde, and bouyte it.", "rotherham": "and, finding one very precious pearl, departing, he at once sold all things, whatsoever he had, and bought it.", "weymouth": "He finds one most costly pearl; he goes away; and though it costs all he has, he buys it.", "darby": "and having found one pearl of great value, he went and sold all whatever he had and bought it.", "twenty": "Finding one of great value, he went and sold everything that he had, and bought it.", "acv": "Who, having found one very valuable pearl, after departing, sold all, as many things as he had, and bought it.", "anderson": "When he finds one pearl of great value, he goes and sells all that he has, and buys it.", "haweis": "who, having discovered one of vast price, went away and sold all that he possessed, and bought it.", "noyes": "And having found one pearl of great price, he went and sold all that he had, and bought it.", "webster": "Who, when he had found one pearl of great price, went and sold all that he had, and bought it.", "vulgate": "inventa autem una pretiosa margarita abiit et vendidit omnia quae habuit et emit eam;"}}, {"v": 47, "ref": "13:47", "o": "Πάλιν ὁμοία ἐστὶν ἡ βασιλεία τῶν οὐρανῶν σαγήνῃ βληθείσῃ εἰς τὴν θάλασσαν καὶ ἐκ παντὸς γένους συναγαγούσῃ·", "en": {"kjv": "Again, the kingdom of heaven is like unto a net, that was cast into the sea, and gathered of every kind:", "web": "“Again, the Kingdom of Heaven is like a dragnet, that was cast into the sea, and gathered some fish of every kind,", "bsb": "Once again, the kingdom of heaven is like a net that was cast into the sea and caught all kinds of fish.", "asv": "Again, the kingdom of heaven is like unto a net, that was cast into the sea, and gathered of every kind:", "ylt": "`Again, the reign of the heavens is like to a net that was cast into the sea, and did gather together of every kind,", "tyndale": "Agayne the kyngdome of heve is lyke vnto a neet cast into ye see yt gadereth of all kyndes of fysshes:", "dra": "Again the kingdom of heaven is like to a net cast into the sea, and gathering together of all kinds of fishes.", "bbe": "Again, the kingdom of heaven is like a net, which was put into the sea and took in every sort of fish:", "geneva": "Againe, the kingdom of heauen is like vnto a drawe net cast into the sea, that gathereth of all kindes of things.", "wycliffe": "Eft the kyngdom of heuenes is lijk to a nette cast into the see, and that gaderith to gidere of al kynde of fisschis;", "rotherham": "Again, the kingdom of the heavens is like unto, a large drag-net, cast into the sea and gathering of every kind,—", "weymouth": "\"Again the Kingdom of the Heavens is like a draw-net let down into the sea, which encloses fish of all sorts.", "darby": "Again, the kingdom of the heavens is like a seine which has been cast into the sea, and which has gathered together of every kind,", "twenty": "Or again, the Kingdom of Heaven is like a net which was cast into the sea, and caught fish of all kinds.", "acv": "Again, the kingdom of the heavens is like a net that was cast into the sea, and gathered from every kind,", "anderson": "Again, the kingdom of heaven is like a net that is cast into the sea, and that gathers of every kind:", "haweis": "Again, the kingdom of heaven is like to a net cast into the sea, and colleting fish of every kind:", "noyes": "Again, the kingdom of heaven is like a net, cast into the sea, and bringing together fish of every kind;", "webster": "Again, the kingdom of heaven is like a net, that was cast into the sea, and gathered of every kind:", "vulgate": "iterum simile est regnum caelorum sagenae missae in mare et ex omni genere congreganti;"}}, {"v": 48, "ref": "13:48", "o": "ἣν ὅτε ἐπληρώθη ἀναβιβάσαντες ἐπὶ τὸν αἰγιαλὸν καὶ καθίσαντες συνέλεξαν τὰ καλὰ εἰς ⸀ἄγγη, τὰ δὲ σαπρὰ ἔξω ἔβαλον.", "en": {"kjv": "Which, when it was full, they drew to shore, and sat down, and gathered the good into vessels, but cast the bad away.", "web": "which, when it was filled, they drew up on the beach. They sat down, and gathered the good into containers, but the bad they threw away.", "bsb": "When it was full, the men pulled it ashore. Then they sat down and sorted the good fish into containers, but threw the bad away.", "asv": "which, when it was filled, they drew up on the beach; and they sat down, and gathered the good into vessels, but the bad they cast away.", "ylt": "which, when it was filled, having drawn up again upon the beach, and having sat down, they gathered the good into vessels, and the bad they did cast out,", "tyndale": "which whe it is full men drawe to londe and sitte and gadre the good into vessels and cast the bad awaye.", "dra": "Which, when it was filled, they drew out, and sitting by the shore, they chose out the good into vessels, but the bad they cast forth.", "bbe": "When it was full, they took it up on the sands; and seated there they put the good into vessels, but the bad they put away.", "geneva": "Which, when it is full, men draw to lande, and sit and gather the good into vessels, and cast the bad away.", "wycliffe": "which whanne it was ful, thei drowen vp, and seten bi the brenke, and chesen the goode in to her vessels, but the yuel thei kesten out.", "rotherham": "which, when it was filled, they dragged up on the beach, and, sitting down, collected the good into vessels, but, the worthless, forth they cast.", "weymouth": "When full, they haul it up on the beach, and sit down and collect the good fish in baskets, while the worthless they throw away.", "darby": "which, when it has been filled, having drawn up on the shore and sat down, they gathered the good into vessels and cast the worthless out.", "twenty": "When it was full, they hauled it up on the beach, and sat down and sorted the good fish into baskets, but threw the worthless ones away.", "acv": "which, when it was full, after dragging to the shore, having sat down, they gathered the good into vessels, but they cast out the useless.", "anderson": "when it is full, they draw it to the shore; and sitting down, they collect the good into vessels, but throw the bad away.", "haweis": "which, when it was full, they drew to the beach, and sitting down, selected the good into baskets, but cast those of a bad kind away.", "noyes": "which, when it was full, they drew upon the beach, and sat down and gathered the good into vessels, but threw the bad away.", "webster": "Which, when it was full, they drew to the shore, and sat down, and gathered the good into vessels, but cast away the bad.", "vulgate": "quam cum impleta esset educentes et secus litus sedentes elegerunt bonos in vasa malos autem foras miserunt;"}}, {"v": 49, "ref": "13:49", "o": "οὕτως ἔσται ἐν τῇ συντελείᾳ τοῦ αἰῶνος· ἐξελεύσονται οἱ ἄγγελοι καὶ ἀφοριοῦσιν τοὺς πονηροὺς ἐκ μέσου τῶν δικαίων", "en": {"kjv": "So shall it be at the end of the world: the angels shall come forth, and sever the wicked from among the just,", "web": "So will it be in the end of the world. The angels will come and separate the wicked from among the righteous,", "bsb": "So will it be at the end of the age: The angels will come and separate the wicked from the righteous,", "asv": "So shall it be in the end of the world: the angels shall come forth, and sever the wicked from among the righteous,", "ylt": "so shall it be in the full end of the age, the messengers shall come forth and separate the evil out of the midst of the righteous,", "tyndale": "So shall it be at the ende of the worlde. The angels shall come oute and sever the bad from the good", "dra": "So shall it be at the end of the world. The angels shall go out, and shall separate the wicked from among the just.", "bbe": "So will it be in the end of the world: the angels will come and take out the bad from the good,", "geneva": "So shall it be at the end of the world. The Angels shall goe foorth, and seuer the bad from among the iust,", "wycliffe": "So it schal be in the endyng of the world. Aungels schulen go out, and schulen departe yuel men fro the myddil of iuste men.", "rotherham": "So, will it be in the conclusion of the age: The messengers will come forth, and separate the wicked from among the righteous;", "weymouth": "So will it be at the Close of the Age. The angels will go forth and separate the wicked from among the righteous,", "darby": "Thus shall it be in the completion of the age: the angels shall go forth and sever the wicked from the midst of the just,", "twenty": "So will it be at the close of the age. The angels will go out and separate the wicked from the righteous,", "acv": "So it will be at the end of the age. The agents will come forth, and separate the bad from among the righteous,", "anderson": "So shall it be in the end of the age: the angels shall come forth and separate the wicked from among the just,", "haweis": "Just so shall it be at the end of this world: the angels shall go forth, and shall separate the wicked from amidst the just,", "noyes": "So will it be at the end of the world. The angels will come forth, and separate the wicked from among the righteous,", "webster": "So shall it be at the end of the world: the angels shall come forth, and sever the wicked from among the just,", "vulgate": "sic erit in consummatione saeculi exibunt angeli et separabunt malos de medio iustorum;"}}, {"v": 50, "ref": "13:50", "o": "καὶ βαλοῦσιν αὐτοὺς εἰς τὴν κάμινον τοῦ πυρός· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "And shall cast them into the furnace of fire: there shall be wailing and gnashing of teeth.", "web": "and will cast them into the furnace of fire. There will be the weeping and the gnashing of teeth.”", "bsb": "and throw them into the fiery furnace, where there will be weeping and gnashing of teeth.", "asv": "and shall cast them into the furnace of fire: there shall be the weeping and the gnashing of teeth.", "ylt": "and shall cast them to the furnace of the fire, there shall be the weeping and the gnashing of the teeth.'", "tyndale": "and shall cast them into a furnes of fyre: there shalbe waylinge and gnasshynge of teth.", "dra": "And shall cast them into the furnace of fire: there shall be weeping and gnashing of teeth.", "bbe": "And will put them into the fire: there will be weeping and cries of sorrow.", "geneva": "And shall cast them into a fornace of fire: there shalbe wailing, and gnashing of teeth.", "wycliffe": "And thei shulen sende hem in to the chymnei of fier; ther shal be weping and gryntyng of teeth.", "rotherham": "and will cast them into the furnace of fire: there, will be wailing and gnashing of teeth.", "weymouth": "and will throw them into the fiery furnace. There will be the weeping aloud and the gnashing of teeth.\"", "darby": "and shall cast them into the furnace of fire; there shall be the weeping and the gnashing of teeth.", "twenty": "and ‘will throw them into the fiery furnace,’ where there will be weeping and grinding of teeth.", "acv": "and will cast them into the furnace of fire. There will be the weeping and the gnashing of teeth.", "anderson": "and cast them into the furnace of fire: there shall be weeping and gnashing of teeth.", "haweis": "and shall cast them into a furnace of fire: there shall be weeping and gnashing of teeth.", "noyes": "and will cast them into the furnace of fire; there will be wailing and gnashing of teeth.", "webster": "And shall cast them into the furnace of fire: there shall be wailing and gnashing of teeth.", "vulgate": "et mittent eos in caminum ignis ibi erit fletus et stridor dentium;"}}, {"v": 51, "ref": "13:51", "o": "⸀Συνήκατε ταῦτα πάντα; λέγουσιν αὐτῷ· ⸀Ναί.", "en": {"kjv": "Jesus saith unto them, Have ye understood all these things? They say unto him, Yea, Lord.", "web": "Jesus said to them, “Have you understood all these things?” They answered him, “Yes, Lord.”", "bsb": "Have you understood all these things?” “Yes,” they answered.", "asv": "Have ye understood all these things? They say unto him, Yea.", "ylt": "Jesus saith to them, `Did ye understand all these?' They say to him, `Yes, sir.'", "tyndale": "Iesus sayde vnto them: vnderstonde ye all these thynges? They sayde ye Lorde.", "dra": "Have ye understood all these things? They say to him: Yes.", "bbe": "Are all these things now clear to you? They say to him, Yes.", "geneva": "Iesus saide vnto them, Vnderstand yee all these things? They saide vnto him, Yea, Lord.", "wycliffe": "Han ye vndirstonde alle these thingis? Thei seien to hym, Yhe.", "rotherham": "Have ye understood all these things? They say unto him, Yea!", "weymouth": "\"Have you understood all this?\" He asked. \"Yes,\" they said.", "darby": "Jesus says to them, Have ye understood all these things? They say to him, Yea, [Lord].", "twenty": "Have you understood all this?” Jesus asked. “Yes,” they answered.", "acv": "Jesus says to them, Have ye understood all these things? They say to him, Yes, Lord.", "anderson": "Jesus said to them: Have you understood all these things? They said to him: Yes, Lord.", "haweis": "Jesus saith unto them, Have ye understood all these things?", "noyes": "Did ye understand all these things? They say to him, Yea.", "webster": "Jesus saith to them, Have ye understood all these things? They say to him, Yes, Lord.", "vulgate": "intellexistis haec omnia dicunt ei etiam;"}}, {"v": 52, "ref": "13:52", "o": "ὁ δὲ εἶπεν αὐτοῖς· Διὰ τοῦτο πᾶς γραμματεὺς μαθητευθεὶς ⸂τῇ βασιλείᾳ⸃ τῶν οὐρανῶν ὅμοιός ἐστιν ἀνθρώπῳ οἰκοδεσπότῃ ὅστις ἐκβάλλει ἐκ τοῦ θησαυροῦ αὐτοῦ καινὰ καὶ παλαιά.", "en": {"kjv": "Then said he unto them, Therefore every scribe which is instructed unto the kingdom of heaven is like unto a man that is an householder, which bringeth forth out of his treasure things new and old.", "web": "He said to them, “Therefore every scribe who has been made a disciple in the Kingdom of Heaven is like a man who is a householder, who brings out of his treasure new and old things.”", "bsb": "Then He told them, “For this reason, every scribe who has been discipled in the kingdom of heaven is like a homeowner who brings out of his storeroom new treasures as well as old.”", "asv": "And he said unto them, Therefore every scribe who hath been made a disciple to the kingdom of heaven is like unto a man that is a householder, who bringeth forth out of his treasure things new and old.", "ylt": "And he said to them, `Because of this every scribe having been discipled in regard to the reign of the heavens, is like to a man, a householder, who doth bring forth out of his treasure things new and old.'", "tyndale": "The sayde he vnto them: Therfore every scribe which is taught vnto the kyngdome of heve is lyke an housholder which bryngeth forth out of hys treasure thynges bothe new and olde.", "dra": "He said unto them: Therefore every scribe instructed in the kingdom of heaven, is like to a man that is a householder, who bringeth forth out of his treasure new things and old.", "bbe": "And he said to them, For this reason every scribe who has become a disciple of the kingdom of heaven is like the owner of a house, who gives out from his store things new and old.", "geneva": "Then sayd hee vnto them, Therefore euery Scribe which is taught vnto the kingdome of heauen, is like vnto an householder, which bringeth foorth out of his treasure things both newe and olde.", "wycliffe": "He seith to hem, Therfor euery wise man of lawe in the kyngdom of heuenes, is lijk to an hosebonde man, that bryngith forth of his tresoure newe thingis and elde.", "rotherham": "And, he, said unto them—Wherefore, every scribe, discipled unto the kingdom of the heavens, is like unto a householder, who putteth forth out of his treasure, things new and old.", "weymouth": "\"Therefore,\" He said, \"remember that every Scribe well trained for the Kingdom of the Heavens is like a householder who brings out of his storehouse new things and old.\"", "darby": "And he said to them, For this reason every scribe discipled to the kingdom of the heavens is like a man [that is] a householder who brings out of his treasure things new and old.", "twenty": "Then he added: “So every Teacher of the Law, who has received instruction about the Kingdom of Heaven, is like a householder who produces from his stores things both new and old.”", "acv": "And he said to them, Because of this every scholar who has been instructed in the kingdom of the heavens is like a man, a house-ruler, who brings forth out of his treasure things new and old.", "anderson": "He said to them: Therefore, every scribe that is trained for the kingdom of heaven, is like the master of a house, who brings out of his treasury things new and old.", "haweis": "They say unto him, Yes, Lord. Then said he unto them, Therefore every scribe instructed unto the kingdom of heaven, is like unto a man, the master of a family, who bringeth out of his storehouse things new and old.", "noyes": "And he said to them, Thus then every scribe, instructed for the kingdom of heaven, is like a householder, who bringeth out from his storehouse things new and old.", "webster": "Then said he to them, Therefore every scribe [who is] instructed to the kingdom of heaven, is like a man [that is] a householder, who bringeth forth out of his treasure [things] new and old.", "vulgate": "ait illis ideo omnis scriba doctus in regno caelorum similis est homini patri familias qui profert de thesauro suo nova et vetera;"}}, {"v": 53, "ref": "13:53", "o": "καὶ ἐγένετο ὅτε ἐτέλεσεν ὁ Ἰησοῦς τὰς παραβολὰς ταύτας, μετῆρεν ἐκεῖθεν.", "en": {"kjv": "And it came to pass, that when Jesus had finished these parables, he departed thence.", "web": "When Jesus had finished these parables, he departed from there.", "bsb": "When Jesus had finished these parables, He withdrew from that place.", "asv": "And it came to pass, when Jesus had finished these parables, he departed thence.", "ylt": "And it came to pass, when Jesus finished these similes, he removed thence,", "tyndale": "And it came to passe when Iesus had finisshed these similitudes yt he departed thece", "dra": "And it came to pass: when Jesus had finished these parables, he passed from thence.", "bbe": "And when Jesus had come to the end of these stories he went away from there.", "geneva": "And it came to passe, that when Iesus had ended these parables, he departed thence,", "wycliffe": "And it was doon, whanne Jhesus hadde endid these parablis, he passide fro thennus.", "rotherham": "And it came to pass, when Jesus had finished these parables, he removed from thence;", "weymouth": "Jesus concluded this series of parables and then departed.", "darby": "And it came to pass when Jesus had finished these parables he withdrew thence.", "twenty": "When Jesus had finished these parables, he withdrew from that place.", "acv": "And it came to pass, when Jesus finished these parables, he departed from there.", "anderson": "And it came to pass, when Jesus had finished these parables, he departed from that place.", "haweis": "And it came to pass, when Jesus had finished there parables, he departed thence.", "noyes": "And it came to pass, when Jesus had ended these parables, that he departed thence.", "webster": "And it came to pass, [that] when Jesus had finished these parables, he departed thence.", "vulgate": "et factum est cum consummasset Iesus parabolas istas transiit inde;"}}, {"v": 54, "ref": "13:54", "o": "καὶ ἐλθὼν εἰς τὴν πατρίδα αὐτοῦ ἐδίδασκεν αὐτοὺς ἐν τῇ συναγωγῇ αὐτῶν, ὥστε ἐκπλήσσεσθαι αὐτοὺς καὶ λέγειν· Πόθεν τούτῳ ἡ σοφία αὕτη καὶ αἱ δυνάμεις;", "en": {"kjv": "And when he was come into his own country, he taught them in their synagogue, insomuch that they were astonished, and said, Whence hath this man this wisdom, and these mighty works?", "web": "Coming into his own country, he taught them in their synagogue, so that they were astonished, and said, “Where did this man get this wisdom, and these mighty works?", "bsb": "Coming to His hometown, He taught the people in their synagogue, and they were astonished. “Where did this man get such wisdom and miraculous powers?” they asked.", "asv": "And coming into his own country he taught them in their synagogue, insomuch that they were astonished, and said, Whence hath this man this wisdom, and these mighty works?", "ylt": "and having come to his own country, he was teaching them in their synagogue, so that they were astonished, and were saying, `Whence to this one this wisdom and the mighty works?", "tyndale": "and came in to his awne coutre and taught them in their synagoges in so moche yt they were astonyed and sayde: whece cometh all this wysdome and power vnto him?", "dra": "And coming into his own country, he taught them in their synagogues, so that they wondered and said: How came this man by this wisdom and miracles?", "bbe": "And coming into his country, he gave them teaching in their Synagogue, so that they were greatly surprised and said, Where did this man get this wisdom and these works of power?", "geneva": "And came into his owne countrey, and taught them in their Synagogue, so that they were astonied, and saide, Whence commeth this wisdome and great woorkes vnto this man?", "wycliffe": "And he cam in to his cuntrei, and tauyte hem in her synagogis, so that thei wondriden, and seiden, Fro whennus this wisdam and vertues camen to this?", "rotherham": "and, coming into his own city, began teaching them in their synagogue, so that with astonishment were they being struck, and were saying—Whence, hath, this one, this wisdom, and the mighty works?", "weymouth": "And He came into His own country and proceeded to teach in their synagogue, so that they were filled with astonishment and exclaimed, \"Where did he obtain such wisdom, and these wondrous powers?", "darby": "And having come into his own country, he taught them in their synagogue, so that they were astonished, and said, Whence has this [man] this wisdom and these works of power?", "twenty": "Going to his own part of the country, he taught the people in their Synagogue in such a manner that they were deeply impressed. “Where did he get this wisdom?” they said, “and the miracles?", "acv": "And having come into his fatherland he taught them in their synagogue, so as for them to be astonished, and say, From where is this wisdom and powers in this man?", "anderson": "And he came into his own country, and taught them in their synagogue, so that they were astonished, and said: Whence has this man this wisdom, and these mighty works?", "haweis": "And coming into his own country, taught them in their synagogues, so that they were exceedingly struck, and said, Whence hath this man this wisdom, and these miracles?", "noyes": "And having come into his own country, he taught them in their synagogue, so that they were astonished, and said, Whence hath this man this wisdom, and the miracles?", "webster": "And when he had come into his own country, he taught them in their synagogue, so that they were astonished, and said, Whence hath this [man] this wisdom, and [these] mighty works?", "vulgate": "et veniens in patriam suam docebat eos in synagogis eorum ita ut mirarentur et dicerent unde huic sapientia haec et virtutes;"}}, {"v": 55, "ref": "13:55", "o": "οὐχ οὗτός ἐστιν ὁ τοῦ τέκτονος υἱός; ⸀οὐχ ἡ μήτηρ αὐτοῦ λέγεται Μαριὰμ καὶ οἱ ἀδελφοὶ αὐτοῦ Ἰάκωβος καὶ ⸀Ἰωσὴφ καὶ Σίμων καὶ Ἰούδας;", "en": {"kjv": "Is not this the carpenter’s son? is not his mother called Mary? and his brethren, James, and Joses, and Simon, and Judas?", "web": "Isn’t this the carpenter’s son? Isn’t his mother called Mary, and his brothers, James, Joses, Simon, and Judas?", "bsb": "“Isn’t this the carpenter’s son? Isn’t His mother’s name Mary, and aren’t His brothers James, Joseph, Simon, and Judas?", "asv": "Is not this the carpenter’s son? is not his mother called Mary? and his brethren, James, and Joseph, and Simon, and Judas?", "ylt": "is not this the carpenter's son? is not his mother called Mary, and his brethren James, and Joses, and Simon, and Judas?", "tyndale": "Is not this the carpeters sonne? Is not his mother called Mary? and his brethre be called Iames and Ioses and Simo and Iudas?", "dra": "Is not this the carpenter's son? Is not his mother called Mary, and his brethren James, and Joseph, and Simon, and Jude:", "bbe": "Is not this the woodworker's son? is not his mother named Mary? and his brothers James and Joseph and Simon and Judas?", "geneva": "Is not this the carpenters sonne? Is not his mother called Marie, and his brethren Iames and Ioses, and Simon and Iudas?", "wycliffe": "Whether `is not this the sone of a carpentere? Whether his modir be not seid Marie? and hise britheren, James, and Joseph, and Symount, and Judas? and hise sistris,", "rotherham": "Is not, this one, the carpenter’s, son? Is not, his mother, called Mary, and are not his brethren—James and Joseph, and Simon, and Judas?", "weymouth": "Is not this the carpenter's son? Is not his mother called Mary? And are not his brothers, James, Joseph, Simon and Judah?", "darby": "Is not this the son of the carpenter? Is not his mother called Mary, and his brethren James, and Joseph, and Simon, and Judas?", "twenty": "Is not he the carpenter’s son? Is not his mother called Mary, and his brothers James, and Joseph, and Simon, and Judas?", "acv": "Is not this the carpenter's son? Is not his mother called Mary, and his brothers, James and Joses and Simon and Judas?", "anderson": "Is not this the son of the carpenter? Is not his mother called Mary? and his brothers, James and Joses and Simon and Judas?", "haweis": "Is not this the carpenter’s son? is not his mother called Mary? his brethren, James, and Joses, and Simon, and Judas?", "noyes": "Is not this the carpenter’s son? Is not his mother called Mary, and his brothers, James, and Joseph, and Simon, and Judas?", "webster": "Is not this the carpenter's son? is not his mother called Mary? and his brethren, James, and Joses, and Simon, and Judas?", "vulgate": "nonne hic est fabri filius nonne mater eius dicitur Maria et fratres eius Iacobus et Ioseph et Simon et Iudas;"}}, {"v": 56, "ref": "13:56", "o": "καὶ αἱ ἀδελφαὶ αὐτοῦ οὐχὶ πᾶσαι πρὸς ἡμᾶς εἰσιν; πόθεν οὖν τούτῳ ταῦτα πάντα;", "en": {"kjv": "And his sisters, are they not all with us? Whence then hath this man all these things?", "web": "Aren’t all of his sisters with us? Where then did this man get all of these things?”", "bsb": "Aren’t all His sisters with us as well? Where then did this man get all these things?”", "asv": "And his sisters, are they not all with us? Whence then hath this man all these things?", "ylt": "and his sisters--are they not all with us? whence, then, to this one all these?'", "tyndale": "And are not his susters all here wt vs? Whece hath he all these thynge.", "dra": "And his sisters, are they not all with us? Whence therefore hath he all these things?", "bbe": "And his sisters, are they not all with us? from where, then, has he all these things?", "geneva": "And are not his sisters all with vs? Whence then hath he all these things?", "wycliffe": "whether thei alle ben not among us? Fro whennus thanne `alle thes thingis camen to this?", "rotherham": "and, his sisters, are they not all with us? Whence, then hath, this one, all these things?", "weymouth": "And his sisters--are they not all living here among us? Where then did he get all this?\"", "darby": "And his sisters, are they not all with us? Whence then has this [man] all these things?", "twenty": "And his sisters, too — are not they all living among us? Where, then did he get all this?”", "acv": "And his sisters, are they not all near us? From where then are all these things in this man?", "anderson": "And his sisters, are they not all with us? Whence, then, has this man all these things?", "haweis": "and his sisters, are they not all among us? whence then hath he all these things?", "noyes": "And his sisters, are they not all with us? Whence then hath this man all these things?", "webster": "And his sisters, are they not all with us? Whence then hath this [man] all these things?", "vulgate": "et sorores eius nonne omnes apud nos sunt unde ergo huic omnia ista;"}}, {"v": 57, "ref": "13:57", "o": "καὶ ἐσκανδαλίζοντο ἐν αὐτῷ. ὁ δὲ Ἰησοῦς εἶπεν αὐτοῖς· Οὐκ ἔστιν προφήτης ἄτιμος εἰ μὴ ἐν τῇ ⸀πατρίδι καὶ ἐν τῇ οἰκίᾳ αὐτοῦ.", "en": {"kjv": "And they were offended in him. But Jesus said unto them, A prophet is not without honour, save in his own country, and in his own house.", "web": "They were offended by him. But Jesus said to them, “A prophet is not without honor, except in his own country, and in his own house.”", "bsb": "And they took offense at Him. But Jesus said to them, “Only in his hometown and in his own household is a prophet without honor.”", "asv": "And they were offended in him. But Jesus said unto them, A prophet is not without honor, save in his own country, and in his own house.", "ylt": "and they were stumbled at him. And Jesus said to them, `A prophet is not without honour except in his own country, and in his own house:'", "tyndale": "And they were offended by him. The Iesus sayd to the a Prophet is not wt out honoure save in hys awne countre and amoge his awne kynne.", "dra": "And they were scandalized in his regard. But Jesus said to them: A prophet is not without honour, save in his own country, and in his own house.", "bbe": "And they were bitter against him. But Jesus said to them, A prophet is nowhere without honour but in his country and among his family.", "geneva": "And they were offended with him. Then Iesus said to them, A Prophet is not without honour, saue in his owne countrey, and in his owne house.", "wycliffe": "And so thei weren sclaundrid in hym. But Jhesus seide to hem, A profete is not with oute worschip, but in his owen cuntre, and in his owen hous.", "rotherham": "And they began to find cause of stumbling in him. But, Jesus, said unto them—A prophet is not without honour, save in his city, and in his house.", "weymouth": "So they turned angrily away from Him. But Jesus said to them, \"There is no prophet left without honour except in his own country and among his own family.\"", "darby": "And they were offended in him. And Jesus said to them, A prophet is not without honour, unless in his country and in his house.", "twenty": "These things proved a hindrance to their believing in him; whereupon Jesus said: “A prophet is not without honour, except in his own country and in his own house.”", "acv": "And they were offended by him. But Jesus said to them, A prophet is not without honor, except in his fatherland, and in his house.", "anderson": "And they found in him occasion for offense. But Jesus said to them: A prophet is not without honor, unless it be in his own country and in his own house.", "haweis": "And they were offended at him. But Jesus said unto them, A prophet is not disrespected, except in his own country, and in his own family.", "noyes": "And they took offence at him. But Jesus said to them, A prophet is not without honor, except in his own country, and in his own house.", "webster": "And they were offended in him. But Jesus said to them, A prophet is not without honor, save in his own country, and in his own house.", "vulgate": "et scandalizabantur in eo Iesus autem dixit eis non est propheta sine honore nisi in patria sua et in domo sua;"}}, {"v": 58, "ref": "13:58", "o": "καὶ οὐκ ἐποίησεν ἐκεῖ δυνάμεις πολλὰς διὰ τὴν ἀπιστίαν αὐτῶν.", "en": {"kjv": "And he did not many mighty works there because of their unbelief.", "web": "He didn’t do many mighty works there because of their unbelief.", "bsb": "And He did not do many miracles there, because of their unbelief.", "asv": "And he did not many mighty works there because of their unbelief.", "ylt": "and he did not there many mighty works, because of their unbelief.", "tyndale": "And he dyd not many miracles there for there vnbelefes sake.", "dra": "And he wrought not many miracles there, because of their unbelief.", "bbe": "And the works of power which he did there were small in number because they had no faith.", "geneva": "And he did not many great woorkes there, for their vnbeliefes sake.", "wycliffe": "And he dide not there manye vertues, for the vnbileue of hem.", "rotherham": "And he did not, there, many mighty works, because of their unbelief.", "weymouth": "And He performed but few mighty deeds there because of their want of faith.", "darby": "And he did not there many works of power, because of their unbelief.", "twenty": "And he did not work many miracles there, because of their want of faith.", "acv": "And he did not many mighty works there because of their unbelief.", "anderson": "And he did not many mighty works there, on account of their unbelief.", "haweis": "And he did not there many miracles because of their unbelief.", "noyes": "And he did not work many miracles there, because of their unbelief.", "webster": "And he did not many mighty works there, because of their unbelief.", "vulgate": "et non fecit ibi virtutes multas propter incredulitatem illorum;"}}]}, {"c": 14, "verses": [{"v": 1, "ref": "14:1", "o": "Ἐν ἐκείνῳ τῷ καιρῷ ἤκουσεν Ἡρῴδης ὁ τετραάρχης τὴν ἀκοὴν Ἰησοῦ,", "en": {"kjv": "At that time Herod the tetrarch heard of the fame of Jesus,", "web": "At that time, Herod the tetrarch heard the report concerning Jesus,", "bsb": "At that time Herod the tetrarch heard the reports about Jesus", "asv": "At that season Herod the tetrarch heard the report concerning Jesus,", "ylt": "At that time did Herod the tetrarch hear the fame of Jesus,", "tyndale": "At that tyme Herod the tetrarcha hearde of the fame of Iesu", "dra": "At that time Herod the Tetrarch heard the fame of Jesus.", "bbe": "At that time news of Jesus came to Herod the king;", "geneva": "At that time Herod the Tetrarche heard of the fame of Iesus,", "wycliffe": "In that tyme Eroude tetrarke, prynce of the fourthe part, herde the fame of Jhesu;", "rotherham": "In that season, heard Herod the tetrarch, the fame of Jesus:", "weymouth": "About that time Herod the Tetrarch heard of the fame of Jesus,", "darby": "At that time Herod the tetrarch heard of the fame of Jesus,", "twenty": "At that time Prince Herod heard of the fame of Jesus,", "acv": "At that time Herod the tetrarch heard the report of Jesus,", "anderson": "At that time Herod the tetrarch heard of the fame of Jesus;", "haweis": "AT that time Herod the tetrarch heard the report of Jesus,", "noyes": "At that time Herod the tetrarch heard of the fame of Jesus,", "webster": "At that time Herod the Tetrarch heard of the fame of Jesus,", "vulgate": "in illo tempore audiit Herodes tetrarcha famam Iesu;"}}, {"v": 2, "ref": "14:2", "o": "καὶ εἶπεν τοῖς παισὶν αὐτοῦ· Οὗτός ἐστιν Ἰωάννης ὁ βαπτιστής· αὐτὸς ἠγέρθη ἀπὸ τῶν νεκρῶν, καὶ διὰ τοῦτο αἱ δυνάμεις ἐνεργοῦσιν ἐν αὐτῷ.", "en": {"kjv": "And said unto his servants, This is John the Baptist; he is risen from the dead; and therefore mighty works do shew forth themselves in him.", "web": "and said to his servants, “This is John the Baptizer. He is risen from the dead. That is why these powers work in him.”", "bsb": "and said to his servants, “This is John the Baptist; he has risen from the dead! That is why miraculous powers are at work in him.”", "asv": "and said unto his servants, This is John the Baptist; he is risen from the dead; and therefore do these powers work in him.", "ylt": "and said to his servants, `This is John the Baptist, he did rise from the dead, and because of this the mighty energies are working in him.'", "tyndale": "and sayde vnto his servautes: This is Ihon ye baptist. He is risen agayne from deeth and therfore are soche myracles wrought by him.", "dra": "And he said to his servants: This is John the Baptist: he is risen from the dead, and therefore mighty works shew forth themselves in him.", "bbe": "And he said to his servants, This is John the Baptist; he has come back from the dead, and so these powers are working in him.", "geneva": "And sayde vnto his seruaunts, This is that Iohn Baptist, hee is risen againe from the deade, and therefore great woorkes are wrought by him.", "wycliffe": "and seide to hise children, This is Joon Baptist, he is rysun fro deeth, and therfor vertues worchen in hym.", "rotherham": "and he said unto his servants—This, is John the Immerser,—he hath arisen from the dead, for this cause, are the powers working mightily within him.", "weymouth": "and he said to his courtiers, \"This is John the Baptist: he has come back to life--and that is why these miraculous Powers are working in him.\"", "darby": "and said to his servants, This is John the baptist: he is risen from the dead, and because of this these works of power display their force in him.", "twenty": "and said to his attendants: “This must be John the Baptist; he must be risen from the dead, and that is why these miraculous powers are active in him.”", "acv": "and he said to his boys, This is John the immerser. He has risen from the dead, and because of this the powers work in him.", "anderson": "and he said to his servants: This is John The Immerser; he has risen from the dead; and for this reason the powers of the spiritual world are active within him.", "haweis": "and said unto his servants, This is John the Baptist; he is risen from the dead, and therefore miracles are wrought by him.", "noyes": "and said to his servants, This is John the Baptist; he hath risen from the dead, and therefore do these powers work in him.", "webster": "And said to his servants, This is John the Baptist; he hath risen from the dead; and therefore mighty works do show forth themselves in him.", "vulgate": "et ait pueris suis hic est Iohannes Baptista ipse surrexit a mortuis et ideo virtutes inoperantur in eo;"}}, {"v": 3, "ref": "14:3", "o": "Ὁ γὰρ Ἡρῴδης κρατήσας τὸν Ἰωάννην ἔδησεν ⸀αὐτὸν καὶ ⸂ἐν φυλακῇ ἀπέθετο⸃ διὰ Ἡρῳδιάδα τὴν γυναῖκα Φιλίππου τοῦ ἀδελφοῦ αὐτοῦ,", "en": {"kjv": "For Herod had laid hold on John, and bound him, and put him in prison for Herodias’ sake, his brother Philip’s wife.", "web": "For Herod had laid hold of John, and bound him, and put him in prison for the sake of Herodias, his brother Philip’s wife.", "bsb": "Now Herod had arrested John and bound him and put him in prison on account of Herodias, his brother Philip’s wife,", "asv": "For Herod had laid hold on John, and bound him, and put him in prison for the sake of Herodias, his brother Philip’s wife.", "ylt": "For Herod having laid hold on John, did bind him, and did put him in prison, because of Herodias his brother Philip's wife,", "tyndale": "For Herod had taken Ihon and bounde him and put him in preson for Herodias sake his brother Philips wyfe.", "dra": "For Herod had apprehended John and bound him, and put him into prison, because of Herodias, his brother's wife.", "bbe": "For Herod had taken John and put him in prison because of Herodias, his brother Philip's wife.", "geneva": "For Herod had taken Iohn, and bounde him, and put him in prison for Herodias sake, his brother Philips wife.", "wycliffe": "For Heroude hadde holde Joon, and bounde hym, and puttide hym `in to prisoun for Herodias, the wijf of his brothir.", "rotherham": "For, Herod, seizing John, had bound him, and, in prison, put him away,—because of Herodias, the wife of Philip his brother;", "weymouth": "For Herod had arrested John, and had put him in chains, and imprisoned him, for the sake of Herodias his brother Philip's wife,", "darby": "For Herod had seized John, and had bound him and put him in prison on account of Herodias the wife of Philip his brother.", "twenty": "For Herod had arrested John, put him in chains, and shut him up in prison, to please Herodias, the wife of Herod’s brother Philip.", "acv": "For Herod having arrested John, bound him and put him in prison because of Herodias, his brother Philip's wife.", "anderson": "For Herod had laid hold of John, and bound him, and put him in prison on account of Herodias, the wife of his brother Philip.", "haweis": "For Herod having seized John, had bound him, and put him in prison, for the sake of Herodias, the wife of Philip his brother.", "noyes": "For Herod had seized John, and bound him, and put him in prison, on account of Herodias, his brother Philip’s wife.", "webster": "For Herod had laid hold on John, and bound him, and put [him] in prison for the sake of Herodias, his brother Philip's wife.", "vulgate": "Herodes enim tenuit Iohannem et alligavit eum et posuit in carcere propter Herodiadem uxorem fratris sui;"}}, {"v": 4, "ref": "14:4", "o": "ἔλεγεν γὰρ ⸂αὐτῷ ὁ Ἰωάννης⸃· Οὐκ ἔξεστίν σοι ἔχειν αὐτήν·", "en": {"kjv": "For John said unto him, It is not lawful for thee to have her.", "web": "For John said to him, “It is not lawful for you to have her.”", "bsb": "because John had been telling him, “It is not lawful for you to have her.”", "asv": "For John said unto him, It is not lawful for thee to have her.", "ylt": "for John was saying to him, `It is not lawful to thee to have her,'", "tyndale": "For Ihon sayde vnto him: Yt is not lawfull for the to have her.", "dra": "For John said to him: It is not lawful for thee to have her.", "bbe": "Because John had said to him, It is not right for you to have her.", "geneva": "For Iohn saide vnto him, It is not lawfull for thee to haue her.", "wycliffe": "For Joon seide to him, It is not leueful to thee to haue hir.", "rotherham": "for John had been saying to him, It is not allowed thee, to have her.", "weymouth": "because John had persistently said to him, \"It is not lawful for you to have her.\"", "darby": "For John said to him, It is not lawful for thee to have her.", "twenty": "For John had said to him ‘You have no right to be living with her.’", "acv": "For John said to him, It is not permitted for thee to have her.", "anderson": "For John said to him: It is not lawful for you to have her.", "haweis": "For John said unto him, It is unlawful for thee to have her.", "noyes": "For John said to him, It is not lawful for thee to have her.", "webster": "For John had said to him, It is not lawful for thee to have her.", "vulgate": "dicebat enim illi Iohannes non licet tibi habere eam;"}}, {"v": 5, "ref": "14:5", "o": "καὶ θέλων αὐτὸν ἀποκτεῖναι ἐφοβήθη τὸν ὄχλον, ὅτι ὡς προφήτην αὐτὸν εἶχον.", "en": {"kjv": "And when he would have put him to death, he feared the multitude, because they counted him as a prophet.", "web": "When he would have put him to death, he feared the multitude, because they counted him as a prophet.", "bsb": "Although Herod wanted to kill John, he was afraid of the people, because they regarded John as a prophet.", "asv": "And when he would have put him to death, he feared the multitude, because they counted him as a prophet.", "ylt": "and, willing to kill him, he feared the multitude, because as a prophet they were holding him.", "tyndale": "And when he wold have put him to deeth he feared the people because they counted him as a prophet.", "dra": "And having a mind to put him to death, he feared the people: because they esteemed him as a prophet.", "bbe": "And he would have put him to death, but for his fear of the people, because in their eyes John was a prophet.", "geneva": "And when hee woulde haue put him to death, hee feared the multitude, because they counted him as a Prophet.", "wycliffe": "And he willynge to sle hym, dredde the puple; for thei hadden hym as a prophete.", "rotherham": "And desiring, to kill, him, he feared the multitude, because, as a prophet, they held him.", "weymouth": "And he would have liked to put him to death, but was afraid of the people, because they regarded John as a Prophet.", "darby": "And [while] desiring to kill him, he feared the crowd, because they held him for a prophet.", "twenty": "Yet, though Herod wanted to put him to death, he was afraid of the people, because they looked on John as a Prophet.", "acv": "And though he wanted to kill him, he feared the multitude because they held him as a prophet.", "anderson": "And he intended to put him to death, but feared the multitude, because they regarded him as a prophet.", "haweis": "And though he wished to kill him, he was afraid of the multitude, for they held him as a prophet.", "noyes": "And wishing to put him to death, he feared the multitude, because they regarded him as a prophet.", "webster": "And when he would have put him to death, he feared the multitude, because they counted him as a prophet.", "vulgate": "et volens illum occidere timuit populum quia sicut prophetam eum habebant;"}}, {"v": 6, "ref": "14:6", "o": "⸂γενεσίοις δὲ γενομένοις⸃ τοῦ Ἡρῴδου ὠρχήσατο ἡ θυγάτηρ τῆς Ἡρῳδιάδος ἐν τῷ μέσῳ καὶ ἤρεσεν τῷ Ἡρῴδῃ,", "en": {"kjv": "But when Herod’s birthday was kept, the daughter of Herodias danced before them, and pleased Herod.", "web": "But when Herod’s birthday came, the daughter of Herodias danced among them and pleased Herod.", "bsb": "On Herod’s birthday, however, the daughter of Herodias danced before them and pleased Herod", "asv": "But when Herod’s birthday came, the daughter of Herodias danced in the midst, and pleased Herod.", "ylt": "But the birthday of Herod being kept, the daughter of Herodias danced in the midst, and did please Herod,", "tyndale": "But when Herodes birth daye was come the doughter of Herodias daunsed before them and pleased Herod.", "dra": "But on Herod's birthday, the daughter of Herodias danced before them: and pleased Herod.", "bbe": "But when Herod's birthday came, the daughter of Herodias was dancing before them, and Herod was pleased with her.", "geneva": "But when Herods birth day was kept, the daughter of Herodias daunced before them, and pleased Herod.", "wycliffe": "But in the dai of Heroudis birthe, the douytir of Herodias daunside in the myddil, and pleside Heroude.", "rotherham": "But, a birthday feast of Herod taking place, the daughter of Herodias danced in the midst, and pleased Herod;", "weymouth": "But when Herod's birthday came, the daughter of Herodias danced before all the company, and so pleased Herod", "darby": "But when Herod's birthday was celebrated, the daughter of Herodias danced before them, and pleased Herod;", "twenty": "But, when Herod’s birthday came, the daughter of Herodias danced before his guests, and so pleased Herod,", "acv": "But Herod's birthday being brought, the daughter of Herodias danced in the midst, and pleased Herod.", "anderson": "But when Herod’s birthday was kept, the daughter of Herodias danced in the midst, and pleased Herod.", "haweis": "But when Herod’s birth-day was kept, the daughter of Herodias danced in the circle, and pleased Herod:", "noyes": "But when Herod’s birthday was kept, the daughter of Herodias danced before them, and pleased Herod;", "webster": "But when Herod's birth-day was kept, the daughter of Herodias danced before them, and pleased Herod.", "vulgate": "die autem natalis Herodis saltavit filia Herodiadis in medio et placuit Herodi;"}}, {"v": 7, "ref": "14:7", "o": "ὅθεν μετὰ ὅρκου ὡμολόγησεν αὐτῇ δοῦναι ὃ ⸀ἐὰν αἰτήσηται.", "en": {"kjv": "Whereupon he promised with an oath to give her whatsoever she would ask.", "web": "Whereupon he promised with an oath to give her whatever she should ask.", "bsb": "so much that he promised with an oath to give to her whatever she asked.", "asv": "Whereupon he promised with an oath to give her whatsoever she should ask.", "ylt": "whereupon with an oath he professed to give her whatever she might ask.", "tyndale": "Wherfore he promised wt an oth that he wolde geve hir whatsoever she wolde axe.", "dra": "Whereupon he promised with an oath, to give her whatsoever she would ask of him.", "bbe": "So he gave her his word with an oath to let her have whatever she might make request for.", "geneva": "Wherefore he promised with an othe, that he would giue her whatsoeuer she would aske.", "wycliffe": "Wherfor with an ooth he bihiyte to yyue to hir, what euere thing she hadde axid of hym.", "rotherham": "wherefore, with an oath, he promised to give her, whatsoever she should ask for herself;", "weymouth": "that with an oath he promised to give her whatever she asked.", "darby": "whereupon he promised with oath to give her whatsoever she should ask.", "twenty": "that he promised with an oath to give her whatever she asked.", "acv": "Whereupon he promised with an oath to give her whatever she would ask.", "anderson": "Wherefore he promised, with an oath, to give her whatever she would ask.", "haweis": "so that with an oath he promised to give her whatever she should ask.", "noyes": "whereupon he promised with an oath to give her whatever she might ask.", "webster": "Upon which he promised with an oath to give her whatever she would ask.", "vulgate": "unde cum iuramento pollicitus est ei dare quodcumque postulasset ab eo;"}}, {"v": 8, "ref": "14:8", "o": "ἡ δὲ προβιβασθεῖσα ὑπὸ τῆς μητρὸς αὐτῆς· Δός μοι, φησίν, ὧδε ἐπὶ πίνακι τὴν κεφαλὴν Ἰωάννου τοῦ βαπτιστοῦ.", "en": {"kjv": "And she, being before instructed of her mother, said, Give me here John Baptist’s head in a charger.", "web": "She, being prompted by her mother, said, “Give me here on a platter the head of John the Baptizer.”", "bsb": "Prompted by her mother, she said, “Give me here on a platter the head of John the Baptist.”", "asv": "And she, being put forward by her mother, saith, Give me here on a platter the head of John the Baptist.", "ylt": "And she having been instigated by her mother--`Give me (says she) here upon a plate the head of John the Baptist;", "tyndale": "And she beinge informed of her mother before sayde: geve me here Ihon baptistes heed in a platter.", "dra": "But she being instructed before by her mother, said: Give me here in a dish the head of John the Baptist.", "bbe": "And she, at her mother's suggestion, said, Give me here on a plate the head of John the Baptist.", "geneva": "And shee being before instructed of her mother, sayde, Giue mee here Iohn Baptists head in a platter.", "wycliffe": "And she bifor warned of hir modir, seide, Yif thou to me here the heed of Joon Baptist in a disch.", "rotherham": "and, she, being led on by her mother,—Give me (saith she) here, upon a charger, the head of John the Immerser.", "weymouth": "So she, instigated by her mother, said, \"Give me here on a dish the head of John the Baptist.\"", "darby": "But she, being set on by her mother, says, Give me here upon a dish the head of John the baptist.", "twenty": "Prompted by her mother, the girl said ‘Give me here, on a dish, the head of John the Baptist.’", "acv": "And she, having been put forward by her mother, says, Give me here on a platter the head of John the immerser.", "anderson": "And being previously instigated by her mother, she said: Give me here in a dish the head of John the Immerser?", "haweis": "And she, being previously urged on by her mother, said, Give me here, in a spacious dish, the head of John the Baptist.", "noyes": "And she, being set on by her mother, saith, Give me here on a platter the head of John the Baptist.", "webster": "And she, being before instructed by her mother, said, Give me here the head of John the Baptist in a dish.", "vulgate": "at illa praemonita a matre sua da mihi inquit hic in disco caput Iohannis Baptistae;"}}, {"v": 9, "ref": "14:9", "o": "καὶ ⸂λυπηθεὶς ὁ βασιλεὺς διὰ⸃ τοὺς ὅρκους καὶ τοὺς συνανακειμένους ἐκέλευσεν δοθῆναι,", "en": {"kjv": "And the king was sorry: nevertheless for the oath’s sake, and them which sat with him at meat, he commanded it to be given her.", "web": "The king was grieved, but for the sake of his oaths, and of those who sat at the table with him, he commanded it to be given,", "bsb": "The king was grieved, but because of his oaths and his guests, he ordered that her wish be granted", "asv": "And the king was grieved; but for the sake of his oaths, and of them that sat at meat with him, he commanded it to be given;", "ylt": "and the king was grieved, but because of the oaths and of those reclining with him, he commanded it to be given;", "tyndale": "And ye kynge sorowed. Neverthelesse for his othes sake and for their sakis which sate also at ye table he comaunded yt to be geven hir:", "dra": "And the king was struck sad: yet because of his oath, and for them that sat with him at table, he commanded it to be given.", "bbe": "And the king was sad; but because of his oaths and because of his guests, he gave the order for it to be given to her;", "geneva": "And the King was sorie: neuerthelesse because of the othe, and them that sate with him at the table, he commanded it to be giuen her,", "wycliffe": "And the kyng was sorewful, but for the ooth, and for hem that saten to gidere at the mete, he comaundide to be youun.", "rotherham": "And the king, though grieved, yet, because of the oaths and the guests, ordered it to be given;", "weymouth": "The king was deeply vexed, yet because of his repeated oath and of the guests at his table he ordered it to be given her,", "darby": "And the king was grieved; but on account of the oaths, and those lying at table with [him], he commanded [it] to be given.", "twenty": "The king was distressed at this; yet, on account of his oath and of the guests at his table, he ordered it to be given her.", "acv": "And he became sad, but because of the oaths, and of those dining together, the king commanded it to be given.", "anderson": "And the king was grieved: but on account of his oath, and those who reclined at table with him, he commanded it to be given.", "haweis": "And the king was grieved: but for his oath’s sake, and on account of those who were with him, he commanded it to be given her.", "noyes": "And the king was sorry; but on account of his oaths, and of those at table with him, he ordered it to be given,", "webster": "And the king was sorry: nevertheless for the sake of the oath, and of them who sat with him at table, he commanded [it] to be given [her].", "vulgate": "et contristatus est rex propter iuramentum autem et eos qui pariter recumbebant iussit dari;"}}, {"v": 10, "ref": "14:10", "o": "καὶ πέμψας ἀπεκεφάλισεν ⸀τὸν Ἰωάννην ἐν τῇ φυλακῇ·", "en": {"kjv": "And he sent, and beheaded John in the prison.", "web": "and he sent and beheaded John in the prison.", "bsb": "and sent to have John beheaded in the prison.", "asv": "and he sent and beheaded John in the prison.", "ylt": "and having sent, he beheaded John in the prison,", "tyndale": "and sent and beheeded Ihon in the preson", "dra": "And he sent, and beheaded John in the prison.", "bbe": "And he sent and had John's head cut off in the prison.", "geneva": "And sent, and beheaded Iohn in the prison.", "wycliffe": "And he sente, and bihedide Joon in the prisoun.", "rotherham": "and sent and beheaded John in the prison.", "weymouth": "and he sent and beheaded John in the prison.", "darby": "And he sent and beheaded John in the prison;", "twenty": "He sent and beheaded John in the prison;", "acv": "And having sent, he beheaded John in the prison.", "anderson": "And he sent and beheaded John in the prison.", "haweis": "And he sent, and beheaded John in the prison.", "noyes": "and sent and beheaded John in the prison.", "webster": "And he sent, and beheaded John in the prison.", "vulgate": "misitque et decollavit Iohannem in carcere;"}}, {"v": 11, "ref": "14:11", "o": "καὶ ἠνέχθη ἡ κεφαλὴ αὐτοῦ ἐπὶ πίνακι καὶ ἐδόθη τῷ κορασίῳ, καὶ ἤνεγκεν τῇ μητρὶ αὐτῆς.", "en": {"kjv": "And his head was brought in a charger, and given to the damsel: and she brought it to her mother.", "web": "His head was brought on a platter, and given to the young lady: and she brought it to her mother.", "bsb": "John’s head was brought in on a platter and presented to the girl, who carried it to her mother.", "asv": "And his head was brought on a platter, and given to the damsel: and she brought it to her mother.", "ylt": "and his head was brought upon a plate, and was given to the damsel, and she brought it nigh to her mother.", "tyndale": "and his heed was brought in a platter and geven to the damsell and she brought it to her mother.", "dra": "And his head was brought in a dish: and it was given to the damsel, and she brought it to her mother.", "bbe": "And his head was put on a plate and given to the girl; and she took it to her mother.", "geneva": "And his head was brought in a platter, and giuen to the maide, and shee brought it vnto her mother.", "wycliffe": "And his heed was brouyt in a dische, and it was youun to the damysel, and she bar it to hir modir.", "rotherham": "And his head was brought upon a charger, and given unto the maiden, and she brought it to her mother.", "weymouth": "The head was brought on a dish and given to the young girl, and she took it to her mother.", "darby": "and his head was brought upon a dish, and was given to the damsel, and she carried [it] to her mother.", "twenty": "and his head was brought on a dish and given to the girl, and she took it to her mother.", "acv": "And his head was brought on a platter, and given to the maiden, and she brought it to her mother.", "anderson": "And his head was brought in a dish, and given to the maiden: and she carried it to her mother.", "haweis": "And his head was brought on a large dish, and was given to the young lady: and she brought it to her mother.", "noyes": "And his head was brought on a platter, and given to the damsel; and she brought it to her mother.", "webster": "And his head was brought in a dish, and given to the damsel: and she brought [it] to her mother.", "vulgate": "et adlatum est caput eius in disco et datum est puellae et tulit matri suae;"}}, {"v": 12, "ref": "14:12", "o": "καὶ προσελθόντες οἱ μαθηταὶ αὐτοῦ ἦραν τὸ ⸀πτῶμα καὶ ἔθαψαν ⸀αὐτόν, καὶ ἐλθόντες ἀπήγγειλαν τῷ Ἰησοῦ.", "en": {"kjv": "And his disciples came, and took up the body, and buried it, and went and told Jesus.", "web": "His disciples came, and took the body, and buried it; and they went and told Jesus.", "bsb": "Then John’s disciples came and took his body and buried it. And they went and informed Jesus.", "asv": "And his disciples came, and took up the corpse, and buried him; and they went and told Jesus.", "ylt": "And his disciples having come, took up the body, and buried it, and having come, they told Jesus,", "tyndale": "And his disciples came and toke vp his body and buryed it: and went and tolde Iesus.", "dra": "And his disciples came and took the body, and buried it, and came and told Jesus.", "bbe": "And his disciples came, and took up his body and put it in the earth; and they went and gave Jesus news of what had taken place.", "geneva": "And his disciples came, and tooke vp the bodie, and buried it, and went, and tolde Iesus.", "wycliffe": "And hise disciplis camen, and token his bodi, and birieden it; and thei camen, and tolden to Jhesu.", "rotherham": "And his disciples, going near, bare away the corpse, and buried him, and came and brought tidings unto Jesus.", "weymouth": "Then John's disciples went and removed the body and buried it, and came and informed Jesus.", "darby": "And his disciples came and took the body and buried it, and came and brought word to Jesus.", "twenty": "Then John’s disciples came, and took the body away, and buried it; and went and told Jesus.", "acv": "And after coming, his disciples took up the body and buried it, and having gone, they informed Jesus.", "anderson": "And his disciples came and took away the body, and buried it; and went and told Jesus.", "haweis": "And his disciples came and took the body, and buried it, and they came and told Jesus.", "noyes": "And his disciples came and took up the body, and buried it, and went and told Jesus.", "webster": "And his disciples came, and took up the body, and buried it, and went and told Jesus.", "vulgate": "et accedentes discipuli eius tulerunt corpus et sepelierunt illud et venientes nuntiaverunt Iesu;"}}, {"v": 13, "ref": "14:13", "o": "⸂Ἀκούσας δὲ⸃ ὁ Ἰησοῦς ἀνεχώρησεν ἐκεῖθεν ἐν πλοίῳ εἰς ἔρημον τόπον κατ’ ἰδίαν· καὶ ἀκούσαντες οἱ ὄχλοι ἠκολούθησαν αὐτῷ πεζῇ ἀπὸ τῶν πόλεων.", "en": {"kjv": "When Jesus heard of it, he departed thence by ship into a desert place apart: and when the people had heard thereof, they followed him on foot out of the cities.", "web": "Now when Jesus heard this, he withdrew from there in a boat, to a deserted place apart. When the multitudes heard it, they followed him on foot from the cities.", "bsb": "When Jesus heard about John, He withdrew by boat privately to a solitary place. But the crowds found out about it and followed Him on foot from the towns.", "asv": "Now when Jesus heardit, he withdrew from thence in a boat, to a desert place apart: and when the multitudes heard thereof, they followed him on foot from the cities.", "ylt": "and Jesus having heard, withdrew thence in a boat to a desolate place by himself, and the multitudes having heard did follow him on land from the cities.", "tyndale": "When Iesus hearde that he departed thence by shippe in to a desert place out of ye waye. And when the people had hearde therof they folowed him afote out of their cities.", "dra": "Which when Jesus had heard, he retired from thence by a boat, into a desert place apart, and the multitudes having heard of it, followed him on foot out of the cities.", "bbe": "Now when it came to the ears of Jesus, he went away from there in a boat, to a waste place by himself: and the people hearing of it, went after him on foot from the towns.", "geneva": "And when Iesus heard it, hee departed thence by shippe into a desert place apart. And when the multitude had heard it, they followed him on foote out of the cities.", "wycliffe": "And whanne Jhesus hadde herd this thing, he wente fro thennus in a boot, in to desert place bisides. And whanne the puple hadde herd, thei folewiden hym on her feet fro citees.", "rotherham": "And Jesus, hearing it, retired from thence in a boat, into a desert place, apart,—and the multitudes, hearing of it, followed him on foot from the cities.", "weymouth": "Upon receiving these tidings, Jesus went away by boat to an uninhabited and secluded district; but the people heard of it and followed Him in crowds from the towns by land.", "darby": "And Jesus, having heard it, went away thence by ship to a desert place apart. And the crowds having heard [of it] followed him on foot from the cities.", "twenty": "When Jesus heard of it, he retired privately in a boat to a lonely spot. The people, however, heard of his going, and followed him in crowds from the towns on foot.", "acv": "Now when Jesus heard it, he departed from there in a boat into a desolate place in private. And when the multitudes heard of it, they followed him on foot from the cities.", "anderson": "And when Jesus heard of it, he withdrew from that place, by ship, into a desert place apart: and the multitudes, when they heard of his departure, followed him, on foot, from the cities.", "haweis": "And when Jesus heard it, he withdrew from thence in a vessel into a desert place apart: and when the multitudes heard it, they followed him on foot from the cities.", "noyes": "When Jesus heard of it, he withdrew thence in a boat into a desert place apart; and the multitudes hearing of it followed him on foot from the cities.", "webster": "When Jesus heard [of it], he departed thence in a boat, into a desert place apart: and when the people had heard [of it], they followed him on foot out of the cities.", "vulgate": "quod cum audisset Iesus secessit inde in navicula in locum desertum seorsum et cum audissent turbae secutae sunt eum pedestres de civitatibus;"}}, {"v": 14, "ref": "14:14", "o": "καὶ ⸀ἐξελθὼν εἶδεν πολὺν ὄχλον, καὶ ἐσπλαγχνίσθη ἐπ’ αὐτοῖς καὶ ἐθεράπευσεν τοὺς ἀρρώστους αὐτῶν.", "en": {"kjv": "And Jesus went forth, and saw a great multitude, and was moved with compassion toward them, and he healed their sick.", "web": "Jesus went out, and he saw a great multitude. He had compassion on them, and healed their sick.", "bsb": "When He stepped ashore and saw a large crowd, He had compassion on them and healed their sick.", "asv": "And he came forth, and saw a great multitude, and he had compassion on them, and healed their sick.", "ylt": "And Jesus having come forth, saw a great multitude, and was moved with compassion upon them, and did heal their infirm;", "tyndale": "And Iesus went forth and sawe moche people and his herte did melte vpon them and he healed of them those that were sicke.", "dra": "And he coming forth saw a great multitude, and had compassion on them, and healed their sick.", "bbe": "And he came out and saw a great number of people and he had pity on them, and made well those of them who were ill.", "geneva": "And Iesus went foorth and sawe a great multitude, and was mooued with compassion toward them, and he healed their sicke.", "wycliffe": "And Jhesus yede out, and sai a greet puple, and hadde reuthe on hem, and heelide the sike men of hem.", "rotherham": "And, coming forth, he saw a great multitude,—and was moved with compassion over them, and cured their sick.", "weymouth": "So Jesus went out and saw an immense multitude, and felt compassion for them, and cured those of them who were out of health.", "darby": "And going out he saw a great crowd, and was moved with compassion about them, and healed their infirm.", "twenty": "On getting out of the boat, Jesus saw a great crowd, and his heart was moved at the sight of them; and he cured all the sick among them.", "acv": "And having come forth, Jesus saw a great multitude, and he felt compassion toward them, and healed the feeble of them.", "anderson": "And when Jesus came out, he saw a great multitude, and was moved with compassion for them, and cured their sick.", "haweis": "And when Jesus was come forth, he saw a great multitude, and was moved with compassion towards them, and healed their sick.", "noyes": "And when he came forth he saw a great multitude; and he was moved with compassion for them, and healed their sick.", "webster": "And Jesus went forth, and saw a great multitude, and was moved with compassion towards them, and he healed their sick.", "vulgate": "et exiens vidit turbam multam et misertus est eius et curavit languidos eorum;"}}, {"v": 15, "ref": "14:15", "o": "ὀψίας δὲ γενομένης προσῆλθον αὐτῷ οἱ ⸀μαθηταὶ λέγοντες· Ἔρημός ἐστιν ὁ τόπος καὶ ἡ ὥρα ἤδη παρῆλθεν· ἀπόλυσον τοὺς ὄχλους, ἵνα ἀπελθόντες εἰς τὰς κώμας ἀγοράσωσιν ἑαυτοῖς βρώματα.", "en": {"kjv": "And when it was evening, his disciples came to him, saying, This is a desert place, and the time is now past; send the multitude away, that they may go into the villages, and buy themselves victuals.", "web": "When evening had come, his disciples came to him, saying, “This place is deserted, and the hour is already late. Send the multitudes away, that they may go into the villages, and buy themselves food.”", "bsb": "When evening came, the disciples came to Him and said, “This is a desolate place, and the hour is already late. Dismiss the crowds so they can go to the villages and buy themselves some food.”", "asv": "And when even was come, the disciples came to him, saying, The place is desert, and the time is already past; send the multitudes away, that they may go into the villages, and buy themselves food.", "ylt": "and evening having come, his disciples came to him, saying, `The place is desolate, and the hour hath now past, let away the multitudes that, having gone to the villages, they may buy to themselves food.'", "tyndale": "When even was come his disciples came to him sayinge. This is a deserte place and the daye is spent: let the people departe yt they maye go into ye tounes and bye them vytayllis.", "dra": "And when it was evening, his disciples came to him, saying: This is a desert place, and the hour is now passed: send away the multitudes, that going into the towns, they may buy themselves victuals.", "bbe": "And when evening had come, the disciples came to him, saying, This place is waste land, and the time is now past; send the people away so that they may go into the towns and get themselves food.", "geneva": "And when euen was come, his disciples came to him, saying, This is a desart place, and the time is alreadie past: let the multitude depart, that they may goe into the townes, and bye them vitailes.", "wycliffe": "But whanne the euentid was com, hise disciplis camen to him, and seiden, The place is desert, and the tyme is now passid; lat the puple go in to townes, to bye hem mete.", "rotherham": "And, evening, arriving, the disciples came unto him, saying—The place is, a desert, and, the hour, hath already passed,—dismiss the multitudes, that they may go away into the villages, and buy themselves food.", "weymouth": "But when evening was come, the disciples came to Him and said, \"This is an uninhabited place, and the best of the day is now gone; send the people away to go into the villages and buy something to eat.\"", "darby": "But when even was come, his disciples came to him saying, The place is desert, and [much of] the [day] time already gone by; dismiss the crowds, that they may go into the villages and buy food for themselves.", "twenty": "In the evening the disciples came up to him, and said: “This is a lonely spot, and the day is now far advanced; send the crowds away, that they may go to the villages, and buy themselves food.”", "acv": "And having become evening, his disciples came to him, saying, The place is desolate, and the hour is now past. Send the multitudes away, so that having gone into the villages, they may buy food for themselves.", "anderson": "And when it was evening, his disciples came to him, and said: This is a desert place, and the hour is now past; send the multitudes away, that they may go into the villages, and buy themselves food.", "haweis": "But when evening was come, his disciples came unto him, saying, The place is desert, and the day is far advanced; send the multitude away, that they may go into the villages, and buy themselves provisions.", "noyes": "And when it was evening, the disciples came to him, saying, This is a desert place, and it is now late; send the multitudes away therefore, that they may go to the villages and buy themselves victuals.", "webster": "And when it was evening, his disciples came to him, saying, This is a desert place, and the time is now past; send the multitude away, that they may go into the villages, and buy themselves victuals.", "vulgate": "vespere autem facto accesserunt ad eum discipuli eius dicentes desertus est locus et hora iam praeteriit dimitte turbas ut euntes in castella emant sibi escas;"}}, {"v": 16, "ref": "14:16", "o": "ὁ δὲ Ἰησοῦς εἶπεν αὐτοῖς· Οὐ χρείαν ἔχουσιν ἀπελθεῖν· δότε αὐτοῖς ὑμεῖς φαγεῖν.", "en": {"kjv": "But Jesus said unto them, They need not depart; give ye them to eat.", "web": "But Jesus said to them, “They don’t need to go away. You give them something to eat.”", "bsb": "“They do not need to go away,” Jesus replied. “You give them something to eat.”", "asv": "But Jesus said unto them, They have no need to go away; give ye them to eat.", "ylt": "And Jesus said to them, `They have no need to go away--give ye them to eat.'", "tyndale": "But Iesus sayde vnto them. They have no neade to go awaye. Geve ye the to eate.", "dra": "But Jesus said to them, They have no need to go: give you them to eat.", "bbe": "But Jesus said to them, There is no need for them to go away; give them food yourselves.", "geneva": "But Iesus saide to them, They haue no neede to goe away: giue yee them to eate.", "wycliffe": "Jhesus seide to hem, Thei han not nede to go; yyue ye hem sumwhat to ete.", "rotherham": "But, Jesus, said unto them, No need, have they to go away,—give, ye, them to eat.", "weymouth": "\"They need not go away,\" replied Jesus; \"you yourselves must give them something to eat.\"", "darby": "But Jesus said to them, They have no need to go: give ye them to eat.", "twenty": "But Jesus said: “They need not go away, it is for you to give them something to eat.”", "acv": "But Jesus said to them, They have no need to depart. Give ye them to eat.", "anderson": "But Jesus said to them: They need not go away; do you give them food.", "haweis": "But Jesus said unto them, They need not depart: give ye them to eat.", "noyes": "But he said to them, They need not go away; do ye give them food.", "webster": "But Jesus said to them, They need not depart; give ye them to eat.", "vulgate": "Iesus autem dixit eis non habent necesse ire date illis vos manducare;"}}, {"v": 17, "ref": "14:17", "o": "οἱ δὲ λέγουσιν αὐτῷ· Οὐκ ἔχομεν ὧδε εἰ μὴ πέντε ἄρτους καὶ δύο ἰχθύας.", "en": {"kjv": "And they say unto him, We have here but five loaves, and two fishes.", "web": "They told him, “We only have here five loaves and two fish.”", "bsb": "“We have here only five loaves of bread and two fish,” they answered.", "asv": "And they say unto him, We have here but five loaves, and two fishes.", "ylt": "And they say to him, `We have not here except five loaves, and two fishes.'", "tyndale": "Then sayde they vnto him: we have here but .v. loves and two fysshes.", "dra": "They answered him: We have not here, but five loaves, and two fishes.", "bbe": "And they say to him, We have here but five cakes of bread and two fishes.", "geneva": "Then saide they vnto him, Wee haue here but fiue loaues, and two fishes.", "wycliffe": "Thei answeriden, We han not heere, but fyue looues and twei fischis.", "rotherham": "But, they, say unto him—We have nothing here, save five loaves and two fishes.", "weymouth": "\"We have nothing here,\" they said, \"but five loaves and a couple of fish.\"", "darby": "But they say to him, We have not here save five loaves and two fishes.", "twenty": "“We have nothing here,” they said, “except five loaves and two fishes.”", "acv": "And they say to him, We have not here, except five loaves and two fishes.", "anderson": "They said to him: We have here but five loaves and two fishes.", "haweis": "And they said unto him, We have nothing here except five loaves and two fishes.", "noyes": "And they say to him, We have here only five loaves, and two fishes.", "webster": "And they say to him, We have here but five loaves, and two fishes.", "vulgate": "responderunt ei non habemus hic nisi quinque panes et duos pisces;"}}, {"v": 18, "ref": "14:18", "o": "ὁ δὲ εἶπεν· Φέρετέ μοι ⸂ὧδε αὐτούς⸃.", "en": {"kjv": "He said, Bring them hither to me.", "web": "He said, “Bring them here to me.”", "bsb": "“Bring them here to Me,” Jesus said.", "asv": "And he said, Bring them hither to me.", "ylt": "And he said, `Bring ye them to me hither.'", "tyndale": "And he sayde: bringe the hyther to me.", "dra": "Who said to them: Bring them hither to me.", "bbe": "And he said, Give them to me.", "geneva": "And he saide, Bring them hither to me.", "wycliffe": "And he seide to hem, Brynge ye hem hidur to me.", "rotherham": "But, he, said—Bring, them, to me, here.", "weymouth": "\"Bring them here to me,\" He said,", "darby": "And he said, Bring them here to me.", "twenty": "“Bring them here to me,” was his reply.", "acv": "But he said, Bring them here to me.", "anderson": "He said: Bring them hither to me.", "haweis": "Then he said, Bring them hither to me.", "noyes": "He said, Bring them hither to me.", "webster": "He said, Bring them hither to me.", "vulgate": "qui ait eis adferte illos mihi huc;"}}, {"v": 19, "ref": "14:19", "o": "καὶ κελεύσας τοὺς ὄχλους ἀνακλιθῆναι ἐπὶ ⸂τοῦ χόρτου⸃, λαβὼν τοὺς πέντε ἄρτους καὶ τοὺς δύο ἰχθύας, ἀναβλέψας εἰς τὸν οὐρανὸν εὐλόγησεν καὶ κλάσας ἔδωκεν τοῖς μαθηταῖς τοὺς ἄρτους οἱ δὲ μαθηταὶ τοῖς ὄχλοις.", "en": {"kjv": "And he commanded the multitude to sit down on the grass, and took the five loaves, and the two fishes, and looking up to heaven, he blessed, and brake, and gave the loaves to his disciples, and the disciples to the multitude.", "web": "He commanded the multitudes to sit down on the grass; and he took the five loaves and the two fish, and looking up to heaven, he blessed, broke and gave the loaves to the disciples, and the disciples gave to the multitudes.", "bsb": "And He directed the crowds to sit down on the grass. Taking the five loaves and the two fish and looking up to heaven, He spoke a blessing. Then He broke the loaves and gave them to the disciples, and the disciples gave them to the people.", "asv": "And he commanded the multitudes to sit down on the grass; and he took the five loaves, and the two fishes, and looking up to heaven, he blessed, and brake and gave the loaves to the disciples, and the disciples to the multitudes.", "ylt": "And having commanded the multitudes to recline upon the grass, and having taken the five loaves and the two fishes, having looked up to the heaven, he did bless, and having broken, he gave the loaves to the disciples, and the disciples to the multitudes,", "tyndale": "And he comaunded ye people to syt downe on ye grasse: and toke ye .v. loves and the .ii. fysshes and loked vp to heven and blessed and brake and gave the loves to his disciples and the disciples gave them to ye people.", "dra": "And when he had commanded the multitude to sit down upon the grass, he took the five loaves and the two fishes, and looking up to heaven, he blessed, and brake, and gave the loaves to his disciples, and the disciples to the multitudes.", "bbe": "And he gave orders for the people to be seated on the grass; and he took the five cakes of bread and the two fishes and, looking up to heaven, he said words of blessing, and made division of the food, and gave it to the disciples, and the disciples gave it to the people.", "geneva": "And hee commanded the multitude to sit downe on the grasse, and tooke the fiue loaues and the two fishes, and looked vp to heauen and blessed, and brake, and gaue the loaues to his disciples, and the disciples to the multitude.", "wycliffe": "And whanne he hadde comaundid the puple to sitte to meete on the heye, he took fyue looues and twei fischis, and he bihelde in to heuene, and blesside, and brak, and yaf to hise disciplis; and the disciplis yauen to the puple.", "rotherham": "And, giving orders that the multitudes should recline upon the grass,—taking the five loaves and the two fishes,—looking up into the heaven, he blessed; and, breaking, gave, the disciples, the loaves, and the disciples unto the multitude.", "weymouth": "and He told all the people to sit down on the grass. Then He took the five loaves and the two fish, and after looking up to heaven and blessing them, He broke up the loaves and gave them to the disciples, and the disciples distributed them to the people.", "darby": "And having commanded the crowds to recline upon the grass, having taken the five loaves and the two fishes, he looked up to heaven, and blessed: and having broken the loaves, he gave [them] to the disciples, and the disciples [gave them] to the crowds.", "twenty": "Jesus ordered the people to take their seats on the grass; and, taking the five loaves and the two fishes, he looked up to Heaven, and said the blessing, and, after he had broken the loaves, gave them to his disciples; and they gave them to the crowds.", "acv": "And after commanding the multitudes to sit down on the grass, having taken the five loaves, and the two fishes, having looking up to heaven, he blessed. And having broken them in pieces, he gave the loaves to the disciples, and the disciples to the multitudes.", "anderson": "And he commanded the multitudes to recline upon the grass: and he took the five loaves and the two fishes, and looked up to heaven, and blessed, and broke, and gave the bread to the disciples, and the disciples gave it to the multitudes.", "haweis": "And he commanded the multitude to sit down on the grass, and taking the five loaves and the two fishes, looking up to heaven, he blessed them, and brake, and gave the loaves to the disciples, and the disciples to the multitude.", "noyes": "And bidding the multitudes to lie down on the grass, he took the five loaves and the two fishes, and, looking up to heaven, he blessed; and having broken the loaves he gave them to his disciples, and the disciples to the multitudes.", "webster": "And he commanded the multitude to sit down on the grass, and took the five loaves, and the two fishes, and looking up to heaven, he blessed, and broke, and gave the loaves to [his] disciples, and the disciples to the multitude.", "vulgate": "et cum iussisset turbam discumbere supra faenum acceptis quinque panibus et duobus piscibus aspiciens in caelum benedixit et fregit et dedit discipulis panes discipuli autem turbis;"}}, {"v": 20, "ref": "14:20", "o": "καὶ ἔφαγον πάντες καὶ ἐχορτάσθησαν, καὶ ἦραν τὸ περισσεῦον τῶν κλασμάτων δώδεκα κοφίνους πλήρεις.", "en": {"kjv": "And they did all eat, and were filled: and they took up of the fragments that remained twelve baskets full.", "web": "They all ate, and were filled. They took up twelve baskets full of that which remained left over from the broken pieces.", "bsb": "They all ate and were satisfied, and the disciples picked up twelve basketfuls of broken pieces that were left over.", "asv": "And they all ate, and were filled: and they took up that which remained over of the broken pieces, twelve baskets full.", "ylt": "and they did all eat, and were filled, and they took up what was over of the broken pieces twelve hand-baskets full;", "tyndale": "And they dyd all eate and were suffised. And they gadered vp of ye gobbetes that remayned vii. basketes full.", "dra": "And they did all eat, and were filled. And they took up what remained, twelve full baskets of fragments.", "bbe": "And they all took of the food and had enough: and they took up twelve baskets full of broken bits which were not used.", "geneva": "And they did all eate, and were sufficed, and they tooke vp of the fragments that remained, twelue baskets full.", "wycliffe": "And alle eten, and weren fulfillid. And thei tooken the relifs of brokun gobetis, twelue cofynes ful.", "rotherham": "And they did all eat, and were filled,—and they took up the remainder of the broken pieces, twelve baskets, full.", "weymouth": "So all ate, and were fully satisfied. The broken portions that remained over they gathered up, filling twelve baskets.", "darby": "And all ate and were filled, and they took up what was over and above of fragments twelve hand-baskets full.", "twenty": "Every one had sufficient to eat, and they picked up enough of the broken pieces that were left to fill twelve baskets.", "acv": "And they all ate, and were filled. And they took up that which remained of the fragments, twelve baskets full.", "anderson": "And they all ate and were satisfied. And they took up what remained of the broken pieces, twelve baskets full.", "haweis": "And they did all eat, and were filled: and they took up the superabundance of the fragments, twelve baskets full.", "noyes": "And they all ate, and were filled. And they took up of the fragments that remained, twelve baskets full.", "webster": "And they all ate, and were satisfied: and they took up of the fragments that remained twelve baskets full.", "vulgate": "et manducaverunt omnes et saturati sunt et tulerunt reliquias duodecim cofinos fragmentorum plenos;"}}, {"v": 21, "ref": "14:21", "o": "οἱ δὲ ἐσθίοντες ἦσαν ἄνδρες ὡσεὶ πεντακισχίλιοι χωρὶς γυναικῶν καὶ παιδίων.", "en": {"kjv": "And they that had eaten were about five thousand men, beside women and children.", "web": "Those who ate were about five thousand men, besides women and children.", "bsb": "About five thousand men were fed, in addition to women and children.", "asv": "And they that did eat were about five thousand men, besides women and children.", "ylt": "and those eating were about five thousand men, apart from women and children.", "tyndale": "And they yt ate werein nobre about .v.M. men besyde wemen and chyldren.", "dra": "And the number of them that did eat, was five thousand men, besides women and children.", "bbe": "And those who had food were about five thousand men, in addition to women and children.", "geneva": "And they that had eaten, were about fiue thousande men, beside women and litle children.", "wycliffe": "And the noumbre of men that eten was fyue thousynde of men, outakun wymmen and lytle children.", "rotherham": "And, they who did eat, were about five thousand, men, besides women and children.", "weymouth": "Those who had eaten were about 5,000 adult men, without reckoning women and children.", "darby": "But those that had eaten were about five thousand men, besides women and children.", "twenty": "The men who ate were about five thousand in number, without counting women and children.", "acv": "And those who ate were about five thousand men, besides women and children.", "anderson": "And they that had eaten were about five thousand men, besides women and children.", "haweis": "And they who had eaten, were about five thousand men, besides women and children.", "noyes": "And they who ate were about five thousand men, besides women and children.", "webster": "And they that had eaten were about five thousand men, besides women and children.", "vulgate": "manducantium autem fuit numerus quinque milia virorum exceptis mulieribus et parvulis;"}}, {"v": 22, "ref": "14:22", "o": "Καὶ εὐθέως ⸀ἠνάγκασεν τοὺς μαθητὰς ἐμβῆναι ⸀εἰς πλοῖον καὶ προάγειν αὐτὸν εἰς τὸ πέραν, ἕως οὗ ἀπολύσῃ τοὺς ὄχλους.", "en": {"kjv": "And straightway Jesus constrained his disciples to get into a ship, and to go before him unto the other side, while he sent the multitudes away.", "web": "Immediately Jesus made the disciples get into the boat, and to go ahead of him to the other side, while he sent the multitudes away.", "bsb": "Immediately Jesus made the disciples get into the boat and go on ahead of Him to the other side, while He dismissed the crowds.", "asv": "And straightway he constrained the disciples to enter into the boat, and to go before him unto the other side, till he should send the multitudes away.", "ylt": "And immediately Jesus constrained his disciples to go into the boat, and to go before him to the other side, till he might let away the multitudes;", "tyndale": "And strayght waye Iesus made his disciples enter into a shippe and to goo over before him whill he sent ye people awaye.", "dra": "And forthwith Jesus obliged his disciples to go up into the boat, and to go before him over the water, till he dismissed the people.", "bbe": "And straight away he made the disciples get into the boat and go before him to the other side, till he had sent the people away.", "geneva": "And straightway Iesus compelled his disciples to enter into a shippe, and to goe ouer before him, while he sent the multitude away.", "wycliffe": "And anoon Jhesus compellide the disciplis to go vp in to a boot, and go bifor hym ouer the see, while he lefte the puple.", "rotherham": "And [straightway] constrained he the disciples to enter into a boat, and be going before him unto the other side, while he dismissed the multitudes.", "weymouth": "Immediately afterwards He made the disciples go on board the boat and cross to the opposite shore, leaving Him to dismiss the people.", "darby": "And immediately he compelled the disciples to go on board ship, and to go on before him to the other side, until he should have dismissed the crowds.", "twenty": "Immediately afterwards Jesus made the disciples get into a boat and cross over in advance of him, while he dismissed the crowds.", "acv": "And straightaway Jesus compelled the disciples to enter into the boat, and to go ahead of him to the other side, until he would dismiss the multitudes.", "anderson": "And he immediately constrained his disciples to get into the ship, and go before him to the opposite side, while he sent the multitudes away.", "haweis": "And immediately Jesus compelled his disciples to go on board the vessel, and pass before him to the other side, while he dismissed the people.", "noyes": "and he constrained the disciples to get into the boat, and to go before him to the other side, while he sent the multitudes away.", "webster": "And immediately Jesus constrained his disciples to get into a boat, and to go before him to the other side, while he sent the multitudes away.", "vulgate": "et statim iussit discipulos ascendere in navicula et praecedere eum trans fretum donec dimitteret turbas;"}}, {"v": 23, "ref": "14:23", "o": "καὶ ἀπολύσας τοὺς ὄχλους ἀνέβη εἰς τὸ ὄρος κατ’ ἰδίαν προσεύξασθαι. ὀψίας δὲ γενομένης μόνος ἦν ἐκεῖ.", "en": {"kjv": "And when he had sent the multitudes away, he went up into a mountain apart to pray: and when the evening was come, he was there alone.", "web": "After he had sent the multitudes away, he went up into the mountain by himself to pray. When evening had come, he was there alone.", "bsb": "After He had sent them away, He went up on the mountain by Himself to pray. When evening came, He was there alone,", "asv": "And after he had sent the multitudes away, he went up into the mountain apart to pray: and when even was come, he was there alone.", "ylt": "and having let away the multitudes, he went up to the mountain by himself to pray, and evening having come, he was there alone,", "tyndale": "And assone as he had sent the people awaye he went vp into a moutayne alone to praye. And when nyght was come he was there himsilf alone.", "dra": "And having dismissed the multitude, he went into a mountain alone to pray. And when it was evening, he was there alone.", "bbe": "And after he had sent the people away, he went up into the mountain by himself for prayer: and when evening was come, he was there by himself.", "geneva": "And assoone as hee had sent the multitude away, he went vp into a moutaine alone to pray: and when the euening was come, hee was there alone.", "wycliffe": "And whanne the puple was left, he stiede aloone in to an hil for to preie. But whanne the euenyng was come, he was there aloone.", "rotherham": "And, dismissing the multitudes, he went up into the mountain, apart, to pray,—and when, evening, came, alone, was he, there.", "weymouth": "When He had done this, He climbed the hill to pray in solitude. Night came on, and he was there alone.", "darby": "And having dismissed the crowds, he went up into the mountain apart to pray. And when even was come, he was alone there,", "twenty": "After dismissing the crowds, he went up the hill by himself to pray; and, when evening fell, he was there alone.", "acv": "And having dismissed the multitudes, he went up onto the mountain in private to pray. And having become evening, he was there alone.", "anderson": "And when he had sent the multitudes away, he went up into the mountain apart to pray. And when evening came, he was there alone.", "haweis": "And when he had sent away the multitude, he went up into a mountain apart to pray: and when evening came, he was there alone.", "noyes": "And when he had sent the multitudes away, he went up into the mountain apart to pray. And when evening came, he was there alone.", "webster": "And when he had sent the multitudes away, he ascended a mountain apart to pray: and when the evening was come, he was there alone.", "vulgate": "et dimissa turba ascendit in montem solus orare vespere autem facto solus erat ibi;"}}, {"v": 24, "ref": "14:24", "o": "τὸ δὲ πλοῖον ἤδη ⸂σταδίους πολλοὺς ἀπὸ τῆς γῆς ἀπεῖχεν⸃, βασανιζόμενον ὑπὸ τῶν κυμάτων, ἦν γὰρ ἐναντίος ὁ ἄνεμος.", "en": {"kjv": "But the ship was now in the midst of the sea, tossed with waves: for the wind was contrary.", "web": "But the boat was now in the middle of the sea, distressed by the waves, for the wind was contrary.", "bsb": "but the boat was already far from land, buffeted by the waves because the wind was against it.", "asv": "But the boat was now in the midst of the sea, distressed by the waves; for the wind was contrary.", "ylt": "and the boat was now in the midst of the sea, distressed by the waves, for the wind was contrary.", "tyndale": "And the shippe was now in the middes of the see and was toost with waves for it was a cotrary wynde.", "dra": "But the boat in the midst of the sea was tossed with the waves: for the wind was contrary.", "bbe": "But the boat was now in the middle of the sea, and was troubled by the waves: for the wind was against them.", "geneva": "And the shippe was nowe in the middes of the sea, and was tossed with waues: for it was a contrarie winde.", "wycliffe": "And the boot in the myddel of the see was schoggid with wawis, for the wynd was contrarie to hem.", "rotherham": "Now, the boat, still many furlongs from the land, was holding off, being distressed by the waves,—for, the wind, was, contrary.", "weymouth": "Meanwhile the boat was far out on the Lake, buffeted and tossed by the waves, the wind being adverse.", "darby": "but the ship was already in the middle of the sea tossed by the waves, for the wind was contrary.", "twenty": "The boat was by this time some miles from shore, labouring in the waves, for the wind was against her.", "acv": "But the boat was now in the midst of the sea, being buffeted by the waves, for the wind was contrary.", "anderson": "But the ship was now in the midst of the sea, tossed by the waves, for the wind was against them.", "haweis": "But the vessel was already in the midst of the sea, tossed with the waves: for the wind was contrary.", "noyes": "But the boat was now in the midst of the lake, tossed by the waves; for the wind was contrary.", "webster": "But the boat was now in the midst of the sea, tossed with waves: for the wind was contrary.", "vulgate": "navicula autem in medio mari iactabatur fluctibus erat enim contrarius ventus;"}}, {"v": 25, "ref": "14:25", "o": "τετάρτῃ δὲ φυλακῇ τῆς νυκτὸς ⸀ἦλθεν πρὸς ⸀αὐτοὺς περιπατῶν ἐπὶ ⸂τὴν θάλασσαν⸃.", "en": {"kjv": "And in the fourth watch of the night Jesus went unto them, walking on the sea.", "web": "In the fourth watch of the night, Jesus came to them, walking on the sea.", "bsb": "During the fourth watch of the night, Jesus went out to them, walking on the sea.", "asv": "And in the fourth watch of the night he came unto them, walking upon the sea.", "ylt": "And in the fourth watch of the night Jesus went away to them, walking upon the sea,", "tyndale": "In the fourthe watche of ye night Iesus came vnto them walkynge on the see.", "dra": "And in the fourth watch of the night, he came to them walking upon the sea.", "bbe": "And in the fourth watch of the night he came to them, walking on the sea.", "geneva": "And in the fourth watch of the night, Iesus went vnto them, walking on the sea.", "wycliffe": "But in the fourthe wakyng of the niyt, he cam to hem walkynge aboue the see.", "rotherham": "And, in the fourth watch of the night, he came unto them, walking upon the sea.", "weymouth": "But towards daybreak He went to them, walking over the waves.", "darby": "But in the fourth watch of the night he went off to them, walking on the sea.", "twenty": "Three hours after midnight, however, Jesus came towards the disciples, walking on the water.", "acv": "And in the fourth watch of the night Jesus went to them, walking upon the sea.", "anderson": "And in the fourth watch of the night he came to them, walking on the sea.", "haweis": "Then at the fourth watch of the night came Jesus unto them, walking on the sea.", "noyes": "And in the fourth watch of the night, he went to them, walking on the lake.", "webster": "And in the fourth watch of the night Jesus went to them, walking on the sea.", "vulgate": "quarta autem vigilia noctis venit ad eos ambulans supra mare;"}}, {"v": 26, "ref": "14:26", "o": "⸂οἱ δὲ μαθηταὶ ἰδόντες αὐτὸν⸃ ἐπὶ ⸂τῆς θαλάσσης⸃ περιπατοῦντα ἐταράχθησαν λέγοντες ὅτι Φάντασμά ἐστιν, καὶ ἀπὸ τοῦ φόβου ἔκραξαν.", "en": {"kjv": "And when the disciples saw him walking on the sea, they were troubled, saying, It is a spirit; and they cried out for fear.", "web": "When the disciples saw him walking on the sea, they were troubled, saying, “It’s a ghost!” and they cried out for fear.", "bsb": "When the disciples saw Him walking on the sea, they were terrified. “It’s a ghost!” they said, and cried out in fear.", "asv": "And when the disciples saw him walking on the sea, they were troubled, saying, It is a ghost; and they cried out for fear.", "ylt": "and the disciples having seen him walking upon the sea, were troubled saying--`It is an apparition,' and from the fear they cried out;", "tyndale": "And when his disciples sawe him walkynge on the see they were troubled sayinge: it is some spirite and cryed out for feare.", "dra": "And they seeing him walking upon the sea, were troubled, saying: It is an apparition. And they cried out for fear.", "bbe": "And when they saw him walking on the sea, they were troubled, saying, It is a spirit; and they gave cries of fear.", "geneva": "And when his disciples sawe him walking on the sea, they were troubled, saying, It is a spirit, and cried out for feare.", "wycliffe": "And thei, seynge hym walking on the see, weren disturblid, and seiden, That it is a fantum; and for drede thei crieden.", "rotherham": "And, the disciples, seeing him, upon the lake walking, were troubled,—saying—It is, a ghost; and, by reason of their fear, they cried out.", "weymouth": "When the disciples saw Him walking on the waves, they were greatly alarmed. \"It is a spirit,\" they exclaimed, and they cried out with terror.", "darby": "And the disciples, seeing him walking on the sea, were troubled, saying, It is an apparition. And they cried out through fear.", "twenty": "But, when they saw him walking on the water, they were terrified. “It is a ghost,” they exclaimed, and cried out for fear.", "acv": "And when the disciples saw him walking on the sea, they were troubled, saying, It is a ghost, and they cried out from fear.", "anderson": "And when the disciples saw him walking on the sea, they were alarmed, and said: It is a specter! and they cried out for fear.", "haweis": "And when the disciples saw him walking on the sea, they were greatly agitated, saying, It is his apparition. And they cried out with terror.", "noyes": "And seeing him walking on the lake, they were dismayed, saying, It is a spectre; and they cried out for fear.", "webster": "And when the disciples saw him walking on the sea, they were troubled, saying, It is a spirit; and they cried out for fear.", "vulgate": "et videntes eum supra mare ambulantem turbati sunt dicentes quia fantasma est et prae timore clamaverunt;"}}, {"v": 27, "ref": "14:27", "o": "⸀εὐθὺς δὲ ἐλάλησεν ⸂αὐτοῖς ὁ Ἰησοῦς⸃ λέγων· Θαρσεῖτε, ἐγώ εἰμι· μὴ φοβεῖσθε.", "en": {"kjv": "But straightway Jesus spake unto them, saying, Be of good cheer; it is I; be not afraid.", "web": "But immediately Jesus spoke to them, saying “Cheer up! It is I! Don’t be afraid.”", "bsb": "But Jesus spoke up at once: “Take courage! It is I. Do not be afraid.”", "asv": "But straightway Jesus spake unto them, saying, Be of good cheer; it is I; be not afraid.", "ylt": "and immediately Jesus spake to them, saying, `Be of good courage, I am he , be not afraid.'", "tyndale": "And streyght waye Iesus spake vnto them sayinge: be of god cheare it is I be not afrayed.", "dra": "And immediately Jesus spoke to them, saying: Be of good heart: it is I, fear ye not.", "bbe": "But straight away Jesus said to them, Take heart; it is I, have no fear.", "geneva": "But straight way Iesus spake vnto them, saying, Be of good comfort, It is I: be not afraide.", "wycliffe": "And anoon Jhesus spac to hem, and seide, Haue ye trust, Y am; nyle ye drede.", "rotherham": "And, straightway, Jesus spake unto them, saying—Take courage! it is, I,—be not afraid.", "weymouth": "But instantly Jesus spoke to them, and said, \"There is no danger; it is I; do not be afraid.\"", "darby": "But Jesus immediately spoke to them, saying, Take courage; it is I: be not afraid.", "twenty": "But Jesus at once spoke to them. “Courage!” he said, “It is I; do not be afraid!”", "acv": "But straightaway Jesus spoke to them, saying, Cheer up. It is I, fear not.", "anderson": "But Jesus immediately spoke to them, and said: Take courage; it is I; be not afraid.", "haweis": "And immediately Jesus spake to them, saying, Be of good courage: it is I; be not terrified.", "noyes": "But he immediately spoke to them, saying, Be of good cheer, it is I; be not afraid.", "webster": "But immediately Jesus spoke to them, saying, Be of good cheer; it is I; be not afraid.", "vulgate": "statimque Iesus locutus est eis dicens habete fiduciam ego sum nolite timere;"}}, {"v": 28, "ref": "14:28", "o": "Ἀποκριθεὶς δὲ ⸂αὐτῷ ὁ Πέτρος εἶπεν⸃· Κύριε, εἰ σὺ εἶ, κέλευσόν με ⸂ἐλθεῖν πρὸς σὲ⸃ ἐπὶ τὰ ὕδατα·", "en": {"kjv": "And Peter answered him and said, Lord, if it be thou, bid me come unto thee on the water.", "web": "Peter answered him and said, “Lord, if it is you, command me to come to you on the waters.”", "bsb": "“Lord, if it is You,” Peter replied, “command me to come to You on the water.”", "asv": "And Peter answered him and said, Lord, if it be thou, bid me come unto thee upon the waters.", "ylt": "And Peter answering him said, `Sir, if it is thou, bid me come to thee upon the waters;'", "tyndale": "Peter answered him and sayde: master if thou be he bid me come vnto the on the water.", "dra": "And Peter making answer, said: Lord, if it be thou, bid me come to thee upon the waters.", "bbe": "And Peter, answering, said to him, Lord, if it is you, give me the order to come to you on the water.", "geneva": "Then Peter answered him, and saide, Master, if it be thou, bid me come vnto thee on the water.", "wycliffe": "And Petre answeride, and seide, Lord, if thou art, comaunde me to come to thee on the watris.", "rotherham": "And, making answer, Peter said unto him,—Lord! if it is, thou, bid me come unto thee, upon the waters.", "weymouth": "\"Master,\" answered Peter, \"if it is you, bid me come to you upon the water.\"", "darby": "And Peter answering him said, Lord, if it be thou, command me to come to thee upon the waters.", "twenty": "“Master,” Peter exclaimed, “if it is you, tell me to come to you on the water.”", "acv": "And having answered him, Peter said, Lord, if it be thou, bid me come to thee on the waters.", "anderson": "And Peter answered him, and said: Lord, if it be thou, bid me come to thee on the water.", "haweis": "Then Peter answering, said, Lord, if it be thou, command me to come unto thee upon the waters.", "noyes": "And Peter answering him said, Lord, if it be thou, bid me come to thee on the water.", "webster": "And Peter answered him and said, Lord, if it is thou, bid me come to thee on the water.", "vulgate": "respondens autem Petrus dixit Domine si tu es iube me venire ad te super aquas;"}}, {"v": 29, "ref": "14:29", "o": "ὁ δὲ εἶπεν· Ἐλθέ. καὶ καταβὰς ἀπὸ τοῦ ⸀πλοίου Πέτρος περιεπάτησεν ἐπὶ τὰ ὕδατα ⸂καὶ ἦλθεν⸃ πρὸς τὸν Ἰησοῦν.", "en": {"kjv": "And he said, Come. And when Peter was come down out of the ship, he walked on the water, to go to Jesus.", "web": "He said, “Come!” Peter stepped down from the boat, and walked on the waters to come to Jesus.", "bsb": "“Come,” said Jesus. Then Peter got down out of the boat, walked on the water, and came toward Jesus.", "asv": "And he said, Come. And Peter went down from the boat, and walked upon the waters to come to Jesus.", "ylt": "and he said, `Come;' and having gone down from the boat, Peter walked upon the waters to come unto Jesus,", "tyndale": "And he sayde come. And when Peter was come doune out of ye shippe he walked on ye water to go to Iesus.", "dra": "And he said: Come. And Peter going down out of the boat walked upon the water to come to Jesus.", "bbe": "And he said, Come. And Peter got out of the boat, and walking on the water, went to Jesus.", "geneva": "And he saide, Come. And when Peter was come downe out of the shippe, he walked on the water, to goe to Iesus.", "wycliffe": "And he seide, Come thou. And Petre yede doun fro the boot, and walkide on the watris to come to Jhesu.", "rotherham": "And, he, said—Come! And, descending from the boat, Peter walked upon the waters, and came unto Jesus.", "weymouth": "\"Come,\" said Jesus. Then Peter climbed down from the boat and walked upon the water to go to Him.", "darby": "And he said, Come. And Peter, having descended from the ship, walked upon the waters to go to Jesus.", "twenty": "And Jesus said: “Come.” So Peter got down from the boat, and walked on the water, and went towards Jesus;", "acv": "And he said, Come. And having come down from the boat, Peter walked upon the water to go to Jesus.", "anderson": "And he said: Come. And Peter went down from the ship, and walked upon the water to go to Jesus.", "haweis": "And he said, Come. And descending from the vessel, Peter walked upon the waters to come to Jesus.", "noyes": "And he said, Come. And Peter, coming down from the boat, walked on the water, and came to Jesus.", "webster": "And he said, Come. And when Peter had come down out of the boat, he walked on the water, to go to Jesus.", "vulgate": "at ipse ait veni et descendens Petrus de navicula ambulabat super aquam ut veniret ad Iesum;"}}, {"v": 30, "ref": "14:30", "o": "βλέπων δὲ τὸν ἄνεμον ⸀ἰσχυρὸν ἐφοβήθη, καὶ ἀρξάμενος καταποντίζεσθαι ἔκραξεν λέγων· Κύριε, σῶσόν με.", "en": {"kjv": "But when he saw the wind boisterous, he was afraid; and beginning to sink, he cried, saying, Lord, save me.", "web": "But when he saw that the wind was strong, he was afraid, and beginning to sink, he cried out, saying, “Lord, save me!”", "bsb": "But when he saw the strength of the wind, he was afraid, and beginning to sink, cried out, “Lord, save me!”", "asv": "But when he saw the wind, he was afraid; and beginning to sink, he cried out, saying, Lord, save me.", "ylt": "but seeing the wind vehement, he was afraid, and having begun to sink, he cried out, saying, `Sir, save me.'", "tyndale": "But when he sawe a myghty wynde he was afrayed. And as he beganne to synke he cryed sayinge: master save me.", "dra": "But seeing the wind strong, he was afraid: and when he began to sink, he cried out, saying: Lord, save me.", "bbe": "But when he saw the wind he was in fear and, starting to go down, he gave a cry, saying, Help, Lord.", "geneva": "But when he sawe a mightie winde, he was afraide: and as he began to sinke, he cried, saying, Master, saue me.", "wycliffe": "But he siy the wynd strong, and was aferde; and whanne he bigan to drenche, he criede, and seide, Lord, make me saaf.", "rotherham": "But, seeing the wind, he was affrighted, and, beginning to sink, cried out, saying—Lord! save me!", "weymouth": "But when he felt the wind he grew frightened, and beginning to sink he cried out, \"Master, save me.\"", "darby": "But seeing the wind strong he was afraid; and beginning to sink he cried out, saying, Lord, save me.", "twenty": "but, when he felt the wind, he was frightened, and, beginning to sink, cried out: “Master! Save me!”", "acv": "But seeing the boisterous wind, he was afraid, and having begun to sink, he cried out, saying, Lord, save me.", "anderson": "But when he saw the wind strong, he was afraid; and beginning to sink, he cried out, saying: Lord, save me.", "haweis": "But seeing the wind boisterous, he was afraid; and beginning to sink in the deep, he cried out, saying, Lord save me.", "noyes": "But seeing the wind, he was afraid; and beginning to sink, he cried out, saying, Lord, save me!", "webster": "But when he saw the wind boisterous, he was afraid; and beginning to sink, he cried, saying, Lord, save me.", "vulgate": "videns vero ventum validum timuit et cum coepisset mergi clamavit dicens Domine salvum me fac;"}}, {"v": 31, "ref": "14:31", "o": "εὐθέως δὲ ὁ Ἰησοῦς ἐκτείνας τὴν χεῖρα ἐπελάβετο αὐτοῦ καὶ λέγει αὐτῷ· Ὀλιγόπιστε, εἰς τί ἐδίστασας;", "en": {"kjv": "And immediately Jesus stretched forth his hand, and caught him, and said unto him, O thou of little faith, wherefore didst thou doubt?", "web": "Immediately Jesus stretched out his hand, took hold of him, and said to him, “You of little faith, why did you doubt?”", "bsb": "Immediately Jesus reached out His hand and took hold of Peter. “You of little faith,” He said, “why did you doubt?”", "asv": "And immediately Jesus stretched forth his hand, and took hold of him, and saith unto him, O thou of little faith, wherefore didst thou doubt?", "ylt": "And immediately Jesus, having stretched forth the hand, laid hold of him, and saith to him, `Little faith! for what didst thou waver?'", "tyndale": "And immediatly Iesus stretched forth his hode and caught him and sayde to him: O thou of lytell faith wherfore diddest thou dout?", "dra": "And immediately Jesus stretching forth his hand took hold of him, and said to him: O thou of little faith, why didst thou doubt?", "bbe": "And straight away Jesus put out his hand and took a grip of him, and said to him, O man of little faith, why were you in doubt?", "geneva": "So immediatly Iesus stretched foorth his hande, and caught him, and saide to him, O thou of litle faith, wherefore diddest thou doubt?", "wycliffe": "And anoon Jhesus helde forth his hoond, and took Petre, and seide to hym, Thou of litil feith, whi hast thou doutid?", "rotherham": "And, straightway, Jesus, stretching forth his hand, laid hold upon him and saith unto him—O little-of-faith! why didst thou doubt?", "weymouth": "Instantly Jesus stretched out His hand and caught hold of him, saying to him, \"O little faith, why did you doubt?\"", "darby": "And immediately Jesus stretched out his hand and caught hold of him, and says to him, O thou of little faith, why didst thou doubt?", "twenty": "Instantly Jesus stretched out his hand, and caught hold of him. “O man of little faith!” he said, “Why did you falter?”", "acv": "And straightaway having stretched forth his hand, Jesus took hold of him, and says to him, O thou of little faith, why did thou doubt?", "anderson": "And Jesus immediately stretched out his hand, and took hold of him, and said to him: O you of little faith, why did you doubt?", "haweis": "Then immediately Jesus stretching out his hand, laid hold on him, and said to him, O thou of little faith, wherefore dost thou doubt?", "noyes": "And Jesus immediately stretched out his hand, and took hold of him, and said to him, Thou of little faith, why didst thou doubt?", "webster": "And immediately Jesus stretched forth [his] hand, and caught him, and said to him, O thou of little faith, Why didst thou doubt?", "vulgate": "et continuo Iesus extendens manum adprehendit eum et ait illi modicae fidei quare dubitasti;"}}, {"v": 32, "ref": "14:32", "o": "καὶ ⸀ἀναβάντων αὐτῶν εἰς τὸ πλοῖον ἐκόπασεν ὁ ἄνεμος.", "en": {"kjv": "And when they were come into the ship, the wind ceased.", "web": "When they got up into the boat, the wind ceased.", "bsb": "And when they had climbed back into the boat, the wind died down.", "asv": "And when they were gone up into the boat, the wind ceased.", "ylt": "and they having gone to the boat the wind lulled,", "tyndale": "And assone as they were come in to ye shippe ye wynde ceassed.", "dra": "And when they were come up into the boat, the wind ceased.", "bbe": "And when they had got into the boat, the wind went down.", "geneva": "And assoone as they were come into the ship, the winde ceased.", "wycliffe": "And whanne he hadde stied in to the boot, the wynd ceessid.", "rotherham": "And, when they came up into the boat, the wind abated.", "weymouth": "So they climbed into the boat, and the wind lulled;", "darby": "And when they had gone up into the ship, the wind fell.", "twenty": "When they had got into the boat, the wind dropped.", "acv": "And when they entered into the boat, the wind ceased.", "anderson": "And when they had entered the ship, the wind ceased.", "haweis": "And when they came aboard the vessel, the wind ceased.", "noyes": "And when they had got into the boat, the wind ceased.", "webster": "And when they had come into the boat, the wind ceased.", "vulgate": "et cum ascendissent in naviculam cessavit ventus;"}}, {"v": 33, "ref": "14:33", "o": "οἱ δὲ ἐν τῷ ⸀πλοίῳ προσεκύνησαν αὐτῷ λέγοντες· Ἀληθῶς θεοῦ υἱὸς εἶ.", "en": {"kjv": "Then they that were in the ship came and worshipped him, saying, Of a truth thou art the Son of God.", "web": "Those who were in the boat came and worshiped him, saying, “You are truly the Son of God!”", "bsb": "Then those who were in the boat worshiped Him, saying, “Truly You are the Son of God!”", "asv": "And they that were in the boat worshipped him, saying, Of a truth thou art the Son of God.", "ylt": "and those in the boat having come, did bow to him, saying, `Truly--God's Son art thou.'", "tyndale": "Then they that were in the shippe came and worshipped him sayinge: of a truth thou arte ye sonne of God.", "dra": "And they that were in the boat came and adored him, saying: Indeed thou art the Son of God.", "bbe": "And those who were in the boat gave him worship, saying, Truly you are the Son of God.", "geneva": "Then they that were in the ship, came and worshipped him, saying, Of a trueth thou art the Sonne of God.", "wycliffe": "And thei, that weren in the boot, camen, and worschipiden hym, and seiden, Verili, thou art Goddis sone.", "rotherham": "And, they in the boat, bowed down to him, saying—Truly, God’s Son, thou art!", "weymouth": "and the men on board fell down before him and said, \"You are indeed God's Son.\"", "darby": "But those in the ship came and did homage to him, saying, Truly thou artGod's Son.", "twenty": "But the men in the boat threw themselves on their faces before him, and said: “You are indeed God’s Son.”", "acv": "And those who came in the boat worshiped him, saying, Thou really are the Son of God.", "anderson": "And they that were in the ship came and worshiped him, saying: Truly, thou art the Son of God.", "haweis": "And they who were in the vessel, came and worshipped him, saying, Truly thou art the Son of God.", "noyes": "And they that were in the boat fell down before him, saying, Truly thou art the Son of God.", "webster": "Then they that were in the boat came and worshiped him, saying, In truth thou art the son of God.", "vulgate": "qui autem in navicula erant venerunt et adoraverunt eum dicentes vere Filius Dei es;"}}, {"v": 34, "ref": "14:34", "o": "Καὶ διαπεράσαντες ἦλθον ⸂ἐπὶ τὴν γῆν εἰς⸃ Γεννησαρέτ.", "en": {"kjv": "And when they were gone over, they came into the land of Gennesaret.", "web": "When they had crossed over, they came to the land of Gennesaret.", "bsb": "When they had crossed over, they landed at Gennesaret.", "asv": "And when they had crossed over, they came to the land, unto Gennesaret.", "ylt": "And having passed over, they came to the land of Gennesaret,", "tyndale": "And when they were come over they went in to ye londe of Genazareth.", "dra": "And having passed the water, they came into the country of Genesar.", "bbe": "And when they had gone across, they came to land at Gennesaret.", "geneva": "And when they were come ouer, they came into the land of Gennezaret.", "wycliffe": "And whanne thei hadden passid ouer the see, thei camen in to the loond of Genesar.", "rotherham": "And, going across, they came up the land, into Gennesaret.", "weymouth": "When they had quite crossed over, they put ashore at Gennesaret;", "darby": "And having crossed over they came to the land of Gennesaret.", "twenty": "When they had crossed over, they landed at Gennesaret.", "acv": "And when they crossed over, they came to the land of Gennesaret.", "anderson": "And when they had passed over, they came into the land of Gennesaret.", "haweis": "And passing over, they came to the land of Gennesareth.", "noyes": "And crossing over, they came to land, to Gennesaret.", "webster": "And when they had gone over, they came into the land of Gennesaret.", "vulgate": "et cum transfretassent venerunt in terram Gennesar;"}}, {"v": 35, "ref": "14:35", "o": "καὶ ἐπιγνόντες αὐτὸν οἱ ἄνδρες τοῦ τόπου ἐκείνου ἀπέστειλαν εἰς ὅλην τὴν περίχωρον ἐκείνην, καὶ προσήνεγκαν αὐτῷ πάντας τοὺς κακῶς ἔχοντας,", "en": {"kjv": "And when the men of that place had knowledge of him, they sent out into all that country round about, and brought unto him all that were diseased;", "web": "When the people of that place recognized him, they sent into all that surrounding region, and brought to him all who were sick,", "bsb": "And when the men of that place recognized Jesus, they sent word to all the surrounding region. People brought all the sick to Him", "asv": "And when the men of that place knew him, they sent into all that region round about, and brought unto him all that were sick;", "ylt": "and having recognized him, the men of that place sent forth to all that region round about, and they brought to him all who were ill,", "tyndale": "And when ye men of yt place had knowledge of him they sent out in to all yt countre rounde about and brought vnto him all that were sicke", "dra": "And when the men of that place had knowledge of him, they sent into all that country, and brought to him all that were diseased.", "bbe": "And when the men of that place had news of him, they sent into all the country round about, and took to him all who were ill,", "geneva": "And when the men of that place knewe him, they sent out into all that countrey rounde about, and brought vnto him all that were sicke,", "wycliffe": "And whanne men of that place hadden knowe hym, thei senten in to al that cuntre; and thei brouyten to hym alle that hadden siknesse.", "rotherham": "And, recognizing him, the men of that place, sent out into all that region, and they brought unto him all who were sick;", "weymouth": "and the men of the place, recognizing Him, sent word into all the country round. So they brought all the sick to Him,", "darby": "And when the men of that place recognised him, they sent to that whole country around, and they brought to him all that were ill,", "twenty": "But the people of that place, recognising Jesus, sent out to the whole country round, and brought to him all who were ill,", "acv": "And when they recognized him, the men of that place sent into that whole region round about, and brought to him all those faring badly.", "anderson": "And when the men of that place had knowledge of him, they sent out into all the neighboring country, and brought to him all that were sick;", "haweis": "And when the men of that place knew him, they sent into all that neighbourhood, and brought to him all that had illnesses:", "noyes": "And the men of that place, when they saw who he was, sent out into all that country round, and brought to him all the diseased,", "webster": "And when the men of that place had knowledge of him, they sent out into all the surrounding country, and brought to him all that were diseased;", "vulgate": "et cum cognovissent eum viri loci illius miserunt in universam regionem illam et obtulerunt ei omnes male habentes;"}}, {"v": 36, "ref": "14:36", "o": "καὶ παρεκάλουν αὐτὸν ἵνα μόνον ἅψωνται τοῦ κρασπέδου τοῦ ἱματίου αὐτοῦ· καὶ ὅσοι ἥψαντο διεσώθησαν.", "en": {"kjv": "And besought him that they might only touch the hem of his garment: and as many as touched were made perfectly whole.", "web": "and they begged him that they might just touch the fringe of his garment. As many as touched it were made whole.", "bsb": "and begged Him just to let them touch the fringe of His cloak. And all who touched Him were healed.", "asv": "and they besought him that they might only touch the border of his garment: and as many as touched were made whole.", "ylt": "and were calling on him that they might only touch the fringe of his garment, and as many as did touch were saved.", "tyndale": "and besought him that they myght touche the hemme of his vesture only. And as many as touched it were made safe.", "dra": "And they besought him that they might touch but the hem of his garment. And as many as touched, were made whole.", "bbe": "With the request that they might only put their hands on the edge of his robe: and all those who did so were made well.", "geneva": "And besought him, that they might touch the hemme of his garment onely: and as many as touched it, were made whole.", "wycliffe": "And thei preieden hym, that thei schulden touche the hemme of his clothing; and who euere touchiden weren maad saaf.", "rotherham": "and were beseeching [him], that they might, only, touch the border of his mantle, and, as many as touched, were made quite well.", "weymouth": "and they entreated Him that they might but touch the tassel of His outer garment; and all who did so were restored to perfect health.", "darby": "and besought him that they might only touch the hem of his garment; and as many as touched were made thoroughly well.", "twenty": "begging him merely to let them touch the tassel of his cloak; and all who touched were made perfectly well.", "acv": "And they besought him that they might only touch the hem of his garment. And as many as touched were healed.", "anderson": "and besought him that they might only touch the fringe of his mantle; and as many as touched were perfectly saved.", "haweis": "and they besought him that they might only touch the fringe of his garment: and as many as touched it were cured.", "noyes": "and besought him that they might only touch the fringe of his garment; and as many as touched were made well.", "webster": "And besought him that they might only touch the hem of his garment: and as many as touched were restored to health.", "vulgate": "et rogabant eum ut vel fimbriam vestimenti eius tangerent et quicumque tetigerunt salvi facti sunt;"}}]}, {"c": 15, "verses": [{"v": 1, "ref": "15:1", "o": "Τότε προσέρχονται τῷ ⸀Ἰησοῦ ἀπὸ Ἱεροσολύμων ⸂Φαρισαῖοι καὶ γραμματεῖς⸃ λέγοντες", "en": {"kjv": "Then came to Jesus scribes and Pharisees, which were of Jerusalem, saying,", "web": "Then Pharisees and scribes came to Jesus from Jerusalem, saying,", "bsb": "Then some Pharisees and scribes came to Jesus from Jerusalem and asked,", "asv": "Then there come to Jesus from Jerusalem Pharisees and scribes, saying,", "ylt": "Then come unto Jesus do they from Jerusalem--scribes and Pharisees--saying,", "tyndale": "Then came to Iesus scribes and pharises from Ierusalem sayinge:", "dra": "Then came to him from Jerusalem scribes and Pharisees, saying:", "bbe": "Then there came to Jesus from Jerusalem Pharisees and scribes, saying,", "geneva": "Then came to Iesus the Scribes and Pharises, which were of Hierusalem, saying,", "wycliffe": "Thanne the scribis and the Farisees camen to hym fro Jerusalem, and seiden,", "rotherham": "Then, there come unto Jesus from Jerusalem Pharisees and Scribes, saying—", "weymouth": "Then there came to Jesus a party of Pharisees and Scribes from Jerusalem, who inquired,", "darby": "Then the scribes and Pharisees from Jerusalem come up to Jesus, saying,", "twenty": "Then some Pharisees and Teachers of the Law came to Jesus, and said:", "acv": "Then scholars and Pharisees from Jerusalem come to Jesus, saying,", "anderson": "Then came to Jesus scribes and Pharisees that were of Jerusalem, saying:", "haweis": "THEN came to Jesus scribes and Pharisees from Jerusalem, saying,", "noyes": "Then come to Jesus Pharisees and scribes from Jerusalem, saying,", "webster": "Then came to Jesus scribes and Pharisees, who were of Jerusalem, saying,", "vulgate": "tunc accesserunt ad eum ab Hierosolymis scribae et Pharisaei dicentes;"}}, {"v": 2, "ref": "15:2", "o": "Διὰ τί οἱ μαθηταί σου παραβαίνουσιν τὴν παράδοσιν τῶν πρεσβυτέρων; οὐ γὰρ νίπτονται τὰς χεῖρας ⸀αὐτῶν ὅταν ἄρτον ἐσθίωσιν.", "en": {"kjv": "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.", "web": "“Why do your disciples disobey the tradition of the elders? For they don’t wash their hands when they eat bread.”", "bsb": "“Why do Your disciples break the tradition of the elders? They do not wash their hands before they eat.”", "asv": "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.", "ylt": "`Wherefore do thy disciples transgress the tradition of the elders? for they do not wash their hands when they may eat bread.'", "tyndale": "why do thy disciples transgresse the tradicios of ye elders? for they wesshe not their hondes when they eate breed.", "dra": "Why do thy disciples transgress the tradition of the ancients? For they wash not their hands when they eat bread.", "bbe": "Why do your disciples go against the teaching of the fathers? for they take food with unwashed hands.", "geneva": "Why do thy disciples transgresse the tradition of the Elders? for they wash not their hands when they eate bread.", "wycliffe": "Whi breken thi disciplis the tradiciouns of eldere men? for thei waisschen not her hondis, whanne thei eten breed.", "rotherham": "Wherefore do thy disciples transgress the tradition of the elders? for they wash not their hands, when they eat bread!", "weymouth": "\"Why do your disciples transgress the tradition of the Elders by not washing their hands before meals?\"", "darby": "Why do thy disciples transgress what has been delivered by the ancients? for they do not wash their hands when they eat bread.", "twenty": "“How is it that your disciples break the traditions of our ancestors? For they do not wash their hands when they eat food.”", "acv": "Why do thy disciples transgress the tradition of the elders? For they do not wash their hands when they eat bread.", "anderson": "Why do your disciples transgress the tradition of the elders? for they do not wash their hands when they eat bread.", "haweis": "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread?", "noyes": "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.", "webster": "Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.", "vulgate": "quare discipuli tui transgrediuntur traditionem seniorum non enim lavant manus suas cum panem manducant;"}}, {"v": 3, "ref": "15:3", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν αὐτοῖς· Διὰ τί καὶ ὑμεῖς παραβαίνετε τὴν ἐντολὴν τοῦ θεοῦ διὰ τὴν παράδοσιν ὑμῶν;", "en": {"kjv": "But he answered and said unto them, Why do ye also transgress the commandment of God by your tradition?", "web": "He answered them, “Why do you also disobey the commandment of God because of your tradition?", "bsb": "Jesus replied, “And why do you break the command of God for the sake of your tradition?", "asv": "And he answered and said unto them, Why do ye also transgress the commandment of God because of your tradition?", "ylt": "And he answering said to them, `Wherefore also do ye transgress the command of God because of your tradition?", "tyndale": "He answered and sayde vnto them: why do ye also transgresse ye comaundment of God thorowe youre tradicions?", "dra": "But he answering, said to them: Why do you also transgress the commandment of God for your tradition? For God said:", "bbe": "And in answer he said to them, Why do you, yourselves, go against the word of God on account of the teaching which has been handed down to you?", "geneva": "But he answered and said vnto them, Why doe yee also transgresse the commandement of God by your tradition?", "wycliffe": "He answeride, and seide to hem, Whi breken ye the maundement of God for youre tradicioun?", "rotherham": "But, he, answering, said unto them—Wherefore do, ye also, transgress the commandment of God for the sake of your tradition?", "weymouth": "\"Why do you, too,\" He retorted, \"transgress God's commands for the sake of your tradition?", "darby": "But he answering said to them, Why do ye also transgress the commandment ofGod on account of your traditional teaching?", "twenty": "His reply was: “How is it that you on your side break God’s commandments out of respect for your own traditions?", "acv": "And having answered, he said to them, Why do ye also transgress the commandment of God, because of your tradition?", "anderson": "But he answered and said to them: And why do you transgress the commandment of God for the sake of your tradition?", "haweis": "And he answering said to them, And why do you transgress the command of God, by your tradition?", "noyes": "But he answered and said to them, Why do ye too transgress the commandment of God for the sake of your tradition?", "webster": "But he answered and said to them, Why do ye also transgress the commandment of God by your tradition?", "vulgate": "ipse autem respondens ait illis quare et vos transgredimini mandatum Dei propter traditionem vestram;"}}, {"v": 4, "ref": "15:4", "o": "ὁ γὰρ θεὸς ⸀εἶπεν· Τίμα τὸν πατέρα καὶ τὴν μητέρα, καί· Ὁ κακολογῶν πατέρα ἢ μητέρα θανάτῳ τελευτάτω·", "en": {"kjv": "For God commanded, saying, Honour thy father and mother: and, He that curseth father or mother, let him die the death.", "web": "For God commanded, ‘Honor your father and your mother,’and, ‘He who speaks evil of father or mother, let him be put to death.’", "bsb": "For God said, ‘Honor your father and mother’ and ‘Anyone who curses his father or mother must be put to death.’", "asv": "For God said, Honor thy father and thy mother: and, He that speaketh evil of father or mother, let him die the death.", "ylt": "for God did command, saying, Honour thy father and mother; and, He who is speaking evil of father or mother--let him die the death;", "tyndale": "For God comaunded sayinge: honoure thy father and mother and he that cursseth father or mother shall suffer deeth.", "dra": "Honour thy father and mother: And: He that shall curse father or mother, let him die the death.", "bbe": "For God said, Give honour to your father and mother: and, He who says evil of father or mother will be put to death.", "geneva": "For God hath commanded, saying, Honour thy father and mother: and he that curseth father or mother, let him die the death.", "wycliffe": "For God seide, Honoure thi fadir and thi modir, and he that cursith fadir or modir, die bi deeth.", "rotherham": "For, God, said—Honour thy father and thy mother, and—He that revileth father or mother, let him, surely die!", "weymouth": "For God said, `Honour thy father and thy mother'; and `Let him who reviles father or mother be certainly put to death';", "darby": "ForGod commanded saying, Honour father and mother; and, He that speaks ill of father or mother, let him die the death.", "twenty": "For God said — ‘Honour thy father and mother,’ and ‘Let him who reviles his father or mother suffer death,’", "acv": "For God commanded, saying, Honor thy father and thy mother, and, He who speaks evil of father or mother, let him perish in death.", "anderson": "For God commanded, saying, Honor your father and your mother; and, He that curses father or mother shall surely be put to death.", "haweis": "For God commanded, saying “Honour thy father and thy mother:” and, He that curseth father or mother, let him surely die.", "noyes": "For God commanded, saying, \"Honor thy father and thy mother;\" and, \"He that curseth father or mother, let him surely die.\"", "webster": "For God commanded, saying, Honor thy father and mother: and, He that curseth father or mother, let him die the death.", "vulgate": "nam Deus dixit honora patrem et matrem et qui maledixerit patri vel matri morte moriatur;"}}, {"v": 5, "ref": "15:5", "o": "ὑμεῖς δὲ λέγετε· Ὃς ἂν εἴπῃ τῷ πατρὶ ἢ τῇ μητρί· Δῶρον ὃ ἐὰν ἐξ ἐμοῦ ὠφεληθῇς,", "en": {"kjv": "But ye say, Whosoever shall say to his father or his mother, It is a gift, by whatsoever thou mightest be profited by me;", "web": "But you say, ‘Whoever may tell his father or his mother, “Whatever help you might otherwise have gotten from me is a gift devoted to God,”", "bsb": "But you say that if anyone says to his father or mother, ‘Whatever you would have received from me is a gift devoted to God,’", "asv": "But ye say, Whosoever shall say to his father or his mother, That wherewith thou mightest have been profited by me is given to God;", "ylt": "but ye say, Whoever may say to father or mother, An offering is whatever thou mayest be profited by me; --", "tyndale": "But ye saye every ma shall saye to his father or mother: That which thou desyrest of me to helpe ye with: is geven God:", "dra": "But you say: Whosoever shall say to father or mother, The gift whatsoever proceedeth from me, shall profit thee.", "bbe": "But you say, If a man says to his father or his mother, That by which you might have had profit from me is given to God;", "geneva": "But ye say, Whosoeuer shall say to father or mother, By the gift that is offered by me, thou maiest haue profite,", "wycliffe": "But ye seien, Who euer seith to fadir or modir, What euere yifte is of me, it schal profite to thee;", "rotherham": "But, ye, say—Whosoever shall say to his father or his mother—A gift! Whatsoever, out of me, thou mightest be profited,", "weymouth": "but you--this is what you say: `If a man says to his father or mother, That is consecrated, whatever it is, which otherwise you should have received from me--", "darby": "But ye say, Whosoever shall say to his father or mother, It is a gift, whatsoever [it be] by which [received] from me thou wouldest be profited:", "twenty": "but you say ‘Whenever any one says to his father or mother “Whatever of mine might have been of service to you is ‘Given to God,’”", "acv": "But ye say, Whoever may say to the father or the mother, Whatever thou might have benefited from me is an offering.", "anderson": "But you say, Whoever shall say to his father or his mother, Whatever of mine might profit you, is a gift, he must in no way honor his father or his mother;", "haweis": "But ye say, If any man declare to his father or mother, This is a devoted gift, which else might have been employed by me for thy advantage;", "noyes": "But ye say, Whoever shall say to his father or his mother, Whatever thou mightst receive in aid from me is a gift [to God],", "webster": "But ye say, Whoever shall say to [his] father or [his] mother, [It is] a gift, by whatever thou mightest be profited by me;", "vulgate": "vos autem dicitis quicumque dixerit patri vel matri munus quodcumque est ex me tibi proderit;"}}, {"v": 6, "ref": "15:6", "o": "⸀οὐ μὴ ⸀τιμήσει τὸν πατέρα ⸀αὐτοῦ· καὶ ἠκυρώσατε ⸂τὸν λόγον⸃ τοῦ θεοῦ διὰ τὴν παράδοσιν ὑμῶν.", "en": {"kjv": "And honour not his father or his mother, he shall be free. Thus have ye made the commandment of God of none effect by your tradition.", "web": "he shall not honor his father or mother.’ You have made the commandment of God void because of your tradition.", "bsb": "he need not honor his father or mother with it. Thus you nullify the word of God for the sake of your tradition.", "asv": "he shall not honor his father. And ye have made void the word of God because of your tradition.", "ylt": "and he may not honour his father or his mother, and ye did set aside the command of God because of your tradition.", "tyndale": "and so shall he not honoure his father or his mother. And thus haue ye made yt the comaundment of God is with out effecte through youre tradicios.", "dra": "And he shall not honour his father or his mother: and you have made void the commandment of God for your tradition.", "bbe": "There is no need for him to give honour to his father. And you have made the word of God without effect because of your teaching.", "geneva": "Though hee honour not his father, or his mother, shalbe free: thus haue ye made the commandement of God of no aucthoritie by your tradition.", "wycliffe": "and he hath not worschipid his fadir or his modir; and ye han maad the maundement of God voide for youre tradicioun.", "rotherham": "in nowise, shall honour his father or his mother—and so ye have cancelled, the word of God, for the sake of your, tradition.", "weymouth": "he shall be absolved from honouring his father'; and so you have abrogated God's Word for the sake of your tradition.", "darby": "and he shall in no wise honour his father or his mother; and ye have made void the commandment ofGod on account of your traditional teaching.", "twenty": "he is in no way bound to honour his father.’ In this way you have nullified the words of God on account of your traditions.", "acv": "And he will, no, not honor his father or mother. And ye have annulled the command of God because of your tradition.", "anderson": "and you make the commandment of God of no effect for the sake of your tradition.", "haweis": "then he shall not with it honour his father and mother: so have ye vacated the command of God by your tradition.", "noyes": "he shall not honor his father or his mother. Thus have ye made void the law of God for the sake of your tradition.", "webster": "And honor not his father or his mother, [he shall be free]. Thus have ye made the commandment of God of no effect by your tradition.", "vulgate": "et non honorificabit patrem suum aut matrem et irritum fecistis mandatum Dei propter traditionem vestram;"}}, {"v": 7, "ref": "15:7", "o": "ὑποκριταί, καλῶς ἐπροφήτευσεν περὶ ὑμῶν Ἠσαΐας λέγων·", "en": {"kjv": "Ye hypocrites, well did Esaias prophesy of you, saying,", "web": "You hypocrites! Well did Isaiah prophesy of you, saying,", "bsb": "You hypocrites! Isaiah prophesied correctly about you:", "asv": "Ye hypocrites, well did Isaiah prophesy of you, saying,", "ylt": "`Hypocrites, well did Isaiah prophesy of you, saying,", "tyndale": "Ypocrites well prophesyed of you Esay sayinge:", "dra": "Hypocrites, well hath Isaias prophesied of you, saying:", "bbe": "You false ones, well did Isaiah say of you,", "geneva": "O hypocrites, Esaias prophecied well of you, saying,", "wycliffe": "Ypocritis, Isaie, the prophete, prophesiede wel of you,", "rotherham": "Hypocrites! well prophesied concerning you, Isaiah, saying—", "weymouth": "Hypocrites! well did Isaiah prophesy of you,", "darby": "Hypocrites! well has Esaias prophesied about you, saying,", "twenty": "Hypocrites! It was well said by Isaiah when he prophesied about you —", "acv": "Ye hypocrites, well did Isaiah prophesy about you, saying,", "anderson": "Hypocrites! well did Isaiah prophesy of you, saying,", "haweis": "Ye hypocrites, well hath Isaiah prophesied concerning you, saying,", "noyes": "Hypocrites! well did Isaiah prophesy concerning you, saying,", "webster": "[Ye] hypocrites, well did Isaiah prophesy of you, saying,", "vulgate": "hypocritae bene prophetavit de vobis Esaias dicens;"}}, {"v": 8, "ref": "15:8", "o": "⸂Ὁ λαὸς οὗτος⸃ τοῖς χείλεσίν με τιμᾷ, ἡ δὲ καρδία αὐτῶν πόρρω ἀπέχει ἀπ’ ἐμοῦ·", "en": {"kjv": "This people draweth nigh unto me with their mouth, and honoureth me with their lips; but their heart is far from me.", "web": "‘These people draw near to me with their mouth, and honor me with their lips; but their heart is far from me.", "bsb": "‘These people honor Me with their lips, but their hearts are far from Me.", "asv": "This people honoreth me with their lips; But their heart is far from me.", "ylt": "This people doth draw nigh to Me with their mouth, and with the lips it doth honour Me, but their heart is far off from Me;", "tyndale": "This people draweth nye vnto me with their mouthes and honoureth me with their lippes howbe it their hertes are farre from me:", "dra": "This people honoureth me with their lips: but their heart is far from me.", "bbe": "These people give me honour with their lips, but their heart is far from me.", "geneva": "This people draweth neere vnto me with their mouth, and honoureth me with the lips, but their heart is farre off from me.", "wycliffe": "and seide, This puple honourith me with lippis, but her herte is fer fro me;", "rotherham": "This people, with the lips, do, honour, me, while, their heart, far off, holdeth from me;", "weymouth": "\"`This is a People who honour Me with their lips, while their heart is far away from Me;", "darby": "This people honour me with the lips, but their heart is far away from me;", "twenty": "‘This is a people that honour me with their lips, While their hearts are far removed from me;", "acv": "This people comes near me with their mouth, and honors me with their lips, but their heart is far distant from me.", "anderson": "This people draws near to me with their mouth, and honors me with their lips; but their heart is far from me.", "haweis": "This people draweth nigh to me with their mouths, and honoureth me with the lips, but their heart is far distant from me.", "noyes": "\"This people honoreth me with their lips, but their heart is far from me.", "webster": "This people draw nigh to me with their mouth, and honor me with [their] lips; but their heart is far from me.", "vulgate": "populus hic labiis me honorat cor autem eorum longe est a me;"}}, {"v": 9, "ref": "15:9", "o": "μάτην δὲ σέβονταί με, διδάσκοντες διδασκαλίας ἐντάλματα ἀνθρώπων.", "en": {"kjv": "But in vain they do worship me, teaching for doctrines the commandments of men.", "web": "And in vain do they worship me, teaching as doctrine rules made by men.’”", "bsb": "They worship Me in vain; they teach as doctrine the precepts of men.’”", "asv": "But in vain do they worship me, Teachingas theirdoctrines the precepts of men.", "ylt": "and in vain do they worship Me, teaching teachings--commands of men.'", "tyndale": "but in vayne they worshippe me teachinge doctrines whiche are nothing but mens precepts.", "dra": "And in vain do they worship me, teaching doctrines and commandments of men.", "bbe": "But their worship is to no purpose, while they give as their teaching the rules of men.", "geneva": "But in vaine they worship me, teaching for doctrines, mens precepts.", "wycliffe": "and thei worschipen me `with outen cause, techynge the doctrines and maundementis of men.", "rotherham": "But, in vain, do they pay devotions unto me, teaching, for teachings, the commandments of men.", "weymouth": "but it is in vain they worship Me, while they lay down precepts which are mere human rules.'\"", "darby": "but in vain do they worship me, teaching [as] teachings commandments of men.", "twenty": "but vainly do they worship me, For they teach but the precepts of men.’”", "acv": "And in vain they worship me, teaching as doctrines the commandments of men.", "anderson": "But in vain, do they worship me, teaching precepts, the commandments of men.", "haweis": "But in vain do they worship me, teaching doctrines the commandments of men.", "noyes": "But in vain do they worship me, teaching as doctrines the commandments of men.\"", "webster": "But in vain they do worship me, teaching [for] doctrines the commandments of men.", "vulgate": "sine causa autem colunt me docentes doctrinas mandata hominum;"}}, {"v": 10, "ref": "15:10", "o": "Καὶ προσκαλεσάμενος τὸν ὄχλον εἶπεν αὐτοῖς· Ἀκούετε καὶ συνίετε·", "en": {"kjv": "And he called the multitude, and said unto them, Hear, and understand:", "web": "He summoned the multitude, and said to them, “Hear, and understand.", "bsb": "Jesus called the crowd to Him and said, “Listen and understand.", "asv": "And he called to him the multitude, and said unto them, Hear, and understand:", "ylt": "And having called near the multitude, he said to them, `Hear and understand:", "tyndale": "And he called the people vnto him and sayde to them: heare and vnderstande.", "dra": "And having called together the multitudes unto him, he said to them: Hear ye and understand.", "bbe": "And he got the people together and said to them, Give ear, and let my words be clear to you:", "geneva": "Then hee called the multitude vnto him, and said to them, Heare and vnderstand.", "wycliffe": "And whanne the puple weren clepid to gidere to hym, he seide to hem, Here ye, and `vndurstonde ye.", "rotherham": "And, calling near the multitude, he said to them—Hear and understand!", "weymouth": "Then, when He had called the people to Him, Jesus said, \"Hear and understand.", "darby": "And having called to [him] the crowd, he said to them, Hear and understand:", "twenty": "Then Jesus called the people to him, and said: “Listen, and mark my words.", "acv": "And having called in the multitude, he said to them, Hear and understand.", "anderson": "And he called the multitude to him, and said to them: Hear and understand;", "haweis": "And he called to him the multitude, and said unto them, Hear, and understand:", "noyes": "And calling the multitude, he said to them, Hear, and understand.", "webster": "And he called the multitude, and said to them, Hear, and understand:", "vulgate": "et convocatis ad se turbis dixit eis audite et intellegite;"}}, {"v": 11, "ref": "15:11", "o": "οὐ τὸ εἰσερχόμενον εἰς τὸ στόμα κοινοῖ τὸν ἄνθρωπον, ἀλλὰ τὸ ἐκπορευόμενον ἐκ τοῦ στόματος τοῦτο κοινοῖ τὸν ἄνθρωπον.", "en": {"kjv": "Not that which goeth into the mouth defileth a man; but that which cometh out of the mouth, this defileth a man.", "web": "That which enters into the mouth doesn’t defile the man; but that which proceeds out of the mouth, this defiles the man.”", "bsb": "A man is not defiled by what enters his mouth, but by what comes out of it.”", "asv": "Not that which entereth into the mouth defileth the man; but that which proceedeth out of the mouth, this defileth the man.", "ylt": "not that which is coming into the mouth doth defile the man, but that which is coming forth from the mouth, this defileth the man.'", "tyndale": "That which goeth into the mouth defyleth not ye man: but that which commeth out of the mouth defyleth the man.", "dra": "Not that which goeth into the mouth defileth a man: but what cometh out of the mouth, this defileth a man.", "bbe": "Not that which goes into the mouth makes a man unclean, but that which comes out of the mouth.", "geneva": "That which goeth into the mouth, defileth not the man, but that which commeth out of the mouth, that defileth the man.", "wycliffe": "That thing that entrith in to the mouth, defoulith not a man; but that thing that cometh out of the mouth, defoulith a man.", "rotherham": "Not that which entereth into the mouth, defileth the man, but, that which proceedeth out of the mouth, the same, defileth the man,", "weymouth": "It is not what goes into a man's mouth that defiles him; but it is what comes out of his mouth-- *that* defiles a man.\"", "darby": "Not what enters into the mouth defiles the man; but what goes forth out of the mouth, this defiles the man.", "twenty": "It is not what enters a man’s mouth that ‘defiles’ him, but what comes out from his mouth — that does defile him!”", "acv": "Not that which enters into the mouth defiles the man, but that which comes out of the mouth, this defiles the man.", "anderson": "That which enters the mouth does not defile the man; but that which comes out of the mouth, this defiles the man.", "haweis": "not that which goeth into the mouth defileth a man; but what cometh out of the mouth, that defileth the man.", "noyes": "Not that which goeth into the mouth defileth a man; but that which cometh out of the mouth, this defileth a man.", "webster": "Not that which goeth into the mouth defileth a man; but that which cometh out of the mouth, this defileth a man.", "vulgate": "non quod intrat in os coinquinat hominem sed quod procedit ex ore hoc coinquinat hominem;"}}, {"v": 12, "ref": "15:12", "o": "Τότε προσελθόντες οἱ ⸀μαθηταὶ ⸀λέγουσιν αὐτῷ· Οἶδας ὅτι οἱ Φαρισαῖοι ἀκούσαντες τὸν λόγον ἐσκανδαλίσθησαν;", "en": {"kjv": "Then came his disciples, and said unto him, Knowest thou that the Pharisees were offended, after they heard this saying?", "web": "Then the disciples came, and said to him, “Do you know that the Pharisees were offended, when they heard this saying?”", "bsb": "Then the disciples came to Him and said, “Are You aware that the Pharisees were offended when they heard this?”", "asv": "Then came the disciples, and said unto him, Knowest thou that the Pharisees were offended, when they heard this saying?", "ylt": "Then his disciples having come near, said to him, `Hast thou known that the Pharisees, having heard the word, were stumbled?'", "tyndale": "Then came his disciples and sayde vnto him. Perceavest thou not how that the pharises are offended in hearinge thys sayinge?", "dra": "Then came his disciples, and said to him: Dost thou know that the Pharisees, when they heard this word, were scandalized?", "bbe": "Then the disciples came and said to him, Did you see that the Pharisees were troubled when these words came to their ears?", "geneva": "Then came his disciples, and saide vnto him, Perceiuest thou not, that the Pharises are offended in hearing this saying?", "wycliffe": "Thanne hise disciplis camen, and seiden to hym, Thou knowist, that, if this word be herd, the Farisees ben sclaundrid?", "rotherham": "Then, coming near, his disciples say unto him—Knowest thou, that the Pharisees, hearing the word, were caused to stumble?", "weymouth": "Then His disciples came and said to Him, \"Do you know that the Pharisees were greatly shocked when they heard those words?\"", "darby": "Then his disciples, coming up, said to him, Dost thou know that the Pharisees, having heard this word, have been offended?", "twenty": "On this his disciples came up to him, and said: “Do you know that the Pharisees were shocked on hearing what you said?”", "acv": "Then having come near, his disciples said to him, Know thou that the Pharisees were offended when they heard the saying?", "anderson": "Then came his disciples and said to him: Dost thou know that the Pharisees, when they heard that saying, were offended?", "haweis": "Then his disciples approaching, said to him, Knowest thou how offended the Pharisees were at hearing that speech?", "noyes": "Then come the disciples, and say to him, Dost thou know that the Pharisees were offended, when they heard that saying?", "webster": "Then came his disciples, and said to him, Knowest thou that the Pharisees were offended after they heard this saying?", "vulgate": "tunc accedentes discipuli eius dixerunt ei scis quia Pharisaei audito verbo scandalizati sunt;"}}, {"v": 13, "ref": "15:13", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Πᾶσα φυτεία ἣν οὐκ ἐφύτευσεν ὁ πατήρ μου ὁ οὐράνιος ἐκριζωθήσεται.", "en": {"kjv": "But he answered and said, Every plant, which my heavenly Father hath not planted, shall be rooted up.", "web": "But he answered, “Every plant which my heavenly Father didn’t plant will be uprooted.", "bsb": "But Jesus replied, “Every plant that My heavenly Father has not planted will be pulled up by its roots.", "asv": "But he answered and said, Every plant which my heavenly Father planted not, shall be rooted up.", "ylt": "And he answering said, `Every plant that my heavenly Father did not plant shall be rooted up;", "tyndale": "He answered and sayde: all plantes which my hevely father hath not planted shalbe plucked vp by the rotes.", "dra": "But he answering, said: Every plant which my heavenly Father hath not planted, shall be rooted up.", "bbe": "But he said in answer, Every plant which my Father in heaven has not put in the earth, will be taken up by the roots.", "geneva": "But hee answered and saide, Euery plant which mine heauenly Father hath not planted, shalbe rooted vp.", "wycliffe": "And he answeride, and seide, Eueri plauntyng, that my fadir of heuene hath not plauntid, shal be drawun vp by the roote.", "rotherham": "And, he, answering, said—Every plant which my heavenly Father hath not planted, will be uprooted:", "weymouth": "\"Every plant,\" He replied, \"which my Heavenly Father has not planted will be rooted up.", "darby": "But he answering said, Every plant which my heavenly Father has not planted shall be rooted up.", "twenty": "“Every plant,” Jesus replied, “that my heavenly Father has not planted will be rooted up.", "acv": "But having answered, he said, Every plant that my heavenly Father did not plant, will be uprooted.", "anderson": "But he answered and said: Every plant that my heavenly Father has not planted, shall be rooted up.", "haweis": "Then he answered and said, Every plant which my heavenly Father hath not planted shall be rooted up.", "noyes": "But he answered and said, Every plant which my heavenly Father did not plant will be rooted up.", "webster": "But he answered and said, Every plant, which my heavenly Father hath not planted, shall be extirpated.", "vulgate": "at ille respondens ait omnis plantatio quam non plantavit Pater meus caelestis eradicabitur;"}}, {"v": 14, "ref": "15:14", "o": "ἄφετε αὐτούς· ⸂τυφλοί εἰσιν ὁδηγοὶ τυφλῶν⸃· τυφλὸς δὲ τυφλὸν ἐὰν ὁδηγῇ, ἀμφότεροι εἰς βόθυνον πεσοῦνται.", "en": {"kjv": "Let them alone: they be blind leaders of the blind. And if the blind lead the blind, both shall fall into the ditch.", "web": "Leave them alone. They are blind guides of the blind. If the blind guide the blind, both will fall into a pit.”", "bsb": "Disregard them! They are blind guides. If a blind man leads a blind man, both will fall into a pit.”", "asv": "Let them alone: they are blind guides. And if the blind guide the blind, both shall fall into a pit.", "ylt": "let them alone, guides they are--blind of blind; and if blind may guide blind, both into a ditch shall fall.'", "tyndale": "Let them alone they be the blynde leaders of the blynde. If the blynde leede the blynde boothe shall fall into the dyche.", "dra": "Let them alone: they are blind, and leaders of the blind. And if the blind lead the blind, both fall into the pit.", "bbe": "Let them be: they are blind guides. And if a blind man is guiding a blind man, the two will go falling into a hole together.", "geneva": "Let them alone, they be the blinde leaders of the blinde: and if the blinde leade ye blinde, both shall fall into the ditche.", "wycliffe": "Suffre ye hem; thei ben blynde, and leederis of blynde men. And if a blynd man lede a blynd man, bothe fallen doun in to the diche.", "rotherham": "Let them alone! they are, blind leaders; and, if the, blind, lead the, blind, both, into a ditch, will fall.", "weymouth": "Leave them alone. They are blind guides of the blind; and if a blind man leads a blind man, both will fall into some pit.\"", "darby": "Leave them alone; they are blind leaders of blind: but if blind lead blind, both will fall into a ditch.", "twenty": "Let them be; they are but blind guides; and, if one blind man guides another, both of them will fall into a ditch.”", "acv": "Leave them. They are blind leaders of blind men, and if a blind man leads a blind man, both will fall into a ditch.", "anderson": "Let them alone; they are blind leaders of the blind; and if the blind lead the blind, both will fall into the pit.", "haweis": "Leave them to themselves: they are blind leaders of the blind. But if the blind lead the blind, they will both fall into the pit.", "noyes": "Let them alone; they are blind leaders of the blind. And if the blind lead the blind, both will fall into a ditch.", "webster": "Let them alone: they are blind leaders of the blind. And if the blind leadeth the blind, both will fall into the ditch.", "vulgate": "sinite illos caeci sunt duces caecorum caecus autem si caeco ducatum praestet ambo in foveam cadunt;"}}, {"v": 15, "ref": "15:15", "o": "Ἀποκριθεὶς δὲ ὁ Πέτρος εἶπεν αὐτῷ· Φράσον ἡμῖν τὴν παραβολὴν ⸀ταύτην.", "en": {"kjv": "Then answered Peter and said unto him, Declare unto us this parable.", "web": "Peter answered him, “Explain the parable to us.”", "bsb": "Peter said to Him, “Explain this parable to us.”", "asv": "And Peter answered and said unto him, Declare unto us the parable.", "ylt": "And Peter answering said to him, `Explain to us this simile.'", "tyndale": "Then answered Peter and sayd to him: declare vnto vs this parable.", "dra": "And Peter answering, said to him: Expound to us this parable.", "bbe": "Then Peter said to him, Make the story clear to us.", "geneva": "Then answered Peter, and said to him, Declare vnto vs this parable.", "wycliffe": "Petre answeride, and seide to hym, Expowne to vs this parable.", "rotherham": "And Peter, answering, said unto him, Declare to us the parable.", "weymouth": "\"Explain to us this figurative language,\" said Peter.", "darby": "And Peter answering said to him, Expound to us this parable.", "twenty": "Upon this, Peter said to Jesus: “Explain this saying to us.”", "acv": "And having answered, Peter said to him, Explain this parable to us.", "anderson": "But Peter answered and said to him: Explain to us this dark saying.", "haweis": "Then Peter answering said unto him, Explain to us this parable.", "noyes": "And Peter answering said to him, Explain to us that dark saying.", "webster": "Then answered Peter and said to him, Declare to us this parable.", "vulgate": "respondens autem Petrus dixit ei edissere nobis parabolam istam;"}}, {"v": 16, "ref": "15:16", "o": "ὁ ⸀δὲ εἶπεν· Ἀκμὴν καὶ ὑμεῖς ἀσύνετοί ἐστε;", "en": {"kjv": "And Jesus said, Are ye also yet without understanding?", "web": "So Jesus said, “Do you also still not understand?", "bsb": "“Do you still not understand?” Jesus asked.", "asv": "And he said, Are ye also even yet without understanding?", "ylt": "And Jesus said, `Are ye also yet without understanding?", "tyndale": "Then sayde Iesus: are ye yet with oute vnderstondinge?", "dra": "But he said: Are you also yet without understanding?", "bbe": "And he said, Are you, like them, still without wisdom?", "geneva": "Then said Iesus, Are ye yet without vnderstanding?", "wycliffe": "And he seide, Yit `ye ben also with oute vndurstondyng?", "rotherham": "And, he, said, To this moment, are, ye also, without discernment?", "weymouth": "\"Are even you,\" He answered, \"still without intellingence?", "darby": "But he said, Are ye also still without intelligence?", "twenty": "“What, do even you understand nothing yet?” Jesus exclaimed.", "acv": "And Jesus said, Are ye also still without understanding?", "anderson": "Jesus replied: Are you also yet without understanding?", "haweis": "And Jesus said, Are ye also to this time destitute of intelligence?", "noyes": "And he said, Are ye too still without discernment?", "webster": "And Jesus said, Are ye also yet without understanding?", "vulgate": "at ille dixit adhuc et vos sine intellectu estis;"}}, {"v": 17, "ref": "15:17", "o": "⸀οὐ νοεῖτε ὅτι πᾶν τὸ εἰσπορευόμενον εἰς τὸ στόμα εἰς τὴν κοιλίαν χωρεῖ καὶ εἰς ἀφεδρῶνα ἐκβάλλεται;", "en": {"kjv": "Do not ye yet understand, that whatsoever entereth in at the mouth goeth into the belly, and is cast out into the draught?", "web": "Don’t you understand that whatever goes into the mouth passes into the belly, and then out of the body?", "bsb": "“Do you not yet realize that whatever enters the mouth goes into the stomach and then is eliminated?", "asv": "Perceive ye not, that whatsoever goeth into the mouth passeth into the belly, and is cast out into the draught?", "ylt": "do ye not understand that all that is going into the mouth doth pass into the belly, and into the drain is cast forth?", "tyndale": "perceave ye not that what soever goeth in at the mouth descendeth doune in to the bely and is cast out into the draught?", "dra": "Do you not understand, that whatsoever entereth into the mouth, goeth into the belly, and is cast out into the privy?", "bbe": "Do you not see that whatever goes into the mouth goes on into the stomach, and is sent out as waste?", "geneva": "Perceiue ye not yet, that whatsoeuer entreth into the mouth, goeth into the bellie, and is cast out into the draught?", "wycliffe": "Vndurstonden ye not, that al thing that entrith in to the mouth, goith in to the wombe, and is sent out in to the goyng awei?", "rotherham": "Perceive ye not that, every thing which entereth into the mouth, into the stomach, findeth way, and, into the draught, is passed;", "weymouth": "Do you not understand that whatever enters the mouth passes into the stomach and is afterwards ejected from the body?", "darby": "Do ye not yet apprehend, that everything that enters into the mouth finds its way into the belly, and is cast forth into the draught?", "twenty": "“Do not you see that whatever goes into the mouth passes into the stomach, and is afterwards expelled?", "acv": "Do ye not yet understand, that everything entering into the mouth goes into the belly, and is cast out into a toilet?", "anderson": "Do you not yet understand that whatever enters the mouth passes into the belly, and is cast out into the sink?", "haweis": "Do ye not observe, that every thing which entereth into the mouth passeth into the belly, and is ejected into the vault?", "noyes": "Do ye not understand, that whatever entereth the mouth goeth into the stomach, and is cast out into the drain?", "webster": "Do ye not yet understand, that whatever entereth in at the mouth goeth into the belly, and is cast out into the draught?", "vulgate": "non intellegitis quia omne quod in os intrat in ventrem vadit et in secessum emittitur;"}}, {"v": 18, "ref": "15:18", "o": "τὰ δὲ ἐκπορευόμενα ἐκ τοῦ στόματος ἐκ τῆς καρδίας ἐξέρχεται, κἀκεῖνα κοινοῖ τὸν ἄνθρωπον.", "en": {"kjv": "But those things which proceed out of the mouth come forth from the heart; and they defile the man.", "web": "But the things which proceed out of the mouth come out of the heart, and they defile the man.", "bsb": "But the things that come out of the mouth come from the heart, and these things defile a man.", "asv": "But the things which proceed out of the mouth come forth out of the heart; and they defile the man.", "ylt": "but the things coming forth from the mouth from the heart do come forth, and these defile the man;", "tyndale": "But those thingis which procede out of the mouth come from the herte and they defyle the man.", "dra": "But the things which proceed out of the mouth, come forth from the heart, and those things defile a man.", "bbe": "But the things which come out of the mouth come from the heart; and they make a man unclean.", "geneva": "But those thinges which proceede out of the mouth, come from the heart, and they defile the man.", "wycliffe": "But tho thingis that comen forth fro the mouth, goon out of the herte, and tho thingis defoulen a man.", "rotherham": "while, the things which proceed out of the mouth, out of the heart, come forth, and, they, defile the man.", "weymouth": "But the things that come out of the mouth proceed from the heart, and it is these that defile the man.", "darby": "but the things which go forth out of the mouth come out of the heart, and those defile man.", "twenty": "But the things that come out from the mouth proceed from the heart, and it is these that defile a man;", "acv": "But the things coming out of the mouth come forth from the heart, and those things defile the man.", "anderson": "But those things which go out from the mouth, come from the heart; and these defile the man.", "haweis": "But the things which go forth out of the mouth, come out of the heart, and they are the things which defile a man:", "noyes": "But the things which proceed from the mouth come out of the heart; and these defile a man.", "webster": "But those things which proceed out of the mouth come forth from the heart; and they defile the man.", "vulgate": "quae autem procedunt de ore de corde exeunt et ea coinquinant hominem;"}}, {"v": 19, "ref": "15:19", "o": "ἐκ γὰρ τῆς καρδίας ἐξέρχονται διαλογισμοὶ πονηροί, φόνοι, μοιχεῖαι, πορνεῖαι, κλοπαί, ψευδομαρτυρίαι, βλασφημίαι.", "en": {"kjv": "For out of the heart proceed evil thoughts, murders, adulteries, fornications, thefts, false witness, blasphemies:", "web": "For out of the heart come evil thoughts, murders, adulteries, sexual sins, thefts, false testimony, and blasphemies.", "bsb": "For out of the heart come evil thoughts, murder, adultery, sexual immorality, theft, false testimony, and slander.", "asv": "For out of the heart come forth evil thoughts, murders, adulteries, fornications, thefts, false witness, railings:", "ylt": "for out of the heart come forth evil thoughts, murders, adulteries, whoredoms, thefts, false witnessings, evil speakings:", "tyndale": "For out of the herte come evyll thoughtis murder breakyng of wedlocke whordo theefte falce witnes berynge blasphemye.", "dra": "For from the heart come forth evil thoughts, murders, adulteries, fornications, thefts, false testimonies, blasphemies.", "bbe": "For out of the heart come evil thoughts, the taking of life, broken faith between the married, unclean desires of the flesh, taking of property, false witness, bitter words:", "geneva": "For out of the heart come euil thoughts, murders, adulteries, fornications, thefts, false testimonies, slaunders.", "wycliffe": "For of the herte goon out yuele thouytis, mansleyngis, auowtries, fornycaciouns, theftis, fals witnessyngis, blasfemyes.", "rotherham": "For, out of the heart, come forth wicked designs,—murders, adulteries, fornications, thefts, false testimonies, profane speakings:", "weymouth": "For out of the heart proceed wicked thoughts, murder, adultery, fornication, theft, perjury, impiety of speech.", "darby": "For out of the heart come forth evil thoughts, murders, adulteries, fornications, thefts, false witnessings, blasphemies;", "twenty": "for out of the heart proceed evil thoughts — murder, adultery, unchastity, theft, perjury, slander.", "acv": "For from the heart comes forth evil thoughts, murders, adulteries, fornications, thefts, false witnessings, revilings.", "anderson": "For from the heart come evil reasonings, murders, adulteries, lewd actions, thefts, false testimonies, impious words.", "haweis": "for out of the heart proceed wicked reasonings, murders, adulteries, whoredoms, thefts, false testimonies, blasphemies:", "noyes": "For out of the heart proceed evil thoughts, murders, adulteries, fornications, thefts, false testimony, blasphemies.", "webster": "For out of the heart proceed evil thoughts, murders, adulteries, fornications, thefts, false witness, blasphemies:", "vulgate": "de corde enim exeunt cogitationes malae homicidia adulteria fornicationes furta falsa testimonia blasphemiae;"}}, {"v": 20, "ref": "15:20", "o": "ταῦτά ἐστιν τὰ κοινοῦντα τὸν ἄνθρωπον, τὸ δὲ ἀνίπτοις χερσὶν φαγεῖν οὐ κοινοῖ τὸν ἄνθρωπον.", "en": {"kjv": "These are the things which defile a man: but to eat with unwashen hands defileth not a man.", "web": "These are the things which defile the man; but to eat with unwashed hands doesn’t defile the man.”", "bsb": "These are what defile a man, but eating with unwashed hands does not defile him.”", "asv": "these are the things which defile the man; but to eat with unwashen hands defileth not the man.", "ylt": "these are the things defiling the man; but to eat with unwashen hands doth not defile the man.'", "tyndale": "These are the thingis which defyle a man. But to eate with vnwesshen hondes defyleth not a man.", "dra": "These are the things that defile a man. But to eat with unwashed hands doth not defile a man.", "bbe": "These are the things which make a man unclean; but to take food with unwashed hands does not make a man unclean.", "geneva": "These are the things, which defile the man: but to eat with vnwashen hands, defileth not ye man.", "wycliffe": "Thes thingis it ben that defoulen a man; but to ete with hondis not waischun, defoulith not a man.", "rotherham": "these, are the things which defile the man, but, the eating with unwashed hands, doth not defile the man.", "weymouth": "These are the things which defile the man; but eating with unwashed hands does not defile.\"", "darby": "these are the things which defile man; but the eating with unwashen hands does not defile man.", "twenty": "These are the things that defile a man; but eating with unwashed hands does not defile a man.”", "acv": "These are things defiling the man. But to eat with unwashed hands does not defile the man.", "anderson": "These are the things that defile the man. But to eat with unwashed hands does not defile the man.", "haweis": "these are the things which defile a man: but to eat with unwashed hands doth not defile a man.", "noyes": "These are the things which defile a man; but to eat with unwashed hands defileth not a man.", "webster": "These are [the things] which defile a man: but to eat with unwashen hands defileth not a man.", "vulgate": "haec sunt quae coinquinant hominem non lotis autem manibus manducare non coinquinat hominem;"}}, {"v": 21, "ref": "15:21", "o": "Καὶ ἐξελθὼν ἐκεῖθεν ὁ Ἰησοῦς ἀνεχώρησεν εἰς τὰ μέρη Τύρου καὶ Σιδῶνος.", "en": {"kjv": "Then Jesus went thence, and departed into the coasts of Tyre and Sidon.", "web": "Jesus went out from there, and withdrew into the region of Tyre and Sidon.", "bsb": "Leaving that place, Jesus withdrew to the district of Tyre and Sidon.", "asv": "And Jesus went out thence, and withdrew into the parts of Tyre and Sidon.", "ylt": "And Jesus having come forth thence, withdrew to the parts of Tyre and Sidon,", "tyndale": "And Iesus went thence and departed in to the costis of Tyre and Sidon.", "dra": "And Jesus went from thence, and retired into the coast of Tyre and Sidon.", "bbe": "And Jesus went away from there into the country of Tyre and Sidon.", "geneva": "And Iesus went thence, and departed into the coastes of Tyrus and Sidon.", "wycliffe": "And Jhesus yede out fro thennus, and wente in to the coostis of Tire and Sidon.", "rotherham": "And, going forth from thence, Jesus retired into the parts of Tyre and Zidon.", "weymouth": "Leaving that place, Jesus withdrew into the vicinity of Tyre and Sidon.", "darby": "And Jesus, going forth from thence, went away into the parts of Tyre and Sidon;", "twenty": "On going away from that place, Jesus retired to the country round Tyre and Sidon.", "acv": "And having gone out from there, Jesus departed into the regions of Tyre and Sidon.", "anderson": "And Jesus went out thence, and withdrew into the regions of Tyre and Sidon.", "haweis": "And going forth thence, Jesus retired into the coasts of Tyre and Sidon.", "noyes": "And Jesus, going from thence, withdrew to the parts of Tyre and Sidon.", "webster": "Then Jesus went thence, and departed into the territories of Tyre and Sidon.", "vulgate": "et egressus inde Iesus secessit in partes Tyri et Sidonis;"}}, {"v": 22, "ref": "15:22", "o": "καὶ ἰδοὺ γυνὴ Χαναναία ἀπὸ τῶν ὁρίων ἐκείνων ἐξελθοῦσα ⸀ἔκραζεν λέγουσα· Ἐλέησόν με, κύριε ⸀υἱὸς Δαυίδ· ἡ θυγάτηρ μου κακῶς δαιμονίζεται.", "en": {"kjv": "And, behold, a woman of Canaan came out of the same coasts, and cried unto him, saying, Have mercy on me, O Lord, thou Son of David; my daughter is grievously vexed with a devil.", "web": "Behold, a Canaanite woman came out from those borders, and cried, saying, “Have mercy on me, Lord, you son of David! My daughter is severely possessed by a demon!”", "bsb": "And a Canaanite woman from that region came to Him, crying out, “Lord, Son of David, have mercy on me! My daughter is miserably possessed by a demon.”", "asv": "And behold, a Canaanitish woman came out from those borders, and cried, saying, Have mercy on me, O Lord, thou son of David; my daughter is grievously vexed with a demon.", "ylt": "and lo, a woman, a Canaanitess, from those borders having come forth, did call to him, saying, `Deal kindly with me, Sir--Son of David; my daughter is miserably demonized.'", "tyndale": "And beholde a woman which was a Cananite came out of ye same coostis and cryed vnto him sayinge: have mercy on me Lorde the sonne of David my doughter is pytiously vexed with a devyll.", "dra": "And behold a woman of Canaan who came out of those coasts, crying out, said to him: Have mercy on me, O Lord, thou son of David: my daughter is grievously troubled by a devil.", "bbe": "And a woman of Canaan came out from those parts, crying and saying, Have pity on me, O Lord, Son of David; my daughter is greatly troubled with an unclean spirit.", "geneva": "And beholde, a woman a Cananite came out of the same coasts, and cried, saying vnto him, Haue mercie on me, O Lord, the sonne of Dauid: my daughter is miserably vexed with a deuil.", "wycliffe": "And lo! a womman of Canane yede out of tho coostis, and criede, and seide to him, Lord, the sone of Dauid, haue merci on me; my douyter is yuel traueilid of a feend.", "rotherham": "And lo! a Canaanite woman, from those bounds, coming forth, began crying out, saying, Have mercy on me, Lord, Son of David! My daughter, is miserably demonized.", "weymouth": "Here a Canaanitish woman of the district came out and persistently cried out, \"Sir, Son of David, pity me; my daughter is cruelly harassed by a demon.\"", "darby": "and lo, a Canaanitish woman, coming out from those borders, cried [to him] saying, Have pity on me, Lord, Son of David; my daughter is miserably possessed by a demon.", "twenty": "There, a Canaanite woman of that district came out and began calling to Jesus: “Take pity on me, Master, Son of David; my daughter is grievously possessed by a demon.”", "acv": "And behold, a Canaanite woman having come out from those regions, cried out to him, saying, Be merciful to me, O Lord, thou son of David, my daughter is grievously demon-possessed.", "anderson": "And behold, a woman of Chanaan came out from those borders, and cried to him, saying: Have mercy on me, Lord, son of David; my daughter is grievously vexed with a demon.", "haweis": "And lo! a woman of Canaan coming out of these coasts, cried aloud, saying to him, Have mercy on me, Lord, Son of David: my daughter is a grievous demoniac.", "noyes": "And, lo! a woman of Canaan came out from those borders, and cried out, saying, Have compassion on me, Lord, Son of David! My daughter is grievously afflicted with a demon.", "webster": "And behold, a woman of Canaan came out of the same territories, and cried to him, saying, Have mercy on me, O Lord, [thou] son of David; my daughter is grievously afflicted with a demon.", "vulgate": "et ecce mulier chananea a finibus illis egressa clamavit dicens ei miserere mei Domine Fili David filia mea male a daemonio vexatur;"}}, {"v": 23, "ref": "15:23", "o": "ὁ δὲ οὐκ ἀπεκρίθη αὐτῇ λόγον. καὶ προσελθόντες οἱ μαθηταὶ αὐτοῦ ⸀ἠρώτουν αὐτὸν λέγοντες· Ἀπόλυσον αὐτήν, ὅτι κράζει ὄπισθεν ἡμῶν.", "en": {"kjv": "But he answered her not a word. And his disciples came and besought him, saying, Send her away; for she crieth after us.", "web": "But he answered her not a word. His disciples came and begged him, saying, “Send her away; for she cries after us.”", "bsb": "But Jesus did not answer a word. So His disciples came and urged Him, “Send her away, for she keeps crying out after us.”", "asv": "But he answered her not a word. And his disciples came and besought him, saying, Send her away; for she crieth after us.", "ylt": "And he did not answer her a word; and his disciples having come to him, were asking him, saying--`Let her away, because she crieth after us;'", "tyndale": "And he gave her never a worde to answer. Then came to him his disciples and besought him sayinge: sende her awaye for she foloweth vs cryinge.", "dra": "Who answered her not a word. And his disciples came and besought him, saying: Send her away, for she crieth after us:", "bbe": "But he gave her no answer. And his disciples came and said to him, Send her away, for she is crying after us.", "geneva": "But hee answered her not a worde. Then came to him his disciples, and besought him, saying, Sende her away, for she crieth after vs.", "wycliffe": "And he answeride not to hir a word. And hise disciplis camen, and preieden hym, and seiden, Leue thou hir, for she crieth aftir vs.", "rotherham": "But, he, answered her no a word. And his disciples, coming forward began requesting him, saying—Dismiss her, because she is crying out after us.", "weymouth": "But He answered her not a word. Then the disciples interposed, and begged Him, saying, \"Send her away because she keeps crying behind us.\"", "darby": "But he did not answer her a word. And his disciples came to [him] and asked him, saying, Dismiss her, for she cries after us.", "twenty": "But Jesus did not answer her a word; and his disciples came up and begged him to send her away. “She keeps calling out after us,” they said.", "acv": "But he answered her not a word. And his disciples having approached, they besought him, saying, Send her away, because she cries out behind us.", "anderson": "But he answered her not a word. And his disciples came and besought him, saying: Send her away, for she cries after us.", "haweis": "But he replied not a word to her. Then his disciples came and intreated him, saying, Send her away; for she is crying aloud after us.", "noyes": "But he did not answer her a word. And his disciples came and besought him, saying Send her away, for she is crying out after us.", "webster": "But he answered her not a word. And his disciples came and besought him, saying, Send her away; for she crieth after us.", "vulgate": "qui non respondit ei verbum et accedentes discipuli eius rogabant eum dicentes dimitte eam quia clamat post nos;"}}, {"v": 24, "ref": "15:24", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Οὐκ ἀπεστάλην εἰ μὴ εἰς τὰ πρόβατα τὰ ἀπολωλότα οἴκου Ἰσραήλ.", "en": {"kjv": "But he answered and said, I am not sent but unto the lost sheep of the house of Israel.", "web": "But he answered, “I wasn’t sent to anyone but the lost sheep of the house of Israel.”", "bsb": "He answered, “I was sent only to the lost sheep of the house of Israel.”", "asv": "But he answered and said, I was not sent but unto the lost sheep of the house of Israel.", "ylt": "and he answering said, `I was not sent except to the lost sheep of the house of Israel.'", "tyndale": "He answered and sayde: I am not sent but vnto ye loost shepe of ye housse of Israel.", "dra": "And he answering, said: I was not sent but to the sheep, that are lost of the house of Israel.", "bbe": "But he made answer and said, I was sent only to the wandering sheep of the house of Israel.", "geneva": "But he answered, and said, I am not sent, but vnto the lost sheepe of the house of Israel.", "wycliffe": "He answeride, and seide, Y am not sent, but to the scheep of the hous of Israel that perischiden.", "rotherham": "But, he, answering, said, I was not sent forth, save unto the lost sheep of the house of Israel.", "weymouth": "\"I have only been sent to the lost sheep of the house of Israel,\" He replied.", "darby": "But he answering said, I have not been sent save to the lost sheep of Israel's house.", "twenty": "“I was not sent,” replied Jesus, “to any one except the lost sheep of Israel.”", "acv": "But having answered, he said, I was not sent except to the lost sheep of the house of Israel.", "anderson": "But he answered and said: I am not sent but to the lost sheep of the house of Israel.", "haweis": "But he said in reply, I am not sent, save only to the lost sheep of the house of Israel.", "noyes": "But he answered and said, I was not sent except to the lost sheep of the house of Israel.", "webster": "But he answered and said, I am not sent but to the lost sheep of the house of Israel.", "vulgate": "ipse autem respondens ait non sum missus nisi ad oves quae perierunt domus Israhel;"}}, {"v": 25, "ref": "15:25", "o": "ἡ δὲ ἐλθοῦσα ⸀προσεκύνει αὐτῷ λέγουσα· Κύριε, βοήθει μοι.", "en": {"kjv": "Then came she and worshipped him, saying, Lord, help me.", "web": "But she came and worshiped him, saying, “Lord, help me.”", "bsb": "The woman came and knelt before Him. “Lord, help me!” she said.", "asv": "But she came and worshipped him, saying, Lord, help me.", "ylt": "And having come, she was bowing to him, saying, `Sir, help me;'", "tyndale": "Then she came and worshipped him sayinge: master helpe me.", "dra": "But she came and adored him, saying: Lord, help me.", "bbe": "But she came and gave him worship, saying, Help, Lord.", "geneva": "Yet she came, and worshipped him, saying, Lord, helpe me.", "wycliffe": "And she cam, and worschipide hym, and seide, Lord, helpe me.", "rotherham": "And, she, coming, began bowing down to him, saying, Lord! help me.", "weymouth": "Then she came and threw herself at His feet and entreated Him. \"O Sir, help me,\" she said.", "darby": "But she came and did him homage, saying, Lord, help me.", "twenty": "But the woman came, and, bowing to the ground before him, said: “Master, help me.”", "acv": "But having come, she worshiped him, saying, Lord, help me.", "anderson": "But she came and did him homage, saying: Lord, help me.", "haweis": "Then she came, and worshiped him, saying, Lord, help me!", "noyes": "Then she came and fell down before him, saying, Lord, help me!", "webster": "Then came she and worshiped him, saying, Lord, help me.", "vulgate": "at illa venit et adoravit eum dicens Domine adiuva me;"}}, {"v": 26, "ref": "15:26", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Οὐκ ἔστιν καλὸν λαβεῖν τὸν ἄρτον τῶν τέκνων καὶ βαλεῖν τοῖς κυναρίοις.", "en": {"kjv": "But he answered and said, It is not meet to take the children’s bread, and to cast it to dogs.", "web": "But he answered, “It is not appropriate to take the children’s bread and throw it to the dogs.”", "bsb": "But Jesus replied, “It is not right to take the children’s bread and toss it to the dogs.”", "asv": "And he answered and said, It is not meet to take the children’s bread and cast it to the dogs.", "ylt": "and he answering said, `It is not good to take the children's bread, and to cast to the little dogs.'", "tyndale": "He answered and sayde: it is not good to take the chyldrens breed and to cast it to whelpes.", "dra": "Who answering, said: It is not good to take the bread of the children, and to cast it to the dogs.", "bbe": "And he made answer and said, It is not right to take the children's bread and give it to the dogs.", "geneva": "And he answered, and said, It is not good to take the childrens bread, and to cast it to whelps.", "wycliffe": "Which answeride, and seide, It is not good to take the breed of children, and caste to houndis.", "rotherham": "But, he, answering, said, It is, not seemly, to take the loaf of, the children, and cast, to the little dogs.", "weymouth": "\"It is not right,\" He said, \"to take the children's bread and throw it to the dogs.\"", "darby": "But he answering said, It is not well to take the bread of the children and cast it to the dogs.", "twenty": "“It is not fair,” replied Jesus, “to take the children’s food and throw it to dogs.”", "acv": "And having answered, he said, It is not right to take the children's bread and cast it to the house dogs.", "anderson": "He answered and said: It is not good to take the children’s bread, and throw it to the little dogs.", "haweis": "But he answering said, It is not proper to take the children’s bread and throw it to the dogs.", "noyes": "But he answering said, It is not allowable to take the children’s bread, and throw it to the little dogs.", "webster": "But he answered and said, It is not meet to take the children's bread, and to cast [it] to dogs.", "vulgate": "qui respondens ait non est bonum sumere panem filiorum et mittere canibus;"}}, {"v": 27, "ref": "15:27", "o": "ἡ δὲ εἶπεν· Ναί, κύριε, καὶ γὰρ τὰ κυνάρια ἐσθίει ἀπὸ τῶν ψιχίων τῶν πιπτόντων ἀπὸ τῆς τραπέζης τῶν κυρίων αὐτῶν.", "en": {"kjv": "And she said, Truth, Lord: yet the dogs eat of the crumbs which fall from their masters’ table.", "web": "But she said, “Yes, Lord, but even the dogs eat the crumbs which fall from their masters’ table.”", "bsb": "“Yes, Lord,” she said, “even the dogs eat the crumbs that fall from their master’s table.”", "asv": "But she said, Yea, Lord: for even the dogs eat of the crumbs which fall from their masters’ table.", "ylt": "And she said, `Yes, sir, for even the little dogs do eat of the crumbs that are falling from their lords' table;'", "tyndale": "She answered and sayde: truthe Lorde: neverthelesse the whelpes eate of the cromes which fall from their masters table.", "dra": "But she said: Yea, Lord; for the whelps also eat of the crumbs that fall from the table of their masters.", "bbe": "But she said, Yes, Lord: but even the dogs take the bits from under their masters' table.", "geneva": "But she said, Trueth, Lord: yet in deede the whelpes eate of the crommes, which fall from their masters table.", "wycliffe": "And she seide, Yhis, Lord; for whelpis eten of the crummes, that fallen doun fro the bord of her lordis.", "rotherham": "And, she, said, True, Lord! [for], even the little dogs, eat of the crumbs which are falling from the table of, their masters.", "weymouth": "\"Be it so, Sir,\" she said, \"for even the dogs eat the scraps which fall from their masters' tables.\"", "darby": "But she said, Yea, Lord; for even the dogs eat of the crumbs which fall from the table of their masters.", "twenty": "“Yes, Master,” she said, “for even dogs do feed on the scraps that fall from their owners’ table.”", "acv": "But she said, Yes, Lord, for even the house dogs eat of the crumbs that fall from the table of their masters.", "anderson": "She replied: Yes, Lord; and yet thou canst help me; for the little dogs eat of the crumbs which fall from the table of their masters.", "haweis": "And she said, True, Lord: yet even the dogs eat of the crumbs which fall from their master’s table.", "noyes": "And she said, Yea, Lord; for the little dogs eat of the crumbs which fall from the table of their masters.", "webster": "And she said, Truth, Lord: yet the dogs eat of the crums which fall from their master's table.", "vulgate": "at illa dixit etiam Domine nam et catelli edunt de micis quae cadunt de mensa dominorum suorum;"}}, {"v": 28, "ref": "15:28", "o": "τότε ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν αὐτῇ· Ὦ γύναι, μεγάλη σου ἡ πίστις· γενηθήτω σοι ὡς θέλεις. καὶ ἰάθη ἡ θυγάτηρ αὐτῆς ἀπὸ τῆς ὥρας ἐκείνης.", "en": {"kjv": "Then Jesus answered and said unto her, O woman, great is thy faith: be it unto thee even as thou wilt. And her daughter was made whole from that very hour.", "web": "Then Jesus answered her, “Woman, great is your faith! Be it done to you even as you desire.” And her daughter was healed from that hour.", "bsb": "“O woman,” Jesus answered, “your faith is great! Let it be done for you as you desire.” And her daughter was healed from that very hour.", "asv": "Then Jesus answered and said unto her, O woman, great is thy faith: be it done unto thee even as thou wilt. And her daughter was healed from that hour.", "ylt": "then answering, Jesus said to her, `O woman, great is thy faith, let it be to thee as thou wilt;' and her daughter was healed from that hour.", "tyndale": "Then Iesus answered and sayde vnto her. O woman greate is thy faith be it to the even as thou desyrest. And her doughter was made whole even at that same houre.", "dra": "Then Jesus answering, said to her: O woman, great is thy faith: be it done to thee as thou wilt: and her daughter was cured from that hour.", "bbe": "Then Jesus, answering, said to her, O woman, great is your faith: let your desire be done. And her daughter was made well from that hour.", "geneva": "Then Iesus answered, and saide vnto her, O woman, great is thy faith: be it to thee, as thou desirest. And her daughter was made whole at that houre.", "wycliffe": "Thanne Jhesus answeride, and seide to hir, A! womman, thi feith is greet; be it doon to thee, as thou wolt. And hir douytir was helid fro that hour.", "rotherham": "Then, answering, Jesus said to her—O woman! great, is, thy faith! Be it, done, for thee, as thou desirest. And her daughter was healed, from that hour.", "weymouth": "\"O woman,\" replied Jesus, \"great is your faith: be it done to you as you desire.\" And from that moment her daughter was restored to health.", "darby": "Then Jesus answering said to her, O woman, thy faith [is] great. Be it to thee as thou desirest. And her daughter was healed from that hour.", "twenty": "“Your faith is great,” was his reply to the woman; “it shall be as you wish!” And her daughter was cured that very hour.", "acv": "Then Jesus having answered, said to her, O woman, great is thy faith. Be it done for thee as thou desire. And her daughter was healed from that hour.", "anderson": "Then Jesus answered and said to her: O woman, great is your faith; be it to you as you desire. And her daughter was restored to health from that hour.", "haweis": "Then Jesus answering said unto her, O woman, great is thy faith! be it unto thee even as thou desirest. And her daughter was cured from that hour.", "noyes": "Then Jesus answering said to her, O woman, great is thy faith; be it done to thee even as thou wilt. And her daughter was cured from that hour.", "webster": "Then Jesus answered and said to her, O woman, great [is] thy faith: be it to thee even as thou wilt. And her daughter was healed from that very hour.", "vulgate": "tunc respondens Iesus ait illi o mulier magna est fides tua fiat tibi sicut vis et sanata est filia illius ex illa hora;"}}, {"v": 29, "ref": "15:29", "o": "Καὶ μεταβὰς ἐκεῖθεν ὁ Ἰησοῦς ἦλθεν παρὰ τὴν θάλασσαν τῆς Γαλιλαίας, καὶ ἀναβὰς εἰς τὸ ὄρος ἐκάθητο ἐκεῖ.", "en": {"kjv": "And Jesus departed from thence, and came nigh unto the sea of Galilee; and went up into a mountain, and sat down there.", "web": "Jesus departed there, and came near to the sea of Galilee; and he went up into the mountain, and sat there.", "bsb": "Moving on from there, Jesus went along the Sea of Galilee. Then He went up on a mountain and sat down.", "asv": "And Jesus departed thence, and came nigh unto the sea of Galilee; and he went up into the mountain, and sat there.", "ylt": "And Jesus having passed thence, came nigh unto the sea of Galilee, and having gone up to the mountain, he was sitting there,", "tyndale": "Then Iesus went awaye from thence and came nye vnto the see of Galile and went vp in to a mountayne and sat doune there.", "dra": "And when Jesus had passed away from thence, he came nigh the sea of Galilee: and going up into a mountain, he sat there.", "bbe": "And Jesus went from there and came to the sea of Galilee; and he went up into the mountain, and took his seat there.", "geneva": "So Iesus went away from thence, and came neere vnto the sea of Galile, and went vp into a mountaine and sate downe there.", "wycliffe": "And whanne Jhesus hadde passed fro thennus, he cam bisidis the see of Galilee. And he yede vp in to an hil, and sat there.", "rotherham": "And, passing on from thence, Jesus came near the sea of Galilee, and, going up into the mountain, was sitting there.", "weymouth": "Again, moving thence, Jesus went along by the Lake of Galilee; and ascending the hill, He sat down there.", "darby": "And Jesus, going away from thence, came towards the sea of Galilee, and he went up into the mountain and sat down there;", "twenty": "On leaving that place, Jesus went to the shore of the Sea of Galilee; and then went up the hill, and sat down., you will do what not only what has been done to the fig tree, but, even if you should say to this hill ‘Be lifted up and hurled into the sea!’ it would be done.", "acv": "And having departed from there, Jesus came near the sea of Galilee. And having gone up onto the mountain, he sat there.", "anderson": "And Jesus departed thence, and came near the sea of Galilee, and went up into the mountain, and sat there.", "haweis": "And departing thence, Jesus went to the sea-side of Galilee; and ascending a mountain, he sat down there.", "noyes": "And departing thence, Jesus came near the lake of Galilee; and going up the mountain, he sat down there.", "webster": "And Jesus departed from thence, and came nigh to the sea of Galilee; and ascended a mountain, and sat down there.", "vulgate": "et cum transisset inde Iesus venit secus mare Galilaeae et ascendens in montem sedebat ibi;"}}, {"v": 30, "ref": "15:30", "o": "καὶ προσῆλθον αὐτῷ ὄχλοι πολλοὶ ἔχοντες μεθ’ ἑαυτῶν ⸂κωφούς, τυφλούς, χωλούς, κυλλούς⸃, καὶ ἑτέρους πολλούς, καὶ ἔρριψαν αὐτοὺς παρὰ τοὺς πόδας ⸀αὐτοῦ, καὶ ἐθεράπευσεν αὐτούς·", "en": {"kjv": "And great multitudes came unto him, having with them those that were lame, blind, dumb, maimed, and many others, and cast them down at Jesus’ feet; and he healed them:", "web": "Great multitudes came to him, having with them the lame, blind, mute, maimed, and many others, and they put them down at his feet. He healed them,", "bsb": "Large crowds came to Him, bringing the lame, the blind, the crippled, the mute, and many others, and laid them at His feet, and He healed them.", "asv": "And there came unto him great multitudes, having with them the lame, blind, dumb, maimed, and many others, and they cast them down at his feet; and he healed them:", "ylt": "and there came to him great multitudes, having with them lame, blind, dumb, maimed, and many others, and they did cast them at the feet of Jesus, and he healed them,", "tyndale": "And moche people came vnto him havinge with the halt blynde domme maymed and other many: and cast them doune at Iesus fete. And he healed them", "dra": "And there came to him great multitudes, having with them the dumb, the blind, the lame, the maimed, and many others: and they cast them down at his feet, and he healed them:", "bbe": "And there came to him great numbers of people having with them those who were broken in body, or blind, or without voice, or wounded, or ill in any way, and a number of others; they put them down at his feet and he made them well:", "geneva": "And great multitudes came vnto him, hauing with them, halt, blinde, dumme, maymed, and many other, and cast them downe at Iesus feete, and he healed them.", "wycliffe": "And myche puple cam to hym, and hadden with hem doumbe men and crokid, feble and blynde, and many other; and thei castiden doun hem at hise feet. And he helide hem,", "rotherham": "And there came unto him large multitudes, having with themselves the lame, the maimed, the blind, the dumb, and many others,—and they cast them near his feet, and he cured them;", "weymouth": "Soon great crowds came to Him, bringing with them those who were crippled in feet or hands, blind or dumb, and many besides, and they hastened to lay them at His feet. And He cured them,", "darby": "and great crowds came to him, having with them lame, blind, dumb, crippled, and many others, and they cast them at his feet, and he healed them:", "twenty": "Great crowds of people came to him, bringing with them those who were lame, crippled, blind, or dumb, and many others. They put them down at his feet, and he cured them;", "acv": "And many multitudes came to him, having with them the lame, blind, mute, crippled, and many others. And they placed them beside Jesus' feet, and he healed them,", "anderson": "And many multitudes came to him, having with them the lame, the blind, the deaf, the maimed, and many others; and laid them at the feet of Jesus, and he cured them;", "haweis": "And great multitudes came to him, bringing with them the lame, blind, dumb, cripples, and many others, and cast them down at the feet of Jesus; and he cured them all:", "noyes": "And great multitudes came to him, having with them those who were lame, blind, dumb, maimed, and many others; and they laid them down at his feet, and he healed them;", "webster": "And great multitudes came to him, having with them [those that were] lame, blind, dumb, maimed, and many others, and cast them down at Jesus' feet; and he healed them:", "vulgate": "et accesserunt ad eum turbae multae habentes secum mutos clodos caecos debiles et alios multos et proiecerunt eos ad pedes eius et curavit eos;"}}, {"v": 31, "ref": "15:31", "o": "ὥστε ⸂τὸν ὄχλον⸃ θαυμάσαι βλέποντας κωφοὺς λαλοῦντας ⸂κυλλοὺς ὑγιεῖς⸃ ⸀καὶ χωλοὺς περιπατοῦντας καὶ τυφλοὺς βλέποντας· καὶ ἐδόξασαν τὸν θεὸν Ἰσραήλ.", "en": {"kjv": "Insomuch that the multitude wondered, when they saw the dumb to speak, the maimed to be whole, the lame to walk, and the blind to see: and they glorified the God of Israel.", "web": "so that the multitude wondered when they saw the mute speaking, injured whole, lame walking, and blind seeing—and they glorified the God of Israel.", "bsb": "The crowd was amazed when they saw the mute speaking, the crippled restored, the lame walking, and the blind seeing. And they glorified the God of Israel.", "asv": "insomuch that the multitude wondered, when they saw the dumb speaking, the maimed whole, and the lame walking, and the blind seeing: and they glorified the God of Israel.", "ylt": "so that the multitudes did wonder, seeing dumb ones speaking, maimed whole, lame walking, and blind seeing; and they glorified the God of Israel.", "tyndale": "in so moche that the people wondred to se the dome speake the maymed whole the halt to go and ye blynde to se. And they glorified the God of Israel.", "dra": "So that the multitudes marvelled seeing the dumb speak, the lame walk, the blind see: and they glorified the God of Israel.", "bbe": "So that the people were full of wonder when they saw that those who had no voice were talking, the feeble were made strong, those whose bodies were broken had the power of walking, and the blind were able to see: and they gave glory to the God of Israel.", "geneva": "In so much that the multitude wondered, to see the dumme speake, the maimed whole, the halt to goe, and the blinde to see: and they glorified the God of Israel.", "wycliffe": "so that the puple wondriden seynge doumbe men spekynge, and crokid goynge, blynde men seynge; and thei magnyfieden God of Israel.", "rotherham": "so that the multitude marvelled, seeing the dumb speaking, the lame walking, and the blind seeing,—and they glorified the God of Israel.", "weymouth": "so that the people were amazed to see the dumb speaking, the maimed with their hands perfect, the lame walking, and the blind seeing; and they gave the glory to the God of Israel.", "darby": "so that the crowds wondered, seeing dumb speaking, crippled sound, lame walking, and blind seeing; and they glorified theGod of Israel.", "twenty": "and the crowds were astonished, when they saw the dumb talking, the cripples made sound, the lame walking about, and the blind with their sight restored; and they praised the God of Israel.", "acv": "so as for the multitudes to marvel seeing the mute speaking, the maimed healthy, and the lame walking, and the blind seeing. And they glorified the God of Israel.", "anderson": "so that the multitudes were astonished, when they saw the dumb speaking, the maimed whole, the lame walking, and the blind seeing; and they glorified the God of Israel.", "haweis": "insomuch that the multitude marvelled when they saw the dumb speaking, the cripples sound, the lame walking, and the blind restored to sight: and they glorified the God of Israel.", "noyes": "so that the multitude wondered, when they saw the dumb speaking, the maimed sound, and the lame walking, and the blind seeing; and they gave glory to the God of Israel.", "webster": "So that the multitude wondered, when they saw the dumb to speak, the maimed to be whole, the lame to walk, and the blind to see: and they glorified the God of Israel.", "vulgate": "ita ut turbae mirarentur videntes mutos loquentes clodos ambulantes caecos videntes et magnificabant Deum Israhel;"}}, {"v": 32, "ref": "15:32", "o": "Ὁ δὲ Ἰησοῦς προσκαλεσάμενος τοὺς μαθητὰς αὐτοῦ εἶπεν· Σπλαγχνίζομαι ἐπὶ τὸν ὄχλον, ὅτι ἤδη ἡμέραι τρεῖς προσμένουσίν μοι καὶ οὐκ ἔχουσιν τί φάγωσιν· καὶ ἀπολῦσαι αὐτοὺς νήστεις οὐ θέλω, μήποτε ἐκλυθῶσιν ἐν τῇ ὁδῷ.", "en": {"kjv": "Then Jesus called his disciples unto him, and said, I have compassion on the multitude, because they continue with me now three days, and have nothing to eat: and I will not send them away fasting, lest they faint in the way.", "web": "Jesus summoned his disciples and said, “I have compassion on the multitude, because they continue with me now three days and have nothing to eat. I don’t want to send them away fasting, or they might faint on the way.”", "bsb": "Then Jesus called His disciples to Him and said, “I have compassion for this crowd, because they have already been with Me three days and have nothing to eat. I do not want to send them away hungry, or they may faint along the way.”", "asv": "And Jesus called unto him his disciples, and said, I have compassion on the multitude, because they continue with me now three days and have nothing to eat: and I would not send them away fasting, lest haply they faint on the way.", "ylt": "And Jesus having called near his disciples, said, `I have compassion upon the multitude, because now three days they continue with me, and they have not what they may eat; and to let them away fasting I will not, lest they faint in the way.'", "tyndale": "Then Iesus called his disciples to him and sayde: I have compassion on ye people becau se they have cotynued with me now .iii. dayes and have nought to eate: and I wyll not let them departe fastinge leste they perisshe in ye waye.", "dra": "And Jesus called together his disciples, and said: I have compassion on the multitudes, because they continue with me now three days, and have not what to eat, and I will not send them away fasting, lest they faint in the way.", "bbe": "And Jesus got his disciples together and said, I have pity for the people, because they have now been with me three days and have no food: and I will not send them away without food, or they will have no strength for the journey.", "geneva": "Then Iesus called his disciples vnto him, and said, I haue compassion on this multitude, because they haue continued with mee already three dayes, and haue nothing to eate: and I wil not let them depart fasting, least they faint in the way.", "wycliffe": "And Jhesus, whanne hise disciplis weren clepid to gidere, seide to hem, Y haue reuthe of the puple, for thei han abiden now thre daies with me, and han no thing to ete; and Y wole not leeue hem fastynge, lest thei failen in the weie.", "rotherham": "But, Jesus, calling near his disciples, said—My compassions are moved towards the multitude, because [even now], three days, abide they with me, and they have nothing to eat,—and, to dismiss them fasting, I am not willing, lest by any means they faint in the way.", "weymouth": "But Jesus called His disciples to Him and said, \"My heart yearns over this mass of people, for it is now the third day that they have been with me and they have nothing to eat. I am unwilling to send them away hungry, lest they should faint on the road.\"", "darby": "But Jesus, having called his disciples to [him], said, I have compassion on the crowd, because they have stayed with me already three days and they have not anything they can eat, and I would not send them away fasting lest they should faint on the way.", "twenty": "Afterwards Jesus called his disciples to him, and said: “My heart is moved at the sight of all these people, for they have already been with me three days and they have nothing to eat; and I am unwilling to send them away hungry, for fear that they should break down on the way.”", "acv": "And Jesus having summoned his disciples, he said, I feel compassion toward the multitude because they continue with me now three days and do not have what they might eat. And I do not want to dismiss them without food, lest they might faint on the way.", "anderson": "Then Jesus called his disciples to him, and said: I have compassion on the multitude, because they have been with me now three days, and have nothing to eat. And I am not willing to send them away fasting, lest they faint on the road.", "haweis": "Then Jesus calling his disciples, said, I have compassion on the multitude, for they have now continued with me three days, and have not any thing to eat: and send them away fasting I will not, lest they faint on the road.", "noyes": "And Jesus having called his disciples to him, said, I have compassion on the multitude, because they have remained with me now three days, and have nothing to eat; and I am not willing to send them away fasting, lest they faint on the road.", "webster": "Then Jesus called his disciples [to him], and said, I have compassion on the multitude, because they continue with me now three days, and have nothing to eat: and I will not send them away fasting, lest they faint in the way.", "vulgate": "Iesus autem convocatis discipulis suis dixit misereor turbae quia triduo iam perseverant mecum et non habent quod manducent et dimittere eos ieiunos nolo ne deficiant in via;"}}, {"v": 33, "ref": "15:33", "o": "καὶ λέγουσιν αὐτῷ οἱ ⸀μαθηταί· Πόθεν ἡμῖν ἐν ἐρημίᾳ ἄρτοι τοσοῦτοι ὥστε χορτάσαι ὄχλον τοσοῦτον;", "en": {"kjv": "And his disciples say unto him, Whence should we have so much bread in the wilderness, as to fill so great a multitude?", "web": "The disciples said to him, “Where should we get so many loaves in a deserted place as to satisfy so great a multitude?”", "bsb": "The disciples replied, “Where in this desolate place could we find enough bread to feed such a large crowd?”", "asv": "And the disciples say unto him, Whence should we have so many loaves in a desert place as to fill so great a multitude?", "ylt": "And his disciples say to him, `Whence to us, in a wilderness, so many loaves, as to fill so great a multitude?'", "tyndale": "And his disciples sayd vnto him: whece shuld we get so moche breed in ye wildernes as shuld suffise so greate a multitude?", "dra": "And the disciples say unto him: Whence then should we have so many loaves in the desert, as to fill so great a multitude?", "bbe": "And the disciples say to him, How may we get enough bread in a waste place, to give food to such a number of people?", "geneva": "And his disciples saide vnto him, Whence should we get so much bread in the wildernes, as should suffice so great a multitude!", "wycliffe": "And the disciplis seien to him, Wherof thanne so many looues among vs in desert, to fulfille so greet a puple?", "rotherham": "And his disciples say unto him—Whence, to us, in a wilderness, loaves in such numbers as to fill a multitude, so great?", "weymouth": "\"Where can we,\" asked the disciples, \"get bread enough in this remote place to satisfy so vast a multitude?\"", "darby": "And his disciples say to him, Whence should we have so many loaves in [the] wilderness as to satisfy so great a crowd?", "twenty": "“Where can we,” his disciples asked, “in a lonely place find enough bread for such a crowd as this?”", "acv": "And his disciples say to him, From where are so many loaves for us in a wilderness so as to feed so great a multitude?", "anderson": "And his disciples said to him: Whence should we have in the desert as many loaves as would satisfy so great a multitude?", "haweis": "And his disciples said unto him, Whence can we in the wilderness have loaves enough to satisfy the cravings of so great a multitude?", "noyes": "And the disciples say to him, Whence should we have so many loaves in a wilderness, as to fill so great a multitude?", "webster": "And his disciples say to him, Whence should we have so much bread in the wilderness, as to satisfy so great a multitude?", "vulgate": "et dicunt ei discipuli unde ergo nobis in deserto panes tantos ut saturemus turbam tantam;"}}, {"v": 34, "ref": "15:34", "o": "καὶ λέγει αὐτοῖς ὁ Ἰησοῦς· Πόσους ἄρτους ἔχετε; οἱ δὲ εἶπαν· Ἑπτά, καὶ ὀλίγα ἰχθύδια.", "en": {"kjv": "And Jesus saith unto them, How many loaves have ye? And they said, Seven, and a few little fishes.", "web": "Jesus said to them, “How many loaves do you have?” They said, “Seven, and a few small fish.”", "bsb": "“How many loaves do you have?” Jesus asked. “Seven,” they replied, “and a few small fish.”", "asv": "And Jesus said unto them, How many loaves have ye? And they said, Seven, and a few small fishes.", "ylt": "And Jesus saith to them, `How many loaves have ye?' and they said, `Seven, and a few little fishes.'", "tyndale": "And Iesus sayde vnto them: how many loves have ye? And they sayde: seven and a feawe litle fysshes.", "dra": "And Jesus said to them: How many loaves have you? But they said: Seven, and a few little fishes.", "bbe": "And Jesus says to them, How much bread have you? And they said, Seven cakes, and some small fishes.", "geneva": "And Iesus said vnto them, How many loaues haue ye? And they said, Seuen, and a few litle fishes.", "wycliffe": "And Jhesus seide to hem, Hou many looues han ye? And thei seiden, Seuene, and a fewe smale fisshis.", "rotherham": "And Jesus saith unto them—How many, loaves have ye? And, they, said,—Seven, and a few small fishes.", "weymouth": "\"How many loaves have you?\" Jesus asked. \"Seven,\" they said, \"and a few small fish.\"", "darby": "And Jesus says to them, How many loaves have ye? But they said, Seven, and a few small fishes.", "twenty": "“How many loaves have you?” said Jesus. “Seven,” they answered, “and a few small fish.”", "acv": "And Jesus says to them, How many loaves have ye? And they said, Seven, and a few small fishes.", "anderson": "And Jesus said to them: How many loaves have you? They said: Seven, and a few little fishes.", "haweis": "And Jesus said unto them, How many loaves have ye? And they said, Seven, and a few small fishes.", "noyes": "And Jesus saith to them, How many loaves have ye? And they said, Seven, and a few small fishes.", "webster": "And Jesus saith to them, How many loaves have ye? And they said, Seven, and a few little fishes.", "vulgate": "et ait illis Iesus quot panes habetis at illi dixerunt septem et paucos pisciculos;"}}, {"v": 35, "ref": "15:35", "o": "καὶ ⸀παραγγείλας ⸂τῷ ὄχλῳ⸃ ἀναπεσεῖν ἐπὶ τὴν γῆν", "en": {"kjv": "And he commanded the multitude to sit down on the ground.", "web": "He commanded the multitude to sit down on the ground;", "bsb": "And He instructed the crowd to sit down on the ground.", "asv": "And he commanded the multitude to sit down on the ground;", "ylt": "And he commanded the multitudes to sit down upon the ground,", "tyndale": "And he comaunded ye people to syt doune on ye grounde:", "dra": "And he commanded the multitude to sit down upon the ground.", "bbe": "Then he gave an order to the people to be seated on the earth,", "geneva": "Then he commanded the multitude to sit downe on the ground,", "wycliffe": "And he comaundide to the puple, to sitte to mete on the erthe.", "rotherham": "And, sending word to the multitude to recline upon the ground,", "weymouth": "So He bade all the people sit down on the ground,", "darby": "And he commanded the crowds to lie down on the ground;", "twenty": "Telling the crowd to sit down on the ground,", "acv": "And he commanded the multitudes to sit down on the ground.", "anderson": "And he commanded the multitude to recline on the ground.", "haweis": "And he commanded the multitude to sit down on the ground.", "noyes": "And bidding the multitude to lie down on the ground,", "webster": "And he commanded the multitude to sit on the ground.", "vulgate": "et praecepit turbae ut discumberet super terram;"}}, {"v": 36, "ref": "15:36", "o": "⸀ἔλαβεν τοὺς ἑπτὰ ἄρτους καὶ τοὺς ἰχθύας ⸀καὶ εὐχαριστήσας ἔκλασεν καὶ ⸀ἐδίδου τοῖς ⸀μαθηταῖς οἱ δὲ μαθηταὶ ⸂τοῖς ὄχλοις⸃.", "en": {"kjv": "And he took the seven loaves and the fishes, and gave thanks, and brake them, and gave to his disciples, and the disciples to the multitude.", "web": "and he took the seven loaves and the fish. He gave thanks and broke them, and gave to the disciples, and the disciples to the multitudes.", "bsb": "Taking the seven loaves and the fish, He gave thanks and broke them. Then He gave them to the disciples, and the disciples gave them to the people.", "asv": "and he took the seven loaves and the fishes; and he gave thanks and brake, and gave to the disciples, and the disciples to the multitudes.", "ylt": "and having taken the seven loaves and the fishes, having given thanks, he did break, and gave to his disciples, and the disciples to the multitude.", "tyndale": "and toke the seven loves and the fysshes and gave thankes and brake them and gave to his disciples and the disciples gave them to the people.", "dra": "And taking the seven loaves and the fishes, and giving thanks, he brake, and gave to his disciples, and the disciples gave to the people.", "bbe": "And he took the seven cakes of bread and the fishes; and having given praise, he gave the broken bread to the disciples, and the disciples gave it to the people.", "geneva": "And tooke the seuen loaues, and the fishes, and gaue thankes, and brake them, and gaue to his disciples, and the disciples to the multitude.", "wycliffe": "And he took seuene looues and fyue fischis, and dide thankyngis, and brak, and yaf to hise disciplis; and the disciplis yauen to the puple.", "rotherham": "he took the seven loaves, and the fishes, and, giving thanks, brake,—and began giving to his disciples, and, the disciples, to the multitudes.", "weymouth": "and He took the seven loaves and the fish, and after giving thanks He broke them up and then distributed them to the disciples, and they to the people.", "darby": "and having taken the seven loaves and the fishes, having given thanks, he broke [them] and gave [them] to his disciples, and the disciples to the crowd.", "twenty": "Jesus took the seven loaves and the fish, and, after saying the thanksgiving, broke them, and gave them to the disciples; and the disciples gave them to the crowds.", "acv": "And after taking the seven loaves and the fishes, having expressed thanks, he broke in pieces, and gave to the disciples, and the disciples to the multitudes.", "anderson": "And he took the seven loaves and the fishes, and gave thanks, and broke, and gave thorn to the disciples, and the disciples gave them to the multitude.", "haweis": "And taking the seven loaves and the fishes, he gave thanks, and brake, and gave to his disciples, and the disciples to the multitude.", "noyes": "he took the seven loaves and the fishes, and gave thanks, and broke, and gave them to the disciples, and the disciples to the multitudes.", "webster": "And he took the seven loaves and the fishes, and gave thanks, and broke [them], and gave to his disciples, and the disciples to the multitude.", "vulgate": "et accipiens septem panes et pisces et gratias agens fregit et dedit discipulis suis et discipuli dederunt populo;"}}, {"v": 37, "ref": "15:37", "o": "καὶ ἔφαγον πάντες καὶ ἐχορτάσθησαν, καὶ ⸂τὸ περισσεῦον τῶν κλασμάτων ἦραν⸃ ἑπτὰ σπυρίδας πλήρεις.", "en": {"kjv": "And they did all eat, and were filled: and they took up of the broken meat that was left seven baskets full.", "web": "They all ate, and were filled. They took up seven baskets full of the broken pieces that were left over.", "bsb": "They all ate and were satisfied, and the disciples picked up seven basketfuls of broken pieces that were left over.", "asv": "And they all ate, and were filled: and they took up that which remained over of the broken pieces, seven baskets full.", "ylt": "And they did all eat, and were filled, and they took up what was over of the broken pieces seven baskets full,", "tyndale": "And they dyd all eate and were suffised. And they toke vp of the broke meate that was lefte .vii. basketes full.", "dra": "And they did all eat, and had their fill. And they took up seven baskets full, of what remained of the fragments.", "bbe": "And they all took food, and had enough; and they took up of the broken bits, seven baskets full.", "geneva": "And they did all eate, and were sufficed: and they tooke vp of the fragments that remained, seuen baskets full.", "wycliffe": "And alle eten, and weren fulfillid, and thei token that that was left of relifes, seuene lepis fulle.", "rotherham": "And they all did eat and were filled,—and, the remainder of the broken pieces, took they up, seven hampers, full.", "weymouth": "And they all ate and were satisfied. The broken portions that remained over they took up--seven full hampers.", "darby": "And all ate and were filled; and they took up what was over and above of the fragments seven baskets full;", "twenty": "Every one had sufficient to eat, and they picked up seven baskets full of the broken pieces left.", "acv": "And they all ate and were filled. And they took up seven hampers full of the fragments that remained.", "anderson": "And they all ate and were satisfied; and they took up what remained of the broken pieces, seven baskets full.", "haweis": "And they did all eat, and were filled: and took up a superabundance of fragments seven baskets full.", "noyes": "And they all ate, and were filled; and they took up of the fragments that remained, seven baskets full.", "webster": "And they all ate and were filled: and they took up of the fragments that were left seven baskets full.", "vulgate": "et comederunt omnes et saturati sunt et quod superfuit de fragmentis tulerunt septem sportas plenas;"}}, {"v": 38, "ref": "15:38", "o": "οἱ δὲ ἐσθίοντες ἦσαν τετρακισχίλιοι ἄνδρες χωρὶς γυναικῶν καὶ παιδίων.", "en": {"kjv": "And they that did eat were four thousand men, beside women and children.", "web": "Those who ate were four thousand men, besides women and children.", "bsb": "A total of four thousand men were fed, in addition to women and children.", "asv": "And they that did eat were four thousand men, besides women and children.", "ylt": "and those eating were four thousand men, apart from women and children.", "tyndale": "And yet they that ate were .iiii.M. men besyde wemen and chyldren.", "dra": "And they that did eat, were four thousand men, beside children and women.", "bbe": "And there were four thousand men who took food, together with women and children.", "geneva": "And they that had eaten, were foure thousand men, beside women, and litle children.", "wycliffe": "And thei that eten weren foure thousynde of men, with outen litle children and wymmen.", "rotherham": "And, they who did eat, were four thousand men, besides women and children.", "weymouth": "Those who ate were 4,000 adult men, without reckoning women and children.", "darby": "but they that ate were four thousand men, besides women and children.", "twenty": "The men who ate were four thousand in number without counting women and children.", "acv": "And those who ate were four thousand men, besides women and children.", "anderson": "And those who ate were four thousand men, besides women and children.", "haweis": "And they that had eaten were four thousand men, besides women and children.", "noyes": "And they who ate were four thousand men, besides children and women.", "webster": "And they that had eaten were four thousand men, besides women and children.", "vulgate": "erant autem qui manducaverant quattuor milia hominum extra parvulos et mulieres;"}}, {"v": 39, "ref": "15:39", "o": "καὶ ἀπολύσας τοὺς ὄχλους ἐνέβη εἰς τὸ πλοῖον, καὶ ἦλθεν εἰς τὰ ὅρια ⸀Μαγαδάν.", "en": {"kjv": "And he sent away the multitude, and took ship, and came into the coasts of Magdala.", "web": "Then he sent away the multitudes, got into the boat, and came into the borders of Magdala.", "bsb": "After Jesus had dismissed the crowds, He got into the boat and went to the region of Magadan.", "asv": "And he sent away the multitudes, and entered into the boat, and came into the borders of Magadan.", "ylt": "And having let away the multitudes, he went into the boat, and did come to the borders of Magdala.", "tyndale": "And he sent awaye the people and toke shippe and came into the parties of Magdala.", "dra": "And having dismissed the multitude, he went up into a boat, and came into the coasts of Magedan.", "bbe": "And when he had sent the people away, he got into the boat, and came into the country of Magadan.", "geneva": "Then Iesus sent away the multitude, and tooke ship, and came into the partes of Magdala.", "wycliffe": "And whanne he hadde left the puple, he wente vp in to a boot, and cam in to the coostis of Magedan.", "rotherham": "And, dismissing the multitudes, he went up into the boat,—and came into the bounds of Magadan.", "weymouth": "He then dismissed the people, went on board the boat, and came into the district of Magadan.", "darby": "And, having dismissed the crowds, he went on board ship and came to the borders of Magadan.", "twenty": "Then, after dismissing the crowds, Jesus got into the boat, and went to the neighbourhood of Magadan.", "acv": "And having dismissed the multitudes, he entered into the boat, and came into the regions of Magdala.", "anderson": "And he sent the multitudes away, and entered the ship, and went into the borders of Magdala.", "haweis": "And dismissing the multitudes he went on board a vessel, and came into the coasts of Magdala.", "noyes": "Then he sent away the multitudes, and went on board the boat, and came into the borders of Magadan.", "webster": "And he sent away the multitude, and took a boat, and came into the borders of Magdala.", "vulgate": "et dimissa turba ascendit in naviculam et venit in fines Magedan;"}}]}, {"c": 16, "verses": [{"v": 1, "ref": "16:1", "o": "Καὶ προσελθόντες οἱ Φαρισαῖοι καὶ Σαδδουκαῖοι πειράζοντες ἐπηρώτησαν αὐτὸν σημεῖον ἐκ τοῦ οὐρανοῦ ἐπιδεῖξαι αὐτοῖς.", "en": {"kjv": "The Pharisees also with the Sadducees came, and tempting desired him that he would shew them a sign from heaven.", "web": "The Pharisees and Sadducees came, and testing him, asked him to show them a sign from heaven.", "bsb": "Then the Pharisees and Sadducees came and tested Jesus by asking Him to show them a sign from heaven.", "asv": "And the Pharisees and Sadducees came, and trying him asked him to show them a sign from heaven.", "ylt": "And the Pharisees and Sadducees having come, tempting, did question him, to shew to them a sign from the heaven,", "tyndale": "Then came the pharises and saduces and did tempte him desyringe him to shewe them some signe from heve.", "dra": "And there came to him the Pharisees and Sadducees tempting: and they asked him to shew them a sign from heaven.", "bbe": "And the Pharisees and Sadducees came and, testing him, made a request to him to give them a sign from heaven.", "geneva": "Then came the Pharises and Sadduces, and did tempt him, desiring him to shew them a signe from heauen.", "wycliffe": "And the Farisees and the Saducees camen to hym temptynge, and preieden hym to schewe hem a tokene fro heuene.", "rotherham": "And, the Pharisees and Sadducees coming near, putting him to the test, requested him, a sign out of the heaven, to shew unto them.", "weymouth": "Here the Pharisees and Sadducees came to Him; and, to make trial of Him, they asked Him to show them a sign in the sky.", "darby": "And the Pharisees and Sadducees, coming to [him], asked him, tempting [him], to shew them a sign out of heaven.", "twenty": "Here the Pharisees and Sadducees came up, and, to test Jesus, requested him to show them some sign from the heavens.", "acv": "And the Pharisees and Sadducees who came, testing, demanded him to exhibit to them a sign from the sky.", "anderson": "And the Pharisees and Sadducees came to tempt him, and asked him to show them a sign from heaven.", "haweis": "AND the Pharisees and the Sadducees came to him, and, to make trial of him, desired him to shew them a sign from heaven.", "noyes": "And the Pharisees and Sadducees came to try him, and asked him to show them a sign from heaven.", "webster": "The Pharisees also and the Sadducees came, and, tempting, desired him that he would show them a sign from heaven.", "vulgate": "et accesserunt ad eum Pharisaei et Sadducaei temptantes et rogaverunt eum ut signum de caelo ostenderet eis;"}}, {"v": 2, "ref": "16:2", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν αὐτοῖς· ⸂Ὀψίας γενομένης λέγετε· Εὐδία, πυρράζει γὰρ ὁ οὐρανός·", "en": {"kjv": "He answered and said unto them, When it is evening, ye say, It will be fair weather: for the sky is red.", "web": "But he answered them, “When it is evening, you say, ‘It will be fair weather, for the sky is red.’", "bsb": "But He replied, “When evening comes, you say, ‘The weather will be fair, for the sky is red,’", "asv": "But he answered and said unto them, When it is evening, ye say, It will be fair weather: for the heaven is red.", "ylt": "and he answering said to them, `Evening having come, ye say, Fair weather, for the heaven is red,", "tyndale": "He answered and sayde vnto the. At even ye saye we shall have fayre wedder and yt because ye skye is reed:", "dra": "But he answered and said to them: When it is evening, you say, It will be fair weather, for the sky is red.", "bbe": "But in answer he said to them, At nightfall you say, The weather will be good, for the sky is red.", "geneva": "But he answered, and said vnto them, When it is euening, ye say, Faire wether: for ye skie is red.", "wycliffe": "And he answeride, and seide to hem, Whanne the euentid is comun, ye seien, It schal be clere, for heuene is rodi;", "rotherham": "But, he, answering said unto them—[[When evening cometh ye say, Fair! for fiery is the heaven;", "weymouth": "He replied, \"In the evening you say, `It will be fine weather, for the sky is red;'", "darby": "But he answering said to them, When evening is come, ye say, Fine weather, for the sky is red;", "twenty": "But Jesus answered: “In the evening you say ‘It will be fine weather, for the sky is as red as fire.’", "acv": "But having answered, he said to them, When it becomes evening, ye say, Fair weather, for the sky is red.", "anderson": "But he answered and said to them: When it is evening, you say, Fair weather; for the sky is red.", "haweis": "And he answering, said unto them, When evening comes, ye say, Fair weather, for the sky is red.", "noyes": "And he answering said to them, When it is evening, ye say, Fair weather! for the sky is red.", "webster": "He answered and said to them, When it is evening, ye say, [It will be] fair weather: for the sky is red.", "vulgate": "at ille respondens ait eis facto vespere dicitis serenum erit rubicundum est enim caelum;"}}, {"v": 3, "ref": "16:3", "o": "καὶ πρωΐ· Σήμερον χειμών, πυρράζει γὰρ στυγνάζων ὁ οὐρανός. ⸀τὸ μὲν πρόσωπον τοῦ οὐρανοῦ γινώσκετε διακρίνειν, τὰ δὲ σημεῖα τῶν καιρῶν οὐ δύνασθε.⸃", "en": {"kjv": "And in the morning, It will be foul weather to day: for the sky is red and lowring. O ye hypocrites, ye can discern the face of the sky; but can ye not discern the signs of the times?", "web": "In the morning, ‘It will be foul weather today, for the sky is red and threatening.’ Hypocrites! You know how to discern the appearance of the sky, but you can’t discern the signs of the times!", "bsb": "and in the morning, ‘Today it will be stormy, for the sky is red and overcast.’ You know how to interpret the appearance of the sky, but not the signs of the times.", "asv": "And in the morning, It will be foul weather to-day: for the heaven is red and lowering. Ye know how to discern the face of the heaven; but ye cannot discern the signs of the times.", "ylt": "and at morning, Foul weather to-day, for the heaven is red--gloomy; hypocrites, the face of the heavens indeed ye do know to discern, but the signs of the times ye are not able!", "tyndale": "and in the morninge ye saye to daye shalbe foule wedder and that because the skye is cloudy and reed. O ye ypocrites ye can discerne ye fassion of the skye: and can ye not discerne ye signes of the tymes?", "dra": "And in the morning: To day there will be a storm, for the sky is red and lowering. You know then how to discern the face of the sky: and can you not know the signs of the times?", "bbe": "And in the morning, The weather will be bad today, for the sky is red and angry. You are able to see the face of heaven, but not the signs of the times.", "geneva": "And in the morning ye say, To day shall be a tempest: for the skie is red and lowring. O hypocrites, ye can discerne the face of the skie, and can ye not discerne the signes of the times?", "wycliffe": "and the morewtid, To dai tempest, for heuene schyneth heueli.", "rotherham": "And at morn, To-day, a storm! for fiery, and yet sad, is the heaven. The face of the heaven indeed, ye learn to distinguish,—but, the signs of the times, ye cannot.]]", "weymouth": "and in the morning, `It will be rough weather to-day, for the sky is red and murky.' You learn how to distinguish the aspect of the heavens, but the signs of the times you cannot.", "darby": "and in the morning, A storm to-day, for the sky is red [and] lowering; ye know [how] to discern the face of the sky, but ye cannot the signs of the times.", "twenty": "But in the morning you say ‘To-day it will be stormy, for the sky is as red as fire and threatening.’ You learn to read the sky; yet you are unable to read the signs of the times!", "acv": "And at morning, Bad weather today, for the sky is red, being gloomy. Hypocrites! Ye indeed know how to discern the face of the sky, but the signs of the times ye are not able.", "anderson": "And in the morning, A storm to-day; for the sky is red and lowering. Hypocrites! you know how to judge of the face of the sky; but you can not judge of the signs of the times.", "haweis": "And in the morning, It will be tempestuous to-day, for the sky is gloomy and fiery red. Ye hypocrites, do ye know how to discern the appearance of the sky, and are ye unable to discern the signs of the times?", "noyes": "And in the morning, A storm today! for the sky is red and lowering. Ye know how to judge of the face of the sky, and can ye not discern the signs of the times?", "webster": "And in the morning, [It will be] foul weather to-day: for the sky is red and lowering. O [ye] hypocrites, ye can discern the face of the sky; but can ye not [discern] the signs of the times?", "vulgate": "et mane hodie tempestas rutilat enim triste caelum;"}}, {"v": 4, "ref": "16:4", "o": "Γενεὰ πονηρὰ καὶ μοιχαλὶς σημεῖον ἐπιζητεῖ, καὶ σημεῖον οὐ δοθήσεται αὐτῇ εἰ μὴ τὸ σημεῖον ⸀Ἰωνᾶ. καὶ καταλιπὼν αὐτοὺς ἀπῆλθεν.", "en": {"kjv": "A wicked and adulterous generation seeketh after a sign; and there shall no sign be given unto it, but the sign of the prophet Jonas. And he left them, and departed.", "web": "An evil and adulterous generation seeks after a sign, and there will be no sign given to it, except the sign of the prophet Jonah.” He left them, and departed.", "bsb": "A wicked and adulterous generation demands a sign, but none will be given it except the sign of Jonah.” Then He left them and went away.", "asv": "An evil and adulterous generation seeketh after a sign; and there shall no sign be given unto it, but the sign of Jonah. And he left them, and departed.", "ylt": "`A generation evil and adulterous doth seek a sign, and a sign shall not be given to it, except the sign of Jonah the prophet;' and having left them he went away.", "tyndale": "The frowarde nacion and advoutrous seketh a signe and there shall non other signe be geven vnto them but the signe of the prophet Ionas. So lefte he them and departed.", "dra": "A wicked and adulterous generation seeketh after a sign: and a sign shall not be given it, but the sign of Jonas the prophet. And he left them, and went away.", "bbe": "An evil and false generation is searching after a sign; and no sign will be given to it but the sign of Jonah. And he went away from them.", "geneva": "The wicked generation, and adulterous seeketh a signe, but there shall no signe be giuen it, but that signe of the Prophet Ionas: so hee left them, and departed.", "wycliffe": "Thanne ye kunne deme the face of heuene, but ye moun not wite the tokenes of tymes. An yuel generacioun and auoutresse sekith a tokene; and a tokene schal not be youun to it, but the tokene of Jonas, the profete. And whanne he hadde left hem, he wente forth.", "rotherham": "A wicked and adulterous generation, a sign, doth seek after, and, a sign, will not be given it,—save the sign of Jonah. And, leaving them behind, he departed.", "weymouth": "A wicked and faithless generation are eager for a sign; but none shall be given to them except the sign of Jonah.\" and He left them and went away.", "darby": "A wicked and adulterous generation seeks after a sign, and a sign shall not be given to it save the sign of Jonas. And he left them and went away.", "twenty": "A wicked and unfaithful generation is asking for a sign, but no sign shall be given it except the sign of Jonah.” So he left them and went away.", "acv": "An evil and adulterous generation seeks after a sign, and no sign will be given to it, except the sign of Jonah the prophet. And having left them behind, he departed.", "anderson": "A wicked and adulterous generation seeks for a sign: and no sign shall be given it but the sign of Jonah the prophet. And he left them and departed.", "haweis": "A wicked and adulterous generation seeketh a sign; and no sign shall be given to it, but the sign of the prophet Jonah. And he left them, and departed.", "noyes": "A wicked and adulterous generation seeketh after a sign; and no sign will be given to it, but the sign of Jonah. And he left them and went away.", "webster": "A wicked and adulterous generation seeketh for a sign; and there shall no sign been to it, but the sign of the prophet Jonah. And he left them, and departed.", "vulgate": "faciem ergo caeli diiudicare nostis signa autem temporum non potestis generatio mala et adultera signum quaerit et signum non dabitur ei nisi signum Ionae et relictis illis abiit;"}}, {"v": 5, "ref": "16:5", "o": "Καὶ ἐλθόντες οἱ ⸀μαθηταὶ εἰς τὸ πέραν ἐπελάθοντο ἄρτους λαβεῖν.", "en": {"kjv": "And when his disciples were come to the other side, they had forgotten to take bread.", "web": "The disciples came to the other side and had forgotten to take bread.", "bsb": "When they crossed to the other side, the disciples forgot to take bread.", "asv": "And the disciples came to the other side and forgot to take bread.", "ylt": "And his disciples having come to the other side, forgot to take loaves,", "tyndale": "And when his disciples were come to the other side of the water they had forgotte to take breed with the.", "dra": "And when his disciples were come over the water, they had forgotten to take bread.", "bbe": "And when the disciples came to the other side they had not taken thought to get bread.", "geneva": "And when his disciples were come to the other side, they had forgotten to take bread with them.", "wycliffe": "And whanne his disciplis camen ouer the see, thei foryaten to take looues.", "rotherham": "And the disciples coming, to the other side, had forgotten to take loaves.", "weymouth": "When the disciples arrived at the other side of the Lake, they found that they had forgotten to bring any bread;", "darby": "And when his disciples were come to the other side, they had forgotten to take bread.", "twenty": "Now the disciples had crossed to the opposite shore, and had forgotten to take any bread.", "acv": "And his disciples having come to the other side, they forgot to take loaves.", "anderson": "And his disciples came to the other side, and had forgotten to take bread.", "haweis": "And when his disciples were come to the other side, they had forgotten to take bread.", "noyes": "And the disciples having come to the other side, had forgotten to take bread.", "webster": "And when his disciples had come to the other side, they had forgotten to take bread.", "vulgate": "et cum venissent discipuli eius trans fretum obliti sunt panes accipere;"}}, {"v": 6, "ref": "16:6", "o": "ὁ δὲ Ἰησοῦς εἶπεν αὐτοῖς· Ὁρᾶτε καὶ προσέχετε ἀπὸ τῆς ζύμης τῶν Φαρισαίων καὶ Σαδδουκαίων.", "en": {"kjv": "Then Jesus said unto them, Take heed and beware of the leaven of the Pharisees and of the Sadducees.", "web": "Jesus said to them, “Take heed and beware of the yeast of the Pharisees and Sadducees.”", "bsb": "“Watch out!” Jesus told them. “Beware of the leaven of the Pharisees and Sadducees.”", "asv": "And Jesus said unto them, Take heed and beware of the leaven of the Pharisees and Sadducees.", "ylt": "and Jesus said to them, `Beware, and take heed of the leaven of the Pharisees and Sadducees;'", "tyndale": "Then Iesus sayd vnto them: Take hede and beware of the leve of ye Pharises and of ye Saduces.", "dra": "Who said to them: Take heed and beware of the leaven of the Pharisees and Sadducees.", "bbe": "And Jesus said to them, Take care to have nothing to do with the leaven of the Pharisees and Sadducees.", "geneva": "Then Iesus said vnto them, Take heede and beware of the leauen of the Pharises and Sadduces.", "wycliffe": "And he seide to hem, Biholde ye, and be war of the soure dowy of Farisees and Saducees.", "rotherham": "And, Jesus, said unto them—Mind! and beware, of the leaven of the Pharisees and Sadducees.", "weymouth": "and when Jesus said to them, \"See to it: beware of the yeast of the Pharisees and Sadducees,\"", "darby": "And Jesus said to them, See and beware of the leaven of the Pharisees and Sadducees.", "twenty": "Presently Jesus said to them: “Take care and be on your guard against the leaven of the Pharisees and Sadducees.”", "acv": "And Jesus said to them, Watch and beware of the leaven of the Pharisees and Sadducees.", "anderson": "And Jesus said to them: Take heed and beware of the leaven of the Pharisees and Sadducees.", "haweis": "Then Jesus said to them, Beware and abstain from the leaven of the Pharisees and of the Sadducees.", "noyes": "And Jesus said to them, Take heed, and beware of the leaven of the Pharisees and Sadducees.", "webster": "Then Jesus said to them, Take heed and beware of the leaven of the Pharisees and of the Sadducees.", "vulgate": "qui dixit illis intuemini et cavete a fermento Pharisaeorum et Sadducaeorum;"}}, {"v": 7, "ref": "16:7", "o": "οἱ δὲ διελογίζοντο ἐν ἑαυτοῖς λέγοντες ὅτι Ἄρτους οὐκ ἐλάβομεν.", "en": {"kjv": "And they reasoned among themselves, saying, It is because we have taken no bread.", "web": "They reasoned among themselves, saying, “We brought no bread.”", "bsb": "They discussed this among themselves and concluded, “It is because we did not bring any bread.”", "asv": "And they reasoned among themselves, saying, We took no bread.", "ylt": "and they were reasoning in themselves, saying, `Because we took no loaves.'", "tyndale": "And they thought in them selves sayinge: because we have brought no breed with vs.", "dra": "But they thought within themselves, saying: Because we have taken no bread.", "bbe": "And they were reasoning among themselves, saying, We took no bread.", "geneva": "And they reasoned among themselues, saying, It is because we haue brought no bread.", "wycliffe": "And thei thouyten among hem, and seiden, For we han not take looues.", "rotherham": "And, they, began to deliberate among themselves, saying—Because, loaves, we took not.", "weymouth": "they reasoned among themselves, saying, \"It is because we have not brought any bread.\"", "darby": "And they reasoned among themselves, saying, Because we have taken no bread.", "twenty": "But the disciples began talking among themselves about their having brought no bread.", "acv": "And they deliberated among themselves, saying, We took no loaves.", "anderson": "And they reasoned among themselves, saying: It is because we took no bread.", "haweis": "So they reasoned among themselves, saying, It is because we have not taken bread.", "noyes": "And they reasoned among themselves, saying, It is because we took no bread.", "webster": "And they reasoned among themselves, saying, [It is] because we have taken no bread.", "vulgate": "at illi cogitabant inter se dicentes quia panes non accepimus;"}}, {"v": 8, "ref": "16:8", "o": "γνοὺς δὲ ὁ Ἰησοῦς ⸀εἶπεν· Τί διαλογίζεσθε ἐν ἑαυτοῖς, ὀλιγόπιστοι, ὅτι ἄρτους οὐκ ⸀ἐλάβετε;", "en": {"kjv": "Which when Jesus perceived, he said unto them, O ye of little faith, why reason ye among yourselves, because ye have brought no bread?", "web": "Jesus, perceiving it, said, “Why do you reason among yourselves, you of little faith, ‘because you have brought no bread?’", "bsb": "Aware of their conversation, Jesus said, “You of little faith, why are you debating among yourselves about having no bread?", "asv": "And Jesus perceiving it said, O ye of little faith, why reason ye among yourselves, because ye have no bread?", "ylt": "And Jesus having known, said to them, `Why reason ye in yourselves, ye of little faith, because ye took no loaves?", "tyndale": "When Iesus vnderstode that he sayd vnto the. O ye of lytell faith why are youre mindes cumbred because ye have brought no breed?", "dra": "And Jesus knowing it, said: Why do you think within yourselves, O ye of little faith, for that you have no bread?", "bbe": "And Jesus, seeing it, said, O you of little faith, why are you reasoning among yourselves, because you have no bread?", "geneva": "But Iesus knowing it, saide vnto them, O ye of litle faith, why reason you thus among your selues, because ye haue brought no bread?", "wycliffe": "But Jhesus witynge seide to hem, What thenken ye among you of litel feith, for ye han not looues?", "rotherham": "And, observing it, Jesus said—Why are ye deliberating among yourselves, ye little-of-faith! because, loaves, ye have not?", "weymouth": "Jesus perceived this and said, \"Why are you reasoning among yourselves, you men of little faith, because you have no bread?", "darby": "And Jesus knowing [it], said, Why reason ye among yourselves, O ye of little faith, because ye have taken no bread?", "twenty": "On noticing this, Jesus said: “Why are you talking among yourselves about your being short of bread, O men of little faith?", "acv": "And having known it, Jesus said to them, O ye of little faith, why do ye deliberate among yourselves because ye brought no loaves?", "anderson": "And Jesus perceiving it, said to them: O you of little faith! why are you reasoning among yourselves because you took no bread?", "haweis": "But when Jesus knew it, he said unto them, Why are ye reasoning among yourselves, O ye of little faith, because ye have not taken bread?", "noyes": "And Jesus knowing it, said, Why are ye reasoning among yourselves, ye of little faith, because ye took no bread?", "webster": "[Which] when Jesus perceived, he said to them, O ye of little faith, why reason ye among yourselves, because ye have brought no bread?", "vulgate": "sciens autem Iesus dixit quid cogitatis inter vos modicae fidei quia panes non habetis;"}}, {"v": 9, "ref": "16:9", "o": "οὔπω νοεῖτε, οὐδὲ μνημονεύετε τοὺς πέντε ἄρτους τῶν πεντακισχιλίων καὶ πόσους κοφίνους ἐλάβετε;", "en": {"kjv": "Do ye not yet understand, neither remember the five loaves of the five thousand, and how many baskets ye took up?", "web": "Don’t you yet perceive, neither remember the five loaves for the five thousand, and how many baskets you took up?", "bsb": "Do you still not understand? Do you not remember the five loaves for the five thousand, and how many basketfuls you gathered?", "asv": "Do ye not yet perceive, neither remember the five loaves of the five thousand, and how many baskets ye took up?", "ylt": "do ye not yet understand, nor remember the five loaves of the five thousand, and how many hand-baskets ye took up?", "tyndale": "Do ye not yet perceave nether remeber those .v. loves when there were .v.M. men and how many baskettes toke ye vp?", "dra": "Do you not yet understand, neither do you remember the five loaves among five thousand men, and how many baskets you took up?", "bbe": "Do you still not see, or keep in mind the five cakes of bread of the five thousand, and the number of baskets you took up?", "geneva": "Doe ye not yet perceiue, neither remember the fiue loaues, when there were fiue thousand men, and how many baskets tooke ye vp?", "wycliffe": "Yit `vndurstonden not ye, nether han mynde of fyue looues in to fyue thousynde of men, and hou many cofyns ye token?", "rotherham": "Not yet, perceive ye, neither remember,—The five loaves of the five thousand, and how many baskets ye received?", "weymouth": "Do you not yet understand? nor even remember the 5,000 and the five loaves, and how many basketfuls you carried away,", "darby": "Do ye not yet understand nor remember the five loaves of the five thousand, and how many hand-baskets ye took [up]?", "twenty": "Do not you yet see, nor remember the five loaves for the five thousand, and how many baskets you took away?", "acv": "Do ye not yet understand, nor remember the five loaves of the five thousand, and how many baskets ye took up,", "anderson": "Do you not yet understand, nor remember the five loaves of the five thousand, and how many baskets you took up?", "haweis": "Do you not consider, nor remember the five loaves among the five thousand, and how many baskets ye took up?", "noyes": "Do ye not yet understand, nor remember the five loaves of the five thousand, and how many baskets ye took up?", "webster": "Do ye not yet understand, neither remember the five loaves of the five thousand, and how many baskets ye took up?", "vulgate": "nondum intellegitis neque recordamini quinque panum quinque milium hominum et quot cofinos sumpsistis;"}}, {"v": 10, "ref": "16:10", "o": "οὐδὲ τοὺς ἑπτὰ ἄρτους τῶν τετρακισχιλίων καὶ πόσας σπυρίδας ἐλάβετε;", "en": {"kjv": "Neither the seven loaves of the four thousand, and how many baskets ye took up?", "web": "Nor the seven loaves for the four thousand, and how many baskets you took up?", "bsb": "Or the seven loaves for the four thousand, and how many basketfuls you gathered?", "asv": "Neither the seven loaves of the four thousand, and how many baskets ye took up?", "ylt": "nor the seven loaves of the four thousand, and how many baskets ye took up?", "tyndale": "Nether the .vii. loves when there were .iiiii.M. and how many baskettes toke ye vp?", "dra": "Nor the seven loaves, among four thousand men, and how many baskets you took up?", "bbe": "Or the seven cakes of bread of the four thousand, and the number of baskets you took up?", "geneva": "Neither the seuen loaues when there were foure thousande men, and howe many baskets tooke ye vp?", "wycliffe": "nether of seuene looues in to foure thousynde of men, and hou many lepis ye token?", "rotherham": "Nor the seven loaves of the four thousand, and how many hampers ye received?", "weymouth": "nor the 4,000 and the seven loaves, and how many hampers you carried away?", "darby": "nor the seven loaves of the four thousand, and how many baskets ye took [up]?", "twenty": "Nor yet the seven loaves for the four thousand, and how many basketfuls you took away?", "acv": "nor the seven loaves of the four thousand, and how many hampers ye took up?", "anderson": "Nor the seven loaves of the four thousand, and how many baskets you took up?", "haweis": "Nor the seven loaves among the four thousand, and how many baskets ye took up?", "noyes": "Nor the seven loaves of the four thousand, and how many baskets ye took up?", "webster": "Neither the seven loaves of the four thousand, and how many baskets ye took up?", "vulgate": "neque septem panum quattuor milium hominum et quot sportas sumpsistis;"}}, {"v": 11, "ref": "16:11", "o": "πῶς οὐ νοεῖτε ὅτι οὐ περὶ ⸀ἄρτων εἶπον ὑμῖν; ⸂προσέχετε δὲ⸃ ἀπὸ τῆς ζύμης τῶν Φαρισαίων καὶ Σαδδουκαίων.", "en": {"kjv": "How is it that ye do not understand that I spake it not to you concerning bread, that ye should beware of the leaven of the Pharisees and of the Sadducees?", "web": "How is it that you don’t perceive that I didn’t speak to you concerning bread? But beware of the yeast of the Pharisees and Sadducees.”", "bsb": "How do you not understand that I was not telling you about bread? But beware of the leaven of the Pharisees and Sadducees.”", "asv": "How is it that ye do not perceive that I spake not to you concerning bread? But beware of the leaven of the Pharisees and Sadducees.", "ylt": "how do ye not understand that I did not speak to you of bread--to take heed of the leaven of the Pharisees and Sadducees?'", "tyndale": "Why perceave ye not then yt I spake not vnto you of breed whe I sayde beware of the leven of the Pharises and of the Saduces?", "dra": "Why do you not understand that it was not concerning bread I said to you: Beware of the leaven of the Pharisees and Sadducees?", "bbe": "How is it that you do not see that I was not talking to you about bread, but about keeping away from the leaven of the Pharisees and Sadducees?", "geneva": "Why perceiue ye not that I said not vnto you concerning bread, that ye shoulde beware of the leauen of the Pharises and Sadduces?", "wycliffe": "Whi vndurstonden ye not, for Y seide not to you of breed, Be ye war of the sourdowy of Farisees and of Saducees?", "rotherham": "How is it ye perceive not, that, not concerning loaves, spake I unto you,—but beware of the leaven, of the Pharisees and Sadducees?", "weymouth": "How is it you do not understand that it was not about bread that I spoke to you? But beware of the yeast of the Pharisees and Sadducees.\"", "darby": "How do ye not understand that [it was] not concerning bread I said to you, Beware of the leaven of the Pharisees and Sadducees?", "twenty": "How is it that you do not see that I was not speaking about bread? Be on your guard against the leaven of the Pharisees and Sadducees.”", "acv": "How do ye not understand that I spoke to you not about bread, to beware of the leaven of the Pharisees and Sadducees?", "anderson": "How is it that you do not understand, that I did not speak of bread when I commanded you to beware of the leaven of the Pharisees and of the Sadducees?", "haweis": "How is it that ye do not understand, that I spake not to you of bread, to beware of the leaven of the Pharisees and of the Sadducees?", "noyes": "How is it that ye do not understand, that I spoke not to you of loaves? But [I said] Beware of the leaven of the Pharisees and Sadducees.", "webster": "How is it that ye do not understand that I spoke not to you concerning bread, that ye should beware of the leaven of the Pharisees and of the Sadducees?", "vulgate": "quare non intellegitis quia non de pane dixi vobis cavete a fermento Pharisaeorum et Sadducaeorum;"}}, {"v": 12, "ref": "16:12", "o": "τότε συνῆκαν ὅτι οὐκ εἶπεν προσέχειν ἀπὸ τῆς ζύμης ⸂τῶν ἄρτων⸃ ἀλλὰ ἀπὸ τῆς διδαχῆς τῶν Φαρισαίων καὶ Σαδδουκαίων.", "en": {"kjv": "Then understood they how that he bade them not beware of the leaven of bread, but of the doctrine of the Pharisees and of the Sadducees.", "web": "Then they understood that he didn’t tell them to beware of the yeast of bread, but of the teaching of the Pharisees and Sadducees.", "bsb": "Then they understood that He was not telling them to beware of the leaven used in bread, but of the teaching of the Pharisees and Sadducees.", "asv": "Then understood they that he bade them not beware of the leaven of bread, but of the teaching of the Pharisees and Sadducees.", "ylt": "Then they understood that he did not say to take heed of the leaven of the bread, but of the teaching, of the Pharisees and Sadducees.", "tyndale": "The vnderstode they how that he bad not them beware of the leven of breed: but of the doctrine of the Pharises and of the Saduces.", "dra": "Then they understood that he said not that they should beware of the leaven of bread, but of the doctrine of the Pharisees and Sadducees.", "bbe": "Then they saw that it was not the leaven of bread which he had in mind, but the teaching of the Pharisees and Sadducees.", "geneva": "Then vnderstood they that he had not said that they should beware of the leauen of bread, but of the doctrine of the Pharises, and Sadduces.", "wycliffe": "Thanne thei vndurstooden, that he seide not to be war of sourdowy of looues, but of the techyng of Farisees and Saducees.", "rotherham": "Then, understood they that he did not bid them beware of [the] leaven [of loaves] but of, the teaching, of the Pharisees and Sadducees.", "weymouth": "Then they perceived that He had not warned them against bread-yeast, but against the teaching of the Pharisees and Sadducees.", "darby": "Then they comprehended that he did not speak of being beware of the leaven of bread, but of the doctrine of the Pharisees and Sadducees.", "twenty": "Then they understood that he had told them to be on their guard, not against the leaven of bread, but against the teaching of the Pharisees and Sadducees.", "acv": "Then they understood that he said not to beware of the leaven of bread, but of the teaching of the Pharisees and Sadducees.", "anderson": "Then they understood that he did not bid them beware of the leaven of bread, but of the teaching of the Pharisees and of the Sadducees.", "haweis": "Then understood they, that he spake about abstaining not from the leaven in the bread, but from the doctrine of the Pharisees and the Sadducees.", "noyes": "Then they understood, that he did not bid them beware of the leaven of the Pharisees and Sadducees, but of the teaching of the Pharisees and Sadducees.", "webster": "Then they understood that he did not caution them against the leaven of bread, but against the doctrine of the Pharisees and of the Sadducees.", "vulgate": "tunc intellexerunt quia non dixerit cavendum a fermento panum sed a doctrina Pharisaeorum et Sadducaeorum;"}}, {"v": 13, "ref": "16:13", "o": "Ἐλθὼν δὲ ὁ Ἰησοῦς εἰς τὰ μέρη Καισαρείας τῆς Φιλίππου ἠρώτα τοὺς μαθητὰς αὐτοῦ λέγων· ⸀Τίνα λέγουσιν οἱ ἄνθρωποι εἶναι τὸν υἱὸν τοῦ ἀνθρώπου;", "en": {"kjv": "When Jesus came into the coasts of Cesarea Philippi, he asked his disciples, saying, Whom do men say that I the Son of man am?", "web": "Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying, “Who do men say that I, the Son of Man, am?”", "bsb": "When Jesus came to the region of Caesarea Philippi, He questioned His disciples: “Who do people say the Son of Man is?”", "asv": "Now when Jesus came into the parts of Cæsarea Philippi, he asked his disciples, saying, Who do men say that the Son of man is?", "ylt": "And Jesus, having come to the parts of Caesarea Philippi, was asking his disciples, saying, `Who do men say me to be--the Son of Man?'", "tyndale": "When Iesus cam in to the costes of the cite which is called Cesarea Philippi he axed his disciples sayinge: whom do men saye yt I the sonne of ma am?", "dra": "And Jesus came into the quarters of Cesarea Philippi: and he asked his disciples, saying: Whom do men say that the Son of man is?", "bbe": "Now when Jesus had come into the parts of Caesarea Philippi, he said, questioning his disciples, Who do men say that the Son of man is?", "geneva": "Nowe when Iesus came into the coastes of Cesarea Philippi, hee asked his disciples, saying, Whome doe men say that I, the sonne of man am?", "wycliffe": "And Jhesus cam in to the parties of Cesarie of Filip, and axide hise disciplis, and seide, Whom seien men to be mannus sone?", "rotherham": "And, Jesus coming into the parts of Caesarea of Philip, began questioning his disciples, saying—Who are men saying that, the Son of Man, is?", "weymouth": "When He arrived in the neighbourhood of Caesarea Philippi, Jesus questioned His disciples. \"Who do people say that the Son of Man is?\" He asked.", "darby": "But when Jesus was come into the parts of Caesarea-Philippi, he demanded of his disciples, saying, Who do men say that I the Son of man am?", "twenty": "On coming into the neighbourhood of Caesarea Philippi, Jesus asked his disciples this question — “Who do people say that the Son of Man is?”", "acv": "Now when Jesus came into the regions of Caesarea Philippi, he asked his disciples, saying, Who do men say I, the Son of man, am?", "anderson": "When Jesus came into the regions of Cæsarea Philippi, he asked his disciples, saying: Who do men say that I, the Son of man, am?", "haweis": "Then Jesus coming into the parts of Caesarea Philippi, questioned his disciples, saying, Who do men say that I am? The Son of Man?", "noyes": "And Jesus, having come into the region of Caesarea Philippi, asked his disciples, saying, Who do men say that the Son of man is?", "webster": "When Jesus came into the borders of Cesarea Phillippi, he asked his disciples, saying, Who do men say that I the Son of man am?", "vulgate": "venit autem Iesus in partes Caesareae Philippi et interrogabat discipulos suos dicens quem dicunt homines esse Filium hominis;"}}, {"v": 14, "ref": "16:14", "o": "οἱ δὲ εἶπαν· Οἱ μὲν Ἰωάννην τὸν βαπτιστήν, ἄλλοι δὲ Ἠλίαν, ἕτεροι δὲ Ἰερεμίαν ἢ ἕνα τῶν προφητῶν.", "en": {"kjv": "And they said, Some say that thou art John the Baptist: some, Elias; and others, Jeremias, or one of the prophets.", "web": "They said, “Some say John the Baptizer, some, Elijah, and others, Jeremiah, or one of the prophets.”", "bsb": "They replied, “Some say John the Baptist; others say Elijah; and still others, Jeremiah or one of the prophets.”", "asv": "And they said, Some say John the Baptist; some, Elijah; and others, Jeremiah, or one of the prophets.", "ylt": "and they said, `Some, John the Baptist, and others, Elijah, and others, Jeremiah, or one of the prophets.'", "tyndale": "They saide some saye yt thou arte Ihon Baptist some Helias some Ieremias or one of ye prophetes.", "dra": "But they said: Some John the Baptist, and other some Elias, and others Jeremias, or one of the prophets.", "bbe": "And they said, Some say, John the Baptist; some, Elijah; and others, Jeremiah, or one of the prophets.", "geneva": "And they said, Some say, Iohn Baptist: and some, Elias: and others, Ieremias, or one of the Prophets.", "wycliffe": "And thei seiden, Summe Joon Baptist; othere Elie; and othere Jeremye, or oon of the prophetis.", "rotherham": "And, they, said—Some, indeed, John the Immerser, and, others, Elijah,—but, others, Jeremiah, or one of the prophets.", "weymouth": "\"Some say John the Baptist,\" they replied; \"others Elijah; others Jeremiah or one of the Prophets.\"", "darby": "And they said, Some, John the baptist; and others, Elias; and others again, Jeremias or one of the prophets.", "twenty": "“Some say John the Baptist,” they answered, “Others, however, say that he is Elijah, while others again say Jeremiah, or one of the Prophets.”", "acv": "And they said, Some, John the immerser, others, Elijah, but others, Jeremiah, or one of the prophets.", "anderson": "They replied: Some say that thou art John the Immerser; others, Elijah; others, Jeremiah, or one of the prophets.", "haweis": "But they replied, Some, that thou art John the Baptist; but others, Elias; and others again, Jeremiah, or one of the prophets.", "noyes": "And they said, Some, John the Baptist; but some, Elijah; and others, Jeremiah, or one of the prophets.", "webster": "And they said, Some [say that thou art] John the Baptist: some Elijah; and others, Jeremiah, or one of the prophets.", "vulgate": "at illi dixerunt alii Iohannem Baptistam alii autem Heliam alii vero Hieremiam aut unum ex prophetis;"}}, {"v": 15, "ref": "16:15", "o": "λέγει αὐτοῖς· Ὑμεῖς δὲ τίνα με λέγετε εἶναι;", "en": {"kjv": "He saith unto them, But whom say ye that I am?", "web": "He said to them, “But who do you say that I am?”", "bsb": "“But what about you?” Jesus asked. “Who do you say I am?”", "asv": "He saith unto them, But who say ye that I am?", "ylt": "He saith to them, `And ye--who do ye say me to be?'", "tyndale": "He sayde vnto the: but who saye ye yt I am?", "dra": "Jesus saith to them: But whom do you say that I am?", "bbe": "He says to them, But who do you say that I am?", "geneva": "He said vnto them, But whome say ye that I am?", "wycliffe": "Jhesus seide to hem, But whom seien ye me to be?", "rotherham": "He saith unto them—But who say, ye, that I am?", "weymouth": "\"But you, who do you say that I am?\" He asked again.", "darby": "He says to them, But ye, who do ye say that I am?", "twenty": "“But you,” he said, “who do you say that I am?”", "acv": "He says to them, But who say ye, I am?", "anderson": "He said to them: But who say you that I am?", "haweis": "He saith unto them, But who do ye say that I am?", "noyes": "He saith to them, But who do ye say that I am?", "webster": "He saith to them, But who say ye that I am?", "vulgate": "dicit illis vos autem quem me esse dicitis;"}}, {"v": 16, "ref": "16:16", "o": "ἀποκριθεὶς δὲ Σίμων Πέτρος εἶπεν· Σὺ εἶ ὁ χριστὸς ὁ υἱὸς τοῦ θεοῦ τοῦ ζῶντος.", "en": {"kjv": "And Simon Peter answered and said, Thou art the Christ, the Son of the living God.", "web": "Simon Peter answered, “You are the Christ, the Son of the living God.”", "bsb": "Simon Peter answered, “You are the Christ, the Son of the living God.”", "asv": "And Simon Peter answered and said, Thou art the Christ, the Son of the living God.", "ylt": "and Simon Peter answering said, `Thou art the Christ, the Son of the living God.'", "tyndale": "Simo Peter answered and sayde: Thou arte Christ ye sonne of the lyvinge God.", "dra": "Simon Peter answered and said: Thou art Christ, the Son of the living God.", "bbe": "And Simon Peter made answer and said, You are the Christ, the Son of the living God.", "geneva": "Then Simon Peter answered, and said, Thou art that Christ, the Sonne of the liuing God.", "wycliffe": "Symount Petre answeride, and seide, Thou art Crist, the sone of God lyuynge.", "rotherham": "And, Simon Peter, answering, said—Thou, art the Christ, the Son of the Living God.", "weymouth": "\"You,\" replied Simon Peter, \"are the Christ, the Son of the ever-living God.\"", "darby": "And Simon Peter answering said, Thou art the Christ, the Son of the livingGod.", "twenty": "And to this Simon Peter answered: “You are the Christ, the Son of the Living God.”", "acv": "And Simon Peter having answered, said, Thou are the Christ, the Son of the living God.", "anderson": "Simon Peter answered and said: Thou art the Christ, the Son of the living God.", "haweis": "Then Simon Peter answering said, Thou art the Messiah, the Son of the living God.", "noyes": "And Simon Peter answering said, Thou art the Christ, the Son of the living God.", "webster": "And Simon Peter answered and said, Thou art the Christ, the Son of the living God.", "vulgate": "respondens Simon Petrus dixit tu es Christus Filius Dei vivi;"}}, {"v": 17, "ref": "16:17", "o": "⸂ἀποκριθεὶς δὲ⸃ ὁ Ἰησοῦς εἶπεν αὐτῷ· Μακάριος εἶ, Σίμων Βαριωνᾶ, ὅτι σὰρξ καὶ αἷμα οὐκ ἀπεκάλυψέν σοι ἀλλ’ ὁ πατήρ μου ὁ ἐν τοῖς οὐρανοῖς·", "en": {"kjv": "And Jesus answered and said unto him, Blessed art thou, Simon Bar–jona: for flesh and blood hath not revealed it unto thee, but my Father which is in heaven.", "web": "Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven.", "bsb": "Jesus replied, “Blessed are you, Simon son of Jonah! For this was not revealed to you by flesh and blood, but by My Father in heaven.", "asv": "And Jesus answered and said unto him, Blessed art thou, Simon Bar-Jonah: for flesh and blood hath not revealed it unto thee, but my Father who is in heaven.", "ylt": "And Jesus answering said to him, `Happy art thou, Simon Bar-Jona, because flesh and blood did not reveal it to thee, but my Father who is in the heavens.", "tyndale": "And Iesus answered and sayde to him: happy arte thou Simon the sonne of Ionas for fleshe and bloud hath not opened vnto the yt but my father which is in heve.", "dra": "And Jesus answering said to him: Blessed art thou, Simon Bar-Jona: because flesh and blood hath not revealed it to thee, but my Father who is in heaven.", "bbe": "And Jesus made answer and said to him, A blessing on you, Simon Bar-jonah: because this knowledge has not come to you from flesh and blood, but from my Father in heaven.", "geneva": "And Iesus answered, and saide to him, Blessed art thou, Simon, the sonne of Ionas: for flesh and blood hath not reueiled it vnto thee, but my Father which is in heauen.", "wycliffe": "Jhesus answeride, and seide to him, Blessid art thou, Symount Bariona; for fleisch and blood schewide not to thee, but my fadir that is in heuenes.", "rotherham": "And Jesus, answering, said to him—Happy, art thou, Simon Bar-yona,—because, flesh and blood, revealed it not unto thee, but my Father who is in the heavens.", "weymouth": "\"Blessed are you, Simon Bar-jonah,\" said Jesus; \"for mere human nature has not revealed this to you, but my Father in Heaven.", "darby": "And Jesus answering said to him, Blessed art thou, Simon Bar-jona, for flesh and blood has not revealed [it] to thee, but my Father who is in the heavens.", "twenty": "“Blessed are you, Simon, Son of Jonah,” Jesus replied. “For no human being has revealed this to you, but my Father who is in Heaven.", "acv": "And having answered, Jesus said to him, Blessed are thou, Simon Bar-jonah, because flesh and blood has not revealed it to thee, but my Father in the heavens.", "anderson": "And Jesus answered and said to him: Blessed are you, Simon, son of Jonah; for flesh and blood did not reveal this to you, but my Father who is in heaven.", "haweis": "And Jesus replying, said to him, Blessed art thou, Simon Barjona; for flesh and blood hath not revealed this to thee, but my Father, who is in heaven.", "noyes": "And Jesus answering said to him, Blessed art thou, Simon, son of Jonah; for flesh and blood did not reveal it to thee, but my Father who is in heaven.", "webster": "And Jesus answered and said to him, Blessed art thou, Simon-Barjona: for flesh and blood hath not revealed [it] to thee, but my Father who is in heaven.", "vulgate": "respondens autem Iesus dixit ei beatus es Simon Bar Iona quia caro et sanguis non revelavit tibi sed Pater meus qui in caelis est;"}}, {"v": 18, "ref": "16:18", "o": "κἀγὼ δέ σοι λέγω ὅτι σὺ εἶ Πέτρος, καὶ ἐπὶ ταύτῃ τῇ πέτρᾳ οἰκοδομήσω μου τὴν ἐκκλησίαν, καὶ πύλαι ᾅδου οὐ κατισχύσουσιν αὐτῆς·", "en": {"kjv": "And I say also unto thee, That thou art Peter, and upon this rock I will build my church; and the gates of hell shall not prevail against it.", "web": "I also tell you that you are Peter,and on this rock I will build my assembly, and the gates of Hadeswill not prevail against it.", "bsb": "And I tell you that you are Peter, and on this rock I will build My church, and the gates of Hades will not prevail against it.", "asv": "And I also say unto thee, that thou art Peter, and upon this rock I will build my church; and the gates of Hades shall not prevail against it.", "ylt": "`And I also say to thee, that thou art a rock, and upon this rock I will build my assembly, and gates of Hades shall not prevail against it;", "tyndale": "And I saye also vnto the yt thou arte Peter: and apon this rocke I wyll bylde my congregacion. And the gates of hell shall not prevayle ageynst it.", "dra": "And I say to thee: That thou art Peter; and upon this rock I will build my church, and the gates of hell shall not prevail against it.", "bbe": "And I say to you that you are Peter, and on this rock will my church be based, and the doors of hell will not overcome it.", "geneva": "And I say also vnto thee, that thou art Peter, and vpon this rocke I will builde my Church: and ye gates of hell shall not ouercome it.", "wycliffe": "And Y seie to thee, that thou art Petre, and on this stoon Y schal bilde my chirche, and the yatis of helle schulen not haue miyt ayens it.", "rotherham": "And, I also, unto thee, say—Thou, art Peter,—and, upon this rock, will I build my assembly, and, the gates of hades, shall not prevail against it.", "weymouth": "And I declare to you that you are Peter, and that upon this Rock I will build my Church, and the might of Hades shall not triumph over it.", "darby": "And I also, I say unto thee that thou art Peter, and on this rock I will build my assembly, and hades' gates shall not prevail against it.", "twenty": "Yes, and I say to you, Your name is ‘Peter — a Rock, and on this rock I will build my Church, and the Powers of the Place of Death shall not prevail over it.", "acv": "And I also say to thee, that thou are Peter, and upon this rock I will build my church, and the gates of Hades will not prevail against it.", "anderson": "And I say to you, That you are Peter, and on this rock I will build my church: and the gates of hades shall not prevail against it.", "haweis": "And I tell thee, That thou art Peter, and upon this rock will I build my church, and the gates of hell shall not prevail against it.", "noyes": "And I on my part say to thee, that thou art Peter, a rock, and on this rock will I build my church, and the gates of the underworld shall not prevail against it.", "webster": "And I say also to thee, that thou art Peter, and upon this rock I will build my church: and the gates of hell shall not prevail against it.", "vulgate": "et ego dico tibi quia tu es Petrus et super hanc petram aedificabo ecclesiam meam et portae inferi non praevalebunt adversum eam;"}}, {"v": 19, "ref": "16:19", "o": "⸀δώσω σοι τὰς ⸀κλεῖδας τῆς βασιλείας τῶν οὐρανῶν, καὶ ὃ ⸀ἐὰν δήσῃς ἐπὶ τῆς γῆς ἔσται δεδεμένον ἐν τοῖς οὐρανοῖς, καὶ ὃ ⸁ἐὰν λύσῃς ἐπὶ τῆς γῆς ἔσται λελυμένον ἐν τοῖς οὐρανοῖς.", "en": {"kjv": "And I will give unto thee the keys of the kingdom of heaven: and whatsoever thou shalt bind on earth shall be bound in heaven: and whatsoever thou shalt loose on earth shall be loosed in heaven.", "web": "I will give to you the keys of the Kingdom of Heaven, and whatever you bind on earth will have been bound in heaven; and whatever you release on earth will have been released in heaven.”", "bsb": "I will give you the keys of the kingdom of heaven. Whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven.”", "asv": "I will give unto thee the keys of the kingdom of heaven: and whatsoever thou shalt bind on earth shall be bound in heaven; and whatsoever thou shalt loose on earth shall be loosed in heaven.", "ylt": "and I will give to thee the keys of the reign of the heavens, and whatever thou mayest bind upon the earth shall be having been bound in the heavens, and whatever thou mayest loose upon the earth shall be having been loosed in the heavens.'", "tyndale": "And I wyll geve vnto the the keyes of the kyngdom of heven: and whatsoever thou byndest vpon erth shall be bounde in heven: and whatsoever thou lowsest on erthe shalbe lowsed in heven.", "dra": "And I will give to thee the keys of the kingdom of heaven. And whatsoever thou shalt bind upon earth, it shall be bound also in heaven: and whatsoever thou shalt loose on earth, it shall be loosed also in heaven.", "bbe": "I will give to you the keys of the kingdom of heaven: and whatever is fixed by you on earth will be fixed in heaven: and whatever you make free on earth will be made free in heaven.", "geneva": "And I will giue vnto thee the keyes of the kingdome of heauen, and whatsoeuer thou shalt binde vpon earth, shalbe bound in heauen: and whatsoeuer thou shalt loose on earth, shall be loosed in heauen.", "wycliffe": "And to thee Y shal yyue the keies of the kingdom of heuenes; and what euer thou shalt bynde on erthe, schal be boundun also in heuenes; and what euer thou schalt vnbynde on erthe, schal be vnbounden also in heuenes.", "rotherham": "I will give thee, the keys of the kingdom of the heavens,—and, whatsoever thou shalt bind upon the earth, shall be bound in the heavens, and, whatsoever thou shalt loose upon the earth, shall be loosed in the heavens.", "weymouth": "I will give you the keys of the Kingdom of the Heavens; and whatever you bind on earth shall remain bound in Heaven, and whatever you loose on earth shall remain loosed in Heaven.\"", "darby": "And I will give to thee the keys of the kingdom of the heavens; and whatsoever thou mayest bind upon the earth shall be bound in the heavens; and whatsoever thou mayest loose on the earth shall be loosed in the heavens.", "twenty": "I will give you the keys of the Kingdom of Heaven. Whatever you forbid on earth will be held in Heaven to be forbidden, and whatever you allow on earth will be held in Heaven to be allowed.”", "acv": "And I will give to thee the keys of the kingdom of the heavens, and whatever thou may bind on earth will be what is bound in the heavens, and whatever thou may loose on the earth will be what is loosed in the heavens.", "anderson": "And I will give to you the keys of the kingdom of heaven; and whatever you shall bind on earth, shall be bound in heaven; and whatever you shall loose on earth, shall be loosed in heaven.", "haweis": "And I will give thee the keys of the kingdom of heaven: and whatsoever thou shalt bind on earth shall be bound in heaven; and whatsoever thou shalt loose on earth shall be loosed in heaven.", "noyes": "I will give thee the keys of the kingdom of heaven; and whatever thou shalt bind on earth will be bound in heaven; and whatever thou shalt loose on earth will be loosed in heaven.", "webster": "And I will give to thee the keys of the kingdom of heaven: and whatever thou shalt bind on earth, shall be bound in heaven; and whatever thou shalt loose on earth, shall be loosed in heaven.", "vulgate": "et tibi dabo claves regni caelorum et quodcumque ligaveris super terram erit ligatum in caelis et quodcumque solveris super terram erit solutum in caelis;"}}, {"v": 20, "ref": "16:20", "o": "τότε ⸀διεστείλατο τοῖς ⸀μαθηταῖς ἵνα μηδενὶ εἴπωσιν ὅτι αὐτός ⸀ἐστιν ὁ χριστός.", "en": {"kjv": "Then charged he his disciples that they should tell no man that he was Jesus the Christ.", "web": "Then he commanded the disciples that they should tell no one that he was Jesus the Christ.", "bsb": "Then He admonished the disciples not to tell anyone that He was the Christ.", "asv": "Then charged he the disciples that they should tell no man that he was the Christ.", "ylt": "Then did he charge his disciples that they may say to no one that he is Jesus the Christ.", "tyndale": "Then he charged his disciples yt they shulde tell no man yt he was Iesus Christ.", "dra": "Then he commanded his disciples, that they should tell no one that he was Jesus the Christ.", "bbe": "Then he gave orders to the disciples to give no man word that he was the Christ.", "geneva": "Then hee charged his disciples, that they should tell no man that he was Iesus that Christ.", "wycliffe": "Thanne he comaundide to hise disciplis, that thei schulden seie to no man, that he was Crist.", "rotherham": "Then, straitly charged he the disciples, lest, to any man, they should say—He, is, the Christ.", "weymouth": "Then He urged His disciples to tell no one that He was the Christ.", "darby": "Then he enjoined on his disciples that they should say to no man that he was the Christ.", "twenty": "Then he charged his disciples not to tell any one that he was the Christ.", "acv": "Then he commanded his disciples that they should tell no man that he is Jesus, the Christ.", "anderson": "Then he charged his disciples to tell no one that he was the Christ.", "haweis": "Then he commanded his disciples, that they should tell no man that he was Jesus the Messiah.", "noyes": "Then he charged the disciples to tell no one that he was the Christ.", "webster": "Then he charged his disciples that they should tell no man that he was Jesus the Christ.", "vulgate": "tunc praecepit discipulis suis ut nemini dicerent quia ipse esset Iesus Christus;"}}, {"v": 21, "ref": "16:21", "o": "Ἀπὸ τότε ἤρξατο ⸂ὁ Ἰησοῦς⸃ δεικνύειν τοῖς μαθηταῖς αὐτοῦ ὅτι δεῖ αὐτὸν ⸂εἰς Ἱεροσόλυμα ἀπελθεῖν⸃ καὶ πολλὰ παθεῖν ἀπὸ τῶν πρεσβυτέρων καὶ ἀρχιερέων καὶ γραμματέων καὶ ἀποκτανθῆναι καὶ τῇ τρίτῃ ἡμέρᾳ ἐγερθῆναι.", "en": {"kjv": "From that time forth began Jesus to shew unto his disciples, how that he must go unto Jerusalem, and suffer many things of the elders and chief priests and scribes, and be killed, and be raised again the third day.", "web": "From that time, Jesus began to show his disciples that he must go to Jerusalem and suffer many things from the elders, chief priests, and scribes, and be killed, and the third day be raised up.", "bsb": "From that time on Jesus began to show His disciples that He must go to Jerusalem and suffer many things at the hands of the elders, chief priests, and scribes, and that He must be killed and on the third day be raised to life.", "asv": "From that time began Jesus to show unto his disciples, that he must go unto Jerusalem, and suffer many things of the elders and chief priests and scribes, and be killed, and the third day be raised up.", "ylt": "From that time began Jesus to shew to his disciples that it is necessary for him to go away to Jerusalem, and to suffer many things from the elders, and chief priests, and scribes, and to be put to death, and the third day to rise.", "tyndale": "From yt tyme forth Iesus began to shewe vnto his disciples how yt he must go vnto Ierusalem and suffer many thinges of ye Elders and of ye hye prestes and of the scribes and must be killed and ryse agayne ye thirde daye.", "dra": "From that time Jesus began to shew to his disciples, that he must go to Jerusalem, and suffer many things from the ancients and scribes and chief priests, and be put to death, and the third day rise again.", "bbe": "From that time Jesus went on to make clear to his disciples how he would have to go up to Jerusalem, and undergo much at the hands of those in authority and the chief priests and scribes, and be put to death, and the third day come again from the dead.", "geneva": "From that time foorth Iesus beganne to shewe vnto his disciples, that he must goe vnto Hierusalem, and suffer many thinges of the Elders, and of the hie Priestes, and Scribes, and be slaine, and be raised againe the thirde day.", "wycliffe": "Fro that tyme Jhesus bigan to schewe to hise disciplis, that it bihofte hym go to Jerusalem, and suffre many thingis, of the eldere men, and of scribis, and princis of prestis; and be slayn, and the thridde dai to rise ayen.", "rotherham": "From that time, began Jesus Christ to be pointing out to his disciples that he must needs, into Jerusalem, go away, and, many things, suffer, from the elders and chief priests and scribes, and be slain,—and on, the third day, arise.", "weymouth": "From this time Jesus began to explain to His disciples that He must go to Jerusalem, and suffer much cruelty from the Elders and the High Priests and the Scribes, and be put to death, and on the third day be raised to life again.", "darby": "From that time Jesus began to shew to his disciples that he must go away to Jerusalem, and suffer many things from the elders and chief priests and scribes, and be killed, and the third day be raised.", "twenty": "At that time Jesus Christ began to explain to his disciples that he must go to Jerusalem, and undergo much suffering at the hands of the Councillors, and Chief Priests, and Teachers of the Law, and be put to death, and rise on the third day.", "acv": "From that time Jesus began to show his disciples that he must go to Jerusalem, and suffer many things from the elders, and chief priests, and scholars, and be killed, and the third day be raised up.", "anderson": "From that time Jesus began to tell his disciples plainly, that he must go to Jerusalem, and suffer many things from the elders, and the chief priests, and the scribes, and be put to death, and be raised again the third day.", "haweis": "From that time Jesus began to shew his disciples, that he must go to Jerusalem, and suffer many things of the elders, and of the chief-priests, and of the scribes, and be put to death, and the third day rise again.", "noyes": "From that time Jesus began to show to his disciples, that he must go to Jerusalem, and suffer many things from the elders and chief priests and scribes, and be put to death, and rise again on the third day.", "webster": "From that time forth Jesus began to show to his disciples, that he must go to Jerusalem, and suffer many things from the elders and chief priests, and scribes, and be killed, and be raised again the third day.", "vulgate": "exinde coepit Iesus ostendere discipulis suis quia oporteret eum ire Hierosolymam et multa pati a senioribus et scribis et principibus sacerdotum et occidi et tertia die resurgere;"}}, {"v": 22, "ref": "16:22", "o": "καὶ προσλαβόμενος αὐτὸν ὁ Πέτρος ἤρξατο ἐπιτιμᾶν αὐτῷ λέγων· Ἵλεώς σοι, κύριε· οὐ μὴ ἔσται σοι τοῦτο.", "en": {"kjv": "Then Peter took him, and began to rebuke him, saying, Be it far from thee, Lord: this shall not be unto thee.", "web": "Peter took him aside, and began to rebuke him, saying, “Far be it from you, Lord! This will never be done to you.”", "bsb": "Peter took Him aside and began to rebuke Him. “Far be it from You, Lord!” he said. “This shall never happen to You!”", "asv": "And Peter took him, and began to rebuke him, saying, Be it far from thee, Lord: this shall never be unto thee.", "ylt": "And having taken him aside, Peter began to rebuke him, saying, `Be kind to thyself, sir; this shall not be to thee;'", "tyndale": "But Peter toke him asyde and began to rebuke him sayinge: master faver thy sylfe this shall not come vnto the.", "dra": "And Peter taking him, began to rebuke him, saying: Lord, be it far from thee, this shall not be unto thee.", "bbe": "And Peter, protesting, said to him, Be it far from you, Lord; it is impossible that this will come about.", "geneva": "Then Peter tooke him aside, and began to rebuke him, saying, Master, pitie thy selfe: this shall not be vnto thee.", "wycliffe": "And Petre took hym, and bigan to blame him, and seide, Fer be it fro thee, Lord; this thing schal not be to thee.", "rotherham": "And, taking him aside, Peter began to rebuke him, saying—Mercy on thee Lord! In nowise, shall, this, befall thee.", "weymouth": "Then Peter took Him aside and began taking Him to task. \"Master,\" he said, \"God forbid; this will not be your lot.\"", "darby": "And Peter taking him to [him] began to rebuke him, saying, [God] be favourable to thee, Lord; this shall in no wise be unto thee.", "twenty": "But Peter took Jesus aside, and began to rebuke him. “Master,” he said, “please God that shall never be your fate!”", "acv": "And having taken him aside, Peter began to rebuke him, saying, Be merciful to thee, Lord. This will, no, not be to thee.", "anderson": "And Peter took him and began to rebuke him, saying: Be it far from thee, Lord: this shall not be to thee.", "haweis": "And Peter taking him aside, began to chide him, saying, Mercy on thee, Lord! this shall never be thy case.", "noyes": "Then Peter, taking him aside, began to rebuke him, saying, Be it far from thee, Lord! This shall not be to thee.", "webster": "Then Peter took him, and began to rebuke him, saying, Be it far from thee, Lord: this shall not be to thee.", "vulgate": "et adsumens eum Petrus coepit increpare illum dicens absit a te Domine non erit tibi hoc;"}}, {"v": 23, "ref": "16:23", "o": "ὁ δὲ στραφεὶς εἶπεν τῷ Πέτρῳ· Ὕπαγε ὀπίσω μου, Σατανᾶ· σκάνδαλον ⸂εἶ ἐμοῦ⸃, ὅτι οὐ φρονεῖς τὰ τοῦ θεοῦ ἀλλὰ τὰ τῶν ἀνθρώπων.", "en": {"kjv": "But he turned, and said unto Peter, Get thee behind me, Satan: thou art an offence unto me: for thou savourest not the things that be of God, but those that be of men.", "web": "But he turned, and said to Peter, “Get behind me, Satan! You are a stumbling block to me, for you are not setting your mind on the things of God, but on the things of men.”", "bsb": "But Jesus turned and said to Peter, “Get behind Me, Satan! You are a stumbling block to Me. For you do not have in mind the things of God, but the things of men.”", "asv": "But he turned, and said unto Peter, Get thee behind me, Satan: thou art a stumbling-block unto me: for thou mindest not the things of God, but the things of men.", "ylt": "and he having turned, said to Peter, `Get thee behind me, adversary! thou art a stumbling-block to me, for thou dost not mind the things of God, but the things of men.'", "tyndale": "Then tourned he aboute and sayde vnto Peter: come after me Satan thou offendest me because thou sauourest not godly thinges but wordly thinges", "dra": "Who turning, said to Peter: Go behind me, Satan, thou art a scandal unto me: because thou savourest not the things that are of God, but the things that are of men.", "bbe": "But he, turning to Peter, said, Get out of my way, Satan: you are a danger to me because your mind is not on the things of God, but on the things of men.", "geneva": "Then he turned backe, and said vnto Peter, Get thee behinde me, Satan: thou art an offence vnto me, because thou vnderstandest not the thinges that are of God, but the thinges that are of men.", "wycliffe": "And he turnede, and seide to Petre, Sathanas, go after me; thou art a sclaundre to me; for thou sauerist not tho thingis that ben of God, but tho thingis that ben of men.", "rotherham": "But, he, turning, said to Peter—Withdraw behind me, Satan! A snare, art thou of mine, because thou art not regarding the things of God, but the things of men.", "weymouth": "But He turned and said to Peter, \"Get behind me, Adversary; you are a hindrance to me, because your thoughts are not God's thoughts, but men's.\"", "darby": "But turning round, he said to Peter, Get away behind me, Satan; thou art an offence to me, for thy mind is not on the things that are ofGod, but on the things that are of men.", "twenty": "Jesus, however, turning to Peter, said: “Out of my way, Satan! You are a hindrance to me; for you look at things, not as God does, but as man does.”", "acv": "But having turned around, he said to Peter, Go thee behind me, Satan. Thou are my stumbling-block, because thou regard not the things of God, but the things of men.", "anderson": "But he turned and said to Peter: Get behind me, adversary; you are a snare to me: for you are not thinking of the things of God; but of the things of men.", "haweis": "Then turning from him, he said unto Peter, Get thee behind me Satan! thou art an offence to me: for thou dost not relish the things of God, but those of men.", "noyes": "But he turned and said to Peter, Get thee behind me, Satan! thou art my stumbling-block; for thy thoughts are not on the things of God, but on those of men.", "webster": "But he turned, and said to Peter, Get thee behind me, Satan; thou art an offense to me: for thou savorest not the things that are of God, but those that are of men.", "vulgate": "qui conversus dixit Petro vade post me Satana scandalum es mihi quia non sapis ea quae Dei sunt sed ea quae hominum;"}}, {"v": 24, "ref": "16:24", "o": "Τότε ὁ Ἰησοῦς εἶπεν τοῖς μαθηταῖς αὐτοῦ· Εἴ τις θέλει ὀπίσω μου ἐλθεῖν, ἀπαρνησάσθω ἑαυτὸν καὶ ἀράτω τὸν σταυρὸν αὐτοῦ καὶ ἀκολουθείτω μοι.", "en": {"kjv": "Then said Jesus unto his disciples, If any man will come after me, let him deny himself, and take up his cross, and follow me.", "web": "Then Jesus said to his disciples, “If anyone desires to come after me, let him deny himself, and take up his cross, and follow me.", "bsb": "Then Jesus told His disciples, “If anyone wants to come after Me, he must deny himself and take up his cross and follow Me.", "asv": "Then said Jesus unto his disciples, If any man would come after me, let him deny himself, and take up his cross, and follow me.", "ylt": "Then said Jesus to his disciples, `If any one doth will to come after me, let him disown himself, and take up his cross, and follow me,", "tyndale": "Iesus then sayde to his disciples. If eny man wyll folowe me leet him forsake him sylfe and take vp his crosse and folowe me.", "dra": "Then Jesus said to his disciples: If any man will come after me, let him deny himself, and take up his cross, and follow me.", "bbe": "Then Jesus said to his disciples, If any man would come after me, let him give up all, and take up his cross, and come after me.", "geneva": "Iesus then saide to his disciples, If any man will follow me, let him forsake himselfe: and take vp his crosse, and follow me.", "wycliffe": "Thanne Jhesus seide to his disciplis, If ony man wole come after me, denye he hym silf, and take his cros, and sue me; for he that wole make his lijf saaf,", "rotherham": "Then, Jesus said unto his disciples—If any one intendeth, after me, to come, let him deny himself, and take up his cross, and be following me;", "weymouth": "Then Jesus said to His disciples, \"If any one desires to follow me, let him renounce self and take up his cross, and so be my follower.", "darby": "Then Jesus said to his disciples, If any one desires to come after me, let him deny himself and take up his cross and follow me.", "twenty": "Then Jesus said to his disciples: “If any man wishes to walk in my steps, let him renounce self, and take up his cross, and follow me.", "acv": "Then Jesus said to his disciples, If any man wants to come behind me, let him deny himself, and take up his cross, and follow me.", "anderson": "Then Jesus said to his disciples: If any one determines to come after me, let him deny himself, and take up his cross, and follow me.", "haweis": "Then said Jesus to his disciples, If any man will come after me, let him deny himself, and take up his cross, and follow me.", "noyes": "Then Jesus said to his disciples, If any one chooseth to come after me, let him deny himself, and take up his cross, and follow me.", "webster": "Then said Jesus to his disciples, If any [man] will come after me, let him deny himself, and take up his cross, and follow me.", "vulgate": "tunc Iesus dixit discipulis suis si quis vult post me venire abneget semet ipsum et tollat crucem suam et sequatur me;"}}, {"v": 25, "ref": "16:25", "o": "ὃς γὰρ ⸀ἐὰν θέλῃ τὴν ψυχὴν αὐτοῦ σῶσαι ἀπολέσει αὐτήν· ὃς δ’ ἂν ἀπολέσῃ τὴν ψυχὴν αὐτοῦ ἕνεκεν ἐμοῦ εὑρήσει αὐτήν.", "en": {"kjv": "For whosoever will save his life shall lose it: and whosoever will lose his life for my sake shall find it.", "web": "For whoever desires to save his life will lose it, and whoever will lose his life for my sake will find it.", "bsb": "For whoever wants to save his life will lose it, but whoever loses his life for My sake will find it.", "asv": "For whosoever would save his life shall lose it: and whosoever shall lose his life for my sake shall find it.", "ylt": "for whoever may will to save his life, shall lose it, and whoever may lose his life for my sake shall find it,", "tyndale": "For who soever wyll save his lyfe shall loose it. And whosoever shall loose his lyfe for my sake shall fynde it.", "dra": "For he that will save his life, shall lose it: and he that shall lose his life for my sake, shall find it.", "bbe": "Because whoever has a desire to keep his life safe will have it taken from him; but whoever gives up his life because of me, will have it given back to him.", "geneva": "For whosoeuer will saue his life, shall lose it: and whosoeuer shall lose his life for my sake, shall finde it.", "wycliffe": "shal leese it; and he that schal leese his lijf for me, schal fynde it.", "rotherham": "For, whosoever intendeth, his life, to save, shall lose it,—but, whosoever shall lose his life, for my sake, shall find it.", "weymouth": "For whoever desires to save his life shall lose it, and whoever loses his life for my sake shall find it.", "darby": "For whosoever shall desire to save his life shall lose it; but whosoever shall lose his life for my sake shall find it.", "twenty": "For whoever wishes to save his life will lose it, and whoever, for my sake, loses his life shall find it.", "acv": "For whoever wants save his life will lose it, and whoever will lose his life for my sake will find it.", "anderson": "For whoever will save his life, shall lose it. But whoever will lose his life for my sake, shall find it.", "haweis": "For whosoever is desirous to preserve his life, shall lose it; but whosoever would lose his life for my sake, shall find it.", "noyes": "For whoever chooseth to save his life will lose it; and whoever shall lose his life for my sake will find it.", "webster": "For whoever will save his life, shall lose it: and whoever will lose his life for my sake, shall find it.", "vulgate": "qui enim voluerit animam suam salvam facere perdet eam qui autem perdiderit animam suam propter me inveniet eam;"}}, {"v": 26, "ref": "16:26", "o": "τί γὰρ ⸀ὠφεληθήσεται ἄνθρωπος ἐὰν τὸν κόσμον ὅλον κερδήσῃ τὴν δὲ ψυχὴν αὐτοῦ ζημιωθῇ; ἢ τί δώσει ἄνθρωπος ἀντάλλαγμα τῆς ψυχῆς αὐτοῦ;", "en": {"kjv": "For what is a man profited, if he shall gain the whole world, and lose his own soul? or what shall a man give in exchange for his soul?", "web": "For what will it profit a man, if he gains the whole world, and forfeits his life? Or what will a man give in exchange for his life?", "bsb": "What will it profit a man if he gains the whole world, yet forfeits his soul? Or what can a man give in exchange for his soul?", "asv": "For what shall a man be profited, if he shall gain the whole world, and forfeit his life? or what shall a man give in exchange for his life?", "ylt": "for what is a man profited if he may gain the whole world, but of his life suffer loss? or what shall a man give as an exchange for his life?", "tyndale": "What shall it proffet a man though he shulde wynne all the whoole worlde: yf he loose his owne soule? Or els what shall a man geve to redeme his soule agayne with all?", "dra": "For what doth it profit a man, if he gain the whole world and suffer the loss of his own soul? Or what exchange shall a man give for his soul?", "bbe": "For what profit has a man, if he gets all the world with the loss of his life? or what will a man give in exchange for his life?", "geneva": "For what shall it profite a man though he should winne the whole worlde, if hee lose his owne soule? or what shall a man giue for recompence of his soule?", "wycliffe": "For what profitith it to a man, if he wynne al the world, and suffre peiryng of his soule? or what chaunging schal a man yyue for his soule?", "rotherham": "For what shall a man be profited, though, the whole world, he gain, and, his life, he forfeit? Or what shall a man give, in exchange for his life?", "weymouth": "Why, what benefit will it be to a man if he gains the whole world but forfeits his life? Or what shall a man give to buy back his life?", "darby": "For what does a man profit, if he should gain the whole world and suffer the loss of his soul? or what shall a man give in exchange for his soul?", "twenty": "What good will it do a man to gain the whole world, if he forfeits his life? or what will a man give that is of equal value with his life?", "acv": "For what does it profit a man, if he should gain the whole world, and lose his soul? Or what will a man give in exchange for his soul?", "anderson": "For what is a man profited, if he gain the whole world, but lose his own life? Or, what will a man give as the ransom of his life?", "haweis": "For what would a man be advantaged, though he could gain the whole world, if he should suffer the loss of his soul? or what will a man give as the ransom for his soul?", "noyes": "For what will a man be profited, if be gain the whole world, and forfeit his life? or what shall a man give as an exchange for his life?", "webster": "For what is a man profited, if he shall gain the whole world, and lose his own soul? or what shall a man give in exchange for his soul?", "vulgate": "quid enim prodest homini si mundum universum lucretur animae vero suae detrimentum patiatur aut quam dabit homo commutationem pro anima sua;"}}, {"v": 27, "ref": "16:27", "o": "μέλλει γὰρ ὁ υἱὸς τοῦ ἀνθρώπου ἔρχεσθαι ἐν τῇ δόξῃ τοῦ πατρὸς αὐτοῦ μετὰ τῶν ἀγγέλων αὐτοῦ, καὶ τότε ἀποδώσει ἑκάστῳ κατὰ τὴν πρᾶξιν αὐτοῦ.", "en": {"kjv": "For the Son of man shall come in the glory of his Father with his angels; and then he shall reward every man according to his works.", "web": "For the Son of Man will come in the glory of his Father with his angels, and then he will render to everyone according to his deeds.", "bsb": "For the Son of Man will come in His Father’s glory with His angels, and then He will repay each one according to what he has done.", "asv": "For the Son of man shall come in the glory of his Father with his angels; and then shall he render unto every man according to his deeds.", "ylt": "`For, the Son of Man is about to come in the glory of his Father, with his messengers, and then he will reward each, according to his work.", "tyndale": "For the sonne of man shall come in the glory of his father wt his angels: and then shall he rewarde every man accordinge to his dedes.", "dra": "For the Son of man shall come in the glory of his Father with his angels: and then will he render to every man according to his works.", "bbe": "For the Son of man will come in the glory of his Father with his angels; and then he will give to every man the reward of his works.", "geneva": "For the Sonne of man shall come in the glory of his Father with his Angels, and then shall he giue to euery man according to his deedes.", "wycliffe": "For mannes sone schal come in glorie of his fader, with his aungels, and thanne he schal yelde to ech man after his werkis.", "rotherham": "For the Son of Man is destined to be coming, in the glory of his Father, with his messengers,—and, then, will he give back unto each one, according to his practice.", "weymouth": "For the Son of Man is soon to come in the glory of the Father with His angels, and then will He requite every man according to his actions.", "darby": "For the Son of man is about to come in the glory of his Father with his angels, and then he will render to each according to his doings.", "twenty": "For the Son of Man is to come in his Father’s Glory, with his angels, and then he ‘will give to every man what his actions deserve.’", "acv": "For the Son of man is going to come in the glory of his Father with his agents, and then he will reward each man according to his actions.", "anderson": "For the Son of man will come in the glory of his Father, with his angels; and then he will reward every one according to his deeds.", "haweis": "For the Son of man shall hereafter come in the glory of his Father, with his angels, and then shall he recompense every man according to his practice.", "noyes": "For the Son of man is to come in the glory of his Father, with his angels; and then will he render to every one according to his works.", "webster": "For the Son of man will come in the glory of his Father, with his angels; and then he will reward every man according to his works.", "vulgate": "Filius enim hominis venturus est in gloria Patris sui cum angelis suis et tunc reddet unicuique secundum opus eius;"}}, {"v": 28, "ref": "16:28", "o": "ἀμὴν λέγω ὑμῖν ⸀ὅτι εἰσίν τινες ⸂τῶν ὧδε ἑστώτων⸃ οἵτινες οὐ μὴ γεύσωνται θανάτου ἕως ἂν ἴδωσιν τὸν υἱὸν τοῦ ἀνθρώπου ἐρχόμενον ἐν τῇ βασιλείᾳ αὐτοῦ.", "en": {"kjv": "Verily I say unto you, There be some standing here, which shall not taste of death, till they see the Son of man coming in his kingdom.", "web": "Most certainly I tell you, there are some standing here who will in no way taste of death, until they see the Son of Man coming in his Kingdom.”", "bsb": "Truly I tell you, some who are standing here will not taste death before they see the Son of Man coming in His kingdom.”", "asv": "Verily I say unto you, There are some of them that stand here, who shall in no wise taste of death, till they see the Son of man coming in his kingdom.", "ylt": "Verily I say to you, there are certain of those standing here who shall not taste of death till they may see the Son of Man coming in his reign.'", "tyndale": "Verely I saye vnto you some ther be amonge them that here stonde which shall not taste of deeth tyll they shall have sene the sonne of man come in his kyngdomen.", "dra": "Amen I say to you, there are some of them that stand here, that shall not taste death, till they see the Son of man coming in his kingdom.", "bbe": "Truly I say to you, There are some of those here who will not have a taste of death, till they see the Son of man coming in his kingdom.", "geneva": "Verely I say vnto you, there bee some of them that stande here, which shall not taste of death, till they haue seene the Sonne of man come in his kingdome.", "wycliffe": "Treuli Y seie to you, `ther ben summe of hem that stonden here, whiche schulen not taste deth, til thei seen mannus sone comynge in his kyngdom.", "rotherham": "Verily, I say unto you—There are some of those, here standing, who, indeed, shall in nowise taste of death, until they see the Son of Man, coming in his kingdom.", "weymouth": "I solemnly tell you that some of those who are standing here will certainly not taste death till they have seen the Son of Man coming in His Kingdom.\"", "darby": "Verily I say unto you, There are some of those standing here that shall not taste of death at all until they shall have seen the Son of man coming in his kingdom.", "twenty": "I tell you, some of those who are standing here will not know death till they have seen the Son of Man coming into his Kingdom.”", "acv": "Truly I say to you, there are some of those who stand here, who will, no, not taste of death, until they see the Son of man coming in his kingdom.", "anderson": "Verily I say to you, There are some standing here that shall not taste of death, till they see the Son of man coming in his kingdom.", "haweis": "Verily I say unto you, There are some of those standing here, who shall in no wise taste of death, until they see the Son of man coming in his kingdom.", "noyes": "Truly do I say to you, There are some of those standing here who will not taste of death, till they have seen the Son of man coming in his kingdom.", "webster": "Verily I say to you, There are some standing here, who shall not taste death, till they shall see the Son of man coming in his kingdom.", "vulgate": "amen dico vobis sunt quidam de hic stantibus qui non gustabunt mortem donec videant Filium hominis venientem in regno suo;"}}]}, {"c": 17, "verses": [{"v": 1, "ref": "17:1", "o": "Καὶ μεθ’ ἡμέρας ἓξ παραλαμβάνει ὁ Ἰησοῦς τὸν Πέτρον καὶ Ἰάκωβον καὶ Ἰωάννην τὸν ἀδελφὸν αὐτοῦ, καὶ ἀναφέρει αὐτοὺς εἰς ὄρος ὑψηλὸν κατ’ ἰδίαν.", "en": {"kjv": "And after six days Jesus taketh Peter, James, and John his brother, and bringeth them up into an high mountain apart,", "web": "After six days, Jesus took with him Peter, James, and John his brother, and brought them up into a high mountain by themselves.", "bsb": "After six days Jesus took with Him Peter, James, and John the brother of James, and led them up a high mountain by themselves.", "asv": "And after six days Jesus taketh with him Peter, and James, and John his brother, and bringeth them up into a high mountain apart:", "ylt": "And after six days Jesus taketh Peter, and James, and John his brother, and doth bring them up to a high mount by themselves,", "tyndale": "And after. vi. dayes Iesus toke Peter and Iames and Ihon his brother and brought them vp into an hye mountayne out of the waye", "dra": "And after six days Jesus taketh unto him Peter and James, and John his brother, and bringeth them up into a high mountain apart:", "bbe": "And after six days Jesus takes with him Peter, and James, and John, his brother, and makes them go up with him into a high mountain by themselves.", "geneva": "And after sixe dayes, Iesus tooke Peter, and Iames and Iohn his brother, and brought them vp into an hie mountaine apart,", "wycliffe": "And after sixe daies Jhesus took Petre, and James, and Joon, his brother, and ledde hem aside in to an hiy hil,", "rotherham": "And, after six days, Jesus taketh with him, Peter and James and John his brother, and bringeth them up into a high mountain, apart;", "weymouth": "Six day later, Jesus took with Him Peter and the brothers James and John, and brought them up a high mountain to a solitary place.", "darby": "And after six days Jesus takes with [him] Peter, and James, and John his brother, and brings them up into a high mountain apart.", "twenty": "Six days later, Jesus took with him Peter, and the brothers James and John, and led them up a high mountain alone.", "acv": "And after six days Jesus takes Peter, and James, and John his brother, and brings them up onto a high mountain in private.", "anderson": "And after six days, Jesus took with him Peter and James and John his brother, and led them up into a high mountain apart:", "haweis": "THEN six days after, Jesus taketh Peter, and James, and John his brother, and bringeth them into an exceeding high mountain apart.", "noyes": "And after six days Jesus taketh with him Peter, and James, and John his brother, and leadeth them up into a high mountain apart.", "webster": "And after six days, Jesus taketh Peter, James, and John his brother, and bringeth them upon a high mountain apart.", "vulgate": "et post dies sex adsumpsit Iesus Petrum et Iacobum et Iohannem fratrem eius et ducit illos in montem excelsum seorsum;"}}, {"v": 2, "ref": "17:2", "o": "καὶ μετεμορφώθη ἔμπροσθεν αὐτῶν, καὶ ἔλαμψεν τὸ πρόσωπον αὐτοῦ ὡς ὁ ἥλιος, τὰ δὲ ἱμάτια αὐτοῦ ⸀ἐγένετο λευκὰ ὡς τὸ φῶς.", "en": {"kjv": "And was transfigured before them: and his face did shine as the sun, and his raiment was white as the light.", "web": "He was transfigured before them. His face shone like the sun, and his garments became as white as the light.", "bsb": "There He was transfigured before them. His face shone like the sun, and His clothes became as white as the light.", "asv": "and he was transfigured before them; and his face did shine as the sun, and his garments became white as the light.", "ylt": "and he was transfigured before them, and his face shone as the sun, and his garments did become white as the light,", "tyndale": "and was transfygured before them: and his face did shyne as the sunne and his clothes were as whyte as the light.", "dra": "And he was transfigured before them. And his face did shine as the sun: and his garments became white as snow.", "bbe": "And he was changed in form before them; and his face was shining like the sun, and his clothing became white as light.", "geneva": "And was transfigured before them: and his face did shine as the Sunne, and his clothes were as white as the light.", "wycliffe": "and was turned in to an othir licnesse bifor hem. And his face schone as the sunne; and hise clothis weren maad white as snowe.", "rotherham": "and was transformed before them,—and his face shone as the sun, and, his garments, became white as the light.", "weymouth": "There in their presence His form underwent a change; His face shone like the sun, and His raiment became as white as the light.", "darby": "And he was transfigured before them. And his face shone as the sun, and his garments became white as the light;", "twenty": "There his appearance was transformed before their eyes; his face shown like the sun, and his clothes became as white as the light.", "acv": "And he was transfigured before them, and his face shone as the sun, and his garments became white as the light.", "anderson": "and he was transfigured before them: and his face did shine as the sun, and his clothing was white as the light.", "haweis": "And he was transformed before them; and his face shone as the sun, and his garments were white as the light.", "noyes": "And he was transfigured before them, and his face shone as the sun; and his garments became white as the light.", "webster": "And [he] was transfigured before them: and his face shone as the sun, and his raiment was white as the light.", "vulgate": "et transfiguratus est ante eos et resplenduit facies eius sicut sol vestimenta autem eius facta sunt alba sicut nix;"}}, {"v": 3, "ref": "17:3", "o": "καὶ ἰδοὺ ⸀ὤφθη αὐτοῖς Μωϋσῆς καὶ Ἠλίας ⸂συλλαλοῦντες μετ’ αὐτοῦ⸃.", "en": {"kjv": "And, behold, there appeared unto them Moses and Elias talking with him.", "web": "Behold, Moses and Elijah appeared to them talking with him.", "bsb": "Suddenly Moses and Elijah appeared before them, talking with Jesus.", "asv": "And behold, there appeared unto them Moses and Elijah talking with him.", "ylt": "and lo, appear to them did Moses and Elijah, talking together with him.", "tyndale": "And beholde ther appered vnto the Moses and Helyas talkinge with him.", "dra": "And behold there appeared to them Moses and Elias talking with him.", "bbe": "And Moses and Elijah came before their eyes, talking with him.", "geneva": "And beholde, there appeared vnto them Moses, and Elias, talking with him.", "wycliffe": "And lo! Moises and Elie apperiden to hem, and spaken with hym.", "rotherham": "And lo! there appeared to them Moses and Elijah, conversing with him.", "weymouth": "And suddenly Moses and Elijah appeared to them conversing with Him.", "darby": "and lo, Moses and Elias appeared to them talking with him.", "twenty": "And all at once Moses and Elijah appeared to them, talking with Jesus.", "acv": "And behold, Moses and Elijah appeared to them, talking with him.", "anderson": "And behold, there appeared to them Moses and Elijah, talking with him.", "haweis": "And behold, there appeared to them, Moses and Elias talking with him.", "noyes": "And lo! there appeared to them Moses and Elijah, talking with him.", "webster": "And behold, there appeared to them Moses and Elijah talking with him.", "vulgate": "et ecce apparuit illis Moses et Helias cum eo loquentes;"}}, {"v": 4, "ref": "17:4", "o": "ἀποκριθεὶς δὲ ὁ Πέτρος εἶπεν τῷ Ἰησοῦ· Κύριε, καλόν ἐστιν ἡμᾶς ὧδε εἶναι· εἰ θέλεις, ⸀ποιήσω ὧδε τρεῖς σκηνάς, σοὶ μίαν καὶ Μωϋσεῖ μίαν καὶ ⸂Ἠλίᾳ μίαν⸃.", "en": {"kjv": "Then answered Peter, and said unto Jesus, Lord, it is good for us to be here: if thou wilt, let us make here three tabernacles; one for thee, and one for Moses, and one for Elias.", "web": "Peter answered, and said to Jesus, “Lord, it is good for us to be here. If you want, let’s make three tents here: one for you, one for Moses, and one for Elijah.”", "bsb": "Peter said to Jesus, “Lord, it is good for us to be here. If You wish, I will put up three shelters—one for You, one for Moses, and one for Elijah.”", "asv": "And Peter answered, and said unto Jesus, Lord, it is good for us to be here: if thou wilt, I will make here three tabernacles; one for thee, and one for Moses, and one for Elijah.", "ylt": "And Peter answering said to Jesus, `Sir, it is good to us to be here; if thou wilt, we may make here three booths--for thee one, and for Moses one, and one for Elijah.'", "tyndale": "Then answered Peter and sayde to Iesus: master here is good beinge for vs. If thou wylt leet vs make here .iii. tabernacles one for the and one for Moses and one for Helyas.", "dra": "And Peter answering, said to Jesus: Lord, it is good for us to be here: if thou wilt, let us make here three tabernacles, one for thee, and one for Moses, and one for Elias.", "bbe": "And Peter made answer and said to Jesus, Lord, it is good for us to be here: if you will let me, I will make here three tents, one for you, and one for Moses, and one for Elijah.", "geneva": "Then answered Peter, and saide to Iesus, Master, it is good for vs to be here: if thou wilt, let vs make here three tabernacles, one for thee, and one for Moses, and one for Elias.", "wycliffe": "And Petre answeride, and seide to Jhesu, Lord, it is good vs to be here. If thou wolt, make we here thre tabernaclis; to thee oon, to Moises oon, and oon to Elye. Yit the while he spak, lo!", "rotherham": "And Peter, answering, said unto Jesus—Lord! it is, delightful, for us, to be here,—If thou wilt, I will make here three tents, for thee, one, and, for Moses, one, and, for Elijah, one.", "weymouth": "Then Peter said to Jesus, \"Master, we are thankful to you that we are here. If you approve, I will put up three tents here, one for you, one for Moses, and one for Elijah.\"", "darby": "And Peter answering said to Jesus, Lord, it is good we should be here. If thou wilt, let us make here three tabernacles: for thee one, and for Moses one, and one for Elias.", "twenty": "“Master,” exclaimed Peter, interposing, “it is good to be here; if you wish, I will make three tents here, one for you, one for Moses, and one for Elijah.”", "acv": "And having responded, Peter said to Jesus, Lord, it is good for us to be here. If thou desire, we could make here three tabernacles, one for thee, and one for Moses, and one for Elijah.", "anderson": "And Peter answered and said to Jesus: Lord, it is good for us to be here; if thou wilt, let us make here three tents, one for thee, and one for Moses, and one for Elijah.", "haweis": "Then Peter addressing him, said to Jesus, Lord, It is well that we are here; if it please thee, we will make here three tents; one for thee, and one for Moses, and one for Elias.", "noyes": "And Peter answering said to Jesus, Lord, it is good for us to be here; if thou wilt, I will make here three tents; one for thee, and one for Moses, and one for Elijah.", "webster": "Then answered Peter, and said to Jesus, Lord, it is good for us to be here: if thou wilt, let us make here three tabernacles; one for thee, and one for Moses, and one for Elijah.", "vulgate": "respondens autem Petrus dixit ad Iesum Domine bonum est nos hic esse si vis faciamus hic tria tabernacula tibi unum et Mosi unum et Heliae unum;"}}, {"v": 5, "ref": "17:5", "o": "ἔτι αὐτοῦ λαλοῦντος ἰδοὺ νεφέλη φωτεινὴ ἐπεσκίασεν αὐτούς, καὶ ἰδοὺ φωνὴ ἐκ τῆς νεφέλης λέγουσα· Οὗτός ἐστιν ὁ υἱός μου ὁ ἀγαπητός, ἐν ᾧ εὐδόκησα· ⸂ἀκούετε αὐτοῦ⸃.", "en": {"kjv": "While he yet spake, behold, a bright cloud overshadowed them: and behold a voice out of the cloud, which said, This is my beloved Son, in whom I am well pleased; hear ye him.", "web": "While he was still speaking, behold, a bright cloud overshadowed them. Behold, a voice came out of the cloud, saying, “This is my beloved Son, in whom I am well pleased. Listen to him.”", "bsb": "While Peter was still speaking, a bright cloud enveloped them, and a voice from the cloud said, “This is My beloved Son, in whom I am well pleased. Listen to Him!”", "asv": "While he was yet speaking, behold, a bright cloud overshadowed them: and behold, a voice out of the cloud, saying, This is my beloved Son, in whom I am well pleased; hear ye him.", "ylt": "While he is yet speaking, lo, a bright cloud overshadowed them, and lo, a voice out of the cloud, saying, `This is My Son, --the Beloved, in whom I did delight; hear him.'", "tyndale": "Whyll he yet spake beholde a bright cloude shadowed them. And beholde there came a voyce out of ye cloude sayinge: this is my deare sonne in whom I delite heare him.", "dra": "And as he was yet speaking, behold a bright cloud overshadowed them. And lo a voice out of the cloud, saying: This is my beloved Son, in whom I am well pleased: hear ye him.", "bbe": "While he was still talking, a bright cloud came over them: and a voice out of the cloud, saying, This is my dearly loved Son, with whom I am well pleased; give ear to him.", "geneva": "While he yet spake, behold, a bright cloude shadowed them: and beholde, there came a voyce out of the cloude, saying, This is that my beloued Sonne, in whom I am well pleased: heare him.", "wycliffe": "a briyt cloude ouerschadewide hem; and lo! a voice out of the cloude, that seide, This is my dereworth sone, in whom Y haue wel pleside to me; here ye hym.", "rotherham": "While yet he was speaking, lo! a brightly shining cloud, overshadowed them, and lo! a voice, out of the cloud, saying—This, is, my Son, the Beloved, in whom I delight,—Be hearkening to him.", "weymouth": "He was still speaking when a luminous cloud spread over them; and a voice was heard from within the cloud, which said, \"This is My Son dearly beloved, in whom is My delight. Listen to Him.\"", "darby": "While he was still speaking, behold, a bright cloud overshadowed them, and lo, a voice out of the cloud, saying, This is my beloved Son, in whom I have found my delight: hear him.", "twenty": "While he was still speaking, a bright cloud enveloped them, and there was a voice from the cloud that said — “This is my Son, the Beloved, in whom I delight; him you must hear.”", "acv": "While he was still speaking, behold, a bright cloud overshadowed them. And lo, a voice out of the cloud, saying, This is my beloved Son in whom I am well pleased. Hear ye him.", "anderson": "While he was yet speaking, behold, a bright cloud overshadowed them; and lo, a voice from the cloud, saying: This is my beloved Son, in whom I delight; hear him.", "haweis": "And while he was yet speaking, behold, a luminous cloud overshadowed them; and lo! a voice out of the cloud, saying, This is my beloved Son, in whom is my delight; hear him!", "noyes": "While he was yet speaking, lo! a bright cloud overshadowed them; and lo! a voice out of the cloud, saying, \"This is my beloved Son, with whom I am well pleased; hear him.\"", "webster": "While he was yet speaking, behold, a bright cloud overshadowed them: and behold, a voice out of the cloud, which said, This is my beloved Son, in whom I am well pleased: hear ye him.", "vulgate": "adhuc eo loquente ecce nubes lucida obumbravit eos et ecce vox de nube dicens hic est Filius meus dilectus in quo mihi bene conplacuit ipsum audite;"}}, {"v": 6, "ref": "17:6", "o": "καὶ ἀκούσαντες οἱ μαθηταὶ ἔπεσαν ἐπὶ πρόσωπον αὐτῶν καὶ ἐφοβήθησαν σφόδρα.", "en": {"kjv": "And when the disciples heard it, they fell on their face, and were sore afraid.", "web": "When the disciples heard it, they fell on their faces, and were very afraid.", "bsb": "When the disciples heard this, they fell facedown in terror.", "asv": "And when the disciples heard it, they fell on their face, and were sore afraid.", "ylt": "And the disciples having heard, did fall upon their face, and were exceedingly afraid,", "tyndale": "And when the disciples hearde that they fell on their faces and were soore afrayed.", "dra": "And the disciples hearing fell upon their face, and were very much afraid.", "bbe": "And at these words the disciples went down on their faces in great fear.", "geneva": "And when the disciples heard that, they fell on their faces, and were sore afraide.", "wycliffe": "And the disciplis herden, and felden doun on her faces, and dredden greetli.", "rotherham": "And, hearing it, the disciples fell upon their face, and were caused to fear exceedingly.", "weymouth": "On hearing this voice, the disciples fell on their faces and were filled with terror.", "darby": "And the disciples hearing [it] fell upon their faces, and were greatly terrified.", "twenty": "The disciples, on hearing this, fell on their faces, greatly afraid.", "acv": "And when the disciples heard it, they fell on their face, and were exceedingly afraid.", "anderson": "And when the disciples heard it, they fell on their faces, and were greatly afraid.", "haweis": "And the disciples hearing it, fell on their face, and were exceedingly affrighted.", "noyes": "And the disciples hearing it, fell on their face, and were exceedingly afraid.", "webster": "And when the disciples heard [it], they fell on their face, and were in great fear.", "vulgate": "et audientes discipuli ceciderunt in faciem suam et timuerunt valde;"}}, {"v": 7, "ref": "17:7", "o": "καὶ ⸂προσῆλθεν ὁ Ἰησοῦς καὶ ἁψάμενος αὐτῶν⸃ εἶπεν· Ἐγέρθητε καὶ μὴ φοβεῖσθε.", "en": {"kjv": "And Jesus came and touched them, and said, Arise, and be not afraid.", "web": "Jesus came and touched them and said, “Get up, and don’t be afraid.”", "bsb": "Then Jesus came over and touched them. “Get up,” He said. “Do not be afraid.”", "asv": "And Jesus came and touched them and said, Arise, and be not afraid.", "ylt": "and Jesus having come near, touched them, and said, `Rise, be not afraid,'", "tyndale": "And Iesus came and touched them and sayde: aryse and be not afrayed.", "dra": "And Jesus came and touched them: and said to them: Arise, and fear not.", "bbe": "And Jesus came and put his hand on them and said, Get up and have no fear.", "geneva": "Then Iesus came and touched them, and said, Arise, and be not afraide.", "wycliffe": "And Jhesus cam, and touchide hem, and seide to hem, Rise vp, and nyle ye drede.", "rotherham": "And Jesus came near, and, touching them, said—Arise! and be not afraid.", "weymouth": "But Jesus came and touched them, and said, \"Rouse yourselves and have no fear.\"", "darby": "And Jesus coming to [them] touched them, and said, Rise up, and be not terrified.", "twenty": "But Jesus came and touched them, saying as he did so: “Rise up, and do not be afraid.”", "acv": "And having come, Jesus touched them and said, Arise, and fear not.", "anderson": "And Jesus came and touched them, and said: Arise and be not afraid.", "haweis": "And Jesus came and touched them, and said, Arise, be not affrighted.", "noyes": "And Jesus came and touched them, and said, Arise, and be not afraid.", "webster": "And Jesus came and touched them, and said, Arise, and be not afraid.", "vulgate": "et accessit Iesus et tetigit eos dixitque eis surgite et nolite timere;"}}, {"v": 8, "ref": "17:8", "o": "ἐπάραντες δὲ τοὺς ὀφθαλμοὺς αὐτῶν οὐδένα εἶδον εἰ μὴ ⸀αὐτὸν Ἰησοῦν μόνον.", "en": {"kjv": "And when they had lifted up their eyes, they saw no man, save Jesus only.", "web": "Lifting up their eyes, they saw no one, except Jesus alone.", "bsb": "And when they looked up, they saw no one except Jesus.", "asv": "And lifting up their eyes, they saw no one, save Jesus only.", "ylt": "and having lifted up their eyes, they saw no one, except Jesus only.", "tyndale": "And when they looked vp they saw no man saue Iesus onely.", "dra": "And they lifting up their eyes, saw no one, but only Jesus.", "bbe": "And lifting up their eyes, they saw no one, but Jesus only.", "geneva": "And when they lifted vp their eyes, they sawe no man, saue Iesus onely.", "wycliffe": "And thei liften vp her iyen, and saien no man, but Jhesu aloone.", "rotherham": "And, lifting up their eyes, no one, saw they, save Jesus, himself, alone.", "weymouth": "So they looked up, and saw no one but Jesus.", "darby": "And lifting up their eyes, they saw no one but Jesus alone.", "twenty": "When they raised their eyes, they saw no one but Jesus himself alone.", "acv": "And having lifted up their eyes, they saw no man, except Jesus only.", "anderson": "And when they lifted up their eyes, they saw no one but Jesus.", "haweis": "Then lifting up their eyes, they saw no person, but Jesus only.", "noyes": "And lifting up their eyes, they saw no one but Jesus only.", "webster": "And when they had lifted up their eyes, they saw no man, save Jesus only.", "vulgate": "levantes autem oculos suos neminem viderunt nisi solum Iesum;"}}, {"v": 9, "ref": "17:9", "o": "Καὶ καταβαινόντων αὐτῶν ἐκ τοῦ ὄρους ἐνετείλατο αὐτοῖς ὁ Ἰησοῦς λέγων· Μηδενὶ εἴπητε τὸ ὅραμα ἕως οὗ ὁ υἱὸς τοῦ ἀνθρώπου ἐκ νεκρῶν ⸀ἐγερθῇ.", "en": {"kjv": "And as they came down from the mountain, Jesus charged them, saying, Tell the vision to no man, until the Son of man be risen again from the dead.", "web": "As they were coming down from the mountain, Jesus commanded them, saying, “Don’t tell anyone what you saw, until the Son of Man has risen from the dead.”", "bsb": "As they were coming down the mountain, Jesus commanded them, “Do not tell anyone about this vision until the Son of Man has been raised from the dead.”", "asv": "And as they were coming down from the mountain, Jesus commanded them, saying, Tell the vision to no man, until the Son of man be risen from the dead.", "ylt": "And as they are coming down from the mount, Jesus charged them, saying, `Say to no one the vision, till the Son of Man out of the dead may rise.'", "tyndale": "And as they came doune from the mountayne Iesus charged them sayinge: se yt ye shewe the vision to no man vntyll the sonne of man be rysen ageyne from deeth.", "dra": "And as they came down from the mountain, Jesus charged them, saying: Tell the vision to no man, till the Son of man be risen from the dead.", "bbe": "And when they were coming down from the mountain, Jesus gave them orders, saying, Let no man have word of what you have seen, till the Son of man has come again from the dead.", "geneva": "And as they came downe from the moutaine, Iesus charged them, saying, Shewe the vision to no man, vntil the Sonne of man rise againe from the dead.", "wycliffe": "And as thei camen doun of the hille, Jhesus comaundide to hem, and seide, Seie ye to no man the visioun, til mannus sone rise ayen fro deeth.", "rotherham": "And, as they were coming down out of the mountain, Jesus commanded them, saying—Unto no one, may ye tell the vision, until the Son of Man, from among the dead shall arise.", "weymouth": "As they were descending the mountain, Jesus laid a command upon them. \"Tell no one,\" He said, \"of the sight you have seen till the Son of Man has risen from among the dead.\"", "darby": "And as they descended from the mountain, Jesus charged them, saying, Tell the vision to no one, until the Son of man be risen up from among [the] dead.", "twenty": "As they were going down the mountain side, Jesus gave them this warning — “Do not speak of this vision to any one, until the Son of Man has risen from the dead.”", "acv": "And while they were coming down from the mountain, Jesus commanded them, saying, Tell the vision to no man, until the Son of man will rise from the dead.", "anderson": "And as they came down from the mountain, Jesus charged them, saying: Tell the vision to no one, till the Son of man has risen from the dead.", "haweis": "And when they were coming down from the mountain, Jesus commanded them, saying, Tell no man the vision, until the Son of man is risen from the dead.", "noyes": "And as they came down from the mountain, Jesus charged them, saying, Tell what hath been seen to no one, until the Son of man hath risen from the dead.", "webster": "And as they were descending the mountain, Jesus charged them, saying, Tell the vision to no man, until the Son of man be raised again from the dead.", "vulgate": "et descendentibus illis de monte praecepit Iesus dicens nemini dixeritis visionem donec Filius hominis a mortuis resurgat;"}}, {"v": 10, "ref": "17:10", "o": "καὶ ἐπηρώτησαν αὐτὸν οἱ ⸀μαθηταὶ λέγοντες· Τί οὖν οἱ γραμματεῖς λέγουσιν ὅτι Ἠλίαν δεῖ ἐλθεῖν πρῶτον;", "en": {"kjv": "And his disciples asked him, saying, Why then say the scribes that Elias must first come?", "web": "His disciples asked him, saying, “Then why do the scribes say that Elijah must come first?”", "bsb": "The disciples asked Him, “Why then do the scribes say that Elijah must come first?”", "asv": "And his disciples asked him, saying, Why then say the scribes that Elijah must first come?", "ylt": "And his disciples questioned him, saying, `Why then do the scribes say that Elijah it behoveth to come first?'", "tyndale": "And his disciples axed of him sayinge: Why then saye the scribes yt Helyas muste fyrst come?", "dra": "And his disciples asked him, saying: Why then do the scribes say that Elias must come first?", "bbe": "And his disciples, questioning him, said, Why then do the scribes say that Elijah has to come first?", "geneva": "And his disciples asked him, saying, Why then say the Scribes that Elias must first come?", "wycliffe": "And his disciplis axiden hym, and seiden, What thanne seien the scribis, that it bihoueth that Elie come first?", "rotherham": "And the disciples questioned him, saying—Why then do, the Scribes, say, that, Elijah, must needs come, first?", "weymouth": "\"Why then,\" asked the disciples, \"do the Scribes say that Elijah must first come?\"", "darby": "And [his] disciples demanded of him saying, Why then say the scribes that Elias must first have come?", "twenty": "“How is it,” his disciples asked, “that our Teachers of the Law say that Elijah has to come first?”", "acv": "And his disciples questioned him, saying, Why then do the scholars say that Elijah must first come?", "anderson": "And his disciples asked him, saying: Why then do the scribes say that Elijah must come first?", "haweis": "And his disciples asked him, saying, Why then do the scribes affirm, that Elias must come first?", "noyes": "And the disciples asked him, saying, Why then say the scribes that Elijah must first come?", "webster": "And his disciples asked him, saying, Why then say the scribes, that Elijah must first come?", "vulgate": "et interrogaverunt eum discipuli dicentes quid ergo scribae dicunt quod Heliam oporteat primum venire;"}}, {"v": 11, "ref": "17:11", "o": "ὁ ⸀δὲ ἀποκριθεὶς ⸀εἶπεν· Ἠλίας μὲν ⸀ἔρχεται καὶ ἀποκαταστήσει πάντα·", "en": {"kjv": "And Jesus answered and said unto them, Elias truly shall first come, and restore all things.", "web": "Jesus answered them, “Elijah indeed comes first, and will restore all things,", "bsb": "Jesus replied, “Elijah does indeed come, and he will restore all things.", "asv": "And he answered and said, Elijah indeed cometh, and shall restore all things:", "ylt": "And Jesus answering said to them, `Elijah doth indeed come first, and shall restore all things,", "tyndale": "Iesus answered and sayd vnto them: Helyas shall fyrst come and restore all thinges.", "dra": "But he answering, said to them: Elias indeed shall come, and restore all things.", "bbe": "And in answer he said, Elijah truly has to come and put all things right:", "geneva": "And Iesus answered, and saide vnto them, Certeinely Elias must first come, and restore all thinges.", "wycliffe": "He answeride, and seide to hem, Elie schal come, and he schal restore alle thingis.", "rotherham": "And, he, answering, said—Elijah, indeed, cometh, and will restored all things;", "weymouth": "\"Elijah was indeed to come,\" He replied, \"and would reform everything.", "darby": "And he answering said to them, Elias indeed comes first and will restore all things.", "twenty": "“Elijah indeed does come,” Jesus replied, “and will restore everything;", "acv": "And having answered, Jesus said to them, Elijah indeed comes first, and will restore all.", "anderson": "Jesus answered and said to them: Elijah, indeed, comes first, and he will restore all things.", "haweis": "Then Jesus answering said unto them, Elias indeed cometh first, and will reform all things.", "noyes": "And he answering said, Elijah indeed cometh, and will restore all things.", "webster": "And Jesus answered and said to them, Elijah truly will first come, and restore all things:", "vulgate": "at ille respondens ait eis Helias quidem venturus est et restituet omnia;"}}, {"v": 12, "ref": "17:12", "o": "λέγω δὲ ὑμῖν ὅτι Ἠλίας ἤδη ἦλθεν, καὶ οὐκ ἐπέγνωσαν αὐτὸν ἀλλὰ ἐποίησαν ἐν αὐτῷ ὅσα ἠθέλησαν· οὕτως καὶ ὁ υἱὸς τοῦ ἀνθρώπου μέλλει πάσχειν ὑπ’ αὐτῶν.", "en": {"kjv": "But I say unto you, That Elias is come already, and they knew him not, but have done unto him whatsoever they listed. Likewise shall also the Son of man suffer of them.", "web": "but I tell you that Elijah has come already, and they didn’t recognize him, but did to him whatever they wanted to. Even so the Son of Man will also suffer by them.”", "bsb": "But I tell you that Elijah has already come, and they did not recognize him, but have done to him whatever they wished. In the same way, the Son of Man will suffer at their hands.”", "asv": "but I say unto you, that Elijah is come already, and they knew him not, but did unto him whatsoever they would. Even so shall the Son of man also suffer of them.", "ylt": "and I say to you--Elijah did already come, and they did not know him, but did with him whatever they would, so also the Son of Man is about to suffer by them.'", "tyndale": "And I saye vnto you yt Helyas is come alredy and they knewe him not: but have done vnto him whatsoever they lusted. In lyke wyse shall also the sonne of man suffre of the.", "dra": "But I say to you, that Elias is already come, and they knew him not, But have done unto him whatsoever they had a mind. So also the Son of man shall suffer from them.", "bbe": "But I say to you that Elijah has come, and they had no knowledge of him, but did to him whatever they were pleased to do; the same will the Son of man undergo at their hands.", "geneva": "But I say vnto you that Elias is come alreadie, and they knewe him not, but haue done vnto him whatsoeuer they would: likewise shall also the Sonne of man suffer of them.", "wycliffe": "And Y seie to you, that Elie is nowe comun, and thei knewen hym not, but thei diden in him what euer thingis thei wolden; and so mannus sone schal suffre of hem.", "rotherham": "But, I say unto you—that, Elijah, just now, came,—and they recognised him not, but did with him, whatsoever they pleased: Thus, the Son of Man also, is destined to suffer by them.", "weymouth": "But I tell you that he has already come, and they did not recognize him, but dealt with him as they chose. And before long the Son of Man will be treated by them in a similar way.\"", "darby": "But I say unto you that Elias has already come, and they have not known him, but have done unto him whatever they would. Thus also the Son of man is about to suffer from them.", "twenty": "and I tell you that Elijah has already come, and people have not recognised him, but have treated him just as they pleased. In the same way, too, the Son of Man is destined to undergo suffering at men’s hands.”", "acv": "But I say to you, that Elijah already came, and they knew him not, but did to him how many things they wanted. Likewise also the Son of man is going to suffer by them.", "anderson": "But I say to you, That Elijah has already come, and they did not recognize him, but did to him what they wished; so also shall the Son of man suffer at their hands.", "haweis": "But I say unto you, That Elias is already come, and they knew him not, but have done by him whatsoever they chose: even so also must the Son of man suffer by them.", "noyes": "But I say to you, that Elijah hath already come, and they knew him not, but did with him whatever they would. So also is the Son of man to suffer by them.", "webster": "But I say to you, that Elijah is come already, and they knew him not, but have done to him whatever they pleased: likewise will also the Son of man suffer by them.", "vulgate": "dico autem vobis quia Helias iam venit et non cognoverunt eum sed fecerunt in eo quaecumque voluerunt sic et Filius hominis passurus est ab eis;"}}, {"v": 13, "ref": "17:13", "o": "τότε συνῆκαν οἱ μαθηταὶ ὅτι περὶ Ἰωάννου τοῦ βαπτιστοῦ εἶπεν αὐτοῖς.", "en": {"kjv": "Then the disciples understood that he spake unto them of John the Baptist.", "web": "Then the disciples understood that he spoke to them of John the Baptizer.", "bsb": "Then the disciples understood that He was speaking to them about John the Baptist.", "asv": "Then understood the disciples that he spake unto them of John the Baptist.", "ylt": "Then understood the disciples that concerning John the Baptist he spake to them.", "tyndale": "Then ye disciples perceaved that he spake vnto them of Ihon baptist.", "dra": "Then the disciples understood, that he had spoken to them of John the Baptist.", "bbe": "Then the disciples saw that he was talking to them of John the Baptist.", "geneva": "Then the disciples perceiued that he spake vnto them of Iohn Baptist.", "wycliffe": "Thanne the disciplis vndurstoden, that he seide to hem of Joon Baptist.", "rotherham": "Then, perceived the disciples, that, concerning John the Immerser, he spake to them.", "weymouth": "Then it dawned upon the disciples that it was John the Baptist about whom He had spoken to them.", "darby": "Then the disciples understood that he spoke to them of John the baptist.", "twenty": "Then the disciples understood that it was of John the Baptist that he had spoken to them.", "acv": "Then the disciples understood that he spoke to them about John the immerser.", "anderson": "Then, the disciples understood that he spoke to them of John the Immerser.", "haweis": "Then understood the disciples that he spake to them of John the Baptist.", "noyes": "Then the disciples understood that he spoke to them of John the Baptist.", "webster": "Then the disciples understood that he spoke to them concerning John the Baptist.", "vulgate": "tunc intellexerunt discipuli quia de Iohanne Baptista dixisset eis;"}}, {"v": 14, "ref": "17:14", "o": "Καὶ ⸀ἐλθόντων πρὸς τὸν ὄχλον προσῆλθεν αὐτῷ ἄνθρωπος γονυπετῶν αὐτὸν", "en": {"kjv": "And when they were come to the multitude, there came to him a certain man, kneeling down to him, and saying,", "web": "When they came to the multitude, a man came to him, kneeling down to him, saying,", "bsb": "When they came to the crowd, a man came up to Jesus and knelt before Him.", "asv": "And when they were come to the multitude, there came to him a man, kneeling to him, and saying,", "ylt": "And when they came unto the multitude, there came to him a man, kneeling down to him,", "tyndale": "And when they were come to ye people ther cam to him a certayne man and kneled doune to him and sayde:", "dra": "And when he was come to the multitude, there came to him a man falling down on his knees before him saying: Lord, have pity on my son, for he is a lunatic, and suffereth much: for he falleth often into the fire, and often into the water.", "bbe": "And when they came to the people, a man went down on his knees to him, saying,", "geneva": "And when they were come to the multitude, there came to him a certaine man, and fell downe at his feete,", "wycliffe": "And whanne he cam to the puple, a man cam to hym, and felde doun on hise knees bifor hym, and seide, Lord, haue merci on my sone; for he is lunatike, and suffrith yuele, for ofte tymes he fallith in to the fier, and ofte tymes in to water.", "rotherham": "And, when they came unto the multitude, there approached him a man, falling on his knees to him,", "weymouth": "When they had returned to the people, there came to Him a man who fell on his knees before Him and besought Him.", "darby": "And when they came to the crowd, a man came to him, falling on his knees before him, and saying,", "twenty": "When they came to the crowd, a man came up to Jesus, and, kneeling down before him, said:", "acv": "And when they came to the multitude, a man came to him, kneeling to him, and saying,", "anderson": "And when they had come to the multitude, there came to him a man who knelt to him,", "haweis": "And when they were come to the multitude, there came to him a man, kneeling down to him, and saying,", "noyes": "And when they had come to the multitude, there came to him a man, kneeling down to him, and saying,", "webster": "And when they had come to the multitude, there came to him a [certain] man kneeling down to him, and saying,", "vulgate": "et cum venisset ad turbam accessit ad eum homo genibus provolutus ante eum dicens;"}}, {"v": 15, "ref": "17:15", "o": "καὶ λέγων· Κύριε, ἐλέησόν μου τὸν υἱόν, ὅτι σεληνιάζεται καὶ κακῶς ⸀πάσχει, πολλάκις γὰρ πίπτει εἰς τὸ πῦρ καὶ πολλάκις εἰς τὸ ὕδωρ.", "en": {"kjv": "Lord, have mercy on my son: for he is lunatick, and sore vexed: for ofttimes he falleth into the fire, and oft into the water.", "web": "“Lord, have mercy on my son, for he is epileptic, and suffers grievously; for he often falls into the fire, and often into the water.", "bsb": "“Lord, have mercy on my son,” he said. “He has seizures and is suffering terribly. He often falls into the fire or into the water.", "asv": "Lord, have mercy on my son: for he is epileptic, and suffereth grievously; for oft-times he falleth into the fire, and oft-times into the water.", "ylt": "and saying, `Sir, deal kindly with my son, for he is lunatic, and doth suffer miserably, for often he doth fall into the fire, and often into the water,", "tyndale": "Master have mercy on my sonne for he is franticke: and is sore vexed. And oft tymes he falleth into the fyre and oft into ye water", "dra": "And I brought him to thy disciples, and they could not cure him.", "bbe": "Lord have mercy on my son: for he is off his head, and is in great pain; and frequently he goes falling into the fire, and frequently into the water.", "geneva": "And saide, Master, haue pitie on my sonne: for he is lunatike, and is sore vexed: for oft times he falleth into the fire, and oft times into the water.", "wycliffe": "And Y brouyte hym to thi disciplis, and thei myyten not heele hym.", "rotherham": "and saying—Lord! have mercy upon my son,—because he is lunatic, and in a grievous condition; For, many times, falleth he into the fire, and, many times, into the water.", "weymouth": "\"Sir,\" he said, \"have pity on my son, for he is an epileptic and is very ill. Often he falls into the fire and often into the water.", "darby": "Lord, have mercy on my son, for he is lunatic, and suffers sorely; for often he falls into the fire and often into the water.", "twenty": "“Master, take pity on my son, for he is epileptic and suffers terribly; indeed, he often falls into the fire and into the water;", "acv": "Lord, be merciful to my son, because he is lunatic, and suffers badly. For he often falls into the fire, and often into the water.", "anderson": "and said: Lord, have mercy on my son; for he is a lunatic, and suffers grievously; for he often falls into the fire, and often into the water.", "haweis": "Lord, have compassion on my son, for he is a lunatic, and suffers grievously; for oftentimes he falleth into the fire, and often into the water.", "noyes": "Lord, have compassion on my son; for he is a lunatic, and is sorely afflicted; for he often falleth into the fire, and often into the water.", "webster": "Lord, have mercy on my son; for he is lunatic, and grievously distressed; for often he falleth into the fire, and often into the water.", "vulgate": "Domine miserere filii mei quia lunaticus est et male patitur nam saepe cadit in ignem et crebro in aquam;"}}, {"v": 16, "ref": "17:16", "o": "καὶ προσήνεγκα αὐτὸν τοῖς μαθηταῖς σου, καὶ οὐκ ἠδυνήθησαν αὐτὸν θεραπεῦσαι.", "en": {"kjv": "And I brought him to thy disciples, and they could not cure him.", "web": "So I brought him to your disciples, and they could not cure him.”", "bsb": "I brought him to Your disciples, but they could not heal him.”", "asv": "And I brought him to thy disciples, and they could not cure him.", "ylt": "and I brought him near to thy disciples, and they were not able to heal him.'", "tyndale": "And I brought him to thy disciples and they coulde not heale him.", "dra": "Then Jesus answered and said: O unbelieving and perverse generation, how long shall I be with you? How long shall I suffer you? Bring him hither to me.", "bbe": "And I took him to your disciples, and they were not able to make him well.", "geneva": "And I brought him to thy disciples, and they could not heale him.", "wycliffe": "Jhesus answeride, and seide, A! thou generacion vnbileueful and weiward; hou long schal Y be with you? hou long schal Y suffre you? Brynge ye hym hider to me.", "rotherham": "And I brought him unto thy disciples, and they could not cure, him.", "weymouth": "I have brought him to your disciples, and they have not been able to cure him.\"", "darby": "And I brought him to thy disciples, and they were not able to heal him.", "twenty": "I brought him to your disciples, but they could not cure him.”", "acv": "And I brought him to thy disciples, and they could not heal him.", "anderson": "And I brought him to thy disciples, and they were not able to cure him.", "haweis": "And I brought him to thy disciples, and they have not been able to cure him.", "noyes": "And I brought him to thy disciples, and they could not cure him.", "webster": "And I brought him to thy disciples, and they could not cure him.", "vulgate": "et obtuli eum discipulis tuis et non potuerunt curare eum;"}}, {"v": 17, "ref": "17:17", "o": "ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν· Ὦ γενεὰ ἄπιστος καὶ διεστραμμένη, ἕως πότε ⸂μεθ’ ὑμῶν ἔσομαι⸃; ἕως πότε ἀνέξομαι ὑμῶν; φέρετέ μοι αὐτὸν ὧδε.", "en": {"kjv": "Then Jesus answered and said, O faithless and perverse generation, how long shall I be with you? how long shall I suffer you? bring him hither to me.", "web": "Jesus answered, “Faithless and perverse generation! How long will I be with you? How long will I bear with you? Bring him here to me.”", "bsb": "“O unbelieving and perverse generation!” Jesus replied. “How long must I remain with you? How long must I put up with you? Bring the boy here to Me.”", "asv": "And Jesus answered and said, O faithless and perverse generation, how long shall I be with you? how long shall I bear with you? bring him hither to me.", "ylt": "And Jesus answering said, `O generation, unstedfast and perverse, till when shall I be with you? till when shall I bear you? bring him to me hither;'", "tyndale": "Iesus answered and sayde: O generacion faythles and croked: how longe shall I be with you? how longe shall I suffre you? bring him hidder to me.", "dra": "And Jesus rebuked him, and the devil went out of him, and the child was cured from that hour.", "bbe": "And Jesus, answering, said, O false and foolish generation, how long will I be with you? how long will I put up with you? let him come here to me.", "geneva": "Then Iesus answered, and said, O generation faithlesse, and crooked, how long now shall I be with you! howe long nowe shall I suffer you! bring him hither to me.", "wycliffe": "And Jhesus blamede hym, and the deuel wente out fro hym; and the child was heelid fro that our.", "rotherham": "And Jesus, answering, said—O faithless and perverted generation! How long shall I be with you? How long shall I bear with you? Bring him to me, here.", "weymouth": "\"O unbelieving and perverse generation!\" replied Jesus; \"how long shall I be with you? how long shall I endure you? Bring him to me.\"", "darby": "And Jesus answering said, O unbelieving and perverted generation, how long shall I be with you? how long shall I bear with you? Bring him here to me.", "twenty": "“O faithless and perverse generation!” Jesus exclaimed, “how long must I be among you? how long must I have patience with you? Bring the boy here to me.”", "acv": "And having answered, Jesus said, O faithless and perverted generation, how long will I be with you? How long will I endure you? Bring him here to me.", "anderson": "Jesus answered and said: O faithless and perverse generation, how long shall I be with you? How long shall I bear with you? Bring him hither to me.", "haweis": "Then Jesus answering, said, O generation, faithless, and perverse! how long shall I be with you? how long shall I bear with you? bring him hither to me.", "noyes": "Then Jesus answering said, Unbelieving and perverse generation! How long shall I be with you? How long shall I bear with you? Bring him hither to me.", "webster": "Then Jesus answered and said, O faithless and perverse generation, how long shall I be with you? how long shall I suffer you? bring him hither to me.", "vulgate": "respondens Iesus ait o generatio incredula et perversa quousque ero vobiscum usquequo patiar vos adferte huc illum ad me;"}}, {"v": 18, "ref": "17:18", "o": "καὶ ἐπετίμησεν αὐτῷ ὁ Ἰησοῦς, καὶ ἐξῆλθεν ἀπ’ αὐτοῦ τὸ δαιμόνιον· καὶ ἐθεραπεύθη ὁ παῖς ἀπὸ τῆς ὥρας ἐκείνης.", "en": {"kjv": "And Jesus rebuked the devil; and he departed out of him: and the child was cured from that very hour.", "web": "Jesus rebuked him, the demon went out of him, and the boy was cured from that hour.", "bsb": "Then Jesus rebuked the demon, and it came out of the boy, and he was healed from that moment.", "asv": "And Jesus rebuked him; and the demon went out of him: and the boy was cured from that hour.", "ylt": "and Jesus rebuked him, and the demon went out of him, and the lad was healed from that hour.", "tyndale": "And Iesus rebuked the devyll and he ca out of him. And ye child was healed even yt same houre.", "dra": "Then came the disciples to Jesus secretly, and said: Why could not we cast him out?", "bbe": "And Jesus gave orders to the unclean spirit, and it went out of him: and the boy was made well from that hour.", "geneva": "And Iesus rebuked the deuill, and he went out of him: and the childe was healed at that houre.", "wycliffe": "Thanne the disciplis camen to Jhesu priueli, and seiden to hym, Whi myyten not we caste hym out?", "rotherham": "And Jesus rebuked it; and the demon came out of him,—and cured was the boy, from that hour.", "weymouth": "Then Jesus reprimanded the demon, and it came out and left him; and the boy was cured from that moment.", "darby": "And Jesus rebuked him, and the demon went out from him, and the boy was healed from that hour.", "twenty": "Then Jesus rebuked the demon, and it came out of the boy; and he was cured from that very hour.", "acv": "And Jesus rebuked it, and the demon departed from him. And the boy was cured from that hour.", "anderson": "And Jesus rebuked the demon, and he came out of him: and the child was cured from that hour.", "haweis": "And Jesus rebuked him, and the devil came out of him; and the child was cured from that hour.", "noyes": "And Jesus rebuked him, and the demon went out of him; and the boy was cured from that hour.", "webster": "And Jesus rebuked the demon, and he departed out of him: and the child was cured from that very hour.", "vulgate": "et increpavit ei Iesus et exiit ab eo daemonium et curatus est puer ex illa hora;"}}, {"v": 19, "ref": "17:19", "o": "Τότε προσελθόντες οἱ μαθηταὶ τῷ Ἰησοῦ κατ’ ἰδίαν εἶπον· Διὰ τί ἡμεῖς οὐκ ἠδυνήθημεν ἐκβαλεῖν αὐτό;", "en": {"kjv": "Then came the disciples to Jesus apart, and said, Why could not we cast him out?", "web": "Then the disciples came to Jesus privately, and said, “Why weren’t we able to cast it out?”", "bsb": "Afterward the disciples came to Jesus privately and asked, “Why couldn’t we drive it out?”", "asv": "Then came the disciples to Jesus apart, and said, Why could not we cast it out?", "ylt": "Then the disciples having come to Jesus by himself, said, `Wherefore were we not able to cast him out?'", "tyndale": "Then came the disciples to Iesus secretly and sayde: Why could not we cast him out?", "dra": "Jesus said to them: Because of your unbelief. For, amen I say to you, if you have faith as a grain of mustard seed, you shall say to this mountain: Remove from hence hither, and it shall remove: and nothing shall be impossible to you.", "bbe": "Then the disciples came to Jesus privately, and said, Why were we not able to send it out?", "geneva": "Then came the disciples to Iesus apart, and said, Why could not we cast him out?", "wycliffe": "Jhesus seith to hem, For youre vnbileue. Treuli Y seie to you, if ye han feith, as a corn of seneueye, ye schulen seie to this hil, Passe thou hennus, and it schal passe; and no thing schal be vnpossible to you;", "rotherham": "Then, the disciples, coming near, to Jesus, privately, said—Wherefore could, we, not cast it out?", "weymouth": "Then the disciples came to Jesus privately and asked Him, \"Why could not we expel the demon?\"", "darby": "Then the disciples, coming to Jesus apart, said [to him], Why were not we able to cast him out?", "twenty": "Afterwards the disciples came up to Jesus, and asked him privately: “Why was it that we could not drive it out?”", "acv": "Then the disciples having come to Jesus in private, said, Why could we not cast it out?", "anderson": "Then the disciples came to Jesus privately, and said: Why were we not able to cast him out?", "haweis": "Then the disciples of Jesus coming privately, said, Why could not we cast it out?", "noyes": "Then the disciples came to Jesus apart, and said, Why could not we cast it out?", "webster": "Then came the disciples to Jesus apart, and said, Why could not we cast him out?", "vulgate": "tunc accesserunt discipuli ad Iesum secreto et dixerunt quare nos non potuimus eicere illum;"}}, {"v": 20, "ref": "17:20", "o": "ὁ δὲ ⸀λέγει αὐτοῖς· Διὰ τὴν ⸀ὀλιγοπιστίαν ὑμῶν· ἀμὴν γὰρ λέγω ὑμῖν, ἐὰν ἔχητε πίστιν ὡς κόκκον σινάπεως, ἐρεῖτε τῷ ὄρει τούτῳ· ⸂Μετάβα ἔνθεν⸃ ἐκεῖ, καὶ μεταβήσεται, καὶ οὐδὲν ἀδυνατήσει ⸀ὑμῖν.", "en": {"kjv": "And Jesus said unto them, Because of your unbelief: for verily I say unto you, If ye have faith as a grain of mustard seed, ye shall say unto this mountain, Remove hence to yonder place; and it shall remove; and nothing shall be impossible unto you.", "web": "He said to them, “Because of your unbelief. For most certainly I tell you, if you have faith as a grain of mustard seed, you will tell this mountain, ‘Move from here to there,’ and it will move; and nothing will be impossible for you.", "bsb": "“Because you have so little faith,” He answered. “For truly I tell you, if you have faith the size of a mustard seed, you can say to this mountain, ‘Move from here to there,’ and it will move. Nothing will be impossible for you.”", "asv": "And he saith unto them, Because of your little faith: for verily I say unto you, If ye have faith as a grain of mustard seed, ye shall say unto this mountain, Remove hence to yonder place; and it shall remove; and nothing shall be impossible unto you.", "ylt": "And Jesus said to them, `Through your want of faith; for verily I say to you, if ye may have faith as a grain of mustard, ye shall say to this mount, Remove hence to yonder place, and it shall remove, and nothing shall be impossible to you,", "tyndale": "Iesus sayd vnto the: Because of youre vnbelefe For I saye veryly vnto you: yf ye had faythe as a grayne of musterd seed ye shuld saye vnto this moutayne remove hence to yonder place and he shuld remove: nether shuld eny thinge be vnpossible for you to do.", "dra": "But this kind is not cast out but by prayer and fasting.", "bbe": "And he says to them, Because of your little faith: for truly I say to you, If you have faith as a grain of mustard seed, you will say to this mountain, Be moved from this place to that; and it will be moved; and nothing will be impossible to you.", "geneva": "And Iesus said vnto them, Because of your vnbeliefe: for verely I say vnto you, if ye haue faith as much as is a graine of mustarde seede, ye shall say vnto this mountaine, Remooue hence to yonder place, and it shall remoue: and nothing shalbe vnpossible vnto you.", "wycliffe": "but this kynde is not caste out, but bi preiyng and fastyng.", "rotherham": "And, he, saith unto them—Because of your little faith. For, verily, I say unto you—If ye have faith as a grain of mustard seed, ye shall say to this mountain, remove hence yonder; and it shall be removed, and, nothing, shall be impossible to you.", "weymouth": "\"Because your faith is so small,\" He replied; \"for I solemnly declare to you that if you have faith like a mustard-seed, you shall say to this mountain, `Remove from this place to that,' and it will remove; and nothing shall be impossible to you.", "darby": "And he says to them, Because of your unbelief; for verily I say unto you, If ye have faith as a grain of mustard [seed], ye shall say to this mountain, Be transported hence there, and it shall transport itself; and nothing shall be impossible to you.", "twenty": "“Because you have so little faith,” he answered; “for, I tell you, if your faith were only like a mustard-seed, you could say to this mountain ‘Move from this place to that!’ and it would be moved; and nothing would be impossible to you.”", "acv": "And Jesus said to them, Because of your unbelief. For truly I say to you, if ye have faith as a grain of a mustard plant, ye will say to this mountain, Remove from here to there, and it will depart, and nothing will be impossible to you.", "anderson": "And Jesus said to them: Because of your unbelief. For verily I say to you, If you have faith like a grain of mustard-seed, you shall say to this mountain, Be removed from this place to that, and it shall be removed: and nothing shall be impossible for you.", "haweis": "Then said Jesus unto them, Because of your unbelief: for verily I say unto you, If ye have faith as a grain of mustard, ye shall say to this mountain, Remove from hence, thither, and it will remove; and nothing will be impossible for you.", "noyes": "And he said to them, Because of your want of faith. For truly do I say to you, If ye have faith as a grain of mustard, ye shall say to this mountain, Remove hence to yonder place, and it will remove; and nothing will be impossible to you.", "webster": "And Jesus said to them, Because of your unbelief: for verily I say to you, If ye have faith as a grain of mustard-seed, ye shall say to this mountain, Remove hence to yonder place, and it shall remove; and nothing shall be impossible to you.", "vulgate": "dicit illis propter incredulitatem vestram amen quippe dico vobis si habueritis fidem sicut granum sinapis dicetis monti huic transi hinc et transibit et nihil inpossibile erit vobis;"}}, {"v": 21, "ref": "17:21", "o": "", "en": {"kjv": "Howbeit this kind goeth not out but by prayer and fasting.", "web": "But this kind doesn’t go out except by prayer and fasting.”", "bsb": "", "asv": "", "ylt": "and this kind doth not go forth except in prayer and fasting.'", "tyndale": "How be it this kynde goeth not oute but by prayer and fastinge.", "dra": "And when they abode together in Galilee, Jesus said to them: The Son of man shall be betrayed into the hands of men:", "bbe": "", "geneva": "Howbeit this kinde goeth not out, but by prayer and fasting.", "wycliffe": "And whilis thei weren abidynge togidere in Galilee, Jhesus seide to hem, Mannus sone schal be bitraied in to the hondis of men;", "rotherham": "", "weymouth": "But an evil spirit of this kind is only driven out by prayer and fasting.\"", "darby": "But this kind does not go out but by prayer and fasting.", "twenty": "", "acv": "But this kind does not go out except by prayer and fasting.", "anderson": "But this kind does not go out but by prayer and fasting.", "haweis": "But this kind goeth not out but by prayer and fasting.", "noyes": "", "webster": "However, this kind goeth not out, but by prayer and fasting.", "vulgate": "hoc autem genus non eicitur nisi per orationem et ieiunium;"}}, {"v": 22, "ref": "17:22", "o": "⸀Συστρεφομένων δὲ αὐτῶν ἐν τῇ Γαλιλαίᾳ εἶπεν αὐτοῖς ὁ Ἰησοῦς· Μέλλει ὁ υἱὸς τοῦ ἀνθρώπου παραδίδοσθαι εἰς χεῖρας ἀνθρώπων,", "en": {"kjv": "And while they abode in Galilee, Jesus said unto them, The Son of man shall be betrayed into the hands of men:", "web": "While they were staying in Galilee, Jesus said to them, “The Son of Man is about to be delivered up into the hands of men,", "bsb": "When they gathered together in Galilee, Jesus told them, “The Son of Man is about to be delivered into the hands of men.", "asv": "And while they abode in Galilee, Jesus said unto them, The Son of man shall be delivered up into the hands of men;", "ylt": "And while they are living in Galilee, Jesus said to them, `The Son of Man is about to be delivered up to the hands of men,", "tyndale": "As they passed the tyme in Galile Iesus sayde vnto them: the sonne of man shalbe betrayed into the hondes of men", "dra": "And they shall kill him, and the third day he shall rise again. And they were troubled exceedingly.", "bbe": "And while they were going about in Galilee, Jesus said to them, The Son of man will be given up into the hands of men;", "geneva": "And they being in Galile, Iesus said vnto them, The Sonne of man shall be deliuered into the handes of men,", "wycliffe": "and thei schulen sle hym, and the thridde day he schal rise ayen to lijf.", "rotherham": "And, as they were being gathered together in Galilee, Jesus said unto them—The Son of Man is about to be delivered up into the hands of men;", "weymouth": "As they were travelling about in Galilee, Jesus said to them, \"The Son of Man is about to be betrayed into the hands of men;", "darby": "And while they abode in Galilee, Jesus said to them, The Son of man is about to be delivered up into [the] hands of men,", "twenty": "While Jesus and his disciples were together in Galilee, he said to them: “The Son of Man is destined to be betrayed into the hands of his fellow-men,", "acv": "And while they turned back in Galilee, Jesus said to them, The Son of man is going to be delivered into the hands of men,", "anderson": "And as they were making their journey in Galilee, Jesus said to them: The Son of man is about to be delivered into the hands of men;", "haweis": "And as they were returning into Galilee, Jesus said unto them, The Son of man must be delivered into the hands of men:", "noyes": "And while they were together in Galilee, Jesus said to them, The Son of man is about to be delivered up into the hands of men,", "webster": "And while they abode in Galilee, Jesus said to them, The Son of man will be betrayed into the hands of men:", "vulgate": "conversantibus autem eis in Galilaea dixit illis Iesus Filius hominis tradendus est in manus hominum;"}}, {"v": 23, "ref": "17:23", "o": "καὶ ἀποκτενοῦσιν αὐτόν, καὶ τῇ τρίτῃ ἡμέρᾳ ἐγερθήσεται. καὶ ἐλυπήθησαν σφόδρα.", "en": {"kjv": "And they shall kill him, and the third day he shall be raised again. And they were exceeding sorry.", "web": "and they will kill him, and the third day he will be raised up.” They were exceedingly sorry.", "bsb": "They will kill Him, and on the third day He will be raised to life.” And the disciples were deeply grieved.", "asv": "and they shall kill him, and the third day he shall be raised up. And they were exceeding sorry.", "ylt": "and they shall kill him, and the third day he shall rise,' and they were exceeding sorry.", "tyndale": "and they shall kill him and the thyrd daye he shall ryse agayne. And they sorowed greatly.", "dra": "And when they were come to Capharnaum, they that received the didrachmas, came to Peter, and said to him: Doth not your master pay the didrachma?", "bbe": "And they will put him to death, and the third day he will come again from the dead. And they were very sad.", "geneva": "And they shall kill him, but the thirde day shall he rise againe: and they were very sorie.", "wycliffe": "And thei weren ful sori. And whanne thei camen to Cafarnaum, thei that token tribute, camen to Petre, and seiden to hym, Youre maister payeth not tribute?", "rotherham": "And they will slay him, and, on the third day, will he, arise. And they were grieved exceedingly.", "weymouth": "they will put Him to death, but on the third day He will be raised to life again.\" And they were exceedingly distressed.", "darby": "and they shall kill him; and the third day he shall be raised up. And they were greatly grieved.", "twenty": "and they will put him to death, but on the third day he will rise.” And the disciples were greatly distressed.", "acv": "and they will kill him, and the third day he will be raised up. And they were exceedingly sorry.", "anderson": "and they will kill him, and on the third day he will be raised again. And they were very sad.", "haweis": "and they shall kill him, and the third day he shall rise again. And they were grieved exceedingly.", "noyes": "and they will put him to death; and on the third day he will rise again. And they were greatly grieved.", "webster": "And they will kill him, and the third day he will be raised again: And they were exceedingly grieved.", "vulgate": "et occident eum et tertio die resurget et contristati sunt vehementer;"}}, {"v": 24, "ref": "17:24", "o": "Ἐλθόντων δὲ αὐτῶν εἰς Καφαρναοὺμ προσῆλθον οἱ τὰ δίδραχμα λαμβάνοντες τῷ Πέτρῳ καὶ εἶπαν· Ὁ διδάσκαλος ὑμῶν οὐ τελεῖ τὰ δίδραχμα;", "en": {"kjv": "And when they were come to Capernaum, they that received tribute money came to Peter, and said, Doth not your master pay tribute?", "web": "When they had come to Capernaum, those who collected the didrachma coins came to Peter, and said, “Doesn’t your teacher pay the didrachma?”", "bsb": "After they had arrived in Capernaum, the collectors of the two-drachma tax came to Peter and asked, “Does your Teacher pay the two drachmas?”", "asv": "And when they were come to Capernaum, they that received the half-shekel came to Peter, and said, Doth not your teacher pay the half-shekel?", "ylt": "And they having come to Capernaum, those receiving the didrachms came near to Peter, and said, `Your teacher--doth he not pay the didrachms?' He saith, `Yes.'", "tyndale": "And when they were come to Capernau they yt were wont to gadre poll money came to Peter and sayde: Doth youre master paye tribute?", "dra": "He said: Yes. And when he was come into the house, Jesus prevented him, saying: What is thy opinion, Simon? The kings of the earth, of whom do they receive tribute or custom, of their own children, or of strangers?", "bbe": "And when they had come to Capernaum, those who took the Temple tax came to Peter and said, Does not your master make payment of the Temple tax?", "geneva": "And when they were come to Capernaum, they that receiued polle money, came to Peter, and sayd, Doeth not your Master pay polle money?", "wycliffe": "And he seide, Yhis. And whanne he was comen in to the hous, Jhesus cam bifor hym, and seide, Symount, what semeth to thee? Kyngis of erthe, of whom taken thei tribute? of her sones, ether of aliens?", "rotherham": "And, when they came into Capernaum, they who, the half shekel, were receiving, came near unto Peter, and said, Your teacher, doth he not pay the half shekel?", "weymouth": "After their arrival at Capernaum the collectors of the half-shekel came and asked Peter, \"Does not your Teacher pay the half-shekel?\"", "darby": "And when they came to Capernaum, those who received the didrachmas came to Peter and said, Does your teacher not pay the didrachmas?", "twenty": "After they had reached Capernaum, the collectors of the Temple-rate came up to Peter, and said: “Does not your Master pay the Temple-rate?”", "acv": "And when they came to Capernaum, those who receive the double-drachma came to Peter, and said, Does not your teacher pay the double-drachma?", "anderson": "And when they had come into Capernaum, those who collected the didrachma came to Peter, and said: Does not your teacher pay the didrachma?", "haweis": "And when they came to Capernaum, they who receive the tax of two drachmas came to Peter, and said, Doth not your master pay tribute?", "noyes": "And when they had come to Capernaum, those who received the half-shekel came to Peter, and said, Doth not your teacher pay the half-shekel?", "webster": "And when they had come to Capernaum, they that received tribute-[money], came to Peter, and said, Doth not your Master pay tribute?", "vulgate": "et cum venissent Capharnaum accesserunt qui didragma accipiebant ad Petrum et dixerunt magister vester non solvit didragma;"}}, {"v": 25, "ref": "17:25", "o": "λέγει· Ναί. καὶ ⸀ἐλθόντα εἰς τὴν οἰκίαν προέφθασεν αὐτὸν ὁ Ἰησοῦς λέγων· Τί σοι δοκεῖ, Σίμων; οἱ βασιλεῖς τῆς γῆς ἀπὸ τίνων λαμβάνουσιν τέλη ἢ κῆνσον; ἀπὸ τῶν υἱῶν αὐτῶν ἢ ἀπὸ τῶν ἀλλοτρίων;", "en": {"kjv": "He saith, Yes. And when he was come into the house, Jesus prevented him, saying, What thinkest thou, Simon? of whom do the kings of the earth take custom or tribute? of their own children, or of strangers?", "web": "He said, “Yes.” When he came into the house, Jesus anticipated him, saying, “What do you think, Simon? From whom do the kings of the earth receive toll or tribute? From their children, or from strangers?”", "bsb": "“Yes,” he answered. When Peter entered the house, Jesus preempted him. “What do you think, Simon?” He asked. “From whom do the kings of the earth collect customs and taxes: from their own sons, or from others?”", "asv": "He saith, Yea. And when he came into the house, Jesus spake first to him, saying, What thinkest thou, Simon? the kings of the earth, from whom do they receive toll or tribute? from their sons, or from strangers?", "ylt": "And when he came into the house, Jesus anticipated him, saying, `What thinkest thou, Simon? the kings of the earth--from whom do they receive custom or poll-tax? from their sons or from the strangers?'", "tyndale": "He sayd: ye. And when he was come into the house Iesus spake fyrst to him saying What thinkest thou Simon? of whome do ye kynges of the erth take tribute or poll money? of their chyldren or of straungers?", "dra": "And he said: Of strangers. Jesus said to him: Then the children are free.", "bbe": "He says, Yes. And when he came into the house, Jesus said to him, What is your opinion, Simon? from whom do the kings of the earth get payment or tax? from their sons or from other people?", "geneva": "He sayd, Yes. And when he was come into the house, Iesus preuented him, saying, What thinkest thou, Simon? Of whome doe the Kings of the earth take tribute, or polle money? of their children, or of strangers?", "wycliffe": "And he seide, Of aliens. Jhesus seide to hym, Thanne sones ben fre.", "rotherham": "He saith—Yea. And, coming into the house, Jesus anticipated him, saying, How, to thee, doth it seem, Simon? The kings of the earth, of whom receive they dues or tax? from their sons, or from the aliens?", "weymouth": "\"Yes,\" he replied, and then went into the house. But before he spoke a word Jesus said, \"What think you, Simon? From whom do this world's kings receive customs or capitation tax? from their own children, or from others?\"", "darby": "He says, Yes. And when he came into the house, Jesus anticipated him, saying, What dost thou think, Simon? the kings of the earth, from whom do they receive custom or tribute? from their own sons or from strangers?", "twenty": "“Yes,” answered Peter. But, on going into the house, before he could speak, Jesus said: “What do you think, Simon? From whom do earthly kings take taxes or tribute? From their sons, or from others?”", "acv": "He says, Yes. And when he entered into the house, Jesus anticipated him, saying, What think thou, Simon? The kings of the earth, from whom do they take taxes or tribute, from their sons or from strangers?", "anderson": "He said: Yes. And when he had come into the house, before he had spoken, Jesus said to him: What think you, Simon? From whom do the kings of the earth collect tax or tribute? From their own sons, or from the sons of others?", "haweis": "He saith, Yes. And when he came into the house, Jesus prevented him, saying, What thinkest thou, Simon? of whom do the kings of the earth receive customs and tax? from their own children, or from aliens?", "noyes": "He saith, Yes. And when he had come into the house, Jesus anticipated him, saying, What thinkest thou, Simon? Of whom do the kings of the earth take customs or taxes? Of their own sons, or of strangers?", "webster": "He saith, Yes. And when he had come into the house, Jesus anticipated him, saying, What thinkest thou, Simon? from whom do the kings of the earth take custom or tribute? from their own children, or from strangers?", "vulgate": "ait etiam et cum intrasset domum praevenit eum Iesus dicens quid tibi videtur Simon reges terrae a quibus accipiunt tributum vel censum a filiis suis an ab alienis;"}}, {"v": 26, "ref": "17:26", "o": "⸂εἰπόντος δέ⸃· Ἀπὸ τῶν ἀλλοτρίων, ἔφη αὐτῷ ὁ Ἰησοῦς· Ἄρα γε ἐλεύθεροί εἰσιν οἱ υἱοί.", "en": {"kjv": "Peter saith unto him, Of strangers. Jesus saith unto him, Then are the children free.", "web": "Peter said to him, “From strangers.” Jesus said to him, “Therefore the children are exempt.", "bsb": "“From others,” Peter answered. “Then the sons are exempt,” Jesus declared.", "asv": "And when he said, From strangers, Jesus said unto him, Therefore the sons are free.", "ylt": "Peter saith to him, `From the strangers.' Jesus said to him, `Then are the sons free;", "tyndale": "Peter sayde vnto him: of straungers. Then sayd Iesus vnto him agayne: Then are the chyldren fre.", "dra": "But that we may not scandalize them, go to the sea, and cast in a hook: and that fish which shall first come up, take: and when thou hast opened it's mouth, thou shalt find a stater: take that, and give it to them for me and thee.", "bbe": "And when he said, From other people, Jesus said to him, Then are the sons free.", "geneva": "Peter sayd vnto him, Of strangers. Then said Iesus vnto him, Then are the children free.", "wycliffe": "But that we sclaundre hem not, go to the see, and caste an hook, and take thilke fisch that first cometh vp; and, whanne his mouth is opened, thou schalt fynde a stater, and yyue for thee and for me.", "rotherham": "And, when he said, From the aliens, Jesus said unto him, Well then, free, are the sons!", "weymouth": "\"From others,\" he replied. \"Then the children go free,\" said Jesus.", "darby": "Peter says to him, From strangers. Jesus said to him, Then are the sons free.", "twenty": "“From others,” answered Peter. “Well then,” continued Jesus, “their sons go free.", "acv": "And Peter says to him, From strangers. Jesus said to him, Therefore the sons are free.", "anderson": "Peter said to him: From the sons of others. Jesus said to him: Then are their own sons free.", "haweis": "Peter saith to him, From aliens. Jesus saith unto him, In that case then the children are free.", "noyes": "And when he said, Of strangers, Jesus said to him, Then are the sons free.", "webster": "Peter saith to him, From strangers. Jesus saith to him, Then are the children free.", "vulgate": "et ille dixit ab alienis dixit illi Iesus ergo liberi sunt filii;"}}, {"v": 27, "ref": "17:27", "o": "ἵνα δὲ μὴ σκανδαλίσωμεν αὐτούς, πορευθεὶς ⸀εἰς θάλασσαν βάλε ἄγκιστρον καὶ τὸν ⸀ἀναβάντα πρῶτον ἰχθὺν ἆρον, καὶ ἀνοίξας τὸ στόμα αὐτοῦ εὑρήσεις στατῆρα· ἐκεῖνον λαβὼν δὸς αὐτοῖς ἀντὶ ἐμοῦ καὶ σοῦ.", "en": {"kjv": "Notwithstanding, lest we should offend them, go thou to the sea, and cast an hook, and take up the fish that first cometh up; and when thou hast opened his mouth, thou shalt find a piece of money: that take, and give unto them for me and thee.", "web": "But, lest we cause them to stumble, go to the sea, cast a hook, and take up the first fish that comes up. When you have opened its mouth, you will find a stater coin.Take that, and give it to them for me and you.”", "bsb": "“But so that we may not offend them, go to the sea, cast a hook, and take the first fish you catch. When you open its mouth, you will find a four-drachma coin. Take it and give it to them for My tax and yours.”", "asv": "But, lest we cause them to stumble, go thou to the sea, and cast a hook, and take up the fish that first cometh up; and when thou hast opened his mouth, thou shalt find a shekel: that take, and give unto them for me and thee.", "ylt": "but, that we may not cause them to stumble, having gone to the sea, cast a hook, and the fish that hath come up first take thou up, and having opened its mouth, thou shalt find a stater, that having taken, give to them for me and thee.'", "tyndale": "Neverthelesse lest we shuld offende the: goo to ye see and cast in thyne angle and take the fysshe yt fyrst cometh vp: and when thou hast opened his mouthe thou shalt fynde a pece of twentie pence: yt take and paye for me and the.", "dra": "", "bbe": "But, so that we may not be a cause of trouble to them, go to the sea, and let down a hook, and take the first fish which comes up; and in his mouth you will see a bit of money: take that, and give it to them for me and you.", "geneva": "Neuerthelesse, lest we should offend them: goe to the sea, and cast in an angle, and take the first fish that commeth vp, and when thou hast opened his mouth, thou shalt finde a piece of twentie pence: that take, and giue it vnto them for me and thee.", "wycliffe": "", "rotherham": "But, that we may not cause them to stumble, go unto the sea, and cast in a hook, and, the first fish that cometh up, take, and, opening its mouth, thou shalt find a shekel,—that, take, and give to them for me and thee.", "weymouth": "\"However, lest we cause them to sin, go and throw a hook into the Lake, and take the first fish that comes up. When you open its mouth, you will find a shekel in it: bring that coin and give it to them for yourself and me.\"", "darby": "But that we may not be an offence to them, go to the sea and cast a hook, and take the first fish that comes up, and when thou hast opened its mouth thou wilt find a stater; take that and give it to them for me and thee.", "twenty": "Still, that we may not shock them, go and throw a line into the Sea; take the first fish that rises, open its mouth, and you will find in it a piece of money. Take that, and give it to the collectors for both of us.”", "acv": "But, so that we might not offend them, after going to the sea, cast a hook. And take up the first fish coming up, and having opened its mouth, thou will find a four-drachma coin. After taking that, give thou to them for me and thee.", "anderson": "But that we may give them no offense, go to the sea, and throw in a hook, and take the fish that comes up first; and when you have opened his mouth, you will find a stater; take that, and give to them for me and you.", "haweis": "But that we give them no offence, go unto the sea, and cast in a hook, and take the first fish which cometh up; and on opening his mouth, thou wilt find a stater, that take and give them for me and thee.", "noyes": "But that we may not give them offence, go to the lake, and cast a hook, and take the fish that first cometh up; and on opening his mouth, thou wilt find a shekel; take that, and give it to them for me and thee.", "webster": "Notwithstanding, lest we should offend them, go thou to the sea, and cast a hook, and take the fish that first cometh up: and when thou hast opened his mouth, thou shalt find a piece of money: take that, and give to them for me and thee.", "vulgate": "ut autem non scandalizemus eos vade ad mare et mitte hamum et eum piscem qui primus ascenderit tolle et aperto ore eius invenies staterem illum sumens da eis pro me et te;"}}]}, {"c": 18, "verses": [{"v": 1, "ref": "18:1", "o": "Ἐν ἐκείνῃ τῇ ὥρᾳ προσῆλθον οἱ μαθηταὶ τῷ Ἰησοῦ λέγοντες· Τίς ἄρα μείζων ἐστὶν ἐν τῇ βασιλείᾳ τῶν οὐρανῶν;", "en": {"kjv": "At the same time came the disciples unto Jesus, saying, Who is the greatest in the kingdom of heaven?", "web": "In that hour the disciples came to Jesus, saying, “Who then is greatest in the Kingdom of Heaven?”", "bsb": "At that time the disciples came to Jesus and asked, “Who then is the greatest in the kingdom of heaven?”", "asv": "In that hour came the disciples unto Jesus, saying, Who then is greatest in the kingdom of heaven?", "ylt": "At that hour came the disciples near to Jesus, saying, `Who, now, is greater in the reign of the heavens?'", "tyndale": "The same tyme the disciples came vnto Iesus saying: who is ye greatest in the kyngdome of heve?", "dra": "At that hour the disciples came to Jesus, saying: Who, thinkest thou, is the greater in the kingdom of heaven?", "bbe": "In that hour the disciples came to Jesus, saying, Who is greatest in the kingdom of heaven?", "geneva": "The same time the disciples came vnto Iesus, saying, Who is the greatest in the kingdome of heauen?", "wycliffe": "In that our the disciplis camen to Jhesu, and seiden, Who, gessist thou, is gretter in the kyngdom of heuenes?", "rotherham": "In that hour came, the disciples unto Jesus, saying—Who then is, greatest, in the kingdom of the heavens?", "weymouth": "Just then the disciples came to Jesus and asked, \"Who ranks higher than others in the Kingdom of the Heavens?\"", "darby": "In that hour the disciples came to Jesus saying, Who then is greatest in the kingdom of the heavens?", "twenty": "On the same occasion the disciples came to Jesus, and asked him: “Who is really the greatest in the Kingdom of Heaven?”", "acv": "In that hour the disciples came to Jesus, saying, Who then is greater in the kingdom of the heavens?", "anderson": "At that hour the disciples came to Jesus, and said: Who then is greatest in the kingdom of heaven?", "haweis": "AT that time came the disciples to Jesus, saying, Who is indeed the greatest in the kingdom of heaven?", "noyes": "At that time the disciples came to Jesus, saying, Who then is greatest in the kingdom of heaven?", "webster": "At the same time came the disciples to Jesus, saying, Who is the greatest in the kingdom of heaven?", "vulgate": "in illa hora accesserunt discipuli ad Iesum dicentes quis putas maior est in regno caelorum;"}}, {"v": 2, "ref": "18:2", "o": "καὶ ⸀προσκαλεσάμενος παιδίον ἔστησεν αὐτὸ ἐν μέσῳ αὐτῶν", "en": {"kjv": "And Jesus called a little child unto him, and set him in the midst of them,", "web": "Jesus called a little child to himself, and set him in their midst,", "bsb": "Jesus invited a little child to stand among them.", "asv": "And he called to him a little child, and set him in the midst of them,", "ylt": "And Jesus having called near a child, did set him in the midst of them,", "tyndale": "Iesus called a chylde vnto him and set him in the middes of them:", "dra": "And Jesus, calling unto him a little child, set him in the midst of them.", "bbe": "And he took a little child, and put him in the middle of them,", "geneva": "And Iesus called a litle childe vnto him, and set him in the mids of them,", "wycliffe": "And Jhesus clepide a litil child, and putte hym in the myddil of hem;", "rotherham": "And, calling near a child, he set it in the midst of them,", "weymouth": "So He called a young child to Him, and, bidding him stand in the midst of them,", "darby": "And Jesus having called a little child to [him], set it in their midst,", "twenty": "Jesus called a little child to him, and placed it in the middle of them, and then said:", "acv": "And having called in a child, Jesus set it in the midst of them.", "anderson": "And Jesus called a little child to him, and placed him in the midst of them,", "haweis": "And Jesus calling a little boy, set him in the midst of them,", "noyes": "And he called a child to him, and set him in the midst of them,", "webster": "And Jesus called a little child to him, and set him in the midst of them,", "vulgate": "et advocans Iesus parvulum statuit eum in medio eorum;"}}, {"v": 3, "ref": "18:3", "o": "καὶ εἶπεν· Ἀμὴν λέγω ὑμῖν, ἐὰν μὴ στραφῆτε καὶ γένησθε ὡς τὰ παιδία, οὐ μὴ εἰσέλθητε εἰς τὴν βασιλείαν τῶν οὐρανῶν.", "en": {"kjv": "And said, Verily I say unto you, Except ye be converted, and become as little children, ye shall not enter into the kingdom of heaven.", "web": "and said, “Most certainly I tell you, unless you turn, and become as little children, you will in no way enter into the Kingdom of Heaven.", "bsb": "“Truly I tell you,” He said, “unless you change and become like little children, you will never enter the kingdom of heaven.", "asv": "and said, Verily I say unto you, Except ye turn, and become as little children, ye shall in no wise enter into the kingdom of heaven.", "ylt": "and said, `Verily I say to you, if ye may not be turned and become as the children, ye may not enter into the reign of the heavens;", "tyndale": "and sayd. Verely I say vnto you: except ye tourne and become as chyldren ye cannot enter into the kyngdom of heven.", "dra": "And said: amen I say to you, unless you be converted, and become as little children, you shall not enter into the kingdom of heaven.", "bbe": "And said, Truly, I say to you, If you do not have a change of heart and become like little children, you will not go into the kingdom of heaven.", "geneva": "And sayd, Verely I say vnto you, except ye be conuerted, and become as litle children, ye shall not enter into the kingdome of heauen.", "wycliffe": "and seide, Y seie treuthe to you, but ye be turned, and maad as litle children, ye schulen not entre in to the kyngdom of heuenes.", "rotherham": "and said—Verily, I say unto you, Except ye turn and become as the children, in nowise, shall ye enter into the kingdom of the heavens.", "weymouth": "said, \"In solemn truth I tell you that unless you turn and become like little children, you will in no case be admitted into the Kingdom of the Heavens.", "darby": "and said, Verily I say to you, Unless ye are converted and become as little children, ye will not at all enter into the kingdom of the heavens.", "twenty": "“I tell you, unless you change and become like little children, you will not enter the Kingdom of Heaven at all.", "acv": "And he said, Truly I say to you, if ye are not turned, and become as children, ye will, no, not enter into the kingdom of the heavens.", "anderson": "and said: Verily I say to you, Unless you turn and become as little children, you can not enter the kingdom of heaven.", "haweis": "and said, Verily I say unto you, Except ye be changed and be as little children, ye shall in no wise enter into the kingdom of heaven.", "noyes": "and said, Truly do I say to you, Unless ye are changed, and become as children, ye will not enter the kingdom of heaven.", "webster": "And said, Verily I say to you, Except ye be converted, and become as little children, ye shall not enter into the kingdom of heaven.", "vulgate": "et dixit amen dico vobis nisi conversi fueritis et efficiamini sicut parvuli non intrabitis in regnum caelorum;"}}, {"v": 4, "ref": "18:4", "o": "ὅστις οὖν ταπεινώσει ἑαυτὸν ὡς τὸ παιδίον τοῦτο, οὗτός ἐστιν ὁ μείζων ἐν τῇ βασιλείᾳ τῶν οὐρανῶν·", "en": {"kjv": "Whosoever therefore shall humble himself as this little child, the same is greatest in the kingdom of heaven.", "web": "Whoever therefore humbles himself as this little child, the same is the greatest in the Kingdom of Heaven.", "bsb": "Therefore, whoever humbles himself like this little child is the greatest in the kingdom of heaven.", "asv": "Whosoever therefore shall humble himself as this little child, the same is the greatest in the kingdom of heaven.", "ylt": "whoever then may humble himself as this child, he is the greater in the reign of the heavens.", "tyndale": "Whosoever therfore humble him sylfe as this chylde the same is the greatest in ye kyngdome of heve.", "dra": "Whosoever therefore shall humble himself as this little child, he is the greater in the kingdom of heaven.", "bbe": "Whoever, then, will make himself as low as this little child, the same is the greatest in the kingdom of heaven.", "geneva": "Whosoeuer therefore shall humble himselfe as this litle childe, the same is the greatest in the kingdome of heauen.", "wycliffe": "Therfor who euer mekith hym as this litil child, he is gretter in the kyngdom of heuenes.", "rotherham": "Whosoever therefore shall humble himself as this child, the same, is the greatest, in the kingdom of the heavens;", "weymouth": "Whoever therefore shall humble himself as this young child, he it is who is superior to others in the Kingdom of the Heavens.", "darby": "Whoever therefore shall humble himself as this little child, he is the greatest in the kingdom of the heavens;", "twenty": "Therefore, any one who will humble himself like this child — that man shall be the greatest in the Kingdom of Heaven.", "acv": "He therefore who will make himself lowly as this child, this man is the greater in the kingdom of the heavens.", "anderson": "Whoever, therefore, humbles himself as this little child, is greatest in the kingdom of heaven.", "haweis": "Whosoever therefore shall humble himself, as this little child, he shall be greatest in the kingdom of heaven.", "noyes": "Whoever therefore shall humble himself as this child, he is the greatest in the kingdom of heaven.", "webster": "Whoever therefore shall humble himself as this little child, the same is greatest in the kingdom of heaven.", "vulgate": "quicumque ergo humiliaverit se sicut parvulus iste hic est maior in regno caelorum;"}}, {"v": 5, "ref": "18:5", "o": "καὶ ὃς ⸀ἐὰν δέξηται ⸂ἓν παιδίον τοιοῦτο⸃ ἐπὶ τῷ ὀνόματί μου, ἐμὲ δέχεται.", "en": {"kjv": "And whoso shall receive one such little child in my name receiveth me.", "web": "Whoever receives one such little child in my name receives me,", "bsb": "And whoever welcomes a little child like this in My name welcomes Me.", "asv": "And whoso shall receive one such little child in my name receiveth me:", "ylt": "`And he who may receive one such child in my name, doth receive me,", "tyndale": "And who soever receaveth suche a chylde in my name receaveth me.", "dra": "And he that shall receive one such little child in my name, receiveth me.", "bbe": "And whoever gives honour to one such little child in my name, gives honour to me:", "geneva": "And whosoeuer shall receiue one such litle childe in my name, receiueth me.", "wycliffe": "And he that resseyueth o siche litil child in my name, resseyueth me.", "rotherham": "And, whosoever shall give welcome unto one such child as this, upon my name, unto me, giveth welcome.", "weymouth": "And whoever for my sake receives one young child such as this, receives me.", "darby": "and whosoever shall receive one such little child in my name, receives me.", "twenty": "And any one who, for the sake of my Name, welcomes even one little child like this, is welcoming me.", "acv": "And whoever will receive one such child in my name receives me.", "anderson": "And whoever receives one such little child on my account, receives me;", "haweis": "And whosoever shall receive one such little child in my name, receiveth me.", "noyes": "And whoever receiveth one such child in my name, receiveth me.", "webster": "And whoever shall receive one such little child in my name, receiveth me.", "vulgate": "et qui susceperit unum parvulum talem in nomine meo me suscipit;"}}, {"v": 6, "ref": "18:6", "o": "Ὃς δ’ ἂν σκανδαλίσῃ ἕνα τῶν μικρῶν τούτων τῶν πιστευόντων εἰς ἐμέ, συμφέρει αὐτῷ ἵνα κρεμασθῇ μύλος ὀνικὸς ⸀εἰς τὸν τράχηλον αὐτοῦ καὶ καταποντισθῇ ἐν τῷ πελάγει τῆς θαλάσσης.", "en": {"kjv": "But whoso shall offend one of these little ones which believe in me, it were better for him that a millstone were hanged about his neck, and that he were drowned in the depth of the sea.", "web": "but whoever causes one of these little ones who believe in me to stumble, it would be better for him that a huge millstone should be hung around his neck, and that he should be sunk in the depths of the sea.", "bsb": "But if anyone causes one of these little ones who believe in Me to stumble, it would be better for him to have a large millstone hung around his neck and to be drowned in the depths of the sea.", "asv": "but whoso shall cause one of these little ones that believe on me to stumble, it is profitable for him that a great millstone should be hanged about his neck, and that he should be sunk in the depth of the sea.", "ylt": "and whoever may cause to stumble one of those little ones who are believing in me, it is better for him that a weighty millstone may be hanged upon his neck, and he may be sunk in the depth of the sea.", "tyndale": "But whosoever offende one of these lytelons which beleve in me: it were better for him that a milstone were hanged aboute his necke and that he were drouned in the depth of the see.", "dra": "But he that shall scandalize one of these little ones that believe in me, it were better for him that a millstone should be hanged about his neck, and that he should be drowned in the depth of the sea.", "bbe": "But whoever is a cause of trouble to one of these little ones who have faith in me, it would be better for him to have a great stone fixed to his neck, and to come to his end in the deep sea.", "geneva": "But whosoeuer shall offend one of these litle ones which beleeue in me, it were better for him, that a milstone were hanged about his necke, and that he were drowned in the depth of the sea.", "wycliffe": "But who so sclaundrith oon of these smale, that bileuen in me, it spedith to hym that a mylnstoon `of assis be hangid in his necke, and he be drenchid in the depnesse of the see.", "rotherham": "And, whosoever shall cause to stumble one of these little ones who believe in me, it profiteth him, that there be hung a large mill-stone about his neck, and he be sunk in the wide main of the sea.", "weymouth": "But whoever shall occasion the fall of one of these little ones who believe in me, it would be better for him to have a millstone hung round his neck and to be drowned in the depths of the sea.", "darby": "But whosoever shall offend one of these little ones who believe in me, it were profitable for him that a great millstone had been hanged upon his neck and he be sunk in the depths of the sea.", "twenty": "But, if any one puts a snare in the way of one of these lowly ones who believe in me, it would be best for him to be sunk in the depths of the sea with a great millstone hung round his neck.", "acv": "But whoever may cause one of these little ones who believe in me to stumble, it is advantageous for him that a donkey-powered millstone were hanged on his neck, and he were drowned in the depth of the sea.", "anderson": "but whoever ensnares one of these little ones that believe in me, it were better for him that a millstone were hung about his neck, and that he were drowned in the depth of the sea.", "haweis": "And whosoever shall cause one of these little ones, who believe in me, to stumble, it were better for him that a millstone was hung at his neck, and that he was sunk in the depth of the sea.", "noyes": "But whoever shall cause one of these little ones that believe in me to fall away, it were better for him to have a great millstone hung round his neck, and be swallowed up in the depth of the sea.", "webster": "But whoever shall cause one of these little ones who believe in me, to sin, it were better for him that a millstone were hanged about his neck, and [that] he were drowned in the depth of the sea.", "vulgate": "qui autem scandalizaverit unum de pusillis istis qui in me credunt expedit ei ut suspendatur mola asinaria in collo eius et demergatur in profundum maris;"}}, {"v": 7, "ref": "18:7", "o": "οὐαὶ τῷ κόσμῳ ἀπὸ τῶν σκανδάλων· ἀνάγκη ⸀γὰρ ἐλθεῖν τὰ σκάνδαλα, πλὴν οὐαὶ τῷ ⸀ἀνθρώπῳ δι’ οὗ τὸ σκάνδαλον ἔρχεται.", "en": {"kjv": "Woe unto the world because of offences! for it must needs be that offences come; but woe to that man by whom the offence cometh!", "web": "“Woe to the world because of occasions of stumbling! For it must be that the occasions come, but woe to that person through whom the occasion comes!", "bsb": "Woe to the world for the causes of sin. These stumbling blocks must come, but woe to the man through whom they come!", "asv": "Woe unto the world because of occasions of stumbling! for it must needs be that the occasions come; but woe to that man through whom the occasion cometh!", "ylt": "`Woe to the world from the stumbling-blocks! for there is a necessity for the stumbling-blocks to come, but woe to that man through whom the stumbling-block doth come!", "tyndale": "Wo be vnto the world because of offences. How be it it cannot be avoided but yt offences shalbe geven. Neverthelesse woo be to ye man by who the offence cometh.", "dra": "Woe to the world because of scandals. For it must needs be that scandals come: but nevertheless woe to that man by whom the scandal cometh.", "bbe": "A curse is on the earth because of trouble! for it is necessary for trouble to come; but unhappy is that man through whom the trouble comes.", "geneva": "Wo be vnto the world because of offences: for it must needes be that offences shall come, but wo be to that man by whome the offence commeth.", "wycliffe": "Woo to the world, for sclaundris; for it is nede that sclaundris come; netheles wo to thilke man bi whom a sclaundre cometh.", "rotherham": "Alas for the world! by reason of the causes of stumbling; for it is, necessary, that the causes of stumbling come,—nevertheless, alas for the man through whom the cause of stumbling cometh!", "weymouth": "\"Alas for the world because of causes of falling! They cannot but come, but alas for each man through whom they come!", "darby": "Woe to the world because of offences! For it must needs be that offences come; yet woe to that man by whom the offence comes!", "twenty": "Alas for the world because of such snares! There cannot but be snares; yet alas for the man who is answerable for the snare!", "acv": "Woe to the world because of stumbling-blocks. For it is necessary that the stumbling-blocks come, yet woe to that man through whom the stumbling-block comes.", "anderson": "Alas for the world because of snares! for it is necessary that snares come: but alas for that man by whom the snare comes!", "haweis": "Wo to the world because of offences! for there is a necessity that offences come: nevertheless, wo to that man by whom the offence cometh!", "noyes": "Woe to the world because of stumbling-blocks! For it must needs be that stumbling-blocks come; but woe to the man through whom the stumbling-block cometh!", "webster": "Woe to the world because of offenses! for it must needs be that offenses come; but woe to that man by whom the offense cometh!", "vulgate": "vae mundo ab scandalis necesse est enim ut veniant scandala verumtamen vae homini per quem scandalum venit;"}}, {"v": 8, "ref": "18:8", "o": "Εἰ δὲ ἡ χείρ σου ἢ ὁ πούς σου σκανδαλίζει σε, ἔκκοψον ⸀αὐτὸν καὶ βάλε ἀπὸ σοῦ· καλόν σοί ἐστιν εἰσελθεῖν εἰς τὴν ζωὴν ⸂κυλλὸν ἢ χωλόν⸃, ἢ δύο χεῖρας ἢ δύο πόδας ἔχοντα βληθῆναι εἰς τὸ πῦρ τὸ αἰώνιον.", "en": {"kjv": "Wherefore if thy hand or thy foot offend thee, cut them off, and cast them from thee: it is better for thee to enter into life halt or maimed, rather than having two hands or two feet to be cast into everlasting fire.", "web": "If your hand or your foot causes you to stumble, cut it off, and cast it from you. It is better for you to enter into life maimed or crippled, rather than having two hands or two feet to be cast into the eternal fire.", "bsb": "If your hand or your foot causes you to sin, cut it off and throw it away. It is better for you to enter life crippled or lame than to have two hands and two feet and be thrown into the eternal fire.", "asv": "And if thy hand or thy foot causeth thee to stumble, cut it off, and cast it from thee: it is good for thee to enter into life maimed or halt, rather than having two hands or two feet to be cast into the eternal fire.", "ylt": "`And if thy hand or thy foot doth cause thee to stumble, cut them off and cast from thee; it is good for thee to enter into the life lame or maimed, rather than having two hands or two feet, to be cast to the fire the age-during.", "tyndale": "Wherfore yf thy honde or thy fote offende the cut him of and cast him from the. It ys better for the to enter into lyfe halt or maymed rather then thou shuldest havinge two hondes or two fete be cast into everlasting fyre.", "dra": "And if thy hand, or thy foot, scandalize thee, cut it off, and cast it from thee. It is better for thee to go into life maimed or lame, than having two hands or two feet, to be cast into everlasting fire.", "bbe": "And if your hand or your foot is a cause of trouble, let it be cut off and put it away from you: it is better for you to go into life with the loss of a hand or a foot than, having two hands or two feet, to go into the eternal fire.", "geneva": "Wherefore, if thy hand or thy foote cause thee to offend, cut them off, and cast them from thee: it is better for thee to enter into life, halt, or maimed, then hauing two hands, or two feete, to be cast into euerlasting fire.", "wycliffe": "And if thin hoond or thi foot sclaundreth thee, kitte it of, and caste awei fro thee. It is betere to thee to entre to lijf feble, ethir crokid, than hauynge tweyne hoondis or twey feet to be sent in to euerlastynge fier.", "rotherham": "But, if, thy hand or thy foot, be causing thee to stumble, cut it off, and cast it from thee: It is, seemly for thee, to enter into life, maimed or lame, rather than, having two hands or two feet, to be cast into the age-abiding fire.", "weymouth": "If your hand or your foot is causing you to fall into sin, cut it off and away with it. It is better for you to enter into Life crippled in hand or foot than to remain in possession of two sound hands or feet but be thrown into the fire of the Ages.", "darby": "And if thy hand or thy foot offend thee, cut it off and cast [it] from thee; it is good for thee to enter into life lame or maimed, [rather] than having two hands or two feet to be cast into eternal fire.", "twenty": "If your hand or your foot is a snare to you, cut it off, and throw it away. It would be better for you to enter the Life maimed or lame, than to have both hands, or both feet, and be thrown into the aeonian fire.", "acv": "And if thy hand or thy foot causes thee to stumble, cut them off and cast from thee. It is good for thee to enter into life crippled or maimed, than having two hands or two feet to be cast into the eternal fire.", "anderson": "If, then, your hand or your foot ensnares you, cut it off, and throw it from you. It is better for you to enter into life lame or maimed, than, having two hands or two feet, to be thrown into the eternal fire.", "haweis": "If then thy hand, or thy foot, lead thee to offend, cut them off, and cast them from thee: for it were better for thee to enter into life, halting or maimed, than having two hands or two feet to be cast into the fire, which is eternal.", "noyes": "And if thy hand or thy foot is causing thee to fall, cut it off, and cast it from thee; it is better for thee to enter into life maimed or lame, than having two hands, or two feet, to be cast into the everlasting fire.", "webster": "Wherefore, if thy hand or thy foot causeth thee to sin, cut them off, and cast [them] from thee: it is better for thee to enter into life halt or maimed, rather than having two hands or two feet, to be cast into everlasting fire.", "vulgate": "si autem manus tua vel pes tuus scandalizat te abscide eum et proice abs te bonum tibi est ad vitam ingredi debilem vel clodum quam duas manus vel duos pedes habentem mitti in ignem aeternum;"}}, {"v": 9, "ref": "18:9", "o": "καὶ εἰ ὁ ὀφθαλμός σου σκανδαλίζει σε, ἔξελε αὐτὸν καὶ βάλε ἀπὸ σοῦ· καλόν σοί ἐστιν μονόφθαλμον εἰς τὴν ζωὴν εἰσελθεῖν, ἢ δύο ὀφθαλμοὺς ἔχοντα βληθῆναι εἰς τὴν γέενναν τοῦ πυρός.", "en": {"kjv": "And if thine eye offend thee, pluck it out, and cast it from thee: it is better for thee to enter into life with one eye, rather than having two eyes to be cast into hell fire.", "web": "If your eye causes you to stumble, pluck it out, and cast it from you. It is better for you to enter into life with one eye, rather than having two eyes to be cast into the Gehennaof fire.", "bsb": "And if your eye causes you to sin, gouge it out and throw it away. It is better for you to enter life with one eye than to have two eyes and be thrown into the fire of hell.", "asv": "And if thine eye causeth thee to stumble, pluck it out, and cast it from thee: it is good for thee to enter into life with one eye, rather than having two eyes to be cast into the hell of fire.", "ylt": "`And if thine eye doth cause thee to stumble, pluck it out and cast from thee; it is good for thee one-eyed to enter into the life, rather than having two eyes to be cast to the gehenna of the fire.", "tyndale": "And yf also thyne eye offende the plucke him oute and caste him from the. It is better for the to enter into lyfe with one eye then havyng two eyes to be cast into hell fyre.", "dra": "And if thy eye scandalize thee, pluck it out, and cast it from thee. It is better for thee having one eye to enter into life, than having two eyes to be cast into hell fire.", "bbe": "And if your eye is a cause of trouble to you, take it out, and put it away from you: it is better for you to go into life with one eye than, having two eyes, to go into the hell of fire.", "geneva": "And if thine eye cause thee to offende, plucke it out, and cast it from thee: it is better for thee to enter into life with one eye, then hauing two eyes to be cast into hell fire.", "wycliffe": "And if thin iye sclaundre thee, pulle it out, and caste awei fro thee. It is betere to thee with oon iye to entre in to lijf, thanne hauynge tweyn iyen to be sent in to the fier of helle.", "rotherham": "And, if, thine eye, causeth thee to stumble, pluck it out, and cast it from thee: It is, seemly, for thee, one-eyed, into life, to enter, rather than, having two eyes, to be cast into the fiery gehenna.", "weymouth": "And if your eye is causing you to fall into sin, tear it out and away with it; it is better for you to enter into Life with only one eye, than to remain in possession of two eyes but be thrown into the Gehenna of fire.", "darby": "And if thine eye offend thee, pluck it out and cast [it] from thee; it is good for thee to enter into life one-eyed, [rather] than having two eyes to be cast into the hell of fire.", "twenty": "If your eye is a snare to you, take it out, and throw it away. It would be better for you to enter the Life with only one eye, than to have both eyes and be thrown into the fiery Pit.", "acv": "And if thine eye causes thee to stumble, remove it and cast it from thee. It is good for thee to enter into life one-eyed, than having two eyes to be cast into the hell of fire.", "anderson": "And if your eye ensnares you, pull it out, and throw it from you. It is better to enter into life with one eye, than, having two eyes, to be thrown into hell-fire.", "haweis": "And if thine eye lead thee to offend, pluck it out and cast it from thee, for it were better for thee to enter into life with one eye only, than having two eyes to be cast into hell-fire.", "noyes": "And if thine eye is causing thee to fall, pluck it out, and cast it from thee; it is better for thee to enter into life with one eye, than having two eyes to be cast into hell-fire.", "webster": "And if thy eye causeth thee to sin, pluck it out, and cast [it] from thee: it is better for thee to enter into life with one eye, rather than having two eyes, to be cast into hell-fire.", "vulgate": "et si oculus tuus scandalizat te erue eum et proice abs te bonum tibi est unoculum in vitam intrare quam duos oculos habentem mitti in gehennam ignis;"}}, {"v": 10, "ref": "18:10", "o": "Ὁρᾶτε μὴ καταφρονήσητε ἑνὸς τῶν μικρῶν τούτων, λέγω γὰρ ὑμῖν ὅτι οἱ ἄγγελοι αὐτῶν ἐν οὐρανοῖς διὰ παντὸς βλέπουσι τὸ πρόσωπον τοῦ πατρός μου τοῦ ἐν ⸀οὐρανοῖς.", "en": {"kjv": "Take heed that ye despise not one of these little ones; for I say unto you, That in heaven their angels do always behold the face of my Father which is in heaven.", "web": "See that you don’t despise one of these little ones, for I tell you that in heaven their angels always see the face of my Father who is in heaven.", "bsb": "See that you do not look down on any of these little ones. For I tell you that their angels in heaven always see the face of My Father in heaven.", "asv": "See that ye despise not one of these little ones: for I say unto you, that in heaven their angels do always behold the face of my Father who is in heaven.", "ylt": "`Beware! --ye may not despise one of these little ones, for I say to you, that their messengers in the heavens do always behold the face of my Father who is in the heavens,", "tyndale": "Se that ye despise not one of these litelons. For I saye vnto you yt in heven their angels alwayes behold the face of my father which is in heven.", "dra": "See that you despise not one of these little ones: for I say to you, that their angels in heaven always see the face of my Father who is in heaven.", "bbe": "Let it not seem to you that one of these little ones is of no value; for I say to you that in heaven their angels see at all times the face of my Father in heaven.", "geneva": "See that ye despise not one of these litle ones: for I say vnto you, that in heauen their Angels alwayes behold the face of my Father which is in heauen.", "wycliffe": "Se ye, that ye dispise not oon of these litle. For Y seie to you, that the aungels of hem in heuenes seen euermore the face of my fadir that is in heuenes.", "rotherham": "Beware! do not despise one of these little ones; For I say unto you—that, their messengers in the heavens, do, continually, behold the face of my Father in the heavens.", "weymouth": "\"Beware of ever despising one of these little ones, for I tell you that in Heaven their angels have continual access to my Father who is in Heaven.", "darby": "See that ye do not despise one of these little ones; for I say unto you that their angels in [the] heavens continually behold the face of my Father who is in [the] heavens.", "twenty": "Beware of despising one of these lowly ones, for in Heaven, I tell you, their angels always see the face of my Father who is in Heaven.", "acv": "See that ye not disparage one of these little ones, for I say to you, that in the heavens their agents do always behold the face of my Father in the heavens.", "anderson": "Take heed that you despise not one of these little ones: for I say to you, That their angels in heaven do always behold the face of my Father who is in heaven.", "haweis": "See that ye despise not one of these little ones, for I say unto you, That their angels in heaven continually behold the face of my Father who is in heaven.", "noyes": "Take heed that ye despise not one of these little ones; for I say to you, that their angels in heaven continually behold the face of my Father who is in heaven.", "webster": "Take heed that ye despise not one of these little ones: for I say to you, that in heaven their angels do always behold the face of my Father who is in heaven.", "vulgate": "videte ne contemnatis unum ex his pusillis dico enim vobis quia angeli eorum in caelis semper vident faciem Patris mei qui in caelis est;"}}, {"v": 11, "ref": "18:11", "o": "", "en": {"kjv": "For the Son of man is come to save that which was lost.", "web": "For the Son of Man came to save that which was lost.", "bsb": "", "asv": "", "ylt": "for the Son of Man did come to save the lost.", "tyndale": "Ye and the sonne of man is come to saue that which is lost.", "dra": "For the Son of man is come to save that which was lost.", "bbe": "", "geneva": "For the Sonne of man is come to saue that which was lost.", "wycliffe": "For mannus sone cam to saue that thing that perischide.", "rotherham": "", "weymouth": "", "darby": "For the Son of man has come to save that which was lost.", "twenty": "", "acv": "For the Son of man came to save that which was lost.", "anderson": "For the Son of man has come to save that which is lost.", "haweis": "For the Son of man is come to save that which was lost.", "noyes": "", "webster": "For the Son of man is come to save that which was lost.", "vulgate": "venit enim Filius hominis salvare quod perierat;"}}, {"v": 12, "ref": "18:12", "o": "τί ὑμῖν δοκεῖ; ἐὰν γένηταί τινι ἀνθρώπῳ ἑκατὸν πρόβατα καὶ πλανηθῇ ἓν ἐξ αὐτῶν, οὐχὶ ⸀ἀφήσει τὰ ἐνενήκοντα ἐννέα ἐπὶ τὰ ὄρη ⸀καὶ πορευθεὶς ζητεῖ τὸ πλανώμενον;", "en": {"kjv": "How think ye? if a man have an hundred sheep, and one of them be gone astray, doth he not leave the ninety and nine, and goeth into the mountains, and seeketh that which is gone astray?", "web": "“What do you think? If a man has one hundred sheep, and one of them goes astray, doesn’t he leave the ninety-nine, go to the mountains, and seek that which has gone astray?", "bsb": "What do you think? If a man has a hundred sheep and one of them goes astray, will he not leave the ninety-nine on the hills and go out to search for the one that is lost?", "asv": "How think ye? if any man have a hundred sheep, and one of them be gone astray, doth he not leave the ninety and nine, and go unto the mountains, and seek that which goeth astray?", "ylt": "`What think ye? if a man may have an hundred sheep, and there may go astray one of them, doth he not--having left the ninety-nine, having gone on the mountains--seek that which is gone astray?", "tyndale": "How thinke ye? Yf a man have an hondred shepe and one of them be gone astray dothe he not leve nynty and nyne in ye moutains and go and seke that one which is gone astray?", "dra": "What think you? If a man have an hundred sheep, and one of them should go astray: doth he not leave the ninety-nine in the mountains, and goeth to seek that which is gone astray?", "bbe": "What would you say now? if a man has a hundred sheep, and one of them has gone wandering away, will he not let the ninety-nine be, and go to the mountains in search of the wandering one?", "geneva": "How thinke ye? If a man haue an hundreth sheepe, and one of them be gone astray, doeth he not leaue ninetie and nine, and go into the mountaines, and seeke that which is gone astray?", "wycliffe": "What semeth to you? If ther weren to sum man an hundrid scheep, and oon of hem hath errid, whethir he schal not leeue nynti and nyne in desert, and schal go to seche that that erride?", "rotherham": "How, to you, doth it seem? If a certain man come to have a hundred sheep and one from among them go astray, Will he not leave the ninety-nine upon the mountains, and going, seek the straying one?", "weymouth": "What do you yourselves think? Suppose a man gets a hundred sheep and one of them strays away, will he not leave the ninety-nine on the hills and go and look for the one that is straying?", "darby": "What think ye? If a certain man should have a hundred sheep, and one of them be gone astray, does he not, leaving the ninety and nine on the mountains, go and seek the one that has gone astray?", "twenty": "What think you? If a man owns a hundred sheep, and one of them strays, will he not leave the ninety-nine on the hills, and go and search for the one that is straying?", "acv": "What does it seem to you? If it happens a hundred sheep are with some man, and one of them went astray, after going (having left the ninety-nine on the mountains), does he not seek the one going astray?", "anderson": "What think you? If a man have a hundred sheep, and one of them go astray, does he not leave the ninety-nine, and go into the mountains, and seek for that which has gone astray?", "haweis": "What think you? If a man have an hundred sheep, and one of them stray, doth he not leave the ninety and nine in the mountains, and go and seek that which had strayed?", "noyes": "What think ye? if a man have a hundred sheep, and one of them hath gone astray, doth he not leave the ninety-nine upon the mountains, and go and seek that which hath gone astray?", "webster": "How think ye? if a man hath a hundred sheep, and one of them is gone astray, doth he not leave the ninety and nine, and go to the mountains, and seek that which is gone astray?", "vulgate": "quid vobis videtur si fuerint alicui centum oves et erraverit una ex eis nonne relinquet nonaginta novem in montibus et vadit quaerere eam quae erravit;"}}, {"v": 13, "ref": "18:13", "o": "καὶ ἐὰν γένηται εὑρεῖν αὐτό, ἀμὴν λέγω ὑμῖν ὅτι χαίρει ἐπ’ αὐτῷ μᾶλλον ἢ ἐπὶ τοῖς ἐνενήκοντα ἐννέα τοῖς μὴ πεπλανημένοις.", "en": {"kjv": "And if so be that he find it, verily I say unto you, he rejoiceth more of that sheep, than of the ninety and nine which went not astray.", "web": "If he finds it, most certainly I tell you, he rejoices over it more than over the ninety-nine which have not gone astray.", "bsb": "And if he finds it, truly I tell you, he rejoices more over that one sheep than over the ninety-nine that did not go astray.", "asv": "And if so be that he find it, verily I say unto you, he rejoiceth over it more than over the ninety and nine which have not gone astray.", "ylt": "and if it may come to pass that he doth find it, verily I say to you, that he doth rejoice over it more than over the ninety-nine that have not gone astray;", "tyndale": "If it happen that he fynd him veryly I say vnto you: he reioyseth more of that shepe then of the nynty and nyne which went not astray.", "dra": "And if it so be that he find it: Amen I say to you, he rejoiceth more for that, than for the ninety-nine that went not astray.", "bbe": "And if he comes across it, truly I say to you, he has more joy over it than over the ninety-nine which have not gone out of the way.", "geneva": "And if so be that he finde it, verely I say vnto you, he reioyceth more of that sheepe, then of the ninetie and nine which went not astray:", "wycliffe": "And if it falle that he fynde it, treuli Y seie to you, that he schal haue ioye theron more than on nynti and nyne that erriden not.", "rotherham": "And, if it should be that he find it, Verily, I say unto you—He rejoiceth over it, more than over the ninety-nine that have not gone astray.", "weymouth": "And if he succeeds in finding it, in solemn truth I tell you that he rejoices over it more than he does over the ninety-nine that have not gone astray.", "darby": "And if it should come to pass that he find it, verily I say unto you, he rejoices more because of it than because of the ninety and nine not gone astray.", "twenty": "And, if he succeeds in finding it, I tell you that he rejoices more over that one sheep than over the ninety-nine which did not stray.", "acv": "And if he happens to find it, truly I say to you, that he rejoices over it more than over the ninety-nine that have not gone astray.", "anderson": "And if it so be that he find it, verily I say to you, he rejoices over it more than over the ninety-nine that did not go astray.", "haweis": "And if he happen to find it, verily I say unto you, that he rejoiceth over it more than over the ninety and nine which never went astray.", "noyes": "And if it happen that he find it, truly do I say to you, he rejoiceth over it more than over the ninety-nine that did not go astray.", "webster": "And if he findeth it, verily I say to you, he rejoiceth more over that [sheep], than over the ninety and nine which went not astray.", "vulgate": "et si contigerit ut inveniat eam amen dico vobis quia gaudebit super eam magis quam super nonaginta novem quae non erraverunt;"}}, {"v": 14, "ref": "18:14", "o": "οὕτως οὐκ ἔστιν θέλημα ⸀ἔμπροσθεν τοῦ πατρὸς ⸀ὑμῶν τοῦ ἐν οὐρανοῖς ἵνα ἀπόληται ⸀ἓν τῶν μικρῶν τούτων.", "en": {"kjv": "Even so it is not the will of your Father which is in heaven, that one of these little ones should perish.", "web": "Even so it is not the will of your Father who is in heaven that one of these little ones should perish.", "bsb": "In the same way, your Father in heaven is not willing that any of these little ones should perish.", "asv": "Even so it is not the will of your Father who is in heaven, that one of these little ones should perish.", "ylt": "so it is not will in presence of your Father who is in the heavens, that one of these little ones may perish.", "tyndale": "Even so it is not the wyll of youre father in heven that one of these lytelons shulde perishe.", "dra": "Even so it is not the will of your Father, who is in heaven, that one of these little ones should perish.", "bbe": "Even so it is not the pleasure of your Father in heaven for one of these little ones to come to destruction.", "geneva": "So is it not ye wil of your Father which is in heauen, that one of these litle ones should perish.", "wycliffe": "So it is not the wille bifor youre fadir that is in heuenes, that oon of these litle perische.", "rotherham": "Thus, there is no desire, in the presence of my Father who is in the heavens, that, one of these little ones, should be lost.", "weymouth": "Just so it is not the will of your Father in Heaven that one of these little ones should be lost.", "darby": "So it is not the will of your Father who is in [the] heavens that one of these little ones should perish.", "twenty": "So, too, it is the will of my Father who is in Heaven that not one of these lowly ones should be lost.", "acv": "So, it is not a purpose before your Father in the heavens, that one of these little ones should perish.", "anderson": "Even so, it is not the will of your Father who is in heaven, that one of these little ones should be lost.", "haweis": "Even so it is not the will of your Father who is in heaven, that one of these little ones perish.", "noyes": "Thus it is not the will of your Father who is in heaven that one of these little ones should perish.", "webster": "Even so it is not the will of your Father who is in heaven, that one of these little ones should perish.", "vulgate": "sic non est voluntas ante Patrem vestrum qui in caelis est ut pereat unus de pusillis istis;"}}, {"v": 15, "ref": "18:15", "o": "Ἐὰν δὲ ἁμαρτήσῃ ⸂εἰς σὲ⸃ ὁ ἀδελφός σου, ⸀ὕπαγε ἔλεγξον αὐτὸν μεταξὺ σοῦ καὶ αὐτοῦ μόνου. ἐάν σου ἀκούσῃ, ἐκέρδησας τὸν ἀδελφόν σου·", "en": {"kjv": "Moreover if thy brother shall trespass against thee, go and tell him his fault between thee and him alone: if he shall hear thee, thou hast gained thy brother.", "web": "“If your brother sins against you, go, show him his fault between you and him alone. If he listens to you, you have gained back your brother.", "bsb": "If your brother sins against you, go and confront him privately. If he listens to you, you have won your brother over.", "asv": "And if thy brother sin against thee, go, show him his fault between thee and him alone: if he hear thee, thou hast gained thy brother.", "ylt": "`And if thy brother may sin against thee, go and show him his fault between thee and him alone, if he may hear thee, thou didst gain thy brother;", "tyndale": "Moreover yf thy brother treaspace agenst the. Go and tell him his faute betwene him and the alone. Yf he heare the thou hast wone thy brother:", "dra": "But if thy brother shall offend against thee, go, and rebuke him between thee and him alone. If he shall hear thee, thou shalt gain thy brother.", "bbe": "And if your brother does wrong to you, go, make clear to him his error between you and him in private: if he gives ear to you, you have got your brother back again.", "geneva": "Moreouer, if thy brother trespasse against thee, goe and tell him his fault betweene thee and him alone: if he heare thee, thou hast wonne thy brother.", "wycliffe": "But if thi brother synneth ayens thee, go thou, and repreue hym, bitwixe thee and hym aloone; if he herith thee, thou hast wonnun thi brother.", "rotherham": "But, if thy brother sin, withdraw, convince him, betwixt thee and him, alone,—If unto thee he hearken, thou hast gained thy brother;", "weymouth": "\"If your brother acts wrongly towards you, go and point out his fault to him when only you and he are there. If he listens to you, you have gained your brother.", "darby": "But if thy brother sin against thee, go, reprove him between thee and him alone. If he hear thee, thou hast gained thy brother.", "twenty": "If your Brother does wrong, go to him and convince him of his fault when you and he are alone. If he listens to you, you have won your Brother.", "acv": "But if thy brother should sin against thee, go and reprove him between thee and him alone. If he should hear thee, thou have gained thy brother.", "anderson": "And if your brother sin against you, go and tell him of his fault between you and him alone; if he hear you, you have gained your brother.", "haweis": "Now if thy brother sin against thee, go and reprove him between thyself and him alone; if he hear thee, thou hast gained thy brother.", "noyes": "Moreover, if thy brother sin, go and reprove him between thee and him alone. If he listen to thee, thou hast gained thy brother;", "webster": "Moreover, if thy brother shall trespass against thee, go and tell him his fault between thee and him alone: if he shall hear thee, thou hast gained thy brother.", "vulgate": "si autem peccaverit in te frater tuus vade et corripe eum inter te et ipsum solum si te audierit lucratus es fratrem tuum;"}}, {"v": 16, "ref": "18:16", "o": "ἐὰν δὲ μὴ ἀκούσῃ, παράλαβε μετὰ σοῦ ἔτι ἕνα ἢ δύο, ἵνα ἐπὶ στόματος δύο μαρτύρων ἢ τριῶν σταθῇ πᾶν ῥῆμα·", "en": {"kjv": "But if he will not hear thee, then take with thee one or two more, that in the mouth of two or three witnesses every word may be established.", "web": "But if he doesn’t listen, take one or two more with you, that at the mouth of two or three witnesses every word may be established.", "bsb": "But if he will not listen, take one or two others along, so that ‘every matter may be established by the testimony of two or three witnesses.’", "asv": "But if he hear thee not, take with thee one or two more, that at the mouth of two witnesses or three every word may be established.", "ylt": "and if he may not hear, take with thee yet one or two, that by the mouth of two witnesses or three every word may stand.", "tyndale": "But yf he heare the not then take yet with the one or two that in the mouth of two or thre witnesses all thinges maye be stablisshed.", "dra": "And if he will not hear thee, take with thee one or two more: that in the mouth of two or three witnesses every word may stand.", "bbe": "But if he will not give ear to you, take with you one or two more, that by the lips of two or three witnesses every word may be made certain.", "geneva": "But if he heare thee not, take yet with thee one or two, that by the mouth of two or three witnesses euery worde may be confirmed.", "wycliffe": "And if he herith thee not, take with thee oon or tweyne, that euery word stonde in the mouth of tweyne or thre witnessis.", "rotherham": "But, if he do not hearken, take with thee, yet one or two, that, at the mouth of two witnesses or three, every declaration, maybe established;", "weymouth": "But if he will not listen to you, go again, and ask one or two to go with you, that every word spoken may be attested by two or three witnesses.", "darby": "But if he do not hear [thee], take with thee one or two besides, that every matter may stand upon the word of two witnesses or of three.", "twenty": "But, if he does not listen to you, take with you one or two others, so that ‘on the evidence of two or three witnesses, every word may be put beyond dispute.’", "acv": "But if he should not hear, take with thee one or two besides, so that at the mouth of two or three witnesses every word may be established.", "anderson": "But if he will not hear you, take with you one or two more, that, by the mouth of two or three witnesses, every word may be established.", "haweis": "But if he will not hear thee, take with thee one or two more, that by the mouth of two or three witnesses every word may be confirmed.", "noyes": "but if he do not listen, take with thee one or two more; that by the mouth of two or three witnesses every word may be established.", "webster": "But if he will not hear [thee], [then] take with thee one or two more, that in the mouth of two or three witnesses every word may be established.", "vulgate": "si autem non te audierit adhibe tecum adhuc unum vel duos ut in ore duorum testium vel trium stet omne verbum;"}}, {"v": 17, "ref": "18:17", "o": "ἐὰν δὲ παρακούσῃ αὐτῶν, εἰπὸν τῇ ἐκκλησίᾳ· ἐὰν δὲ καὶ τῆς ἐκκλησίας παρακούσῃ, ἔστω σοι ὥσπερ ὁ ἐθνικὸς καὶ ὁ τελώνης.", "en": {"kjv": "And if he shall neglect to hear them, tell it unto the church: but if he neglect to hear the church, let him be unto thee as an heathen man and a publican.", "web": "If he refuses to listen to them, tell it to the assembly. If he refuses to hear the assembly also, let him be to you as a Gentile or a tax collector.", "bsb": "If he refuses to listen to them, tell it to the church. And if he refuses to listen even to the church, regard him as you would a pagan or a tax collector.", "asv": "And if he refuse to hear them, tell it unto the church: and if he refuse to hear the church also, let him be unto thee as the Gentile and the publican.", "ylt": "`And if he may not hear them, say it to the assembly, and if also the assembly he may not hear, let him be to thee as the heathen man and the tax-gatherer.", "tyndale": "If he heare not them tell it vnto the congregacion. If he heare not ye congregacion take him as an hethen man and as a publican.", "dra": "And if he will not hear them: tell the church. And if he will not hear the church, let him be to thee as the heathen and publican.", "bbe": "And if he will not give ear to them, let it come to the hearing of the church: and if he will not give ear to the church, let him be to you as a Gentile and a tax-farmer.", "geneva": "And if he refuse to heare them, tell it vnto the Church: and if he refuse to heare the Church also, let him be vnto thee as an heathen man, and a Publicane.", "wycliffe": "And if he herith not hem, seie thou to the chirche. But if he herith not the chirche, be he as an hethen and a pupplican to thee.", "rotherham": "But, if he hear them amiss, tell it to the assembly,—And, if, even the assembly, he hear amiss, Let him be unto thee, just as the man of the nations and the tax-collector.", "weymouth": "If he refuses to hear them, appeal to the Church; and if he refuses to hear even the Church, regard him just as you regard a Gentile or a tax-gatherer.", "darby": "But if he will not listen to them, tell it to the assembly; and if also he will not listen to the assembly, let him be to thee as one of the nations and a tax-gatherer.", "twenty": "If he refuses to listen to them, speak to the Church; and, if he also refuses to listen to the Church, treat him as you would a Gentile or a tax-gatherer.", "acv": "And if he is heedless of them, speak to the church. But if he is also heedless of the church, let him be to thee as the heathen and the tax collector.", "anderson": "But if he refuse to hear them, tell it to the church; and if he also refuse to hear the church, let him be to you as a heathen man and a publican.", "haweis": "But if he disregard them, inform the church: and if he disregard the church, let him be to thee as a heathen, or a publican.", "noyes": "And if he disregard them, tell the matter to the church; but if he disregard the church also, let him be to thee as a heathen and a publican.", "webster": "And if he shall neglect to hear them, tell [it] to the church: but if he shall neglect to hear the church, let him be to thee as a heathen and a publican.", "vulgate": "quod si non audierit eos dic ecclesiae si autem et ecclesiam non audierit sit tibi sicut ethnicus et publicanus;"}}, {"v": 18, "ref": "18:18", "o": "ἀμὴν λέγω ὑμῖν, ὅσα ⸀ἐὰν δήσητε ἐπὶ τῆς γῆς ἔσται δεδεμένα ⸀ἐν οὐρανῷ καὶ ὅσα ἐὰν λύσητε ἐπὶ τῆς γῆς ἔσται λελυμένα ⸁ἐν οὐρανῷ.", "en": {"kjv": "Verily I say unto you, Whatsoever ye shall bind on earth shall be bound in heaven: and whatsoever ye shall loose on earth shall be loosed in heaven.", "web": "Most certainly I tell you, whatever things you bind on earth will have been bound in heaven, and whatever things you release on earth will have been released in heaven.", "bsb": "Truly I tell you, whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven.", "asv": "Verily I say unto you, What things soever ye shall bind on earth shall be bound in heaven; and what things soever ye shall loose on earth shall be loosed in heaven.", "ylt": "`Verily I say to you, Whatever things ye may bind upon the earth shall be having been bound in the heavens, and whatever things ye may loose on the earth shall be having been loosed in the heavens.", "tyndale": "Verely I say vnto you what soever ye bynde on erth shalbe bounde in heven. And what soever ye lowse on erth shalbe lowsed in heven.", "dra": "Amen I say to you, whatsoever you shall bind upon earth, shall be bound also in heaven: and whatsoever you shall loose upon earth, shall be loosed also in heaven.", "bbe": "Truly I say to you, Whatever things are fixed by you on earth will be fixed in heaven: and whatever you make free on earth will be made free in heaven.", "geneva": "Verely I say vnto you, Whatsoeuer ye bind on earth, shall be bound in heauen: and whatsoeuer ye loose on earth, shalbe loosed in heauen.", "wycliffe": "Y seie to you treuli, what euer thingis ye bynden on erthe, tho schulen be boundun also in heuene; and what euer thingis ye vnbynden on erthe, tho schulen be vnboundun also in heuene.", "rotherham": "Verily, I say unto you—Whatsoever things ye shall bind on the earth, shall be bound in heaven; and, whatsoever things ye shall loose on the earth, shall be loosed in heaven.", "weymouth": "I solemnly tell you that whatever you as a Church bind on earth will in Heaven be held as bound, and whatever you loose on earth will in Heaven be held to be loosed.", "darby": "Verily I say to you, Whatsoever ye shall bind on the earth shall be bound in heaven, and whatsoever ye shall loose on the earth shall be loosed in heaven.", "twenty": "I tell you, all that you forbid on earth will be held in Heaven to be forbidden, and all that you allow on earth will be held in Heaven to be allowed.", "acv": "Truly I say to you, however many things ye may bind on the earth will be things that are bound in heaven, and however many things ye may loose on the earth will be things that that are loosed in heaven.", "anderson": "Verily, I say to you, my disciples, Whatever you bind on earth, shall be bound in heaven; and whatever you loose on earth, shall be loosed in heaven.", "haweis": "Verily I say unto you, Whatsoever things ye shall bind on earth, shall be bound in heaven: and whatsoever things ye shall loose on earth shall be loosed in heaven.", "noyes": "Truly do I say to you, Whatever ye shall bind on earth will be bound in heaven; and whatever ye shall loose on earth will be loosed in heaven.", "webster": "Verily I say to you, Whatever ye shall bind on earth, shall be bound in heaven: and whatever ye shall loose on earth, shall be loosed in heaven.", "vulgate": "amen dico vobis quaecumque alligaveritis super terram erunt ligata et in caelo et quaecumque solveritis super terram erunt soluta et in caelo;"}}, {"v": 19, "ref": "18:19", "o": "Πάλιν ⸀ἀμὴν λέγω ὑμῖν ὅτι ἐὰν δύο ⸂συμφωνήσωσιν ἐξ ὑμῶν⸃ ἐπὶ τῆς γῆς περὶ παντὸς πράγματος οὗ ἐὰν αἰτήσωνται, γενήσεται αὐτοῖς παρὰ τοῦ πατρός μου τοῦ ἐν οὐρανοῖς.", "en": {"kjv": "Again I say unto you, That if two of you shall agree on earth as touching any thing that they shall ask, it shall be done for them of my Father which is in heaven.", "web": "Again, assuredly I tell you, that if two of you will agree on earth concerning anything that they will ask, it will be done for them by my Father who is in heaven.", "bsb": "Again, I tell you truly that if two of you on the earth agree about anything you ask for, it will be done for you by My Father in heaven.", "asv": "Again I say unto you, that if two of you shall agree on earth as touching anything that they shall ask, it shall be done for them of my Father who is in heaven.", "ylt": "`Again, I say to you, that, if two of you may agree on the earth concerning anything, whatever they may ask--it shall be done to them from my Father who is in the heavens,", "tyndale": "Agayn I say vnto you that yf two of you shall agre in erth apon eny maner thynge what soever they shall desyre: it shalbe geven them of my father which is in heven.", "dra": "Again I say to you, that if two of you shall consent upon earth, concerning anything whatsoever they shall ask, it shall be done to them by my Father who is in heaven.", "bbe": "Again, I say to you, that if two of you are in agreement on earth about anything for which they will make a request, it will be done for them by my Father in heaven.", "geneva": "Againe, verely I say vnto you, that if two of you shall agree in earth vpon any thing, whatsoeuer they shall desire, it shall be giuen them of my Father which is in heauen.", "wycliffe": "Eftsoone Y seie to you, that if tweyne of you consenten on the erthe, of euery thing what euer thei axen, it schal be don to hem of my fadir that is in heuenes.", "rotherham": "Again, [verily] I say unto you—If two from among you shall agree upon the earth concerning any matter, whatsoever they shall ask, it shall be brought to pass for them, from my Father who is in the heavens;", "weymouth": "I also solemnly tell you that if two of you here on earth agree together concerning anything whatever that they shall ask, the boon will come to them from my Father who is in Heaven.", "darby": "Again I say to you, that if two of you shall agree on the earth concerning any matter, whatsoever it may be that they shall ask, it shall come to them from my Father who is in [the] heavens.", "twenty": "Again, I tell you that, if but two of you on earth agree as to what they shall pray for, whatever it be, it will be granted them by my Father who is in Heaven.", "acv": "Again I say to you truly, that if two of you should agree on the earth concerning every matter, whatever they might ask, it will happen for them from my Father in the heavens.", "anderson": "Again, I say to you, that if two of you agree on earth about any thing for which they will ask, it shall be done for them by my Father who is in heaven.", "haweis": "Again I say unto you, That if two of you are concurring upon earth, respecting any matter, which ye shall ask, it shall be done for them by my Father who is in heaven.", "noyes": "Again, I say to you, that if two of you shall agree on earth concerning any thing that they shall ask, it will be done for them by my Father o who is in heaven.", "webster": "Again I say to you, That if two of you shall agree on earth, concerning any thing that they shall ask, it shall be done for them by my Father who is in heaven.", "vulgate": "iterum dico vobis quia si duo ex vobis consenserint super terram de omni re quacumque petierint fiet illis a Patre meo qui in caelis est;"}}, {"v": 20, "ref": "18:20", "o": "οὗ γάρ εἰσιν δύο ἢ τρεῖς συνηγμένοι εἰς τὸ ἐμὸν ὄνομα, ἐκεῖ εἰμι ἐν μέσῳ αὐτῶν.", "en": {"kjv": "For where two or three are gathered together in my name, there am I in the midst of them.", "web": "For where two or three are gathered together in my name, there I am in their midst.”", "bsb": "For where two or three gather together in My name, there am I with them.”", "asv": "For where two or three are gathered together in my name, there am I in the midst of them.", "ylt": "for where there are two or three gathered together--to my name, there am I in the midst of them.'", "tyndale": "For where two or thre are gathered togedder in my name there am I in the myddes of them.", "dra": "For where there are two or three gathered together in my name, there am I in the midst of them.", "bbe": "For where two or three are come together in my name, there am I among them.", "geneva": "For where two or three are gathered together in my Name, there am I in the mids of them.", "wycliffe": "For where tweyne or thre ben gaderid in my name, there Y am in the myddil of hem.", "rotherham": "For, where there are two or three, gathered together into my name, there, am I, in their midst.", "weymouth": "For where there are two or three assembled in my name, there am I in the midst of them.\"", "darby": "For where two or three are gathered together unto my name, there am I in the midst of them.", "twenty": "For where two or three have come together in my Name, I am present with them.”", "acv": "For where two or three are gathered together in my name, there am I in the midst of them.", "anderson": "For where there are two or three that have come together for my sake, there I am in the midst of them.", "haweis": "For where two or three are gathered together in my name, there am I in the midst of them.", "noyes": "For where two or three are gathered together in my name, there am I in the midst of them.", "webster": "For where two or three are assembled in my name, there am I in the midst of them.", "vulgate": "ubi enim sunt duo vel tres congregati in nomine meo ibi sum in medio eorum;"}}, {"v": 21, "ref": "18:21", "o": "Τότε προσελθὼν ⸂αὐτῷ ὁ Πέτρος εἶπεν⸃· Κύριε, ποσάκις ἁμαρτήσει εἰς ἐμὲ ὁ ἀδελφός μου καὶ ἀφήσω αὐτῷ; ἕως ἑπτάκις;", "en": {"kjv": "Then came Peter to him, and said, Lord, how oft shall my brother sin against me, and I forgive him? till seven times?", "web": "Then Peter came and said to him, “Lord, how often shall my brother sin against me, and I forgive him? Until seven times?”", "bsb": "Then Peter came to Jesus and asked, “Lord, how many times shall I forgive my brother who sins against me? Up to seven times?”", "asv": "Then came Peter and said to him, Lord, how oft shall my brother sin against me, and I forgive him? until seven times?", "ylt": "Then Peter having come near to him, said, `Sir, how often shall my brother sin against me, and I forgive him--till seven times?'", "tyndale": "Then came Peter to him and sayde: master howe ofte shall I forgeve my brother yf he synne agaynst me seven tymes?", "dra": "Then came Peter unto him and said: Lord, how often shall my brother offend against me, and I forgive him? till seven times?", "bbe": "Then Peter came and said to him, Lord, what number of times may my brother do wrong against me, and I give him forgiveness? till seven times?", "geneva": "Then came Peter to him, and said, Master, howe oft shall my brother sinne against me, and I shall forgiue him? vnto seuen times?", "wycliffe": "Thanne Petre cam to hym, and seide, Lord, how ofte schal my brother synne ayens me, and Y schal foryyue hym?", "rotherham": "Then, coming near, Peter said [to him]—Lord! how many times, shall my brother sin against me, and I forgive him? Until, seven, times?", "weymouth": "At this point Peter came to Him with the question, \"Master, how often shall my brother act wrongly towards me and I forgive him? seven times?\"", "darby": "Then Peter came to him and said, Lord, how often shall my brother sin against me and I forgive him? until seven times?", "twenty": "Then Peter came up, and said to Jesus: “Master, how often am I to forgive my Brother when he wrongs me? As many as seven times?”", "acv": "Then Peter having come to him, he said, Lord, how often will my brother sin against me, and I forgive him? Until seven times?", "anderson": "Then Peter came to him, and said: Lord, how often shall my brother sin against me, and I forgive him? Till seven times?", "haweis": "Then Peter coming to him, said, Lord, how often shall my brother sin against me, and I forgive him? till seven times?", "noyes": "Then came Peter, and said to him, Lord, how often shall my brother sin against me, and I forgive him? Until seven times?", "webster": "Then came Peter to him, and said, Lord, how often shall my brother sin against me, and I forgive him? till seven times?", "vulgate": "tunc accedens Petrus ad eum dixit Domine quotiens peccabit in me frater meus et dimittam ei usque septies;"}}, {"v": 22, "ref": "18:22", "o": "λέγει αὐτῷ ὁ Ἰησοῦς· Οὐ λέγω σοι ἕως ἑπτάκις ἀλλὰ ἕως ἑβδομηκοντάκις ἑπτά.", "en": {"kjv": "Jesus saith unto him, I say not unto thee, Until seven times: but, Until seventy times seven.", "web": "Jesus said to him, “I don’t tell you until seven times, but, until seventy times seven.", "bsb": "Jesus answered, “I tell you, not just seven times, but seventy-seven times!", "asv": "Jesus saith unto him, I say not unto thee, Until seven times; but, Until seventy times seven.", "ylt": "Jesus saith to him, `I do not say to thee till seven times, but till seventy times seven.", "tyndale": "Iesus sayd vnto him: I saye not vnto the seven tymes: but seventy tymes seven tymes.", "dra": "Jesus saith to him: I say not to thee, till seven times; but till seventy times seven times.", "bbe": "Jesus says to him, I say not to you, Till seven times; but, Till seventy times seven.", "geneva": "Iesus said vnto him, I say not to thee, Vnto seuen times, but, Vnto seuentie times seuen times.", "wycliffe": "Whether til seuen tymes? Jhesus seith to hym, Y seie not to thee, til seuene sithis; but til seuenti sithis seuene sithis.", "rotherham": "Jesus saith to him—I say not unto thee, unto, seven, times, but, until seventy times seven.", "weymouth": "\"I do not say seven times,\" answered Jesus, \"but seventy times seven times.", "darby": "Jesus says to him, I say not to thee until seven times, but until seventy times seven.", "twenty": "But Jesus answered: “Not seven times, but ‘seventy times seven.’", "acv": "Jesus says to him, I say to thee, not until seven times, but until seventy times seven.", "anderson": "Jesus said to him: I say to you, Not till seven times, but till seventy times seven.", "haweis": "Jesus saith to him, I tell thee not until seven times, but unto seventy times seven.", "noyes": "Jesus saith to him, I say not to thee, until seven times, but until seventy times seven.", "webster": "Jesus saith to him, I say not to thee, Until seven times: but, Until seventy times seven.", "vulgate": "dicit illi Iesus non dico tibi usque septies sed usque septuagies septies;"}}, {"v": 23, "ref": "18:23", "o": "Διὰ τοῦτο ὡμοιώθη ἡ βασιλεία τῶν οὐρανῶν ἀνθρώπῳ βασιλεῖ ὃς ἠθέλησεν συνᾶραι λόγον μετὰ τῶν δούλων αὐτοῦ·", "en": {"kjv": "Therefore is the kingdom of heaven likened unto a certain king, which would take account of his servants.", "web": "Therefore the Kingdom of Heaven is like a certain king, who wanted to reconcile accounts with his servants.", "bsb": "Because of this, the kingdom of heaven is like a king who wanted to settle accounts with his servants.", "asv": "Therefore is the kingdom of heaven likened unto a certain king, who would make a reckoning with his servants.", "ylt": "`Because of this was the reign of the heavens likened to a man, a king, who did will to take reckoning with his servants,", "tyndale": "Therfore is ye kingdome of heven lykened vnto a certayne kynge which wolde take a countis of his servauntis.", "dra": "Therefore is the kingdom of heaven likened to a king, who would take an account of his servants.", "bbe": "For this reason the kingdom of heaven is like a king, who went over his accounts with his servants.", "geneva": "Therefore is the kingdome of heauen likened vnto a certaine King, which would take an account of his seruants.", "wycliffe": "Therfor the kyngdom of heuenes is licned to a kyng, that wolde rekyn with hise seruauntis.", "rotherham": "For this cause, hath the kingdom of the heavens become like unto a man, a king, who wished to settle an account with his servants;", "weymouth": "\"For this reason the Kingdom of the Heavens may be compared to a king who determined to have a settlement of accounts with his servants.", "darby": "For this cause the kingdom of the heavens has become like a king who would reckon with his bondmen.", "twenty": "And therefore the Kingdom of Heaven may be compared to a king who wished to settle accounts with his servants.", "acv": "Because of this the kingdom of the heavens is compared to a man, a king, who wanted to settle account with his bondmen.", "anderson": "For this reason, the kingdom of heaven is likened to a king that wished to settle accounts with his servants.", "haweis": "Therefore is the kingdom of heaven like unto a certain king who purposed to settle his account with his servants.", "noyes": "Therefore the kingdom of heaven is likened to a king, who would settle accounts with his servants.", "webster": "Therefore is the kingdom of heaven likened to a certain king who would take account of his servants.", "vulgate": "ideo adsimilatum est regnum caelorum homini regi qui voluit rationem ponere cum servis suis;"}}, {"v": 24, "ref": "18:24", "o": "ἀρξαμένου δὲ αὐτοῦ συναίρειν ⸀προσηνέχθη ⸂αὐτῷ εἷς⸃ ὀφειλέτης μυρίων ταλάντων.", "en": {"kjv": "And when he had begun to reckon, one was brought unto him, which owed him ten thousand talents.", "web": "When he had begun to reconcile, one was brought to him who owed him ten thousand talents.", "bsb": "As he began the settlements, a debtor was brought to him owing ten thousand talents.", "asv": "And when he had begun to reckon, one was brought unto him, that owed him ten thousand talents.", "ylt": "and he having begun to take account, there was brought near to him one debtor of a myriad of talents,", "tyndale": "And when he had begone to recken one was broughte vnto him whiche ought him ten thousande talentis:", "dra": "And when he had begun to take the account, one as brought to him, that owed him ten thousand talents.", "bbe": "And at the start, one came to him who was in his debt for ten thousand talents.", "geneva": "And when he had begun to reckon, one was brought vnto him, which ought him ten thousand talents.", "wycliffe": "And whanne he bigan to rekene, oon that ouyte ten thousynde talentis, was brouyt to hym.", "rotherham": "And, when he, began, to settle, there was brought unto him a, certain, debtor, of a thousand talents;", "weymouth": "But as soon as he began the settlement, one was brought before him who owed 10,000 talents,", "darby": "And having begun to reckon, one debtor of ten thousand talents was brought to him.", "twenty": "When he had begun to do so, one of them was brought to him who owed him six million pounds;", "acv": "And when he began to settle, one debtor of ten thousand talents was brought to him.", "anderson": "And when he began to make a settlement, there was brought to him one that owed him ten thou sand talents.", "haweis": "And when he began to make up the account, there was brought to him one debtor, ten thousand talents in arrear:", "noyes": "And when he had begun to reckon, there was brought to him one, who owed him ten thousand talents.", "webster": "And when he had begun to reckon, one was brought to him who owed him ten thousand talents.", "vulgate": "et cum coepisset rationem ponere oblatus est ei unus qui debebat decem milia talenta;"}}, {"v": 25, "ref": "18:25", "o": "μὴ ἔχοντος δὲ αὐτοῦ ἀποδοῦναι ἐκέλευσεν αὐτὸν ὁ ⸀κύριος πραθῆναι καὶ τὴν ⸀γυναῖκα καὶ τὰ τέκνα καὶ πάντα ὅσα ⸀ἔχει καὶ ἀποδοθῆναι.", "en": {"kjv": "But forasmuch as he had not to pay, his lord commanded him to be sold, and his wife, and children, and all that he had, and payment to be made.", "web": "But because he couldn’t pay, his lord commanded him to be sold, with his wife, his children, and all that he had, and payment to be made.", "bsb": "Since the man was unable to pay, the master ordered that he be sold to pay his debt, along with his wife and children and everything he owned.", "asv": "But forasmuch as he had not wherewith to pay, his lord commanded him to be sold, and his wife, and children, and all that he had, and payment to be made.", "ylt": "and he having nothing to pay, his lord did command him to be sold, and his wife, and the children, and all, whatever he had, and payment to be made.", "tyndale": "whome be cause he had nought to paye his master commaunded him to be solde and his wyfe and his chyldren and all that he had and payment to be made.", "dra": "And as he had not wherewith to pay it, his lord commanded that he should be sold, and his wife and children, and all that he had, and payment to be made.", "bbe": "And because he was not able to make payment, his lord gave orders for him, and his wife, and his sons and daughters, and all he had, to be given for money, and payment to be made.", "geneva": "And because he had nothing to pay, his Lord commanded him to be solde, and his wife, and his children, and all that he had, and the dette to be payed.", "wycliffe": "And whanne he hadde not wherof to yelde, his lord comaundide hym to be seld, and his wijf, and children, and alle thingis that he hadde, and to be paied.", "rotherham": "and, he, not having, wherewith to pay, the master ordered him to be sold, and the wife, and the children, and whatsoever he had,—and payment to be made.", "weymouth": "and was unable to pay. So his master ordered that he and his wife and children and everything that he had should be sold, and payment be made.", "darby": "But he not having anything to pay, [his] lord commanded him to be sold, and his wife, and his children, and everything that he had, and that payment should be made.", "twenty": "and, as he could not pay, his master ordered him to be sold towards the payment of the debt, together with his wife, and his children, and everything that he had.", "acv": "But of him not having to pay, his lord commanded him to be sold, and his wife and children, and all things, as many as he had, and payment to be made.", "anderson": "But as he was not able to pay, his lord commanded him, and his wife, and children, and all that he had, to be sold, and payment to be made.", "haweis": "but not having wherewithal to pay, his lord ordered him to be sold, and his wife and his children, and all things whatsoever he possessed, and payment to be made.", "noyes": "But as he was unable to pay, his lord ordered him to be sold, and his wife and children, and all that he had, and payment to be made.", "webster": "But as he had not ability to pay, his lord commanded him to be sold, and his wife and children, and all that he had, and payment to be made.", "vulgate": "cum autem non haberet unde redderet iussit eum dominus venundari et uxorem eius et filios et omnia quae habebat et reddi;"}}, {"v": 26, "ref": "18:26", "o": "πεσὼν οὖν ὁ δοῦλος προσεκύνει αὐτῷ λέγων· ⸀Μακροθύμησον ἐπ’ ⸀ἐμοί, καὶ πάντα ⸂ἀποδώσω σοι⸃.", "en": {"kjv": "The servant therefore fell down, and worshipped him, saying, Lord, have patience with me, and I will pay thee all.", "web": "The servant therefore fell down and kneeled before him, saying, ‘Lord, have patience with me, and I will repay you all!’", "bsb": "Then the servant fell on his knees before him. ‘Have patience with me,’ he begged, ‘and I will pay back everything.’", "asv": "The servant therefore fell down and worshipped him, saying, Lord, have patience with me, and I will pay thee all.", "ylt": "The servant then, having fallen down, was bowing to him, saying, Sir, have patience with me, and I will pay thee all;", "tyndale": "The servaunt fell doune and besought him sayinge: Sir geve me respyte and I wyll paye it every whit.", "dra": "But that servant falling down, besought him, saying: Have patience with me, and I will pay thee all.", "bbe": "So the servant went down on his face and gave him worship, saying, Lord, give me time to make payment and I will give you all.", "geneva": "The seruant therefore fell downe, and worshipped him, saying, Lord, refraine thine anger toward me, and I will pay thee all.", "wycliffe": "But thilke seruaunt felde doun, and preiede hym, and seide, Haue pacience in me, and Y schal yelde to thee alle thingis.", "rotherham": "The servant therefore, falling down, began to do homage unto him, saying—Have patience with me, and, all, will I pay thee.", "weymouth": "The servant therefore falling down, prostrated himself at his feet and entreated him. \"`Only give me time,' he said, `and I will pay you the whole.'", "darby": "The bondman therefore falling down did him homage, saying, Lord, have patience with me and I will pay thee all.", "twenty": "Thereupon the servant threw himself down on the ground before him and said ‘Have patience with me, and I will pay you all.’", "acv": "The bondman therefore having fallen down, worshiped him, saying, Lord, be patient toward me and I will pay thee all.", "anderson": "Therefore, the servant fell down and besought him, saying, Have patience with me, Lord, and I will pay you all.", "haweis": "Then that servant falling prostrate, paid him the most profound homage, saying, Lord, have forbearance with me, and I will pay thee all.", "noyes": "Then that servant fell down and did obeisance to him, saying, Have patience with me, and I will pay thee all.", "webster": "The servant therefore fell down, and worshiped him, saying, Lord, have patience with me, and I will pay thee all.", "vulgate": "procidens autem servus ille orabat eum dicens patientiam habe in me et omnia reddam tibi;"}}, {"v": 27, "ref": "18:27", "o": "σπλαγχνισθεὶς δὲ ὁ κύριος τοῦ δούλου ἐκείνου ἀπέλυσεν αὐτόν, καὶ τὸ δάνειον ἀφῆκεν αὐτῷ.", "en": {"kjv": "Then the lord of that servant was moved with compassion, and loosed him, and forgave him the debt.", "web": "The lord of that servant, being moved with compassion, released him, and forgave him the debt.", "bsb": "His master had compassion on him, forgave his debt, and released him.", "asv": "And the lord of that servant, being moved with compassion, released him, and forgave him the debt.", "ylt": "and the lord of that servant having been moved with compassion did release him, and the debt he forgave him.", "tyndale": "Then had the Lorde pytie on that servaunt and lowsed him and forgave him the det.", "dra": "And the lord of that servant being moved with pity, let him go and forgave him the debt.", "bbe": "And the lord of that servant, being moved with pity, let him go, and made him free of the debt.", "geneva": "Then that seruants Lord had compassion, and loosed him, and forgaue him the dette.", "wycliffe": "And the lord hadde merci on that seruaunt, and suffride hym to go, and foryaf to hym the dette.", "rotherham": "And, moved with compassion, the master of that servant released him, and, the loan, he, forgave, him.", "weymouth": "\"Whereupon his master, touched with compassion, set him free and forgave him the debt.", "darby": "And the lord of that bondman, being moved with compassion, loosed him and forgave him the loan.", "twenty": "The master was moved with compassion; and he let him go, and forgave him the debt.", "acv": "And having felt compassion, the lord of that bondman released him, and forgave him the debt.", "anderson": "And the lord of that servant was moved with compassion, and let him go, and forgave him the debt.", "haweis": "Then his lord, moved with compassion towards that servant, discharged him, and forgave him the debt.", "noyes": "And the lord of that servant, being moved with compassion, released him, and forgave him the debt.", "webster": "Then the lord of that servant was moved with compassion, and loosed him, and forgave him the debt.", "vulgate": "misertus autem dominus servi illius dimisit eum et debitum dimisit ei;"}}, {"v": 28, "ref": "18:28", "o": "ἐξελθὼν δὲ ὁ δοῦλος ἐκεῖνος εὗρεν ἕνα τῶν συνδούλων αὐτοῦ ὃς ὤφειλεν αὐτῷ ἑκατὸν δηνάρια, καὶ κρατήσας αὐτὸν ἔπνιγεν λέγων· ⸀Ἀπόδος εἴ τι ὀφείλεις.", "en": {"kjv": "But the same servant went out, and found one of his fellowservants, which owed him an hundred pence: and he laid hands on him, and took him by the throat, saying, Pay me that thou owest.", "web": "“But that servant went out, and found one of his fellow servants, who owed him one hundred denarii,and he grabbed him, and took him by the throat, saying, ‘Pay me what you owe!’", "bsb": "But when that servant went out, he found one of his fellow servants who owed him a hundred denarii. He grabbed him and began to choke him, saying, ‘Pay back what you owe me!’", "asv": "But that servant went out, and found one of his fellow-servants, who owed him a hundred shillings: and he laid hold on him, and took him by the throat, saying, Pay what thou owest.", "ylt": "`And, that servant having come forth, found one of his fellow-servants who was owing him an hundred denaries, and having laid hold, he took him by the throat, saying, Pay me that which thou owest.", "tyndale": "And ye sayde servaut wet oute and founde one of his felowes which ought him an hundred pence and leyed hondes on him and toke him by the throote sayinge: paye me yt thou owest.", "dra": "But when that servant was gone out, he found one of his fellow-servants that owed him an hundred pence: and laying hold of him, he throttled him, saying: Pay what thou owest.", "bbe": "But that servant went out, and meeting one of the other servants, who was in debt to him for one hundred pence, he took him by the throat, saying, Make payment of your debt.", "geneva": "But when the seruant was departed, hee found one of his felow seruants, which ought him an hundred pence, and he layde hands on him, and thratled him, saying, Pay me that thou owest.", "wycliffe": "But thilke seruaunt yede out, and foonde oon of his euen seruauntis, that ouyte hym an hundrid pens; and he helde hym, and stranglide hym, and seide, Yelde that that thou owest.", "rotherham": "But that servant, going out, found one of his fellow-servants, who owed him, a hundred denaries, and, laying hold of him, he began seizing him by the throat, saying, Pay! if anything thou owest.", "weymouth": "But no sooner had that servant gone out, than he met with one of his fellow servants who owed him 100 shillings; and seizing him by the throat and nearly strangling him he exclaimed, \"`Pay me all you owe.'", "darby": "But that bondman having gone out, found one of his fellow-bondmen who owed him a hundred denarii. And having seized him, he throttled him, saying, Pay [me] if thou owest anything.", "twenty": "But, on going out, that same servant came upon one of his fellow-servants who owed him ten pounds. Seizing him by the throat, he said ‘Pay what you owe me.’", "acv": "But after going out, that bondman found one of his fellow bondmen who owed him a hundred denarii. And having grabbed him, he choked him, saying, Pay me if thou owe anything.", "anderson": "But that servant went out, and found one of his fellow-servants, who owed him a hundred denarii; and he laid hold of him, and took him by the throat, saying: Pay me what you owe.", "haweis": "But that servant going out, found one of his fellow-servants, who owed him a hundred denarii, and seizing, throttled him, saying, Pay me what thou owest.", "noyes": "But that servant went out, and found one of his fellow-servants, who owed him a hundred denaries; and he laid hold of him, and took him by the throat, saying, Pay what thou owest.", "webster": "But the same servant went out, and found one of his fellow-servants, who owed him a hundred pence: and he laid hands on him, and took [him] by the throat, saying, Pay me what thou owest.", "vulgate": "egressus autem servus ille invenit unum de conservis suis qui debebat ei centum denarios et tenens suffocabat eum dicens redde quod debes;"}}, {"v": 29, "ref": "18:29", "o": "πεσὼν οὖν ὁ σύνδουλος ⸀αὐτοῦ παρεκάλει αὐτὸν λέγων· Μακροθύμησον ἐπ’ ⸀ἐμοί, καὶ ἀποδώσω σοι.", "en": {"kjv": "And his fellowservant fell down at his feet, and besought him, saying, Have patience with me, and I will pay thee all.", "web": "“So his fellow servant fell down at his feet and begged him, saying, ‘Have patience with me, and I will repay you!’", "bsb": "So his fellow servant fell down and begged him, ‘Have patience with me, and I will pay you back.’", "asv": "So his fellow-servant fell down and besought him, saying, Have patience with me, and I will pay thee.", "ylt": "His fellow-servant then, having fallen down at his feet, was calling on him, saying, Have patience with me, and I will pay thee all;", "tyndale": "And his felowe fell doune and besought him sayinge: have pacience with me and I wyll paye the all.", "dra": "And his fellow-servant falling down, besought him, saying: Have patience with me, and I will pay thee all.", "bbe": "So that servant went down on his face, requesting him and saying, Give me time and I will make payment to you.", "geneva": "Then his fellow seruant fell downe at his feete, and besought him, saying, Refraine thine anger towards me, and I will pay thee all.", "wycliffe": "And his euen seruaunt felle doun, and preyede hym, and seide, Haue pacience in me, and Y schal quyte alle thingis to thee.", "rotherham": "His fellow servant, therefore, falling down, began beseeching him, saying, Have patience with me! And I will pay thee.", "weymouth": "\"His fellow servant therefore fell at his feet and entreated him, \"`Only give me time,' he said, `and I will pay you.'", "darby": "His fellow-bondman therefore, having fallen down [at his feet], besought him, saying, Have patience with me, and I will pay thee.", "twenty": "Thereupon his fellow-servant threw himself on the ground and begged for mercy. ‘Have patience with me,’ he said, ‘and I will pay you.’", "acv": "So his fellow bondman having fallen down at his feet, besought him, saying, Be patience toward me, and I will pay thee.", "anderson": "Then his fellow-servant fell down at his feet, and besought him, saying: Have patience with me, and I will pay you all.", "haweis": "Then his fellow-servant fell at his feet, and besought him, saying, Have forbearance with me, and I will pay thee all.", "noyes": "His fellow-servant then fell down and besought him, saying, Have patience with me, and I will pay thee.", "webster": "And his fellow-servant fell down at his feet, and besought him, saying, Have patience with me, and I will pay thee all.", "vulgate": "et procidens conservus eius rogabat eum dicens patientiam habe in me et omnia reddam tibi;"}}, {"v": 30, "ref": "18:30", "o": "ὁ δὲ οὐκ ἤθελεν, ἀλλὰ ἀπελθὼν ἔβαλεν αὐτὸν εἰς φυλακὴν ἕως ⸀οὗ ἀποδῷ τὸ ὀφειλόμενον.", "en": {"kjv": "And he would not: but went and cast him into prison, till he should pay the debt.", "web": "He would not, but went and cast him into prison, until he should pay back that which was due.", "bsb": "But he refused. Instead, he went and had the man thrown into prison until he could pay his debt.", "asv": "And he would not: but went and cast him into prison, till he should pay that which was due.", "ylt": "and he would not, but having gone away, he cast him into prison, till he might pay that which was owing.", "tyndale": "And he wolde not but went and cast him into preson tyll he shulde paye the det.", "dra": "And he would not: but went and cast him into prison, till he paid the debt.", "bbe": "And he would not: but went and put him into prison till he had made payment of the debt.", "geneva": "Yet he would not, but went and cast him into prison, till he should pay the dette.", "wycliffe": "But he wolde not; but wente out, and putte hym in to prisoun, til he paiede al the dette.", "rotherham": "He, however, would not, but went away and cast him into prison,—until he should pay what was owing.", "weymouth": "\"He would not, however, but went and threw him into prison until he should pay what was due.", "darby": "But he would not, but went away and cast him into prison, until he should pay what was owing.", "twenty": "But the other would not, but went and put him in prison till he should pay his debt.", "acv": "But he would not, instead, having left him, he cast him into prison until he would pay that which was owed.", "anderson": "And he would not; but went and threw him into prison, till he should pay the debt.", "haweis": "And he would not: but went and cast him into prison, till he should pay what he owed.", "noyes": "And he would not; but went away and cast him into prison, till he should pay the debt.", "webster": "And he would not: but went and cast him into prison, till he should pay the debt.", "vulgate": "ille autem noluit sed abiit et misit eum in carcerem donec redderet debitum;"}}, {"v": 31, "ref": "18:31", "o": "ἰδόντες ⸀οὖν οἱ σύνδουλοι αὐτοῦ τὰ γενόμενα ἐλυπήθησαν σφόδρα, καὶ ἐλθόντες διεσάφησαν τῷ κυρίῳ ἑαυτῶν πάντα τὰ γενόμενα.", "en": {"kjv": "So when his fellowservants saw what was done, they were very sorry, and came and told unto their lord all that was done.", "web": "So when his fellow servants saw what was done, they were exceedingly sorry, and came and told to their lord all that was done.", "bsb": "When his fellow servants saw what had happened, they were greatly distressed, and they went and recounted all of this to their master.", "asv": "So when his fellow-servants saw what was done, they were exceeding sorry, and came and told unto their lord all that was done.", "ylt": "`And his fellow-servants having seen the things that were done, were grieved exceedingly, and having come, shewed fully to their lord all the things that were done;", "tyndale": "When his other felowes sawe what was done they were very sory and came and tolde vnto their lorde all yt had happened.", "dra": "Now his fellow servants seeing what was done, were very much grieved, and they came, and told their lord all that was done.", "bbe": "So when the other servants saw what was done they were very sad, and came and gave word to their lord of what had been done.", "geneva": "And when his other felowe seruants sawe what was done, they were very sory, and came, and declared vnto their Lord all that was done.", "wycliffe": "And hise euen seruauntis, seynge the thingis that weren don, soreweden greetli. And thei camen, and telden to her lord alle the thingis that weren don.", "rotherham": "His fellow-servants, therefore, seeing, the things that were done, were grieved exceedingly,—and went and made quite plain to their master all the things which had been done.", "weymouth": "His fellow servants, therefore, seeing what had happened, were exceedingly angry; and they came and told their master without reserve all that had happened.", "darby": "But his fellow-bondmen, having seen what had taken place, were greatly grieved, and went and recounted to their lord all that had taken place.", "twenty": "When his fellow-servants saw what had happened, they were greatly distressed, and went to their master and laid the whole matter before him.", "acv": "And when his fellow bondmen saw the things that happened, they were extremely sorry. And after coming, they reported to their lord all the things that happened.", "anderson": "When his fellow-servants saw what was done, they were very sad, and went and made known to their lord all that was done.", "haweis": "Then his fellow-servants, when they saw what was done, were exceedingly sorry, and came to their lord, and gave him an explicit account of all things that had passed.", "noyes": "Then his fellow-servants, seeing what was done, were greatly grieved; and went and told their lord all that had been done.", "webster": "So when his fellow-servants saw what was done, they were very sorry, and came and told to their lord all that was done.", "vulgate": "videntes autem conservi eius quae fiebant contristati sunt valde et venerunt et narraverunt domino suo omnia quae facta erant;"}}, {"v": 32, "ref": "18:32", "o": "τότε προσκαλεσάμενος αὐτὸν ὁ κύριος αὐτοῦ λέγει αὐτῷ· Δοῦλε πονηρέ, πᾶσαν τὴν ὀφειλὴν ἐκείνην ἀφῆκά σοι, ἐπεὶ παρεκάλεσάς με·", "en": {"kjv": "Then his lord, after that he had called him, said unto him, O thou wicked servant, I forgave thee all that debt, because thou desiredst me:", "web": "Then his lord called him in, and said to him, ‘You wicked servant! I forgave you all that debt, because you begged me.", "bsb": "Then the master summoned him and declared, ‘You wicked servant! I forgave all your debt because you begged me.", "asv": "Then his lord called him unto him, and saith to him, Thou wicked servant, I forgave thee all that debt, because thou besoughtest me:", "ylt": "then having called him, his lord saith to him, Evil servant! all that debt I did forgive thee, seeing thou didst call upon me,", "tyndale": "Then his lorde called him and sayde vnto him. O evyll servaut I forgave the all that det because thou prayedst me: was it not mete also yt thou", "dra": "Then his lord called him: and said to him: Thou wicked servant, I forgave thee all the debt, because thou besoughtest me:", "bbe": "Then his lord sent for him and said, You evil servant; I made you free of all that debt, because of your request to me:", "geneva": "Then his Lord called him vnto him, and sayd to him, O euil seruant, I forgaue thee all that dette, because thou prayedst me.", "wycliffe": "Thanne his lord clepide hym, and seide to hym, Wickid seruaunt, Y foryaf to thee al the dette, for thou preiedist me.", "rotherham": "Then, calling him near, his master saith unto him—O wicked servant! All that debt, forgave I thee, because thou didst beseech me.", "weymouth": "At once his master called him and said, \"`Wicked servant, I forgave you all that debt, because you entreated me:", "darby": "Then his lord, having called him to [him], says to him, Wicked bondman! I forgave thee all that debt because thou besoughtest me;", "twenty": "Upon that the master sent for the servant, and said to him ‘You wicked servant! When you begged me for mercy, I forgave you the whole of that debt.", "acv": "Then his lord having summoned him, he says to him, Thou evil bondman, I forgave thee all that debt because thou besought me.", "anderson": "Then his lord called him and said to him: Wicked servant! I forgave you all that debt, because you besought me.", "haweis": "Then his lord, calling him before him, said to him, Thou vile slave! all that debt I forgave thee, because thou besoughtest me:", "noyes": "Then his lord, having called him, saith to him, Thou wicked servant! All that debt I forgave thee because thou didst beseech me;", "webster": "Then his lord, having called him, said to him, O thou wicked servant, I forgave thee all that debt, because thou desiredst me:", "vulgate": "tunc vocavit illum dominus suus et ait illi serve nequam omne debitum dimisi tibi quoniam rogasti me;"}}, {"v": 33, "ref": "18:33", "o": "οὐκ ἔδει καὶ σὲ ἐλεῆσαι τὸν σύνδουλόν σου, ὡς κἀγὼ σὲ ἠλέησα;", "en": {"kjv": "Shouldest not thou also have had compassion on thy fellowservant, even as I had pity on thee?", "web": "Shouldn’t you also have had mercy on your fellow servant, even as I had mercy on you?’", "bsb": "Shouldn’t you have had mercy on your fellow servant, just as I had on you?’", "asv": "shouldest not thou also have had mercy on thy fellow-servant, even as I had mercy on thee?", "ylt": "did it not behove also thee to have dealt kindly with thy fellow-servant, as I also dealt kindly with thee?", "tyndale": "shuldest have had copassion on thy felow even as I had pitie on ye?", "dra": "Shouldst not thou then have had compassion also on thy fellow servant, even as I had compassion on thee?", "bbe": "Was it not right for you to have mercy on the other servant, even as I had mercy on you?", "geneva": "Oughtest not thou also to haue had pitie on thy fellowe seruant, euen as I had pitie on thee?", "wycliffe": "Therfor whether it bihouede not also thee to haue merci on thin euen seruaunt, as Y hadde merci on thee?", "rotherham": "Was it not binding, upon thee also, to have mercy upon thy fellow-servant, as, I also, on thee, had mercy?", "weymouth": "ought not you also to have had pity on your fellow servant, just as I had pity on you?'", "darby": "shouldest not thou also have had compassion on thy fellow-bondman, as I also had compassion on thee?", "twenty": "Ought not you, also, to have shown mercy to your fellow-servant, just as I showed mercy to you?’", "acv": "Was it not necessary for thee also to be merciful to thy fellow bondman, as I also was merciful to thee?", "anderson": "Ought you not to have had mercy on your fellow-servant, even as I had mercy on you?", "haweis": "and oughtest thou not to have had compassion on thy fellow-servant, even as I had pity on thee?", "noyes": "shouldst not thou also have had pity on thy fellow-servant, even as I had pity on thee?", "webster": "Shouldst thou not also have had compassion on thy fellow-servant, even as I had pity on thee?", "vulgate": "non ergo oportuit et te misereri conservi tui sicut et ego tui misertus sum;"}}, {"v": 34, "ref": "18:34", "o": "καὶ ὀργισθεὶς ὁ κύριος αὐτοῦ παρέδωκεν αὐτὸν τοῖς βασανισταῖς ἕως οὗ ἀποδῷ πᾶν τὸ ⸀ὀφειλόμενον.", "en": {"kjv": "And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due unto him.", "web": "His lord was angry, and delivered him to the tormentors, until he should pay all that was due to him.", "bsb": "In anger his master turned him over to the jailers to be tortured, until he should repay all that he owed.", "asv": "And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due.", "ylt": "`And having been wroth, his lord delivered him to the inquisitors, till he might pay all that was owing to him;", "tyndale": "And his lorde was wrooth and delyuered him to the iaylers tyll he shnld paye all that was due to him.", "dra": "And his lord being angry, delivered him to the torturers until he paid all the debt.", "bbe": "And his lord was very angry, and put him in the hands of those who would give him punishment till he made payment of all the debt.", "geneva": "So his Lord was wroth, and deliuered him to the tormentours, till he should pay all that was due to him.", "wycliffe": "And his lord was wroth, and took hym to turmentouris, til he paiede al the dette.", "rotherham": "And, provoked to anger, his master delivered him up to the torturers, until he should pay all that was owing.", "weymouth": "\"So his master, greatly incensed, handed him over to the jailers until he should pay all he owed him.", "darby": "And his lord being angry delivered him to the tormentors till he paid all that was owing to him.", "twenty": "Then his master, in anger, handed him over to the jailers, until he should pay the whole of his debt.", "acv": "And having become angry, his lord delivered him to the tormentors until he would pay all that was due to him.", "anderson": "And his lord was angry, and delivered him to the jailers, till he should pay all that was due him.", "haweis": "And his lord, incensed, delivered him up to the torturers, till he should pay all that he owed him.", "noyes": "And his lord was enraged, and delivered him to the inflicters of punishment, till he should pay all that was due to him.", "webster": "And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due to him.", "vulgate": "et iratus dominus eius tradidit eum tortoribus quoadusque redderet universum debitum;"}}, {"v": 35, "ref": "18:35", "o": "Οὕτως καὶ ὁ πατήρ μου ὁ ⸀οὐράνιος ποιήσει ὑμῖν ἐὰν μὴ ἀφῆτε ἕκαστος τῷ ἀδελφῷ αὐτοῦ ἀπὸ τῶν καρδιῶν ⸀ὑμῶν.", "en": {"kjv": "So likewise shall my heavenly Father do also unto you, if ye from your hearts forgive not every one his brother their trespasses.", "web": "So my heavenly Father will also do to you, if you don’t each forgive your brother from your hearts for his misdeeds.”", "bsb": "That is how My heavenly Father will treat each of you unless you forgive your brother from your heart.”", "asv": "So shall also my heavenly Father do unto you, if ye forgive not every one his brother from your hearts.", "ylt": "so also my heavenly Father will do to you, if ye may not forgive each one his brother from your hearts their trespasses.'", "tyndale": "So lyke wyse shall my hevenly father do vnto you except ye forgeve with youre hertes eache one to his brother their treaspases.", "dra": "So also shall my heavenly Father do to you, if you forgive not every one his brother from your hearts.", "bbe": "So will my Father in heaven do to you, if you do not everyone, from your hearts, give forgiveness to his brother.", "geneva": "So likewise shall mine heauenly Father doe vnto you, except ye forgiue from your hearts, eche one to his brother their trespasses.", "wycliffe": "So my fadir of heuene schal do to you, if ye foryyuen not euery man to his brother, of youre hertes.", "rotherham": "Thus, my heavenly Father also, will do unto you, if ye forgive not each one his brother, from your hearts.", "weymouth": "\"In the same way my Heavenly Father will deal with you, if you do not all of you forgive one another from your hearts.\"", "darby": "Thus also my heavenly Father shall do to you if ye forgive not from your hearts every one his brother.", "twenty": "So, also, will my heavenly Father do to you, unless each one of you forgives his Brother from his heart.”", "acv": "So also my heavenly Father will do to you, if ye do not forgive each man his brother, from your hearts, their trespasses.", "anderson": "So also will my heavenly Father do to you, if, from your hearts, you forgive not every one his brother’s offenses.", "haweis": "Even so also will my heavenly Father do to you, except ye forgive every one of you his brother, from your hearts, their trespasses.", "noyes": "So also will my heavenly Father do to you, if ye forgive not every one his brother from your hearts.", "webster": "So likewise shall my heavenly Father do to you, if ye from your hearts forgive not every one his brother their trespasses.", "vulgate": "sic et Pater meus caelestis faciet vobis si non remiseritis unusquisque fratri suo de cordibus vestris;"}}]}, {"c": 19, "verses": [{"v": 1, "ref": "19:1", "o": "Καὶ ἐγένετο ὅτε ἐτέλεσεν ὁ Ἰησοῦς τοὺς λόγους τούτους, μετῆρεν ἀπὸ τῆς Γαλιλαίας καὶ ἦλθεν εἰς τὰ ὅρια τῆς Ἰουδαίας πέραν τοῦ Ἰορδάνου.", "en": {"kjv": "And it came to pass, that when Jesus had finished these sayings, he departed from Galilee, and came into the coasts of Judea beyond Jordan;", "web": "When Jesus had finished these words, he departed from Galilee, and came into the borders of Judea beyond the Jordan.", "bsb": "When Jesus had finished saying these things, He left Galilee and went into the region of Judea beyond the Jordan.", "asv": "And it came to pass when Jesus had finished these words, he departed from Galilee, and came into the borders of Judæa beyond the Jordan;", "ylt": "And it came to pass, when Jesus finished these words, he removed from Galilee, and did come to the borders of Judea, beyond the Jordan,", "tyndale": "And it came to passe when Iesus had fynisshed those sayinges he gat him from Galile and came into the coostes of Iewry beyonde Iordan", "dra": "And it came to pass when Jesus had ended these words, he departed from Galilee and came into the coasts of Judea, beyond Jordan.", "bbe": "And it came about that after saying these words, Jesus went away from Galilee, and came into the parts of Judaea on the other side of Jordan.", "geneva": "And it came to passe, that when Iesus had finished these sayings, he departed from Galile, and came into ye coasts of Iudea beyond Iordan.", "wycliffe": "And it was don, whanne Jhesus hadde endid these wordis, he passide fro Galilee, and cam in to the coostis of Judee ouer Jordan.", "rotherham": "And it came to pass, when Jesus ended these words, he removed from Galilee and came into the bounds of Judaea beyond the Jordan.", "weymouth": "When Jesus had finished these discourses, He removed from Galilee and came into that part of Judaea which lay beyond the Jordan.", "darby": "And it came to pass, when Jesus had finished these words, he withdrew from Galilee, and came to the coasts of Judaea beyond the Jordan;", "twenty": "At the conclusion of this teaching, Jesus withdrew from Galilee, and went into that district of Judea which is on the other side of the Jordan.", "acv": "And it came to pass when Jesus had finished these sayings, he departed from Galilee and came into the regions of Judea beyond the Jordan.", "anderson": "And it came to pass when Jesus had finished these discourses, that he departed from Galilee, and came into the borders of Judea, beyond the Jordan.", "haweis": "AND it came to pass when Jesus had finished these sayings, he departed from Galilee, and came into the coasts of Judea beyond Jordan.", "noyes": "And it came to pass, that when Jesus had ended these sayings, he removed from Galilee, and came into the borders of Judaea, beyond the Jordan.", "webster": "And it came to pass, [that] when Jesus had finished these sayings, he departed from Galilee, and came into the borders of Judea, beyond Jordan:", "vulgate": "et factum est cum consummasset Iesus sermones istos migravit a Galilaea et venit in fines Iudaeae trans Iordanen;"}}, {"v": 2, "ref": "19:2", "o": "καὶ ἠκολούθησαν αὐτῷ ὄχλοι πολλοί, καὶ ἐθεράπευσεν αὐτοὺς ἐκεῖ.", "en": {"kjv": "And great multitudes followed him; and he healed them there.", "web": "Great multitudes followed him, and he healed them there.", "bsb": "Large crowds followed Him, and He healed them there.", "asv": "and great multitudes followed him; and he healed them there.", "ylt": "and great multitudes followed him, and he healed them there.", "tyndale": "and moche people folowed him and he healed them theare.", "dra": "And great multitudes followed him: and he healed them there.", "bbe": "And a great number went after him; and he made them well there.", "geneva": "And great multitudes followed him, and he healed them there.", "wycliffe": "And myche puple suede him, and he heelide hem there.", "rotherham": "And there followed him large multitudes, and he cured them there.", "weymouth": "And a vast multitude followed him, and He cured them there.", "darby": "and great crowds followed him, and he healed them there.", "twenty": "Great crowds followed him, and he cured them there.", "acv": "And many multitudes followed him and he healed them there.", "anderson": "And many multitudes followed him; and he cured them there.", "haweis": "And great multitudes followed him; and he healed them there.", "noyes": "And great multitudes followed him; and he healed them there.", "webster": "And great multitudes followed him, and he healed them there.", "vulgate": "et secutae sunt eum turbae multae et curavit eos ibi;"}}, {"v": 3, "ref": "19:3", "o": "Καὶ προσῆλθον ⸀αὐτῷ Φαρισαῖοι πειράζοντες αὐτὸν καὶ ⸀λέγοντες· Εἰ ἔξεστιν ⸀ἀνθρώπῳ ἀπολῦσαι τὴν γυναῖκα αὐτοῦ κατὰ πᾶσαν αἰτίαν;", "en": {"kjv": "The Pharisees also came unto him, tempting him, and saying unto him, Is it lawful for a man to put away his wife for every cause?", "web": "Pharisees came to him, testing him, and saying, “Is it lawful for a man to divorce his wife for any reason?”", "bsb": "Then some Pharisees came and tested Him by asking, “Is it lawful for a man to divorce his wife for any reason?”", "asv": "And there came unto him Pharisees, trying him, and saying, Is it lawful for a man to put away his wife for every cause?", "ylt": "And the Pharisees came near to him, tempting him, and saying to him, `Is it lawful for a man to put away his wife for every cause?'", "tyndale": "Then came vnto him the pharises temtinge him and sayinge to him: Ys it lawfull for a man to put awaye his wyfe for all maner of causes?", "dra": "And there came to him the Pharisees tempting him, saying: Is it lawful for a man to put away his wife for every cause?", "bbe": "And certain Pharisees came to him, testing him, and saying, Is it right for a man to put away his wife for every cause?", "geneva": "Then came vnto him the Pharises tempting him, and saying to him, Is it lawfull for a man to put away his wife vpon euery occasion?", "wycliffe": "And Farisees camen to him, temptynge him, and seiden, Whether it be leueful to a man to leeue his wijf, for ony cause?", "rotherham": "And there came unto him Pharisees, testing him, and saying,—Whether is it allowed a man to divorce his wife, for every cause?", "weymouth": "Then came some of the Pharisees to Him to put Him to the proof by the question, \"Has a man a right to divorce his wife whenever he chooses?\"", "darby": "And the Pharisees came to him tempting him, and saying, Is it lawful for a man to put away his wife for every cause?", "twenty": "Presently some Pharisees came up to him, and, to test him, said: “Has a man the right to divorce his wife for every cause?”", "acv": "And Pharisees came to him, trying him, and saying to him, Is it permitted for a man to divorce his wife for every cause?", "anderson": "And the Pharisees came to him to tempt him, and said to him: Is it lawful for a man to put away his wife for every cause?", "haweis": "And the Pharisees came to him, tempting him, and saying, Is it lawful for a man to put away his wife for every cause?", "noyes": "And the Pharisees came to him, trying him, and saying, Is it lawful for a man to put away his wife for every cause?", "webster": "The Pharisees also came to him, tempting him, and saying to him, Is it lawful for a man to put away his wife for every cause?", "vulgate": "et accesserunt ad eum Pharisaei temptantes eum et dicentes si licet homini dimittere uxorem suam quacumque ex causa;"}}, {"v": 4, "ref": "19:4", "o": "ὁ δὲ ἀποκριθεὶς ⸀εἶπεν· Οὐκ ἀνέγνωτε ὅτι ὁ ⸀κτίσας ἀπ’ ἀρχῆς ἄρσεν καὶ θῆλυ ἐποίησεν αὐτοὺς", "en": {"kjv": "And he answered and said unto them, Have ye not read, that he which made them at the beginning made them male and female,", "web": "He answered, “Haven’t you read that he who made them from the beginning made them male and female,", "bsb": "Jesus answered, “Have you not read that from the beginning the Creator ‘made them male and female,’", "asv": "And he answered and said, Have ye not read, that he who made them from the beginning made them male and female,", "ylt": "And he answering said to them, `Did ye not read, that He who made them , from the beginning a male and a female made them,", "tyndale": "He answered and sayd vnto them: Have ye not redde how that he which made man at the beginninge made them man and woman", "dra": "Who answering, said to them: Have ye not read, that he who made man from the beginning, made them male and female? And he said:", "bbe": "And he said in answer, Have you not seen in the Writings, that he who made them at the first made them male and female, and said,", "geneva": "And he answered and sayd vnto them, Haue ye not read, that hee which made them at the beginning, made them male and female,", "wycliffe": "Which answeride, and seide to hem, Han ye not red, for he that made men at the bigynnyng, made hem male and female?", "rotherham": "And, he, answering, said—Did ye never read—He who created at the beginning, Male and female, made them,—", "weymouth": "\"Have you not read,\" He replied, \"that He who made them `made them' from the beginning `male and female,", "darby": "But he answering said [to them], Have ye not read that he who made [them], from the beginning made them male and female,", "twenty": "“Have not you read,” replied Jesus, “that at the beginning the Creator ‘made them male and female,’", "acv": "And having answered, he said to them, Have ye not read that he who made them from the beginning made them male and female,", "anderson": "He answered and said to them: Have you not read that the Creator, at the beginning, created them male and female,", "haweis": "But he replying, said unto them, Have ye not read, that he who created them from the beginning, created them male and female?", "noyes": "And he answering said, Have ye not read, that he who made them at the beginning, made them male and female?", "webster": "And he answered and said to them, Have ye not read, that he who made [them], at the beginning made them male and female,", "vulgate": "qui respondens ait eis non legistis quia qui fecit ab initio masculum et feminam fecit eos;"}}, {"v": 5, "ref": "19:5", "o": "καὶ εἶπεν· ⸀Ἕνεκα τούτου καταλείψει ἄνθρωπος τὸν πατέρα καὶ τὴν μητέρα καὶ ⸀κολληθήσεται τῇ γυναικὶ αὐτοῦ, καὶ ἔσονται οἱ δύο εἰς σάρκα μίαν;", "en": {"kjv": "And said, For this cause shall a man leave father and mother, and shall cleave to his wife: and they twain shall be one flesh?", "web": "and said, ‘For this cause a man shall leave his father and mother, and shall join to his wife; and the two shall become one flesh?’", "bsb": "and said, ‘For this reason a man will leave his father and mother and be united to his wife, and the two will become one flesh’?", "asv": "and said, For this cause shall a man leave his father and mother, and shall cleave to his wife; and the two shall become one flesh?", "ylt": "and said, For this cause shall a man leave father and mother, and cleave to his wife, and they shall be--the two--for one flesh?", "tyndale": "and sayde: for this thinge shall a ma leve father and mother and cleve vnto his wyfe and they twayne shalbe one flesshe.", "dra": "For this cause shall a man leave father and mother, and shall cleave to his wife, and they two shall be in one flesh.", "bbe": "For this cause will a man go away from his father and mother, and be joined to his wife; and the two will become one flesh?", "geneva": "And sayd, For this cause, shall a man leaue father and mother, and cleaue vnto his wife, and they which were two shalbe one flesh.", "wycliffe": "And he seide, For this thing a man schal leeue fadir and modir, and he schal draw to his wijf; and thei schulen be tweyne in o fleisch.", "rotherham": "and said—For this cause, will a man leave his father and his mother, and be united to his wife,—and, the two, will become, one flesh;", "weymouth": "and said, For this reason a man shall leave his father and mother and be united to his wife, and the two shall be one'?", "darby": "and said, On account of this a man shall leave father and mother, and shall be united to his wife, and the two shall be one flesh?", "twenty": "and said — ‘For this reason a man shall leave his father and mother, and be united to his wife, and the man and his wife shall become one’?", "acv": "and said, For this reason a man will leave his father and mother behind, and will be bonded with his wife, and the two will be in one flesh?", "anderson": "and said, For this cause shall a man leave his father and his mother, and shall cleave to his wife, and the two shall be one flesh?", "haweis": "And he said, for this reason shall a man forsake father and mother, and shall cleave to his wife, and they two shall be one flesh.", "noyes": "And He said: \"For this cause shall a man leave father and mother, and cleave to his wife; and the two shall become one flesh.\"", "webster": "And said, For this [cause] shall a man leave father and mother, and shall cleave to his wife: and they two shall be one flesh?", "vulgate": "et dixit propter hoc dimittet homo patrem et matrem et adherebit uxori suae et erunt duo in carne una;"}}, {"v": 6, "ref": "19:6", "o": "ὥστε οὐκέτι εἰσὶν δύο ἀλλὰ σὰρξ μία. ὃ οὖν ὁ θεὸς συνέζευξεν ἄνθρωπος μὴ χωριζέτω.", "en": {"kjv": "Wherefore they are no more twain, but one flesh. What therefore God hath joined together, let not man put asunder.", "web": "So that they are no more two, but one flesh. What therefore God has joined together, don’t let man tear apart.”", "bsb": "So they are no longer two, but one flesh. Therefore what God has joined together, let man not separate.”", "asv": "So that they are no more two, but one flesh. What therefore God hath joined together, let not man put asunder.", "ylt": "so that they are no more two, but one flesh; what therefore God did join together, let no man put asunder.'", "tyndale": "Wherfore now are they not twayne but one flesshe. Let not man therfore put a sunder that which God hath cuppled to gedder.", "dra": "Therefore now they are not two, but one flesh. What therefore God hath joined together, let no man put asunder.", "bbe": "So that they are no longer two, but one flesh. Then let not that which has been joined by God be parted by man.", "geneva": "Wherefore they are no more twaine, but one flesh. Let not man therefore put asunder that, which God hath coupled together.", "wycliffe": "And so thei ben not now tweyne, but o fleisch. Therfor a man departe not that thing that God hath ioyned.", "rotherham": "So that, the longer, are they, two, but, one flesh, What, therefore, God, hath yoked together, Let not, a man, put asunder.", "weymouth": "Thus they are no longer two, but `one'! What therefore God has joined together, let not man separate.\"", "darby": "so that they are no longer two, but one flesh. What thereforeGod has joined together, let not man separate.", "twenty": "So that they are no longer two, but one. What God himself, then, has yoked together man must not separate.”", "acv": "So that they are no longer two, but one flesh. What therefore God has joined together, no man shall separate.", "anderson": "So then, they are no longer two, but one flesh. Therefore, what God has joined together, let not man put asunder.", "haweis": "Wherefore they are no longer two, but one flesh. What therefore God hath yoked together, let no man separate.", "noyes": "So they are no longer two, but one flesh. What therefore God joined together, let not man put asunder.", "webster": "Wherefore they are no more two, but one flesh. Therefore what God hath joined together, let not man put asunder.", "vulgate": "itaque iam non sunt duo sed una caro quod ergo Deus coniunxit homo non separet;"}}, {"v": 7, "ref": "19:7", "o": "λέγουσιν αὐτῷ· Τί οὖν Μωϋσῆς ἐνετείλατο δοῦναι βιβλίον ἀποστασίου καὶ ἀπολῦσαι ⸀αὐτήν;", "en": {"kjv": "They say unto him, Why did Moses then command to give a writing of divorcement, and to put her away?", "web": "They asked him, “Why then did Moses command us to give her a bill of divorce, and divorce her?”", "bsb": "“Why then,” they asked, “did Moses order a man to give his wife a certificate of divorce and send her away?”", "asv": "They say unto him, Why then did Moses command to give a bill of divorcement, and to put her away?", "ylt": "They say to him, `Why then did Moses command to give a roll of divorce, and to put her away?'", "tyndale": "The sayde they to him: why did Moses comaunde to geve a testimoniall of divorsemet and to put hyr awaye?", "dra": "They say to him: Why then did Moses command to give a bill of divorce, and to put away?", "bbe": "They say to him, Why then did Moses give orders that a husband might give her a statement in writing and be free from her?", "geneva": "They said to him, Why did then Moses commaund to giue a bill of diuorcement, and to put her away?", "wycliffe": "Thei seien to hym, What thanne comaundide Moises, to yyue a libel of forsakyng, and to leeue of?", "rotherham": "They say unto him—Why then did, Moses, command, to give a writing of repudiation and to divorce?", "weymouth": "\"Why then,\" said they, \"did Moses command the husband to give her `a written notice of divorce,' and so put her away?\"", "darby": "They say to him, Why then did Moses command to give a letter of divorce and to send [her] away?", "twenty": "“Why, then,” they said, “did Moses direct that a man should ‘serve his wife with a notice of separation and divorce her’?”", "acv": "They say to him, Why then did Moses command to give a writing of divorcement, and to divorce her?", "anderson": "They said to him: Why, then, did Moses command us to give a bill of divorce and put her away?", "haweis": "They say unto him, Why then did Moses command to give her a bill of divorce, and to put her away?", "noyes": "They say to him, Why then did Moses ordain that a man may give his wife a writing of divorcement, and put her away?", "webster": "They say to him, Why did Moses then command to give a writing of divorcement, and to put her away?", "vulgate": "dicunt illi quid ergo Moses mandavit dari libellum repudii et dimittere;"}}, {"v": 8, "ref": "19:8", "o": "λέγει αὐτοῖς ὅτι Μωϋσῆς πρὸς τὴν σκληροκαρδίαν ὑμῶν ἐπέτρεψεν ὑμῖν ἀπολῦσαι τὰς γυναῖκας ὑμῶν, ἀπ’ ἀρχῆς δὲ οὐ γέγονεν οὕτως.", "en": {"kjv": "He saith unto them, Moses because of the hardness of your hearts suffered you to put away your wives: but from the beginning it was not so.", "web": "He said to them, “Moses, because of the hardness of your hearts, allowed you to divorce your wives, but from the beginning it has not been so.", "bsb": "Jesus replied, “Moses permitted you to divorce your wives because of your hardness of heart; but it was not this way from the beginning.", "asv": "He saith unto them, Moses for your hardness of heart suffered you to put away your wives: but from the beginning it hath not been so.", "ylt": "He saith to them--`Moses for your stiffness of heart did suffer you to put away your wives, but from the beginning it hath not been so.", "tyndale": "He sayde vnto them: Moses because of the hardnes of youre hertes suffred you to put awaye youre wyfes: But from ye beginnynge it was not so.", "dra": "He saith to them: Because Moses by reason of the hardness of your heart permitted you to put away your wives: but from the beginning it was not so.", "bbe": "He says to them, Moses, because of your hard hearts, let you put away your wives: but it has not been so from the first.", "geneva": "He sayd vnto them, Moses, because of the hardnesse of your heart, suffered you to put away your wiues: but from the beginning it was not so.", "wycliffe": "And he seide to hem, For Moises, for the hardnesse of youre herte, suffride you leeue youre wyues; but fro the bigynnyng it was not so.", "rotherham": "He saith unto them—Moses, in view of your hardness of heart, permitted you to divorce your wives; From the beginning however, hath it not been done, thus.", "weymouth": "\"Moses,\" He replied, \"in consideration of the hardness of your nature permitted you to put away your wives, but it has not been so from the beginning.", "darby": "He says to them, Moses, in view of your hardheartedness, allowed you to put away your wives; but from the beginning it was not thus.", "twenty": "“Moses, owing to the hardness of your hearts,” answered Jesus, “permitted you to divorce your wives, but that was not so at the beginning.", "acv": "He says to them, For your hard heart Moses allowed you to divorce your wives, but from the beginning it did not happen this way.", "anderson": "He said to them: Moses, on account of the hardness of your hearts, permitted you to put away your wives; but from the beginning it was not so.", "haweis": "He saith unto them, It was on account of the hardness of your hearts that Moses gave you permission to put away your wives: but from the beginning it was not thus.", "noyes": "He saith to them, Moses, on account of your hardness of heart, allowed you m put away your wives; but in the beginning it was not so.", "webster": "He saith to them, Moses, because of the hardness of your hearts, suffered you to put away your wives: but from the beginning it was not so.", "vulgate": "ait illis quoniam Moses ad duritiam cordis vestri permisit vobis dimittere uxores vestras ab initio autem non sic fuit;"}}, {"v": 9, "ref": "19:9", "o": "λέγω δὲ ὑμῖν ⸀ὅτι ὃς ἂν ἀπολύσῃ τὴν γυναῖκα αὐτοῦ μὴ ἐπὶ πορνείᾳ καὶ γαμήσῃ ἄλλην μοιχᾶται ⸂καὶ ὁ ἀπολελυμένην γαμήσας μοιχᾶται⸃.", "en": {"kjv": "And I say unto you, Whosoever shall put away his wife, except it be for fornication, and shall marry another, committeth adultery: and whoso marrieth her which is put away doth commit adultery.", "web": "I tell you that whoever divorces his wife, except for sexual immorality, and marries another, commits adultery; and he who marries her when she is divorced commits adultery.”", "bsb": "Now I tell you that whoever divorces his wife, except for sexual immorality, and marries another woman, commits adultery.”", "asv": "And I say unto you, Whosoever shall put away his wife, except for fornication, and shall marry another, committeth adultery: and he that marrieth her when she is put away committeth adultery.", "ylt": "`And I say to you, that, whoever may put away his wife, if not for whoredom, and may marry another, doth commit adultery; and he who did marry her that hath been put away, doth commit adultery.'", "tyndale": "I saye therfore vnto you whosoever putteth awaye his wyfe (except it be for fornicacion) and maryeth another breaketh wedlocke. And whosoever maryeth her which is divorsed doeth commyt advoutry.", "dra": "And I say to you, that whosoever shall put away his wife, except it be for fornication, and shall marry another, committeth adultery: and he that shall marry her that is put away, committeth adultery.", "bbe": "And I say to you, Whoever puts away his wife for any other cause than the loss of her virtue, and takes another, is a false husband: and he who takes her as his wife when she is put away, is no true husband to her.", "geneva": "I say therefore vnto you, that whosoeuer shall put away his wife, except it be for whoredome, and marry another, committeth adulterie: and whosoeuer marieth her which is diuorced, doeth commit adulterie.", "wycliffe": "And Y seie to you, that who euer leeueth his wijf, but for fornycacioun, and weddith another, doith letcherie; and he that weddith the forsakun wijf, doith letcherie.", "rotherham": "And I say unto you—Whosoever shall divorce his wife, saving for unfaithfulness, and shall marry another, committeth adultery.", "weymouth": "And I tell you that whoever divorces his wife for any reason except her unfaithfulness, and marries another woman, commits adultery.\"", "darby": "But I say unto you, that whosoever shall put away his wife, not for fornication, and shall marry another, commits adultery; and he who marries one put away commits adultery.", "twenty": "But I tell you that any one who divorces his wife, except on the ground of her unchastity, and marries another woman, is guilty of adultery.”", "acv": "And I say to you, that whoever may divorce his wife, not for fornication, and will marry another, commits adultery. And he who married her who has been divorced commits adultery.", "anderson": "But I say to you, That whoever puts away his wife, unless for lewdness, and marries another, commits adultery; and he that marries her that is put away, commits adultery.", "haweis": "And I tell you, that whosoever shall put away his wife, except for whoredom, and shall marry another, committeth adultery: and he that marrieth the divorced woman, committeth adultery.", "noyes": "And I say to you, Whoever putteth away his wife, except for fornication, and marrieth another, committeth adultery.", "webster": "And I say to you, Whoever shall put away his wife, except for lewdness, and shall marry another, committeth adultery: and whoever marrieth her who is put away, committeth adultery.", "vulgate": "dico autem vobis quia quicumque dimiserit uxorem suam nisi ob fornicationem et aliam duxerit moechatur et qui dimissam duxerit moechatur;"}}, {"v": 10, "ref": "19:10", "o": "Λέγουσιν αὐτῷ οἱ ⸀μαθηταί· Εἰ οὕτως ἐστὶν ἡ αἰτία τοῦ ἀνθρώπου μετὰ τῆς γυναικός, οὐ συμφέρει γαμῆσαι.", "en": {"kjv": "His disciples say unto him, If the case of the man be so with his wife, it is not good to marry.", "web": "His disciples said to him, “If this is the case of the man with his wife, it is not expedient to marry.”", "bsb": "His disciples said to Him, “If this is the case between a man and his wife, it is better not to marry.”", "asv": "The disciples say unto him, If the case of the man is so with his wife, it is not expedient to marry.", "ylt": "His disciples say to him, `If the case of the man with the woman is so, it is not good to marry.'", "tyndale": "Then sayde his disciples to him: yf the mater be so betwene man and wyfe then is it not good to mary.", "dra": "His disciples say unto him: If the case of a man with his wife be so, it is not expedient to marry.", "bbe": "The disciples say to him, If this is the position of a man in relation to his wife, it is better not to be married.", "geneva": "Then sayd his disciples to him, If the matter be so betweene man and wife, it is not good to marry.", "wycliffe": "His disciplis seien to him, If the cause of a man with a wijf is so, it spedith not to be weddid.", "rotherham": "The disciples say unto him—If, so, is the cause of the husband with the wife, it is not expedient to marry.", "weymouth": "\"If this is the case with a man in relation to his wife,\" said the disciples to Him, \"it is better not to marry.\"", "darby": "His disciples say to him, If the case of the man be so with his wife, it is not good to marry.", "twenty": "“If that,” said the disciples, “is the position of a man with regard to his wife, it is better not to marry.”", "acv": "His disciples say to him, If the case of the man with his wife is this way, it is not advantageous to marry.", "anderson": "His disciples said to him: If the relation of man and wife be such, it is not good to marry.", "haweis": "His disciples said unto him, If the case of a man with his wife be thus, it is not expedient to marry.", "noyes": "The disciples say to him, If such be the case of a man with his wife, it is not good to marry.", "webster": "His disciples say to him, If the case of the man is so with [his] wife, it is not good to marry.", "vulgate": "dicunt ei discipuli eius si ita est causa homini cum uxore non expedit nubere;"}}, {"v": 11, "ref": "19:11", "o": "ὁ δὲ εἶπεν αὐτοῖς· Οὐ πάντες χωροῦσι τὸν λόγον ⸀τοῦτον ἀλλ’ οἷς δέδοται.", "en": {"kjv": "But he said unto them, All men cannot receive this saying, save they to whom it is given.", "web": "But he said to them, “Not all men can receive this saying, but those to whom it is given.", "bsb": "“Not everyone can accept this word,” He replied, “but only those to whom it has been given.", "asv": "But he said unto them, Not all men can receive this saying, but they to whom it is given.", "ylt": "And he said to them, `All do not receive this word, but those to whom it hath been given;", "tyndale": "He sayde vnto them: all men can not awaye with that sayinge save they to whom it is geve.", "dra": "Who said to them: All men take not this word, but they to whom it is given.", "bbe": "But he said to them, Not all men are able to take in this saying, but only those to whom it is given.", "geneva": "But he sayd vnto them, All men cannot receiue this thing, saue they to whom it is giuen.", "wycliffe": "And he seide to hem, Not alle men taken this word; but to whiche it is youun.", "rotherham": "But, he, said unto them—Not all, find room for he word, save they to whom it hath been given;", "weymouth": "\"It is not every man,\" He replied, \"who can receive this teaching, but only those on whom the grace has been bestowed.", "darby": "And he said to them, All cannot receive this word, but those to whom it has been given;", "twenty": "“It is not every one,” replied Jesus, “who can accept this teaching, but only those who have been enabled to do so.", "acv": "But he said to them, Not all men can accommodate this saying, but to whom it has been given.", "anderson": "But he said to them: All can not accept this saying; only those to whom it is given.", "haweis": "Then he said to them, All men are not capable of receiving this saying, but they to whom it is given.", "noyes": "But he said to them, All cannot receive this saying, but they only to whom it is given.", "webster": "But he said to them, All [men] cannot receive this saying, save [they] to whom it is given.", "vulgate": "qui dixit non omnes capiunt verbum istud sed quibus datum est;"}}, {"v": 12, "ref": "19:12", "o": "εἰσὶν γὰρ εὐνοῦχοι οἵτινες ἐκ κοιλίας μητρὸς ἐγεννήθησαν οὕτως, καὶ εἰσὶν εὐνοῦχοι οἵτινες εὐνουχίσθησαν ὑπὸ τῶν ἀνθρώπων, καὶ εἰσὶν εὐνοῦχοι οἵτινες εὐνούχισαν ἑαυτοὺς διὰ τὴν βασιλείαν τῶν οὐρανῶν. ὁ δυνάμενος χωρεῖν χωρείτω.", "en": {"kjv": "For there are some eunuchs, which were so born from their mother’s womb: and there are some eunuchs, which were made eunuchs of men: and there be eunuchs, which have made themselves eunuchs for the kingdom of heaven’s sake. He that is able to receive it, let him receive it.", "web": "For there are eunuchs who were born that way from their mother’s womb, and there are eunuchs who were made eunuchs by men; and there are eunuchs who made themselves eunuchs for the Kingdom of Heaven’s sake. He who is able to receive it, let him receive it.”", "bsb": "For there are eunuchs who were born that way; others were made that way by men; and still others live like eunuchs for the sake of the kingdom of heaven. The one who can accept this should accept it.”", "asv": "For there are eunuchs, that were so born from their mother’s womb: and there are eunuchs, that were made eunuchs by men: and there are eunuchs, that made themselves eunuchs for the kingdom of heaven’s sake. He that is able to receive it, let him receive it.", "ylt": "for there are eunuchs who from the mother's womb were so born; and there are eunuchs who were made eunuchs by men; and there are eunuchs who kept themselves eunuchs because of the reign of the heavens: he who is able to receive it --let him receive.'", "tyndale": "Ther are chaste which were so borne out of their mothers belly. And ther are chaste which be made of men. And ther be chaste which have made them selves chaste for the kyngdome of heves sake. He that can take it let him take it.", "dra": "For there are eunuchs, who were born so from their mothers womb: and there are eunuchs, who were made so by men: and there are eunuchs, who have made themselves eunuchs for the kingdom of heaven. He that can take, let him take it.", "bbe": "For there are men who, from birth, were without sex: and there are some who were made so by men: and there are others who have made themselves so for the kingdom of heaven. He who is able to take it, let him take it.", "geneva": "For there are some eunuches, which were so borne of their mothers belly: and there be some eunuches, which be gelded by men: and there be some eunuches, which haue gelded them selues for the kingdome of heauen. He that is able to receiue this, let him receiue it.", "wycliffe": "For ther ben geldingis, whiche ben thus born of the modris wombe; and ther ben geldyngis, that ben maad of men; and there ben geldyngis, that han geldid hem silf, for the kyngdom of heuenes. He that may take, `take he.", "rotherham": "For there, are, eunuchs, who, from their mother’s womb, were born so, and there, are, eunuchs, who were made eunuchs, by men,—and there, are, eunuchs, who have made, themselves, eunuchs, for the sake the kingdom of the heavens: He that is able to find room, let him find room.", "weymouth": "There are men who from their birth have been disabled from marriage, others who have been so disabled by men, and others who have disabled themselves for the sake of the Kingdom of the Heavens. He who is able to receive this, let him receive it.\"", "darby": "for there are eunuchs which have been born thus from [their] mother's womb; and there are eunuchs who have been made eunuchs of men; and there are eunuchs who have made eunuchs of themselves for the sake of the kingdom of the heavens. He that is able to receive [it], let him receive [it].", "twenty": "Some men, it is true, have from birth been disabled for marriage, while others have been disabled by their fellow men, and others again have disabled themselves for the sake of the Kingdom of Heaven. Let him accept it who can.”", "acv": "For there are eunuchs who were born this way from their mother's belly, and there are eunuchs who were made eunuchs by men, and there are eunuchs who made themselves eunuchs because of the kingdom of the heavens. He who is able to receive it, let him receive it.", "anderson": "For there are eunuchs that were born such from their mother’s womb; and there are eunuchs that have been made eunuchs by men; and there are eunuchs that have made themselves eunuchs for the sake of the kingdom of heaven. Let him accept it that is able to accept it.", "haweis": "For there are eunuchs, who were so from their mothers’ womb; and there are eunuchs, who have been made eunuchs by men; and there are eunuchs, who have made themselves eunuchs for the kingdom of heaven. He that is capable of receiving, let him receive it.", "noyes": "For there are eunuchs, who were so born from their mother’s womb; and there are eunuchs, who were made eunuchs by men; and there are eunuchs, who made themselves eunuchs for the sake of the kingdom of heaven. He that is able to receive it, let him receive it.", "webster": "For there are some eunuchs, who were so born from [their] mothers womb: and there are some eunuchs, who were made eunuchs by men: and there are eunuchs, who have made themselves eunuchs for the kingdom of heaven's sake. He that is able to receive [it], let him receive [it].", "vulgate": "sunt enim eunuchi qui de matris utero sic nati sunt et sunt eunuchi qui facti sunt ab hominibus et sunt eunuchi qui se ipsos castraverunt propter regnum caelorum qui potest capere capiat;"}}, {"v": 13, "ref": "19:13", "o": "Τότε ⸀προσηνέχθησαν αὐτῷ παιδία ἵνα τὰς χεῖρας ἐπιθῇ αὐτοῖς καὶ προσεύξηται· οἱ δὲ μαθηταὶ ἐπετίμησαν αὐτοῖς.", "en": {"kjv": "Then were there brought unto him little children, that he should put his hands on them, and pray: and the disciples rebuked them.", "web": "Then little children were brought to him, that he should lay his hands on them and pray; and the disciples rebuked them.", "bsb": "Then the little children were brought to Jesus for Him to place His hands on them and pray for them. And the disciples rebuked those who brought them.", "asv": "Then were there brought unto him little children, that he should lay his hands on them, and pray: and the disciples rebuked them.", "ylt": "Then were brought near to him children that he might put hands on them and pray, and the disciples rebuked them.", "tyndale": "Then were brought to him yonge chyldre that he shuld put his hondes on them and praye And the disciples rebuked them.", "dra": "Then were little children presented to him, that he should impose hands upon them and pray. And the disciples rebuked them.", "bbe": "Then some people took little children to him, so that he might put his hands on them in blessing: and the disciples said sharp words to them.", "geneva": "Then were brought to him litle children, that he should put his hands on them, and pray: and the disciples rebuked them.", "wycliffe": "Thanne litle children weren brouyte to hym, that he schulde putte hondis to hem, and preie.", "rotherham": "Then, were brought unto him children,—that he might lay his hands upon them, and pray. And, the disciples, rebuked them.", "weymouth": "Then young children were brought to Him for Him to put His hands on them and pray; but the disciples interfered.", "darby": "Then there were brought to him little children that he might lay his hands on them and pray; but the disciples rebuked them.", "twenty": "Then some little children were brought to Jesus, for him to place his hands on them, and pray; but the disciples found fault with those who had brought them.", "acv": "Then children were brought to him, so that he would lay his hands on them and pray, but the disciples rebuked them.", "anderson": "Then little children were brought to him, that he might lay his hands on them and pray. And the disciples rebuked them.", "haweis": "Then were brought to him little children, that he should lay his hands upon them, and pray for them: but the disciples rebuked them.", "noyes": "Then there were brought to him children, that be might lay his hands on them, and pray; and the disciples rebuked them.", "webster": "Then were brought to him little children, that he should put [his] hands on them, and pray: and the disciples rebuked them.", "vulgate": "tunc oblati sunt ei parvuli ut manus eis inponeret et oraret discipuli autem increpabant eis;"}}, {"v": 14, "ref": "19:14", "o": "ὁ δὲ Ἰησοῦς εἶπεν· Ἄφετε τὰ παιδία καὶ μὴ κωλύετε αὐτὰ ἐλθεῖν πρός με, τῶν γὰρ τοιούτων ἐστὶν ἡ βασιλεία τῶν οὐρανῶν.", "en": {"kjv": "But Jesus said, Suffer little children, and forbid them not, to come unto me: for of such is the kingdom of heaven.", "web": "But Jesus said, “Allow the little children, and don’t forbid them to come to me; for the Kingdom of Heaven belongs to ones like these.”", "bsb": "But Jesus said, “Let the little children come to Me, and do not hinder them! For the kingdom of heaven belongs to such as these.”", "asv": "But Jesus said, Suffer the little children, and forbid them not, to come unto me: for to such belongeth the kingdom of heaven.", "ylt": "But Jesus said, `Suffer the children, and forbid them not, to come unto me, for of such is the reign of the heavens;'", "tyndale": "But Iesus sayde: suffre the chyldren and forbid them not to come to me: for of suche is the kyngdome of heven.", "dra": "But Jesus said to them: Suffer the little children, and forbid them not to come to me: for the kingdom of heaven is for such.", "bbe": "But Jesus said, Let the little ones come to me, and do not keep them away: for of such is the kingdom of heaven.", "geneva": "But Iesus sayd, Suffer the litle children, and forbid them not to come to me: for of such is the kingdome of heauen.", "wycliffe": "And the disciplis blamyden hem. But Jhesus seide to hem, Suffre ye that litle children come to me, and nyle ye forbede hem; for of siche is the kyngdom of heuenes.", "rotherham": "But, Jesus, said—Suffer the children—and do not hinder them—to come unto me,—for, of such, is the kingdom of the heavens.", "weymouth": "Jesus however said, \"Let the little children come to me, and do not hinder them; for it is to those who are childlike that the Kingdom of the Heavens belongs.\"", "darby": "But Jesus said, Suffer little children, and do not hinder them from coming to me; for the kingdom of the heavens is of such:", "twenty": "Jesus, however, said: “Let the little children come to me, and do not hinder them, for it is to the childlike that the Kingdom of Heaven belongs.”", "acv": "But Jesus said, Allow the children, and do not forbid them to come to me, for of such kind is the kingdom of the heavens.", "anderson": "But Jesus said: Let the little children come to me, and forbid them not: for of such is the kingdom of heaven.", "haweis": "Then said Jesus, Permit little children, and hinder them not from coming to me; for of such is the kingdom of heaven.", "noyes": "But Jesus said to them, Suffer the children, and forbid them not to come to me; for to such belongeth the kingdom of heaven.", "webster": "But Jesus said, Suffer little children, and forbid them not to come to me: for of such is the kingdom of heaven.", "vulgate": "Iesus vero ait eis sinite parvulos et nolite eos prohibere ad me venire talium est enim regnum caelorum;"}}, {"v": 15, "ref": "19:15", "o": "καὶ ἐπιθεὶς ⸂τὰς χεῖρας αὐτοῖς⸃ ἐπορεύθη ἐκεῖθεν.", "en": {"kjv": "And he laid his hands on them, and departed thence.", "web": "He laid his hands on them, and departed from there.", "bsb": "And after He had placed His hands on them, He went on from there.", "asv": "And he laid his hands on them, and departed thence.", "ylt": "and having laid on them his hands, he departed thence.", "tyndale": "And when he had put his hondes on them he departed thence.", "dra": "And when he had imposed hands upon them, he departed from thence.", "bbe": "And he put his hands on them, and went away.", "geneva": "And when he had put his hands on them, he departed thence.", "wycliffe": "And whanne he hadde put to hem hondis, he wente fro thennus.", "rotherham": "And, laying his hands upon them, he went his way from thence.", "weymouth": "So He laid His hands upon them and went away.", "darby": "and having laid his hands upon them, he departed thence.", "twenty": "So he placed his hands on them, and then went on his way.", "acv": "And having laid his hands on them, he departed from there.", "anderson": "And he laid his hands on them, and departed from that place.", "haweis": "And when he had laid his hands upon them, he departed thence.", "noyes": "And he laid his hands on them, and departed thence.", "webster": "And he laid [his] hands on them, and departed thence.", "vulgate": "et cum inposuisset eis manus abiit inde;"}}, {"v": 16, "ref": "19:16", "o": "Καὶ ἰδοὺ εἷς προσελθὼν ⸂αὐτῷ εἶπεν⸃· ⸀Διδάσκαλε, τί ἀγαθὸν ποιήσω ἵνα ⸀σχῶ ζωὴν αἰώνιον;", "en": {"kjv": "And, behold, one came and said unto him, Good Master, what good thing shall I do, that I may have eternal life?", "web": "Behold, one came to him and said, “Good teacher, what good thing shall I do, that I may have eternal life?”", "bsb": "Just then a man came up to Jesus and inquired, “Teacher, what good thing must I do to obtain eternal life?”", "asv": "And behold, one came to him and said, Teacher, what good thing shall I do, that I may have eternal life?", "ylt": "And lo, one having come near, said to him, `Good teacher, what good thing shall I do, that I may have life age-during?'", "tyndale": "And beholde one came and sayde vnto him: good master what good thinge shall I do that I maye have eternall lyfe?", "dra": "And behold one came and said to him: Good master, what good shall I do that I may have life everlasting?", "bbe": "And one came to him and said, Master, what good thing have I to do, so that I may have eternal life?", "geneva": "And beholde, one came and sayd vnto him, Good Master, what good thing shall I doe, that I may haue eternall life?", "wycliffe": "And lo! oon cam, and seide to hym, Good maister, what good schal Y do, that Y haue euerlastynge lijf?", "rotherham": "And lo! one coming near unto him, said, Teacher! what good thing shall I do, that I may have life age-abiding?", "weymouth": "\"Teacher,\" said one man, coming up to Him, \"what that is good shall I do in order to win the Life of the Ages?\"", "darby": "And lo, one coming up said to him, Teacher, what good thing shall I do that I may have life eternal?", "twenty": "And a man came up to Jesus, and said: “Teacher, what good thing must I do to obtain Immortal Life?”", "acv": "And behold one man having come to him, said, Good teacher, what good thing should I do so that I may have eternal life?", "anderson": "And behold, one came and said to him: Good teacher, what good thing must I do that I may have eternal life? He said to him:", "haweis": "And lo! a person coming to him, said, Good Master, what good thing shall I do, in order to attain eternal life?", "noyes": "And lo! one came to him and said, Teacher, what good thing shall I do, that I may have everlasting life?", "webster": "And behold, one came and said to him, Good Master, what good thing shall I do that I may have eternal life?", "vulgate": "et ecce unus accedens ait illi magister bone quid boni faciam ut habeam vitam aeternam;"}}, {"v": 17, "ref": "19:17", "o": "ὁ δὲ εἶπεν αὐτῷ· Τί με ⸂ἐρωτᾷς περὶ τοῦ ἀγαθοῦ; εἷς ἐστιν ὁ ἀγαθός⸃· εἰ δὲ θέλεις ⸂εἰς τὴν ζωὴν εἰσελθεῖν⸃, ⸀τήρησον τὰς ἐντολάς.", "en": {"kjv": "And he said unto him, Why callest thou me good? there is none good but one, that is, God: but if thou wilt enter into life, keep the commandments.", "web": "He said to him, “Why do you call me good?No one is good but one, that is, God. But if you want to enter into life, keep the commandments.”", "bsb": "“Why do you ask Me about what is good?” Jesus replied. “There is only One who is good. If you want to enter life, keep the commandments.”", "asv": "And he said unto him, Why askest thou me concerning that which is good? One there is who is good: but if thou wouldest enter into life, keep the commandments.", "ylt": "And he said to him, `Why me dost thou call good? no one is good except One--God; but if thou dost will to enter into the life, keep the commands.'", "tyndale": "He sayde vnto him: why callest thou me good? there is none good but one and that is God. But yf thou wylt entre in to lyfe kepe the commaundementes.", "dra": "Who said to him: Why askest thou me concerning good? One is good, God. But if thou wilt enter into life, keep the commandments.", "bbe": "And he said to him, Why are you questioning me about what is good? One there is who is good: but if you have a desire to go into life, keep the rules of the law.", "geneva": "And he said vnto him, Why callest thou me good? there is none good but one, eue God: but if thou wilt enter into life, keepe ye commandemets.", "wycliffe": "Which seith to hym, What axist thou me of good thing? There is o good God. But if thou wolt entre to lijf, kepe the comaundementis.", "rotherham": "And, he, said unto him—Why dost thou question me concerning that which is good? There is, One, that is good! But, if thou desirest, into life, to enter, be keeping the commandments.", "weymouth": "\"Why do you ask me,\" He replied, \"about what is good? There is only One who is truly good. But if you desire to enter into Life, keep the Commandments.\"", "darby": "And he said to him, What askest thou me concerning goodness? one is good. But if thou wouldest enter into life, keep the commandments.", "twenty": "“Why ask me about goodness?” answered Jesus. “There is but One who is good. If you want to enter the Life, keep the commandments.”", "acv": "And he said to him, Why do thou call me good? There is none good except one, God. But if thou want to enter into life, keep the commandments.", "anderson": "Why do you call me good? There is none good but one, that is God. But if you desire to enter into life, keep the commandments.", "haweis": "Then he said to him, Why callest thou me good? there is none good but one, even God: but if thou art desirous of entering into life, keep the commandments.", "noyes": "And he said to him, Why dost thou ask me concerning what is good? There is but one who is good. But if thou wilt enter into life, keep the commandments.", "webster": "And he said to him, Why callest thou me good? [there is] none good but one, [that is], God: but if thou wilt enter into life, keep the commandments.", "vulgate": "qui dixit ei quid me interrogas de bono unus est bonus Deus si autem vis ad vitam ingredi serva mandata;"}}, {"v": 18, "ref": "19:18", "o": "λέγει αὐτῷ· Ποίας; ὁ δὲ Ἰησοῦς ⸀εἶπεν· Τὸ Οὐ φονεύσεις, Οὐ μοιχεύσεις, Οὐ κλέψεις, Οὐ ψευδομαρτυρήσεις,", "en": {"kjv": "He saith unto him, Which? Jesus said, Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,", "web": "He said to him, “Which ones?” Jesus said, “‘You shall not murder.’ ‘You shall not commit adultery.’ ‘You shall not steal.’ ‘You shall not offer false testimony.’", "bsb": "“Which ones?” the man asked. Jesus answered, “‘Do not murder, do not commit adultery, do not steal, do not bear false witness,", "asv": "He saith unto him, Which? And Jesus said, Thou shalt not kill, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,", "ylt": "He saith to him, `What kind?' And Jesus said, `Thou shalt not kill, thou shalt not commit adultery, thou shalt not steal, thou shalt not bear false witness,", "tyndale": "The other sayde to him Which? And Iesus sayde: breake no wedloke kill not steale not: beare not falce witnes:", "dra": "He said to him: Which? And Jesus said: Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness.", "bbe": "He says to him, Which? And Jesus said, Do not put anyone to death, Do not be untrue in married life, Do not take what is not yours, Do not give false witness,", "geneva": "He sayd to him, Which? And Iesus sayde, These, Thou shalt not kill: Thou shalt not commit adulterie: Thou shalt not steale: Thou shalt not beare false witnesse.", "wycliffe": "He seith to hym, Whiche? And Jhesus seide, Thou schalt not do mansleying, thou schalt not do auowtrie, thou schalt not do thefte, thou schalt not seie fals witnessying;", "rotherham": "He saith unto him, Which? Jesus, said—These: Thou shalt not commit murder, Thou shalt not commit adultery, Thou shalt not steal,—Thou shalt not bear false witness;", "weymouth": "\"Which Commandments?\" he asked. Jesus answered, \"`Thou shalt not kill;' `Thou shalt not commit adultery;' `Thou shalt not steal;' `Thou shalt not lie in giving evidence;'", "darby": "He says to him, Which? And Jesus said, Thou shalt not kill, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,", "twenty": "“What commandments?” asked the man. “These,” answered Jesus: — “‘Thou shalt not kill. Thou shalt not commit adultery. Thou shalt not steal. Thou shalt not say what is false about others.", "acv": "He says to him, Which? And Jesus said, Thou shall not murder. Thou shall not commit adultery. Thou shall not steal. Thou shall not testify falsely.", "anderson": "He said to him: Which? Jesus replied: You shall not kill; You shall not commit adultery; You shall not steal; You shall not give false testimony;", "haweis": "He saith unto him, Which? Then said Jesus, these, Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,", "noyes": "Which? saith he. And Jesus said, These: \"Thou shalt not kill; Thou shalt not commit adultery; Thou shalt not steal; Thou shalt not bear false witness;", "webster": "He saith to him, Which? Jesus said, Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,", "vulgate": "dicit illi quae Iesus autem dixit non homicidium facies non adulterabis non facies furtum non falsum testimonium dices;"}}, {"v": 19, "ref": "19:19", "o": "Τίμα τὸν πατέρα καὶ τὴν μητέρα, καὶ Ἀγαπήσεις τὸν πλησίον σου ὡς σεαυτόν.", "en": {"kjv": "Honour thy father and thy mother: and, Thou shalt love thy neighbour as thyself.", "web": "‘Honor your father and mother.’And, ‘You shall love your neighbor as yourself.’”", "bsb": "honor your father and mother, and love your neighbor as yourself.’”", "asv": "Honor thy father and thy mother; and, Thou shalt love thy neighbor as thyself.", "ylt": "honour thy father and mother, and, thou shalt love thy neighbour as thyself.'", "tyndale": "honoure father and mother: and love thyne neighbour as thy sylfe.", "dra": "Honour thy father and thy mother: and, Thou shalt love thy neighbor as thyself.", "bbe": "Give honour to your father and your mother: and, Have love for your neighbour as for yourself.", "geneva": "Honour thy father and mother: and thou shalt loue thy neighbour as thy selfe.", "wycliffe": "worschipe thi fadir and thi modir, and, thou schalt loue thi neiybore as thi silf.", "rotherham": "Honour thy father and thy mother,—and—Thou shalt love thy neighbour as, thyself.", "weymouth": "`Honour thy father and thy mother'; and `Thou shalt love thy fellow man as much as thyself.'\"", "darby": "Honour thy father and thy mother, and Thou shalt love thy neighbour as thyself.", "twenty": "Honour thy father and thy mother.’ And ‘Thou shalt love thy neighbour as thou dost thyself.”", "acv": "Honor the father and mother, and, Thou shall love thy neighbor as thyself.", "anderson": "Honor your father and your mother; and, You shall love your neighbor as yourself.", "haweis": "Honour thy father and thy mother; and, Thou shalt love thy neighbour as thyself.", "noyes": "Honor thy father and thy mother;\" and, \"Thou shalt love thy neighbor as thyself.\"", "webster": "Honor thy father and [thy] mother: and, Thou shalt love thy neighbor as thyself.", "vulgate": "honora patrem et matrem et diliges proximum tuum sicut te ipsum;"}}, {"v": 20, "ref": "19:20", "o": "λέγει αὐτῷ ὁ νεανίσκος· ⸂Πάντα ταῦτα⸃ ⸀ἐφύλαξα· τί ἔτι ὑστερῶ;", "en": {"kjv": "The young man saith unto him, All these things have I kept from my youth up: what lack I yet?", "web": "The young man said to him, “All these things I have observed from my youth. What do I still lack?”", "bsb": "“All these I have kept,” said the young man. “What do I still lack?”", "asv": "The young man saith unto him, All these things have I observed: what lack I yet?", "ylt": "The young man saith to him, `All these did I keep from my youth; what yet do I lack?'", "tyndale": "And the younge man sayde vnto him: I have observed all these thingis from my youth what lacke I yet?", "dra": "The young man saith to him: All these have I kept from my youth, what is yet wanting to me?", "bbe": "The young man says to him, All these things have I done: what more is there?", "geneva": "The yong man sayd vnto him, I haue obserued all these things from my youth: what lacke I yet?", "wycliffe": "The yonge man seith to hym, Y haue kept alle these thingis fro my youthe, what yit failith to me?", "rotherham": "The young man saith unto him—These all, have I kept,—What, further, do I lack?", "weymouth": "\"All of these,\" said the young man, \"I have carefully kept. What do I still lack?\"", "darby": "The young man says to him, All these have I kept; what lack I yet?", "twenty": "“I have observed all these,” said the young man. “What is still wanting in me?”", "acv": "The young man says to him, All these things I have kept from my youthfulness. What do I lack yet?", "anderson": "The young man said to him: All these have I kept from my youth, what do I lack?", "haweis": "The young man saith to him, All these things have I observed from my youth: in what am I still deficient?", "noyes": "The young man saith to him, All these things have I kept; in what am I still wanting?", "webster": "The young man saith to him, All these things have I kept from my youth: what lack I yet?", "vulgate": "dicit illi adulescens omnia haec custodivi quid adhuc mihi deest;"}}, {"v": 21, "ref": "19:21", "o": "ἔφη αὐτῷ ὁ Ἰησοῦς· Εἰ θέλεις τέλειος εἶναι, ὕπαγε πώλησόν σου τὰ ὑπάρχοντα καὶ ⸀δὸς πτωχοῖς, καὶ ἕξεις θησαυρὸν ἐν ⸀οὐρανοῖς, καὶ δεῦρο ἀκολούθει μοι.", "en": {"kjv": "Jesus said unto him, If thou wilt be perfect, go and sell that thou hast, and give to the poor, and thou shalt have treasure in heaven: and come and follow me.", "web": "Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”", "bsb": "Jesus told him, “If you want to be perfect, go, sell your possessions and give to the poor, and you will have treasure in heaven. Then come, follow Me.”", "asv": "Jesus said unto him, If thou wouldest be perfect, go, sell that which thou hast, and give to the poor, and thou shalt have treasure in heaven: and come, follow me.", "ylt": "Jesus said to him, `If thou dost will to be perfect, go away, sell what thou hast, and give to the poor, and thou shalt have treasure in heaven, and come, follow me.'", "tyndale": "And Iesus sayde vnto him yf thou wylt be perfecte goo and sell that thou hast and geve it to the povre and thou shalt have treasure in heven and come and folowe me.", "dra": "Jesus saith to him: If thou wilt be perfect, go sell what thou hast, and give to the poor, and thou shalt have treasure in heaven: and come, follow me.", "bbe": "Jesus said to him, If you have a desire to be complete, go, get money for your property, and give it to the poor, and you will have wealth in heaven: and come after me.", "geneva": "Iesus sayd vnto him, If thou wilt be perfite, go, sell that thou hast, and giue it to the poore, and thou shalt haue treasure in heauen, and come, and follow me.", "wycliffe": "Jhesus seith to hym, If thou wolt be perfite, go, and sille alle thingis that thou hast, and yyue to pore men, and thou schalt haue tresoure in heuene; and come, and sue me.", "rotherham": "Jesus said unto him—If thou desirest to be perfect, Withdraw! sell thy substance, and give to the destitute,—and thou shalt have treasure in the heavens; and come! be following me.", "weymouth": "\"If you desire to be perfect,\" replied Jesus, \"go and sell all that you have, and give to the poor, and you shall have wealth in Heaven; and come, follow me.\"", "darby": "Jesus said to him, If thou wouldest be perfect, go, sell what thou hast and give to [the] poor, and thou shalt have treasure in heaven; and come, follow me.", "twenty": "“If you wish to be perfect,” answered Jesus, “go and sell your property, and give to the poor, and you shall have wealth in Heaven; then come and follow me.”", "acv": "Jesus said to him, If thou want to be perfect, go, sell the things being possessed by thee, and give to the poor, and thou will have treasure in heaven. And come, follow me.", "anderson": "Jesus said to him: If you would be perfect, go, sell your possessions, and give to the poor, and you shall have treasure in heaven; and come, follow me.", "haweis": "Jesus said to him, If thou art desirous to be perfect, go, sell all thy substance, and give to the poor, and thou shalt have treasure in heaven; and come, follow me.", "noyes": "Jesus said to him, If thou wilt be perfect, go, sell what thou hast, and give to the poor, and thou shalt have treasure in heaven; and come, follow me.", "webster": "Jesus said to him, If thou wilt be perfect, go [and] sell what thou hast, and give to the poor, and thou shalt have treasure in heaven: and come [and] follow me.", "vulgate": "ait illi Iesus si vis perfectus esse vade vende quae habes et da pauperibus et habebis thesaurum in caelo et veni sequere me;"}}, {"v": 22, "ref": "19:22", "o": "ἀκούσας δὲ ὁ νεανίσκος τὸν ⸀λόγον ἀπῆλθεν λυπούμενος, ἦν γὰρ ἔχων κτήματα πολλά.", "en": {"kjv": "But when the young man heard that saying, he went away sorrowful: for he had great possessions.", "web": "But when the young man heard the saying, he went away sad, for he was one who had great possessions.", "bsb": "When the young man heard this, he went away in sorrow, because he had great wealth.", "asv": "But when the young man heard the saying, he went away sorrowful; for he was one that had great possessions.", "ylt": "And the young man, having heard the word, went away sorrowful, for he had many possessions;", "tyndale": "When ye younge ma hearde yt sayinge he wet awaye mourninge. For he had greate possessions.", "dra": "And when the young man had heard this word, he went away sad: for he had great possessions.", "bbe": "But hearing these words the young man went away sorrowing: for he had much property.", "geneva": "And when the yong man heard that saying, he went away sorowfull: for he had great possessions.", "wycliffe": "And whanne the yong man hadde herd these wordis, he wente awei sorewful, for he hadde many possessiouns.", "rotherham": "And the young man, hearing, this word, went away sorrowing,—for he was holding large possessions.", "weymouth": "On hearing those words the young man went away much cast down; for he had much property.", "darby": "But the young man, having heard the word, went away grieved, for he had large possessions.", "twenty": "On hearing these words, the young man went away distressed, for he had great possessions.", "acv": "But when the young man heard the saying, he went away sorrowing, for he was having many possessions.", "anderson": "When the young man heard that saying, he went away grieved; for he had great possessions.", "haweis": "Now when the young man heard this speech, he went away sorrowful: for he had great possessions.", "noyes": "But the young man, on hearing this went away sorrowful; for he had great possessions.", "webster": "But when the young man heard that saying, he went away sorrowful: for he had great possessions.", "vulgate": "cum audisset autem adulescens verbum abiit tristis erat enim habens multas possessiones;"}}, {"v": 23, "ref": "19:23", "o": "Ὁ δὲ Ἰησοῦς εἶπεν τοῖς μαθηταῖς αὐτοῦ· Ἀμὴν λέγω ὑμῖν ὅτι ⸂πλούσιος δυσκόλως⸃ εἰσελεύσεται εἰς τὴν βασιλείαν τῶν οὐρανῶν·", "en": {"kjv": "Then said Jesus unto his disciples, Verily I say unto you, That a rich man shall hardly enter into the kingdom of heaven.", "web": "Jesus said to his disciples, “Most certainly I say to you, a rich man will enter into the Kingdom of Heaven with difficulty.", "bsb": "Then Jesus said to His disciples, “Truly I tell you, it is hard for a rich man to enter the kingdom of heaven.", "asv": "And Jesus said unto his disciples, Verily I say unto you, It is hard for a rich man to enter into the kingdom of heaven.", "ylt": "and Jesus said to his disciples, `Verily I say to you, that hardly shall a rich man enter into the reign of the heavens;", "tyndale": "Then Iesus sayde vnto his disciples: Verely I saye vnto you: yt is harde for a ryche ma to enter into ye kyngdome of heaven.", "dra": "Then Jesus said to his disciples: Amen, I say to you, that a rich man shall hardly enter into the kingdom of heaven.", "bbe": "And Jesus said to his disciples, Truly I say to you, It is hard for a man with much money to go into the kingdom of heaven.", "geneva": "Then Iesus sayd vnto his disciples, Verely I say vnto you, that a rich man shall hardly enter into the kingdome of heauen.", "wycliffe": "And Jhesus seide to hise disciplis, Y seie to you treuthe, for a riche man of hard schal entre in to the kyngdom of heuenes.", "rotherham": "And, Jesus, said unto his disciples—Verily, I say unto you, A rich man, with difficulty, shall enter into the kingdom of the heavens.", "weymouth": "So Jesus said to His disciples, \"I solemnly tell you that it is with difficulty that a rich man will enter the Kingdom of the Heavens.", "darby": "And Jesus said to his disciples, Verily I say unto you, A rich man shall with difficulty enter into the kingdom of the heavens;", "twenty": "At this, Jesus said to his disciples: “I tell you that a rich man will find it hard to enter the Kingdom of Heaven!", "acv": "And Jesus said to his disciples, Truly I say to you, that a rich man will enter into the kingdom of the heavens difficultly.", "anderson": "Jesus said to his disciples: Verily I say to you, A rich man will with difficulty enter into the kingdom of heaven.", "haweis": "Then Jesus said to his disciples, Verily I say unto you, That very difficultly shall a rich man enter into the kingdom of heaven.", "noyes": "Then Jesus said to his disciples, Truly do I say to you, it will be hard for a rich man to enter the kingdom of heaven.", "webster": "Then said Jesus to his disciples, Verily I say to you, that a rich man shall with difficulty enter into the kingdom of heaven.", "vulgate": "Iesus autem dixit discipulis suis amen dico vobis quia dives difficile intrabit in regnum caelorum;"}}, {"v": 24, "ref": "19:24", "o": "πάλιν δὲ λέγω ὑμῖν, εὐκοπώτερόν ἐστιν κάμηλον διὰ ⸀τρυπήματος ῥαφίδος ⸀εἰσελθεῖν ἢ πλούσιον ⸂εἰς τὴν βασιλείαν τοῦ θεοῦ⸃.", "en": {"kjv": "And again I say unto you, It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God.", "web": "Again I tell you, it is easier for a camel to go through a needle’s eye, than for a rich man to enter into the Kingdom of God.”", "bsb": "Again I tell you, it is easier for a camel to pass through the eye of a needle than for a rich man to enter the kingdom of God.”", "asv": "And again I say unto you, It is easier for a camel to go through a needle’s eye, than for a rich man to enter into the kingdom of God.", "ylt": "and again I say to you, it is easier for a camel through the eye of a needle to go, than for a rich man to enter into the reign of God.'", "tyndale": "And moreover I saye vnto you: it is easier for a camell to go through the eye of a nedle then for a ryche man to enter into the kyngdome of God.", "dra": "And again I say to you: It is easier for a camel to pass through the eye of a needle, than for a rich man to enter into the kingdom of heaven.", "bbe": "And again I say to you, It is simpler for a camel to go through a needle's eye, than for a man with much money to go into the kingdom of God.", "geneva": "And againe I say vnto you, It is easier for a camel to go through the eye of a needle, then for a rich man to enter into ye kingdome of God.", "wycliffe": "And eftsoone Y seie to you, it is liyter a camel to passe thorou a needlis iye, thanne a riche man to entre in to the kyngdom of heuens.", "rotherham": "Again I say unto you—Easier, is it for, a camel, through the eye of a needle, to enter, than a rich man—into the kingdom of God.", "weymouth": "Yes, I tell you, it is easier for a camel to go through the eye of a needle than for a rich man to enter the Kingdom of God.\"", "darby": "and again I say unto you, It is easier for a camel to enter a needle's eye than a rich man into the kingdom ofGod.", "twenty": "I say again, it is easier for a camel to get through a needle’s eye than for a rich man to enter the Kingdom of Heaven!”", "acv": "And again I say to you, it is easier for a camel to pass through the hole of a needle, than for a rich man to enter into the kingdom of God.", "anderson": "And again I say to you: It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God.", "haweis": "And again I repeat it to you, It is easier for a camel to pass through the eye of a needle, than for a rich man to enter into the kingdom of God.", "noyes": "And again I say to you, It is easier for a camel to go through the eye of a needle, than for a rich man to enter the kingdom of heaven.", "webster": "And again I say to you, It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God.", "vulgate": "et iterum dico vobis facilius est camelum per foramen acus transire quam divitem intrare in regnum caelorum;"}}, {"v": 25, "ref": "19:25", "o": "ἀκούσαντες δὲ οἱ ⸀μαθηταὶ ἐξεπλήσσοντο σφόδρα λέγοντες· Τίς ἄρα δύναται σωθῆναι;", "en": {"kjv": "When his disciples heard it, they were exceedingly amazed, saying, Who then can be saved?", "web": "When the disciples heard it, they were exceedingly astonished, saying, “Who then can be saved?”", "bsb": "When the disciples heard this, they were greatly astonished and asked, “Who then can be saved?”", "asv": "And when the disciples heard it, they were astonished exceedingly, saying, Who then can be saved?", "ylt": "And his disciples having heard, were amazed exceedingly, saying, `Who, then, is able to be saved?'", "tyndale": "When his disciples hearde that they were excedingly amased sayinge: who then can be saved?", "dra": "And when they had heard this, the disciples wondered much, saying: Who then can be saved?", "bbe": "And the disciples, hearing this, were greatly surprised, saying, Who then may have salvation?", "geneva": "And whe his disciples heard it, they were exceedingly amased, saying, Who then can be saued?", "wycliffe": "Whanne these thingis weren herd, the disciplis wondriden greetli, and seiden, Who thanne may be saaf?", "rotherham": "And, hearing it, the disciples were being struck with the greatest astonishment, saying—Who then can be saved?", "weymouth": "These words utterly amazed the disciples, and they asked, \"Who then can be saved?\"", "darby": "And when the disciples heard [it] they were exceedingly astonished, saying, Who then can be saved?", "twenty": "On hearing this, the disciples exclaimed in great astonishment: “Who then can possibly be saved?”", "acv": "And when his disciples heard it, they were exceedingly amazed, saying, Who then can be saved?", "anderson": "When the disciples heard it, they were greatly amazed, and said: Who, then, can be saved?", "haweis": "But when his disciples heard it, they were exceedingly amazed, saying, Who then can be saved?", "noyes": "And the disciples, hearing this, were exceedingly amazed, saying, Who then can be saved?", "webster": "When his disciples heard [it], they were exceedingly amazed, saying, Who then can be saved?", "vulgate": "auditis autem his discipuli mirabantur valde dicentes quis ergo poterit salvus esse;"}}, {"v": 26, "ref": "19:26", "o": "ἐμβλέψας δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Παρὰ ἀνθρώποις τοῦτο ἀδύνατόν ἐστιν, παρὰ δὲ θεῷ πάντα δυνατά.", "en": {"kjv": "But Jesus beheld them, and said unto them, With men this is impossible; but with God all things are possible.", "web": "Looking at them, Jesus said, “With men this is impossible, but with God all things are possible.”", "bsb": "Jesus looked at them and said, “With man this is impossible, but with God all things are possible.”", "asv": "And Jesus looking upon them said to them, With men this is impossible; but with God all things are possible.", "ylt": "And Jesus having earnestly beheld, said to them, `With men this is impossible, but with God all things are possible.'", "tyndale": "Iesus behelde the and sayde vnto them: with men this is vnpossible but with God all thinges are possible.", "dra": "And Jesus beholding, said to them: With men this is impossible: but with God all things are possible.", "bbe": "And Jesus, looking at them, said, With men this is not possible; but with God all things are possible.", "geneva": "And Iesus behelde them, and sayde vnto them, With men this is vnpossible, but with God all things are possible.", "wycliffe": "Jhesus bihelde, and seide to hem, Anentis men this thing is impossible; but anentis God alle thingis ben possible.", "rotherham": "And, looking intently, Jesus said unto them—With men, this is, impossible, but, with God, all things are possible.", "weymouth": "Jesus looked at them and said, \"With men this is impossible, but with God everything is possible.\"", "darby": "But Jesus, looking on [them], said to them, With men this is impossible; but withGod all things are possible.", "twenty": "But Jesus looked at them, and said: “With men this is impossible, but with God everything is possible.” Then Peter turned and said to Jesus:", "acv": "And having looked, Jesus said to them, With men this is impossible, but with God all things are possible.", "anderson": "But Jesus looked on them, and said to them: With men, this is impossible; but with God, all things are possible.", "haweis": "And Jesus looking upon them, said unto them, With men this is impossible; but with God all things are possible.", "noyes": "But Jesus, fixing his eyes on them, said, With men this is impossible; but with God all things are possible.", "webster": "But Jesus beheld [them], and said to them, With men this is impossible, but with God all things are possible.", "vulgate": "aspiciens autem Iesus dixit illis apud homines hoc inpossibile est apud Deum autem omnia possibilia sunt;"}}, {"v": 27, "ref": "19:27", "o": "Τότε ἀποκριθεὶς ὁ Πέτρος εἶπεν αὐτῷ· Ἰδοὺ ἡμεῖς ἀφήκαμεν πάντα καὶ ἠκολουθήσαμέν σοι· τί ἄρα ἔσται ἡμῖν;", "en": {"kjv": "Then answered Peter and said unto him, Behold, we have forsaken all, and followed thee; what shall we have therefore?", "web": "Then Peter answered, “Behold, we have left everything, and followed you. What then will we have?”", "bsb": "“Look,” Peter replied, “we have left everything to follow You. What then will there be for us?”", "asv": "Then answered Peter and said unto him, Lo, we have left all, and followed thee; what then shall we have?", "ylt": "Then Peter answering said to him, `Lo, we did leave all, and follow thee, what then shall we have?'", "tyndale": "Then answered Peter and sayde to him: Beholde we have forsaken all and folowed the what shall we have?", "dra": "Then Peter answering, said to him: Behold we have left all things, and have followed thee: what therefore shall we have?", "bbe": "Then Peter said to him, See, we have given up everything and have come after you; what then will we have?", "geneva": "Then answered Peter, and said to him, Beholde, we haue forsaken all, and followed thee: what therefore shall we haue?", "wycliffe": "Thanne Petre answeride, and seide to hym, Lo! we han forsake alle thingis, and we han suede thee; what thanne schal be to vs?", "rotherham": "Then, making answer, Peter said unto him—Lo! we, have left all, and followed thee,—What then shall there be, for us?", "weymouth": "Then Peter said to Jesus, \"See, *we* have forsaken everything and followed you; what then will be *our* reward?\"", "darby": "Then Peter answering said to him, Behold, we have left all things and have followed thee; what then shall happen to us?", "twenty": "“But we — we left everything, and followed you; what, then, shall we have?”", "acv": "Then having answered, Peter said to him, Lo, we have forsaken all, and followed thee. What then will be for us?", "anderson": "Then Peter answered and said to him: Behold, we have left all and followed thee; what, then, shall we have?", "haweis": "Then Peter addressing him, said unto him, Lo! we have left all and followed thee; what, I pray thee, shall we receive?", "noyes": "Then Peter answering said to him, Lo! we left all, and followed thee; what then shall we have?", "webster": "Then answered Peter, and said to him, Behold, we have forsaken all, and followed thee? what shall we have therefore?", "vulgate": "tunc respondens Petrus dixit ei ecce nos reliquimus omnia et secuti sumus te quid ergo erit nobis;"}}, {"v": 28, "ref": "19:28", "o": "ὁ δὲ Ἰησοῦς εἶπεν αὐτοῖς· Ἀμὴν λέγω ὑμῖν ὅτι ὑμεῖς οἱ ἀκολουθήσαντές μοι ἐν τῇ παλιγγενεσίᾳ, ὅταν καθίσῃ ὁ υἱὸς τοῦ ἀνθρώπου ἐπὶ θρόνου δόξης αὐτοῦ, ⸀καθήσεσθε καὶ ⸀ὑμεῖς ἐπὶ δώδεκα θρόνους κρίνοντες τὰς δώδεκα φυλὰς τοῦ Ἰσραήλ.", "en": {"kjv": "And Jesus said unto them, Verily I say unto you, That ye which have followed me, in the regeneration when the Son of man shall sit in the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.", "web": "Jesus said to them, “Most certainly I tell you that you who have followed me, in the regeneration when the Son of Man will sit on the throne of his glory, you also will sit on twelve thrones, judging the twelve tribes of Israel.", "bsb": "Jesus said to them, “Truly I tell you, in the renewal of all things, when the Son of Man sits on His glorious throne, you who have followed Me will also sit on twelve thrones, judging the twelve tribes of Israel.", "asv": "And Jesus said unto them, Verily I say unto you, that ye who have followed me, in the regeneration when the Son of man shall sit on the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.", "ylt": "And Jesus said to them, `Verily I say to you, that ye who did follow me, in the regeneration, when the Son of Man may sit upon a throne of his glory, shall sit--ye also--upon twelve thrones, judging the twelve tribes of Israel;", "tyndale": "Iesus sayde vnto them: verely I saye to you: when the sonne of man shall syt in ye seate of his maieste ye which folowe me in ye seconde generacion shall syt also vpon .xii. seates and iudge ye .xii. tribes of Israel.", "dra": "And Jesus said to them: Amen I say to you, that you who have followed me, in the regeneration, when the Son of man shall sit on the seat of his majesty, you also shall sit on twelve seats judging the twelve tribes of Israel.", "bbe": "And Jesus said to them, Truly I say to you that in the time when all things are made new, and the Son of man is seated in his glory, you who have come after me will be seated on twelve seats, judging the twelve tribes of Israel.", "geneva": "And Iesus said vnto them, Verely I say to you, that when the Sonne of man shall sit in the throne of his maiestie, ye which folowed me in the regeneration, shall sit also vpon twelue thrones and iudge the twelue tribes of Israel.", "wycliffe": "Jhesus seide to hem, Truli I seie to you, that ye that han forsake alle thingis, and han sued me, in the regeneracioun whanne mannus sone schal sitte in the sete of his maieste, ye schulen sitte on twelue setis, demynge the twelue kynredis of Israel.", "rotherham": "And, Jesus, said unto them—Verily, I say unto you, As for you who followed me in the regeneration, When the Son of Man shall take his seat on his throne of glory, ye also, shall be seated upon twelve thrones, judging the twelve tribes of Israel.", "weymouth": "\"I solemnly tell you,\" replied Jesus, \"that in the New Creation, when the Son of Man has taken His seat on His glorious throne, all of you who have followed me shall also sit on twelve thrones and judge the twelve tribes of Israel.", "darby": "And Jesus said to them, Verily I say unto you, That ye who have followed me, in the regeneration when the Son of man shall sit down upon his throne of glory, ye also shall sit on twelve thrones, judging the twelve tribes of Israel.", "twenty": "“I tell you,” answered Jesus, “that at the New Creation, ‘when the Son of Man takes his seat on his throne of glory,’ you who followed me shall be seated upon twelve thrones, as judges of the twelve tribes of Israel.", "acv": "And Jesus said to them, Truly I say to you, that ye who have followed me, in the regeneration when the Son of man will sit on the throne of his glory, ye also will sit upon twelve thrones, judging the twelve tribes of Israel.", "anderson": "Jesus said to them: Verily I say to you, That, in the restoration, when the Son of man shall sit on his glorious throne, you also who have followed me shall sit on twelve thrones, judging the twelve tribes of Israel.", "haweis": "Then said Jesus unto them, Verily I say unto you, That ye who have followed me in the regeneration, when the Son of man shall sit on the throne of his glory, ye also shall sit on twelve thrones, judging the twelve tribes of Israel.", "noyes": "And Jesus said to them, Truly do I say to you, that, in the renovation when the Son of man sitteth on the throne of his glory, ye who have followed me shall also yourselves sit on twelve thrones, judging the twelve tribes of Israel.", "webster": "And Jesus said to them, Verily I say to you, that ye who have followed me in the regeneration, when the Son of man shall sit on the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.", "vulgate": "Iesus autem dixit illis amen dico vobis quod vos qui secuti estis me in regeneratione cum sederit Filius hominis in sede maiestatis suae sedebitis et vos super sedes duodecim iudicantes duodecim tribus Israhel;"}}, {"v": 29, "ref": "19:29", "o": "καὶ πᾶς ⸀ὅστις ἀφῆκεν ⸂οἰκίας ἢ⸃ ἀδελφοὺς ἢ ἀδελφὰς ἢ πατέρα ἢ μητέρα ἢ ⸂γυναῖκα ἢ⸃ τέκνα ἢ ⸀ἀγροὺς ἕνεκεν τοῦ ⸂ὀνόματός μου⸃, ⸀ἑκατονταπλασίονα λήμψεται καὶ ζωὴν αἰώνιον κληρονομήσει.", "en": {"kjv": "And every one that hath forsaken houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, shall receive an hundredfold, and shall inherit everlasting life.", "web": "Everyone who has left houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, will receive one hundred times, and will inherit eternal life.", "bsb": "And everyone who has left houses or brothers or sisters or father or mother or wife or children or fields for the sake of My name will receive a hundredfold and will inherit eternal life.", "asv": "And every one that hath left houses, or brethren, or sisters, or father, or mother, or children, or lands, for my name’s sake, shall receive a hundredfold, and shall inherit eternal life.", "ylt": "and every one who left houses, or brothers, or sisters, or father, or mother, or wife, or children, or fields, for my name's sake, an hundredfold shall receive, and life age-during shall inherit;", "tyndale": "And whosoever forsaketh housses or brethren or systers other father or mother or wyfe or chyldren or landes for my names sake ye same shall receave an hundred folde and shall inheret everlastynge lyfe.", "dra": "And every one that hath left house, or brethren, or sisters, or father, or mother, or wife, or children, or lands for my name's sake, shall receive an hundredfold, and shall possess life everlasting.", "bbe": "And everyone who has given up houses, or brothers, or sisters, or father, or mother, or child, or land, for my name, will be given a hundred times as much, and have eternal life.", "geneva": "And whosoeuer shall forsake houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my Names sake, he shall receiue an hundreth folde more, and shall inherite euerlasting life.", "wycliffe": "And euery man that forsakith hous, britheren or sistren, fadir or modir, wijf ethir children, or feeldis, for my name, he schal take an hundrid foold, and schal welde euerlastynge lijf.", "rotherham": "And, whosoever left houses, or brethren, or sisters, or father, or mother, or children, or lands, for sake of my name, manifold, shall receive, and life, age-abiding, shall inherit.", "weymouth": "And whoever has forsaken houses, or brothers or sisters, or father or mother, or children or lands, for my sake, shall receive many times as much and shall have as his inheritance the Life of the Ages.", "darby": "And every one who has left houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my name's sake, shall receive a hundredfold, and shall inherit life eternal.", "twenty": "Every one who has left houses, or brothers, or sisters, or father, or mother, or children, or land, on account of my Name, will receive many times as much, and will ‘gain Immortal Life.’", "acv": "And every man who has forsaken houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, because of my name, will receive a hundredfold, and will inherit eternal life.", "anderson": "And every one that has left houses, or brothers, or sisters, or father, or mother, or wife, or children, or lands, for my name’s sake, shall receive a hundred-fold, and shall inherit eternal life. But many that are first shall be last; and the last first.", "haweis": "And every one who hath left family, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my name sake, shall receive an hundred fold, and shall inherit life eternal.", "noyes": "And every one who hath left brothers, or sisters, or father, or mother, or children, or lands, or houses, for the sake of my name, will receive many fold more, and will inherit everlasting life.", "webster": "And every one that hath forsaken houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands for my name's sake, shall receive a hundred-fold, and shall inherit everlasting life.", "vulgate": "et omnis qui reliquit domum vel fratres aut sorores aut patrem aut matrem aut uxorem aut filios aut agros propter nomen meum centuplum accipiet et vitam aeternam possidebit;"}}, {"v": 30, "ref": "19:30", "o": "πολλοὶ δὲ ἔσονται πρῶτοι ἔσχατοι καὶ ἔσχατοι πρῶτοι.", "en": {"kjv": "But many that are first shall be last; and the last shall be first.", "web": "But many will be last who are first; and first who are last.", "bsb": "But many who are first will be last, and the last will be first.", "asv": "But many shall be last that are first; and first that are last.", "ylt": "and many first shall be last, and last first.", "tyndale": "Many that are fyrste shalbe laste and the laste shalbe fyrste.", "dra": "And many that are first, shall be last: and the last shall be first.", "bbe": "But a great number who are first will be last, and some who are last will be first.", "geneva": "But many that are first, shalbe last, and the last shalbe first.", "wycliffe": "But manye schulen be, the firste the laste, and the laste the firste.", "rotherham": "But many shall be—first-last, and last-first.", "weymouth": "\"But many who are now first will be last, and many who are now last will be first.", "darby": "But many first shall be last, and last first.", "twenty": "But many who are first now will then be last, and those who are last will be first.", "acv": "But many first will be last, and last, first.", "anderson": "", "haweis": "But many, now first, will be the last; and last, who will be the first.", "noyes": "But many who are first will be last, and the last first.", "webster": "But many [that are] first shall be last, and the last [shall be] first.", "vulgate": "multi autem erunt primi novissimi et novissimi primi;"}}]}, {"c": 20, "verses": [{"v": 1, "ref": "20:1", "o": "Ὁμοία γάρ ἐστιν ἡ βασιλεία τῶν οὐρανῶν ἀνθρώπῳ οἰκοδεσπότῃ ὅστις ἐξῆλθεν ἅμα πρωῒ μισθώσασθαι ἐργάτας εἰς τὸν ἀμπελῶνα αὐτοῦ.", "en": {"kjv": "For the kingdom of heaven is like unto a man that is an householder, which went out early in the morning to hire labourers into his vineyard.", "web": "“For the Kingdom of Heaven is like a man who was the master of a household, who went out early in the morning to hire laborers for his vineyard.", "bsb": "“For the kingdom of heaven is like a landowner who went out early in the morning to hire workers for his vineyard.", "asv": "For the kingdom of heaven is like unto a man that was a householder, who went out early in the morning to hire laborers into his vineyard.", "ylt": "`For the reign of the heavens is like to a man, a householder, who went forth with the morning to hire workmen for his vineyard,", "tyndale": "For the kyngdome of heven ys lyke vnto an houssholder which went out erly in the morninge to hyre labourers into hys vyneyarde.", "dra": "The kingdom of heaven is like to an householder, who went out early in the morning to hire labourers into his vineyard.", "bbe": "For the kingdom of heaven is like the master of a house, who went out early in the morning to get workers into his vine-garden.", "geneva": "For the kingdome of heauen is like vnto a certaine, housholder, which went out at the dawning of the day to hire labourers into his vineyarde.", "wycliffe": "The kyngdom of heuenes is lijc to an housbonde man, that wente out first bi the morewe, to hire werk men in to his vyneyerd.", "rotherham": "For the kingdom of the heavens, is like, a man, a householder,—who went forth with the morning, to hire labourers into his vineyard;", "weymouth": "\"For the Kingdom of the Heavens is like an employer who went out early in the morning to hire men to work in his vineyard,", "darby": "For the kingdom of the heavens is like a householder who went out with the early morn to hire workmen for his vineyard.", "twenty": "For the Kingdom of Heaven is like an employer who went out in the early morning to hire labourers for his vineyards.", "acv": "For the kingdom of the heavens is compared to a man, a house-ruler, who went out in the early morning at the same time to hire workmen for his vineyard.", "anderson": "For the kingdom of heaven is like the master of a house, who went out early in the morning to hire laborers for his vineyard.", "haweis": "FOR the kingdom of heaven is like a man, the master of a family, who went out at break of day, to hire labourers into his vineyard.", "noyes": "For the kingdom of heaven is like a householder, who went out early in the morning to hire laborers for his vineyard.", "webster": "For the kingdom of heaven is like to a man [that is] a householder, who went out early in the morning to hire laborers into his vineyard.", "vulgate": "simile est enim regnum caelorum homini patri familias qui exiit primo mane conducere operarios in vineam suam;"}}, {"v": 2, "ref": "20:2", "o": "⸂συμφωνήσας δὲ⸃ μετὰ τῶν ἐργατῶν ἐκ δηναρίου τὴν ἡμέραν ἀπέστειλεν αὐτοὺς εἰς τὸν ἀμπελῶνα αὐτοῦ.", "en": {"kjv": "And when he had agreed with the labourers for a penny a day, he sent them into his vineyard.", "web": "When he had agreed with the laborers for a denariusa day, he sent them into his vineyard.", "bsb": "He agreed to pay them a denarius for the day and sent them into his vineyard.", "asv": "And when he had agreed with the laborers for a shilling a day, he sent them into his vineyard.", "ylt": "and having agreed with the workmen for a denary a day, he sent them into his vineyard.", "tyndale": "And he agreed wt the labourers for a peny a daye and sent them into his vyneyarde.", "dra": "And having agreed with the labourers for a penny a day, he sent them into his vineyard.", "bbe": "And when he had made an agreement with the workmen for a penny a day, he sent them into his vine-garden.", "geneva": "And he agreed with the labourers for a peny a day, and sent them into his vineyard.", "wycliffe": "And whanne the couenaunt was maad with werk men, of a peny for the dai, he sente hem in to his vyneyerd.", "rotherham": "and, when he had agreed with the labourers for a denary the day, he sent them into his vineyard.", "weymouth": "and having made an agreement with them for a shilling a day, sent them into his vineyard.", "darby": "And having agreed with the workmen for a denarius the day, he sent them into his vineyard.", "twenty": "He agreed with the labourers to pay them two shillings a day, and sent them into his vineyard.", "acv": "And having agreed with the workmen for a denarius a day, he sent them into his vineyard.", "anderson": "And when he had agreed with the laborers for a denarius a day, he sent them into his vineyard.", "haweis": "And when he had agreed with the labourers at a denarius a day, he sent them into the vineyard.", "noyes": "And having agreed with the laborers for a denary a day, he sent them into his vineyard.", "webster": "And when he had agreed with the laborers for a penny a day, he sent them into his vineyard.", "vulgate": "conventione autem facta cum operariis ex denario diurno misit eos in vineam suam;"}}, {"v": 3, "ref": "20:3", "o": "καὶ ἐξελθὼν περὶ τρίτην ὥραν εἶδεν ἄλλους ἑστῶτας ἐν τῇ ἀγορᾷ ἀργούς·", "en": {"kjv": "And he went out about the third hour, and saw others standing idle in the marketplace,", "web": "He went out about the third hour,and saw others standing idle in the marketplace.", "bsb": "About the third hour he went out and saw others standing in the marketplace doing nothing.", "asv": "And he went out about the third hour, and saw others standing in the marketplace idle;", "ylt": "`And having gone forth about the third hour, he saw others standing in the market-place idle,", "tyndale": "And he went out about the thyrde houre and sawe other stonding ydell in the marketplace", "dra": "And going out about the third hour, he saw others standing in the marketplace idle.", "bbe": "And he went out about the third hour, and saw others in the market-place doing nothing;", "geneva": "And he went out about the third houre, and sawe other standing idle in the market place,", "wycliffe": "And he yede out aboute the thridde our, and say othere stondynge idel in the chepyng.", "rotherham": "And, going forth about the third hour, he saw others, standing in the market-place, unemployed;", "weymouth": "About nine o'clock he went out and saw others loitering in the market-place.", "darby": "And having gone out about [the] third hour, he saw others standing in the market-place idle;", "twenty": "On going out again, about nine o’clock, he saw some others standing in the market-place, doing nothing.", "acv": "And having gone out about the third hour, he saw others having stood idle in the marketplace.", "anderson": "And he went out about the third hour, and saw others standing in the market, idle;", "haweis": "And going out about the third hour, he saw others standing in the market place unemployed.", "noyes": "And going out about the third hour, he saw others standing idle in the market-place;", "webster": "And he went out about the third hour, and saw others standing idle in the market-place,", "vulgate": "et egressus circa horam tertiam vidit alios stantes in foro otiosos;"}}, {"v": 4, "ref": "20:4", "o": "καὶ ἐκείνοις εἶπεν· Ὑπάγετε καὶ ὑμεῖς εἰς τὸν ἀμπελῶνα, καὶ ὃ ἐὰν ᾖ δίκαιον δώσω ὑμῖν·", "en": {"kjv": "And said unto them; Go ye also into the vineyard, and whatsoever is right I will give you. And they went their way.", "web": "To them he said, ‘You also go into the vineyard, and whatever is right I will give you.’ So they went their way.", "bsb": "‘You also go into my vineyard,’ he said, ‘and I will pay you whatever is right.’", "asv": "and to them he said, Go ye also into the vineyard, and whatsoever is right I will give you. And they went their way.", "ylt": "and to these he said, Go ye--also ye--to the vineyard, and whatever may be righteous I will give you;", "tyndale": "and sayd vnto them go ye also into my vyneyarde: and whatsoever is right I will geve you. And they went there waye.", "dra": "And he said to them: Go you also into my vineyard, and I will give you what shall be just.", "bbe": "And he said to them, Go into the vine-garden with the others, and whatever is right I will give you. And they went to work.", "geneva": "And sayd vnto them, Goe ye also into my vineyard, and whatsoeuer is right, I will giue you: and they went their way.", "wycliffe": "And he seide to hem, Go ye also in to myn vynyerd, and that that schal be riytful, Y schal yyue to you.", "rotherham": "and, to them, he said—ye also, go your way into the vineyard, and, whatsoever may be right, I will give you;", "weymouth": "To these also he said, \"`You also, go into the vineyard, and whatever is right I will give you.'", "darby": "and to them he said, Go also ye into the vineyard, and whatsoever may be just I will give you. And they went their way.", "twenty": "‘You also may go into my vineyard,’ he said, ‘and I will pay you what is fair.’", "acv": "And he said to those men, Go ye also into the vineyard, and whatever would be right I will give you, and they went.", "anderson": "and he said to them: Go you also into my vineyard, and whatever is right I will give you.", "haweis": "And he said to them, Go ye also into the vineyard, and whatever is equitable, I will give it you. So they went.", "noyes": "and said to them, Go ye also into the vineyard; and whatever is right, I will give you. And they went.", "webster": "And said to them, Go ye also into the vineyard; and whatever is right, I will give you. And they departed.", "vulgate": "et illis dixit ite et vos in vineam et quod iustum fuerit dabo vobis;"}}, {"v": 5, "ref": "20:5", "o": "οἱ δὲ ἀπῆλθον. ⸀πάλιν ἐξελθὼν περὶ ἕκτην καὶ ἐνάτην ὥραν ἐποίησεν ὡσαύτως.", "en": {"kjv": "Again he went out about the sixth and ninth hour, and did likewise.", "web": "Again he went out about the sixth and the ninth hour,and did likewise.", "bsb": "So they went. He went out again about the sixth hour and the ninth hour and did the same thing.", "asv": "Again he went out about the sixth and the ninth hour, and did likewise.", "ylt": "and they went away. `Again, having gone forth about the sixth and the ninth hour, he did in like manner.", "tyndale": "Agayne he wet out about the sixte and nynthe houre and dyd lyke wyse.", "dra": "And they went their way. And again he went out about the sixth and the ninth hour, and did in like manner.", "bbe": "Again he went out about the sixth and the ninth hour, and did the same.", "geneva": "Againe he went out about the sixt and ninth houre, and did likewise.", "wycliffe": "And thei wenten forth. Eftsoones he wente out aboute the sixte our, and the nynthe, and dide in lijk maner.", "rotherham": "and, they, departed. And, again, going forth about the sixth and ninth hour, he did likewise.", "weymouth": "\"So they went. Again about twelve, and about three o'clock, he went out and did the same.", "darby": "Again, having gone out about the sixth and ninth hour, he did likewise.", "twenty": "So the men went. Going out again about mid-day and about three o’clock, he did as before.", "acv": "Again having gone out about the sixth and the ninth hour, he did likewise.", "anderson": "And they went. Again he went out about the sixth, and about the ninth hour, and did in like manner.", "haweis": "Again going out, about the sixth and ninth hour, he did after the same manner.", "noyes": "Again going out about the sixth and the ninth hour, he did likewise.", "webster": "Again he went out about the sixth and ninth hour, and did likewise.", "vulgate": "illi autem abierunt iterum autem exiit circa sextam et nonam horam et fecit similiter;"}}, {"v": 6, "ref": "20:6", "o": "περὶ δὲ τὴν ⸀ἑνδεκάτην ἐξελθὼν εὗρεν ἄλλους ⸀ἑστῶτας, καὶ λέγει αὐτοῖς· Τί ὧδε ἑστήκατε ὅλην τὴν ἡμέραν ἀργοί;", "en": {"kjv": "And about the eleventh hour he went out, and found others standing idle, and saith unto them, Why stand ye here all the day idle?", "web": "About the eleventh hourhe went out, and found others standing idle. He said to them, ‘Why do you stand here all day idle?’", "bsb": "About the eleventh hour he went out and found still others standing around. ‘Why have you been standing here all day long doing nothing?’ he asked.", "asv": "And about the eleventh hour he went out, and found others standing; and he saith unto them, Why stand ye here all the day idle?", "ylt": "And about the eleventh hour, having gone forth, he found others standing idle, and saith to them, Why here have ye stood all the day idle?", "tyndale": "And he went out aboute the eleventhe houre and founde other stondynge ydell and sayde vnto them: Why stonde ye here all the daye ydell?", "dra": "But about the eleventh hour he went out and found others standing, and he saith to them: Why stand you here all the day idle?", "bbe": "And about the eleventh hour he went out and saw others doing nothing; and he says to them, Why are you here all the day doing nothing?", "geneva": "And he went about the eleuenth houre, and found other standing idle, and sayd vnto them, Why stand ye here all the day idle?", "wycliffe": "But aboute the elleuenthe our he wente out, and foond other stondynge; and he seide to hem, What stonden ye idel here al dai?", "rotherham": "And, about the eleventh, going forth, he found others, standing, and saith unto them—Why, here, stand ye, all the day, unemployed?", "weymouth": "And going out about five o'clock he found others loitering, and he asked them, \"`Why have you been standing here all day long, doing nothing?'", "darby": "But about the eleventh [hour], having gone out, he found others standing, and says to them, Why stand ye here all the day idle?", "twenty": "When he went out about five, he found some other men standing there, and said to them ‘Why have you been standing here all day long, doing nothing?’", "acv": "And having gone out about the eleventh hour, he found others who have stood idle. And he says to them, Why have ye stood here idle the whole day?", "anderson": "And about the eleventh hour he went out, and found others standing idle, and said to them, Why do you stand here all the day idle?", "haweis": "But about the eleventh hour, going out, he found others standing unemployed, and saith unto them, Why stand ye here all the day idle?", "noyes": "And going out about the eleventh hour, he found others standing, and saith to them, Why stand ye here all the day idle?", "webster": "And about the eleventh hour he went out, and found others standing idle, and saith to them, Why stand ye here all the day idle?", "vulgate": "circa undecimam vero exiit et invenit alios stantes et dicit illis quid hic statis tota die otiosi;"}}, {"v": 7, "ref": "20:7", "o": "λέγουσιν αὐτῷ· Ὅτι οὐδεὶς ἡμᾶς ἐμισθώσατο. λέγει αὐτοῖς· Ὑπάγετε καὶ ὑμεῖς εἰς τὸν ⸀ἀμπελῶνα.", "en": {"kjv": "They say unto him, Because no man hath hired us. He saith unto them, Go ye also into the vineyard; and whatsoever is right, that shall ye receive.", "web": "“They said to him, ‘Because no one has hired us.’ “He said to them, ‘You also go into the vineyard, and you will receive whatever is right.’", "bsb": "‘Because no one has hired us,’ they answered. So he told them, ‘You also go into my vineyard.’", "asv": "They say unto him, Because no man hath hired us. He saith unto them, Go ye also into the vineyard.", "ylt": "they say to him, Because no one did hire us; he saith to them, Go ye--ye also--to the vineyard, and whatever may be righteous ye shall receive.", "tyndale": "They sayde vnto hym: because no man hath hyred vs. He sayde to them: goo ye alsoo into my vyneyarde and whatsoever is right that shall ye receave.", "dra": "They say to him: Because no man hath hired us. He saith to them: Go ye also into my vineyard.", "bbe": "They say to him, Because no man has given us work. He says to them, Go in with the rest, into the vine-garden.", "geneva": "They sayd vnto him, Because no man hath hired vs. He sayd to them, Goe ye also into my vineyard, and whatsoeuer is right, that shall ye receiue.", "wycliffe": "Thei seien to him, For no man hath hirid vs. He seith to hem, Go ye also in to my vyneyerd.", "rotherham": "They say unto him—Because, no one, hath hired, us. He saith unto them—Ye also, go your way into the vineyard.", "weymouth": "\"`Because no one has hired us,' they replied. \"`You also, go into the vineyard,' he said.", "darby": "They say to him, Because no man has hired us. He says to them, Go also ye into the vineyard [and whatsoever may be just ye shall receive].", "twenty": "‘Because no one has hired us,’ they answered. ‘You also may go into my vineyard,’ he said.", "acv": "They say to him, Because no man has hired us. He says to them, Go ye also into the vineyard, and whatever would be right ye will receive.", "anderson": "They said to him: No man has hired us. He said to them: Go you also into the vineyard, and whatever is right you shall receive.", "haweis": "They say unto him, Because no man hath hired us. He saith to them, Go ye also into the vineyard; and whatever is equitable, ye shall receive.", "noyes": "They say to him, Because no one hath hired us. He saith to them, Go ye also into the vineyard.", "webster": "They say to him, Because no man hath hired us. He saith to them, Go ye also into the vineyard; and whatever is right, [that] shall ye receive.", "vulgate": "dicunt ei quia nemo nos conduxit dicit illis ite et vos in vineam;"}}, {"v": 8, "ref": "20:8", "o": "ὀψίας δὲ γενομένης λέγει ὁ κύριος τοῦ ἀμπελῶνος τῷ ἐπιτρόπῳ αὐτοῦ· Κάλεσον τοὺς ἐργάτας καὶ ἀπόδος ⸀αὐτοῖς τὸν μισθὸν ἀρξάμενος ἀπὸ τῶν ἐσχάτων ἕως τῶν πρώτων.", "en": {"kjv": "So when even was come, the lord of the vineyard saith unto his steward, Call the labourers, and give them their hire, beginning from the last unto the first.", "web": "When evening had come, the lord of the vineyard said to his manager, ‘Call the laborers and pay them their wages, beginning from the last to the first.’", "bsb": "When evening came, the owner of the vineyard said to his foreman, ‘Call the workers and pay them their wages, starting with the last ones hired and moving on to the first.’", "asv": "And when even was come, the lord of the vineyard saith unto his steward, Call the laborers, and pay them their hire, beginning from the last unto the first.", "ylt": "`And evening having come, the lord of the vineyard saith to his steward, Call the workmen, and pay them the reward, having begun from the last--unto the first.", "tyndale": "When even was come the lorde of the vyneyarde sayde vnto hys steward: call the labourers and geve them their hyre beginnyng at ye laste tyll thou come to ye fyrste.", "dra": "And when evening was come, the lord of the vineyard saith to his steward: Call the labourers and pay them their hire, beginning from the last even to the first.", "bbe": "And when evening came, the lord of the vine-garden said to his manager, Let the workers come, and give them their payment, from the last to the first.", "geneva": "And when euen was come, the master of the vineyard sayd vnto his steward, Call the labourers, and giue them their hire, beginning at the last, till thou come to the first.", "wycliffe": "And whanne euenyng was comun, the lord of the vyneyerd seith to his procuratoure, Clepe the werk men, and yelde to hem her hire, and bigynne thou at the laste til to the firste.", "rotherham": "And, when evening came, the master of the vineyard saith unto his steward—Call the labourers, and pay the hire,—beginning from the last, unto the first.", "weymouth": "\"When evening came, the master said to his steward, \"`Call the men and pay them their wages. Begin with the last set and finish with the first.'", "darby": "But when the evening was come, the lord of the vineyard says to his steward, Call the workmen and pay [them] their wages, beginning from the last even to the first.", "twenty": "In the evening the owner of the vineyard said to his steward ‘Call the labourers, and pay them their wages, beginning with the last, and ending with the first.", "acv": "And having become evening, the lord of the vineyard says to his manager, Call the workmen, and render to them their wage, having begun from the last until the first.", "anderson": "When the evening came, the owner of the vineyard said to his steward: Call the laborers, and, beginning with the last, pay them their hire even to the first.", "haweis": "Now when the evening came, the master of the vineyard said to his overseer, Call the labourers, and give them their wages, beginning from the last to the first.", "noyes": "And when evening came, the lord of the vineyard saith to his steward, Call the laborers, and give them their pay, beginning with the last, and going on to the first.", "webster": "So when evening was come, the lord of the vineyard saith to his steward, Call the laborers, and give them [their] hire, beginning from the last to the first.", "vulgate": "cum sero autem factum esset dicit dominus vineae procuratori suo voca operarios et redde illis mercedem incipiens a novissimis usque ad primos;"}}, {"v": 9, "ref": "20:9", "o": "⸂καὶ ἐλθόντες⸃ οἱ περὶ τὴν ἑνδεκάτην ὥραν ἔλαβον ἀνὰ δηνάριον.", "en": {"kjv": "And when they came that were hired about the eleventh hour, they received every man a penny.", "web": "“When those who were hired at about the eleventh hour came, they each received a denarius.", "bsb": "The workers who were hired about the eleventh hour came and each received a denarius.", "asv": "And when they came that were hired about the eleventh hour, they received every man a shilling.", "ylt": "And they of about the eleventh hour having come, did receive each a denary.", "tyndale": "And they whiche were hyred aboute the eleventhe houre came and receaved every man a peny.", "dra": "When therefore they were come that came about the eleventh hour, they received every man a penny.", "bbe": "And when those men came who had gone to work at the eleventh hour, they were given every man a penny.", "geneva": "And they which were hired about ye eleuenth houre, came and receiued euery man a penie.", "wycliffe": "And so whanne thei weren comun, that camen aboute the elleuenthe our, also thei token eueryche of hem a peny.", "rotherham": "And they of the eleventh hour, coming, received severally a denary.", "weymouth": "\"When those came who had begun at five o'clock, they received a shilling apiece;", "darby": "And when they [who came to work] about the eleventh hour came, they received each a denarius.", "twenty": "Now when those who had been hired about five o’clock went up, they received two shillings each.", "acv": "And those who came about the eleventh hour, each received a denarius.", "anderson": "And when those came who had been hired about the eleventh hour, they received each one a denarius.", "haweis": "And when they came, who began about the eleventh hour, they received each a denarius.", "noyes": "And they who were hired about the eleventh hour came, and received each a denary.", "webster": "And when they came that [were hired] about the eleventh hour, they received every man a penny.", "vulgate": "cum venissent ergo qui circa undecimam horam venerant acceperunt singulos denarios;"}}, {"v": 10, "ref": "20:10", "o": "⸂καὶ ἐλθόντες⸃ οἱ πρῶτοι ἐνόμισαν ὅτι ⸀πλεῖον λήμψονται· καὶ ἔλαβον ⸂τὸ ἀνὰ δηνάριον καὶ αὐτοί⸃.", "en": {"kjv": "But when the first came, they supposed that they should have received more; and they likewise received every man a penny.", "web": "When the first came, they supposed that they would receive more; and they likewise each received a denarius.", "bsb": "So when the original workers came, they assumed they would receive more. But each of them also received a denarius.", "asv": "And when the first came, they supposed that they would receive more; and they likewise received every man a shilling.", "ylt": "`And the first having come, did suppose that they shall receive more, and they received, they also, each a denary,", "tyndale": "Then came ye fyrst supposyng yt they shuld receave moare: and they likewyse receaved every man a peny.", "dra": "But when the first also came, they thought that they should receive more: And they also received every man a penny.", "bbe": "Then those who came first had the idea that they would get more; and they, like the rest, were given a penny.", "geneva": "Nowe when the first came, they supposed that they should receiue more, but they likewise receiued euery man a penie.", "wycliffe": "But the firste camen, and demeden, that thei schulden take more, but thei token ech oon bi hem silf a peny;", "rotherham": "And, when the first came, they supposed that, more, they should receive,—and, they also, received severally a denary.", "weymouth": "and when the first came, they expected to get more, but they also each got the shilling.", "darby": "And when the first came, they supposed that they would receive more, and they received also themselves each a denarius.", "twenty": "So, when the first went up, they thought that they would receive more, but they also received two shillings each;", "acv": "But when the first came, they supposed that they would receive more. And they also received a denarius each.", "anderson": "But when those came who had been hired first, they thought that they would receive more; and they received each one a denarius.", "haweis": "But when the first came, they expected that they should receive more; and they also received every man a denarius.", "noyes": "But when the first came, they supposed that they should receive more; and they too received each a denary.", "webster": "But when the first came, they supposed that they should receive more; and they likewise received every man a penny.", "vulgate": "venientes autem et primi arbitrati sunt quod plus essent accepturi acceperunt autem et ipsi singulos denarios;"}}, {"v": 11, "ref": "20:11", "o": "λαβόντες δὲ ἐγόγγυζον κατὰ τοῦ οἰκοδεσπότου", "en": {"kjv": "And when they had received it, they murmured against the goodman of the house,", "web": "When they received it, they murmured against the master of the household,", "bsb": "On receiving their pay, they began to grumble against the landowner.", "asv": "And when they received it, they murmured against the householder,", "ylt": "and having received it , they were murmuring against the householder, saying,", "tyndale": "And when they had receaved it they murmured agaynst the good man of the housse", "dra": "And receiving it they murmured against the master of the house,", "bbe": "And when they got it, they made a protest against the master of the house,", "geneva": "And when they had receiued it, they murmured against the master of the house,", "wycliffe": "and in the takyng grutchiden ayens the hosebonde man, and seiden,", "rotherham": "And, having received it, they began to murmur against the householder, saying—", "weymouth": "So when they had received it, they grumbled against the employer, saying,", "darby": "And on receiving it they murmured against the master of the house,", "twenty": "on which they began to grumble at their employer.", "acv": "And when they received it, they murmured against the house-ruler,", "anderson": "And when they received it, they murmured against the master of the house,", "haweis": "But when they received it, they murmured against the master of the family:", "noyes": "And when they had received it, they murmured against the householder,", "webster": "And when they had received [it], they murmured against the master of the house.", "vulgate": "et accipientes murmurabant adversus patrem familias;"}}, {"v": 12, "ref": "20:12", "o": "⸀λέγοντες· Οὗτοι οἱ ἔσχατοι μίαν ὥραν ἐποίησαν, καὶ ἴσους ⸂αὐτοὺς ἡμῖν⸃ ἐποίησας τοῖς βαστάσασι τὸ βάρος τῆς ἡμέρας καὶ τὸν καύσωνα.", "en": {"kjv": "Saying, These last have wrought but one hour, and thou hast made them equal unto us, which have borne the burden and heat of the day.", "web": "saying, ‘These last have spent one hour, and you have made them equal to us, who have borne the burden of the day and the scorching heat!’", "bsb": "‘These men who were hired last worked only one hour,’ they said, ‘and you have made them equal to us who have borne the burden and the scorching heat of the day.’", "asv": "saying, These last have spent but one hour, and thou hast made them equal unto us, who have borne the burden of the day and the scorching heat.", "ylt": "that These, the last, wrought one hour, and thou didst make them equal to us, who were bearing the burden of the day--and the heat.", "tyndale": "saying: These laste have wrought but one houre and thou hast made them equall vnto vs which have born ye burthe and heet of the daye.", "dra": "Saying: These last have worked but one hour. and thou hast made them equal to us, that have borne the burden of the day and the heats.", "bbe": "Saying, These last have done only one hour's work, and you have made them equal to us, who have undergone the hard work of the day and the burning heat.", "geneva": "Saying, These last haue wrought but one houre, and thou hast made them equall vnto vs, which haue borne the burden and heate of the day.", "wycliffe": "These laste wrouyten oon our, and thou hast maad hem euen to vs, that han born the charge of the dai, and heete?", "rotherham": "These last, one hour, wrought, and thou hast made them, equal unto us, who have borne the burden of the day, and the scorching heat.", "weymouth": "\"`These who came last have done only one hour's work, and you have put them on a level with us who have worked the whole day and have borne the scorching heat.'", "darby": "saying, These last have worked one hour, and thou hast made them equal to us, who have borne the burden of the day and the heat.", "twenty": "‘These last,’ they said, ‘have done only one hour’s work, and yet you have put them on the same footing with us, who have borne the brunt of the day’s work, and the heat.’", "acv": "saying, These last did one hour, and thou have made them equal to us, who have borne the burden of the day and the heat.", "anderson": "saying: These last have worked one hour, and you have made them equal to us, who have borne the burden of the day, and the heat.", "haweis": "saying, These last have wrought only a single hour, and thou hast put them on an equality with us, who have borne the burden and heat of the day.", "noyes": "saying, These last have worked but one hour, and thou hast made them equal to us, who have borne the burden and heat of the day.", "webster": "Saying, These last have wrought [but] one hour, and thou hast made them equal to us, who have borne the burden and heat of the day.", "vulgate": "dicentes hii novissimi una hora fecerunt et pares illos nobis fecisti qui portavimus pondus diei et aestus;"}}, {"v": 13, "ref": "20:13", "o": "ὁ δὲ ἀποκριθεὶς ⸂ἑνὶ αὐτῶν εἶπεν⸃· Ἑταῖρε, οὐκ ἀδικῶ σε· οὐχὶ δηναρίου συνεφώνησάς μοι;", "en": {"kjv": "But he answered one of them, and said, Friend, I do thee no wrong: didst not thou agree with me for a penny?", "web": "“But he answered one of them, ‘Friend, I am doing you no wrong. Didn’t you agree with me for a denarius?", "bsb": "But he answered one of them, ‘Friend, I am not being unfair to you. Did you not agree with me on one denarius?", "asv": "But he answered and said to one of them, Friend, I do thee no wrong: didst not thou agree with me for a shilling?", "ylt": "`And he answering said to one of them, Comrade, I do no unrighteousness to thee; for a denary didst not thou agree with me?", "tyndale": "He answered to one of the sayinge: frende I do the no wronge: dyddest thou not agre wt me for a peny?", "dra": "But he answering said to one of them: friend, I do thee no wrong: didst thou not agree with me for a penny?", "bbe": "But he in answer said to one of them, Friend, I do you no wrong: did you not make an agreement with me for a penny?", "geneva": "And hee answered one of them, saying, Friend, I doe thee no wrong: didst thou not agree with me for a penie?", "wycliffe": "And he answeride to oon of hem, and seide, Freend, Y do thee noon wrong; whether thou hast not acordid with me for a peny?", "rotherham": "And, he, answering, unto one of them, said,—Friend! I wrong thee not: Was it not, for a denary, thou didst agree with me?", "weymouth": "\"`My friend,' he answered to one of them, `I am doing you no injustice. Did you not agree with me for a shilling?", "darby": "But he answering said to one of them, [My] friend, I do not wrong thee. Didst thou not agree with me for a denarius?", "twenty": "‘My friend,’ was his reply to one of them, ‘I am not treating you unfairly. Did not you agree with me for two shillings?", "acv": "But having answered, he said to one of them, Friend, I do thee no wrong. Did thou not agree with me for a denarius?", "anderson": "But he answered and said to one of them: Friend, I do you no injustice; did you not agree with me for a denarius?", "haweis": "But he answering, said to one of them, Friend, I do thee no injustice; did I not agree with thee for a denarius?", "noyes": "But he answering said to one of them, Friend, I do thee no wrong; didst not thou agree with me for a denary?", "webster": "But he answered one of them, and said, Friend, I do thee no wrong: didst thou not agree with me for a penny?", "vulgate": "at ille respondens uni eorum dixit amice non facio tibi iniuriam nonne ex denario convenisti mecum;"}}, {"v": 14, "ref": "20:14", "o": "ἆρον τὸ σὸν καὶ ὕπαγε· θέλω δὲ τούτῳ τῷ ἐσχάτῳ δοῦναι ὡς καὶ σοί·", "en": {"kjv": "Take that thine is, and go thy way: I will give unto this last, even as unto thee.", "web": "Take that which is yours, and go your way. It is my desire to give to this last just as much as to you.", "bsb": "Take your pay and go. I want to give this last man the same as I gave you.", "asv": "Take up that which is thine, and go thy way; it is my will to give unto this last, even as unto thee.", "ylt": "take that which is thine, and go; and I will to give to this, the last, also as to thee;", "tyndale": "Take that which is thy duty and go thy waye. I will geve vnto this last as moche as to the.", "dra": "Take what is thine, and go thy way: I will also give to this last even as to thee.", "bbe": "Take what is yours, and go away; it is my pleasure to give to this last, even as to you.", "geneva": "Take that which is thine owne, and go thy way: I will giue vnto this last, as much as to thee.", "wycliffe": "Take thou that that is thin, and go; for Y wole yyue to this laste man, as to thee.", "rotherham": "Take thine own, and go thy way; but I please, unto this last, to give, as also to thee:", "weymouth": "Take your money and go. I choose to give this last comer just as much as I give you.", "darby": "Take what is thine and go. But it is my will to give to this last even as to thee:", "twenty": "Take what belongs to you, and go. I choose to give to this last man the same as to you.", "acv": "Take thine and go. But I want to give to this last man, as to thee also.", "anderson": "Take what is yours, and go; I will give to this last even as to you.", "haweis": "Take then thine own, and begone: I chuse to give to this last even as to thee.", "noyes": "Take thy due, and go. But I will give to this last even as to thee.", "webster": "Take [that] which [is] thine, and depart: I will give to this last, even as to thee.", "vulgate": "tolle quod tuum est et vade volo autem et huic novissimo dare sicut et tibi;"}}, {"v": 15, "ref": "20:15", "o": "⸀οὐκ ἔξεστίν μοι ⸂ὃ θέλω ποιῆσαι⸃ ἐν τοῖς ἐμοῖς; ⸀ἢ ὁ ὀφθαλμός σου πονηρός ἐστιν ὅτι ἐγὼ ἀγαθός εἰμι;", "en": {"kjv": "Is it not lawful for me to do what I will with mine own? Is thine eye evil, because I am good?", "web": "Isn’t it lawful for me to do what I want to with what I own? Or is your eye evil, because I am good?’", "bsb": "Do I not have the right to do as I please with what is mine? Or are you envious because I am generous?’", "asv": "Is it not lawful for me to do what I will with mine own? or is thine eye evil, because I am good?", "ylt": "is it not lawful to me to do what I will in mine own? is thine eye evil because I am good?", "tyndale": "Ys it not lawfull for me to do as me listeth with myne awne? Ys thyne eye evyll because I am good?", "dra": "Or, is it not lawful for me to do what I will? Is thy eye evil, because I am good?", "bbe": "Have I not the right to do as seems good to me in my house? or is your eye evil, because I am good?", "geneva": "Is it not lawfull for me to do as I will with mine owne? Is thine eye euil, because I am good?", "wycliffe": "Whether it is not leueful to me to do that that Y wole? Whether thin iye is wickid, for Y am good?", "rotherham": "Is it not allowed me to do, what I please, with my own? or is, thine eye, evil, because I good?", "weymouth": "Have I not a right to do what I choose with my own property? Or are you envious because I am generous?'", "darby": "is it not lawful for me to do what I will in my own affairs? Is thine eye evil because I am good?", "twenty": "Have not I the right to do as I choose with what is mine? Are you envious because I am liberal?’", "acv": "Is it not permitted for me to do what I want with my own? Is thine eye evil, because I am good?", "anderson": "Is it not allowed me to do what I will with my own? Or, is your eye envious, because I am good?", "haweis": "Is it not lawful for me to do what I will with my own? Is thine eye evil, because I am good?", "noyes": "Am I not free to do what I will with my own? Is thine eye evil, because I am good?", "webster": "Is it not lawful for me to do what I will with my own? is thy eye evil because I am good?", "vulgate": "aut non licet mihi quod volo facere an oculus tuus nequam est quia ego bonus sum;"}}, {"v": 16, "ref": "20:16", "o": "οὕτως ἔσονται οἱ ἔσχατοι πρῶτοι καὶ οἱ πρῶτοι ⸀ἔσχατοι.", "en": {"kjv": "So the last shall be first, and the first last: for many be called, but few chosen.", "web": "So the last will be first, and the first last. For many are called, but few are chosen.”", "bsb": "So the last will be first, and the first will be last.”", "asv": "So the last shall be first, and the first last.", "ylt": "So the last shall be first, and the first last, for many are called, and few chosen.'", "tyndale": "Soo the laste shalbe fyrste and the fyrste shalbe laste. For many are called and feawe be chosen.", "dra": "So shall the last be first and the first last. For many are called but few chosen.", "bbe": "So the last will be first, and the first last.", "geneva": "So the last shalbe first, and the first last: for many are called, but fewe chosen.", "wycliffe": "So the laste schulen be the firste, and the firste the laste; `for many ben clepid, but fewe ben chosun.", "rotherham": "Thus, shall be—The last first, and the first last.", "weymouth": "\"So the last shall be first, and the first last.\"", "darby": "Thus shall the last be first, and the first last; for many are called ones, but few chosen ones.", "twenty": "So those who are last will be first, and the first last.”", "acv": "So the last will be first, and the first last, for many are called, but few chosen.", "anderson": "So the last shall be first, and the first last. For many are called, but few are chosen.", "haweis": "Thus shall the last be first, and the first last; for many are called, but the elect are few.", "noyes": "Thus the last will be first, and the first, last. And as", "webster": "So the last shall be first, and the first last: for many are called, but few chosen.", "vulgate": "sic erunt novissimi primi et primi novissimi multi sunt enim vocati pauci autem electi;"}}, {"v": 17, "ref": "20:17", "o": "⸂Καὶ ἀναβαίνων ὁ⸃ Ἰησοῦς εἰς Ἱεροσόλυμα παρέλαβεν τοὺς δώδεκα ⸀μαθητὰς κατ’ ἰδίαν, ⸂καὶ ἐν τῇ ὁδῷ⸃ εἶπεν αὐτοῖς·", "en": {"kjv": "And Jesus going up to Jerusalem took the twelve disciples apart in the way, and said unto them,", "web": "As Jesus was going up to Jerusalem, he took the twelve disciples aside, and on the way he said to them,", "bsb": "As Jesus was going up to Jerusalem, He took the twelve disciples aside and said,", "asv": "And as Jesus was going up to Jerusalem, he took the twelve disciples apart, and on the way he said unto them,", "ylt": "And Jesus going up to Jerusalem, took the twelve disciples by themselves in the way, and said to them,", "tyndale": "And Iesus ascended to Ierusalem and toke the .xii. disciples a parte in the waye and sayde to the.", "dra": "And Jesus going up to Jerusalem, took the twelve disciples apart and said to them:", "bbe": "And when Jesus was going up to Jerusalem, he took the twelve disciples on one side, and said to them,", "geneva": "And Iesus went vp to Hierusalem, and tooke the twelue disciples apart in the way, and said vnto them,", "wycliffe": "And Jhesus wente vp to Jerusalem, and took hise twelue disciplis in priuetee, and seide to hem, Lo!", "rotherham": "And, Jesus, being about to go up unto Jerusalem, took unto him the twelve [disciples], apart, and, in the way, he said unto them—", "weymouth": "Jesus was now going up to Jerusalem, and He took the twelve disciples aside by themselves, and on the way He said to them,", "darby": "And Jesus, going up to Jerusalem, took the twelve disciples with [him] apart in the way, and said to them,", "twenty": "When Jesus was on the point of going up to Jerusalem, he gathered the twelve disciples round him by themselves, and said to them as they were on their way:", "acv": "And while going up to Jerusalem, Jesus took the twelve disciples in private on the way, and he said to them,", "anderson": "And as Jesus was going up to Jerusalem, he took the twelve disciples aside on his journey, and said to them:", "haweis": "And Jesus going up to Jerusalem, took his twelve disciples aside on the road, and said to them;", "noyes": "Jesus was going up to Jerusalem, he took the twelve apart, and on the way said to them,", "webster": "And Jesus going up to Jerusalem, took the twelve disciples apart in the way, and said to them,", "vulgate": "et ascendens Iesus Hierosolymam adsumpsit duodecim discipulos secreto et ait illis;"}}, {"v": 18, "ref": "20:18", "o": "Ἰδοὺ ἀναβαίνομεν εἰς Ἱεροσόλυμα, καὶ ὁ υἱὸς τοῦ ἀνθρώπου παραδοθήσεται τοῖς ἀρχιερεῦσιν καὶ γραμματεῦσιν, καὶ κατακρινοῦσιν αὐτὸν θανάτῳ,", "en": {"kjv": "Behold, we go up to Jerusalem; and the Son of man shall be betrayed unto the chief priests and unto the scribes, and they shall condemn him to death,", "web": "“Behold, we are going up to Jerusalem, and the Son of Man will be delivered to the chief priests and scribes, and they will condemn him to death,", "bsb": "“Look, we are going up to Jerusalem, and the Son of Man will be delivered over to the chief priests and scribes. They will condemn Him to death", "asv": "Behold, we go up to Jerusalem; and the Son of man shall be delivered unto the chief priests and scribes; and they shall condemn him to death,", "ylt": "`Lo, we go up to Jerusalem, and the Son of Man shall be delivered to the chief priests and scribes,", "tyndale": "Beholde we goo vp to Ierusalem and the sonne of ma shalbe betrayed vnto ye chefe prestes and vnto the scribes and they shall condene him to deeth", "dra": "Behold we go up to Jerusalem, and the Son of man shall be betrayed to the chief priests and the scribes: and they shall condemn him to death.", "bbe": "See, we go up to Jerusalem; and the Son of man will be given into the hands of the chief priests and scribes; and they will give orders for him to be put to death,", "geneva": "Beholde, wee goe vp to Hierusalem, and the Sonne of man shall bee deliuered vnto the chiefe priestes, and vnto the Scribes, and they shall condemne him to death,", "wycliffe": "we goon vp to Jerusalem, and mannus sone schal be bitakun to princis of prestis, and scribis; and thei schulen condempne him to deeth.", "rotherham": "Lo! we are going up unto Jerusalem; and, the Son of Man, will be delivered up unto the chief-priests and Scribes, and they will condemn him, [to death],", "weymouth": "\"We are going up to Jerusalem, and there the Son of Man will be betrayed to the High Priests and Scribes. They will condemn Him to death,", "darby": "Behold we go up to Jerusalem, and the Son of man will be delivered up to the chief priests and scribes, and they will condemn him to death;", "twenty": "“Listen! We are going up to Jerusalem; and there the Son of Man will be betrayed to the Chief Priests and Teachers of the Law, and they will condemn him to death,", "acv": "Behold, we go up to Jerusalem, and the Son of man will be betrayed to the chief priests and scholars. And they will condemn him to death,", "anderson": "Behold, we are going up to Jerusalem, and the Son of man shall be delivered to the chief priests and the scribes, and they will condemn him to death,", "haweis": "Lo! we are going up to Jerusalem, and the Son of man will be betrayed to the chief priests and scribes, and they shall condemn him to death,", "noyes": "Lo! we are going up to Jerusalem, and the Son of man will be delivered up to the chief priests and scribes; and they will condemn him to death,", "webster": "Behold, we go up to Jerusalem; and the Son of man will be betrayed to the chief priests, and to the scribes, and they will condemn him to death,", "vulgate": "ecce ascendimus Hierosolymam et Filius hominis tradetur principibus sacerdotum et scribis et condemnabunt eum morte;"}}, {"v": 19, "ref": "20:19", "o": "καὶ παραδώσουσιν αὐτὸν τοῖς ἔθνεσιν εἰς τὸ ἐμπαῖξαι καὶ μαστιγῶσαι καὶ σταυρῶσαι, καὶ τῇ τρίτῃ ἡμέρᾳ ⸀ἐγερθήσεται.", "en": {"kjv": "And shall deliver him to the Gentiles to mock, and to scourge, and to crucify him: and the third day he shall rise again.", "web": "and will hand him over to the Gentiles to mock, to scourge, and to crucify; and the third day he will be raised up.”", "bsb": "and will deliver Him over to the Gentiles to be mocked and flogged and crucified. And on the third day He will be raised to life.”", "asv": "and shall deliver him unto the Gentiles to mock, and to scourge, and to crucify: and the third day he shall be raised up.", "ylt": "and they shall condemn him to death, and shall deliver him to the nations to mock, and to scourge, and to crucify, and the third day he will rise again.'", "tyndale": "and shall delyvre him to the getils to be mocked to be scourged and to be crucified: and ye thyrd daye he shall ryse agayne.", "dra": "And shall deliver him to the Gentiles to be mocked and scourged and crucified: and the third day he shall rise again.", "bbe": "And will give him up to the Gentiles to be made sport of and to be whipped and to be put to death on the cross: and the third day he will come back again from the dead.", "geneva": "And shall deliuer him to the Gentiles, to mocke, and to scourge, and to crucifie him, but the third day he shall rise againe.", "wycliffe": "And thei schulen bitake hym to hethene men, for to be scorned, and scourgid, and crucified; and the thridde day he schal rise ayen to lijf.", "rotherham": "And deliver him up unto the nations, to mock and to scourge and to crucify,—and, on the third day, he will, arise.", "weymouth": "and hand Him over to the Gentiles to be made sport of and scourged and crucified; and on the third day He will be raised to life.\"", "darby": "and they will deliver him up to the nations to mock and to scourge and to crucify, and the third day he shall rise again.", "twenty": "and give him up to the Gentiles for them to mock, and to scourge, and to crucify; and on the third day he will rise.”", "acv": "and will deliver him to the Gentiles to ridicule, and to scourge, and to crucify. And the third day he will rise.", "anderson": "and will deliver him to the Gentiles to deride, and to scourge, and to crucify: and on the third day he shall rise again.", "haweis": "and shall deliver him to the Gentiles, to insult, and to scourge, and to crucify: and the third day he shall rise again.", "noyes": "and will deliver him up to the gentiles to mock, and scourge, and crucify; and on the third day he will rise again.", "webster": "And will deliver him to the Gentiles to mock, and to scourge, and to crucify [him]: and the third day he will rise again.", "vulgate": "et tradent eum gentibus ad deludendum et flagellandum et crucifigendum et tertia die resurget;"}}, {"v": 20, "ref": "20:20", "o": "Τότε προσῆλθεν αὐτῷ ἡ μήτηρ τῶν υἱῶν Ζεβεδαίου μετὰ τῶν υἱῶν αὐτῆς προσκυνοῦσα καὶ αἰτοῦσά τι ⸀παρ’ αὐτοῦ.", "en": {"kjv": "Then came to him the mother of Zebedee’s children with her sons, worshipping him, and desiring a certain thing of him.", "web": "Then the mother of the sons of Zebedee came to him with her sons, kneeling and asking a certain thing of him.", "bsb": "Then the mother of Zebedee’s sons came to Jesus with her sons and knelt down to make a request of Him.", "asv": "Then came to him the mother of the sons of Zebedee with her sons, worshipping him, and asking a certain thing of him.", "ylt": "Then came near to him the mother of the sons of Zebedee, with her sons, bowing and asking something from him,", "tyndale": "Then came to hym the mother of zebedes chyldren with her sonnes worshippynge him and desyringe a certayne thinge of him.", "dra": "Then came to him the mother of the sons of Zebedee with her sons, adoring and asking something of him.", "bbe": "Then the mother of the sons of Zebedee came to him with her sons, giving him worship and making a request of him.", "geneva": "Then came to him the mother of Zebedeus children with her sonnes, worshipping him, and desiring a certaine thing of him.", "wycliffe": "Thanne the modir of the sones of Zebedee cam to hym with hir sones, onourynge, and axynge sum thing of hym.", "rotherham": "Then came unto him the mother of the sons of Zebedee, with her sons, bowing down, and asking something from him.", "weymouth": "Then the mother of the sons of Zabdi came to Him with her sons, and knelt before Him to make a request of Him.", "darby": "Then came to him the mother of the sons of Zebedee, with her sons, doing homage, and asking something of him.", "twenty": "Then the mother of Zebediah’s sons came to him with her sons, bowing to the ground, and begging a favour.", "acv": "Then the mother of the sons of Zebedee came to him with her sons, worshiping, and asking something from him.", "anderson": "Then came to him the mother of the sons of Zebedee, with her sons, bowing down, and asking something of him.", "haweis": "Then came to him the mother of Zebedee’s children, with her sons, paying him obeisance, and petitioning a favour of him.", "noyes": "Then came to him the mother of the sons of Zebedee with her sons, falling down before him, and asking a certain thing of him.", "webster": "Then came to him the mother of Zebedee's children, with her sons, worshiping [him], and desiring a certain thing of him.", "vulgate": "tunc accessit ad eum mater filiorum Zebedaei cum filiis suis adorans et petens aliquid ab eo;"}}, {"v": 21, "ref": "20:21", "o": "ὁ δὲ εἶπεν αὐτῇ· Τί θέλεις; λέγει αὐτῷ· Εἰπὲ ἵνα καθίσωσιν οὗτοι οἱ δύο υἱοί μου εἷς ἐκ δεξιῶν ⸀σου καὶ εἷς ἐξ εὐωνύμων σου ἐν τῇ βασιλείᾳ σου.", "en": {"kjv": "And he said unto her, What wilt thou? She saith unto him, Grant that these my two sons may sit, the one on thy right hand, and the other on the left, in thy kingdom.", "web": "He said to her, “What do you want?” She said to him, “Command that these, my two sons, may sit, one on your right hand, and one on your left hand, in your Kingdom.”", "bsb": "“What do you want?” He inquired. She answered, “Declare that in Your kingdom one of these two sons of mine may sit at Your right hand, and the other at Your left.”", "asv": "And he said unto her, What wouldest thou? She saith unto him, Command that these my two sons may sit, one on thy right hand, and one on thy left hand, in thy kingdom.", "ylt": "and he said to her, `What wilt thou?' She saith to him, `Say, that they may sit--these my two sons--one on thy right hand, and one on the left, in thy reign.'", "tyndale": "And he sayd vnto her: what wilt thou have? She sayde vnto him: Gravnte that these my two sonnes may sit ye one on thy right hond and the other on ye lifte hond in thy kyngdome.", "dra": "Who said to her: What wilt thou? She saith to him: say that these my two sons may sit, the one on thy right hand, and the other on thy left, in thy kingdom.", "bbe": "And he said to her, What is your desire? She says to him, Let my two sons be seated, the one at your right hand, and the other at your left, in your kingdom.", "geneva": "And he said vnto her, What wouldest thou? She said to him, Graunt that these my two sonnes may sit, the one at thy right hand, and the other at thy left hand in thy kingdome.", "wycliffe": "And he seide to hir, What wolt thou? She seith to hym, Seie that thes tweyne my sones sitte, oon at thi riythalf, and oon at thi lefthalf, in thi kyngdom.", "rotherham": "And, he, said to her—What desirest thou? She saith unto him—Bid, that these my two sons may sit, one on thy right hand, and one on thy left, in thy kingdom.", "weymouth": "\"What is it you desire?\" He asked. \"Command,\" she replied, \"that these my two sons may sit one at your right hand and one at your left in your Kingdom.\"", "darby": "And he said to her, What wilt thou? She says to him, Speak [the word] that these my two sons may sit, one on thy right hand and one on thy left in thy kingdom.", "twenty": "“What is it that you want?” he asked. “I want you to say,” she replied, “that in your Kingdom these two sons of mine may sit, one on your right, and the other on your left.”", "acv": "And he said to her, What do thou want? She says to him, Speak that these my two sons may sit, one at thy right hand and one at thy left hand in thy kingdom.", "anderson": "He said to her: What do you wish? She said to him: Command that these two sons of mine may sit, the one on thy right hand, and the other on thy left, in thy kingdom.", "haweis": "Then he said to her, What is thy wish? She saith unto him, Tell me that these my two sons shall sit, the one at thy right hand, and the other at thy left, in thy kingdom.", "noyes": "And he said to her, What is thy wish? She saith to him, Grant that these my two sons may sit, one on thy right hand, and one on thy left, in thy kingdom.", "webster": "And he said to her, What wilt thou: She saith to him, Grant that these my two sons may sit, the one on thy right hand, and the other on the left in thy kingdom.", "vulgate": "qui dixit ei quid vis ait illi dic ut sedeant hii duo filii mei unus ad dexteram tuam et unus ad sinistram in regno tuo;"}}, {"v": 22, "ref": "20:22", "o": "ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν· Οὐκ οἴδατε τί αἰτεῖσθε· δύνασθε πιεῖν τὸ ποτήριον ὃ ἐγὼ μέλλω ⸀πίνειν; λέγουσιν αὐτῷ· Δυνάμεθα.", "en": {"kjv": "But Jesus answered and said, Ye know not what ye ask. Are ye able to drink of the cup that I shall drink of, and to be baptized with the baptism that I am baptized with? They say unto him, We are able.", "web": "But Jesus answered, “You don’t know what you are asking. Are you able to drink the cup that I am about to drink, and be baptized with the baptism that I am baptized with?” They said to him, “We are able.”", "bsb": "“You do not know what you are asking,” Jesus replied. “Can you drink the cup I am going to drink?” “We can,” the brothers answered.", "asv": "But Jesus answered and said, Ye know not what ye ask. Are ye able to drink the cup that I am about to drink? They say unto him, We are able.", "ylt": "And Jesus answering said, `Ye have not known what ye ask for yourselves; are ye able to drink of the cup that I am about to drink? and with the baptism that I am baptized with, to be baptized?' They say to him, `We are able.'", "tyndale": "Iesus answered and sayd: Ye wot not what ye axe. Are ye able to drynke of the cuppe yt I shall drynke of and to be baptised wt the baptyme that I shalbe baptised with? They answered to him that we are.", "dra": "And Jesus answering, said: You know not what you ask. Can you drink the chalice that I shall drink? They say to him: We can.", "bbe": "But Jesus made answer and said, You have no idea what you are requesting. Are you able to take of the cup which I am about to take?", "geneva": "And Iesus answered and said, Ye know not what ye aske. Are ye able to drinke of the cup that I shall drinke of, and to be baptized with the baptisme that I shalbe baptized with? They said to him, We are able.", "wycliffe": "Jhesus answeride, and seide, Ye witen not what ye axen. Moun ye drynke the cuppe which Y schal drynke? Thei seien to hym, We moun.", "rotherham": "But Jesus, answering, said—Ye know not what ye are asking: Are ye able to drink the cup, which, I, am about to drink; They say unto him—We are able.", "weymouth": "\"None of you know what you are asking for,\" said Jesus; \"can you drink out of the cup from which I am about to drink?\" \"We can,\" they replied.", "darby": "And Jesus answering said, Ye know not what ye ask. Can ye drink the cup which I am about to drink? They say to him, We are able.", "twenty": "“You do not know what you are asking,” was Jesus’ answer. “Can you drink the cup that I am to drink?” “Yes,” they exclaimed, “we can.”", "acv": "But having answered, Jesus said, Ye know not what ye are asking. Are ye able to drink the cup that I am going to drink, or to be immersed the immersion that I am immersed? They say to him, We are able.", "anderson": "But Jesus answered and said: You know not what you ask. Are you able to drink the cup that I am about to drink, and to be immersed with the immersion with which I am immersed? They said to him: We are able.", "haweis": "Then Jesus answering said, Ye know not what ye ask. Can ye drink of the cup that I am going to drink, and be baptised with the baptism with which I am baptised? They say unto him, We are able.", "noyes": "But Jesus answering said, Ye know not what ye ask. Can ye drink the cup which I am to drink? They say to him, We can.", "webster": "But Jesus answered and said, Ye know not what ye ask. Are ye able to drink of the cup that I shall drink of, and to be baptized with the baptism that I am baptized with? They say to him, We are able.", "vulgate": "respondens autem Iesus dixit nescitis quid petatis potestis bibere calicem quem ego bibiturus sum dicunt ei possumus;"}}, {"v": 23, "ref": "20:23", "o": "⸀λέγει αὐτοῖς· Τὸ μὲν ποτήριόν μου ⸀πίεσθε, τὸ δὲ καθίσαι ἐκ δεξιῶν μου καὶ ἐξ ⸀εὐωνύμων οὐκ ἔστιν ⸀ἐμὸν δοῦναι, ἀλλ’ οἷς ἡτοίμασται ὑπὸ τοῦ πατρός μου.", "en": {"kjv": "And he saith unto them, Ye shall drink indeed of my cup, and be baptized with the baptism that I am baptized with: but to sit on my right hand, and on my left, is not mine to give, but it shall be given to them for whom it is prepared of my Father.", "web": "He said to them, “You will indeed drink my cup, and be baptized with the baptism that I am baptized with, but to sit on my right hand and on my left hand is not mine to give; but it is for whom it has been prepared by my Father.”", "bsb": "“You will indeed drink My cup,” Jesus said. “But to sit at My right or left is not Mine to grant. These seats belong to those for whom My Father has prepared them.”", "asv": "He saith unto them, My cup indeed ye shall drink: but to sit on my right hand, and on my left hand, is not mine to give; but it is for them for whom it hath been prepared of my Father.", "ylt": "And he saith to them, `Of my cup indeed ye shall drink, and with the baptism that I am baptized with ye shall be baptized; but to sit on my right hand and on my left is not mine to give, but--to those for whom it hath been prepared by my father.'", "tyndale": "And he sayd vnto the: Ye shall drinke of my cvp and shalbe baptised with the baptyme that I shalbe baptised with. But to syt on my ryght hond and on my lyst hond is not myne to geve: but to them for whom it is prepared of my father.", "dra": "He saith to them: My chalice indeed you shall drink; but to sit on my right or left hand is not mine to give to you, but to them for whom it is prepared by my Father.", "bbe": "They say to him, We are able. He says to them, Truly, you will take of my cup: but to be seated at my right hand and at my left is not for me to give, but it is for those for whom my Father has made it ready.", "geneva": "And he said vnto them, Ye shall drinke in deede of my cup, and shall be baptized with the baptisme, that I am baptized with, but to sit at my right hande, and at my left hand, is not mine to giue: but it shalbe giuen to them for whome it is prepared of my Father.", "wycliffe": "He seith to hem, Ye schulen drinke my cuppe; but to sitte at my riythalf or lefthalf, it is not myn to yyue to you; but to whiche it is maad redi of my fadir.", "rotherham": "He saith unto them—My cup, indeed, ye shall drink; but, to sit on my right hand and on my left, is not mine to give,—except unto those for whom it hath been prepared by my Father.", "weymouth": "\"You shall drink out of my cup,\" He said, \"but a seat at my right hand or at my left it is not for me to allot, but it belongs to those for whom it has been prepared by my Father.\"", "darby": "[And] he says to them, Ye shall drink indeed my cup, but to sit on my right hand and on [my] left, is not mine to give, but to those for whom it is prepared of my Father.", "twenty": "“You shall indeed drink my cup,” he said, “but as to a seat at my right and at my left — that is not mine to give, but it is for those for whom it has been prepared by my Father.”", "acv": "And he says to them, Ye will indeed drink my cup, and ye will be immersed the immersion that I am immersed. But to sit at my right hand and at my left hand is not mine to give, but to whom it has been prepared by my Father.", "anderson": "And he said to them: You shall drink my cup, and be immersed with the immersion with which I am immersed: but to sit on my right hand, and on my left, is not mine to give; but it shall be given to them for whom it has been prepared by my Father.", "haweis": "And he saith unto them, Ye shall indeed drink of my cup, and with the baptism with which I am baptised, shall ye be baptised; but to sit on my right hand, and on my left, it is not in my power to bestow, but on those, for whom it was prepared by my Father.", "noyes": "He saith to them, Ye will indeed drink my cup; but to sit on my right hand and on my left is not mine to give, but it will be given to those for whom it hath been prepared by my Father.", "webster": "And he saith to them, Ye shall drink indeed of my cup, and be baptized with the baptism that I am baptized with: but to sit on my right hand, and on my left, is not mine to give, but [it shall be given] to them for whom it is prepared by my Father.", "vulgate": "ait illis calicem quidem meum bibetis sedere autem ad dexteram meam et sinistram non est meum dare vobis sed quibus paratum est a Patre meo;"}}, {"v": 24, "ref": "20:24", "o": "Καὶ ἀκούσαντες οἱ δέκα ἠγανάκτησαν περὶ τῶν δύο ἀδελφῶν.", "en": {"kjv": "And when the ten heard it, they were moved with indignation against the two brethren.", "web": "When the ten heard it, they were indignant with the two brothers.", "bsb": "When the ten heard about this, they were indignant with the two brothers.", "asv": "And when the ten heard it, they were moved with indignation concerning the two brethren.", "ylt": "And the ten having heard, were much displeased with the two brothers,", "tyndale": "And when the ten hearde this they disdayned at ye two brethre:", "dra": "And the ten, hearing it, were moved with indignation against the two brethren.", "bbe": "And when it came to the ears of the ten, they were angry with the two brothers.", "geneva": "And when the other ten heard this, they disdained at the two brethren.", "wycliffe": "And the ten herynge, hadden indignacioun of the twei britheren.", "rotherham": "And the ten, hearing, were sorely displeased, concerning the two brethren.", "weymouth": "The other ten heard of this, and their indignation was aroused against the two brothers.", "darby": "And the ten, having heard [of it], were indignant about the two brothers.", "twenty": "On hearing of this, the ten others were very indignant about the two brothers.", "acv": "And when the ten heard it, they were indignant about the two brothers.", "anderson": "And when the ten heard it, their anger was aroused against the two brothers.", "haweis": "And the twelve, on hearing this, were filled with indignation against the two brethren.", "noyes": "And when the ten heard this, they were much displeased with the two brothers.", "webster": "And when the ten heard [it], they were moved with indignation against the two brethren.", "vulgate": "et audientes decem indignati sunt de duobus fratribus;"}}, {"v": 25, "ref": "20:25", "o": "ὁ δὲ Ἰησοῦς προσκαλεσάμενος αὐτοὺς εἶπεν· Οἴδατε ὅτι οἱ ἄρχοντες τῶν ἐθνῶν κατακυριεύουσιν αὐτῶν καὶ οἱ μεγάλοι κατεξουσιάζουσιν αὐτῶν.", "en": {"kjv": "But Jesus called them unto him, and said, Ye know that the princes of the Gentiles exercise dominion over them, and they that are great exercise authority upon them.", "web": "But Jesus summoned them, and said, “You know that the rulers of the nations lord it over them, and their great ones exercise authority over them.", "bsb": "But Jesus called them aside and said, “You know that the rulers of the Gentiles lord it over them, and their superiors exercise authority over them.", "asv": "But Jesus called them unto him, and said, Ye know that the rulers of the Gentiles lord it over them, and their great ones exercise authority over them.", "ylt": "and Jesus having called them near, said, `Ye have known that the rulers of the nations do exercise lordship over them, and those great do exercise authority over them,", "tyndale": "But Iesus called them vnto him and sayde: Ye knowe yt the lordes of the gentyls have dominacio over them. And they that are great exercise power over the.", "dra": "But Jesus called them to him and said: You know that the princes of the Gentiles lord it over them; and that they that are the greater, exercise power upon them.", "bbe": "But Jesus said to them, You see that the rulers of the Gentiles are lords over them, and their great ones have authority over them.", "geneva": "Therefore Iesus called them vnto him, and saide, We knowe that the lordes of the Gentiles haue domination ouer them, and they that are great, exercise authoritie ouer them.", "wycliffe": "But Jhesus clepide hem to hym, and seide, Ye witen, that princis of hethene men ben lordis of hem, and thei that ben gretter, vsen power on hem.", "rotherham": "But, Jesus, calling them near, said—Ye know that, the rulers of the nations, lord it over them, and, the great ones, wield authority over them:", "weymouth": "But Jesus called them to Him, and said, \"You know that the rulers of the Gentiles lord it over them, and their great men exercise authority over them.", "darby": "But Jesus having called them to [him], said, Ye know that the rulers of the nations exercise lordship over them, and the great exercise authority over them.", "twenty": "Jesus, however, called the ten to him, and said: “The rulers of the Gentiles lord it over them as you know, and their great men oppress them.", "acv": "But having summoned them, Jesus said, Ye know that the rulers of the Gentiles lord over them, and their eminent men have power over them.", "anderson": "But Jesus called them to him, and said: You know that the rulers of the Gentiles act as lords over them, and their great men have authority over them.", "haweis": "But Jesus, calling them to him, said, Ye know that the princes of the Gentiles lord it over them, and their great men exercise authority among them.", "noyes": "But Jesus called them to him, and said, Ye know that the rulers of the nations lord it over them, and their great men exercise a strict authority over them.", "webster": "But Jesus called them [to him], and said, Ye know that the princes of the Gentiles exercise dominion over them, and they that are great exercise authority upon them.", "vulgate": "Iesus autem vocavit eos ad se et ait scitis quia principes gentium dominantur eorum et qui maiores sunt potestatem exercent in eos;"}}, {"v": 26, "ref": "20:26", "o": "οὐχ οὕτως ⸀ἔσται ἐν ὑμῖν· ἀλλ’ ὃς ⸀ἂν θέλῃ ἐν ὑμῖν μέγας γενέσθαι ἔσται ὑμῶν διάκονος,", "en": {"kjv": "But it shall not be so among you: but whosoever will be great among you, let him be your minister;", "web": "It shall not be so among you, but whoever desires to become great among you shall beyour servant.", "bsb": "It shall not be this way among you. Instead, whoever wants to become great among you must be your servant,", "asv": "Not so shall it be among you: but whosoever would become great among you shall be your minister;", "ylt": "but not so shall it be among you, but whoever may will among you to become great, let him be your ministrant;", "tyndale": "It shall not be so amoge you. But whosoever wyll be greate amoge you let him be youre minister:", "dra": "It shall not be so among you: but whosoever is the greater among you, let him be your minister.", "bbe": "Let it not be so among you: but if anyone has a desire to become great among you, let him be your servant;", "geneva": "But it shall not be so among you: but whosoeuer will be great among you, let him be your seruant.", "wycliffe": "It schal not be so among you; but who euer wole be maad gretter among you, be he youre mynystre; and who euer among you wole be the firste, he schal be youre seruaunt.", "rotherham": "Not so, is it, among you,—but, whosoever shall desire, among you, to become, great, shall be, your minister;", "weymouth": "Not so shall it be among you; but whoever desires to be great among you shall be your servant,", "darby": "It shall not be thus amongst you, but whosoever will be great among you, shall be your servant;", "twenty": "Among you it is not so.", "acv": "But it shall not be so among you. Rather whoever wants to become great among you, he shall be your helper,", "anderson": "It shall not be so among you. But whoever will be great among you, let him be your minister.", "haweis": "But thus shall it not be with you. But whosoever will be a great man among you, let him be your servant;", "noyes": "Not so shall it be among you; but whoever desireth to become great among you, will be your minister;", "webster": "But it shall not be so among you: but whoever will be great among you, let him be your minister;", "vulgate": "non ita erit inter vos sed quicumque voluerit inter vos maior fieri sit vester minister;"}}, {"v": 27, "ref": "20:27", "o": "καὶ ὃς ⸀ἂν θέλῃ ἐν ὑμῖν εἶναι πρῶτος ⸀ἔσται ὑμῶν δοῦλος·", "en": {"kjv": "And whosoever will be chief among you, let him be your servant:", "web": "Whoever desires to be first among you shall be your bondservant,", "bsb": "and whoever wants to be first among you must be your slave—", "asv": "and whosoever would be first among you shall be your servant:", "ylt": "and whoever may will among you to be first, let him be your servant;", "tyndale": "and whosoever wil be chefe let him be youre servaut", "dra": "And he that will be first among you shall be your servant.", "bbe": "And whoever has a desire to be first among you, let him take the lowest place:", "geneva": "And whosoeuer will be chiefe among you, let him be your seruant.", "wycliffe": "", "rotherham": "And, whosoever shall desire, among you, to be first, shall be, your servant:—", "weymouth": "and whoever desires to be first among you shall be your bondservant;", "darby": "and whosoever will be first among you, let him be your bondman;", "twenty": "No, whoever wants to become great among you must be your servant, and whoever wants to take the first place among you, must be your slave;", "acv": "and whoever wants be first among you shall be your bondman.", "anderson": "And whoever will be first among you, let him be your servant;", "haweis": "and whosoever will be first, let him be your slave.", "noyes": "and whoever desireth to be first among you, will be your servant;", "webster": "And whoever will be chief among you, let him be your servant:", "vulgate": "et qui voluerit inter vos primus esse erit vester servus;"}}, {"v": 28, "ref": "20:28", "o": "ὥσπερ ὁ υἱὸς τοῦ ἀνθρώπου οὐκ ἦλθεν διακονηθῆναι ἀλλὰ διακονῆσαι καὶ δοῦναι τὴν ψυχὴν αὐτοῦ λύτρον ἀντὶ πολλῶν.", "en": {"kjv": "Even as the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many.", "web": "even as the Son of Man came not to be served, but to serve, and to give his life as a ransom for many.”", "bsb": "just as the Son of Man did not come to be served, but to serve, and to give His life as a ransom for many.”", "asv": "even as the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many.", "ylt": "even as the Son of Man did not come to be ministered to, but to minister, and to give his life a ransom for many.'", "tyndale": "eve as the sonne of man came not to be ministred vnto but to minister and to geve his lyfe for the redempcion of many.", "dra": "Even as the Son of man is not come to be ministered unto, but to minister and to give his life a redemption for many.", "bbe": "Even as the Son of man did not come to have servants, but to be a servant, and to give his life for the salvation of men.", "geneva": "Euen as the Sonne of man came not to be serued, but to serue, and to giue his life for the ransome of many.", "wycliffe": "As mannus sone cam not to be seruyd, but to serue, and to yyue his lijf redempcioun for manye.", "rotherham": "Just as, the Son of Man, came not to be ministered unto, but to minister, and to give his life a ransom instead of many.", "weymouth": "just as the Son of Man came not to be served but to serve, and to give His life as the redemption-price for many.\"", "darby": "as indeed the Son of man did not come to be served, but to serve, and to give his life a ransom for many.", "twenty": "just as the Son of Man came, not to be served, but to serve, and to give his life as a ransom for many.”", "acv": "Just as the Son of man came not to be served, but to serve, and to give his life a ransom for many.", "anderson": "even as the Son of man came, not to be ministered to, but to minister, and to give his life a ransom for many.", "haweis": "Even as the Son of man came not to be waited upon, but to serve, and to give his life a ransom for many.", "noyes": "even as the Son of man came not to be served, but to serve, and to give his life a ransom for many.", "webster": "Even as the Son of man came not to be ministered to, but to minister, and to give his life a ransom for many.", "vulgate": "sicut Filius hominis non venit ministrari sed ministrare et dare animam suam redemptionem pro multis;"}}, {"v": 29, "ref": "20:29", "o": "Καὶ ἐκπορευομένων αὐτῶν ἀπὸ Ἰεριχὼ ἠκολούθησεν αὐτῷ ὄχλος πολύς.", "en": {"kjv": "And as they departed from Jericho, a great multitude followed him.", "web": "As they went out from Jericho, a great multitude followed him.", "bsb": "As they were leaving Jericho, a large crowd followed Him.", "asv": "And as they went out from Jericho, a great multitude followed him.", "ylt": "And they going forth from Jericho, there followed him a great multitude,", "tyndale": "And as they departed fro Hierico moche people folowed him.", "dra": "And when they went out from Jericho, a great multitude followed him.", "bbe": "And when they were going out from Jericho, a great number went after him.", "geneva": "And as they departed from Iericho, a great multitude followed him.", "wycliffe": "And whanne thei yeden out of Jerico, miche puple suede him.", "rotherham": "And, as they were going forth from Jericho, there followed him a great multitude;", "weymouth": "As they were leaving Jericho, an immense crowd following Him,", "darby": "And as they went out from Jericho a great crowd followed him.", "twenty": "As they were going out of Jericho, a great crowd followed him.", "acv": "And when they went out from Jericho, a great multitude followed him.", "anderson": "And as they went out from Jericho, a great multitude followed him.", "haweis": "And as they were going out of Jericho, a great multitude followed him.", "noyes": "And as they were going out of Jericho, a great multitude followed him.", "webster": "And as they departed from Jericho, a great multitude followed him.", "vulgate": "et egredientibus eis ab Hiericho secuta est eum turba multa;"}}, {"v": 30, "ref": "20:30", "o": "καὶ ἰδοὺ δύο τυφλοὶ καθήμενοι παρὰ τὴν ὁδόν, ἀκούσαντες ὅτι Ἰησοῦς παράγει, ἔκραξαν λέγοντες· ⸂Κύριε, ἐλέησον ἡμᾶς⸃, ⸀υἱὸς Δαυίδ.", "en": {"kjv": "And, behold, two blind men sitting by the way side, when they heard that Jesus passed by, cried out, saying, Have mercy on us, O Lord, thou Son of David.", "web": "Behold, two blind men sitting by the road, when they heard that Jesus was passing by, cried out, “Lord, have mercy on us, you son of David!”", "bsb": "And there were two blind men sitting beside the road. When they heard that Jesus was passing by, they cried out, “Lord, Son of David, have mercy on us!”", "asv": "And behold, two blind men sitting by the way side, when they heard that Jesus was passing by, cried out, saying, Lord, have mercy on us, thou son of David.", "ylt": "and lo, two blind men sitting by the way, having heard that Jesus doth pass by, cried, saying, `Deal kindly with us, sir--Son of David.'", "tyndale": "And beholde two blinde men sittinge by ye waysyde whe they hearde Iesus passe by cryed sayinge: Thou Lorde ye sonne of David have mercy on vs.", "dra": "And behold two blind men sitting by the way side heard that Jesus passed by. And they cried out, saying: O Lord, thou son of David, have mercy on us.", "bbe": "And two blind men seated by the wayside, when they had the news that Jesus was going by, gave a loud cry, saying, Lord, Son of David, have mercy on us.", "geneva": "And beholde, two blinde men, sitting by the way side, when they heard that Iesus passed by, cryed, saying, O Lord, the Sonne of Dauid, haue mercie on vs.", "wycliffe": "And lo! twei blynde men saten bisydis the weie, and herden that Jhesus passide; and thei crieden, and seiden, Lord, the sone of Dauid, haue merci on vs.", "rotherham": "and lo! two blind men, sitting beside the road, hearing that Jesus was passing by, cried aloud saying—Lord! have mercy on us! Son of David!", "weymouth": "two blind men sitting by the roadside heard that it was Jesus who was passing by, and cried aloud, \"Sir, Son of David, pity us.\"", "darby": "And lo, two blind men, sitting by the wayside, having heard that Jesus was passing by, cried out saying, Have mercy on us, Lord, Son of David.", "twenty": "Two blind men who were sitting by the road-side, hearing that Jesus was passing, called out: “Take pity on us, Master, Son of David!”", "acv": "And behold, two blind men sitting by the wayside, having heard that Jesus was passing by, cried out, saying, Be merciful to us, Lord, thou son of David.", "anderson": "And behold, two blind men, sitting by the road, when they heard that Jesus was passing by, cried out, saying: Have mercy on us, Lord, son of David.", "haweis": "And, behold, two blind men sat by the road side, who hearing that Jesus was passing by, cried out, saying, Have mercy on us, O Lord, son of David!", "noyes": "And lo! two blind men, who were sitting by the way-side, when they heard that Jesus was passing by, cried out, saying, Have pity on us, Son of David!", "webster": "And behold, two blind men sitting by the way-side, when they heard that Jesus passed by, cried out, saying, Have mercy on us, O Lord, [thou] son of David.", "vulgate": "et ecce duo caeci sedentes secus viam audierunt quia Iesus transiret et clamaverunt dicentes Domine miserere nostri Fili David;"}}, {"v": 31, "ref": "20:31", "o": "ὁ δὲ ὄχλος ἐπετίμησεν αὐτοῖς ἵνα σιωπήσωσιν· οἱ δὲ μεῖζον ⸀ἔκραξαν λέγοντες· ⸂Κύριε, ἐλέησον ἡμᾶς⸃, ⸀υἱὸς Δαυίδ.", "en": {"kjv": "And the multitude rebuked them, because they should hold their peace: but they cried the more, saying, Have mercy on us, O Lord, thou Son of David.", "web": "The multitude rebuked them, telling them that they should be quiet, but they cried out even more, “Lord, have mercy on us, you son of David!”", "bsb": "The crowd admonished them to be silent, but they cried out all the louder, “Lord, Son of David, have mercy on us!”", "asv": "And the multitude rebuked them, that they should hold their peace: but they cried out the more, saying, Lord, have mercy on us, thou son of David.", "ylt": "And the multitude charged them that they might be silent, and they cried out the more, saying, `Deal kindly with us sir--Son of David.'", "tyndale": "And ye people rebuked them be cause they shulde holde their peace. But they cryed ye moare sayinge: have mercy on vs thou Lorde which arte ye sonne of David.", "dra": "And the multitude rebuked them that they should hold their peace. But they cried out the more, saying: O Lord, thou son of David, have mercy on us.", "bbe": "And the people gave them orders to be quiet; but they went on crying even louder, Lord, Son of David, have mercy on us.", "geneva": "And the multitude rebuked them, because they should holde their peace: but they cried the more, saying, O Lord, the Sonne of Dauid, haue mercie on vs.", "wycliffe": "And the puple blamede hem, that thei schulden be stille; and thei crieden the more, and seiden, Lord, the sone of Dauid, haue merci on vs.", "rotherham": "But the multitude rebuked them, that they might hold their peace. But, they, the more, cried aloud, saying—Lord, have mercy on us! Son of David!", "weymouth": "The people angrily tried to silence them, but they cried all the louder. \"O Sir, Son of David, pity us,\" they said.", "darby": "But the crowd rebuked them, that they might be silent. But they cried out the more, saying, Have mercy on us, Lord, Son of David.", "twenty": "The crowd told them to be quiet; but the men only called out the louder: “Take pity on us, Master, Son of David!”", "acv": "And the multitude rebuked them, so that they would be quiet, but they cried out greater, saying, Be merciful to us, Lord, thou son of David.", "anderson": "And the multitude charged them to be silent. But they cried the more, saying: Have mercy on us, Lord, son of David.", "haweis": "And the multitude checked them, that they should be silent; but they cried out the more, Have mercy on us, Lord, son of David.", "noyes": "And the multitude sharply bade them be silent. But they cried out the more, saying, Lord, have pity on us, Son of David!", "webster": "And the multitude rebuked them, that they should hold their peace: but they cried the more, saying, Have mercy on us, O Lord, [thou] son of David.", "vulgate": "turba autem increpabat eos ut tacerent at illi magis clamabant dicentes Domine miserere nostri Fili David;"}}, {"v": 32, "ref": "20:32", "o": "καὶ στὰς ὁ Ἰησοῦς ἐφώνησεν αὐτοὺς καὶ εἶπεν· Τί θέλετε ποιήσω ὑμῖν;", "en": {"kjv": "And Jesus stood still, and called them, and said, What will ye that I shall do unto you?", "web": "Jesus stood still, and called them, and asked, “What do you want me to do for you?”", "bsb": "Jesus stopped and called them. “What do you want Me to do for you?” He asked.", "asv": "And Jesus stood still, and called them, and said, What will ye that I should do unto you?", "ylt": "And having stood, Jesus called them, and said, `What will ye that I may do to you?'", "tyndale": "Then Iesus stode styll and called the and sayde: what will ye that I shulde do to you:", "dra": "And Jesus stood and called them and said: What will ye that I do to you?", "bbe": "And Jesus, stopping, sent for them, and said, What would you have me do to you?", "geneva": "Then Iesus stoode still, and called them, and said, What will ye that I should do to you?", "wycliffe": "And Jhesus stood, and clepide hem, and seide, What wolen ye, that Y do to you?", "rotherham": "And, standing still, Jesus called them, and said—What desire ye I should do for you?", "weymouth": "So Jesus stood still and called to them. \"What shall I do for you?\" He asked.", "darby": "And Jesus, having stopped, called them and said, What will ye that I shall do to you?", "twenty": "Then Jesus stopped and called them. “What do you want me to do for you?” he said.", "acv": "And having stood still, Jesus called them and said, What do ye want that I would do to you?", "anderson": "And Jesus stood still, and called them, and said: What do you wish me to do for you?", "haweis": "And Jesus standing called them, and said, What desire ye, that I should do for you?", "noyes": "And Jesus stopped, and called them, and said, What would ye have me do for you?", "webster": "And Jesus stood still, and called them, and said, What will ye that I shall do to you?", "vulgate": "et stetit Iesus et vocavit eos et ait quid vultis ut faciam vobis;"}}, {"v": 33, "ref": "20:33", "o": "λέγουσιν αὐτῷ· Κύριε, ἵνα ⸂ἀνοιγῶσιν οἱ ὀφθαλμοὶ ἡμῶν⸃.", "en": {"kjv": "They say unto him, Lord, that our eyes may be opened.", "web": "They told him, “Lord, that our eyes may be opened.”", "bsb": "“Lord,” they answered, “let our eyes be opened.”", "asv": "They say unto him, Lord, that our eyes may be opened.", "ylt": "they say to him, `Sir, that our eyes may be opened;'", "tyndale": "They sayd to him: Lorde that oure eyes maye be opened.", "dra": "They say to him: Lord, that our eyes be opened.", "bbe": "They say to him, Lord, that our eyes may be open.", "geneva": "They saide to him, Lord, that our eyes may be opened.", "wycliffe": "Thei seien to him, Lord, that oure iyen be opened.", "rotherham": "They say unto him—Lord! that, our eyes, may open.", "weymouth": "\"Sir, let our eyes be opened,\" they replied.", "darby": "They say to him, Lord, that our eyes may be opened.", "twenty": "“Master,” they replied, “we want our eyes to be opened.”", "acv": "They say to him, Lord, that our eyes may be opened.", "anderson": "They said to him: Lord, that our eyes may be opened.", "haweis": "They say unto him, Lord, that our eyes may be opened.", "noyes": "They say to him, Lord, to open our eyes.", "webster": "They say to him, Lord, that our eyes may be opened.", "vulgate": "dicunt illi Domine ut aperiantur oculi nostri;"}}, {"v": 34, "ref": "20:34", "o": "σπλαγχνισθεὶς δὲ ὁ Ἰησοῦς ἥψατο τῶν ⸀ὀμμάτων αὐτῶν, καὶ εὐθέως ⸀ἀνέβλεψαν καὶ ἠκολούθησαν αὐτῷ.", "en": {"kjv": "So Jesus had compassion on them, and touched their eyes: and immediately their eyes received sight, and they followed him.", "web": "Jesus, being moved with compassion, touched their eyes; and immediately their eyes received their sight, and they followed him.", "bsb": "Moved with compassion, Jesus touched their eyes, and at once they received their sight and followed Him.", "asv": "And Jesus, being moved with compassion, touched their eyes; and straightway they received their sight, and followed him.", "ylt": "and having been moved with compassion, Jesus touched their eyes, and immediately their eyes received sight, and they followed him.", "tyndale": "Iesus had copassion on the and touched their eyes. And immediatly their eyes receaved syght. And they folowed him.", "dra": "And Jesus having compassion on them, touched their eyes. And immediately they saw and followed him.", "bbe": "And Jesus, being moved with pity, put his fingers on their eyes: and straight away they were able to see, and went after him.", "geneva": "And Iesus mooued with compassion, touched their eyes, and immediatly their eyes receiued sight, and they followed him.", "wycliffe": "And Jhesus hadde merci on hem, and touchide her iyen; and anoon thei sayen, and sueden him.", "rotherham": "And, moved with compassion, Jesus touched their eyes,—and, straightway, they recovered sight, and followed him.", "weymouth": "Moved with compassion, Jesus touched their eyes, and immediately they regained their sight and followed Him.", "darby": "And Jesus, moved with compassion, touched their eyes; and immediately their eyes had sight restored to them, and they followed him.", "twenty": "So Jesus, moved with compassion, touched their eyes, and immediately they recovered their sight, and followed him.", "acv": "And having felt compassion, Jesus touched their eyes, and straightaway they received their sight, and followed him.", "anderson": "Jesus had compassion on them, and touched their eyes; and their eyes immediately received sight, and they followed him.", "haweis": "Then Jesus, moved with compassion, touched their eyes; and immediately their eyes recovered sight, and they followed him.", "noyes": "Then Jesus, moved with compassion, touched their eyes; and they immediately received sight, and followed him.", "webster": "So Jesus had compassion [on them], and touched their eyes: and immediately their eyes received sight, and they followed him.", "vulgate": "misertus autem eorum Iesus tetigit oculos eorum et confestim viderunt et secuti sunt eum;"}}]}, {"c": 21, "verses": [{"v": 1, "ref": "21:1", "o": "Καὶ ὅτε ἤγγισαν εἰς Ἱεροσόλυμα καὶ ἦλθον εἰς Βηθφαγὴ ⸀εἰς τὸ Ὄρος τῶν Ἐλαιῶν, τότε ⸀Ἰησοῦς ἀπέστειλεν δύο μαθητὰς", "en": {"kjv": "And when they drew nigh unto Jerusalem, and were come to Bethphage, unto the mount of Olives, then sent Jesus two disciples,", "web": "When they drew near to Jerusalem, and came to Bethsphage, to the Mount of Olives, then Jesus sent two disciples,", "bsb": "As they approached Jerusalem and came to Bethphage on the Mount of Olives, Jesus sent out two disciples,", "asv": "And when they drew nigh unto Jerusalem, and came unto Bethphage, unto the mount of Olives, then Jesus sent two disciples,", "ylt": "And when they came nigh to Jerusalem, and came to Bethphage, unto the mount of the Olives, then Jesus sent two disciples,", "tyndale": "When they drewe neye vnto Ierusalem and were come to Betphage vnto mounte olivete: then sent Iesus two of his disciples", "dra": "And when they drew nigh to Jerusalem and were come to Bethphage, unto mount Olivet, then Jesus sent two disciples,", "bbe": "And when they were near Jerusalem, and had come to Beth-phage, to the Mountain of Olives, Jesus sent two disciples,", "geneva": "And when they drewe neere to Hierusalem, and were come to Bethphage, vnto the mount of the Oliues, then sent Iesus two disciples,", "wycliffe": "And whanne Jhesus cam nyy to Jerusalem, and cam to Bethfage, at the mount of Olyuete, thanne sente he his twei disciplis, and seide to hem,", "rotherham": "And, when they drew near unto Jerusalem, and came unto Bethphage, unto the Mount of Olives, then, Jesus sent forth two disciples;", "weymouth": "When they were come near Jerusalem and had arrived at Bethphage and the Mount of Olives, Jesus sent two of the disciples on in front,", "darby": "And when they drew near to Jerusalem and came to Bethphage, at the mount of Olives, then Jesus sent two disciples,", "twenty": "When they had almost reached Jerusalem, having come as far as Bethphage, on the Mount of Olives, Jesus sent on two disciples.", "acv": "And when they came near to Jerusalem, and came to Bethsphage, to the mount of Olives, then Jesus sent two disciples,", "anderson": "And when they drew near to Jerusalem, and had come to Bethphage, to the mount of Olives, then Jesus sent two disciples,", "haweis": "AND when they drew nigh to Jerusalem, and were come to Bethphage to the mount of Olives, then Jesus sent two disciples,", "noyes": "And when they drew near to Jerusalem, and came to Bethphage at the Mount of Olives, Jesus sent two disciples,", "webster": "And when they drew nigh to Jerusalem, and had come to Bethphage, to the mount of Olives, then Jesus sent two disciples,", "vulgate": "et cum adpropinquassent Hierosolymis et venissent Bethfage ad montem Oliveti tunc Iesus misit duos discipulos;"}}, {"v": 2, "ref": "21:2", "o": "λέγων αὐτοῖς· ⸀Πορεύεσθε εἰς τὴν κώμην τὴν ⸀κατέναντι ὑμῶν, καὶ ⸀εὐθέως εὑρήσετε ὄνον δεδεμένην καὶ πῶλον μετ’ αὐτῆς· λύσαντες ⸀ἀγάγετέ μοι.", "en": {"kjv": "Saying unto them, Go into the village over against you, and straightway ye shall find an ass tied, and a colt with her: loose them, and bring them unto me.", "web": "saying to them, “Go into the village that is opposite you, and immediately you will find a donkey tied, and a colt with her. Untie them, and bring them to me.", "bsb": "saying to them, “Go into the village ahead of you, and at once you will find a donkey tied there, with her colt beside her. Untie them and bring them to Me.", "asv": "saying unto them, Go into the village that is over against you, and straightway ye shall find an ass tied, and a colt with her: loose them, and bring them unto me.", "ylt": "saying to them, `Go on to the village over-against you, and immediately ye shall find an ass bound, and a colt with her--having loosed, bring ye to me;", "tyndale": "saiynge to the. Go in to the toune that lyeth over agaynste you and anone ye shall fynde an asse bounde and her colte with her: lose them and bringe them vnto me.", "dra": "Saying to them: Go ye into the village that is over against you: and immediately you shall find an ass tied and a colt with her. Loose them and bring them to me.", "bbe": "Saying to them, Go into the little town in front of you, and straight away you will see an ass with a cord round her neck, and a young one with her; let them loose and come with them to me.", "geneva": "Saying to them, Goe into the towne that is ouer against you, and anon yee shall finde an asse bounde, and a colt with her: loose them, and bring them vnto me.", "wycliffe": "Go ye in to the castel that is ayens you, and anoon ye schulen fynde an asse tied, and a colt with hir; vntien ye, and brynge to me.", "rotherham": "saying unto them—Be going into the village that is over against you, and, straightway, ye shall find an ass, bound, and a colt with her,—loose them, and lead them unto me.", "weymouth": "saying to them, \"Go to the village you see facing you, and as you enter it you will find a she-ass tied up and a foal with her. Untie her and bring them to me.", "darby": "saying to them, Go into the village over against you, and immediately ye will find an ass tied, and a colt with it; loose [them] and lead [them] to me.", "twenty": "“Go to the village facing you,” he said, “and you will immediately find an ass tethered, with a foal by her side; untie her, and lead her here for me.", "acv": "saying to them, Go into the village opposite you, and straightaway ye will find a donkey tied, and a colt with it. Having loosed them, bring to me.", "anderson": "saying to them: Go into the village opposite to you, and immediately you will find an ass tied, and a colt with her: loose them, and bring them to me.", "haweis": "saying to them, Go into the village, which is opposite you, and immediately you will find an ass tied, and a foal with her; loose and bring them to me.", "noyes": "saying to them, Go m the village over against you, and immediately ye will find an ass tied, and a colt with her; loose and bring them to me.", "webster": "Saying to them, Go into the village over against you, and immediately ye shall find an ass tied, and a colt with her, loose [them], and bring [them] to me.", "vulgate": "dicens eis ite in castellum quod contra vos est et statim invenietis asinam alligatam et pullum cum ea solvite et adducite mihi;"}}, {"v": 3, "ref": "21:3", "o": "καὶ ἐάν τις ὑμῖν εἴπῃ τι, ἐρεῖτε ὅτι Ὁ κύριος αὐτῶν χρείαν ἔχει· ⸀εὐθὺς δὲ ⸀ἀποστελεῖ αὐτούς.", "en": {"kjv": "And if any man say ought unto you, ye shall say, The Lord hath need of them; and straightway he will send them.", "web": "If anyone says anything to you, you shall say, ‘The Lord needs them,’ and immediately he will send them.”", "bsb": "If anyone questions you, tell him that the Lord needs them, and he will send them right away.”", "asv": "And if any one say aught unto you, ye shall say, The Lord hath need of them; and straightway he will send them.", "ylt": "and if any one may say anything to you, ye shall say, that the lord hath need of them, and immediately he will send them.'", "tyndale": "And if eny man saye ought vnto you saye ye yt the lorde hath neade of them: and streyght waye he will let them go.", "dra": "And if any man shall say anything to you, say ye that the Lord hath need of them. And forthwith he will let them go.", "bbe": "And if anyone says anything to you, you will say, The Lord has need of them; and straight away he will send them.", "geneva": "And if any man say ought vnto you, say ye, that the Lord hath neede of them, and straightway he will let them goe.", "wycliffe": "And if ony man seie to you ony thing, seie ye, that the Lord hath nede to hem; and anoon he schal leeue hem.", "rotherham": "And, if anyone, unto you, say aught, ye shall say—Their Lord, hath, need,—and, straightway, he will send them.", "weymouth": "And if any one says anything to you, say, `The Master needs them,' and he will at once send them.\"", "darby": "And if any one say anything to you, ye shall say, The Lord has need of them, and straightway he will send them.", "twenty": "And, if any one says anything to you, you are to say this — ‘The Master wants them’; and he will send them at once.”", "acv": "And if any man says anything to you, ye will say, The Lord has need of them, and straightaway he will send them.", "anderson": "And if any one say any thing to you, you shall reply: The Lord has need of them: and he will immediately send them.", "haweis": "And if any man say aught to you, ye shall tell them, That the Lord hath need of them, and immediately he will send them.", "noyes": "And if any one say aught to you, ye shall say, The Lord hath need of them; and he will immediately send them.", "webster": "And if any [man] shall say aught to you, ye shall say, The Lord hath need of them; and immediately he will send them.", "vulgate": "et si quis vobis aliquid dixerit dicite quia Dominus his opus habet et confestim dimittet eos;"}}, {"v": 4, "ref": "21:4", "o": "Τοῦτο ⸀δὲ γέγονεν ἵνα πληρωθῇ τὸ ῥηθὲν διὰ τοῦ προφήτου λέγοντος·", "en": {"kjv": "All this was done, that it might be fulfilled which was spoken by the prophet, saying,", "web": "All this was done, that it might be fulfilled which was spoken through the prophet, saying,", "bsb": "This took place to fulfill what was spoken through the prophet:", "asv": "Now this is come to pass, that it might be fulfilled which was spoken through the prophet, saying,", "ylt": "And all this came to pass, that it might be fulfilled that was spoken through the prophet, saying,", "tyndale": "All this was done to fulfyll that which was spoken by the Prophet sayinge:", "dra": "Now all this was done that it might be fulfilled which was spoken by the prophet, saying:", "bbe": "Now this took place so that these words of the prophet might come true,", "geneva": "All this was done that it might be fulfilled, which was spoken by the Prophet, saying,", "wycliffe": "Al this was doon, that that thing schulde be fulfillid, that was seid bi the prophete, seiynge, Seie ye to the douyter of Syon, Lo!", "rotherham": "But, this, hath come to pass, that it might be fulfilled, which was spoken through the prophet, saying:", "weymouth": "This took place in order that the Prophet's prediction might be fulfilled:", "darby": "But all this came to pass, that that might be fulfilled which was spoken through the prophet, saying,", "twenty": "This happened in fulfilment of these words in the Prophet —", "acv": "Now all this came to pass, so that what was spoken through the prophet might be fulfilled, which says,", "anderson": "All this was done, that the word might be fulfilled which was spoken by the prophet, saying:", "haweis": "Now this was entirely done, that what was spoken by the prophet might be fulfilled, saying,", "noyes": "Now this took place, that it might be fulfilled which was spoken through the prophet, saying,", "webster": "All this was done, that it might be fulfilled which was spoken by the prophet, saying,", "vulgate": "hoc autem factum est ut impleretur quod dictum est per prophetam dicentem;"}}, {"v": 5, "ref": "21:5", "o": "Εἴπατε τῇ θυγατρὶ Σιών· Ἰδοὺ ὁ βασιλεύς σου ἔρχεταί σοι πραῢς καὶ ἐπιβεβηκὼς ἐπὶ ὄνον καὶ ⸀ἐπὶ πῶλον υἱὸν ὑποζυγίου.", "en": {"kjv": "Tell ye the daughter of Sion, Behold, thy King cometh unto thee, meek, and sitting upon an ass, and a colt the foal of an ass.", "web": "“Tell the daughter of Zion, behold, your King comes to you, humble, and riding on a donkey, on a colt, the foal of a donkey.”", "bsb": "“Say to the Daughter of Zion, ‘See, your King comes to you, gentle and riding on a donkey, on a colt, the foal of a donkey.’”", "asv": "Tell ye the daughter of Zion, Behold, thy King cometh unto thee, Meek, and riding upon an ass, And upon a colt the foal of an ass.", "ylt": "`Tell ye the daughter of Zion, Lo, thy king doth come to thee, meek, and mounted on an ass, and a colt, a foal of a beast of burden.'", "tyndale": "Tell ye the doughter of Sion: beholde thy kynge cometh vnto the meke and sittinge vpon an asse and a colte the fole of an asse vsed to the yooke.", "dra": "Tell ye the daughter of Sion: Behold thy king cometh to thee, meek and sitting upon an ass and a colt, the foal of her that is used to the yoke.", "bbe": "Say to the daughter of Zion, See, your King comes to you, gentle and seated on an ass, and on a young ass.", "geneva": "Tell ye the daughter of Sion, Beholde, thy King commeth vnto thee, meeke and sitting vpon an asse, and a colte, the foale of an asse vsed to the yoke.", "wycliffe": "thi kyng cometh to thee, meke, sittynge on an asse, and a fole of an asse vnder yok.", "rotherham": "Tell ye the daughter of Zion, Lo! thy King, is coming unto thee, meek and mounted upon an ass, and upon a colt the foal of a toiling ass.", "weymouth": "\"Tell the Daughter of Zion, `See, thy King is coming to thee, gentle, and yet mounted on an ass, even on a colt the foal of a beast of burden.'\"", "darby": "Say to the daughter of Zion, Behold thy King cometh to thee, meek, and mounted upon an ass, and upon a colt the foal of an ass.", "twenty": "‘Say to the daughter of Zion — “Behold, thy King is coming to thee, Gentle, and riding on an ass, and on the foal of a beast of burden.”’", "acv": "Say ye to the daughter of Zion, Behold, thy King comes to thee, meek, and mounted upon a donkey, and a colt the foal of a pack animal.", "anderson": "Say you to the daughter of Zion, Behold, your king comes to you, meek, and sitting upon an ass, and a colt the foal of an ass.", "haweis": "“Tell the daughter of Sion, Lo! thy King cometh to thee, meek, and sitting on an ass, even on a foal the ass’s colt.”", "noyes": "\"Say to the daughter of Zion, Behold, thy king cometh to thee, meek, and riding on an ass, and on a colt the foal of a beast of burden.\"", "webster": "Tell ye the daughter of Sion, Behold, thy King cometh to thee, meek, and sitting upon an ass, and a colt the foal of an ass.", "vulgate": "dicite filiae Sion ecce rex tuus venit tibi mansuetus et sedens super asinam et pullum filium subiugalis;"}}, {"v": 6, "ref": "21:6", "o": "πορευθέντες δὲ οἱ μαθηταὶ καὶ ποιήσαντες καθὼς ⸀συνέταξεν αὐτοῖς ὁ Ἰησοῦς", "en": {"kjv": "And the disciples went, and did as Jesus commanded them,", "web": "The disciples went, and did just as Jesus commanded them,", "bsb": "So the disciples went and did as Jesus had directed them.", "asv": "And the disciples went, and did even as Jesus appointed them,", "ylt": "And the disciples having gone and having done as Jesus commanded them,", "tyndale": "The disciples went and dyd as Iesus comaunded them", "dra": "And the disciples going, did as Jesus commanded them.", "bbe": "And the disciples went and did as Jesus had given them orders,", "geneva": "So the disciples went, and did as Iesus had commanded them,", "wycliffe": "And the disciplis yeden, and diden as Jhesus comaundide hem.", "rotherham": "And the disciples, went, and did as Jesus directed them;", "weymouth": "So the disciples went and did as Jesus had instructed them:", "darby": "But the disciples, having gone and done as Jesus had ordered them,", "twenty": "So the disciples went and did as Jesus had directed them.", "acv": "And the disciples having gone, and having done as Jesus commanded them,", "anderson": "And the disciples went and did as Jesus commanded them;", "haweis": "Then the disciples going, and doing as Jesus had commanded them,", "noyes": "And the disciples o went, and did as Jesus bade them,", "webster": "And the disciples went, and did as Jesus commanded them,", "vulgate": "euntes autem discipuli fecerunt sicut praecepit illis Iesus;"}}, {"v": 7, "ref": "21:7", "o": "ἤγαγον τὴν ὄνον καὶ τὸν πῶλον, καὶ ἐπέθηκαν ⸀ἐπ’ αὐτῶν τὰ ⸀ἱμάτια, καὶ ἐπεκάθισεν ἐπάνω αὐτῶν.", "en": {"kjv": "And brought the ass, and the colt, and put on them their clothes, and they set him thereon.", "web": "and brought the donkey and the colt, and laid their clothes on them; and he sat on them.", "bsb": "They brought the donkey and the colt and laid their cloaks on them, and Jesus sat on them.", "asv": "and brought the ass, and the colt, and put on them their garments; and he sat thereon.", "ylt": "brought the ass and the colt, and did put on them their garments, and set him upon them;", "tyndale": "and brought ye asse and the colte and put on them their clothes and set him theron.", "dra": "And they brought the ass and the colt and laid their garments upon them and made him sit thereon.", "bbe": "And got the ass and the young one, and put their clothing on them, and he took his seat on it.", "geneva": "And brought the asse and the colt, and put on them their clothes, and set him thereon.", "wycliffe": "And thei brouyten an asse, and the fole, and leiden her clothis on hem, and maden hym sitte aboue.", "rotherham": "and led the ass and the colt, and laid upon them their garments, and he took his seat upon them.", "weymouth": "they brought the she-ass and the foal, and threw their outer garments on them. So He sat on them;", "darby": "brought the ass and the colt and put their garments upon them, and he sat on them.", "twenty": "They led the ass and the foal back, and, when they had put their cloaks on them, he seated himself upon them.", "acv": "they brought the donkey and the colt, and put their garments over them. And he sat upon them.", "anderson": "and brought the ass and the colt, and put their mantles on them, and caused him to sit upon them.", "haweis": "brought the ass and her foal, and they spread over them their garments, and seated him upon them.", "noyes": "and brought the ass and the colt, and put on them their garments, and he sat on them.", "webster": "And brought the ass and the colt, and put on them their clothes, and they set [him] thereon.", "vulgate": "et adduxerunt asinam et pullum et inposuerunt super eis vestimenta sua et eum desuper sedere fecerunt;"}}, {"v": 8, "ref": "21:8", "o": "ὁ δὲ πλεῖστος ὄχλος ἔστρωσαν ἑαυτῶν τὰ ἱμάτια ἐν τῇ ὁδῷ, ἄλλοι δὲ ἔκοπτον κλάδους ἀπὸ τῶν δένδρων καὶ ἐστρώννυον ἐν τῇ ὁδῷ.", "en": {"kjv": "And a very great multitude spread their garments in the way; others cut down branches from the trees, and strawed them in the way.", "web": "A very great multitude spread their clothes on the road. Others cut branches from the trees, and spread them on the road.", "bsb": "A massive crowd spread their cloaks on the road, while others cut branches from the trees and spread them on the road.", "asv": "And the most part of the multitude spread their garments in the way; and others cut branches from the trees, and spread them in the way.", "ylt": "and the very great multitude spread their own garments in the way, and others were cutting branches from the trees, and were strewing in the way,", "tyndale": "And many of the people spreed their garmentes in ye waye. Other cut doune braunches fro the trees and strawed them in the waye.", "dra": "And a very great multitude spread their garments in the way: and others cut boughs from the trees and strewed them in the way.", "bbe": "And all the people put their clothing down in the way; and others got branches from the trees, and put them down in the way.", "geneva": "And a great multitude spred their garments in the way: and other cut downe branches from the trees, and strawed them in the way.", "wycliffe": "And ful myche puple strewiden her clothis in the weie; othere kittiden braunchis of trees, and strewiden in the weie.", "rotherham": "And, the chief multitude, spread their own mantles in the way, and, others, were cutting off young branches from the trees, and spreading them in the way;", "weymouth": "and most of the crowd kept spreading their garments along the road, while others cut branches from the trees and carpeted the road with them,", "darby": "But a very great crowd strewed their own garments on the way, and others kept cutting down branches from the trees and strewing them on the way.", "twenty": "The immense crowd of people spread their cloaks in the road, while some cut branches off the trees, and spread them on the road.", "acv": "And the great multitude spread their garments on the road, and others cut down branches from the trees, and spread them on the road.", "anderson": "And a very great multitude spread their mantles in the road: and others cut branches from the trees, and spread them in the road.", "haweis": "And a vast multitude spread their garments on the road, and others cut down branches from the trees, and strewed them on the road:", "noyes": "And very many of the multitude spread their garments in the road; others cut down branches from the trees, and strewed them in the road.", "webster": "And a very great multitude spread their garments in the way; others cut down branches from the trees, and strewed [them] in the way.", "vulgate": "plurima autem turba straverunt vestimenta sua in via alii autem caedebant ramos de arboribus et sternebant in via;"}}, {"v": 9, "ref": "21:9", "o": "οἱ δὲ ὄχλοι οἱ προάγοντες ⸀αὐτὸν καὶ οἱ ἀκολουθοῦντες ἔκραζον λέγοντες· Ὡσαννὰ τῷ υἱῷ Δαυίδ· Εὐλογημένος ὁ ἐρχόμενος ἐν ὀνόματι κυρίου· Ὡσαννὰ ἐν τοῖς ὑψίστοις.", "en": {"kjv": "And the multitudes that went before, and that followed, cried, saying, Hosanna to the Son of David: Blessed is he that cometh in the name of the Lord; Hosanna in the highest.", "web": "The multitudes who went before him, and who followed kept shouting, “Hosanna to the son of David! Blessed is he who comes in the name of the Lord! Hosanna in the highest!”", "bsb": "The crowds that went ahead of Him and those that followed were shouting: “Hosanna to the Son of David!” “Blessed is He who comes in the name of the Lord!” “Hosanna in the highest!”", "asv": "And the multitudes that went before him, and that followed, cried, saying, Hosanna to the son of David: Blessed is he that cometh in the name of the Lord; Hosanna in the highest.", "ylt": "and the multitudes who were going before, and who were following, were crying, saying, `Hosanna to the Son of David, blessed is he who is coming in the name of the Lord; Hosanna in the highest.'", "tyndale": "Moreover the people that went before and they also that came after cryed sayinge: Hosanna to ye sonne of David. Blessed be he that cometh in the name of the Lorde Hosanna in the hyest.", "dra": "And the multitudes that went before and that followed cried, saying: Hosanna to the son of David: Blessed is he that cometh in the name of the Lord: Hosanna in the highest.", "bbe": "And those who went before him, and those who came after, gave loud cries, saying, Glory to the Son of David: A blessing on him who comes in the name of the Lord: Glory in the highest.", "geneva": "Moreouer, the people that went before, and they also that followed, cried, saying, Hosanna to the Sonne of Dauid, Blessed be hee that commeth in the Name of the Lord, Hosanna thou which art in the highest heauens.", "wycliffe": "And the puple that wente bifore, and that sueden, crieden, and seiden, Osanna to the sone of Dauid; blessid is he that cometh in the name of the Lord; Osanna in hiy thingis.", "rotherham": "and the multitudes, they who were going before him and they who were following after, were crying aloud, saying—Hosanna! to the Son of David, Blessed is he that is coming in the name of the Lord, Hosanna in the highest.", "weymouth": "and the multitudes--some of the people preceding Him and some following--sang aloud, \"God save the Son of David! Blessings on Him who comes in the Lord's name! God in the highest Heavens save Him!\"", "darby": "And the crowds who went before him and who followed cried, saying, Hosanna to the Son of David; blessed [be] he who comes in the name of [the] Lord; hosanna in the highest.", "twenty": "The crowds that led the way, as well as those that followed behind, kept shouting: “God save the Son of David! Blessed is he who comes in the name of the Lord! God save him from on high!”", "acv": "And the multitudes who went ahead and those who followed, cried out, saying, Hosanna to the son of David! Blessed is he who comes in the name of the Lord. Hosanna in the highest!", "anderson": "And the multitudes that went before, and that followed after, cried, saying: Hosanna to the son of David. Blessed is he that comes in the name of the Lord. Hosanna in the highest.", "haweis": "and the multitudes who went before, and who followed after, cried, saying, Hosanna, to the son of David; blessed is he who cometh in the name of the Lord: Hosanna in the highest.", "noyes": "And the multitudes that went before him, and that followed, were crying out, saying, Hosanna to the Son of David! Blessed is he that cometh in the name of the Lord! Hosanna in the highest heavens!", "webster": "And the multitudes that went before, and that followed, cried, saying, Hosanna to the son of David: blessed [is] he that cometh in the name of the Lord: Hosanna in the highest.", "vulgate": "turbae autem quae praecedebant et quae sequebantur clamabant dicentes osanna Filio David benedictus qui venturus est in nomine Domini osanna in altissimis;"}}, {"v": 10, "ref": "21:10", "o": "καὶ εἰσελθόντος αὐτοῦ εἰς Ἱεροσόλυμα ἐσείσθη πᾶσα ἡ πόλις λέγουσα· Τίς ἐστιν οὗτος;", "en": {"kjv": "And when he was come into Jerusalem, all the city was moved, saying, Who is this?", "web": "When he had come into Jerusalem, all the city was stirred up, saying, “Who is this?”", "bsb": "When Jesus had entered Jerusalem, the whole city was stirred and asked, “Who is this?”", "asv": "And when he was come into Jerusalem, all the city was stirred, saying, Who is this?", "ylt": "And he having entered into Jerusalem, all the city was moved, saying, `Who is this?'", "tyndale": "And when he was come in to Ierusalem all the cyte was moved sayinge: who is this?", "dra": "And when he was come into Jerusalem, the whole city was moved, saying: Who is this?", "bbe": "And when he came into Jerusalem, all the town was moved, saying, Who is this?", "geneva": "And when he was come into Hierusalem, all the citie was mooued, saying, Who is this?", "wycliffe": "And whanne he was entrid in to Jerusalem, al the citee was stirid, and seide, Who is this?", "rotherham": "And, when he entered into Jerusalem, all the city was startled, saying—Who is this?", "weymouth": "When He thus entered Jerusalem, the whole city was thrown into commotion, every one inquiring, \"Who is this?\"", "darby": "And as he entered into Jerusalem, the whole city was moved, saying, Who is this?", "twenty": "When he had entered Jerusalem, the whole city was stirred, and asked —", "acv": "And when he entered into Jerusalem, all the city was shaken, saying, Who is this?", "anderson": "And when he entered Jerusalem, all the city was moved, and said: Who is this?", "haweis": "And when he was entered into Jerusalem, the whole city was in commotion, saying, Who is this?", "noyes": "And when he came into Jerusalem, the whole city was in commotion, saying, Who is this?", "webster": "And when he had come into Jerusalem, all the city was moved, saying, Who is this?", "vulgate": "et cum intrasset Hierosolymam commota est universa civitas dicens quis est hic;"}}, {"v": 11, "ref": "21:11", "o": "οἱ δὲ ὄχλοι ἔλεγον· Οὗτός ἐστιν ⸂ὁ προφήτης Ἰησοῦς⸃ ὁ ἀπὸ Ναζαρὲθ τῆς Γαλιλαίας.", "en": {"kjv": "And the multitude said, This is Jesus the prophet of Nazareth of Galilee.", "web": "The multitudes said, “This is the prophet, Jesus, from Nazareth of Galilee.”", "bsb": "The crowds replied, “This is Jesus, the prophet from Nazareth in Galilee.”", "asv": "And the multitudes said, This is the prophet, Jesus, from Nazareth of Galilee.", "ylt": "And the multitudes said, `This is Jesus the prophet, who is from Nazareth of Galilee.'", "tyndale": "And the people sayde: this is Iesus the Prophet of Nazareth a cyte of Galile.", "dra": "And the people said: This is Jesus, the prophet from Nazareth of Galilee.", "bbe": "And the people said, This is the prophet Jesus, from Nazareth of Galilee.", "geneva": "And the people said, This is Iesus that Prophet of Nazareth in Galile.", "wycliffe": "But the puple seide, This is Jhesus, the prophete, of Nazareth of Galilee.", "rotherham": "And, the multitudes, were saying—This, is the prophet Jesus,—He from Nazareth of Galilee.", "weymouth": "\"This is Jesus, the Prophet, from Nazareth in Galilee,\" replied the crowds.", "darby": "And the crowds said, This is Jesus the prophet who is from Nazareth of Galilee.", "twenty": "“Who is this?”, to which the crowd replied — “This is the Prophet Jesus from Nazareth in Galilee.”", "acv": "And the multitudes said, This is Jesus, the prophet from Nazareth of Galilee.", "anderson": "And the multitude said: This is Jesus the prophet, that is from Nazareth of Galilee.", "haweis": "Then the multitudes said, This is Jesus, the prophet, who is from Nazareth of Galilee.", "noyes": "And the multitudes said, This is the prophet Jesus, from Nazareth of Galilee.", "webster": "And the multitude said, This is Jesus the prophet of Nazareth of Galilee.", "vulgate": "populi autem dicebant hic est Iesus propheta a Nazareth Galilaeae;"}}, {"v": 12, "ref": "21:12", "o": "Καὶ εἰσῆλθεν ⸀Ἰησοῦς εἰς τὸ ⸀ἱερόν, καὶ ἐξέβαλεν πάντας τοὺς πωλοῦντας καὶ ἀγοράζοντας ἐν τῷ ἱερῷ καὶ τὰς τραπέζας τῶν κολλυβιστῶν κατέστρεψεν καὶ τὰς καθέδρας τῶν πωλούντων τὰς περιστεράς,", "en": {"kjv": "And Jesus went into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the moneychangers, and the seats of them that sold doves,", "web": "Jesus entered into the temple of God, and drove out all of those who sold and bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves.", "bsb": "Then Jesus entered the temple courts and drove out all who were buying and selling there. He overturned the tables of the money changers and the seats of those selling doves.", "asv": "And Jesus entered into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the money-changers, and the seats of them that sold the doves;", "ylt": "And Jesus entered into the temple of God, and did cast forth all those selling and buying in the temple, and the tables of the money-changers he overturned, and the seats of those selling the doves,", "tyndale": "And Iesus went in to the temple of God and cast out all them that soulde and bought in the temple and overthrew the tables of the mony chaugers and the seates of them that solde doves", "dra": "And Jesus went into the temple of God and cast out all them that sold and bought in the temple and overthrew the tables of the money changers and the chairs of them that sold doves.", "bbe": "And Jesus went into the Temple and sent out all who were trading there, overturning the tables of the money-changers and the seats of those trading in doves.", "geneva": "And Iesus went into the Temple of God, and cast out all them that solde and bought in the Temple, and ouerthrew the tables of the money chagers, and the seates of them that sold doues,", "wycliffe": "And Jhesus entride in to the temple of God, and castide out of the temple alle that bouyten and solden; and he turnede vpsedoun the bordis of chaungeris, and the chayeris of men that solden culueris.", "rotherham": "And Jesus entered into the temple, and cast out all who were selling and buying in the temple,—and, the tables of the money-changers, he overthrew, and the seats of them who were selling doves;", "weymouth": "Entering the Temple, Jesus drove out all who were buying and selling there, and overturned the money-changers' tables and the seats of the pigeon-dealers.", "darby": "And Jesus entered into the temple [ofGod], and cast out all that sold and bought in the temple, and overthrew the tables of the money-changers and the seats of those that sold the doves.", "twenty": "Jesus went into the Temple Courts, and drove out all those who were buying and selling there. He overturned the tables of the money-changers, and the seats of the pigeon-dealers,", "acv": "And Jesus entered into the temple of God, and cast out all those who sold and bought in the temple. And he overturned the tables of the moneychangers, and the seats of those who sold the doves.", "anderson": "And Jesus went into the temple of God, and drove out all that sold and bought in the temple, and overthrew the tables of the money-changers, and the seats of those who sold doves,", "haweis": "And Jesus entered into the temple of God, and cast out all those who sold and bought in the temple, and overturned the tables of the money-changers, and the seats of those who sold doves", "noyes": "And Jesus went into the temple of God, and cast out all those who sold and bought in the temple, and overturned the tables of the money-changers, and the seats of those who sold the doves;", "webster": "And Jesus went into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the money-changers, and the seats of them that sold doves.", "vulgate": "et intravit Iesus in templum Dei et eiciebat omnes vendentes et ementes in templo et mensas nummulariorum et cathedras vendentium columbas evertit;"}}, {"v": 13, "ref": "21:13", "o": "καὶ λέγει αὐτοῖς· Γέγραπται· Ὁ οἶκός μου οἶκος προσευχῆς κληθήσεται, ὑμεῖς δὲ αὐτὸν ⸀ποιεῖτε σπήλαιον λῃστῶν.", "en": {"kjv": "And said unto them, It is written, My house shall be called the house of prayer; but ye have made it a den of thieves.", "web": "He said to them, “It is written, ‘My house shall be called a house of prayer,’but you have made it a den of robbers!”", "bsb": "And He declared to them, “It is written: ‘My house will be called a house of prayer.’ But you are making it ‘a den of robbers.’”", "asv": "and he saith unto them, It is written, My house shall be called a house of prayer: but ye make it a den of robbers.", "ylt": "and he saith to them, `It hath been written, My house a house of prayer shall be called, but ye did make it a den of robbers.'", "tyndale": "and sayde to them: It is wrytten my housse shalbe called the housse of prayer. But ye have made it a denne of theves.", "dra": "And he saith to them: It is written, My house shall be called the house of prayer; but you have made it a den of thieves.", "bbe": "And he said to them, It is in the Writings, My house is to be named a house of prayer, but you are making it a hole of thieves.", "geneva": "And said to them, it is written, My house shall be called the house of prayer: but ye haue made it a denne of theeues.", "wycliffe": "And he seith to hem, It is writun, Myn hous schal be clepid an hous of preier; but ye han maad it a denne of theues.", "rotherham": "and saith unto them—It is written, My house, a house of prayer, shall be called; but, ye, are making it, A den of robbers!", "weymouth": "\"It is written,\" He said, \"`My House shall be called the House of Prayer', but you are making it a robbers' cave.\"", "darby": "And he says to them, It is written, My house shall be called a house of prayer, but ye have made it a den of robbers.", "twenty": "and said to them: “Scripture says ‘My House shall be called a house of prayer’; but you are making it ‘a den of robbers.’”", "acv": "And he says to them, It is written, My house will be called a house of prayer, but ye made it a den of robbers.", "anderson": "and said to them: It is written, My house shall be called a house of prayer; but you have made it a den of robbers.", "haweis": "and said unto them, It is written, “My house shall be called a house of prayer,” but ye have made it a den of robbers.", "noyes": "and said to them, It is written, \"My house shall be called a house of prayer; but ye make it a den of robbers.\"", "webster": "And said to them, It is written, My house shall be called the house of prayer, but ye have made it a den of thieves.", "vulgate": "et dicit eis scriptum est domus mea domus orationis vocabitur vos autem fecistis eam speluncam latronum;"}}, {"v": 14, "ref": "21:14", "o": "Καὶ προσῆλθον αὐτῷ ⸂τυφλοὶ καὶ χωλοὶ⸃ ἐν τῷ ἱερῷ, καὶ ἐθεράπευσεν αὐτούς.", "en": {"kjv": "And the blind and the lame came to him in the temple; and he healed them.", "web": "The blind and the lame came to him in the temple, and he healed them.", "bsb": "The blind and the lame came to Him at the temple, and He healed them.", "asv": "And the blind and the lame came to him in the temple; and he healed them.", "ylt": "And there came to him blind and lame men in the temple, and he healed them,", "tyndale": "And the blinde and the halt came to him in ye teple and he healed the.", "dra": "And there came to him the blind and the lame in the temple: and he healed them.", "bbe": "And the blind and the broken in body came to him in the Temple, and he made them well.", "geneva": "Then the blinde, and the halt came to him in the Temple, and he healed them.", "wycliffe": "And blynde and crokid camen to hym in the temple, and he heelide hem.", "rotherham": "And there came unto him blind and lame, in the temple, and he cured them.", "weymouth": "And the blind and the lame came to Him in the Temple, and He cured them.", "darby": "And blind and lame came to him in the temple, and he healed them.", "twenty": "While he was still in the Temple Courts, some blind and some lame people came up to him, and he cured them.", "acv": "And the lame and the blind came to him in the temple, and he healed them.", "anderson": "And the blind and the lame came to him in the temple, and he cured them.", "haweis": "Then the blind and the lame came unto him, into the temple, and he cured them.", "noyes": "And the blind and lame came to him in the temple, and he cured them.", "webster": "And the blind and the lame came to him in the temple; and he healed them.", "vulgate": "et accesserunt ad eum caeci et claudi in templo et sanavit eos;"}}, {"v": 15, "ref": "21:15", "o": "ἰδόντες δὲ οἱ ἀρχιερεῖς καὶ οἱ γραμματεῖς τὰ θαυμάσια ἃ ἐποίησεν καὶ τοὺς παῖδας ⸀τοὺς κράζοντας ἐν τῷ ἱερῷ καὶ λέγοντας· Ὡσαννὰ τῷ υἱῷ Δαυίδ ἠγανάκτησαν", "en": {"kjv": "And when the chief priests and scribes saw the wonderful things that he did, and the children crying in the temple, and saying, Hosanna to the Son of David; they were sore displeased,", "web": "But when the chief priests and the scribes saw the wonderful things that he did, and the children who were crying in the temple and saying, “Hosanna to the son of David!” they were indignant,", "bsb": "But the chief priests and scribes were indignant when they saw the wonders He performed and the children shouting in the temple courts, “Hosanna to the Son of David!”", "asv": "But when the chief priests and the scribes saw the wonderful things that he did, and the children that were crying in the temple and saying, Hosanna to the son of David; they were moved with indignation,", "ylt": "and the chief priests and the scribes having seen the wonderful things that he did, and the children crying in the temple, and saying, `Hosanna to the Son of David,' were much displeased;", "tyndale": "When the chefe prestes and scribes sawe the marveylles that he dyd and the chyldren cryinge in the teple and sayinge Hosanna to the sonne of David they disdayned", "dra": "And the chief priests and scribes, seeing the wonderful things that he did and the children crying in the temple and saying: Hosanna to the son of David, were moved with indignation,", "bbe": "But when the chief priests and the scribes saw the works of power which he did, and the children crying out in the Temple, Glory to the son of David, they were angry and said to him,", "geneva": "But when the chiefe priestes and Scribes sawe the marueiles that hee did, and the children crying in the Temple, and saying, Hosanna to the Sonne of Dauid, they disdained,", "wycliffe": "But the princis of prestis and scribis, seynge the merueilouse thingis that he dide, and children criynge in the temple, and seiynge, Osanna to the sone of Dauid, hadden indignacioun,", "rotherham": "But the Chief-priests and the Scribes, seeing, the marvels that he wrought, and the boys who were crying aloud in the temple, and saying, Hosanna to the Son of David! were greatly displeased;", "weymouth": "But when the High Priests and the Scribes saw the wonderful things that He had done and the children who were crying aloud in the Temple, \"God save the Son of David,\" they were filled with indignation.", "darby": "And when the chief priests and the scribes saw the wonders which he wrought, and the children crying in the temple and saying, Hosanna to the Son of David, they were indignant,", "twenty": "But, when the Chief Priests and the Teachers of the Law saw the wonderful things that Jesus did, and the boys who were calling out in the Temple Courts “God save the Son of David!”, they were indignant,", "acv": "But when the chief priests and the scholars saw the wonderful things that he did, and the boys crying out in the temple and saying, Hosanna to the son of David, they were indignant,", "anderson": "But when the chief priests and the scribes saw the wonderful things that he did, and the children crying in the temple, and saying, Hosanna to the son of David, their anger was aroused,", "haweis": "But when the chief priests and scribes saw the marvellous acts which he did, and the children crying out in the temple, and saying, Hosanna to the son of David; they were filled with indignation;", "noyes": "But the chief priests and the scribes, when they saw the wonderful things which he did, and the children that were crying out in the temple, and saying, Hosanna to the Son of David, were much displeased;", "webster": "And when the chief priests and scribes saw the wonderful things that he did, and the children crying in the temple, and saying, Hosanna to the son of David; they were greatly displeased,", "vulgate": "videntes autem principes sacerdotum et scribae mirabilia quae fecit et pueros clamantes in templo et dicentes osanna Filio David indignati sunt;"}}, {"v": 16, "ref": "21:16", "o": "καὶ εἶπαν αὐτῷ· Ἀκούεις τί οὗτοι λέγουσιν; ὁ δὲ Ἰησοῦς λέγει αὐτοῖς· Ναί. οὐδέποτε ἀνέγνωτε ὅτι Ἐκ στόματος νηπίων καὶ θηλαζόντων κατηρτίσω αἶνον;", "en": {"kjv": "And said unto him, Hearest thou what these say? And Jesus saith unto them, Yea; have ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?", "web": "and said to him, “Do you hear what these are saying?” Jesus said to them, “Yes. Did you never read, ‘Out of the mouth of babes and nursing babies you have perfected praise?’”", "bsb": "“Do You hear what these children are saying?” they asked. “Yes,” Jesus answered. “Have you never read: ‘From the mouths of children and infants You have ordained praise’?”", "asv": "and said unto him, Hearest thou what these are saying? And Jesus saith unto them, Yea: did ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?", "ylt": "and they said to him, `Hearest thou what these say?' And Jesus saith to them, `Yes, did ye never read, that, Out of the mouth of babes and sucklings Thou didst prepare praise?'", "tyndale": "and sayde vnto him: hearest thou what these saye? Iesus sayde vnto them yee: have ye never redde of the mouth of babes and suckelinges thou haste ordeyned prayse?", "dra": "And said to him: Hearest thou what these say? And Jesus said to them: Yea, have you never read: Out of the mouth of infants and of sucklings thou hast perfected praise?", "bbe": "Have you any idea what these are saying? And Jesus said to them, Yes: have you not seen in the Writings, From the lips of children and babies at the breast you have made your praise complete?", "geneva": "And said vnto him, Hearest thou what these say? And Iesus said vnto them, Yea: read ye neuer, By the mouth of babes and sucklings thou hast made perfite the praise?", "wycliffe": "and seiden to hym, Herist thou what these seien? And Jhesus seide to hem, Yhe; whether ye han neuer redde, That of the mouth of yonge children, and of soukynge childryn, thou hast maad perfit heriyng?", "rotherham": "and said unto him—Hearest thou what these are saying? And, Jesus, saith unto them—Yea: Have ye never read, Out of the mouth of babes and sucklings, hast thou prepared praise?", "weymouth": "\"Do you hear,\" they asked Him, \"what these children are saying?\" \"Yes,\" He replied; \"have you never read, `Out of the mouths of infants and of babes at the breast Thou hast brought forth the praise which is due'?\"", "darby": "and said to him, Hearest thou what these say? And Jesus says to them, Yea; have ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?", "twenty": "and said to him: “Do you hear what these boys are saying?” “Yes,” answered Jesus; “but did you never read the words — ‘Out of the mouths of babes and sucklings thou hast called forth perfect praise’?”", "acv": "and said to him, Do thou hear what these are saying? And Jesus says to them, Yes! Did ye never read, Out of the mouth of children and those who suckle thou have perfected praise?", "anderson": "and they said to him: Do you not hear what these say? And Jesus said to them: Yes; have you never read, Out of the mouth of babes and sucklings thou hast perfected praise?", "haweis": "and said to him, Hearest thou what these say? Jesus replied to them, Yes; but have ye never read, “That out of the mouths of infants and sucklings thou hast perfected praise?”", "noyes": "and said to him, Dost thou hear what these say? But Jesus saith to them, Yea; did ye never read, \"From the mouth of babes and sucklings thou didst prepare praise\"?", "webster": "And said to him, Hearest thou what these say? And Jesus saith to them, Yes: have ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?", "vulgate": "et dixerunt ei audis quid isti dicant Iesus autem dicit eis utique numquam legistis quia ex ore infantium et lactantium perfecisti laudem;"}}, {"v": 17, "ref": "21:17", "o": "καὶ καταλιπὼν αὐτοὺς ἐξῆλθεν ἔξω τῆς πόλεως εἰς Βηθανίαν, καὶ ηὐλίσθη ἐκεῖ.", "en": {"kjv": "And he left them, and went out of the city into Bethany; and he lodged there.", "web": "He left them, and went out of the city to Bethany, and lodged there.", "bsb": "Then He left them and went out of the city to Bethany, where He spent the night.", "asv": "And he left them, and went forth out of the city to Bethany, and lodged there.", "ylt": "And having left them, he went forth out of the city to Bethany, and did lodge there,", "tyndale": "And he lefte the and wet out of ye cite vnto Bethanie and had his abydige there.", "dra": "And leaving them, he went out of the city into Bethania and remained here.", "bbe": "And he went away from them, and went out of the town to Bethany, and was there for the night.", "geneva": "So hee left them, and went out of the citie vnto Bethania, and lodged there.", "wycliffe": "And whanne he hadde left hem, he wente forth out of the citee, in to Bethanye; and there he dwelte, and tauyte hem of the kyngdom of God.", "rotherham": "And, leaving them behind, he went forth outside the city into Bethany, and spent the night there.", "weymouth": "So He left them and went out of the city to Bethany and passed the night there.", "darby": "And leaving them he went forth out of the city to Bethany, and there he passed the night.", "twenty": "Then he left them, and went out of the city to Bethany, and spent the night there.", "acv": "And having left them behind, he went out of the city to Bethany, and lodged there.", "anderson": "And he left them, and went out of the city to Bethany, and there spent the night.", "haweis": "And turning his back upon them, he went out of the city to Bethany, and lodged there.", "noyes": "And he left them, and went out of the city to Bethany, and lodged there.", "webster": "And he left them, and went out of the city into Bethany, and he lodged there.", "vulgate": "et relictis illis abiit foras extra civitatem in Bethaniam ibique mansit;"}}, {"v": 18, "ref": "21:18", "o": "⸀Πρωῒ δὲ ⸀ἐπανάγων εἰς τὴν πόλιν ἐπείνασεν.", "en": {"kjv": "Now in the morning as he returned into the city, he hungered.", "web": "Now in the morning, as he returned to the city, he was hungry.", "bsb": "In the morning, as Jesus was returning to the city, He was hungry.", "asv": "Now in the morning as he returned to the city, he hungered.", "ylt": "and in the morning turning back to the city, he hungered,", "tyndale": "In the mornynge as he returned in to the cyte ageyne he hungred", "dra": "And in the morning, returning into the city, he was hungry.", "bbe": "Now in the morning when he was coming back to the town, he had a desire for food.", "geneva": "And in the morning, as he returned into the citie, he was hungrie,", "wycliffe": "But on the morowe, he, turnynge ayen in to the citee, hungride.", "rotherham": "And, early, returning into the city, he hungered;", "weymouth": "Early in the morning as He was on His way to return to the city He was hungry,", "darby": "But early in the morning, as he came back into the city, he hungered.", "twenty": "The next morning, in returning to the city, Jesus became hungry;", "acv": "Now early while returning to the city, he was hungry.", "anderson": "Now in the morning, as he was returning to the city, he was hungry:", "haweis": "Now in the morning, when returning into the city, he was hungry:", "noyes": "And in the morning, as he was returning to the city, he was hungry.", "webster": "Now in the morning as he was returning into the city, he was hungry.", "vulgate": "mane autem revertens in civitatem esuriit;"}}, {"v": 19, "ref": "21:19", "o": "καὶ ἰδὼν συκῆν μίαν ἐπὶ τῆς ὁδοῦ ἦλθεν ἐπ’ αὐτήν, καὶ οὐδὲν εὗρεν ἐν αὐτῇ εἰ μὴ φύλλα μόνον, καὶ λέγει αὐτῇ· ⸀Μηκέτι ἐκ σοῦ καρπὸς γένηται εἰς τὸν αἰῶνα· καὶ ἐξηράνθη παραχρῆμα ἡ συκῆ.", "en": {"kjv": "And when he saw a fig tree in the way, he came to it, and found nothing thereon, but leaves only, and said unto it, Let no fruit grow on thee henceforward for ever. And presently the fig tree withered away.", "web": "Seeing a fig tree by the road, he came to it, and found nothing on it but leaves. He said to it, “Let there be no fruit from you forever!” Immediately the fig tree withered away.", "bsb": "Seeing a fig tree by the road, He went up to it but found nothing on it except leaves. “May you never bear fruit again!” He said. And immediately the tree withered.", "asv": "And seeing a fig tree by the way side, he came to it, and found nothing thereon, but leaves only; and he saith unto it, Let there be no fruit from thee henceforward for ever. And immediately the fig tree withered away.", "ylt": "and having seen a certain fig-tree on the way, he came to it, and found nothing in it except leaves only, and he saith to it, `No more from thee may fruit be--to the age;' and forthwith the fig-tree withered.", "tyndale": "and spyed a fygge trre in the waye and came to it and founde nothinge theron but leves only and sayd to it never frute growe on the hence forwardes. And ano the fygge tree wyddered awaye.", "dra": "And seeing a certain fig tree by the way side, he came to it and found nothing on it but leaves only. And he saith to it: May no fruit grow on thee henceforward for ever. And immediately the fig tree withered away.", "bbe": "And seeing a fig-tree by the wayside, he came to it, and saw nothing on it but leaves only; and he said to it, Let there be no fruit from you from this time forward for ever. And straight away the fig-tree became dry and dead.", "geneva": "And seeing a figge tree in the way, he came to it, and found nothing thereon, but leaues onely, and said to it, Neuer fruite grow on thee henceforwards. And anon the figge tree withered.", "wycliffe": "And he saye a fige tree bisidis the weie, and cam to it, and foond no thing ther ynne but leeues oneli. And he seide to it, Neuer fruyt come forth of thee, in to with outen eende, And anoon the fige tre was dried vp.", "rotherham": "and, seeing one fig-tree by the way, he came up to it, and nothing, found he thereon, save leaves only,—and he saith unto it—No more, from thee, let fruit spring forth, unto times age-abiding,—and the fig-tree, instantly withered away.", "weymouth": "and seeing a fig-tree on the road-side He went up to it, but found nothing on it but leaves. \"On you,\" He said, \"no fruit shall ever again grow.\" And immediately the fig-tree withered away.", "darby": "And seeing one fig-tree in the way, he came to it and found on it nothing but leaves only. And he says to it, Let there be never more fruit of thee for ever. And the fig-tree was immediately dried up.", "twenty": "and, noticing a solitary fig tree by the road-side, he went up to it, but found nothing on it but leaves. So he said to it: “Never again shall fruit be gathered off you.” And suddenly the fruit tree withered up.", "acv": "And having seen a fig tree, one on the way, he came to it, and found nothing on it, except leaves only. And he says to it, Let fruit no longer be produced from thee into the age. And immediately the fig tree dried out.", "anderson": "and seeing a fig-tree on the road, he went to it, and found nothing on it but leaves; and he said to it: Let no fruit grow on you henceforth forever. And the fig-tree immediately withered.", "haweis": "and seeing a fig-tree at the road side, he went up to it, and found nothing on it but leaves only: and saith unto it, Let no fruit spring from thee henceforth for ever: and immediately the fig-tree withered entirely away.", "noyes": "And seeing one fig-tree by the road-side, he went up to it, and found nothing on it, but leaves only; and he saith to it, Let there be no fruit from thee hencefoward for ever. And immediately the fig-tree withered.", "webster": "And when he saw a fig-tree in the way, he came to it, and found nothing on it, but leaves only, and said to it, Let no fruit grow on thee henceforth for ever. And immediately the fig-tree withered.", "vulgate": "et videns fici arborem unam secus viam venit ad eam et nihil invenit in ea nisi folia tantum et ait illi numquam ex te fructus nascatur in sempiternum et arefacta est continuo ficulnea;"}}, {"v": 20, "ref": "21:20", "o": "καὶ ἰδόντες οἱ μαθηταὶ ἐθαύμασαν λέγοντες· Πῶς παραχρῆμα ἐξηράνθη ἡ συκῆ;", "en": {"kjv": "And when the disciples saw it, they marvelled, saying, How soon is the fig tree withered away!", "web": "When the disciples saw it, they marveled, saying, “How did the fig tree immediately wither away?”", "bsb": "When the disciples saw this, they marveled and asked, “How did the fig tree wither so quickly?”", "asv": "And when the disciples saw it, they marvelled, saying, How did the fig tree immediately wither away?", "ylt": "And the disciples having seen, did wonder, saying, `How did the fig-tree forthwith wither?'", "tyndale": "And when his disciples sawe that they marveled sayinge: Howe sone is the fygge tree wyddered awaye?", "dra": "And the disciples seeing it wondered, saying: How is it presently withered away?", "bbe": "And when the disciples saw it they were surprised, saying, How did the fig-tree become dry in so short a time?", "geneva": "And when his disciples saw it, they marueiled, saying, How soone is the figge tree withered!", "wycliffe": "And disciplis `sawen, and wondriden, seiynge, Hou anoon it driede.", "rotherham": "And the disciples, seeing it, marvelled, saying—How instantly, did the fig-tree wither away.", "weymouth": "When the disciples saw it they exclaimed in astonishment, \"How instantaneously the fig-tree has withered away!\"", "darby": "And when the disciples saw [it], they wondered, saying, How immediately is the fig-tree dried up!", "twenty": "When the disciples saw this, they exclaimed in astonishment: “How suddenly the fig tree withered up!”", "acv": "And when the disciples saw it, they marveled, saying, How did the fig tree dry out immediately?", "anderson": "And when the disciples saw it, they were astonished, and said: How soon has the fig-tree withered!", "haweis": "And when his disciples saw it, they marvelled, saying, How suddenly is the fig-tree withered away!", "noyes": "And the disciples seeing it, marveled, saying, How suddenly did the fig-tree wither!", "webster": "And when the disciples saw [it], they marveled, saying, How soon is the fig-tree withered!", "vulgate": "et videntes discipuli mirati sunt dicentes quomodo continuo aruit;"}}, {"v": 21, "ref": "21:21", "o": "ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Ἀμὴν λέγω ὑμῖν, ἐὰν ἔχητε πίστιν καὶ μὴ διακριθῆτε, οὐ μόνον τὸ τῆς συκῆς ποιήσετε, ἀλλὰ κἂν τῷ ὄρει τούτῳ εἴπητε· Ἄρθητι καὶ βλήθητι εἰς τὴν θάλασσαν, γενήσεται·", "en": {"kjv": "Jesus answered and said unto them, Verily I say unto you, If ye have faith, and doubt not, ye shall not only do this which is done to the fig tree, but also if ye shall say unto this mountain, Be thou removed, and be thou cast into the sea; it shall be done.", "web": "Jesus answered them, “Most certainly I tell you, if you have faith, and don’t doubt, you will not only do what was done to the fig tree, but even if you told this mountain, ‘Be taken up and cast into the sea,’ it would be done.", "bsb": "“Truly I tell you,” Jesus replied, “if you have faith and do not doubt, not only will you do what was done to the fig tree, but even if you say to this mountain, ‘Be lifted up and thrown into the sea,’ it will happen.", "asv": "And Jesus answered and said unto them, Verily I say unto you, If ye have faith, and doubt not, ye shall not only do what is done to the fig tree, but even if ye shall say unto this mountain, Be thou taken up and cast into the sea, it shall be done.", "ylt": "And Jesus answering said to them, `Verily I say to you, If ye may have faith, and may not doubt, not only this of the fig-tree shall ye do, but even if to this mount ye may say, Be lifted up and be cast into the sea, it shall come to pass;", "tyndale": "Iesus answered and sayde vnto the: Verely I saye vnto you yf ye shall have faith and shall not dout ye shall not only do that which I have done to the fygge tree: but also yf ye shall saye vnto this moutayne take thy silfe awaye and cast thy silfe into the see it shalbe done.", "dra": "And Jesus answering, said to them: Amen, I say to you, if you shall have faith and stagger not, not only this of the fig tree shall you do, but also if you shall say to this mountain, Take up and cast thyself into the sea, it shall be done.", "bbe": "And Jesus in answer said to them, Truly I say to you, If you have faith, without doubting, not only may you do what has been done to the fig-tree, but even if you say to this mountain, Be taken up and put into the sea, it will be done.", "geneva": "And Iesus answered and said vnto them, Verely I say vnto you, if ye haue faith, and doubt not, ye shall not only doe that, which I haue done to the figge tree, but also if ye say vnto this mountaine, Take thy selfe away, and cast thy selfe into the sea, it shalbe done.", "wycliffe": "And Jhesus answeride, and seide to hem, Treuli Y seie to you, if ye haue feith, and douten not, not oonli ye schulen do of the fige tree, but also if ye seyn to this hil, Take, and caste thee in to the see, it schal be don so.", "rotherham": "And Jesus, answering, said unto them—Verily, I say unto you, If ye have faith, and do not doubt, not only, this of the fig-tree, shall ye do,—but, even if, unto this mountain, ye shall say, Be lifted up, and be cast into the sea, it shall be done.", "weymouth": "\"I solemnly tell you,\" said Jesus, \"that if you have an unwavering faith, you shall not only perform such a miracle as this of the fig-tree, but that even if you say to this mountain, `Be thou lifted up and hurled into the sea,' it shall be done;", "darby": "And Jesus answering said to them, Verily I say unto you, If ye have faith, and do not doubt, not only shall ye do what [is done] to the fig-tree, but even if ye should say to this mountain, Be thou taken away and be thou cast into the sea, it shall come to pass.", "twenty": "“I tell you,” replied Jesus, “if you have faith, without ever a doubt, you will do what not only what has been done to the fig tree, but, even if you should say to this hill ‘Be lifted up and hurled into the sea!’ it would be done.", "acv": "And having answered, Jesus said to them, Truly I say to you, if ye have faith, and doubt not, ye will not only do that of the fig tree, but even if ye may say to this mountain, Be thou taken up and cast into the sea, it will happen.", "anderson": "Jesus answered and said to them: Verily I say to you, If you have faith, and doubt not, you shall do, not only what is done to the fig-tree, but even if you shall say to this mountain, Be taken up, and be thrown into the sea, it shall be done.", "haweis": "But Jesus addressing them, said, Verily I tell you, if ye have faith, and entertain no doubt, not only shall ye do what is done to the fig-tree, but if ye should even say to this mountain, Be lifted up, and be cast into the sea, it be done.", "noyes": "Jesus answering said to them, Truly do I say to you, If ye have faith, and do not doubt, not only shall ye do what hath been done to the fig-tree, but should ye even say to this mountain, Be thou taken up and cast into the sea, it would be done.", "webster": "Jesus answered and said to them, Verily I say to you, If ye have faith, and doubt not, ye shall not only do this [which is done] to the fig-tree, but also, if ye shall say to this mountain, Be thou removed, and be thou cast into the sea; it shall be done.", "vulgate": "respondens autem Iesus ait eis amen dico vobis si habueritis fidem et non haesitaveritis non solum de ficulnea facietis sed et si monti huic dixeritis tolle et iacta te in mare fiet;"}}, {"v": 22, "ref": "21:22", "o": "καὶ πάντα ὅσα ⸀ἂν αἰτήσητε ἐν τῇ προσευχῇ πιστεύοντες λήμψεσθε.", "en": {"kjv": "And all things, whatsoever ye shall ask in prayer, believing, ye shall receive.", "web": "All things, whatever you ask in prayer, believing, you will receive.”", "bsb": "If you believe, you will receive whatever you ask for in prayer.”", "asv": "And all things, whatsoever ye shall ask in prayer, believing, ye shall receive.", "ylt": "and all--as much as ye may ask in the prayer, believing, ye shall receive.'", "tyndale": "And whatsoever ye shall axe in prayer (if ye beleve) ye shall receave it.", "dra": "And all things whatsoever you shall ask in prayer believing, you shall receive.", "bbe": "And all things, whatever you make request for in prayer, having faith, you will get.", "geneva": "And whatsoeuer ye shall aske in prayer, if ye beleeue, ye shall receiue it.", "wycliffe": "And alle thingis what euere ye bileuynge schulen axe in preyer, ye schulen take.", "rotherham": "And, all things whatsoever ye shall ask in prayer, believing, ye shall receive.", "weymouth": "and everything, whatever it be, that you ask for in your prayers, if you have faith, you shall obtain.\"", "darby": "And all things whatsoever ye shall ask in prayer, believing, ye shall receive.", "twenty": "And whatever you ask for in your prayers will, if you have faith, be granted you.”", "acv": "And all things, as many as ye may ask in prayer, believing, ye will receive.", "anderson": "And all things that you ask for in prayer, believing, you shall receive.", "haweis": "And all things whatsoever ye shall ask in prayer, believing, ye shall receive.", "noyes": "And all things whatever ye shall ask in prayer, believing, ye will receive.", "webster": "And all things whatever ye shall ask in prayer, believing, ye shall receive.", "vulgate": "et omnia quaecumque petieritis in oratione credentes accipietis;"}}, {"v": 23, "ref": "21:23", "o": "Καὶ ⸂ἐλθόντος αὐτοῦ⸃ εἰς τὸ ἱερὸν προσῆλθον αὐτῷ διδάσκοντι οἱ ἀρχιερεῖς καὶ οἱ πρεσβύτεροι τοῦ λαοῦ λέγοντες· Ἐν ποίᾳ ἐξουσίᾳ ταῦτα ποιεῖς; καὶ τίς σοι ἔδωκεν τὴν ἐξουσίαν ταύτην;", "en": {"kjv": "And when he was come into the temple, the chief priests and the elders of the people came unto him as he was teaching, and said, By what authority doest thou these things? and who gave thee this authority?", "web": "When he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, “By what authority do you do these things? Who gave you this authority?”", "bsb": "When Jesus returned to the temple courts and began to teach, the chief priests and elders of the people came up to Him. “By what authority are You doing these things?” they asked. “And who gave You this authority?”", "asv": "And when he was come into the temple, the chief priests and the elders of the people came unto him as he was teaching, and said, By what authority doest thou these things? and who gave thee this authority?", "ylt": "And he having come to the temple, there came to him when teaching the chief priests and the elders of the people, saying, `By what authority dost thou do these things? and who gave thee this authority?'", "tyndale": "And when he was come into the teple the chefe prestes and the elders of the people came vnto him as he was teachinge and sayde: by what auctorite doest thou these thinges? and who gave the this power?", "dra": "And when he was come into the temple, there came to him, as he was teaching, the chief priests and ancients of the people, saying: By what authority dost thou these things? And who hath given thee this authority?", "bbe": "And when he had come into the Temple, the chief priests and those in authority over the people came to him while he was teaching, and said, By what authority do you do these things? and who gave you this authority?", "geneva": "And whe he was come into the Temple, the chiefe Priestes, and the Elders of the people came vnto him, as he was teaching, and saide, By what authoritie doest thou these things? and who gaue thee this authoritie?", "wycliffe": "And whanne he cam in to the temple, the princis of prestis and elder men of the puple camen to hym that tauyte, and seiden, In what power doist thou these thingis? and who yaf thee this power?", "rotherham": "And, when he, entered, the temple, the Chief-priests and the Elders of the people, came unto him as he was teaching, saying, By what authority, these things, art thou doing? and, who, to thee, gave, this authority?", "weymouth": "He entered the Temple; and while He was teaching, the High Priests and the Elders of the people came to Him and asked Him, \"By what authority are you doing these things? and who gave you this authority?\"", "darby": "And when he came into the temple, the chief priests and the elders of the people came to him [as he was] teaching, saying, By what authority doest thou these things? and who gave thee this authority?", "twenty": "After Jesus had come into the Temple Courts, the Chief Priests and the Councillors of the Nation came up to him as he was teaching, and said: “What authority have you to do these things? Who gave you this authority?”", "acv": "And when he came into the temple, the chief priests and the elders of the people came to him while he taught, saying, By what authority do thou these things? And who gave thee this authority?", "anderson": "And after he had come into the temple, the chief priests and elders of the people came to him as he was teaching, and said: By what authority do you these things? And who gave you this authority?", "haweis": "And when he was come into the temple, the chief priests and the elders of the people came to him, as he was teaching, demanding, By what authority doest thou these things? And who gave thee this authority?", "noyes": "And when he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, By what authority doest thou these things? And who gave thee this authority?", "webster": "And when he had come into the temple, the chief priests and the elders of the people came to him as he was teaching, and said, By what authority doest thou these things; and who gave thee this authority?", "vulgate": "et cum venisset in templum accesserunt ad eum docentem principes sacerdotum et seniores populi dicentes in qua potestate haec facis et quis tibi dedit hanc potestatem;"}}, {"v": 24, "ref": "21:24", "o": "ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Ἐρωτήσω ὑμᾶς κἀγὼ λόγον ἕνα, ὃν ἐὰν εἴπητέ μοι κἀγὼ ὑμῖν ἐρῶ ἐν ποίᾳ ἐξουσίᾳ ταῦτα ποιῶ·", "en": {"kjv": "And Jesus answered and said unto them, I also will ask you one thing, which if ye tell me, I in like wise will tell you by what authority I do these things.", "web": "Jesus answered them, “I also will ask you one question, which if you tell me, I likewise will tell you by what authority I do these things.", "bsb": "“I will also ask you one question,” Jesus replied, “and if you answer Me, I will tell you by what authority I am doing these things.", "asv": "And Jesus answered and said unto them, I also will ask you one question, which if ye tell me, I likewise will tell you by what authority I do these things.", "ylt": "And Jesus answering said to them, `I will ask you--I also--one word, which if ye may tell me, I also will tell you by what authority I do these things;", "tyndale": "Iesus answered and sayde vnto them: I also will axe of you a certayne question which if ye assoyle me I in lyke wyse wyll tell you by what auctorite I do these thinges.", "dra": "Jesus answering, said to them: I also will ask you one word, which if you shall tell me, I will also tell you by what authority I do these things.", "bbe": "And Jesus said to them in answer, I will put one question to you, and if you give me the answer, I will say by what authority I do these things.", "geneva": "Then Iesus answered and said vnto them, I also will aske of you a certaine thing, which if ye tell me, I likewise will tell you by what authoritie I doe these things.", "wycliffe": "Jhesus answeride, and seide to hem, And Y schal axe you o word, the which if ye tellen me, Y schal seie to you, in what power Y do these thingis.", "rotherham": "And, making answer, Jesus said unto them—I also, will ask, you, one thing,—which if ye tell me, I also, will tell, you, by what authority, these things, I am doing:—", "weymouth": "\"And I also have a question to ask *you*,\" replied Jesus, \"and if you answer me, I in turn will tell you by what authority I do these things.", "darby": "And Jesus answering said to them, I also will ask you one thing, which if ye tell me, I also will tell you by what authority I do these things:", "twenty": "“I, too,” said Jesus in reply, “will ask you one question; if you will give me an answer to it, then I, also, will tell you what authority I have to act as I do.", "acv": "And having answered, Jesus said to them, I also will ask you one word, which if ye tell me, I also will tell you by what authority I do these things.", "anderson": "Jesus answered and said to them: I also will ask you one thing, which if you will tell me, I also will tell you by what authority I do these things.", "haweis": "Then Jesus answering, said to them, I also will ask you one question, which if ye answer me, then will I tell you by what authority I do these things.", "noyes": "And Jesus answering said to them, I also will ask you one question; which if ye answer me, I too will tell you by what authority I do these things.", "webster": "And Jesus answered and said to them, I also will ask you one thing, which if ye tell me, I also will tell you by what authority I do these things.", "vulgate": "respondens Iesus dixit illis interrogabo vos et ego unum sermonem quem si dixeritis mihi et ego vobis dicam in qua potestate haec facio;"}}, {"v": 25, "ref": "21:25", "o": "τὸ βάπτισμα ⸀τὸ Ἰωάννου πόθεν ἦν; ἐξ οὐρανοῦ ἢ ἐξ ἀνθρώπων; οἱ δὲ διελογίζοντο ⸀ἐν ἑαυτοῖς λέγοντες· Ἐὰν εἴπωμεν· Ἐξ οὐρανοῦ, ἐρεῖ ἡμῖν· Διὰ τί οὖν οὐκ ἐπιστεύσατε αὐτῷ;", "en": {"kjv": "The baptism of John, whence was it? from heaven, or of men? And they reasoned with themselves, saying, If we shall say, From heaven; he will say unto us, Why did ye not then believe him?", "web": "The baptism of John, where was it from? From heaven or from men?” They reasoned with themselves, saying, “If we say, ‘From heaven,’ he will ask us, ‘Why then did you not believe him?’", "bsb": "What was the source of John’s baptism? Was it from heaven or from men?” They deliberated among themselves and said, “If we say, ‘From heaven,’ He will ask, ‘Why then did you not believe him?’", "asv": "The baptism of John, whence was it? from heaven or from men? And they reasoned with themselves, saying, If we shall say, From heaven; he will say unto us, Why then did ye not believe him?", "ylt": "the baptism of John, whence was it? --from heaven, or from men?' And they were reasoning with themselves, saying, `If we should say, From heaven; he will say to us, Wherefore, then, did ye not believe him?", "tyndale": "The baptime of Iohn: whence was it? fro heve or of men? Then they reasoned amoge them selves sayinge: yf we shall saye fro heven he will saye vnto vs: why dyd ye not then beleve hym?", "dra": "The baptism of John, whence was it? From heaven or from men? But they thought within themselves, saying:", "bbe": "The baptism of John, where did it come from? from heaven or from men? And they were reasoning among themselves, saying, If we say, From heaven; he will say to us, Why then did you not have faith in him?", "geneva": "The baptisme of Iohn, whence was it? from heauen, or of men? Then they reasoned among themselues, saying, If we shall say, From heauen, he will say vnto vs, Why did ye not then beleeue him?", "wycliffe": "Of whennys was the baptym of Joon; of heuene, or of men? And thei thouyten with ynne hem silf,", "rotherham": "The immersion by John, whence was it? Of heaven, or of men? But, they, began to deliberate among themselves, saying—If we say, Of heaven; He will say unto us, Wherefore then did ye not believe him?", "weymouth": "John's Baptism, whence was it? --had it a heavenly or a human origin?\" So they debated the matter among themselves. \"If we say `a heavenly origin,'\" they argued, \"he will say, `Why then did you not believe him?'", "darby": "The baptism of John, whence was it? of heaven or of men? And they reasoned among themselves, saying, If we should say, Of heaven, he will say to us, Why then have ye not believed him?", "twenty": "It is about John’s baptism. What was its origin? divine or human?” But they began arguing among themselves: “If we say ‘divine,’ he will say to us ‘Why then did not you believe him?’", "acv": "The immersion of John, from where was it, from heaven or from men? And they deliberated with themselves, saying, If we should say, From heaven, he will say to us, Why then did ye not believe him?", "anderson": "The immersion of John, whence was it? from heaven, or from men? But they reasoned among themselves, and said, If we reply, From heaven, he will say to us, Why then did you not believe him?", "haweis": "The baptism of John whence was it? from heaven, or from men? Hereupon they reasoned among themselves, saying, If we reply, From heaven, he will say to us, Why then did ye not believe him?", "noyes": "The baptism of John, whence was it? From heaven, or from men? And they reasoned among themselves, saying, If we say, From heaven, he will say to us, Why then did ye not believe him?", "webster": "The baptism of John, whence was it? from heaven, or from men? And they reasoned with themselves, saying, if we shall say, From heaven; he will say to us, Why then did ye not believe him?", "vulgate": "baptismum Iohannis unde erat e caelo an ex hominibus at illi cogitabant inter se dicentes si dixerimus e caelo dicet nobis quare ergo non credidistis illi;"}}, {"v": 26, "ref": "21:26", "o": "ἐὰν δὲ εἴπωμεν· Ἐξ ἀνθρώπων, φοβούμεθα τὸν ὄχλον, πάντες γὰρ ⸂ὡς προφήτην ἔχουσιν τὸν Ἰωάννην⸃.", "en": {"kjv": "But if we shall say, Of men; we fear the people; for all hold John as a prophet.", "web": "But if we say, ‘From men,’ we fear the multitude, for all hold John as a prophet.”", "bsb": "But if we say, ‘From men,’ we are afraid of the people, for they all regard John as a prophet.”", "asv": "But if we shall say, From men; we fear the multitude; for all hold John as a prophet.", "ylt": "and if we should say, From men, we fear the multitude, for all hold John as a prophet.'", "tyndale": "But and if we shall saye of men then feare we the people. For all men helde Iohn as a Prophet.", "dra": "If we shall say, from heaven, he will say to us: Why then did you not believe him? But if we shall say, from men, we are afraid of the multitude: for all held John as a prophet.", "bbe": "But if we say, From men; we are in fear of the people, because all take John to be a prophet.", "geneva": "And if we say, Of men, we feare the multitude, for all holde Iohn as a Prophet.", "wycliffe": "seiynge, If we seien of heuene, he schal seie to vs, Whi thanne bileuen ye not to hym? If we seien of men, we dreden the puple, for alle hadden Joon as a prophete.", "rotherham": "But, if we say, Of men, we fear the multitude, for, all, as a prophet, are holding John.", "weymouth": "and if we say `a human origin' we have the people to fear, for they all hold John to have been a Prophet.\"", "darby": "but if we should say, Of men, we fear the crowd, for all hold John for a prophet.", "twenty": "But if we say ‘human,’ we are afraid of the people, for every one regards John as a Prophet.”", "acv": "But if we should say, From men, we fear the multitude, for all hold John as a prophet.", "anderson": "But if we reply, From men, we fear the multitude; for all regard John as a prophet.", "haweis": "But if we say, From men, we are afraid of the populace, for they all hold John as a prophet.", "noyes": "But if we say, From men, we fear the multitude; for all regard John as a prophet.", "webster": "But if we shall say, From men; we fear the people: for all hold John as a prophet.", "vulgate": "si autem dixerimus ex hominibus timemus turbam omnes enim habent Iohannem sicut prophetam;"}}, {"v": 27, "ref": "21:27", "o": "καὶ ἀποκριθέντες τῷ Ἰησοῦ εἶπαν· Οὐκ οἴδαμεν. ἔφη αὐτοῖς καὶ αὐτός· Οὐδὲ ἐγὼ λέγω ὑμῖν ἐν ποίᾳ ἐξουσίᾳ ταῦτα ποιῶ.", "en": {"kjv": "And they answered Jesus, and said, We cannot tell. And he said unto them, Neither tell I you by what authority I do these things.", "web": "They answered Jesus, and said, “We don’t know.” He also said to them, “Neither will I tell you by what authority I do these things.", "bsb": "So they answered, “We do not know.” And Jesus replied, “Neither will I tell you by what authority I am doing these things.", "asv": "And they answered Jesus, and said, We know not. He also said unto them, Neither tell I you by what authority I do these things.", "ylt": "And answering Jesus they said, `We have not known.' He said to them--he also--`Neither do I tell you by what authority I do these things.", "tyndale": "And they answered Iesus and sayde: we cannot tell. And he lyke wyse sayd vnto them: nether tell I you by what auctorite I do these thinges.", "dra": "And answering Jesus, they said: We know not. He also said to them: Neither do I tell you by what authority I do these things.", "bbe": "And they made answer and said, We have no idea. Then he said to them, And I will not say to you by what authority I do these things.", "geneva": "Then they answered Iesus, and said, We can not tell. And he said vnto them, Neither tell I you by what authoritie I doe these things.", "wycliffe": "And thei answeriden to Jhesu, and seiden, We witen not. And he seide to hem, Nether Y seie to you, in what power Y do these thingis.", "rotherham": "And, making answer to Jesus, they said—We know not. He also, said unto them—Neither do, I, tell, you, by what authority, these things, I am doing.", "weymouth": "So they answered Jesus, \"We do not know.\" \"Nor do I tell you,\" He replied, \"by what authority I do these things.\"", "darby": "And answering Jesus they said, We do not know. He also said to them, Neither do I tell you by what authority I do these things.", "twenty": "So the answer they gave Jesus was — “We do not know.” “Then I,” he said, “refuse to tell you what authority I have to do these things.", "acv": "And having answered Jesus, they said, We know not. He said to them, And neither do I tell you by what authority I do these things.", "anderson": "And they answered and said to Jesus: We know not. And he said to them: Neither do I tell you by what authority I do these things.", "haweis": "So they answered Jesus, and said, We cannot tell. Then said he also to them, Neither tell I you by what authority I do these things.", "noyes": "And they answered Jesus and said, We do not know. And he said to them, Neither do I tell you by what authority I do these things.", "webster": "And they answered Jesus, and said, We cannot tell. And he said to them, Neither do I tell you by what authority I do these things.", "vulgate": "et respondentes Iesu dixerunt nescimus ait illis et ipse nec ego dico vobis in qua potestate haec facio;"}}, {"v": 28, "ref": "21:28", "o": "Τί δὲ ὑμῖν δοκεῖ; ἄνθρωπος εἶχεν τέκνα δύο. ⸀προσελθὼν τῷ πρώτῳ εἶπεν· Τέκνον, ὕπαγε σήμερον ἐργάζου ἐν τῷ ⸀ἀμπελῶνι.", "en": {"kjv": "But what think ye? A certain man had two sons; and he came to the first, and said, Son, go work to day in my vineyard.", "web": "But what do you think? A man had two sons, and he came to the first, and said, ‘Son, go work today in my vineyard.’", "bsb": "But what do you think? There was a man who had two sons. He went to the first one and said, ‘Son, go and work today in the vineyard.’", "asv": "But what think ye? A man had two sons; and he came to the first, and said, Son, go work to-day in the vineyard.", "ylt": "`And what think ye? A man had two children, and having come to the first, he said, Child, go, to-day be working in my vineyard.'", "tyndale": "What saye ye to this? A certayne man had two sonnes and came to ye elder and sayde: sonne go and worke to daye in my vineyarde.", "dra": "But what think you? A certain man had two sons: and coming to the first, he said: Son, go work to day in my vineyard.", "bbe": "But how does it seem to you? A man had two sons; and he came to the first, and said, Son, go and do work today in the vine-garden.", "geneva": "But what thinke ye? A certaine man had two sonnes, and came to the elder, and saide, Sonne, goe and worke to day in my vineyarde.", "wycliffe": "But what semeth to you? A man hadde twey sones; and he cam to the firste, and seide, Sone, go worche this dai in my vyneyerd.", "rotherham": "But how, to you, doth it seem? A man, had two sons: coming unto the first, he said, Son! go thy way, to-day, be working in the vineyard.", "weymouth": "\"But give me your judgement. There was a man who had two sons. He came to the elder of them, and said, \"`My son, go and work in the vineyard to-day.'", "darby": "But what think ye? A man had two children, and coming to the first he said, Child, go to-day, work in [my] vineyard.", "twenty": "What do you think of this? There was a man who had two sons. He went to the elder and said ‘Go and work in the vineyard to-day my son.’", "acv": "But what does it seem to you? A man had two children. And having come to the first, he said, Child, go work today in my vineyard.", "anderson": "But what think you? A man had two sons; and he went to the first, and said, Son, go work to-day in my vineyard.", "haweis": "But what think ye? A man had two sons; and coming to the first he said, Son, go work to-day in my vineyard.", "noyes": "But what think ye? A man had two sons: he came to the first, and said, Son, go, work today in the vineyard.", "webster": "But what think ye? A [certain] man had two sons; and he came to the first, and said, Son, go, work to-day in my vineyard.", "vulgate": "quid autem vobis videtur homo habebat duos filios et accedens ad primum dixit fili vade hodie operare in vinea mea;"}}, {"v": 29, "ref": "21:29", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· ⸂Οὐ θέλω· ὕστερον δὲ μεταμεληθεὶς⸃ ἀπῆλθεν.", "en": {"kjv": "He answered and said, I will not: but afterward he repented, and went.", "web": "He answered, ‘I will not,’ but afterward he changed his mind, and went.", "bsb": "‘I will not,’ he replied. But later he changed his mind and went.", "asv": "And he answered and said, I will not: but afterward he repented himself, and went.", "ylt": "And he answering said, `I will not,' but at last, having repented, he went.", "tyndale": "He answered and sayde I will not: but afterwarde repented and went.", "dra": "And he answering, said: I will not. But afterwards, being moved with repentance, he went.", "bbe": "And he said in answer, I will not: but later, changing his decision, he went.", "geneva": "But he answered, and said, I will not: yet afterward he repented himselfe, and went.", "wycliffe": "And he answeride, and seide, Y nyle; but afterward he forthouyte, and wente forth.", "rotherham": "And, he, answering, said, I, sir! and went not;", "weymouth": "\"`I will not,' he replied. \"But afterwards he was sorry, and went.", "darby": "And he answering said, I will not; but afterwards repenting himself he went.", "twenty": "‘Yes, sir,’ he answered; but he did not go.", "acv": "And having answered, he said, I do not want to, but having repented later, he went.", "anderson": "He answered and said, I will not. But he afterward regretted it, and went.", "haweis": "But he answering said, I will not: yet repenting afterwards, he went.", "noyes": "And he answered and said, I will not. Afterward he repented, and went.", "webster": "He answered and said, I will not; but afterward he repented, and went.", "vulgate": "ille autem respondens ait nolo postea autem paenitentia motus abiit;"}}, {"v": 30, "ref": "21:30", "o": "⸂προσελθὼν δὲ⸃ τῷ ⸀δευτέρῳ εἶπεν ὡσαύτως· ὁ δὲ ἀποκριθεὶς εἶπεν· ⸂Ἐγώ, κύριε· καὶ οὐκ⸃ ἀπῆλθεν.", "en": {"kjv": "And he came to the second, and said likewise. And he answered and said, I go, sir: and went not.", "web": "He came to the second, and said the same thing. He answered, ‘I go, sir,’ but he didn’t go.", "bsb": "Then the man went to the second son and told him the same thing. ‘I will, sir,’ he said. But he did not go.", "asv": "And he came to the second, and said likewise. And he answered and said, I go, sir: and went not.", "ylt": "`And having come to the second, he said in the same manner, and he answering said, I go , sir, and went not;", "tyndale": "Then came he to the second and sayde lyke wyse. And he answered and sayde: I will syr: yet wet not.", "dra": "And coming to the other, he said in like manner. And he answering said: I go, Sir. And he went not.", "bbe": "And he came to the second and said the same. And he made answer and said, I go, sir: and went not.", "geneva": "Then came he to the second, and said likewise. And he answered, and said, I will, Syr: yet he went not.", "wycliffe": "But he cam to `the tother, and seide on lijk maner. And he answeride, and seide, Lord, Y go; and he wente not.", "rotherham": "And, coming unto the second, he spake, in like manner,—and, he, answering, said, I will not: afterwards, smitten with regret, he went.", "weymouth": "He came to the second and spoke in the same manner. His answer was, \"`I will go, Sir.' \"But he did not go.", "darby": "And coming to the second he said likewise; and he answering said, I [go], sir, and went not.", "twenty": "Then the father went to the second son, and said the same. ‘I will not,’ he answered; but afterwards he was sorry and went.", "acv": "And having come to the second, he said likewise. And having answered, he said, I, sir, and did not go.", "anderson": "And he came to the other, and spoke to him in like manner. And he answered and said, I go, sir; and went not.", "haweis": "And coming to the other, he spake after the same manner, and he replying, said, I go, sir; yet went not.", "noyes": "And he came to the other and said the same. And he answered and said, I will, sir; and went not.", "webster": "And he came to the second, and said likewise. And he answered and said, I [go], sir: and went not.", "vulgate": "accedens autem ad alterum dixit similiter at ille respondens ait eo domine et non ivit;"}}, {"v": 31, "ref": "21:31", "o": "τίς ἐκ τῶν δύο ἐποίησεν τὸ θέλημα τοῦ πατρός; ⸀λέγουσιν· Ὁ ⸀πρῶτος. λέγει αὐτοῖς ὁ Ἰησοῦς· Ἀμὴν λέγω ὑμῖν ὅτι οἱ τελῶναι καὶ αἱ πόρναι προάγουσιν ὑμᾶς εἰς τὴν βασιλείαν τοῦ θεοῦ.", "en": {"kjv": "Whether of them twain did the will of his father? They say unto him, The first. Jesus saith unto them, Verily I say unto you, That the publicans and the harlots go into the kingdom of God before you.", "web": "Which of the two did the will of his father?” They said to him, “The first.” Jesus said to them, “Most certainly I tell you that the tax collectors and the prostitutes are entering into the Kingdom of God before you.", "bsb": "Which of the two did the will of his father?” “The first,” they answered. Jesus said to them, “Truly I tell you, the tax collectors and prostitutes are entering the kingdom of God before you.", "asv": "Which of the two did the will of his father? They say, The first. Jesus saith unto them, Verily I say unto you, that the publicans and the harlots go into the kingdom of God before you.", "ylt": "which of the two did the will of the father?' They say to him, `The first.' Jesus saith to them, `Verily I say to you, that the tax-gatherers and the harlots do go before you into the reign of God,", "tyndale": "Whether of the twayne dyd the will of the father? And they sayde vnto hym: the fyrst. Iesus sayde vnto the: verely I saye vnto you that the publicans and the harlotes shall come into ye kyngdome of God before you.", "dra": "Which of the two did the father's will? They say to him: The first. Jesus saith to them: Amen I say to you that the publicans and the harlots shall go into the kingdom of God before you.", "bbe": "Which of the two did his father's pleasure? They say, The first. Jesus said to them, Truly I say to you, that tax-farmers and loose women are going into the kingdom of God before you.", "geneva": "Whether of them twaine did the will of the father? They saide vnto him, The first. Iesus saide vnto them, Verely I say vnto you, that the Publicanes and the harlots goe before you into the kingdome of God.", "wycliffe": "Who of the tweyne dide the fadris wille? Thei seien to hym, The firste. Jhesus seith to hem, Treuli Y seie to you, for pupplicans and hooris schulen go bifor you `in to the kyngdom of God.", "rotherham": "Which of the two, did the will of the father? They say, The latter. Jesus saith unto them—Verily, I say unto you, the tax-collectors and the harlots, are going before you, into the kingdom of God;", "weymouth": "Which of the two did as his father desired?\" \"The first,\" they said. \"I solemnly tell you,' replied Jesus, \"that the tax-gatherers and the notorious sinners are entering the Kingdom of God in front of you.", "darby": "Which of the two did the will of the father? They say [to him], The first. Jesus says to them, Verily I say unto you that the tax-gatherers and the harlots go into the kingdom ofGod before you.", "twenty": "Which of the two sons did as his father wished?” “The second,” they said. “I tell you,” added Jesus, “that tax-gatherers and prostitutes are going into the Kingdom of God before you.", "acv": "Which of the two did the will of the father? They say to him, The first. Jesus says to them, Truly I say to you, that the tax collectors and the harlots go into the kingdom of God before you.", "anderson": "Which of the two did the will of his father? They said to him, The first. Jesus said to them: Verily I say to you, The publicans and the harlots go into the kingdom of God before you.", "haweis": "Which of the two did the will of his father? They say to him, The first. Jesus saith to them, Verily I say unto you, That tax-gatherers and harlots shall go before you into the kingdom of God.", "noyes": "Which of the two did the will of his father? They say, The first. Jesus saith to them, Truly do I say to you, that the publicans and the harlots go into the kingdom of God before you.", "webster": "Which of the two did the will of [his] father? They say to him, The first. Jesus saith to them, Verily I say to you, that the publicans and the harlots go into the kingdom of God before you.", "vulgate": "quis ex duobus fecit voluntatem patris dicunt novissimus dicit illis Iesus amen dico vobis quia publicani et meretrices praecedunt vos in regno Dei;"}}, {"v": 32, "ref": "21:32", "o": "ἦλθεν γὰρ ⸂Ἰωάννης πρὸς ὑμᾶς⸃ ἐν ὁδῷ δικαιοσύνης, καὶ οὐκ ἐπιστεύσατε αὐτῷ· οἱ δὲ τελῶναι καὶ αἱ πόρναι ἐπίστευσαν αὐτῷ· ὑμεῖς δὲ ἰδόντες ⸀οὐδὲ μετεμελήθητε ὕστερον τοῦ πιστεῦσαι αὐτῷ.", "en": {"kjv": "For John came unto you in the way of righteousness, and ye believed him not: but the publicans and the harlots believed him: and ye, when ye had seen it, repented not afterward, that ye might believe him.", "web": "For John came to you in the way of righteousness, and you didn’t believe him, but the tax collectors and the prostitutes believed him. When you saw it, you didn’t even repent afterward, that you might believe him.", "bsb": "For John came to you in a righteous way and you did not believe him, but the tax collectors and prostitutes did. And even after you saw this, you did not repent and believe him.", "asv": "For John came unto you in the way of righteousness, and ye believed him not; but the publicans and the harlots believed him: and ye, when ye saw it, did not even repent yourselves afterward, that ye might believe him.", "ylt": "for John came unto you in the way of righteousness, and ye did not believe him, and the tax-gatherers and the harlots did believe him, and ye, having seen, repented not at last--to believe him.", "tyndale": "For Iohn came vnto you in the waye of rightewesnes and ye beleved hym not. But the publicans and the harlotes beleved him. And yet ye (though ye sawe it) were not yet moved with repentaunce that ye myght afterwarde have beleved hym.", "dra": "For John came to you in the way of justice: and you did not believe him. But the publicans and the harlots believed him: but you, seeing it, did not even afterwards repent, that you might believe him.", "bbe": "For John came to you in the way of righteousness, and you had no faith in him, but the tax-farmers and the loose women had faith in him: and you, when you saw it, did not even have regret for your sins, so as to have faith in him.", "geneva": "For Iohn came vnto you in the way of righteousnes, and yee beleeued him not: but the Publicanes, and the harlots beleeued him, and ye, though ye sawe it, were not mooued with repentance afterward, that ye might beleeue him.", "wycliffe": "For Joon cam to you in the weie of riytwisnesse, and ye bileueden not to him; but pupplicans and hooris bileueden to hym. But ye sayn, and hadden no forthenkyng aftir, that ye bileueden to hym.", "rotherham": "For John came unto you, in a way of righteousness, and ye believed him not,—but, the tax-collectors and the harlots, believed him; and, ye, seeing it, were not even smitten with regret, afterwards, so as to believe him.", "weymouth": "For John came to you observing all sorts of ritual, and you put no faith in him: the tax-gatherers and the notorious sinners did put faith in him, and you, though you saw this example set you, were not even afterwards sorry so as to believe him.", "darby": "For John came to you in the way of righteousness, and ye believed him not; but the tax-gatherers and the harlots believed him; but ye when ye saw [it] repented not yourselves afterwards to believe him.", "twenty": "For when John came to you, walking in the path of righteousness, you did not believe him, but tax-gatherers and prostitutes did; and yet you, though you saw this, even then were not sorry, nor did you believe him.", "acv": "For John came to you in a way of righteousness, and ye did not believe him, but the tax collectors and the harlots believed him. And having seen it, ye did not repent afterward to believe him.", "anderson": "For John came to you in the way of righteousness, and you believed him not. But the publicans and the harlots believed him. And you, when you had seen it, afterward felt no regret, that you might believe him.", "haweis": "For John came unto you in the way of righteousness, and ye believed him not: but the tax-gatherers and harlots believed on him. But ye, when ye saw it, repented not afterwards, that ye should believe on him.", "noyes": "For John came to you as a preacher of righteousness, and ye did not believe him; but the publicans and the harlots believed him; and ye, when ye had seen it, did not afterward repent, that ye might believe him.", "webster": "For John came to you in the way of righteousness, and ye believed him not: but the publicans and the harlots believed him: and ye, when ye had seen [it], repented not afterward, that ye might believe him.", "vulgate": "venit enim ad vos Iohannes in via iustitiae et non credidistis ei publicani autem et meretrices crediderunt ei vos autem videntes nec paenitentiam habuistis postea ut crederetis ei;"}}, {"v": 33, "ref": "21:33", "o": "Ἄλλην παραβολὴν ἀκούσατε. ⸀Ἄνθρωπος ἦν οἰκοδεσπότης ὅστις ἐφύτευσεν ἀμπελῶνα καὶ φραγμὸν αὐτῷ περιέθηκεν καὶ ὤρυξεν ἐν αὐτῷ ληνὸν καὶ ᾠκοδόμησεν πύργον, καὶ ἐξέδετο αὐτὸν γεωργοῖς, καὶ ἀπεδήμησεν.", "en": {"kjv": "Hear another parable: There was a certain householder, which planted a vineyard, and hedged it round about, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into a far country:", "web": "“Hear another parable. There was a man who was a master of a household, who planted a vineyard, set a hedge about it, dug a wine press in it, built a tower, leased it out to farmers, and went into another country.", "bsb": "Listen to another parable: There was a landowner who planted a vineyard. He put a wall around it, dug a winepress in it, and built a tower. Then he rented it out to some tenants and went away on a journey.", "asv": "Hear another parable: There was a man that was a householder, who planted a vineyard, and set a hedge about it, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into another country.", "ylt": "`Hear ye another simile: There was a certain man, a householder, who planted a vineyard, and did put a hedge round it, and digged in it a wine-press, and built a tower, and gave it out to husbandmen, and went abroad.", "tyndale": "Herken another similitude. Ther was a certayne housholder which planted a vineyarde and hedged it roude about and made a wynpresse in it and bilt a tower and let it out to husbandmen and wet in to a straunge coutre.", "dra": "Hear ye another parable. There was a man, an householder, who planted a vineyard and made a hedge round about it and dug in it a press and built a tower and let it out to husbandmen and went into a strange country.", "bbe": "Give ear to another story. A master of a house made a vine garden, and put a wall round it, and made a place for crushing out the wine, and made a tower, and let it out to field-workers, and went into another country.", "geneva": "Heare another parable, There was a certaine housholder, which planted a vineyard, and hedged it round about, and made a winepresse therein, and built a tower, and let it out to husbandmen, and went into a strange countrey.", "wycliffe": "Here ye another parable. There was an hosebonde man, that plauntide a vynyerd, and heggide it aboute, and dalfe a presour ther ynne, and bildide a tour, and hiride it to erthe tilieris, and wente fer in pilgrimage.", "rotherham": "Another parable, hear ye:—A man there was, a householder, who planted a vineyard, and, a wall around it, placed, and digged in it a wine-vat, and built a tower, and let it out to husbandmen,—and left home.", "weymouth": "\"Listen to another parable. There was a householder who planted a vineyard, made a fence round it, dug a wine-tank in it, and built a strong lodge; then let the place to vine-dressers, and went abroad.", "darby": "Hear another parable: There was a householder who planted a vineyard, and made a fence round it, and dug a winepress in it, and built a tower, and let it out to husbandmen, and left the country.", "twenty": "Listen to another parable. A man, who was an employer, once planted a vineyard, put a fence round it, dug a winepress in it, built a tower, and then let it out to tenants and went abroad.", "acv": "Hear ye another parable. There was a certain man who was a house-ruler, who planted a vineyard, and placed a hedge around it, and dug a winepress in it, and built a tower, and leased it to farmers, and went on a journey.", "anderson": "Hear another parable: There was a master of a house who planted a vineyard, and put a hedge around it, and rigged in it a wine-press, and built a tower, and let it out to vine-dressers, and went into another country.", "haweis": "Hear another parable: There was a certain man, the master of a family, who planted a vineyard, and set a hedge about it, and digged in it a wine-press, and built a tower, and hired it out to husbandmen, and went into a distant country.", "noyes": "Hear another parable. There was a householder, who planted a vineyard, and set a hedge about it, and dug in it a wine-press, and built a tower, and let it out to husbandmen, and went abroad.", "webster": "Hear another parable; There was a certain householder, who planted a vineyard, and hedged it around, and digged a wine-press in it, and built a tower, and let it out to husbandmen, and went into a remote country:", "vulgate": "aliam parabolam audite homo erat pater familias qui plantavit vineam et sepem circumdedit ei et fodit in ea torcular et aedificavit turrem et locavit eam agricolis et peregre profectus est;"}}, {"v": 34, "ref": "21:34", "o": "ὅτε δὲ ἤγγισεν ὁ καιρὸς τῶν καρπῶν, ἀπέστειλεν τοὺς δούλους αὐτοῦ πρὸς τοὺς γεωργοὺς λαβεῖν τοὺς καρποὺς αὐτοῦ.", "en": {"kjv": "And when the time of the fruit drew near, he sent his servants to the husbandmen, that they might receive the fruits of it.", "web": "When the season for the fruit drew near, he sent his servants to the farmers, to receive his fruit.", "bsb": "When the harvest time drew near, he sent his servants to the tenants to collect his share of the fruit.", "asv": "And when the season of the fruits drew near, he sent his servants to the husbandmen, to receive his fruits.", "ylt": "`And when the season of the fruits came nigh, he sent his servants unto the husbandmen, to receive the fruits of it,", "tyndale": "And when the tyme of the frute drewe neare he sent his servauntes to the husbandmen to receave the frutes of it.", "dra": "And when the time of the fruits drew nigh, he sent his servants to the husbandmen that they might receive the fruits thereof.", "bbe": "And when the time for the fruit came near, he sent his servants to the workmen, to get the fruit.", "geneva": "And when the time of the fruite drewe neere, hee sent his seruants to the husbandmen to receiue the fruites thereof.", "wycliffe": "But whanne the tyme of fruytis neiyede, he sente his seruauntis to the erthe tilieris, to take fruytis of it.", "rotherham": "And, when the season of fruits drew near, He sent forth his servants unto the husbandmen to receive his fruits.", "weymouth": "When vintage-time approached, he sent his servants to the vine-dressers to receive his share of the grapes;", "darby": "But when the time of fruit drew near, he sent his bondmen to the husbandmen to receive his fruits.", "twenty": "When the time for the vintage drew near, he sent his servants to the tenants, to receive his share of the produce.", "acv": "And when the time of the fruits approached, he sent his bondmen to the farmers to receive his fruits.", "anderson": "And when the time of the fruit drew near, he sent his servants to the vine-dressers to receive the fruits of it.", "haweis": "But when the season for fruits drew near, he sent his servants to the husbandmen to receive his fruits.", "noyes": "And when the season of the fruits drew near, he sent his servants to the husbandmen, that they might receive his fruits.", "webster": "And when the time of the fruit drew near, he sent his servants to the husbandmen, that they might receive the fruits of it.", "vulgate": "cum autem tempus fructuum adpropinquasset misit servos suos ad agricolas ut acciperent fructus eius;"}}, {"v": 35, "ref": "21:35", "o": "καὶ λαβόντες οἱ γεωργοὶ τοὺς δούλους αὐτοῦ ὃν μὲν ἔδειραν, ὃν δὲ ἀπέκτειναν, ὃν δὲ ἐλιθοβόλησαν.", "en": {"kjv": "And the husbandmen took his servants, and beat one, and killed another, and stoned another.", "web": "The farmers took his servants, beat one, killed another, and stoned another.", "bsb": "But the tenants seized his servants. They beat one, killed another, and stoned a third.", "asv": "And the husbandmen took his servants, and beat one, and killed another, and stoned another.", "ylt": "and the husbandmen having taken his servants, one they scourged, and one they killed, and one they stoned.", "tyndale": "And ye husbandme caught his servauntes and bet one kylled another and stoned another.", "dra": "And the husbandmen laying hands on his servants, beat one and killed another and stoned another.", "bbe": "And the workmen made an attack on his servants, giving blows to one, putting another to death, and stoning another.", "geneva": "And ye husbandmen tooke his seruants and beat one, and killed another, and stoned another.", "wycliffe": "And the erthetilieris token his seruauntis, and beeten `the toon, thei slowen another, and thei stonyden another.", "rotherham": "And the husbandmen, taking his servants, one, indeed, they beat, and, another, slew,—and, another, stoned.", "weymouth": "but the vine-dressers seized the servants, and one they cruelly beat, one they killed, one they pelted with stones.", "darby": "And the husbandmen took his bondmen, and beat one, killed another, and stoned another.", "twenty": "But the tenants seized his servants, beat one, killed another, and stoned a third.", "acv": "And the farmers having taken his bondmen, they beat one, and killed another, and stoned another.", "anderson": "And the vine-dressers took his servants, and scourged one, and killed another, and stoned another.", "haweis": "And the husbandmen took his servants, one they beat, and another they killed, and a third they stoned.", "noyes": "And the husbandmen took his servants, and beat one, and killed another, and stoned another.", "webster": "And the husbandmen took his servants, and beat one, and killed another, and stoned another.", "vulgate": "et agricolae adprehensis servis eius alium ceciderunt alium occiderunt alium vero lapidaverunt;"}}, {"v": 36, "ref": "21:36", "o": "πάλιν ἀπέστειλεν ἄλλους δούλους πλείονας τῶν πρώτων, καὶ ἐποίησαν αὐτοῖς ὡσαύτως.", "en": {"kjv": "Again, he sent other servants more than the first: and they did unto them likewise.", "web": "Again, he sent other servants more than the first: and they treated them the same way.", "bsb": "Again, he sent other servants, more than the first group. But the tenants did the same to them.", "asv": "Again, he sent other servants more than the first: and they did unto them in like manner.", "ylt": "`Again he sent other servants more than the first, and they did to them in the same manner.", "tyndale": "Agayne he sent other servantes moo then the fyrst: and they served them lyke wyse.", "dra": "Again he sent other servants, more than the former; and they did to them in like manner.", "bbe": "Again, he sent other servants more in number than the first: and they did the same to them.", "geneva": "Againe hee sent other seruants, moe then the first: and they did the like vnto them.", "wycliffe": "Eftsoone he sente othere seruauntis, mo than the firste, and in lijk maner thei diden to hem.", "rotherham": "Again, sent he forth other servants, more than the first, and they did unto them, likewise.", "weymouth": "Again he sent another party of servants more numerous than the first; and these they treated in the same manner.", "darby": "Again he sent other bondmen more than the first, and they did to them in like manner.", "twenty": "A second time the owner sent some servants, a larger number than before, and the tenants treated them in the same way.", "acv": "Again, he sent other bondmen more than the first, and they did to them in like manner.", "anderson": "Again he sent other servants more than the first: and they treated them in like manner.", "haweis": "Again he sent other servants more than the first, and they treated them in the same manner.", "noyes": "Again he sent other servants more than the first; and they dealt with them in the same manner.", "webster": "Again he sent other servants more than the first: and they did to them in like manner.", "vulgate": "iterum misit alios servos plures prioribus et fecerunt illis similiter;"}}, {"v": 37, "ref": "21:37", "o": "ὕστερον δὲ ἀπέστειλεν πρὸς αὐτοὺς τὸν υἱὸν αὐτοῦ λέγων· Ἐντραπήσονται τὸν υἱόν μου.", "en": {"kjv": "But last of all he sent unto them his son, saying, They will reverence my son.", "web": "But afterward he sent to them his son, saying, ‘They will respect my son.’", "bsb": "Finally, he sent his son to them. ‘They will respect my son,’ he said.", "asv": "But afterward he sent unto them his son, saying, They will reverence my son.", "ylt": "`And at last he sent unto them his son, saying, They will reverence my son;", "tyndale": "But last of all he sent vnto the his awne sonne sayinge: they will feare my sonne.", "dra": "And last of all he sent to them his son, saying: They will reverence my son.", "bbe": "But after that he sent his son to them, saying, They will have respect for my son.", "geneva": "But last of all he sent vnto them his owne sonne, saying, They will reuerence my sonne.", "wycliffe": "And at the laste he sente his sone to hem, and seide, Thei schulen drede my sone.", "rotherham": "Afterwards, however, he sent forth unto them his son, saying,—They will pay deference unto my son!", "weymouth": "Later still he sent to them his son, saying, \"`They will respect my son.'", "darby": "And at last he sent to them his son, saying, They will have respect for my son.", "twenty": "As a last resource he sent his son to them. ‘They will respect my son,’ he said.", "acv": "But finally he sent to them his son, saying, They will be made ashamed by my son.", "anderson": "But afterward he sent to them his son, saying, They will reverence my son.", "haweis": "Then at last he sent unto them his son, saying, They will reverence my son.", "noyes": "And afterward he sent to them his son, saying, They will respect my son.", "webster": "But last of all he sent to them his son, saying, They will reverence my son.", "vulgate": "novissime autem misit ad eos filium suum dicens verebuntur filium meum;"}}, {"v": 38, "ref": "21:38", "o": "οἱ δὲ γεωργοὶ ἰδόντες τὸν υἱὸν εἶπον ἐν ἑαυτοῖς· Οὗτός ἐστιν ὁ κληρονόμος· δεῦτε ἀποκτείνωμεν αὐτὸν καὶ ⸀σχῶμεν τὴν κληρονομίαν αὐτοῦ·", "en": {"kjv": "But when the husbandmen saw the son, they said among themselves, This is the heir; come, let us kill him, and let us seize on his inheritance.", "web": "But the farmers, when they saw the son, said among themselves, ‘This is the heir. Come, let’s kill him, and seize his inheritance.’", "bsb": "But when the tenants saw the son, they said to one another, ‘This is the heir. Come, let us kill him and take his inheritance.’", "asv": "But the husbandmen, when they saw the son, said among themselves, This is the heir; come, let us kill him, and take his inheritance.", "ylt": "and the husbandmen having seen the son, said among themselves, This is the heir, come, we may kill him, and may possess his inheritance;", "tyndale": "But when the husbandmen sawe the sonne they sayde amoge the selves: This is the heyre: come let vs kyll him and let vs take his inheritaunce to oure selves.", "dra": "But the husbandmen seeing the son, said among themselves: This is the heir: come, let us kill him, and we shall have his inheritance.", "bbe": "But when the workmen saw the son, they said among themselves, This is he who will one day be the owner of the property; come, let us put him to death and take his heritage.", "geneva": "But when the husbandmen saw the sonne, they saide among themselues, This is the heire: come, let vs kill him, and let vs take his inheritance.", "wycliffe": "But the erthe tilieris, seynge the sone, seiden with ynne hem silf, This is the eire; come ye, sle we hym, and we schulen haue his eritage.", "rotherham": "But, the husbandmen, seeing the son, said among themselves,—This, is, the heir: Come on! Let us slay him, and have his inheritance.", "weymouth": "\"But the vine-dressers, when they saw the son, said to one another, \"`Here is the heir: come, let us kill him and get his inheritance.'", "darby": "But the husbandmen, seeing the son, said among themselves, This is the heir; come, let us kill him and possess his inheritance.", "twenty": "But the tenants, on seeing his son, said to each other ‘Here is the heir! Come, let us kill him, and get his inheritance.’", "acv": "But the farmers, when they saw the son, said among themselves, This is the heir, come, let us kill him, and possess his inheritance.", "anderson": "But the vine-dressers, when they saw the son, said among themselves, This is the heir; come, let us kill him, and seize upon the inheritance.", "haweis": "But the husbandmen, when they saw the son, said among themselves, This is the heir, come let us kill him, and let us seize on the inheritance.", "noyes": "But the husbandmen, when they saw the son, said among themselves, This is the heir; come, let us kill him, and get his inheritance.", "webster": "But when the husbandmen saw the son, they said among themselves, This is the heir; come, let us kill him, and let us seize on his inheritance.", "vulgate": "agricolae autem videntes filium dixerunt intra se hic est heres venite occidamus eum et habebimus hereditatem eius;"}}, {"v": 39, "ref": "21:39", "o": "καὶ λαβόντες αὐτὸν ἐξέβαλον ἔξω τοῦ ἀμπελῶνος καὶ ἀπέκτειναν.", "en": {"kjv": "And they caught him, and cast him out of the vineyard, and slew him.", "web": "So they took him, and threw him out of the vineyard, and killed him.", "bsb": "So they seized him and threw him out of the vineyard and killed him.", "asv": "And they took him, and cast him forth out of the vineyard, and killed him.", "ylt": "and having taken him, they cast him out of the vineyard, and killed him;", "tyndale": "And they caught him and thrust him out of the vineyarde and slewe him.", "dra": "And taking him, they cast him forth out of the vineyard and killed him.", "bbe": "And they took him and, driving him out of the vine-garden, put him to death.", "geneva": "So they tooke him, and cast him out of the vineyarde, and slewe him.", "wycliffe": "And thei token, and castiden hym out of the vynyerd, and slowen hym.", "rotherham": "And, taking him, they cast him forth outside the vineyard,—and slew him.", "weymouth": "\"So they seized him, dragged him out of the vineyard, and killed him.", "darby": "And they took him, and cast him forth out of the vineyard, and killed him.", "twenty": "So they seized him, and threw him outside the vineyard, and killed him.", "acv": "And having seized him, they cast him out of the vineyard, and killed him.", "anderson": "And they took him, and carried him out of the vineyard, and killed him.", "haweis": "And they took him, and cast him out of the vineyard, and slew him.", "noyes": "And they took him, and cast him out of the vineyard, and killed him.", "webster": "And they caught him, and cast [him] out of the vineyard, and slew [him].", "vulgate": "et adprehensum eum eiecerunt extra vineam et occiderunt;"}}, {"v": 40, "ref": "21:40", "o": "ὅταν οὖν ἔλθῃ ὁ κύριος τοῦ ἀμπελῶνος, τί ποιήσει τοῖς γεωργοῖς ἐκείνοις;", "en": {"kjv": "When the lord therefore of the vineyard cometh, what will he do unto those husbandmen?", "web": "When therefore the lord of the vineyard comes, what will he do to those farmers?”", "bsb": "Therefore, when the owner of the vineyard returns, what will he do to those tenants?”", "asv": "When therefore the lord of the vineyard shall come, what will he do unto those husbandmen?", "ylt": "whenever therefore the lord of the vineyard may come, what will he do to these husbandmen?'", "tyndale": "When the lorde of the vyneyarde commeth what will he do wt those husbandme?", "dra": "When therefore the lord of the vineyard shall come, what will he do to those husbandmen?", "bbe": "When, then, the lord of the vine-garden comes, what will he do to those workmen?", "geneva": "When therefore the Lord of the vineyarde shall come, what will hee doe to those husbandmen?", "wycliffe": "Therfor whanne the lord of the vyneyerd schal come, what schal he do to thilke erthe tilieris?", "rotherham": "When therefore the master of the vineyard shall come, what will he do unto those husbandmen?", "weymouth": "When then the owner of the vineyard comes, what will he do to those vine-dressers?\"", "darby": "When therefore the lord of the vineyard comes, what shall he do to those husbandmen?", "twenty": "Now, when the owner of the vineyard comes, what will he do to those tenants?”", "acv": "When therefore the lord of the vineyard comes, what will he do to those farmers?", "anderson": "Therefore, when the owner of the vineyard comes, what will he do to those vine-dressers?", "haweis": "When therefore the master of the vineyard cometh, what will he do with these husbandmen?", "noyes": "When therefore the lord of the vineyard cometh, what will he do to those husbandmen?", "webster": "When therefore the Lord of the vineyard cometh, what will he do to those husbandmen?", "vulgate": "cum ergo venerit dominus vineae quid faciet agricolis illis;"}}, {"v": 41, "ref": "21:41", "o": "λέγουσιν αὐτῷ· Κακοὺς κακῶς ἀπολέσει αὐτούς, καὶ τὸν ἀμπελῶνα ἐκδώσεται ἄλλοις γεωργοῖς, οἵτινες ἀποδώσουσιν αὐτῷ τοὺς καρποὺς ἐν τοῖς καιροῖς αὐτῶν.", "en": {"kjv": "They say unto him, He will miserably destroy those wicked men, and will let out his vineyard unto other husbandmen, which shall render him the fruits in their seasons.", "web": "They told him, “He will miserably destroy those miserable men, and will lease out the vineyard to other farmers, who will give him the fruit in its season.”", "bsb": "“He will bring those wretches to a wretched end,” they replied, “and will rent out the vineyard to other tenants who will give him his share of the fruit at harvest time.”", "asv": "They say unto him, He will miserably destroy those miserable men, and will let out the vineyard unto other husbandmen, who shall render him the fruits in their seasons.", "ylt": "They say to him, `Evil men--he will evilly destroy them, and the vineyard will give out to other husbandmen, who will give back to him the fruits in their seasons.'", "tyndale": "They sayde vnto him: he will cruellye destroye those evyll persons and wyll let out his vyneyarde vnto other husbandmen which shall delyver him the frute at tymes convenient", "dra": "They say to him: He will bring those evil men to an evil end and let out his vineyard to other husbandmen that shall render him the fruit in due season.", "bbe": "They say to him, He will put those cruel men to a cruel death, and will let out the vine-garden to other workmen, who will give him the fruit when it is ready.", "geneva": "They saide vnto him, Hee will cruelly destroy those wicked men, and will let out his vineyard vnto other husbandmen, which shall deliuer him the fruites in their seasons.", "wycliffe": "Thei seien to hym, He schal leese yuele the yuele men, and he schal sette to hire his vyneyerd to othere erthetilieris, whyche schulen yelde to hym fruyt in her tymes.", "rotherham": "They say unto him—Miserable men! Miserably, will he destroy them; and will let out, the vineyard, to other husbandmen, who will render unto him the fruits in their seasons.", "weymouth": "\"He will put the wretches to a wretched death,\" was the reply, \"and will entrust the vineyard to other vine-dressers who will render the produce to him at the vintage season.\"", "darby": "They say to him, He will miserably destroy those evil [men], and let out the vineyard to other husbandmen, who shall render him the fruits in their seasons.", "twenty": "“Miserable wretches!” they exclaimed, “he will put them to a miserable death, and he will let out the vineyard to other tenants, who will pay him his share of the produce at the proper times.”", "acv": "They say to him, Evil men, he will miserably destroy them, and will lease out the vineyard to other farmers, who will render him the fruits in their seasons.", "anderson": "They said to him: He will miserably destroy those wicked men, and let out his vineyard to other vine-dressers, who will give him the fruits in their season.", "haweis": "They say unto him, He will dreadfully destroy those wicked wretches, and will let out his vineyard to other husbandmen, who will render him the fruits in their seasons.", "noyes": "They say to him, He will bring those wicked men to a miserable end, and will let out his vineyard to other husbandmen, who will render him the fruits in their season.", "webster": "They say to him, He will miserably destroy those wicked men, and will let out [his] vineyard to other husbandmen, who will render him the fruits in their seasons.", "vulgate": "aiunt illi malos male perdet et vineam locabit aliis agricolis qui reddant ei fructum temporibus suis;"}}, {"v": 42, "ref": "21:42", "o": "Λέγει αὐτοῖς ὁ Ἰησοῦς· Οὐδέποτε ἀνέγνωτε ἐν ταῖς γραφαῖς· Λίθον ὃν ἀπεδοκίμασαν οἱ οἰκοδομοῦντες οὗτος ἐγενήθη εἰς κεφαλὴν γωνίας· παρὰ κυρίου ἐγένετο αὕτη, καὶ ἔστιν θαυμαστὴ ἐν ὀφθαλμοῖς ἡμῶν;", "en": {"kjv": "Jesus saith unto them, Did ye never read in the scriptures, The stone which the builders rejected, the same is become the head of the corner: this is the Lord’s doing, and it is marvellous in our eyes?", "web": "Jesus said to them, “Did you never read in the Scriptures, ‘The stone which the builders rejected, the same was made the head of the corner. This was from the Lord. It is marvelous in our eyes?’", "bsb": "Jesus said to them, “Have you never read in the Scriptures: ‘The stone the builders rejected has become the cornerstone. This is from the Lord, and it is marvelous in our eyes’?", "asv": "Jesus saith unto them, Did ye never read in the scriptures, The stone which the builders rejected, The same was made the head of the corner; This was from the Lord, And it is marvellous in our eyes?", "ylt": "Jesus saith to them, `Did ye never read in the Writings, A stone that the builders disallowed, it became head of a corner; from the Lord hath this come to pass, and it is wonderful in our eyes.", "tyndale": "Iesus sayde vnto the: dyd ye never redde in the scriptures? The stone which ye bylders refused ye same is set in ye principall parte of ye corner: this was the lordes doinge and yt is mervelous in oure eyes.", "dra": "Jesus saith to them: Have you never read in the Scriptures: The stone which the builders rejected, the same is become the head of the corner? By the Lord this has been done; and it is wonderful in our eyes.", "bbe": "Jesus says to them, Did you never see in the Writings, The stone which the builders put on one side, the same has been made the chief stone of the building: this was the Lord's doing, and it is a wonder in our eyes?", "geneva": "Iesus saide vnto them, Read ye neuer in the Scriptures, The stone which the builders refused, the same is made the head of the corner? This was the Lordes doing, and it is marueilous in our eyes.", "wycliffe": "Jhesus seith to hem, Redden ye neuer in scripturis, The stoon which bilderis repreueden, this is maad in to the heed of the corner? Of the Lord this thing is don, and it is merueilous bifor oure iyen.", "rotherham": "Jesus saith unto them—Have ye, never, read in the Scriptures, A stone which the builders rejected, the same, hath become, head of the corner: From the Lord, hath this come to pass, and is marvellous in our eyes.", "weymouth": "\"Have you never read in the Scriptures,\" said Jesus, \"`The Stone which the builders rejected has been made the Cornerstone: this Cornerstone came from the Lord, and is wonderful in our eyes'?", "darby": "Jesus says to them, Have ye never read in the scriptures, The stone which they that builded rejected, this has become the corner-stone: this is of [the] Lord, and it is wonderful in our eyes?", "twenty": "Then Jesus added: “Have you never read in the Scriptures? — ‘The very stone which the builders despised — Has now itself become the corner-stone; This corner-stone has come from the Lord, and is marvellous in our eyes.’", "acv": "Jesus says to them, Did ye never read in the scriptures, The stone that those who build rejected, this came to be in the head of the corner. This happened from the Lord, and it is marvelous in our eyes?", "anderson": "Jesus said to them: Did you never read in the Scriptures, The stone which the builders rejected has become the head of the corner?", "haweis": "Jesus saith unto them, Have ye not read in the Scriptures, “The stone, which the builders rejected; the same is become the head of the corner; this is done by the Lord, and it is wonderful in our eyes.”", "noyes": "Jesus saith to them, Did ye never read in the Scriptures, \"The stone which the builders rejected, the same hath become the corner-stone; from the Lord did this come, and it is marvelous in our eyes?\"", "webster": "Jesus saith to them, Did ye never read in the scriptures, The stone which the builders rejected, the same is become the head of the corner: this is the Lord's doing, and it is marvelous in our eyes?", "vulgate": "dicit illis Iesus numquam legistis in scripturis lapidem quem reprobaverunt aedificantes hic factus est in caput anguli a Domino factum est istud et est mirabile in oculis nostris;"}}, {"v": 43, "ref": "21:43", "o": "διὰ τοῦτο λέγω ὑμῖν ὅτι ἀρθήσεται ἀφ’ ὑμῶν ἡ βασιλεία τοῦ θεοῦ καὶ δοθήσεται ἔθνει ποιοῦντι τοὺς καρποὺς αὐτῆς.", "en": {"kjv": "Therefore say I unto you, The kingdom of God shall be taken from you, and given to a nation bringing forth the fruits thereof.", "web": "“Therefore I tell you, the Kingdom of God will be taken away from you, and will be given to a nation producing its fruit.", "bsb": "Therefore I tell you that the kingdom of God will be taken away from you and given to a people who will produce its fruit.", "asv": "Therefore say I unto you, The kingdom of God shall be taken away from you, and shall be given to a nation bringing forth the fruits thereof.", "ylt": "`Because of this I say to you, that the reign of God shall be taken from you, and given to a nation bringing forth its fruit;", "tyndale": "Therfore saye I vnto you the kyngdome of God shalbe take from you and shalbe geve to the getyls which shall brynge forth the frutes of it.", "dra": "Therefore I say to you that the kingdom of God shall be taken from you and shall be given to a nation yielding the fruits thereof.", "bbe": "For this reason I say to you, The kingdom of God will be taken away from you, and will be given to a nation producing the fruits of it.", "geneva": "Therefore say I vnto you, The kingdome of God shalbe taken from you, and shalbe giuen to a nation, which shall bring foorth the fruites thereof.", "wycliffe": "Therfor Y seie to you, that the kyngdom of God schal be takun fro you, and shal be youun to a folc doynge fruytis of it.", "rotherham": "Wherefore I say unto you, The kingdom of God, will be taken away from you, and given to a nation bringing forth the fruits thereof:", "weymouth": "\"That, I tell you, is the reason why the Kingdom of God will be taken away from you, and given to a nation that will exhibit the power of it.", "darby": "Therefore I say to you, that the kingdom ofGod shall be taken from you and shall be given to a nation producing the fruits of it.", "twenty": "And that, I tell you, is why the Kingdom of God will be taken from you, and given to a nation that does produce the fruit of the Kingdom.", "acv": "Because of this I say to you, that the kingdom of God will be taken away from you, and will be given to a nation producing the fruits of it.", "anderson": "This was from the Lord, and it is wondrous in our eyes. For this reason, I say to you, The kingdom of God shall be taken from you, and given to a nation that will bring forth the fruits of it.", "haweis": "Therefore I tell you, That the kingdom of God shall be taken away from you, and given to a nation, producing the fruits thereof.", "noyes": "Therefore I say to you, that the kingdom of God will be taken away from you, and given to a nation yielding the fruits thereof.", "webster": "Therefore I say to you, The kingdom of God shall be taken from you, and given to a nation bringing forth the fruits of it.", "vulgate": "ideo dico vobis quia auferetur a vobis regnum Dei et dabitur genti facienti fructus eius;"}}, {"v": 44, "ref": "21:44", "o": "⸂Καὶ ὁ πεσὼν ἐπὶ τὸν λίθον τοῦτον συνθλασθήσεται· ἐφ’ ὃν δ’ ἂν πέσῃ λικμήσει αὐτόν.⸃", "en": {"kjv": "And whosoever shall fall on this stone shall be broken: but on whomsoever it shall fall, it will grind him to powder.", "web": "He who falls on this stone will be broken to pieces, but on whomever it will fall, it will scatter him as dust.”", "bsb": "He who falls on this stone will be broken to pieces, but he on whom it falls will be crushed.”", "asv": "And he that falleth on this stone shall be broken to pieces: but on whomsoever it shall fall, it will scatter him as dust.", "ylt": "and he who is falling on this stone shall be broken, and on whomsoever it may fall it will crush him to pieces.'", "tyndale": "And whosoever shall fall on this stone he shalbe broken but on whosoever it shall fall vpon it will grynde him to powder.", "dra": "And whosoever shall fall on this stone shall be broken: but on whomsoever it shall fall, it shall grind him to powder.", "bbe": "Any man falling on this stone will be broken, but he on whom it comes down will be crushed to dust.", "geneva": "And whosoeuer shall fall on this stone, he shalbe broken: but on whomsoeuer it shall fall, it will dash him a pieces.", "wycliffe": "And he that schal falle on this stoon, schal be brokun; but on whom it schal falle, it schal al tobrise hym.", "rotherham": "[And, he that falleth on this stone, will be sorely bruised; but, on whomsoever it may fall, it will utterly destroy him.]", "weymouth": "He who falls on this stone will be severely hurt; but he on whom it falls will be utterly crushed.\"", "darby": "And he that falls on this stone shall be broken, but on whomsoever it shall fall, it shall grind him to powder.", "twenty": "Yes, and he who falls on this stone will be dashed to pieces, while any one on whom it falls — it will scatter him as dust.”", "acv": "And he who falls on this stone will be shattered, but on whomever it may fall, it will grind him to dust.", "anderson": "And he that falls upon this stone shall be dashed to pieces; but him on whom it shall fall, it will make like chaff for the wind.", "haweis": "And whosoever shall fall on this stone, shall be broken in pieces, but on whomsoever it shall fall, it shall grind him to powder.", "noyes": "", "webster": "And whoever shall fall on this stone, shall be broken: but on whomsoever it shall fall, it will grind him to powder.", "vulgate": "et qui ceciderit super lapidem istum confringetur super quem vero ceciderit conteret eum;"}}, {"v": 45, "ref": "21:45", "o": "Καὶ ἀκούσαντες οἱ ἀρχιερεῖς καὶ οἱ Φαρισαῖοι τὰς παραβολὰς αὐτοῦ ἔγνωσαν ὅτι περὶ αὐτῶν λέγει·", "en": {"kjv": "And when the chief priests and Pharisees had heard his parables, they perceived that he spake of them.", "web": "When the chief priests and the Pharisees heard his parables, they perceived that he spoke about them.", "bsb": "When the chief priests and Pharisees heard His parables, they knew that Jesus was speaking about them.", "asv": "And when the chief priests and the Pharisees heard his parables, they perceived that he spake of them.", "ylt": "And the chief priests and the Pharisees having heard his similes, knew that of them he speaketh,", "tyndale": "And when the chefe prestes and Pharises hearde these similitudes they perceaved yt he spake of the.", "dra": "And when the chief priests and Pharisees had heard his parables, they knew that he spoke of them.", "bbe": "And when his stories came to the ears of the chief priests and the Pharisees, they saw that he was talking of them.", "geneva": "And when the chiefe Priestes and Pharises had heard his parables, they perceiued that hee spake of them.", "wycliffe": "And whanne the princes of prestis and Farisees hadden herd hise parablis, thei knewen that he seide of hem.", "rotherham": "And the Chief-priests and the Pharisees, hearing his parables, took note, that, concerning them, he was speaking.", "weymouth": "After listening to His parables the High Priests and the Pharisees perceived that He was speaking about them;", "darby": "And the chief priests and the Pharisees, having heard his parables, knew that he spoke about them.", "twenty": "After listening to these parables, the Chief Priests and the Pharisees saw that it was about them that he was speaking;", "acv": "And when the chief priests and the Pharisees heard his parables, they knew that he spoke about them.", "anderson": "And when the chief priests and the Pharisees heard his parables, they knew that he spoke of them.", "haweis": "And when the chief priests and Pharisees heard his parables, they knew that he was speaking concerning them.", "noyes": "And the chief priests and the Pharisees when they heard his parables, knew that he was speaking of them.", "webster": "And when the chief priests and Pharisees had heard his parables, they perceived that he spoke of them.", "vulgate": "et cum audissent principes sacerdotum et Pharisaei parabolas eius cognoverunt quod de ipsis diceret;"}}, {"v": 46, "ref": "21:46", "o": "καὶ ζητοῦντες αὐτὸν κρατῆσαι ἐφοβήθησαν τοὺς ὄχλους, ⸂ἐπεὶ εἰς⸃ προφήτην αὐτὸν εἶχον.", "en": {"kjv": "But when they sought to lay hands on him, they feared the multitude, because they took him for a prophet.", "web": "When they sought to seize him, they feared the multitudes, because they considered him to be a prophet.", "bsb": "Although they wanted to arrest Him, they were afraid of the crowds, because the people regarded Him as a prophet.", "asv": "And when they sought to lay hold on him, they feared the multitudes, because they took him for a prophet.", "ylt": "and seeking to lay hold on him, they feared the multitudes, seeing they were holding him as a prophet.", "tyndale": "And they wet about to laye hondes on him but they feared ye people because they tooke him as a Prophet.", "dra": "And seeking to lay hands on him, they feared the multitudes, because they held him as a prophet.", "bbe": "And though they had a desire to take him, they were in fear of the people, because in their eyes he was a prophet.", "geneva": "And they seeking to laye handes on him, feared the people, because they tooke him as a Prophet.", "wycliffe": "And thei souyten to holde hym, but thei dredden the puple, for thei hadden hym as a prophete.", "rotherham": "And, seeking to secure him, they feared the multitudes; since, for a prophet, were they holding him.", "weymouth": "but though they were eager to lay hands upon Him, they were afraid of the people, for by them He was regarded as a Prophet.", "darby": "And seeking to lay hold of him, they were afraid of the crowds, because they held him for a prophet.", "twenty": "yet, although eager to arrest him, they were afraid of the crowds, who regarded him as a Prophet.", "acv": "And when they sought to seize him, they feared the multitudes, because they held him as a prophet.", "anderson": "And when they sought to lay hold of him, they feared the multitude, because they regarded him as a prophet.", "haweis": "And they sought to apprehend him; but were afraid of the people, for they held him as a prophet.", "noyes": "And they sought to seize him, but feared the multitudes, because they regarded him as a prophet.", "webster": "But when they sought to lay hands on him, they feared the multitude, because they took him for a prophet.", "vulgate": "et quaerentes eum tenere timuerunt turbas quoniam sicut prophetam eum habebant;"}}]}, {"c": 22, "verses": [{"v": 1, "ref": "22:1", "o": "Καὶ ἀποκριθεὶς ὁ Ἰησοῦς πάλιν εἶπεν ⸂ἐν παραβολαῖς αὐτοῖς⸃ λέγων·", "en": {"kjv": "And Jesus answered and spake unto them again by parables, and said,", "web": "Jesus answered and spoke again in parables to them, saying,", "bsb": "Once again, Jesus spoke to them in parables:", "asv": "And Jesus answered and spake again in parables unto them, saying,", "ylt": "And Jesus answering, again spake to them in similes, saying,", "tyndale": "And Iesus answered and spake vnto them agayne in similitudes sayinge.", "dra": "And Jesus answering, spoke again in parables to them, saying:", "bbe": "And Jesus, talking to them again in stories, said:", "geneva": "Then Iesus answered, and spake vnto them againe in parables, saying,", "wycliffe": "And Jhesus answeride, and spak eftsoone in parablis to hem,", "rotherham": "And, answering, Jesus, again, spake in parables unto them, saying:—", "weymouth": "Again Jesus spoke to them in figurative language.", "darby": "And Jesus answering spoke to them again in parables, saying,", "twenty": "Once more Jesus spoke to them in parables.", "acv": "And having responded, Jesus again spoke to them in parables, saying,", "anderson": "And Jesus answering, spoke to them again in parables, saying:", "haweis": "AND Jesus continuing his discourse, spake again to them in parables, saying,", "noyes": "Jesus answered and spoke to them again in parables, and said,", "webster": "And Jesus answered, and spoke to them again by parables, and said,", "vulgate": "et respondens Iesus dixit iterum in parabolis eis dicens;"}}, {"v": 2, "ref": "22:2", "o": "Ὡμοιώθη ἡ βασιλεία τῶν οὐρανῶν ἀνθρώπῳ βασιλεῖ, ὅστις ἐποίησεν γάμους τῷ υἱῷ αὐτοῦ.", "en": {"kjv": "The kingdom of heaven is like unto a certain king, which made a marriage for his son,", "web": "“The Kingdom of Heaven is like a certain king, who made a marriage feast for his son,", "bsb": "“The kingdom of heaven is like a king who prepared a wedding banquet for his son.", "asv": "The kingdom of heaven is likened unto a certain king, who made a marriage feast for his son,", "ylt": "`The reign of the heavens was likened to a man, a king, who made marriage-feasts for his son,", "tyndale": "The kingdome of heve is lyke vnto a certayne kynge which maryed his sonne", "dra": "The kingdom of heaven is likened to a king who made a marriage for his son.", "bbe": "The kingdom of heaven is like a certain king, who made a feast when his son was married,", "geneva": "The kingdome of heauen is like vnto a certaine King which maried his sonne,", "wycliffe": "and seide, The kyngdom of heuenes is maad lijk to a kyng that made weddyngis to his sone.", "rotherham": "The kingdom of the heavens hath become like a man, a king,—who made a marriage-feast for his son;", "weymouth": "\"The Kingdom of the Heavens,\" He said, \"may be compared to a king who celebrated the marriage of his son,", "darby": "The kingdom of the heavens has become like a king who made a wedding feast for his son,", "twenty": "“The Kingdom of Heaven,” he said, “may be compared to a king who gave a banquet in honour of his son’s wedding.", "acv": "The kingdom of the heavens is like a man, a king who made a wedding for his son.", "anderson": "The kingdom of heaven is like a king that made a marriage feast for his son;", "haweis": "The kingdom of heaven is like to a certain king, who made a marriage-feast for his son:", "noyes": "The kingdom of heaven is like a certain king, who made a marriage-feast for his son,", "webster": "The kingdom of heaven is like to a certain king, who made a marriage for his son,", "vulgate": "simile factum est regnum caelorum homini regi qui fecit nuptias filio suo;"}}, {"v": 3, "ref": "22:3", "o": "καὶ ἀπέστειλεν τοὺς δούλους αὐτοῦ καλέσαι τοὺς κεκλημένους εἰς τοὺς γάμους, καὶ οὐκ ἤθελον ἐλθεῖν.", "en": {"kjv": "And sent forth his servants to call them that were bidden to the wedding: and they would not come.", "web": "and sent out his servants to call those who were invited to the marriage feast, but they would not come.", "bsb": "He sent his servants to call those he had invited to the banquet, but they refused to come.", "asv": "and sent forth his servants to call them that were bidden to the marriage feast: and they would not come.", "ylt": "and he sent forth his servants to call those having been called to the marriage-feasts, and they were not willing to come.", "tyndale": "and sent forth his servantes to call them that were byd to the weddinge and they wolde not come.", "dra": "And he sent his servants to call them that were invited to the marriage: and they would not come.", "bbe": "And sent out his servants to get in the guests to the feast: and they would not come.", "geneva": "And sent foorth his seruants, to call them that were bidde to the wedding, but they woulde not come.", "wycliffe": "And he sente hise seruauntis for to clepe men that weren bode to the weddyngis, and thei wolden not come.", "rotherham": "And sent his servants, to call the invited into the marriage-feast,—and they would not come.", "weymouth": "and sent his servants to call the invited guests to the wedding, but they were unwilling to come.", "darby": "and sent his bondmen to call the persons invited to the wedding feast, and they would not come.", "twenty": "He sent his servants to call those who had been invited to the banquet, but they were unwilling to come.", "acv": "And he sent forth his bondmen to call those who were invited to the wedding festivities, and they did not want to come.", "anderson": "and sent his servants to call those who had been invited to the marriage feast; and they refused to come.", "haweis": "and sent his servants to call those who were invited to the entertainment: and they would not come.", "noyes": "and sent forth his servants to call to the feast those who had been invited; and they would not come.", "webster": "And sent his servants to call them that were invited to the wedding: and they would not come.", "vulgate": "et misit servos suos vocare invitatos ad nuptias et nolebant venire;"}}, {"v": 4, "ref": "22:4", "o": "πάλιν ἀπέστειλεν ἄλλους δούλους λέγων· Εἴπατε τοῖς κεκλημένοις· Ἰδοὺ τὸ ἄριστόν μου ⸀ἡτοίμακα, οἱ ταῦροί μου καὶ τὰ σιτιστὰ τεθυμένα, καὶ πάντα ἕτοιμα· δεῦτε εἰς τοὺς γάμους.", "en": {"kjv": "Again, he sent forth other servants, saying, Tell them which are bidden, Behold, I have prepared my dinner: my oxen and my fatlings are killed, and all things are ready: come unto the marriage.", "web": "Again he sent out other servants, saying, ‘Tell those who are invited, “Behold, I have prepared my dinner. My cattle and my fatlings are killed, and all things are ready. Come to the marriage feast!”’", "bsb": "Again, he sent other servants and said, ‘Tell those who have been invited that I have prepared my dinner. My oxen and fattened cattle have been killed, and everything is ready. Come to the wedding banquet.’", "asv": "Again he sent forth other servants, saying, Tell them that are bidden, Behold, I have made ready my dinner; my oxen and my fatlings are killed, and all things are ready: come to the marriage feast.", "ylt": "`Again he sent forth other servants, saying, Say to those who have been called: Lo, my dinner I prepared, my oxen and the fatlings have been killed, and all things are ready, come ye to the marriage-feasts;", "tyndale": "Ageyne he sent forth other servauntes sayinge: Tell them which are bydden: beholde I have prepared my dynner myne oxen and my fatlinges are kylled and all thinges are redy come vnto the mariage.", "dra": "Again he sent other servants, saying: Tell them that were invited, Behold, I have prepared my dinner: my beeves and fatlings are killed, and all things are ready. Come ye to the marriage.", "bbe": "Again he sent out other servants, with orders to say to the guests, See, I have made ready my feast: my oxen and my fat beasts have been put to death, and all things are ready: come to the feast.", "geneva": "Againe hee sent foorth other seruants, saying. Tell them which are bidden, Beholde, I haue prepared my dinner: mine oxen and my fatlings are killed, and all thinges are readie: come vnto the mariage.", "wycliffe": "Eftsoone he sente othere seruauntis, and seide, Seie ye to the men that ben bode to the feeste, Lo! Y haue maad redi my meete, my bolis and my volatilis ben slayn, and alle thingis ben redy; come ye to the weddyngis.", "rotherham": "Again, sent he other servants, saying—Say to the invited, Lo! my dinner, have I prepared, mine oxen and my fatlings, are slain,—and, all things, are, ready: Come ye into the marriage-feast.", "weymouth": "\"Again he sent other servants with a message to those who were invited. \"`My breakfast is now ready,\" he said, `my bullocks and fat cattle are killed, and every preparation is made: come to the wedding.'", "darby": "Again he sent other bondmen, saying, Say to the persons invited, Behold, I have prepared my dinner; my oxen and my fatted beasts are killed, and all things ready; come to the wedding feast.", "twenty": "A second time he sent some servants, with orders to say to those who had been invited ‘I have prepared my breakfast, my cattle and fat beasts are killed and everything is ready; come to the banquet.’", "acv": "Again he sent forth other bondmen, saying, Speak to those who were invited, Behold, I have prepared my dinner. My oxen and my fatlings have been killed, and all things are ready. Come to the wedding festivities.", "anderson": "Again, he sent other servants, saying, Tell those who have been invited, Behold, I have prepared my dinner; my oxen and my fatlings are killed, and all things are ready: come to the marriage feast.", "haweis": "Again he sent other servants, saying, Tell those who have been invited, Behold, I have prepared my dinner; my oxen and the fatlings are killed, and all things are ready; come unto the marriage-feast.", "noyes": "Again, he sent other servants, saying, Tell those who have been invited, Behold, I have prepared my dinner; my oxen and my fatlings are killed, and all things are ready; come to the feast.", "webster": "Again, he sent other servants, saying, Tell them who are invited, Behold, I have prepared my dinner: my oxen and [my] fatlings [are] killed, and all things [are] ready: come to the marriage.", "vulgate": "iterum misit alios servos dicens dicite invitatis ecce prandium meum paravi tauri mei et altilia occisa et omnia parata venite ad nuptias;"}}, {"v": 5, "ref": "22:5", "o": "οἱ δὲ ἀμελήσαντες ἀπῆλθον, ⸀ὃς μὲν εἰς τὸν ἴδιον ἀγρόν, ⸁ὃς δὲ ⸀ἐπὶ τὴν ἐμπορίαν αὐτοῦ·", "en": {"kjv": "But they made light of it, and went their ways, one to his farm, another to his merchandise:", "web": "But they made light of it, and went their ways, one to his own farm, another to his merchandise,", "bsb": "But they paid no attention and went away, one to his field, another to his business.", "asv": "But they made light of it, and went their ways, one to his own farm, another to his merchandise;", "ylt": "and they, having disregarded it , went away, the one to his own field, and the other to his merchandise;", "tyndale": "But they made light of it and went their wayes: one to his ferme place another about his marchaundise", "dra": "But they neglected and went their ways, one to his farm and another to his merchandise.", "bbe": "But they gave no attention, and went about their business, one to his farm, another to his trade:", "geneva": "But they made light of it, and went their wayes, one to his farme, and another about his marchandise.", "wycliffe": "But thei dispisiden, and wenten forth, oon in to his toun, anothir to his marchaundise. But othere helden his seruauntis, and turmentiden hem, and slowen.", "rotherham": "And, they, slighting it, went off, one, indeed, into his own field, and, another, unto his merchandise,—", "weymouth": "\"They however gave no heed, but went, one to his home in the country, another to his business;", "darby": "But they made light of it, and went, one to his own land, and another to his commerce.", "twenty": "They, however, took no notice, but went off, one to his farm, another to his business;", "acv": "But having disregarded, they departed, one to his own farm, another to his merchandise,", "anderson": "But they were careless, and went away, one to his farm, another to his merchandise.", "haweis": "But they gave themselves no concern about it, and went their several ways, one to his own farm, and another to his traffick:", "noyes": "But they made light of it, and went away; one to his farm, another to his merchandise.", "webster": "But they made light of [it], and went, one to his farm, another to his merchandise.", "vulgate": "illi autem neglexerunt et abierunt alius in villam suam alius vero ad negotiationem suam;"}}, {"v": 6, "ref": "22:6", "o": "οἱ δὲ λοιποὶ κρατήσαντες τοὺς δούλους αὐτοῦ ὕβρισαν καὶ ἀπέκτειναν.", "en": {"kjv": "And the remnant took his servants, and entreated them spitefully, and slew them.", "web": "and the rest grabbed his servants, and treated them shamefully, and killed them.", "bsb": "The rest seized his servants, mistreated them, and killed them.", "asv": "and the rest laid hold on his servants, and treated them shamefully, and killed them.", "ylt": "and the rest, having laid hold on his servants, did insult and slay them .", "tyndale": "the remnaunt toke his seruantes and intreated them vngodly and slewe them.", "dra": "And the rest laid hands on his servants and, having treated them contumeliously, put them to death.", "bbe": "And the rest put violent hands on his servants, and did evil to them, and put them to death.", "geneva": "And the remnant tooke his seruants, and intreated them sharpely, and slewe them.", "wycliffe": "", "rotherham": "And, the rest, securing his servants, ill-treated and slew them.", "weymouth": "and the rest seized the king's servants, maltreated them, and murdered them.", "darby": "And the rest, laying hold of his bondmen, ill-treated and slew [them].", "twenty": "while the rest, seizing his servants, ill-treated them and killed them.", "acv": "and the others having seized his bondmen, abused and killed them.", "anderson": "And the rest laid hold of his servants, and abused them, and killed them.", "haweis": "And the rest seizing his servants, insulted and slew them.", "noyes": "And the rest seized his servants, and ill-treated and slew them.", "webster": "And the remnant took his servants, and treated [them] spitefully, and slew [them].", "vulgate": "reliqui vero tenuerunt servos eius et contumelia adfectos occiderunt;"}}, {"v": 7, "ref": "22:7", "o": "⸂ὁ δὲ βασιλεὺς⸃ ὠργίσθη, καὶ πέμψας τὰ στρατεύματα αὐτοῦ ἀπώλεσεν τοὺς φονεῖς ἐκείνους καὶ τὴν πόλιν αὐτῶν ἐνέπρησεν.", "en": {"kjv": "But when the king heard thereof, he was wroth: and he sent forth his armies, and destroyed those murderers, and burned up their city.", "web": "When the king heard that, he was angry, and sent his armies, destroyed those murderers, and burned their city.", "bsb": "The king was enraged, and he sent his troops to destroy those murderers and burn their city.", "asv": "But the king was wroth; and he sent his armies, and destroyed those murderers, and burned their city.", "ylt": "`And the king having heard, was wroth, and having sent forth his soldiers, he destroyed those murderers, and their city he set on fire;", "tyndale": "When the kinge hearde that he was wroth and send forth his warryers and distroyed those murtherers and brent vp their cyte.", "dra": "But when the king had heard of it, he was angry: and sending his armies, he destroyed those murderers and burnt their city.", "bbe": "But the king was angry; and he sent his armies, and those who had put his servants to death he gave to destruction, burning down their town with fire.", "geneva": "But when the King heard it, he was wroth, and sent foorth his warriers, and destroyed those murtherers, and burnt vp their citie.", "wycliffe": "But the kyng, whanne he hadde herd, was wroth; and he sente hise oostis, and he distruyede tho manquelleris, and brente her citee.", "rotherham": "And, the king, was provoked to anger,—and, sending his armies, destroyed those murderers, and, their city, set on fire.", "weymouth": "So the king's anger was stirred, and he sent his troops and destroyed those murderers and burnt their city.", "darby": "And [when] the king [heard of it he] was wroth, and having sent his forces, destroyed those murderers and burned their city.", "twenty": "The king, in anger, sent his troops, put those murderers to death, and set their city on fire.", "acv": "But having heard that, the king was angry, and having sent forth his armies, he destroyed those murderers, and burned their city.", "anderson": "And when that king heard of it, he was angry, and sent his armies, and destroyed those murderers, and burned up their city.", "haweis": "Then the king, when he heard it, was incensed: and sending out his armies, destroyed these murderers, and burnt down their city.", "noyes": "And the king was enraged; and sent forth his armies, and destroyed those murderers, and burned their city.", "webster": "But when the king heard [of it], he was wroth: and he sent his armies, and destroyed those murderers, and burned up their city.", "vulgate": "rex autem cum audisset iratus est et missis exercitibus suis perdidit homicidas illos et civitatem illorum succendit;"}}, {"v": 8, "ref": "22:8", "o": "τότε λέγει τοῖς δούλοις αὐτοῦ· Ὁ μὲν γάμος ἕτοιμός ἐστιν, οἱ δὲ κεκλημένοι οὐκ ἦσαν ἄξιοι·", "en": {"kjv": "Then saith he to his servants, The wedding is ready, but they which were bidden were not worthy.", "web": "“Then he said to his servants, ‘The wedding is ready, but those who were invited weren’t worthy.", "bsb": "Then he said to his servants, ‘The wedding banquet is ready, but those I invited were not worthy.", "asv": "Then saith he to his servants, The wedding is ready, but they that were bidden were not worthy.", "ylt": "then saith he to his servants, The marriage-feast indeed is ready, and those called were not worthy,", "tyndale": "Then sayde he to his servauutes: the weddinge was prepared. But they which were bydden were not worthy.", "dra": "Then he saith to his servants: The marriage indeed is ready; but they that were invited were not worthy.", "bbe": "Then he said to his servants, The feast is ready but the guests were not good enough.", "geneva": "Then saide hee to his seruants, Truely the wedding is prepared: but they which were bidden, were not worthy.", "wycliffe": "Thanne he seide to hise seruauntis, The weddyngis ben redi, but thei that weren clepid to the feeste, weren not worthi.", "rotherham": "Then, saith he unto his servants—The marriage, indeed, is ready,—but, the invited, were not, worthy;", "weymouth": "Then he said to his servants, \"`The wedding banquet is ready, but those who were invited were unworthy of it.", "darby": "Then he says to his bondmen, The wedding feast is ready, but those invited were not worthy;", "twenty": "Then he said to his servants ‘The banquet is prepared, but those who were invited were not worthy.", "acv": "Then he says to his bondmen, The wedding is indeed ready, but those who were invited were not worthy.", "anderson": "Then he said to his servants: The marriage feast is ready, but those who were invited were not worthy.", "haweis": "Then he said to his servants, The wedding entertainment indeed is ready, but those who were invited were not worthy:", "noyes": "Then saith he to his servants, The feast is ready, but those who were invited were not worthy.", "webster": "Then he saith to his servants, The wedding is ready, but they who were invited were not worthy.", "vulgate": "tunc ait servis suis nuptiae quidem paratae sunt sed qui invitati erant non fuerunt digni;"}}, {"v": 9, "ref": "22:9", "o": "πορεύεσθε οὖν ἐπὶ τὰς διεξόδους τῶν ὁδῶν, καὶ ὅσους ⸀ἐὰν εὕρητε καλέσατε εἰς τοὺς γάμους.", "en": {"kjv": "Go ye therefore into the highways, and as many as ye shall find, bid to the marriage.", "web": "Go therefore to the intersections of the highways, and as many as you may find, invite to the marriage feast.’", "bsb": "Go therefore to the crossroads and invite to the banquet as many as you can find.’", "asv": "Go ye therefore unto the partings of the highways, and as many as ye shall find, bid to the marriage feast.", "ylt": "be going, then, on to the cross-ways, and as many as ye may find, call ye to the marriage-feasts.", "tyndale": "Go ye therfore out into ye hyewayes and as many as ye finde byd them to the mariage.", "dra": "Go ye therefore into the highways; and as many as you shall find, call to the marriage.", "bbe": "Go then to the cross-roads, and get all those whom you see to come to the bride-feast.", "geneva": "Go ye therefore out into the high wayes, and as many as ye finde, bid them to the mariage.", "wycliffe": "Therfor go ye to the endis of weies, and whom euere ye fynden, clepe ye to the weddyngis.", "rotherham": "Be going, therefore, into the crossways of the roads, and, as many as ye shall find, call ye into the marriage-feast.", "weymouth": "Go out therefore to the crossroads, and everybody you meet invite to the wedding.'", "darby": "go therefore into the thoroughfares of the highways, and as many as ye shall find invite to the wedding feast.", "twenty": "So go to the cross-roads, and invite everyone you find to the banquet.’", "acv": "Go ye therefore to the crossings of the ways, and as many as ye may find, call to the wedding festivities.", "anderson": "Go, therefore, to the cross-ways, and invite to the marriage feast as many as you find.", "haweis": "go therefore into the thoroughfares of the roads, and as many as ye find, invite to the banquet.", "noyes": "Go therefore into the thoroughfares, and as many as ye find, invite to the feast.", "webster": "Go ye therefore into the highways, and as many as ye shall find, invite to the marriage.", "vulgate": "ite ergo ad exitus viarum et quoscumque inveneritis vocate ad nuptias;"}}, {"v": 10, "ref": "22:10", "o": "καὶ ἐξελθόντες οἱ δοῦλοι ἐκεῖνοι εἰς τὰς ὁδοὺς συνήγαγον πάντας ⸀οὓς εὗρον, πονηρούς τε καὶ ἀγαθούς· καὶ ἐπλήσθη ὁ ⸀γάμος ἀνακειμένων.", "en": {"kjv": "So those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was furnished with guests.", "web": "Those servants went out into the highways, and gathered together as many as they found, both bad and good. The wedding was filled with guests.", "bsb": "So the servants went out into the streets and gathered everyone they could find, both evil and good, and the wedding hall was filled with guests.", "asv": "And those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was filled with guests.", "ylt": "`And those servants, having gone forth to the ways, did gather all, as many as they found, both bad and good, and the marriage-feast apartment was filled with those reclining.", "tyndale": "The seruauntes wet out into the hiewayes and gaddered to gedder as many as they coulde fynde both good and bad and ye weddinge was furnysshed with gestes.", "dra": "And his servants going forth into the ways, gathered together all that they found, both bad and good: and the marriage was filled with guests.", "bbe": "And those servants went out into the streets, and got together all those whom they came across, bad and good: and the feast was full of guests.", "geneva": "So those seruantes went out into the hie wayes, and gathered together all that euer they found, both good and bad: so the wedding was furnished with ghestes.", "wycliffe": "And hise seruauntis yeden out in to weies, and gadriden togider alle that thei founden, good and yuele; and the bridale was fulfillid with men sittynge at the mete.", "rotherham": "And those servants, going forth, into the roads, gathered together all whom they found, both bad and good,—and filled was the bride-chamber with guests.", "weymouth": "\"So they went out into the roads and gathered together all they could find, both bad and good, and the banqueting hall was filled with guests.", "darby": "And those bondmen went out into the highways, and brought together all as many as they found, both evil and good; and the wedding feast was furnished with guests.", "twenty": "The servants went out into the roads and collected all the people whom they found, whether bad or good; and the bridal-hall was filled with guests.", "acv": "And those bondmen having departed into the roads, they gathered together all, as many as they found, both bad and good. And the wedding was filled with those who were dining.", "anderson": "And those servants went out into the roads, and brought together all, as many as they found, both bad and good: and the banquet-room was filled with guests.", "haweis": "So these servants going out into the roads, collected all, as many as they found, both bad and good; and the wedding feast was fully furnished with guests.", "noyes": "So those servants went out into the highways, and gathered together all, as many as they found, both bad and good; and the bride-chamber was fully furnished with guests.", "webster": "So those servants went out into the highways, and collected all as many as they found, both bad and good: and the wedding was furnished with guests.", "vulgate": "et egressi servi eius in vias congregaverunt omnes quos invenerunt malos et bonos et impletae sunt nuptiae discumbentium;"}}, {"v": 11, "ref": "22:11", "o": "εἰσελθὼν δὲ ὁ βασιλεὺς θεάσασθαι τοὺς ἀνακειμένους εἶδεν ἐκεῖ ἄνθρωπον οὐκ ἐνδεδυμένον ἔνδυμα γάμου·", "en": {"kjv": "And when the king came in to see the guests, he saw there a man which had not on a wedding garment:", "web": "But when the king came in to see the guests, he saw there a man who didn’t have on wedding clothing,", "bsb": "But when the king came in to see the guests, he spotted a man who was not dressed in wedding clothes.", "asv": "But when the king came in to behold the guests, he saw there a man who had not on a wedding-garment:", "ylt": "`And the king having come in to view those reclining, saw there a man not clothed with clothing of the marriage-feast,", "tyndale": "Then the kynge came in to viset the gestes and spyed there a ma which had not on a weddinge garment", "dra": "And the king went in to see the guests: and he saw there a man who had not on a wedding garment.", "bbe": "But when the king came in to see the guests, he saw there a man who had not on a guest's robe;", "geneva": "Then the King came in, to see the ghestes, and sawe there a man which had not on a wedding garment.", "wycliffe": "And the kyng entride, to se men sittynge at the mete; and he siye there a man not clothid with bride cloth.", "rotherham": "But the king, entering to view the guests, saw there a man, who had not put on a wedding-garment,—", "weymouth": "\"Now the king came in to see the guests; and among them he discovered one who was not wearing a wedding-robe.", "darby": "And the king, having gone in to see the guests, beheld there a man not clothed with a wedding garment.", "twenty": "But, when the king went in to see his guests, he noticed there a man who had not put on a wedding-robe.", "acv": "But when the king came in to see those who were dining, he saw there a man who was not clothed with a wedding garment.", "anderson": "And when the king came in to see the guests, he saw there a man that had not put on a wedding-robe.", "haweis": "Then the king coming in to look around on the guests, saw there a man who had not put on the wedding garment:", "noyes": "And the king, coming in to view the guests, saw there a man who had not on a wedding garment;", "webster": "And when the king came in to see the guests, he saw there a man who had not a wedding-garment:", "vulgate": "intravit autem rex ut videret discumbentes et vidit ibi hominem non vestitum veste nuptiali;"}}, {"v": 12, "ref": "22:12", "o": "καὶ λέγει αὐτῷ· Ἑταῖρε, πῶς εἰσῆλθες ὧδε μὴ ἔχων ἔνδυμα γάμου; ὁ δὲ ἐφιμώθη.", "en": {"kjv": "And he saith unto him, Friend, how camest thou in hither not having a wedding garment? And he was speechless.", "web": "and he said to him, ‘Friend, how did you come in here not wearing wedding clothing?’ He was speechless.", "bsb": "‘Friend,’ he asked, ‘how did you get in here without wedding clothes?’ But the man was speechless.", "asv": "and he saith unto him, Friend, how camest thou in hither not having a wedding-garment? And he was speechless.", "ylt": "and he saith to him, Comrade, how didst thou come in hither, not having clothing of the marriage-feast? and he was speechless.", "tyndale": "and sayde vnto him: frende how fortuned it that thou camest in hither and hast not on a weddyng garment? And he was eve spechlesse.", "dra": "And he saith to him: Friend, how camest thou in hither not having on a wedding garment? But he was silent.", "bbe": "And he says to him, Friend, how came you in here not having a guest's robe? And he had nothing to say.", "geneva": "And he sayd vnto him, Friend, how camest thou in hither, and hast not on a wedding garment? And he was speachlesse.", "wycliffe": "And he seide to hym, Freend, hou entridist thou hidir with out bride clothis? And he was doumbe.", "rotherham": "And saith unto him—Friend! how camest thou in here, not having a wedding-garment? And, he, was put to silence.", "weymouth": "\"`My friend,' he said, `how is it that you came in here without a wedding robe?'", "darby": "And he says to him, [My] friend, how camest thou in here not having on a wedding garment? But he was speechless.", "twenty": "So he said to him ‘My friend, how is it that you came in here without a wedding-robe?’ The man was speechless.", "acv": "And he says to him, Friend, how did thou come in here not having a wedding garment? But he was speechless.", "anderson": "And he said to him, Friend, how came you in hither without a wedding-robe? And he was silent.", "haweis": "and he saith to him, Friend, how came thou in here, not having the garment provided for the marriage feast? And he was speechless.", "noyes": "and he saith to him, Friend, how camest thou in here, not having a wedding garment? And he was struck dumb.", "webster": "And he saith to him, Friend, how camest thou in hither, not having a wedding-garment? And he was speechless.", "vulgate": "et ait illi amice quomodo huc intrasti non habens vestem nuptialem at ille obmutuit;"}}, {"v": 13, "ref": "22:13", "o": "τότε ⸂ὁ βασιλεὺς εἶπεν⸃ τοῖς διακόνοις· Δήσαντες αὐτοῦ πόδας καὶ χεῖρας ⸂ἐκβάλετε αὐτὸν⸃ εἰς τὸ σκότος τὸ ἐξώτερον· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "Then said the king to the servants, Bind him hand and foot, and take him away, and cast him into outer darkness; there shall be weeping and gnashing of teeth.", "web": "Then the king said to the servants, ‘Bind him hand and foot, take him away, and throw him into the outer darkness; there is where the weeping and grinding of teeth will be.’", "bsb": "Then the king told the servants, ‘Tie him hand and foot, and throw him into the outer darkness, where there will be weeping and gnashing of teeth.’", "asv": "Then the king said to the servants, Bind him hand and foot, and cast him out into the outer darkness; there shall be the weeping and the gnashing of teeth.", "ylt": "`Then said the king to the ministrants, Having bound his feet and hands, take him up and cast forth to the outer darkness, there shall be the weeping and the gnashing of the teeth;", "tyndale": "Then sayde the kynge to his ministers: take and bynde hym hand and fote and caste hym into vtter darcknes there shalbe wepinge and gnasshinge of teth.", "dra": "Then the king said to the waiters: Bind his hands and feet, and cast him into the exterior darkness. There shall be weeping and gnashing of teeth.", "bbe": "Then the king said to the servants, Put cords round his hands and feet and put him out into the dark; there will be weeping and cries of sorrow.", "geneva": "Then sayd the King to the seruants, Binde him hand and foote: take him away, and cast him into vtter darkenes: there shalbe weeping and gnashing of teeth.", "wycliffe": "Thanne the kyng bad hise mynystris, Bynde hym bothe hondis and feet, and sende ye him in to vtmer derknessis; there schal be wepyng and grentyng of teeth.", "rotherham": "Then, the king said unto the ministers, Binding him feet and hands, cast him forth into the darkness, outside: There, shall be wafting and gnashing of teeth.", "weymouth": "\"The man stood speechless. Then the king said to the servants, \"`Bind him hand and foot and fling him into the darkness outside: there will be the weeping aloud and the gnashing of teeth.'", "darby": "Then said the king to the servants, Bind him feet and hands, and take him away, and cast him out into the outer darkness: there shall be the weeping and the gnashing of teeth.", "twenty": "Then the king said to the attendants ‘Tie him hand and foot, and ‘put him out into the darkness’ outside, where there will be weeping and grinding of teeth.’", "acv": "Then the king said to the helpers, After binding him hands and feet, take him away and cast him out into the outer darkness. There will be the weeping and the gnashing of teeth.", "anderson": "Then the king said to his servants, Bind him hand and foot, and take him away, and throw him into the darkness without: there shall be weeping and gnashing of teeth.", "haweis": "Then said the king to the servants, Bind his feet and hands, and take him away, and cast him into the darkness, which is without; there shall be weeping and gnashing of teeth.", "noyes": "Then the king said to the servants, Bind him hand and foot, and cast him out into the outer darkness; there will be wailing and gnashing of teeth.", "webster": "Then said the king to the servants, Bind him hand and foot, and take him away, and cast [him] into utter darkness: there shall be weeping and gnashing of teeth.", "vulgate": "tunc dixit rex ministris ligatis pedibus eius et manibus mittite eum in tenebras exteriores ibi erit fletus et stridor dentium;"}}, {"v": 14, "ref": "22:14", "o": "πολλοὶ γάρ εἰσιν κλητοὶ ὀλίγοι δὲ ἐκλεκτοί.", "en": {"kjv": "For many are called, but few are chosen.", "web": "For many are called, but few chosen.”", "bsb": "For many are called, but few are chosen.”", "asv": "For many are called, but few chosen.", "ylt": "for many are called, and few chosen.'", "tyndale": "For many are called and feawe be chosen.", "dra": "For many are called, but few are chosen.", "bbe": "For out of all to whom the good news has come, only a small number will get salvation.", "geneva": "For many are called, but fewe chosen.", "wycliffe": "For many ben clepid, but fewe ben chosun.", "rotherham": "For, many, are called, but, few, chosen.", "weymouth": "\"For there are many called, but few chosen.\"", "darby": "For many are called ones, but few chosen ones.", "twenty": "For many are called, but few chosen.”", "acv": "For many are called, but few chosen.", "anderson": "For many are called, but few chosen.", "haweis": "For many are called, but few elect.", "noyes": "For many are called, but few are chosen.", "webster": "For many are called, but few [are] chosen.", "vulgate": "multi autem sunt vocati pauci vero electi;"}}, {"v": 15, "ref": "22:15", "o": "Τότε πορευθέντες οἱ Φαρισαῖοι συμβούλιον ἔλαβον ὅπως αὐτὸν παγιδεύσωσιν ἐν λόγῳ.", "en": {"kjv": "Then went the Pharisees, and took counsel how they might entangle him in his talk.", "web": "Then the Pharisees went and took counsel how they might entrap him in his talk.", "bsb": "Then the Pharisees went out and conspired to trap Jesus in His words.", "asv": "Then went the Pharisees, and took counsel how they might ensnare him in his talk.", "ylt": "Then the Pharisees having gone, took counsel how they might ensnare him in words,", "tyndale": "Then wet the Pharises and toke counsell how they might tagle him in his wordes.", "dra": "Then the Pharisees going, consulted among themselves how to insnare him in his speech.", "bbe": "Then the Pharisees went and had a meeting to see how they might make use of his words to take him.", "geneva": "Then went the Pharises and tooke counsell how they might tangle him in talke.", "wycliffe": "Thanne Farisees yeden awei, and token a counsel to take Jhesu in word.", "rotherham": "Then, went the Pharisees and took, counsel, that they might ensnare him, in discourse.", "weymouth": "Then the Pharisees went and consulted together how they might entrap Him in His conversation.", "darby": "Then went the Pharisees and held a council how they might ensnare him in speaking.", "twenty": "Then the Pharisees went away and conferred together as to how they might lay a snare for Jesus in the course of conversation.", "acv": "Then the Pharisees having departed, they took counsel how they might trap him in his talk.", "anderson": "Then the Pharisees went and held a consultation, that they might entrap him in his words.", "haweis": "Then went the Pharisees, and took counsel together how they might lay a snare to entrap him in his discourse.", "noyes": "Then the Pharisees went and consulted together how l they might ensnare him in speech.", "webster": "Then went the Pharisees, and took counsel how they might entangle him in [his] talk.", "vulgate": "tunc abeuntes Pharisaei consilium inierunt ut caperent eum in sermone;"}}, {"v": 16, "ref": "22:16", "o": "καὶ ἀποστέλλουσιν αὐτῷ τοὺς μαθητὰς αὐτῶν μετὰ τῶν Ἡρῳδιανῶν ⸀λέγοντες· Διδάσκαλε, οἴδαμεν ὅτι ἀληθὴς εἶ καὶ τὴν ὁδὸν τοῦ θεοῦ ἐν ἀληθείᾳ διδάσκεις, καὶ οὐ μέλει σοι περὶ οὐδενός, οὐ γὰρ βλέπεις εἰς πρόσωπον ἀνθρώπων·", "en": {"kjv": "And they sent out unto him their disciples with the Herodians, saying, Master, we know that thou art true, and teachest the way of God in truth, neither carest thou for any man: for thou regardest not the person of men.", "web": "They sent their disciples to him, along with the Herodians, saying, “Teacher, we know that you are honest, and teach the way of God in truth, no matter whom you teach, for you aren’t partial to anyone.", "bsb": "They sent their disciples to Him along with the Herodians. “Teacher,” they said, “we know that You are honest and that You teach the way of God in accordance with the truth. You seek favor from no one, because You pay no attention to external appearance.", "asv": "And they send to him their disciples, with the Herodians, saying, Teacher, we know that thou art true, and teachest the way of God in truth, and carest not for any one: for thou regardest not the person of men.", "ylt": "and they send to him their disciples with the Herodians, saying, `Teacher, we have known that thou art true, and the way of God in truth thou dost teach, and thou art not caring for any one, for thou dost not look to the face of men;", "tyndale": "And they sent vnto him their disciples with Herodes servauntes sayinge: Master we knowe yt thou are true and teachest the waye of god trulie nether carest for eny man for thou consydrest not menes estate.", "dra": "And they sent to him their disciples with the Herodians, saying: Master, we know that thou art a true speaker and teachest the way of God in truth. Neither carest thou for any man: for thou dost not regard the person of men.", "bbe": "And they sent to him their disciples, with the Herodians, saying, Master, we see that you are true, and that you are teaching the true way of God, and have no fear of anyone, because you have no respect for a man's position.", "geneva": "And they sent vnto him their disciples with the Herodians, saying, Master, we knowe that thou art true, and teachest the way of God truely, neither carest for any man: for thou considerest not the person of men.", "wycliffe": "And thei senden to hym her disciplis, with Erodians, and seien, Maister, we witen, that thou art sothefast, and thou techist in treuthe the weie of God, and thou chargist not of ony man, for thou biholdist not the persoone of men.", "rotherham": "And they sent forth to him their disciples, with the Herodians, saying, Teacher! we know that, true, thou art, and, the way of God, in truth, dost teach, and it concerneth thee not about anyone,—for thou lookest not unto the face of men:", "weymouth": "So they sent to Him their disciples together with the Herodians; who said, \"Teacher, we know that you are truthful and that you faithfully teach God's truth; and that no fear of man misleads you, for you are not biased by men's wealth or rank.", "darby": "And they send out to him their disciples with the Herodians, saying, Teacher, we know that thou art true and teachest the way ofGod in truth, and carest not for any one, for thou regardest not men's person;", "twenty": "They sent their disciples, with the Herodians, to say to him: “Teacher, we know that you are an honest man, and that you teach the way of God honestly, and are not afraid of any one; for you pay no regard to a man’s position.", "acv": "And they send out their disciples to him, with the Herodians, saying, Teacher, we know that thou are true, and teach the way of God in truth, and it is not a concern to thee about a man, for thou look not to the personage of men.", "anderson": "And they sent to him their disciples, with the Herodians, saying: Teacher, we know that you are true, and that you teach the way of God in truth, and care not for any one: for you do not look upon the person of men.", "haweis": "And they sent to him their disciples, with the Herodians, saying, Master, we know that thou art true, and teachest the way of God with veracity; and carest for no man, for thou regardest not the person of men:", "noyes": "And they send out to him their disciples with the Herodians, saying, Teacher, we know that thou art true, and teachest the way of God in truth, and thou carest for no one; for thou regardest not the person of men.", "webster": "And they sent out to him their disciples, with the Herodians, saying, Master, we know that thou art true, and teachest the way of God in truth, neither carest thou for any [man]: for thou regardest not the person of men.", "vulgate": "et mittunt ei discipulos suos cum Herodianis dicentes magister scimus quia verax es et viam Dei in veritate doces et non est tibi cura de aliquo non enim respicis personam hominum;"}}, {"v": 17, "ref": "22:17", "o": "εἰπὸν οὖν ἡμῖν τί σοι δοκεῖ· ἔξεστιν δοῦναι κῆνσον Καίσαρι ἢ οὔ;", "en": {"kjv": "Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Cesar, or not?", "web": "Tell us therefore, what do you think? Is it lawful to pay taxes to Caesar, or not?”", "bsb": "So tell us what You think: Is it lawful to pay taxes to Caesar or not?”", "asv": "Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Cæsar, or not?", "ylt": "tell us, therefore, what dost thou think? is it lawful to give tribute to Caesar or not?'", "tyndale": "Tell vs therfore: how thynkest thou? Is it lawfull to geve tribute vnto Cesar or not?", "dra": "Tell us therefore what dost thou think? Is it lawful to give tribute to Caesar, or not?", "bbe": "Give us, then, your opinion of this: Is it right to give tax to Caesar, or not?", "geneva": "Tell vs therefore, how thinkest thou? Is it lawfull to giue tribute vnto Cesar, or not?", "wycliffe": "Therfor seie to vs, what it seemeth to thee. Is it leueful that tribute be youun to the emperoure, ether nay?", "rotherham": "Tell us then, how, to thee, it seemeth? Is it allowable to give tax unto Caesar, or not?", "weymouth": "Give us your judgement therefore: is it allowable for us to pay a poll-tax to Caesar, or not?\"", "darby": "tell us therefore what thou thinkest: Is it lawful to give tribute to Caesar, or not?", "twenty": "Tell us, then, what you think. Are we right in paying taxes to the Emperor, or not?”", "acv": "Tell us therefore, what does it seem to thee? Is it permitted to give tribute to Caesar or not?", "anderson": "Tell us, therefore, what do you think? Is it lawful to give tribute to Cæsar, or not?", "haweis": "tell us therefore, What thinkest thou? Is it lawful to pay tribute to Caesar, or not?", "noyes": "Tell us, therefore, What thinkest thou? Is it lawful to give tribute to Caesar, or not?", "webster": "Tell us therefore, What thinkest thou? Is it lawful to give tribute to Cesar, or not?", "vulgate": "dic ergo nobis quid tibi videatur licet censum dare Caesari an non;"}}, {"v": 18, "ref": "22:18", "o": "γνοὺς δὲ ὁ Ἰησοῦς τὴν πονηρίαν αὐτῶν εἶπεν· Τί με πειράζετε, ὑποκριταί;", "en": {"kjv": "But Jesus perceived their wickedness, and said, Why tempt ye me, ye hypocrites?", "web": "But Jesus perceived their wickedness, and said, “Why do you test me, you hypocrites?", "bsb": "But Jesus knew their evil intent and said, “You hypocrites, why are you testing Me?", "asv": "But Jesus perceived their wickedness, and said, Why make ye trial of me, ye hypocrites?", "ylt": "And Jesus having known their wickedness, said, `Why me do ye tempt, hypocrites?", "tyndale": "Iesus perceaved their wikednes and sayde: Why tempte ye me ye ypocrites?", "dra": "But Jesus knowing their wickedness, said: Why do you tempt me, ye hypocrites?", "bbe": "But Jesus saw their trick and said, Oh false ones, why are you attempting to put me in the wrong?", "geneva": "But Iesus perceiued their wickednes, and sayd, Why tempt ye me, ye hypocrites?", "wycliffe": "And whanne Jhesus hadde knowe the wickidnesse of hem, he seide, Ypocritis, what tempten ye me?", "rotherham": "But Jesus, taking note of their wickedness, said—Why are ye tempting me, hypocrites?", "weymouth": "Perceiving their wickedness, Jesus replied, \"Why are you hypocrites trying to ensnare me?", "darby": "But Jesus, knowing their wickedness, said, Why tempt ye me, hypocrites?", "twenty": "Perceiving their malice, Jesus answered: “Why are you testing me, you hypocrites?", "acv": "But Jesus having known their wickedness, said, Why do ye tempt me, ye hypocrites?", "anderson": "But Jesus, knowing their wickedness, said to them: Why do you tempt me, hypocrites?", "haweis": "But Jesus knew their wicked design, and said, Why tempt ye me, ye hypocrites?", "noyes": "But Jesus, perceiving their wickedness, said, Why are ye trying me, hypocrites?", "webster": "But Jesus perceived their wickedness, and said, Why tempt ye me, [ye] hypocrites?", "vulgate": "cognita autem Iesus nequitia eorum ait quid me temptatis hypocritae;"}}, {"v": 19, "ref": "22:19", "o": "ἐπιδείξατέ μοι τὸ νόμισμα τοῦ κήνσου. οἱ δὲ προσήνεγκαν αὐτῷ δηνάριον.", "en": {"kjv": "Shew me the tribute money. And they brought unto him a penny.", "web": "Show me the tax money.” They brought to him a denarius.", "bsb": "Show Me the coin used for the tax.” And they brought Him a denarius.", "asv": "Show me the tribute money. And they brought unto him a denarius.", "ylt": "show me the tribute-coin?' and they brought to him a denary;", "tyndale": "Let me se ye tribute money. And they toke hym a peny.", "dra": "Shew me the coin of the tribute. And they offered him a penny.", "bbe": "Let me see the tax money. And they gave him a penny.", "geneva": "Shewe me the tribute money. And they brought him a peny.", "wycliffe": "Schewe ye to me the prynte of the money. And thei brouyten to hym a peny.", "rotherham": "Shew me the coin appointed for the tax. And, they, brought unto him a denary.", "weymouth": "Show me the tribute coin.\" And they brought Him a shilling.", "darby": "Shew me the money of the tribute. And they presented to him a denarius.", "twenty": "Show me the coin with which the tax is paid.” And, when they had brought him a florin,", "acv": "Exhibit to me the tribute money. And they brought to him a denarius.", "anderson": "Show me the tribute-money. And they brought him a denarius.", "haweis": "Shew me the money for the tribute; and they brought him a denarius.", "noyes": "Show me the tribute money. And they brought to him a denary.", "webster": "Show me the tribute-money. And they brought to him a penny.", "vulgate": "ostendite mihi nomisma census at illi obtulerunt ei denarium;"}}, {"v": 20, "ref": "22:20", "o": "καὶ λέγει αὐτοῖς· Τίνος ἡ εἰκὼν αὕτη καὶ ἡ ἐπιγραφή;", "en": {"kjv": "And he saith unto them, Whose is this image and superscription?", "web": "He asked them, “Whose is this image and inscription?”", "bsb": "“Whose image is this,” He asked, “and whose inscription?”", "asv": "And he saith unto them, Whose is this image and superscription?", "ylt": "and he saith to them, `Whose is this image and the inscription?'", "tyndale": "And he sayde vnto them: whose is this ymage and superscripcion?", "dra": "And Jesus saith to them: Whose image and inscription is this?", "bbe": "And he said to them, Whose is this image and name on it?", "geneva": "And he sayde vnto them, Whose is this image and superscription?", "wycliffe": "And Jhesus seide to hem, Whos is this ymage, and the writyng aboue?", "rotherham": "And he saith unto them—Whose, is this image and the inscription?", "weymouth": "\"Whose likeness and inscription,\" He asked, \"is this?\"", "darby": "And he says to them, Whose [is] this image and superscription?", "twenty": "he asked: “Whose head and title are these?”", "acv": "And he says to them, Whose is this image and inscription?", "anderson": "And he said to them: Whose image and superscription is this?", "haweis": "And he saith unto them, Whose figure is this and inscription?", "noyes": "And Jesus saith to them, Whose is this image and inscription?", "webster": "And he saith to them, Whose [is] this image, and superscription?", "vulgate": "et ait illis Iesus cuius est imago haec et suprascriptio;"}}, {"v": 21, "ref": "22:21", "o": "λέγουσιν ⸀αὐτῷ· Καίσαρος. τότε λέγει αὐτοῖς· Ἀπόδοτε οὖν τὰ Καίσαρος Καίσαρι καὶ τὰ τοῦ θεοῦ τῷ θεῷ.", "en": {"kjv": "They say unto him, Cesar’s. Then saith he unto them, Render therefore unto Cesar the things which are Cesar’s; and unto God the things that are God’s.", "web": "They said to him, “Caesar’s.” Then he said to them, “Give therefore to Caesar the things that are Caesar’s, and to God the things that are God’s.”", "bsb": "“Caesar’s,” they answered. So Jesus told them, “Give to Caesar what is Caesar’s, and to God what is God’s.”", "asv": "They say unto him, Cæsar’s. Then saith he unto them, Render therefore unto Cæsar the things that are Cæsar’s; and unto God the things that are God’s.", "ylt": "they say to him, `Caesar's;' then saith he to them, `Render therefore the things of Caesar to Caesar, and the things of God to God;'", "tyndale": "They sayde vnto him: Cesars. Then sayde he vnto them. Geve therfore to Cesar that which is Cesars: and geve vnto god that which is goddes.", "dra": "They say to him: Caesar's. Then he saith to them: Render therefore to Caesar the things that are Caesar's; and to God, the things that are God's.", "bbe": "They say to him, Caesar's. Then he said to them, Give to Caesar the things which are Caesar's, and to God the things which are God's.", "geneva": "They sayd vnto him, Cesars. Then sayd he vnto them, Giue therefore to Cesar, the things which are Cesars, and giue vnto God, those things which are Gods.", "wycliffe": "Thei seien to hym, The emperouris. Thanne he seide to hem, Therfor yelde ye to the emperoure tho thingis that ben the emperouris, and to God tho thingis that ben of God.", "rotherham": "They say—Caesar’s. Then, saith he unto them—Render, therefore, the things of Caesar, unto Caesar,—and, the things of God, unto God.", "weymouth": "\"Caesar's,\" they replied. \"Pay therefore,\" He rejoined, \"what is Caesar's to Caesar; and what is God's to God.\"", "darby": "They say to him, Caesar's. Then he says to them, Pay then what is Caesar's to Caesar, and what isGod's toGod.", "twenty": "“The Emperor’s,” they answered: on which he said to them: “Then pay to the Emperor what belongs to the Emperor, and to God what belongs to God.”", "acv": "They say to him, Caesar's. Then he says to them, Therefore, render the things of Caesar to Caesar, and the things of God to God.", "anderson": "They said to him: Cæsar’s. Then he said to them: Give, therefore, to Cæsar the things that are Cæsar’s, and to God the things that are God’s.", "haweis": "They say unto him, Caesar’s. Then saith he to them, Render therefore to Caesar, the things which are Caesar’s; and to God, the things which are God’s.", "noyes": "They say, Caesar’s. Then saith he to them, Render then to Caesar the things that are Caesar’s, and to God the things that are God’s.", "webster": "They say to him, Cesar's. Then saith he to them, Render therefore to Cesar, the things which are Cesar's; and to God, the things that are God's.", "vulgate": "dicunt ei Caesaris tunc ait illis reddite ergo quae sunt Caesaris Caesari et quae sunt Dei Deo;"}}, {"v": 22, "ref": "22:22", "o": "καὶ ἀκούσαντες ἐθαύμασαν, καὶ ἀφέντες αὐτὸν ἀπῆλθαν.", "en": {"kjv": "When they had heard these words, they marvelled, and left him, and went their way.", "web": "When they heard it, they marveled, and left him, and went away.", "bsb": "And when they heard this, they were amazed. So they left Him and went away.", "asv": "And when they heard it, they marvelled, and left him, and went away.", "ylt": "and having heard they wondered, and having left him they went away.", "tyndale": "When they hearde that they marveled and lefte hym and went there waye.", "dra": "And hearing this, they wondered and, leaving him, went their ways.", "bbe": "And hearing it, they were full of wonder, and went away from him.", "geneva": "And when they heard it, they marueiled, and left him, and went their way.", "wycliffe": "And thei herden, and wondriden; and thei leften hym, and wenten awey.", "rotherham": "And, hearing, they marvelled,—and, leaving him, departed.", "weymouth": "They heard this, and were astonished; then left Him, and went their way.", "darby": "And when they heard [him], they wondered, and left him, and went away.", "twenty": "They wondered at his answer, and left him alone and went away.", "acv": "And when they heard it, they marveled. And having left him, they departed.", "anderson": "And when they heard it, they were astonished, and left him, and went away.", "haweis": "And when they heard him, they marvelled, and leaving him, went away.", "noyes": "And hearing this, they wondered, and left him, and went away.", "webster": "When they had heard [these words], they marveled, and left him, and departed.", "vulgate": "et audientes mirati sunt et relicto eo abierunt;"}}, {"v": 23, "ref": "22:23", "o": "Ἐν ἐκείνῃ τῇ ἡμέρᾳ προσῆλθον αὐτῷ Σαδδουκαῖοι, ⸀λέγοντες μὴ εἶναι ἀνάστασιν, καὶ ἐπηρώτησαν αὐτὸν", "en": {"kjv": "The same day came to him the Sadducees, which say that there is no resurrection, and asked him,", "web": "On that day Sadducees (those who say that there is no resurrection) came to him. They asked him,", "bsb": "That same day the Sadducees, who say there is no resurrection, came to Jesus and questioned Him.", "asv": "On that day there came to him Sadducees, they that say that there is no resurrection: and they asked him,", "ylt": "In that day there came near to him Sadducees, who are saying there is not a rising again, and they questioned him, saying,", "tyndale": "The same daye the Saduces came to him (which saye that there is no resurrcecion) and axed him", "dra": "That day there came to him the Sadducees, who say there is no resurrection; and asked him,", "bbe": "On the same day there came to him the Sadducees, who say that there is no coming back from the dead: and they put a question to him, saying,", "geneva": "The same day the Sadduces came to him (which say that there is no resurrection) and asked him,", "wycliffe": "In that dai Saduceis, that seien there is no risyng ayen to lijf, camen to hym, and axiden him,", "rotherham": "On that day, there came unto him Sadducees, who say, there is, no resurrection—and they questioned him,", "weymouth": "On the same day a party of Sadducees came to Him, contending that there is no resurrection. And they put this case to Him.", "darby": "On that day came to him Sadducees, who say there is no resurrection; and they demanded of him,", "twenty": "That same day some Sadducees came up to Jesus, maintaining that there is no resurrection. Their question was this: —", "acv": "On that day Sadducees came to him, those who claim to be no resurrection. And they questioned him, saying,", "anderson": "On that day there came to him the Sadducees, who say that there is no resurrection; and they put a question to him,", "haweis": "On the same day the Sadducees came to him, who say, that there is no resurrection, and they put a question to him,", "noyes": "The same day there came to him Sadducees, saying that there is no resurrection; and they asked him,", "webster": "The same day came to him the Sadducees, who say that there is no resurrection, and asked him,", "vulgate": "in illo die accesserunt ad eum Sadducaei qui dicunt non esse resurrectionem et interrogaverunt eum;"}}, {"v": 24, "ref": "22:24", "o": "λέγοντες· Διδάσκαλε, Μωϋσῆς εἶπεν· Ἐάν τις ἀποθάνῃ μὴ ἔχων τέκνα, ἐπιγαμβρεύσει ὁ ἀδελφὸς αὐτοῦ τὴν γυναῖκα αὐτοῦ καὶ ἀναστήσει σπέρμα τῷ ἀδελφῷ αὐτοῦ.", "en": {"kjv": "Saying, Master, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.", "web": "saying, “Teacher, Moses said, ‘If a man dies, having no children, his brother shall marry his wife, and raise up seed for his brother.’", "bsb": "“Teacher,” they said, “Moses declared that if a man dies without having children, his brother is to marry the widow and raise up offspring for him.", "asv": "saying, Teacher, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.", "ylt": "`Teacher, Moses said, If any one may die not having children, his brother shall marry his wife, and shall raise up seed to his brother.", "tyndale": "sayinge: Master Moses bade yf a man dye havinge no chyldre that the brother mary his wyfe and reyse vp seed vnto his brother.", "dra": "Saying: Master, Moses said: If a man die having no son, his brother shall marry his wife and raise up issue to his brother.", "bbe": "Master, Moses said, If a man, at the time of his death, has no children, let his brother take his wife, and get a family for his brother;", "geneva": "Saying, Master, Moses sayd, If a man die, hauing no children, his brother shall marie his wife by the right of alliance, and raise vp seede vnto his brother.", "wycliffe": "and seiden, Mayster, Moises seide, if ony man is deed, not hauynge a sone, that his brother wedde his wijf, and reise seed to his brothir.", "rotherham": "saying—Teacher! Moses, said, If any man die not having children, his brother shall marry his wife, and raise up seed unto his brother.", "weymouth": "\"Teacher,\" they said, \"Moses enjoined, `If a man die childless, his brother shall marry his widow, and raise up a family for him.'", "darby": "saying, Teacher, Moses said, If any one die, not having children, his brother shall marry his wife and shall raise up seed to his brother.", "twenty": "“Teacher, Moses said — ‘should a man die without children, the man’s brother shall become the husband of the widow, and raise a family for his brother.’", "acv": "Teacher, Moses said, If some man dies, having no children, his brother shall marry his wife, and raise up seed to his brother.", "anderson": "saying: Teacher, Moses commanded, If any one die without children, his brother shall marry his wife, and raise up children for his brother.", "haweis": "saying, Master, Moses said, “If a man die having no children, his brother in right of affinity shall marry his wife, and raise up seed for his brother.”", "noyes": "saying, Teacher, Moses said, \"If a man die having no children, his brother shall marry his wife, and raise up seed to his brother.\"", "webster": "Saying, Master, Moses said, If a man shall die, having no children, his brother shall marry his wife, and raise up seed to his brother.", "vulgate": "dicentes magister Moses dixit si quis mortuus fuerit non habens filium ut ducat frater eius uxorem illius et suscitet semen fratri suo;"}}, {"v": 25, "ref": "22:25", "o": "ἦσαν δὲ παρ’ ἡμῖν ἑπτὰ ἀδελφοί· καὶ ὁ πρῶτος ⸀γήμας ἐτελεύτησεν, καὶ μὴ ἔχων σπέρμα ἀφῆκεν τὴν γυναῖκα αὐτοῦ τῷ ἀδελφῷ αὐτοῦ·", "en": {"kjv": "Now there were with us seven brethren: and the first, when he had married a wife, deceased, and, having no issue, left his wife unto his brother:", "web": "Now there were with us seven brothers. The first married and died, and having no seed left his wife to his brother.", "bsb": "Now there were seven brothers among us. The first one married and died without having children. So he left his wife to his brother.", "asv": "Now there were with us seven brethren: and the first married and deceased, and having no seed left his wife unto his brother;", "ylt": "`And there were with us seven brothers, and the first having married did die, and not having seed, he left his wife to his brother;", "tyndale": "Ther were wt vs seven brethre and the fyrste maried and deceased wt oute yssue and lefte his wyfe vnto his brother.", "dra": "Now there were with us seven brethren: and the first having married a wife, died; and not having issue, left his wife to his brother.", "bbe": "Now there were among us seven brothers; and the first was married and at his death, having no seed, gave his wife to his brother;", "geneva": "Nowe there were with vs seuen brethren, and the first maried a wife, and deceased: and hauing none yssue, left his wife vnto his brother.", "wycliffe": "And seuen britheren weren at vs; and the firste weddide a wijf, and is deed. And he hadde no seed, and lefte his wijf to his brother;", "rotherham": "Now there were, with us, seven brethren; and, the first, marrying, died, and not having seed, left his wife unto his brother.", "weymouth": "Now we had among us seven brothers. The eldest of them married, but died childless, leaving his wife to his brother.", "darby": "Now there were with us seven brethren; and the first having married died, and not having seed, left his wife to his brother.", "twenty": "Now we had living among us seven brothers; of whom the eldest married and died, and, as he had no family, left his wife for his brother.", "acv": "Now there were with us seven brothers. And the first having married perished. And having no seed left his wife to his brother.", "anderson": "Now there were with us seven brothers; and the first took a wife, and died; and, having no child, left his wife to his brother.", "haweis": "Now there were with us seven brothers; and the first marrying, died, and had no offspring, and left his wife to his brother;", "noyes": "Now there were with us seven brothers; and the first married and died; and, having no offspring, left his wife to his brother.", "webster": "Now there were with us seven brothers: and the first, when he had married a wife, deceased; and having no issue, left his wife to his brother.", "vulgate": "erant autem apud nos septem fratres et primus uxore ducta defunctus est et non habens semen reliquit uxorem suam fratri suo;"}}, {"v": 26, "ref": "22:26", "o": "ὁμοίως καὶ ὁ δεύτερος καὶ ὁ τρίτος, ἕως τῶν ἑπτά·", "en": {"kjv": "Likewise the second also, and the third, unto the seventh.", "web": "In the same way, the second also, and the third, to the seventh.", "bsb": "The same thing happened to the second and third brothers, down to the seventh.", "asv": "in like manner the second also, and the third, unto the seventh.", "ylt": "in like manner also the second, and the third, unto the seventh,", "tyndale": "Lykewise the seconde and ye thryd vnto the sevethe.", "dra": "In like manner the second and the third and so on, to the seventh.", "bbe": "In the same way the second and the third, up to the seventh.", "geneva": "Likewise also the second, and the third, vnto the seuenth.", "wycliffe": "also the secounde, and the thridde, til to the seuenthe.", "rotherham": "Likewise, the second also, and the third,—unto the seven.", "weymouth": "So also did the second and the third, down to the seventh,", "darby": "In like manner also the second and the third, unto the seven.", "twenty": "The same thing happened to the second and the third brothers, and indeed to all the seven.", "acv": "Likewise also the second, and the third, until the seventh.", "anderson": "In like manner also the second, and the third, to the seventh.", "haweis": "likewise the second also; then the third; so on to the seven.", "noyes": "And so also the second, and the third, even to the seventh.", "webster": "Likewise the second also, and the third, to the seventh.", "vulgate": "similiter secundus et tertius usque ad septimum;"}}, {"v": 27, "ref": "22:27", "o": "ὕστερον δὲ πάντων ἀπέθανεν ⸀ἡ γυνή.", "en": {"kjv": "And last of all the woman died also.", "web": "After them all, the woman died.", "bsb": "And last of all, the woman died.", "asv": "And after them all, the woman died.", "ylt": "and last of all died also the woman;", "tyndale": "Laste of all the woman dyed also.", "dra": "And last of all the woman died also.", "bbe": "And last of all the woman came to her end.", "geneva": "And last of all the woman died also.", "wycliffe": "But the laste of alle, the woman is deed.", "rotherham": "And, last of all, died, the wife.", "weymouth": "till the woman also died, after surviving them all.", "darby": "And last of all the woman also died.", "twenty": "The woman herself died last of all.", "acv": "And last of all, the woman also died.", "anderson": "Last of all, the woman also died.", "haweis": "Last of all the woman died also.", "noyes": "And last of all the woman died.", "webster": "And last of all the woman died also.", "vulgate": "novissime autem omnium et mulier defuncta est;"}}, {"v": 28, "ref": "22:28", "o": "ἐν τῇ ⸂ἀναστάσει οὖν⸃ τίνος τῶν ἑπτὰ ἔσται γυνή; πάντες γὰρ ἔσχον αὐτήν.", "en": {"kjv": "Therefore in the resurrection whose wife shall she be of the seven? for they all had her.", "web": "In the resurrection therefore, whose wife will she be of the seven? For they all had her.”", "bsb": "In the resurrection, then, whose wife will she be of the seven? For all of them were married to her.”", "asv": "In the resurrection therefore whose wife shall she be of the seven? for they all had her.", "ylt": "therefore in the rising again, of which of the seven shall she be wife--for all had her?'", "tyndale": "Now in the resurreccion whose wyfe shall she be of the seven? For all had her.", "dra": "At the resurrection therefore, whose wife of the seven shall she be? For they all had her.", "bbe": "When they come back from the dead, then, whose wife will she be of the seven? because they all had her.", "geneva": "Therefore in the resurrection, whose wife shall she be of the seuen? for all had her.", "wycliffe": "Also in the risyng ayen to lijf, whos wijf of the seuene schal sche be? for alle hadden hir.", "rotherham": "In the resurrection, therefore,—Of which of the seven, shall she be wife? For, all, had her.", "weymouth": "At the Resurrection, therefore, whose wife of the seven will she be? for they all married her.\"", "darby": "In the resurrection therefore of which of the seven shall she be wife, for all had her?", "twenty": "At the resurrection, then, whose wife will she be out of the seven, all of them having had her?”", "acv": "In the resurrection therefore, which of the seven will she be wife? For they all had her.", "anderson": "Therefore, in the resurrection, of which of the seven will she be the wife? for they all had her.", "haweis": "In the resurrection therefore, whose wife shall she be of the seven? for they all had her.", "noyes": "In the resurrection, then, of which of the seven will she be the wife? For they all had her.", "webster": "Therefore in the resurrection, whose wife shall she be of the seven? for they all had her.", "vulgate": "in resurrectione ergo cuius erit de septem uxor omnes enim habuerunt eam;"}}, {"v": 29, "ref": "22:29", "o": "Ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Πλανᾶσθε μὴ εἰδότες τὰς γραφὰς μηδὲ τὴν δύναμιν τοῦ θεοῦ·", "en": {"kjv": "Jesus answered and said unto them, Ye do err, not knowing the scriptures, nor the power of God.", "web": "But Jesus answered them, “You are mistaken, not knowing the Scriptures, nor the power of God.", "bsb": "Jesus answered, “You are mistaken because you do not know the Scriptures or the power of God.", "asv": "But Jesus answered and said unto them, Ye do err, not knowing the scriptures, nor the power of God.", "ylt": "And Jesus answering said to them, `Ye go astray, not knowing the Writings, nor the power of God;", "tyndale": "Iesus answered and sayde vnto the: ye are deceaved and vnderstonde not the scriptures nor yet the power of God.", "dra": "And Jesus answering, said to them: You err, not knowing the Scriptures nor the power of God.", "bbe": "But Jesus said to them in answer, You are in error, not having knowledge of the Writings, or of the power of God.", "geneva": "Then Iesus answered, and sayd vnto them, Ye are deceiued, not knowing the Scriptures, nor the power of God.", "wycliffe": "Jhesus answeride, and seide to hem, Ye erren, `and ye knowen not scripturis, ne the vertu of God.", "rotherham": "And Jesus answering, said—Ye are deceiving yourselves, knowing neither the Scriptures, nor yet the power of God.", "weymouth": "The reply of Jesus was, \"You are in error, through ignorance of the Scriptures and of the power of God.", "darby": "And Jesus answering said to them, Ye err, not knowing the scriptures nor the power ofGod.", "twenty": "“Your mistake,” replied Jesus, “is due to your ignorance of the Scriptures, and of the power of God.", "acv": "But having answered, Jesus said to them, Ye are led astray, not knowing the scriptures, nor the power of God.", "anderson": "Jesus answered and said to them: You err, because you know neither the scriptures nor the power of God.", "haweis": "Jesus then answering, said unto them, Ye are in an error, from not knowing the Scriptures, and the power of God.", "noyes": "Jesus answered and said to them, Ye err, not knowing the Scriptures, nor the power of God.", "webster": "Jesus answered and said to them, Ye do err, not knowing the scriptures, nor the power of God.", "vulgate": "respondens autem Iesus ait illis erratis nescientes scripturas neque virtutem Dei;"}}, {"v": 30, "ref": "22:30", "o": "ἐν γὰρ τῇ ἀναστάσει οὔτε γαμοῦσιν οὔτε ⸀γαμίζονται, ἀλλ’ ὡς ἄγγελοι ⸀θεοῦ ἐν ⸀τῷ οὐρανῷ εἰσιν·", "en": {"kjv": "For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.", "web": "For in the resurrection they neither marry, nor are given in marriage, but are like God’s angels in heaven.", "bsb": "In the resurrection, people will neither marry nor be given in marriage. Instead, they will be like the angels in heaven.", "asv": "For in the resurrection they neither marry, nor are given in marriage, but are as angels in heaven.", "ylt": "for in the rising again they do not marry, nor are they given in marriage, but are as messengers of God in heaven.", "tyndale": "For in the resurreccion they nether mary nor are maryed: but are as the angels of God in heven.", "dra": "For in the resurrection they shall neither marry nor be married, but shall be as the angels of God in heaven.", "bbe": "For when they come back from the dead there are no husbands and wives, but they are as the angels in heaven.", "geneva": "For in the resurrection they neither marie wiues, nor wiues are bestowed in mariage, but are as the Angels of God in heauen.", "wycliffe": "For in the rysyng ayen to lijf, nether thei schulen wedde, nethir schulen be weddid; but thei ben as the aungels of God in heuene.", "rotherham": "For, in the resurrection, they neither marry, nor are given in marriage, but, as messengers in the heaven, are they.", "weymouth": "For in the Resurrection, men neither marry nor are women given in marriage, but they are like angels in Heaven.", "darby": "For in the resurrection they neither marry nor are given in marriage, but are as angels ofGod in heaven.", "twenty": "For at the resurrection there is no marrying or being married, but all who rise are as angels in Heaven.", "acv": "For in the resurrection they neither marry, nor are given in marriage, but are as agents of God in heaven.", "anderson": "For in the resurrection they neither marry nor are given in marriage, but are as the angels of God in heaven.", "haweis": "For at the resurrection, they neither marry, nor are given in marriage, but are as the angels of God in heaven.", "noyes": "For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.", "webster": "For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.", "vulgate": "in resurrectione enim neque nubent neque nubentur sed sunt sicut angeli Dei in caelo;"}}, {"v": 31, "ref": "22:31", "o": "περὶ δὲ τῆς ἀναστάσεως τῶν νεκρῶν οὐκ ἀνέγνωτε τὸ ῥηθὲν ὑμῖν ὑπὸ τοῦ θεοῦ λέγοντος·", "en": {"kjv": "But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,", "web": "But concerning the resurrection of the dead, haven’t you read that which was spoken to you by God, saying,", "bsb": "But concerning the resurrection of the dead, have you not read what God said to you:", "asv": "But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,", "ylt": "`And concerning the rising again of the dead, did ye not read that which was spoken to you by God, saying,", "tyndale": "As touchynge the resurreccion of the deed: have ye not redde what is sayde vnto you of God which sayeth:", "dra": "And concerning the resurrection of the dead, have you not read that which was spoken by God, saying to you:", "bbe": "But about the dead coming back to life, have you no knowledge of what was said to you by God in the Writings:", "geneva": "And concerning the resurrection of the dead, haue ye not read what is spoken vuto you of God, saying,", "wycliffe": "And of the risyng ayen of deed men, `han ye not red, that is seid of the Lord, that seith to you,", "rotherham": "But, as touching the resurrection of the dead—Have ye not read what was spoken unto you by God, saying—", "weymouth": "But as to the Resurrection of the dead, have you never read what God says to you,", "darby": "But concerning the resurrection of the dead, have ye not read what was spoken to you byGod, saying,", "twenty": "As to the resurrection of the dead, have you not read these words of God —", "acv": "But concerning the resurrection of the dead, have ye not read that which was spoken to you by God, saying,", "anderson": "But, concerning the resurrection of the dead, have you not read that which was spoken to you by God, saying:", "haweis": "But with respect to the resurrection of the dead, have ye not read what was spoken to you of God, saying,", "noyes": "But concerning the resurrection of the dead, have ye not read that which was spoken to you by God, saying,", "webster": "But as concerning the resurrection of the dead, have ye not read that which was spoken to you by God, saying,", "vulgate": "de resurrectione autem mortuorum non legistis quod dictum est a Deo dicente vobis;"}}, {"v": 32, "ref": "22:32", "o": "Ἐγώ εἰμι ὁ θεὸς Ἀβραὰμ καὶ ὁ θεὸς Ἰσαὰκ καὶ ὁ θεὸς Ἰακώβ; οὐκ ἔστιν ⸂ὁ θεὸς⸃ νεκρῶν ἀλλὰ ζώντων.", "en": {"kjv": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.", "web": "‘I am the God of Abraham, and the God of Isaac, and the God of Jacob?’God is not the God of the dead, but of the living.”", "bsb": "‘I am the God of Abraham, the God of Isaac, and the God of Jacob’? He is not the God of the dead, but of the living.”", "asv": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.", "ylt": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not a God of dead men, but of living.'", "tyndale": "I am Abrahams God and Ysaacks God and the God of Iacob? God is not the God of the deed: but of the lyvinge.", "dra": "I am the God of Abraham and the God of Isaac and the God of Jacob? He is not the God of the dead but of the living.", "bbe": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead but of the living.", "geneva": "I am the God of Abraham, and the God of Isaac, and the God of Iacob? God is not the God of the dead, but of the liuing.", "wycliffe": "Y am God of Abraham, and God of Ysaac, and God of Jacob? he is not God of deede men, but of lyuynge men.", "rotherham": "I, am the God of Abraham, and the God of Isaac, and the God of Jacob?—He is not God, of the dead, but, of the living.", "weymouth": "`I am the God of Abraham, the God of Isaac, and the God of Jacob'? He is not the God of dead, but of living men.\"", "darby": "I am theGod of Abraham, and theGod of Isaac, and theGod of Jacob?God is notGod of [the] dead, but of [the] living.", "twenty": "‘I am the God of Abraham, and the God of Isaac, and the God of Jacob’? He is not the God of dead men, but of living.”", "acv": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not God of the dead, but of the living.", "anderson": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.", "haweis": "“I am the God of Abraham, and the God of Isaac, and the God of Jacob?” God is not the God of the dead, but of the living.", "noyes": "\"I am the God of Abraham, and the God of Isaac, and the God of Jacob\"? He is not a God of the dead, but of the living.", "webster": "I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.", "vulgate": "ego sum Deus Abraham et Deus Isaac et Deus Iacob non est Deus mortuorum sed viventium;"}}, {"v": 33, "ref": "22:33", "o": "καὶ ἀκούσαντες οἱ ὄχλοι ἐξεπλήσσοντο ἐπὶ τῇ διδαχῇ αὐτοῦ.", "en": {"kjv": "And when the multitude heard this, they were astonished at his doctrine.", "web": "When the multitudes heard it, they were astonished at his teaching.", "bsb": "When the crowds heard this, they were astonished at His teaching.", "asv": "And when the multitudes heard it, they were astonished at his teaching.", "ylt": "And having heard, the multitudes were astonished at his teaching;", "tyndale": "And when the people hearde that they were astonyed at his doctrine.", "dra": "And the multitudes hearing it were in admiration at his doctrine.", "bbe": "And the people hearing it were surprised at his teaching.", "geneva": "And when the multitude heard it, they were astonied at his doctrine.", "wycliffe": "And the puple herynge, wondriden in his techynge.", "rotherham": "And, the multitudes, hearing, were being struck with astonishment at his teaching.", "weymouth": "All the crowd heard this, and were filled with amazement at His teaching.", "darby": "And when the crowds heard [it] they were astonished at his doctrine.", "twenty": "The crowds, who had been listening to him, were greatly struck with his teaching.", "acv": "And when the multitudes heard it, they were astonished at his doctrine.", "anderson": "And when the multitude heard this, they were astonished at his teaching.", "haweis": "And when the multitude heard it, they were amazingly struck with his doctrine.", "noyes": "And when the multitudes heard this, they were astonished at his teaching.", "webster": "And when the multitude heard [this], they were astonished at his doctrine.", "vulgate": "et audientes turbae mirabantur in doctrina eius;"}}, {"v": 34, "ref": "22:34", "o": "Οἱ δὲ Φαρισαῖοι ἀκούσαντες ὅτι ἐφίμωσεν τοὺς Σαδδουκαίους συνήχθησαν ἐπὶ τὸ αὐτό.", "en": {"kjv": "But when the Pharisees had heard that he had put the Sadducees to silence, they were gathered together.", "web": "But the Pharisees, when they heard that he had silenced the Sadducees, gathered themselves together.", "bsb": "And when the Pharisees heard that Jesus had silenced the Sadducees, they themselves gathered together.", "asv": "But the Pharisees, when they heard that he had put the Sadducees to silence, gathered themselves together.", "ylt": "and the Pharisees, having heard that he did silence the Sadducees, were gathered together unto him;", "tyndale": "When the Pharises had hearde how yt he had put the Saduces to silence they drewe to gedder", "dra": "But the Pharisees, hearing that he had silenced the Sadducees, came together.", "bbe": "But the Pharisees, hearing how the mouths of the Sadducees had been stopped, came together;", "geneva": "But when the Pharises had heard, that he had put the Sadduces to silence, they assembled together.", "wycliffe": "And Fariseis herden that he hadde put silence to Saduceis, and camen togidere.", "rotherham": "Now, the Pharisees, hearing that he had silenced the Sadducees, were brought together with one accord;", "weymouth": "Now the Pharisees came up when they heard that He had silenced the Sadducees,", "darby": "But the Pharisees, having heard that he had put the Sadducees to silence, were gathered together.", "twenty": "When the Pharisees heard that Jesus had silenced the Sadducees, they collected together.", "acv": "But the Pharisees, having heard that he silenced the Sadducees, they came together in the same place.", "anderson": "When the Pharisees heard that he had put the Sadducees to silence, they came together.", "haweis": "But the Pharisees hearing that he had stopped the Sadducees’ mouths, they assembled together:", "noyes": "And the Pharisees, hearing that he had put the Sadducees to silence, assembled together;", "webster": "But when the Pharisees had heard that he had put the Sadducees to silence, they were assembled about him.", "vulgate": "Pharisaei autem audientes quod silentium inposuisset Sadducaeis convenerunt in unum;"}}, {"v": 35, "ref": "22:35", "o": "καὶ ἐπηρώτησεν εἷς ἐξ αὐτῶν νομικὸς πειράζων ⸀αὐτόν·", "en": {"kjv": "Then one of them, which was a lawyer, asked him a question, tempting him, and saying,", "web": "One of them, a lawyer, asked him a question, testing him.", "bsb": "One of them, an expert in the law, tested Him with a question:", "asv": "And one of them, a lawyer, asked him a question, trying him:", "ylt": "and one of them, a lawyer, did question, tempting him, and saying,", "tyndale": "and one of them which was a doctoure of lawe axed a question teptinge h m and sayinge:", "dra": "And one of them, a doctor of the law, asked him, tempting him:", "bbe": "And one of them, a teacher of the law, put a question to him, testing him, and saying,", "geneva": "And one of them, which was an expounder of the Lawe, asked him a question, tempting him, and saying,", "wycliffe": "And oon of hem, a techere of the lawe, axide Jhesu, and temptide him,", "rotherham": "and one from among them, a lawyer, proposed a question, putting him to the test:", "weymouth": "and one of them, an expounder of the Law, asked Him as a test question,", "darby": "And one of them, a lawyer, demanded, tempting him, and saying,", "twenty": "Then one of them, a Student of the Law, to test him, asked this question —", "acv": "And one of them, a lawyer, questioned, trying him, and saying,", "anderson": "And one of them, who was a lawyer, asked him a question, that he might tempt him, saying:", "haweis": "and one of them, a teacher of the law, put a question to him, to make trial of him, and said,", "noyes": "and one of them, a lawyer, asked, trying him,", "webster": "Then one of them [who was] a lawyer, asked [him a question], tempting him, and saying,", "vulgate": "et interrogavit eum unus ex eis legis doctor temptans eum;"}}, {"v": 36, "ref": "22:36", "o": "Διδάσκαλε, ποία ἐντολὴ μεγάλη ἐν τῷ νόμῳ;", "en": {"kjv": "Master, which is the great commandment in the law?", "web": "“Teacher, which is the greatest commandment in the law?”", "bsb": "“Teacher, which commandment is the greatest in the Law?”", "asv": "Teacher, which is the great commandment in the law?", "ylt": "`Teacher, which is the great command in the Law?'", "tyndale": "Master which is ye chefe comaundment in the lawe?", "dra": "Master, which is the great commandment in the law?", "bbe": "Master, which is the chief rule in the law?", "geneva": "Master, which is ye great commandement in the Lawe?", "wycliffe": "Maistir, which is a greet maundement in the lawe?", "rotherham": "Teacher! which commandment, is greatest in the law?", "weymouth": "\"Teacher, which is the greatest Commandment in the Law?\"", "darby": "Teacher, which is the great commandment in the law?", "twenty": "“Teacher, what is the great commandment in the Law?”", "acv": "Teacher, which is the great commandment in the law?", "anderson": "Teacher, which is the great commandment in the law?", "haweis": "Master, which is the great commandment in the law?", "noyes": "Teacher, which commandment is great in the Law?", "webster": "Master, which [is] the great commandment in the law?", "vulgate": "magister quod est mandatum magnum in lege;"}}, {"v": 37, "ref": "22:37", "o": "ὁ ⸀δὲ ἔφη αὐτῷ· Ἀγαπήσεις κύριον τὸν θεόν σου ἐν ὅλῃ ⸀τῇ καρδίᾳ σου καὶ ἐν ὅλῃ ⸁τῇ ψυχῇ σου καὶ ἐν ὅλῃ τῇ διανοίᾳ σου·", "en": {"kjv": "Jesus said unto him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.", "web": "Jesus said to him, “‘You shall love the Lord your God with all your heart, with all your soul, and with all your mind.’", "bsb": "Jesus declared, “‘Love the Lord your God with all your heart and with all your soul and with all your mind.’", "asv": "And he said unto him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.", "ylt": "And Jesus said to him, `Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thine understanding--", "tyndale": "Iesus sayde vnto him: love the Lorde thy God wt all thine herte with all thy soule and with all thy mynde.", "dra": "Jesus said to him: Thou shalt love the Lord thy God with thy whole heart and with thy whole soul and with thy whole mind.", "bbe": "And he said to him, Have love for the Lord your God with all your heart, and with all your soul, and with all your mind.", "geneva": "Iesus sayd to him, Thou shalt loue the Lord thy God with all thine heart, with all thy soule, and with all thy minde.", "wycliffe": "Jhesus seide to him, Thou schalt loue thi Lord God, of al thin herte, and in al thi soule, and in al thi mynde.", "rotherham": "And, he, said unto him—Thou shalt love the Lord thy God—with all thy heart, and with all thy soul, and with all thy mind:", "weymouth": "\"`Thou shalt love the Lord thy God,'\" He answered, \"`with thy whole heart, thy whole soul, thy whole mind.'", "darby": "And he said to him, Thou shalt love [the] Lord thyGod with all thy heart, and with all thy soul, and with all thy understanding.", "twenty": "His answer was: “‘Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.’", "acv": "And Jesus said to him, Thou shall love the Lord thy God with thy whole heart, and with thy whole soul, and with thy whole mind.", "anderson": "Jesus said to him: You shall love the Lord your God with your whole heart, and with your whole soul, and with your whole mind.", "haweis": "Then Jesus said to him, “Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.”", "noyes": "And he said to him, \"Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.\"", "webster": "Jesus said to him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.", "vulgate": "ait illi Iesus diliges Dominum Deum tuum ex toto corde tuo et in tota anima tua et in tota mente tua;"}}, {"v": 38, "ref": "22:38", "o": "αὕτη ἐστὶν ⸂ἡ μεγάλη καὶ πρώτη⸃ ἐντολή.", "en": {"kjv": "This is the first and great commandment.", "web": "This is the first and great commandment.", "bsb": "This is the first and greatest commandment.", "asv": "This is the great and first commandment.", "ylt": "this is a first and great command;", "tyndale": "This is the fyrst and the chefe comaundement.", "dra": "This is the greatest and the first commandment.", "bbe": "This is the first and greatest rule.", "geneva": "This is the first and the great commandement.", "wycliffe": "This is the firste and the moste maundement.", "rotherham": "This, is the great and first commandment.", "weymouth": "This is the greatest and foremost Commandment.", "darby": "This is [the] great and first commandment.", "twenty": "This is the great first commandment.", "acv": "This is the first and great commandment.", "anderson": "This is the first and great commandment.", "haweis": "This is the first and great commandment.", "noyes": "This is the great and first commandment.", "webster": "This is the first and great commandment.", "vulgate": "hoc est maximum et primum mandatum;"}}, {"v": 39, "ref": "22:39", "o": "Δευτέρα ⸀δὲ ὁμοία ⸀αὐτῇ· Ἀγαπήσεις τὸν πλησίον σου ὡς σεαυτόν.", "en": {"kjv": "And the second is like unto it, Thou shalt love thy neighbour as thyself.", "web": "A second likewise is this, ‘You shall love your neighbor as yourself.’", "bsb": "And the second is like it: ‘Love your neighbor as yourself.’", "asv": "And a second like unto it is this, Thou shalt love thy neighbor as thyself.", "ylt": "and the second is like to it, Thou shalt love thy neighbour as thyself;", "tyndale": "And ther is another lyke vnto this. Love thyne neghbour as thy selfe.", "dra": "And the second is like to this: Thou shalt love thy neighbour as thyself.", "bbe": "And a second like it is this, Have love for your neighbour as for yourself.", "geneva": "And the second is like vnto this, Thou shalt loue thy neighbour as thy selfe.", "wycliffe": "And the secounde is lijk to this; Thou schalt loue thi neiyebore as thi silf.", "rotherham": "The second, like it, is, this: Thou shalt love thy neighbour as thyself.", "weymouth": "And the second is similar to it: `Thou shalt love thy fellow man as much as thyself.'", "darby": "And [the] second is like it, Thou shalt love thy neighbour as thyself.", "twenty": "The second, which is like it, is this — ‘Thou shalt love thy neighbour as thou dost thyself.’", "acv": "And the second is like it, Thou shall love thy neighbor as thyself.", "anderson": "And the second is like it: You shall love your neighbor as yourself.", "haweis": "And the second is like to it, “Thou shalt love thy neighbour as thyself.”", "noyes": "There is a second like it: \"Thou shalt love thy neighbor as thyself.\"", "webster": "And the second [is] like it, Thou shalt love thy neighbor as thyself.", "vulgate": "secundum autem simile est huic diliges proximum tuum sicut te ipsum;"}}, {"v": 40, "ref": "22:40", "o": "ἐν ταύταις ταῖς δυσὶν ἐντολαῖς ὅλος ὁ νόμος ⸂κρέμαται καὶ οἱ προφῆται⸃.", "en": {"kjv": "On these two commandments hang all the law and the prophets.", "web": "The whole law and the prophets depend on these two commandments.”", "bsb": "All the Law and the Prophets hang on these two commandments.”", "asv": "On these two commandments the whole law hangeth, and the prophets.", "ylt": "on these--the two commands--all the law and the prophets do hang.'", "tyndale": "In these two commaundemetes hange all the lawe and the Prophetes.", "dra": "On these two commandments dependeth the whole law and the prophets.", "bbe": "On these two rules all the law and the prophets are based.", "geneva": "On these two commandements hangeth the whole Lawe, and the Prophets.", "wycliffe": "In these twey maundementis hangith al the lawe and the profetis.", "rotherham": "In these two commandments, all the law, is contained, and the prophets.", "weymouth": "The whole of the Law and the Prophets is summed up in these two Commandments.\"", "darby": "On these two commandments the whole law and the prophets hang.", "twenty": "On these two commandments hang all the Law and the Prophets.”", "acv": "On these two commandments hang all the law and the prophets.", "anderson": "On these two commandments hang the whole law and the prophets.", "haweis": "On these two commandments, the whole law and the prophets depend.", "noyes": "On these two commandments hang all the Law and the Prophets.", "webster": "On these two commandments hang all the law and the prophets.", "vulgate": "in his duobus mandatis universa lex pendet et prophetae;"}}, {"v": 41, "ref": "22:41", "o": "Συνηγμένων δὲ τῶν Φαρισαίων ἐπηρώτησεν αὐτοὺς ὁ Ἰησοῦς", "en": {"kjv": "While the Pharisees were gathered together, Jesus asked them,", "web": "Now while the Pharisees were gathered together, Jesus asked them a question,", "bsb": "While the Pharisees were assembled, Jesus questioned them:", "asv": "Now while the Pharisees were gathered together, Jesus asked them a question,", "ylt": "And the Pharisees having been gathered together, Jesus did question them,", "tyndale": "Whyll the Pharises were gaddered togeder Iesus axed", "dra": "And the Pharisees being gathered together, Jesus asked them,", "bbe": "Now while the Pharisees were together, Jesus put a question to them, saying,", "geneva": "While the Pharises were gathered together, Iesus asked them,", "wycliffe": "And whanne the Farisees weren gederid togidere, Jhesus axide hem,", "rotherham": "Now, the Pharisees having come together, Jesus questioned them, saying—", "weymouth": "While the Pharisees were still assembled there, Jesus put a question to them.", "darby": "And the Pharisees being gathered together, Jesus demanded of them,", "twenty": "Before the Pharisees separated, Jesus put this question to them —", "acv": "Now the Pharisees having been gathered together, Jesus interrogated them, saying,", "anderson": "While the Pharisees were together, Jesus asked them a question,", "haweis": "The Pharisees being then assembled, Jesus put a question to them,", "noyes": "And while the Pharisees were assembled, Jesus asked them,", "webster": "While the Pharisees were assembled, Jesus asked them,", "vulgate": "congregatis autem Pharisaeis interrogavit eos Iesus;"}}, {"v": 42, "ref": "22:42", "o": "λέγων· Τί ὑμῖν δοκεῖ περὶ τοῦ χριστοῦ; τίνος υἱός ἐστιν; λέγουσιν αὐτῷ· Τοῦ Δαυίδ.", "en": {"kjv": "Saying, What think ye of Christ? whose son is he? They say unto him, The Son of David.", "web": "saying, “What do you think of the Christ? Whose son is he?” They said to him, “Of David.”", "bsb": "“What do you think about the Christ? Whose son is He?” “David’s,” they answered.", "asv": "saying, What think ye of the Christ? whose son is he? They say unto him, The son of David.", "ylt": "saying, `What do ye think concerning the Christ? of whom is he son?' They say to him, `Of David.'", "tyndale": "the sayinge: what thinke ye of Christ? Whose sonne is he? They sayde vnto him: the sonne of David.", "dra": "Saying: What think you of Christ? Whose son is he? They say to him: David's.", "bbe": "What is your opinion of the Christ? whose son is he? They say to him, The Son of David.", "geneva": "Saying, What thinke ye of Christ? whose sonne is he? They sayd vnto him, Dauids.", "wycliffe": "and seide, What semeth to you of Crist, whos sone is he? Thei seien to hym, Of Dauid.", "rotherham": "How, to you, doth it seem, concerning the Christ? Whose son, is he? They say unto him—David’s.", "weymouth": "\"What think you about the Christ,\" He said, \"whose son is He?\" \"David's,\" they replied.", "darby": "saying, What think ye concerning the Christ? whose son is he? They say to him, David's.", "twenty": "“What do you think about the Christ? Whose son is he?” “David’s,” they said.", "acv": "What does it seem to you about the Christ? Whose son is he? They say to him, Of David.", "anderson": "saying: What think you of the Christ? whose son is he? They said to him: The son of David.", "haweis": "saying, What think ye of the Messiah, whose son is he? They say unto him, David’s.", "noyes": "saying, What think ye concerning the Christ? whose son is he? They say to him, David’s.", "webster": "Saying, What think ye of Christ? whose son is he? They say to him, [The son] of David.", "vulgate": "dicens quid vobis videtur de Christo cuius filius est dicunt ei David;"}}, {"v": 43, "ref": "22:43", "o": "λέγει αὐτοῖς· Πῶς οὖν Δαυὶδ ἐν πνεύματι ⸂καλεῖ αὐτὸν κύριον⸃ λέγων·", "en": {"kjv": "He saith unto them, How then doth David in spirit call him Lord, saying,", "web": "He said to them, “How then does David in the Spirit call him Lord, saying,", "bsb": "Jesus said to them, “How then does David in the Spirit call Him ‘Lord’? For he says:", "asv": "He saith unto them, How then doth David in the Spirit call him Lord, saying,", "ylt": "He saith to them, `How then doth David in the Spirit call him lord, saying,", "tyndale": "He sayde vnto the: how then doeth David in spirite call him Lorde sayinge?", "dra": "He saith to them: How then doth David in spirit call him Lord, saying:", "bbe": "He says to them, How then does David in the Spirit give him the name of Lord, saying,", "geneva": "He sayd vnto them, How then doeth Dauid in spirit call him Lord, saying,", "wycliffe": "He seith to hem, Hou thanne Dauid in spirit clepith hym Lord,", "rotherham": "He saith unto them—How then doth, David, in spirit, call him, Lord, saying—", "weymouth": "\"How then,\" He asked, \"does David, taught by the Spirit, call Him Lord, when he says,", "darby": "He says to them, How then does David in Spirit call him Lord, saying,", "twenty": "“How is it, then,” Jesus replied, “that David, speaking under inspiration, calls him ‘lord,’ in the passage —", "acv": "He says to them, How then does David in Spirit call him Lord, saying,", "anderson": "He said to them: How then does David in spirit call him Lord, saying,", "haweis": "He saith unto them, How then doth David by the Spirit call him Lord? saying,", "noyes": "He saith to them, How then doth David in the Spirit call him lord? saying,", "webster": "He saith to them, How then doth David in spirit call him Lord, saying,", "vulgate": "ait illis quomodo ergo David in spiritu vocat eum Dominum dicens;"}}, {"v": 44, "ref": "22:44", "o": "⸀Εἶπεν κύριος τῷ κυρίῳ μου· Κάθου ἐκ δεξιῶν μου ἕως ἂν θῶ τοὺς ἐχθρούς σου ⸀ὑποκάτω τῶν ποδῶν σου;", "en": {"kjv": "The Lord said unto my Lord, Sit thou on my right hand, till I make thine enemies thy footstool?", "web": "‘The Lord said to my Lord, sit on my right hand, until I make your enemies a footstool for your feet?’", "bsb": "‘The Lord said to my Lord, “Sit at My right hand until I put Your enemies under Your feet.”’", "asv": "The Lord said unto my Lord, Sit thou on my right hand, Till I put thine enemies underneath thy feet?", "ylt": "The Lord said to my lord, Sit at my right hand, till I may make thine enemies thy footstool?", "tyndale": "The Lorde sayde to my Lorde syt on my right honde: tyll I make thyne enemyes thy fote stole.", "dra": "The Lord said to my Lord: Sit on my right hand, until I make thy enemies thy footstool?", "bbe": "The Lord said to my Lord, Be seated at my right hand, till I put under your feet all those who are against you?", "geneva": "The Lord sayd to my Lord, Sit at my right hand, till I make thine enemies thy footestoole?", "wycliffe": "and seith, The Lord seide to my Lord, Sitte on my riythalf, til Y putte thin enemyes a stool of thi feet?", "rotherham": "The Lord, hath said unto, my Lord,—Sit thou on my right hand, until I make thy foes thy footstool?", "weymouth": "\"`The Lord said to my Lord, sit at My right hand until I have put thy foes beneath thy feet'?", "darby": "The Lord said to my Lord, Sit on my right hand until I put thine enemies under thy feet?", "twenty": "‘The Lord said to my Lord: “Sit at my right hand, until I put thy enemies beneath thy feet”’?", "acv": "The Lord said to my Lord, Sit thou at my right hand until I place thine enemies a footstool of thy feet?", "anderson": "The Lord said to my Lord, Sit thou at my right hand till I make thy enemies thy footstool.", "haweis": "“The Lord said unto my Lord, Sit at my right hand, till I put thine enemies as a footstool for thy feet.”", "noyes": "\"The Lord said to my lord, Sit thou on my right hand, till I put thine enemies under thy feet.\"", "webster": "The LORD said to my Lord, Sit thou on my right hand, till I make thy enemies thy footstool?", "vulgate": "dixit Dominus Domino meo sede a dextris meis donec ponam inimicos tuos scabillum pedum tuorum;"}}, {"v": 45, "ref": "22:45", "o": "εἰ οὖν Δαυὶδ καλεῖ αὐτὸν κύριον, πῶς υἱὸς αὐτοῦ ἐστιν;", "en": {"kjv": "If David then call him Lord, how is he his son?", "web": "“If then David calls him Lord, how is he his son?”", "bsb": "So if David calls Him ‘Lord,’ how can He be David’s son?”", "asv": "If David then calleth him Lord, how is he his son?", "ylt": "If then David doth call him lord, how is he his son?'", "tyndale": "Yf David call him Lorde: how is he then his sonne?", "dra": "If David then call him Lord, how is he his son?", "bbe": "If David then gives him the name of Lord, how is he his son?", "geneva": "If then Dauid call him Lord, howe is he his sonne?", "wycliffe": "Thanne if Dauid clepith hym Lord, hou is he his sone?", "rotherham": "If then, David, calleth him, Lord, How, is he, his son?", "weymouth": "\"If therefore David calls Him Lord, how can He be his son?\"", "darby": "If therefore David call him Lord, how is he his son?", "twenty": "Since, then, David calls him ‘lord,’ how is he David’s son?”", "acv": "If David therefore calls him Lord, how is he his son?", "anderson": "If then David calls him Lord, how is he his son?", "haweis": "If then David calleth him Lord, how is he his son?", "noyes": "If David then calleth him lord, how is he his son?", "webster": "If David then calleth him Lord, how is he his son?", "vulgate": "si ergo David vocat eum Dominum quomodo filius eius est;"}}, {"v": 46, "ref": "22:46", "o": "καὶ οὐδεὶς ἐδύνατο ⸂ἀποκριθῆναι αὐτῷ⸃ λόγον, οὐδὲ ἐτόλμησέν τις ἀπ’ ἐκείνης τῆς ἡμέρας ἐπερωτῆσαι αὐτὸν οὐκέτι.", "en": {"kjv": "And no man was able to answer him a word, neither durst any man from that day forth ask him any more questions.", "web": "No one was able to answer him a word, neither did any man dare ask him any more questions from that day forward.", "bsb": "No one was able to answer a word, and from that day on no one dared to question Him any further.", "asv": "And no one was able to answer him a word, neither durst any man from that day forth ask him any more questions.", "ylt": "And no one was able to answer him a word, nor durst any from that day question him any more.", "tyndale": "And none coulde answere him ageyne one worde: nether dueste eny from that daye forth axe him eny moo questions.", "dra": "And no man was able to answer him a word: neither durst any man from that day forth ask him any more questions.", "bbe": "And no one was able to give him an answer, and so great was their fear of him, that from that day no one put any more questions to him.", "geneva": "And none could answere him a worde, neither durst any from that day foorth aske him any moe questions.", "wycliffe": "And no man miyte answere a word to hym, nethir ony man was hardi fro that day, to axe hym more.", "rotherham": "And, no one, was able to answer him a word, neither durst anyone, from that day, question him, any more.", "weymouth": "No one could say a word in reply, nor from that day did any one venture again to put a question to Him.", "darby": "And no one was able to answer him a word, nor did any one dare from that day to question him any more.", "twenty": "No one could say a word in answer; nor did any one after that day venture to question him further.", "acv": "And no man was able to answer him a word, nor did any man from that day dare to question him any more.", "anderson": "And no one was able to answer him a word; nor did any one, from that day, dare to ask him another question.", "haweis": "And no man could answer him a word, neither durst any man, from that day, interrogate him any more.", "noyes": "And no one was able to answer him a word; nor durst any one from that day question him any more.", "webster": "And no man was able to answer him a word, neither durst any [man], from that day forth, ask him any more questions.", "vulgate": "et nemo poterat respondere ei verbum neque ausus fuit quisquam ex illa die eum amplius interrogare;"}}]}, {"c": 23, "verses": [{"v": 1, "ref": "23:1", "o": "Τότε ὁ Ἰησοῦς ἐλάλησεν τοῖς ὄχλοις καὶ τοῖς μαθηταῖς αὐτοῦ", "en": {"kjv": "Then spake Jesus to the multitude, and to his disciples,", "web": "Then Jesus spoke to the multitudes and to his disciples,", "bsb": "Then Jesus spoke to the crowds and to His disciples:", "asv": "Then spake Jesus to the multitudes and to his disciples,", "ylt": "Then Jesus spake to the multitudes, and to his disciples,", "tyndale": "Then spake Iesus to the people and to his disciples", "dra": "Then Jesus spoke to the multitudes and to his disciples,", "bbe": "Then Jesus said to the people and to his disciples:", "geneva": "Then spake Iesus to the multitude, and to his disciples,", "wycliffe": "Thanne Jhesus spac to the puple, and to hise disciplis,", "rotherham": "Then, Jesus spake unto the multitudes and unto his disciples,", "weymouth": "Then Jesus addressed the crowds and His disciples.", "darby": "Then Jesus spoke to the crowds and to his disciples,", "twenty": "Then Jesus speaking to the crowds and to his disciples, said:", "acv": "Then Jesus spoke to the multitudes and to his disciples, saying,", "anderson": "Then Jesus spoke to the multitudes, and to his disciples,", "haweis": "THEN Jesus spake to the multitudes and to his disciples,", "noyes": "Then Jesus spoke to the multitudes, and to his disciples,", "webster": "Then Jesus spoke to the multitude, and to his disciples,", "vulgate": "tunc Iesus locutus est ad turbas et discipulos suos;"}}, {"v": 2, "ref": "23:2", "o": "λέγων· Ἐπὶ τῆς Μωϋσέως καθέδρας ἐκάθισαν οἱ γραμματεῖς καὶ οἱ Φαρισαῖοι.", "en": {"kjv": "Saying, The scribes and the Pharisees sit in Moses’ seat:", "web": "saying, “The scribes and the Pharisees sat on Moses’ seat.", "bsb": "“The scribes and Pharisees sit in Moses’ seat.", "asv": "saying, The scribes and the Pharisees sit on Moses’ seat:", "ylt": "saying, `On the seat of Moses sat down the scribes and the Pharisees;", "tyndale": "sayinge. The Scribes and the Pharises sit in Moses seate.", "dra": "Saying: The scribes and the Pharisees have sitten on the chair of Moses.", "bbe": "The scribes and the Pharisees have the authority of Moses;", "geneva": "Saying, The Scribes and the Pharises sit in Moses seate.", "wycliffe": "and seide, On the chayere of Moises, scribis and Farisees han sete.", "rotherham": "saying—Upon Moses’ seat, have sat down, the Scribes and the Pharisees:", "weymouth": "\"The Scribes,\" He said, \"and the Pharisees sit in the chair of Moses.", "darby": "saying, The scribes and the Pharisees have set themselves down in Moses' seat:", "twenty": "“The teachers of the Law and the Pharisees now occupy the chair of Moses.", "acv": "The scholars and the Pharisees sit on Moses' seat.", "anderson": "saying: The scribes and the Pharisees sit in Moses seat:", "haweis": "saying, The scribes and Pharisees are seated on the chair of Moses;", "noyes": "saying, The scribes and the Pharisees sit in the seat of Moses.", "webster": "Saying, The scribes and the Pharisees sit in Moses's seat.", "vulgate": "dicens super cathedram Mosi sederunt scribae et Pharisaei;"}}, {"v": 3, "ref": "23:3", "o": "πάντα οὖν ὅσα ⸀ἐὰν εἴπωσιν ὑμῖν ⸂ποιήσατε καὶ τηρεῖτε⸃, κατὰ δὲ τὰ ἔργα αὐτῶν μὴ ποιεῖτε, λέγουσιν γὰρ καὶ οὐ ποιοῦσιν.", "en": {"kjv": "All therefore whatsoever they bid you observe, that observe and do; but do not ye after their works: for they say, and do not.", "web": "All things therefore whatever they tell you to observe, observe and do, but don’t do their works; for they say, and don’t do.", "bsb": "So practice and observe everything they tell you. But do not do what they do, for they do not practice what they preach.", "asv": "all things therefore whatsoever they bid you, these do and observe: but do not ye after their works; for they say, and do not.", "ylt": "all, then, as much as they may say to you to observe, observe and do, but according to their works do not, for they say, and do not;", "tyndale": "All therfore whatsoever they byd you observe that observe and do: but after their workes do not:", "dra": "All things therefore whatsoever they shall say to you, observe and do: but according to their works do ye not. For they say, and do not.", "bbe": "All things, then, which they give you orders to do, these do and keep: but do not take their works as your example, for they say and do not.", "geneva": "All therefore whatsoeuer they bid you obserue, that obserue and doe: but after their workes doe not: for they say, and doe not.", "wycliffe": "Therfor kepe ye, and do ye alle thingis, what euer thingis thei seien to you. But nyle ye do aftir her werkis; for thei seien, and don not.", "rotherham": "All things, therefore, whatsoever they tell you, do and observe,—but, according to their works, do ye not, for they, say, and do not, perform.", "weymouth": "Therefore do and observe everything that they command you; but do not imitate their lives, for though they tell others what to do, they do not do it themselves.", "darby": "all things therefore, whatever they may tell you, do and keep. But do not after their works, for they say and do not,", "twenty": "Therefore practice and lay to heart everything that they tell preach but do not practice.", "acv": "All things therefore, however many they may tell you to observe, observe and do, but do not ye according to their works, for they say, and do not.", "anderson": "therefore, all things that they command you to observe, observe and do. But do not according to their works: for they command, and do not.", "haweis": "all things therefore which they prescribe for you to observe, observe and practise; but do not according to their works, for they say, yet do not practise.", "noyes": "All, therefore, whatever they bid you, do and observe; but do not according to their works; for they say, and do not.", "webster": "All therefore, whatever they bid you observe, [that] observe and do: but do not ye according to their works: for they say, and do not.", "vulgate": "omnia ergo quaecumque dixerint vobis servate et facite secundum opera vero eorum nolite facere dicunt enim et non faciunt;"}}, {"v": 4, "ref": "23:4", "o": "δεσμεύουσιν ⸀δὲ φορτία ⸀βαρέα καὶ ἐπιτιθέασιν ἐπὶ τοὺς ὤμους τῶν ἀνθρώπων, ⸂αὐτοὶ δὲ τῷ⸃ δακτύλῳ αὐτῶν οὐ θέλουσιν κινῆσαι αὐτά.", "en": {"kjv": "For they bind heavy burdens and grievous to be borne, and lay them on men’s shoulders; but they themselves will not move them with one of their fingers.", "web": "For they bind heavy burdens that are grievous to be borne, and lay them on men’s shoulders; but they themselves will not lift a finger to help them.", "bsb": "They tie up heavy, burdensome loads and lay them on men’s shoulders, but they themselves are not willing to lift a finger to move them.", "asv": "Yea, they bind heavy burdens and grievous to be borne, and lay them on men’s shoulders; but they themselves will not move them with their finger.", "ylt": "for they bind together burdens heavy and grievous to be borne, and lay upon the shoulders of men, but with their finger they will not move them.", "tyndale": "For they saye and do not. Ye and they bynde hevy burthes and grevous to be borne and ley the on menes shulders: but they themsylfes will not heave at them with one of their fyngers.", "dra": "For they bind heavy and insupportable burdens and lay them on men's shoulders: but with a finger of their own they will not move them.", "bbe": "They make hard laws and put great weights on men's backs; but they themselves will not put a finger to them.", "geneva": "For they binde heauie burdens, and grieuous to be borne, and lay them on mens shoulders, but they themselues will not moue them with one of their fingers.", "wycliffe": "And thei bynden greuouse chargis, and that moun not be borun, and putten on schuldris of men; but with her fyngur thei wolen not moue hem.", "rotherham": "But they bind together heavy burdens, and lay upon men’s shoulders, whereas, they, with their finger, are not willing to move them.", "weymouth": "Heavy and cumbrous burdens they bind together and load men's shoulders with them, while as for themselves, not with one finger do they choose to lift them.", "darby": "but bind burdens heavy and hard to bear, and lay them on the shoulders of men, but will not move them with their finger.", "twenty": "While they make up heavy loads and pile them on other men’s shoulder’s they decline, themselves, to lift a finger to move them.", "acv": "For they bind heavy burdens and difficult to bear, and lay them on men's shoulders, but they do not want to move them with their finger.", "anderson": "For they bind up burdens that are heavy and hard to be borne, and lay them on the shoulders of men; but they refuse to move them with one of their fingers.", "haweis": "For they bind burdens grievous, and difficultly borne, and lay them on men’s shoulders; but they will not move them with a finger of their own.", "noyes": "They bind heavy burdens, and lay them on men’s shoulders, and will not themselves move them with a finger.", "webster": "For they bind heavy burdens, and grievous to be borne, and lay [them] on men's shoulders; but they [themselves] will not move them with one of their fingers.", "vulgate": "alligant autem onera gravia et inportabilia et inponunt in umeros hominum digito autem suo nolunt ea movere;"}}, {"v": 5, "ref": "23:5", "o": "πάντα δὲ τὰ ἔργα αὐτῶν ποιοῦσιν πρὸς τὸ θεαθῆναι τοῖς ἀνθρώποις· πλατύνουσι ⸀γὰρ τὰ φυλακτήρια αὐτῶν καὶ μεγαλύνουσι τὰ ⸀κράσπεδα,", "en": {"kjv": "But all their works they do for to be seen of men: they make broad their phylacteries, and enlarge the borders of their garments,", "web": "But all their works they do to be seen by men. They make their phylacteries broad, enlarge the fringesof their garments,", "bsb": "All their deeds are done for men to see. They broaden their phylacteries and lengthen their tassels.", "asv": "But all their works they do to be seen of men: for they make broad their phylacteries, and enlarge the borders of their garments,", "ylt": "`And all their works they do to be seen by men, and they make broad their phylacteries, and enlarge the fringes of their garments,", "tyndale": "All their workes they do for to be sene of me. They set abroade their philateries and make large borders on there garmetes", "dra": "And all their works they do for to be seen of men. For they make their phylacteries broad and enlarge their fringes.", "bbe": "But all their works they do so as to be seen by men: for they make wide their phylacteries, and the edges of their robes,", "geneva": "All their workes they doe for to be seene of men: for they make their phylacteries broad, and make long the frindges of their garments,", "wycliffe": "Therfor thei don alle her werkis `that thei be seen of men; for thei drawen abrood her filateries, and magnifien hemmes.", "rotherham": "But, all their works, they do, to be gazed at, by men,—for they make broad their amulets, and make large their fringes,", "weymouth": "And everything they do they do with a view to being observed by men; for they widen their phylacteries and make the tassels large,", "darby": "And all their works they do to be seen of men: for they make broad their phylacteries and enlarge the borders [of their garments],", "twenty": "All their actions are done to attract attention. They widen their phylacteries, and increase the size of their tassels,", "acv": "But all their works they do in order to be seen by men. And they make broad their phylacteries, and enlarge the hems of their garments.", "anderson": "And they do all their works for the purpose of being seen by men. They make their amulets broad, and enlarge the fringes of their mantles.", "haweis": "And all their works they do to be seen of men: they make their phylacteries broad, and deepen the fringes of their garments,", "noyes": "And all their works they do to be observed by men. They make broad their phylacteries, and enlarge their fringes,", "webster": "But all their works they do to be seen by men: they make broad their phylacteries, and enlarge the borders of their garments,", "vulgate": "omnia vero opera sua faciunt ut videantur ab hominibus dilatant enim phylacteria sua et magnificant fimbrias;"}}, {"v": 6, "ref": "23:6", "o": "φιλοῦσι ⸀δὲ τὴν πρωτοκλισίαν ἐν τοῖς δείπνοις καὶ τὰς πρωτοκαθεδρίας ἐν ταῖς συναγωγαῖς", "en": {"kjv": "And love the uppermost rooms at feasts, and the chief seats in the synagogues,", "web": "and love the place of honor at feasts, the best seats in the synagogues,", "bsb": "They love the places of honor at banquets, the chief seats in the synagogues,", "asv": "and love the chief place at feasts, and the chief seats in the synagogues,", "ylt": "they love also the chief couches in the supper, and the chief seats in the synagogues,", "tyndale": "and love to sit vppermooste at feastes and to have the chefe seates in the synagoges", "dra": "And they love the first places at feasts and the first chairs in the synagogues,", "bbe": "And the things desired by them are the first places at feasts, and the chief seats in the Synagogues,", "geneva": "And loue the chiefe place at feastes, and to haue the chiefe seates in the assemblies,", "wycliffe": "And thei louen the first sittyng placis in soperis, and the first chaieris in synagogis;", "rotherham": "And dearly love the first couch in the chief meals, and the first seats in the synagogues,", "weymouth": "and love the best seats at a dinner party or in the synagogues,", "darby": "and love the chief place in feasts and the first seats in the synagogues,", "twenty": "and like to have the place of honour at dinner, and the best seats in the Synagogues,", "acv": "And they love the chief place at feasts, and the chief seats in the synagogues,", "anderson": "They also love the most honorable places at suppers, and the first seats in the synagogues,", "haweis": "and love the principal couch at suppers, and the chief seats in the synagogues,", "noyes": "and love the first place at feasts, and the chief seats in the synagogues,", "webster": "And love the uppermost rooms at feasts, and the chief seats in the synagogues,", "vulgate": "amant autem primos recubitus in cenis et primas cathedras in synagogis;"}}, {"v": 7, "ref": "23:7", "o": "καὶ τοὺς ἀσπασμοὺς ἐν ταῖς ἀγοραῖς καὶ καλεῖσθαι ὑπὸ τῶν ἀνθρώπων· ⸀Ῥαββί.", "en": {"kjv": "And greetings in the markets, and to be called of men, Rabbi, Rabbi.", "web": "the salutations in the marketplaces, and to be called ‘Rabbi, Rabbi’ by men.", "bsb": "the greetings in the marketplaces, and the title of ‘Rabbi’ by which they are addressed.", "asv": "and the salutations in the marketplaces, and to be called of men, Rabbi.", "ylt": "and the salutations in the market-places, and to be called by men, Rabbi, Rabbi.", "tyndale": "and gretinges in the marketes and to be called of men Rabi.", "dra": "And salutations in the market place, and to be called by men, Rabbi.", "bbe": "And words of respect in the market-places, and to be named by men, Teacher.", "geneva": "And greetings in the markets, and to be called of men, Rabbi, Rabbi.", "wycliffe": "and salutaciouns in chepyng, and to be clepid of men maystir.", "rotherham": "And the salutations in the market-places, and to be called by men, Rabbi.", "weymouth": "and like to be bowed to in places of public resort, and to be addressed by men as `Rabbi.'", "darby": "and salutations in the market-places, and to be called of men, Rabbi, Rabbi.", "twenty": "and to be greeted in the markets with respect, and to be called ‘Rabbi’ for everybody.", "acv": "and the greetings in the marketplaces, and to be designated by men, Rabbi, Rabbi.", "anderson": "and salutations in the markets, and to be called by men, Rabbi, Rabbi.", "haweis": "and salutations in the places of public concourse, and to be called of men, Rabbi, Rabbi.", "noyes": "and salutations in the markets, and to be called by men, Rabbi.", "webster": "And greetings in the markets, and to be called by men, Rabbi, Rabbi.", "vulgate": "et salutationes in foro et vocari ab hominibus rabbi;"}}, {"v": 8, "ref": "23:8", "o": "ὑμεῖς δὲ μὴ κληθῆτε· Ῥαββί, εἷς γάρ ἐστιν ὑμῶν ὁ ⸀διδάσκαλος, πάντες δὲ ὑμεῖς ἀδελφοί ἐστε·", "en": {"kjv": "But be not ye called Rabbi: for one is your Master, even Christ; and all ye are brethren.", "web": "But don’t you be called ‘Rabbi,’ for one is your teacher, the Christ, and all of you are brothers.", "bsb": "But you are not to be called ‘Rabbi,’ for you have one Teacher, and you are all brothers.", "asv": "But be not ye called Rabbi: for one is your teacher, and all ye are brethren.", "ylt": "`And ye--ye may not be called Rabbi, for one is your director--the Christ, and all ye are brethren;", "tyndale": "But ye shall not suffre youre selves to be called Rabi. For one is youre master that is to wyt Christ and all ye are brethre.", "dra": "But be not you called Rabbi. For one is your master: and all you are brethren.", "bbe": "But you may not be named Teacher: for one is your teacher, and you are all brothers.", "geneva": "But be not ye called, Rabbi: for one is your doctour, to wit, Christ, and all ye are brethren.", "wycliffe": "But nyle ye be clepid maister; for oon is youre maystir, and alle ye ben britheren.", "rotherham": "But, ye,—do not be called Rabbi,—for, one, is your Teacher, and, all ye, are brethren;", "weymouth": "\"As for you, do not accept the title of `Rabbi,' for one alone is your Teacher, and you are all brothers.", "darby": "But ye, be not ye called Rabbi; for one is your instructor, and all ye are brethren.", "twenty": "But do not allow yourselves to be called ‘Rabbi,’ for you have only one Teacher, and you yourselves are all Brothers.", "acv": "But be ye not designated Rabbi, for one is your leader, the Christ, and ye are all brothers.", "anderson": "But you must not be called Rabbi; for one is your leader, and all of you are brethren.", "haweis": "But be not ye called Rabbi, for one is your leader, the Messiah; and ye all are brethren.", "noyes": "But be not ye called Rabbi; for one is your teacher; and ye are all brethren.", "webster": "But be not ye called Rabbi: for one is your Master, [even] Christ; and all ye are brethren.", "vulgate": "vos autem nolite vocari rabbi unus enim est magister vester omnes autem vos fratres estis;"}}, {"v": 9, "ref": "23:9", "o": "καὶ πατέρα μὴ καλέσητε ὑμῶν ἐπὶ τῆς γῆς, εἷς γάρ ἐστιν ⸂ὑμῶν ὁ πατὴρ⸃ ὁ ⸀οὐράνιος·", "en": {"kjv": "And call no man your father upon the earth: for one is your Father, which is in heaven.", "web": "Call no man on the earth your father, for one is your Father, he who is in heaven.", "bsb": "And do not call anyone on earth your father, for you have one Father, who is in heaven.", "asv": "And call no man your father on the earth: for one is your Father, even he who is in heaven.", "ylt": "and ye may not call any your father on the earth, for one is your Father, who is in the heavens,", "tyndale": "And call no man youre father vpon the erth for there is but one youre father and he is in heven.", "dra": "And call none your father upon earth; for one is your father, who is in heaven.", "bbe": "And give no man the name of father on earth: because one is your Father, who is in heaven.", "geneva": "And call no man your father vpon the earth: for there is but one, your father which is in heauen.", "wycliffe": "And nyle ye clepe to you a fadir on erthe, for oon is your fadir, that is in heuenes.", "rotherham": "And, father, be none of you called, upon the earth, for, one, is your Father, the Heavenly;", "weymouth": "And call no one on earth your Father, for One alone is your Father--the Heavenly Father.", "darby": "And call not [any one] your father upon the earth; for one is your Father, he who is in the heavens.", "twenty": "And do not call any one on the earth your ‘Father,’ for your have only one Father, the heavenly Father.", "acv": "And do not designate a father of you upon the earth, for one is your Father, he in the heavens.", "anderson": "And call no man on earth your father; for one is your Father, who is in heaven.", "haweis": "And call no man your father upon earth; for one is your father, who is in heaven.", "noyes": "And call no one your father on the earth; for one is your father, he who is in heaven.", "webster": "And call no [man] your father upon the earth: for one is your Father who is in heaven.", "vulgate": "et patrem nolite vocare vobis super terram unus enim est Pater vester qui in caelis est;"}}, {"v": 10, "ref": "23:10", "o": "μηδὲ κληθῆτε καθηγηταί, ⸂ὅτι καθηγητὴς ὑμῶν ἐστιν εἷς⸃ ὁ χριστός·", "en": {"kjv": "Neither be ye called masters: for one is your Master, even Christ.", "web": "Neither be called masters, for one is your master, the Christ.", "bsb": "Nor are you to be called instructors, for you have one Instructor, the Christ.", "asv": "Neither be ye called masters: for one is your master, even the Christ.", "ylt": "nor may ye be called directors, for one is your director--the Christ.", "tyndale": "Be not called masters for there is but one youre master and he is Christ.", "dra": "Neither be ye called masters: for one is your master, Christ.", "bbe": "And you may not be named guides: because one is your Guide, even Christ.", "geneva": "Be not called doctours: for one is your doctour, euen Christ.", "wycliffe": "Nether be ye clepid maistris, for oon is youre maister, Crist.", "rotherham": "Neither be called leaders, for, your leader, is one, the Christ;", "weymouth": "And do not accept the name of `leader,' for your Leader is one alone--the Christ.", "darby": "Neither be called instructors, for one is your instructor, the Christ.", "twenty": "Nor must you allow yourselves to be called ‘Leaders,’ for you have only one Leader, the Christ.", "acv": "And be ye not designated leaders, for one is your leader, the Christ.", "anderson": "And be not called leaders; for one is your leader, the Christ.", "haweis": "And be not called leaders; for one is your leader, the Messiah.", "noyes": "Nor be ye called leaders; for one is your leader, the Christ.", "webster": "Neither be ye called masters: for one is your master, [even] Christ.", "vulgate": "nec vocemini magistri quia magister vester unus est Christus;"}}, {"v": 11, "ref": "23:11", "o": "ὁ δὲ μείζων ὑμῶν ἔσται ὑμῶν διάκονος.", "en": {"kjv": "But he that is greatest among you shall be your servant.", "web": "But he who is greatest among you will be your servant.", "bsb": "The greatest among you shall be your servant.", "asv": "But he that is greatest among you shall be your servant.", "ylt": "And the greater of you shall be your ministrant,", "tyndale": "He that is greatest amoge you shalbe youre seruaunte.", "dra": "He that is the greatest among you shall be your servant.", "bbe": "But let the greatest among you be your servant.", "geneva": "But he that is greatest among you, let him be your seruant.", "wycliffe": "He that is grettest among you, schal be youre mynystre.", "rotherham": "And, the greatest of you, shall be to you, a minister;", "weymouth": "He who is the greatest among you shall be your servant;", "darby": "But the greatest of you shall be your servant.", "twenty": "The man who would be the greatest among you must be your servant.", "acv": "But the greater of you will be your helper.", "anderson": "And the greatest among you shall be your minister.", "haweis": "But he who is greatest among you shall be your servant.", "noyes": "But the greatest among you will be your servant.", "webster": "But he that is greatest among you, shall be your servant.", "vulgate": "qui maior est vestrum erit minister vester;"}}, {"v": 12, "ref": "23:12", "o": "ὅστις δὲ ὑψώσει ἑαυτὸν ταπεινωθήσεται, καὶ ὅστις ταπεινώσει ἑαυτὸν ⸀ὑψωθήσεται.", "en": {"kjv": "And whosoever shall exalt himself shall be abased; and he that shall humble himself shall be exalted.", "web": "Whoever exalts himself will be humbled, and whoever humbles himself will be exalted.", "bsb": "For whoever exalts himself will be humbled, and whoever humbles himself will be exalted.", "asv": "And whosoever shall exalt himself shall be humbled; and whosoever shall humble himself shall be exalted.", "ylt": "and whoever shall exalt himself shall be humbled, and whoever shall humble himself shall be exalted.", "tyndale": "But whosoever exalteth himsilfe shalbe brought lowe. And he yt hubleth himsilfe shalbe exalted.", "dra": "And whosoever shall exalt himself shall be humbled: and he that shall humble himself shall be exalted.", "bbe": "And whoever makes himself high will be made low, and whoever makes himself low will be made high.", "geneva": "For whosoeuer will exalt himselfe, shall be brought lowe: and whosoeuer will humble himselfe, shalbe exalted.", "wycliffe": "For he that hieth himself, schal be mekid; and he that mekith hym silf, schal be enhaunsid.", "rotherham": "And, whoever shall exalt himself, shall be, abased, and, whoever shall abase himself, shall be, exalted,", "weymouth": "and one who exalts himself shall be abased, while one who abases himself shall be exalted.", "darby": "And whoever shall exalt himself shall be humbled, and whoever shall humble himself shall be exalted.", "twenty": "Whoever shall exalt himself will be humbled, and whoever shall humble himself will be exalted.", "acv": "And he who will exalt himself will be made low, and he who will make himself low will be exalted.", "anderson": "Whoever exalts himself shall be humbled; and whoever humbles himself shall be exalted.", "haweis": "For whosoever exalteth himself shall be abased; and whosoever abaseth himself shall be exalted.", "noyes": "And whoever shall exalt himself will be humbled; and whoever shall humble himself will be exalted.", "webster": "And whoever shall exalt himself, shall be abased; and he that shall humble himself, shall be exalted.", "vulgate": "qui autem se exaltaverit humiliabitur et qui se humiliaverit exaltabitur;"}}, {"v": 13, "ref": "23:13", "o": "Οὐαὶ ⸀δὲ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι κλείετε τὴν βασιλείαν τῶν οὐρανῶν ἔμπροσθεν τῶν ἀνθρώπων· ὑμεῖς γὰρ οὐκ εἰσέρχεσθε, οὐδὲ τοὺς εἰσερχομένους ἀφίετε ⸀εἰσελθεῖν.", "en": {"kjv": "But woe unto you, scribes and Pharisees, hypocrites! for ye shut up the kingdom of heaven against men: for ye neither go in yourselves, neither suffer ye them that are entering to go in.", "web": "“Woe to you, scribes and Pharisees, hypocrites! For you devour widows’ houses, and as a pretense you make long prayers. Therefore you will receive greater condemnation.", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You shut the kingdom of heaven in men’s faces. You yourselves do not enter, nor will you let in those who wish to enter.", "asv": "But woe unto you, scribes and Pharisees, hypocrites! because ye shut the kingdom of heaven against men: for ye enter not in yourselves, neither suffer ye them that are entering in to enter.", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye shut up the reign of the heavens before men, for ye do not go in, nor those going in do ye suffer to enter.", "tyndale": "Wo be vnto you Scribes and Pharises ypocrites for ye shutte vp the kyngdome of heve before men: ye youre selves goo not in nether suffre ye them that come to enter in.", "dra": "But woe to you, scribes and Pharisees, hypocrites, because you shut the kingdom of heaven against men: for you yourselves do not enter in and those that are going in, you suffer not to enter.", "bbe": "But a curse is on you, scribes and Pharisees, false ones! because you are shutting the kingdom of heaven against men: for you do not go in yourselves, and those who are going in, you keep back.", "geneva": "Wo therefore be vnto you, Scribes and Pharises, hypocrites, because ye shut vp the kingdome of heauen before men: for ye your selues go not in, neither suffer ye them that would enter, to come in.", "wycliffe": "But wo to you, scribis and Farisees, ipocritis, that closen the kyngdom of heuenes bifore men; and ye entren not, nether suffren men entrynge to entre.", "rotherham": "", "weymouth": "\"But alas for you, Scribes and Pharisees, hypocrites, for you lock the door of the Kingdom of the Heavens against men; you yourselves do not enter, nor do you allow those to enter who are seeking to do so.", "darby": "But woe unto you, scribes and Pharisees, hypocrites, for ye shut up the kingdom of the heavens before men; for ye do not enter, nor do ye suffer those that are entering to go in.", "twenty": "But alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You turn the key of the Kingdom of Heaven in men’s faces. For you do not go in yourselves, nor yet allow those who try to go in to do so.", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye close up the kingdom of the heavens ahead of men. For ye enter not in, nor do ye allow those who are entering to enter in.", "anderson": "But alas for you, scribes and Pharisees, hypocrites! for you eat up the houses of widows, and for a pretext make long prayers. For this reason, you shall receive the greater condemnation.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! because ye shut up the kingdom of heaven from men; for ye yourselves enter not in, and those who were coming in, ye suffer not to enter.", "noyes": "But woe to you, scribes and Pharisees, hypocrites I because ye shut up the kingdom of heaven against men; for ye go not in yourselves, nor suffer those who are entering to go in.", "webster": "But woe to you, scribes and Pharisees! hypocrites! for ye shut up the kingdom of heaven against men: for ye neither go in [yourselves], neither suffer ye them that are entering, to go in.", "vulgate": "vae autem vobis scribae et Pharisaei hypocritae quia clauditis regnum caelorum ante homines vos enim non intratis nec introeuntes sinitis intrare;"}}, {"v": 14, "ref": "23:14", "o": "", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! for ye devour widows’ houses, and for a pretence make long prayer: therefore ye shall receive the greater damnation.", "web": "“But woe to you, scribes and Pharisees, hypocrites! Because you shut up the Kingdom of Heaven against men; for you don’t enter in yourselves, neither do you allow those who are entering in to enter.", "bsb": "", "asv": "", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye eat up the houses of the widows, and for a pretence make long prayers, because of this ye shall receive more abundant judgment.", "tyndale": "Wo be vnto you Scribes and Pharises ypocrites: ye devoure widdowes houses and that vnder a coloure of praying longe prayers: wherfore ye shall receave greater damnacion.", "dra": "Woe to you scribes and Pharisees, hypocrites, because you devour the houses of widows, praying long prayers. For this you shall receive the greater judgment.", "bbe": "", "geneva": "Wo be vnto you, Scribes and Pharises, hypocrites: for ye deuoure widowes houses, euen vnder a colour of long prayers: wherefore ye shall receiue the greater damnation.", "wycliffe": "Wo to you, scribis and Farisees, ipocritis, that eten the housis of widowis, and preien bi longe preier; for this thing ye schulen take more doom.", "rotherham": "But alas for you, Scribes and Pharisees, hypocrites; because ye are locking up the kingdom of the heavens before men,—for, ye, are not entering, neither, them who are entering, suffer ye to enter.", "weymouth": "", "darby": "", "twenty": "Alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You destroy widow’s houses, even while pretending to make long prayers; therefore you shall receive greater condemnation.", "acv": "But woe to you, scholars and Pharisees, hypocrites! Because ye devour widows' houses, and praying long in pretence. Because of this ye will receive greater condemnation.", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you close the kingdom of heaven in the face of men; for you neither go in yourselves, nor do you suffer those who are entering, to go in.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye devour widows’ houses, and for a pretence make long prayers: wherefore ye shall receive greater condemnation.", "noyes": "", "webster": "Woe to you, scribes and Pharisees, hypocrites! for ye devour widows' houses, and for a pretense make long prayer: therefore ye shall receive the greater damnation.", "vulgate": "[];"}}, {"v": 15, "ref": "23:15", "o": "Οὐαὶ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι περιάγετε τὴν θάλασσαν καὶ τὴν ξηρὰν ποιῆσαι ἕνα προσήλυτον, καὶ ὅταν γένηται ποιεῖτε αὐτὸν υἱὸν γεέννης διπλότερον ὑμῶν.", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte, and when he is made, ye make him twofold more the child of hell than yourselves.", "web": "Woe to you, scribes and Pharisees, hypocrites! For you travel around by sea and land to make one proselyte; and when he becomes one, you make him twice as much of a son of Gehennaas yourselves.", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You traverse land and sea to win a single convert, and when he becomes one, you make him twice as much a son of hell as you are.", "asv": "Woe unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte; and when he is become so, ye make him twofold more a son of hell than yourselves.", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye go round the sea and the dry land to make one proselyte, and whenever it may happen--ye make him a son of gehenna twofold more than yourselves.", "tyndale": "Wo be vnto you Scribes and Pharises ypocrites which compasse see and londe to bringe one in to youre belefe: and when he ys brought ye make him two folde more the chylde of hell then ye youre selves are.", "dra": "Woe to you, scribes and Pharisees, hypocrites, because you go round about the sea and the land to make one proselyte. And when he is made, you make him the child of hell twofold more than yourselves.", "bbe": "A curse is on you, scribes and Pharisees, false ones! for you go about land and sea to get one disciple and, having him, you make him twice as much a son of hell as yourselves.", "geneva": "Wo be vnto you, Scribes and Pharises, hypocrites: for ye compasse sea and land to make one of your profession: and when he is made, ye make him two folde more the childe of hell, then you your selues.", "wycliffe": "Wo to you, scribis and Farisees, ypocritis, that goon aboute the see and the loond, to make o prosilite; and whanne he is maad, ye maken hym a sone of helle, double more than ye ben.", "rotherham": "Alas for you, Scribes and Pharisees, hypocrites: because ye compass sea and dry land, to make one convert—and, when it is done, ye make him a son of gehenna, twofold more than ye.", "weymouth": "\"Alas for you, Scribes and Pharisees, hypocrites, for you scour sea and land in order to win one convert--and when he is gained, you make him twice as much a son of Gehenna as yourselves.", "darby": "Woe to you, scribes and Pharisees, hypocrites, for ye compass the sea and the dry [land] to make one proselyte, and when he is become [such], ye make him twofold more [the] son of hell than yourselves.", "twenty": "Alas for you, teachers of the law and Pharisees, hypocrites that you are! You scour land and sea to make a single convert, and, when he is gained, you make him twice as deserving of the Pit as you are yourselves.", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye encompass the sea and the land to make one proselyte, and when it happens, ye make him twice more a son of hell than yourselves.", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you traverse sea and land to make one proselyte; and when he is made, you make him twofold more a child of hell than yourselves.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte; and when he is gained, ye make him doubly more the child of hell than yourselves.", "noyes": "Woe to you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte; and when he is made, ye make him two-fold mole a son of hell than yourselves.", "webster": "Woe to you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte, and when he is made, ye make him two-fold more the child of hell than yourselves.", "vulgate": "vae vobis scribae et Pharisaei hypocritae quia circuitis mare et aridam ut faciatis unum proselytum et cum fuerit factus facitis eum filium gehennae duplo quam vos;"}}, {"v": 16, "ref": "23:16", "o": "Οὐαὶ ὑμῖν, ὁδηγοὶ τυφλοὶ οἱ λέγοντες· Ὃς ἂν ὀμόσῃ ἐν τῷ ναῷ, οὐδέν ἐστιν, ὃς δ’ ἂν ὀμόσῃ ἐν τῷ χρυσῷ τοῦ ναοῦ ὀφείλει.", "en": {"kjv": "Woe unto you, ye blind guides, which say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor!", "web": "“Woe to you, you blind guides, who say, ‘Whoever swears by the temple, it is nothing; but whoever swears by the gold of the temple, he is obligated.’", "bsb": "Woe to you, blind guides! You say, ‘If anyone swears by the temple, it means nothing; but if anyone swears by the gold of the temple, he is bound by his oath.’", "asv": "Woe unto you, ye blind guides, that say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor.", "ylt": "`Woe to you, blind guides, who are saying, Whoever may swear by the sanctuary, it is nothing, but whoever may swear by the gold of the sanctuary--is debtor!", "tyndale": "Wo be vnto you blynd gides which saye whosoever sweare by the teple it is no thinge: but whosoever sweare by the golde of the temple he offendeth.", "dra": "Woe to you, blind guides, that say, Whosoever shall swear by the temple, it is nothing; but he that shall swear by the gold of the temple is a debtor.", "bbe": "A curse is on you, blind guides, who say, Whoever takes an oath by the Temple, it is nothing; but whoever takes an oath by the gold of the Temple, he is responsible.", "geneva": "Wo be vnto you blinde guides, which say, Whosoeuer sweareth by the Temple, it is nothing: but whosoeuer sweareth by the golde of the Temple, he offendeth.", "wycliffe": "Wo to you, blynde lederis, that seien, Who euer swerith bi the temple of God, it is `no thing; but he that swerith in the gold of the temple, is dettoure.", "rotherham": "Alas for you, blind guides! that say—Whosoever shall swear by the Temple, it is, nothing, but, whosoever shall swear by the gold of the Temple, is bound:", "weymouth": "\"Alas for you, you blind guides, who say, \"`Whoever swears by the Sanctuary it is nothing; but whoever swears by the gold of the Sanctuary, is bound by the oath.'", "darby": "Woe to you, blind guides, who say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor.", "twenty": "Alas for you, you blind guides! You say ‘if any answer by the Temple, his oath counts for nothing; but, if any one swears by the gold of the Temple, his oath is binding him’!", "acv": "Woe to you, ye blind guides, who say, Whoever may swear by the temple, it is nothing, but whoever may swear by the gold of the temple, he is obligated.", "anderson": "Alas for you, blind guides! who say, Whoever shall swear by the temple, it is nothing; but whoever shall swear by the gold of the temple, becomes a debtor.", "haweis": "Wo unto you ye blind guides! who say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, it is binding.", "noyes": "Woe to you, blind guides, that say, Whoever sweareth by the temple, it is nothing; but whoever sweareth by the gold of the temple, is bound.", "webster": "Woe to you, [ye] blind guides, who say, Whoever shall swear by the temple, it is nothing; but whoever shall swear by the gold of the temple, he is a debtor.", "vulgate": "vae vobis duces caeci qui dicitis quicumque iuraverit per templum nihil est qui autem iuraverit in aurum templi debet;"}}, {"v": 17, "ref": "23:17", "o": "μωροὶ καὶ τυφλοί, τίς γὰρ μείζων ἐστίν, ὁ χρυσὸς ἢ ὁ ναὸς ὁ ⸀ἁγιάσας τὸν χρυσόν;", "en": {"kjv": "Ye fools and blind: for whether is greater, the gold, or the temple that sanctifieth the gold?", "web": "You blind fools! For which is greater, the gold, or the temple that sanctifies the gold?", "bsb": "You blind fools! Which is greater: the gold, or the temple that makes it sacred?", "asv": "Ye fools and blind: for which is greater, the gold, or the temple that hath sanctified the gold?", "ylt": "Fools and blind! for which is greater, the gold, or the sanctuary that is sanctifying the gold?", "tyndale": "Ye foles and blinde? whether is greater the golde or the teple that sanctifieth ye golde.", "dra": "Ye foolish and blind: for whether is greater, the gold or the temple that sanctifieth the gold?", "bbe": "You foolish ones and blind: which is greater, the gold, or the Temple which makes the gold holy?", "geneva": "Ye fooles and blinde, whether is greater, the golde, or the Temple that sanctifieth the golde?", "wycliffe": "Ye foolis and blynde, for what is grettere, the gold, or the temple that halewith the gold?", "rotherham": "Foolish and blind! for which is, greater, The gold, or the Temple that hath hallowed the gold?", "weymouth": "\"Blind fools! Why, which is greater? --the gold, or the Sanctuary which has made the gold holy?", "darby": "Fools and blind, for which is greater, the gold, or the temple which sanctifies the gold?", "twenty": "Fools that you are and blind! Which is the more important? The gold? Or the Temple which has given sacredness to the gold?", "acv": "Ye foolish and blind men, for which is greater, the gold, or the temple that makes the gold sacred?", "anderson": "Fools and blind! for which is greater, the gold, or the temple that sanctifies the gold?", "haweis": "Ye fools and blind! for which is the greater, the gold, or the temple which consecrates the gold?", "noyes": "Fools and blind I for which is greater, the gold, or the temple that sanctifieth the gold?", "webster": "[Ye] fools, and blind: for which is greater, the gold, or the temple that sanctifieth the gold?", "vulgate": "stulti et caeci quid enim maius est aurum an templum quod sanctificat aurum;"}}, {"v": 18, "ref": "23:18", "o": "καί· Ὃς ⸀ἂν ὀμόσῃ ἐν τῷ θυσιαστηρίῳ, οὐδέν ἐστιν, ὃς δ’ ἂν ὀμόσῃ ἐν τῷ δώρῳ τῷ ἐπάνω αὐτοῦ ὀφείλει.", "en": {"kjv": "And, Whosoever shall swear by the altar, it is nothing; but whosoever sweareth by the gift that is upon it, he is guilty.", "web": "‘Whoever swears by the altar, it is nothing; but whoever swears by the gift that is on it, he is obligated?’", "bsb": "And you say, ‘If anyone swears by the altar, it means nothing; but if anyone swears by the gift on it, he is bound by his oath.’", "asv": "And, Whosoever shall swear by the altar, it is nothing; but whosoever shall swear by the gift that is upon it, he is a debtor.", "ylt": "`And, whoever may swear by the altar, it is nothing; but whoever may swear by the gift that is upon it--is debtor!", "tyndale": "And whosoever sweareth by the aulter it is nothinge: but whosoever sweareth by ye offeringe yt lyeth on ye aultre offendeth.", "dra": "And whosoever shall swear by the altar, it is nothing; but whosoever shall swear by the gift that is upon it is a debtor.", "bbe": "And, Whoever takes an oath by the altar, it is nothing; but whoever takes an oath by the offering which is on it, he is responsible.", "geneva": "And whosoeuer sweareth by the altar, it is nothing: but whosoeuer sweareth by the offering that is vpon it, offendeth.", "wycliffe": "And who euer swerith in the auter, it is no thing; but he that swerith in the yifte that is on the auter, owith.", "rotherham": "And, whosoever shall swear by the altar, it is, nothing, but, whosoever shall swear by the gift that is upon it, is bound:", "weymouth": "And you say, \"`Whoever swears by the altar, it is nothing; but whoever swears by the offering lying on it is bound by the oath.'", "darby": "And, Whosoever shall swear by the altar, it is nothing; but whosoever shall swear by the gift that is upon it is a debtor.", "twenty": "You say, too, ‘If any one swears by the altar, his oath counts for nothing, but, if any one swears by the offering placed on it, his oath is binding on him’!", "acv": "And, Whoever may swear by the altar, it is nothing, but whoever may swear by the gift upon it, he is obligated.", "anderson": "And, Whoever shall swear by the altar, it is nothing; but whoever shall swear by the gift that is on it, becomes a debtor.", "haweis": "And again, Whosoever shall swear by the altar, it is nothing; but whosoever shall swear by the gift that is upon it, it is binding.", "noyes": "And, Whoever sweareth by the altar, it is nothing; but whoever sweareth by the gift that is upon it, is bound.", "webster": "And whoever shall swear by the altar, it is nothing; but whoever sweareth by the gift that is upon it, he is guilty.", "vulgate": "et quicumque iuraverit in altari nihil est quicumque autem iuraverit in dono quod est super illud debet;"}}, {"v": 19, "ref": "23:19", "o": "⸀τυφλοί, τί γὰρ μεῖζον, τὸ δῶρον ἢ τὸ θυσιαστήριον τὸ ἁγιάζον τὸ δῶρον;", "en": {"kjv": "Ye fools and blind: for whether is greater, the gift, or the altar that sanctifieth the gift?", "web": "You blind fools! For which is greater, the gift, or the altar that sanctifies the gift?", "bsb": "You blind men! Which is greater: the gift, or the altar that makes it sacred?", "asv": "Ye blind: for which is greater, the gift, or the altar that sanctifieth the gift?", "ylt": "Fools and blind! for which is greater, the gift, or the altar that is sanctifying the gift?", "tyndale": "Ye foles and blinde: whether is greater ye offeringe or ye aultre which sanctifieth ye offeringe?", "dra": "Ye foolish and blind: for whether is greater, the gift or the altar that sanctifieth the gift?", "bbe": "You blind ones: which is greater, the offering, or the altar which makes the offering holy?", "geneva": "Ye fooles and blinde, whether is greater, the offering, or the altar which sanctifieth the offering?", "wycliffe": "Blynde men, for what is more, the yifte, or the auter that halewith the yifte?", "rotherham": "Blind! for which is greater, The gift, or the altar that halloweth the gift?", "weymouth": "\"You are blind! Why, which is greater? --the offering, or the altar which makes the offering holy?", "darby": "[Fools and] blind ones, for which is greater, the gift, or the altar which sanctifies the gift?", "twenty": "Blind indeed! Which is the more important? The offering? or the altar which gives sacredness to the offering?", "acv": "Ye foolish and blind men, for which is greater, the gift, or the altar that makes the gift sacred?", "anderson": "Fools and blind! for which is greater, the gift, or the altar that sanctifies the gift?", "haweis": "Ye fools and blind! which is the greater, the gift, or the altar which consecrates the gift?", "noyes": "Blind men! For which is greater, the gift, or the altar flint sanctifieth the gift?", "webster": "[Ye] fools, and blind: for which [is] greater, the gift, or the altar that sanctifieth the gift?", "vulgate": "caeci quid enim maius est donum an altare quod sanctificat donum;"}}, {"v": 20, "ref": "23:20", "o": "ὁ οὖν ὀμόσας ἐν τῷ θυσιαστηρίῳ ὀμνύει ἐν αὐτῷ καὶ ἐν πᾶσι τοῖς ἐπάνω αὐτοῦ·", "en": {"kjv": "Whoso therefore shall swear by the altar, sweareth by it, and by all things thereon.", "web": "He therefore who swears by the altar, swears by it, and by everything on it.", "bsb": "So then, he who swears by the altar swears by it and by everything on it.", "asv": "He therefore that sweareth by the altar, sweareth by it, and by all things thereon.", "ylt": "`He therefore who did swear by the altar, doth swear by it, and by all things on it;", "tyndale": "Whosoever therfore sweareth by ye aultre sweareth by it and by all yt there on is.", "dra": "He therefore that sweareth by the altar sweareth by it and by all things that are upon it.", "bbe": "He, then, who takes an oath by the altar, takes it by the altar and by all things on it.", "geneva": "Whosoeuer therefore sweareth by the altar, sweareth by it, and by all things thereon.", "wycliffe": "Therfor he that swerith in the auter, swerith in it, and in alle thingis that ben ther on.", "rotherham": "He therefore that hath sworn by the altar, sweareth by it, and by all that is upon it;", "weymouth": "He who swears by the altar swears both by it and by everything on it;", "darby": "He therefore that swears by the altar swears by it and by all things that are upon it.", "twenty": "Therefore a man, swearing by the altar, swears by it and by all that is on it,", "acv": "He therefore who swears by the altar, swears by it, and by all things on it.", "anderson": "Therefore, whoever swears by the altar, swears by it, and by all that is on it.", "haweis": "Whosoever therefore sweareth by the altar, sweareth by it, and by all things that are upon it.", "noyes": "He then who sweareth by the altar, sweareth by it, and by all that is upon it;", "webster": "Whoever therefore shall swear by the altar, sweareth by it, and by all things upon it.", "vulgate": "qui ergo iurat in altare iurat in eo et in omnibus quae super illud sunt;"}}, {"v": 21, "ref": "23:21", "o": "καὶ ὁ ὀμόσας ἐν τῷ ναῷ ὀμνύει ἐν αὐτῷ καὶ ἐν τῷ ⸀κατοικοῦντι αὐτόν·", "en": {"kjv": "And whoso shall swear by the temple, sweareth by it, and by him that dwelleth therein.", "web": "He who swears by the temple, swears by it, and by him who was livingin it.", "bsb": "And he who swears by the temple swears by it and by the One who dwells in it.", "asv": "And he that sweareth by the temple, sweareth by it, and by him that dwelleth therein.", "ylt": "and he who did swear by the sanctuary, doth swear by it, and by Him who is dwelling in it;", "tyndale": "And whosoever sweareth by the teple sweareth by it and by hym yt dwelleth therin.", "dra": "And whosoever shall swear by the temple sweareth by it and by him that dwelleth in it.", "bbe": "And he who takes an oath by the Temple, takes it by the Temple and by him whose house it is.", "geneva": "And whosoeuer sweareth by the Temple, sweareth by it, and by him that dwelleth therein.", "wycliffe": "And he that swerith in the temple, swerith in it, and in hym that dwellith in the temple.", "rotherham": "And, he that hath sworn by the Temple, sweareth by it, and by him who dwelleth therein;", "weymouth": "he who swears by the Sanctuary swears both by it and by Him who dwells in it;", "darby": "And he that swears by the temple swears by it and by him that dwells in it.", "twenty": "and a man, swearing by the Temple, swears by it and by him who dwells in it,", "acv": "And he who swears by the temple, swears by it, and by him who dwells in it.", "anderson": "And whoever swears by the temple, swears by it, and by him that dwells in it.", "haweis": "And whosoever sweareth by the temple, sweareth by it, and by him also who dwelleth in it.", "noyes": "and he that sweareth by the temple, sweareth by it, and by him who dwelleth in it;", "webster": "And whoever shall swear by the temple, sweareth by it, and by him that dwelleth in it.", "vulgate": "et qui iuraverit in templo iurat in illo et in eo qui inhabitat in ipso;"}}, {"v": 22, "ref": "23:22", "o": "καὶ ὁ ὀμόσας ἐν τῷ οὐρανῷ ὀμνύει ἐν τῷ θρόνῳ τοῦ θεοῦ καὶ ἐν τῷ καθημένῳ ἐπάνω αὐτοῦ.", "en": {"kjv": "And he that shall swear by heaven, sweareth by the throne of God, and by him that sitteth thereon.", "web": "He who swears by heaven, swears by the throne of God, and by him who sits on it.", "bsb": "And he who swears by heaven swears by God’s throne and by the One who sits on it.", "asv": "And he that sweareth by the heaven, sweareth by the throne of God, and by him that sitteth thereon.", "ylt": "and he who did swear by the heaven, doth swear by the throne of God, and by Him who is sitting upon it.", "tyndale": "And he that sweareth by heve swereth by the seate of God and by hym that sytteth theron.", "dra": "And he that sweareth by heaven sweareth by the throne of God and by him that sitteth thereon.", "bbe": "And he who takes an oath by heaven, takes it by the seat of God, and by him who is seated on it.", "geneva": "And he that sweareth by heauen, sweareth by the throne of God, and by him that sitteth thereon.", "wycliffe": "And he that swerith in heuene, swerith in the trone of God, and in hym that sittith ther on.", "rotherham": "And, he that hath sworn by heaven, sweareth by the throne of God, and by him who sitteth thereupon.", "weymouth": "and he who swears by Heaven swears both by the throne of God and by Him who sits upon it.", "darby": "And he that swears by heaven swears by the throne ofGod and by him that sits upon it.", "twenty": "while a man, swearing by Heaven, swears by the throne of God, and by him who sits upon it.", "acv": "And he who swears by heaven, swears by the throne of God, and by him who sits upon it.", "anderson": "And he that swears by heaven, swears by the throne of God, and by him that sits upon it.", "haweis": "So he that sweareth by heaven, sweareth by the throne of God, and by him who is seated upon it.", "noyes": "and he who sweareth by heaven, sweareth by the throne of God, and by him who sitteth thereon.", "webster": "And he that shall swear by heaven, sweareth by the throne of God, and by him that sitteth upon it.", "vulgate": "et qui iurat in caelo iurat in throno Dei et in eo qui sedet super eum;"}}, {"v": 23, "ref": "23:23", "o": "Οὐαὶ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι ἀποδεκατοῦτε τὸ ἡδύοσμον καὶ τὸ ἄνηθον καὶ τὸ κύμινον, καὶ ἀφήκατε τὰ βαρύτερα τοῦ νόμου, τὴν κρίσιν καὶ ⸂τὸ ἔλεος⸃ καὶ τὴν πίστιν· ⸀ταῦτα ἔδει ποιῆσαι κἀκεῖνα μὴ ⸀ἀφιέναι.", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! for ye pay tithe of mint and anise and cummin, and have omitted the weightier matters of the law, judgment, mercy, and faith: these ought ye to have done, and not to leave the other undone.", "web": "“Woe to you, scribes and Pharisees, hypocrites! For you tithe mint, dill, and cumin, and have left undone the weightier matters of the law: justice, mercy, and faith. But you ought to have done these, and not to have left the other undone.", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You pay tithes of mint, dill, and cumin. But you have disregarded the weightier matters of the law: justice, mercy, and faithfulness. You should have practiced the latter, without neglecting the former.", "asv": "Woe unto you, scribes and Pharisees, hypocrites! for ye tithe mint and anise and cummin, and have left undone the weightier matters of the law, justice, and mercy, and faith: but these ye ought to have done, and not to have left the other undone.", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye give tithe of the mint, and the dill, and the cumin, and did neglect the weightier things of the Law--the judgment, and the kindness, and the faith; these it behoved you to do, and those not to neglect.", "tyndale": "Wo be to you Scribes and Pharises ypocrites which tythe mynt annyse and comen and leave the waygthtyer mattres of ye lawe vndone: iudgemet mercy and fayth. These ought ye to have done and not to have left the othre vndone.", "dra": "Woe to you, scribes and Pharisees, hypocrites; because you tithe mint and anise and cummin and have left the weightier things of the law: judgment and mercy and faith. These things you ought to have done and not to leave those undone.", "bbe": "A curse is on you, scribes and Pharisees, false ones! for you make men give a tenth of all sorts of sweet-smelling plants, but you give no thought to the more important things of the law, righteousness, and mercy, and faith; but it is right for you to do these, and not to let the others be undone.", "geneva": "Wo be to you, Scribes and Pharises, hypocrites: for ye tithe mynt, and annyse, and cummyn, and leaue the weightier matters of the law, as iudgement, and mercy and fidelitie. These ought ye to haue done, and not to haue left the other.", "wycliffe": "Wo to you, scribis and Farisees, ypocritis, that tithen mynte, anete, and cummyn, and han left tho thingis that ben of more charge of the lawe, doom, and merci, and feith. And it bihofte to do these thingis, and not to leeue tho.", "rotherham": "Alas for you, Scribes and Pharisees, hypocrites; because ye tithe the mint and the anise and the cummin,—and have dismissed the weightier matters of the law—the justice, the mercy, and the faith; whereas, these, it was binding, to do, and, those, not to, dismiss.", "weymouth": "\"Alas for you, Scribes and Pharisees, hypocrites, for you pay the tithe on mint, dill, and cumin, while you have neglected the weightier requirements of the Law--just judgement, mercy, and faithful dealing. These things you ought to have done, and yet you ought not to have left the others undone.", "darby": "Woe to you, scribes and Pharisees, hypocrites, for ye pay tithes of mint and anise and cummin, and ye have left aside the weightier matters of the law, judgment and mercy and faith: these ye ought to have done and not have left those aside.", "twenty": "Alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You pay tithes on mint, fennel, and caraway seed, and have neglected the weightier matters of the Law — justice, mercy, and good faith. These last you ought to have put into practice, without neglecting the first.", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye tithe the mint and the anise and the cummin, and have omitted the weightier matters of the law-justice and mercy and faith. These things must be done, and not neglecting those things.", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you pay tithes of mint and dill and cummin, and have neglected the weightier matters of the law, its justice, its mercy, and its faithfulness. These you ought to have done, and those you ought not to have neglected.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye pay tithes of mint, and anise, and cummin, and have neglected the weightier precepts of the law, judgment, and mercy, and fidelity: these thing ought ye to have done, and not to leave the others undone.", "noyes": "Woe to you, scribes and Pharisees, hypocrites! for ye pay tithes of the mint, and the dill, and the cummin, and have omitted the weightier matters of the Law, justice, and mercy, and faith; these ought ye to have done, and not to leave those undone.", "webster": "Woe to you, scribes and Pharisees, hypocrites! for ye pay tithe of mint, and anise, and cummin, and have omitted the weightier [matters] of the law, judgment, mercy, and faith: these ye ought to have done, and not to leave the others undone.", "vulgate": "vae vobis scribae et Pharisaei hypocritae quia decimatis mentam et anethum et cyminum et reliquistis quae graviora sunt legis iudicium et misericordiam et fidem haec oportuit facere et illa non omittere;"}}, {"v": 24, "ref": "23:24", "o": "ὁδηγοὶ τυφλοί, ⸀οἱ διϋλίζοντες τὸν κώνωπα τὴν δὲ κάμηλον καταπίνοντες.", "en": {"kjv": "Ye blind guides, which strain at a gnat, and swallow a camel.", "web": "You blind guides, who strain out a gnat, and swallow a camel!", "bsb": "You blind guides! You strain out a gnat but swallow a camel.", "asv": "Ye blind guides, that strain out the gnat, and swallow the camel!", "ylt": "`Blind guides! who are straining out the gnat, and the camel are swallowing.", "tyndale": "Ye blinde gydes which strayne out a gnat and swalowe a cammyll.", "dra": "Blind guides, who strain out a gnat and swallow a camel.", "bbe": "You blind guides, who take out a fly from your drink, but make no trouble over a camel.", "geneva": "Ye blinde guides, which straine out a gnat, and swallowe a camell.", "wycliffe": "Blynde lederis, clensinge a gnatte, but swolewynge a camel.", "rotherham": "Blind guides! Straining out the gnat, but, the camel, swallowing.", "weymouth": "You blind guides, straining out the gnat while you gulp down the camel!", "darby": "Blind guides, who strain out the gnat, but drink down the camel.", "twenty": "You blind guides, to strain out a gnat and to swallow a camel!", "acv": "Ye blind guides, who strain out the gnat, and swallow the camel.", "anderson": "Blind guides! who strain out a gnat, but swallow a camel.", "haweis": "Ye blind guides! who strain out a gnat, but gulp down a camel.", "noyes": "Blind guides! who strain out a gnat, and swallow a camel.", "webster": "[Ye] blind guides, who strain out a gnat, and swallow a camel.", "vulgate": "duces caeci excolantes culicem camelum autem gluttientes;"}}, {"v": 25, "ref": "23:25", "o": "Οὐαὶ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι καθαρίζετε τὸ ἔξωθεν τοῦ ποτηρίου καὶ τῆς παροψίδος, ἔσωθεν δὲ γέμουσιν ἐξ ἁρπαγῆς καὶ ⸀ἀκρασίας.", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and of the platter, but within they are full of extortion and excess.", "web": "“Woe to you, scribes and Pharisees, hypocrites! For you clean the outside of the cup and of the platter, but within they are full of extortion and unrighteousness.", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You clean the outside of the cup and dish, but inside they are full of greed and self-indulgence.", "asv": "Woe unto you, scribes and Pharisees, hypocrites! for ye cleanse the outside of the cup and of the platter, but within they are full from extortion and excess.", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye make clean the outside of the cup and the plate, and within they are full of rapine and incontinence.", "tyndale": "Wo be to you scribes and pharises ypocrites which make clene ye vtter syde of the cuppe and of the platter: but within they are full of brybery and excesse.", "dra": "Woe to you, scribes and Pharisees, hypocrites; because you make clean the outside of the cup and of the dish, but within you are full of rapine and uncleanness.", "bbe": "A curse is on you, scribes and Pharisees, false ones! for you make clean the outside of the cup and of the plate, but inside they are full of violent behaviour and uncontrolled desire.", "geneva": "Wo be to you, Scribes and Pharises, hypocrites: for ye make cleane the vtter side of the cup, and of the platter: but within they are ful of briberie and excesse.", "wycliffe": "Woo to you, scribis and Farisees, ypocritis, that clensen the cuppe and the plater with outforth; but with ynne ye ben ful of raueyne and vnclennesse.", "rotherham": "Alas for you, Scribes and Pharisees, hypocrites; because ye cleanse the outside of the cup and of the dish,—while, within, they are full of plunder and intemperance.", "weymouth": "\"Alas for you, Scribes and Pharisees, hypocrites, for you wash clean the outside of the cup or dish, while within they are full of greed and self-indulgence.", "darby": "Woe to you, scribes and Pharisees, hypocrites, for ye make clean the outside of the cup and of the dish, but within they are full of rapine and intemperance.", "twenty": "Alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You clean the outside of the cup and the dish, but inside they are filled with the results of greed and self-indulgence.", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye cleanse the outside of the cup and of the platter, but inside they are full of plunder and unrighteousness.", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you make clean the outside of the cup and the plate; but within they are full of rapine and excess.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye cleanse the outside of the cup, and of the dish, but within they are full of rapacity and intemperance.", "noyes": "Woe to you, scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and the platter, but within they are full of robbery and licentiousness.", "webster": "Woe to you, scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and of the platter, but within they are full of extortion and excess.", "vulgate": "vae vobis scribae et Pharisaei hypocritae quia mundatis quod de foris est calicis et parapsidis intus autem pleni sunt rapina et inmunditia;"}}, {"v": 26, "ref": "23:26", "o": "Φαρισαῖε τυφλέ, καθάρισον πρῶτον τὸ ἐντὸς τοῦ ποτηρίου ⸂καὶ τῆς παροψίδος⸃, ἵνα γένηται καὶ τὸ ἐκτὸς ⸀αὐτοῦ καθαρόν.", "en": {"kjv": "Thou blind Pharisee, cleanse first that which is within the cup and platter, that the outside of them may be clean also.", "web": "You blind Pharisee, first clean the inside of the cup and of the platter, that its outside may become clean also.", "bsb": "Blind Pharisee! First clean the inside of the cup and dish, so that the outside may become clean as well.", "asv": "Thou blind Pharisee, cleanse first the inside of the cup and of the platter, that the outside thereof may become clean also.", "ylt": "`Blind Pharisee! cleanse first the inside of the cup and the plate, that the outside of them also may become clean.", "tyndale": "Thou blinde Pharise clense fyrst the outsyde of the cup and platter that the ynneside of them maye be clene also.", "dra": "Thou blind Pharisee, first make clean the inside of the cup and of the dish, that the outside may become clean.", "bbe": "You blind Pharisee, first make clean the inside of the cup and of the plate, so that the outside may become equally clean.", "geneva": "Thou blinde Pharise, cleanse first the inside of the cup and platter, that the outside of them may be cleane also.", "wycliffe": "Thou blynde Farisee, clense the cuppe and the plater with ynneforth, that that that is with outforth be maad clene.", "rotherham": "Blind Pharisee! cleanse, first, the inside, of the cup [and of the dish], that, the outside thereof, may become, clean.", "weymouth": "Blind Pharisee, first wash clean the inside of the cup or dish, and then the outside will be clean also.", "darby": "Blind Pharisee, make clean first the inside of the cup and of the dish, that their outside also may become clean.", "twenty": "You blind Pharisee! First clean the inside of the cup and the dish, so that the outside may become clean as well.", "acv": "Thou blind Pharisee, cleanse first the inside of the cup and of the platter, so that the outside of them may also become clean.", "anderson": "Blind Pharisee! first make clean the inside of the cup and the plate, that the outside of them also may be clean.", "haweis": "Thou blind Pharisee! cleanse first the inside of the cup and dish, that their outside may become clean also.", "noyes": "Blind Pharisee! cleanse first the inside of the cup, that its outside side also may become clean.", "webster": "[Thou] blind Pharisee, cleanse first that [which is] within the cup and platter, that the outside of them may be clean also.", "vulgate": "Pharisaee caece munda prius quod intus est calicis et parapsidis ut fiat et id quod de foris est mundum;"}}, {"v": 27, "ref": "23:27", "o": "Οὐαὶ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι ⸀παρομοιάζετε τάφοις κεκονιαμένοις, οἵτινες ἔξωθεν μὲν φαίνονται ὡραῖοι ἔσωθεν δὲ γέμουσιν ὀστέων νεκρῶν καὶ πάσης ἀκαθαρσίας·", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! for ye are like unto whited sepulchres, which indeed appear beautiful outward, but are within full of dead men’s bones, and of all uncleanness.", "web": "“Woe to you, scribes and Pharisees, hypocrites! For you are like whitened tombs, which outwardly appear beautiful, but inwardly are full of dead men’s bones, and of all uncleanness.", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You are like whitewashed tombs, which look beautiful on the outside, but on the inside are full of dead men’s bones and every kind of impurity.", "asv": "Woe unto you, scribes and Pharisees, hypocrites! for ye are like unto whited sepulchres, which outwardly appear beautiful, but inwardly are full of dead men’s bones, and of all uncleanness.", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye are like to whitewashed sepulchres, which outwardly indeed do appear beautiful, and within are full of bones of dead men, and of all uncleanness;", "tyndale": "Wo be to you Scribe and Pharises ypocrite for ye are lyke vnto paynted tombes which appere beautyfull outwarde: but are wt in full of deed bones and of all fylthynes.", "dra": "Woe to you, scribes and Pharisees, hypocrites; because you are like to whited sepulchres, which outwardly appear to men beautiful but within are full of dead men's bones and of all filthiness.", "bbe": "A curse is on you, scribes and Pharisees, false ones! for you are like the resting-places of the dead, which are made white, and seem beautiful on the outside, but inside are full of dead men's bones and of all unclean things.", "geneva": "Wo be to you, Scribes and Pharises, hypocrites: for ye are like vnto whited tombes, which appeare beautifull outward, but are within full of dead mens bones, and all filthines.", "wycliffe": "Wo to you, scribis and Farisees, ipocritis, that ben lijk to sepulcris whitid, whiche with outforth semen faire to men; but with ynne thei ben fulle of boonus of deed men, and of al filthe.", "rotherham": "Alas for you, Scribes and Pharisees, hypocrites; because ye make yourselves like sepulchres whitewashed, which, outside, indeed, appear, beautiful, but, within, are full, of dead men’s bones and all uncleanness,—", "weymouth": "\"Alas for you, Scribes and Pharisees, hypocrites, for you are just like whitewashed sepulchres, the outside of which pleases the eye, though inside they are full of dead men's bones and of all that is unclean.", "darby": "Woe to you, scribes and Pharisees, hypocrites, for ye are like whited sepulchres, which appear beautiful outwardly, but within are full of dead men's bones and all uncleanness.", "twenty": "Alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You are like whitewashed tombs, which indeed look fair outside, while inside they are filled with dead men’s bones and all kinds of filth.", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye are like whitewashed tombs, which indeed appear beautiful outwardly, but inside are full of dead men's bones, and of all uncleanness.", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you are like whitened sepulchers, which without appear beautiful, but within are full of dead men’s bones, and of all uncleanness.", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye resemble tombs whitewashed, which outwardly indeed appear specious, but within are full of dead men’s bones, and all manner of impurity.", "noyes": "Woe to you, scribes and Pharisees, hypocrites! for ye are like whited sepulchres, which outwardly indeed appear beautiful, but within are full of dead men’s bones, and of all uncleanness.", "webster": "Woe to you, scribes and Pharisees, hypocrites! for ye are like whitened sepulchers, which indeed appear beautiful outward, but are within full of dead [men's] bones, and of all uncleanness.", "vulgate": "vae vobis scribae et Pharisaei hypocritae quia similes estis sepulchris dealbatis quae a foris parent hominibus speciosa intus vero plena sunt ossibus mortuorum et omni spurcitia;"}}, {"v": 28, "ref": "23:28", "o": "οὕτως καὶ ὑμεῖς ἔξωθεν μὲν φαίνεσθε τοῖς ἀνθρώποις δίκαιοι, ἔσωθεν δέ ⸂ἐστε μεστοὶ⸃ ὑποκρίσεως καὶ ἀνομίας.", "en": {"kjv": "Even so ye also outwardly appear righteous unto men, but within ye are full of hypocrisy and iniquity.", "web": "Even so you also outwardly appear righteous to men, but inwardly you are full of hypocrisy and iniquity.", "bsb": "In the same way, on the outside you appear to be righteous, but on the inside you are full of hypocrisy and wickedness.", "asv": "Even so ye also outwardly appear righteous unto men, but inwardly ye are full of hypocrisy and iniquity.", "ylt": "so also ye outwardly indeed do appear to men righteous, and within ye are full of hypocrisy and lawlessness.", "tyndale": "So are ye for outwarde ye appere righteous vnto me when within ye are full of ypocrisie and iniquite.", "dra": "So you also outwardly indeed appear to men just: but inwardly you are full of hypocrisy and iniquity.", "bbe": "Even so you seem to men to be full of righteousness, but inside you are all false and full of wrongdoing.", "geneva": "So are ye also: for outwarde ye appeare righteous vnto men, but within ye are full of hypocrisie and iniquitie.", "wycliffe": "So ye with outforth semen iust to men; but with ynne ye ben ful of ypocrisy and wickidnesse.", "rotherham": "Thus, ye also, outside, indeed, appear to men, righteous, but, within, are full, of hypocrisy and lawlessness.", "weymouth": "The same is true of you: outwardly you seem to the human eye to be good and honest men, but, within, you are full of insincerity and disregard of God's Law.", "darby": "Thus also ye, outwardly ye appear righteous to men, but within are full of hypocrisy and lawlessness.", "twenty": "It is the same with you. Outwardly, and to others, you have the look of religious men, but inwardly you are full of hypocrisy and sin.", "acv": "In this way also, ye indeed outwardly appear righteous to men, but inside ye are full of hypocrisy and lawlessness.", "anderson": "So also you outwardly appear to men to be just, but within you are full of hypocrisy and lawlessness.", "haweis": "And just so, ye without indeed appear to men righteous, but within ye are full of hypocrisy and iniquity.", "noyes": "Even so ye also outwardly appear righteous to men, but within ye are full of hypocrisy and iniquity.", "webster": "Thus ye also outwardly appear righteous to men, but within ye are full of hypocrisy and iniquity.", "vulgate": "sic et vos a foris quidem paretis hominibus iusti intus autem pleni estis hypocrisi et iniquitate;"}}, {"v": 29, "ref": "23:29", "o": "Οὐαὶ ὑμῖν, γραμματεῖς καὶ Φαρισαῖοι ὑποκριταί, ὅτι οἰκοδομεῖτε τοὺς τάφους τῶν προφητῶν καὶ κοσμεῖτε τὰ μνημεῖα τῶν δικαίων,", "en": {"kjv": "Woe unto you, scribes and Pharisees, hypocrites! because ye build the tombs of the prophets, and garnish the sepulchres of the righteous,", "web": "“Woe to you, scribes and Pharisees, hypocrites! For you build the tombs of the prophets, and decorate the tombs of the righteous,", "bsb": "Woe to you, scribes and Pharisees, you hypocrites! You build tombs for the prophets and decorate the monuments of the righteous.", "asv": "Woe unto you, scribes and Pharisees, hypocrites! for ye build the sepulchres of the prophets, and garnish the tombs of the righteous,", "ylt": "`Woe to you, Scribes and Pharisees, hypocrites! because ye build the sepulchres of the prophets, and adorn the tombs of the righteous,", "tyndale": "Wo be vnto you Scribes and Pharises ypocrites: ye bylde the tombes of the Prophetes and garnisshe the sepulchres of the righteous", "dra": "Woe to you, scribes and Pharisees, hypocrites, that build the sepulchres of the prophets and adorn the monuments of the just,", "bbe": "A curse is on you, scribes and Pharisees, false ones! because you put up buildings for housing the dead bodies of the prophets, and make fair the last resting-places of good men, and say,", "geneva": "Wo be vnto you, Scribes and Pharises, hypocrites: for ye build the tombes of the Prophets, and garnish the sepulchres of the righteous,", "wycliffe": "Wo to you, scribis and Farisees, ipocritis, that bilden sepulcris of profetis, and maken faire the birielis of iust men,", "rotherham": "Alas for you, Scribes and Pharisees, hypocrites; because ye build the sepulchres of the prophets, and adorn the monuments of the righteous,", "weymouth": "\"Alas for you, Scribes and Pharisees, hypocrites, for you repair the sepulchres of the Prophets and keep in order the tombs of the righteous,", "darby": "Woe to you, scribes and Pharisees, hypocrites, for ye build the sepulchres of the prophets and adorn the tombs of the just,", "twenty": "Alas for you, Teachers of the Law and Pharisees, hypocrites that you are! You build the tombs of the Prophets, and decorate the monuments of religious men,", "acv": "Woe to you, scholars and Pharisees, hypocrites! Because ye build the tombs of the prophets, and adorn the sepulchers of the righteous,", "anderson": "Alas for you, scribes and Pharisees, hypocrites! for you build the tombs of the prophets, and adorn the sepulchers of the righteous,", "haweis": "Wo unto you, scribes and Pharisees, hypocrites! for ye build the tombs of the prophets, and adorn the sepulchres of the just,", "noyes": "Woe to you, scribes and Pharisees, hypocrites! because ye build the sepulchres of the prophets, and adorn the tombs of the righteous,", "webster": "Woe to you, scribes and Pharisees, hypocrites! because ye build the tombs of the prophets, and garnish the sepulchers of the righteous,", "vulgate": "vae vobis scribae et Pharisaei hypocritae quia aedificatis sepulchra prophetarum et ornatis monumenta iustorum;"}}, {"v": 30, "ref": "23:30", "o": "καὶ λέγετε· Εἰ ⸀ἤμεθα ἐν ταῖς ἡμέραις τῶν πατέρων ἡμῶν, οὐκ ἂν ⸁ἤμεθα ⸂αὐτῶν κοινωνοὶ⸃ ἐν τῷ αἵματι τῶν προφητῶν·", "en": {"kjv": "And say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "web": "and say, ‘If we had lived in the days of our fathers, we wouldn’t have been partakers with them in the blood of the prophets.’", "bsb": "And you say, ‘If we had lived in the days of our fathers, we would not have been partners with them in shedding the blood of the prophets.’", "asv": "and say, If we had been in the days of our fathers, we should not have been partakers with them in the blood of the prophets.", "ylt": "and say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "tyndale": "and saye: Yf we had bene in the dayes of oure fathers we wolde not have bene parteners with them in the bloud of the Prophetes.", "dra": "And say: If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "bbe": "If we had been living in the days of our fathers, we would not have taken part with them in the blood of the prophets.", "geneva": "And say, If we had bene in the dayes of our fathers, we would not haue bene partners with them in the blood of the Prophets.", "wycliffe": "and seien, If we hadden be in the daies of oure fadris, we schulden not haue be her felowis in the blood of prophetis.", "rotherham": "and say—If we had been in the days of our fathers, we would not have been their partners in the blood of the prophets:", "weymouth": "and your boast is, \"`If we had lived in the time of our forefathers, we should not have been implicated with them in the murder of the Prophets.'", "darby": "and ye say, If we had been in the days of our fathers we would not have been partakers with them in the blood of the prophets.", "twenty": "and say ‘Had we been living in the days of our ancestors, we should have taken part in their murder of the Prophets!", "acv": "and say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "anderson": "and say: If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "haweis": "and say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "noyes": "and say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "webster": "And say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.", "vulgate": "et dicitis si fuissemus in diebus patrum nostrorum non essemus socii eorum in sanguine prophetarum;"}}, {"v": 31, "ref": "23:31", "o": "ὥστε μαρτυρεῖτε ἑαυτοῖς ὅτι υἱοί ἐστε τῶν φονευσάντων τοὺς προφήτας.", "en": {"kjv": "Wherefore ye be witnesses unto yourselves, that ye are the children of them which killed the prophets.", "web": "Therefore you testify to yourselves that you are children of those who killed the prophets.", "bsb": "So you testify against yourselves that you are the sons of those who murdered the prophets.", "asv": "Wherefore ye witness to yourselves, that ye are sons of them that slew the prophets.", "ylt": "So that ye testify to yourselves, that ye are sons of them who did murder the prophets;", "tyndale": "So then ye be witnesses vnto youre selfes that ye are the chyldren of them which killed the prophetes.", "dra": "Wherefore you are witnesses against yourselves, that you are the sons of them that killed the prophets.", "bbe": "So that you are witnesses against yourselves that you are the sons of those who put the prophets to death.", "geneva": "So then ye be witnesses vnto your selues, that ye are the children of them that murthered the Prophets.", "wycliffe": "And so ye ben in witnessyng to you silf, that ye ben the sones of hem that slowen the prophetis.", "rotherham": "So that ye bear witness against yourselves, that ye are, sons, of them who murdered the prophets.", "weymouth": "\"So that you bear witness against yourselves that you are descendants of those who murdered the Prophets.", "darby": "So that ye bear witness of yourselves that ye are sons of those who slew the prophets:", "twenty": "By doing this you are furnishing evidence against yourselves that you are true children of the men who murdered the Prophets.", "acv": "So then ye testify to yourselves that ye are sons of those who murdered the prophets.", "anderson": "So then you testify against yourselves, that you are the sons of those who killed the prophets.", "haweis": "Wherefore ye bear a testimony to yourselves, that ye are the children of those who killed the prophets.", "noyes": "So that ye bear witness against yourselves, that ye are the sons of those who killed the prophets.", "webster": "Wherefore ye are witnesses to yourselves, that ye are the children of them who killed the prophets.", "vulgate": "itaque testimonio estis vobismet ipsis quia filii estis eorum qui prophetas occiderunt;"}}, {"v": 32, "ref": "23:32", "o": "καὶ ὑμεῖς πληρώσατε τὸ μέτρον τῶν πατέρων ὑμῶν.", "en": {"kjv": "Fill ye up then the measure of your fathers.", "web": "Fill up, then, the measure of your fathers.", "bsb": "Fill up, then, the measure of the sin of your fathers.", "asv": "Fill ye up then the measure of your fathers.", "ylt": "and ye--ye fill up the measure of your fathers.", "tyndale": "Fulfill ye lyke wyse the measure of youre fathers.", "dra": "Fill ye up then the measure of your fathers.", "bbe": "Make full, then, the measure of your fathers.", "geneva": "Fulfill ye also ye measure of your fathers.", "wycliffe": "And fulfille ye the mesure of youre fadris.", "rotherham": "And, ye, fill ye up the measure of your fathers!", "weymouth": "Fill up the measure of your forefathers' guilt.", "darby": "and ye, fill ye up the measure of your fathers.", "twenty": "Fill up the measure of your ancestor’s guilt.", "acv": "Then fill ye up the measure of your fathers.", "anderson": "Do you also fill up the measure of your fathers.", "haweis": "Fill ye up then the measure of your fathers.", "noyes": "Fill ye up then the measure of your fathers!", "webster": "Fill ye up then the measure of your fathers.", "vulgate": "et vos implete mensuram patrum vestrorum;"}}, {"v": 33, "ref": "23:33", "o": "ὄφεις γεννήματα ἐχιδνῶν, πῶς φύγητε ἀπὸ τῆς κρίσεως τῆς γεέννης;", "en": {"kjv": "Ye serpents, ye generation of vipers, how can ye escape the damnation of hell?", "web": "You serpents, you offspring of vipers, how will you escape the judgment of Gehenna?", "bsb": "You snakes! You brood of vipers! How will you escape the sentence of hell?", "asv": "Ye serpents, ye offspring of vipers, how shall ye escape the judgment of hell?", "ylt": "`Serpents! brood of vipers! how may ye escape from the judgment of the gehenna?", "tyndale": "Yee serpentes and generacion of vipers how shuld ye scape ye dapnacio of hell?", "dra": "You serpents, generation of vipers, how will you flee from the judgment of hell?", "bbe": "You snakes, offspring of snakes, how will you be kept from the punishment of hell?", "geneva": "O serpents, the generation of vipers, howe should ye escape the damnation of hell!", "wycliffe": "Ye eddris, and eddris briddis, hou schulen ye fle fro the doom of helle?", "rotherham": "Serpents! broods of vipers! how should ye flee from the judgment of gehenna?", "weymouth": "O serpents, O vipers' brood, how are you to escape condemnation to Gehenna?", "darby": "Serpents, offspring of vipers, how should ye escape the judgment of hell?", "twenty": "You serpents and brood of vipers! How can you escape being sentenced to the Pit?", "acv": "Ye serpents, ye offspring of vipers, how will ye escape from the damnation of hell?", "anderson": "Serpents, generation of vipers, how can you escape the condemnation of hell?", "haweis": "Ye serpents, ye broods of vipers! how can ye escape from the damnation of hell?", "noyes": "Serpents, brood of vipers! how can ye escape the punishment of hell?", "webster": "[Ye] serpents, [ye] generation of vipers, how can ye escape the damnation of hell?", "vulgate": "serpentes genimina viperarum quomodo fugietis a iudicio gehennae;"}}, {"v": 34, "ref": "23:34", "o": "διὰ τοῦτο ἰδοὺ ἐγὼ ἀποστέλλω πρὸς ὑμᾶς προφήτας καὶ σοφοὺς καὶ γραμματεῖς· ⸀ἐξ αὐτῶν ἀποκτενεῖτε καὶ σταυρώσετε, καὶ ἐξ αὐτῶν μαστιγώσετε ἐν ταῖς συναγωγαῖς ὑμῶν καὶ διώξετε ἀπὸ πόλεως εἰς πόλιν·", "en": {"kjv": "Wherefore, behold, I send unto you prophets, and wise men, and scribes: and some of them ye shall kill and crucify; and some of them shall ye scourge in your synagogues, and persecute them from city to city:", "web": "Therefore behold, I send to you prophets, wise men, and scribes. Some of them you will kill and crucify; and some of them you will scourge in your synagogues, and persecute from city to city;", "bsb": "Because of this, I am sending you prophets and wise men and teachers. Some of them you will kill and crucify, and others you will flog in your synagogues and persecute in town after town.", "asv": "Therefore, behold, I send unto you prophets, and wise men, and scribes: some of them shall ye kill and crucify; and some of them shall ye scourge in your synagogues, and persecute from city to city:", "ylt": "`Because of this, lo, I send to you prophets, and wise men, and scribes, and of them ye will kill and crucify, and of them ye will scourge in your synagogues, and will pursue from city to city;", "tyndale": "Wherfore beholde I sende vnto you prophetes wyse men and scribes and of the ye shall kyll and crucifie: and of the ye shall scourge in youre synagoges and persecute from cyte to cyte", "dra": "Therefore behold I send to you prophets and wise men and scribes: and some of them you will put to death and crucify: and some you will scourge in your synagogues and persecute from city to city.", "bbe": "For this reason, I send you prophets, and wise men, and scribes: some of them you will put to death and put on the cross, and to some of them you will give blows in your Synagogues, driving them from town to town;", "geneva": "Wherefore beholde, I send vnto you Prophets, and wise men, and Scribes, and of them ye shall kill and crucifie: and of them shall ye scourge in your Synagogues, and persecute from citie to citie,", "wycliffe": "Therfor lo! Y sende to you profetis, and wise men, and scribis; and of hem ye schulen sle and crucifie, and of hem ye schulen scourge in youre sinagogis, and schulen pursue fro cite in to citee;", "rotherham": "For this cause, lo! I, send unto you, prophets and wise men and scribes,—some from among them, ye will slay and crucify, And some from among them ye will—scourge in your synagogues, and pursue from city to city:", "weymouth": "\"For this reason I am sending to you Prophets and wise men and Scribes. Some of them you will put to death--nay, crucify; some of them you will flog in your synagogues and chase from town to town;", "darby": "Therefore, behold, I send unto you prophets, and wise men, and scribes; and [some] of them ye will kill and crucify, and [some] of them ye will scourge in your synagogues, and will persecute from city to city;", "twenty": "That is why I send you Prophets, wise men, and Teachers of the Law, some of whom you will crucify and kill, and some of whom you will scourge in your Synagogues, and persecute from town to town;", "acv": "Because of this, behold, I send to you prophets, and wise men, and scholars. And some of them ye will kill and crucify, and some of them ye will scourge in your synagogues, and will persecute from city to city,", "anderson": "For this reason, behold, I send you prophets and wise men and scribes; and some of them you will kill and crucify; and some of them you will scourge in your synagogues, and persecute from city to city;", "haweis": "Therefore, behold, I am sending to you prophets, and wise men, and scribes; and some of them ye shall kill, and crucify; and some of them ye shall scourge in your synagogues, and persecute from city to city:", "noyes": "Therefore, behold, I send to you prophets, and wise men, and scribes; some of them ye will kill and crucify, and some of them ye will scourge in your synagogues, and persecute from city to city;", "webster": "Wherefore behold, I send to you prophets, and wise men, and scribes; and [some] of them ye will kill and crucify, and [some] of them ye will scourge in your synagogues, and persecute [them] from city to city:", "vulgate": "ideo ecce ego mitto ad vos prophetas et sapientes et scribas ex illis occidetis et crucifigetis et ex eis flagellabitis in synagogis vestris et persequemini de civitate in civitatem;"}}, {"v": 35, "ref": "23:35", "o": "ὅπως ἔλθῃ ἐφ’ ὑμᾶς πᾶν αἷμα δίκαιον ἐκχυννόμενον ἐπὶ τῆς γῆς ἀπὸ τοῦ αἵματος Ἅβελ τοῦ δικαίου ἕως τοῦ αἵματος Ζαχαρίου υἱοῦ Βαραχίου, ὃν ἐφονεύσατε μεταξὺ τοῦ ναοῦ καὶ τοῦ θυσιαστηρίου.", "en": {"kjv": "That upon you may come all the righteous blood shed upon the earth, from the blood of righteous Abel unto the blood of Zacharias son of Barachias, whom ye slew between the temple and the altar.", "web": "that on you may come all the righteous blood shed on the earth, from the blood of righteous Abel to the blood of Zachariah son of Barachiah, whom you killed between the sanctuary and the altar.", "bsb": "And so upon you will come all the righteous blood shed on earth, from the blood of righteous Abel to the blood of Zechariah son of Berechiah, whom you murdered between the temple and the altar.", "asv": "that upon you may come all the righteous blood shed on the earth, from the blood of Abel the righteous unto the blood of Zachariah son of Barachiah, whom ye slew between the sanctuary and the altar.", "ylt": "that on you may come all the righteous blood being poured out on the earth from the blood of Abel the righteous, unto the blood of Zacharias son of Barachias, whom ye slew between the sanctuary and the altar:", "tyndale": "that vpon you maye come all the righteous bloude that was sheed vpon the erth fro the bloud of righteous Abell vnto ye bloud of zacharias the sonne of Barachias who ye slewe betwene the teple and ye altre.", "dra": "That upon you may come all the just blood that hath been shed upon the earth, from the blood of Abel the just, even unto the blood of Zacharias the son of Barachias, whom you killed between the temple and the altar.", "bbe": "So that on you may come all the blood of the upright on the earth, from the blood of upright Abel to the blood of Zachariah, son of Barachiah, whom you put to death between the Temple and the altar.", "geneva": "That vpon you may come all the righteous blood that was shed vpon the earth, from the blood of Abel the righteous, vnto the blood of Zacharias the sonne of Barachias, whome ye slewe betweene the Temple and the altar.", "wycliffe": "that al the iust blood come on you, that was sched on the erthe, fro the blood of iust Abel to the blood of Zacarie, the sone of Barachie, whom ye slowen bitwixe the temple and the auter.", "rotherham": "That there may come upon you—all righteous blood poured out upon the earth, from the blood of Abel the righteous, unto the blood of Zachariah, son of Barachiah, whom ye murdered between the Temple and the altar.", "weymouth": "that all the innocent blood shed upon earth may come on you, from the blood of righteous Abel to the blood of Zechariah the son of Berechiah whom you murdered between the Sanctuary and the altar.", "darby": "so that all righteous blood shed upon the earth should come upon you, from the blood of righteous Abel to the blood of Zacharias son of Barachias, whom ye slew between the temple and the altar.", "twenty": "in order that upon your heads may fall every drop of innocent ‘blood split on earth,’ from the blood of innocent Abel down to that of Zechariah, Barachiah’s son, whom you murdered between the Temple and the altar.", "acv": "so that upon you may come all the righteous blood shed on the earth, from the blood of righteous Abel to the blood of Zachariah son of Barachiah, whom ye murdered between the sanctuary and the altar.", "anderson": "that upon you may come all the righteous blood which has been shed upon the earth, from the blood of Abel the just to the blood of Zachariah, the son of Barachiah, whom you slew between the temple and the altar.", "haweis": "that upon you may come all the righteous blood which hath been poured out upon the earth, from the blood of the righteous Abel, to the blood of Zachariah, son of Barachiah, whom ye slew between the temple and the altar.", "noyes": "that on you may come all the righteous blood shed upon the earth, from the blood of righteous Abel to the blood of Zechariah, son of Barachiah, whom ye slew, between the temple and the altar.", "webster": "That upon you may come all the righteous blood shed upon the earth, from the blood of righteous Abel, to the blood of Zacharias son of Barachias, whom ye slew between the temple and the altar.", "vulgate": "ut veniat super vos omnis sanguis iustus qui effusus est super terram a sanguine Abel iusti usque ad sanguinem Zacchariae filii Barachiae quem occidistis inter templum et altare;"}}, {"v": 36, "ref": "23:36", "o": "ἀμὴν λέγω ὑμῖν, ⸀ἥξει ⸂ταῦτα πάντα⸃ ἐπὶ τὴν γενεὰν ταύτην.", "en": {"kjv": "Verily I say unto you, All these things shall come upon this generation.", "web": "Most certainly I tell you, all these things will come upon this generation.", "bsb": "Truly I tell you, all these things will come upon this generation.", "asv": "Verily I say unto you, All these things shall come upon this generation.", "ylt": "verily I say to you, all these things shall come upon this generation.", "tyndale": "Verely I say vnto you all these thinges shall light vpon this generacion.", "dra": "Amen I say to you, all these things shall come upon this generation.", "bbe": "Truly I say to you, All these things will come on this generation.", "geneva": "Verely I say vnto you, all these things shall come vpon this generation.", "wycliffe": "Treuli Y seie to you, alle these thingis schulen come on this generacioun.", "rotherham": "Verily, I say unto you—All these things, will have come, upon this generation.", "weymouth": "I tell you in solemn truth that all these things will come upon the present generation.", "darby": "Verily I say unto you, All these things shall come upon this generation.", "twenty": "All this, I tell you, will come home to the present generation.", "acv": "Truly I say to you, that all these things will come upon this generation.", "anderson": "Verily I say to you, All these things shall come upon this generation.", "haweis": "Verily I say unto you, All these things shall come on this generation.", "noyes": "Truly do I say to you, All these things will come upon this generation.", "webster": "Verily I say to you, all these things shall come upon this generation.", "vulgate": "amen dico vobis venient haec omnia super generationem istam;"}}, {"v": 37, "ref": "23:37", "o": "Ἰερουσαλὴμ Ἰερουσαλήμ, ἡ ⸀ἀποκτείνουσα τοὺς προφήτας καὶ λιθοβολοῦσα τοὺς ἀπεσταλμένους πρὸς αὐτήν— ποσάκις ἠθέλησα ἐπισυναγαγεῖν τὰ τέκνα σου, ὃν τρόπον ⸂ὄρνις ἐπισυνάγει⸃ τὰ νοσσία ⸀αὐτῆς ὑπὸ τὰς πτέρυγας, καὶ οὐκ ἠθελήσατε;", "en": {"kjv": "O Jerusalem, Jerusalem, thou that killest the prophets, and stonest them which are sent unto thee, how often would I have gathered thy children together, even as a hen gathereth her chickens under her wings, and ye would not!", "web": "“Jerusalem, Jerusalem, who kills the prophets, and stones those who are sent to her! How often I would have gathered your children together, even as a hen gathers her chicks under her wings, and you would not!", "bsb": "O Jerusalem, Jerusalem, who kills the prophets and stones those sent to her, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, but you were unwilling!", "asv": "O Jerusalem, Jerusalem, that killeth the prophets, and stoneth them that are sent unto her! how often would I have gathered thy children together, even as a hen gathereth her chickens under her wings, and ye would not!", "ylt": "`Jerusalem, Jerusalem, that art killing the prophets, and stoning those sent unto thee, how often did I will to gather thy children together, as a hen doth gather her own chickens under the wings, and ye did not will.", "tyndale": "Hierusalem hierusalem which kyllest prophetes and stonest the which are sent to the: how often wolde I have gadered thy chyldren to gether as the henne gadreth her chickes vnder her winges but ye wolde not:", "dra": "Jerusalem, Jerusalem, thou that killest the prophets and stonest them that are sent unto thee, how often would I have gathered together thy children, as the hen doth gather her chickens under her wings, and thou wouldst not?", "bbe": "O Jerusalem, Jerusalem, putting to death the prophets, and stoning those who are sent to her! Again and again would I have taken your children to myself as a bird takes her young ones under her wings, and you would not!", "geneva": "Hierusalem, Hierusalem, which killest the Prophets, and stonest them which are sent to thee, how often would I haue gathered thy children together, as the henne gathereth her chickins vnder her wings, and ye would not!", "wycliffe": "Jerusalem, Jerusalem, that sleest prophetis, and stoonest hem that ben sent to thee, hou ofte wolde Y gadere togidere thi children, as an henne gaderith togidir her chikenes vndir hir wengis, and thou woldist not.", "rotherham": "Jerusalem! Jerusalem! that slayeth the prophets, and stoneth them that have been sent unto her,—how often, would I have gathered thy children, like as a hen gathereth her chickens under her wings,—and ye would not!", "weymouth": "\"O Jerusalem, Jerusalem! thou who murderest the Prophets and stonest those who have been sent to thee! how often have I desired to gather thy children to me, just as a hen gathers her chickens under her wings, and you would not come!", "darby": "Jerusalem, Jerusalem, [the city] that kills the prophets and stones those that are sent unto her, how often would I have gathered thy children as a hen gathers her chickens under her wings, and ye would not!", "twenty": "Jerusalem! Jerusalem! She who slays the Prophets and stones the messengers sent to her — Oh, how often have I wished to gather your children round me, as a hen gathers her brood under her wings, and you would not come!", "acv": "O Jerusalem, Jerusalem, who kills the prophets, and stones those who have been sent to her. How often I wanted to gathered thy children together the way a hen gathers her chicks under her wings, and ye would not.", "anderson": "Jerusalem, Jerusalem, thou that killest the prophets and stonest those who are sent to thee, how often have I desired to gather thy children together, as a bird gathers her young under her wings, and you refused.", "haweis": "O Jerusalem, Jerusalem, that killest the prophets, and stonest those who were sent unto thee, how often would I have gathered thy children to me, as a hen gathereth her chickens under her wings, and ye would not?", "noyes": "Jerusalem, Jerusalem, that killeth the prophets, and stoneth those who are sent to her! How often would I have gathered thy children together, as a hen gathereth her chickens under her wings, and ye would not!", "webster": "O Jerusalem, Jerusalem, [thou] that killest the prophets, and stonest them who are sent to thee, how often would I have gathered thy children, even as a hen gathereth her chickens under [her] wings, and ye would not!", "vulgate": "Hierusalem Hierusalem quae occidis prophetas et lapidas eos qui ad te missi sunt quotiens volui congregare filios tuos quemadmodum gallina congregat pullos suos sub alas et noluisti;"}}, {"v": 38, "ref": "23:38", "o": "ἰδοὺ ἀφίεται ὑμῖν ὁ οἶκος ὑμῶν ⸀ἔρημος.", "en": {"kjv": "Behold, your house is left unto you desolate.", "web": "Behold, your house is left to you desolate.", "bsb": "Look, your house is left to you desolate.", "asv": "Behold, your house is left unto you desolate.", "ylt": "Lo, left desolate to you is your house;", "tyndale": "Beholde youre habitacio shalbe lefte vnto you desolate.", "dra": "Behold, your house shall be left to you, desolate.", "bbe": "See, your house is made waste.", "geneva": "Beholde, your habitation shalbe left vnto you desolate,", "wycliffe": "Lo! youre hous schal be left to you desert.", "rotherham": "Lo! your house is left to you;", "weymouth": "See, your house will now be left to you desolate!", "darby": "Behold, your house is left unto you desolate;", "twenty": "Verily, your house is left to you desolate!", "acv": "Behold, your house is left to you desolate.", "anderson": "Behold, your house is left to you deserted.", "haweis": "Behold, your habitation is left unto you desolate.", "noyes": "Lo! your house is left to you desolate.", "webster": "Behold, your house is left to you desolate.", "vulgate": "ecce relinquitur vobis domus vestra deserta;"}}, {"v": 39, "ref": "23:39", "o": "λέγω γὰρ ὑμῖν, οὐ μή με ἴδητε ἀπ’ ἄρτι ἕως ἂν εἴπητε· Εὐλογημένος ὁ ἐρχόμενος ἐν ὀνόματι κυρίου.", "en": {"kjv": "For I say unto you, Ye shall not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.", "web": "For I tell you, you will not see me from now on, until you say, ‘Blessed is he who comes in the name of the Lord!’”", "bsb": "For I tell you that you will not see Me again until you say, ‘Blessed is He who comes in the name of the Lord.’”", "asv": "For I say unto you, Ye shall not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.", "ylt": "for I say to you, ye may not see me henceforth, till ye may say, Blessed is he who is coming in the name of the Lord.'", "tyndale": "For I saye to you ye shall not se me heceforthe tyll that ye saye: blessed is he that cometh in the name of ye Lorde.", "dra": "For I say to you, you shall not see me henceforth till you say: Blessed is he that cometh in the name of the Lord.", "bbe": "For I say to you, You will not see me from this time till you say, A blessing on him who comes in the name of the Lord.", "geneva": "For I say vnto you, ye shall not see mee henceforth till that ye say, Blessed is he that commeth in the Name of the Lord.", "wycliffe": "And Y seie to you, ye schulen not se me fro hennus forth, til ye seien, Blessid is he, that cometh in the name of the Lord.", "rotherham": "For I say unto you—in no wise, may ye see me, henceforth, until ye say, Blessed, is he that cometh, in the name of the Lord!", "weymouth": "For I tell you that you will never see me again until you say, `Blessed be He who comes in the name of the Lord.'\"", "darby": "for I say unto you, Ye shall in no wise see me henceforth until ye say, Blessed [be] he that comes in the name of [the] Lord.", "twenty": "For nevermore, I tell you, shall you see me, until you say — ‘Blessed is He who comes in the Name of the Lord!’”", "acv": "For I say to you, ye will, no, not see me henceforth, until ye say, Blessed is he who comes in the name of the Lord.", "anderson": "For I say to you, That you shall not see me henceforth, till you shall say, Blessed is he that comes in the name of the Lord.", "haweis": "For I tell you, Ye shall henceforth no more see me, until ye say, Blessed is he that cometh in the name of the Lord.", "noyes": "For I say to you, Ye will not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.", "webster": "For I say to you, Ye shall not see me henceforth, till ye shall say, Blessed [is] he that cometh in the name of the Lord.", "vulgate": "dico enim vobis non me videbitis amodo donec dicatis benedictus qui venit in nomine Domini;"}}]}, {"c": 24, "verses": [{"v": 1, "ref": "24:1", "o": "Καὶ ἐξελθὼν ὁ Ἰησοῦς ⸂ἀπὸ τοῦ ἱεροῦ ἐπορεύετο⸃, καὶ προσῆλθον οἱ μαθηταὶ αὐτοῦ ἐπιδεῖξαι αὐτῷ τὰς οἰκοδομὰς τοῦ ἱεροῦ·", "en": {"kjv": "And Jesus went out, and departed from the temple: and his disciples came to him for to shew him the buildings of the temple.", "web": "Jesus went out from the temple, and was going on his way. His disciples came to him to show him the buildings of the temple.", "bsb": "As Jesus left the temple and was walking away, His disciples came up to Him to point out its buildings.", "asv": "And Jesus went out from the temple, and was going on his way; and his disciples came to him to show him the buildings of the temple.", "ylt": "And having gone forth, Jesus departed from the temple, and his disciples came near to show him the buildings of the temple,", "tyndale": "And Iesus went out and departed fro the teple: and his disciples came to hym for to shewe him the byldinge of the teple.", "dra": "And Jesus being come out of the temple, went away. And his disciples came to shew him the buildings of the temple.", "bbe": "And Jesus went out of the Temple, and on the way his disciples came to him, pointing out the buildings of the Temple.", "geneva": "And Iesus went out, and departed from the Temple, and his disciples came to him, to shewe him the building of the Temple.", "wycliffe": "And Jhesus wente out of the temple; and his disciplis camen to hym, to schewe hym the bildyngis of the temple.", "rotherham": "And, Jesus coming forth, from the temple, was taking his departure, when his disciples came forward to point out to him the buildings of the temple.", "weymouth": "Jesus had left the Temple and was going on His way, when His disciples came and called His attention to the Temple buildings.", "darby": "And Jesus went forth and went away from the temple, and his disciples came to [him] to point out to him the buildings of the temple.", "twenty": "Leaving the Temple Courts, Jesus was walking away, when his disciples came up to draw his attention to the Temple buildings.", "acv": "And when Jesus departed he was going from the temple. And his disciples came near to exhibit to him the buildings of the temple.", "anderson": "And Jesus went out, and was departing from the temple, and his disciples came to him to point out to him the buildings of the temple.", "haweis": "AND Jesus departing was going his way from the temple: and his disciples came to him, to point out to his observation the buildings of the temple.", "noyes": "And Jesus went out, and was going from the temple; and his disciples came to him, to show him the buildings of the temple.", "webster": "And Jesus went out, and departed from the temple: and his disciples came to [him] to show him the buildings of the temple.", "vulgate": "et egressus Iesus de templo ibat et accesserunt discipuli eius ut ostenderent ei aedificationes templi;"}}, {"v": 2, "ref": "24:2", "o": "ὁ δὲ ⸀ἀποκριθεὶς εἶπεν αὐτοῖς· Οὐ βλέπετε ⸂ταῦτα πάντα⸃; ἀμὴν λέγω ὑμῖν, οὐ μὴ ἀφεθῇ ὧδε λίθος ἐπὶ λίθον ὃς οὐ καταλυθήσεται.", "en": {"kjv": "And Jesus said unto them, See ye not all these things? verily I say unto you, There shall not be left here one stone upon another, that shall not be thrown down.", "web": "But he answered them, “You see all of these things, don’t you? Most certainly I tell you, there will not be left here one stone on another, that will not be thrown down.”", "bsb": "“Do you see all these things?” He replied. “Truly I tell you, not one stone here will be left on another; every one will be thrown down.”", "asv": "But he answered and said unto them, See ye not all these things? verily I say unto you, There shall not be left here one stone upon another, that shall not be thrown down.", "ylt": "and Jesus said to them, `Do ye not see all these? verily I say to you, There may not be left here a stone upon a stone, that shall not be thrown down.'", "tyndale": "Iesus sayde vnto the: se ye not all these thinges? Verely I saye vnto you: ther shall not be here lefte one stone vpon another that shall not be cast doune.", "dra": "And he answering, said to them: Do you see all these things? Amen I say to you, there shall not be left here a stone upon a stone that shall not be destroyed.", "bbe": "But he, answering, said to them, See you not all these things? truly I say to you that here there will not be one stone resting on another, which will not be pulled down.", "geneva": "And Iesus sayd vnto them, See ye not all these things? Verely I say vnto you, there shall not be here left a stone vpon a stone, that shall not be cast downe.", "wycliffe": "But he answeride, and seide to hem, Seen ye alle these thingis? Treuli Y seie to you, a stoon schal not be left here on a stoon, that ne it schal be destried.", "rotherham": "But, he, answering, said unto them—Are ye not beholding all these things? Verily, I say unto you—in no wise, shall there be left here, stone upon stone, which shall not be thrown down.", "weymouth": "\"You see all these?\" He replied; \"in solemn truth I tell you that there will not be left here one stone upon another that will not be pulled down.\"", "darby": "And he answering said to them, Do ye not see all these things? Verily I say to you, Not a stone shall be left here upon a stone which shall not be thrown down.", "twenty": "“Do you see all these things?” was his answer. “I tell you, not a single stone will be left here upon another, which will not be thrown down,”", "acv": "But Jesus said to them, Do ye not see all these things? Truly I say to you, there will be left here, no, not a stone upon a stone, that will not be thrown down.", "anderson": "But Jesus said to them: Do you not see all these things? Verily I say to you, There shall not be left here a stone upon a stone that shall not be thrown down,", "haweis": "But Jesus said unto them, Do you not see all these things? I tell you of a certainty, There shall not be left here one stone upon another, which shall not be utterly thrown down.", "noyes": "And he answering said to them, See ye not all these? Truly do I say to you, There will not be left here one stone upon another, that will not be thrown down.", "webster": "And Jesus said to them, See ye not all these things? verily I say to you, There shall not be left here one stone upon another, that shall not be thrown down.", "vulgate": "ipse autem respondens dixit eis videtis haec omnia amen dico vobis non relinquetur hic lapis super lapidem qui non destruatur;"}}, {"v": 3, "ref": "24:3", "o": "Καθημένου δὲ αὐτοῦ ἐπὶ τοῦ Ὄρους τῶν Ἐλαιῶν προσῆλθον αὐτῷ οἱ μαθηταὶ κατ’ ἰδίαν λέγοντες· Εἰπὸν ἡμῖν πότε ταῦτα ἔσται, καὶ τί τὸ σημεῖον τῆς σῆς παρουσίας ⸀καὶ συντελείας τοῦ αἰῶνος.", "en": {"kjv": "And as he sat upon the mount of Olives, the disciples came unto him privately, saying, Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the world?", "web": "As he sat on the Mount of Olives, the disciples came to him privately, saying, “Tell us, when will these things be? What is the sign of your coming, and of the end of the age?”", "bsb": "While Jesus was sitting on the Mount of Olives, the disciples came to Him privately. “Tell us,” they said, “when will these things happen, and what will be the sign of Your coming and of the end of the age?”", "asv": "And as he sat on the mount of Olives, the disciples came unto him privately, saying, Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the world?", "ylt": "And when he is sitting on the mount of the Olives, the disciples came near to him by himself, saying, `Tell us, when shall these be? and what is the sign of thy presence, and of the full end of the age?'", "tyndale": "And as he sat vpon the mout Olivete his disciples came vnto hym secretely sayinge. Tell vs when these thinges shalbe? And what signe shalbe of thy comynge and of the ende of the worlde?", "dra": "And when he was sitting on mount Olivet, the disciples came to him privately, saying: Tell us when shall these things be? And what shall be the sign of thy coming and of the consummation of the world?", "bbe": "And while he was seated on the Mountain of Olives, the disciples came to him privately, saying, Make clear to us, when will these things be? and what will be the sign of your coming and of the end of the world?", "geneva": "And as he sate vpon the mount of Oliues, his disciples came vnto him apart, saying, Tell vs when these things shall be, and what signe shalbe of thy comming, and of the ende of the world.", "wycliffe": "And whanne he satte on the hille of Olyuete, hise disciplis camen to hym priueli, and seiden, Seie vs, whanne these thingis schulen be, and what token of thi comyng, and of the ending of the world.", "rotherham": "And, as he was sitting upon the Mount of Olives, the disciples came unto him, privately, saying—Tell us, when these things shall be,—and what the sign of thy presence, and the conclusion of the age.", "weymouth": "Afterwards He was on the Mount of Olives and was seated there when the disciples came to Him, apart from the others, and said, \"Tell us when this will be; and what will be the sign of your Coming and of the Close of the Age?\"", "darby": "And as he was sitting upon the mount of Olives the disciples came to him privately, saying, Tell us, when shall these things be, and what is the sign of thy coming and [the] completion of the age?", "twenty": "so, while Jesus was sitting on the Mount of Olives, his disciples came up to him privately and said: “Tell us when this will be, and what will be the sign of your Coming, and of the close of the age.”", "acv": "And as he sat on the mount of Olives, the disciples came to him privately, saying, Tell us, when will these things be? And what is the sign of thy coming, and of the termination of the age?", "anderson": "And as he was sitting upon the mount of Olives, the disciples came to him privately, and said: Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the age?", "haweis": "Then as he was sitting upon the mount of Olives, his disciples came to him privately, saying, Tell us, when shall there things be? and what is the sign of thy coming, and of the consummation of the age?", "noyes": "And as he was sitting upon the Mount of Olives, the disciples came to him privately, saying, Tell us, when will these things be? and what will be the signs of thy coming, and of the end of the world?", "webster": "And as he sat upon the mount of Olives, the disciples came to him privately, saying, Tell us, when will these things be? and what [will be] the sign of thy coming, and of the end of the world?", "vulgate": "sedente autem eo super montem Oliveti accesserunt ad eum discipuli secreto dicentes dic nobis quando haec erunt et quod signum adventus tui et consummationis saeculi;"}}, {"v": 4, "ref": "24:4", "o": "καὶ ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν αὐτοῖς· Βλέπετε μή τις ὑμᾶς πλανήσῃ·", "en": {"kjv": "And Jesus answered and said unto them, Take heed that no man deceive you.", "web": "Jesus answered them, “Be careful that no one leads you astray.", "bsb": "Jesus answered, “See to it that no one deceives you.", "asv": "And Jesus answered and said unto them, Take heed that no man lead you astray.", "ylt": "And Jesus answering said to them, `Take heed that no one may lead you astray,", "tyndale": "And Iesus answered and sayde vnto them: take hede that no ma deceave you.", "dra": "And Jesus answering, said to them: Take heed that no man seduce you.", "bbe": "And Jesus said to them in answer, Take care that you are not tricked.", "geneva": "And Iesus answered, and sayd vnto them, Take heede that no man deceiue you.", "wycliffe": "And Jhesus answeride, and seide to hem, Loke ye, that no man disseyue you.", "rotherham": "And, answering, Jesus said unto them—Be taking heed, lest anyone, deceive, you;", "weymouth": "\"Take care that no one misleads you,\" answered Jesus;", "darby": "And Jesus answering said to them, See that no one mislead you.", "twenty": "Jesus replied to them as follows: “See that no one leads you astray;", "acv": "And having answered, Jesus said to them, See that not any man may lead you astray.", "anderson": "And Jesus answered and said to them: Take heed that no one deceive you.", "haweis": "And Jesus answering said unto them, Beware that no man deceive you.", "noyes": "And Jesus answering said to them, See that no one deceive you.", "webster": "And Jesus answered and said to them, Take heed that no man deceive you.", "vulgate": "et respondens Iesus dixit eis videte ne quis vos seducat;"}}, {"v": 5, "ref": "24:5", "o": "πολλοὶ γὰρ ἐλεύσονται ἐπὶ τῷ ὀνόματί μου λέγοντες· Ἐγώ εἰμι ὁ χριστός, καὶ πολλοὺς πλανήσουσιν.", "en": {"kjv": "For many shall come in my name, saying, I am Christ; and shall deceive many.", "web": "For many will come in my name, saying, ‘I am the Christ,’ and will lead many astray.", "bsb": "For many will come in My name, claiming, ‘I am the Christ,’ and will deceive many.", "asv": "For many shall come in my name, saying, I am the Christ; and shall lead many astray.", "ylt": "for many shall come in my name, saying, I am the Christ, and they shall lead many astray,", "tyndale": "For many shall come in my name sayinge: I am Christ and shall deceave many.", "dra": "For many will come in my name saying, I am Christ. And they will seduce many.", "bbe": "For people will come in my name, saying, I am the Christ; and a number will be turned from the true way through them.", "geneva": "For many shall come in my name, saying, I am Christ, and shall deceiue many.", "wycliffe": "For many schulen come in my name, and schulen seie, Y am Crist; and thei schulen disseyue manye.", "rotherham": "For, many, will come upon my name, saying—I, am the Christ,—and will, deceive many.", "weymouth": "\"for many will come assuming my name and saying `I am the Christ;' and they will mislead many.", "darby": "For many shall come in my name, saying, I am the Christ, and they shall mislead many.", "twenty": "for, many will take my name, and come saying ‘I am the Christ,’ and will lead many astray.", "acv": "For many will come in my name, saying, I am the Christ, and will lead many astray.", "anderson": "For many will come in my name, saying, I am the Christ; and will deceive many.", "haweis": "For many will come in my name, saying, I am the Messiah; and shall deceive multitudes.", "noyes": "For many will come in my name, saying, I am the Christ, and will deceive many.", "webster": "For many will come in my name, saying, I am Christ; and will deceive many.", "vulgate": "multi enim venient in nomine meo dicentes ego sum Christus et multos seducent;"}}, {"v": 6, "ref": "24:6", "o": "μελλήσετε δὲ ἀκούειν πολέμους καὶ ἀκοὰς πολέμων· ὁρᾶτε, μὴ θροεῖσθε· δεῖ ⸀γὰρ γενέσθαι, ἀλλ’ οὔπω ἐστὶν τὸ τέλος.", "en": {"kjv": "And ye shall hear of wars and rumours of wars: see that ye be not troubled: for all these things must come to pass, but the end is not yet.", "web": "You will hear of wars and rumors of wars. See that you aren’t troubled, for all this must happen, but the end is not yet.", "bsb": "You will hear of wars and rumors of wars, but see to it that you are not alarmed. These things must happen, but the end is still to come.", "asv": "And ye shall hear of wars and rumors of wars; see that ye be not troubled: for these things must needs come to pass; but the end is not yet.", "ylt": "and ye shall begin to hear of wars, and reports of wars; see, be not troubled, for it behoveth all these to come to pass, but the end is not yet.", "tyndale": "Ye shall heare of warres and of the fame of warres: but se yt ye be not troubled. For all these thinges must come to passe but the ende is not yet.", "dra": "And you shall hear of wars and rumours of wars. See that ye be not troubled. For these things must come to pass: but the end is not yet.", "bbe": "And news will come to you of wars and talk of wars: do not be troubled, for these things have to be; but it is still not the end.", "geneva": "And ye shall heare of warres, and rumours of warres: see that ye be not troubled: for all these things must come to passe, but the end is not yet.", "wycliffe": "For ye schulen here batels, and opyniouns of batels; se ye that ye be not disturblid; for it byhoueth these thingis to be don, but not yit is the ende.", "rotherham": "Moreover ye will be sure to be hearing of wars, and rumours of wars: Mind! be not alarmed, for it must needs happen,—but, not yet, is, the end;", "weymouth": "And before long you will hear of wars and rumours of wars. Do not be alarmed, for such things must be; but the End is not yet.", "darby": "But ye will hear of wars and rumours of wars. See that ye be not disturbed; for all [these things] must take place, but it is not yet the end.", "twenty": "And you will hear of wars and rumours of wars; take care not to be alarmed, for such things must occur; but the end is not yet here.", "acv": "And ye are going to hear of wars and rumors of wars. See that ye not be alarmed, for all the things must happen, but the end is not yet.", "anderson": "And you will hear of wars and rumors of wars: see that you be not troubled, for all things must be fulfilled; but the end is not yet.", "haweis": "And ye shall hear of wars, and rumours of wars: see that ye be not terrified: for these things must first be, but the end is not yet.", "noyes": "And ye are to hear of wars, and rumors of wars; see that ye be not troubled; for these things must come to pass; but not yet is the end.", "webster": "And ye will hear of wars, and rumors of wars: see that ye be not troubled: for all [these things] must come to pass, but the end is not yet.", "vulgate": "audituri autem estis proelia et opiniones proeliorum videte ne turbemini oportet enim haec fieri sed nondum est finis;"}}, {"v": 7, "ref": "24:7", "o": "ἐγερθήσεται γὰρ ἔθνος ἐπὶ ἔθνος καὶ βασιλεία ἐπὶ βασιλείαν, καὶ ἔσονται ⸀λιμοὶ καὶ σεισμοὶ κατὰ τόπους·", "en": {"kjv": "For nation shall rise against nation, and kingdom against kingdom: and there shall be famines, and pestilences, and earthquakes, in divers places.", "web": "For nation will rise against nation, and kingdom against kingdom; and there will be famines, plagues, and earthquakes in various places.", "bsb": "Nation will rise against nation, and kingdom against kingdom. There will be famines and earthquakes in various places.", "asv": "For nation shall rise against nation, and kingdom against kingdom; and there shall be famines and earthquakes in divers places.", "ylt": "`For nation shall rise against nation, and kingdom against kingdom, and there shall be famines, and pestilences, and earthquakes, in divers places;", "tyndale": "For nacio shall ryse ageynste nacio and realme ageynste realme: and ther shalbe pestilence honger and erthquakes in all quarters.", "dra": "For nation shall rise against nation, and kingdom against kingdom: And there shall be pestilences and famines and earthquakes in places.", "bbe": "For nation will be moved against nation, and kingdom against kingdom, and men will be without food, and the earth will be shaking in different places;", "geneva": "For nation shall rise against nation, and realme against realme, and there shalbe famine, and pestilence, and earthquakes in diuers places.", "wycliffe": "Folk schal rise togidere ayens folc, and rewme ayens rewme, and pestilences, and hungris, and the erthemouyngis schulen be bi placis;", "rotherham": "For there will arise—nation against nation, and kingdom against kingdom,—and there will be famines and earthquakes, in places.", "weymouth": "For nation will rise in arms against nation, kingdom against kingdom, and there will be famines and earthquakes in various places;", "darby": "For nation shall rise up against nation, and kingdom against kingdom; and there shall be famines and pestilences, and earthquakes in divers places.", "twenty": "For ‘nation will rise against nation and kingdom against kingdom,’ and there will be famines and earthquakes in various places.", "acv": "For nation will rise against nation, and kingdom against kingdom, and there will be famines and plagues and earthquakes in places.", "anderson": "For nation will rise against nation, and kingdom against kingdom; and there will be famines and pestilences and earthquakes in various places.", "haweis": "For nation shall be roused up against nation, and kingdom against kingdom: and there shall be famines, and pestilences, and earthquakes, in diverse places.", "noyes": "For nation will rise against nation, and kingdom against kingdom; and there will be famines and earthquakes in divers places.", "webster": "For nation will rise against nation, and kingdom against kingdom: and there will be famines, and pestilences, and earthquakes in divers places.", "vulgate": "consurget enim gens in gentem et regnum in regnum et erunt pestilentiae et fames et terraemotus per loca;"}}, {"v": 8, "ref": "24:8", "o": "πάντα δὲ ταῦτα ἀρχὴ ὠδίνων.", "en": {"kjv": "All these are the beginning of sorrows.", "web": "But all these things are the beginning of birth pains.", "bsb": "All these are the beginning of birth pains.", "asv": "But all these things are the beginning of travail.", "ylt": "and all these are the beginning of sorrows;", "tyndale": "All these are the beginninge of sorowes.", "dra": "Now all these are the beginnings of sorrows.", "bbe": "But all these things are the first of the troubles.", "geneva": "All these are but ye beginning of sorowes.", "wycliffe": "and alle these ben bigynnyngis of sorewes.", "rotherham": "But, all these things, are a beginning of birth-pangs.", "weymouth": "but all these miseries are but like the early pains of childbirth.", "darby": "But all these [are the] beginning of throes.", "twenty": "All this, however, will be but the beginning of the birth pangs!", "acv": "But all these things are the beginning of travail.", "anderson": "But all these are the beginning of sorrows.", "haweis": "Now all these things are the beginning of the travailing pangs.", "noyes": "But all these things are the beginning of travail-pains.", "webster": "All these [are] the beginning of sorrows.", "vulgate": "haec autem omnia initia sunt dolorum;"}}, {"v": 9, "ref": "24:9", "o": "Τότε παραδώσουσιν ὑμᾶς εἰς θλῖψιν καὶ ἀποκτενοῦσιν ὑμᾶς, καὶ ἔσεσθε μισούμενοι ὑπὸ πάντων τῶν ἐθνῶν διὰ τὸ ὄνομά μου.", "en": {"kjv": "Then shall they deliver you up to be afflicted, and shall kill you: and ye shall be hated of all nations for my name’s sake.", "web": "Then they will deliver you up to oppression, and will kill you. You will be hated by all of the nations for my name’s sake.", "bsb": "Then they will deliver you over to be persecuted and killed, and you will be hated by all nations because of My name.", "asv": "Then shall they deliver you up unto tribulation, and shall kill you: and ye shall be hated of all the nations for my name’s sake.", "ylt": "then they shall deliver you up to tribulation, and shall kill you, and ye shall be hated by all the nations because of my name;", "tyndale": "Then shall they put you to trouble and shall kyll you: and ye shalbe hated of all nacions for my names sake.", "dra": "Then shall they deliver you up to be afflicted and shall put you to death: and you shall be hated by all nations for my name's sake.", "bbe": "Then they will be cruel to you, and will put you to death: and you will be hated by all nations because of my name.", "geneva": "Then shall they deliuer you vp to be afflicted, and shall kill you, and ye shall be hated of all nations for my Names sake.", "wycliffe": "Thanne men schulen bitake you in to tribulacion, and schulen sle you, and ye schulen be in hate to alle folk for my name.", "rotherham": "Then, will they deliver you up into tribulation, and will slay you,—and ye will be men hated by all the nations, because of my name", "weymouth": "\"At that time they will deliver you up to punishment and will put you to death; and you will be objects of hatred to all the nations because you are called by my name.", "darby": "Then shall they deliver you up to tribulation, and shall kill you; and ye will be hated of all the nations for my name's sake.", "twenty": "When that time comes, they will give you up to persecution, and will put you to death, and you will be hated by all nations on account of my Name.", "acv": "Then they will deliver you up for tribulation, and will kill you, and ye will be hated by all the nations because of my name.", "anderson": "Then they will deliver you up to affliction, and kill you; and you will be hated by all nations on my account.", "haweis": "Then shall they deliver you up to affliction, and shall kill you: and ye shall be hated of all nations for my name’s sake.", "noyes": "Then will they deliver you up to distress, and will kill you; and ye will be hated by all nations on account of my name.", "webster": "Then will they deliver you up to be afflicted, and will kill you: and ye will be hated by all nations for my name's sake.", "vulgate": "tunc tradent vos in tribulationem et occident vos et eritis odio omnibus gentibus propter nomen meum;"}}, {"v": 10, "ref": "24:10", "o": "καὶ τότε σκανδαλισθήσονται πολλοὶ καὶ ἀλλήλους παραδώσουσιν καὶ μισήσουσιν ἀλλήλους·", "en": {"kjv": "And then shall many be offended, and shall betray one another, and shall hate one another.", "web": "Then many will stumble, and will deliver up one another, and will hate one another.", "bsb": "At that time many will fall away and will betray and hate one another,", "asv": "And then shall many stumble, and shall deliver up one another, and shall hate one another.", "ylt": "and then shall many be stumbled, and they shall deliver up one another, and shall hate one another.", "tyndale": "And then shall many be offended and shall betraye one another and shall hate one the other.", "dra": "And then shall many be scandalized and shall betray one another and shall hate one another.", "bbe": "And numbers of people will be turned from the right way, and will give one another up and have hate for one another.", "geneva": "And then shall many be offended, and shall betray one another, and shall hate one another.", "wycliffe": "And thanne many schulen be sclaundrid, and bitraye ech other, and thei schulen hate ech other.", "rotherham": "And, then, will many be caused to stumble, and, one another, will deliver up, and will hate one another;", "weymouth": "Then will many stumble and fall, and they will betray one another and hate one another.", "darby": "And then will many be offended, and will deliver one another up, and hate one another;", "twenty": "And then many will fall away, and will betray one another, and hate one another.", "acv": "And then many will be caused to stumble, and they will betray each other and will hate each other.", "anderson": "And then will many be ensnared, and they will deliver one another up, and hate one another;", "haweis": "And then shall many be offended, and shall betray one another, and hate one another.", "noyes": "And then will many fall away; and will deliver up one another, and will hate one another.", "webster": "And then will many be offended, and will betray one another, and will hate one another.", "vulgate": "et tunc scandalizabuntur multi et invicem tradent et odio habebunt invicem;"}}, {"v": 11, "ref": "24:11", "o": "καὶ πολλοὶ ψευδοπροφῆται ἐγερθήσονται καὶ πλανήσουσιν πολλούς·", "en": {"kjv": "And many false prophets shall rise, and shall deceive many.", "web": "Many false prophets will arise, and will lead many astray.", "bsb": "and many false prophets will arise and mislead many.", "asv": "And many false prophets shall arise, and shall lead many astray.", "ylt": "`And many false prophets shall arise, and shall lead many astray;", "tyndale": "And many falce Prophetes shall aryse and shall deceave many.", "dra": "And many false prophets shall rise and shall seduce many.", "bbe": "And a number of false prophets will come, causing error.", "geneva": "And many false prophets shall arise, and shall deceiue many.", "wycliffe": "And many false prophetis schulen rise, and disseyue manye.", "rotherham": "And, many false prophets, will arise, and deceive, many;", "weymouth": "Many false prophets will rise up and lead multitudes astray;", "darby": "and many false prophets shall arise and shall mislead many;", "twenty": "Many false Prophets, also, will appear and lead many astray;", "acv": "And many false prophets will arise, and will lead many astray.", "anderson": "and many false prophets will arise, and deceive many;", "haweis": "And many false prophets shall arise, and shall deceive many.", "noyes": "And many false prophets will arise, and will deceive many.", "webster": "And many false prophets will rise, and will deceive many.", "vulgate": "et multi pseudoprophetae surgent et seducent multos;"}}, {"v": 12, "ref": "24:12", "o": "καὶ διὰ τὸ πληθυνθῆναι τὴν ἀνομίαν ψυγήσεται ἡ ἀγάπη τῶν πολλῶν.", "en": {"kjv": "And because iniquity shall abound, the love of many shall wax cold.", "web": "Because iniquity will be multiplied, the love of many will grow cold.", "bsb": "Because of the multiplication of wickedness, the love of most will grow cold.", "asv": "And because iniquity shall be multiplied, the love of the many shall wax cold.", "ylt": "and because of the abounding of the lawlessness, the love of the many shall become cold;", "tyndale": "And because iniquite shall have the vpper hande the love of many shall abate.", "dra": "And because iniquity hath abounded, the charity of many shall grow cold.", "bbe": "And because wrongdoing will be increased, the love of most people will become cold.", "geneva": "And because iniquitie shalbe increased, the loue of many shalbe colde.", "wycliffe": "And for wickidnesse schal `be plenteuouse, the charite of manye schal wexe coold;", "rotherham": "And, because of lawlessness being brought to the full, the love of the many, will grew cold.", "weymouth": "and because of the prevalent disregard of God's law the love of the great majority will grow cold;", "darby": "and because lawlessness shall prevail, the love of the most shall grow cold;", "twenty": "and, owing to the increase of wickedness, the love of most will grow cold.", "acv": "And because of the increased lawlessness, the love of the many will become cold.", "anderson": "and because iniquity abounds, the love of many will grow cold.", "haweis": "And because iniquity shall abound, the love of many will grow cool.", "noyes": "And because iniquity shall abound, the love of the many will wax cold.", "webster": "And because iniquity will abound, the love of many will become cold.", "vulgate": "et quoniam abundabit iniquitas refrigescet caritas multorum;"}}, {"v": 13, "ref": "24:13", "o": "ὁ δὲ ὑπομείνας εἰς τέλος οὗτος σωθήσεται.", "en": {"kjv": "But he that shall endure unto the end, the same shall be saved.", "web": "But he who endures to the end, the same will be saved.", "bsb": "But the one who perseveres to the end will be saved.", "asv": "But he that endureth to the end, the same shall be saved.", "ylt": "but he who did endure to the end, he shall be saved;", "tyndale": "But he that endureth to the ende the same shalbe safe.", "dra": "But he that shall persevere to the end, he shall be saved.", "bbe": "But he who goes through to the end will get salvation.", "geneva": "But he that endureth to the ende, he shalbe saued.", "wycliffe": "but he that schal dwelle stable in to the ende, schal be saaf.", "rotherham": "But, he that hath endured throughout, the same, shall be saved.", "weymouth": "but those who stand firm to the End shall be saved.", "darby": "but he that has endured to the end, he shall be saved.", "twenty": "Yet the man that endures to the end shall be saved.", "acv": "But he who endures to the end, this man will be saved.", "anderson": "But he that endures to the end, shall be saved.", "haweis": "But he that endureth to the end, that man will be saved.", "noyes": "But he that endureth to the end will be saved.", "webster": "But he that shall endure to the end, the same shall be saved.", "vulgate": "qui autem permanserit usque in finem hic salvus erit;"}}, {"v": 14, "ref": "24:14", "o": "καὶ κηρυχθήσεται τοῦτο τὸ εὐαγγέλιον τῆς βασιλείας ἐν ὅλῃ τῇ οἰκουμένῃ εἰς μαρτύριον πᾶσιν τοῖς ἔθνεσιν, καὶ τότε ἥξει τὸ τέλος.", "en": {"kjv": "And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come.", "web": "This Good News of the Kingdom will be preached in the whole world for a testimony to all the nations, and then the end will come.", "bsb": "And this gospel of the kingdom will be preached in all the world as a testimony to all nations, and then the end will come.", "asv": "And this gospel of the kingdom shall be preached in the whole world for a testimony unto all the nations; and then shall the end come.", "ylt": "and this good news of the reign shall be proclaimed in all the world, for a testimony to all the nations; and then shall the end arrive.", "tyndale": "And this gladtidingees of the kyngdome shalbe preached in all the worlde for a witnes vnto all nacions: and then shall the ende come.", "dra": "And this gospel of the kingdom shall be preached in the whole world, for a testimony to all nations: and then shall the consummation come.", "bbe": "And this good news of the kingdom will be given through all the world for a witness to all nations; and then the end will come.", "geneva": "And this Gospel of the kingdome shalbe preached through the whole world for a witnes vnto all nations, and then shall the end come.", "wycliffe": "And this gospel of the kyngdom schal be prechid in al the world, in witnessyng to al folc;", "rotherham": "And this glad message of the kingdom will be proclaimed in all the inhabited earth, for a witness unto all the nations,—and, then, will have come, the end.", "weymouth": "And this Good News of the Kingdom shall be proclaimed throughout the whole world to set the evidence before all the Gentiles; and then the End will come.", "darby": "And these glad tidings of the kingdom shall be preached in the whole habitable earth, for a witness to all the nations, and then shall come the end.", "twenty": "And this Good News of the Kingdom shall be proclaimed throughout the world as a witness to all nations; and then will come the end.", "acv": "And this good news of the kingdom will be proclaimed in the whole world for a testimony to all the nations, and then the end will come.", "anderson": "And this gospel of the kingdom shall be preached in the whole habitable earth, for a testimony to all nations, and then shall the end come.", "haweis": "And this gospel of the kingdom shall be preached through the whole world for a testimony to all the nations: and then shall come the final close.", "noyes": "And these glad tidings of the kingdom will be published throughout the whole world for a testimony to all the nations; and then will come the end.", "webster": "And this gospel of the kingdom shall be preached in all the world, for a testimony to all nations; and then shall the end come.", "vulgate": "et praedicabitur hoc evangelium regni in universo orbe in testimonium omnibus gentibus et tunc veniet consummatio;"}}, {"v": 15, "ref": "24:15", "o": "Ὅταν οὖν ἴδητε τὸ βδέλυγμα τῆς ἐρημώσεως τὸ ῥηθὲν διὰ Δανιὴλ τοῦ προφήτου ⸀ἑστὸς ἐν τόπῳ ἁγίῳ, ὁ ἀναγινώσκων νοείτω,", "en": {"kjv": "When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place, (whoso readeth, let him understand:)", "web": "“When, therefore, you see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let the reader understand),", "bsb": "So when you see standing in the holy place ‘the abomination of desolation,’ described by the prophet Daniel (let the reader understand),", "asv": "When therefore ye see the abomination of desolation, which was spoken of through Daniel the prophet, standing in the holy place (let him that readeth understand),", "ylt": "`Whenever, therefore, ye may see the abomination of the desolation, that was spoken of through Daniel the prophet, standing in the holy place (whoever is reading let him observe)", "tyndale": "When ye therfore shall se ye abhominacio that betokeneth desolacion spoken of by Daniell the Prophet stonde in ye holy place: let him that redeth it vnderstonde it.", "dra": "When therefore you shall see the abomination of desolation, which was spoken of by Daniel the prophet, standing in the holy place: he that readeth let him understand.", "bbe": "When, then, you see in the holy place the unclean thing which makes destruction, of which word was given by Daniel the prophet (let this be clear to the reader),", "geneva": "When ye therefore shall see the abomination of desolation spoken of by Daniel the Prophet, set in the holy place (let him that readeth consider it.)", "wycliffe": "and thanne the ende schal come. Therfor whanne ye se the abhomynacioun of discomfort, that is seid of Danyel, the prophete, stondynge in the hooli place; he that redith, vndirstonde he;", "rotherham": "Whensoever, therefore, ye shall see the abomination desolation, that was spoken of through Daniel the prophet, standing in a holy place,—he that readeth, let him think,", "weymouth": "\"When you have seen (to use the language of the Prophet Daniel) the `Abomination of Desolation', standing in the Holy Place\" --let the reader observe those words--", "darby": "When therefore ye shall see the abomination of desolation, which is spoken of through Daniel the prophet, standing in [what is a] holy place, (he that reads let him understand,)", "twenty": "As soon, then, as you see ‘the Foul Desecration,’ mentioned by the Prophet Daniel, standing in the Holy Place,” (the reader must consider what this means)", "acv": "When therefore ye see the abomination of desolation that was spoken of through Daniel the prophet, standing in the holy place (let him who reads understand),", "anderson": "When, therefore, you see that detestable thing that makes desolate, spoken of by Daniel the prophet, standing in the holy place, (let him that reads understand;)", "haweis": "When therefore ye see the abomination of desolation, spoken of by the prophet Daniel, erected in the holy place, (let him that readeth, mark this,)", "noyes": "When, therefore, ye see the abomination of desolation, spoken of through Daniel the prophet, standing in the holy place, (let him that readeth understand,)", "webster": "When therefore ye shall see the abomination of desolation spoken of by Daniel the prophet, stand in the holy place, (whoever readeth, let him understand,)", "vulgate": "cum ergo videritis abominationem desolationis quae dicta est a Danihelo propheta stantem in loco sancto qui legit intellegat;"}}, {"v": 16, "ref": "24:16", "o": "τότε οἱ ἐν τῇ Ἰουδαίᾳ φευγέτωσαν ⸀ἐπὶ τὰ ὄρη,", "en": {"kjv": "Then let them which be in Judea flee into the mountains:", "web": "then let those who are in Judea flee to the mountains.", "bsb": "then let those who are in Judea flee to the mountains.", "asv": "then let them that are in Judæa flee unto the mountains:", "ylt": "then those in Judea--let them flee to the mounts;", "tyndale": "Then let them which be in Iury flye into the moutaynes.", "dra": "Then they that are in Judea, let them flee to the mountains:", "bbe": "Then let those who are in Judaea go in flight to the mountains:", "geneva": "Then let them which be in Iudea, flee into the mountaines.", "wycliffe": "thanne thei that ben in Judee, fle to the mounteyns; and he that is in the hous roof,", "rotherham": "Then, they who are in Judaea, let them flee into the mountains;", "weymouth": "\"then let those who are in Judaea escape to the hills;", "darby": "then let those who are in Judaea flee to the mountains;", "twenty": "“then those of you who are in Judea must take refuge in the mountains;", "acv": "then let those in Judea flee to the mountains.", "anderson": "then let those who are in Judea flee to the mountains;", "haweis": "then let such as are in Judea flee into the mountains.", "noyes": "then let those who are in Judaea flee to the mountains;", "webster": "Then let them who are in Judea flee to the mountains:", "vulgate": "tunc qui in Iudaea sunt fugiant ad montes;"}}, {"v": 17, "ref": "24:17", "o": "ὁ ἐπὶ τοῦ δώματος μὴ ⸀καταβάτω ἆραι τὰ ἐκ τῆς οἰκίας αὐτοῦ,", "en": {"kjv": "Let him which is on the housetop not come down to take any thing out of his house:", "web": "Let him who is on the housetop not go down to take out things that are in his house.", "bsb": "Let no one on the housetop come down to retrieve anything from his house.", "asv": "let him that is on the housetop not go down to take out the things that are in his house:", "ylt": "he on the house-top--let him not come down to take up any thing out of his house;", "tyndale": "And let him which is on ye housse toppe not come downe to fet eny thinge out of his housse.", "dra": "And he that is on the housetop, let him not come down to take any thing out of his house:", "bbe": "Let not him who is on the house-top go down to take anything out of his house:", "geneva": "Let him which is on the house top, not come downe to fetch any thing out of his house.", "wycliffe": "come not doun to take ony thing of his hous; and he that is in the feeld,", "rotherham": "And, he that is on the house-top, let him not come down, to take away the things out of his house;", "weymouth": "let him who is on the roof not go down to fetch what is in his house;", "darby": "let not him that is on the house come down to take the things out of his house;", "twenty": "and a man on the housetop must not go down to get the things that are in his house;", "acv": "Let the man on the housetop not go down to take things from his house.", "anderson": "let not him that is on the house-top come down to take his goods out of his house;", "haweis": "Let not him who is upon the roof go down to take any thing out of his house.", "noyes": "let not him that is on the house-top go down to take away the things belonging to his house;", "webster": "Let him who is on the house-top not come down to take any thing out of his house:", "vulgate": "et qui in tecto non descendat tollere aliquid de domo sua;"}}, {"v": 18, "ref": "24:18", "o": "καὶ ὁ ἐν τῷ ἀγρῷ μὴ ἐπιστρεψάτω ὀπίσω ἆραι ⸂τὸ ἱμάτιον⸃ αὐτοῦ.", "en": {"kjv": "Neither let him which is in the field return back to take his clothes.", "web": "Let him who is in the field not return back to get his clothes.", "bsb": "And let no one in the field return for his cloak.", "asv": "and let him that is in the field not return back to take his cloak.", "ylt": "and he in the field--let him not turn back to take his garments.", "tyndale": "Nether let him which is in ye felde returne backe to fetche his clothes.", "dra": "And he that is in the field, let him not go back to take his coat.", "bbe": "And let not him who is in the field go back to get his coat.", "geneva": "And he that is in the fielde, let not him returne backe to fetch his clothes.", "wycliffe": "turne not ayen to take his coote.", "rotherham": "And, he that is in the field, let him not turn back, to take away his mantle.", "weymouth": "nor let him who is outside the city stay to pick up his outer garment.", "darby": "and let not him that is in the field turn back to take his garment.", "twenty": "nor must one who is on his farm turn back to get his cloak.", "acv": "And let the man in the field not return back to take his clothes.", "anderson": "and let not him that is in the field turn back to take his clothing.", "haweis": "And he that is in the field, let him not turn back to take his garment.", "noyes": "and let not him that is in the field turn back to take his garment.", "webster": "Neither let him who is in the field return back to take his clothes.", "vulgate": "et qui in agro non revertatur tollere tunicam suam;"}}, {"v": 19, "ref": "24:19", "o": "οὐαὶ δὲ ταῖς ἐν γαστρὶ ἐχούσαις καὶ ταῖς θηλαζούσαις ἐν ἐκείναις ταῖς ἡμέραις.", "en": {"kjv": "And woe unto them that are with child, and to them that give suck in those days!", "web": "But woe to those who are with child and to nursing mothers in those days!", "bsb": "How miserable those days will be for pregnant and nursing mothers!", "asv": "But woe unto them that are with child and to them that give suck in those days!", "ylt": "`And woe to those with child, and to those giving suck in those days;", "tyndale": "Wo be in those dayes to the that are wt chylde and to the yt geve sucke.", "dra": "And woe to them that are with child and that give suck in those days.", "bbe": "But it will be hard for women who are with child and for those with babies at the breast in those days.", "geneva": "And woe shalbe to them that are with childe, and to them that giue sucke in those dayes.", "wycliffe": "But wo to hem that ben with child, and nurischen in tho daies.", "rotherham": "But alas! for the women with child, and for them that are giving suck, in those days;", "weymouth": "And alas for the women who at that time are with child or have infants!", "darby": "But woe to those that are with child, and those that give suck in those days.", "twenty": "And alas for the women that are with child, and for those that are nursing infants in those days!", "acv": "And woe to those who have in the womb and to those who suckle in those days.", "anderson": "But alas for those who are with child, and those who give suck in those days!", "haweis": "But wo to those who are with child, and have an infant at their breasts in those days!", "noyes": "And woe to the women with child, and to those with children at the breast, in those days!", "webster": "And woe to them that are with child, and to them that nurse infants in those days!", "vulgate": "vae autem praegnatibus et nutrientibus in illis diebus;"}}, {"v": 20, "ref": "24:20", "o": "προσεύχεσθε δὲ ἵνα μὴ γένηται ἡ φυγὴ ὑμῶν χειμῶνος μηδὲ σαββάτῳ·", "en": {"kjv": "But pray ye that your flight be not in the winter, neither on the sabbath day:", "web": "Pray that your flight will not be in the winter, nor on a Sabbath,", "bsb": "Pray that your flight will not occur in the winter or on the Sabbath.", "asv": "And pray ye that your flight be not in the winter, neither on a sabbath:", "ylt": "and pray ye that your flight may not be in winter, nor on a sabbath;", "tyndale": "But praye yt youre flight be not in ye winter nether on ye saboth daye.", "dra": "But pray that your flight be not in the winter or on the sabbath.", "bbe": "And say a prayer that your flight may not be in the winter, or on a Sabbath.", "geneva": "But pray that your flight be not in the winter, neither on the Sabbath day.", "wycliffe": "Preye ye, that youre fleyng be not maad in wynter, or in the saboth.", "rotherham": "But be praying that your flight, may not happen in winter, nor on sabbath;", "weymouth": "\"But pray that your flight may not be in winter, nor on the Sabbath;", "darby": "But pray that your flight may not be in winter time nor on sabbath:", "twenty": "Pray, too, that your flight may not take place in winter, nor on a Sabbath;", "acv": "And pray ye that your flight may not happen in winter, nor on a sabbath,", "anderson": "Pray that your flight may not be in the winter, nor on the Sabbath:", "haweis": "And pray that your flight be not in winter, nor on the sabbath.", "noyes": "And pray that your flight be not in winter, nor on a sabbath.", "webster": "But pray ye that your flight may not be in the winter, neither on the sabbath:", "vulgate": "orate autem ut non fiat fuga vestra hieme vel sabbato;"}}, {"v": 21, "ref": "24:21", "o": "ἔσται γὰρ τότε θλῖψις μεγάλη οἵα οὐ γέγονεν ἀπ’ ἀρχῆς κόσμου ἕως τοῦ νῦν οὐδ’ οὐ μὴ γένηται.", "en": {"kjv": "For then shall be great tribulation, such as was not since the beginning of the world to this time, no, nor ever shall be.", "web": "for then there will be great oppression, such as has not been from the beginning of the world until now, no, nor ever will be.", "bsb": "For at that time there will be great tribulation, unmatched from the beginning of the world until now, and never to be seen again.", "asv": "for then shall be great tribulation, such as hath not been from the beginning of the world until now, no, nor ever shall be.", "ylt": "for there shall be then great tribulation, such as was not from the beginning of the world till now, no, nor may be.", "tyndale": "For then shalbe greate tribulacio suche as was not fro the beginninge of the worlde to this tyme ner shalbe.", "dra": "For there shall be then great tribulation, such as hath not been from the beginning of the world until now, neither shall be.", "bbe": "Because in those days there will be great sorrow, such as there has not been from the start of the world till now, or ever will be.", "geneva": "For then shall be great tribulation, such as was not from the beginning of the worlde to this time, nor shalbe.", "wycliffe": "For thanne schal be greet tribulacioun, what maner `was not fro the bigynnyng of the world to now, nether schal be maad.", "rotherham": "For there will be then, Great tribulation, such as hath not happened, from the beginning of the world, until the present time, neither in any wise shall happen.", "weymouth": "for it will be a time of great suffering, such as never has been from the beginning of the world till now, and assuredly never will be again.", "darby": "for then shall there be great tribulation, such as has not been from [the] beginning of [the] world until now, nor ever shall be;", "twenty": "for that will be ‘a time of great distress, the like of which has not occurred from the beginning of the world down to the present time’ — no, nor ever will again.", "acv": "for then there will be great tribulation, such as not has happened from the beginning of the world until now, nor, no, it will not happen.", "anderson": "for then shall be great affliction, such as has not been from the beginning of the world till now, nor shall ever be.", "haweis": "For then the tribulation will be great, such as never was from the beginning of the world, and never more shall be.", "noyes": "For there will then be great distress, such as hath not been from the beginning of the world to this time; no, nor shall ever be.", "webster": "For then shall be great tribulation, such as hath not been since the beginning of the world to this time, no, nor ever shall be.", "vulgate": "erit enim tunc tribulatio magna qualis non fuit ab initio mundi usque modo neque fiet;"}}, {"v": 22, "ref": "24:22", "o": "καὶ εἰ μὴ ἐκολοβώθησαν αἱ ἡμέραι ἐκεῖναι, οὐκ ἂν ἐσώθη πᾶσα σάρξ· διὰ δὲ τοὺς ἐκλεκτοὺς κολοβωθήσονται αἱ ἡμέραι ἐκεῖναι.", "en": {"kjv": "And except those days should be shortened, there should no flesh be saved: but for the elect’s sake those days shall be shortened.", "web": "Unless those days had been shortened, no flesh would have been saved. But for the sake of the chosen ones, those days will be shortened.", "bsb": "If those days had not been cut short, nobody would be saved. But for the sake of the elect, those days will be cut short.", "asv": "And except those days had been shortened, no flesh would have been saved: but for the elect’s sake those days shall be shortened.", "ylt": "And if those days were not shortened, no flesh would have been saved; but because of the chosen, shall those days be shortened.", "tyndale": "Ye and except those dayes shuld be shortened there shuld no fleshe be saved: but for ye chosens sake those dayes shalbe shortened.", "dra": "And unless those days had been shortened, no flesh should be saved: but for the sake of the elect those days shall be shortened.", "bbe": "And if those days had not been made short there would have been no salvation for any, but because of the saints those days will be made short.", "geneva": "And except those dayes should be shortened, there should no flesh be saued: but for the elects sake those dayes shalbe shortened.", "wycliffe": "And but tho daies hadden be abreggide, ech flesch schulde not be maad saaf; but tho daies schulen be maad schort, for the chosun men.", "rotherham": "And, except those days had been shortened, no flesh had been saved; but, for the sake of the chosen, those days shall be shortened.", "weymouth": "And if those days had not been cut short, no one would escape; but for the sake of God's own People those days will be cut short.", "darby": "and if those days had not been cut short, no flesh had been saved; but on account of the elect those days shall be cut short.", "twenty": "And had not those days been limited, not a single soul would escape; but for the sake of ‘God’s People’ a limit will be put to them.", "acv": "And if those days were not shortened, no flesh would be saved. But because of the chosen those days will be shortened.", "anderson": "And unless those days should be made few, no flesh could be saved. But on account of the elect those days shall be made few.", "haweis": "And except those days were shortened, there would be no flesh saved: but for the elect’s sake these days shall be shortened.", "noyes": "And were not those days to shortened, no flesh would be saved; but, for the sake of the chosen, these days will be shortened.", "webster": "And except those days should be shortened, there would no flesh be saved: but for the elect's sake those days shall be shortened.", "vulgate": "et nisi breviati fuissent dies illi non fieret salva omnis caro sed propter electos breviabuntur dies illi;"}}, {"v": 23, "ref": "24:23", "o": "τότε ἐάν τις ὑμῖν εἴπῃ· Ἰδοὺ ὧδε ὁ χριστός, ἤ· Ὧδε, μὴ πιστεύσητε·", "en": {"kjv": "Then if any man shall say unto you, Lo, here is Christ, or there; believe it not.", "web": "“Then if any man tells you, ‘Behold, here is the Christ,’ or, ‘There,’ don’t believe it.", "bsb": "At that time, if anyone says to you, ‘Look, here is the Christ!’ or ‘There He is!’ do not believe it.", "asv": "Then if any man shall say unto you, Lo, here is the Christ, or, Here; believe it not.", "ylt": "`Then if any one may say to you, Lo, here is the Christ! or here! ye may not believe;", "tyndale": "Then yf eny ma shall saye vnto you: lo here is Christ or there is Christ: beleve it not.", "dra": "Then if any man shall say to you, Lo here is Christ, or there: do not believe him.", "bbe": "Then if any man says to you, See, here is the Christ, or, Here; do not put faith in him;", "geneva": "Then if any shall say vnto you, Loe, here is Christ, or there, beleeue it not.", "wycliffe": "Thanne if ony man seie to you, Lo! here is Crist, or there, nyle ye bileue.", "rotherham": "Then, if any, unto you, say—Lo! here, is the Christ, or, there, Do not believe it;", "weymouth": "\"If at that time any one should say to you, `See, here is the Christ!' or `Here!' give no credence to it.", "darby": "Then if any one say to you, Behold, here is the Christ, or here, believe [it] not.", "twenty": "And, at that time, if any one should say to you ‘Look! here is the Christ!’ or ‘Here he is!’, do not believe it;", "acv": "Then if any man should say to you, Lo, here is the Christ, or, Here, believe ye not.", "anderson": "Then if any one shall say to you: Lo! here is the Christ, or there; believe it not.", "haweis": "Then if any man say unto you, Lo! here is the Messiah, or there; believe it not:", "noyes": "Then if any one say to you, Lo! here is the Christ; or there, believe him not.", "webster": "Then if any man shall say to you, Lo, here [is] Christ, or there; believe [it] not.", "vulgate": "tunc si quis vobis dixerit ecce hic Christus aut illic nolite credere;"}}, {"v": 24, "ref": "24:24", "o": "ἐγερθήσονται γὰρ ψευδόχριστοι καὶ ψευδοπροφῆται, καὶ δώσουσιν σημεῖα μεγάλα καὶ τέρατα ὥστε ⸀πλανῆσαι εἰ δυνατὸν καὶ τοὺς ἐκλεκτούς·", "en": {"kjv": "For there shall arise false Christs, and false prophets, and shall shew great signs and wonders; insomuch that, if it were possible, they shall deceive the very elect.", "web": "For there will arise false christs, and false prophets, and they will show great signs and wonders, so as to lead astray, if possible, even the chosen ones.", "bsb": "For false Christs and false prophets will appear and perform great signs and wonders that would deceive even the elect, if that were possible.", "asv": "For there shall arise false Christs, and false prophets, and shall show great signs and wonders; so as to lead astray, if possible, even the elect.", "ylt": "for there shall arise false Christs, and false prophets, and they shall give great signs and wonders, so as to lead astray, if possible, also the chosen.", "tyndale": "For there shall arise false christes and false prophete and shall do great myracles and wondres. In so moche yt if it were possible ye verie electe shuld be deceaved.", "dra": "For there shall arise false Christs and false prophets and shall shew great signs and wonders, insomuch as to deceive (if possible) even the elect.", "bbe": "For there will come up false Christs, and false prophets, who will do great signs and wonders; so that if possible even the saints might be tricked.", "geneva": "For there shall arise false Christes, and false prophets, and shall shewe great signes and wonders, so that if it were possible, they should deceiue the very elect.", "wycliffe": "For false Cristis and false prophetis schulen rise, and thei schulen yyue grete tokenes and wondrys; so that also the chosun be led in to erroure, if it may be done.", "rotherham": "For there will arise, false Christs, and false prophets,—and they will show great signs and wonders, so that, if possible, even the chosen, should be deceived:—", "weymouth": "For there will rise up false Christs and false prophets, displaying wonderful signs and prodigies, so as to deceive, were it possible, even God's own People.", "darby": "For there shall arise false Christs, and false prophets, and shall give great signs and wonders, so as to mislead, if possible, even the elect.", "twenty": "for false Christs and false Prophets will arise, and will display great signs and marvels, so that, were it possible, even God’s People would be led astray.", "acv": "For there will arise false Christs and false prophets, and they will give great signs and wonders, so as to lead astray, if possible, even the chosen.", "anderson": "For false Christs and false prophets will arise, and will show great signs and wonders, so as to deceive, if possible, even the elect.", "haweis": "for false Messiahs and false prophets shall arise, and give out great signs and wonders; so as to deceive, if it were possible, even the elect.", "noyes": "For there will rise up false Christs, and false prophets, and will show great signs and wonders, so that, if possible, even the chosen will be deceived.", "webster": "For false Christs will arise, and false prophets, and will show great signs and wonders; so that, if [it were] possible, they would deceive the very elect.", "vulgate": "surgent enim pseudochristi et pseudoprophetae et dabunt signa magna et prodigia ita ut in errorem inducantur si fieri potest etiam electi;"}}, {"v": 25, "ref": "24:25", "o": "ἰδοὺ προείρηκα ὑμῖν.", "en": {"kjv": "Behold, I have told you before.", "web": "“Behold, I have told you beforehand.", "bsb": "See, I have told you in advance.", "asv": "Behold, I have told you beforehand.", "ylt": "Lo, I did tell you beforehand.", "tyndale": "Take hede I have tolde you before.", "dra": "Behold I have told it to you, beforehand.", "bbe": "See, I have made it clear to you before it comes about.", "geneva": "Beholde, I haue tolde you before.", "wycliffe": "Lo! Y haue bifor seid to you.", "rotherham": "Lo! I have foretold you.", "weymouth": "Remember, I have forewarned you.", "darby": "Behold, I have told you beforehand.", "twenty": "Remember, I have told you beforehand.", "acv": "Behold, I have foretold it to you.", "anderson": "Behold, I have told you beforehand.", "haweis": "Behold, I have forewarned you.", "noyes": "Lo! I have told you beforehand.", "webster": "Behold, I have told you before.", "vulgate": "ecce praedixi vobis;"}}, {"v": 26, "ref": "24:26", "o": "ἐὰν οὖν εἴπωσιν ὑμῖν· Ἰδοὺ ἐν τῇ ἐρήμῳ ἐστίν, μὴ ἐξέλθητε· Ἰδοὺ ἐν τοῖς ταμείοις, μὴ πιστεύσητε·", "en": {"kjv": "Wherefore if they shall say unto you, Behold, he is in the desert; go not forth: behold, he is in the secret chambers; believe it not.", "web": "If therefore they tell you, ‘Behold, he is in the wilderness,’ don’t go out; ‘Behold, he is in the inner rooms,’ don’t believe it.", "bsb": "So if they tell you, ‘There He is in the wilderness,’ do not go out; or, ‘Here He is in the inner rooms,’ do not believe it.", "asv": "If therefore they shall say unto you, Behold, he is in the wilderness; go not forth: Behold, he is in the inner chambers; believe it not.", "ylt": "`If therefore they may say to you, Lo, in the wilderness he is, ye may not go forth; lo, in the inner chambers, ye may not believe;", "tyndale": "Wherfore if they shall saye vnto you: beholde he is in ye desert go not forth: beholde he is in ye secret places beleve not.", "dra": "If therefore they shall say to you, Behold he is in the desert: go ye not out. Behold he is in the closets: believe it not.", "bbe": "If, then, they say to you, See, he is in the waste land; go not out: See, he is in the inner rooms; put no faith in it.", "geneva": "Wherefore if they shall say vnto you, Beholde, he is in the desert, goe not forth: Beholde, he is in the secret places, beleeue it not.", "wycliffe": "Therfor if thei seie to you, Lo! he is in desert, nyle ye go out; lo! in priuey placis, nyle ye trowe.", "rotherham": "If therefore they should say unto you, Lo! in the desert, he is, Do not go forth; Lo! in the chambers, Do not believe it.", "weymouth": "If therefore they should say to you, `See, He is in the Desert!' do not go out there: or `See, He is indoors in the room!' do not believe it.", "darby": "If therefore they say to you, Behold, he is in the desert, go not forth; behold, [he is] in the inner chambers, do not believe [it].", "twenty": "Therefore, if people say to you ‘He is in the Wilderness!’, do not go out there; or ‘He is in an inner room!’, do not believe it;", "acv": "If therefore they should say to you, Behold, he is in the wilderness, do not go forth. Behold, he is in the inner chambers, do not believe.", "anderson": "Therefore, if they say to you: Behold, he is in the desert; go not out: Behold, he is in the secret chambers; believe it not.", "haweis": "Therefore if they say to you, He is in the wilderness; go not out: lo! he is in the secret closets; believe it not.", "noyes": "If therefore they say to you, Lo! he is in the wilderness; go not forth; lo! he is in the private chambers; believe them not.", "webster": "Wherefore, if they shall say to you, Behold, he is in the desert; go not forth: behold, [he is] in the secret chambers; believe [it] not.", "vulgate": "si ergo dixerint vobis ecce in deserto est nolite exire ecce in penetrabilibus nolite credere;"}}, {"v": 27, "ref": "24:27", "o": "ὥσπερ γὰρ ἡ ἀστραπὴ ἐξέρχεται ἀπὸ ἀνατολῶν καὶ φαίνεται ἕως δυσμῶν, οὕτως ⸀ἔσται ἡ παρουσία τοῦ υἱοῦ τοῦ ἀνθρώπου·", "en": {"kjv": "For as the lightning cometh out of the east, and shineth even unto the west; so shall also the coming of the Son of man be.", "web": "For as the lightning flashes from the east, and is seen even to the west, so will be the coming of the Son of Man.", "bsb": "For just as the lightning comes from the east and flashes as far as the west, so will be the coming of the Son of Man.", "asv": "For as the lightning cometh forth from the east, and is seen even unto the west; so shall be the coming of the Son of man.", "ylt": "for as the lightning doth come forth from the east, and doth appear unto the west, so shall be also the presence of the Son of Man;", "tyndale": "For as ye lightninge cometh out of ye eest and shyneth vnto the weest: so shall the comynge of the sonne of ma be.", "dra": "For as lightning cometh out of the east and appeareth even into the west: so shall also the cowling of the Son of man be.", "bbe": "Because as in a thunderstorm the bright light coming from the east is seen even in the west; so will be the coming of the Son of man.", "geneva": "For as the lightning commeth out of the East, and is seene into the West, so shall also the comming of the Sonne of man be.", "wycliffe": "For as leit goith out fro the eest, and apperith in to the weste, so schal be also the coming of mannus sone.", "rotherham": "For, just as the lightning goeth forth from the east, and shineth unto the west, so, shall be the presence of the Son of Man.", "weymouth": "For just as the lightning flashes in the east and is seen to the very west, so will be the Coming of the Son of Man.", "darby": "For as the lightning goes forth from the east and shines to the west, so shall be the coming of the Son of man.", "twenty": "for, just as lightning will start from the east and flash across to the west, so will it be with the Coming of the Son of Man.", "acv": "For as the lightning comes out from the east, and shines as far as the west, so also will be the coming of the Son of man.", "anderson": "For as the lightning comes out from the east, and shines even to the west, so also shall the coming of the Son of man be.", "haweis": "For as the lightning cometh out from the east, and flashes to the west; so shall be the coming of the Son of man.", "noyes": "For as the lightning cometh from the east, and shineth even to the west, so will be the coming of the Son of man.", "webster": "For as the lightning cometh out of the east, and shineth even to the west; so shall also the coming of the Son of man be.", "vulgate": "sicut enim fulgur exit ab oriente et paret usque in occidente ita erit et adventus Filii hominis;"}}, {"v": 28, "ref": "24:28", "o": "⸀ὅπου ἐὰν ᾖ τὸ πτῶμα, ἐκεῖ συναχθήσονται οἱ ἀετοί.", "en": {"kjv": "For wheresoever the carcase is, there will the eagles be gathered together.", "web": "For wherever the carcass is, there is where the vultures gather together.", "bsb": "Wherever there is a carcass, there the vultures will gather.", "asv": "Wheresoever the carcase is, there will the eagles be gathered together.", "ylt": "for wherever the carcase may be, there shall the eagles be gathered together.", "tyndale": "For wheresoever a deed karkas is eve thyther will the egles resorte.", "dra": "Wheresoever the body shall be, there shall the eagles also be gathered together.", "bbe": "Wherever the dead body is, there will the eagles come together.", "geneva": "For wheresoeuer a dead carkeis is, thither will the Egles be gathered together.", "wycliffe": "Where euer the bodi schal be, also the eglis schulen be gaderid thidur.", "rotherham": "Wheresoever, the corpse, shall be, there, shall be gathered, the vultures!", "weymouth": "Wherever the dead body is, there will the vultures flock together.", "darby": "[For] wherever the carcase is, there will be gathered the eagles.", "twenty": "Wherever a dead body lies, there will the vultures flock.’", "acv": "For wherever the carcass may be, there the vultures will be gathered together.", "anderson": "For wherever the carcass is, there will the vultures come together.", "haweis": "For wheresoever the carcase is, there will the eagles be gathered together.", "noyes": "Wherever the carcass is, there will the eagles be gathered together.", "webster": "For wherever the carcass is, there will the eagles be collected.", "vulgate": "ubicumque fuerit corpus illuc congregabuntur aquilae;"}}, {"v": 29, "ref": "24:29", "o": "Εὐθέως δὲ μετὰ τὴν θλῖψιν τῶν ἡμερῶν ἐκείνων ὁ ἥλιος σκοτισθήσεται, καὶ ἡ σελήνη οὐ δώσει τὸ φέγγος αὐτῆς, καὶ οἱ ἀστέρες πεσοῦνται ἀπὸ τοῦ οὐρανοῦ, καὶ αἱ δυνάμεις τῶν οὐρανῶν σαλευθήσονται.", "en": {"kjv": "Immediately after the tribulation of those days shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:", "web": "But immediately after the oppression of those days, the sun will be darkened, the moon will not give its light, the stars will fall from the sky, and the powers of the heavens will be shaken;", "bsb": "Immediately after the tribulation of those days: ‘The sun will be darkened, and the moon will not give its light; the stars will fall from the sky, and the powers of the heavens will be shaken.’", "asv": "But immediately after the tribulation of those days the sun shall be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:", "ylt": "`And immediately after the tribulation of those days, the sun shall be darkened, and the moon shall not give her light, and the stars shall fall from the heaven, and the powers of the heavens shall be shaken;", "tyndale": "Immediatly after the tribulacios of those dayes shall the sunne be derkened: and ye mone shall not geve hir light and the starre shall fall from heve and the powers of heve shall move.", "dra": "And immediately after the tribulation of those days, the sun shall be darkened and the moon shall not give her light and the stars shall fall from heaven and the powers of heaven shall be moved.", "bbe": "But straight away, after the trouble of those days, the sun will be made dark and the moon will not give her light and the stars will come down from heaven and the powers of heaven will be moved:", "geneva": "And immediatly after ye tribulations of those dayes, shall the sunne be darkened, and the moone shall not giue her light, and the starres shall fal from heauen, and ye powers of heaue shalbe shake.", "wycliffe": "And anoon after the tribulacioun of tho daies, the sunne schal be maad derk, and the moone schal not yyue hir liyt, and the sterris schulen falle fro heuene, and the vertues of heuenes schulen be moued.", "rotherham": "But, straightway after the tribulation of those days, the sun, will be darkened, and, the moon, will not give her brightness, and, the stars, will fall from heaven,—and, the powers of the heavens, will be shaken;", "weymouth": "\"But immediately after those times of distress the sun will be darkened, the moon will not shed her light, the stars will fall from the firmament, and the forces which control the heavens will be disordered and disturbed.", "darby": "But immediately after the tribulation of those days the sun shall be darkened, and the moon not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken.", "twenty": "Immediately after the distress of those days, ‘the sun will be darkened, the moon will not give her light, the stars will fall from the heavens,’ and ‘the forces of the heavens will be convulsed.’", "acv": "But straightaway after the tribulation of those days the sun will be darkened, and the moon will not give its light. And the stars will fall from the sky, and the powers of the heavens will be shaken.", "anderson": "Immediately after the affliction of those days, the sun shall be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the hosts of the heavens shall be shaken.", "haweis": "Then, immediately after the tribulation of those days, shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken.", "noyes": "And immediately after the distress of those days will the sun be darkened, and the moon will not give her light, and the stars will fall from heaven, and the powers of the heavens will be shaken.", "webster": "Immediately after the tribulation of those days, shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:", "vulgate": "statim autem post tribulationem dierum illorum sol obscurabitur et luna non dabit lumen suum et stellae cadent de caelo et virtutes caelorum commovebuntur;"}}, {"v": 30, "ref": "24:30", "o": "καὶ τότε φανήσεται τὸ σημεῖον τοῦ υἱοῦ τοῦ ἀνθρώπου ἐν ⸀τῷ οὐρανῷ, καὶ τότε κόψονται πᾶσαι αἱ φυλαὶ τῆς γῆς καὶ ὄψονται τὸν υἱὸν τοῦ ἀνθρώπου ἐρχόμενον ἐπὶ τῶν νεφελῶν τοῦ οὐρανοῦ μετὰ δυνάμεως καὶ δόξης πολλῆς·", "en": {"kjv": "And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.", "web": "and then the sign of the Son of Man will appear in the sky. Then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of the sky with power and great glory.", "bsb": "At that time the sign of the Son of Man will appear in heaven, and all the tribes of the earth will mourn. They will see the Son of Man coming on the clouds of heaven, with power and great glory.", "asv": "and then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming on the clouds of heaven with power and great glory.", "ylt": "and then shall appear the sign of the Son of Man in the heaven; and then shall all the tribes of the earth smite the breast, and they shall see the Son of Man coming upon the clouds of the heaven, with power and much glory;", "tyndale": "And then shall appere the sygne of the sonne of man in heven. And then shall all the kynreddes of the erth morne and they shall se the sonne of man come in the cloudes of heven with power and greate glorie.", "dra": "And then shall appear the sign of the Son of man in heaven. And then shall all tribes of the earth mourn: and they shall see the Son of man coming in the clouds of heaven with much power and majesty.", "bbe": "And then the sign of the Son of man will be seen in heaven: and then all the nations of the earth will have sorrow, and they will see the Son of man coming on the clouds of heaven with power and great glory.", "geneva": "And then shall appeare the signe of the Sonne of man in heauen: and then shall all the kinreds of the earth mourne, and they shall see the Sonne of man come in the cloudes of heauen with power and great glorie.", "wycliffe": "And thanne the tokene of mannus sone schal appere in heuene, and thanne alle kynredis of the erthe schulen weile; and thei schulen see mannus sone comynge in the cloudis of heuene, with miche vertu and maieste.", "rotherham": "And, then, will be displayed—The sign of the Son of Man in heaven, and, then, will smite their breasts—all the tribes of the earth; and they will see the Son of Man—coming upon the clouds of heaven, with great power and glory.", "weymouth": "Then will appear the Sign of the Son of Man in the sky; and then will all the nations of the earth lament, when they see the Son of Man coming on the clouds of the sky with great power and glory.", "darby": "And then shall appear the sign of the Son of man in heaven; and then shall all the tribes of the land lament, and they shall see the Son of man coming on the clouds of heaven with power and great glory.", "twenty": "Then will appear the sign of the Son of Man in the heavens; and all the peoples of the earth will mourn, when they see the Son of Man coming on the clouds of the heavens,’ with power and great glory;", "acv": "And then the sign of the Son of man will appear in the sky. And then all the tribes of the earth will beat the breast, and they will see the Son of man coming in the clouds of the sky with power and much glory.", "anderson": "And then shall appear the sign of the Son of man in heaven; and then shall all the tribes of the land mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.", "haweis": "And then shall the sign of the Son of man appear in the heaven: and then shall all the tribes of the earth lament bitterly, and they shall see the Son of man coming on the clouds of heaven with power and great glory.", "noyes": "And then will appear the sign of the Son of man in heaven; and all the tribes of the earth will mourn, and will see the Son of man coming upon the clouds of heaven with power and great glory.", "webster": "And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.", "vulgate": "et tunc parebit signum Filii hominis in caelo et tunc plangent omnes tribus terrae et videbunt Filium hominis venientem in nubibus caeli cum virtute multa et maiestate;"}}, {"v": 31, "ref": "24:31", "o": "καὶ ἀποστελεῖ τοὺς ἀγγέλους αὐτοῦ μετὰ ⸀σάλπιγγος μεγάλης, καὶ ἐπισυνάξουσιν τοὺς ἐκλεκτοὺς αὐτοῦ ἐκ τῶν τεσσάρων ἀνέμων ἀπ’ ἄκρων οὐρανῶν ἕως ⸀τῶν ἄκρων αὐτῶν.", "en": {"kjv": "And he shall send his angels with a great sound of a trumpet, and they shall gather together his elect from the four winds, from one end of heaven to the other.", "web": "He will send out his angels with a great sound of a trumpet, and they will gather together his chosen ones from the four winds, from one end of the sky to the other.", "bsb": "And He will send out His angels with a loud trumpet call, and they will gather His elect from the four winds, from one end of the heavens to the other.", "asv": "And he shall send forth his angels with a great sound of a trumpet, and they shall gather together his elect from the four winds, from one end of heaven to the other.", "ylt": "and he shall send his messengers with a great sound of a trumpet, and they shall gather together his chosen from the four winds, from the ends of the heavens unto the ends thereof.", "tyndale": "And he shall sende his angeles with the greate voyce of a trope and they shall gader to gether his chosen from the fower wyndes and from the one ende of the worlde to the other.", "dra": "And he shall send his angels with a trumpet and a great voice: and they shall gather together his elect from the four winds, from the farthest parts of the heavens to the utmost bounds of them.", "bbe": "And he will send out his angels with a great sound of a horn, and they will get his saints together from the four winds, from one end of heaven to the other.", "geneva": "And he shall send his Angels with a great sound of a trumpet, and they shall gather together his elect, from the foure windes, and from the one ende of the heauens vnto the other.", "wycliffe": "And he schal sende hise aungels with a trumpe, and a greet vois; and thei schulen gedere hise chosun fro foure wyndis, fro the hiyest thingis of heuenes to the endis of hem.", "rotherham": "And he will send forth his messengers, with a great trumpet, and they will gather together his chosen—Out of the four winds, from heavens’ bounds, unto their bounds.", "weymouth": "And He will send out His angels with a loud trumpet-blast, and they will bring together His own People to Him from north, south, east and west--from one extremity of the world to the other.", "darby": "And he shall send his angels with a great sound of trumpet, and they shall gather together his elect from the four winds, from [the one] extremity of [the] heavens to [the other] extremity of them.", "twenty": "and he will send his angels, with a great trumpet, and they will gather his People round him from the four winds, from one end of heaven to the other.", "acv": "And he will send forth his agents with a great trumpet sound, and they will gather together his chosen from the four winds, from the boundaries of the heavens-as far as their boundaries.", "anderson": "And he will send his angels with a trumpet of great voice, and they shall gather his elect from the four winds, from one end of heaven to the other.", "haweis": "And he shall send forth his angels with a trumpet, and a great shout, and they shall gather together his elect from the four winds, from the extremities of the heavens to the extremities of the same.", "noyes": "And he will send forth his angels with a great trumpet, and they will gather his chosen from the four winds, from one end of heaven to the other.", "webster": "And he will send his angels with a great sound of a trumpet, and they will gather his elect from the four winds, from one end of heaven to the other.", "vulgate": "et mittet angelos suos cum tuba et voce magna et congregabunt electos eius a quattuor ventis a summis caelorum usque ad terminos eorum;"}}, {"v": 32, "ref": "24:32", "o": "Ἀπὸ δὲ τῆς συκῆς μάθετε τὴν παραβολήν· ὅταν ἤδη ὁ κλάδος αὐτῆς γένηται ἁπαλὸς καὶ τὰ φύλλα ἐκφύῃ, γινώσκετε ὅτι ἐγγὺς τὸ θέρος·", "en": {"kjv": "Now learn a parable of the fig tree; When his branch is yet tender, and putteth forth leaves, ye know that summer is nigh:", "web": "“Now from the fig tree learn this parable. When its branch has now become tender, and produces its leaves, you know that the summer is near.", "bsb": "Now learn this lesson from the fig tree: As soon as its branches become tender and sprout leaves, you know that summer is near.", "asv": "Now from the fig tree learn her parable: when her branch is now become tender, and putteth forth its leaves, ye know that the summer is nigh;", "ylt": "`And from the fig-tree learn ye the simile: When already its branch may have become tender, and the leaves it may put forth, ye know that summer is nigh,", "tyndale": "Learne, a similitude of the fygge tree: when his braunches are yet tender and his leves sproge ye knowe that sommer is nye.", "dra": "And from the fig tree learn a parable: When the branch thereof is now tender and the leaves come forth, you know that summer is nigh.", "bbe": "Now take an example from the fig-tree: when her branch has become soft and puts out its leaves, you are certain that the summer is near;", "geneva": "Now learne the parable of the figge tree: when her bough is yet tender, and it putteth foorth leaues, ye knowe that sommer is neere.", "wycliffe": "And lerne ye the parable of a fige tre. Whanne his braunche is now tendir, and the leeues ben sprongun, ye witen that somer is nyy;", "rotherham": "Now, from the fig-tree, learn ye, the parable:—When, already, her young branch, becometh tender, and the leaves, may be sprouting, ye observe, that, near, is, the summer:", "weymouth": "\"Now learn from the fig-tree the lesson it teaches. As soon as its branches have now become soft and it is bursting into leaf, you all know that summer is near.", "darby": "But learn the parable from the fig-tree: When already its branch becomes tender and produces leaves, ye know that the summer is near.", "twenty": "Learn the lesson taught by the fig tree. As soon as its branches are full of sap, and it is bursting into leaf, you know that summer is near.", "acv": "Now learn a parable from the fig tree. When its branch now becomes tender, and sprouts leaves, ye know that the summer is near.", "anderson": "Learn now a parable from the fig-tree: As soon as its branch becomes tender, and puts forth leaves, you know that summer is near.", "haweis": "Learn then a parable from the fig-tree; when its branch is now tender, and the leaves shoot forth, ye know that summer is nigh:", "noyes": "And from the fig-tree learn its parable. When its branch hath now become tender, and putteth forth its leaves, ye know that summer is near.", "webster": "Now learn a parable of the fig-tree; When its branch is yet tender and putteth forth leaves, ye know that summer [is] nigh:", "vulgate": "ab arbore autem fici discite parabolam cum iam ramus eius tener fuerit et folia nata scitis quia prope est aestas;"}}, {"v": 33, "ref": "24:33", "o": "οὕτως καὶ ὑμεῖς, ὅταν ἴδητε ⸂πάντα ταῦτα⸃, γινώσκετε ὅτι ἐγγύς ἐστιν ἐπὶ θύραις.", "en": {"kjv": "So likewise ye, when ye shall see all these things, know that it is near, even at the doors.", "web": "Even so you also, when you see all these things, know that it is near, even at the doors.", "bsb": "So also, when you see all these things, you will know that He is near, right at the door.", "asv": "even so ye also, when ye see all these things, know ye that he is nigh, even at the doors.", "ylt": "so also ye, when ye may see all these, ye know that it is nigh--at the doors.", "tyndale": "So lyke wyse ye when ye see all these thynges be ye sure that it is neare even at the dores.", "dra": "So you also, when you shall see all these things, know ye that it is nigh, even at the doors.", "bbe": "Even so, when you see all these things, you may be certain that he is near, even at the doors.", "geneva": "So likewise ye, when ye see all these things, know that the kingdom of God is neere, eue at ye doores.", "wycliffe": "`so and ye whanne ye seen alle these thingis, wite ye that it is nyy, in the yatis.", "rotherham": "Thus, ye also, when ye shall see all these things, observe ye, that, near, he is, at the doors.", "weymouth": "So you also, when you see all these signs, may be sure that He is near--at your very door.", "darby": "Thus also ye, when ye see all these things, know that it is near, at the doors.", "twenty": "And so may you, as soon as you see all these things, know that he is at your doors.", "acv": "So ye also, when ye see all these things, know that it is near, at the doors.", "anderson": "So also, when you see all these things, know that it is near at the doors.", "haweis": "just so ye, when ye behold these things, know that it is near, even at the gates.", "noyes": "So also, when ye see all these things, know ye that he is near, at the doors.", "webster": "So likewise ye, when ye shall see all these things, know that it is near, [even at] the doors.", "vulgate": "ita et vos cum videritis haec omnia scitote quia prope est in ianuis;"}}, {"v": 34, "ref": "24:34", "o": "ἀμὴν λέγω ὑμῖν ⸀ὅτι οὐ μὴ παρέλθῃ ἡ γενεὰ αὕτη ἕως ἂν πάντα ταῦτα γένηται.", "en": {"kjv": "Verily I say unto you, This generation shall not pass, till all these things be fulfilled.", "web": "Most certainly I tell you, this generationwill not pass away, until all these things are accomplished.", "bsb": "Truly I tell you, this generation will not pass away until all these things have happened.", "asv": "Verily I say unto you, This generation shall not pass away, till all these things be accomplished.", "ylt": "Verily I say to you, this generation may not pass away till all these may come to pass.", "tyndale": "Verely I saye vnto you that this generacion shall not passe tyll all these be fulfilled.", "dra": "Amen I say to you that this generation shall not pass till all these things be done.", "bbe": "Truly I say to you, This generation will not come to an end till all these things are complete.", "geneva": "Verely I say vnto you, this generation shall not passe, till all these things be done.", "wycliffe": "Treuli Y seie to you, for this generacioun schal not passe, til alle thingis be don;", "rotherham": "Verily, I say unto you—In nowise, shall this generation, pass away, until all these things, shall happen:", "weymouth": "I tell you in solemn truth that the present generation will certainly not pass away without all these things having first taken place.", "darby": "Verily I say to you, This generation will not have passed away until all these things shall have taken place.", "twenty": "I tell you, even the present generation will not pass away, till all these things have taken place.", "acv": "Truly I say to you, this generation will, no, not pass away, until all these things happen.", "anderson": "Verily I say to you, This generation shall not pass away till all these things shall have taken place.", "haweis": "Verily I say unto you, This generation shall not pass away until all these things shall be done.", "noyes": "Truly do I say to you, This generation will not pass away, till all these things take place.", "webster": "Verily I say to you, This generation shall not pass, till all these things shall be fulfilled.", "vulgate": "amen dico vobis quia non praeteribit haec generatio donec omnia haec fiant;"}}, {"v": 35, "ref": "24:35", "o": "ὁ οὐρανὸς καὶ ἡ γῆ ⸀παρελεύσεται, οἱ δὲ λόγοι μου οὐ μὴ παρέλθωσιν.", "en": {"kjv": "Heaven and earth shall pass away, but my words shall not pass away.", "web": "Heaven and earth will pass away, but my words will not pass away.", "bsb": "Heaven and earth will pass away, but My words will never pass away.", "asv": "Heaven and earth shall pass away, but my words shall not pass away.", "ylt": "The heaven and the earth shall pass away, but my words shall not pass away.", "tyndale": "Heven and erth shall perisshe: but my wordes shall abyde.", "dra": "Heaven and earth shall pass: but my words shall not pass.", "bbe": "Heaven and earth will come to an end, but my words will not come to an end.", "geneva": "Heauen and earth shall passe away: but my wordes shall not passe away.", "wycliffe": "heuene and erthe schulen passe, but my wordis schulen not passe.", "rotherham": "The heaven and the earth, shall pass away, but, my words, shall, in nowise, pass away.", "weymouth": "Earth and sky will pass away, but it is certain that my words will not pass away.", "darby": "The heaven and the earth shall pass away, but my words shall in no wise pass away.", "twenty": "The heavens and the earth will pass away, but my words shall never pass away.", "acv": "The sky and the earth will pass away, but my words may, no, not pass away.", "anderson": "Heaven and earth shall pass away, but my words shall not pass away.", "haweis": "Heaven and earth shall pass away, but my words shall in no wise pass away.", "noyes": "Heaven and earth will pass away, but my words will not pass away.", "webster": "Heaven and earth shall pass away, but my words shall not pass away.", "vulgate": "caelum et terra transibunt verba vero mea non praeteribunt;"}}, {"v": 36, "ref": "24:36", "o": "Περὶ δὲ τῆς ἡμέρας ἐκείνης καὶ ὥρας οὐδεὶς οἶδεν, οὐδὲ οἱ ἄγγελοι τῶν οὐρανῶν ⸂οὐδὲ ὁ υἱός⸃, εἰ μὴ ὁ ⸀πατὴρ μόνος.", "en": {"kjv": "But of that day and hour knoweth no man, no, not the angels of heaven, but my Father only.", "web": "But no one knows of that day and hour, not even the angels of heaven,but my Father only.", "bsb": "No one knows about that day or hour, not even the angels in heaven, nor the Son, but only the Father.", "asv": "But of that day and hour knoweth no one, not even the angels of heaven, neither the Son, but the Father only.", "ylt": "`And concerning that day and the hour no one hath known--not even the messengers of the heavens--except my Father only;", "tyndale": "But of that daye and houre knowith no man no not ye angels of heve but my father only.", "dra": "But of that day and hour no one knoweth: no, not the angels of heaven, but the Father alone.", "bbe": "But of that day and hour no one has knowledge, not even the angels in heaven, or the Son, but the Father only.", "geneva": "But of that day and houre knoweth no man, no not the Angels of heauen, but my father only.", "wycliffe": "But of thilke dai and our no man wote, nethir aungels of heuenes, but the fadir aloone.", "rotherham": "But, concerning that day and hour, no one, knoweth, neither the messengers of the heavens, nor the Son,—save the Father only.", "weymouth": "\"But as to that day and the exact time no one knows--not even the angels of heaven, nor the Son, but the Father alone.", "darby": "But of that day and hour no one knows, not even the angels of the heavens, but [my] Father alone.", "twenty": "But about that Day and Hour, no one knows — not even the angels of Heaven, nor yet the Son — but only the Father himself.", "acv": "But about that day and hour no man knows, not even the agents of the heavens, except my Father only.", "anderson": "But of that day and hour no one knows, not the angels of heaven, but my Father only.", "haweis": "But of that day and hour no man knoweth, not even the angels of heaven, but my Father alone.", "noyes": "But that day and hour knoweth no one, not even the angels of heaven, nor the Son, but the Father only.", "webster": "But of that day and hour knoweth no [man], no, not the angels of heaven, but my Father only.", "vulgate": "de die autem illa et hora nemo scit neque angeli caelorum nisi Pater solus;"}}, {"v": 37, "ref": "24:37", "o": "ὥσπερ ⸀γὰρ αἱ ἡμέραι τοῦ Νῶε, οὕτως ⸀ἔσται ἡ παρουσία τοῦ υἱοῦ τοῦ ἀνθρώπου·", "en": {"kjv": "But as the days of Noe were, so shall also the coming of the Son of man be.", "web": "“As the days of Noah were, so will be the coming of the Son of Man.", "bsb": "As it was in the days of Noah, so will it be at the coming of the Son of Man.", "asv": "And as were the days of Noah, so shall be the coming of the Son of man.", "ylt": "and as the days of Noah--so shall be also the presence of the Son of Man;", "tyndale": "As the tyme of Noe was so lyke wyse shall the cominge of ye sonne of man be.", "dra": "And as in the days of Noe, so shall also the coming of the Son of man be.", "bbe": "And as were the days of Noah, so will be the coming of the Son of man.", "geneva": "But as the dayes of Noe were, so likewise shall the comming of the Sonne of man be.", "wycliffe": "But as it was in the daies of Noe, so schal be the comyng of mannus sone.", "rotherham": "For, just as the days of Noah, so, will be the presence of the Son of Man;", "weymouth": "`For as it was in the time of Noah, so it will be at the Coming of the Son of Man.", "darby": "But as the days of Noe, so also shall be the coming of the Son of man.", "twenty": "For, just as in the days of Noah, so will it be at the Coming of the Son of Man.", "acv": "And as the days of Noah, so also will be the coming of the Son of man.", "anderson": "But as the days of Noah were, so shall be the coming of the Son of man.", "haweis": "But as the days of Noah were, so also shall the coming of the Son of man be.", "noyes": "But as were the days of Noah, so will be the coming of the Son of man.", "webster": "But as the days of Noah [were], so will also the coming of the Son of man be.", "vulgate": "sicut autem in diebus Noe ita erit et adventus Filii hominis;"}}, {"v": 38, "ref": "24:38", "o": "⸀ὡς γὰρ ἦσαν ἐν ταῖς ⸀ἡμέραις ταῖς πρὸ τοῦ κατακλυσμοῦ τρώγοντες καὶ πίνοντες, γαμοῦντες καὶ ⸀γαμίζοντες, ἄχρι ἧς ἡμέρας εἰσῆλθεν Νῶε εἰς τὴν κιβωτόν,", "en": {"kjv": "For as in the days that were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noe entered into the ark,", "web": "For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ship,", "bsb": "For in the days before the flood, people were eating and drinking, marrying and giving in marriage, up to the day Noah entered the ark.", "asv": "For as in those days which were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ark,", "ylt": "for as they were, in the days before the flood, eating, and drinking, marrying, and giving in marriage, till the day Noah entered into the ark,", "tyndale": "For as in ye dayes before ye floud: they dyd eate and drynke mary and were maried eve vnto ye daye that Noe entred into the shyppe", "dra": "For, as in the days before the flood they were eating and drinking, marrying and giving in marriage, even till that day in which Noe entered into the ark:", "bbe": "Because as in those days before the overflowing of the waters, they were feasting and taking wives and getting married, till the day when Noah went into the ark,", "geneva": "For as in the dayes before the flood, they did eate and drinke, marrie, and giue in mariage, vnto the day that Noe entred into the Arke,", "wycliffe": "For as in the daies bifore the greet flood, thei weren etynge and drynkynge, weddynge and takynge to weddyng, to that dai, that Noe entride in to the schippe;", "rotherham": "For, as they were in those days that were before the flood, feeding and drinking, marrying and being given in marriage,—until the day Noah entered into the ark;", "weymouth": "At that time, before the Deluge, men were busy eating and drinking, taking wives or giving them, up to the very day when Noah entered the Ark,", "darby": "For as they were in the days which were before the flood, eating and drinking, marrying and giving in marriage, until the day on which Noe entered into the ark,", "twenty": "In those days before the flood they went on eating and drinking, marrying and being married, up to the very day on which Noah entered the ark,", "acv": "For as in the days before the flood they were eating and drinking, marrying and giving in marriage until that day Noah entered into the ark.", "anderson": "For as in the days before the flood, they were eating and drinking, marrying and giving in marriage, till the day in which Noah entered the ark,", "haweis": "For as they were in the days preceding the deluge, eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ark,", "noyes": "For as in the days before the flood they were eating and drinking, marrying and giving in marriage, until the day when Noah entered the ark,", "webster": "For as in the days that were before the flood, they were eating and drinking, marrying and giving in marriage, until the day that Noah entered into the ark,", "vulgate": "sicut enim erant in diebus ante diluvium comedentes et bibentes nubentes et nuptum tradentes usque ad eum diem quo introivit in arcam Noe;"}}, {"v": 39, "ref": "24:39", "o": "καὶ οὐκ ἔγνωσαν ἕως ἦλθεν ὁ κατακλυσμὸς καὶ ἦρεν ἅπαντας, οὕτως ἔσται ⸀καὶ ἡ παρουσία τοῦ υἱοῦ τοῦ ἀνθρώπου.", "en": {"kjv": "And knew not until the flood came, and took them all away; so shall also the coming of the Son of man be.", "web": "and they didn’t know until the flood came, and took them all away, so will be the coming of the Son of Man.", "bsb": "And they were oblivious, until the flood came and swept them all away. So will it be at the coming of the Son of Man.", "asv": "and they knew not until the flood came, and took them all away; so shall be the coming of the Son of man.", "ylt": "and they did not know till the flood came and took all away; so shall be also the presence of the Son of Man.", "tyndale": "and knewe of nothynge tyll the floude came and toke them all awaye. So shall also the commynge of the sonne of man be.", "dra": "And they knew not till the flood came and took them all away: so also shall the coming of the Son of man be.", "bbe": "And they had no care till the waters came and took them all away; so will be the coming of the Son of man.", "geneva": "And knewe nothing, till the flood came, and tooke them all away, so shall also the comming of the Sonne of man be.", "wycliffe": "and thei knewen not, til the greet flood cam, and took alle men, so schal be the comyng of mannus sone.", "rotherham": "And they observed not, until the flood came and took away all together, so, will be, the presence of the Son of Man.", "weymouth": "nor did they realise any danger till the Deluge came and swept them all away; so will it be at the Coming of the Son of Man.", "darby": "and they knew not till the flood came and took all away; thus also shall be the coming of the Son of man.", "twenty": "taking not notice till the flood came and swept them one and all away; and so will it be at the Coming of the Son of Man.", "acv": "And they knew not until the flood came, and took them all away. So also will be the coming of the Son of man.", "anderson": "and knew not, till the flood came and took them all away: so shall be the coming of the Son of man.", "haweis": "and they knew it not till the deluge came, and swept them all away; such also shall the coming of the Son of man be.", "noyes": "and knew not, until the flood came, and took them all away, so also will be the coming of the Son of man.", "webster": "And knew not until the flood came, and took them all away: so also will be the coming of the Son of man.", "vulgate": "et non cognoverunt donec venit diluvium et tulit omnes ita erit et adventus Filii hominis;"}}, {"v": 40, "ref": "24:40", "o": "τότε ⸂δύο ἔσονται⸃ ἐν τῷ ἀγρῷ, ⸀εἷς παραλαμβάνεται καὶ ⸁εἷς ἀφίεται·", "en": {"kjv": "Then shall two be in the field; the one shall be taken, and the other left.", "web": "Then two men will be in the field: one will be taken and one will be left;", "bsb": "Two men will be in the field: one will be taken and the other left.", "asv": "Then shall two men be in the field; one is taken, and one is left:", "ylt": "Then two men shall be in the field, the one is received, and the one is left;", "tyndale": "Then two shalbe in the feldes the one shalbe receaved and the other shalbe refused", "dra": "Then two shall be in the field. One shall be taken and one shall be left.", "bbe": "Then two men will be in the field; one is taken, and one let go;", "geneva": "Then two shall be in the fieldes, the one shalbe receiued, and the other shalbe refused.", "wycliffe": "Thanne tweyne schulen be in o feeld, oon schal be takun, and another left;", "rotherham": "Then, shall there be two men in the field,—one, is taken near, and, one, is left behind:", "weymouth": "Then will two men be in the open country: one will be taken away, and one left behind.", "darby": "Then two shall be in the field, one is taken and one is left;", "twenty": "At that time, of two men on a farm one will be taken and one left;", "acv": "Then two men will be in the field, one is taken, and one is left.", "anderson": "Then two men shall be in the field; one shall be taken, and the other left.", "haweis": "Then two shall be in the field; the one shall be taken, and the other dismissed.", "noyes": "Then will two men be in the field; one will be taken, and one left.", "webster": "Then will two be in the field; the one shall be taken, and the other left.", "vulgate": "tunc duo erunt in agro unus adsumetur et unus relinquetur;"}}, {"v": 41, "ref": "24:41", "o": "δύο ἀλήθουσαι ἐν τῷ ⸀μύλῳ, μία παραλαμβάνεται καὶ μία ἀφίεται.", "en": {"kjv": "Two women shall be grinding at the mill; the one shall be taken, and the other left.", "web": "two women grinding at the mill, one will be taken and one will be left.", "bsb": "Two women will be grinding at the mill: one will be taken and the other left.", "asv": "two women shall be grinding at the mill; one is taken, and one is left.", "ylt": "two women shall be grinding in the mill, one is received, and one is left.", "tyndale": "two shalbe gryndinge at ye myll: ye oue shalbe receaved and ye other shalbe refused.", "dra": "Two women shall be grinding at the mill. One shall be taken and one shall be left.", "bbe": "Two women will be crushing grain; one is taken, and one let go.", "geneva": "Two women shalbe grinding at ye mill: the one shalbe receiued, and the other shalbe refused.", "wycliffe": "twey wymmen schulen be gryndynge in o queerne, oon schal be takun, and `the tother left; tweyn in a bedde, `the toon schal be takun, and the tother left.", "rotherham": "Two women grinding at the mill,—one, is taken near, and, one, is left behind.", "weymouth": "Two women will be grinding at the mill: one will be taken away, and one left behind.", "darby": "two [women] grinding at the mill, one is taken and one is left.", "twenty": "of two women grinding with the hand-mill one will be taken and one left.", "acv": "Two women grinding at the mill, one is taken, and one is left.", "anderson": "Two women shall be grinding at the mill; one shall be taken, and the other left.", "haweis": "Two women grinding at the mill; the one taken, the other dismissed.", "noyes": "Two women will be grinding at the mill; one will be taken, and one left.", "webster": "Two [women will be] grinding at the mill; the one shall be taken, and the other left.", "vulgate": "duae molentes in mola una adsumetur et una relinquetur;"}}, {"v": 42, "ref": "24:42", "o": "γρηγορεῖτε οὖν, ὅτι οὐκ οἴδατε ποίᾳ ⸀ἡμέρᾳ ὁ κύριος ὑμῶν ἔρχεται.", "en": {"kjv": "Watch therefore: for ye know not what hour your Lord doth come.", "web": "Watch therefore, for you don’t know in what hour your Lord comes.", "bsb": "Therefore keep watch, because you do not know the day on which your Lord will come.", "asv": "Watch therefore: for ye know not on what day your Lord cometh.", "ylt": "`Watch ye therefore, because ye have not known in what hour your Lord doth come;", "tyndale": "Wake therfore because ye knowe not what houre youre master wyll come.", "dra": "Watch ye therefore, because you know not what hour your Lord will come.", "bbe": "Be watching, then! for you have no knowledge on what day your Lord will come.", "geneva": "Watch therefore: for ye knowe not what houre your master will come.", "wycliffe": "Therfor wake ye, for ye witen not in what our the Lord schal come.", "rotherham": "Be watching, therefore, for ye know not, on what manner of day, your Lord is coming.", "weymouth": "Be on the alert therefore, for you do not know the day on which your Lord is coming.", "darby": "Watch therefore, for ye know not in what hour your Lord comes.", "twenty": "Therefore watch; for you cannot be sure on what day your Master is coming.", "acv": "Watch therefore, because ye know not at what hour your Lord comes.", "anderson": "Watch, therefore, for you know not at what hour your Lord is coming.", "haweis": "Watch therefore: for ye know not at what hour your Master cometh.", "noyes": "Watch, therefore, for ye know not on what day your Lord is coming.", "webster": "Watch therefore; for ye know not what hour your Lord cometh.", "vulgate": "vigilate ergo quia nescitis qua hora Dominus vester venturus sit;"}}, {"v": 43, "ref": "24:43", "o": "ἐκεῖνο δὲ γινώσκετε ὅτι εἰ ᾔδει ὁ οἰκοδεσπότης ποίᾳ φυλακῇ ὁ κλέπτης ἔρχεται, ἐγρηγόρησεν ἂν καὶ οὐκ ἂν εἴασεν διορυχθῆναι τὴν οἰκίαν αὐτοῦ.", "en": {"kjv": "But know this, that if the goodman of the house had known in what watch the thief would come, he would have watched, and would not have suffered his house to be broken up.", "web": "But know this, that if the master of the house had known in what watch of the night the thief was coming, he would have watched, and would not have allowed his house to be broken into.", "bsb": "But understand this: If the homeowner had known in which watch of the night the thief was coming, he would have kept watch and would not have let his house be broken into.", "asv": "But know this, that if the master of the house had known in what watch the thief was coming, he would have watched, and would not have suffered his house to be broken through.", "ylt": "and this know, that if the master of the house had known in what watch the thief doth come, he had watched, and not suffered his house to be broken through;", "tyndale": "Of this be sure that yf the good man of the housse knewe what houre the thefe wolde come: he wolde suerly watche and not suffre his housse to be broke vppe.", "dra": "But this know ye, that, if the goodman of the house knew at what hour the thief would come, he would certainly watch and would not suffer his house to be broken open.", "bbe": "But be certain of this, that if the master of the house had had knowledge of the time when the thief was coming, he would have been watching, and would not have let his house be broken into.", "geneva": "Of this be sure, that if the good man of the house knewe at what watch the thiefe would come, he woulde surely watch, and not suffer his house to be digged through.", "wycliffe": "But wite ye this, that if the hosebonde man wiste in what our the thefe were to come, certis he wolde wake, and suffre not his hous to be vndurmyned.", "rotherham": "But there is, one thing, ye know—That, if the householder, had known, in what watch, the thief was coming, he would have been on the alert, and not have suffered his house to be dug through.", "weymouth": "But of this be assured, that if the master of the house had known the hour at which the robber was coming, he would have kept awake, and not have allowed his house to be broken into.", "darby": "But know this, that if the master of the house had known in what watch the thief was coming, he would have watched and not have suffered his house to be dug through [into].", "twenty": "But this you do know, that, had the owner of the house known at what time of night the thief was coming, he would have been on the watch, and would not have allowed his house to be broken into.", "acv": "But know this, that if the house-ruler had known in what watch the thief was coming, he would have watched, and would not have allowed his house to be broken into.", "anderson": "But know this, That if the master of the house had known at what watch the thief comes, he would have watched, and would not have permitted his house to be broken open.", "haweis": "And this observe, that if the master of the family had known in which watch of the night the thief would have come, he would have watched, and not have suffered him to break into his house.", "noyes": "But be sure of this, that if the master of the house had known in what watch the thief was coming, he would have watched, and would not have suffered his house to be broken through.", "webster": "But know this, that if the master of the house knew in what watch the thief would come, he would watch, and would not suffer his house to be broken up.", "vulgate": "illud autem scitote quoniam si sciret pater familias qua hora fur venturus esset vigilaret utique et non sineret perfodiri domum suam;"}}, {"v": 44, "ref": "24:44", "o": "διὰ τοῦτο καὶ ὑμεῖς γίνεσθε ἕτοιμοι, ὅτι ᾗ ⸂οὐ δοκεῖτε ὥρᾳ⸃ ὁ υἱὸς τοῦ ἀνθρώπου ἔρχεται.", "en": {"kjv": "Therefore be ye also ready: for in such an hour as ye think not the Son of man cometh.", "web": "Therefore also be ready, for in an hour that you don’t expect, the Son of Man will come.", "bsb": "For this reason, you also must be ready, because the Son of Man will come at an hour you do not expect.", "asv": "Therefore be ye also ready; for in an hour that ye think not the Son of man cometh.", "ylt": "because of this also ye, become ye ready, because in what hour ye do not think, the Son of Man doth come.", "tyndale": "Therfore be ye also redy for in ye houre ye thinke he wolde not: wyll the sonne of ma come.", "dra": "Wherefore be you also ready, because at what hour you know not the Son of man will come.", "bbe": "Be ready then; for at a time which you have no thought of the Son of man will come.", "geneva": "Therefore be ye also ready: for in the houre that ye thinke not, will the Sonne of man come.", "wycliffe": "And therfor be ye redi, for in what our ye gessen not, mannus sone schal come.", "rotherham": "Wherefore, ye also, be getting ready, because, in what hour ye are, not thinking, The Son of Man doth come.", "weymouth": "Therefore you also must be ready; for it is at a time when you do not expect Him that the Son of Man will come.", "darby": "Wherefore ye also, be ye ready, for in that hour that ye think not the Son of man comes.", "twenty": "Therefore, do you also prepare, since it is just when you are least expecting him that the Son of Man will come.", "acv": "Because of this ye also be ready, because in that hour ye think not the Son of man comes.", "anderson": "For this reason, be you also ready; for at an hour in which you think not, the Son of man comes.", "haweis": "Therefore be ye also prepared: for in an hour that ye think not, the Son of man cometh.", "noyes": "Therefore be ye also ready; for at an hour when ye think not, the Son of man cometh.", "webster": "Therefore be ye also ready: for in such an hour as ye think not, the Son of man cometh.", "vulgate": "ideoque et vos estote parati quia qua nescitis hora Filius hominis venturus est;"}}, {"v": 45, "ref": "24:45", "o": "Τίς ἄρα ἐστὶν ὁ πιστὸς δοῦλος καὶ φρόνιμος ὃν κατέστησεν ὁ ⸀κύριος ἐπὶ τῆς ⸀οἰκετείας αὐτοῦ τοῦ ⸀δοῦναι αὐτοῖς τὴν τροφὴν ἐν καιρῷ;", "en": {"kjv": "Who then is a faithful and wise servant, whom his lord hath made ruler over his household, to give them meat in due season?", "web": "“Who then is the faithful and wise servant, whom his lord has set over his household, to give them their food in due season?", "bsb": "Who then is the faithful and wise servant, whom the master has put in charge of his household, to give the others their food at the proper time?", "asv": "Who then is the faithful and wise servant, whom his lord hath set over his household, to give them their food in due season?", "ylt": "`Who, then, is the servant, faithful and wise, whom his lord did set over his household, to give them the nourishment in season?", "tyndale": "If there be any faithfull servaut and wyse whome his master hath made ruler over his housholde to geve the meate in season covenient:", "dra": "Who, thinkest thou, is a faithful and wise servant, whom his lord hath appointed over his family, to give them meat in season?", "bbe": "Who is the true and wise servant, whom his lord has put over those in his house, to give them their food at the right time?", "geneva": "Who then is a faithfull seruaunt and wise, whom his master hath made ruler ouer his household, to giue them meate in season?", "wycliffe": "Who gessist thou is a trewe seruaunt and prudent, whom his lord ordeyned on his meynee, to yyue hem mete in tyme?", "rotherham": "Who then is the faithful and prudent servant, whom the master hath appointed over his household, to give them food in season?", "weymouth": "\"Who therefore is the loyal and intelligent servant to whom his master has entrusted the control of his household to give them their rations at the appointed time?", "darby": "Who then is the faithful and prudent bondman whom his lord has set over his household, to give them food in season?", "twenty": "Who, then is that trustworthy, careful servant, who has been placed by his master over his household, to give them their food at the proper time?", "acv": "Who then is the faithful and wise bondman, whom his lord appointed over his service, to give them the provision on time?", "anderson": "Who then is that faithful and wise servant, whom his master has made ruler over his household servants, to give them their food in due time?", "haweis": "Who then is the faithful and provident servant, whom his Lord hath appointed over his household, to give them meat in the proper time?", "noyes": "Who then is the faithful and wise servant, whom his lord placed over his household, to give them their food in due season?", "webster": "Who then is a faithful and wise servant, whom his Lord hath made ruler over his household, to give them food in due season?", "vulgate": "quis putas est fidelis servus et prudens quem constituit dominus suus supra familiam suam ut det illis cibum in tempore;"}}, {"v": 46, "ref": "24:46", "o": "μακάριος ὁ δοῦλος ἐκεῖνος ὃν ἐλθὼν ὁ κύριος αὐτοῦ εὑρήσει ⸂οὕτως ποιοῦντα⸃·", "en": {"kjv": "Blessed is that servant, whom his lord when he cometh shall find so doing.", "web": "Blessed is that servant whom his lord finds doing so when he comes.", "bsb": "Blessed is that servant whose master finds him doing so when he returns.", "asv": "Blessed is that servant, whom his lord when he cometh shall find so doing.", "ylt": "Happy that servant, whom his lord, having come, shall find doing so;", "tyndale": "happy is that servaunt whom his master (when he cometh) shall finde so doinge.", "dra": "Blessed is that servant, whom when his lord shall come he shall find so doing.", "bbe": "A blessing on that servant, who will be doing so when his lord comes.", "geneva": "Blessed is that seruant, whom his master when he commeth, shall finde so doing.", "wycliffe": "Blessed is that seruaunt, whom `his lord, whanne he schal come, schal fynde so doynge.", "rotherham": "Happy! that servant, whom his master, when he cometh, shall find so doing!", "weymouth": "Blessed is that servant whom his master when he comes shall find so doing!", "darby": "Blessed is that bondman whom his lord on coming shall find doing thus.", "twenty": "Happy will that servant be whom his master, when he comes home, shall find doing this.", "acv": "Blessed is that bondman, whom his lord when he comes will find so doing.", "anderson": "Blessed is that servant, whom his master, when he comes, shall find so doing.", "haweis": "Blessed is that servant whom his Lord when he cometh shall find thus occupied.", "noyes": "Happy is that servant whom his lord, when he cometh, shall find so doing.", "webster": "Blessed [is] that servant, whom his lord, when he cometh, shall find so doing.", "vulgate": "beatus ille servus quem cum venerit dominus eius invenerit sic facientem;"}}, {"v": 47, "ref": "24:47", "o": "ἀμὴν λέγω ὑμῖν ὅτι ἐπὶ πᾶσιν τοῖς ὑπάρχουσιν αὐτοῦ καταστήσει αὐτόν.", "en": {"kjv": "Verily I say unto you, That he shall make him ruler over all his goods.", "web": "Most certainly I tell you that he will set him over all that he has.", "bsb": "Truly I tell you, he will put him in charge of all his possessions.", "asv": "Verily I say unto you, that he will set him over all that he hath.", "ylt": "verily I say to you, that over all his substance he will set him.", "tyndale": "Verely I saye vnto you he shall make him ruler over all his goodes.", "dra": "Amen I say to you: he shall place him over all his goods.", "bbe": "Truly, I say to you, he will put him over all he has.", "geneva": "Verely I say vnto you, he shall make him ruler ouer all his goods.", "wycliffe": "Treuli Y seye to you, for on alle his goodis he schal ordeyne hym.", "rotherham": "Verily, I say unto you—Over all his substance, will he appoint him.", "weymouth": "In solemn truth I tell you that he will give him the management of all his wealth.", "darby": "Verily I say unto you, that he will set him over all his substance.", "twenty": "I tell you that his master will put him in charge of the whole of his property.", "acv": "Truly I say to you, that he will appoint him over all things being possessed by him.", "anderson": "Verily I say to you, That he will make him ruler over all his goods.", "haweis": "Verily I say unto you, that he will place him over all his substance.", "noyes": "Truly do I say to you, that he will place him in charge of all his substance.", "webster": "Verily I say to you, that he will make him ruler over all his goods.", "vulgate": "amen dico vobis quoniam super omnia bona sua constituet eum;"}}, {"v": 48, "ref": "24:48", "o": "ἐὰν δὲ εἴπῃ ὁ κακὸς δοῦλος ἐκεῖνος ἐν τῇ καρδίᾳ αὐτοῦ· Χρονίζει ⸂μου ὁ κύριος⸃,", "en": {"kjv": "But and if that evil servant shall say in his heart, My lord delayeth his coming;", "web": "But if that evil servant should say in his heart, ‘My lord is delaying his coming,’", "bsb": "But suppose that servant is wicked and says in his heart, ‘My master will be away a long time.’", "asv": "But if that evil servant shall say in his heart, My lord tarrieth;", "ylt": "`And, if that evil servant may say in his heart, My Lord doth delay to come,", "tyndale": "But and yf that evill servaut shall saye in his herte my master wyll defer his comynge", "dra": "But if that evil servant shall say in his heart: My lord is long a coming:", "bbe": "But if that evil servant says in his heart, My lord is a long time in coming;", "geneva": "But if that euil seruant shall say in his heart, My master doth deferre his comming,", "wycliffe": "But if thilke yuel seruaunt seie in his herte, My lord tarieth to come,", "rotherham": "But, if that wicked servant should say in his heart—My master, delayeth,", "weymouth": "But if the man, being a bad servant, should say in his heart, `My master is a long time in coming,'", "darby": "But if that evil bondman should say in his heart, My lord delays to come,", "twenty": "But, should he be a bad servant, and say to himself ‘My master is a long time in coming,’", "acv": "But if that evil bondman should say in his heart, My lord is late coming,", "anderson": "But if that wicked servant shall say in his heart, My master delays his coming;", "haweis": "But if that wicked servant say in his heart, My master will be a long while ere he comes;", "noyes": "But if the bad servant say in his heart, My lord is tarrying long;", "webster": "But if that evil servant shall say in his heart, My Lord delayeth his coming;", "vulgate": "si autem dixerit malus servus ille in corde suo moram facit dominus meus venire;"}}, {"v": 49, "ref": "24:49", "o": "καὶ ἄρξηται τύπτειν τοὺς συνδούλους ⸂αὐτοῦ, ἐσθίῃ δὲ καὶ πίνῃ⸃ μετὰ τῶν μεθυόντων,", "en": {"kjv": "And shall begin to smite his fellowservants, and to eat and drink with the drunken;", "web": "and begins to beat his fellow servants, and eat and drink with the drunkards,", "bsb": "And he begins to beat his fellow servants and to eat and drink with drunkards.", "asv": "and shall begin to beat his fellow-servants, and shall eat and drink with the drunken;", "ylt": "and may begin to beat the fellow-servants, and to eat and to drink with the drunken,", "tyndale": "and beginne to smyte his felowes ye and to eate and to drinke with the dronke:", "dra": "And shall begin to strike his fellow servants and shall eat and drink with drunkards:", "bbe": "And is cruel to the other servants, taking his pleasure with those who are overcome with wine;", "geneva": "And begin to smite his fellowes, and to eate, and to drinke with the drunken,", "wycliffe": "and bigynneth to smyte hise euen seruauntis, and ete, and drynke with drunken men;", "rotherham": "And begin to be striking his fellow-servants, and eating and drinking with the drunken,", "weymouth": "and should begin to beat his fellow servants, while he eats and drinks with drunkards;", "darby": "and begin to beat his fellow-bondmen, and eat and drink with the drunken;", "twenty": "and begin to beat his fellow-servants, and eat and drink with drunkards,", "acv": "and should begin to beat the fellow bondmen, and to eat and drink with the drunken,", "anderson": "and shall begin to strike his fellow-servants, and shall eat and drink with the drunken;", "haweis": "and shall begin to beat his fellow-servants, and to eat and drink with the drunken;", "noyes": "and begin to beat his fellow-servants, and eat and drink with the drunken,", "webster": "And shall begin to beat [his] fellow-servants, and to eat and drink with the drunken;", "vulgate": "et coeperit percutere conservos suos manducet autem et bibat cum ebriis;"}}, {"v": 50, "ref": "24:50", "o": "ἥξει ὁ κύριος τοῦ δούλου ἐκείνου ἐν ἡμέρᾳ ᾗ οὐ προσδοκᾷ καὶ ἐν ὥρᾳ ᾗ οὐ γινώσκει,", "en": {"kjv": "The lord of that servant shall come in a day when he looketh not for him, and in an hour that he is not aware of,", "web": "the lord of that servant will come in a day when he doesn’t expect it, and in an hour when he doesn’t know it,", "bsb": "The master of that servant will come on a day he does not expect and at an hour he does not anticipate.", "asv": "the lord of that servant shall come in a day when he expecteth not, and in an hour when he knoweth not,", "ylt": "the lord of that servant will arrive in a day when he doth not expect, and in an hour of which he doth not know,", "tyndale": "that servauntes master wyll come in adaye when he loketh not for him and in an houre yt he is not ware of", "dra": "The lord of that servant shall come in a day that he hopeth not and at an hour that he knoweth not:", "bbe": "The lord of that servant will come in a day when he is not looking for him, and in an hour of which he has no knowledge,", "geneva": "That seruaunts master will come in a day, when he looketh not for him, and in an houre that he is not ware of,", "wycliffe": "the lord of that seruaunt schal come in the dai which he hopith not, and in the our that he knowith not,", "rotherham": "The master of that servant, will have come, on a day when he is not expecting, and in an hour when he is not observing,—", "weymouth": "the master of that servant will arrive on a day when he is not expecting him and at an hour of which he has not been informed;", "darby": "the lord of that bondman shall come in a day when he does not expect it, and in an hour he knows not of,", "twenty": "that servant’s master will come on a day when he does not expect him, and at an hour of which he is unaware,", "acv": "the lord of that bondman will come in a day that he does not expect, and in an hour that he is not aware,", "anderson": "the master of that servant will come in a day in which he looks not for him, and at an hour which he knows not,", "haweis": "the master of that servant will come in a day that he doth not expect him, and at an hour which he knoweth not.", "noyes": "the lord of that servant will come in a day when he looketh not for it, and at an hour when he is not aware;", "webster": "The Lord of that servant will come in a day when he looketh not for [him], and in an hour that he is not aware of,", "vulgate": "veniet dominus servi illius in die qua non sperat et hora qua ignorat;"}}, {"v": 51, "ref": "24:51", "o": "καὶ διχοτομήσει αὐτὸν καὶ τὸ μέρος αὐτοῦ μετὰ τῶν ὑποκριτῶν θήσει· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "And shall cut him asunder, and appoint him his portion with the hypocrites: there shall be weeping and gnashing of teeth.", "web": "and will cut him in pieces, and appoint his portion with the hypocrites. There is where the weeping and grinding of teeth will be.", "bsb": "Then he will cut him to pieces and assign him a place with the hypocrites, where there will be weeping and gnashing of teeth.", "asv": "and shall cut him asunder, and appoint his portion with the hypocrites: there shall be the weeping and the gnashing of teeth.", "ylt": "and will cut him off, and his portion with the hypocrites will appoint; there shall be the weeping and the gnashing of the teeth.", "tyndale": "and wyll devyde him and geve him his rewarde with ypocrites. There shalbe wepinge and gnasshinge of tethe.", "dra": "And shall separate him and appoint his portion with the hypocrites. There shall be weeping and gnashing of teeth.", "bbe": "And will have him cut in two, and will give him a part in the fate of the false ones: there will be weeping and cries of sorrow.", "geneva": "And will cut him off, and giue him his portion with hypocrites: there shalbe weeping, and gnashing of teeth.", "wycliffe": "and schal departe hym, and putte his part with ypocritis; there schal be wepyng, and gryntyng of teeth.", "rotherham": "And will cut him asunder; and, his part, with the hypocrites, will appoint: There, shall be wailing and gnashing of teeth!", "weymouth": "he will treat him with the utmost severity and assign him a place among the hypocrites: there will be the weeping and the gnashing of teeth.", "darby": "and shall cut him in two and appoint his portion with the hypocrites: there shall be the weeping and the gnashing of teeth.", "twenty": "and will flog him severely, and assign him his place among the hypocrites, where there will be weeping and grinding of teeth.", "acv": "and he will cut him in two, and place his share with the hypocrites. There will be the weeping and the gnashing of teeth.", "anderson": "and will cut him in two, and appoint him his part with the hypocrites. There shall be weeping and gnashing of teeth.", "haweis": "And will cut him asunder, and give him his portion with the hypocrites: there shall be weeping and gnashing of teeth.", "noyes": "and will cut him asunder, and appoint him his portion with the hypocrites; there will be wailing and gnashing of teeth.", "webster": "And will cut him asunder, and appoint [him] his portion with the hypocrites: there shall be weeping and gnashing of teeth.", "vulgate": "et dividet eum partemque eius ponet cum hypocritis illic erit fletus et stridor dentium;"}}]}, {"c": 25, "verses": [{"v": 1, "ref": "25:1", "o": "Τότε ὁμοιωθήσεται ἡ βασιλεία τῶν οὐρανῶν δέκα παρθένοις, αἵτινες λαβοῦσαι τὰς λαμπάδας ⸀ἑαυτῶν ἐξῆλθον εἰς ⸀ὑπάντησιν τοῦ νυμφίου.", "en": {"kjv": "Then shall the kingdom of heaven be likened unto ten virgins, which took their lamps, and went forth to meet the bridegroom.", "web": "“Then the Kingdom of Heaven will be like ten virgins, who took their lamps, and went out to meet the bridegroom.", "bsb": "“At that time the kingdom of heaven will be like ten virgins who took their lamps and went out to meet the bridegroom.", "asv": "Then shall the kingdom of heaven be likened unto ten virgins, who took their lamps, and went forth to meet the bridegroom.", "ylt": "`Then shall the reign of the heavens be likened to ten virgins, who, having taken their lamps, went forth to meet the bridegroom;", "tyndale": "Then ye kyngdome of heven shalbe lykened vnto .x. virgins which toke their lampes and wet to mete the brydgrome:", "dra": "Then shall the kingdom of heaven be like to ten virgins, who taking their lamps went out to meet the bridegroom and the bride.", "bbe": "Then the kingdom of heaven will be like ten virgins, the friends of the bride, who took their lights, and went out with the purpose of meeting the husband.", "geneva": "Then the kingdome of heauen shalbe likened vnto tenne virgins, which tooke their lampes, and went foorth to meete the bridegrome.", "wycliffe": "Thanne the kyngdoom of heuenes schal be lijk to ten virgyns, whiche token her laumpis, and wenten out ayens the hosebonde and the wijf;", "rotherham": "Then, will the kingdom of the heavens become like unto, ten virgins, who, taking their torches, went forth to meet the bridegroom.", "weymouth": "\"Then will the Kingdom of the Heavens be found to be like ten bridesmaids who took their torches and went out to meet the bridegroom.", "darby": "Then shall the kingdom of the heavens be made like to ten virgins that having taken their torches, went forth to meet the bridegroom.", "twenty": "Then the Kingdom of Heaven will be like ten bridesmaids who took their lamps and went out to meet the bridegroom.", "acv": "Then the kingdom of heaven will be like ten virgins, who, having taken their lamps, went forth to the bridegroom's gathering.", "anderson": "Then shall the kingdom of heaven be likened to ten virgins, who took their lamps and went out to meet the bride-groom.", "haweis": "THEN shall the kingdom of heaven be like to ten virgins, who taking their lamps, went forth to meet the bridegroom.", "noyes": "Then the kingdom of heaven will be like ten virgins, who took their lamps, and went out to meet the bridegroom.", "webster": "Then shall the kingdom of heaven be likened to ten virgins, who took their lamps, and went forth to meet the bridegroom.", "vulgate": "tunc simile erit regnum caelorum decem virginibus quae accipientes lampadas suas exierunt obviam sponso et sponsae;"}}, {"v": 2, "ref": "25:2", "o": "πέντε δὲ ⸂ἐξ αὐτῶν ἦσαν⸃ ⸂μωραὶ καὶ πέντε φρόνιμοι⸃.", "en": {"kjv": "And five of them were wise, and five were foolish.", "web": "Five of them were foolish, and five were wise.", "bsb": "Five of them were foolish, and five were wise.", "asv": "And five of them were foolish, and five were wise.", "ylt": "and five of them were prudent, and five foolish;", "tyndale": "fyve of them were folysshe and fyve were wyse.", "dra": "And five of them were foolish and five wise.", "bbe": "And five of them were foolish, and five were wise.", "geneva": "And fiue of them were wise, and fiue foolish.", "wycliffe": "and fyue of hem weren foolis, and fyue prudent.", "rotherham": "Now, five of them, were foolish, and, five, prudent.", "weymouth": "Five of them were foolish and five were wise.", "darby": "And five of them were prudent and five foolish.", "twenty": "Five of them were foolish, and five were prudent.", "acv": "And five of them were wise, and five were foolish,", "anderson": "Five of them were wise, and five were foolish.", "haweis": "But five of them were provident, and five foolish.", "noyes": "And five of them were foolish, and five wise.", "webster": "And five of them were wise, and five [were] foolish.", "vulgate": "quinque autem ex eis erant fatuae et quinque prudentes;"}}, {"v": 3, "ref": "25:3", "o": "⸂αἱ γὰρ⸃ μωραὶ λαβοῦσαι τὰς λαμπάδας αὐτῶν οὐκ ἔλαβον μεθ’ ἑαυτῶν ἔλαιον·", "en": {"kjv": "They that were foolish took their lamps, and took no oil with them:", "web": "Those who were foolish, when they took their lamps, took no oil with them,", "bsb": "The foolish ones took their lamps but did not take along any extra oil.", "asv": "For the foolish, when they took their lamps, took no oil with them:", "ylt": "they who were foolish having taken their lamps, did not take with themselves oil;", "tyndale": "The folysshe toke their lampes but toke none oyle wt the.", "dra": "But the five foolish, having taken their lamps, did not take oil with them.", "bbe": "For the foolish, when they took their lights, took no oil with them.", "geneva": "The foolish tooke their lampes, but tooke none oyle with them.", "wycliffe": "But the fyue foolis token her laumpis, and token not oile with hem;", "rotherham": "For, the foolish—though they took, their torches, took not with them, oil:", "weymouth": "For the foolish, when they took their torches, did not provide themselves with oil;", "darby": "They that were foolish took their torches and did not take oil with them;", "twenty": "The foolish ones took their lamps, but took no oil with them;", "acv": "foolish women, who, having taken their lamps, took no olive oil with them.", "anderson": "Those who were foolish took their lamps, and took no oil with them:", "haweis": "Those who were taking their lamps, took no oil with them:", "noyes": "For the foolish took their lamps, and took no oil with them.", "webster": "They that [were] foolish took their lamps, and took no oil with them:", "vulgate": "sed quinque fatuae acceptis lampadibus non sumpserunt oleum secum;"}}, {"v": 4, "ref": "25:4", "o": "αἱ δὲ φρόνιμοι ἔλαβον ἔλαιον ἐν τοῖς ⸀ἀγγείοις μετὰ τῶν λαμπάδων ⸀ἑαυτῶν.", "en": {"kjv": "But the wise took oil in their vessels with their lamps.", "web": "but the wise took oil in their vessels with their lamps.", "bsb": "But the wise ones took oil in flasks along with their lamps.", "asv": "but the wise took oil in their vessels with their lamps.", "ylt": "and the prudent took oil in their vessels, with their lamps.", "tyndale": "But ye wyse tooke oyle wt the in their vesselles wt their lampes also.", "dra": "But the wise took oil in their vessels with the lamps.", "bbe": "But the wise took oil in their vessels with their lights.", "geneva": "But the wise tooke oyle in their vessels with their lampes.", "wycliffe": "but the prudent token oile in her vessels with the laumpis.", "rotherham": "But, the prudent, took oil in their vessels, with their torches.", "weymouth": "but the wise, besides their torches, took oil in their flasks.", "darby": "but the prudent took oil in their vessels with their torches.", "twenty": "while the prudent ones, besides taking their lamps, took oil in their jars.", "acv": "But the wise took olive oil in their vessels with their lamps.", "anderson": "but the wise took oil in their vessels, with their lamps.", "haweis": "but the provident took oil in their vessels with their lamps.", "noyes": "But the wise took oil in their vessels with their lamps.", "webster": "But the wise took oil in their vessels with their lamps.", "vulgate": "prudentes vero acceperunt oleum in vasis suis cum lampadibus;"}}, {"v": 5, "ref": "25:5", "o": "χρονίζοντος δὲ τοῦ νυμφίου ἐνύσταξαν πᾶσαι καὶ ἐκάθευδον.", "en": {"kjv": "While the bridegroom tarried, they all slumbered and slept.", "web": "Now while the bridegroom delayed, they all slumbered and slept.", "bsb": "When the bridegroom was delayed, they all became drowsy and fell asleep.", "asv": "Now while the bridegroom tarried, they all slumbered and slept.", "ylt": "`And the bridegroom tarrying, they all nodded and were sleeping,", "tyndale": "Whill the brydgrome taryed all slombred and slepte.", "dra": "And the bridegroom tarrying, they all slumbered and slept.", "bbe": "Now the husband was a long time in coming, and they all went to sleep.", "geneva": "Nowe while the bridegrome taried long, all slumbred and slept.", "wycliffe": "And whilis the hosebonde tariede, alle thei nappiden and slepten.", "rotherham": "Now, the bridegroom, delaying, they all became drowsy, and were sleeping.", "weymouth": "The bridegroom was a long time in coming, so that meanwhile they all became drowsy and fell asleep.", "darby": "Now the bridegroom tarrying, they all grew heavy and slept.", "twenty": "As the bridegroom was late in coming, they all became drowsy, and slept.", "acv": "Now while the bridegroom delayed, they all slumbered and slept.", "anderson": "While the bridegroom delayed, they all slumbered and slept.", "haweis": "But as the bridegroom stayed long, they all slumbered and slept.", "noyes": "And as the bridegroom tarried, they all slumbered and slept.", "webster": "While the bridegroom tarried, they all slumbered and slept.", "vulgate": "moram autem faciente sponso dormitaverunt omnes et dormierunt;"}}, {"v": 6, "ref": "25:6", "o": "μέσης δὲ νυκτὸς κραυγὴ γέγονεν· Ἰδοὺ ὁ ⸀νυμφίος, ἐξέρχεσθε εἰς ἀπάντησιν ⸀αὐτοῦ.", "en": {"kjv": "And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him.", "web": "But at midnight there was a cry, ‘Behold! The bridegroom is coming! Come out to meet him!’", "bsb": "At midnight the cry rang out: ‘Here is the bridegroom! Come out to meet him!’", "asv": "But at midnight there is a cry, Behold, the bridegroom! Come ye forth to meet him.", "ylt": "and in the middle of the night a cry was made, Lo, the bridegroom doth come; go ye forth to meet him.", "tyndale": "And even at mydnyght there was a crye made: beholde the brydgrome cometh goo out against him.", "dra": "And at midnight there was a cry made: Behold the bridegroom cometh. Go ye forth to meet him.", "bbe": "But in the middle of the night there is a cry, The husband comes! Go out to him.", "geneva": "And at midnight there was a crie made, Behold, the bridegrome commeth: goe out to meete him.", "wycliffe": "But at mydnyyt a cryy was maad, Lo! the spouse cometh, go ye oute to mete with him.", "rotherham": "And, at midnight, an outcry hath been made—Lo! the bridegroom! Be going forth to meet him!", "weymouth": "But at midnight there is a loud cry, \"`The bridegroom! Go out and meet him!'", "darby": "But in [the] middle of [the] night there was a cry, Behold, the bridegroom; go forth to meet him.", "twenty": "But at midnight a shout was raised — ‘The bridegroom is coming! Come out to meet him!’", "acv": "But at midnight a shout occurred, Behold, the bridegroom comes! Go ye forth for his gathering.", "anderson": "And at midnight a cry was made: Behold, the bridegroom comes! Go you out to meet him.", "haweis": "Then at midnight the cry came, Behold, the bridegroom is coming; go forth to meet him.", "noyes": "But at midnight there was a cry, Lo! the bridegroom! go out to meet him.", "webster": "And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him.", "vulgate": "media autem nocte clamor factus est ecce sponsus venit exite obviam ei;"}}, {"v": 7, "ref": "25:7", "o": "τότε ἠγέρθησαν πᾶσαι αἱ παρθένοι ἐκεῖναι καὶ ἐκόσμησαν τὰς λαμπάδας ⸀ἑαυτῶν.", "en": {"kjv": "Then all those virgins arose, and trimmed their lamps.", "web": "Then all those virgins arose, and trimmed their lamps.", "bsb": "Then all the virgins woke up and trimmed their lamps.", "asv": "Then all those virgins arose, and trimmed their lamps.", "ylt": "`Then rose all those virgins, and trimmed their lamps,", "tyndale": "Then all those virgins arose and prepared their lampes.", "dra": "Then all those virgins arose and trimmed their lamps.", "bbe": "Then all those virgins got up, and made ready their lights.", "geneva": "Then all those virgins arose, and trimmed their lampes.", "wycliffe": "Thanne alle tho virgyns risen vp, and araieden her laumpis.", "rotherham": "Then, arose all those virgins, and trimmed their torches.", "weymouth": "\"Then all those bridesmaids roused themselves and trimmed their torches.", "darby": "Then all those virgins arose and trimmed their torches.", "twenty": "Then all the bridesmaids awoke and trimmed their lamps.", "acv": "Then all those virgins were roused, and put their lamps in order.", "anderson": "Then all those virgins arose, and trimmed their lamps.", "haweis": "Then all these virgins arose, and set about trimming their lamps.", "noyes": "Then all those virgins arose, and trimmed their lamps.", "webster": "Then all those virgins arose, and trimmed their lamps.", "vulgate": "tunc surrexerunt omnes virgines illae et ornaverunt lampades suas;"}}, {"v": 8, "ref": "25:8", "o": "αἱ δὲ μωραὶ ταῖς φρονίμοις εἶπαν· Δότε ἡμῖν ἐκ τοῦ ἐλαίου ὑμῶν, ὅτι αἱ λαμπάδες ἡμῶν σβέννυνται.", "en": {"kjv": "And the foolish said unto the wise, Give us of your oil; for our lamps are gone out.", "web": "The foolish said to the wise, ‘Give us some of your oil, for our lamps are going out.’", "bsb": "The foolish ones said to the wise, ‘Give us some of your oil; our lamps are going out.’", "asv": "And the foolish said unto the wise, Give us of your oil; for our lamps are going out.", "ylt": "and the foolish said to the prudent, Give us of your oil, because our lamps are going out;", "tyndale": "And ye folysshe sayde to ye wyse: geve vs of youre oyle for our lampes goo out?", "dra": "And the foolish said to the wise: Give us of your oil, for our lamps are gone out.", "bbe": "And the foolish said to the wise, Give us of your oil; for our lights are going out.", "geneva": "And the foolish said to the wise, Giue vs of your oyle, for our lampes are out.", "wycliffe": "And the foolis seiden to the wise, Yyue ye to vs of youre oile, for oure laumpis ben quenchid.", "rotherham": "And, the foolish, unto the prudent, said—Give us of your oil, because, our torches, are going out.", "weymouth": "\"`Give us some of your oil,' said the foolish ones to the wise, `for our torches are going out.'", "darby": "And the foolish said to the prudent, Give us of your oil, for our torches are going out.", "twenty": "And the foolish said to the prudent ‘Give us some of your oil; our lamps are going out.’", "acv": "And the foolish said to the wise, Give us from your olive oil, because our lamps are going out.", "anderson": "And the foolish said to the wise: Give us of your oil, for our lamps are going out.", "haweis": "And the foolish said to the provident, Give us of your oil; for our lamps are gone out.", "noyes": "And the foolish said to the wise, Give us of your oil, for our lamps are going out.", "webster": "And the foolish said to the wise, Give us of your oil: for our lamps are gone out.", "vulgate": "fatuae autem sapientibus dixerunt date nobis de oleo vestro quia lampades nostrae extinguntur;"}}, {"v": 9, "ref": "25:9", "o": "ἀπεκρίθησαν δὲ αἱ φρόνιμοι λέγουσαι· Μήποτε ⸂οὐ μὴ⸃ ἀρκέσῃ ἡμῖν καὶ ὑμῖν· ⸀πορεύεσθε μᾶλλον πρὸς τοὺς πωλοῦντας καὶ ἀγοράσατε ἑαυταῖς.", "en": {"kjv": "But the wise answered, saying, Not so; lest there be not enough for us and you: but go ye rather to them that sell, and buy for yourselves.", "web": "But the wise answered, saying, ‘What if there isn’t enough for us and you? You go rather to those who sell, and buy for yourselves.’", "bsb": "‘No,’ said the wise ones, ‘or there may not be enough for both us and you. Instead, go to those who sell oil and buy some for yourselves.’", "asv": "But the wise answered, saying, Peradventure there will not be enough for us and you: go ye rather to them that sell, and buy for yourselves.", "ylt": "and the prudent answered, saying--Lest there may not be sufficient for us and you, go ye rather unto those selling, and buy for yourselves.", "tyndale": "but ye wyse answered sayinge. Not so lest ther be not ynough for vs and you: but goo rather to them yt sell and by for youre selves.", "dra": "The wise answered, saying: Lest perhaps there be not enough for us and for you, go ye rather to them that sell and buy for yourselves.", "bbe": "But the wise made answer, saying, There may not be enough for us and you; it would be better for you to go to the traders and get oil for yourselves.", "geneva": "But the wise answered, saying, Not so, lest there will not be ynough for vs and you: but goe ye rather to them that sell, and bye for your selues.", "wycliffe": "The prudent answeriden, and seiden, Lest perauenture it suffice not to vs and to you, go ye rather to men that sellen, and bie to you.", "rotherham": "But the prudent, answered, saying—Lest once, by any means, there be not enough for us and you, be going rather unto them that sell, and buy for yourselves", "weymouth": "\"`But perhaps,' replied the wise, `there will not be enough for all of us. Go to the shops rather, and buy some for yourselves.'", "darby": "But the prudent answered saying, [We cannot,] lest it might not suffice for us and for you. Go rather to those that sell, and buy for yourselves.", "twenty": "But the prudent ones answered ‘No, for fear that there will not be enough for you and for us. Go instead to those who sell it, and buy for yourselves.’", "acv": "But the wise answered, saying, Perhaps there may not be enough for us and you. But go ye rather to those who sell, and buy for yourselves.", "anderson": "But the wise answered, saying: Lest there may not be enough for us and you, go rather to those who sell, and buy for yourselves.", "haweis": "But the provident replied, saying, No; lest there be not a sufficiency for us and you: but go rather to those who sell, and buy for yourselves.", "noyes": "But the wise answered, saying, Perhaps there will not be enough for us and you; go rather to those who sell, and buy for yourselves.", "webster": "But the wise answered, saying, [Not so]; lest there be not enough for us and you: but go ye rather to them that sell, and buy for yourselves.", "vulgate": "responderunt prudentes dicentes ne forte non sufficiat nobis et vobis ite potius ad vendentes et emite vobis;"}}, {"v": 10, "ref": "25:10", "o": "ἀπερχομένων δὲ αὐτῶν ἀγοράσαι ἦλθεν ὁ νυμφίος, καὶ αἱ ἕτοιμοι εἰσῆλθον μετ’ αὐτοῦ εἰς τοὺς γάμους, καὶ ἐκλείσθη ἡ θύρα.", "en": {"kjv": "And while they went to buy, the bridegroom came; and they that were ready went in with him to the marriage: and the door was shut.", "web": "While they went away to buy, the bridegroom came, and those who were ready went in with him to the marriage feast, and the door was shut.", "bsb": "But while they were on their way to buy it, the bridegroom arrived. Those who were ready went in with him to the wedding banquet, and the door was shut.", "asv": "And while they went away to buy, the bridegroom came; and they that were ready went in with him to the marriage feast: and the door was shut.", "ylt": "`And while they are going away to buy, the bridegroom came, and those ready went in with him to the marriage-feasts, and the door was shut;", "tyndale": "And whill they went to bye ye brydgrome came: and they yt were redy went in with him to ye weddinge and the gate was shett vp:", "dra": "Now whilst they went to buy the bridegroom came: and they that were ready went in with him to the marriage. And the door was shut.", "bbe": "And while they went to get oil, the master came; and those who were ready went in with him to the feast: and the door was shut.", "geneva": "And while they went to bye, the bridegrome came: and they that were readie, went in with him to the wedding, and the gate was shut.", "wycliffe": "And while thei wenten for to bie, the spouse cam; and tho that weren redi, entreden with him to the weddyngis; and the yate was schit.", "rotherham": "But, as they were going away to buy, the bridegroom came; and, they who were ready, went in with him, into the marriage-feast, and, the door was locked.", "weymouth": "\"So they went to buy. But meanwhile the bridegroom came; those bridesmaids who were ready went in with him to the wedding banquet; and the door was shut.", "darby": "But as they went away to buy, the bridegroom came, and the [ones that were] ready went in with him to the wedding feast, and the door was shut.", "twenty": "But while they were on their way to buy it, the bridegroom came; and the bridesmaids who were ready went in with him to the banquet, and the door was shut.", "acv": "And while they went to buy, the bridegroom came. And the prepared entered in with him for the wedding festivities, and the door was shut.", "anderson": "While they were going to buy, the bridegroom came; and those who were ready went in with him to the marriage-supper; and the door was closed.", "haweis": "But while they were gone away to buy, the bridegroom came; and they who were prepared went in with him to the marriage-feast: and the door was shut.", "noyes": "And while they went to buy, the bridegroom came; and they who were ready went in with him to the wedding; and the door was shut.", "webster": "And while they were going to buy, the bridegroom came; and they that were ready, went in with him to the marriage, and the door was shut.", "vulgate": "dum autem irent emere venit sponsus et quae paratae erant intraverunt cum eo ad nuptias et clausa est ianua;"}}, {"v": 11, "ref": "25:11", "o": "ὕστερον δὲ ἔρχονται καὶ αἱ λοιπαὶ παρθένοι λέγουσαι· Κύριε κύριε, ἄνοιξον ἡμῖν·", "en": {"kjv": "Afterward came also the other virgins, saying, Lord, Lord, open to us.", "web": "Afterward the other virgins also came, saying, ‘Lord, Lord, open to us.’", "bsb": "Later the other virgins arrived and said, ‘Lord, lord, open the door for us!’", "asv": "Afterward came also the other virgins, saying, Lord, Lord, open to us.", "ylt": "and afterwards come also do the rest of the virgins, saying, Sir, sir, open to us;", "tyndale": "Afterwardes came also ye other virgins sayinge: master master open to vs.", "dra": "But at last came also the other virgins, saying: Lord, Lord, open to us.", "bbe": "After that the other virgins came, saying, Lord, Lord, let us in.", "geneva": "Afterwards came also the other virgins, saying, Lord, Lord, open to vs.", "wycliffe": "And at the last the othere virgyns camen, and seiden, Lord, lord, opene to vs.", "rotherham": "But, afterwards, came the other virgins also, saying—Lord! Lord! open unto us!", "weymouth": "\"Afterwards the other bridesmaids came and cried, \"`Sir, Sir, open the door to us.'", "darby": "Afterwards come also the rest of the virgins, saying, Lord, Lord, open to us;", "twenty": "Afterwards the other bridesmaids came. ‘Sir, Sir,’ they said, ‘open the door to us!’", "acv": "But afterward the other virgins also came, saying, Lord, Lord, open to us.", "anderson": "Afterward the other virgins also came, and said: Lord! Lord! open for us.", "haweis": "Then came afterwards the other virgins, saying, Lord, Lord, open unto us.", "noyes": "Afterward came also the other virgins, saying, Lord, lord, open to us.", "webster": "Afterward came also the other virgins, saying, Lord, Lord, open to us.", "vulgate": "novissime veniunt et reliquae virgines dicentes domine domine aperi nobis;"}}, {"v": 12, "ref": "25:12", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Ἀμὴν λέγω ὑμῖν, οὐκ οἶδα ὑμᾶς.", "en": {"kjv": "But he answered and said, Verily I say unto you, I know you not.", "web": "But he answered, ‘Most certainly I tell you, I don’t know you.’", "bsb": "But he replied, ‘Truly I tell you, I do not know you.’", "asv": "But he answered and said, Verily I say unto you, I know you not.", "ylt": "and he answering said, Verily I say to you, I have not known you.", "tyndale": "But he answered and sayde: verely I saye vnto you: I knowe not you.", "dra": "But he answering said: Amen I say to you, I know you not.", "bbe": "But he made answer and said, Truly I say to you, I have no knowledge of you.", "geneva": "But he answered, and said, Verely I say vnto you, I knowe you not.", "wycliffe": "And he answeride, and seide, Treuli Y seie to you, Y knowe you not.", "rotherham": "And, he, answering, said—Verily, I say unto you, I know you not.", "weymouth": "\"`In solemn truth I tell you,' he replied, `I do not know you.'", "darby": "but he answering said, Verily I say unto you, I do not know you.", "twenty": "But the bridegroom answered ‘I tell you, I do not know you.’", "acv": "But having answered, he said, Truly I say to you, I know you not.", "anderson": "But he answered and said: Verily I say to you, I know you not.", "haweis": "But he answering said, Verily, I know you not.", "noyes": "But he answering said, Truly do I say to you, I know you not,", "webster": "But he answered and said, Verily I say to you, I know you not.", "vulgate": "at ille respondens ait amen dico vobis nescio vos;"}}, {"v": 13, "ref": "25:13", "o": "γρηγορεῖτε οὖν, ὅτι οὐκ οἴδατε τὴν ἡμέραν οὐδὲ τὴν ⸀ὥραν.", "en": {"kjv": "Watch therefore, for ye know neither the day nor the hour wherein the Son of man cometh.", "web": "Watch therefore, for you don’t know the day nor the hour in which the Son of Man is coming.", "bsb": "Therefore keep watch, because you do not know the day or the hour.", "asv": "Watch therefore, for ye know not the day nor the hour.", "ylt": "`Watch therefore, for ye have not known the day nor the hour in which the Son of Man doth come.", "tyndale": "Watche therefore: for ye knowe nether the daye nor yet the houre when the sonne of man shall come.", "dra": "Watch ye therefore, because you know not the day nor the hour.", "bbe": "Keep watch, then, because you are not certain of the day or of the hour.", "geneva": "Watch therfore: for ye know neither the day, nor the houre, when the sonne of man will come.", "wycliffe": "Therfor wake ye, for ye witen not the dai ne the our.", "rotherham": "Be watching, therefore, because ye know, neither the day nor the hour.", "weymouth": "\"Keep awake therefore; for you know neither the day nor the hour.", "darby": "Watch therefore, for ye know not the day nor the hour.", "twenty": "Therefore watch, since you know neither the Day nor the Hour.", "acv": "Watch therefore, because ye know not the day nor the hour in which the Son of man comes.", "anderson": "Watch, therefore, for you know neither the day nor the hour.", "haweis": "Watch therefore, for ye know not the day nor the hour in which the Son of man cometh.", "noyes": "Watch, therefore, for ye know not the day nor the hour.", "webster": "Watch therefore, for ye know neither the day nor the hour in which the Son of man cometh.", "vulgate": "vigilate itaque quia nescitis diem neque horam;"}}, {"v": 14, "ref": "25:14", "o": "Ὥσπερ γὰρ ἄνθρωπος ἀποδημῶν ἐκάλεσεν τοὺς ἰδίους δούλους καὶ παρέδωκεν αὐτοῖς τὰ ὑπάρχοντα αὐτοῦ,", "en": {"kjv": "For the kingdom of heaven is as a man travelling into a far country, who called his own servants, and delivered unto them his goods.", "web": "“For it is like a man, going into another country, who called his own servants, and entrusted his goods to them.", "bsb": "For it is just like a man going on a journey, who called his servants and entrusted them with his possessions.", "asv": "Forit isaswhena man, going into another country, called his own servants, and delivered unto them his goods.", "ylt": "`For--as a man going abroad did call his own servants, and did deliver to them his substance,", "tyndale": "Lykwyse as a certeyne ma redy to take his iorney to a straunge coutre called his servautes and delivered to them his gooddes.", "dra": "For even as a man going into a far country called his servants and delivered to them his goods;", "bbe": "For it is as when a man, about to take a journey, got his servants together, and gave them his property.", "geneva": "For the kingdome of heauen is as a man that going into a strange countrey, called his seruants, and deliuered to them his goods.", "wycliffe": "For as a man that goith in pilgrimage, clepide hise seruauntis, and bitook to hem hise goodis;", "rotherham": "For it is, just as a man, who, going from home, called his own servants, and delivered up to them his substance;", "weymouth": "\"Why, it is like a man who, when going on his travels, called his bondservants and entrusted his property to their care.", "darby": "For [it is] as [if] a man going away out of a country called his own bondmen and delivered to them his substance.", "twenty": "For it is as though a man, going on his travels, called his servants, and gave his property into their charge.", "acv": "For, like a man going on a journey, he called his own bondmen, and delivered to them the things possessed by him.", "anderson": "For as a man, on leaving his country, called his own servants, and delivered to them his goods:", "haweis": "For the case is like that of a man, who travelling abroad, called his own servants, and delivered to them his goods.", "noyes": "For it will be as when a man going abroad called his own servants, and intrusted to them his property;", "webster": "For [the kingdom of heaven is] as a man traveling into a far country, [who] called his own servants, and delivered to them his goods.", "vulgate": "sicut enim homo proficiscens vocavit servos suos et tradidit illis bona sua;"}}, {"v": 15, "ref": "25:15", "o": "καὶ ᾧ μὲν ἔδωκεν πέντε τάλαντα ᾧ δὲ δύο ᾧ δὲ ἕν, ἑκάστῳ κατὰ τὴν ἰδίαν δύναμιν, καὶ ἀπεδήμησεν. εὐθέως", "en": {"kjv": "And unto one he gave five talents, to another two, and to another one; to every man according to his several ability; and straightway took his journey.", "web": "To one he gave five talents, to another two, to another one; to each according to his own ability. Then he went on his journey.", "bsb": "To one he gave five talents, to another two talents, and to another one talent—each according to his own ability. And he went on his journey.", "asv": "And unto one he gave five talents, to another two, to another one; to each according to his several ability; and he went on his journey.", "ylt": "and to one he gave five talents, and to another two, and to another one, to each according to his several ability, went abroad immediately.", "tyndale": "And vnto one he gave .v. talentes to another .ii. and to another one: to every man after his abilite and streyght waye departed.", "dra": "And to one he gave five talents, and to another two, and to another one, to every one according to his proper ability: and immediately he took his journey.", "bbe": "And to one he gave five talents, to another two, to another one; to everyone as he was able; and he went on his journey.", "geneva": "And vnto one he gaue fiue talents, and to an other two, and to another one, to euery man after his own ability, and straightway went from home.", "wycliffe": "and to oon he yaf fyue talentis, and to another tweyne, and to another oon, to ech after his owne vertu; and wente forth anoon.", "rotherham": "And, to one, indeed, gave he five talents, and, to another, two, and, to another, one,—to each according to his particular ability, and went from home.", "weymouth": "To one he gave five talents, to another two, to another one--to each according to his individual capacity; and then started from home.", "darby": "And to one he gave five talents, to another two, and to another one; to each according to his particular ability, and immediately went away out of the country.", "twenty": "He gave three thousand pounds to one, twelve hundred to another, and six hundred to a third, in proportion to the ability of each. Then he set out on his travels.", "acv": "And to one he gave five talents, to another two, to another one, to each according to his personal ability, and straightaway he journeyed.", "anderson": "To one he gave five talents; to another, two; and to another, one; to each one, according to his own ability, and immediately left his country.", "haweis": "And to one he gave five talents, to another two, and to another one, to each according to his several capacity; and immediately went abroad.", "noyes": "and to one he gave five talents, to another two, and to another one, to each according to his ability, and went abroad.", "webster": "And to one he gave five talents, to another two, and to another one; to every man according to his several ability; and forthwith took his journey.", "vulgate": "et uni dedit quinque talenta alii autem duo alii vero unum unicuique secundum propriam virtutem et profectus est statim;"}}, {"v": 16, "ref": "25:16", "o": "⸀πορευθεὶς ὁ τὰ πέντε τάλαντα λαβὼν ἠργάσατο ἐν αὐτοῖς καὶ ⸀ἐκέρδησεν ἄλλα ⸀πέντε·", "en": {"kjv": "Then he that had received the five talents went and traded with the same, and made them other five talents.", "web": "Immediately he who received the five talents went and traded with them, and made another five talents.", "bsb": "The servant who had received the five talents went at once and put them to work and gained five more.", "asv": "Straightway he that received the five talents went and traded with them, and made other five talents.", "ylt": "`And he who did receive the five talents, having gone, wrought with them, and made other five talents;", "tyndale": "Then he that had receaved the fyve talentes went and bestowed them and wanne other fyve talentes.", "dra": "And he that had received the five talents went his way and traded with the same and gained other five.", "bbe": "Straight away he who had been given the five talents went and did trade with them, and made five more.", "geneva": "Then he that had receiued the fiue talents, went and occupied with them, and gained other fiue talents.", "wycliffe": "And he that hadde fyue besauntis, wente forth, and wrouyte in hem, and wan othere fyue.", "rotherham": "Straightway, he who, the five talents, had received, went and traded with them, and gained other five:", "weymouth": "Without delay the one who had received the five talents went and employed them in business, and gained five more.", "darby": "And he that had received the five talents went and trafficked with them, and made five other talents.", "twenty": "The man who had received the three thousand pounds went at once and traded with it, and made another three thousand.", "acv": "And having departed, the man who received the five talents worked with them, and made five other talents.", "anderson": "Then he that had received the five talents, went and traded with them, and made other five talents.", "haweis": "He then who had received the five talents, went and traded with them, and acquired five other talents.", "noyes": "He that had received the five talents went immediately and traded with the same, and gained five talents more.", "webster": "Then he that had received the five talents, went and traded with the same, and gained other five talents.", "vulgate": "abiit autem qui quinque talenta acceperat et operatus est in eis et lucratus est alia quinque;"}}, {"v": 17, "ref": "25:17", "o": "⸀ὡσαύτως ὁ τὰ δύο ⸀ἐκέρδησεν ἄλλα δύο·", "en": {"kjv": "And likewise he that had received two, he also gained other two.", "web": "In the same way, he also who got the two gained another two.", "bsb": "Likewise, the one with the two talents gained two more.", "asv": "In like manner he also that received the two gained other two.", "ylt": "in like manner also he who received the two, he gained, also he, other two;", "tyndale": "Lykwyse he that receaved .ii. gayned other .ii.", "dra": "And in like manner he that had received the two gained other two.", "bbe": "In the same way he who had been given the two got two more.", "geneva": "Likewise also, he that receiued two, he also gained other two.", "wycliffe": "Also and he that hadde takun tweyne, wan othere tweyne.", "rotherham": "Likewise, he of the two, gained other two:", "weymouth": "In the same way he who had the two gained two more.", "darby": "In like manner also he that [had received] the two, [he also] gained two others.", "twenty": "So, too, the man who had received the twelve hundred pounds made another twelve hundred.", "acv": "And likewise also the man of the two gained two others.", "anderson": "In like manner also, he that had received the two, gained other two.", "haweis": "In the same manner also he that had the two, gained also himself two others.", "noyes": "In like manner, he that had received the two gained two more.", "webster": "And likewise he that [had received] two, he also gained other two.", "vulgate": "similiter qui duo acceperat lucratus est alia duo;"}}, {"v": 18, "ref": "25:18", "o": "ὁ δὲ τὸ ἓν λαβὼν ἀπελθὼν ὤρυξεν ⸀γῆν καὶ ⸀ἔκρυψεν τὸ ἀργύριον τοῦ κυρίου αὐτοῦ.", "en": {"kjv": "But he that had received one went and digged in the earth, and hid his lord’s money.", "web": "But he who received the one went away and dug in the earth, and hid his lord’s money.", "bsb": "But the servant who had received the one talent went off, dug a hole in the ground, and hid his master’s money.", "asv": "But he that received the one went away and digged in the earth, and hid his lord’s money.", "ylt": "and he who did receive the one, having gone away, digged in the earth, and hid his lord's money.", "tyndale": "But he yt receaved ye one went and digged a pit in the erth and hyd his masters money.", "dra": "But he that had received the one, going his way, digged into the earth and hid his lord's money.", "bbe": "But he who was given the one went away and put it in a hole in the earth, and kept his lord's money in a secret place.", "geneva": "But he that receiued that one, went and digged it in the earth, and hid his masters money.", "wycliffe": "But he that hadde takun oon, yede forth, and dalf in to the erthe, and hidde the money of his lord.", "rotherham": "But, he who the one had received, went away, and digged up ground, and hid the silver of his lord.", "weymouth": "But the man who had received the one went and dug a hole and buried his master's money.", "darby": "But he that had received the one went and dug in the earth, and hid the money of his lord.", "twenty": "But the man who had received the six hundred went and dug a hole in the ground, and hid his master’s money.", "acv": "But having departed, the man who received the one dug in the ground, and hid his lord's silver.", "anderson": "But he that had received the one, went and digged in the earth, and hid his lord’s money.", "haweis": "But he that had received the one talent, went and digged a hole in the ground, and hid the silver of his master.", "noyes": "But he that had received the one went and dug in the earth, and hid his lord’s money.", "webster": "But he that had received one, went and digged in the earth, and hid his lord's money.", "vulgate": "qui autem unum acceperat abiens fodit in terra et abscondit pecuniam domini sui;"}}, {"v": 19, "ref": "25:19", "o": "μετὰ δὲ ⸂πολὺν χρόνον⸃ ἔρχεται ὁ κύριος τῶν δούλων ἐκείνων καὶ συναίρει ⸂λόγον μετ’ αὐτῶν⸃", "en": {"kjv": "After a long time the lord of those servants cometh, and reckoneth with them.", "web": "“Now after a long time the lord of those servants came, and reconciled accounts with them.", "bsb": "After a long time the master of those servants returned to settle accounts with them.", "asv": "Now after a long time the lord of those servants cometh, and maketh a reckoning with them.", "ylt": "`And after a long time cometh the lord of those servants, and taketh reckoning with them;", "tyndale": "After a longe season ye lorde of those servauntes came and rekened with the.", "dra": "But after a long time the lord of those servants came and reckoned with them.", "bbe": "Now after a long time the lord of those servants comes, and makes up his account with them.", "geneva": "But after a long season, the master of those seruants came, and reckoned with them.", "wycliffe": "But after long tyme, the lord of tho seruauntis cam, and rekenede with hem.", "rotherham": "And, after a long time, cometh the lord of those servants, and reckoneth with them.", "weymouth": "\"After a long lapse of time the master of those servants returned, and had a reckoning with them.", "darby": "And after a long time the lord of those bondmen comes and reckons with them.", "twenty": "After a long time the master of those servants returned, and settled accounts with them.", "acv": "Now after a long time the lord of those bondmen comes, and takes up accounting with them.", "anderson": "After a long time, the lord of those servants came and settled with them.", "haweis": "Then after a long absence the master of these servants cometh, and maketh a reckoning with them.", "noyes": "And after a long time the lord of those servants cometh, and reckoneth with them.", "webster": "After a long time the lord of those servants cometh, and reckoneth with them.", "vulgate": "post multum vero temporis venit dominus servorum illorum et posuit rationem cum eis;"}}, {"v": 20, "ref": "25:20", "o": "καὶ προσελθὼν ὁ τὰ πέντε τάλαντα λαβὼν προσήνεγκεν ἄλλα πέντε τάλαντα λέγων· Κύριε, πέντε τάλαντά μοι παρέδωκας· ἴδε ἄλλα πέντε τάλαντα ⸀ἐκέρδησα.", "en": {"kjv": "And so he that had received five talents came and brought other five talents, saying, Lord, thou deliveredst unto me five talents: behold, I have gained beside them five talents more.", "web": "He who received the five talents came and brought another five talents, saying, ‘Lord, you delivered to me five talents. Behold, I have gained another five talents besides them.’", "bsb": "The servant who had received the five talents came and presented five more. ‘Master,’ he said, ‘you entrusted me with five talents. See, I have gained five more.’", "asv": "And he that received the five talents came and brought other five talents, saying, Lord, thou deliveredst unto me five talents: lo, I have gained other five talents.", "ylt": "and he who did receive the five talents having come, brought other five talents, saying, `Sir, five talents thou didst deliver to me; lo, other five talents did I gain besides them.", "tyndale": "Then came he yt had receaved fyve talentes and brought other fyve talentes sayinge: master thou deliveredst vnto one fyve talentes: beholde I have gayned wt the fyve talentes moo.", "dra": "And he that had received the five talents coming, brought other five talents, saying: Lord, thou didst deliver to me five talents. Behold I have gained other five over and above.", "bbe": "And he who had the five talents came with his other five talents, saying, Lord, you gave into my care five talents: see, I have got five more.", "geneva": "Then came he that had receiued fiue talents, and brought other fiue talents, saying, Master, thou deliueredst vnto me fiue talents: behold, I haue gained with them other fiue talents.", "wycliffe": "And he that hadde takun fyue besauntis, cam, and brouyte othere fyue, and seide, Lord, thou bytokist to me fyue besauntis, loo! Y haue getun aboue fyue othere.", "rotherham": "And he who the five talents had received, coming forward, brought other five talents, saying,—Lord! five talents, to me, thou didst deliver up: See! other five talents, I gained.", "weymouth": "The one who had received the five talents came and brought five more, and said, \"`Sir, it was five talents that you entrusted to me: see, I have gained five more.'", "darby": "And he that had received the five talents came to [him] and brought five other talents, saying, [My] lord, thou deliveredst me five talents; behold, I have gained five other talents besides them.", "twenty": "The man who had received the three thousand pounds came up and brought three thousand more. ‘Sir,’ he said, ‘you entrusted me with three thousand pounds; look, I have made another three thousand!’", "acv": "And having come, the man who received the five talents brought five other talents, saying, Lord, thou delivered five talents to me, lo, I have gained five other talents besides them.", "anderson": "And he that had received the five talents came and brought other five talents, and said: Lord, you delivered to me five talents: see, I have gained other five talents in addition to them.", "haweis": "And he who had received the five talents, coming to him, brought five other talents, saying, Sir, thou deliveredst to me five talents: I have gained to them five other talents.", "noyes": "And he that had received the five talents came and brought five talents more, saying, Lord, thou intrustedst to me five talents; see, I have gained five talents more.", "webster": "And he that had received five talents, came and brought other five talents, saying, Lord, thou deliveredst to me five talents: behold, I have gained besides them five talents more.", "vulgate": "et accedens qui quinque talenta acceperat obtulit alia quinque talenta dicens domine quinque talenta mihi tradidisti ecce alia quinque superlucratus sum;"}}, {"v": 21, "ref": "25:21", "o": "⸀ἔφη αὐτῷ ὁ κύριος αὐτοῦ· Εὖ, δοῦλε ἀγαθὲ καὶ πιστέ, ἐπὶ ὀλίγα ἦς πιστός, ἐπὶ πολλῶν σε καταστήσω· εἴσελθε εἰς τὴν χαρὰν τοῦ κυρίου σου.", "en": {"kjv": "His lord said unto him, Well done, thou good and faithful servant: thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.", "web": "“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’", "bsb": "His master replied, ‘Well done, good and faithful servant! You have been faithful with a few things; I will put you in charge of many things. Enter into the joy of your master!’", "asv": "His lord said unto him, Well done, good and faithful servant: thou hast been faithful over a few things, I will set thee over many things; enter thou into the joy of thy lord.", "ylt": "`And his lord said to him, Well done, servant, good and faithful, over a few things thou wast faithful, over many things I will set thee; enter into the joy of thy lord.", "tyndale": "The his master sayde vnto him: well good servaut and faithfull. Thou hast bene faithfull in lytell I will make the ruler over moche: entre in into thy masters ioye.", "dra": "His lord said to him: Well done, good and faithful servant, because thou hast been faithful over a few things, I will place thee over many things. Enter thou into the joy of thy lord.", "bbe": "His lord said to him, Well done, good and true servant: you have been true in a small thing, I will give you control over great things: take your part in the joy of your lord.", "geneva": "Then his master saide vnto him, It is well done good seruant and faithfull, Thou hast bene faithfull in litle, I will make thee ruler ouer much: enter into thy masters ioy.", "wycliffe": "His lord seide to hym, Wel be thou, good seruaunt and feithful; for on fewe thingis thou hast be trewe, Y schal ordeyne thee on manye thingis; entre thou in to the ioye of thi lord.", "rotherham": "His lord said unto him—Well-done! good and faithful servant,—Over a few things wast thou faithful, over many things, will I appoint thee: Enter into the joy of thy lord.", "weymouth": "\"`You have done well, good and trustworthy servant,' replied his master; `you have been trustworthy in the management of a little, I will put you in charge of much: share your master's joy.'", "darby": "His lord said to him, Well, good and faithful bondman, thou wast faithful over a few things, I will set thee over many things: enter into the joy of thy lord.", "twenty": "‘Well done, good, trustworthy servant!’ said his master. ‘You have been trustworthy with a small sum; now I will place a large one in your hands; come and share your master’s joy!’", "acv": "And his lord said to him, Well, good and faithful bondman. Thou were faithful over a few things, I will appoint thee over many things. Enter thou into the joy of thy lord.", "anderson": "His lord said to him: Well done, good and faithful servant; you have been faithful over a few things, I will make you ruler over many. Enter into the joy of your lord.", "haweis": "His master said to him, Well done, good and faithful servant: thou hast been faithful over a few things, I will place thee over many: enter into the joy of thy master.", "noyes": "His lord said to him, Well done, good and faithful servant! thou hast been faithful over a little, I will place thee in charge of much; enter into the joy of thy lord.", "webster": "His lord said to him, Well done [thou] good and faithful servant; thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.", "vulgate": "ait illi dominus eius euge bone serve et fidelis quia super pauca fuisti fidelis super multa te constituam intra in gaudium domini tui;"}}, {"v": 22, "ref": "25:22", "o": "προσελθὼν ⸀δὲ καὶ ὁ τὰ δύο ⸀τάλαντα εἶπεν· Κύριε, δύο τάλαντά μοι παρέδωκας· ἴδε ἄλλα δύο τάλαντα ⸀ἐκέρδησα.", "en": {"kjv": "He also that had received two talents came and said, Lord, thou deliveredst unto me two talents: behold, I have gained two other talents beside them.", "web": "“He also who got the two talents came and said, ‘Lord, you delivered to me two talents. Behold, I have gained another two talents besides them.’", "bsb": "The servant who had received the two talents also came and said, ‘Master, you entrusted me with two talents. See, I have gained two more.’", "asv": "And he also that received the two talents came and said, Lord, thou deliveredst unto me two talents: lo, I have gained other two talents.", "ylt": "`And he who also did receive the two talents having come, said, Sir, two talents thou didst deliver to me; lo, other two talents I did gain besides them.", "tyndale": "Also he that receaved .ii. talentes came and sayde: master thou deliveredest vnto me .ii. talentes: beholde I have wone .ii. other talentes with them.", "dra": "And he also that had received the two talents came and said: Lord, thou deliveredst two talents to me. Behold I have gained other two.", "bbe": "And he who had the two talents came and said, Lord, you gave into my care two talents: see, I have got two more.", "geneva": "Also he that had receiued two talents, came, and said, Master, thou deliueredst vnto me two talents: behold, I haue gained two other talets more.", "wycliffe": "And he that hadde takun twey talentis, cam, and seide, Lord, thou bitokist to me twey besauntis; loo!", "rotherham": "He also of the two talents, coming forward, said—Lord! two talents, to me, didst thou deliver up: See! other two talents, I gained.", "weymouth": "\"The second, who had received the two talents, came and said, \"`Sir, it was two talents you entrusted to me: see, I have gained two more.'", "darby": "And he also that had received the two talents came to [him] and said, [My] lord, thou deliveredst me two talents; behold, I have gained two other talents besides them.", "twenty": "Then the one who had received the twelve hundred pounds came up and said ‘Sir, you entrusted me with twelve hundred pounds; look, I have made another twelve hundred!’", "acv": "And also having come, the man who received the two talents said, Lord, thou delivered two talents to me, lo, I have gained two other talents besides them.", "anderson": "And he also that had received the two talents came, and said: Lord, you delivered to me two talents; see, I have gained other two talents in addition to them.", "haweis": "Then came also he that had received the two talents: and said, Sir, thou deliveredst to me two talents: lo! I have gained to them two other talents.", "noyes": "He also that had received the two talents came and said, Lord, thou intrustedst to me two talents; see, I have gained two talents more.", "webster": "He also that had received two talents came, and said, Lord, thou deliveredst to me two talents: behold, I have gained two other talents besides them.", "vulgate": "accessit autem et qui duo talenta acceperat et ait domine duo talenta tradidisti mihi ecce alia duo lucratus sum;"}}, {"v": 23, "ref": "25:23", "o": "ἔφη αὐτῷ ὁ κύριος αὐτοῦ· Εὖ, δοῦλε ἀγαθὲ καὶ πιστέ, ἐπὶ ὀλίγα ἦς πιστός, ἐπὶ πολλῶν σε καταστήσω· εἴσελθε εἰς τὴν χαρὰν τοῦ κυρίου σου.", "en": {"kjv": "His lord said unto him, Well done, good and faithful servant; thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.", "web": "“His lord said to him, ‘Well done, good and faithful servant. You have been faithful over a few things, I will set you over many things. Enter into the joy of your lord.’", "bsb": "His master replied, ‘Well done, good and faithful servant! You have been faithful with a few things; I will put you in charge of many things. Enter into the joy of your master!’", "asv": "His lord said unto him, Well done, good and faithful servant: thou hast been faithful over a few things, I will set thee over many things; enter thou into the joy of thy lord.", "ylt": "`His lord said to him, Well done, servant, good and faithful, over a few things thou wast faithful, over many things I will set thee; enter into the joy of thy lord.", "tyndale": "And his master sayde vnto him well good servaunt and faithfull. Thou hast bene faithfull in lytell I wyll make the ruler over moche: go in into thy masters ioye.", "dra": "His lord said to him: Well done, good and faithful servant: because thou hast been faithful over a few things, I will place thee over many things. Enter thou into the joy of thy lord.", "bbe": "His lord said to him, Well done, good and true servant: you have been true in a small thing, I will give you control over great things: take your part in the joy of your lord.", "geneva": "His master saide vnto him, It is well done good seruant, and faithfull, Thou hast bene faithfull in litle, I will make thee ruler ouer much: enter into thy masters ioy.", "wycliffe": "Y haue wonnen ouer othir tweyne. His lord seide to him, Wel be thou, good seruaunt and trewe; for on fewe thingis thou hast be trewe, Y schal ordeyne thee on many thingis; entre thou in to the ioie of thi lord.", "rotherham": "His lord said unto him—Well-done! good and faithful servant,—Over a few things, wast thou faithful, over many things, will I appoint thee: Enter into the joy of thy lord.", "weymouth": "\"`Good and trustworthy servant, you have done well,' his master replied; `you have been trustworthy in the management of a little, I will put you in charge of much: share your master's joy.'", "darby": "His lord said to him, Well, good and faithful bondman, thou wast faithful over a few things, I will set thee over many things: enter thou into the joy of thy lord.", "twenty": "‘Well done, good, trustworthy servant!’ said his master. ‘You have been trustworthy with a small sum; now I will place a large one in your hands; come and share your master’s joy!’", "acv": "His lord said to him, Well, good and faithful bondman. Thou were faithful over a few things, I will appoint thee over many things. Enter thou into the joy of thy lord.", "anderson": "His lord said to him: Well done, good and faithful servant; you have been faithful over a few things, I will make you ruler over many. Enter into the joy of your lord.", "haweis": "His master said to him, Well done, good and faithful servant: thou hast been faithful over a few things, I will place thee over many: enter thou into thy master’s joy.", "noyes": "His lord said to him, Well done, good and faithful servant! thou hast been faithful over a little, I will place thee in charge of much; enter into the joy of thy lord.", "webster": "His lord said to him, Well done, good and faithful servant; thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.", "vulgate": "ait illi dominus eius euge serve bone et fidelis quia super pauca fuisti fidelis supra multa te constituam intra in gaudium domini tui;"}}, {"v": 24, "ref": "25:24", "o": "προσελθὼν δὲ καὶ ὁ τὸ ἓν τάλαντον εἰληφὼς εἶπεν· Κύριε, ἔγνων σε ὅτι σκληρὸς εἶ ἄνθρωπος, θερίζων ὅπου οὐκ ἔσπειρας καὶ συνάγων ὅθεν οὐ διεσκόρπισας·", "en": {"kjv": "Then he which had received the one talent came and said, Lord, I knew thee that thou art an hard man, reaping where thou hast not sown, and gathering where thou hast not strawed:", "web": "“He also who had received the one talent came and said, ‘Lord, I knew you that you are a hard man, reaping where you did not sow, and gathering where you did not scatter.", "bsb": "Finally, the servant who had received the one talent came and said, ‘Master, I knew that you are a hard man, reaping where you have not sown and gathering where you have not scattered seed.", "asv": "And he also that had received the one talent came and said, Lord, I knew thee that thou art a hard man, reaping where thou didst not sow, and gathering where thou didst not scatter;", "ylt": "`And he also who hath received the one talent having come, said, Sir, I knew thee, that thou art a hard man, reaping where thou didst not sow, and gathering from whence thou didst not scatter;", "tyndale": "Then he which had receaved ye one talent came and sayd: master I considered yt thou wast an harde man which repest where thou sowedst not and gadderest where thou strawedst not", "dra": "But he that had received the one talent, came and said: Lord, I know that thou art a hard man; thou reapest where thou hast not sown and gatherest where thou hast not strewed.", "bbe": "And he who had had the one talent came and said, Lord, I had knowledge that you are a hard man, getting in grain where you have not put seed, and making profits for which you have done no work:", "geneva": "Then he which had receiued the one talent, came, and said, Master, I knewe that thou wast an hard man, which reapest where thou sowedst not, and gatherest where thou strawedst not:", "wycliffe": "But he that hadde takun o besaunt, cam, and seide, Lord, Y woot that thou art an hard man; thou repist where thou hast not sowe, and thou gederist togidere where thou hast not spred abrood;", "rotherham": "But he also who, the one talent, had received, coming forward, said—Lord I knew thee, that thou art a, hard, man, reaping, where thou hast not sown,—and gathering, whence thou hast not winnowed;", "weymouth": "\"But, next, the man who had the one talent in his keeping came and said, \"`Sir, I knew you to be a severe man, reaping where you had not sown and garnering what you had not winnowed.", "darby": "And he also that had received the one talent coming to [him] said, [My] lord, I knew thee that thou art a hard man, reaping where thou hadst not sowed, and gathering from where thou hadst not scattered,", "twenty": "The man who had received the six hundred pounds came up, too, and said ‘Sir, I knew that you were a hard man; you reap where you have not sown, and gather up where you have not winnowed;", "acv": "And the man who received the one talent also having come, said, Lord, I knew thee that thou are a hard man, reaping where thou did not sow, and gathering from where thou did not scatter.", "anderson": "But he that had received the one talent came, and said: Lord, I knew you, that you are a hard man, reaping where you did not sow, and gathering where you did not scatter.", "haweis": "Then came also he that had received the one talent, and said, Sir, knowing thee, that thou art a severe man, reaping where thou hast not sowed, and gathering from whence thou hast not scattered:", "noyes": "Then he also that had received the one talent came and said, Lord, I knew thee to be a hard man, reaping where thou didst not sow, and gathering where thou didst not scatter seed;", "webster": "Then he who had received the one talent came, and said, Lord, I knew thee that thou art a hard man, reaping where thou hast not sown, and gathering where thou hast not strewed:", "vulgate": "accedens autem et qui unum talentum acceperat ait domine scio quia homo durus es metis ubi non seminasti et congregas ubi non sparsisti;"}}, {"v": 25, "ref": "25:25", "o": "καὶ φοβηθεὶς ἀπελθὼν ἔκρυψα τὸ τάλαντόν σου ἐν τῇ γῇ· ἴδε ἔχεις τὸ σόν.", "en": {"kjv": "And I was afraid, and went and hid thy talent in the earth: lo, there thou hast that is thine.", "web": "I was afraid, and went away and hid your talent in the earth. Behold, you have what is yours.’", "bsb": "So I was afraid and went out and hid your talent in the ground. See, you have what belongs to you.’", "asv": "and I was afraid, and went away and hid thy talent in the earth: lo, thou hast thine own.", "ylt": "and having been afraid, having gone away, I hid thy talent in the earth; lo, thou hast thine own!", "tyndale": "and was therfore afrayde and went and hyd thy talent in ye erth: Beholde thou hast thyn awne.", "dra": "And being afraid, I went and hid thy talent in the earth. Behold here thou hast that which is thine.", "bbe": "And I was in fear, and went away, and put your talent in the earth: here is what is yours.", "geneva": "I was therefore afraide, and went, and hid thy talent in the earth: behold, thou hast thine owne.", "wycliffe": "and Y dredynge wente, and hidde thi besaunt in the erthe; lo! thou hast that that is thin.", "rotherham": "And, overcome with fear, I went away, and hid thy talent in the ground: See! thou hast what is thine!", "weymouth": "So being afraid I went and buried your talent in the ground: there you have what belongs to you.'", "darby": "and being afraid I went away and hid thy talent in the earth; behold, thou hast that which is thine.", "twenty": "and, in my fear, I went and hid your money in the ground; look, here is what belongs to you!’", "acv": "And after being afraid, having gone, I hid thy talent in the ground. Lo, thou have thine own.", "anderson": "And I was afraid, and went and hid your talent in the earth; see, you have yours.", "haweis": "and being afraid, I went and hid thy talent in the ground: see here, thou hast thine own.", "noyes": "and I was afraid, and went and hid thy talent in the earth. See! thou hast thine own.", "webster": "And I was afraid, and went and hid thy talent in the earth: lo, [there] thou hast [what is] thine.", "vulgate": "et timens abii et abscondi talentum tuum in terra ecce habes quod tuum est;"}}, {"v": 26, "ref": "25:26", "o": "ἀποκριθεὶς δὲ ὁ κύριος αὐτοῦ εἶπεν αὐτῷ· Πονηρὲ δοῦλε καὶ ὀκνηρέ, ᾔδεις ὅτι θερίζω ὅπου οὐκ ἔσπειρα καὶ συνάγω ὅθεν οὐ διεσκόρπισα;", "en": {"kjv": "His lord answered and said unto him, Thou wicked and slothful servant, thou knewest that I reap where I sowed not, and gather where I have not strawed:", "web": "“But his lord answered him, ‘You wicked and slothful servant. You knew that I reap where I didn’t sow, and gather where I didn’t scatter.", "bsb": "‘You wicked, lazy servant!’ replied his master. ‘You knew that I reap where I have not sown and gather where I have not scattered seed.", "asv": "But his lord answered and said unto him, Thou wicked and slothful servant, thou knewest that I reap where I sowed not, and gather where I did not scatter;", "ylt": "`And his lord answering said to him, Evil servant, and slothful, thou hadst known that I reap where I did not sow, and I gather whence I did not scatter!", "tyndale": "His master answered and sayde vnto him: thou evyll servaut and slewthfull thou knewest yt I repe where I sowed not and gaddre where I strawed not:", "dra": "And his lord answering, said to him: Wicked and slothful servant, thou knewest that I reap where I sow not and gather where I have not strewed.", "bbe": "But his lord in answer said to him, You are a bad and unready servant; if you had knowledge that I get in grain where I did not put seed, and make profits for which I have done no work,", "geneva": "And his master answered, and said vnto him, Thou euill seruant, and slouthfull, thou knewest that I reape where I sowed not, and gather where I strawed not.", "wycliffe": "His lord answeride, and seide to hym, Yuel seruaunt and slowe, wistist thou that Y repe where Y sewe not, and gadir to gidere where Y spredde not abrood?", "rotherham": "And his lord, answering, said unto him—O wicked servant, and cowardly, knewest thou that I reap, where I have not sown, and gather, whence I have not winnowed?", "weymouth": "\"`You wicked and slothful servant,' replied his master, `did you know that I reap where I have not sown, and garner what I have not winnowed?", "darby": "And his lord answering said to him, Wicked and slothful bondman, thou knewest that I reap where I had not sowed, and gather from where I had not scattered;", "twenty": "‘You lazy, worthless servant!’ was his master’s reply. ‘You knew that I reap where I have not sown, and gather up where I have not winnowed?", "acv": "But having answered, his lord said to him, Thou evil and lazy bondman, thou knew that I reap where I sowed not, and gather from where I did not scatter.", "anderson": "His lord answered and said to him: Wicked and slothful servant; did you know that I reap where I did not sow, and gather where I did not scatter?", "haweis": "Then his master answering said to him, Thou wicked and idle slave, thou knewest that I reap whence I had not sown, and gather where I had not scattered:", "noyes": "But his lord answered and said to him, Wicked and slothful servant! Didst thou know that I reap where I sowed not, and gather where I did not scatter seed?", "webster": "His lord answered and said to him, [Thou] wicked and slothful servant, thou knewest that I reap where I have not sown, and gather where I have not strewed:", "vulgate": "respondens autem dominus eius dixit ei serve male et piger sciebas quia meto ubi non semino et congrego ubi non sparsi;"}}, {"v": 27, "ref": "25:27", "o": "ἔδει ⸂σε οὖν⸃ βαλεῖν ⸂τὰ ἀργύριά⸃ μου τοῖς τραπεζίταις, καὶ ἐλθὼν ἐγὼ ἐκομισάμην ἂν τὸ ἐμὸν σὺν τόκῳ.", "en": {"kjv": "Thou oughtest therefore to have put my money to the exchangers, and then at my coming I should have received mine own with usury.", "web": "You ought therefore to have deposited my money with the bankers, and at my coming I should have received back my own with interest.", "bsb": "Then you should have deposited my money with the bankers, and on my return I would have received it back with interest.", "asv": "thou oughtest therefore to have put my money to the bankers, and at my coming I should have received back mine own with interest.", "ylt": "it behoved thee then to put my money to the money-lenders, and having come I had received mine own with increase.", "tyndale": "thou oughtest therfore to have had my money to ye chaugers and then at my comynge shulde I have receaved myne awne with vauntage.", "dra": "Thou oughtest therefore to have committed my money to the bankers: and at my coming I should have received my own with usury.", "bbe": "Why, then, did you not put my money in the bank, and at my coming I would have got back what is mine with interest?", "geneva": "Thou oughtest therefore to haue put my money to ye exchangers, and then at my comming should I haue receiued mine owne with vantage.", "wycliffe": "Therfor it bihofte thee to bitake my money to chaungeris, that whanne Y cam, Y schulde resseyue that that is myn with vsuris.", "rotherham": "It was binding on thee, therefore, to cast my silver into the money-changers,—and, I, when I, came, might have obtained what was mine, with interest.", "weymouth": "Your duty then was to deposit my money in some bank, and so when I came I should have got back my property with interest.", "darby": "thou oughtest then to have put my money to the money-changers, and when I came I should have got what is mine with interest.", "twenty": "Then you ought to have placed my money in the hands of bankers, and I, on my return, should have received my money, with interest.", "acv": "Thou ought therefore to have placed my silver with the bankers, and having come I would have received back my own with interest.", "anderson": "Therefore, you ought to have put my money with the bankers; and, when I came, I could have received my own with interest.", "haweis": "thou oughtest then to have placed my money with the bankers, so when I came I should have received my own with interest.", "noyes": "Thou oughtest then to have put my money with the money-dealers, and on my coming I should have received mine own with interest.", "webster": "Thou oughtest therefore to have put my money to the exchangers, and [then] at my coming I should have received my own with interest.", "vulgate": "oportuit ergo te mittere pecuniam meam nummulariis et veniens ego recepissem utique quod meum est cum usura;"}}, {"v": 28, "ref": "25:28", "o": "ἄρατε οὖν ἀπ’ αὐτοῦ τὸ τάλαντον καὶ δότε τῷ ἔχοντι τὰ δέκα τάλαντα·", "en": {"kjv": "Take therefore the talent from him, and give it unto him which hath ten talents.", "web": "Take away therefore the talent from him, and give it to him who has the ten talents.", "bsb": "Therefore take the talent from him and give it to the one who has ten talents.", "asv": "Take ye away therefore the talent from him, and give it unto him that hath the ten talents.", "ylt": "`Take therefore from him the talent, and give to him having the ten talents,", "tyndale": "Take therfore the talent from him and geve it vnto him which hath .x. talentes.", "dra": "Take ye away therefore the talent from him and give it him that hath ten talents.", "bbe": "Take away, then, his talent and give it to him who has the ten talents.", "geneva": "Take therefore the talent from him, and giue it vnto him which hath tenne talents.", "wycliffe": "Therfor take awei fro hym the besaunt, and yyue ye to hym that hath ten besauntis.", "rotherham": "Therefore take away, from him, the talent, and give unto him that hath the ten talents;", "weymouth": "So take away the talent from him, and give it to the man who has the ten.'", "darby": "Take therefore the talent from him, and give it to him that has the ten talents:", "twenty": "‘Therefore,’ he continued, ‘take away from him the six hundred pounds, and give it to the one who has the six thousand.", "acv": "Take ye therefore the talent from him, and give it to him who has the ten talents.", "anderson": "Therefore, take from him the talent, and give it to him that has the ten talents.", "haweis": "Take therefore from him the talent, and give it to him that hath the ten talents.", "noyes": "Take therefore the talent from him, and give it to him who hath the ten talents.", "webster": "Take therefore the talent from him, and give [it] to him who hath ten talents.", "vulgate": "tollite itaque ab eo talentum et date ei qui habet decem talenta;"}}, {"v": 29, "ref": "25:29", "o": "τῷ γὰρ ἔχοντι παντὶ δοθήσεται καὶ περισσευθήσεται· ⸂τοῦ δὲ⸃ μὴ ἔχοντος καὶ ὃ ἔχει ἀρθήσεται ἀπ’ αὐτοῦ.", "en": {"kjv": "For unto every one that hath shall be given, and he shall have abundance: but from him that hath not shall be taken away even that which he hath.", "web": "For to everyone who has will be given, and he will have abundance, but from him who doesn’t have, even that which he has will be taken away.", "bsb": "For everyone who has will be given more, and he will have an abundance. But the one who does not have, even what he has will be taken away from him.", "asv": "For unto every one that hath shall be given, and he shall have abundance: but from him that hath not, even that which he hath shall be taken away.", "ylt": "for to every one having shall be given, and he shall have overabundance, and from him who is not having, even that which he hath shall be taken from him;", "tyndale": "For vnto every man that hath shalbe geven and he shall have aboundance: and from him that hath not shalbe taken awaye even that he hath.", "dra": "For to every one that hath shall be given, and he shall abound: but from him that hath not, that also which he seemeth to have shall be taken away.", "bbe": "For to everyone who has will be given, and he will have more: but from him who has not, even what he has will be taken away.", "geneva": "For vnto euery man that hath, it shall be giuen, and he shall haue abundance, and from him that hath not, euen that he hath, shalbe taken away.", "wycliffe": "For to euery man that hath me schal yyue, and he schal encreese; but fro hym that hath not, also that that hym semeth to haue, schal be taken awey fro him.", "rotherham": "For, to every one that hath, shall be given, and he shall be made to abound; but, from him that hath not, even what he hath, shall be taken away from him:", "weymouth": "(For to every one who has, more shall be given, and he shall have abundance; but from him who has nothing, even what he has shall be taken away.)", "darby": "for to every one that has shall be given, and he shall be in abundance; but from him that has not, that even which he has shall be taken from him.", "twenty": "For, to him who has, more will be given, and he shall have abundance; but, as for him who has nothing, even what he has will be taken away from him.", "acv": "For to every man who has will be given, and he will have abundance, but from him who has not, even what he has will be taken away from him.", "anderson": "For to every one that has, it shall be given, and he shall have abundance. But from him that has not, even that which he has shall be taken away.", "haweis": "For to every one that hath shall be given, and he shall abound: but from him that hath not, even that he hath shall be taken away from him.", "noyes": "For to every one that hath will be given, and he will have abundance; but from him that hath not, even that which he hath will be taken away.", "webster": "For to every one that hath shall be given, and he shall have abundance: but from him that hath not shall be taken away even that which he hath.", "vulgate": "omni enim habenti dabitur et abundabit ei autem qui non habet et quod videtur habere auferetur ab eo;"}}, {"v": 30, "ref": "25:30", "o": "καὶ τὸν ἀχρεῖον δοῦλον ἐκβάλετε εἰς τὸ σκότος τὸ ἐξώτερον· ἐκεῖ ἔσται ὁ κλαυθμὸς καὶ ὁ βρυγμὸς τῶν ὀδόντων.", "en": {"kjv": "And cast ye the unprofitable servant into outer darkness: there shall be weeping and gnashing of teeth.", "web": "Throw out the unprofitable servant into the outer darkness, where there will be weeping and gnashing of teeth.’", "bsb": "And throw that worthless servant into the outer darkness, where there will be weeping and gnashing of teeth.’", "asv": "And cast ye out the unprofitable servant into the outer darkness: there shall be the weeping and the gnashing of teeth.", "ylt": "and the unprofitable servant cast ye forth to the outer darkness; there shall be the weeping and the gnashing of the teeth.", "tyndale": "And cast yt vnprofitable servaunt into vtter dercknes: there shalbe wepynge and gnasshinge of teeth.", "dra": "And the unprofitable servant, cast ye out into the exterior darkness. There shall be weeping and gnashing of teeth.", "bbe": "And put out the servant who is of no profit into the outer dark: there will be weeping and cries of sorrow.", "geneva": "Cast therefore that vnprofitable seruant into vtter darkenes: there shalbe weeping and gnasshing of teeth.", "wycliffe": "And caste ye out the vnprofitable seruaunt in to vtmer derknessis; ther schal be wepyng, and gryntyng of teeth.", "rotherham": "And, the unprofitable servant, cast ye forth into the darkness, outside: There, shall be wailing and gnashing of teeth.", "weymouth": "`But as for this worthless servant, put him out into the darkness outside: *there* will be the weeping and the gnashing of teeth.'", "darby": "And cast out the useless bondman into the outer darkness; there shall be the weeping and the gnashing of teeth.", "twenty": "As for the useless servant, ‘put him out into the darkness’ outside, where there will be weeping and grinding of teeth.’", "acv": "And cast ye the unprofitable bondman into the outer darkness. There will be the weeping and the gnashing of teeth.", "anderson": "And cast the unprofitable servant into the darkness without. There shall be weeping and gnashing of teeth.", "haweis": "And cast the unprofitable servant into the outer darkness: there shall be weeping and gnashing of teeth.", "noyes": "And cast out the unprofitable servant into the outer darkness; there will be wailing and gnashing of teeth.", "webster": "And cast ye the unprofitable servant into utter darkness: there shall be weeping and gnashing of teeth.", "vulgate": "et inutilem servum eicite in tenebras exteriores illic erit fletus et stridor dentium;"}}, {"v": 31, "ref": "25:31", "o": "Ὅταν δὲ ἔλθῃ ὁ υἱὸς τοῦ ἀνθρώπου ἐν τῇ δόξῃ αὐτοῦ καὶ πάντες ⸀οἱ ἄγγελοι μετ’ αὐτοῦ, τότε καθίσει ἐπὶ θρόνου δόξης αὐτοῦ·", "en": {"kjv": "When the Son of man shall come in his glory, and all the holy angels with him, then shall he sit upon the throne of his glory:", "web": "“But when the Son of Man comes in his glory, and all the holy angels with him, then he will sit on the throne of his glory.", "bsb": "When the Son of Man comes in His glory, and all the angels with Him, He will sit on His glorious throne.", "asv": "But when the Son of man shall come in his glory, and all the angels with him, then shall he sit on the throne of his glory:", "ylt": "`And whenever the Son of Man may come in his glory, and all the holy messengers with him, then he shall sit upon a throne of his glory;", "tyndale": "When the sonne of ma cometh in his glorie and all the holy angels wt him then shall he syt vpon the seate of his glorie", "dra": "And when the Son of man shall come in his majesty, and all the angels with him, then shall he sit upon the seat of his majesty.", "bbe": "But when the Son of man comes in his glory, and all the angels with him, then will he be seated in his glory:", "geneva": "And when the Sonne of man commeth in his glory, and all the holy Angels with him, then shall he sit vpon the throne of his glorie,", "wycliffe": "Whanne mannus sone schal come in his maieste, and alle hise aungels with hym, thanne he schal sitte on the sege of his maieste;", "rotherham": "But, whensoever the Son of Man shall come in his glory, and all the messengers with him, then will he sit on his throne of glory;", "weymouth": "\"When the Son of Man comes in His glory, and all the angels with Him, then will He sit upon His glorious throne,", "darby": "But when the Son of man comes in his glory, and all the angels with him, then shall he sit down upon his throne of glory,", "twenty": "When the Son of Man has come in his glory and all the angels with him, then he ‘will take his seat on his throne of glory’;", "acv": "But when the Son of man comes in his glory, and all the holy agents with him, then he will sit on the throne of his glory.", "anderson": "When the Son of man shall come in his own glory, and all the holy angels with him, then will he sit on the throne of his own glory;", "haweis": "But when the Son of man shall come in his glory, and all the holy angels with him, then shall he sit on the throne of his glory:", "noyes": "And when the Son of man shall come in his glory, and all the angels with him, then will he sit on the throne of his glory,", "webster": "When the Son of man shall come in his glory, and all the holy angels with him, then will he sit upon the throne of his glory:", "vulgate": "cum autem venerit Filius hominis in maiestate sua et omnes angeli cum eo tunc sedebit super sedem maiestatis suae;"}}, {"v": 32, "ref": "25:32", "o": "καὶ ⸀συναχθήσονται ἔμπροσθεν αὐτοῦ πάντα τὰ ἔθνη, καὶ ἀφορίσει αὐτοὺς ἀπ’ ἀλλήλων, ὥσπερ ὁ ποιμὴν ἀφορίζει τὰ πρόβατα ἀπὸ τῶν ἐρίφων,", "en": {"kjv": "And before him shall be gathered all nations: and he shall separate them one from another, as a shepherd divideth his sheep from the goats:", "web": "Before him all the nations will be gathered, and he will separate them one from another, as a shepherd separates the sheep from the goats.", "bsb": "All the nations will be gathered before Him, and He will separate the people one from another, as a shepherd separates the sheep from the goats.", "asv": "and before him shall be gathered all the nations: and he shall separate them one from another, as the shepherd separateth the sheep from the goats;", "ylt": "and gathered together before him shall be all the nations, and he shall separate them from one another, as the shepherd doth separate the sheep from the goats,", "tyndale": "and before him shalbe Gaddred all nacions. And he shall seperate the one from a nother as a shepherde deuideth the shepe from the gootes.", "dra": "And all nations shall be gathered together before him: and he shall separate them one from another, as the shepherd separateth the sheep from the goats:", "bbe": "And before him all the nations will come together; and they will be parted one from another, as the sheep are parted from the goats by the keeper.", "geneva": "And before him shalbe gathered all nations, and he shall seperate them one from another, as a shepheard separateth the sheepe from ye goates.", "wycliffe": "and alle folkis schulen be gaderid bifor hym,", "rotherham": "And there will be gathered before him, all the nations, and he will separate them one from another, just as, the shepherd! separateth the sheep from the goats,—", "weymouth": "and all the nations will be gathered into His presence. And He will separate them from one another, just as a shepherd separates the sheep from the goats;", "darby": "and all the nations shall be gathered before him; and he shall separate them from one another, as the shepherd separates the sheep from the goats;", "twenty": "and all the nations will be gathered before him, and he will separate the people — just as a shepherd separates sheep from goats —", "acv": "And all the nations will be gathered before him, and he will separate them from each other, as the shepherd separates the sheep from the goats.", "anderson": "and all nations shall be gathered before him; and he will separate them one from another, as a shepherd separates his sheep from the goats.", "haweis": "and before him shall all the nations be gathered together; and he shall separate them one from another, as a shepherd separates the sheep from the goats:", "noyes": "and before him will be gathered all the nations; and he will separate men one from another, as a shepherd separateth the sheep from the goats;", "webster": "And before him shall be gathered all nations: and he will separate them one from another, as a shepherd divideth [his] sheep from the goats:", "vulgate": "et congregabuntur ante eum omnes gentes et separabit eos ab invicem sicut pastor segregat oves ab hedis;"}}, {"v": 33, "ref": "25:33", "o": "καὶ στήσει τὰ μὲν πρόβατα ἐκ δεξιῶν αὐτοῦ τὰ δὲ ἐρίφια ἐξ εὐωνύμων.", "en": {"kjv": "And he shall set the sheep on his right hand, but the goats on the left.", "web": "He will set the sheep on his right hand, but the goats on the left.", "bsb": "He will place the sheep on His right and the goats on His left.", "asv": "and he shall set the sheep on his right hand, but the goats on the left.", "ylt": "and he shall set the sheep indeed on his right hand, and the goats on the left.", "tyndale": "And he shall set the shepe on his right honde and the gotes on the lyfte.", "dra": "And he shall set the sheep on his right hand, but the goats on his left.", "bbe": "And he will put the sheep on his right, but the goats on the left.", "geneva": "And he shall set the sheepe on his right hand, and the goates on the left.", "wycliffe": "and he schal departe hem atwynne, as a scheeperde departith scheep from kidis; and he schal sette the scheep on his riythalf, and the kidis on the lefthalf.", "rotherham": "And he will set, the sheep, indeed, on his right hand, but, the goats, on the left.", "weymouth": "and will make the sheep stand at His right hand, and the goats at His left.", "darby": "and he will set the sheep on his right hand, and the goats on [his] left.", "twenty": "placing the sheep on his right hand, and the goats on his left.", "acv": "And he will truly place the sheep at his right hand, but the goats at the left.", "anderson": "And he will place the sheep on his right hand, but the goats on his left.", "haweis": "and he shall place the sheep at his right hand, but the goats at the left.", "noyes": "and he will set the sheep on his right hand, and the goats on the left.", "webster": "And he will set the sheep on his right hand, but the goats on the left.", "vulgate": "et statuet oves quidem a dextris suis hedos autem a sinistris;"}}, {"v": 34, "ref": "25:34", "o": "τότε ἐρεῖ ὁ βασιλεὺς τοῖς ἐκ δεξιῶν αὐτοῦ· Δεῦτε, οἱ εὐλογημένοι τοῦ πατρός μου, κληρονομήσατε τὴν ἡτοιμασμένην ὑμῖν βασιλείαν ἀπὸ καταβολῆς κόσμου.", "en": {"kjv": "Then shall the King say unto them on his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:", "web": "Then the King will tell those on his right hand, ‘Come, blessed of my Father, inherit the Kingdom prepared for you from the foundation of the world;", "bsb": "Then the King will say to those on His right, ‘Come, you who are blessed by My Father, inherit the kingdom prepared for you from the foundation of the world.", "asv": "Then shall the King say unto them on his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:", "ylt": "`Then shall the king say to those on his right hand, Come ye, the blessed of my Father, inherit the reign that hath been prepared for you from the foundation of the world;", "tyndale": "Then shall the kynge saye to them on his right honde: Come ye blessed chyldren of my father inheret ye the kyngdo prepared for you from the beginninge of the worlde.", "dra": "Then shall the king say to them that shall be on his right hand: Come, ye blessed of my Father, possess you the kingdom prepared for you from the foundation of the world.", "bbe": "Then will the King say to those on his right, Come, you who have the blessing of my Father, into the kingdom made ready for you before the world was:", "geneva": "Then shall ye king say to them on his right hand, Come ye blessed of my father: take the inheritance of the kingdome prepared for you from the foundation of the world.", "wycliffe": "Thanne the kyng schal seie to hem, that schulen be on his riythalf, Come ye, the blessid of my fadir, take ye in possessioun the kyngdoom maad redi to you fro the makyng of the world.", "rotherham": "Then, will the king say to those on his right hand: Come ye, the blessed of my Father! Inherit the kingdom prepared for you from the foundation of the world;", "weymouth": "\"Then the King will say to those at His right, \"`Come, my Father's blessed ones, receive your inheritance of the Kingdom which has been divinely intended for you ever since the creation of the world.", "darby": "Then shall the King say to those on his right hand, Come, blessed of my Father, inherit the kingdom prepared for you from [the] world's foundation:", "twenty": "Then the King will say to those on his right ‘Come, you who are blessed by my Father, enter upon possession of the Kingdom prepared for you ever since the beginning of the world.", "acv": "Then the King will say to those at his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world.", "anderson": "Then the King will say to those on his right hand: Come, you blessed of my Father, inherit the kingdom prepared for you from the foundation of the world.", "haweis": "Then shall the King say to those on his right-hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world;", "noyes": "Then will the king say to those on his right hand, Come, ye blessed by my Father, inherit the kingdom prepared for you from the foundation of the world.", "webster": "Then will the King say to them on his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:", "vulgate": "tunc dicet rex his qui a dextris eius erunt venite benedicti Patris mei possidete paratum vobis regnum a constitutione mundi;"}}, {"v": 35, "ref": "25:35", "o": "ἐπείνασα γὰρ καὶ ἐδώκατέ μοι φαγεῖν, ἐδίψησα καὶ ἐποτίσατέ με, ξένος ἤμην καὶ συνηγάγετέ με,", "en": {"kjv": "For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:", "web": "for I was hungry, and you gave me food to eat. I was thirsty, and you gave me drink. I was a stranger, and you took me in.", "bsb": "For I was hungry and you gave Me something to eat, I was thirsty and you gave Me something to drink, I was a stranger and you took Me in,", "asv": "for I was hungry, and ye gave me to eat; I was thirsty, and ye gave me drink; I was a stranger, and ye took me in;", "ylt": "for I did hunger, and ye gave me to eat; I did thirst, and ye gave me to drink; I was a stranger, and ye received me;", "tyndale": "For I was anhongred and ye gave me meate. I thursted and ye gave me drinke. I was herbourlesse and ye lodged me.", "dra": "For I was hungry, and you gave me to eat: I was thirsty, and you gave me to drink: I was a stranger, and you took me in:", "bbe": "For I was in need of food, and you gave it to me: I was in need of drink, and you gave it to me: I was wandering, and you took me in;", "geneva": "For I was an hungred, and ye gaue me meate: I thirsted, and ye gaue me drinke: I was a stranger, and ye tooke me in vnto you.", "wycliffe": "For Y hungride, and ye yauen me to ete; Y thristide, and ye yauen me to drynke; Y was herboreles, and ye herboriden me;", "rotherham": "For I hungered, and ye gave me to eat, I thirsted, and ye gave me drink, a stranger, was I, and ye took me home,", "weymouth": "For when I was hungry, you gave me food; when I was thirsty, you gave me drink; when I was homeless, you gave me a welcome;", "darby": "for I hungered, and ye gave me to eat; I thirsted, and ye gave me to drink; I was a stranger, and ye took me in;", "twenty": "For, when I was hungry, you gave me food; when I was thirsty, you gave me drink; when I was a stranger, you took me to your homes;", "acv": "For I was hungry, and ye gave me to eat. I was thirsty, and ye gave me to drink. I was a stranger, and ye took me in,", "anderson": "For I was hungry, and you gave me food; I was thirsty, and you gave me drink; I was a stranger, and you took me to your houses;", "haweis": "for I was hungry, and ye gave me to eat: I was thirsty, and ye gave me to drink: I was a stranger, and ye received me hospitably:", "noyes": "For I was hungry, and ye gave me food; I was thirsty, and ye gave me drink; I was a stranger, and ye took me in;", "webster": "For I was hungry, and ye gave me food: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:", "vulgate": "esurivi enim et dedistis mihi manducare sitivi et dedistis mihi bibere hospes eram et collexistis me;"}}, {"v": 36, "ref": "25:36", "o": "γυμνὸς καὶ περιεβάλετέ με, ἠσθένησα καὶ ἐπεσκέψασθέ με, ἐν φυλακῇ ἤμην καὶ ἤλθατε πρός με.", "en": {"kjv": "Naked, and ye clothed me: I was sick, and ye visited me: I was in prison, and ye came unto me.", "web": "I was naked, and you clothed me. I was sick, and you visited me. I was in prison, and you came to me.’", "bsb": "I was naked and you clothed Me, I was sick and you looked after Me, I was in prison and you visited Me.’", "asv": "naked, and ye clothed me; I was sick, and ye visited me; I was in prison, and ye came unto me.", "ylt": "naked, and ye put around me; I was infirm, and ye looked after me; in prison I was, and ye came unto me.", "tyndale": "I was naked and ye clothed me. I was sicke and ye visited me. I was in preson and ye came vnto me.", "dra": "Naked, and you covered me: sick, and you visited me: I was in prison, and you came to me.", "bbe": "I had no clothing, and you gave it to me: when I was ill, or in prison, you came to me.", "geneva": "I was naked, and ye clothed me: I was sicke, and ye visited me: I was in prison, and ye came vnto me.", "wycliffe": "nakid, and ye hiliden me; sijk, and ye visitiden me; Y was in prisoun, and ye camen to me.", "rotherham": "Naked, and ye clothed me, sick, and ye visited me, in prison, was I, and ye came unto me.", "weymouth": "when I was ill-clad, you clothed me; when I was sick, you visited me; when I was in prison, you came to see me.'", "darby": "naked, and ye clothed me; I was ill, and ye visited me; I was in prison, and ye came to me.", "twenty": "when I was naked, you clothed me; when I fell ill, you visited me; and when I was in prison, you came to me.’", "acv": "naked, and ye clothed me. I was feeble, and ye came to help me. I was in prison, and ye came to me.", "anderson": "naked, and you clothed me; I was sick, and you visited me; I was in prison, and you came to me.", "haweis": "naked, and ye clothed me: I was sick, and ye took care of me: I was in prison, and ye came to me.", "noyes": "naked, and ye clothed me; I was sick, and ye visited me; I was in prison, and ye came to me.", "webster": "Naked, and ye clothed me: I was sick, and ye visited me: I was in prison, and ye came to me.", "vulgate": "nudus et operuistis me infirmus et visitastis me in carcere eram et venistis ad me;"}}, {"v": 37, "ref": "25:37", "o": "τότε ἀποκριθήσονται αὐτῷ οἱ δίκαιοι λέγοντες· Κύριε, πότε σε εἴδομεν πεινῶντα καὶ ἐθρέψαμεν, ἢ διψῶντα καὶ ἐποτίσαμεν;", "en": {"kjv": "Then shall the righteous answer him, saying, Lord, when saw we thee an hungred, and fed thee? or thirsty, and gave thee drink?", "web": "“Then the righteous will answer him, saying, ‘Lord, when did we see you hungry, and feed you; or thirsty, and give you a drink?", "bsb": "Then the righteous will answer Him, ‘Lord, when did we see You hungry and feed You, or thirsty and give You something to drink?", "asv": "Then shall the righteous answer him, saying, Lord, when saw we thee hungry, and fed thee? or athirst, and gave thee drink?", "ylt": "`Then shall the righteous answer him, saying, Lord, when did we see thee hungering, and we nourished? or thirsting, and we gave to drink?", "tyndale": "Then shall ye righteous answere him sayinge master whe sawe we ye anhongred and feed the? or a thurst and gave ye drinke?", "dra": "Then shall the just answer him, saying: Lord, when did we see thee hungry and fed thee: thirsty and gave thee drink?", "bbe": "Then will the upright make answer to him, saying, Lord, when did we see you in need of food, and give it to you? or in need of drink, and give it to you?", "geneva": "Then shall the righteous answere him, saying, Lord, when sawe we thee an hungred, and fed thee? or a thirst, and gaue thee drinke?", "wycliffe": "Thanne iust men schulen answere to hym, and seie, Lord, whanne siyen we thee hungry, and we fedden thee; thristi, and we yauen to thee drynk?", "rotherham": "Then, will the righteous answer him, saying: Lord! when, saw we thee—hungry, and fed thee, or thirsty, and gave thee drink?", "weymouth": "\"`When, Lord,' the righteous will reply, `did we see Thee hungry, and feed Thee; or thirsty, and give Thee drink?", "darby": "Then shall the righteous answer him saying, Lord, when saw we thee hungering, and nourished thee; or thirsting, and gave thee to drink?", "twenty": "Then the Righteous will answer ‘Lord, when did we see you hungry, and feed you? Or thirsty, and give you a drink?", "acv": "Then the righteous will answer him, saying, Lord, when did we see thee hungering, and fed thee, or thirsting, and gave thee drink?", "anderson": "Then will the righteous answer him, saying: Lord, when did we see thee hungry, and feed thee? or thirsty, and give thee drink?", "haweis": "Then shall the righteous answer him, saying, Lord, when saw we thee hungry, and fed thee? or thirsty, and gave thee drink?", "noyes": "Then will the righteous answer him, saying, Lord, when saw we thee hungry, and fed thee? or thirsty, and gave thee drink?", "webster": "Then will the righteous answer him, saying, Lord, when saw we thee hungry, and fed [thee]? or thirsty, and gave [thee] drink?", "vulgate": "tunc respondebunt ei iusti dicentes Domine quando te vidimus esurientem et pavimus sitientem et dedimus tibi potum;"}}, {"v": 38, "ref": "25:38", "o": "πότε δέ σε εἴδομεν ξένον καὶ συνηγάγομεν, ἢ γυμνὸν καὶ περιεβάλομεν;", "en": {"kjv": "When saw we thee a stranger, and took thee in? or naked, and clothed thee?", "web": "When did we see you as a stranger, and take you in; or naked, and clothe you?", "bsb": "When did we see You a stranger and take You in, or naked and clothe You?", "asv": "And when saw we thee a stranger, and took thee in? or naked, and clothed thee?", "ylt": "and when did we see thee a stranger, and we received? or naked, and we put around?", "tyndale": "when sawe we ye herbourlesse and lodged the? or naked and clothed the?", "dra": "Or when did we see thee a stranger and took thee in? Or naked and covered thee?", "bbe": "And when did we see you wandering, and take you in? or without clothing, and give it to you?", "geneva": "And when sawe we thee a stranger, and tooke thee in vnto vs? or naked, and clothed thee?", "wycliffe": "and whanne sayn we thee herborles, and we herboreden thee; or nakid, and we hiliden thee?", "rotherham": "And, when, saw we thee—a stranger, and took thee home, or naked, and clothed thee?", "weymouth": "When did we see Thee homeless, and give Thee a welcome? or ill-clad, and clothe Thee?", "darby": "and when saw we thee a stranger, and took thee in; or naked, and clothed thee?", "twenty": "When did we see you a stranger, and take you to our homes? Or naked, and clothe you?", "acv": "And when did we see thee a stranger, and took thee in, or naked, and clothed thee?", "anderson": "When did we see thee a stranger, and take thee to our home? or naked, and clothe thee?", "haweis": "When indeed saw we thee a stranger, and took thee in? or naked, and clothed thee?", "noyes": "and when saw we thee a stranger, and took thee in? or naked, and clothed thee?", "webster": "When saw we thee a stranger, and took [thee] in? or naked, and clothed [thee]?", "vulgate": "quando autem te vidimus hospitem et colleximus te aut nudum et cooperuimus;"}}, {"v": 39, "ref": "25:39", "o": "πότε δέ σε εἴδομεν ⸀ἀσθενοῦντα ἢ ἐν φυλακῇ καὶ ἤλθομεν πρός σε;", "en": {"kjv": "Or when saw we thee sick, or in prison, and came unto thee?", "web": "When did we see you sick, or in prison, and come to you?’", "bsb": "When did we see You sick or in prison and visit You?’", "asv": "And when saw we thee sick, or in prison, and came unto thee?", "ylt": "and when did we see thee infirm, or in prison, and we came unto thee?", "tyndale": "or when sawe we the sicke or in preson and came vnto the?", "dra": "Or when did we see thee sick or in prison and came to thee?", "bbe": "And when did we see you ill, or in prison, and come to you?", "geneva": "Or when sawe we thee sicke, or in prison, and came vnto thee?", "wycliffe": "or whanne sayn we thee sijk, or in prisoun, and we camen to thee?", "rotherham": "And, when, saw we thee—sick, or in prison, and came unto thee?", "weymouth": "When did we see Thee sick or in prison, and come to see Thee?'", "darby": "and when saw we thee ill, or in prison, and came to thee?", "twenty": "When did we see you ill, or in prison, and come to you?’", "acv": "And when did we see thee weak, or in prison, and came to thee?", "anderson": "When did we see thee sick, or in prison, and come to thee?", "haweis": "When indeed saw we thee sick, or in prison, and came unto thee?", "noyes": "or when did we see thee sick, or in prison, and come to thee?", "webster": "Or when saw we thee sick, or in prison, and came to thee?", "vulgate": "aut quando te vidimus infirmum aut in carcere et venimus ad te;"}}, {"v": 40, "ref": "25:40", "o": "καὶ ἀποκριθεὶς ὁ βασιλεὺς ἐρεῖ αὐτοῖς· Ἀμὴν λέγω ὑμῖν, ἐφ’ ὅσον ἐποιήσατε ἑνὶ τούτων τῶν ἀδελφῶν μου τῶν ἐλαχίστων, ἐμοὶ ἐποιήσατε.", "en": {"kjv": "And the King shall answer and say unto them, Verily I say unto you, Inasmuch as ye have done it unto one of the least of these my brethren, ye have done it unto me.", "web": "“The King will answer them, ‘Most certainly I tell you, because you did it to one of the least of these my brothers, you did it to me.’", "bsb": "And the King will reply, ‘Truly I tell you, whatever you did for one of the least of these brothers of Mine, you did for Me.’", "asv": "And the King shall answer and say unto them, Verily I say unto you, Inasmuch as ye did it unto one of these my brethren, even these least, ye did it unto me.", "ylt": "`And the king answering, shall say to them, Verily I say to you, Inasmuch as ye did it to one of these my brethren--the least--to me ye did it .", "tyndale": "And ye kynge shall answere and saye vnto them: verely I saye vnto you: in as moche as ye have done it vnto one of ye leest of these my brethren ye have done it to me.", "dra": "And the king answering shall say to them: Amen I say to you, as long as you did it to one of these my least brethren, you did it to me.", "bbe": "And the King will make answer and say to them, Truly I say to you, Because you did it to the least of these my brothers, you did it to me.", "geneva": "And the King shall answere, and say vnto them, Verely I say vnto you, in as much as ye haue done it vnto one of the least of these my brethre, ye haue done it to me.", "wycliffe": "And the kyng answerynge schal seie to hem, Treuli Y seie to you, as longe as ye diden to oon of these my leeste britheren, ye diden to me.", "rotherham": "And, answering, the king will say unto them: Verily, I say unto you—Inasmuch as ye did it unto one of these my least brethren, unto me, ye did it.", "weymouth": "\"But the King will answer them, \"`In solemn truth I tell you that in so far as you rendered such services to one of the humblest of these my brethren, you rendered them to myself.'", "darby": "And the King answering shall say to them, Verily, I say to you, Inasmuch as ye have done it to one of the least of these my brethren, ye have done it to me.", "twenty": "And the King will reply ‘I tell you, as often as you did it to one of these my Brothers, however lowly, you did it to me.’", "acv": "And having answered, the King will say to them, Truly I say to you, inasmuch as ye did it to one of these my brothers, the least, ye did it to me.", "anderson": "And the King will answer and say to them: Verily I say to you, Inasmuch as you did it to one of the least of these my brethren, you did it to me.", "haweis": "And the king answering shall say to them, Verily I tell you, for as much as ye have done it to one of these my brethren, the very least of them, ye have done it unto me.", "noyes": "And the king will answer and say to them, Truly do I say to you, Inasmuch as ye did it to one of the least of these my brethren, ye did it to me.", "webster": "And the king will answer and say to them, Verily I say to you, Inasmuch as ye have done [it] to one of the least of these my brethren, ye have done [it] to me.", "vulgate": "et respondens rex dicet illis amen dico vobis quamdiu fecistis uni de his fratribus meis minimis mihi fecistis;"}}, {"v": 41, "ref": "25:41", "o": "τότε ἐρεῖ καὶ τοῖς ἐξ εὐωνύμων· Πορεύεσθε ἀπ’ ἐμοῦ ⸀οἱ κατηραμένοι εἰς τὸ πῦρ τὸ αἰώνιον τὸ ἡτοιμασμένον τῷ διαβόλῳ καὶ τοῖς ἀγγέλοις αὐτοῦ.", "en": {"kjv": "Then shall he say also unto them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels:", "web": "Then he will say also to those on the left hand, ‘Depart from me, you cursed, into the eternal fire which is prepared for the devil and his angels;", "bsb": "Then He will say to those on His left, ‘Depart from Me, you who are cursed, into the eternal fire prepared for the devil and his angels.", "asv": "Then shall he say also unto them on the left hand, Depart from me, ye cursed, into the eternal fire which is prepared for the devil and his angels:", "ylt": "Then shall he say also to those on the left hand, Go ye from me, the cursed, to the fire, the age-during, that hath been prepared for the Devil and his messengers;", "tyndale": "Then shall the kynge saye vnto them that shalbe on the lyfte hande: departe from me ye coursed into everlastinge fire which is prepared for the devyll and his angels.", "dra": "Then he shall say to them also that shall be on his left hand: Depart from me, you cursed, into everlasting fire, which was prepared for the devil and his angels.", "bbe": "Then will he say to those on the left, Go from me, you cursed ones, into the eternal fire which is ready for the Evil One and his angels:", "geneva": "Then shall he say vnto them on ye left hand, Depart from me ye cursed, into euerlasting fire, which is prepared for the deuill and his angels.", "wycliffe": "Thanne the kyng schal seie also to hem, that schulen be on his lefthalf, Departe fro me, ye cursid, in to euerlastynge fijr, that is maad redi to the deuel and hise aungels.", "rotherham": "Then, will he say unto those also, on his left hand: Depart ye from me, accursed ones! Into the age-abiding fire, which hath been prepared for the adversary and his messengers;", "weymouth": "\"Then will He say to those at His left, \"`Begone from me, with the curse resting upon you, into the Fire of the Ages, which has been prepared for the Devil and his angels.", "darby": "Then shall he say also to those on the left, Go from me, cursed, into eternal fire, prepared for the devil and his angels:", "twenty": "Then he will say to those on his left ‘Go from my presence, accursed, into the ‘aeonian fire which has been prepared for the Devil and his angels.’", "acv": "Then he will also say to those at the left hand, Depart from me, ye accursed, into the eternal fire prepared for the devil and his agents.", "anderson": "Then will he say to those on his left hand: Depart from me, you cursed, into the eternal fire, prepared for the devil and his angels.", "haweis": "Then shall he say also to those on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels:", "noyes": "Then will he say also to those on the left hand, Depart from me, ye cursed, into the everlasting fire, which is prepared for the Devil and his angels.", "webster": "Then will he say also to them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels:", "vulgate": "tunc dicet et his qui a sinistris erunt discedite a me maledicti in ignem aeternum qui paratus est diabolo et angelis eius;"}}, {"v": 42, "ref": "25:42", "o": "ἐπείνασα γὰρ καὶ οὐκ ἐδώκατέ μοι φαγεῖν, ⸀ἐδίψησα καὶ οὐκ ἐποτίσατέ με,", "en": {"kjv": "For I was an hungred, and ye gave me no meat: I was thirsty, and ye gave me no drink:", "web": "for I was hungry, and you didn’t give me food to eat; I was thirsty, and you gave me no drink;", "bsb": "For I was hungry and you gave Me nothing to eat, I was thirsty and you gave Me nothing to drink,", "asv": "for I was hungry, and ye did not give me to eat; I was thirsty, and ye gave me no drink;", "ylt": "for I did hunger, and ye gave me not to eat; I did thirst, and ye gave me not to drink;", "tyndale": "For I was an hungred and ye gave me no meate. I thursted and ye gave me no drinke.", "dra": "For I was hungry and you gave me not to eat: I was thirsty and you gave me not to drink.", "bbe": "For I was in need of food, and you gave it not to me; I was in need of drink, and you gave it not to me:", "geneva": "For I was an hungred, and ye gaue me no meate: I thirsted, and ye gaue me no drinke:", "wycliffe": "For Y hungride, and ye yauen not me to ete; Y thristide, and ye yauen not me to drynke;", "rotherham": "For I hungered, and ye gave me not to eat, [and] I was thirsty, and ye gave me not to drink,", "weymouth": "For when I was hungry, you gave me nothing to eat; when thirsty, you gave me nothing to drink;", "darby": "for I hungered, and ye gave me not to eat; I thirsted, and ye gave me not to drink;", "twenty": "For, when I was hungry, you gave me no food; when I was thirsty, you gave me no drink;", "acv": "For I was hungry, and ye did not give me to eat, I was thirsty, and ye gave me no drink,", "anderson": "For I was hungry, and you gave me no food; I was thirsty, and you gave me no drink;", "haweis": "for I was hungry, and ye gave me nothing to eat: I was thirsty, and ye gave me nothing to drink:", "noyes": "For I was hungry, and ye gave me no food; I was thirsty, and ye gave me no drink;", "webster": "For I was hungry, and ye gave me no food: I was thirsty, and ye gave me no drink:", "vulgate": "esurivi enim et non dedistis mihi manducare sitivi et non dedistis mihi potum;"}}, {"v": 43, "ref": "25:43", "o": "ξένος ἤμην καὶ οὐ συνηγάγετέ με, γυμνὸς καὶ οὐ περιεβάλετέ με, ἀσθενὴς καὶ ἐν φυλακῇ καὶ οὐκ ἐπεσκέψασθέ με.", "en": {"kjv": "I was a stranger, and ye took me not in: naked, and ye clothed me not: sick, and in prison, and ye visited me not.", "web": "I was a stranger, and you didn’t take me in; naked, and you didn’t clothe me; sick, and in prison, and you didn’t visit me.’", "bsb": "I was a stranger and you did not take Me in, I was naked and you did not clothe Me, I was sick and in prison and you did not visit Me.’", "asv": "I was a stranger, and ye took me not in; naked, and ye clothed me not; sick, and in prison, and ye visited me not.", "ylt": "a stranger I was, and ye did not receive me; naked, and ye put not around me; infirm, and in prison, and ye did not look after me.", "tyndale": "I was herbourlesse and ye lodged me not. I was naked and ye clothed me not. I was sicke and in preson and ye visited me not.", "dra": "I was a stranger and you took me not in: naked and you covered me not: sick and in prison and you did not visit me.", "bbe": "I was wandering, and you took me not in; without clothing, and you gave me no clothing; ill, and in prison, and you came not to me.", "geneva": "I was a stranger, and ye tooke me not in vnto you: I was naked, and ye clothed me not: sicke, and in prison, and ye visited me not.", "wycliffe": "Y was herborles, and ye herberden not me; nakid, and ye keuerden not me; sijk, and in prisoun, and ye visitiden not me.", "rotherham": "A stranger, was I, and ye took me not home, naked, and ye clothed me not, sick, and in prison, and ye visited me not.", "weymouth": "when homeless, you gave me no welcome; ill-clad, you clothed me not; sick or in prison, you visited me not.'", "darby": "I was a stranger, and ye took me not in; naked, and ye did not clothe me; ill, and in prison, and ye did not visit me.", "twenty": "when I was a stranger, you did not take me to your homes; when I was naked, you did not clothe me; and, when I was ill and in prison, you did not visit me.’", "acv": "I was a stranger, and ye did not take me in, naked, and ye did not clothe me, weak, and in prison, and ye did not come to help me.", "anderson": "I was a stranger, and you took me not to your houses; naked, and you did not clothe me; I was sick, and in prison, and you did not visit me.", "haweis": "I was a stranger, and ye took me not in: naked, and ye did not clothe me: sick, and in prison, and ye took no care of me.", "noyes": "I was a stranger, and ye took me not in; naked, and ye clothed me not; sick, and in prison, and ye visited me not.", "webster": "I was a stranger, and ye took me not in: naked, and ye clothed me not: sick, and in prison, and ye visited me not.", "vulgate": "hospes eram et non collexistis me nudus et non operuistis me infirmus et in carcere et non visitastis me;"}}, {"v": 44, "ref": "25:44", "o": "τότε ἀποκριθήσονται καὶ αὐτοὶ λέγοντες· Κύριε, πότε σε εἴδομεν πεινῶντα ἢ διψῶντα ἢ ξένον ἢ γυμνὸν ἢ ἀσθενῆ ἢ ἐν φυλακῇ καὶ οὐ διηκονήσαμέν σοι;", "en": {"kjv": "Then shall they also answer him, saying, Lord, when saw we thee an hungred, or athirst, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?", "web": "“Then they will also answer, saying, ‘Lord, when did we see you hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and didn’t help you?’", "bsb": "And they too will reply, ‘Lord, when did we see You hungry or thirsty or a stranger or naked or sick or in prison, and did not minister to You?’", "asv": "Then shall they also answer, saying, Lord, when saw we thee hungry, or athirst, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?", "ylt": "`Then shall they answer, they also, saying, Lord, when did we see thee hungering, or thirsting, or a stranger, or naked, or infirm, or in prison, and we did not minister to thee?", "tyndale": "Then shall they also answere him sayinge: master when sawe we the an hungred or a thurst or herbourlesse or naked or sicke or in preson and did not ministre vnto the?", "dra": "Then they also shall answer him, saying: Lord, when did we see thee hungry or thirsty or a stranger or naked or sick or in prison and did not minister to thee?", "bbe": "Then will they make answer, saying, Lord, when did we see you in need of food or drink, or wandering, or without clothing, or ill, or in prison, and did not take care of you?", "geneva": "Then shall they also answere him, saying, Lord, when sawe we thee an hungred, or a thirst, or a stranger, or naked, or sicke, or in prison, and did not minister vnto thee?", "wycliffe": "Thanne and thei schulen answere to hym, and schulen seie, Lord, whanne sayn we thee hungrynge, or thristynge, or herboreles, or nakid, or sijk, or in prisoun, and we serueden not to thee?", "rotherham": "Then, will, they also, answer, saying: Lord! when saw we thee—hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and ministered not unto thee?", "weymouth": "\"Then will they also answer, \"`Lord, when did we see Thee hungry or thirsty or homeless or ill-clad or sick or in prison, and not come to serve Thee?'", "darby": "Then shall they also answer saying, Lord, when saw we thee hungering, or thirsting, or a stranger, or naked, or ill, or in prison, and have not ministered to thee?", "twenty": "Then they, in their turn, will answer ‘Lord, when did we see you hungry, or thirsty, or a stranger, or naked, or ill, or in prison, and did not supply your wants?’", "acv": "Then they will also answer, saying, Lord, when did we see thee hungering, or thirsting, or a stranger, or naked, or weak, or in prison, and did not serve thee?", "anderson": "Then they also will answer, and say: Lord, when did we see thee hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and did not minister to thee?", "haweis": "Then shall they also answer him, saying, Lord, when saw we thee hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?", "noyes": "Then will they also answer, saying, Lord, when saw we thee hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and did not minister to thee?", "webster": "Then will they also answer him, saying, Lord, when saw we thee hungry, or thirsty, or a stranger, or naked, or sick, or in prison, and did not minister to thee?", "vulgate": "tunc respondebunt et ipsi dicentes Domine quando te vidimus esurientem aut sitientem aut hospitem aut nudum aut infirmum vel in carcere et non ministravimus tibi;"}}, {"v": 45, "ref": "25:45", "o": "τότε ἀποκριθήσεται αὐτοῖς λέγων· Ἀμὴν λέγω ὑμῖν, ἐφ’ ὅσον οὐκ ἐποιήσατε ἑνὶ τούτων τῶν ἐλαχίστων, οὐδὲ ἐμοὶ ἐποιήσατε.", "en": {"kjv": "Then shall he answer them, saying, Verily I say unto you, Inasmuch as ye did it not to one of the least of these, ye did it not to me.", "web": "“Then he will answer them, saying, ‘Most certainly I tell you, because you didn’t do it to one of the least of these, you didn’t do it to me.’", "bsb": "Then the King will answer, ‘Truly I tell you, whatever you did not do for one of the least of these, you did not do for Me.’", "asv": "Then shall he answer them, saying, Verily I say unto you, Inasmuch as ye did it not unto one of these least, ye did it not unto me.", "ylt": "`Then shall he answer them, saying, Verily I say to you, Inasmuch as ye did it not to one of these, the least, ye did it not to me.", "tyndale": "Then shall he answere the and saye: Verely I saye vnto you in as moche as ye did it not to one of ye leest of these ye did it not to me.", "dra": "Then he shall answer them, saying: Amen: I say to you, as long as you did it not to one of these least, neither did you do it to me.", "bbe": "Then will he make answer to them, saying, Truly I say to you, Because you did it not to the least of these, you did it not to me.", "geneva": "Then shall he answere them, and say, Verely I say vnto you, in as much as ye did it not to one of the least of these, ye did it not to me.", "wycliffe": "Thanne he schal answere to hem, and seie, Treuli Y seie to you, `hou longe ye diden not to oon of these leeste, nether ye diden to me.", "rotherham": "Then, will he answer them, saying: Verily, I say unto you—Inasmuch as ye did it not, unto one of these least, neither unto me, did ye it.", "weymouth": "\"But he will reply, \"`In solemn truth I tell you that in so far as you withheld such services from one of the humblest of these, you withheld them from me.'", "darby": "Then shall he answer them saying, Verily I say to you, Inasmuch as ye have not done it to one of these least, neither have ye done it to me.", "twenty": "And then he will reply ‘I tell you, as often as you failed to do it to one of these, however lowly, you failed to do it to me.’", "acv": "Then he will answer them, saying, Truly I say to you, inasmuch as ye did it not to one of these least, ye did it not to me.", "anderson": "Then will he answer them, saying: Verily I say to you, Inasmuch as you did it not to one of the least of these, you did it not to me.", "haweis": "Then shall he reply to them, saying, For as much as ye have not done it to one of the least of these, neither have ye done it to me.", "noyes": "Then will he answer them, saying, Truly do I say to you, Inasmuch as ye did it not to one of the least of these, ye did it not to me.", "webster": "Then will he answer them, saying, Verily I say to you, Inasmuch as ye did [it] not to one of the least of these, ye did [it] not to me.", "vulgate": "tunc respondebit illis dicens amen dico vobis quamdiu non fecistis uni de minoribus his nec mihi fecistis;"}}, {"v": 46, "ref": "25:46", "o": "καὶ ἀπελεύσονται οὗτοι εἰς κόλασιν αἰώνιον, οἱ δὲ δίκαιοι εἰς ζωὴν αἰώνιον.", "en": {"kjv": "And these shall go away into everlasting punishment: but the righteous into life eternal.", "web": "These will go away into eternal punishment, but the righteous into eternal life.”", "bsb": "And they will go away into eternal punishment, but the righteous into eternal life.”", "asv": "And these shall go away into eternal punishment: but the righteous into eternal life.", "ylt": "And these shall go away to punishment age-during, but the righteous to life age-during.'", "tyndale": "And these shall go into everlastinge payne: And the righteous into lyfe eternall.", "dra": "And these shall go into everlasting punishment: but the just, into life everlasting.", "bbe": "And these will go away into eternal punishment; but the upright into eternal life.", "geneva": "And these shall goe into euerlasting paine, and the righteous into life eternall.", "wycliffe": "And these schulen goo in to euerlastynge turment; but the iust men schulen go in to euerlastynge lijf.", "rotherham": "And, these, shall go away, into, age-abiding, correction, but, the righteous, into, age-abiding, life.", "weymouth": "\"And these shall go away into the Punishment of the Ages, but the righteous into the Life of the Ages.\"", "darby": "And these shall go away into eternal punishment, and the righteous into life eternal.", "twenty": "And these last will go away ‘into aeonian punishment,’ but the righteous ‘into aeonian life.’”", "acv": "And these will go away into eternal punishment, but the righteous into eternal life.", "anderson": "And these shall go away into eternal punishment, but the righteous into eternal life.", "haweis": "And these shall go away into everlasting punishment: but the righteous into life eternal.", "noyes": "And these will go away into everlasting punishment; but the righteous into everlasting life.", "webster": "And these shall go away into everlasting punishment: but the righteous into life eternal.", "vulgate": "et ibunt hii in supplicium aeternum iusti autem in vitam aeternam;"}}]}, {"c": 26, "verses": [{"v": 1, "ref": "26:1", "o": "Καὶ ἐγένετο ὅτε ἐτέλεσεν ὁ Ἰησοῦς πάντας τοὺς λόγους τούτους, εἶπεν τοῖς μαθηταῖς αὐτοῦ·", "en": {"kjv": "And it came to pass, when Jesus had finished all these sayings, he said unto his disciples,", "web": "When Jesus had finished all these words, he said to his disciples,", "bsb": "When Jesus had finished saying all these things, He told His disciples,", "asv": "And it came to pass, when Jesus had finished all these words, he said unto his disciples,", "ylt": "And it came to pass, when Jesus finished all these words, he said to his disciples,", "tyndale": "And it came to passe when Iesus had fynisshed all these sayinges he sayd vnto his disciples:", "dra": "And it came to pass, when Jesus had ended all these words, he said to his disciples:", "bbe": "And when Jesus had come to the end of all these words, he said to his disciples,", "geneva": "And it came to passe, when Iesus had finished all these sayings, he saide vnto his disciples,", "wycliffe": "And it was doon, whanne Jhesus hadde endid alle these wordis, he seide to hise disciplis,", "rotherham": "And it came to pass, when Jesus ended all these words, he said unto his disciples:", "weymouth": "When Jesus had ended all these discourses, He said to His disciples,", "darby": "And it came to pass when Jesus had finished all these sayings, he said to his disciples,", "twenty": "When Jesus had finished all this teaching, he said to his disciples:", "acv": "And it came to pass, when Jesus had finished all these saying, he said to his disciples,", "anderson": "And it came to pass, when Jesus had finished all these words, that he said to his disciples:", "haweis": "AND it came to pass, that when Jesus had finished all these sayings, he said to his disciples,", "noyes": "And it came to pass, when Jesus had finished all these sayings, that he said to his disciples,", "webster": "And it came to pass, when Jesus had finished all these sayings, he said to his disciples,", "vulgate": "et factum est cum consummasset Iesus sermones hos omnes dixit discipulis suis;"}}, {"v": 2, "ref": "26:2", "o": "Οἴδατε ὅτι μετὰ δύο ἡμέρας τὸ πάσχα γίνεται, καὶ ὁ υἱὸς τοῦ ἀνθρώπου παραδίδοται εἰς τὸ σταυρωθῆναι.", "en": {"kjv": "Ye know that after two days is the feast of the passover, and the Son of man is betrayed to be crucified.", "web": "“You know that after two days the Passover is coming, and the Son of Man will be delivered up to be crucified.”", "bsb": "“You know that the Passover is two days away, and the Son of Man will be handed over to be crucified.”", "asv": "Ye know that after two days the passover cometh, and the Son of man is delivered up to be crucified.", "ylt": "`Ye have known that after two days the passover cometh, and the Son of Man is delivered up to be crucified.'", "tyndale": "Ye knowe that after ii. dayes shalbe ester and the sonne of man shalbe delyvered to be crucified.", "dra": "You know that after two days shall be the pasch: and the Son of man shall be delivered up to be crucified.", "bbe": "After two days is the Passover, and the Son of man will be given up to the death of the cross.", "geneva": "Ye know that after two dayes is ye Passeouer, and the Sonne of man shalbe deliuered to be crucified.", "wycliffe": "Ye witen, that aftir twei daies pask schal be maad, and mannus sone schal be bitakun to be crucified.", "rotherham": "Ye know that, after two days, the passover, taketh place,—and, the Son of Man, is to be delivered up, to be crucified.", "weymouth": "\"You know that in two days' time the Passover comes. And the Son of Man will be delivered up to be crucified.\"", "darby": "Ye know that after two days the passover takes place, and the Son of man is delivered up to be crucified.", "twenty": "“You know that in two days time the Festival of the Passover will be here; and that the Son of Man is to be given up to be crucified.”", "acv": "Ye know that after two days the Passover comes, and the Son of man is betrayed to be crucified.", "anderson": "You know that after two days the passover is kept, and the Son of man is delivered up to be crucified.", "haweis": "Ye know that after two days is the passover, and the Son of man is betrayed to be crucified.", "noyes": "Ye know that after two days cometh the passover; and the Son of man is delivered up to be crucified.", "webster": "Ye know that after two days is the passover, and the Son of man is betrayed to be crucified.", "vulgate": "scitis quia post biduum pascha fiet et Filius hominis tradetur ut crucifigatur;"}}, {"v": 3, "ref": "26:3", "o": "Τότε συνήχθησαν οἱ ⸀ἀρχιερεῖς καὶ οἱ πρεσβύτεροι τοῦ λαοῦ εἰς τὴν αὐλὴν τοῦ ἀρχιερέως τοῦ λεγομένου Καϊάφα,", "en": {"kjv": "Then assembled together the chief priests, and the scribes, and the elders of the people, unto the palace of the high priest, who was called Caiaphas,", "web": "Then the chief priests, the scribes, and the elders of the people were gathered together in the court of the high priest, who was called Caiaphas.", "bsb": "At that time the chief priests and elders of the people assembled in the courtyard of the high priest, whose name was Caiaphas,", "asv": "Then were gathered together the chief priests, and the elders of the people, unto the court of the high priest, who was called Caiaphas;", "ylt": "Then were gathered together the chief priests, and the scribes, and the elders of the people, to the court of the chief priest who was called Caiaphas;", "tyndale": "Then assembled togedder the chefe prestes and the scribes and the elders of the people to the palice of the hye preste called Cayphas", "dra": "Then were gathered together the chief priests and ancients of the people, into the court of the high priest, who was called Caiphas:", "bbe": "Then the chief priests and the rulers of the people came together in the house of the high priest, who was named Caiaphas.", "geneva": "Then assembled together the chiefe Priests, and the Scribes, and the Elders of ye people into the hall of the high Priest called Caiaphas:", "wycliffe": "Than the princes of prestis and the elder men of the puple were gaderid in to the halle of the prince of prestis, that was seid Cayfas,", "rotherham": "Then, were gathered together, the High-priests and the Elders of the people, into the court of the High-priest who was called Caiaphas;", "weymouth": "Then the High Priests and Elders of the People assembled in the court of the palace of the High Priest Caiaphas,", "darby": "Then the chief priests and the elders of the people were gathered together to the palace of the high priest who was called Caiaphas,", "twenty": "Then the Chief Priests and the Councillors of the Nation met in the house of the High Priest, who was called Caiaphas,", "acv": "Then the chief priests, and the scholars, and the elders of the people, assembled together to the courtyard of the high priest, who was called Caiaphas,", "anderson": "Then the chief priests, and the scribes, and the elders of the people met together at the palace of the chief priest, who was called Caiaphas.", "haweis": "Then were the chief priests and scribes, and the elders of the people gathered together in the palace of the high-priest, called Caiaphas.", "noyes": "Then the chief priests and the elders of the people assembled in the court of the palace of the high-priest, named Caiaphas;", "webster": "Then assembled the chief priests, and the scribes, and the elders of the people, in the palace of the high priest, who was called Caiaphas,", "vulgate": "tunc congregati sunt principes sacerdotum et seniores populi in atrium principis sacerdotum qui dicebatur Caiaphas;"}}, {"v": 4, "ref": "26:4", "o": "καὶ συνεβουλεύσαντο ἵνα τὸν Ἰησοῦν δόλῳ κρατήσωσιν καὶ ἀποκτείνωσιν·", "en": {"kjv": "And consulted that they might take Jesus by subtilty, and kill him.", "web": "They took counsel together that they might take Jesus by deceit, and kill him.", "bsb": "and they conspired to arrest Jesus covertly and kill Him.", "asv": "and they took counsel together that they might take Jesus by subtlety, and kill him.", "ylt": "and they consulted together that they might take Jesus by guile, and kill him ,", "tyndale": "and heelde a counsell how they mygt take Iesus by suttelte and kyll him.", "dra": "And they consulted together that by subtilty they might apprehend Jesus and put him to death.", "bbe": "And they made designs together to take Jesus by some trick, and put him to death.", "geneva": "And consulted together that they might take Iesus by subtiltie, and kill him.", "wycliffe": "and maden a counsel to holde Jhesu with gile, and sle him;", "rotherham": "and they took counsel together, in order that, Jesus, by guile, they might secure, and slay.", "weymouth": "and consulted how to get Jesus into their power by stratagem and put Him to death.", "darby": "and took counsel together in order that they might seize Jesus by subtlety and kill him;", "twenty": "and plotted together to arrest Jesus by stealth and put him to death;", "acv": "and they deliberated so that they might take Jesus by trickery, and kill him.", "anderson": "And they consulted together that they might take Jesus by craft and kill him.", "haweis": "And they consulted together, how they might seize Jesus by guile, and put him to death.", "noyes": "and took counsel together that they might seize Jesus by craft, and put him to death.", "webster": "And consulted that they might take Jesus by subtilty, and kill [him].", "vulgate": "et consilium fecerunt ut Iesum dolo tenerent et occiderent;"}}, {"v": 5, "ref": "26:5", "o": "ἔλεγον δέ· Μὴ ἐν τῇ ἑορτῇ, ἵνα μὴ θόρυβος γένηται ἐν τῷ λαῷ.", "en": {"kjv": "But they said, Not on the feast day, lest there be an uproar among the people.", "web": "But they said, “Not during the feast, lest a riot occur among the people.”", "bsb": "“But not during the feast,” they said, “or there may be a riot among the people.”", "asv": "But they said, Not during the feast, lest a tumult arise among the people.", "ylt": "and they said, `Not in the feast, that there may not be a tumult among the people.'", "tyndale": "But they sayd not on the holy daye lest eny vproure aryse amonge the people.", "dra": "But they said: Not on the festival day, lest perhaps there should be a tumult among the people.", "bbe": "But they said, Not while the feast is going on, for fear of trouble among the people.", "geneva": "But they sayd, Not on the feast day, least any vprore be among the people.", "wycliffe": "but thei seiden, Not in the haliday, lest perauenture noyse were maad in the puple.", "rotherham": "They were saying, however: Not during the feast, lest, an uproar, arise among the people.", "weymouth": "But they said, \"Not during the Festival, lest there be a riot among the people.\"", "darby": "but they said, Not in the feast, that there be not a tumult among the people.", "twenty": "but they said: “Not during the Festival, for fear of causing a riot.”", "acv": "But they said, Not during the feast, lest an uproar develop among people.", "anderson": "But they said: Not during the feast, lest there be a tumult among the people.", "haweis": "But they said, Not on the feast-day, lest there be a tumult among the people.", "noyes": "But they said, Not at the feast, lest there be an uproar among the people.", "webster": "But they said, Not on the feast-[day], lest there be an uproar among the people.", "vulgate": "dicebant autem non in die festo ne forte tumultus fieret in populo;"}}, {"v": 6, "ref": "26:6", "o": "Τοῦ δὲ Ἰησοῦ γενομένου ἐν Βηθανίᾳ ἐν οἰκίᾳ Σίμωνος τοῦ λεπροῦ,", "en": {"kjv": "Now when Jesus was in Bethany, in the house of Simon the leper,", "web": "Now when Jesus was in Bethany, in the house of Simon the leper,", "bsb": "While Jesus was in Bethany in the home of Simon the Leper,", "asv": "Now when Jesus was in Bethany, in the house of Simon the leper,", "ylt": "And Jesus having been in Bethany, in the house of Simon the leper,", "tyndale": "When Iesus was in Bethany in the house of Symon the leper", "dra": "And when Jesus was in Bethania, in the house of Simon the leper,", "bbe": "Now when Jesus was in Bethany in the house of Simon the leper,", "geneva": "And when Iesus was in Bethania, in the house of Simon the leper,", "wycliffe": "And whanne Jhesus was in Betanye, in the hous of Symount leprous,", "rotherham": "But, Jesus, happening to be in Bethany, in the house of Simon the leper,", "weymouth": "Now when Jesus was come to Bethany and was at the house of Simon the Leper,", "darby": "But Jesus being in Bethany, in Simon the leper's house,", "twenty": "After Jesus had reached Bethany, and while he was in the house of Simon the leper,", "acv": "Now when Jesus happened to be in Bethany, in the house of Simon the leper,", "anderson": "When Jesus was in Bethany, in the house of Simon the leper,", "haweis": "Now when Jesus was at Bethany, in the house of Simon the leper,", "noyes": "Now when Jesus was at Bethany, in the house of Simon the leper,", "webster": "Now when Jesus was in Bethany, in the house of Simon the leper,", "vulgate": "cum autem esset Iesus in Bethania in domo Simonis leprosi;"}}, {"v": 7, "ref": "26:7", "o": "προσῆλθεν αὐτῷ γυνὴ ⸂ἔχουσα ἀλάβαστρον μύρου⸃ βαρυτίμου καὶ κατέχεεν ἐπὶ ⸂τῆς κεφαλῆς⸃ αὐτοῦ ἀνακειμένου.", "en": {"kjv": "There came unto him a woman having an alabaster box of very precious ointment, and poured it on his head, as he sat at meat.", "web": "a woman came to him having an alabaster jar of very expensive ointment, and she poured it on his head as he sat at the table.", "bsb": "a woman came to Him with an alabaster jar of expensive perfume, which she poured on His head as He reclined at the table.", "asv": "there came unto him a woman having an alabaster cruse of exceeding precious ointment, and she poured it upon his head, as he sat at meat.", "ylt": "there came to him a woman having an alabaster box of ointment, very precious, and she poured on his head as he is reclining (at meat).", "tyndale": "ther came vnto him a woman which had an alablaster boxe of precious oyntment and powred it on his heed as he sate at the bourde.", "dra": "There came to him a woman having an alabaster box of precious ointment and poured it on his head as he was at table.", "bbe": "There came to him a woman having a bottle of perfume of great price, and she put the perfume on his head when he was seated at table.", "geneva": "There came vnto him a woman, which had a boxe of very costly oyntment, and powred it on his head, as he sate at the table.", "wycliffe": "a womman that hadde a box of alabastre of precious oynement, cam to hym, and schedde out on the heed of hym restynge.", "rotherham": "there came unto him a woman, holding an alabaster-jar of costly perfume, and she poured it down upon his head, as he was reclining.", "weymouth": "a woman came to Him with a jar of very costly, sweet-scented ointment, which she poured over His head as He reclined at table.", "darby": "a woman, having an alabaster flask of very precious ointment, came to him and poured it out upon his head as he lay at table.", "twenty": "a woman came up to him with an alabaster jar of very costly perfume, and poured the perfume upon his head as he was at table.", "acv": "a woman came to him having an alabaster cruse of precious ointment, and she poured it upon his head as he sat relaxing.", "anderson": "there came to him a woman who had an alabaster box of very costly ointment; and she poured it on his head as he reclined at table.", "haweis": "there came to him a woman having an alabaster-box of very precious aromatic ointment, and poured it upon his head as he sat at table.", "noyes": "there came to him a woman having an alabaster bottle of very costly ointment, and poured it on his head while he was reclining at table.", "webster": "There came to him a woman having an alabaster-box of very precious ointment, and poured it on his head as he sat [at table].", "vulgate": "accessit ad eum mulier habens alabastrum unguenti pretiosi et effudit super caput ipsius recumbentis;"}}, {"v": 8, "ref": "26:8", "o": "ἰδόντες δὲ οἱ ⸀μαθηταὶ ἠγανάκτησαν λέγοντες· Εἰς τί ἡ ἀπώλεια αὕτη;", "en": {"kjv": "But when his disciples saw it, they had indignation, saying, To what purpose is this waste?", "web": "But when his disciples saw this, they were indignant, saying, “Why this waste?", "bsb": "When the disciples saw this, they were indignant and asked, “Why this waste?", "asv": "But when the disciples saw it, they had indignation, saying, To what purpose is this waste?", "ylt": "And having seen it , his disciples were much displeased, saying, `To what purpose is this waste?", "tyndale": "When his disciples sawe that they had indignacion sayinge: what neded this wast?", "dra": "And the disciples seeing it had indignation, saying: To what purpose is this waste?", "bbe": "But when the disciples saw it they were angry, saying, To what purpose is this waste?", "geneva": "And when his disciples sawe it, they had indignation, saying, What needed this waste?", "wycliffe": "And disciplis seynge hadden dedeyn, and seiden, Wherto this loss? for it myyte be seld for myche,", "rotherham": "And the disciples, seeing it, were greatly displeased, saying—To what end, this loss?", "weymouth": "\"Why such waste?\" indignantly exclaimed the disciples;", "darby": "But the disciples seeing it became indignant, saying, To what end [was] this waste?", "twenty": "The disciples were indignant at seeing this. “What is this waste for?” they exclaimed.", "acv": "But when his disciples saw it, they were indignant, saying, Why this waste?", "anderson": "But when his disciples saw it, they were displeased, and said: For what purpose was this waste?", "haweis": "But when the disciples saw it, they had indignation, saying, For what end is this waste?", "noyes": "But the disciples seeing it, were much displeased, saying, To what purpose is this waste?.", "webster": "But when his disciples saw [it], they had indignation, saying, To what purpose [is] this waste?", "vulgate": "videntes autem discipuli indignati sunt dicentes ut quid perditio haec;"}}, {"v": 9, "ref": "26:9", "o": "ἐδύνατο γὰρ ⸀τοῦτο πραθῆναι πολλοῦ καὶ δοθῆναι πτωχοῖς.", "en": {"kjv": "For this ointment might have been sold for much, and given to the poor.", "web": "For this ointment might have been sold for much, and given to the poor.”", "bsb": "This perfume could have been sold at a high price, and the money given to the poor.”", "asv": "For this ointment might have been sold for much, and given to the poor.", "ylt": "for this ointment could have been sold for much, and given to the poor.'", "tyndale": "This oyntmet myght have bene well solde and geven to the povre.", "dra": "For this might have been sold for much and given to the poor.", "bbe": "For we might have got much money for this and given it to the poor.", "geneva": "For this oyntment might haue bene solde for much, and bene giuen to the poore.", "wycliffe": "and be youun to pore men.", "rotherham": "For this could have been sold for much, and given to the destitute.", "weymouth": "\"for this might have been sold for a considerable sum, and the money given to the poor.\"", "darby": "for this might have been sold for much and been given to the poor.", "twenty": "“It could have been sold for a large sum, and the money given to poor people.”", "acv": "For this ointment could have been sold for much, and given to the poor.", "anderson": "For this could have been sold for much, and given to the poor.", "haweis": "For this ointment might have been sold for a considerable sum, and given to the poor.", "noyes": "For this might have been sold for much, and given to the poor.", "webster": "For this ointment might have been sold for much, and given to the poor.", "vulgate": "potuit enim istud venundari multo et dari pauperibus;"}}, {"v": 10, "ref": "26:10", "o": "γνοὺς δὲ ὁ Ἰησοῦς εἶπεν αὐτοῖς· Τί κόπους παρέχετε τῇ γυναικί; ἔργον γὰρ καλὸν ἠργάσατο εἰς ἐμέ·", "en": {"kjv": "When Jesus understood it, he said unto them, Why trouble ye the woman? for she hath wrought a good work upon me.", "web": "However, knowing this, Jesus said to them, “Why do you trouble the woman? Because she has done a good work for me.", "bsb": "Aware of this, Jesus asked, “Why are you bothering this woman? She has done a beautiful deed to Me.", "asv": "But Jesus perceiving it said unto them, Why trouble ye the woman? for she hath wrought a good work upon me.", "ylt": "And Jesus having known, said to them, `Why do ye give trouble to the woman? for a good work she wrought for me;", "tyndale": "When Iesus vnderstod that he sayde vnto the: why trouble ye the woman? She hath wrought a good worke apon me.", "dra": "And Jesus knowing it, said to them: Why do you trouble this woman? For she hath wrought a good work upon me.", "bbe": "But Jesus, seeing it, said to them, Why are you troubling the woman? she has done a kind act to me.", "geneva": "And Iesus knowing it, sayde vnto them, Why trouble yee the woman? for shee hath wrought a good woorke vpon me.", "wycliffe": "But Jhesus knewe, and seide to hem, What ben ye heuy to this womman? for sche hath wrouyt in me a good werk.", "rotherham": "But Jesus, taking note, said unto them—Why vex ye the woman? for, a seemly work, hath she wrought for me;", "weymouth": "But Jesus heard it, and said to them, \"Why are you vexing her? For she has done a most gracious act towards me.", "darby": "But Jesus knowing [it] said to them, Why do ye trouble the woman? for she has wrought a good work toward me.", "twenty": "“Why are you troubling the woman?” Jesus said, when he noticed it. “For this is a beautiful deed that she has done to me.", "acv": "But Jesus knowing it, he said to them, Why do ye cause troubles to the woman? For she has wrought a good work upon me.", "anderson": "Jesus perceived it, and said to them: Why do you trouble the woman? For she has performed a good work upon me.", "haweis": "Then Jesus knowing it, said unto them, Why trouble ye the woman? for she hath performed a good act upon me:", "noyes": "And Jesus, perceiving it, said to them, Why do ye trouble the woman? For she hath done a good deed to me.", "webster": "When Jesus understood [it], he said to them, Why trouble ye the woman? for she hath wrought a good work upon me.", "vulgate": "sciens autem Iesus ait illis quid molesti estis mulieri opus bonum operata est in me;"}}, {"v": 11, "ref": "26:11", "o": "πάντοτε γὰρ τοὺς πτωχοὺς ἔχετε μεθ’ ἑαυτῶν, ἐμὲ δὲ οὐ πάντοτε ἔχετε·", "en": {"kjv": "For ye have the poor always with you; but me ye have not always.", "web": "For you always have the poor with you; but you don’t always have me.", "bsb": "The poor you will always have with you, but you will not always have Me.", "asv": "For ye have the poor always with you; but me ye have not always.", "ylt": "for the poor always ye have with you, and me ye have not always;", "tyndale": "For ye shall have povre folcke alwayes with you: but me shall ye not have all wayes.", "dra": "For the poor you have always with you: but me you have not always.", "bbe": "For the poor you have ever with you, but me you have not for ever.", "geneva": "For yee haue the poore alwayes with you, but me shall yee not haue alwaies.", "wycliffe": "For ye schulen euere haue pore men with you, but ye schulen not algatis haue me.", "rotherham": "For, always, the destitute, have ye with you,—but, me, not always, have ye;", "weymouth": "The poor you always have with you, but me you have not always.", "darby": "For ye have the poor always with you, but me ye have not always.", "twenty": "You always have the poor with you, but you will not always have me.", "acv": "For ye always have the poor with you, but ye do not always have me.", "anderson": "For you have the poor always with you, but me you have not always.", "haweis": "for the poor ye have always with you, but me ye have not always:", "noyes": "For the poor ye have always with you; but me ye have not always.", "webster": "For ye have the poor always with you; but me ye have not always.", "vulgate": "nam semper pauperes habetis vobiscum me autem non semper habetis;"}}, {"v": 12, "ref": "26:12", "o": "βαλοῦσα γὰρ αὕτη τὸ μύρον τοῦτο ἐπὶ τοῦ σώματός μου πρὸς τὸ ἐνταφιάσαι με ἐποίησεν.", "en": {"kjv": "For in that she hath poured this ointment on my body, she did it for my burial.", "web": "For in pouring this ointment on my body, she did it to prepare me for burial.", "bsb": "By pouring this perfume on Me, she has prepared My body for burial.", "asv": "For in that she poured this ointment upon my body, she did it to prepare me for burial.", "ylt": "for she having put this ointment on my body--for my burial she did it .", "tyndale": "And in yt she casted this oyntment on my bodye she dyd it to burye me wt all.", "dra": "For she in pouring this ointment on my body hath done it for my burial.", "bbe": "For in putting this perfume on my body, she did it to make me ready for my last resting-place.", "geneva": "For in that shee powred this oyntment on my bodie, shee did it to burie me.", "wycliffe": "This womman sendynge this oynement in to my bodi, dide to birie me.", "rotherham": "For, she, pouring this perfume upon my body, so as to prepare me for burial, did it.", "weymouth": "In pouring this ointment over me, her object was to prepare me for burial.", "darby": "For in pouring out this ointment on my body, she has done it for my burying.", "twenty": "In pouring this perfume on my body, she has done it for my burying.", "acv": "For by pouring this ointment upon my body, she did it for my burial.", "anderson": "For in pouring this ointment on my body, she has done it to prepare me for burial.", "haweis": "for in pouring this odoriferous ointment on my body, she hath done it for my burial.", "noyes": "For she, in pouring this ointment on my body, hath done it to prepare me for burial.", "webster": "For in that she hath poured this ointment on my body, she did [it] for my burial.", "vulgate": "mittens enim haec unguentum hoc in corpus meum ad sepeliendum me fecit;"}}, {"v": 13, "ref": "26:13", "o": "ἀμὴν λέγω ὑμῖν, ὅπου ἐὰν κηρυχθῇ τὸ εὐαγγέλιον τοῦτο ἐν ὅλῳ τῷ κόσμῳ, λαληθήσεται καὶ ὃ ἐποίησεν αὕτη εἰς μνημόσυνον αὐτῆς.", "en": {"kjv": "Verily I say unto you, Wheresoever this gospel shall be preached in the whole world, there shall also this, that this woman hath done, be told for a memorial of her.", "web": "Most certainly I tell you, wherever this Good News is preached in the whole world, what this woman has done will also be spoken of as a memorial of her.”", "bsb": "Truly I tell you, wherever this gospel is preached in all the world, what she has done will also be told in memory of her.”", "asv": "Verily I say unto you, Wheresoever this gospel shall be preached in the whole world, that also which this woman hath done shall be spoken of for a memorial of her.", "ylt": "Verily I say to you, Wherever this good news may be proclaimed in the whole world, what this one did shall also be spoken of--for a memorial of her.'", "tyndale": "Verely I saye vnto you wheresoever this gospell shalbe preached throughoute all the worlde there shall also this that she hath done be tolde for a memoriall of her.", "dra": "Amen I say to you, wheresoever this gospel shall be preached in the whole world, that also which she hath done shall be told for a memory of her.", "bbe": "Truly I say to you, Wherever this good news goes out in all the world, what this woman has done will be talked of in memory of her.", "geneva": "Verely I say vnto you, wheresoeuer this Gospel shall bee preached throughout all the worlde, there shall also this that shee hath done, be spoken of for a memoriall of her.", "wycliffe": "Treuli Y seie to you, where euer this gospel schal be prechid in al the world, it schal be seid, that sche dide this, in mynde of hym.", "rotherham": "Verily, I say unto you—Wheresoever this glad-message shall be proclaimed in all the world, also what she did, will be told, as a memorial of her.", "weymouth": "In solemn truth I tell you that wherever in the whole world this Good News shall be proclaimed, this deed of hers shall be spoken of in memory of her.\"", "darby": "Verily I say to you, Wheresoever these glad tidings may be preached in the whole world, that also which this [woman] has done shall be spoken of for a memorial of her.", "twenty": "I tell you, wherever, in the whole world, this Good News is proclaimed, what this woman has done will be told in memory of her.”", "acv": "Truly I say to you, wherever this good news may be proclaimed in the whole world, what this woman did will also be told for a memorial of her.", "anderson": "Verily I say to you, Wherever this gospel shall be preached in the whole world, this also which she has done shall be told for a memorial of her.", "haweis": "Verily I say unto you, Wherever this Gospel is preached through the whole world, what she hath done shall be also spoken of for a memorial of her.", "noyes": "Truly do I say to you, Wherever these glad tidings shall be published in the whole world, this too which she hath done will be told for a memorial of her.", "webster": "Verily I say to you, Wherever this gospel shall be preached in the whole world, [there] shall also this, which this woman hath done, be told for a memorial of her.", "vulgate": "amen dico vobis ubicumque praedicatum fuerit hoc evangelium in toto mundo dicetur et quod haec fecit in memoriam eius;"}}, {"v": 14, "ref": "26:14", "o": "Τότε πορευθεὶς εἷς τῶν δώδεκα, ὁ λεγόμενος Ἰούδας Ἰσκαριώτης, πρὸς τοὺς ἀρχιερεῖς", "en": {"kjv": "Then one of the twelve, called Judas Iscariot, went unto the chief priests,", "web": "Then one of the twelve, who was called Judas Iscariot, went to the chief priests,", "bsb": "Then one of the Twelve, the one called Judas Iscariot, went to the chief priests", "asv": "Then one of the twelve, who was called Judas Iscariot, went unto the chief priests,", "ylt": "Then one of the twelve, who is called Judas Iscariot, having gone unto the chief priests, said,", "tyndale": "Then one of the twelve called Iudas Iscarioth went vnto the chefe prestes", "dra": "Then went one of the twelve, who was called Judas Iscariot, to the chief priests.", "bbe": "Then one of the twelve, who was named Judas Iscariot, went to the chief priests and said,", "geneva": "Then one of the twelue, called Iudas Iscariot, went vnto the chiefe Priestes,", "wycliffe": "Thanne oon of the twelue, that was clepid Judas Scarioth, wente forth to the princis of prestis,", "rotherham": "Then, went one of the twelve, the one called Judas Iscariot, unto the High-priests,", "weymouth": "At that time one of the Twelve, the one called Judas Iscariot, went to the High Priests", "darby": "Then one of the twelve, he who was called Judas Iscariote, went to the chief priests", "twenty": "It was then that one of the Twelve, named Judas Iscariot, made his way to the Chief Priests,", "acv": "Then one of the twelve, who was called Judas Iscariot, having gone to the chief priests,", "anderson": "Then one of the twelve, called Judas Iscariot, went to the chief priests,", "haweis": "Then went one of the twelve, called Judas Iscariot, to the chief priests,", "noyes": "Then one of the twelve, called Judas Iscariot, went to the chief priests,", "webster": "Then one of the twelve, called Judas Iscariot, went to the chief priests,", "vulgate": "tunc abiit unus de duodecim qui dicitur Iudas Scarioth ad principes sacerdotum;"}}, {"v": 15, "ref": "26:15", "o": "εἶπεν· Τί θέλετέ μοι δοῦναι κἀγὼ ὑμῖν παραδώσω αὐτόν; οἱ δὲ ἔστησαν αὐτῷ τριάκοντα ἀργύρια.", "en": {"kjv": "And said unto them, What will ye give me, and I will deliver him unto you? And they covenanted with him for thirty pieces of silver.", "web": "and said, “What are you willing to give me, that I should deliver him to you?” They weighed out for him thirty pieces of silver.", "bsb": "and asked, “What are you willing to give me if I hand Him over to you?” And they set out for him thirty pieces of silver.", "asv": "and said, What are ye willing to give me, and I will deliver him unto you? And they weighed unto him thirty pieces of silver.", "ylt": "`What are ye willing to give me, and I will deliver him up to you?' and they weighed out to him thirty silverlings,", "tyndale": "and sayd: what will ye geve me and I will deliver him vnto you? And they apoynted vnto him thirty peces of sylver.", "dra": "And said to them: What will you give me, and I will deliver him unto you? But they appointed him thirty pieces of silver.", "bbe": "What will you give me, if I give him up to you? And the price was fixed at thirty bits of silver.", "geneva": "And said, What will ye giue me, and I will deliuer him vnto you? and they appoynted vnto him thirtie pieces of siluer.", "wycliffe": "and seide to hem, What wolen ye yyue to me, and Y schal bitake hym to you? And thei ordeyneden to hym thretti pans of siluer.", "rotherham": "and said—What are ye willing to give unto me? and, I, unto you, will deliver him up. And they appointed him thirty pieces of silver.", "weymouth": "and said, \"What are you willing to give me if I betray him to you?\" So they weighed out to him thirty shekels,", "darby": "and said, What are ye willing to give me, and I will deliver him up to you? And they appointed to him thirty pieces of silver.", "twenty": "and said “What are you willing to give me, if I betray Jesus to you?” The Priests ‘weighed him out thirty pieces of silver’ as payment.", "acv": "he said, What are ye willing to give me, and I will deliver him to you? And they weighed out to him thirty silver pieces.", "anderson": "and said: What are you willing to give me, and I will deliver him to you? And they weighed to him thirty pieces of silver.", "haweis": "and said, What will ye give me, and I will deliver him unto you? Then they placed before him thirty pieces of silver.", "noyes": "and said, What will ye give me, and I will deliver him up to you? And they paid him thirty pieces of silver.", "webster": "And said, What will ye give me, and I will deliver him to you? And they covenanted with him for thirty pieces of silver.", "vulgate": "et ait illis quid vultis mihi dare et ego vobis eum tradam at illi constituerunt ei triginta argenteos;"}}, {"v": 16, "ref": "26:16", "o": "καὶ ἀπὸ τότε ἐζήτει εὐκαιρίαν ἵνα αὐτὸν παραδῷ.", "en": {"kjv": "And from that time he sought opportunity to betray him.", "web": "From that time he sought opportunity to betray him.", "bsb": "So from then on Judas looked for an opportunity to betray Jesus.", "asv": "And from that time he sought opportunity to deliver him unto them.", "ylt": "and from that time he was seeking a convenient season to deliver him up.", "tyndale": "And from that tyme he sought oportunite to betraye him.", "dra": "And from thenceforth he sought opportunity to betray him.", "bbe": "And from that time he was watching for a chance to give him into their hands.", "geneva": "And from that time, he sought opportunitie to betraie him.", "wycliffe": "And fro that tyme he souyte oportunyte, to bitraye hym.", "rotherham": "And, from that time, was he seeking a favourable opportunity that he might, deliver him up.", "weymouth": "and from that moment he was on the look out for an opportunity to betray Him.", "darby": "And from that time he sought a good opportunity that he might deliver him up.", "twenty": "So from that time Judas looked for an opportunity to betray Jesus.", "acv": "And from that time he sought a favorable opportunity so that he might betray him.", "anderson": "And from that time he sought an opportunity to deliver him up.", "haweis": "And from that time he sought an opportunity to deliver him up to them.", "noyes": "And from that time he sought an opportunity to deliver him up.", "webster": "And from that time he sought opportunity to betray him.", "vulgate": "et exinde quaerebat oportunitatem ut eum traderet;"}}, {"v": 17, "ref": "26:17", "o": "Τῇ δὲ πρώτῃ τῶν ἀζύμων προσῆλθον οἱ μαθηταὶ τῷ Ἰησοῦ ⸀λέγοντες· Ποῦ θέλεις ⸀ἑτοιμάσωμέν σοι φαγεῖν τὸ πάσχα;", "en": {"kjv": "Now the first day of the feast of unleavened bread the disciples came to Jesus, saying unto him, Where wilt thou that we prepare for thee to eat the passover?", "web": "Now on the first day of unleavened bread, the disciples came to Jesus, saying to him, “Where do you want us to prepare for you to eat the Passover?”", "bsb": "On the first day of the Feast of Unleavened Bread, the disciples came to Jesus and asked, “Where do You want us to prepare for You to eat the Passover?”", "asv": "Now on the firstdayof unleavened bread the disciples came to Jesus, saying, Where wilt thou that we make ready for thee to eat the passover?", "ylt": "And on the first day of the unleavened food came the disciples near to Jesus, saying to him, `Where wilt thou that we may prepare for thee to eat the passover?'", "tyndale": "The fyrst daye of swete breed ye disciples cam to Iesus sayinge vnto him: where wylt thou that we prepare for ye to eate ye paschall lambe?", "dra": "And on the first day of the Azymes, the disciples came to Jesus, saying: Where wilt thou that we prepare for thee to eat the pasch?", "bbe": "Now on the first day of unleavened bread the disciples came to Jesus, saying, Where are we to make ready for you to take the Passover meal?", "geneva": "Nowe on the first day of the feast of vnleauened bread the disciples came to Iesus, saying vnto him, Where wilt thou that we prepare for thee to eate the Passeouer?", "wycliffe": "And in the firste dai of therf looues the disciplis camen to Jhesu, and seiden, Where wolt thou we make redi to thee, to ete paske?", "rotherham": "And, on the first of the days of unleavened bread, the disciples came unto Jesus, saying—Where wilt thou, that we make ready for thee to eat the passover?", "weymouth": "On the first day of the Unleavened Bread the disciples came to Jesus with the question, \"Where shall we make preparations for you to eat the Passover?\"", "darby": "Now on the first [day] of [the feast of] unleavened bread, the disciples came to Jesus, saying, Where wilt thou that we prepare for thee to eat the passover?", "twenty": "On the first day of the Festival of the Unleavened Bread, the disciples came up to Jesus, and said: “Where do you wish us to make preparations for you to eat the Passover?”", "acv": "Now on the first day of unleavened bread the disciples came to Jesus, saying, Where do thou want that we should prepare for thee to eat the Passover?", "anderson": "On the first day of unleavened bread, the disciples came to Jesus, and said to him: Where dost thou wish that we prepare for thee to eat the passover?", "haweis": "Then on the first day of unleavened bread the disciples came to Jesus, saying to him, Where wilt thou that we prepare for thee to eat the passover?", "noyes": "And on the first of the days of unleavened bread the disciples came to Jesus, saying, Where wilt thou that we make ready for thee to eat the passover?", "webster": "Now the first [day] of the [feast of] unleavened bread, the disciples came to Jesus, saying to him, Where wilt thou that we prepare for thee to eat the passover?", "vulgate": "prima autem azymorum accesserunt discipuli ad Iesum dicentes ubi vis paremus tibi comedere pascha;"}}, {"v": 18, "ref": "26:18", "o": "ὁ δὲ εἶπεν· Ὑπάγετε εἰς τὴν πόλιν πρὸς τὸν δεῖνα καὶ εἴπατε αὐτῷ· Ὁ διδάσκαλος λέγει· Ὁ καιρός μου ἐγγύς ἐστιν· πρὸς σὲ ποιῶ τὸ πάσχα μετὰ τῶν μαθητῶν μου.", "en": {"kjv": "And he said, Go into the city to such a man, and say unto him, The Master saith, My time is at hand; I will keep the passover at thy house with my disciples.", "web": "He said, “Go into the city to a certain person, and tell him, ‘The Teacher says, “My time is at hand. I will keep the Passover at your house with my disciples.”’”", "bsb": "He answered, “Go into the city to a certain man and tell him that the Teacher says, ‘My time is near. I will keep the Passover with My disciples at your house.’”", "asv": "And he said, Go into the city to such a man, and say unto him, The Teacher saith, My time is at hand; I keep the passover at thy house with my disciples.", "ylt": "and he said, `Go away to the city, unto such a one, and say to him, The Teacher saith, My time is nigh; near thee I keep the passover, with my disciples;'", "tyndale": "And he sayd: Go into the cite vnto soche a man and saye to him: the master sayeth my tyme is at hande I will kepe myne ester at thy housse with my disciples.", "dra": "But Jesus said: Go ye into the city to a certain man and say to him: The master saith, My time is near at hand. With thee I make the pasch with my disciples.", "bbe": "And he said to them, Go into the town to such a man, and say to him, The Master says, My time is near: I will keep the Passover at your house with my disciples.", "geneva": "And he said, Goe yee into the citie to such a man, and say to him, The master saieth, My time is at hande: I will keepe the Passeouer at thine house with my disciples.", "wycliffe": "Jhesus seide, Go ye into the citee to `sum man, and seie to hym, The maistir seith, My tyme is nyy; at thee Y make paske with my disciplis.", "rotherham": "And, he, said—Go your way into the city, unto such-a-one, and say to him, The teacher, saith, My season, is, near, with thee, will I keep the passover, with my disciples.", "weymouth": "\"Go into the city,\" He replied, \"to a certain man, and tell him, `The Teacher says, My time is close at hand. It is at your house that I shall keep the Passover with my disciples.'\"", "darby": "And he said, Go into the city unto such a one, and say to him, The Teacher says, My time is near, I will keep the passover in thy house with my disciples.", "twenty": "“Go into the city to a certain man,” he answered, “and say to him ‘The Teacher says — My time is near. I will keep the Passover with my disciples at your house.’”", "acv": "And he said, Go into the city to a certain man, and say to him, The teacher says, My time is near. I keep the Passover with my disciples with thee.", "anderson": "He replied: Go into the city, to a certain man, and say to him, The Teacher says, My time is near; I will keep the passover at your house, with my disciples.", "haweis": "And he said, Go into the city, unto such a man, and say unto him, The Master saith, My time is at hand: I will keep the passover with my disciples at thy house.", "noyes": "And he said, Go into the city to such a man, and say to him, The Teacher saith, My time is at hand; I keep the passover at thy house with my disciples.", "webster": "And he said, Go into the city to such a man, and say to him, The Master saith, My time is at hand; I will keep the passover at thy house with my disciples.", "vulgate": "at Iesus dixit ite in civitatem ad quendam et dicite ei magister dicit tempus meum prope est apud te facio pascha cum discipulis meis;"}}, {"v": 19, "ref": "26:19", "o": "καὶ ἐποίησαν οἱ μαθηταὶ ὡς συνέταξεν αὐτοῖς ὁ Ἰησοῦς, καὶ ἡτοίμασαν τὸ πάσχα.", "en": {"kjv": "And the disciples did as Jesus had appointed them; and they made ready the passover.", "web": "The disciples did as Jesus commanded them, and they prepared the Passover.", "bsb": "So the disciples did as Jesus had directed them and prepared the Passover.", "asv": "And the disciples did as Jesus appointed them; and they made ready the passover.", "ylt": "and the disciples did as Jesus appointed them, and prepared the passover.", "tyndale": "And the disciples did as Iesus had apoynted them and made redy the esterlambe.", "dra": "And the disciples did as Jesus appointed to them: and they prepared the pasch.", "bbe": "And the disciples did as Jesus had said to them; and they made ready the Passover.", "geneva": "And the disciples did as Iesus had giuen them charge, and made readie the Passeouer.", "wycliffe": "And the disciplis diden, as Jhesus comaundide to hem; and thei maden the paske redi.", "rotherham": "And the disciples did, as Jesus directed them, and made ready the passover.", "weymouth": "The disciples did as Jesus directed them, and got the Passover ready.", "darby": "And the disciples did as Jesus had directed them, and they prepared the passover.", "twenty": "The disciples did as Jesus directed them, and prepared the Passover.", "acv": "And the disciples did as Jesus arranged for them, and they prepared the Passover.", "anderson": "And the disciples did as Jesus commanded them, and prepared the passover.", "haweis": "And his disciples did as Jesus commanded them; and they made ready the passover.", "noyes": "And the disciples did as Jesus directed them, and made ready the passover.", "webster": "And the disciples did as Jesus had appointed them; and they made ready the passover.", "vulgate": "et fecerunt discipuli sicut constituit illis Iesus et paraverunt pascha;"}}, {"v": 20, "ref": "26:20", "o": "Ὀψίας δὲ γενομένης ἀνέκειτο μετὰ τῶν δώδεκα ⸀μαθητῶν", "en": {"kjv": "Now when the even was come, he sat down with the twelve.", "web": "Now when evening had come, he was reclining at the table with the twelve disciples.", "bsb": "When evening came, Jesus was reclining with the twelve disciples.", "asv": "Now when even was come, he was sitting at meat with the twelve disciples;", "ylt": "And evening having come, he was reclining (at meat) with the twelve,", "tyndale": "When the even was come he sate doune wt the .xii.", "dra": "But when it was evening, he sat down with his twelve disciples.", "bbe": "Now when evening was come, he was seated at table with the twelve disciples;", "geneva": "So when the Euen was come, hee sate downe with the twelue.", "wycliffe": "And whanne euentid was come, he sat to mete with hise twelue disciplis.", "rotherham": "And, when, evening, came, he was reclining with the twelve [disciples];", "weymouth": "When evening came, He was at table with the twelve disciples,", "darby": "And when the evening was come he lay down at table with the twelve.", "twenty": "In the evening Jesus took his place with the twelve disciples,", "acv": "Now having become evening, he was sitting with the twelve.", "anderson": "When the evening had come, he reclined at table with the twelve.", "haweis": "And when the evening was come, he sat down at table with the twelve.", "noyes": "And when evening came, he took his place at table with the twelve disciples.", "webster": "Now when the evening was come, he sat down with the twelve.", "vulgate": "vespere autem facto discumbebat cum duodecim discipulis;"}}, {"v": 21, "ref": "26:21", "o": "καὶ ἐσθιόντων αὐτῶν εἶπεν· Ἀμὴν λέγω ὑμῖν ὅτι εἷς ἐξ ὑμῶν παραδώσει με.", "en": {"kjv": "And as they did eat, he said, Verily I say unto you, that one of you shall betray me.", "web": "As they were eating, he said, “Most certainly I tell you that one of you will betray me.”", "bsb": "And while they were eating, He said to them, “Truly I tell you, one of you will betray Me.”", "asv": "and as they were eating, he said, Verily I say unto you, that one of you shall betray me.", "ylt": "and while they are eating, he said, `Verily I say to you, that one of you shall deliver me up.'", "tyndale": "And as they dyd eate he sayde: Verely I saye vnto you that one of you shall betraye me.", "dra": "And whilst they were eating, he said: Amen I say to you that one of you is about to betray me.", "bbe": "And while they were taking food, he said, Truly I say to you that one of you will be false to me.", "geneva": "And as they did eate, he sayde, Verely I say vnto you, that one of you shall betraie me.", "wycliffe": "And he seide to hem, as thei eten, Treuli Y seie to you, that oon of you schal bitraye me.", "rotherham": "and, as they were eating, he said—Verily, I say unto you, One from among you, will deliver me up.", "weymouth": "and the meal was proceeding, when Jesus said, \"In solemn truth I tell you that one of you will betray me.\"", "darby": "And as they were eating he said, Verily I say to you, that one of you shall deliver me up.", "twenty": "and, while they were eating, he said: “I tell you that one of you will betray me.”", "acv": "And as they were eating, he said, Truly I say to you, that one of you will betray me.", "anderson": "And as they were eating, he said: Verily I say to you, One of you will deliver me up.", "haweis": "And as they were eating, he said, Verily I say unto you, that one of you shall betray me.", "noyes": "And as they were eating, he said, Truly do I say to you, that one of you will betray me.", "webster": "And as they were eating, he said, Verily I say to you, that one of you will betray me.", "vulgate": "et edentibus illis dixit amen dico vobis quia unus vestrum me traditurus est;"}}, {"v": 22, "ref": "26:22", "o": "καὶ λυπούμενοι σφόδρα ἤρξαντο λέγειν αὐτῷ ⸂εἷς ἕκαστος⸃· Μήτι ἐγώ εἰμι, κύριε;", "en": {"kjv": "And they were exceeding sorrowful, and began every one of them to say unto him, Lord, is it I?", "web": "They were exceedingly sorrowful, and each began to ask him, “It isn’t me, is it, Lord?”", "bsb": "They were deeply grieved and began to ask Him one after another, “Surely not I, Lord?”", "asv": "And they were exceeding sorrowful, and began to say unto him every one, Is it I, Lord?", "ylt": "And being grieved exceedingly, they began to say to him, each of them, `Is it I, Sir?'", "tyndale": "And they were excedinge sorowfull and beganne every one of the to saye vnto him: is it I master?", "dra": "And they being very much troubled began every one to say: Is it I, Lord?", "bbe": "And they were very said, and said to him, one by one, Is it I, Lord?", "geneva": "And they were exceeding sorowfull, and began euery one of them to say vnto him, Is it I, Master?", "wycliffe": "And thei ful sori bigunnen ech bi hym silf to seie, Lord, whether `Y am?", "rotherham": "And, being exceedingly grieved, they began to be saying to him, each one—Can it be, I, Lord?", "weymouth": "Intensely grieved they began one after another to ask Him, \"Can it be I, Master?\"", "darby": "And being exceedingly grieved they began to say to him, each of them, Is it I, Lord?", "twenty": "In great grief they began to say to him, one by one: “Can it be I, Master?”", "acv": "And being exceedingly sorrowful, they began, each of them, to say to him, Is it I, Lord?", "anderson": "And they were very sad, and began each one of them to say to him: Lord, is it I?", "haweis": "And exceedingly grieved, they began to say to him every one of them, Lord, am I the person?", "noyes": "And they were exceedingly sorrowful, and began every one to say to him, Is it I, Lord?", "webster": "And they were exceeding sorrowful, and began every one of them to say to him, Lord, is it I?", "vulgate": "et contristati valde coeperunt singuli dicere numquid ego sum Domine;"}}, {"v": 23, "ref": "26:23", "o": "ὁ δὲ ἀποκριθεὶς εἶπεν· Ὁ ἐμβάψας μετ’ ἐμοῦ ⸂τὴν χεῖρα ἐν τῷ τρυβλίῳ⸃ οὗτός με παραδώσει·", "en": {"kjv": "And he answered and said, He that dippeth his hand with me in the dish, the same shall betray me.", "web": "He answered, “He who dipped his hand with me in the dish, the same will betray me.", "bsb": "Jesus answered, “The one who has dipped his hand into the bowl with Me will betray Me.", "asv": "And he answered and said, He that dipped his hand with me in the dish, the same shall betray me.", "ylt": "And he answering said, `He who did dip with me the hand in the dish, he will deliver me up;", "tyndale": "He answered and sayde: he yt deppeth his honde wt me in ye disshe the same shall betraye me.", "dra": "But he answering said: He that dippeth his hand with me in the dish, he shall betray me.", "bbe": "And he made answer and said, He who puts his hand into the plate with me, the same will be false to me.", "geneva": "And hee answered and sayde, Hee that dippeth his hande with me in the dish, hee shall betraie me.", "wycliffe": "And he answeride, and seide, He that puttith with me his hoond in the plater, schal bitraye me.", "rotherham": "And, he, answering, said—He who hath dipped with me his hand in the bowl, the same, will deliver me up.", "weymouth": "\"The one who has dipped his fingers in the bowl with me,\" He answered, \"is the man who will betray me.", "darby": "But he answering said, He that dips his hand with me in the dish, he it is who shall deliver me up.", "twenty": "“The one who dipped his bread beside me in the dish,” replied Jesus, “is the one who will betray me.", "acv": "And having answered, he said, He who dipped his hand with me in the dish, this man will betray me.", "anderson": "He answered and said: He that dips his hand with me in the dish, will deliver me up.", "haweis": "But he answering said, He that dippeth his hand with me into the dish, that man shall betray me.", "noyes": "And he answering said, He that hath dipped his hand with me in the dish, he will betray me.", "webster": "And he answered and said, He that dippeth [his] hand with me in the dish, the same will betray me.", "vulgate": "at ipse respondens ait qui intinguit mecum manum in parapside hic me tradet;"}}, {"v": 24, "ref": "26:24", "o": "ὁ μὲν υἱὸς τοῦ ἀνθρώπου ὑπάγει καθὼς γέγραπται περὶ αὐτοῦ, οὐαὶ δὲ τῷ ἀνθρώπῳ ἐκείνῳ δι’ οὗ ὁ υἱὸς τοῦ ἀνθρώπου παραδίδοται· καλὸν ἦν αὐτῷ εἰ οὐκ ἐγεννήθη ὁ ἄνθρωπος ἐκεῖνος.", "en": {"kjv": "The Son of man goeth as it is written of him: but woe unto that man by whom the Son of man is betrayed! it had been good for that man if he had not been born.", "web": "The Son of Man goes, even as it is written of him, but woe to that man through whom the Son of Man is betrayed! It would be better for that man if he had not been born.”", "bsb": "The Son of Man will go just as it is written about Him, but woe to that man by whom He is betrayed. It would be better for him if he had not been born.”", "asv": "The Son of man goeth, even as it is written of him: but woe unto that man through whom the Son of man is betrayed! good were it for that man if he had not been born.", "ylt": "the Son of Man doth indeed go, as it hath been written concerning him, but woe to that man through whom the Son of Man is delivered up! good it were for him if that man had not been born.'", "tyndale": "The sonne of ma goeth as it is written of him: but wo be to yt ma by whom ye sonne of man shalbe betrayed. It had bene good for that man yf he had never bene borne.", "dra": "The Son of man indeed goeth, as it is written of him. But woe to that man by whom the Son of man shall be betrayed. It were better for him, if that man had not been born.", "bbe": "The Son of man goes, even as the Writings say of him: but a curse is on that man through whom the Son of man is given up; it would have been well for that man if he had never come into the world.", "geneva": "Surely the Sonne of man goeth his way, as it is written of him: but woe be to that man, by whom the Sonne of man is betrayed: it had bene good for that man, if hee had neuer bene borne.", "wycliffe": "Forsothe mannus sone goith, as it is writun of hym; but wo to that man, bi whom mannus sone schal be bitrayed; it were good to hym, if that man hadde not be borun.", "rotherham": "The Son of Man, indeed, goeth his way, according as it is written concerning him,—But alas! for that man, through whom the Son of Man, is being delivered up: Well, had it been for him, if, that man, had not been born!", "weymouth": "The Son of Man is indeed going as is written concerning Him; but alas for that man by whom the Son of Man is betrayed! It had been a happy thing for that man if he had never been born.\"", "darby": "The Son of man goes indeed, according as it is written concerning him, but woe to that man by whom the Son of man is delivered up; it were good for that man if he had not been born.", "twenty": "True, the Son of Man must go, as Scripture says of him, yet alas for that man by whom the Son of Man is being betrayed! For that man ‘it would be better never to have been born!’”", "acv": "The Son of man indeed goes as it is written about him, but woe to that man through whom the Son of man is betrayed! It were good for him if that man had not been born.", "anderson": "The Son of man goes, as it is written of him; but alas for that man by whom the Son of man is delivered up! It would have been good for that man, if he had not been born.", "haweis": "The Son of man indeed is departing, as it is written of him: but wo to that man, by whom the Son of man is betrayed! well had it been for that man if he had never had a being.", "noyes": "The Son of man indeed goeth away, as it hath been written concerning him; but woe to that man by whom the Son of man is betrayed! Well were it for that man if he had not been born.", "webster": "The Son of man goeth, as it is written concerning him: but woe to that man by whom the Son of man is betrayed! it had been good for that man, if he had not been born.", "vulgate": "Filius quidem hominis vadit sicut scriptum est de illo vae autem homini illi per quem Filius hominis traditur bonum erat ei si natus non fuisset homo ille;"}}, {"v": 25, "ref": "26:25", "o": "ἀποκριθεὶς δὲ Ἰούδας ὁ παραδιδοὺς αὐτὸν εἶπεν· Μήτι ἐγώ εἰμι, ῥαββί; λέγει αὐτῷ· Σὺ εἶπας.", "en": {"kjv": "Then Judas, which betrayed him, answered and said, Master, is it I? He said unto him, Thou hast said.", "web": "Judas, who betrayed him, answered, “It isn’t me, is it, Rabbi?” He said to him, “You said it.”", "bsb": "Then Judas, who would betray Him, said, “Surely not I, Rabbi?” Jesus answered, “You have said it yourself.”", "asv": "And Judas, who betrayed him, answered and said, Is it I, Rabbi? He saith unto him, Thou hast said.", "ylt": "And Judas--he who delivered him up--answering said, `Is it I, Rabbi?' He saith to him, `Thou hast said.'", "tyndale": "Then Iudas wich betrayed him answered and sayde: is it I master? He sayde vnto him: thou hast sayde.", "dra": "And Judas that betrayed him answering, said: Is it I, Rabbi? He saith to him: Thou hast said it.", "bbe": "And Judas, who was false to him, made answer and said, Is it I, Master? He says to him, Yes.", "geneva": "Then Iudas which betraied him, answered and sayde, Is it I, Master? He sayde vnto him, Thou hast sayd it.", "wycliffe": "But Judas that bitraiede hym, answeride, seiynge, Maister, whether `Y am? Jhesus seide to hym, Thou hast seid.", "rotherham": "And Judas, who was delivering him up, answering, said—Can it be, I, Rabbi? He saith unto him—Thou, hast said.", "weymouth": "Then Judas, the disciple who was betraying Him, asked, \"Can it be I, Rabbi?\" \"It is you,\" He replied.", "darby": "And Judas, who delivered him up, answering said, Is it I, Rabbi? He says to him, Thou hast said.", "twenty": "And Judas, who was betraying him, turned to him and said: “Can it be I, Rabbi?” “It is,” answered Jesus.", "acv": "And Judas (the man who betrayed him) having answered, he said, Is it I, Rabbi? He says to him, Thou have said.", "anderson": "And Judas, who delivered him up, answered and said: Rabbi, is it I? He replied: You have said.", "haweis": "Then Judas, who betrayed him, addressing him said, Master, is it I? He saith to him, Thou hast named the person.", "noyes": "Then Judas, his betrayer, answering said, Is it I, Rabbi? He saith to him, It is.", "webster": "Then Judas, who betrayed him, answered and said, Master, is it I? He said to him, Thou hast said.", "vulgate": "respondens autem Iudas qui tradidit eum dixit numquid ego sum rabbi ait illi tu dixisti;"}}, {"v": 26, "ref": "26:26", "o": "Ἐσθιόντων δὲ αὐτῶν λαβὼν ὁ Ἰησοῦς ⸀ἄρτον καὶ ⸀εὐλογήσας ἔκλασεν καὶ ⸂δοὺς τοῖς μαθηταῖς⸃ εἶπεν· Λάβετε φάγετε, τοῦτό ἐστιν τὸ σῶμά μου.", "en": {"kjv": "And as they were eating, Jesus took bread, and blessed it, and brake it, and gave it to the disciples, and said, Take, eat; this is my body.", "web": "As they were eating, Jesus took bread, gave thanks for it, and broke it. He gave to the disciples, and said, “Take, eat; this is my body.”", "bsb": "While they were eating, Jesus took bread, spoke a blessing and broke it, and gave it to the disciples, saying, “Take and eat; this is My body.”", "asv": "And as they were eating, Jesus took bread, and blessed, and brake it; and he gave to the disciples, and said, Take, eat; this is my body.", "ylt": "And while they were eating, Jesus having taken the bread, and having blessed, did brake, and was giving to the disciples, and said, `Take, eat, this is my body;'", "tyndale": "As they dyd eate Iesus toke breed and gave thankes brake it and gave it to the disciples and sayde: Take eate this is my body.", "dra": "And whilst they were at supper, Jesus took bread and blessed and broke and gave to his disciples and said: Take ye and eat. This is my body.", "bbe": "And when they were taking food, Jesus took bread and, after blessing it, he gave the broken bread to the disciples and said, Take it; this is my body.", "geneva": "And as they did eate, Iesus tooke the bread, and when he had blessed, he brake it, and gaue it to the disciples, and sayd, Take, eate: this is my bodie.", "wycliffe": "And while thei soupeden, Jhesus took breed, and blesside, and brak, and yaf to hise disciplis, and seide, Take ye, and ete; this is my body.", "rotherham": "And, as they were eating, Jesus, taking a loaf and blessing, brake,—and, giving to his disciples, said—Take, eat! This, is, my body.", "weymouth": "During the meal Jesus took a Passover biscuit, blessed it and broke it. He then gave it to the disciples, saying, \"Take this and eat it: it is my body.\"", "darby": "And as they were eating, Jesus, having taken [the] bread and blessed, broke [it] and gave [it] to the disciples, and said, Take, eat: this is my body.", "twenty": "While they were eating, Jesus took some bread, and, after saying the blessing, broke it and, as he gave it to his disciples, said: “Take it and eat it; this is my body.”", "acv": "And as they were eating, Jesus, having taken bread, having expressed thanks, broke in pieces, and he gave to the disciples, and said, Take, eat, this is my body.", "anderson": "And as they were eating, Jesus took bread, and when he had given thanks, he broke it, and gave it to the disciples, and said: Take, eat; this is my body.", "haweis": "Then as they were eating, Jesus took bread, and blessing, brake, and gave it to the disciples, and said, Take, eat: this is my body.", "noyes": "And, as they were eating, Jesus took a loaf, and having blessed, broke it, and gave it to the disciples, and said, Take, eat; this is my body.", "webster": "And as they were eating, Jesus took bread, and blessed [it], and broke [it], and gave [it] to the disciples, and said, Take, eat; this is my body.", "vulgate": "cenantibus autem eis accepit Iesus panem et benedixit ac fregit deditque discipulis suis et ait accipite et comedite hoc est corpus meum;"}}, {"v": 27, "ref": "26:27", "o": "καὶ ⸀λαβὼν ποτήριον καὶ εὐχαριστήσας ἔδωκεν αὐτοῖς λέγων· Πίετε ἐξ αὐτοῦ πάντες,", "en": {"kjv": "And he took the cup, and gave thanks, and gave it to them, saying, Drink ye all of it;", "web": "He took the cup, gave thanks, and gave to them, saying, “All of you drink it,", "bsb": "Then He took the cup, gave thanks, and gave it to them, saying, “Drink from it, all of you.", "asv": "And he took a cup, and gave thanks, and gave to them, saying, Drink ye all of it;", "ylt": "and having taken the cup, and having given thanks, he gave to them, saying, `Drink ye of it--all;", "tyndale": "And he toke the cup and thanked and gave it them sayinge: drinke of it every one.", "dra": "And taking the chalice, he gave thanks and gave to them, saying: Drink ye all of this.", "bbe": "And he took a cup and, having given praise, he gave it to them, saying,", "geneva": "Also he tooke the cuppe, and when he had giuen thankes, he gaue it them, saying, Drinke ye all of it.", "wycliffe": "And he took the cuppe, and dide thankyngis, and yaf to hem,", "rotherham": "And, taking a cup, and giving thanks, he gave unto them, saying—Drink of it, all of you;", "weymouth": "And He took the cup and gave thanks, and gave it to them saying, \"Drink from it, all of you;", "darby": "And having taken [the] cup and given thanks, he gave [it] to them, saying, Drink ye all of it.", "twenty": "Then he took a cup, and, after saying the thanksgiving, gave it to them, with the words: “Drink from it, all of you;", "acv": "And having taken the cup, having expressed thanks, he gave to them, saying, All ye drink of it,", "anderson": "And he took the cup, and gave thanks, and gave it to them, saying: Do you all drink of it:", "haweis": "And taking the cup, and giving thanks, he gave it to them, saying, Drink ye all of this:", "noyes": "And he took a cup, and gave thanks, and gave it to them, saying, Drink ye all of it;", "webster": "And he took the cup, and gave thanks, and gave [it] to them, saying, Drink ye all of it;", "vulgate": "et accipiens calicem gratias egit et dedit illis dicens bibite ex hoc omnes;"}}, {"v": 28, "ref": "26:28", "o": "τοῦτο γάρ ἐστιν τὸ αἷμά ⸀μου ⸀τῆς διαθήκης τὸ περὶ πολλῶν ἐκχυννόμενον εἰς ἄφεσιν ἁμαρτιῶν·", "en": {"kjv": "For this is my blood of the new testament, which is shed for many for the remission of sins.", "web": "for this is my blood of the new covenant, which is poured out for many for the remission of sins.", "bsb": "This is My blood of the covenant, which is poured out for many for the forgiveness of sins.", "asv": "for this is my blood of the covenant, which is poured out for many unto remission of sins.", "ylt": "for this is my blood of the new covenant, that for many is being poured out--to remission of sins;", "tyndale": "For this is my bloude of the new testament that shalbe shedde for many for the remission of synnes.", "dra": "For this is my blood of the new testament, which shall be shed for many unto remission of sins.", "bbe": "Take of it, all of you, for this is my blood of the testament, which is given for men for the forgiveness of sins.", "geneva": "For this is my blood of the Newe Testament, that is shedde for many, for the remission of sinnes.", "wycliffe": "and seide, Drynke ye alle herof; this is my blood of the newe testament, which schal be sched for many, in to remissioun of synnes.", "rotherham": "For, this, is my blood of the covenant, which, for many, is to be poured out, for remission of sins.", "weymouth": "for this is my blood which is to be poured out for many for the remission of sins--the blood which ratifies the Covenant.", "darby": "For this is my blood, that of the [new] covenant, that shed for many for remission of sins.", "twenty": "for this is my Covenant blood, which is poured out for many for the forgiveness of sins.", "acv": "for this is my blood of the new covenant, which is shed on behalf of many for remission of sins.", "anderson": "for this is my blood of the new covenant, which is poured out for many in order to the remission of sins.", "haweis": "for this is my blood, that blood of the new testament, which is shed for many, for the remission of sins.", "noyes": "for this is my blood of the covenant, which is shed for many for remission of sins.", "webster": "For this is my blood of the new testament, which is shed for many for the remission of sin.", "vulgate": "hic est enim sanguis meus novi testamenti qui pro multis effunditur in remissionem peccatorum;"}}, {"v": 29, "ref": "26:29", "o": "λέγω δὲ ⸀ὑμῖν, οὐ μὴ πίω ἀπ’ ἄρτι ἐκ τούτου τοῦ γενήματος τῆς ἀμπέλου ἕως τῆς ἡμέρας ἐκείνης ὅταν αὐτὸ πίνω μεθ’ ὑμῶν καινὸν ἐν τῇ βασιλείᾳ τοῦ πατρός μου.", "en": {"kjv": "But I say unto you, I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father’s kingdom.", "web": "But I tell you that I will not drink of this fruit of the vine from now on, until that day when I drink it anew with you in my Father’s Kingdom.”", "bsb": "I tell you, I will not drink of this fruit of the vine from now on until that day when I drink it anew with you in My Father’s kingdom.”", "asv": "But I say unto you, I shall not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father’s kingdom.", "ylt": "and I say to you, that I may not drink henceforth on this produce of the vine, till that day when I may drink it with you new in the reign of my Father.'", "tyndale": "I saye vnto you: I will not drinke hence forth of this frute of the vyne tree vntyll that daye when I shall drinke it new with you in my fathers kyngdome.", "dra": "And I say to you, I will not drink from henceforth of this fruit of the vine until that day when I shall drink it with you new in the kingdom of my Father.", "bbe": "But I say to you that from now I will not take of this fruit of the vine, till that day when I take it new with you in my Father's kingdom.", "geneva": "I say vnto you, that I will not drinke henceforth of this fruit of the vine vntil that day, when I shall drinke it new with you in my Fathers kingdome.", "wycliffe": "And Y seie to you, Y schal not drynke fro this tyme, of this fruyt of the vyne, in to that dai whanne Y schal drynke it newe with you, in the kyngdom of my fadir.", "rotherham": "Moreover, I say unto you—In nowise, will I drink, henceforth, of this produce of the vine, until that day, whensoever I shall drink it with you, new, in the kingdom of my Father.", "weymouth": "I tell you that I will never again take the produce of the vine till that day when I shall drink the new wine with you in my Father's Kingdom.\"", "darby": "But I say to you, that I will not at all drink henceforth of this fruit of the vine, until that day when I drink it new with you in the kingdom of my Father.", "twenty": "And I tell you that I shall never, after this, drink of this juice of the grape, until that day when I shall drink it new with you in the Kingdom of my Father.”", "acv": "But I say to you, that I will, no, not drink of this fruit of the grapevine henceforth until that day when I drink it new with you in my Father's kingdom.", "anderson": "But I say to you, I will not drink henceforth of this fruit of the vine, till that day when I drink it with you new in the kingdom of my Father.", "haweis": "And I tell you, That I will no more henceforth drink of this produce of the vine, until that day when I drink it with you, new, in the kingdom of my Father.", "noyes": "And I say to you, I shall not drink henceforth of this fruit of the vine, until that day when I drink it new with you in the kingdom of my Father.", "webster": "But I say to you, I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father's kingdom.", "vulgate": "dico autem vobis non bibam amodo de hoc genimine vitis usque in diem illum cum illud bibam vobiscum novum in regno Patris mei;"}}, {"v": 30, "ref": "26:30", "o": "καὶ ὑμνήσαντες ἐξῆλθον εἰς τὸ Ὄρος τῶν Ἐλαιῶν.", "en": {"kjv": "And when they had sung an hymn, they went out into the mount of Olives.", "web": "When they had sung a hymn, they went out to the Mount of Olives.", "bsb": "And when they had sung a hymn, they went out to the Mount of Olives.", "asv": "And when they had sung a hymn, they went out into the mount of Olives.", "ylt": "And having sung a hymn, they went forth to the mount of the Olives;", "tyndale": "And when they had sayde grace they went out into mounte olyvete.", "dra": "And a hymn being said, they went out unto mount Olivet.", "bbe": "And after a song of praise to God, they went out to the Mountain of Olives.", "geneva": "And when they had sung a Psalme, they went out into the mount of Oliues.", "wycliffe": "And whanne the ympne was seid, thei wenten out in to the mount of Olyuete.", "rotherham": "And, having sung praise, they went forth unto the Mount of Olives.", "weymouth": "So they sang the hymn and went out to the Mount of Olives.", "darby": "And having sung a hymn, they went out to the mount of Olives.", "twenty": "They then sang a hymn, and went out to the Mount of Olives.", "acv": "And having sung a hymn, they went out to the mount of Olives.", "anderson": "And when they had sung a hymn, they went out into the mount of Olives.", "haweis": "And when they had sung an hymn, they went out to the mount of Olives.", "noyes": "And having sung a hymn, they went out to the Mount of Olives.", "webster": "And when they had sung a hymn, they went out to the mount of Olives.", "vulgate": "et hymno dicto exierunt in montem Oliveti;"}}, {"v": 31, "ref": "26:31", "o": "Τότε λέγει αὐτοῖς ὁ Ἰησοῦς· Πάντες ὑμεῖς σκανδαλισθήσεσθε ἐν ἐμοὶ ἐν τῇ νυκτὶ ταύτῃ, γέγραπται γάρ· Πατάξω τὸν ποιμένα, καὶ ⸀διασκορπισθήσονται τὰ πρόβατα τῆς ποίμνης·", "en": {"kjv": "Then saith Jesus unto them, All ye shall be offended because of me this night: for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.", "web": "Then Jesus said to them, “All of you will be made to stumble because of me tonight, for it is written, ‘I will strike the shepherd, and the sheep of the flock will be scattered.’", "bsb": "Then Jesus said to them, “This very night you will all fall away on account of Me. For it is written: ‘I will strike the Shepherd, and the sheep of the flock will be scattered.’", "asv": "Then saith Jesus unto them, All ye shall be offended in me this night: for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.", "ylt": "then saith Jesus to them, `All ye shall be stumbled at me this night; for it hath been written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad;", "tyndale": "Then sayd Iesus vnto them: all ye shall be offended by me this night. For it is wrytten. I will smyte ye shepe herde and the shepe of ye flocke shalbe scattered abroode.", "dra": "Then Jesus saith to them: All you shall be scandalized in me this night. For it is written: I will strike the shepherd: and the sheep of the flock shall be dispersed.", "bbe": "Then said Jesus to them, All of you will be turned away from me this night: for it is said in the Writings, I will put to death the keeper of the sheep, and the sheep of the flock will be put to flight.", "geneva": "Then saide Iesus vnto them, All yee shall be offended by me this night: for it is written, I wil smite the shepheard, and the sheepe of the flocke shalbe scattered.", "wycliffe": "Thanne Jhesus seide to hem, Alle ye schulen suffre sclaundre in me, in this niyt; for it is writun, Y schal smyte the scheeperde, and the scheep of the flok schulen be scaterid.", "rotherham": "Then, Jesus saith unto them—All ye, will find cause of stumbling in me, during this night; for it is written, I will smite the shepherd, and, the sheep of the flock, will be scattered abroad;", "weymouth": "Then said Jesus, \"This night all of you will stumble and fail in your fidelity to me; for it is written, `I will strike the Shepherd, and the sheep of the flock will be scattered in all directions.'", "darby": "Then saith Jesus to them, All ye shall be offended in me during this night. For it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.", "twenty": "Then Jesus said to them: “Even you will all fall away from me to-night. Scripture says — ‘I will strike down the shepherd, and the sheep of the flock will be scattered.’", "acv": "Then Jesus says to them, All ye will be caused to stumble by me in this night, for it is written, I will strike the shepherd, and the sheep of the flock will be scattered.", "anderson": "Then Jesus said to them: All of you will he offended at me this night; for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered.", "haweis": "Then saith Jesus unto them, Ye all will be offended at me this night: for it is written, “I will smite the shepherd, and the sheep of the flock shall be scattered abroad.”", "noyes": "Then Jesus saith to them, This night will all of you fall away from me; for it is written, \"I will smite the shepherd, and the sheep of the flock will be scattered.\"", "webster": "Then saith Jesus to them, All ye shall be offended because of me this night: for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.", "vulgate": "tunc dicit illis Iesus omnes vos scandalum patiemini in me in ista nocte scriptum est enim percutiam pastorem et dispergentur oves gregis;"}}, {"v": 32, "ref": "26:32", "o": "μετὰ δὲ τὸ ἐγερθῆναί με προάξω ὑμᾶς εἰς τὴν Γαλιλαίαν.", "en": {"kjv": "But after I am risen again, I will go before you into Galilee.", "web": "But after I am raised up, I will go before you into Galilee.”", "bsb": "But after I have risen, I will go ahead of you into Galilee.”", "asv": "But after I am raised up, I will go before you into Galilee.", "ylt": "but, after my having risen, I will go before you to Galilee.'", "tyndale": "But after I am rysen ageyne I will goo before you into Galile.", "dra": "But after I shall be risen again, I will go before you into Galilee.", "bbe": "But after I am come back from the dead, I will go before you into Galilee.", "geneva": "But after I am risen againe, I will go before you into Galile.", "wycliffe": "But aftir that Y schal rise ayen, Y schal go bifore you in to Galilee.", "rotherham": "But, after my arising, I will go before you into Galilee.", "weymouth": "But after I have risen to life again I will go before you into Galilee.\"", "darby": "But after that I shall be risen, I will go before you to Galilee.", "twenty": "But, after I have risen, I shall go before you into Galilee.”", "acv": "But after I am raised up, I will go before you into Galilee.", "anderson": "But after I have risen, I will go before you into Galilee.", "haweis": "But after I am risen, I will go before you into Galilee.", "noyes": "But after I have risen, I will go before you into Galilee.", "webster": "But after I am risen again, I will go before you into Galilee.", "vulgate": "postquam autem resurrexero praecedam vos in Galilaeam;"}}, {"v": 33, "ref": "26:33", "o": "ἀποκριθεὶς δὲ ὁ Πέτρος εἶπεν αὐτῷ· Εἰ πάντες σκανδαλισθήσονται ἐν σοί, ⸀ἐγὼ οὐδέποτε σκανδαλισθήσομαι.", "en": {"kjv": "Peter answered and said unto him, Though all men shall be offended because of thee, yet will I never be offended.", "web": "But Peter answered him, “Even if all will be made to stumble because of you, I will never be made to stumble.”", "bsb": "Peter said to Him, “Even if all fall away on account of You, I never will.”", "asv": "But Peter answered and said unto him, If all shall be offended in thee, I will never be offended.", "ylt": "And Peter answering said to him, `Even if all shall be stumbled at thee, I will never be stumbled.'", "tyndale": "Peter answered and sayde vnto him: though all men shulde be offended by ye yet wolde I never be offended.", "dra": "And Peter answering, said to him: Although all shall be scandalized in thee, I will never be scandalized.", "bbe": "But Peter made answer and said to him, Though all may be turned away from you, I will never be turned away.", "geneva": "But Peter aunswered, and sayde vnto him, Though that al men should be offended by thee, yet will I neuer be offended.", "wycliffe": "Petre answeride, and seide to hym, Thouy alle schulen be sclaundrid in thee, Y schal neuer be sclaundrid.", "rotherham": "Now Peter, answering, said unto him—Though, all, shall find cause of stumbling in thee, I, shall never find cause of stumbling.", "weymouth": "\"All may stumble and fail,\" said Peter, \"but I never will.\"", "darby": "And Peter answering said to him, If all shall be offended in thee, I will never be offended.", "twenty": "“If every one else falls away from you,” Peter answered, “I shall never fall away!”", "acv": "But having answered, Peter said to him, If all men will be caused to stumble by thee, I will never be caused to stumble.", "anderson": "Peter answered and said to him: Though all shall be offended at thee, yet will I never be offended.", "haweis": "Then Peter, taking up the word, said to him, Though all should be offended at thee, yet will I never be offended.", "noyes": "Peter answering said to him, Though all should fall away from thee, yet will I never fall away.", "webster": "Peter answered and said to him, Though all [men] shall be offended because of thee, [yet] will I never be offended.", "vulgate": "respondens autem Petrus ait illi et si omnes scandalizati fuerint in te ego numquam scandalizabor;"}}, {"v": 34, "ref": "26:34", "o": "ἔφη αὐτῷ ὁ Ἰησοῦς· Ἀμὴν λέγω σοι ὅτι ἐν ταύτῃ τῇ νυκτὶ πρὶν ἀλέκτορα φωνῆσαι τρὶς ἀπαρνήσῃ με.", "en": {"kjv": "Jesus said unto him, Verily I say unto thee, That this night, before the cock crow, thou shalt deny me thrice.", "web": "Jesus said to him, “Most certainly I tell you that tonight, before the rooster crows, you will deny me three times.”", "bsb": "“Truly I tell you,” Jesus declared, “this very night, before the rooster crows, you will deny Me three times.”", "asv": "Jesus said unto him, Verily I say unto thee, that this night, before the cock crow, thou shalt deny me thrice.", "ylt": "Jesus said to him, `Verily I say to thee, that, this night, before cock-crowing, thrice thou wilt deny me.'", "tyndale": "Iesus sayde vnto him. Verely I saye vnto ye that this same night before the cocke crowe thou shalt denye me thryse.", "dra": "Jesus said to him: Amen I say to thee that in this night before the cock crow, thou wilt deny me thrice.", "bbe": "Jesus said to him, Truly I say to you that this night, before the hour of the cock's cry, you will say three times that you have no knowledge of me.", "geneva": "Iesus sayde vnto him, Verely I say vnto thee, that this night, before the cocke crow, thou shalt denie me thrise.", "wycliffe": "Jhesus seide to him, Treuli Y seie to thee, for in this nyyt bifor the cok crowe, thries thou schalt denye me.", "rotherham": "Jesus saith unto him: Verily, I say unto thee—During this night, before a cock crow, Thrice, wilt thou deny me.", "weymouth": "\"In solemn truth I tell you,\" replied Jesus, \"that this very night, before the cock crows, you will three times disown me.\"", "darby": "Jesus said to him, Verily I say to thee, that during this night, before [the] cock shall crow, thou shalt deny me thrice.", "twenty": "“I tell you,” replied Jesus, “that this very night, before the cock crows, you will disown me three times!”", "acv": "Jesus said to him, Truly I say to thee, that in this night, before a cock sounds, thou will deny me thrice.", "anderson": "Jesus said to him: Verily I say to you, This night, before the cock crows, you will deny me three times.", "haweis": "Jesus saith to him, I tell thee of a certainty, that this night, before the cock crow, thou shalt deny me thrice.", "noyes": "Jesus said to him, Truly do I say to thee, that this night, before a cock crows, thou wilt thrice deny me.", "webster": "Jesus said to him, Verily I say to thee, that this night, before the cock shall crow, thou wilt deny me thrice.", "vulgate": "ait illi Iesus amen dico tibi quia in hac nocte antequam gallus cantet ter me negabis;"}}, {"v": 35, "ref": "26:35", "o": "λέγει αὐτῷ ὁ Πέτρος· Κἂν δέῃ με σὺν σοὶ ἀποθανεῖν, οὐ μή σε ⸀ἀπαρνήσομαι. ⸀ὁμοίως καὶ πάντες οἱ μαθηταὶ εἶπαν.", "en": {"kjv": "Peter said unto him, Though I should die with thee, yet will I not deny thee. Likewise also said all the disciples.", "web": "Peter said to him, “Even if I must die with you, I will not deny you.” All of the disciples also said likewise.", "bsb": "Peter replied, “Even if I have to die with You, I will never deny You.” And all the other disciples said the same thing.", "asv": "Peter saith unto him, Even if I must die with thee, yet will I not deny thee. Likewise also said all the disciples.", "ylt": "Peter saith to him, `Even if it may be necessary for me to die with thee, I will not deny thee;' in like manner also said all the disciples.", "tyndale": "Peter sayde vnto him: Yf I shulde dye with ye yet wolde I not denye ye Lyke wyse also sayde all ye disciples.", "dra": "Peter saith to him: Yea, though I should die with thee, I will not deny thee. And in like manner said all the disciples.", "bbe": "Peter says to him, Even if I am put to death with you, I will not be false to you. So said all the disciples.", "geneva": "Peter saide vnto him, Though I should die with thee, I will in no case denie thee. Likewise also sayd all the disciples.", "wycliffe": "Peter seide to him, Yhe, thouy it bihoue that Y die with thee, Y schal not denye thee. Also alle the disciplis seiden.", "rotherham": "Peter saith unto him: Even though it be needful for me, with thee to die, in nowise, will I deny thee. Likewise, all the disciples also, said.", "weymouth": "\"Even if I must die with you,\" declared Peter, \"I will never disown you.\" In like manner protested all the disciples.", "darby": "Peter says to him, If I should needs die with thee, I will in no wise deny thee. Likewise said all the disciples also.", "twenty": "“Even if I must die with you,” Peter exclaimed, “I shall never disown you!” All the disciples spoke in the same way.", "acv": "Peter says to him, Even if I must die with thee, I will, no, not deny thee. And likewise also, said all the disciples.", "anderson": "Peter said to him: Though it should be necessary for me to die with thee, I will not deny thee. In like manner said all the disciples.", "haweis": "Peter said to him, Though I should die with thee, never will I deny thee. In like manner also said all the disciples.", "noyes": "Peter saith to him, Even if I must die with thee, I will not deny thee. And so said all the disciples.", "webster": "Peter said to him, Though I should die with thee, yet will I not deny thee. Likewise also said all the disciples.", "vulgate": "ait illi Petrus etiam si oportuerit me mori tecum non te negabo similiter et omnes discipuli dixerunt;"}}, {"v": 36, "ref": "26:36", "o": "Τότε ἔρχεται μετ’ αὐτῶν ὁ Ἰησοῦς εἰς χωρίον λεγόμενον Γεθσημανί, καὶ λέγει τοῖς μαθηταῖς· Καθίσατε αὐτοῦ ἕως οὗ ἀπελθὼν ⸂ἐκεῖ προσεύξωμαι⸃.", "en": {"kjv": "Then cometh Jesus with them unto a place called Gethsemane, and saith unto the disciples, Sit ye here, while I go and pray yonder.", "web": "Then Jesus came with them to a place called Gethsemane, and said to his disciples, “Sit here, while I go there and pray.”", "bsb": "At that time Jesus went with His disciples to a place called Gethsemane, and He told them, “Sit here while I go over there and pray.”", "asv": "Then cometh Jesus with them unto a place called Gethsemane, and saith unto his disciples, Sit ye here, while I go yonder and pray.", "ylt": "Then come with them doth Jesus to a place called Gethsemane, and he saith to the disciples, `Sit ye here, till having gone away, I shall pray yonder.'", "tyndale": "Then went Iesus with them into a place which is called Gethsemane and sayde vnto the disciples syt ye here whyll I go and praye yonder.", "dra": "Then Jesus came with them into a country place which is called Gethsemani. And he said to his disciples: Sit you here, till I go yonder and pray.", "bbe": "Then comes Jesus with them to a place named Gethsemane, and says to his disciples, Be seated here, while I go over there for prayer.", "geneva": "Then went Iesus with them into a place which is called Gethsemane, and said vnto his disciples, Sit ye here, while I goe, and pray yonder.", "wycliffe": "Thanne Jhesus cam with hem in to a toun, that is seid Jessamanye. And he seide to his disciplis, Sitte ye here, the while Y go thider, and preye.", "rotherham": "Then Jesus cometh with them, into a place called Gethsemane,—and he saith unto his disciples, Sit ye here, while I go yonder and pray.", "weymouth": "Then Jesus came with them to a place called Gethsemane. And He said to the disciples, \"Sit down here, whilst I go yonder and there pray.\"", "darby": "Then Jesus comes with them to a place called Gethsemane, and says to the disciples, Sit here until I go away and pray yonder.", "twenty": "Then Jesus came with them to a garden called Gethsemane, and he said to his disciples: “Sit down here while I go and pray yonder.”", "acv": "Then Jesus comes with them to a place called Gethsemane, and he says to his disciples, Sit ye here until, after going, I may pray there.", "anderson": "Then Jesus came with them to a place called Gethsemane, and said to his disciples: Sit here, till I go and pray yonder.", "haweis": "Then cometh Jesus with them to a place called Gethsemane, and saith to his disciples, Sit ye here, while I go and pray yonder.", "noyes": "Then Jesus cometh with them to a place called Gethsemane, and saith to the disciples, Sit here, while I go yonder and pray.", "webster": "Then cometh Jesus with them to a place called Gethsemane, and saith to the disciples, Sit ye here, while I go yonder and pray.", "vulgate": "tunc venit Iesus cum illis in villam quae dicitur Gethsemani et dixit discipulis suis sedete hic donec vadam illuc et orem;"}}, {"v": 37, "ref": "26:37", "o": "καὶ παραλαβὼν τὸν Πέτρον καὶ τοὺς δύο υἱοὺς Ζεβεδαίου ἤρξατο λυπεῖσθαι καὶ ἀδημονεῖν.", "en": {"kjv": "And he took with him Peter and the two sons of Zebedee, and began to be sorrowful and very heavy.", "web": "He took with him Peter and the two sons of Zebedee, and began to be sorrowful and severely troubled.", "bsb": "He took with Him Peter and the two sons of Zebedee and began to be sorrowful and deeply distressed.", "asv": "And he took with him Peter and the two sons of Zebedee, and began to be sorrowful and sore troubled.", "ylt": "And having taken Peter, and the two sons of Zebedee, he began to be sorrowful, and to be very heavy;", "tyndale": "And he toke with him Peter and the two sonnes of zebede and began to wexe sorowfull and to be in an agonye.", "dra": "And taking with him Peter and the two sons of Zebedee, he began to grow sorrowful and to be sad.", "bbe": "And he took with him Peter and the two sons of Zebedee, and became sad and very troubled.", "geneva": "And hee tooke vnto him Peter, and the two sonnes of Zebedeus, and began to waxe sorowfull, and grieuously troubled.", "wycliffe": "And whanne he hadde take Peter, and twei sones of Zebedee, he bigan to be heuy and sori.", "rotherham": "And, taking with him, Peter and the two sons of Zebedee, he began to be grieved and to be in great distress.", "weymouth": "And He took with Him Peter and the two sons of Zabdi. Then He began to be full of anguish and distress,", "darby": "And taking with [him] Peter and the two sons of Zebedee, he began to be sorrowful and deeply depressed.", "twenty": "Taking with him Peter and the two sons of Zebediah, he began to show signs of sadness and deep distress of mind.", "acv": "And having taken Peter and the two sons of Zebedee, he began to be sorrowful and distressed.", "anderson": "And he took with him Peter and the two sons of Zebedee, and began to be in deep distress and anguish of soul.", "haweis": "And taking Peter and the two sons of Zebedee, he began to be deeply sorrowful, and to be overwhelmed with dejection.", "noyes": "And taking with him Peter and the two sons of Zebedee, he began to he sorrowful and full of anguish.", "webster": "And he took with him Peter, and the two sons of Zebedee, and began to be sorrowful and very heavy.", "vulgate": "et adsumpto Petro et duobus filiis Zebedaei coepit contristari et maestus esse;"}}, {"v": 38, "ref": "26:38", "o": "τότε λέγει ⸀αὐτοῖς· Περίλυπός ἐστιν ἡ ψυχή μου ἕως θανάτου· μείνατε ὧδε καὶ γρηγορεῖτε μετ’ ἐμοῦ.", "en": {"kjv": "Then saith he unto them, My soul is exceeding sorrowful, even unto death: tarry ye here, and watch with me.", "web": "Then he said to them, “My soul is exceedingly sorrowful, even to death. Stay here, and watch with me.”", "bsb": "Then He said to them, “My soul is consumed with sorrow to the point of death. Stay here and keep watch with Me.”", "asv": "Then saith he unto them, My soul is exceeding sorrowful, even unto death: abide ye here, and watch with me.", "ylt": "then saith he to them, `Exceedingly sorrowful is my soul--unto death; abide ye here, and watch with me.'", "tyndale": "Then sayd Iesus vnto them: my soule is hevy even vnto the deeth. Tary ye here and watche wt me.", "dra": "Then he saith to them: My soul is sorrowful even unto death. Stay you here and watch with me.", "bbe": "Then says he to them, My soul is very sad, even to death: keep watch with me here.", "geneva": "Then sayde Iesus vnto them, My soule is very heauie, euen vnto the death: tarie yee here, and watch with me.", "wycliffe": "Thanne he seide to hem, My soule is soreuful to the deeth; abide ye here, and wake ye with me.", "rotherham": "Then, saith he unto them: Encompassed with grief, is my soul, unto death: Abide ye here, and be watching with me.", "weymouth": "and He said to them, \"My soul is crushed with anguish to the very point of death; wait here, and keep awake with me.\"", "darby": "Then he says to them, My soul is very sorrowful even unto death; remain here and watch with me.", "twenty": "“I am sad at heart,” he said, “sad even to death; wait here and watch with me.”", "acv": "Then Jesus says to them, My soul is deeply grieved, as far as of death. Remain ye here and watch with me.", "anderson": "Then Jesus said to them: My soul is encompassed with sorrow even to death; remain here, and watch with me.", "haweis": "Then saith he to them. My soul is exceeding sorrowful even to death: abide here, and watch with me.", "noyes": "Then he saith to them, My soul is exceedingly sorrowful, even to death; remain here, and watch with me.", "webster": "Then saith he to them, My soul is exceeding sorrowful, even to death: tarry ye here, and watch with me.", "vulgate": "tunc ait illis tristis est anima mea usque ad mortem sustinete hic et vigilate mecum;"}}, {"v": 39, "ref": "26:39", "o": "καὶ ⸀προελθὼν μικρὸν ἔπεσεν ἐπὶ πρόσωπον αὐτοῦ προσευχόμενος καὶ λέγων· Πάτερ μου, εἰ δυνατόν ἐστιν, παρελθάτω ἀπ’ ἐμοῦ τὸ ποτήριον τοῦτο· πλὴν οὐχ ὡς ἐγὼ θέλω ἀλλ’ ὡς σύ.", "en": {"kjv": "And he went a little further, and fell on his face, and prayed, saying, O my Father, if it be possible, let this cup pass from me: nevertheless not as I will, but as thou wilt.", "web": "He went forward a little, fell on his face, and prayed, saying, “My Father, if it is possible, let this cup pass away from me; nevertheless, not what I desire, but what you desire.”", "bsb": "Going a little farther, He fell facedown and prayed, “My Father, if it is possible, let this cup pass from Me. Yet not as I will, but as You will.”", "asv": "And he went forward a little, and fell on his face, and prayed, saying, My Father, if it be possible, let this cup pass away from me: nevertheless, not as I will, but as thou wilt.", "ylt": "And having gone forward a little, he fell on his face, praying, and saying, `My Father, if it be possible, let this cup pass from me; nevertheless, not as I will, but as Thou.'", "tyndale": "And he went a lytell aparte and fell flat on his face and prayed sayinge: O my father yf it be possible let this cuppe passe from me: neverthelesse not as I wyll but as thou wylt.", "dra": "And going a little further, he fell upon his face, praying and saying: My Father, if it be possible, let this chalice pass from me. Nevertheless, not as I will but as thou wilt.", "bbe": "And he went forward a little, and falling down on his face in prayer, he said, O my Father, if it is possible, let this cup go from me; but let not my pleasure, but yours be done.", "geneva": "So hee went a litle further, and fell on his face, and praied, saying, O my Father, if it be possible, let this cup passe from me: neuerthelesse, not as I will, but as thou wilt.", "wycliffe": "And he yede forth a litil, and felde doun on his face, preiynge, and seiynge, My fader, if it is possible, passe this cuppe fro me; netheles not as Y wole, but as thou wolt.", "rotherham": "And, going forward a little, he fell upon his face, offering prayer, and saying—My Father! If it is possible, let this cup pass from me,—Nevertheless, not as, I, will, but as, thou, wilt.", "weymouth": "Going forward a short distance He fell on His face and prayed. \"My Father,\" He said, \"if it is possible, let this cup pass away from me; nevertheless, not as I will, but as Thou willest.\"", "darby": "And going forward a little he fell upon his face, praying and saying, My Father, if it be possible let this cup pass from me; but not as I will, but as thou [wilt].", "twenty": "Going on a little further, he threw himself on his face in prayer. “My Father,” he said, “if it is possible, let me be spared this cup; only, not as I will, but as thou willest.”", "acv": "And having gone forward a little, he fell on his face praying, and saying, My Father, if it be possible, may this cup pass from me. Nevertheless, not as I want, but as thou.", "anderson": "And he went forward a little, and fell on his face in prayer, saying: My Father, if it is possible, let this cup pass from me; yet not as I will, but as thou willest.", "haweis": "And going a little farther, he fell on his face, praying, and saying, My Father, if it be possible, let this cup pass from me: nevertheless, not as I will, but as thou wilt.", "noyes": "And he came a little nearer, and fell on his face, praying and saying, Father, if it be possible, let this cup pass from me! nevertheless, not as I will, but as Thou wilt.", "webster": "And he went a little further, and fell on his face, and prayed, saying, O my Father, if it is possible, let this cup pass from me: nevertheless, not as I will, but as thou [wilt].", "vulgate": "et progressus pusillum procidit in faciem suam orans et dicens mi Pater si possibile est transeat a me calix iste verumtamen non sicut ego volo sed sicut tu;"}}, {"v": 40, "ref": "26:40", "o": "καὶ ἔρχεται πρὸς τοὺς μαθητὰς καὶ εὑρίσκει αὐτοὺς καθεύδοντας, καὶ λέγει τῷ Πέτρῳ· Οὕτως οὐκ ἰσχύσατε μίαν ὥραν γρηγορῆσαι μετ’ ἐμοῦ;", "en": {"kjv": "And he cometh unto the disciples, and findeth them asleep, and saith unto Peter, What, could ye not watch with me one hour?", "web": "He came to the disciples, and found them sleeping, and said to Peter, “What, couldn’t you watch with me for one hour?", "bsb": "Then Jesus returned to the disciples and found them sleeping. “Were you not able to keep watch with Me for one hour?” He asked Peter.", "asv": "And he cometh unto the disciples, and findeth them sleeping, and saith unto Peter, What, could ye not watch with me one hour?", "ylt": "And he cometh unto the disciples, and findeth them sleeping, and he saith to Peter, `So! ye were not able one hour to watch with me!", "tyndale": "And he came vnto the disciples and founde them a slepe and sayde to Peter: what coulde ye not watche with me one houre:", "dra": "And he cometh to his disciples and findeth them asleep. And he saith to Peter: What? Could you not watch one hour with me?", "bbe": "And he comes to the disciples, and sees that they are sleeping, and says to Peter, What, were you not able to keep watch with me one hour?", "geneva": "After, hee came vnto the disciples, and founde them a sleepe, and sayde to Peter, What? coulde yee not watch with me one houre?", "wycliffe": "And he cam to his disciplis, and foond hem slepynge. And he seide to Petir, So, whethir ye myyten not oon our wake with me?", "rotherham": "And he cometh unto his disciples, and findeth them sleeping, and said unto Peter—Thus, powerless are ye, one hour, to watch with me?", "weymouth": "Then He came to the disciples and found them asleep, and He said to Peter, \"Alas, none of you could keep awake with me for even a single hour!", "darby": "And he comes to the disciples and finds them sleeping, and says to Peter, Thus ye have not been able to watch one hour with me?", "twenty": "Then he came to his disciples, and found them asleep. “What!” he said to Peter, “could none of you watch with me for one hour?", "acv": "And he comes to the disciples, and finds them sleeping. And he says to Peter, So ye could not watch with me one hour.", "anderson": "And he came to his disciples, and found them sleeping; and he said to Peter: Was it so, that you had not strength to watch with me one hour?", "haweis": "And he cometh to the disciples, and findeth them sleeping, and he saith to Peter, Is it so, that ye have not strength to watch with me one hour?", "noyes": "And he cometh to the disciples, and findeth them sleeping, and saith to Peter, Is it so that ye could not watch with me one hour?", "webster": "And he cometh to the disciples, and findeth them asleep, and saith to Peter, What, could ye not watch with me one hour?", "vulgate": "et venit ad discipulos et invenit eos dormientes et dicit Petro sic non potuistis una hora vigilare mecum;"}}, {"v": 41, "ref": "26:41", "o": "γρηγορεῖτε καὶ προσεύχεσθε, ἵνα μὴ εἰσέλθητε εἰς πειρασμόν· τὸ μὲν πνεῦμα πρόθυμον ἡ δὲ σὰρξ ἀσθενής.", "en": {"kjv": "Watch and pray, that ye enter not into temptation: the spirit indeed is willing, but the flesh is weak.", "web": "Watch and pray, that you don’t enter into temptation. The spirit indeed is willing, but the flesh is weak.”", "bsb": "“Watch and pray so that you will not enter into temptation. For the spirit is willing, but the body is weak.”", "asv": "Watch and pray, that ye enter not into temptation: the spirit indeed is willing, but the flesh is weak.", "ylt": "watch, and pray, that ye may not enter into temptation: the spirit indeed is forward, but the flesh weak.'", "tyndale": "watche and praye that ye fall not into temptacion. The spirite is willynge but the flesshe is weake.", "dra": "Watch ye: and pray that ye enter not into temptation. The spirit indeed is willing, but the flesh is weak.", "bbe": "Keep watch with prayer, so that you may not be put to the test: the spirit truly is ready, but the flesh is feeble.", "geneva": "Watch, and praie, that yee enter not into tentation: the spirit in deede is readie, but the flesh is weake.", "wycliffe": "Wake ye, and preye ye, that ye entre not in to temptacioun; for the spirit is redi, but the fleisch is sijk.", "rotherham": "Be watching and praying, that ye may not enter into temptation: The spirit, indeed, is, eager, but, the flesh, weak.", "weymouth": "Keep awake, and pray that you may not enter into temptation: the spirit is right willing, but the body is frail.\"", "darby": "Watch and pray, that ye enter not into temptation: the spirit indeed [is] ready, but the flesh weak.", "twenty": "Watch and pray, that you may not fall into temptation. True, the spirit is eager, but human nature is weak.”", "acv": "Watch and pray that ye enter not into temptation. Truly, the spirit is willing, but the flesh is weak.", "anderson": "Watch and pray, lest you enter into temptation. The spirit is, willing, but the flesh is weak.", "haweis": "Watch and pray, that ye enter not into temptation. The spirit indeed is willing, but the flesh weak.", "noyes": "Watch, and pray that ye enter not into temptation; the spirit indeed is willing, but the flesh is weak.", "webster": "Watch and pray, that ye enter not into temptation: the spirit indeed [is] willing, but the flesh [is] weak.", "vulgate": "vigilate et orate ut non intretis in temptationem spiritus quidem promptus est caro autem infirma;"}}, {"v": 42, "ref": "26:42", "o": "πάλιν ἐκ δευτέρου ἀπελθὼν προσηύξατο λέγων· Πάτερ μου, εἰ οὐ δύναται ⸀τοῦτο ⸀παρελθεῖν ἐὰν μὴ αὐτὸ πίω, γενηθήτω τὸ θέλημά σου.", "en": {"kjv": "He went away again the second time, and prayed, saying, O my Father, if this cup may not pass away from me, except I drink it, thy will be done.", "web": "Again, a second time he went away, and prayed, saying, “My Father, if this cup can’t pass away from me unless I drink it, your desire be done.”", "bsb": "A second time He went away and prayed, “My Father, if this cup cannot pass unless I drink it, may Your will be done.”", "asv": "Again a second time he went away, and prayed, saying, My Father, if this cannot pass away, except I drink it, thy will be done.", "ylt": "Again, a second time, having gone away, he prayed, saying, `My Father, if this cup cannot pass away from me except I drink it, Thy will be done;'", "tyndale": "He went awaye once moare and prayed sayinge: O my father yf this cuppe can not passe away from me but yt I drinke of it thy wyll be fulfylled.", "dra": "Again the second time, he went and prayed, saying: My Father, if this chalice may not pass away, but I must drink it, thy will be done.", "bbe": "Again, a second time he went away, and said in prayer, O my Father, if this may not go from me without my taking it, let your pleasure be done.", "geneva": "Againe he went away the second time, and praied, saying, O my Father, if this cuppe can not passe away from mee, but that I must drinke it, thy will be done.", "wycliffe": "Eft the secounde tyme he wente, and preyede, seiynge, My fadir, if this cuppe may not passe, but Y drynke hym, thi wille be doon.", "rotherham": "Again, a second time, departing he prayed, saying: My Father! If it is impossible for this to pass, except I, drink, it, Accomplished, be, thy will.", "weymouth": "Again a second time He went away and prayed, saying, \"My Father, if it is impossible for this cup to pass without my drinking it, Thy will be done.\"", "darby": "Again going away a second time he prayed saying, My Father, if this cannot pass [from me] unless I drink it, thy will be done.", "twenty": "Again, a second time, he went away, and prayed. “My Father,” he said, “if I cannot be spared this cup, but must drink it, thy will be done!”", "acv": "Having gone again a second time, he prayed, saying, My Father, if it is not possible for this cup to pass from me, except I drink it, may thy will happen.", "anderson": "Again, a second time, he went away, and prayed, saying: My Father, if this cup cannot pass from me, unless I drink it, thy will be done.", "haweis": "Again the second time he went away, and prayed, saying, O my Father, If it be not possible, that this cup pass from me, but that I should drink it, thy will be done.", "noyes": "Again he went away a second time, and prayed, saying, My Father, if this [cup] cannot pass away from me, but I must drink it, thy will be done!", "webster": "He went away again the second time, and prayed, saying, O my Father, if this cup may not pass away from me, except I drink it, thy will be done.", "vulgate": "iterum secundo abiit et oravit dicens Pater mi si non potest hic calix transire nisi bibam illum fiat voluntas tua;"}}, {"v": 43, "ref": "26:43", "o": "καὶ ἐλθὼν ⸂πάλιν εὗρεν αὐτοὺς⸃ καθεύδοντας, ἦσαν γὰρ αὐτῶν οἱ ὀφθαλμοὶ βεβαρημένοι.", "en": {"kjv": "And he came and found them asleep again: for their eyes were heavy.", "web": "He came again and found them sleeping, for their eyes were heavy.", "bsb": "And again Jesus returned and found them sleeping—for their eyes were heavy.", "asv": "And he came again and found them sleeping, for their eyes were heavy.", "ylt": "and having come, he findeth them again sleeping, for their eyes were heavy.", "tyndale": "And he came and founde the a slepe agayne. For their eyes were hevy.", "dra": "And he cometh again and findeth them sleeping: for their eyes were heavy.", "bbe": "And he came again and saw them sleeping, for their eyes were tired.", "geneva": "And he came, and founde them a sleepe againe, for their eyes were heauie.", "wycliffe": "And eftsoone he cam, and foond hem slepynge; for her iyen weren heuyed.", "rotherham": "And coming, he, again, found them sleeping, for their eyes had become heavy.", "weymouth": "He came and again found them asleep, for they were very tired.", "darby": "And coming he found them again sleeping, for their eyes were heavy.", "twenty": "And coming back again he found them asleep, for their eyes were heavy.", "acv": "And having come again, he finds them sleeping, for their eyes were heavy.", "anderson": "And he came and found them sleeping again, for their eyes were heavy.", "haweis": "And coming, he found them asleep again, for their eyes were weighed down.", "noyes": "And coming again he found them sleeping; for their eyes were heavy.", "webster": "And he came and found them asleep again: for their eyes were heavy.", "vulgate": "et venit iterum et invenit eos dormientes erant enim oculi eorum gravati;"}}, {"v": 44, "ref": "26:44", "o": "καὶ ἀφεὶς αὐτοὺς ⸂πάλιν ἀπελθὼν⸃ προσηύξατο ἐκ τρίτου τὸν αὐτὸν λόγον εἰπὼν ⸀πάλιν.", "en": {"kjv": "And he left them, and went away again, and prayed the third time, saying the same words.", "web": "He left them again, went away, and prayed a third time, saying the same words.", "bsb": "So He left them and went away once more and prayed a third time, saying the same thing.", "asv": "And he left them again, and went away, and prayed a third time, saying again the same words.", "ylt": "And having left them, having gone away again, he prayed a third time, saying the same word;", "tyndale": "And he lefte them and went agayne and prayed ye thrid tyme sayinge ye same wordes.", "dra": "And leaving them, he went again: and he prayed the third time, saying the selfsame word.", "bbe": "And he went away from them again, and a third time said the same prayer.", "geneva": "So he left them and went away againe, and praied the third time, saying the same woordes.", "wycliffe": "And he lefte hem, and wente eftsoone, and preiede the thridde tyme, and seide the same word.", "rotherham": "And, leaving them, he, again, departed, and prayed a third time, the same word, saying again.", "weymouth": "So He left them, and went away once more and prayed a third time, again using the same words.", "darby": "And leaving them, he went away again and prayed the third time, saying the same thing.", "twenty": "So he left them, and went away again, and prayed a third time, again saying the same words.", "acv": "And when he left them, having gone away again, he prayed a third time, saying again the same statement.", "anderson": "And he left them, and went away again, and prayed the third time, saying the same thing.", "haweis": "And leaving them, he went away again, and prayed the third time, repeating the same sentence.", "noyes": "And leaving them, he went away again, and prayed the third time, saying again the same words.", "webster": "And he left them, and went away again, and prayed the third time, saying the same words.", "vulgate": "et relictis illis iterum abiit et oravit tertio eundem sermonem dicens;"}}, {"v": 45, "ref": "26:45", "o": "τότε ἔρχεται πρὸς τοὺς ⸀μαθητὰς καὶ λέγει αὐτοῖς· Καθεύδετε ⸀τὸ λοιπὸν καὶ ἀναπαύεσθε· ἰδοὺ ἤγγικεν ἡ ὥρα καὶ ὁ υἱὸς τοῦ ἀνθρώπου παραδίδοται εἰς χεῖρας ἁμαρτωλῶν.", "en": {"kjv": "Then cometh he to his disciples, and saith unto them, Sleep on now, and take your rest: behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.", "web": "Then he came to his disciples, and said to them, “Sleep on now, and take your rest. Behold, the hour is at hand, and the Son of Man is betrayed into the hands of sinners.", "bsb": "Then He returned to the disciples and said, “Are you still sleeping and resting? Look, the hour is near, and the Son of Man is betrayed into the hands of sinners.", "asv": "Then cometh he to the disciples, and saith unto them, Sleep on now, and take your rest: behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.", "ylt": "then cometh he unto his disciples, and saith to them, `Sleep on henceforth, and rest! lo, the hour hath come nigh, and the Son of Man is delivered up to the hands of sinners.", "tyndale": "Then came he to his disciples and sayd vnto them: Slepe hence forth and take youre reest. Take hede the houre is at honde and ye sonne of man shalbe betrayed into ye hondes of synners.", "dra": "Then he cometh to his disciples and said to them: Sleep ye now and take your rest. Behold the hour is at hand: and the Son of man shall be betrayed into the hands of sinners.", "bbe": "Then he comes to the disciples; and says to them, Go on sleeping now, and take your rest: for the hour is come, and the Son of man is given into the hands of evil men.", "geneva": "Then came he to his disciples, and said vnto them, Sleepe henceforth, and take your rest: behold, the houre is at hand, and the Sonne of man is giuen into the hands of sinners.", "wycliffe": "Thanne he cam to his disciplis, and seide to hem, Slepe ye now, and reste ye; loo! the our hath neiyed, and mannus sone schal be takun in to the hondis of synneris;", "rotherham": "Then, cometh he unto the disciples, and saith unto them,—Ye are sleeping what time remaineth, and taking your rest: Lo! the hour hath drawn near, and, the Son of Man, is being delivered up into the hands of sinners.", "weymouth": "Then He came to the disciples and said, \"Sleep on and rest. See, the moment is close at hand when the Son of Man is to be betrayed into the hands of sinful men.", "darby": "Then he comes to the disciples and says to them, Sleep on now and take your rest; behold, the hour has drawn nigh, and the Son of man is delivered up into the hands of sinners.", "twenty": "Then he came to the disciples, and said: “Sleep on now, and rest yourselves. Hark! my time is close at hand, and the Son of Man is being betrayed into the hands of wicked men.", "acv": "Then he comes to his disciples, and says to them, Sleep what remains, and take rest. Behold, the hour has come near, and the Son of man is betrayed into the hands of sinners.", "anderson": "Then he came to his disciples, and said to them: Bleep what time is left, and take your rest; behold, the hour draws near, and the Son of man is delivered into the hands of sinners.", "haweis": "Then cometh he to his disciples, and saith unto them, Do ye still sleep on, and repose yourselves? lo! the hour is at hand, and the Son of man is betrayed into the hands of sinners.", "noyes": "Then he cometh to the disciples, and saith to them, Sleep on, and take your rest! Lo! the hour is at hand, and the Son of man is delivered up into the hands of sinners.", "webster": "Then he cometh to his disciples, and saith to them, Sleep on now, and take [your] rest: behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.", "vulgate": "tunc venit ad discipulos suos et dicit illis dormite iam et requiescite ecce adpropinquavit hora et Filius hominis traditur in manus peccatorum;"}}, {"v": 46, "ref": "26:46", "o": "ἐγείρεσθε ἄγωμεν· ἰδοὺ ἤγγικεν ὁ παραδιδούς με.", "en": {"kjv": "Rise, let us be going: behold, he is at hand that doth betray me.", "web": "Arise, let’s be going. Behold, he who betrays me is at hand.”", "bsb": "Rise, let us go! See, My betrayer is approaching!”", "asv": "Arise, let us be going: behold, he is at hand that betrayeth me.", "ylt": "Rise, let us go; lo, he hath come nigh who is delivering me up.'", "tyndale": "Ryse let vs be goinge: beholde he is at honde yt shall betraye me.", "dra": "Rise: let us go. Behold he is at hand that will betray me.", "bbe": "Up, let us be going: see, he who gives me up is near.", "geneva": "Rise, let vs goe: beholde, hee is at hande that betraieth me.", "wycliffe": "rise ye, go we; loo! he that schal take me, is nyy.", "rotherham": "Arise! let us be going,—Lo! he that delivereth me up, hath drawn near.", "weymouth": "Rouse yourselves. Let us be going. My betrayer is close at hand.\"", "darby": "Arise, let us go; behold, he that delivers me up has drawn nigh.", "twenty": "Up, and let us be going. Look! my betrayer is close at hand.”", "acv": "Awake, we go. Behold, he who betrays me has come near.", "anderson": "Arise, let us go; behold, he that delivers me up is at hand.", "haweis": "Arise, let us go: lo! he that betrayeth me approaches.", "noyes": "Rise, let us be going; lo! he is at hand that delivereth me up.", "webster": "Rise, let us be going: behold, he is at hand that doth betray me.", "vulgate": "surgite eamus ecce adpropinquavit qui me tradit;"}}, {"v": 47, "ref": "26:47", "o": "Καὶ ἔτι αὐτοῦ λαλοῦντος ἰδοὺ Ἰούδας εἷς τῶν δώδεκα ἦλθεν καὶ μετ’ αὐτοῦ ὄχλος πολὺς μετὰ μαχαιρῶν καὶ ξύλων ἀπὸ τῶν ἀρχιερέων καὶ πρεσβυτέρων τοῦ λαοῦ.", "en": {"kjv": "And while he yet spake, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.", "web": "While he was still speaking, behold, Judas, one of the twelve, came, and with him a great multitude with swords and clubs, from the chief priest and elders of the people.", "bsb": "While Jesus was still speaking, Judas, one of the Twelve, arrived, accompanied by a large crowd armed with swords and clubs, sent from the chief priests and elders of the people.", "asv": "And while he yet spake, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.", "ylt": "And while he is yet speaking, lo, Judas, one of the twelve did come, and with him a great multitude, with swords and sticks, from the chief priests and elders of the people.", "tyndale": "Whyll he yet spake: lo Iudas one of ye xii. came and wt him a greate multitude wt sweardes and staves sent from the chefe prestes and elders of the people.", "dra": "As he yet spoke, behold Judas, one of the twelve, came, and with him a great multitude with swords and clubs, sent from the chief priests and the ancients of the people.", "bbe": "And while he was still talking, Judas, one of the twelve, came, and with him a band armed with swords and sticks, from the chief priests and those in authority over the people.", "geneva": "And while hee yet spake, loe Iudas, one of the twelue, came, and with him a great multitude with swordes and staues, from the high Priests and Elders of the people.", "wycliffe": "Yit the while he spak, lo! Judas, oon of the twelue, cam, and with hym a greet cumpeny, with swerdis and battis, sent fro the princis of prestis, and fro the eldre men of the puple.", "rotherham": "And, while, yet, he was speaking, lo! Judas, one of the twelve, came, and, with him, a large multitude, with swords and clubs, from the High-priests and Elders of the people.", "weymouth": "He had scarcely finished speaking when Judas came--one of the Twelve--accompanied by a great crowd of men armed with swords and bludgeons, sent by the High Priests and Elders of the People.", "darby": "And while he was yet speaking, behold, Judas, one of the twelve, came, and with him a great crowd with swords and sticks from the chief priests and elders of the people.", "twenty": "And, while he was still speaking, Judas, who was one of the Twelve, came in sight; and with him was a great crowd of people, with swords and clubs, sent from the Chief Priests and Councillors of the Nation.", "acv": "And while he was still speaking, lo, Judas, one of the twelve, came, and with him a great multitude with swords and clubs from the chief priest and elders of the people.", "anderson": "And while he was yet speaking, behold, Judas, one of the twelve, and with him a great multitude with swords and clubs, came from the chief priests and elders of the people.", "haweis": "And while he was yet speaking, behold, Judas one of the twelve came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.", "noyes": "And while he was yet speaking, lo! Judas, one of the twelve, came, and with him a great multitude with swords and clubs, from the chief priests and elders of the people.", "webster": "And while he was yet speaking, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staffs, from the chief priests and elders of the people.", "vulgate": "adhuc ipso loquente ecce Iudas unus de duodecim venit et cum eo turba multa cum gladiis et fustibus a principibus sacerdotum et senioribus populi;"}}, {"v": 48, "ref": "26:48", "o": "ὁ δὲ παραδιδοὺς αὐτὸν ἔδωκεν αὐτοῖς σημεῖον λέγων· Ὃν ἂν φιλήσω αὐτός ἐστιν· κρατήσατε αὐτόν.", "en": {"kjv": "Now he that betrayed him gave them a sign, saying, Whomsoever I shall kiss, that same is he: hold him fast.", "web": "Now he who betrayed him gave them a sign, saying, “Whoever I kiss, he is the one. Seize him.”", "bsb": "Now the betrayer had arranged a signal with them: “The One I kiss is the man; arrest Him.”", "asv": "Now he that betrayed him gave them a sign, saying, Whomsoever I shall kiss, that is he: take him.", "ylt": "And he who did deliver him up did give them a sign, saying, `Whomsoever I will kiss, it is he: lay hold on him;'", "tyndale": "And he that betrayed him had geven the a token sayinge: whosoever I kysse yt same is he ley hondes on him.", "dra": "And he that betrayed him gave them a sign, saying: Whomsoever I shall kiss, that is he. Hold him fast.", "bbe": "Now the false one had given them a sign saying, The one to whom I give a kiss, that is he: take him.", "geneva": "Now he that betraied him, had giuen them a token, saying, Whomesoeuer I shall kisse, that is he, laie holde on him.", "wycliffe": "And he that bitraiede hym, yaf to hem a tokene, and seide, Whom euer Y schal kisse, he it is; holde ye hym.", "rotherham": "And, he who was delivering him up, gave them a sign, saying—Whomsoever I shall kiss, he, it is,—secure him.", "weymouth": "Now the betrayer had agreed upon a sign with them, to direct them. He had said, \"The one whom I kiss is the man: lay hold of him.\"", "darby": "Now he that delivered him up had given them a sign, saying, Whomsoever I shall kiss, he it is: seize him.", "twenty": "Now the betrayer had arranged a signal with them. “The man whom I kiss,” he had said, “will be the one; arrest him.”", "acv": "Now the man who betrayed him gave them a sign, saying, Whomever I may kiss is he. Seize him.", "anderson": "He that delivered him up had given them a sign, saying: The one that I shall kiss is he; hold him fast.", "haweis": "Now he that betrayed him had given them a signal, saying, Whomsoever I shall kiss, that is he: seize him.", "noyes": "And his betrayer had given them a sign, saying, Whomever I shall kiss, he is the man; seize him.", "webster": "Now he that betrayed him, gave them a sign, saying, Whomsoever I shall kiss, that same is he; hold him fast.", "vulgate": "qui autem tradidit eum dedit illis signum dicens quemcumque osculatus fuero ipse est tenete eum;"}}, {"v": 49, "ref": "26:49", "o": "καὶ εὐθέως προσελθὼν τῷ Ἰησοῦ εἶπεν· Χαῖρε, ῥαββί· καὶ κατεφίλησεν αὐτόν.", "en": {"kjv": "And forthwith he came to Jesus, and said, Hail, master; and kissed him.", "web": "Immediately he came to Jesus, and said, “Hail, Rabbi!” and kissed him.", "bsb": "Going directly to Jesus, he said, “Greetings, Rabbi!” and kissed Him.", "asv": "And straightway he came to Jesus, and said, Hail, Rabbi; and kissed him.", "ylt": "and immediately, having come to Jesus, he said, `Hail, Rabbi,' and kissed him;", "tyndale": "And forth wt all he came to Iesus and sayde: hayle master and kyssed him.", "dra": "And forthwith coming to Jesus, he said: Hail, Rabbi. And he kissed him.", "bbe": "And straight away he came to Jesus and said, Master! and gave him a kiss.", "geneva": "And forthwith he came to Iesus, and sayd, God saue thee, Master, and kissed him.", "wycliffe": "And anoon he cam to Jhesu, and seid, Haile, maister;", "rotherham": "And, straightway, coming unto Jesus, he said—Joy to thee! Rabbi, and eagerly kissed him.", "weymouth": "So he went straight to Jesus and said, \"Peace to you, Rabbi!\" And he kissed Him eagerly.", "darby": "And immediately coming up to Jesus he said, Hail, Rabbi, and covered him with kisses.", "twenty": "So he went up to Jesus at once, and exclaimed: “Welcome, Rabbi!” and kissed him;", "acv": "And straightaway having come to Jesus, he said, Hail, Rabbi, and kissed him much.", "anderson": "And immediately he came to Jesus, and said: Hail, Rabbi! and kissed him.", "haweis": "And immediately approaching to Jesus, he said, Hail, master; and kissed him.", "noyes": "And immediately going up to Jesus, he said, Hail, Rabbi! and kissed him.", "webster": "And forthwith he came to Jesus, and said, Hail Master; and kissed him.", "vulgate": "et confestim accedens ad Iesum dixit have rabbi et osculatus est eum;"}}, {"v": 50, "ref": "26:50", "o": "ὁ δὲ Ἰησοῦς εἶπεν αὐτῷ· Ἑταῖρε, ἐφ’ ⸀ὃ πάρει. τότε προσελθόντες ἐπέβαλον τὰς χεῖρας ἐπὶ τὸν Ἰησοῦν καὶ ἐκράτησαν αὐτόν.", "en": {"kjv": "And Jesus said unto him, Friend, wherefore art thou come? Then came they, and laid hands on Jesus, and took him.", "web": "Jesus said to him, “Friend, why are you here?” Then they came and laid hands on Jesus, and took him.", "bsb": "“Friend,” Jesus replied, “do what you came for.” Then the men stepped forward, seized Jesus, and arrested Him.", "asv": "And Jesus said unto him, Friend, do that for which thou art come. Then they came and laid hands on Jesus, and took him.", "ylt": "and Jesus said to him, `Comrade, for what art thou present?' Then having come near, they laid hands on Jesus, and took hold on him.", "tyndale": "And Iesus sayde vnto him: frende wherfore arte thou come? Then came they and layed hondes on Iesus and toke him.", "dra": "And Jesus said to him: Friend, whereto art thou come? Then they came up and laid hands on Jesus and held him.", "bbe": "And Jesus said to him, Friend, do that for which you have come. Then they came and put hands on Jesus, and took him.", "geneva": "Then Iesus sayde vnto him, Friende, wherefore art thou come? Then came they, and laide hands on Iesus, and tooke him.", "wycliffe": "and he kisside hym. And Jhesus seide to hym, Freend, wherto art thou comun? Thanne thei camen niy, and leiden hoondis on Jhesu, and helden hym.", "rotherham": "But, Jesus, said unto him—Friend! wherefore art thou here? Then, coming forward, they thrust their hands upon Jesus, and secured him.", "weymouth": "\"Friend,\" said Jesus, \"carry out your intention.\" Then they came and laid their hands on Jesus and seized Him firmly.", "darby": "But Jesus said to him, [My] friend, for what purpose art thou come? Then coming up they laid hands upon Jesus and seized him.", "twenty": "on which Jesus said to him: “Friend, do what you have come for.” Thereupon the men went up, seized Jesus, and arrested him.", "acv": "And Jesus said to him, Friend, why are thou here? Then having come, they threw their hands on Jesus, and seized him.", "anderson": "Jesus said to him: Friend, for what purpose have you come? Then they came, and laid hands on Jesus, and held him fast.", "haweis": "Then spake Jesus to him, Friend, for what purpose art thou here? Then approaching they laid hands on Jesus, and seized him.", "noyes": "And Jesus said to him, Friend, for what hast thou come! Then they came and laid hands on Jesus, and seized him.", "webster": "And Jesus said to him, Friend, Why art thou come? Then they came, and laid hands on Jesus, and took him.", "vulgate": "dixitque illi Iesus amice ad quod venisti tunc accesserunt et manus iniecerunt in Iesum et tenuerunt eum;"}}, {"v": 51, "ref": "26:51", "o": "καὶ ἰδοὺ εἷς τῶν μετὰ Ἰησοῦ ἐκτείνας τὴν χεῖρα ἀπέσπασεν τὴν μάχαιραν αὐτοῦ καὶ πατάξας τὸν δοῦλον τοῦ ἀρχιερέως ἀφεῖλεν αὐτοῦ τὸ ὠτίον.", "en": {"kjv": "And, behold, one of them which were with Jesus stretched out his hand, and drew his sword, and struck a servant of the high priest’s, and smote off his ear.", "web": "Behold, one of those who were with Jesus stretched out his hand, and drew his sword, and struck the servant of the high priest, and struck off his ear.", "bsb": "At this, one of Jesus’ companions drew his sword and struck the servant of the high priest, cutting off his ear.", "asv": "And behold, one of them that were with Jesus stretched out his hand, and drew his sword, and smote the servant of the high priest, and struck off his ear.", "ylt": "And lo, one of those with Jesus, having stretched forth the hand, drew his sword, and having struck the servant of the chief priest, he took off his ear.", "tyndale": "And beholde one of them which were with Iesus stretched oute his honde and drue his swearde and stroke a servaunt of the hye preste and smote of his eare.", "dra": "And behold one of them that were with Jesus, stretching forth his hand, drew out his sword: and striking the servant of the high priest, cut off his ear.", "bbe": "And one of those who were with Jesus put out his hand, and took out his sword and gave the servant of the high priest a blow, cutting off his ear.", "geneva": "And behold, one of them which were with Iesus, stretched out his hand, and drewe his sworde, and strooke a seruaunt of the high Priest, and smote off his eare.", "wycliffe": "And lo! oon of hem that weren with Jhesu, streiyte out his hoond, and drouy out his swerd; and he smoot the seruaunt of the prince of prestis, and kitte of his ere.", "rotherham": "And lo! one of those with Jesus, stretching forth his hand, grasped his sword, and smiting the servant of the High-priest, cut off his ear.", "weymouth": "But one of those with Jesus drew his sword and struck the High Priest's servant, cutting off his ear.", "darby": "And behold, one of those with Jesus stretched out his hand and drew his sword, and smiting the bondman of the high priest took off his ear.", "twenty": "Suddenly one of those who were with Jesus stretched out his hand, and drew his sword, and striking the High Priest’s servant, cut off his ear.", "acv": "And behold, one of those with Jesus, having stretched out a hand, drew his sword, and when he struck the bondman of the high priest, he cut off his ear.", "anderson": "And behold, one of those who were with Jesus stretched out his hand, and drew his sword, and struck the servant of the chief priest, and cut off his ear.", "haweis": "And behold, one of those who were with Jesus stretching out his hand, drew his sword, and striking at a servant of the high-priest, cut off his ear.", "noyes": "And, lo! one of those who were with Jesus stretched out his hand, and drew his sword, and struck the servant of the high-priest, and cut off his ear.", "webster": "And behold, one of them, who were with Jesus, stretched out [his] hand, and drew his sword, and struck a servant of the high priest, and smote off his ear.", "vulgate": "et ecce unus ex his qui erant cum Iesu extendens manum exemit gladium suum et percutiens servum principis sacerdotum amputavit auriculam eius;"}}, {"v": 52, "ref": "26:52", "o": "τότε λέγει αὐτῷ ὁ Ἰησοῦς· Ἀπόστρεψον ⸂τὴν μάχαιράν σου⸃ εἰς τὸν τόπον αὐτῆς, πάντες γὰρ οἱ λαβόντες μάχαιραν ἐν μαχαίρῃ ⸀ἀπολοῦνται·", "en": {"kjv": "Then said Jesus unto him, Put up again thy sword into his place: for all they that take the sword shall perish with the sword.", "web": "Then Jesus said to him, “Put your sword back into its place, for all those who take the sword will die by the sword.", "bsb": "“Put your sword back in its place,” Jesus said to him. “For all who draw the sword will die by the sword.", "asv": "Then saith Jesus unto him, Put up again thy sword into its place: for all they that take the sword shall perish with the sword.", "ylt": "Then saith Jesus to him, `Turn back thy sword to its place; for all who did take the sword, by the sword shall perish;", "tyndale": "Then sayde Iesus vnto him: put vp thy swearde into his sheathe. For all that ley hond on ye swearde shall perisshe with ye swearde.", "dra": "Then Jesus saith to him: Put up again thy sword into its place: for all that take the sword shall perish with the sword.", "bbe": "Then says Jesus to him, Put up your sword again into its place: for all those who take the sword will come to death by the sword.", "geneva": "Then sayde Iesus vnto him, Put vp thy sworde into his place: for all that take the sworde, shall perish with the sworde.", "wycliffe": "Thanne Jhesus seide to hym, Turne thi swerd in to his place; for alle that taken swerd, schulen perische bi swerd.", "rotherham": "Then, Jesus saith unto him—Put back thy sword into its place, for, all they who take a sword, by a sword, shall perish.", "weymouth": "\"Put back your sword again,\" said Jesus, \"for all who draw the sword shall perish by the sword.", "darby": "Then saith Jesus to him, Return thy sword to its place; for all who take the sword shall perish by the sword.", "twenty": "“Sheathe your sword,” Jesus said, “for all who draw the sword will be put to the sword.", "acv": "Then Jesus says to him, Return thy sword into its place, for all those who take a sword will die by a sword.", "anderson": "Then Jesus said to him: Put back your sword into its place; for all that take the sword, shall perish by the sword.", "haweis": "Then saith Jesus unto him, Return thy sword into its sheath: for all who take the sword, shall perish by the sword.", "noyes": "Then Jesus saith to him, Put back thy sword into its place; for all they that take the sword will perish by the sword.", "webster": "Then said Jesus to him, Put up again thy sword into its place: for all they that take the sword, shall perish by the sword.", "vulgate": "tunc ait illi Iesus converte gladium tuum in locum suum omnes enim qui acceperint gladium gladio peribunt;"}}, {"v": 53, "ref": "26:53", "o": "ἢ δοκεῖς ὅτι οὐ ⸀δύναμαι παρακαλέσαι τὸν πατέρα μου, καὶ παραστήσει μοι ⸂ἄρτι πλείω⸃ δώδεκα λεγιῶνας ἀγγέλων;", "en": {"kjv": "Thinkest thou that I cannot now pray to my Father, and he shall presently give me more than twelve legions of angels?", "web": "Or do you think that I couldn’t ask my Father, and he would even now send me more than twelve legions of angels?", "bsb": "Are you not aware that I can call on My Father, and He will at once put at My disposal more than twelve legions of angels?", "asv": "Or thinkest thou that I cannot beseech my Father, and he shall even now send me more than twelve legions of angels?", "ylt": "dost thou think that I am not able now to call upon my Father, and He will place beside me more than twelve legions of messengers?", "tyndale": "Ether thinkest thou that I cannot now praye to my father and he shall geve me moo then .xii. legions of angelles?", "dra": "Thinkest thou that I cannot ask my Father, and he will give me presently more than twelve legions of angels?", "bbe": "Does it not seem possible to you that if I make request to my Father he will even now send me an army of angels?", "geneva": "Either thinkest thou, that I can not now pray to my Father, and he will giue me moe then twelue legions of Angels?", "wycliffe": "Whether gessist thou, that Y may not preie my fadir, and he schal yyue to me now mo than twelue legiouns of aungels?", "rotherham": "Or thinkest thou that I cannot call upon my Father, and he will set near me, even now, more than twelve legions of messengers?", "weymouth": "Or do you suppose I cannot entreat my Father and He would instantly send to my help more than twelve legions of angels?", "darby": "Or thinkest thou that I cannot now call upon my Father, and he will furnish me more than twelve legions of angels?", "twenty": "Do you think that I cannot ask my Father for help, when he would at once send to my aid more than twelve legions of angels?", "acv": "Or do thou think that I cannot now call my Father, and he will provide to me more than twelve legions of agents?", "anderson": "Do you think that I can not now call upon my Father, and he would cause more than twelve legions of angels to stand by me?", "haweis": "Thinkest thou, that I cannot now entreat my Father, and he will give me more than twelve legions of angels?", "noyes": "Dost thou think that I cannot pray to my Father, and he will now give me more than twelve legions of angels?", "webster": "Thinkest thou that I cannot now pray to my Father, and he will presently give me more than twelve legions of angels?", "vulgate": "an putas quia non possum rogare Patrem meum et exhibebit mihi modo plus quam duodecim legiones angelorum;"}}, {"v": 54, "ref": "26:54", "o": "πῶς οὖν πληρωθῶσιν αἱ γραφαὶ ὅτι οὕτως δεῖ γενέσθαι;", "en": {"kjv": "But how then shall the scriptures be fulfilled, that thus it must be?", "web": "How then would the Scriptures be fulfilled that it must be so?”", "bsb": "But how then would the Scriptures be fulfilled that say it must happen this way?”", "asv": "How then should the scriptures be fulfilled, that thus it must be?", "ylt": "how then may the Writings be fulfilled, that thus it behoveth to happen?'", "tyndale": "But how then shuld the scriptures be fulfylled: for so must it be.", "dra": "How then shall the scriptures be fulfilled, that so it must be done?", "bbe": "But how then would the Writings come true, which say that so it has to be?", "geneva": "Howe then shoulde the Scriptures bee fulfilled, which say, that it must be so?", "wycliffe": "Hou thanne schulen the scriptures be fulfilled? for so it bihoueth to be doon.", "rotherham": "How then should the Scriptures be fulfilled, that, thus, it must needs come to pass?", "weymouth": "In that case how are the Scriptures to be fulfilled which declare that thus it must be?\"", "darby": "How then should the scriptures be fulfilled that thus it must be?", "twenty": "But in that case how would the Scriptures be fulfilled, which say that this must be?”", "acv": "How then would the scriptures be fulfilled that it is necessary to happen this way?", "anderson": "But how then shall the scriptures be fulfilled, that thus it must be?", "haweis": "But how then would the scriptures be fulfilled, that thus it must be?", "noyes": "But how then shall the Scriptures be fulfilled, that thus it must be?", "webster": "But how then shall the scriptures be fulfilled, that thus it must be?", "vulgate": "quomodo ergo implebuntur scripturae quia sic oportet fieri;"}}, {"v": 55, "ref": "26:55", "o": "ἐν ἐκείνῃ τῇ ὥρᾳ εἶπεν ὁ Ἰησοῦς τοῖς ὄχλοις· Ὡς ἐπὶ λῃστὴν ἐξήλθατε μετὰ μαχαιρῶν καὶ ξύλων συλλαβεῖν με; καθ’ ⸀ἡμέραν ⸂ἐν τῷ ἱερῷ ἐκαθεζόμην διδάσκων⸃ καὶ οὐκ ἐκρατήσατέ με.", "en": {"kjv": "In that same hour said Jesus to the multitudes, Are ye come out as against a thief with swords and staves for to take me? I sat daily with you teaching in the temple, and ye laid no hold on me.", "web": "In that hour Jesus said to the multitudes, “Have you come out as against a robber with swords and clubs to seize me? I sat daily in the temple teaching, and you didn’t arrest me.", "bsb": "At that time Jesus said to the crowd, “Have you come out with swords and clubs to arrest Me as you would an outlaw? Every day I sat teaching in the temple courts, and you did not arrest Me.", "asv": "In that hour said Jesus to the multitudes, Are ye come out as against a robber with swords and staves to seize me? I sat daily in the temple teaching, and ye took me not.", "ylt": "In that hour said Jesus to the multitudes, `As against a robber ye did come forth, with swords and sticks, to take me! daily with you I was sitting teaching in the temple, and ye did not lay hold on me;", "tyndale": "The same tyme sayd Iesus to the multitude: ye be come out as it were vnto a thefe with sweardes and staves for to take me. I sate daylie teachinge in the temple amoge you and ye toke me not.", "dra": "In that same hour, Jesus said to the multitudes: You are come out, as it were to a robber, with swords and clubs to apprehend me. I sat daily with you, teaching in the temple: and you laid not hands on me.", "bbe": "In that hour Jesus said to the people, Have you come out as against a thief with swords and sticks to take me? I was teaching every day in the Temple and you took me not.", "geneva": "The same houre sayde Iesus to the multitude, Ye be come out as it were against a thiefe, with swordes and staues to take mee: I sate daily teaching in the Temple among you, and yee tooke me not.", "wycliffe": "In that our Jhesus seide to the puple, As to a theef ye han gon out, with swerdis and battis, to take me; dai bi dai Y sat among you, and tauyt in the temple, and ye helden me not.", "rotherham": "In that hour, said Jesus unto the multitudes: As against a robber, came ye forth, with swords and clubs, to arrest me? Daily in the temple, used I to sit teaching, and ye secured me not;", "weymouth": "Then said Jesus to the crowds, \"Have you come out as if to fight with a robber, with swords and bludgeons to apprehend me? Day after day I have been sitting teaching in the Temple, and you did not arrest me.", "darby": "In that hour Jesus said to the crowds, Are ye come out as against a robber with swords and sticks to take me? I sat daily [with you] teaching in the temple, and ye did not seize me.", "twenty": "Jesus at the same time said to the crowds: “Have you come out, as if after a robber, with swords and clubs, to take me? I have sat teaching day after day in the Temple Courts, and yet you did not arrest me.”", "acv": "In that hour Jesus said to the multitudes, Did ye come out as against a robber with swords and clubs to seize me? I sat daily with you teaching in the temple, and ye did not seize me.", "anderson": "At the same time Jesus said to the multitudes: Have you come out as against a robber, with swords and clubs, to take me? I sat daily with you in the temple and taught, and you did not take me.", "haweis": "In that hour said Jesus to the multitudes, Are ye come out as against a robber, with swords and staves to apprehend me? I sat daily with you teaching in the temple, and ye laid not hold upon me.", "noyes": "In that hour Jesus said to the multitudes, Ye have come out as against a robber, with swords and clubs to take me; I sat daily teaching in the temple, and ye did not lay hands on me.", "webster": "In that same hour said Jesus to the multitudes, Are ye come out as against a thief with swords and staffs to take me? I sat daily with you teaching in the temple, and ye laid no hold on me.", "vulgate": "in illa hora dixit Iesus turbis tamquam ad latronem existis cum gladiis et fustibus conprehendere me cotidie apud vos sedebam docens in templo et non me tenuistis;"}}, {"v": 56, "ref": "26:56", "o": "τοῦτο δὲ ὅλον γέγονεν ἵνα πληρωθῶσιν αἱ γραφαὶ τῶν προφητῶν. τότε οἱ μαθηταὶ πάντες ἀφέντες αὐτὸν ἔφυγον.", "en": {"kjv": "But all this was done, that the scriptures of the prophets might be fulfilled. Then all the disciples forsook him, and fled.", "web": "But all this has happened, that the Scriptures of the prophets might be fulfilled.” Then all the disciples left him, and fled.", "bsb": "But this has all happened so that the writings of the prophets would be fulfilled.” Then all the disciples deserted Him and fled.", "asv": "But all this is come to pass, that the scriptures of the prophets might be fulfilled. Then all the disciples left him, and fled.", "ylt": "but all this hath come to pass, that the Writings of the prophets may be fulfilled;' then all the disciples, having left him, fled.", "tyndale": "All this was done that the scriptures of the Prophetes myght be fulfilled.", "dra": "Now all this was done that the scriptures of the prophets might be fulfilled. Then the disciples, all leaving him, fled.", "bbe": "But all this has taken place so that the writings of the prophets might come true. Then all his disciples went from him in flight.", "geneva": "But all this was done, that the Scriptures of the Prophets might be fulfilled. Then all the disciples forsooke him, and fled.", "wycliffe": "But al this thing was don, that the scripturis of profetis schulden be fulfillid. Thanne alle the disciplis fledden, and leften hym.", "rotherham": "But, this, hath, wholly, come to pass, that, the Scriptures of the prophets, may be fulfilled. Then, the disciples, all forsaking him, fled.", "weymouth": "But all this has taken place in order that the writings of the Prophets may be fulfilled.\" At this point the disciples all left Him and fled.", "darby": "But all this is come to pass that the scriptures of the prophets may be fulfilled. Then all the disciples left him and fled.", "twenty": "The whole of this occurred in fulfilment of the Prophetic Scriptures. Then the disciples all forsook him and fled.", "acv": "But all this has come to pass, so that the scriptures of the prophets might be fulfilled. Then all the disciples fled, having forsook him.", "anderson": "All this was done, that the scriptures of the prophets might be fulfilled. Then all the disciples left him and fled.", "haweis": "But all this is come to pass, that the scriptures of the prophets should be fulfilled. Then all the disciples forsook him, and fled.", "noyes": "But all this hath been done, that the Scriptures of the prophets may be fulfilled. Then all the disciples forsook him, and fled.", "webster": "But all this was done, that the scriptures of the prophets might be fulfilled. Then all the disciples forsook him, and fled.", "vulgate": "hoc autem totum factum est ut implerentur scripturae prophetarum tunc discipuli omnes relicto eo fugerunt;"}}, {"v": 57, "ref": "26:57", "o": "Οἱ δὲ κρατήσαντες τὸν Ἰησοῦν ἀπήγαγον πρὸς Καϊάφαν τὸν ἀρχιερέα, ὅπου οἱ γραμματεῖς καὶ οἱ πρεσβύτεροι συνήχθησαν.", "en": {"kjv": "And they that had laid hold on Jesus led him away to Caiaphas the high priest, where the scribes and the elders were assembled.", "web": "Those who had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together.", "bsb": "Those who had arrested Jesus led Him away to the house of Caiaphas the high priest, where the scribes and elders had gathered.", "asv": "And they that had taken Jesus led him away to the house of Caiaphas the high priest, where the scribes and the elders were gathered together.", "ylt": "And those laying hold on Jesus led him away unto Caiaphas the chief priest, where the scribes and the elders were gathered together,", "tyndale": "Then all the disciples forsoke him and fleed. And they toke Iesus and leed him to Cayphas the hye preeste where the Scribes and the Elders where assembled.", "dra": "But they holding Jesus led him to Caiphas the high priest, where the scribes and the ancients were assembled.", "bbe": "And those who had made Jesus prisoner took him away to the house of Caiaphas, the high priest, where the scribes and those in authority over the people had come together.", "geneva": "And they tooke Iesus, and led him to Caiaphas the hie Priest, where the Scribes and the Elders were assembled.", "wycliffe": "And thei helden Jhesu, and ledden hym to Cayfas, the prince of prestis, where the scribis and the Farisees, and the eldre men of the puple weren comun togidere.", "rotherham": "And, they who secured Jesus, led him away unto Caiaphas the High-priest, where the Scribes and the Elders gathered themselves together.", "weymouth": "But the officers who had laid hold of Jesus led Him away to Caiaphas the High Priest, at whose house the Scribes and the Elders had assembled.", "darby": "Now they that had seized Jesus led [him] away to Caiaphas the high priest, where the scribes and the elders were assembled.", "twenty": "Those who had arrested Jesus took him to Caiaphas, the High Priest, where the Teachers of the Law and the Councillors had assembled.", "acv": "And those who seized Jesus led him away to Caiaphas the high priest where the scholars and the elders were assembled together.", "anderson": "And those who took Jesus led him away to Caiaphas the chief priest, where the scribes and elders had come together.", "haweis": "Then they who had apprehended Jesus, brought him to Caiaphas the high-priest, where the scribes and elders were assembled.", "noyes": "And they who seized Jesus led him away to Caiaphas the high-priest, where the scribes and the elders were assembled.", "webster": "And they that had laid hold on Jesus, led [him] away to Caiaphas the high priest, where the scribes and the elders were assembled.", "vulgate": "at illi tenentes Iesum duxerunt ad Caiaphan principem sacerdotum ubi scribae et seniores convenerant;"}}, {"v": 58, "ref": "26:58", "o": "ὁ δὲ Πέτρος ἠκολούθει αὐτῷ ἀπὸ μακρόθεν ἕως τῆς αὐλῆς τοῦ ἀρχιερέως, καὶ εἰσελθὼν ἔσω ἐκάθητο μετὰ τῶν ὑπηρετῶν ἰδεῖν τὸ τέλος.", "en": {"kjv": "But Peter followed him afar off unto the high priest’s palace, and went in, and sat with the servants, to see the end.", "web": "But Peter followed him from a distance, to the court of the high priest, and entered in and sat with the officers, to see the end.", "bsb": "But Peter followed Him at a distance, right up to the courtyard of the high priest. And he went in and sat down with the guards to see the outcome.", "asv": "But Peter followed him afar off, unto the court of the high priest, and entered in, and sat with the officers, to see the end.", "ylt": "and Peter was following him afar off, unto the court of the chief priest, and having gone in within, he was sitting with the officers, to see the end.", "tyndale": "And Peter folowed him a farre of vnto the hye prestes place: and went in and sate with the servauntes to se the ende.", "dra": "And Peter followed him afar off, even to the court of the high priest, And going in, he sat with the servants, that he might see the end.", "bbe": "But Peter went after him at a distance, to the house of the high priest, and went in and took his seat with the servants, to see the end.", "geneva": "And Peter followed him a farre off vnto the hie Priestes hall, and went in, and sate with the seruants to see the ende.", "wycliffe": "But Petir swede him afer, in to the halle of the prince of prestis; and he wente in, and sat with the seruauntis, to se the ende.", "rotherham": "Now, Peter, was following him afar off, unto the court of the High-priest,—and, entering within, was sitting with the attendants, to see the end.", "weymouth": "And Peter kept following Him at a distance, till he came even to the court of the High Priest's palace, where he entered and sat down among the officers to see the issue.", "darby": "And Peter followed him at a distance, even to the palace of the high priest, and entering in sat with the officers to see the end.", "twenty": "Peter followed him at a distance as far as the courtyard of the offices, to see the end.", "acv": "But Peter followed him from afar, as far as the courtyard of the high priest. And having entered inside, he sat with the subordinates to see the outcome.", "anderson": "But Peter followed him, at a distance, to the palace of the chief priest, and went in and sat with the attendants, to see the end.", "haweis": "But Peter followed him at a great distance unto the palace of the high-priest, and entering in, sat down with the servants, to see the issue.", "noyes": "But Peter followed him at a distance, as far as to the court of the high-priest’s palace, and went in, and sat with the officers to see the end.", "webster": "But Peter followed him at a distance, to the high priest's palace, and went in, and sat with the servants to see the end.", "vulgate": "Petrus autem sequebatur eum a longe usque in atrium principis sacerdotum et ingressus intro sedebat cum ministris ut videret finem;"}}, {"v": 59, "ref": "26:59", "o": "οἱ δὲ ἀρχιερεῖς ⸀καὶ τὸ συνέδριον ὅλον ἐζήτουν ψευδομαρτυρίαν κατὰ τοῦ Ἰησοῦ ὅπως ⸂αὐτὸν θανατώσωσιν⸃,", "en": {"kjv": "Now the chief priests, and elders, and all the council, sought false witness against Jesus, to put him to death;", "web": "Now the chief priests, the elders, and the whole council sought false testimony against Jesus, that they might put him to death;", "bsb": "Now the chief priests and the whole Sanhedrin were seeking false testimony against Jesus in order to put Him to death.", "asv": "Now the chief priests and the whole council sought false witness against Jesus, that they might put him to death;", "ylt": "And the chief priests, and the elders, and all the council, were seeking false witness against Jesus, that they might put him to death,", "tyndale": "The chefe prestes and the elders and all the counsell sought false witnes agenste Iesus for to put him to deeth", "dra": "And the chief priests and the whole council sought false witness against Jesus, that they might put him to death.", "bbe": "Now the chief priests and all the Sanhedrin were looking for false witness against Jesus, so that they might put him to death;", "geneva": "Nowe the chiefe Priestes and the Elders, and all the whole councill sought false witnesse against Iesus, to put him to death.", "wycliffe": "And the prince of prestis, and al the counsel souyten fals witnessing ayens Jhesu, that thei schulden take hym to deeth;", "rotherham": "Now, the High-priests and all the High-council, were seeking false-witness against Jesus, that they might, put him to death;", "weymouth": "Meanwhile the High Priests and the whole Sanhedrin were seeking false testimony against Jesus in order to put Him to death;", "darby": "And the chief priests and the elders and the whole sanhedrim sought false witness against Jesus, so that they might put him to death.", "twenty": "Meanwhile the Chief Priests and the whole of the High Council were trying to get such false evidence against Jesus, as would warrant putting him to death,", "acv": "Now the chief priests and the elders and the whole council sought false testimony against Jesus, so that they might put him to death,", "anderson": "And the chief priests and the elders, and the whole Sanhedrin, sought false testimony against Jesus, that they might put him to death,", "haweis": "Now the chief priests and elders and the whole sanhedrim, sought false witness against Jesus, that they might put him to death;", "noyes": "And the chief priests and the whole council sought false witness against Jesus, to put him to death;", "webster": "Now the chief priests and elders, and all the council, sought false testimony against Jesus, to put him to death;", "vulgate": "principes autem sacerdotum et omne concilium quaerebant falsum testimonium contra Iesum ut eum morti traderent;"}}, {"v": 60, "ref": "26:60", "o": "καὶ οὐχ εὗρον ⸂πολλῶν προσελθόντων ψευδομαρτύρων. ὕστερον δὲ προσελθόντες δύο⸃", "en": {"kjv": "But found none: yea, though many false witnesses came, yet found they none. At the last came two false witnesses,", "web": "and they found none. Even though many false witnesses came forward, they found none. But at last two false witnesses came forward,", "bsb": "But they did not find any, though many false witnesses came forward. Finally two came forward", "asv": "and they found it not, though many false witnesses came. But afterward came two,", "ylt": "and they did not find; and many false witnesses having come near, they did not find; and at last two false witnesses having come near,", "tyndale": "but founde none: in somoche that when many false witnesses cam yet founde they none. At the last came two false witnesses", "dra": "And they found not, whereas many false witnesses had come in. And last of all there came two false witnesses:", "bbe": "And they were not able to get it, though a number of false witnesses came.", "geneva": "But they founde none, and though many false witnesses came, yet founde they none: but at the last came two false witnesses,", "wycliffe": "and thei founden not, whanne manye false witnessis weren comun. But at the laste, twei false witnessis camen,", "rotherham": "and found not any, though many came forward as false-witnesses. At length, however, there came forward, two,", "weymouth": "but they could find none, although many false witnesses came forward. At length there came two", "darby": "And they found none, though many false witnesses came forward. But at the last two false witnesses came forward", "twenty": "but they did not find any, although many came forward with false evidence. Later on, however, two men came forward and said:", "acv": "and they did not find it. And although many false witnesses came, they did not find it.", "anderson": "and found none. Though many false witnesses came, yet they found none. At last two false witnesses came,", "haweis": "and found none: and though many false witnesses came, they found it not sufficient. But at the last two false witnesses stepping forth,", "noyes": "and they found none, though many false witnesses came forward. But at last came two,", "webster": "But found none: and, though many false witnesses came, [yet] found they none. At the last came two false witnesses,", "vulgate": "et non invenerunt cum multi falsi testes accessissent novissime autem venerunt duo falsi testes;"}}, {"v": 61, "ref": "26:61", "o": "εἶπαν· Οὗτος ἔφη· Δύναμαι καταλῦσαι τὸν ναὸν τοῦ θεοῦ καὶ διὰ τριῶν ἡμερῶν ⸀οἰκοδομῆσαι.", "en": {"kjv": "And said, This fellow said, I am able to destroy the temple of God, and to build it in three days.", "web": "and said, “This man said, ‘I am able to destroy the temple of God, and to build it in three days.’”", "bsb": "and declared, “This man said, ‘I am able to destroy the temple of God and rebuild it in three days.’”", "asv": "and said, This man said, I am able to destroy the temple of God, and to build it in three days.", "ylt": "said, `This one said, I am able to throw down the sanctuary of God, and after three days to build it.'", "tyndale": "and sayd: This felowe sayde: I can distroye the temple of God and bylde it agayne in .iii. dayes.", "dra": "And they said: This man said, I am able to destroy the temple of God and after three days to rebuild it.", "bbe": "But later there came two who said, This man said, I am able to give the Temple of God to destruction, and to put it up again in three days.", "geneva": "And saide, This man saide, I can destroie the Temple of God, and build it in three daies.", "wycliffe": "and seiden, `This seide, Y may distruye the temple of God, and after the thridde dai bilde it ayen.", "rotherham": "and said: This, man said—I am able to pull down the shrine of God, and, in three days, to, build, it.", "weymouth": "who testified, \"This man said, `I am able to pull down the Sanctuary of God and three days afterwards to build a new one.'\"", "darby": "and said, He said, I am able to destroy the temple ofGod, and in three days build it.", "twenty": "“This man said ‘I am able to destroy the Temple of God, and to build it in three days.’”", "acv": "But finally two false witnesses having come, they said, This man said, I am able to destroy the temple of God, and to build it by three days.", "anderson": "and said: This man said, I am able to destroy the temple of God, and to build it in three days.", "haweis": "said, This fellow said, I am able to pull down the temple of God, and to build it up in three days.", "noyes": "and said, This man affirmed, I am able to destroy the temple of God, and to build it within three days.", "webster": "And said, This [man] said, I am able to destroy the temple of God, and to build it in three days.", "vulgate": "et dixerunt hic dixit possum destruere templum Dei et post triduum aedificare illud;"}}, {"v": 62, "ref": "26:62", "o": "καὶ ἀναστὰς ὁ ἀρχιερεὺς εἶπεν αὐτῷ· Οὐδὲν ἀποκρίνῃ; τί οὗτοί σου καταμαρτυροῦσιν;", "en": {"kjv": "And the high priest arose, and said unto him, Answerest thou nothing? what is it which these witness against thee?", "web": "The high priest stood up, and said to him, “Have you no answer? What is this that these testify against you?”", "bsb": "So the high priest stood up and asked Him, “Have You no answer? What are these men testifying against You?”", "asv": "And the high priest stood up, and said unto him, Answerest thou nothing? what is it which these witness against thee?", "ylt": "And the chief priest having stood up, said to him, `Nothing thou dost answer! what do these witness against thee?", "tyndale": "And the chefe preste arose and sayde to him: answerest thou nothinge? How is it yt these beare witnes ageynst the?", "dra": "And the high priest rising up, said to him: Answerest thou nothing to the things which these witness against thee?", "bbe": "And the high priest got up and said to him, Have you no answer? what is it which these say against you?", "geneva": "Then the chiefe Priest arose, and sayde to him, Answerest thou nothing? What is the matter that these men witnesse against thee?", "wycliffe": "And the prince of prestis roos, and seide to hym, Answerist thou no thing to tho thingis, that these witnessen ayens thee?", "rotherham": "And the High-priest, arising, said unto him—Nothing, answerest thou? What are these, against thee bearing witness?", "weymouth": "Then the High Priest stood up and asked Him, \"Have you no answer to make? What is it these men are saying in evidence against you?\"", "darby": "And the high priest standing up said to him, Answerest thou nothing? What do these witness against thee?", "twenty": "Then the High Priest stood up, and said to Jesus: “Have you no answer? What is this evidence which these men are giving against you?”", "acv": "And the high priest having stood up, he said to him, Answer thou nothing? What do these testify against thee?", "anderson": "And the chief priest arose, and said to him: Do you make no answer? What do these testify against you?", "haweis": "And the high-priest rising up, said to him, Answerest thou nothing? what do these men witness against thee?", "noyes": "And the high-priest arose, and said to him, Dost thou make no answer to what these men testify against thee?", "webster": "And the high priest arose, and said to him, Answerest thou nothing, what [is it which] these testify against thee?", "vulgate": "et surgens princeps sacerdotum ait illi nihil respondes ad ea quae isti adversum te testificantur;"}}, {"v": 63, "ref": "26:63", "o": "ὁ δὲ Ἰησοῦς ἐσιώπα. ⸀καὶ ὁ ἀρχιερεὺς εἶπεν αὐτῷ· Ἐξορκίζω σε κατὰ τοῦ θεοῦ τοῦ ζῶντος ἵνα ἡμῖν εἴπῃς εἰ σὺ εἶ ὁ χριστὸς ὁ υἱὸς τοῦ θεοῦ.", "en": {"kjv": "But Jesus held his peace. And the high priest answered and said unto him, I adjure thee by the living God, that thou tell us whether thou be the Christ, the Son of God.", "web": "But Jesus held his peace. The high priest answered him, “I adjure you by the living God, that you tell us whether you are the Christ, the Son of God.”", "bsb": "But Jesus remained silent. Then the high priest said to Him, “I charge You under oath by the living God: Tell us if You are the Christ, the Son of God.”", "asv": "But Jesus held his peace. And the high priest said unto him, I adjure thee by the living God, that thou tell us whether thou art the Christ, the Son of God.", "ylt": "and Jesus was silent. And the chief priest answering said to him, `I adjure thee, by the living God, that thou mayest say to us, if thou art the Christ--the Son of God.'", "tyndale": "But Iesus helde his peace: And the chefe Preeste answered and sayd to him: I charge the in the name of the lyvinge God that thou tell vs whether thou be Christ the sonne of God.", "dra": "But Jesus held his peace. And the high priest said to him: I adjure thee by the living God, that thou tell us if thou be the Christ the Son of God.", "bbe": "But Jesus said not a word. And the high priest said to him, I put you on oath, by the living God, that you will say to us if you are the Christ, the Son of God.", "geneva": "But Iesus helde his peace. Then the chiefe Priest answered, and saide to him, I charge thee sweare vnto vs by the liuing God, to tell vs, If thou be that Christ the Sonne of God, or no.", "wycliffe": "But Jhesus was stille. And the prince of prestis seide to hym, Y coniure thee bi lyuynge God, that thou seie to vs, if thou art Crist, the sone of God.", "rotherham": "But, Jesus, was silent. And, the High-priest, said unto him: I put thee on oath, by the Living God, that, to us, thou say—Whether, thou, art the Christ, the Son of God.", "weymouth": "Jesus however remained silent. Again the High Priest addressed Him. \"In the name of the ever-living God,\" he said, \"I now put you on your oath. Tell us whether you are the Christ, the Son of God.\"", "darby": "But Jesus was silent. And the high priest answering said to him, I adjure thee by the livingGod that thou tell us if thou art the Christ the Son ofGod.", "twenty": "But Jesus remained silent. On this the High Priest said to him: “I adjure you, by the Living God, to tell us whether you are the Christ, the Son of God.”", "acv": "But Jesus was silent. And having responded, the high priest said to him, I adjure thee by the living God, that thou tell us if thou are the Christ, the Son of God.", "anderson": "But Jesus remained silent. And the chief priest answered and said to him: I adjure you, by the living God, that you tell us whether you are the Christ, the Son of God?", "haweis": "But Jesus was silent. And the high-priest addressing him, said, I adjure thee, by the living God, that thou tell us, if thou art the Messiah, the Son of God.", "noyes": "But Jesus was silent. And the high-priest answering said to him, I adjure thee by the living God, that thou tell us whether thou art the Christ, the Son of God.", "webster": "But Jesus held his peace. And the high priest answered and said to him, I adjure thee by the living God, that thou tell us whether thou art the Christ the Son of God.", "vulgate": "Iesus autem tacebat et princeps sacerdotum ait illi adiuro te per Deum vivum ut dicas nobis si tu es Christus Filius Dei;"}}, {"v": 64, "ref": "26:64", "o": "λέγει αὐτῷ ὁ Ἰησοῦς· Σὺ εἶπας· πλὴν λέγω ὑμῖν, ἀπ’ ἄρτι ὄψεσθε τὸν υἱὸν τοῦ ἀνθρώπου καθήμενον ἐκ δεξιῶν τῆς δυνάμεως καὶ ἐρχόμενον ἐπὶ τῶν νεφελῶν τοῦ οὐρανοῦ.", "en": {"kjv": "Jesus saith unto him, Thou hast said: nevertheless I say unto you, Hereafter shall ye see the Son of man sitting on the right hand of power, and coming in the clouds of heaven.", "web": "Jesus said to him, “You have said it. Nevertheless, I tell you, after this you will see the Son of Man sitting at the right hand of Power, and coming on the clouds of the sky.”", "bsb": "“You have said it yourself,” Jesus answered. “But I say to all of you, from now on you will see the Son of Man sitting at the right hand of Power and coming on the clouds of heaven.”", "asv": "Jesus saith unto him, Thou hast said: nevertheless I say unto you, Henceforth ye shall see the Son of man sitting at the right hand of Power, and coming on the clouds of heaven.", "ylt": "Jesus saith to him, `Thou hast said; nevertheless I say to you, hereafter ye shall see the Son of Man sitting on the right hand of the power, and coming upon the clouds, of the heaven.'", "tyndale": "Iesus sayd to him: thou haste sayd. Neverthelesse I saye vnto you hereafter shall ye se the sonne of ma syttinge on the right honde of power and come in the clowddes of the skye.", "dra": "Jesus saith to him: Thou hast said it. Nevertheless I say to you, hereafter you shall see the Son of man sitting on the right hand of the power of God and coming in the clouds of heaven.", "bbe": "Jesus says to him, You say so: but I say to you, From now you will see the Son of man seated at the right hand of power, and coming on the clouds of heaven.", "geneva": "Iesus saide to him, Thou hast saide it: neuerthelesse I say vnto you, hereafter shall ye see the Sonne of man, sitting at the right hande of the power of God, and come in the cloudes of the heauen.", "wycliffe": "Jhesus seide to him, Thou hast seid; netheles Y seie to you, `fro hennus forth ye schulen se mannus sone sittinge at the riythalf of the vertu of God, and comynge in the cloudis of heuene.", "rotherham": "Jesus saith unto him: Thou, hast said; Moreover, I say unto you—Hereafter, ye will see the Son of Man, sitting on the right hand of power, and coming upon the clouds of heaven.", "weymouth": "\"I am He,\" replied Jesus. \"But I tell you that, later on, you will see the Son of Man sitting at the right hand of Omnipotence, and coming on the clouds of the sky.\"", "darby": "Jesus says to him, Thou hast said. Moreover, I say to you, From henceforth ye shall see the Son of man sitting at the right hand of power, and coming on the clouds of heaven.", "twenty": "“It is true,” Jesus answered; “Moreover I tell you all that hereafter you shall ‘see the Son of Man sitting on the right hand of the Almighty, and coming on the clouds of the heavens.’”", "acv": "Jesus says to him, Thou have said. Nevertheless I say to you, Henceforth ye will see the Son of man sitting at the right hand of Power, and coming in the clouds of the sky.", "anderson": "Jesus said to him: You have said. Moreover, I say to you, Hereafter you shall see the Son of man sitting on the right hand of the Almighty, and coming upon the clouds of heaven.", "haweis": "Jesus saith to him, Thou hast spoken the fact. Moreover I tell you, hereafter ye shall see the Son of man sitting at the right hand of power, and coming in the clouds of heaven.", "noyes": "Jesus saith to him, I am. Moreover I say to you, Henceforth ye will see the Son of man sitting on the right hand of Power, and coming on the clouds of heaven.", "webster": "Jesus saith to him, Thou hast said: nevertheless I say to you, Hereafter shall ye see the Son of man sitting on the right hand of power, and coming in the clouds of heaven.", "vulgate": "dicit illi Iesus tu dixisti verumtamen dico vobis amodo videbitis Filium hominis sedentem a dextris virtutis et venientem in nubibus caeli;"}}, {"v": 65, "ref": "26:65", "o": "τότε ὁ ἀρχιερεὺς διέρρηξεν τὰ ἱμάτια αὐτοῦ ⸀λέγων· Ἐβλασφήμησεν· τί ἔτι χρείαν ἔχομεν μαρτύρων; ἴδε νῦν ἠκούσατε τὴν ⸀βλασφημίαν·", "en": {"kjv": "Then the high priest rent his clothes, saying, He hath spoken blasphemy; what further need have we of witnesses? behold, now ye have heard his blasphemy.", "web": "Then the high priest tore his clothing, saying, “He has spoken blasphemy! Why do we need any more witnesses? Behold, now you have heard his blasphemy.", "bsb": "At this, the high priest tore his clothes and declared, “He has blasphemed! Why do we need any more witnesses? Look, now you have heard the blasphemy.", "asv": "Then the high priest rent his garments, saying, He hath spoken blasphemy: what further need have we of witnesses? behold, now ye have heard the blasphemy:", "ylt": "Then the chief priest rent his garments, saying, --`He hath spoken evil; what need have we yet of witnesses? lo, now ye heard his evil speaking;", "tyndale": "Then the hye preste rent his clothes sayinge: He hath blasphemed: what nede we of eny moo witnesses? Behold now ye have hearde his blasphemy:", "dra": "Then the high priest rent his garments, saying: He hath blasphemed: What further need have we of witnesses? Behold, now you have heard the blasphemy.", "bbe": "Then the high priest, violently parting his robes, said, He has said evil against God: what more need have we of witnesses? for now his words against God have come to your ears:", "geneva": "Then the hie Priest rent his clothes, saying, Hee hath blasphemed, what haue wee any more neede of witnesses? beholde: nowe yee haue heard his blasphemie.", "wycliffe": "Thanne the prince of prestis to-rente his clothis, and seide, He hath blasfemed; what yit han we nede to witnessis? lo! now ye han herd blasfemye; what semeth to you?", "rotherham": "Then, the High-priest rent asunder his garments, saying—He hath spoken profanely! What further need have we, of witnesses? Lo! now, ye have heard the profanity!", "weymouth": "Then the High Priest tore his robes and exclaimed, \"Impious language! What further need have we of witnesses! See, you have now heard the impiety.", "darby": "Then the high priest rent his clothes, saying, He has blasphemed: what need have we any more of witnesses? behold, now ye have heard the blasphemy.", "twenty": "Then the High Priest tore his robes. “This is blasphemy!” he exclaimed. “Why do we want any more witnesses? You have just heard his blasphemy!", "acv": "Then the high priest tore his garments, saying, He has blasphemed. What further need have we of witnesses? Behold, now ye heard his blasphemy.", "anderson": "Then the chief priest rent his clothes, and said: He has spoken impiously; what further need have we of witnesses? See now, you have heard his impious words:", "haweis": "Then the high-priest rent his garments, saying, he hath blasphemed: what farther need have we of witnesses? lo! now ye have heard his blasphemy:", "noyes": "Then the high-priest rent his garments, saying, He hath spoken blasphemy; what further need have we of witnesses? See! ye have now heard the blasphemy.", "webster": "Then the high priest rent his clothes, saying, He hath spoken blasphemy; what further need have we of witnesses? behold, now ye have heard his blasphemy.", "vulgate": "tunc princeps sacerdotum scidit vestimenta sua dicens blasphemavit quid adhuc egemus testibus ecce nunc audistis blasphemiam;"}}, {"v": 66, "ref": "26:66", "o": "τί ὑμῖν δοκεῖ; οἱ δὲ ἀποκριθέντες εἶπαν· Ἔνοχος θανάτου ἐστίν.", "en": {"kjv": "What think ye? They answered and said, He is guilty of death.", "web": "What do you think?” They answered, “He is worthy of death!”", "bsb": "What do you think?” “He deserves to die,” they answered.", "asv": "what think ye? They answered and said, He is worthy of death.", "ylt": "what think ye?' and they answering said, `He is worthy of death.'", "tyndale": "what thinke ye? They answered and sayd: he his worthy to dye.", "dra": "What think you? But they answering, said: He is guilty of death.", "bbe": "What is your opinion? They made answer and said, It is right for him to be put to death.", "geneva": "What thinke yee? They answered, and said, He is guiltie of death.", "wycliffe": "And thei answeriden, and seiden, He is gilti of deeth.", "rotherham": "How, to you, doth it seem? And, they, answering, said: Guilty of death, he is.", "weymouth": "What is your verdict?\" \"He deserves to die,\" they replied.", "darby": "What think ye? And they answering said, He is liable to the penalty of death.", "twenty": "What is your decision?” They answered: “He deserves death.”", "acv": "What does it seem to you? Having answered, they said, He is deserving of death.", "anderson": "What think you? They answered and said: He is a subject for death.", "haweis": "what think ye? They answered and said, He is deserving of death.", "noyes": "What think ye? They answered and said, He should be punished with death.", "webster": "What think ye? They answered and said, He is guilty of death.", "vulgate": "quid vobis videtur at illi respondentes dixerunt reus est mortis;"}}, {"v": 67, "ref": "26:67", "o": "τότε ἐνέπτυσαν εἰς τὸ πρόσωπον αὐτοῦ καὶ ἐκολάφισαν αὐτόν, οἱ δὲ ἐράπισαν", "en": {"kjv": "Then did they spit in his face, and buffeted him; and others smote him with the palms of their hands,", "web": "Then they spit in his face and beat him with their fists, and some slapped him,", "bsb": "Then they spit in His face and struck Him. Others slapped Him", "asv": "Then did they spit in his face and buffet him: and some smote him with the palms of their hands,", "ylt": "Then did they spit in his face and buffet him, and others did slap,", "tyndale": "Then spat they in his face and boffeted him with fistes. And other smote him with the palme af their hondes", "dra": "Then did they spit in his face and buffeted him. And others struck his face with the palms of their hands,", "bbe": "Then they put shame on him, and were cruel to him: and some gave him blows, saying,", "geneva": "Then spet they in his face, and buffeted him, and other smote him with roddes,", "wycliffe": "Thanne thei speten `in to his face, and smyten hym with buffatis; and othere yauen strokis with the pawme of her hondis in his face,", "rotherham": "Then, spat they into his face, and buffeted him; and, others, struck him smartly,", "weymouth": "Then they spat in His face, and struck Him--some with the fist, some with the open hand--", "darby": "Then they spit in his face, and buffeted him, and some struck him with the palms of their hand,", "twenty": "Then they spat in his face, and struck him, while others dealt blows at him, saying as they did so:", "acv": "Then they spat in his face and struck him with a fist. And some slapped him,", "anderson": "Then did they spit in his face, and strike him with their fists; some struck him with the open hand,", "haweis": "Then they spit in his face, and buffeted him about; and some slapt his face with their hands,", "noyes": "Then they spit in his face, and buffeted him; and some smote him with the palms of their hands,", "webster": "Then they spit in his face, and buffetted him; and others smote [him] with the palms of their hands,", "vulgate": "tunc expuerunt in faciem eius et colaphis eum ceciderunt alii autem palmas in faciem ei dederunt;"}}, {"v": 68, "ref": "26:68", "o": "λέγοντες· Προφήτευσον ἡμῖν, χριστέ, τίς ἐστιν ὁ παίσας σε;", "en": {"kjv": "Saying, Prophesy unto us, thou Christ, Who is he that smote thee?", "web": "saying, “Prophesy to us, you Christ! Who hit you?”", "bsb": "and said, “Prophesy to us, Christ! Who hit You?”", "asv": "saying, Prophesy unto us, thou Christ: who is he that struck thee?", "ylt": "saying, `Declare to us, O Christ, who he is that struck thee?'", "tyndale": "on ye face sayinge: tell vs thou Christ who is he that smote the?", "dra": "Saying: Prophesy unto us, O Christ. Who is he that struck thee?", "bbe": "Be a prophet, O Christ, and say who gave you a blow!", "geneva": "Saying, Prophecie to vs, O Christ, Who is he that smote thee?", "wycliffe": "and seide, Thou Crist, arede to vs, who is he that smoot thee?", "rotherham": "saying—Prophesy unto us, O Christ! Who is he that struck thee?", "weymouth": "while they taunted Him, saying, \"Christ, prove yourself a Prophet by telling us who it was that struck you.\"", "darby": "saying, Prophesy to us, Christ, Who is it who struck thee?", "twenty": "“Now play the Prophet for us, you Christ! Who was it that struck you?”", "acv": "saying, Prophesy to us, thou Christ. Who is he who struck thee?", "anderson": "and said: Give a response to us, Christ: Who is he that struck you?", "haweis": "saying, Prophesy to us, you Messiah, who it is that struck thee!", "noyes": "saying, Prophesy to us, O Messiah! who it was that struck thee.", "webster": "Saying, Prophesy to us, thou Christ, Who is he that smote thee?", "vulgate": "dicentes prophetiza nobis Christe quis est qui te percussit;"}}, {"v": 69, "ref": "26:69", "o": "Ὁ δὲ Πέτρος ⸂ἐκάθητο ἔξω⸃ ἐν τῇ αὐλῇ· καὶ προσῆλθεν αὐτῷ μία παιδίσκη λέγουσα· Καὶ σὺ ἦσθα μετὰ Ἰησοῦ τοῦ Γαλιλαίου·", "en": {"kjv": "Now Peter sat without in the palace: and a damsel came unto him, saying, Thou also wast with Jesus of Galilee.", "web": "Now Peter was sitting outside in the court, and a maid came to him, saying, “You were also with Jesus, the Galilean!”", "bsb": "Meanwhile, Peter was sitting out in the courtyard, and a servant girl came up to him. “You also were with Jesus the Galilean,” she said.", "asv": "Now Peter was sitting without in the court: and a maid came unto him, saying, Thou also wast with Jesus the Galilæan.", "ylt": "And Peter without was sitting in the court, and there came near to him a certain maid, saying, `And thou wast with Jesus of Galilee!'", "tyndale": "Peter sate with out in the palice. And a damsell came to him sayinge: Thou also waste wt Iesus of Galilee:", "dra": "But Peter sat without in the court. And there came to him a servant maid, saying: Thou also wast with Jesus the Galilean.", "bbe": "Now Peter was seated in the open square outside the house: and a servant-girl came to him, saying, You were with Jesus the Galilaean.", "geneva": "Peter sate without in the hall, and a maide came to him, saying, Thou also wast with Iesus of Galile:", "wycliffe": "And Petir sat with outen in the halle; and a damysel cam to hym, and seide, Thou were with Jhesu of Galilee.", "rotherham": "Now, Peter, was sitting without, in the court; and there came unto him a certain female servant, saying—Thou also, wast with Jesus, the Galilaean.", "weymouth": "Peter meanwhile was sitting outside in the court of the palace, when one of the maidservants came over to him and said, \"You too were with Jesus the Galilaean.\"", "darby": "But Peter sat without in the palace-court; and a maid came to him, saying, And thou wast with Jesus the Galilaean.", "twenty": "Peter, meanwhile, was sitting outside in the courtyard; and a maidservant came up to him, and exclaimed: “Why, you were with Jesus the Galilean!”", "acv": "Now Peter was sitting outside in the courtyard, and one servant girl came to him, saying, Thou also were with Jesus the Galilean.", "anderson": "But Peter was sitting without in the court; and a maid-servant came to him, and said: You also were with Jesus of Galilee.", "haweis": "Now Peter sat without in the hall: and there came to him a single maid-servant, saying, Thou also wert with Jesus of Galilee.", "noyes": "Now Peter was sitting outside in the court. And a maid-servant came to him, saying, Thou also wast with Jesus the Galilaean.", "webster": "Now Peter sat without in the palace: and a damsel came to him, saying, Thou also wast with Jesus of Galilee.", "vulgate": "Petrus vero sedebat foris in atrio et accessit ad eum una ancilla dicens et tu cum Iesu Galilaeo eras;"}}, {"v": 70, "ref": "26:70", "o": "ὁ δὲ ἠρνήσατο ⸀ἔμπροσθεν πάντων λέγων· Οὐκ οἶδα τί λέγεις.", "en": {"kjv": "But he denied before them all, saying, I know not what thou sayest.", "web": "But he denied it before them all, saying, “I don’t know what you are talking about.”", "bsb": "But he denied it before them all: “I do not know what you are talking about.”", "asv": "But he denied before them all, saying, I know not what thou sayest.", "ylt": "And he denied before all, saying, `I have not known what thou sayest.'", "tyndale": "but he denyed before the all sayinge: I woot not what thou sayst.", "dra": "But he denied before them all, saying: I know not what thou sayest.", "bbe": "But he said before them all that it was false, saying, I have no knowledge of what you say.", "geneva": "But hee denied before them all, saying, I wote not what thou saiest.", "wycliffe": "And he denyede bifor alle men, and seide, Y woot not what thou seist.", "rotherham": "But, he, denied before all, saying—I know not what thou sayest.", "weymouth": "He denied it before them all, saying, \"I do not know what you mean.\"", "darby": "But he denied before all, saying, I do not know what thou sayest.", "twenty": "But Peter denied it before them all. “I do not know what you mean,” he replied.", "acv": "But he denied before them all, saying, I do not know what thou say.", "anderson": "But he denied before them all, saying: I know not what you say.", "haweis": "But he denied it before them all, asserting, I know not what thou art saying.", "noyes": "But he denied before them all, saying, I know not what thou sayest.", "webster": "But he denied before [them] all, saying, I know not what thou sayest.", "vulgate": "at ille negavit coram omnibus dicens nescio quid dicis;"}}, {"v": 71, "ref": "26:71", "o": "ἐξελθόντα ⸀δὲ εἰς τὸν πυλῶνα εἶδεν αὐτὸν ἄλλη καὶ λέγει ⸀τοῖς ἐκεῖ· ⸀Οὗτος ἦν μετὰ Ἰησοῦ τοῦ Ναζωραίου·", "en": {"kjv": "And when he was gone out into the porch, another maid saw him, and said unto them that were there, This fellow was also with Jesus of Nazareth.", "web": "When he had gone out onto the porch, someone else saw him, and said to those who were there, “This man also was with Jesus of Nazareth.”", "bsb": "When Peter had gone out to the gateway, another servant girl saw him and said to the people there, “This man was with Jesus of Nazareth.”", "asv": "And when he was gone out into the porch, another maid saw him, and saith unto them that were there, This man also was with Jesus of Nazareth.", "ylt": "And he having gone forth to the porch, another female saw him, and saith to those there, `And this one was with Jesus of Nazareth;'", "tyndale": "When he was goone out into the poorche another wenche sawe him and sayde vnto them that were there: This felowe was also with Iesus of Nazareth.", "dra": "And as he went out of the gate, another maid saw him; and she saith to them that were there: This man also was with Jesus of Nazareth.", "bbe": "And when he had gone out into the doorway, another saw him and says to those who were there, This man was with Jesus the Nazarene.", "geneva": "And when hee went out into the porche, another maide sawe him, and sayde vnto them that were there, This man was also with Iesus of Nazareth.", "wycliffe": "And whanne he yede out at the yate, another damysel say hym, and seide to hem that weren there, And this was with Jhesu of Nazareth.", "rotherham": "And, when he went out into the porch, another female saw him, and said unto them who were there—This, one was with Jesus the Nazarene.", "weymouth": "Soon afterwards he went out and stood in the gateway, when another girl saw him, and said, addressing the people there, \"This man was with Jesus the Nazarene.\"", "darby": "And when he had gone out into the entrance, another [maid] saw him, and says to those there, This [man] also was with Jesus the Nazaraean.", "twenty": "When he had gone out into the gateway, another maid saw him, and said to those who were there: “This man was with Jesus of Nazareth!”", "acv": "And when he was gone out into the porch, another woman saw him, and says to them there, This man was also with Jesus the Nazarene.", "anderson": "And when he went out into the entrance, another maid-servant saw him, and said to those who were there: This man was also with Jesus the Nazarene.", "haweis": "Then as he was going out at the gate, another maid-servant saw him, and saith to those who were there, This fellow also was with Jesus of Nazareth.", "noyes": "And when he had gone out into the porch, another woman saw him, and said to those who were there, This man was with Jesus the Nazarene.", "webster": "And when he had gone out into the porch, another [maid] saw him, and said to them that were there, This [man] was also with Jesus of Nazareth.", "vulgate": "exeunte autem illo ianuam vidit eum alia et ait his qui erant ibi et hic erat cum Iesu Nazareno;"}}, {"v": 72, "ref": "26:72", "o": "καὶ πάλιν ἠρνήσατο μετὰ ὅρκου ὅτι Οὐκ οἶδα τὸν ἄνθρωπον.", "en": {"kjv": "And again he denied with an oath, I do not know the man.", "web": "Again he denied it with an oath, “I don’t know the man.”", "bsb": "And again he denied it with an oath: “I do not know the man!”", "asv": "And again he denied with an oath, I know not the man.", "ylt": "and again did he deny with an oath--`I have not known the man.'", "tyndale": "And agayne he denyed with an oothe that he knew the man.", "dra": "And again he denied with an oath: I know not the man.", "bbe": "And again he said with an oath, I have no knowledge of the man.", "geneva": "And againe he denied with an othe, saying, I knowe not the man.", "wycliffe": "And eftsoone he denyede with an ooth, For I knewe not the man.", "rotherham": "And, again, he denied, with an oath—I know not the man.", "weymouth": "Again he denied it with an oath. \"I do not know the man,\" he said.", "darby": "And again he denied with an oath: I do not know the man.", "twenty": "Again he denied it with an oath: “I do not know the man!”", "acv": "And again he denied with an oath, I do not know the man.", "anderson": "And again he denied, with an oath: I know not the man.", "haweis": "Then again he denied with an oath, I know not the man.", "noyes": "And again he denied with an oath; I do not know the man.", "webster": "And again he denied with an oath, I do not know the man.", "vulgate": "et iterum negavit cum iuramento quia non novi hominem;"}}, {"v": 73, "ref": "26:73", "o": "μετὰ μικρὸν δὲ προσελθόντες οἱ ἑστῶτες εἶπον τῷ Πέτρῳ· Ἀληθῶς καὶ σὺ ἐξ αὐτῶν εἶ, καὶ γὰρ ἡ λαλιά σου δῆλόν σε ποιεῖ·", "en": {"kjv": "And after a while came unto him they that stood by, and said to Peter, Surely thou also art one of them; for thy speech bewrayeth thee.", "web": "After a little while those who stood by came and said to Peter, “Surely you are also one of them, for your speech makes you known.”", "bsb": "After a little while, those standing nearby came up to Peter. “Surely you are one of them,” they said, “for your accent gives you away.”", "asv": "And after a little while they that stood by came and said to Peter, Of a truth thou also art one of them; for thy speech maketh thee known.", "ylt": "And after a little those standing near having come, said to Peter, `Truly thou also art of them, for even thy speech doth make thee manifest.'", "tyndale": "And after a whyle came vnto him they yt stode bye and sayde vnto Peter: suerly thou arte even one of the for thy speache bewreyeth ye.", "dra": "And after a little while, they came that stood by and said to Peter: Surely thou also art one of them. For even thy speech doth discover thee.", "bbe": "And after a little time those who were near came and said to Peter, Truly you are one of them; because your talk is witness against you.", "geneva": "So after a while, came vnto him they that stoode by, and sayde vnto Peter, Surely thou art also one of them: for euen thy speache bewraieth thee.", "wycliffe": "And a litil aftir, thei that stooden camen, and seiden to Petir, Treuli thou art of hem; for thi speche makith thee knowun.", "rotherham": "And, after a little, the by-standers, coming forward, said unto Peter: Truly, thou also, art, from among them, for, thy very speech, maketh thee, manifest.", "weymouth": "A short time afterwards the people standing there came and said to Peter, \"Certainly you too are one of them, for your brogue shows it.\"", "darby": "And after a little, those who stood [there], coming to [him], said to Peter, Truly thou too art of them, for also thy speech makes thee manifest.", "twenty": "But soon afterwards those who were standing by came up and said to Peter: “You also are certainly one of them; why, your very way of speaking proves it!”", "acv": "And after a little while those who stood, having approached, said to Peter, Surely thou also are of them, for thy accent even makes thee apparent.", "anderson": "After a little while, those who stood by came and said to Peter: Of a truth you also are one of them, for your speech betrays you.", "haweis": "But after a little while they who stood by, came up and said to Peter, Assuredly thou also art one of them: for even thy speech maketh thee manifest.", "noyes": "And shortly after, they who were standing by came and said to Peter, Surely thou too art one of them; for thy speech betrayeth thee.", "webster": "And after a while came to [him] they that stood by, and said to Peter, Surely thou also art [one] of them; for thy speech betrayeth thee.", "vulgate": "et post pusillum accesserunt qui stabant et dixerunt Petro vere et tu ex illis es nam et loquella tua manifestum te facit;"}}, {"v": 74, "ref": "26:74", "o": "τότε ἤρξατο καταθεματίζειν καὶ ὀμνύειν ὅτι Οὐκ οἶδα τὸν ἄνθρωπον. καὶ ⸀εὐθέως ἀλέκτωρ ἐφώνησεν·", "en": {"kjv": "Then began he to curse and to swear, saying, I know not the man. And immediately the cock crew.", "web": "Then he began to curse and to swear, “I don’t know the man!” Immediately the rooster crowed.", "bsb": "At that he began to curse and swear to them, “I do not know the man!” And immediately a rooster crowed.", "asv": "Then began he to curse and to swear, I know not the man. And straightway the cock crew.", "ylt": "Then began he to anathematise, and to swear--`I have not known the man;' and immediately did a cock crow,", "tyndale": "Then beganne he to course and to sweare that he knewe not the man. And immedyatly the cocke krewe.", "dra": "Then he began to curse and to swear that he knew not the man. And immediately the cock crew.", "bbe": "Then with curses and oaths he said, I have no knowledge of the man. And straight away there came the cry of a cock.", "geneva": "Then began hee to curse himselfe, and to sweare, saying, I knowe not the man. And immediately the cocke crewe.", "wycliffe": "Thanne he bigan to warie and to swere, that he knewe not the man. And anoon the cok crewe.", "rotherham": "Then, began he to be cursing and swearing—I know not the man! And, straightway, a cock crowed.", "weymouth": "Then with curses and oaths he declared, \"I do not know the man.\" Immediately a cock crowed,", "darby": "Then he began to curse and to swear, I know not the man. And immediately [the] cock crew.", "twenty": "Then Peter began to swear, with most solemn imprecations: “I do not know the man.” At that moment a cock crowed;", "acv": "Then he began to curse vehemently and to swear, I do not know the man. And straightaway a cock sounded.", "anderson": "Then he began to curse and to swear, I know not the man. And immediately the cock crew.", "haweis": "Then began he to utter the bitterest curses, and to swear, I know not the man. And immediately the cock crew.", "noyes": "Then he began to curse and to swear, saying, I do not know the man. And immediately a cock crew.", "webster": "Then began he to curse and to swear, [saying], I know not the man. And immediately the cock crowed.", "vulgate": "tunc coepit detestari et iurare quia non novisset hominem et continuo gallus cantavit;"}}, {"v": 75, "ref": "26:75", "o": "καὶ ἐμνήσθη ὁ Πέτρος τοῦ ⸀ῥήματος Ἰησοῦ ⸀εἰρηκότος ὅτι Πρὶν ἀλέκτορα φωνῆσαι τρὶς ἀπαρνήσῃ με, καὶ ἐξελθὼν ἔξω ἔκλαυσεν πικρῶς.", "en": {"kjv": "And Peter remembered the word of Jesus, which said unto him, Before the cock crow, thou shalt deny me thrice. And he went out, and wept bitterly.", "web": "Peter remembered the word which Jesus had said to him, “Before the rooster crows, you will deny me three times.” He went out and wept bitterly.", "bsb": "Then Peter remembered the word that Jesus had spoken: “Before the rooster crows, you will deny Me three times.” And he went outside and wept bitterly.", "asv": "And Peter remembered the word which Jesus had said, Before the cock crow, thou shalt deny me thrice. And he went out, and wept bitterly.", "ylt": "and Peter remembered the saying of Jesus, he having said to him--`Before cock-crowing, thrice thou wilt deny me;' and having gone without, he did weep bitterly.", "tyndale": "And Peter remembred the wordes of Iesu which sayde vnto him: before the cocke crowe thou shalt deny me thryse: and went out at the dores and wepte bitterly.", "dra": "And Peter remembered the word of Jesus which he had said: Before the cock crow, thou wilt deny me thrice. And going forth, he wept bitterly.", "bbe": "And the word of Jesus came back to Peter, when he said, Before the hour of the cock's cry, you will say three times that you have no knowledge of me. And he went out, weeping bitterly.", "geneva": "Then Peter remembred the wordes of Iesus, which had sayde vnto him, Before the cocke crowe thou shalt denie me thrise. So he went out, and wept bitterly.", "wycliffe": "And Petir bithouyte on the word of Jhesu, that he hadde seid, Bifore the cok crowe, thries thou schalt denye me. And he yede out, and wepte bitterli.", "rotherham": "And Peter was put in mind of the declaration of Jesus, of his having said—Before a cock crow, thrice, wilt thou utterly deny me; and, going forth outside, he wept bitterly.", "weymouth": "and Peter recollected the words of Jesus, how He had said, \"Before the cock crows you will three times disown me.\" And he went out and wept aloud, bitterly.", "darby": "And Peter remembered the word of Jesus, who had said [to him], Before [the] cock crow thou shalt deny me thrice. And he went forth without, and wept bitterly.", "twenty": "and Peter remembered the words which Jesus had said — ‘Before a cock has crowed, you will disown me three times’; and he went outside, and wept bitterly.", "acv": "And Peter remembered the saying that Jesus said to him, Before a cock sounds, thou will deny me thrice. And having gone outside, he wept bitterly.", "anderson": "And Peter remembered the word which. Jesus had spoken to him: Before the cock crows, you will deny me three times. And he went out, and wept bitterly.", "haweis": "And Peter remembered the word of Jesus, who had said unto him, Before the cock shall crow, thou shalt deny me thrice. And going out, he wept bitterly.", "noyes": "And Peter remembered the word of Jesus, who had said, Before a cock crows, thou wilt thrice deny me. And he went out, and wept bitterly.", "webster": "And Peter remembered the word of Jesus, who said to him, Before the cock shall crow, thou wilt deny me thrice. And he went out, and wept bitterly.", "vulgate": "et recordatus est Petrus verbi Iesu quod dixerat priusquam gallus cantet ter me negabis et egressus foras ploravit amare;"}}]}, {"c": 27, "verses": [{"v": 1, "ref": "27:1", "o": "Πρωΐας δὲ γενομένης συμβούλιον ἔλαβον πάντες οἱ ἀρχιερεῖς καὶ οἱ πρεσβύτεροι τοῦ λαοῦ κατὰ τοῦ Ἰησοῦ ὥστε θανατῶσαι αὐτόν·", "en": {"kjv": "When the morning was come, all the chief priests and elders of the people took counsel against Jesus to put him to death:", "web": "Now when morning had come, all the chief priests and the elders of the people took counsel against Jesus to put him to death:", "bsb": "When morning came, all the chief priests and elders of the people conspired against Jesus to put Him to death.", "asv": "Now when morning was come, all the chief priests and the elders of the people took counsel against Jesus to put him to death:", "ylt": "And morning having come, all the chief priests and the elders of the people took counsel against Jesus, so as to put him to death;", "tyndale": "When the mornynge was come all ye chefe prestes and the elders of ye people helde a counsayle agenst Iesu to put him to deeth", "dra": "And when morning was come, all the chief priests and ancients of the people took counsel against Jesus, that they might put him to death.", "bbe": "Now when it was morning, all the chief priests and those in authority took thought together with the purpose of putting Jesus to death.", "geneva": "When the morning was come, all the chiefe Priests, and the elders of the people tooke counsell against Iesus, to put him to death,", "wycliffe": "But whanne the morowtid was comun, alle the princis of prestis, and the eldre men of the puple token counsel ayens Jhesu, that thei schulden take hym to the deeth.", "rotherham": "Now, when morning came, all the High-priests and Elders of the people took, counsel, against Jesus, so as to put him to death:", "weymouth": "When morning came all the High Priests and the Elders of the people consulted together against Jesus to put Him to death;", "darby": "And when it was morning all the chief priests and the elders of the people took counsel against Jesus so that they might put him to death.", "twenty": "At daybreak all the Chief Priests and the Councillors of the Nation consulted together against Jesus, to bring about his death.", "acv": "But having become morning, all the chief priests and the elders of the people held consultation against Jesus in order to condemn him to death.", "anderson": "When the morning came, all the chief priests and elders of the people held a consultation against Jesus, that they might put him to death.", "haweis": "NOW when the morning came, all the chief priests and the elders of the people took counsel against Jesus how they might put him to death.", "noyes": "And when it was morning, all the chief priests and the elders of the people consulted together against Jesus, to put him to death.", "webster": "When the morning was come, all the chief priests and elders of the people took counsel against Jesus to put him to death.", "vulgate": "mane autem facto consilium inierunt omnes principes sacerdotum et seniores populi adversus Iesum ut eum morti traderent;"}}, {"v": 2, "ref": "27:2", "o": "καὶ δήσαντες αὐτὸν ἀπήγαγον καὶ ⸀παρέδωκαν Πιλάτῳ τῷ ἡγεμόνι.", "en": {"kjv": "And when they had bound him, they led him away, and delivered him to Pontius Pilate the governor.", "web": "and they bound him, and led him away, and delivered him up to Pontius Pilate, the governor.", "bsb": "They bound Him, led Him away, and handed Him over to Pilate the governor.", "asv": "and they bound him, and led him away, and delivered him up to Pilate the governor.", "ylt": "and having bound him, they did lead away, and delivered him up to Pontius Pilate, the governor.", "tyndale": "and brought him bounde and delivered him vnto Poncius Pilate the debite.", "dra": "And they brought him bound and delivered him to Pontius Pilate the governor.", "bbe": "And they put cords on him and took him away, and gave him up to Pilate, the ruler.", "geneva": "And led him away bounde, and deliuered him vnto Pontius Pilate the gouernour.", "wycliffe": "And thei ledden him boundun, and bitoken to Pilat of Pounce, iustice.", "rotherham": "and, binding him, they led him away, and delivered him up unto Pilate the governor.", "weymouth": "and binding Him they led Him away and handed Him over to Pilate the Governor.", "darby": "And having bound him they led him away, and delivered him up to Pontius Pilate, the governor.", "twenty": "They put him in chains and led him away, and gave him up to the Roman Governor, Pilate.", "acv": "And having bound him, they led him away and delivered him to Pontius Pilate the governor.", "anderson": "And they bound him and led him away, and delivered him to Pontius Pilate the governor.", "haweis": "And having bound him, they led him away, and delivered him to Pontius Pilate the governor.", "noyes": "And having bound him, they led him away, and delivered him up to Pilate the governor.", "webster": "And when they had bound him, they led [him] away, and delivered him to Pontius Pilate the governor.", "vulgate": "et vinctum adduxerunt eum et tradiderunt Pontio Pilato praesidi;"}}, {"v": 3, "ref": "27:3", "o": "Τότε ἰδὼν Ἰούδας ὁ ⸀παραδιδοὺς αὐτὸν ὅτι κατεκρίθη μεταμεληθεὶς ⸀ἔστρεψεν τὰ τριάκοντα ἀργύρια τοῖς ἀρχιερεῦσιν ⸀καὶ πρεσβυτέροις", "en": {"kjv": "Then Judas, which had betrayed him, when he saw that he was condemned, repented himself, and brought again the thirty pieces of silver to the chief priests and elders,", "web": "Then Judas, who betrayed him, when he saw that Jesus was condemned, felt remorse, and brought back the thirty pieces of silver to the chief priests and elders,", "bsb": "When Judas, who had betrayed Him, saw that Jesus was condemned, he was filled with remorse and returned the thirty pieces of silver to the chief priests and elders.", "asv": "Then Judas, who betrayed him, when he saw that he was condemned, repented himself, and brought back the thirty pieces of silver to the chief priests and elders,", "ylt": "Then Judas--he who delivered him up--having seen that he was condemned, having repented, brought back the thirty silverlings to the chief priests, and to the elders, saying,", "tyndale": "Then when Iudas which betrayed him sawe that he was condempned he repented him sylfe and brought ageyne the .xxx. plattes of sylver to ye chefe prestes and elders", "dra": "Then Judas, who betrayed him, seeing that he was condemned, repenting himself, brought back the thirty pieces of silver to the chief priests and ancients,", "bbe": "Then Judas, who was false to him, seeing that he was to be put to death, in his regret took back the thirty bits of silver to the chief priests and those in authority,", "geneva": "Then when Iudas which betraied him, sawe that hee was condemned, hee repented himselfe, and brought againe the thirtie pieces of siluer to the chiefe Priestes, and Elders,", "wycliffe": "Thanne Judas that bitraiede hym, say that he was dampned, he repentide, and brouyte ayen the thretti pans to the princis of prestis, and to the elder men of the puple,", "rotherham": "Then, Judas who had delivered him up, seeing that he was condemned, being smitten with remorse, returned the thirty pieces of silver unto the High-priests and Elders,", "weymouth": "Then when Judas, who had betrayed Him, saw that He was condemned, smitten with remorse he brought back the thirty shekels to the High Priests and Elders", "darby": "Then Judas, who delivered him up, seeing that he had been condemned, filled with remorse, returned the thirty pieces of silver to the chief priests and the elders,", "twenty": "Then Judas, who betrayed him, seeing that Jesus was condemned, repented of what he had done, and returned the thirty pieces of silver to the Chief Priests and Councillors.", "acv": "Then Judas, who betrayed him, after seeing that he was condemned, having repented, he brought back the thirty silver pieces to the chief priests and elders,", "anderson": "Then Judas, who had delivered him up, when he saw that he was condemned, stung by remorse, brought back the thirty pieces of silver to the chief priests and elders,", "haweis": "Then Judas who betrayed him, seeing that he was condemned, repenting, carried back the thirty silver pieces to the chief priests and the elders,", "noyes": "Then Judas, who betrayed him, when he saw that he was condemned, repented, and brought back the thirty pieces of silver to the chief priests and elders,", "webster": "Then Judas, who had betrayed him, when he saw that he was condemned, repented and brought again the thirty pieces of silver to the chief priests and elders,", "vulgate": "tunc videns Iudas qui eum tradidit quod damnatus esset paenitentia ductus rettulit triginta argenteos principibus sacerdotum et senioribus;"}}, {"v": 4, "ref": "27:4", "o": "λέγων· Ἥμαρτον παραδοὺς αἷμα ⸀ἀθῷον. οἱ δὲ εἶπαν· Τί πρὸς ἡμᾶς; σὺ ⸀ὄψῃ.", "en": {"kjv": "Saying, I have sinned in that I have betrayed the innocent blood. And they said, What is that to us? see thou to that.", "web": "saying, “I have sinned in that I betrayed innocent blood.” But they said, “What is that to us? You see to it.”", "bsb": "“I have sinned by betraying innocent blood,” he said. “What is that to us?” they replied. “You bear the responsibility.”", "asv": "saying, I have sinned in that I betrayed innocent blood. But they said, What is that to us? see thou to it.", "ylt": "`I did sin, having delivered up innocent blood;' and they said, `What--to us? thou shalt see!'", "tyndale": "sayinge: I have synned betrayinge the innocent bloud. And they sayde: what is that to vs? Se thou to that.", "dra": "Saying: I have sinned in betraying innocent blood. But they said: What is that to us? Look thou to it.", "bbe": "Saying, I have done wrong in giving into your hands an upright man. But they said, What is that to us? it is your business.", "geneva": "Saying, I haue sinned, betraying the innocent bloud. But they sayde, What is that to vs? see thou to it.", "wycliffe": "and seide, Y haue synned, bitraiynge riytful blood. And thei seiden, What to vs? bise thee.", "rotherham": "saying—I have sinned, in delivering up righteous blood. But, they, said—What is that to us? thou, shalt see to it for thyself.", "weymouth": "and said, \"I have sinned, in betraying to death one who is innocent.\" \"What does that matter to us?\" they replied; it is your business.\"", "darby": "saying, I have sinned [in] having delivered up guiltless blood. But they said, What is that to us? see thou [to that].", "twenty": "“I did wrong in betraying a good man to his death,” he said. “What has that to do with us?” they replied. “You must see to that yourself.”", "acv": "saying, I sinned, having betrayed innocent blood. But they said, What is it to us? See thou to it.", "anderson": "saying: I have sinned in having delivered up innocent blood. They replied: What is that to us? You will see to that.", "haweis": "saying, I have sinned, in betraying innocent blood. But they said, What is that to us? see thou to that.", "noyes": "saying, I sinned in betraying innocent blood. And they said, What is that to us? See thou to it.", "webster": "Saying, I have sinned in that I have betrayed innocent blood. And they said, What [is that] to us? see thou [to that].", "vulgate": "dicens peccavi tradens sanguinem iustum at illi dixerunt quid ad nos tu videris;"}}, {"v": 5, "ref": "27:5", "o": "καὶ ῥίψας τὰ ἀργύρια ⸂εἰς τὸν ναὸν⸃ ἀνεχώρησεν, καὶ ἀπελθὼν ἀπήγξατο.", "en": {"kjv": "And he cast down the pieces of silver in the temple, and departed, and went and hanged himself.", "web": "He threw down the pieces of silver in the sanctuary, and departed. He went away and hanged himself.", "bsb": "So Judas threw the silver into the temple and left. Then he went away and hanged himself.", "asv": "And he cast down the pieces of silver into the sanctuary, and departed; and he went away and hanged himself.", "ylt": "and having cast down the silverlings in the sanctuary, he departed, and having gone away, he did strangle himself.", "tyndale": "And he cast doune the sylver plattes in the temple and departed and went and hounge him sylfe.", "dra": "And casting down the pieces of silver in the temple, he departed and went and hanged himself with an halter.", "bbe": "And he put down the silver in the Temple and went out, and put himself to death by hanging.", "geneva": "And when hee had cast downe the siluer pieces in the Temple, hee departed, and went, and hanged himselfe.", "wycliffe": "And whanne he hadde cast forth the siluer in the temple, he passide forth, and yede, and hongide hym silf with a snare.", "rotherham": "And, throwing the pieces of silver into the Temple, he withdrew, and, going away, hanged himself.", "weymouth": "Flinging the shekels into the Sanctuary he left the place, and went and hanged himself.", "darby": "And having cast down the pieces of silver in the temple, he left the place, and went away and hanged himself.", "twenty": "Judas flung down the pieces of silver in the Temple, and left; and went away and hanged himself.", "acv": "And having cast down the silver pieces in the temple, he departed, and after going away, he hanged himself.", "anderson": "And he threw down the money in the temple, and departed, and went and hanged himself.", "haweis": "And throwing down the silver pieces in the temple, he departed; and going out, hanged himself.", "noyes": "And he cast down the pieces of silver in the temple, and withdrew; and went away and hanged himself.", "webster": "And he cast down the pieces of silver in the temple, and departed, and went and hanged himself.", "vulgate": "et proiectis argenteis in templo recessit et abiens laqueo se suspendit;"}}, {"v": 6, "ref": "27:6", "o": "οἱ δὲ ἀρχιερεῖς λαβόντες τὰ ἀργύρια εἶπαν· Οὐκ ἔξεστιν βαλεῖν αὐτὰ εἰς τὸν κορβανᾶν, ἐπεὶ τιμὴ αἵματός ἐστιν·", "en": {"kjv": "And the chief priests took the silver pieces, and said, It is not lawful for to put them into the treasury, because it is the price of blood.", "web": "The chief priests took the pieces of silver, and said, “It’s not lawful to put them into the treasury, since it is the price of blood.”", "bsb": "The chief priests picked up the pieces of silver and said, “It is unlawful to put this into the treasury, since it is blood money.”", "asv": "And the chief priests took the pieces of silver, and said, It is not lawful to put them into the treasury, since it is the price of blood.", "ylt": "And the chief priests having taken the silverlings, said, `It is not lawful to put them to the treasury, seeing it is the price of blood;'", "tyndale": "And the chefe prestes toke the sylver plattes and sayd: it is not lawfull for to put them in to the treasury because it is the pryce of bloud.", "dra": "But the chief priests having taken the pieces of silver, said: It is not lawful to put them into the corbona, because it is the price of blood.", "bbe": "And the chief priests took the silver and said, It is not right to put it in the Temple store for it is the price of blood.", "geneva": "And the chiefe Priestes tooke the siluer pieces, and sayde, It is not lawfull for vs to put them into the treasure, because it is the price of bloud.", "wycliffe": "And the princis of prestis token the siluer, and seide, It is not leueful to putte it in to the treserie, for it is the prijs of blood.", "rotherham": "But, the High-priests, taking the pieces of silver, said—It is not allowed, to cast them into the treasury; since, a price of blood, they are.", "weymouth": "When the High Priests had gathered up the money they said, \"It is illegal to put it into the Treasury, because it is the price of blood.\"", "darby": "And the chief priests took the pieces of silver and said, It is not lawful to cast them into the Corban, since it is [the] price of blood.", "twenty": "The Chief Priests took the pieces of silver, but they said: “We must not put them into the Temple treasury, because they are blood-money.”", "acv": "And after taking the silver pieces, the chief priests said, It is not permitted to put them into the treasury, since it is a price of blood.", "anderson": "And the chief priests took the money, and said: It is not lawful to put it into the sacred treasury, because it is the price of blood.", "haweis": "Then the chief priests taking up the silver pieces, said, It is not lawful to put them to the treasure destined for sacred uses, because it is the price of blood.", "noyes": "And the chief priests took the pieces of silver, and said, It is not lawful to put them into the treasury, since they are the price of blood.", "webster": "And the chief priests took the silver pieces, and said, It is not lawful to put them into the treasury, because it is the price of blood.", "vulgate": "principes autem sacerdotum acceptis argenteis dixerunt non licet mittere eos in corbanan quia pretium sanguinis est;"}}, {"v": 7, "ref": "27:7", "o": "συμβούλιον δὲ λαβόντες ἠγόρασαν ἐξ αὐτῶν τὸν Ἀγρὸν τοῦ Κεραμέως εἰς ταφὴν τοῖς ξένοις.", "en": {"kjv": "And they took counsel, and bought with them the potter’s field, to bury strangers in.", "web": "They took counsel, and bought the potter’s field with them, to bury strangers in.", "bsb": "After conferring together, they used the money to buy the potter’s field as a burial place for foreigners.", "asv": "And they took counsel, and bought with them the potter’s field, to bury strangers in.", "ylt": "and having taken counsel, they bought with them the field of the potter, for the burial of strangers;", "tyndale": "And they toke counsell and bought with them a potters felde to bury strangers in.", "dra": "And after they had consulted together, they bought with them the potter's field, to be a burying place for strangers.", "bbe": "And they made a decision to get with the silver the potter's field, as a place for the dead of other countries.", "geneva": "And they tooke counsell, and bought with them a potters fielde, for the buriall of strangers.", "wycliffe": "And whanne thei hadden take counsel, thei bouyten with it a feeld of a potter, in to biryyng of pilgrymys.", "rotherham": "And, taking counsel, they bought with them, the field of the potter, as a burial-place for strangers.", "weymouth": "So after consulting together they spent the money in the purchase of the Potter's Field as a burial place for people not belonging to the city;", "darby": "And having taken counsel, they bought with them the field of the potter for a burying-ground for strangers.", "twenty": "So, after consultation, they bought with them the ‘Potter’s Field’ for a burial-ground for foreigners;", "acv": "And having held consultation, they bought the potter's field with them for burial for foreigners.", "anderson": "And they took counsel, and bought with it the potter’s field, as a burial-place for foreigners.", "haweis": "So taking counsel, they bought with them a potter’s field, as a burial-place for strangers.", "noyes": "And they consulted together, and bought with them the potter’s field, for a burial-place for strangers.", "webster": "And they took counsel, and bought with them the potter's field, to bury strangers in.", "vulgate": "consilio autem inito emerunt ex illis agrum figuli in sepulturam peregrinorum;"}}, {"v": 8, "ref": "27:8", "o": "διὸ ἐκλήθη ὁ ἀγρὸς ἐκεῖνος Ἀγρὸς Αἵματος ἕως τῆς σήμερον.", "en": {"kjv": "Wherefore that field was called, The field of blood, unto this day.", "web": "Therefore that field was called “The Field of Blood” to this day.", "bsb": "That is why it has been called the Field of Blood to this day.", "asv": "Wherefore that field was called, The field of blood, unto this day.", "ylt": "therefore was that field called, `Field of blood,' unto this day.", "tyndale": "Wherfore that felde is called the felde of bloud vntyll this daye.", "dra": "For this cause that field was called Haceldama, that is, the field of blood, even to this day.", "bbe": "For this cause that field was named, The field of blood, to this day.", "geneva": "Wherefore that field is called, The field of bloud, vntill this day.", "wycliffe": "Herfor thilke feeld is clepid Acheldemac, that is, a feeld of blood, in to this dai.", "rotherham": "Wherefore, that field hath been called Field of Blood, until this day.", "weymouth": "for which reason that piece of ground received the name, which it still bears, of `the Field of Blood.'", "darby": "Wherefore that field has been called Blood-field unto this day.", "twenty": "and that is why that field is called the ‘Field of Blood’ to this very day.", "acv": "Therefore that field was called the field of blood, to this day.", "anderson": "For this reason, that field is called the field of blood, to this day.", "haweis": "Therefore is that field called, The field of blood unto this day.", "noyes": "Wherefore that field hath been called, The Field of Blood, unto this day.", "webster": "Wherefore that field has been called, The field of blood, to this day.", "vulgate": "propter hoc vocatus est ager ille Acheldemach ager sanguinis usque in hodiernum diem;"}}, {"v": 9, "ref": "27:9", "o": "τότε ἐπληρώθη τὸ ῥηθὲν διὰ Ἰερεμίου τοῦ προφήτου λέγοντος· Καὶ ἔλαβον τὰ τριάκοντα ἀργύρια, τὴν τιμὴν τοῦ τετιμημένου ὃν ἐτιμήσαντο ἀπὸ υἱῶν Ἰσραήλ,", "en": {"kjv": "Then was fulfilled that which was spoken by Jeremy the prophet, saying, And they took the thirty pieces of silver, the price of him that was valued, whom they of the children of Israel did value;", "web": "Then that which was spoken through Jeremiah the prophet was fulfilled, saying, “They took the thirty pieces of silver, the price of him upon whom a price had been set, whom some of the children of Israel priced,", "bsb": "Then what was spoken through Jeremiah the prophet was fulfilled: “They took the thirty pieces of silver, the price set on Him by the people of Israel,", "asv": "Then was fulfilled that which was spoken through Jeremiah the prophet, saying, And they took the thirty pieces of silver, the price of him that was priced, whom certain of the children of Israel did price;", "ylt": "Then was fulfilled that spoken through Jeremiah the prophet, saying, `And I took the thirty silverlings, the price of him who hath been priced, whom they of the sons of Israel did price,", "tyndale": "Then was fulfylled that which was spoken by Ieremy the Prophet sayinge: and they toke .xxx. sylver plattes the prise of him that was valued whom they bought of the chyldren of Israel", "dra": "Then was fulfilled that which was spoken by Jeremias the prophet, saying: And they took the thirty pieces of silver, the price of him that was prized, whom they prized of the children of Israel.", "bbe": "Then came true that which was said by Jeremiah the prophet, And they took the thirty bits of silver, the price of him who was valued by the children of Israel;", "geneva": "(Then was fulfilled that which was spoken by Ieremias the Prophet, saying, And they tooke thirtie siluer pieces, ye price of him that was valued, whom they of ye children of Israel valued.", "wycliffe": "Thanne that was fulfillid, that was seid bi the prophete Jeremye, seiynge, And thei han takun thretti pans, the prijs of a man preysid, whom thei preiseden of the children of Israel;", "rotherham": "Then, was fulfilled, that which was spoken through Jeremiah the prophet, saying: And they took the thirty pieces of silver, as the value of him whom they had valued, whom they had valued, of Israel’s sons,—", "weymouth": "Then were fulfilled the words spoken by the Prophet Jeremiah, \"And I took the thirty shekels, the price of the prized one on whom Israelites had set a price,", "darby": "Then was fulfilled that which was spoken through Jeremias the prophet, saying, And I took the thirty pieces of silver, the price of him that was set a price on, whom [they who were] of the sons of Israel had set a price on,", "twenty": "Then it was that these words spoken by the Prophet Jeremiah were fulfilled — ‘They took the thirty pieces of silver, the price of him who was valued, whom some of the people of Israel valued,", "acv": "Then that which was spoken through Jeremiah the prophet was fulfilled, which says, And they took the thirty silver pieces, the price of him who was valued, whom they valued from the sons of Israel,", "anderson": "Then the word was fulfilled which was spoken by Jeremiah the prophet, saying: And they took the thirty pieces of silver, the price of him that had a price set upon him, on whom some of the children of Israel did set a price,", "haweis": "Then was fulfilled what was spoken by Jeremiah the prophet, saying, And they took the thirty silver pieces, the price of him who had been estimated at that rate, whom they of the children of Israel did value:", "noyes": "Then was fulfilled that which was spoken through Jeremiah the prophet, saying, \"And they took the thirty pieces of silver, the price of him that was priced, whom they of the sons of Israel priced,", "webster": "Then was fulfilled that which was spoken by Jeremiah the prophet, saying, And they took the thirty pieces of silver, the price of him that was valued, whom they of the children of Israel did value;", "vulgate": "tunc impletum est quod dictum est per Hieremiam prophetam dicentem et acceperunt triginta argenteos pretium adpretiati quem adpretiaverunt a filiis Israhel;"}}, {"v": 10, "ref": "27:10", "o": "καὶ ἔδωκαν αὐτὰ εἰς τὸν ἀγρὸν τοῦ κεραμέως, καθὰ συνέταξέν μοι κύριος.", "en": {"kjv": "And gave them for the potter’s field, as the Lord appointed me.", "web": "and they gave them for the potter’s field, as the Lord commanded me.”", "bsb": "and they gave them for the potter’s field, as the Lord had commanded me.”", "asv": "and they gave them for the potter’s field, as the Lord appointed me.", "ylt": "and gave them for the field of the potter, as the Lord did appoint to me.'", "tyndale": "and they gave them for the potters felde as the Lorde appoynted me.", "dra": "And they gave them unto the potter's field, as the Lord appointed to me.", "bbe": "And they gave them for the potter's field, as I had word from the Lord.", "geneva": "And they gaue them for the potters fielde, as the Lord appointed me.)", "wycliffe": "and thei yauen hem in to a feeld of a potter, as the Lord hath ordenyd to me.", "rotherham": "And gave them for the field of the potter, as, the Lord, directed me.", "weymouth": "and gave them for the potter's field, as the Lord directed me.\"", "darby": "and they gave them for the field of the potter, according as [the] Lord commanded me.", "twenty": "and gave them for the Potter’s field, as the Lord commanded me.’", "acv": "and they gave them for the potter's field, as the Lord appointed me.", "anderson": "and gave them for the potter’s field, as the Lord appointed me.", "haweis": "and gave them for the potter’s field, as the Lord had ordered me.", "noyes": "and gave them for the potter’s field; as the Lord commanded me.\"", "webster": "And gave them for the potter's field, as the Lord appointed me.", "vulgate": "et dederunt eos in agrum figuli sicut constituit mihi Dominus;"}}, {"v": 11, "ref": "27:11", "o": "Ὁ δὲ Ἰησοῦς ⸀ἐστάθη ἔμπροσθεν τοῦ ἡγεμόνος· καὶ ἐπηρώτησεν αὐτὸν ὁ ἡγεμὼν λέγων· Σὺ εἶ ὁ βασιλεὺς τῶν Ἰουδαίων; ὁ δὲ Ἰησοῦς ⸀ἔφη· Σὺ λέγεις.", "en": {"kjv": "And Jesus stood before the governor: and the governor asked him, saying, Art thou the King of the Jews? And Jesus said unto him, Thou sayest.", "web": "Now Jesus stood before the governor: and the governor asked him, saying, “Are you the King of the Jews?” Jesus said to him, “So you say.”", "bsb": "Meanwhile Jesus stood before the governor, who questioned Him: “Are You the King of the Jews?” “You have said so,” Jesus replied.", "asv": "Now Jesus stood before the governor: and the governor asked him, saying, Art thou the King of the Jews? And Jesus said unto him, Thou sayest.", "ylt": "And Jesus stood before the governor, and the governor did question him, saying, `Art thou the king of the Jews!' And Jesus said to him, `Thou sayest.'", "tyndale": "Iesus stode before the debite: and the debite axed him sayinge: Arte thou the kynge of ye Iues? Iesus sayd vnto him: Thou sayest", "dra": "And Jesus stood before the governor, and the governor asked him, saying: Art thou the king of the Jews? Jesus saith to him: Thou sayest it.", "bbe": "And Jesus was before the ruler, who put a question to him, Are you the King of the Jews? And Jesus said to him, You say so.", "geneva": "And Iesus stood before ye gouernour, and the gouernour asked him, saying, Art thou that King of the Iewes? Iesus said vnto him, Thou sayest it.", "wycliffe": "And Jhesus stood bifor the domesman; and the iustice axide him, and seide, Art thou king of Jewis?", "rotherham": "Now, Jesus, stood before the governor; and the governor questioned him, saying—Thou, art the king of the Jews? And, Jesus, said—Thou, sayest.", "weymouth": "Meanwhile Jesus was brought before the Governor, and the latter put the question, \"Are you the King of the Jews?\" \"I am their King,\" He answered.", "darby": "But Jesus stood before the governor. And the governor questioned him, saying, Art thou the King of the Jews? And Jesus said to him, Thou sayest.", "twenty": "Meanwhile Jesus was brought before the Roman Governor. “Are you the King of the Jews?” asked the Governor. “It is true,” answered Jesus.", "acv": "Now Jesus stood before the governor, and the governor questioned him, saying, Are thou the king of the Jews? And Jesus said to him, Thou say.", "anderson": "And Jesus stood before the governor; and the governor asked him, saying: Are you the king of the Jews? Jesus replied to him: You say it.", "haweis": "Then was Jesus placed before the governor, and the governor interrogated him, saying, Art thou the King of the Jews? Then Jesus replied to him, Thou sayest true.", "noyes": "And Jesus stood before the governor; and the governor questioned him, saying, Art thou the king of the Jews? And Jesus said, I am.", "webster": "And Jesus stood before the governor: and the governor asked him, saying, Art thou the King of the Jews? And Jesus said to him, Thou sayest.", "vulgate": "Iesus autem stetit ante praesidem et interrogavit eum praeses dicens tu es rex Iudaeorum dicit ei Iesus tu dicis;"}}, {"v": 12, "ref": "27:12", "o": "καὶ ἐν τῷ κατηγορεῖσθαι αὐτὸν ὑπὸ τῶν ἀρχιερέων ⸀καὶ πρεσβυτέρων οὐδὲν ἀπεκρίνατο.", "en": {"kjv": "And when he was accused of the chief priests and elders, he answered nothing.", "web": "When he was accused by the chief priests and elders, he answered nothing.", "bsb": "And when He was accused by the chief priests and elders, He gave no answer.", "asv": "And when he was accused by the chief priests and elders, he answered nothing.", "ylt": "And in his being accused by the chief priests and the elders, he did not answer any thing,", "tyndale": "and when he was accused of ye chefe prestes and elders he answered nothinge.", "dra": "And when he was accused by the chief priests and ancients, he answered nothing.", "bbe": "But when the chief priests and those in authority made statements against him, he gave no answer.", "geneva": "And when he was accused of the chiefe Priestes, and Elders, he answered nothing.", "wycliffe": "Jhesus seith to hym, Thou seist. And whanne he was accusid of the princis of prestis, and of the eldere men of the puple, he answeride no thing.", "rotherham": "And, while he was being accused by the High-priests and Elders, he answered nothing.", "weymouth": "When however the High Priests and the Elders kept bringing their charges against Him, He said not a word in reply.", "darby": "And when he was accused of the chief priests and the elders, he answered nothing.", "twenty": "While charges were being brought against him by the Chief Priests and Councillors, Jesus made no reply.", "acv": "And when he was accused by the chief priests and elders, he answered nothing.", "anderson": "And when he was accused by the chief priests and elders, he made no answer.", "haweis": "And when he was accused of the chief priests and elders, he made no reply.", "noyes": "And when he was accused by the chief priests and elders, he made no answer.", "webster": "And when he was accused by the chief priests and elders, he answered nothing.", "vulgate": "et cum accusaretur a principibus sacerdotum et senioribus nihil respondit;"}}, {"v": 13, "ref": "27:13", "o": "τότε λέγει αὐτῷ ὁ Πιλᾶτος· Οὐκ ἀκούεις πόσα σου καταμαρτυροῦσιν;", "en": {"kjv": "Then said Pilate unto him, Hearest thou not how many things they witness against thee?", "web": "Then Pilate said to him, “Don’t you hear how many things they testify against you?”", "bsb": "Then Pilate asked Him, “Do You not hear how many charges they are bringing against You?”", "asv": "Then saith Pilate unto him, Hearest thou not how many things they witness against thee?", "ylt": "then saith Pilate to him, `Dost thou not hear how many things they witness against thee?'", "tyndale": "Then sayd Pilate vnto him: hearest thou not how many thinges they laye ageynste ye?", "dra": "Then Pilate saith to him: Dost not thou hear how great testimonies they allege against thee?", "bbe": "Then says Pilate to him, Do you give no attention to what their witnesses say against you?", "geneva": "Then saide Pilate vnto him, Hearest thou not howe many things they lay against thee?", "wycliffe": "Thanne Pilat seith to him, Herist thou not, hou many witnessyngis thei seien ayens thee?", "rotherham": "Then, Pilate saith unto him—Hearest thou not how many things against thee they are bearing witness?", "weymouth": "\"Do you not hear,\" asked Pilate, \"what a mass of evidence they are bringing against you?\"", "darby": "Then says Pilate to him, Hearest thou not how many things they witness against thee?", "twenty": "Then Pilate said to him: “Do not you hear how many accusations they are making against you?”", "acv": "Then Pilate says to him, Do thou not hear how many things they testify against thee?", "anderson": "Then Pilate said to him: Do you not hear how many things they testify against you?", "haweis": "Then saith Pilate to him, Hearest thou not how many things they testify against thee?", "noyes": "Then saith Pilate to him, Dost thou not hear what things they are testifying against thee?", "webster": "Then saith Pilate to him, Hearest thou not how many things they testify against thee?", "vulgate": "tunc dicit illi Pilatus non audis quanta adversum te dicant testimonia;"}}, {"v": 14, "ref": "27:14", "o": "καὶ οὐκ ἀπεκρίθη αὐτῷ πρὸς οὐδὲ ἓν ῥῆμα, ὥστε θαυμάζειν τὸν ἡγεμόνα λίαν.", "en": {"kjv": "And he answered him to never a word; insomuch that the governor marvelled greatly.", "web": "He gave him no answer, not even one word, so that the governor marveled greatly.", "bsb": "But Jesus gave no answer, not even to a single charge, much to the governor’s amazement.", "asv": "And he gave him no answer, not even to one word: insomuch that the governor marvelled greatly.", "ylt": "And he did not answer him, not even to one word, so that the governor did wonder greatly.", "tyndale": "And he answered him to never a worde: in so moche that the debite marveylled greatlie.", "dra": "And he answered him to never a word, so that the governor wondered exceedingly.", "bbe": "And he gave him no answer, not even a word: so that the ruler was greatly surprised.", "geneva": "But he answered him not to one worde, in so much that the gouernour marueiled greatly.", "wycliffe": "And he answeride not `to hym ony word, so that the iustice wondride greetli.", "rotherham": "And he answered him, no not so much as a single word, so that the governor was marvelling exceedingly.", "weymouth": "But He made no reply to a single accusation, so that the Governor was greatly astonished.", "darby": "And he answered him not so much as one word, so that the governor wondered exceedingly.", "twenty": "Yet Jesus made no reply — not even a single word; at which the Governor was greatly astonished.", "acv": "And he did not answer him, not even one word, so as for the governor to marvel greatly.", "anderson": "And he gave him answer to not one word, so that the governor was greatly astonished.", "haweis": "And he made him no reply, no not to a single word: so that the governor marvelled exceedingly.", "noyes": "And he made him no answer, not even to one word; so that the governor greatly wondered.", "webster": "And he answered him to not a word; so that the governor marveled greatly.", "vulgate": "et non respondit ei ad ullum verbum ita ut miraretur praeses vehementer;"}}, {"v": 15, "ref": "27:15", "o": "Κατὰ δὲ ἑορτὴν εἰώθει ὁ ἡγεμὼν ἀπολύειν ἕνα τῷ ὄχλῳ δέσμιον ὃν ἤθελον.", "en": {"kjv": "Now at that feast the governor was wont to release unto the people a prisoner, whom they would.", "web": "Now at the feast the governor was accustomed to release to the multitude one prisoner, whom they desired.", "bsb": "Now it was the governor’s custom at the feast to release to the crowd a prisoner of their choosing.", "asv": "Now at the feast the governor was wont to release unto the multitude one prisoner, whom they would.", "ylt": "And at the feast the governor had been accustomed to release one to the multitude, a prisoner, whom they willed,", "tyndale": "At that feest the debite was wonte to deliver vnto ye people a presoner whom they wolde desyer.", "dra": "Now upon the solemn day the governor was accustomed to release to the people one prisoner, whom they would.", "bbe": "Now at the feast it was the way for the ruler to let free to the people one prisoner, at their selection.", "geneva": "Nowe at the feast, the gouernour was wont to deliuer vnto the people a prisoner whom they would.", "wycliffe": "But for a solempne dai the iustice was wont to delyuere to the puple oon boundun, whom thei wolden.", "rotherham": "But, feast by feast, the governor had been wont to release one unto the multitude, a prisoner whom they were desiring.", "weymouth": "\"Now it was the Governor's custom at the Festival to release some one prisoner, whomsoever the populace desired;", "darby": "Now at [the] feast the governor was accustomed to release one prisoner to the crowd, whom they would.", "twenty": "Now, at the Feast, the Governor was accustomed to grant the people the release of any one prisoner whom they might choose.", "acv": "Now during a feast the governor had been accustomed to release to the crowd one prisoner whom they wanted.", "anderson": "Now at the feast, the governor was in the habit of releasing to the multitude one prisoner, whom they chose.", "haweis": "Now at the feast, the governor had been accustomed to release one prisoner to the people, whomsoever they chose.", "noyes": "Now at the feast the governor was wont to release to the multitude one prisoner, whom they would.", "webster": "Now at [that] feast, the governor was wont to release to the people a prisoner, whom they would.", "vulgate": "per diem autem sollemnem consueverat praeses dimittere populo unum vinctum quem voluissent;"}}, {"v": 16, "ref": "27:16", "o": "εἶχον δὲ τότε δέσμιον ἐπίσημον λεγόμενον ⸀Ἰησοῦν Βαραββᾶν.", "en": {"kjv": "And they had then a notable prisoner, called Barabbas.", "web": "They had then a notable prisoner, called Barabbas.", "bsb": "At that time they were holding a notorious prisoner named Barabbas.", "asv": "And they had then a notable prisoner, called Barabbas.", "ylt": "and they had then a noted prisoner, called Barabbas,", "tyndale": "He had then a notable presoner called Barrabas.", "dra": "And he had then a notorious prisoner that was called Barabbas.", "bbe": "And they had then an important prisoner, whose name was Barabbas.", "geneva": "And they had then a notable prisoner, called Barabbas.", "wycliffe": "And he hadde tho a famous man boundun, that was seid Barrabas.", "rotherham": "Now they had at that time a distinguished prisoner, called, Barabbas.", "weymouth": "and at this time they had a notorious prisoner called Barabbas.", "darby": "And they had then a notable prisoner, named Barabbas.", "twenty": "At that time they had a notorious prisoner called Barabbas.", "acv": "And they had then a notorious prisoner called Barabbas.", "anderson": "They then had a notorious prisoner, called Barabbas.", "haweis": "And they had at that time a notorious prisoner, called Barabbas.", "noyes": "And they had then a notorious prisoner, called Barabbas.", "webster": "And they had then a notable prisoner, called Barabbas.", "vulgate": "habebat autem tunc vinctum insignem qui dicebatur Barabbas;"}}, {"v": 17, "ref": "27:17", "o": "συνηγμένων οὖν αὐτῶν εἶπεν αὐτοῖς ὁ Πιλᾶτος· Τίνα θέλετε ἀπολύσω ὑμῖν, ⸂Ἰησοῦν τὸν⸃ Βαραββᾶν ἢ Ἰησοῦν τὸν λεγόμενον χριστόν;", "en": {"kjv": "Therefore when they were gathered together, Pilate said unto them, Whom will ye that I release unto you? Barabbas, or Jesus which is called Christ?", "web": "When therefore they were gathered together, Pilate said to them, “Whom do you want me to release to you? Barabbas, or Jesus, who is called Christ?”", "bsb": "So when the crowd had assembled, Pilate asked them, “Which one do you want me to release to you: Barabbas, or Jesus who is called Christ?”", "asv": "When therefore they were gathered together, Pilate said unto them, Whom will ye that I release unto you? Barabbas, or Jesus who is called Christ?", "ylt": "they therefore having been gathered together, Pilate said to them, `Whom will ye I shall release to you? Barabbas or Jesus who is called Christ?'", "tyndale": "And when they were gadered together Pilate sayde vnto the: whether wyll ye that I geve losse vnto you Barrabas or Iesus which is called Christ?", "dra": "They therefore being gathered together, Pilate said: Whom will you that I release to You: Barabbas, or Jesus that is called Christ?", "bbe": "So when they came together, Pilate said to them, Whom will you have? Barabbas, or Jesus, who is named Christ?", "geneva": "When they were then gathered together, Pilate said vnto the, Whether will ye that I let loose vnto you Barabbas, or Iesus which is called Christ?", "wycliffe": "Therfor Pilate seide to hem, whanne thei weren to gidere, Whom wolen ye, that Y delyuere to you? whether Barabas, or Jhesu, that is seid Crist?", "rotherham": "They therefore having come together, Pilate, said to them—Whom will ye I should release unto you? Barabbas? or Jesus, who is called Christ?", "weymouth": "So when they were now assembled Pilate appealed to them. \"Whom shall I release to you,\" he said, \"Barabbas, or Jesus the so-called Christ?\"", "darby": "They therefore being gathered together, Pilate said to them, Whom will ye that I release to you, Barabbas, or Jesus who is called Christ?", "twenty": "So, when the people had collected, Pilate said to them: “Which do you wish me to release for you? Barabbas? Or Jesus who is called ‘Christ’?”", "acv": "When therefore they were gathered together, Pilate said to them, Whom do ye want I should release to you? Barabbas, or Jesus who is called Christ?", "anderson": "Therefore, while they were together, Pilate said to them: Which do you wish me to release to you, Barabbas, or Jesus, who is called Christ?", "haweis": "Being therefore gathered around him, Pilate said to them, Whom will ye that I release unto you? Barabbas, or Jesus called Messiah?", "noyes": "When therefore they were assembled, Pilate said to them, Whom will ye that I release to you? Barabbas, or Jesus, who is called Christ?", "webster": "Therefore when they were assembled, Pilate said to them, Whom will ye that I release to you? Barabbas, or Jesus, who is called Christ?", "vulgate": "congregatis ergo illis dixit Pilatus quem vultis dimittam vobis Barabban an Iesum qui dicitur Christus;"}}, {"v": 18, "ref": "27:18", "o": "ᾔδει γὰρ ὅτι διὰ φθόνον παρέδωκαν αὐτόν.", "en": {"kjv": "For he knew that for envy they had delivered him.", "web": "For he knew that because of envy they had delivered him up.", "bsb": "For he knew it was out of envy that they had handed Jesus over to him.", "asv": "For he knew that for envy they had delivered him up.", "ylt": "for he had known that because of envy they had delivered him up.", "tyndale": "For he knewe well that for envie they had delivred him.", "dra": "For he knew that for envy they had delivered him.", "bbe": "For he saw that for envy they had given him up.", "geneva": "(For he knewe well, that for enuie they had deliuered him.", "wycliffe": "For he wiste, that bi enuye thei bitraieden hym.", "rotherham": "For he knew that, for envy, they had delivered him up.", "weymouth": "For he knew that it was from envious hatred that Jesus had been brought before him.", "darby": "For he knew that they had delivered him up through envy.", "twenty": "For he knew that it was out of jealousy that they had given Jesus up to him.", "acv": "For he knew that they delivered him up because of envy.", "anderson": "For he knew that through envy they had delivered him up.", "haweis": "For he knew that out of envy they had delivered him up.", "noyes": "For he knew that for envy they had delivered him up.", "webster": "(For he knew that for envy they had delivered him.)", "vulgate": "sciebat enim quod per invidiam tradidissent eum;"}}, {"v": 19, "ref": "27:19", "o": "Καθημένου δὲ αὐτοῦ ἐπὶ τοῦ βήματος ἀπέστειλεν πρὸς αὐτὸν ἡ γυνὴ αὐτοῦ λέγουσα· Μηδὲν σοὶ καὶ τῷ δικαίῳ ἐκείνῳ, πολλὰ γὰρ ἔπαθον σήμερον κατ’ ὄναρ δι’ αὐτόν.", "en": {"kjv": "When he was set down on the judgment seat, his wife sent unto him, saying, Have thou nothing to do with that just man: for I have suffered many things this day in a dream because of him.", "web": "While he was sitting on the judgment seat, his wife sent to him, saying, “Have nothing to do with that righteous man, for I have suffered many things this day in a dream because of him.”", "bsb": "While Pilate was sitting on the judgment seat, his wife sent him this message: “Have nothing to do with that innocent man, for I have suffered terribly in a dream today because of Him.”", "asv": "And while he was sitting on the judgment-seat, his wife sent unto him, saying, Have thou nothing to do with that righteous man; for I have suffered many things this day in a dream because of him.", "ylt": "And as he is sitting on the tribunal, his wife sent unto him, saying, `Nothing--to thee and to that righteous one, for many things did I suffer to-day in a dream because of him.'", "tyndale": "When he was set doune to geve iudgemet his wyfe sent to him sayinge: have thou nothinge to do with that iuste man. For I have suffered many thinges this daye in a dreame about him.", "dra": "And as he was sitting in the place of judgment, his wife sent to him, saying: Have thou nothing to do with that just man; for I have suffered many things this day in a dream because of him.", "bbe": "And while he was on the judge's seat, his wife sent to him, saying, Have nothing to do with that upright man, for I have had much trouble this day in a dream because of him.", "geneva": "Also when he was set downe vpon the iudgement seate, his wife sent to him, saying, Haue thou nothing to do with that iust man: for I haue suffered many things this day in a dreame by reason of him.)", "wycliffe": "And while he sat for domesman, his wijf sente to hym, and seide, No thing to thee and to that iust man; for Y haue suffrid this dai many thingis for hym, bi a visioun.", "rotherham": "And, as he was sitting upon the judgment seat, his wife sent unto him, saying: Have thou nothing to do with that righteous man, for, many things, have I suffered this day, by dream, because of him.", "weymouth": "While he was sitting on the tribunal a message came to him from his wife. \"Have nothing to do with that innocent man,\" she said, \"for during the night I have suffered terribly in a dream through him.\"", "darby": "But, as he was sitting on the judgment-seat, his wife sent to him, saying, Have thou nothing to do with that righteous [man]; for I have suffered to-day many things in a dream because of him.", "twenty": "While he was still on the Bench, his wife sent this message to him — “Do not have anything to do with that good man, for I have been very unhappy to-day in a dream on account of him.”", "acv": "And while he was sitting on the judgment seat, his wife sent to him, saying, There is nothing for thee and that righteous man. For I suffered many things this day in a dream because of him.", "anderson": "While he was sitting on the judgment-seat, his wife sent to him, saying: Have nothing to do with that just man, for I have suffered much to-day in a dream, because of him.", "haweis": "Then, as he was sitting on the tribunal, his wife sent a message to him, saying, Have thou nothing to do with that righteous person; for I have suffered much to-day in a dream on his account.", "noyes": "And while he was sitting on the judgment-seat, his wife sent to him, saying, Have nothing to do with that righteous man; for I have suffered much this day in a dream because of him.", "webster": "When he was sitting on the judgment-seat, his wife sent to him, saying, Have thou nothing to do with that just man: for I have suffered many things this day in a dream, because of him.", "vulgate": "sedente autem illo pro tribunali misit ad illum uxor eius dicens nihil tibi et iusto illi multa enim passa sum hodie per visum propter eum;"}}, {"v": 20, "ref": "27:20", "o": "Οἱ δὲ ἀρχιερεῖς καὶ οἱ πρεσβύτεροι ἔπεισαν τοὺς ὄχλους ἵνα αἰτήσωνται τὸν Βαραββᾶν τὸν δὲ Ἰησοῦν ἀπολέσωσιν.", "en": {"kjv": "But the chief priests and elders persuaded the multitude that they should ask Barabbas, and destroy Jesus.", "web": "Now the chief priests and the elders persuaded the multitudes to ask for Barabbas, and destroy Jesus.", "bsb": "But the chief priests and elders persuaded the crowds to ask for Barabbas and to have Jesus put to death.", "asv": "Now the chief priests and the elders persuaded the multitudes that they should ask for Barabbas, and destroy Jesus.", "ylt": "And the chief priests and the elders did persuade the multitudes that they might ask for themselves Barabbas, and might destroy Jesus;", "tyndale": "But the chefe preestes and the elders had parswaded the people that they shulde axe Barrabas and shulde destroye Iesus.", "dra": "But the chief priests and ancients persuaded the people that they should ask Barabbas and make Jesus away.", "bbe": "Now the chief priests and those in authority got the people to make request for Barabbas, and for Jesus to be put to death.", "geneva": "But the chiefe Priestes and the Elders had persuaded the people that they shoulde aske Barabbas, and should destroy Iesus.", "wycliffe": "Forsothe the prince of prestis, and the eldere men counseiliden the puple, that thei schulden axe Barabas, but thei schulden distrye Jhesu.", "rotherham": "But, the High-priests and the elders, persuaded the multitudes, that they should claim Barabbas, but, Jesus, should, destroy.", "weymouth": "The High Priests, however, and the Elders urged the crowd to ask for Barabbas and to demand the death of Jesus.", "darby": "But the chief priests and the elders persuaded the crowds that they should beg for Barabbas, and destroy Jesus.", "twenty": "But the Chief Priests and the Councillors persuaded the crowds to ask for Barabbas, and to kill Jesus.", "acv": "But the chief priests and the elders persuaded the multitudes that they should ask for Barabbas, and destroy Jesus.", "anderson": "But the chief priests and the elders persuaded the multitude to ask Barabbas, and destroy Jesus.", "haweis": "But the chief priests and elders persuaded the populace that they should ask for Barabbas, and destroy Jesus.", "noyes": "But the chief priests and the elders persuaded the multitudes to ask for Barabbas, and to destroy Jesus.", "webster": "But the chief priests and elders persuaded the multitude that they should ask Barabbas, and destroy Jesus.", "vulgate": "princeps autem sacerdotum et seniores persuaserunt populis ut peterent Barabban Iesum vero perderent;"}}, {"v": 21, "ref": "27:21", "o": "ἀποκριθεὶς δὲ ὁ ἡγεμὼν εἶπεν αὐτοῖς· Τίνα θέλετε ἀπὸ τῶν δύο ἀπολύσω ὑμῖν; οἱ δὲ εἶπαν· ⸀Τὸν Βαραββᾶν.", "en": {"kjv": "The governor answered and said unto them, Whether of the twain will ye that I release unto you? They said, Barabbas.", "web": "But the governor answered them, “Which of the two do you want me to release to you?” They said, “Barabbas!”", "bsb": "“Which of the two do you want me to release to you?” asked the governor. “Barabbas,” they replied.", "asv": "But the governor answered and said unto them, Which of the two will ye that I release unto you? And they said, Barabbas.", "ylt": "and the governor answering said to them, `Which of the two will ye that I shall release to you?' And they said, `Barabbas.'", "tyndale": "Then the debite answered and sayde vnto them: whether of the twayne wyll ye that I let loosse vnto you? And they sayde Barrabas.", "dra": "And the governor answering, said to them: Whether will you of the two to be released unto you? But they said: Barabbas.", "bbe": "But the ruler made answer and said to them, Which of the two is it your pleasure that I let go free? And they said, Barabbas.", "geneva": "Then the gouernour answered, and said vnto them, Whether of the twaine will ye that I let loose vnto you? And they said, Barabbas.", "wycliffe": "But the iustice answeride, and seide to hem, Whom of the tweyn wolen ye, that be delyuerit to you? And thei seiden, Barabas.", "rotherham": "Now the governor, answering, said unto them—Which of the two desire ye I should release unto you? And they said—Barabbas!", "weymouth": "So when the Governor a second time asked them, \"Which of the two shall I release to you?\" --they cried, \"Barabbas!\"", "darby": "And the governor answering said to them, Which of the two will ye that I release unto you? And they said, Barabbas.", "twenty": "The Governor, however, said to them: “Which of these two do you wish me to release for you?” “Barabbas,” they answered.", "acv": "Now the governor having answered, he said to them, Which of the two do ye want I would release to you? And they said, Barabbas.", "anderson": "The governor answered and said to them: Which of the two do you wish me to release to you? They replied: Barabbas.", "haweis": "The governor repeating the question, said to them, Which of the two will ye that I release unto you? They said Barabbas.", "noyes": "And the governor answering said to them, Which of the two will ye that I release to you? And they said, Barabbas.", "webster": "The governor answered and said to them, Which of the two will ye that I release to you? They said, Barabbas.", "vulgate": "respondens autem praeses ait illis quem vultis vobis de duobus dimitti at illi dixerunt Barabban;"}}, {"v": 22, "ref": "27:22", "o": "λέγει αὐτοῖς ὁ Πιλᾶτος· Τί οὖν ποιήσω Ἰησοῦν τὸν λεγόμενον χριστόν; ⸀λέγουσιν πάντες· Σταυρωθήτω.", "en": {"kjv": "Pilate saith unto them, What shall I do then with Jesus which is called Christ? They all say unto him, Let him be crucified.", "web": "Pilate said to them, “What then shall I do to Jesus, who is called Christ?” They all said to him, “Let him be crucified!”", "bsb": "“What then should I do with Jesus who is called Christ?” Pilate asked. They all answered, “Crucify Him!”", "asv": "Pilate saith unto them, What then shall I do unto Jesus who is called Christ? They all say, Let him be crucified.", "ylt": "Pilate saith to them, `What then shall I do with Jesus who is called Christ?' They all say to him, `Let be crucified!'", "tyndale": "Pilate sayde vnto them: what shall I do then with Iesus which is called Christ? They all sayde to him: let him be crucified.", "dra": "Pilate saith to them: What shall I do then with Jesus that is called Christ? They say all: Let him be crucified.", "bbe": "Pilate says to them, What, then, am I to do with Jesus, who is named Christ? They all say, Let him be put to death on the cross.", "geneva": "Pilate said vnto them, What shall I do then with Iesus, which is called Christ? They all said to him, Let him be crucified.", "wycliffe": "Pilat seith to hem, What thanne schal Y do of Jhesu, that is seid Crist?", "rotherham": "Pilate saith unto them—What then shall I do unto Jesus, who is called Christ? They all say—Let him be crucified!", "weymouth": "\"What then,\" said Pilate, \"shall I do with Jesus, the so-called Christ?\" With one voice they shouted, \"Let him be crucified!\"", "darby": "Pilate says to them, What then shall I do with Jesus, who is called Christ? They all say, Let him be crucified.", "twenty": "“What then,” Pilate asked, “shall I do with Jesus who is called ‘Christ?’ “Let him be crucified,” they all replied.", "acv": "Pilate says to them, What then shall I do to Jesus who is called Christ? They all say to him, He should be crucified.", "anderson": "Pilate said to them: What then shall I do with Jesus, who is called Christ? They all said to him: Let him be crucified.", "haweis": "Pilate saith unto them, What then shall I do with Jesus, who is called the Messiah? They all say to him, Let him be crucified.", "noyes": "Pilate saith to them, What then shall I do with Jesus, who is called Christ? They all say, Let him be crucified.", "webster": "Pilate saith to them, What shall I do then with Jesus, who is called Christ? [They] all say to him, Let him be crucified.", "vulgate": "dicit illis Pilatus quid igitur faciam de Iesu qui dicitur Christus;"}}, {"v": 23, "ref": "27:23", "o": "ὁ ⸀δὲ ἔφη· Τί γὰρ κακὸν ἐποίησεν; οἱ δὲ περισσῶς ἔκραζον λέγοντες· Σταυρωθήτω.", "en": {"kjv": "And the governor said, Why, what evil hath he done? But they cried out the more, saying, Let him be crucified.", "web": "But the governor said, “Why? What evil has he done?” But they cried out exceedingly, saying, “Let him be crucified!”", "bsb": "“Why?” asked Pilate. “What evil has He done?” But they shouted all the louder, “Crucify Him!”", "asv": "And he said, Why, what evil hath he done? But they cried out exceedingly, saying, Let him be crucified.", "ylt": "And the governor said, `Why, what evil did he?' and they were crying out the more, saying, `Let be crucified.'", "tyndale": "Then sayde the debite: what evyll hath he done? And they cryed the more sayinge: let him be crucified.", "dra": "The governor said to them: Why, what evil hath he done? But they cried out the more, saying: Let him be crucified.", "bbe": "And he said, Why, what evil has he done? But they gave loud cries, saying, To the cross with him!", "geneva": "Then saide the gouernour, But what euill hath he done? Then they cryed the more, saying, Let him be crucified.", "wycliffe": "Alle seien, `Be he crucified. The iustice seith to hem, What yuel hath he doon? And thei crieden more, and seiden, Be he crucified.", "rotherham": "But, he, said—Indeed! what evil hath he done? But, they, vehemently, were crying aloud, saying—Let him be crucified!", "weymouth": "\"Why, what crime has he committed?\" asked Pilate. But they kept on furiously shouting, \"Let him be crucified!\"", "darby": "And the governor said, What evil then has he done? But they cried more than ever, saying, Let him be crucified.", "twenty": "“Why, what harm has he done?” he asked. But they kept shouting furiously: “Let him be crucified!”", "acv": "And the governor said, For what evil has he done? But they cried out even more, saying, He should be crucified.", "anderson": "But the governor said: Why, what evil has he done? But they cried vehemently, saying: Let him be crucified.", "haweis": "The governor replied, But what evil hath he done? They cried out with greater vehemence, saying, Let him be crucified.", "noyes": "And he said, Why, what evil hath he done? But they cried out the more, saying, Let him be crucified.", "webster": "And the governor said, Why, what evil hath he done? But they cried out the more, saying, Let him be crucified.", "vulgate": "dicunt omnes crucifigatur ait illis praeses quid enim mali fecit at illi magis clamabant dicentes crucifigatur;"}}, {"v": 24, "ref": "27:24", "o": "ἰδὼν δὲ ὁ Πιλᾶτος ὅτι οὐδὲν ὠφελεῖ ἀλλὰ μᾶλλον θόρυβος γίνεται λαβὼν ὕδωρ ἀπενίψατο τὰς χεῖρας ⸀ἀπέναντι τοῦ ὄχλου λέγων· Ἀθῷός εἰμι ἀπὸ τοῦ ⸀αἵματος τούτου· ὑμεῖς ὄψεσθε.", "en": {"kjv": "When Pilate saw that he could prevail nothing, but that rather a tumult was made, he took water, and washed his hands before the multitude, saying, I am innocent of the blood of this just person: see ye to it.", "web": "So when Pilate saw that nothing was being gained, but rather that a disturbance was starting, he took water, and washed his hands before the multitude, saying, “I am innocent of the blood of this righteous person. You see to it.”", "bsb": "When Pilate saw that he was accomplishing nothing, but that instead a riot was breaking out, he took water and washed his hands before the crowd. “I am innocent of this man’s blood,” he said. “You bear the responsibility.”", "asv": "So when Pilate saw that he prevailed nothing, but rather that a tumult was arising, he took water, and washed his hands before the multitude, saying, I am innocent of the blood of this righteous man; see ye to it.", "ylt": "And Pilate having seen that it profiteth nothing, but rather a tumult is made, having taken water, he did wash the hands before the multitude, saying, `I am innocent from the blood of this righteous one; ye--ye shall see;'", "tyndale": "When Pilate sawe that he prevayled nothinge but that moare busines was made he toke water and wasshed his hondes before ye people sayinge: I am innocent of the bloud of this iuste person and that ye shall se.", "dra": "And Pilate seeing that he prevailed nothing, but that rather a tumult was made, taking water washed his hands before the people, saying: I am innocent of the blood of this just man. Look you to it.", "bbe": "So when Pilate saw that he was able to do nothing, but that trouble was working up, he took water and, washing his hands before the people, said, The blood of this upright man is not on my hands: you are responsible.", "geneva": "When Pilate saw that he auailed nothing, but that more tumult was made, he tooke water and washed his hands before the multitude, saying, I am innocent of the blood of this iust man: looke you to it.", "wycliffe": "And Pilat seynge that he profitide no thing, but that the more noyse was maad, took watir, and waischide hise hondis bifor the puple, and seide, Y am giltles of the blood of this riytful man; bise you.", "rotherham": "And Pilate, seeing, that, nothing, it availed, but rather, a tumult, was arising, taking water, washed his hands of it before the multitude, saying—Innocent, am I, of the blood of this man,—Ye, shall see to it for yourselves.", "weymouth": "So when he saw that he could gain nothing, but that on the contrary there was a riot threatening, he called for water and washed his hands in sight of them all, saying, \"I am not responsible for this murder: you must answer for it.\"", "darby": "And Pilate, seeing that it availed nothing, but that rather a tumult was arising, having taken water, washed his hands before the crowd, saying, I am guiltless of the blood of this righteous one: see ye [to it].", "twenty": "When Pilate saw that his efforts were unavailing, but that, on the contrary, a riot was beginning, he took some water, and washed his hands in the sight of the crowd, saying as he did so: “I am not answerable for this bloodshed; you must see to it yourselves.”", "acv": "And when Pilate saw that he was accomplishing nothing, but rather an uproar was developing, after taking water, he washed his hands in front of the multitude, saying, I am innocent of the blood of this righteous man. See ye to it.", "anderson": "When Pilate saw that he gained nothing, but rather that a tumult was rising, he took water, and washed his hands before the multitude, and said: I am innocent of the blood of this just man; you will see to it.", "haweis": "When Pilate saw that it was of no use to contend, but that rather a tumult was rising, he took water, and washed his hands before the people, saying, I am innocent of the blood of this righteous man: ye must answer for it.", "noyes": "And when Pilate saw that it availed nothing, but that rather a tumult was arising, he took water, and washed his hands before the multitude, saying, I am innocent of this blood; see ye to it.", "webster": "When Pilate saw that he could not prevail at all, but [that] rather a tumult was made, he took water, and washed [his] hands before the multitude, saying, I am innocent of the blood of this just person: see ye [to it].", "vulgate": "videns autem Pilatus quia nihil proficeret sed magis tumultus fieret accepta aqua lavit manus coram populo dicens innocens ego sum a sanguine iusti huius vos videritis;"}}, {"v": 25, "ref": "27:25", "o": "καὶ ἀποκριθεὶς πᾶς ὁ λαὸς εἶπεν· Τὸ αἷμα αὐτοῦ ἐφ’ ἡμᾶς καὶ ἐπὶ τὰ τέκνα ἡμῶν.", "en": {"kjv": "Then answered all the people, and said, His blood be on us, and on our children.", "web": "All the people answered, “May his blood be on us, and on our children!”", "bsb": "All the people answered, “His blood be on us and on our children!”", "asv": "And all the people answered and said, His blood be on us, and on our children.", "ylt": "and all the people answering said, `His blood is upon us, and upon our children!'", "tyndale": "Then answered all the people and sayde: his bloud be on vs and on oure chyldren.", "dra": "And the whole people answering, said: His blood be upon us and upon our children.", "bbe": "And all the people made answer and said, Let his blood be on us, and on our children.", "geneva": "Then answered all the people, and saide, His bloud be on vs, and on our children.", "wycliffe": "And al the puple answeride, and seide, His blood be on vs, and on oure children.", "rotherham": "And all the people, answering, said—His blood be upon us and upon our children!", "weymouth": "\"His blood,\" replied all the people, \"be on us and on our children!\"", "darby": "And all the people answering said, His blood [be] on us and on our children.", "twenty": "And all the people answered: “His blood be on our heads and on our children’s!”", "acv": "And having answered, all the people said, His blood be on us, and on our children.", "anderson": "And all the people answered and said: His blood be upon us and upon our children.", "haweis": "Then all the people answering said, His blood be on us, and on our children.", "noyes": "And all the people answering said, His blood be on us, and on our children.", "webster": "Then answered all the people, and said, His blood [be] on us, and on our children.", "vulgate": "et respondens universus populus dixit sanguis eius super nos et super filios nostros;"}}, {"v": 26, "ref": "27:26", "o": "τότε ἀπέλυσεν αὐτοῖς τὸν Βαραββᾶν, τὸν δὲ Ἰησοῦν φραγελλώσας παρέδωκεν ἵνα σταυρωθῇ.", "en": {"kjv": "Then released he Barabbas unto them: and when he had scourged Jesus, he delivered him to be crucified.", "web": "Then he released to them Barabbas, but Jesus he flogged and delivered to be crucified.", "bsb": "So Pilate released Barabbas to them. But he had Jesus flogged, and handed Him over to be crucified.", "asv": "Then released he unto them Barabbas; but Jesus he scourged and delivered to be crucified.", "ylt": "Then did he release to them Barabbas, and having scourged Jesus, he delivered him up that he may be crucified;", "tyndale": "Then let he Barrabas loose vnto them and scourged Iesus and delivered him to be crucified.", "dra": "Then he released to them Barabbas: and having scourged Jesus, delivered him unto them to be crucified.", "bbe": "Then he let Barabbas go free: but after having Jesus whipped, he gave him up to be put to death on the cross.", "geneva": "Thus let he Barabbas loose vnto them, and scourged Iesus, and deliuered him to be crucified.", "wycliffe": "Thanne he deliuerede to hem Barabas, but he took to hem Jhesu scourgid, to be crucified.", "rotherham": "Then released he unto them Barabbas, but, scourging, Jesus, delivered him up, that he might be crucified.", "weymouth": "Then he released Barabbas to them, but Jesus he ordered to be scourged, and gave Him up to be crucified.", "darby": "Then he released to them Barabbas; but Jesus, having scourged [him], he delivered up that he might be crucified.", "twenty": "The Pilate released Barabbas to them; but Jesus he scourged, and gave him up to be crucified.", "acv": "Then he released Barabbas to them, and having scourged Jesus he delivered him so that he would be crucified.", "anderson": "Then he released to them Barabbas; but after he had scourged Jesus, he delivered him up to be crucified.", "haweis": "Then he released unto them Barabbas: but having scourged Jesus, he delivered him up to be crucified.", "noyes": "Then he released Barabbas to them, and having scourged Jesus, he delivered him up to be crucified.", "webster": "Then he released Barabbas to them: and when he had scourged Jesus, he delivered [him] to be crucified.", "vulgate": "tunc dimisit illis Barabban Iesum autem flagellatum tradidit eis ut crucifigeretur;"}}, {"v": 27, "ref": "27:27", "o": "Τότε οἱ στρατιῶται τοῦ ἡγεμόνος παραλαβόντες τὸν Ἰησοῦν εἰς τὸ πραιτώριον συνήγαγον ἐπ’ αὐτὸν ὅλην τὴν σπεῖραν.", "en": {"kjv": "Then the soldiers of the governor took Jesus into the common hall, and gathered unto him the whole band of soldiers.", "web": "Then the governor’s soldiers took Jesus into the Praetorium, and gathered the whole garrison together against him.", "bsb": "Then the governor’s soldiers took Jesus into the Praetorium and gathered the whole company around Him.", "asv": "Then the soldiers of the governor took Jesus into the Prætorium, and gathered unto him the whole band.", "ylt": "then the soldiers of the governor having taken Jesus to the Praetorium, did gather to him all the band;", "tyndale": "Then the soudeours of the debite toke Iesus vnto the comen hall and gaddered vnto him all the company.", "dra": "Then the soldiers of the governor, taking Jesus into the hall, gathered together unto him the whole band.", "bbe": "Then the ruler's armed men took Jesus into the open square, and got all their band together.", "geneva": "Then the souldiers of the gouernour tooke Iesus into the common hall, and gathered about him the whole band,", "wycliffe": "Thanne knyytis of the iustice token Jhesu in the moot halle, and gadriden to hym al the cumpeny `of knyytis.", "rotherham": "Then the soldiers of the governor, taking Jesus aside into the judgment-hall, gathered unto him all the band;", "weymouth": "Then the Governor's soldiers took Jesus into the Praetorium, and called together the whole battalion to make sport of Him.", "darby": "Then the soldiers of the governor, having taken Jesus with [them] to the praetorium, gathered against him the whole band,", "twenty": "After that, the Governor’s soldiers took Jesus with them into the Government House, and gathered the whole garrison round him.", "acv": "Then the soldiers of the governor, having taken Jesus into the Praetorium, gathered the whole band to him.", "anderson": "Then the soldiers of the governor took Jesus into the palace, and brought together to him the whole band.", "haweis": "Thereupon the soldiers of the governor taking Jesus away to the Praetorium, gathered around him the whole band:", "noyes": "Then the soldiers of the governor took Jesus into the governor’s palace, and gathered to him the whole band.", "webster": "Then the soldiers of the governor took Jesus into the common hall, and gathered to him the whole band [of soldiers].", "vulgate": "tunc milites praesidis suscipientes Iesum in praetorio congregaverunt ad eum universam cohortem;"}}, {"v": 28, "ref": "27:28", "o": "καὶ ἐκδύσαντες αὐτὸν ⸂χλαμύδα κοκκίνην περιέθηκαν αὐτῷ⸃,", "en": {"kjv": "And they stripped him, and put on him a scarlet robe.", "web": "They stripped him, and put a scarlet robe on him.", "bsb": "They stripped Him and put a scarlet robe on Him.", "asv": "And they stripped him, and put on him a scarlet robe.", "ylt": "and having unclothed him, they put around him a crimson cloak,", "tyndale": "And they stripped him and put on him a purpyll roobe", "dra": "And stripping him, they put a scarlet cloak about him.", "bbe": "And they took off his clothing, and put on him a red robe.", "geneva": "And they stripped him, and put about him a skarlet robe,", "wycliffe": "And thei vnclothiden hym, and diden aboute hym a reed mantil;", "rotherham": "and, unclothing him, a scarlet scarf, put they about him,—", "weymouth": "Stripping off His garments, they put on Him a general's short crimson cloak.", "darby": "and having taken off his garment, put on him a scarlet cloak;", "twenty": "They stripped him, and put on him a red military cloak,", "acv": "And having stripped him, they put a scarlet robe on him.", "anderson": "And they stripped him, and put on him a scarlet cloak;", "haweis": "and stripping him, put about him a scarlet cloak.", "noyes": "And they stripped him, and put on him a scarlet robe.", "webster": "And they stripped him, and put on him a scarlet robe.", "vulgate": "et exuentes eum clamydem coccineam circumdederunt ei;"}}, {"v": 29, "ref": "27:29", "o": "καὶ πλέξαντες στέφανον ἐξ ἀκανθῶν ἐπέθηκαν ἐπὶ ⸂τῆς κεφαλῆς⸃ αὐτοῦ καὶ κάλαμον ⸂ἐν τῇ δεξιᾷ⸃ αὐτοῦ, καὶ γονυπετήσαντες ἔμπροσθεν αὐτοῦ ⸀ἐνέπαιξαν αὐτῷ λέγοντες· Χαῖρε, ⸀βασιλεῦ τῶν Ἰουδαίων,", "en": {"kjv": "And when they had platted a crown of thorns, they put it upon his head, and a reed in his right hand: and they bowed the knee before him, and mocked him, saying, Hail, King of the Jews!", "web": "They braided a crown of thorns and put it on his head, and a reed in his right hand; and they kneeled down before him, and mocked him, saying, “Hail, King of the Jews!”", "bsb": "And they twisted together a crown of thorns and set it on His head. They put a staff in His right hand and knelt down before Him to mock Him, saying, “Hail, King of the Jews!”", "asv": "And they platted a crown of thorns and put it upon his head, and a reed in his right hand; and they kneeled down before him, and mocked him, saying, Hail, King of the Jews!", "ylt": "and having plaited him a crown out of thorns they put it on his head, and a reed in his right hand, and having kneeled before him, they were mocking him, saying, `Hail, the king of the Jews.'", "tyndale": "and platted a croune of thornes and put vpon his heed and a rede in his ryght honde: and bowed their knees before him and mocked him saying: hayle kinge of the Iewes:", "dra": "And platting a crown of thorns, they put it upon his head, and a reed in his right hand. And bowing the knee before him, they mocked him, saying: Hail, King of the Jews.", "bbe": "And they made a crown of thorns and put it on his head, and put a rod in his right hand, and they went down on their knees before him, and made sport of him, saying, Long life to the King of the Jews.", "geneva": "And platted a crowne of thornes, and put it vpon his head, and a reede in his right hand, and bowed their knees before him, and mocked him, saying, God saue thee King of the Iewes,", "wycliffe": "and thei foldiden a coroun of thornes, and putten on his heed, and a rehed in his riyt hoond; and thei kneliden bifore hym, and scornyden hym, and seiden, Heil, kyng of Jewis.", "rotherham": "and, plaiting a crown out of thorns, they put it upon his head, and a reed in his right hand,—and, kneeling before him, began to mock him, saying—Joy to thee, King of the Jews!", "weymouth": "They twisted a wreath of thorny twigs and put it on His head, and they put a sceptre of cane in His right hand, and kneeling to Him they shouted in mockery, \"Long live the King of the Jews!\"", "darby": "and having woven a crown out of thorns, they put it on his head, and a reed in his right hand; and, bowing the knee before him, they mocked him, saying, Hail, King of the Jews!", "twenty": "and having twisted some thorns into a crown, put it on his head, and a rod in his right hand, and then, going down on their knees before him, they mocked him. “Long life to you, King of the Jews!” they said.", "acv": "And having woven a crown of thorns, they put it upon his head, and a reed in his right hand. And having knelt down before him, they ridiculed him, saying, Hail, king of the Jews!", "anderson": "and when they had plaited a crown of thorn branches, they put it upon his head, and a reed in his right hand; and kneeling before him, they derided him, saying: Hail, King of the Jews!", "haweis": "And platting a crown of thorns, they placed it on his head, and a cane in his right hand: and bowing the knee before him, mocked him, saying, Hail, king of the Jews!", "noyes": "And having platted a crown of thorns, they put it on his head, and a reed in his right hand; and bowing the knee before him, they mocked him, saying, Hail, king of the Jews!", "webster": "And when they had platted a crown of thorns, they put [it] upon his head, and a reed in his right hand: and they bowed the knee before him, and mocked him, saying, Hail, King of the Jews?", "vulgate": "et plectentes coronam de spinis posuerunt super caput eius et harundinem in dextera eius et genu flexo ante eum inludebant dicentes have rex Iudaeorum;"}}, {"v": 30, "ref": "27:30", "o": "καὶ ἐμπτύσαντες εἰς αὐτὸν ἔλαβον τὸν κάλαμον καὶ ἔτυπτον εἰς τὴν κεφαλὴν αὐτοῦ.", "en": {"kjv": "And they spit upon him, and took the reed, and smote him on the head.", "web": "They spat on him, and took the reed and struck him on the head.", "bsb": "Then they spit on Him and took the staff and struck Him on the head repeatedly.", "asv": "And they spat upon him, and took the reed and smote him on the head.", "ylt": "And having spit on him, they took the reed, and were smiting on his head;", "tyndale": "and spitted vpon him and toke the rede and smoote him on the heed.", "dra": "And spitting upon him, they took the reed and struck his head.", "bbe": "And they put shame on him, and gave him blows on the head with the rod.", "geneva": "And spitted vpon him, and tooke a reede, and smote him on the head.", "wycliffe": "And thei speten on hym, and tooken a rehed, and smoot his heed.", "rotherham": "And, spitting upon him, they took the reed, and began striking upon his head.", "weymouth": "Then they spat upon Him, and taking the cane they repeatedly struck Him on the head with it.", "darby": "And having spit upon him, they took the reed and beat [him] on his head.", "twenty": "They spat at him and, taking the rod, kept striking him on the head;", "acv": "And having spat upon him, they took the reed and were striking him on his head.", "anderson": "And they spit upon him, and took the reed, and struck him on the head.", "haweis": "And spitting upon him, they took the cane, and struck him upon his head.", "noyes": "And they spit upon him, and took the reed and struck him on the head.", "webster": "And they spit upon him, and took the reed, and struck him on the head.", "vulgate": "et expuentes in eum acceperunt harundinem et percutiebant caput eius;"}}, {"v": 31, "ref": "27:31", "o": "καὶ ὅτε ἐνέπαιξαν αὐτῷ, ἐξέδυσαν αὐτὸν τὴν χλαμύδα καὶ ἐνέδυσαν αὐτὸν τὰ ἱμάτια αὐτοῦ καὶ ἀπήγαγον αὐτὸν εἰς τὸ σταυρῶσαι.", "en": {"kjv": "And after that they had mocked him, they took the robe off from him, and put his own raiment on him, and led him away to crucify him.", "web": "When they had mocked him, they took the robe off of him, and put his clothes on him, and led him away to crucify him.", "bsb": "After they had mocked Him, they removed the robe and put His own clothes back on Him. Then they led Him away to crucify Him.", "asv": "And when they had mocked him, they took off from him the robe, and put on him his garments, and led him away to crucify him.", "ylt": "and when they had mocked him, they took off from him the cloak, and put on him his own garments, and led him away to crucify him .", "tyndale": "And when they had mocked him they toke the robe of him ageyne and put his awne reymet on him and leed him awaye to crucify him.", "dra": "And after they had mocked him, they took off the cloak from him and put on him his own garments and led him away to crucify him.", "bbe": "And when they had made sport of him, they took the robe off him, and put his clothing on him, and took him away to put him on the cross.", "geneva": "Thus when they had mocked him, they tooke the robe from him, and put his owne rayment on him, and led him away to crucifie him.", "wycliffe": "And aftir that thei hadden scorned him, thei vnclothiden hym of the mantil, and thei clothiden hym with hise clothis, and ledden hym to `crucifien hym.", "rotherham": "And, when they had mocked him, they put off him the scarf, and put on him his garments, and led him away unto the crucifying.", "weymouth": "At last, having finished their sport, they took off the cloak, clothed Him again in His own garments, and led Him away for crucifixion.", "darby": "And when they had mocked him, they took the cloak off him, and put his own clothes on him, and led him away to crucify.", "twenty": "and, when they had left off mocking him, they took off the military cloak, and put his own clothes on him, and led him away to be crucified.", "acv": "And after they ridiculed him, they took the robe off of him, and put his clothes on him, and led him away in order to crucify.", "anderson": "And when they had derided him, they took off the cloak from him, and put his own clothes on him, and led him away to crucify him.", "haweis": "And when they had insulted him, they took off from him the cloak, and put his own garments on him, and led him away to crucify him.", "noyes": "And after they had made sport of him, they took off the robe from him, and put on him his own garments, and led him away to crucify him.", "webster": "And after that they had mocked him, they took the robe off from him, and put his own raiment on him, and led him away to crucify [him].", "vulgate": "et postquam inluserunt ei exuerunt eum clamydem et induerunt eum vestimentis eius et duxerunt eum ut crucifigerent;"}}, {"v": 32, "ref": "27:32", "o": "Ἐξερχόμενοι δὲ εὗρον ἄνθρωπον Κυρηναῖον ὀνόματι Σίμωνα· τοῦτον ἠγγάρευσαν ἵνα ἄρῃ τὸν σταυρὸν αὐτοῦ.", "en": {"kjv": "And as they came out, they found a man of Cyrene, Simon by name: him they compelled to bear his cross.", "web": "As they came out, they found a man of Cyrene, Simon by name, and they compelled him to go with them, that he might carry his cross.", "bsb": "Along the way they found a man from Cyrene, named Simon, and they forced him to carry the cross of Jesus.", "asv": "And as they came out, they found a man of Cyrene, Simon by name: him they compelled to go with them, that he might bear his cross.", "ylt": "And coming forth, they found a man, a Cyrenian, by name Simon: him they impressed that he might bear his cross;", "tyndale": "And as they came out they fonnde a man of Cyren named Simon: him they compelled to beare his crosse.", "dra": "And going out, they found a man of Cyrene, named Simon: him they forced to take up his cross.", "bbe": "And while they were coming out, they saw a man of Cyrene, Simon by name, and they made him go with them, so that he might take up his cross.", "geneva": "And as they came out, they found a man of Cyrene, named Simon: him they compelled to beare his crosse.", "wycliffe": "And as thei yeden out, thei founden a man of Cirenen comynge fro the toun, Symont bi name; thei constreyneden hym to take his cross.", "rotherham": "And, as they were going forth, they found a man of Cyrene, by name, Simon,—the same, they impressed to bear his cross.", "weymouth": "Going out they met a Cyrenaean named Simon; whom they compelled to carry His cross,", "darby": "And as they went forth they found a man of Cyrene, Simon by name; him they compelled to go [with them] that he might bear his cross.", "twenty": "As they were on their way out, they came upon a man from Cyrene of the name of Simon; and they compelled him to go with them to carry the cross.", "acv": "And while coming out, they found a man of Cyrene, Simon by name. They drafted this man, so that he might take his cross.", "anderson": "And as they were going out, they found a man of Cyrene, named Simon: this man they compelled to carry his cross.", "haweis": "And as they were going out, they found a man of Cyrene, Simon by name; him they compelled to carry his cross.", "noyes": "And as they were going out, they found a man of Cyrene, Simon by name, whom they compelled to carry his cross.", "webster": "And as they came out, they found a man of Cyrene, Simon by name: him they constrained to bear his cross.", "vulgate": "exeuntes autem invenerunt hominem cyreneum nomine Simonem hunc angariaverunt ut tolleret crucem eius;"}}, {"v": 33, "ref": "27:33", "o": "Καὶ ἐλθόντες εἰς τόπον λεγόμενον Γολγοθᾶ, ὅ ἐστιν ⸂Κρανίου Τόπος λεγόμενος⸃,", "en": {"kjv": "And when they were come unto a place called Golgotha, that is to say, a place of a skull,", "web": "They came to a place called “Golgotha”, that is to say, “The place of a skull.”", "bsb": "And when they came to a place called Golgotha, which means The Place of the Skull,", "asv": "And when they were come unto a place called Golgotha, that is to say, The place of a skull,", "ylt": "and having come to a place called Golgotha, that is called Place of a Skull,", "tyndale": "And whe they cam vnto ye place called Golgotha (that is to saye a place of deed mens sculles)", "dra": "And they came to the place that is called Golgotha, which is the place of Calvary.", "bbe": "And when they came to the place named Golgotha, that is to say, Dead Man's Head,", "geneva": "And when they came vnto the place called Golgotha, (that is to say, the place of dead mens skulles)", "wycliffe": "And thei camen in to a place that is clepid Golgatha, that is, the place of Caluarie.", "rotherham": "And, coming into a place called Golgotha, that is to say, Skull-place,", "weymouth": "and so they came to a place called Golgotha, which means `Skull-ground.'", "darby": "And having come to a place called Golgotha, which means Place of a skull,", "twenty": "On reaching a place named Golgotha (a place named from its likeness to a skull),", "acv": "And having come to a place called Golgotha, that is called, the place of a skull,", "anderson": "And when they had come to a place called Golgotha, which, when translated, is the place of a skull,", "haweis": "And when they were come to a place called Golgotha (which is called the place of a skull),", "noyes": "And having come to a place called Golgotha, that is, Place of a Skull,", "webster": "And when they had come to a place called Golgotha, that is to say, a place of a skull,", "vulgate": "et venerunt in locum qui dicitur Golgotha quod est Calvariae locus;"}}, {"v": 34, "ref": "27:34", "o": "ἔδωκαν αὐτῷ πιεῖν ⸀οἶνον μετὰ χολῆς μεμιγμένον· καὶ γευσάμενος οὐκ ⸀ἠθέλησεν πιεῖν.", "en": {"kjv": "They gave him vinegar to drink mingled with gall: and when he had tasted thereof, he would not drink.", "web": "They gave him sour wine to drink mixed with gall. When he had tasted it, he would not drink.", "bsb": "they offered Him wine to drink, mixed with gall; but after tasting it, He refused to drink it.", "asv": "they gave him wine to drink mingled with gall: and when he had tasted it, he would not drink.", "ylt": "they gave him to drink vinegar mixed with gall, and having tasted, he would not drink.", "tyndale": "they gave him veneger to drinke mengled with gall. And when he had tasted therof he wolde not drinke.", "dra": "And they gave him wine to drink mingled with gall. And when he had tasted, he would not drink.", "bbe": "They gave him wine mixed with bitter drink: and after tasting it, he took no more.", "geneva": "They gaue him vineger to drinke, mingled with gall: and when he had tasted thereof, he would not drinke.", "wycliffe": "And thei yauen hym to drynke wyne meynd with galle; and whanne he hadde tastid, he wolde not drynke.", "rotherham": "they gave him to drink, wine, with gall, mingled, and, tasting, he would not drink.", "weymouth": "Here they gave Him a mixture of wine and gall to drink, but having tasted it He refused to drink it.", "darby": "they gave to him to drink vinegar mingled with gall; and having tasted [it], he would not drink.", "twenty": "they gave him some wine to drink which had been mixed with gall; but after tasting it, Jesus refused to drink it.", "acv": "they gave him vinegar to drink mingled with gall. And having tasted it, he would not drink.", "anderson": "they gave him vinegar to drink, mingled with gall; and when he had tasted it, he refused to drink.", "haweis": "they gave him vinegar to drink mingled with gall: and having tasted it, he refused to drink.", "noyes": "they gave him wine to drink mingled with gall; and when he had tasted it, he refused to drink.", "webster": "They gave him vinegar to drink, mingled with gall: and when he had tasted [of it], he would not drink.", "vulgate": "et dederunt ei vinum bibere cum felle mixtum et cum gustasset noluit bibere;"}}, {"v": 35, "ref": "27:35", "o": "σταυρώσαντες δὲ αὐτὸν διεμερίσαντο τὰ ἱμάτια αὐτοῦ βάλλοντες κλῆρον,", "en": {"kjv": "And they crucified him, and parted his garments, casting lots: that it might be fulfilled which was spoken by the prophet, They parted my garments among them, and upon my vesture did they cast lots.", "web": "When they had crucified him, they divided his clothing among them, casting lots,", "bsb": "When they had crucified Him, they divided up His garments by casting lots.", "asv": "And when they had crucified him, they parted his garments among them, casting lots;", "ylt": "And having crucified him, they divided his garments, casting a lot, that it might be fulfilled that was spoken by the prophet, `They divided my garments to themselves, and over my vesture they cast a lot;'", "tyndale": "When they had crucified him they parted his garmentes and did cast lottes: to fulfyll that was spoken by the prophet. They deuyded my garmetes amonge them: and apon my vesture did cast loottes.", "dra": "And after they had crucified him, they divided his garments, casting lots; that it might be fulfilled which was spoken by the prophet, saying: They divided my garments among them; and upon my vesture they cast lots.", "bbe": "And when they had put him on the cross, they made division of his clothing among them by the decision of chance.", "geneva": "And when they had crucified him, they parted his garments, and did cast lottes, that it might be fulfilled, which was spoken by the Prophet, They deuided my garments among them, and vpon my vesture did cast lottes.", "wycliffe": "And aftir that thei hadden crucified hym, thei departiden his clothis, and kesten lotte, to fulfille that is seid bi the prophete, seiynge, Thei partiden to hem my clothis, and on my clooth thei kesten lott.", "rotherham": "And, having crucified him, they parted among themselves his garments, casting a cloth;", "weymouth": "After crucifying Him, they divided His garments among them by lot,", "darby": "And having crucified him, they parted his clothes amongst [themselves], casting lots.", "twenty": "When they had crucified him, they divided his clothes among them by casting lots.", "acv": "And when they crucified him, they divided his garments, casting a lot.", "anderson": "And when they had crucified him, they divided his clothing among themselves, by casting the lot.", "haweis": "Then having crucified him, they parted his garments, casting the lot: that it might be fulfilled, what was spoken by the prophet, They parted my garments among them, and for my vesture they threw the lot.", "noyes": "And when they had crucified him, they divided his garments among them, casting lots.", "webster": "And they crucified him, and parted his garments, casting lots: that it might be fulfilled which was spoken by the prophet, They parted my garments among them, and upon my vesture they cast lots.", "vulgate": "postquam autem crucifixerunt eum diviserunt vestimenta eius sortem mittentes;"}}, {"v": 36, "ref": "27:36", "o": "καὶ καθήμενοι ἐτήρουν αὐτὸν ἐκεῖ.", "en": {"kjv": "And sitting down they watched him there;", "web": "and they sat and watched him there.", "bsb": "And sitting down, they kept watch over Him there.", "asv": "and they sat and watched him there.", "ylt": "and sitting down, they were watching him there,", "tyndale": "And they sate and watched him there.", "dra": "And they sat and watched him.", "bbe": "And they were seated there watching him.", "geneva": "And they sate, and watched him there.", "wycliffe": "And thei seten, and kepten him;", "rotherham": "and, being seated, were watching him there.", "weymouth": "and sat down there on guard.", "darby": "And sitting down, they kept guard over him there.", "twenty": "Then they sat down, and kept watch over him there.", "acv": "And as they sat, they keep watch over him there.", "anderson": "And they sat down and watched him there.", "haweis": "And sitting down, they guarded him there.", "noyes": "And sitting down, they watched him there.", "webster": "And sitting down, they watched him there:", "vulgate": "et sedentes servabant eum;"}}, {"v": 37, "ref": "27:37", "o": "καὶ ἐπέθηκαν ἐπάνω τῆς κεφαλῆς αὐτοῦ τὴν αἰτίαν αὐτοῦ γεγραμμένην· Οὗτός ἐστιν Ἰησοῦς ὁ βασιλεὺς τῶν Ἰουδαίων.", "en": {"kjv": "And set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.", "web": "They set up over his head the accusation against him written, “THIS IS JESUS, THE KING OF THE JEWS.”", "bsb": "Above His head they posted the written charge against Him: THIS IS JESUS, THE KING OF THE JEWS.", "asv": "And they set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.", "ylt": "and they put up over his head, his accusation written, `This is Jesus, the king of the Jews.'", "tyndale": "And they set vp over his heed the cause of his deeth written. This is Iesus the kynge of the Iewes.", "dra": "And they put over his head his cause written: THIS IS JESUS THE KING OF THE JEWS.", "bbe": "And they put up over his head the statement of his crime in writing, THIS IS JESUS THE KING OF THE JEWS.", "geneva": "They set vp also ouer his head his cause written, THIS IS IESVS THE KING OF THE IEVVES.", "wycliffe": "and setten aboue his heed his cause writun, This is Jhesu of Nazareth, kyng of Jewis.", "rotherham": "And they put up, over his head, his accusation, written—THIS, IS JESUS, THE KING OF THE JEWS.", "weymouth": "Over His head they placed a written statement of the charge against Him: THIS IS JESUS THE KING OF THE JEWS.", "darby": "And they set up over his head his accusation written: This is Jesus, the King of the Jews.", "twenty": "Above his head they fixed the accusation against him written out — ‘THIS IS JESUS THE KING OF THE JEWS.’", "acv": "And they set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.", "anderson": "And they placed above his head the charge that was made against him, written: THIS IS JESUS THE KING OF THE JEWS.", "haweis": "And they placed over his head his accusation in writing, THIS IS JESUS THE KING OF THE JEWS.", "noyes": "And they set up over his head the charge against him in writing: \"This is Jesus the king of the Jews.\"", "webster": "And set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.", "vulgate": "et inposuerunt super caput eius causam ipsius scriptam hic est Iesus rex Iudaeorum;"}}, {"v": 38, "ref": "27:38", "o": "Τότε σταυροῦνται σὺν αὐτῷ δύο λῃσταί, εἷς ἐκ δεξιῶν καὶ εἷς ἐξ εὐωνύμων.", "en": {"kjv": "Then were there two thieves crucified with him, one on the right hand, and another on the left.", "web": "Then there were two robbers crucified with him, one on his right hand and one on the left.", "bsb": "Two robbers were crucified with Him, one on His right hand and the other on His left.", "asv": "Then are there crucified with him two robbers, one on the right hand and one on the left.", "ylt": "Then crucified with him are two robbers, one on the right hand, and one on the left,", "tyndale": "And ther were two theves crucified with him one on ye right honde and another on the lyfte.", "dra": "Then were crucified with him two thieves: one on the right hand and one on the left.", "bbe": "Then two thieves were put on crosses with him, one on the right and one on the left.", "geneva": "And there were two theeues crucified with him, one on the right hand, and another on the left.", "wycliffe": "Thanne twey theues weren crucified with hym, oon on the riythalf, and oon on the lefthalf.", "rotherham": "Then, are crucified with him, two robbers,—one on the right hand, and one on the left.", "weymouth": "At the same time two robbers were crucified with Him, one at His right hand and the other at His left.", "darby": "Then are crucified with him two robbers, one on the right hand and one on the left.", "twenty": "At the same time two robbers were crucified with him, one on the right, the other on the left.", "acv": "Then two robbers are crucified with him, one at the right hand and one at the left.", "anderson": "Then were two robbers crucified with him; one on his right hand, and the other on his left.", "haweis": "Then were crucified with him two robbers, one on his right hand, and the other on his left.", "noyes": "Then are crucified with him two robbers, one on the right hand, and one on the left.", "webster": "Then were there two thieves crucified with him: one on the right hand, and another on the left.", "vulgate": "tunc crucifixi sunt cum eo duo latrones unus a dextris et unus a sinistris;"}}, {"v": 39, "ref": "27:39", "o": "οἱ δὲ παραπορευόμενοι ἐβλασφήμουν αὐτὸν κινοῦντες τὰς κεφαλὰς αὐτῶν", "en": {"kjv": "And they that passed by reviled him, wagging their heads,", "web": "Those who passed by blasphemed him, wagging their heads,", "bsb": "And those who passed by heaped abuse on Him, shaking their heads", "asv": "And they that passed by railed on him, wagging their heads,", "ylt": "and those passing by were speaking evil of him, wagging their heads,", "tyndale": "They that passed by revyled him waggynge ther heeddes", "dra": "And they that passed by blasphemed him, wagging their heads,", "bbe": "And those who went by said bitter words to him, shaking their heads and saying,", "geneva": "And they that passed by, reuiled him, wagging their heades,", "wycliffe": "And men that passiden forth blasfemeden hym,", "rotherham": "And, they who were passing by, were reviling him, shaking their heads,", "weymouth": "And the passers-by reviled Him. They shook their heads at Him", "darby": "But the passers-by reviled him, shaking their heads", "twenty": "The passers-by railed at him, shaking their heads as they said:", "acv": "And those who passed by reviled him, shaking their heads,", "anderson": "And they that passed by reviled him, shaking their heads,", "haweis": "And they who were passing by reviled him, shaking their heads,", "noyes": "And they who passed by reviled him, wagging their heads,", "webster": "And they that passed by, reviled him, wagging their heads,", "vulgate": "praetereuntes autem blasphemabant eum moventes capita sua;"}}, {"v": 40, "ref": "27:40", "o": "καὶ λέγοντες· Ὁ καταλύων τὸν ναὸν καὶ ἐν τρισὶν ἡμέραις οἰκοδομῶν, σῶσον σεαυτόν· εἰ υἱὸς εἶ τοῦ θεοῦ, ⸀κατάβηθι ἀπὸ τοῦ σταυροῦ.", "en": {"kjv": "And saying, Thou that destroyest the temple, and buildest it in three days, save thyself. If thou be the Son of God, come down from the cross.", "web": "and saying, “You who destroy the temple, and build it in three days, save yourself! If you are the Son of God, come down from the cross!”", "bsb": "and saying, “You who are going to destroy the temple and rebuild it in three days, save Yourself! If You are the Son of God, come down from the cross!”", "asv": "and saying, Thou that destroyest the temple, and buildest it in three days, save thyself: if thou art the Son of God, come down from the cross.", "ylt": "and saying, `Thou that art throwing down the sanctuary, and in three days building it , save thyself; if Son thou art of God, come down from the cross.'", "tyndale": "and sayinge: Thou that destroyest the temple of God and byldest it in thre dayes save thy sylfe. If thou be ye sonne of God come doune from the crosse.", "dra": "And saying: Vah, thou that destroyest the temple of God and in three days dost rebuild it: save thy own self. If thou be the Son of God, come down from the cross.", "bbe": "You who would give the Temple to destruction and put it up again in three days, get yourself free: if you are the Son of God, come down from the cross.", "geneva": "And saying, Thou that destroyest ye Temple, and buildest it in three dayes, saue thy selfe: if thou be ye Sonne of God, come downe from ye crosse.", "wycliffe": "mouynge her heedis, and seiynge, Vath to thee, that distriest the temple of God, and in the thridde dai bildist it ayen; saue thou thi silf; if thou art the sone of God, come doun of the cross.", "rotherham": "and saying—The man that taketh down the Temple and in three days buildeth it! Save, thyself! If thou art God’s, Son, come down from the cross.", "weymouth": "and said, \"You who would pull down the Sanctuary and build a new one within three days, save yourself. If you are God's Son, come down from the cross.\"", "darby": "and saying, Thou that destroyest the temple and buildest it in three days, save thyself. If thou art Son ofGod, descend from the cross.", "twenty": "“You who ‘destroy the Temple and build one in three days,’ save yourself! If you are God’s Son, come down from the cross!”", "acv": "and saying, Thou who destroy the temple, and build it in three days, save thyself. If thou are the Son of God, come down from the cross.", "anderson": "and saying: You that destroy the temple, and build it in three days, save yourself; if you are the Son of God, come down from the cross.", "haweis": "and saying, Thou that canst pull down the temple, and build it in three days, save thyself. If thou be the Son of God, descend from the cross.", "noyes": "and saying, Thou that destroyest the temple, and buildest it up in three days, save thyself, if thou art the Son of God, and come down from the cross.", "webster": "And saying, Thou that destroyest the temple, and buildest [it] in three days, save thyself. If thou art the Son of God, come down from the cross.", "vulgate": "et dicentes qui destruit templum et in triduo illud reaedificat salva temet ipsum si Filius Dei es descende de cruce;"}}, {"v": 41, "ref": "27:41", "o": "ὁμοίως ⸀καὶ οἱ ἀρχιερεῖς ἐμπαίζοντες μετὰ τῶν γραμματέων καὶ ⸀πρεσβυτέρων ἔλεγον·", "en": {"kjv": "Likewise also the chief priests mocking him, with the scribes and elders, said,", "web": "Likewise the chief priests also mocking, with the scribes, the Pharisees, and the elders, said,", "bsb": "In the same way, the chief priests, scribes, and elders mocked Him, saying,", "asv": "In like manner also the chief priests mocking him, with the scribes and elders, said,", "ylt": "And in like manner also the chief priests mocking, with the scribes and elders, said,", "tyndale": "Lykwyse also the hye prestes mockinge him with the scribes aud elders sayde:", "dra": "In like manner also the chief priests, with the scribes and ancients, mocking said:", "bbe": "In the same way, the chief priests, making sport of him, with the scribes and those in authority, said,", "geneva": "Likewise also the hie Priests mocking him, with the Scribes, and Elders, and Pharises, said,", "wycliffe": "Also and princis of prestis scornynge, with scribis and elder men,", "rotherham": "Likewise, the High-priests, [also], mocking, with the Scribes and Elders, were saying: Others, he saved,—Himself, he cannot save:", "weymouth": "In like manner the High Priests also, together with the Scribes and the Elders, taunted Him.", "darby": "[And] in like manner the chief priests also, mocking, with the scribes and elders, said,", "twenty": "In the same way the Chief Priests, with the Teaches of the Law and Councillors, said in mockery:", "acv": "And likewise also the chief priests, ridiculing with the scholars, and elders, and Pharisees, said,", "anderson": "In like manner also the chief priests, with the scribes and elders, derided him, and said:", "haweis": "And with similar language also did the chief priests, insulting him, with the scribes and elders, and Pharisees,", "noyes": "So also the chief priests, mocking, with the scribes and elders, said,", "webster": "Likewise also the chief priests mocking [him], with the scribes and elders, said,", "vulgate": "similiter et principes sacerdotum inludentes cum scribis et senioribus dicentes;"}}, {"v": 42, "ref": "27:42", "o": "Ἄλλους ἔσωσεν, ἑαυτὸν οὐ δύναται σῶσαι· ⸀βασιλεὺς Ἰσραήλ ἐστιν, καταβάτω νῦν ἀπὸ τοῦ σταυροῦ καὶ πιστεύσομεν ἐπ’ ⸀αὐτόν.", "en": {"kjv": "He saved others; himself he cannot save. If he be the King of Israel, let him now come down from the cross, and we will believe him.", "web": "“He saved others, but he can’t save himself. If he is the King of Israel, let him come down from the cross now, and we will believe in him.", "bsb": "“He saved others, but He cannot save Himself. He is the King of Israel! Let Him come down now from the cross, and we will believe in Him.", "asv": "He saved others; himself he cannot save. He is the King of Israel; let him now come down from the cross, and we will believe on him.", "ylt": "`Others he saved; himself he is not able to save! If he be King of Israel, let him come down now from the cross, and we will believe him;", "tyndale": "He saved other him sylfe he can not save. If he be ye kynge of Israel: let him now come doune from the crosse and we will beleve him.", "dra": "He saved others: himself he cannot save. If he be the king of Israel, let him now come down from the cross: and we will believe him.", "bbe": "A saviour of others, he has no salvation for himself. If he is the King of Israel, let him now come down from the cross, and we will have faith in him.", "geneva": "He saued others, but he cannot saue him selfe: if he be ye King of Israel, let him now come downe from ye crosse, and we will beleeue in him.", "wycliffe": "seiden, He made othere men saaf, he may not make hym silf saaf; if he is kyng of Israel, come he now doun fro the crosse, and we bileuen to hym;", "rotherham": "Israel’s King, he is! Let him come down, now, from the cross,—and we will believe on him!", "weymouth": "\"He saved others,\" they said, \"himself he cannot save! He is the King of Israel! Let him now come down from the cross, and we will believe in him.", "darby": "He saved others, himself he cannot save. He is King of Israel: let him descend now from the cross, and we will believe on him.", "twenty": "“He saved others, but he cannot save himself! He is the ‘King of Israel’! Let him come down from the cross now, and we will believe in him.", "acv": "He saved others, he cannot save himself. If he is the king of Israel, let him now come down from the cross, and we will believe in him.", "anderson": "He saved others; himself he can not save. If he is the King of Israel, let him now come down from the cross, and we will believe on him.", "haweis": "say, He saved others, himself he is unable to save. If he be the King of Israel, let him come down now from the cross, and we will believe him.", "noyes": "He saved others, cannot he save himself? He is the king of Israel, let him now come down from the cross, and we will believe in him.", "webster": "He saved others; himself he cannot save. If he is King of Israel, let him now come down from the cross, and we will believe him.", "vulgate": "alios salvos fecit se ipsum non potest salvum facere si rex Israhel est descendat nunc de cruce et credemus ei;"}}, {"v": 43, "ref": "27:43", "o": "πέποιθεν ἐπὶ τὸν θεόν, ῥυσάσθω ⸀νῦν εἰ θέλει αὐτόν· εἶπεν γὰρ ὅτι Θεοῦ εἰμι υἱός.", "en": {"kjv": "He trusted in God; let him deliver him now, if he will have him: for he said, I am the Son of God.", "web": "He trusts in God. Let God deliver him now, if he wants him; for he said, ‘I am the Son of God.’”", "bsb": "He trusts in God. Let God deliver Him now if He wants Him. For He said, ‘I am the Son of God.’”", "asv": "He trusteth on God; let him deliver him now, if he desireth him: for he said, I am the Son of God.", "ylt": "he hath trusted on God, let Him now deliver him, if He wish him, because he said--Son of God I am;'", "tyndale": "He trusted in God let him deliver him now yf he will have him: for he sayde I am the sonne of God.", "dra": "He trusted in God: let him now deliver him if he will have him. For he said: I am the Son of God.", "bbe": "He put his faith in God; let God be his saviour now, if he will have him; for he said, I am the Son of God.", "geneva": "He trusted in God, let him deliuer him nowe, if he will haue him: for he saide, I am the Sonne of God.", "wycliffe": "he tristide in God; delyuer he hym now, if he wole; for he seide, That Y am Goddis sone.", "rotherham": "He hath put confidence upon God, Let him rescue him, now, if he desireth him; for he said, I am, God’s Son.", "weymouth": "His trust is in God: let God deliver him now, if He will have him; for he said, `I am God's Son.'\"", "darby": "He trusted uponGod; let him save him now if he will [have] him. For he said, I am Son ofGod.", "twenty": "He has trusted in God; if God wants him, let him deliver him now; for he said ‘I am God’s Son.’”", "acv": "He trusted in God, let him rescue him now, if he wants him, for he said, I am the Son of God.", "anderson": "He trusted in God; let him deliver him now, if he delights in him; for he said: I am the Son of God.", "haweis": "He trusted in God; let him now deliver him, if he will have him: for he said, I am the Son of God.", "noyes": "He trusteth in God; let him now deliver him, if he desireth him; for he said, I am the Son of God.", "webster": "He trusted in God; let him deliver him now if he will have him: for he said, I am the Son of God.", "vulgate": "confidet in Deo liberet nunc eum si vult dixit enim quia Dei Filius sum;"}}, {"v": 44, "ref": "27:44", "o": "τὸ δ’ αὐτὸ καὶ οἱ λῃσταὶ οἱ συσταυρωθέντες ⸀σὺν αὐτῷ ὠνείδιζον αὐτόν.", "en": {"kjv": "The thieves also, which were crucified with him, cast the same in his teeth.", "web": "The robbers also who were crucified with him cast on him the same reproach.", "bsb": "In the same way, even the robbers who were crucified with Him berated Him.", "asv": "And the robbers also that were crucified with him cast upon him the same reproach.", "ylt": "with the same also the robbers, who were crucified with him, were reproaching him.", "tyndale": "That same also the theves which were crucified with him cast in his tethe.", "dra": "And the selfsame thing the thieves also that were crucified with him reproached him with.", "bbe": "And the thieves who were on the crosses said evil words to him.", "geneva": "The selfe same thing also ye theeues which were crucified with him, cast in his teeth.", "wycliffe": "And the theues, that weren crucified with hym, vpbreididen hym of the same thing.", "rotherham": "And, the same thing, the robbers also, who were crucified with him, were casting in his teeth.", "weymouth": "Insults of the same kind were heaped on Him even by the robbers who were being crucified with Him.", "darby": "And the robbers also who had been crucified with him cast the same reproaches on him.", "twenty": "Even the robbers, who were crucified with him, reviled him in the same way.", "acv": "And also the robbers who were crucified with him reviled him the same way.", "anderson": "The robbers also that were crucified with him, uttered the same reproaches against him.", "haweis": "And in the same manner also, did the robbers who were crucified with him, revile him.", "noyes": "The robbers also, who were crucified with him, reviled him in the same manner.", "webster": "The thieves also who were crucified with him, cast the same in his teeth.", "vulgate": "id ipsum autem et latrones qui fixi erant cum eo inproperabant ei;"}}, {"v": 45, "ref": "27:45", "o": "Ἀπὸ δὲ ἕκτης ὥρας σκότος ἐγένετο ἐπὶ πᾶσαν τὴν γῆν ἕως ὥρας ἐνάτης.", "en": {"kjv": "Now from the sixth hour there was darkness over all the land unto the ninth hour.", "web": "Now from the sixth hour there was darkness over all the land until the ninth hour.", "bsb": "From the sixth hour until the ninth hour darkness came over all the land.", "asv": "Now from the sixth hour there was darkness over all the land until the ninth hour.", "ylt": "And from the sixth hour darkness came over all the land unto the ninth hour,", "tyndale": "From the sixte houre was there dercknes over all the londe vnto the nynth houre.", "dra": "Now from the sixth hour, there was darkness over the whole earth, until the ninth hour.", "bbe": "Now from the sixth hour it was dark over all the land till the ninth hour.", "geneva": "Now from ye sixt houre was there darkenesse ouer all the land, vnto the ninth houre.", "wycliffe": "But fro the sixte our derknessis weren maad on al the erthe, to the nynthe our.", "rotherham": "Now, from the sixth hour, darkness, came upon all the land—until the ninth hour.", "weymouth": "Now from noon until three o'clock in the afternoon there was darkness over the whole land;", "darby": "Now from [the] sixth hour there was darkness over the whole land until [the] ninth hour;", "twenty": "After mid-day a darkness came over all the country, lasting till three in the afternoon.", "acv": "Now from the sixth hour darkness developed over all the land until the ninth hour.", "anderson": "From the sixth hour there was darkness over all the land till the ninth hour.", "haweis": "Now from the fifth hour darkness fell upon all the land, unto the ninth hour.", "noyes": "And from the sixth hour there was darkness over all the land, until the ninth hour.", "webster": "Now from the sixth hour there was darkness over all the land to the ninth hour.", "vulgate": "a sexta autem hora tenebrae factae sunt super universam terram usque ad horam nonam;"}}, {"v": 46, "ref": "27:46", "o": "περὶ δὲ τὴν ἐνάτην ὥραν ⸀ἀνεβόησεν ὁ Ἰησοῦς φωνῇ μεγάλῃ λέγων· ⸂Ἠλὶ ἠλὶ⸃ λεμὰ σαβαχθάνι; τοῦτ’ ἔστιν· Θεέ μου θεέ μου, ἱνατί με ἐγκατέλιπες;", "en": {"kjv": "And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lama sabachthani? that is to say, My God, my God, why hast thou forsaken me?", "web": "About the ninth hour Jesus cried with a loud voice, saying, “Eli, Eli, limasabachthani?” That is, “My God, my God, why have you forsaken me?”", "bsb": "About the ninth hour Jesus cried out in a loud voice, “Eli, Eli, lema sabachthani?” which means, “My God, My God, why have You forsaken Me?”", "asv": "And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lama sabachthani? that is, My God, my God, why hast thou forsaken me?", "ylt": "and about the ninth hour Jesus cried out with a great voice, saying, `Eli, Eli, lama sabachthani?' that is, `My God, my God, why didst Thou forsake me?'", "tyndale": "And about ye nynth houre Iesus cryed with a loude voyce sayinge: Eli Eli lama asbathani. That is to saye my God my God why hast thou forsaken me?", "dra": "And about the ninth hour, Jesus cried with a loud voice, saying: Eli, Eli, lamma sabacthani? That is, My God, My God, why hast thou forsaken me?", "bbe": "And about the ninth hour Jesus gave a loud cry, saying, Eli, Eli, lama sabachthani? that is, My God, my God, why are you turned away from me?", "geneva": "And about ye ninth houre Iesus cryed with a loud voyce, saying, Eli, Eli, lamasabachthani? that is, My God, my God, why hast thou forsaken me?", "wycliffe": "And aboute the nynthe our Jhesus criede with a greet vois, and seide, Heli, Heli, lamazabatany, that is, My God, my God, whi hast thou forsake me?", "rotherham": "And, about the ninth hour, Jesus uttered a cry, with a loud voice, saying—Eloi! Eloi! lema sabachthanei? that is, My God! my God! to what end hast thou forsaken me?", "weymouth": "but about three o'clock Jesus cried out in a loud voice, \"Eli, Eli, lama sabachthani?\" that is to say, \"My God, My God, why hast Thou forsaken me?\"", "darby": "but about the ninth hour Jesus cried out with a loud voice, saying, Eli, Eli, lama sabachthani? that is, MyGod, myGod, why hast thou forsaken me?", "twenty": "And about three Jesus called out loudly: “Eloi, Eloi, lema sabacthani” — that is to say, ‘O my God, my God, why has thou forsaken me?’", "acv": "And about the ninth hour Jesus cried out in a great voice, saying, Eli, Eli, lama sabachthani? That is, My God, my God, why have thou forsaken me?", "anderson": "But about the ninth hour, Jesus cried out with a loud voice, saying: Eli, Eli, lamah sabachthani? that is, My God, my God, why hast thou forsaken me?", "haweis": "But about the ninth hour Jesus cried out with an exceeding loud cry, saying, Eli! Eli! lama, sabacthani? that is, My God! my God! why hast thou forsaken me?", "noyes": "And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lema sabachthani? that is to say, My God, my God, why hast thou forsaken me?", "webster": "And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lama sabachthani? that is to say, My God, my God, why hast thou forsaken me?", "vulgate": "et circa horam nonam clamavit Iesus voce magna dicens Heli Heli lema sabacthani hoc est Deus meus Deus meus ut quid dereliquisti me;"}}, {"v": 47, "ref": "27:47", "o": "τινὲς δὲ τῶν ἐκεῖ ⸀ἑστηκότων ἀκούσαντες ἔλεγον ὅτι Ἠλίαν φωνεῖ οὗτος.", "en": {"kjv": "Some of them that stood there, when they heard that, said, This man calleth for Elias.", "web": "Some of them who stood there, when they heard it, said, “This man is calling Elijah.”", "bsb": "When some of those standing there heard this, they said, “He is calling Elijah.”", "asv": "And some of them that stood there, when they heard it, said, This man calleth Elijah.", "ylt": "And certain of those standing there having heard, said--`Elijah he doth call;'", "tyndale": "Some of them that stode there when they herde that sayde: This man calleth for Helyas.", "dra": "And some that stood there and heard said: This man calleth Elias.", "bbe": "And some of those who were near by, hearing it, said, This man is crying to Elijah.", "geneva": "And some of them that stoode there, when they heard it, said, This man calleth Elias.", "wycliffe": "And summen that stoden there, and herynge, seiden, This clepith Helye.", "rotherham": "Now certain of them who were there standing, when they heard, began to say—This man, calleth, Elijah.", "weymouth": "\"The man is calling for Elijah,\" said some of the bystanders.", "darby": "And some of those who stood there, when they heard [it], said, This [man] calls for Elias.", "twenty": "Some of those standing by heard this, and said: “The man is calling for Elijah!”", "acv": "And some of those who stood there, when they heard it, said, This man calls Elijah.", "anderson": "Some of those who were standing there, when they heard it, said: This man calls for Elijah.", "haweis": "Then some of those who stood there, hearing him, said, This man is calling out for Elias.", "noyes": "Some of those standing there, when they heard this, said, This man is calling for Elijah.", "webster": "Some of them that stood there, when they heard [that], said, This [man] calleth for Elijah.", "vulgate": "quidam autem illic stantes et audientes dicebant Heliam vocat iste;"}}, {"v": 48, "ref": "27:48", "o": "καὶ εὐθέως δραμὼν εἷς ἐξ αὐτῶν καὶ λαβὼν σπόγγον πλήσας τε ὄξους καὶ περιθεὶς καλάμῳ ἐπότιζεν αὐτόν.", "en": {"kjv": "And straightway one of them ran, and took a spunge, and filled it with vinegar, and put it on a reed, and gave him to drink.", "web": "Immediately one of them ran, and took a sponge, and filled it with vinegar, and put it on a reed, and gave him a drink.", "bsb": "One of them quickly ran and brought a sponge. He filled it with sour wine, put it on a reed, and held it up for Jesus to drink.", "asv": "And straightway one of them ran, and took a sponge, and filled it with vinegar, and put it on a reed, and gave him to drink.", "ylt": "and immediately, one of them having run, and having taken a spunge, having filled it with vinegar, and having put it on a reed, was giving him to drink,", "tyndale": "And streyght waye one of them ranne and toke a sponge and filled it full of veneger and put it on a rede and gave him to drinke.", "dra": "And immediately one of them running took a sponge and filled it with vinegar and put it on a reed and gave him to drink.", "bbe": "And straight away one of them went quickly, and took a sponge, and made it full of bitter wine, and put it on a rod and gave him drink.", "geneva": "And straightway one of them ran, and tooke a spondge, and filled it with vineger, and put it on a reede, and gaue him to drinke.", "wycliffe": "And anoon oon of hem rennynge, took and fillide a spounge with vynegre, and puttide on a rehed, and yaf to hym to drynke.", "rotherham": "And, straightway, one from among them, running, and taking a sponge, and filling it with vinegar and putting it on a reed, was giving him to drink;", "weymouth": "One of them ran forthwith, and filling a sponge with sour wine put it on the end of a cane and offered it Him to drink;", "darby": "And immediately one of them running and getting a sponge, having filled [it] with vinegar and fixed [it] on a reed, gave him to drink.", "twenty": "One of them immediately ran and took a sponge, and, filling it with common wine, put it on the end of a rod, and offered it to him to drink.", "acv": "And straightaway one of them, after running, and having taken a sponge, and having filled it with vinegar, put it on a reed, and gave him to drink.", "anderson": "And immediately one of them ran, and took a sponge, and having filled it with vinegar, put it on a reed, and gave it to him to drink.", "haweis": "And immediately one of them, running, and taking a sponge, and filling it with vinegar, and fastening it to a pole, put it to him to drink.", "noyes": "And one of them immediately ran and took a sponge, and filled it with vinegar, and put it on a reed, and gave it to him to drink.", "webster": "And immediately one of them ran, and took a spunge, and filled [it] with vinegar, and put [it] on a reed, and gave him to drink.", "vulgate": "et continuo currens unus ex eis acceptam spongiam implevit aceto et inposuit harundini et dabat ei bibere;"}}, {"v": 49, "ref": "27:49", "o": "οἱ δὲ λοιποὶ ⸀ἔλεγον· Ἄφες ἴδωμεν εἰ ἔρχεται Ἠλίας σώσων ⸀αὐτόν.", "en": {"kjv": "The rest said, Let be, let us see whether Elias will come to save him.", "web": "The rest said, “Let him be. Let’s see whether Elijah comes to save him.”", "bsb": "But the others said, “Leave Him alone. Let us see if Elijah comes to save Him.”", "asv": "And the rest said, Let be; let us see whether Elijah cometh to save him.", "ylt": "but the rest said, `Let alone, let us see if Elijah doth come--about to save him.'", "tyndale": "Other sayde let be: let vs se whyther Helyas will come and deliver him.", "dra": "And the others said: Let be. Let us see whether Elias will come to deliver him.", "bbe": "And the rest said, Let him be; let us see if Elijah will come to his help.", "geneva": "Other said, Let be: let vs see, if Elias wil come and saue him.", "wycliffe": "But othir seiden, Suffre thou; se we whether Helie come to deliuer hym.", "rotherham": "but, the rest, said—Stay! let us see whether Elijah is coming, and will save him. [[But, another, taking a spear, pierced his side, and there came forth water and blood]].", "weymouth": "while the rest said, \"Let us see whether Elijah is coming to deliver him.\"", "darby": "But the rest said, Let be; let us see if Elias comes to save him.", "twenty": "But the rest said: “Wait and let us see if Elijah is coming to save him.” [However another man took a spear, and pierced his side; and water and blood flowed from it.]", "acv": "But the others said, Leave thou be. We might see if Elijah comes he will save him.", "anderson": "The rest said: Wait, let us see if Elijah is coming to save him.", "haweis": "The others said, Let him alone, let us see whether Elias will come to save him.", "noyes": "But the rest said, Hold! let us see whether Elijah will come to save him.", "webster": "The rest said, Forbear, let us see whether Elijah will come to save him.", "vulgate": "ceteri vero dicebant sine videamus an veniat Helias liberans eum;"}}, {"v": 50, "ref": "27:50", "o": "ὁ δὲ Ἰησοῦς πάλιν κράξας φωνῇ μεγάλῃ ἀφῆκεν τὸ πνεῦμα.", "en": {"kjv": "Jesus, when he had cried again with a loud voice, yielded up the ghost.", "web": "Jesus cried again with a loud voice, and yielded up his spirit.", "bsb": "When Jesus had cried out again in a loud voice, He yielded up His spirit.", "asv": "And Jesus cried again with a loud voice, and yielded up his spirit.", "ylt": "And Jesus having again cried with a great voice, yielded the spirit;", "tyndale": "Iesus cryed agayne with a lowde voyce and yelded vp the goost.", "dra": "And Jesus again crying with a loud voice, yielded up the ghost.", "bbe": "And Jesus gave another loud cry, and gave up his spirit.", "geneva": "Then Iesus cryed againe with a loude voyce, and yeelded vp the ghost.", "wycliffe": "Forsothe Jhesus eftsoone criede with a greet voyce, and yaf vp the goost.", "rotherham": "And, Jesus, again crying out with a loud voice, dismissed the spirit.", "weymouth": "But Jesus uttered another loud cry and then yielded up His spirit.", "darby": "And Jesus, having again cried with a loud voice, gave up the ghost.", "twenty": "But Jesus, uttering another loud cry, gave up his spirit.", "acv": "And Jesus, having cried out again in a great voice, yielded up his spirit.", "anderson": "And Jesus again cried with a loud voice, and gave up his spirit.", "haweis": "Then Jesus crying again with a loud voice gave up the ghost.", "noyes": "And Jesus, crying out again with a loud voice, yielded up his spirit.", "webster": "Jesus, when he had cried again with a loud voice, expired.", "vulgate": "Iesus autem iterum clamans voce magna emisit spiritum;"}}, {"v": 51, "ref": "27:51", "o": "καὶ ἰδοὺ τὸ καταπέτασμα τοῦ ναοῦ ἐσχίσθη ⸂ἀπ’ ἄνωθεν ἕως κάτω εἰς δύο⸃, καὶ ἡ γῆ ἐσείσθη, καὶ αἱ πέτραι ἐσχίσθησαν,", "en": {"kjv": "And, behold, the veil of the temple was rent in twain from the top to the bottom; and the earth did quake, and the rocks rent;", "web": "Behold, the veil of the temple was torn in two from the top to the bottom. The earth quaked and the rocks were split.", "bsb": "At that moment the veil of the temple was torn in two from top to bottom. The earth quaked and the rocks were split.", "asv": "And behold, the veil of the temple was rent in two from the top to the bottom; and the earth did quake; and the rocks were rent;", "ylt": "and lo, the vail of the sanctuary was rent in two from top unto bottom, and the earth did quake, and the rocks were rent,", "tyndale": "And beholde the vayle of the temple dyd rent in twayne from ye toppe to the bottome and the erth dyd quake and the stones dyd rent", "dra": "And behold the veil of the temple was rent in two from the top even to the bottom: and the earth quaked and the rocks were rent.", "bbe": "And the curtain of the Temple was parted in two from end to end; and there was an earth-shock; and the rocks were broken;", "geneva": "And behold, the vayle of the Temple was rent in twaine, from the top to the bottome, and the earth did quake, and the stones were cloue.", "wycliffe": "And lo! the veil of the temple was to-rent in twey parties, fro the hiest to the lowest. And the erthe schoke, and stoonus weren cloue; and birielis weren openyd,", "rotherham": "And lo! the veil of the Temple, was rent, from top to bottom, into two; and, the earth, was shaken, and, the rocks, were rent;", "weymouth": "Immediately the curtain of the Sanctuary was torn in two from top to bottom: the earth quaked; the rocks split;", "darby": "And lo, the veil of the temple was rent in two from the top to the bottom, and the earth was shaken, and the rocks were rent,", "twenty": "Suddenly the Temple curtain was torn in two from top to bottom, the earth shook, the rocks were torn asunder,", "acv": "And behold, the curtain of the temple was torn in two from the top to the bottom, and the earth quaked, and the rocks split,", "anderson": "And behold, the vail of the temple was rent in two from top to bottom. And the earth did shake, and the rocks were rent:", "haweis": "And, lo! the vail of the temple was rent in two, from the upper part to the bottom; and the earth was shaken; and the rocks were rent;", "noyes": "And, lo! the veil of the temple was rent in two from the top to the bottom; and the earth, quaked, and the rocks were rent,", "webster": "And behold, the vail of the temple was rent in two, from the top to the bottom: and the earth shook, and the rocks rent;", "vulgate": "et ecce velum templi scissum est in duas partes a summo usque deorsum et terra mota est et petrae scissae sunt;"}}, {"v": 52, "ref": "27:52", "o": "καὶ τὰ μνημεῖα ἀνεῴχθησαν καὶ πολλὰ σώματα τῶν κεκοιμημένων ἁγίων ⸀ἠγέρθησαν,", "en": {"kjv": "And the graves were opened; and many bodies of the saints which slept arose,", "web": "The tombs were opened, and many bodies of the saints who had fallen asleep were raised;", "bsb": "The tombs broke open, and the bodies of many saints who had fallen asleep were raised.", "asv": "and the tombs were opened; and many bodies of the saints that had fallen asleep were raised;", "ylt": "and the tombs were opened, and many bodies of the saints who have fallen asleep, arose,", "tyndale": "and graves dyd open: and the bodies of many sainctes which slept arose", "dra": "And the graves were opened: and many bodies of the saints that had slept arose,", "bbe": "And the resting-places of the dead came open; and the bodies of a number of sleeping saints came to life;", "geneva": "And the graues did open themselues, and many bodies of the Saintes, which slept, arose,", "wycliffe": "and many bodies of seyntis that hadden slepte, rysen vp.", "rotherham": "and, the tombs, were opened and, many bodies of the holy ones who had fallen asleep, arose,—", "weymouth": "the tombs opened; and many of God's people who were asleep in death awoke.", "darby": "and the tombs were opened; and many bodies of the saints fallen asleep arose,", "twenty": "the tombs opened, and the bodies of many of God’s People who had fallen asleep rose,", "acv": "and the sepulchers were opened, and many bodies of the sanctified who have been asleep arose.", "anderson": "and the sepulchers were opened, and many bodies of the saints that slept, arose.", "haweis": "and the sepulchres were opened; and many bodies of saints, who slept, arose;", "noyes": "and the tombs were opened; and many bodies of holy men that slept, arose,", "webster": "And the graves were opened, and many bodies of saints who slept, arose,", "vulgate": "et monumenta aperta sunt et multa corpora sanctorum qui dormierant surrexerunt;"}}, {"v": 53, "ref": "27:53", "o": "καὶ ἐξελθόντες ἐκ τῶν μνημείων μετὰ τὴν ἔγερσιν αὐτοῦ εἰσῆλθον εἰς τὴν ἁγίαν πόλιν καὶ ἐνεφανίσθησαν πολλοῖς.", "en": {"kjv": "And came out of the graves after his resurrection, and went into the holy city, and appeared unto many.", "web": "and coming out of the tombs after his resurrection, they entered into the holy city and appeared to many.", "bsb": "After Jesus’ resurrection, when they had come out of the tombs, they entered the holy city and appeared to many people.", "asv": "and coming forth out of the tombs after his resurrection they entered into the holy city and appeared unto many.", "ylt": "and having come forth out of the tombs after his rising, they went into the holy city, and appeared to many.", "tyndale": "and came out of ye graves after his resurreccion and came into the holy cite and appered vnto many.", "dra": "And coming out of the tombs after his resurrection, came into the holy city and appeared to many.", "bbe": "And coming out of their resting-places, after he had come again from the dead, they went into the holy town and were seen by a number of people.", "geneva": "And came out of the graues after his resurrection, and went into the holy citie, and appeared vnto many.", "wycliffe": "And thei yeden out of her birielis, and aftir his resurreccioun thei camen in to the holi citee, and apperiden to many.", "rotherham": "and, coming forth out of the tombs after his arising, entered into, the holy city, and plainly appeared unto many.", "weymouth": "And coming out of their tombs after Christ's resurrection they entered the holy city and showed themselves to many.", "darby": "and going out of the tombs after his arising, entered into the holy city and appeared unto many.", "twenty": "and they, leaving their tombs, went, after the resurrection of Jesus, into the Holy City, and appeared to many people.", "acv": "And having come forth out of the sepulchers after his resurrection they entered into the holy city and appeared to many.", "anderson": "And they came out of their sepulchers after his resurrection, and entered the holy city, and appeared to many.", "haweis": "and coming out of the sepulchres after his resurrection, entered into the holy city, and appeared unto many.", "noyes": "and coming out of the tombs after his resurrection went into the holy city and appeared to many.", "webster": "And came out of the graves after his resurrection, and went into the holy city, and appeared to many.", "vulgate": "et exeuntes de monumentis post resurrectionem eius venerunt in sanctam civitatem et apparuerunt multis;"}}, {"v": 54, "ref": "27:54", "o": "Ὁ δὲ ἑκατόνταρχος καὶ οἱ μετ’ αὐτοῦ τηροῦντες τὸν Ἰησοῦν ἰδόντες τὸν σεισμὸν καὶ τὰ ⸀γενόμενα ἐφοβήθησαν σφόδρα λέγοντες· Ἀληθῶς ⸂θεοῦ υἱὸς⸃ ἦν οὗτος.", "en": {"kjv": "Now when the centurion, and they that were with him, watching Jesus, saw the earthquake, and those things that were done, they feared greatly, saying, Truly this was the Son of God.", "web": "Now the centurion, and those who were with him watching Jesus, when they saw the earthquake, and the things that were done, feared exceedingly, saying, “Truly this was the Son of God.”", "bsb": "When the centurion and those with him who were guarding Jesus saw the earthquake and all that had happened, they were terrified and said, “Truly this was the Son of God.”", "asv": "Now the centurion, and they that were with him watching Jesus, when they saw the earthquake, and the things that were done, feared exceedingly, saying, Truly this was the Son of God.", "ylt": "And the centurion, and those with him watching Jesus, having seen the earthquake, and the things that were done, were exceedingly afraid, saying, `Truly this was God's Son.'", "tyndale": "When the Centurion and they that were with him watchinge Iesus sawe ye erth quake and those thinges which hapened they feared greatly sayinge. Of a surete this was the sonne of God.", "dra": "Now the centurion and they that were with him watching Jesus, having seen the earthquake and the things that were done, were sore afraid, saying: Indeed this was the Son of God.", "bbe": "Now the captain and those who were with him watching Jesus, when they saw the earth-shock and the things which were done, were in great fear and said, Truly this was a son of God.", "geneva": "When the Centurion, and they that were with him watching Iesus, saw the earthquake, and the thinges that were done, they feared greatly, saying, Truely this was the Sonne of God.", "wycliffe": "And the centurien and thei that weren with hym kepinge Jhesu, whanne thei saien the erthe schakynge, and tho thingis that weren doon, thei dredden greetli,", "rotherham": "Now, the centurion, and those with him watching Jesus, seeing the earthquake and the things coming to pass, were violently affrighted, saying—Truly, God’s Son, was, he!", "weymouth": "As for the Captain and the soldiers who were with Him keeping guard over Jesus, when they witnessed the earthquake and the other occurrences they were filled with terror, and exclaimed, \"Assuredly he was God's Son.\"", "darby": "But the centurion, and they who were with him on guard over Jesus, seeing the earthquake and the things that took place, feared greatly, saying, Truly this [man] was Son ofGod.", "twenty": "The Roman Captain, and the men with him who were watching Jesus, on seeing the earthquake and all that was happening, became greatly frightened and exclaimed: “This must indeed have been God’s Son!”", "acv": "Now the centurion, and those with him watching over Jesus, when they saw the earthquake, and the things that happened, they feared greatly, saying, Truly this was the Son of God.", "anderson": "Now the centurion, and those who were with him watching Jesus, when they saw the earthquake, and what was done, were greatly afraid, and said: Of a truth, this was the Son of God.", "haweis": "Then the centurion, and they who were with him, guarding Jesus, when they saw the earthquake, and the things which were done, were exceedingly terrified, saying, Assuredly this was the Son of God.", "noyes": "And the centurion and they who with him were watching Jesus, when they saw the earthquake, and what was taking place, were exceedingly afraid, saying, Truly this was the Son of God.", "webster": "Now when the centurion, and they that were with him, watching Jesus, saw the earthquake, and those things that were done, they feared greatly, saying, Truly this was the Son of God.", "vulgate": "centurio autem et qui cum eo erant custodientes Iesum viso terraemotu et his quae fiebant timuerunt valde dicentes vere Dei Filius erat iste;"}}, {"v": 55, "ref": "27:55", "o": "Ἦσαν δὲ ἐκεῖ γυναῖκες πολλαὶ ἀπὸ μακρόθεν θεωροῦσαι, αἵτινες ἠκολούθησαν τῷ Ἰησοῦ ἀπὸ τῆς Γαλιλαίας διακονοῦσαι αὐτῷ·", "en": {"kjv": "And many women were there beholding afar off, which followed Jesus from Galilee, ministering unto him:", "web": "Many women were there watching from afar, who had followed Jesus from Galilee, serving him.", "bsb": "And many women were there, watching from a distance. They had followed Jesus from Galilee to minister to Him.", "asv": "And many women were there beholding from afar, who had followed Jesus from Galilee, ministering unto him:", "ylt": "And there were there many women beholding from afar, who did follow Jesus from Galilee, ministering to him,", "tyndale": "And many wemen were there beholdinge him a farre of which folowed Iesus fro Galile ministringe vnto him.", "dra": "And there were there many women afar off, who had followed Jesus from Galilee, ministering unto him:", "bbe": "And a number of women were there, watching from a distance, who had come with Jesus from Galilee, waiting on his needs.", "geneva": "And many women were there, beholding him a farre off, which had folowed Iesus from Galile, ministring vnto him.", "wycliffe": "and seiden, Verili this was Goddis sone. And ther weren there many wymmen afer, that sueden Jhesu fro Galilee, and mynystriden to hym.", "rotherham": "Now there were there, many women, from afar, beholding, who indeed had followed Jesus from Galilee, ministering unto him;", "weymouth": "And there were a number of women there looking on from a distance, who had followed Jesus from Galilee ministering to His necessities;", "darby": "And there were there many women beholding from afar off, who had followed Jesus from Galilee ministering to him,", "twenty": "There were many women there, watching from a distance, who had accompanied Jesus from Galilee and had been attending on him.", "acv": "And many women were there watching from afar, who followed Jesus from Galilee, serving him,", "anderson": "Many women that had followed Jesus from Galilee, and had ministered to him, were there, looking on from a distance.", "haweis": "Now there were many women on the spot, looking on at a distance, who had followed Jesus from Galilee, ministering unto him:", "noyes": "And many women were there, looking on from a distance, who had followed Jesus from Galilee, rendering services to him;", "webster": "And many women were there (beholding at a distance) who followed Jesus from Galilee, ministering to him:", "vulgate": "erant autem ibi mulieres multae a longe quae secutae erant Iesum a Galilaea ministrantes ei;"}}, {"v": 56, "ref": "27:56", "o": "ἐν αἷς ἦν Μαρία ἡ Μαγδαληνὴ καὶ Μαρία ἡ τοῦ Ἰακώβου καὶ ⸀Ἰωσὴφ μήτηρ καὶ ἡ μήτηρ τῶν υἱῶν Ζεβεδαίου.", "en": {"kjv": "Among which was Mary Magdalene, and Mary the mother of James and Joses, and the mother of Zebedee’s children.", "web": "Among them were Mary Magdalene, Mary the mother of James and Joses, and the mother of the sons of Zebedee.", "bsb": "Among them were Mary Magdalene, Mary the mother of James and Joseph, and the mother of Zebedee’s sons.", "asv": "among whom was Mary Magdalene, and Mary the mother of James and Joses, and the mother of the sons of Zebedee.", "ylt": "among whom was Mary the Magdalene, and Mary the mother of James and of Joses, and the mother of the sons of Zebedee.", "tyndale": "Amonge which was Mary Magdalen and Mary the mother of Iames and Ioses and ye mother of zebedes chyldren.", "dra": "Among whom was Mary Magdalen and Mary the mother of James and Joseph and the mother of the sons of Zebedee.", "bbe": "Among whom was Mary Magdalene, and Mary, the mother of James and Joses, and the mother of the sons of Zebedee.", "geneva": "Among whom was Marie Magdalene, and Marie the mother of Iames, and Ioses, and the mother of Zebedeus sonnes.", "wycliffe": "Among whiche was Marie Magdalene, and Marie, the modir of James, and of Joseph, and the modir of Zebedees sones.", "rotherham": "among whom was Mary the Magdalene, also Mary the mother of James and Joseph, and the mother of the sons of Zebedee.", "weymouth": "among them being Mary of Magdala, Mary the mother of James and Joses, and the mother of the sons of Zabdi.", "darby": "among whom was Mary of Magdala, and Mary the mother of James and Joses, and the mother of the sons of Zebedee.", "twenty": "Among them were Mary of Magdala, Mary the mother of James and Joseph, and the mother of Zebediah’s sons.", "acv": "among whom was Mary Magdalene, and Mary the mother of James and Joses, and the mother of the sons of Zebedee.", "anderson": "Among these was Mary Magdalene, and Mary the mother of James and Joses, and the mother of the sons of Zebedee.", "haweis": "among whom was Mary Magdalen, and Mary the mother of James and Joses, and the mother of Zebedee’s children.", "noyes": "among whom was Mary the Magdalene, and Mary the mother of James and Joseph, and the mother of the sons of Zebedee.", "webster": "Among whom was Mary Magdalene, and Mary the mother of James and Joses, and the mother of Zebedee's children.", "vulgate": "inter quas erat Maria Magdalene et Maria Iacobi et Ioseph mater et mater filiorum Zebedaei;"}}, {"v": 57, "ref": "27:57", "o": "Ὀψίας δὲ γενομένης ἦλθεν ἄνθρωπος πλούσιος ἀπὸ Ἁριμαθαίας, τοὔνομα Ἰωσήφ, ὃς καὶ αὐτὸς ⸀ἐμαθητεύθη τῷ Ἰησοῦ·", "en": {"kjv": "When the even was come, there came a rich man of Arimathea, named Joseph, who also himself was Jesus’ disciple:", "web": "When evening had come, a rich man from Arimathaea, named Joseph, who himself was also Jesus’ disciple came.", "bsb": "When it was evening, there came a rich man from Arimathea named Joseph, who himself was a disciple of Jesus.", "asv": "And when even was come, there came a rich man from Arimathæa, named Joseph, who also himself was Jesus’ disciple:", "ylt": "And evening having come, there came a rich man, from Arimathea, named Joseph, who also himself was discipled to Jesus,", "tyndale": "When the even was come there came a ryche man of Aramathia named Ioseph which same also was Iesus disciple.", "dra": "And when it was evening, there came a certain rich man of Arimathea, named Joseph, who also himself was a disciple of Jesus.", "bbe": "And in the evening, there came a man of wealth from Arimathaea, Joseph by name, who was a disciple of Jesus:", "geneva": "And when the euen was come, there came a riche man of Arimathea, named Ioseph, who had also himselfe bene Iesus disciple.", "wycliffe": "But whanne the euenyng was come, ther cam a riche man of Armathi, Joseph bi name, and he was a disciple of Jhesu.", "rotherham": "And, when, evening, arrived, there came a rich man from Arimathaea, whose name was Joseph, who also, himself, had been discipled unto Jesus.", "weymouth": "Towards sunset there came a wealthy inhabitant of Arimathaea, named Joseph, who himself also had become a disciple of Jesus.", "darby": "Now when even was come there came a rich man of Arimathaea, his name Joseph, who also himself was a disciple to Jesus.", "twenty": "When evening had fallen, there came a rich man belonging to Ramah, named Joseph, who had himself become a disciple of Jesus.", "acv": "And having become evening, there came a rich man from Arimathaea, named Joseph, who also himself was discipled by Jesus.", "anderson": "When the evening had come, there came a rich man of Arimathea, named Joseph; and he also was a disciple of Jesus.", "haweis": "But when the evening was come, there came a rich man of Arimathea, whose name was Joseph, who himself also was a disciple of Jesus:", "noyes": "And at evening there came a rich man of Arimathaea, named Joseph, who was himself also a disciple of Jesus.", "webster": "When the evening was come, there came a rich man of Arimathea, named Joseph, who also himself was a disciple of Jesus.", "vulgate": "cum sero autem factum esset venit quidam homo dives ab Arimathia nomine Ioseph qui et ipse discipulus erat Iesu;"}}, {"v": 58, "ref": "27:58", "o": "οὗτος προσελθὼν τῷ Πιλάτῳ ᾐτήσατο τὸ σῶμα τοῦ Ἰησοῦ. τότε ὁ Πιλᾶτος ἐκέλευσεν ⸀ἀποδοθῆναι.", "en": {"kjv": "He went to Pilate, and begged the body of Jesus. Then Pilate commanded the body to be delivered.", "web": "This man went to Pilate, and asked for Jesus’ body. Then Pilate commanded the body to be given up.", "bsb": "He went to Pilate to ask for the body of Jesus, and Pilate ordered that it be given to him.", "asv": "this man went to Pilate, and asked for the body of Jesus. Then Pilate commanded it to be given up.", "ylt": "he having gone near to Pilate, asked for himself the body of Jesus; then Pilate commanded the body to be given back.", "tyndale": "He went to Pilate and begged the body of Iesus. Then Pilate commaunded the body to be delivered.", "dra": "He went to Pilate and asked the body of Jesus. Then Pilate commanded that the body should be delivered.", "bbe": "This man went in to Pilate, and made a request for the body of Jesus. Then Pilate gave orders for it to be given to him.", "geneva": "He went to Pilate, and asked ye body of Iesus. Then Pilate commanded ye body to be deliuered.", "wycliffe": "He wente to Pilat, and axide the bodi of Jhesu.", "rotherham": "The same, going unto Pilate, claimed the body of Jesus. Then, Pilate commanded it to be given up.", "weymouth": "He went to Pilate and begged to have the body of Jesus, and Pilate ordered it to be given to him.", "darby": "He, going to Pilate, begged the body of Jesus. Then Pilate commanded the body to be given up.", "twenty": "He went to see Pilate, and asked for the body of Jesus; upon which Pilate ordered it to be given him.", "acv": "This man having come to Pilate, requested the body of Jesus. Then Pilate commanded the body to be given.", "anderson": "This man went to Pilate, and asked for the body of Jesus. Then Pilate commanded the body to be given.", "haweis": "he going in to Pilate, begged for the body of Jesus. Then Pilate ordered the body to be given him.", "noyes": "This man went to Pilate, and asked for the body of Jesus. Then Pilate ordered it to be given him.", "webster": "He went to Pilate, and begged the body of Jesus. Then Pilate commanded the body to be delivered.", "vulgate": "hic accessit ad Pilatum et petiit corpus Iesu tunc Pilatus iussit reddi corpus;"}}, {"v": 59, "ref": "27:59", "o": "καὶ λαβὼν τὸ σῶμα ὁ Ἰωσὴφ ἐνετύλιξεν ⸀αὐτὸ σινδόνι καθαρᾷ,", "en": {"kjv": "And when Joseph had taken the body, he wrapped it in a clean linen cloth,", "web": "Joseph took the body, and wrapped it in a clean linen cloth,", "bsb": "So Joseph took the body, wrapped it in a clean linen cloth,", "asv": "And Joseph took the body, and wrapped it in a clean linen cloth,", "ylt": "And having taken the body, Joseph wrapped it in clean linen,", "tyndale": "And Ioseph toke the body and wrapped it in a clene lynnyn clooth", "dra": "And Joseph taking the body wrapped it up in a clean linen cloth:", "bbe": "And Joseph took the body, folding it in clean linen,", "geneva": "So Ioseph tooke the body, and wrapped it in a cleane linnen cloth,", "wycliffe": "Thanne Pilat comaundide the bodie to be youun. And whanne the bodi was takun, Joseph lappide it in a clene sendel,", "rotherham": "And Joseph, taking the body, wrapped it up in a clean Indian-cloth,", "weymouth": "So Joseph took the body and wrapped it in a clean sheet of fine linen.", "darby": "And Joseph having got the body, wrapped it in a clean linen cloth,", "twenty": "So Joseph took the body, and wrapped it in a clean linen sheet,", "acv": "And Joseph having taken the body, wrapped it in a clean linen cloth,", "anderson": "And Joseph took the body and wrapped it in clean linen,", "haweis": "And Joseph receiving the body, wrapped it in clean linen;", "noyes": "And Joseph took the body, and wrapped it in a clean linen cloth,", "webster": "And when Joseph had taken the body, he wrapped it in a clean linen cloth,", "vulgate": "et accepto corpore Ioseph involvit illud sindone munda;"}}, {"v": 60, "ref": "27:60", "o": "καὶ ἔθηκεν αὐτὸ ἐν τῷ καινῷ αὐτοῦ μνημείῳ ὃ ἐλατόμησεν ἐν τῇ πέτρᾳ, καὶ προσκυλίσας λίθον μέγαν τῇ θύρᾳ τοῦ μνημείου ἀπῆλθεν.", "en": {"kjv": "And laid it in his own new tomb, which he had hewn out in the rock: and he rolled a great stone to the door of the sepulchre, and departed.", "web": "and laid it in his own new tomb, which he had cut out in the rock, and he rolled a great stone to the door of the tomb, and departed.", "bsb": "and placed it in his own new tomb that he had cut into the rock. Then he rolled a great stone across the entrance to the tomb and went away.", "asv": "and laid it in his own new tomb, which he had hewn out in the rock: and he rolled a great stone to the door of the tomb, and departed.", "ylt": "and laid it in his new tomb, that he hewed in the rock, and having rolled a great stone to the door of the tomb, he went away;", "tyndale": "and put it in his newe tombe which he had hewen out even in the roke and rolled a greate stone to the dore of ye sepulcre and departed.", "dra": "And laid it in his own new monument, which he had hewed out in a rock. And he rolled a great stone to the door of the monument and went his way.", "bbe": "And put it in the resting-place which had been cut out of the rock for himself; and after rolling a great stone to the door of it he went away.", "geneva": "And put it in his new tombe, which he had hewen out in a rocke, and rolled a great stone to the doore of the sepulchre, and departed.", "wycliffe": "and leide it in his newe biriel, that he hadde hewun in a stoon; and he walewide a greet stoon to the dore of the biriel, and wente awei.", "rotherham": "and laid it in his new tomb, which he had hewn in the rock, and, rolling near a large stone unto the door of the tomb, departed.", "weymouth": "He then laid it in his own new tomb which he had hewn in the solid rock, and after rolling a great stone against the door of the tomb he went home.", "darby": "and laid it in his new tomb which he had hewn in the rock; and having rolled a great stone to the door of the tomb, went away.", "twenty": "and laid it in his newly-made tomb which he had cut in the rock; and, before he left, he rolled a great stone against the entrance of the tomb.", "acv": "and laid it in his own new sepulcher, which he hewed out in the rock. And having rolled a great stone to the door of the sepulcher, he departed.", "anderson": "and laid it in his own new tomb, which he had hewn out in the rock. And he rolled a great stone to the door of the tomb, and departed.", "haweis": "and laid it in his own new sepulchre, which he had hewn out in a rock: and rolling a vast stone against the door of the sepulchre, departed.", "noyes": "and laid it in his own new tomb, which he had hewn out in the rock, and having rolled a great stone to the door of the tomb, went away.", "webster": "And laid it in his own new tomb, which he had hewn out in the rock; and he rolled a great stone to the door of the sepulcher, and departed.", "vulgate": "et posuit illud in monumento suo novo quod exciderat in petra et advolvit saxum magnum ad ostium monumenti et abiit;"}}, {"v": 61, "ref": "27:61", "o": "ἦν δὲ ἐκεῖ ⸀Μαριὰμ ἡ Μαγδαληνὴ καὶ ἡ ἄλλη Μαρία καθήμεναι ἀπέναντι τοῦ τάφου.", "en": {"kjv": "And there was Mary Magdalene, and the other Mary, sitting over against the sepulchre.", "web": "Mary Magdalene was there, and the other Mary, sitting opposite the tomb.", "bsb": "Mary Magdalene and the other Mary were sitting there opposite the tomb.", "asv": "And Mary Magdalene was there, and the other Mary, sitting over against the sepulchre.", "ylt": "and there were there Mary the Magdalene, and the other Mary, sitting over-against the sepulchre.", "tyndale": "And there was Mary Magdalene and the other Mary sittynge over ageynste the sepulcre.", "dra": "And there was there Mary Magdalen and the other Mary, sitting over against the sepulchre.", "bbe": "And Mary Magdalene was there, and the other Mary, seated by the place of the dead.", "geneva": "And there was Marie Magdalene, and the other Marie sitting ouer against the sepulchre.", "wycliffe": "But Marie Maudelene and anothir Marie weren there, sittynge ayens the sepulcre.", "rotherham": "Now there were there, Mary the Magdalene, and the other Mary, sitting over against the sepulchre.", "weymouth": "Mary of Magdala and the other Mary were both present there, sitting opposite to the sepulchre.", "darby": "But Mary of Magdala was there, and the other Mary, sitting opposite the sepulchre.", "twenty": "Mary of Magdala and the other Mary remained behind, sitting in front of the grave.", "acv": "And Mary Magdalene, and the other Mary were there, sitting opposite the tomb.", "anderson": "And Mary Magdalene was there, and the other Mary, sitting opposite the tomb.", "haweis": "And Mary Magdalen, and the other Mary, were there sitting opposite the sepulchre.", "noyes": "And Mary the Magdalene was there, and the other Mary, sitting over against the sepulchre.", "webster": "And there was Mary Magdalene, and the other Mary, sitting over against the sepulcher.", "vulgate": "erat autem ibi Maria Magdalene et altera Maria sedentes contra sepulchrum;"}}, {"v": 62, "ref": "27:62", "o": "Τῇ δὲ ἐπαύριον, ἥτις ἐστὶν μετὰ τὴν παρασκευήν, συνήχθησαν οἱ ἀρχιερεῖς καὶ οἱ Φαρισαῖοι πρὸς Πιλᾶτον", "en": {"kjv": "Now the next day, that followed the day of the preparation, the chief priests and Pharisees came together unto Pilate,", "web": "Now on the next day, which was the day after the Preparation Day, the chief priests and the Pharisees were gathered together to Pilate,", "bsb": "The next day, the one after Preparation Day, the chief priests and Pharisees assembled before Pilate.", "asv": "Now on the morrow, which is the day after the Preparation, the chief priests and the Pharisees were gathered together unto Pilate,", "ylt": "And on the morrow that is after the preparation, were gathered together the chief priests, and the Pharisees, unto Pilate,", "tyndale": "The nexte daye that foloweth good frydaye the hye prestes and pharises got them selves to Pilate", "dra": "And the next day, which followed the day of preparation, the chief priests and the Pharisees came together to Pilate,", "bbe": "Now on the day after the getting ready of the Passover, the chief priests and Pharisees came together to Pilate,", "geneva": "Nowe the next day that followed the Preparation of the Sabbath, the hie Priestes and Pharises assembled to Pilate,", "wycliffe": "And on `the tother dai, that is aftir pask euen, the princis of prestis and the Farisees camen togidere to Pilat,", "rotherham": "And, on the morrow, which is after the preparation, the High-priests and the Pharisee were gathered together unto Pilate,", "weymouth": "On the next day, the day after the Preparation, the High Priests and the Pharisees came in a body to Pilate.", "darby": "Now on the morrow, which is after the preparation, the chief priests and the Pharisees came together to Pilate,", "twenty": "The next day — that is, the day following the Preparation-Day — the Chief Priests and Pharisees came in a body to Pilate, and said:", "acv": "Now on the morrow, which is after the Preparation, the chief priests and the Pharisees came together to Pilate,", "anderson": "On the morrow, which was the day after the preparation, the chief priests and the Pharisees came together to Pilate,", "haweis": "Now on the morrow, which is the day after the preparation, the chief priests and Pharisees came in a body to Pilate,", "noyes": "And on the next day, that following the day of the preparation, the chief priests and the Pharisees came together to Pilate,", "webster": "Now the next day that followed the day of the preparation, the chief priests and Pharisees came together to Pilate,", "vulgate": "altera autem die quae est post parasceven convenerunt principes sacerdotum et Pharisaei ad Pilatum;"}}, {"v": 63, "ref": "27:63", "o": "λέγοντες· Κύριε, ἐμνήσθημεν ὅτι ἐκεῖνος ὁ πλάνος εἶπεν ἔτι ζῶν· Μετὰ τρεῖς ἡμέρας ἐγείρομαι·", "en": {"kjv": "Saying, Sir, we remember that that deceiver said, while he was yet alive, After three days I will rise again.", "web": "saying, “Sir, we remember what that deceiver said while he was still alive: ‘After three days I will rise again.’", "bsb": "“Sir,” they said, “we remember that while He was alive that deceiver said, ‘After three days I will rise again.’", "asv": "saying, Sir, we remember that that deceiver said while he was yet alive, After three days I rise again.", "ylt": "saying, `Sir, we have remembered that that deceiver said while yet living, After three days I do rise;", "tyndale": "and sayde: Syr we remember yt this deceaver sayde whyll he was yet alyve After thre dayes I will aryse agayne.", "dra": "Saying: Sir, we have remembered, that that seducer said, while he was yet alive: After three days I will rise again.", "bbe": "Saying, Sir, we have in mind how that false man said, while he was still living, After three days I will come again from the dead.", "geneva": "And said, Syr, we remember that that deceiuer saide, while he was yet aliue, Within three dayes I will rise.", "wycliffe": "and seiden, Sir, we han mynde, that thilke giloure seide yit lyuynge, Aftir thre daies Y schal rise ayen to lijf.", "rotherham": "saying—Sir! we have been put in mind that, that deceiver, said, while yet living,—After three days, will I, arise.", "weymouth": "\"Sir,\" they said, \"we recollect that during his lifetime that impostor pretended that after two days he was to rise to life again.", "darby": "saying, Sir, we have called to mind that that deceiver said when he was still alive, After three days I arise.", "twenty": "“Sir, we remember that, during his lifetime, that impostor said ‘I shall rise after three days.’", "acv": "saying, Sir, we remember that that deceiver said while he was still alive, After three days I am raised.", "anderson": "and said: Sir, we remember that that deceiver said, while he was yet alive, After three days I will arise.", "haweis": "saying, Sir, we have reflected, that this deceiver, when yet alive, said, After three days I will rise again.", "noyes": "saying, Sir, we remember that that deceiver said, while he was yet alive, After three days I rise.", "webster": "Saying, Sir, we remember that that deceiver said, while he was yet alive, After three days I will rise again.", "vulgate": "dicentes domine recordati sumus quia seductor ille dixit adhuc vivens post tres dies resurgam;"}}, {"v": 64, "ref": "27:64", "o": "κέλευσον οὖν ἀσφαλισθῆναι τὸν τάφον ἕως τῆς τρίτης ἡμέρας, μήποτε ἐλθόντες οἱ μαθηταὶ ⸀αὐτοῦ κλέψωσιν αὐτὸν καὶ εἴπωσιν τῷ λαῷ· Ἠγέρθη ἀπὸ τῶν νεκρῶν, καὶ ἔσται ἡ ἐσχάτη πλάνη χείρων τῆς πρώτης.", "en": {"kjv": "Command therefore that the sepulchre be made sure until the third day, lest his disciples come by night, and steal him away, and say unto the people, He is risen from the dead: so the last error shall be worse than the first.", "web": "Command therefore that the tomb be made secure until the third day, lest perhaps his disciples come at night and steal him away, and tell the people, ‘He is risen from the dead;’ and the last deception will be worse than the first.”", "bsb": "So give the order that the tomb be secured until the third day. Otherwise, His disciples may come and steal Him away and tell the people He has risen from the dead. And this last deception would be worse than the first.”", "asv": "Command therefore that the sepulchre be made sure until the third day, lest haply his disciples come and steal him away, and say unto the people, He is risen from the dead: and the last error will be worse than the first.", "ylt": "command, then, the sepulchre to be made secure till the third day, lest his disciples, having come by night, may steal him away, and may say to the people, He rose from the dead, and the last deceit shall be worse than the first.'", "tyndale": "Commaunde therfore that the sepulcre be made sure vntyll ye thyrd daye lest paraventure his disciples come and steale him awaye and saye vnto the people he is rysen from deeth and the laste erroure be worsse then the fyrst.", "dra": "Command therefore the sepulchre to be guarded until the third day: lest perhaps his disciples come and steal him away and say to the people: He is risen from the dead. And the last error shall be worse than the first.", "bbe": "Give orders, then, that the place where his body is may be made safe till the third day, for fear that his disciples come and take him away secretly and say to the people, He has come back from the dead: and the last error will be worse than the first.", "geneva": "Command therefore, that the sepulchre be made sure vntill the third day, lest his disciples come by night, and steale him away, and say vnto the people, He is risen from the dead: so shall the last errour be worse then the first.", "wycliffe": "Therfor comaunde thou, that the sepulcre be kept in to the thridde dai; lest hise disciplis comen, and stelen hym, and seie to the puple, He hath rise fro deeth; and the laste errour schal be worse than the formere.", "rotherham": "Command, therefore, that the sepulchre be made secure until the third day,—lest once the disciples should come and steal him, and say unto the people, He hath arisen from the dead! and, the last deception, shall be, worse than the first.", "weymouth": "So give orders for the sepulchre to be securely guarded till the third day, for fear his disciples should come by night and steal the body, and then tell the people that he has come back to life; and so the last imposture will be more serious than the first.\"", "darby": "Command therefore that the sepulchre be secured until the third day, lest his disciples should come and steal him away, and say to the people, He is risen from the dead; and the last error shall be worse than the first.", "twenty": "So order the tomb to be made secure till the third day. Otherwise his disciples may come and steal him, and then say to the people ‘He has risen from the dead,’ when the latest imposture will be worse than the first.”", "acv": "Command therefore to secure the tomb until the third day, lest his disciples having come by night steal him away, and say to the people, He was raised from the dead. And the last error will be worse than the first.", "anderson": "Therefore, command that the sepulcher be made safe till the third day, lest his disciples come and steal him away, and say to the people, He has risen from the dead; and the last error will be worse than the first.", "haweis": "Command therefore that the sepulchre be made perfectly secure until the third day, lest his disciples coming by night, steal him, and say to the people, He is risen from the dead, so the last delusion would be worse than the first.", "noyes": "Command therefore that the sepulchre be made secure until the third day, lest his disciples come and steal him away, and say to the people, He hath risen from the dead; and the last error will be worse than the first.", "webster": "Command therefore that the sepulcher be made secure until the third day, lest his disciples come by night, and steal him away, and say to the people, He is risen from the dead: so the last error will be worse than the first.", "vulgate": "iube ergo custodiri sepulchrum usque in diem tertium ne forte veniant discipuli eius et furentur eum et dicant plebi surrexit a mortuis et erit novissimus error peior priore;"}}, {"v": 65, "ref": "27:65", "o": "⸀ἔφη αὐτοῖς ὁ Πιλᾶτος· Ἔχετε κουστωδίαν· ὑπάγετε ἀσφαλίσασθε ὡς οἴδατε.", "en": {"kjv": "Pilate said unto them, Ye have a watch: go your way, make it as sure as ye can.", "web": "Pilate said to them, “You have a guard. Go, make it as secure as you can.”", "bsb": "“You have a guard,” Pilate said. “Go, make the tomb as secure as you know how.”", "asv": "Pilate said unto them, Ye have a guard: go, make it as sure as ye can.", "ylt": "And Pilate said to them, `Ye have a watch, go away, make secure--as ye have known;'", "tyndale": "Pilate sayde vnto them. Take watche men: Go and make it as sure as ye can.", "dra": "Pilate saith to them: You have a guard. Go, guard it as you know.", "bbe": "Pilate said to them, You have watchmen; go and make it as safe as you are able.", "geneva": "Then Pilate saide vnto them, Ye haue a watch: goe, and make it sure as ye knowe.", "wycliffe": "Pilat seide to hem, Ye han the kepyng; go ye, kepe ye as ye kunnen.", "rotherham": "Pilate saith unto them—Ye have a guard: Go your way, secure it for yourselves, as ye know how.", "weymouth": "\"You can have a guard,\" said Pilate: \"go and make all safe, as best you can.\"", "darby": "And Pilate said to them, Ye have a watch: go, secure it as well as ye know how.", "twenty": "“You may have a guard,” was Pilate’s reply; “go and make the tomb as secure as you can.”", "acv": "Pilate said to them, Ye have security. Go, make it as secure as ye know how.", "anderson": "Pilate said to them: You have a guard; go, make it as safe as you know how.", "haweis": "Then said Pilate unto them, Ye have a guard, go and make it as secure as ye think fit.", "noyes": "Pilate said to them, Ye have a guard; go, make it as secure as ye know how.", "webster": "Pilate said to them, Ye have a watch: go, make [it] as secure as ye can.", "vulgate": "ait illis Pilatus habetis custodiam ite custodite sicut scitis;"}}, {"v": 66, "ref": "27:66", "o": "οἱ δὲ πορευθέντες ἠσφαλίσαντο τὸν τάφον σφραγίσαντες τὸν λίθον μετὰ τῆς κουστωδίας.", "en": {"kjv": "So they went, and made the sepulchre sure, sealing the stone, and setting a watch.", "web": "So they went with the guard and made the tomb secure, sealing the stone.", "bsb": "So they went and secured the tomb by sealing the stone and posting the guard.", "asv": "So they went, and made the sepulchre sure, sealing the stone, the guard being with them.", "ylt": "and they, having gone, did make the sepulchre secure, having sealed the stone, together with the watch.", "tyndale": "And they went and made the sepulcre sure with watche men and sealed the stone.", "dra": "And they departing, made the sepulchre sure, sealing the stone and setting guards.", "bbe": "So they went, and made safe the place where his body was, putting a stamp on the stone, and the watchmen were with them.", "geneva": "And they went, and made the sepulchre sure with the watch, and sealed the stone.", "wycliffe": "And thei yeden forth, and kepten the sepulcre, markynge the stoon, with keperis.", "rotherham": "And, they, went and secured for themselves the sepulchre, sealing the stone, with the guard.", "weymouth": "So they went and made the sepulchre secure, sealing the stone besides setting the guard.", "darby": "And they went and secured the sepulchre, having sealed the stone, with the watch [besides].", "twenty": "So they went made the tomb secure, by sealing the stone, in presence of the guard.", "acv": "And having gone, they made the tomb secure, with the security having sealed the stone.", "anderson": "And they went and made the sepulcher safe, by placing a seal upon the stone, and setting the guard.", "haweis": "So they went and made the sepulchre secure, putting a seal upon the stone, after placing the guard.", "noyes": "And they went, and made the sepulchre secure, sealing the stone, and setting the guard.", "webster": "So they went, and having sealed the stone, made the sepulcher secure with a watch.", "vulgate": "illi autem abeuntes munierunt sepulchrum signantes lapidem cum custodibus;"}}]}, {"c": 28, "verses": [{"v": 1, "ref": "28:1", "o": "Ὀψὲ δὲ σαββάτων, τῇ ἐπιφωσκούσῃ εἰς μίαν σαββάτων, ἦλθεν ⸀Μαριὰμ ἡ Μαγδαληνὴ καὶ ἡ ἄλλη Μαρία θεωρῆσαι τὸν τάφον.", "en": {"kjv": "In the end of the sabbath, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.", "web": "Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb.", "bsb": "After the Sabbath, at dawn on the first day of the week, Mary Magdalene and the other Mary went to see the tomb.", "asv": "Now late on the sabbath day, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.", "ylt": "And on the eve of the sabbaths, at the dawn, toward the first of the sabbaths, came Mary the Magdalene, and the other Mary, to see the sepulchre,", "tyndale": "The Sabboth daye at even which dauneth the morowe after the Sabboth Mary Magdalene and the other Mary came to se the sepulcre.", "dra": "And in the end of the sabbath, when it began to dawn towards the first day of the week, came Mary Magdalen and the other Mary, to see the sepulchre.", "bbe": "Now late on the Sabbath, when the dawn of the first day of the week was near, Mary Magdalene and the other Mary came to see the place where his body was.", "geneva": "Now in the end of the Sabbath, when the first day of ye weeke began to dawne, Marie Magdalene, and the other Marie came to see the sepulchre,", "wycliffe": "But in the euentid of the sabat, that bigynneth to schyne in the firste dai of the woke, Marie Mawdelene cam, and another Marie, to se the sepulcre.", "rotherham": "And, late in the week, when it was on the point of dawning into the first of the week, came Mary the Magdalene, and the other Mary, to view the sepulchre.", "weymouth": "After the Sabbath, in the early dawn of the first day of the week, Mary of Magdala and the other Mary came to see the sepulchre.", "darby": "Now late on sabbath, as it was the dusk of the next day after sabbath, came Mary of Magdala and the other Mary to look at the sepulchre.", "twenty": "After the Sabbath, as the first day of the week began to dawn, Mary of Magdala and the other Mary had gone to look at the grave,", "acv": "Now late on the sabbath day, being dawn toward the first day of the week, Mary Magdalene and the other Mary came to see the tomb.", "anderson": "And after the sabbath, as it began to dawn toward the first day of the week, Mary Magdalene and the other Mary came to see the sepulcher.", "haweis": "NOW after the eve of the sabbath, as the light was dawning, towards the first day of the week, Mary Magdalen had come, and the other Mary, to view the sepulchre.", "noyes": "And the sabbath being over, as it began to dawn toward the first day of the week, came Mary the Magdalene, and the other Mary, to view the sepulchre.", "webster": "In the end of the sabbath, as it began to dawn towards the first [day] of the week, came Mary Magdalene, and the other Mary to see the sepulcher.", "vulgate": "vespere autem sabbati quae lucescit in primam sabbati venit Maria Magdalene et altera Maria videre sepulchrum;"}}, {"v": 2, "ref": "28:2", "o": "καὶ ἰδοὺ σεισμὸς ἐγένετο μέγας· ἄγγελος γὰρ κυρίου καταβὰς ἐξ οὐρανοῦ ⸀καὶ προσελθὼν ἀπεκύλισε τὸν ⸀λίθον καὶ ἐκάθητο ἐπάνω αὐτοῦ.", "en": {"kjv": "And, behold, there was a great earthquake: for the angel of the Lord descended from heaven, and came and rolled back the stone from the door, and sat upon it.", "web": "Behold, there was a great earthquake, for an angel of the Lord descended from the sky, and came and rolled away the stone from the door, and sat on it.", "bsb": "Suddenly there was a great earthquake, for an angel of the Lord descended from heaven, rolled away the stone, and sat on it.", "asv": "And behold, there was a great earthquake; for an angel of the Lord descended from heaven, and came and rolled away the stone, and sat upon it.", "ylt": "and lo, there came a great earthquake, for a messenger of the Lord, having come down out of heaven, having come, did roll away the stone from the door, and was sitting upon it,", "tyndale": "And beholde ther was a greate erth quake. For the angell of ye lorde descended from heven: and came and rowlled backe the stone from the dore and sate apon it.", "dra": "And behold there was a great earthquake. For an angel of the Lord descended from heaven and coming rolled back the stone and sat upon it.", "bbe": "And there was a great earth-shock; for an angel of the Lord came down from heaven and, rolling back the stone, took his seat on it.", "geneva": "And behold, there was a great earthquake: for the Angel of the Lord descended from heauen, and came and rolled backe the stone from the doore, and sate vpon it.", "wycliffe": "And lo! ther was maad a greet ertheschakyng; for the aungel of the Lord cam doun fro heuene, and neiyede, and turnede awei the stoon, and sat theron.", "rotherham": "And lo! a great commotion occurred,—for, a messenger of the Lord, descending out of heaven, and coming near, had rolled away the stone, and was sitting upon it.", "weymouth": "But to their amazement there had been a great earthquake; for an angel of the Lord had descended from Heaven, and had come and rolled back the stone, and was sitting upon it.", "darby": "And behold, there was a great earthquake; for an angel of [the] Lord, descending out of heaven, came and rolled away the stone and sat upon it.", "twenty": "when suddenly a great earthquake occurred. For an angel of the Lord descended from Heaven, and came and rolled away the stone, and seated himself upon it.", "acv": "And behold, a great earthquake occurred, for an agent of the Lord, having descended from heaven, having come, he rolled the stone away from the door and sat upon it.", "anderson": "And behold, there had been a great earthquake; for an angel of the Lord having descended from heaven, came and rolled away the stone from the door, and sat upon it.", "haweis": "And, lo! there was a great earthquake; for an angel of the Lord descending from heaven, came and rolled back the stone from the door, and sat upon it.", "noyes": "And, lo! there was a great earthquake; for an angel of the Lord descended from heaven, and came and rolled away the stone, and sat upon it.", "webster": "And behold, there was a great earthquake: for the angel of the Lord descended from heaven, and came and rolled back the stone from the door, and sat upon it.", "vulgate": "et ecce terraemotus factus est magnus angelus enim Domini descendit de caelo et accedens revolvit lapidem et sedebat super eum;"}}, {"v": 3, "ref": "28:3", "o": "ἦν δὲ ἡ εἰδέα αὐτοῦ ⸀ὡς ἀστραπὴ καὶ τὸ ἔνδυμα αὐτοῦ λευκὸν ὡς χιών.", "en": {"kjv": "His countenance was like lightning, and his raiment white as snow:", "web": "His appearance was like lightning, and his clothing white as snow.", "bsb": "His appearance was like lightning, and his clothes were white as snow.", "asv": "His appearance was as lightning, and his raiment white as snow:", "ylt": "and his countenance was as lightning, and his clothing white as snow,", "tyndale": "His countenaunce was lyke lyghtnynge and his raymet whyte as snowe.", "dra": "And his countenance was as lightning and his raiment as snow.", "bbe": "His form was shining like the light, and his clothing was white as snow:", "geneva": "And his countenance was like lightning, and his raiment white as snowe.", "wycliffe": "And his lokyng was as leit, and hise clothis as snowe;", "rotherham": "Now his appearance, was, as lightning, and, his clothing, white as snow;", "weymouth": "His appearance was like lightning, and his raiment white as snow.", "darby": "And his look was as lightning, and his clothing white as snow.", "twenty": "His appearance was as dazzling as lightning, and his clothing was as white as snow;", "acv": "And his appearance was as lightning and his clothing white as snow.", "anderson": "His appearance was like lightning, and his raiment was white as snow.", "haweis": "His aspect was as lightning, and his raiment white as snow.", "noyes": "His appearance was like lightning, and his raiment white as snow.", "webster": "His countenance was like lightning, and his raiment white as snow.", "vulgate": "erat autem aspectus eius sicut fulgur et vestimentum eius sicut nix;"}}, {"v": 4, "ref": "28:4", "o": "ἀπὸ δὲ τοῦ φόβου αὐτοῦ ἐσείσθησαν οἱ τηροῦντες καὶ ἐγενήθησαν ⸀ὡς νεκροί.", "en": {"kjv": "And for fear of him the keepers did shake, and became as dead men.", "web": "For fear of him, the guards shook, and became like dead men.", "bsb": "The guards trembled in fear of him and became like dead men.", "asv": "and for fear of him the watchers did quake, and became as dead men.", "ylt": "and from the fear of him did the keepers shake, and they became as dead men.", "tyndale": "And for feare of him the kepers were astunnyed and became as deed men.", "dra": "And for fear of him, the guards were struck with terror and became as dead men.", "bbe": "And for fear of him the watchmen were shaking, and became as dead men.", "geneva": "And for feare of him, the keepers were astonied, and became as dead men.", "wycliffe": "and for drede of hym the keperis weren afeerd, and thei weren maad as deede men.", "rotherham": "and, for fear of him, they who were keeping watch were thrown into a commotion, and became as dead men.", "weymouth": "For fear of him the guards trembled violently, and became like dead men.", "darby": "And for fear of him the guards trembled and became as dead men.", "twenty": "and, in their terror of him, the men on guard trembled violently and became like dead men.", "acv": "And those watching over shook from fear of him, and became as dead men.", "anderson": "From fear of him the keepers did shake and become like dead men.", "haweis": "And for fear of him the guards shook, and became as dead men.", "noyes": "And for fear of him the keepers shook, and became as dead men.", "webster": "And for fear of him the keepers trembled and became as dead [men].", "vulgate": "prae timore autem eius exterriti sunt custodes et facti sunt velut mortui;"}}, {"v": 5, "ref": "28:5", "o": "ἀποκριθεὶς δὲ ὁ ἄγγελος εἶπεν ταῖς γυναιξίν· Μὴ φοβεῖσθε ὑμεῖς, οἶδα γὰρ ὅτι Ἰησοῦν τὸν ἐσταυρωμένον ζητεῖτε·", "en": {"kjv": "And the angel answered and said unto the women, Fear not ye: for I know that ye seek Jesus, which was crucified.", "web": "The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified.", "bsb": "But the angel said to the women, “Do not be afraid, for I know that you are looking for Jesus, who was crucified.", "asv": "And the angel answered and said unto the women, Fear not ye; for I know that ye seek Jesus, who hath been crucified.", "ylt": "And the messenger answering said to the women, `Fear not ye, for I have known that Jesus, who hath been crucified, ye seek;", "tyndale": "The angell answered and sayde to the wemen feare ye not. I knowe yt ye seke Iesus which was crucified:", "dra": "And the angel answering, said to the women: Fear not you: for I know that you seek Jesus who was crucified.", "bbe": "And the angel said to the women, Have no fear: for I see that you are searching for Jesus, who was put to death on the cross.", "geneva": "But the Angel answered, and said to the women, Feare ye not: for I know that ye seeke Iesus which was crucified:", "wycliffe": "But the aungel answeride, and seide to the wymmen, Nyle ye drede, for Y woot that ye seken Jhesu, that was crucified;", "rotherham": "But the messenger, answering, said unto the women—Be not, ye, afraid! For I know that, Jesus the crucified, ye are seeking:", "weymouth": "But the angel said to the women, \"As for you, dismiss your fears. I know that it is Jesus that you are looking for--the crucified One.", "darby": "And the angel answering said to the women, Fear not ye, for I know that ye seek Jesus the crucified one.", "twenty": "But the angel, addressing the women, said; “You need not be afraid. I now that it is Jesus, who was crucified, for whom you are looking.", "acv": "And having responded, the agent said to the women, Fear ye not, for I know that ye seek Jesus, who was crucified.", "anderson": "But the angel answered and said to the women: Fear not; for I know that you seek Jesus, who was crucified.", "haweis": "Then the angel addressing them, said to the women, Fear not ye; for I know that ye are seeking Jesus who was crucified.", "noyes": "And the angel answering said to the women, Fear ye not; for I know that ye are seeking Jesus, who was crucified.", "webster": "And the angel answered and said to the women, Fear ye not: for I know that ye seek Jesus, who was crucified.", "vulgate": "respondens autem angelus dixit mulieribus nolite timere vos scio enim quod Iesum qui crucifixus est quaeritis;"}}, {"v": 6, "ref": "28:6", "o": "οὐκ ἔστιν ὧδε, ἠγέρθη γὰρ καθὼς εἶπεν· δεῦτε ἴδετε τὸν τόπον ὅπου ⸀ἔκειτο·", "en": {"kjv": "He is not here: for he is risen, as he said. Come, see the place where the Lord lay.", "web": "He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying.", "bsb": "He is not here; He has risen, just as He said! Come, see the place where He lay.", "asv": "He is not here; for he is risen, even as he said. Come, see the place where the Lord lay.", "ylt": "he is not here, for he rose, as he said; come, see the place where the Lord was lying;", "tyndale": "he is not here: he is rysen as he sayde. Come and se the place where the lorde was put:", "dra": "He is not here. For he is risen, as he said. Come, and see the place where the Lord was laid.", "bbe": "He is not here, for he has come to life again, even as he said. Come, see the Lord's resting-place.", "geneva": "He is not here, for he is risen; as he saide: come, see the place where the Lord was laid,", "wycliffe": "he is not here, for he is risun, as he seide; come ye, and se ye the place, where the Lord was leid.", "rotherham": "He is not here, for he hath arisen, as he said. Come! see the place where he lay;", "weymouth": "He is not here: He has come back to life, as He foretold. Come and see the place where He lay.", "darby": "He is not here, for he is risen, as he said. Come, see the place where the Lord lay.", "twenty": "He is not here; for he has risen, as he said he would. Come, and see the place where he was lying;", "acv": "He is not here, for he was raised as he said. Come, see the place where the Lord lay.", "anderson": "He is not here; for he has risen, as he said. Come, see the place where the Lord lay.", "haweis": "He is not here: he is risen, as he said. Come hither, behold the place where the Lord lay.", "noyes": "He is not here; for he hath risen, as he said. Come, see the place where he lay.", "webster": "He is not here: for he is risen, as he said. Come, see the place where the Lord lay.", "vulgate": "non est hic surrexit enim sicut dixit venite videte locum ubi positus erat Dominus;"}}, {"v": 7, "ref": "28:7", "o": "καὶ ταχὺ πορευθεῖσαι εἴπατε τοῖς μαθηταῖς αὐτοῦ ὅτι Ἠγέρθη ἀπὸ τῶν νεκρῶν, καὶ ἰδοὺ προάγει ὑμᾶς εἰς τὴν Γαλιλαίαν, ἐκεῖ αὐτὸν ὄψεσθε· ἰδοὺ εἶπον ὑμῖν.", "en": {"kjv": "And go quickly, and tell his disciples that he is risen from the dead; and, behold, he goeth before you into Galilee; there shall ye see him: lo, I have told you.", "web": "Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes before you into Galilee; there you will see him.’ Behold, I have told you.”", "bsb": "Then go quickly and tell His disciples, ‘He has risen from the dead and is going ahead of you into Galilee. There you will see Him.’ See, I have told you.”", "asv": "And go quickly, and tell his disciples, He is risen from the dead; and lo, he goeth before you into Galilee; there shall ye see him: lo, I have told you.", "ylt": "and having gone quickly, say ye to his disciples, that he rose from the dead; and lo, he doth go before you to Galilee, there ye shall see him; lo, I have told you.'", "tyndale": "and goo quickly and tell his disciples yt he is rysen from deeth. And beholde he will go before you into Galile there ye shall se him. Lo I have tolde you.", "dra": "And going quickly, tell ye his disciples that he is risen. And behold he will go before you into Galilee. There you shall see him. Lo, I have foretold it to you.", "bbe": "And go quickly and give his disciples the news that he has come back from the dead, and is going before you into Galilee; there you will see him, as I have said to you.", "geneva": "And go quickly, and tel his disciples that he is risen from ye dead: and behold, he goeth before you into Galile: there ye shall see him: loe, I haue told you.", "wycliffe": "And go ye soone, and seie ye to his disciplis, that he is risun. And lo! he schal go bifore you in to Galilee; there ye schulen se hym.", "rotherham": "And, quickly going, tell his disciples—He hath arisen from the dead, and lo! he is going before you into Galilee;—There, shall ye yourselves see him: Lo! I have told you.", "weymouth": "And go quickly and tell His disciples that He has risen from the dead and is going before you into Galilee: there you shall see Him. Remember, I have told you.\"", "darby": "And go quickly and say to his disciples that he is risen from the dead; and behold, he goes before you into Galilee, there shall ye see him. Behold, I have told you.", "twenty": "and then go quickly and say to him disciples ‘He has risen from the dead, and is going before you into Galilee; there you will see him.’ Remember, I have told you.”", "acv": "And after going quickly, tell his disciples, He was raised from the dead, and lo, he goes before you into Galilee. There ye will see him. Behold, I have told you.", "anderson": "And go quickly, and tell his disciples, that he has risen from the dead: and behold, he goes before you into Galilee. There you shall see him. Lo, I have told you.", "haweis": "And go quickly, tell his disciples that he is risen from the dead: and, lo! he goeth before you into Galilee; there shall ye see him, as he said unto you.", "noyes": "And go quickly, and tell his disciples that he hath risen from the dead, and, lo! he is going before you into Galilee; there shall ye see him. Lo! I have told you.", "webster": "And go quickly, and tell his disciples, that he is risen from the dead, and behold, he goeth before you into Galilee; there shall ye see him: lo, I have told you.", "vulgate": "et cito euntes dicite discipulis eius quia surrexit et ecce praecedit vos in Galilaeam ibi eum videbitis ecce praedixi vobis;"}}, {"v": 8, "ref": "28:8", "o": "καὶ ⸀ἀπελθοῦσαι ταχὺ ἀπὸ τοῦ μνημείου μετὰ φόβου καὶ χαρᾶς μεγάλης ἔδραμον ἀπαγγεῖλαι τοῖς μαθηταῖς αὐτοῦ.", "en": {"kjv": "And they departed quickly from the sepulchre with fear and great joy; and did run to bring his disciples word.", "web": "They departed quickly from the tomb with fear and great joy, and ran to bring his disciples word.", "bsb": "So they hurried away from the tomb in fear and great joy, and ran to tell His disciples.", "asv": "And they departed quickly from the tomb with fear and great joy, and ran to bring his disciples word.", "ylt": "And having gone forth quickly from the tomb, with fear and great joy, they ran to tell to his disciples;", "tyndale": "And they departed quickly from the sepulcre with feare and greate Ioye: and did runne to bringe his disciples worde.", "dra": "And they went out quickly from the sepulchre with fear and great joy, running to tell his disciples.", "bbe": "And they went away quickly, with fear and great joy, to give his disciples the news.", "geneva": "So they departed quickly from the sepulchre, with feare and great ioye, and did runne to bring his disciples worde.", "wycliffe": "Lo! Y haue biforseid to you. And thei wenten out soone fro the biriels, with drede and greet ioye, rennynge to telle to hise disciplis.", "rotherham": "And, departing quickly from the tomb with fear and great joy, they ran to bring tidings unto his disciples.", "weymouth": "They quickly left the tomb and ran, still terrified but full of unspeakable joy, to carry the news to His disciples.", "darby": "And going out quickly from the tomb with fear and great joy, they ran to bring his disciples word.", "twenty": "On this they left the tomb quickly, in awe and great joy, and ran to tell the news to the disciples.", "acv": "And after coming out quickly from the sepulcher with fear and great joy, they ran to notify his disciples.", "anderson": "And they went out quickly from the sepulcher, with fear and great joy, and ran to tell his disciples.", "haweis": "And they went out quickly from the sepulchre with fear, and great joy; and ran to carry the tidings to his disciples.", "noyes": "And they went away quickly from the tomb with fear and great joy, and ran to tell his disciples.", "webster": "And they departed quickly from the sepulcher, with fear and great joy; and ran to bring word to his disciples.", "vulgate": "et exierunt cito de monumento cum timore et magno gaudio currentes nuntiare discipulis eius;"}}, {"v": 9, "ref": "28:9", "o": "⸀καὶ ⸀ἰδοὺ Ἰησοῦς ⸀ὑπήντησεν αὐταῖς λέγων· Χαίρετε· αἱ δὲ προσελθοῦσαι ἐκράτησαν αὐτοῦ τοὺς πόδας καὶ προσεκύνησαν αὐτῷ.", "en": {"kjv": "And as they went to tell his disciples, behold, Jesus met them, saying, All hail. And they came and held him by the feet, and worshipped him.", "web": "As they went to tell his disciples, behold, Jesus met them, saying, “Rejoice!” They came and took hold of his feet, and worshiped him.", "bsb": "Suddenly Jesus met them and said, “Greetings!” They came to Him, grasped His feet, and worshiped Him.", "asv": "And behold, Jesus met them, saying, All hail. And they came and took hold of his feet, and worshipped him.", "ylt": "and as they were going to tell to his disciples, then lo, Jesus met them, saying, `Hail!' and they having come near, laid hold of his feet, and did bow to him.", "tyndale": "And as they went to tell his disciples: beholde Iesus met them sayinge: All hayle. And they came and held him by the fete and worshipped him.", "dra": "And behold, Jesus met them, saying: All hail. But they came up and took hold of his feet and adored him.", "bbe": "And on the way, Jesus came to them, saying, Be glad. And they came and put their hands on his feet, and gave him worship.", "geneva": "And as they wet to tel his disciples, behold, Iesus also met the, saying, God saue you. And they came, and tooke him by the feete, and worshipped him.", "wycliffe": "And lo! Jhesus mette hem, and seide, Heile ye. And thei neiyeden, and heelden his feet, and worschipiden him.", "rotherham": "And lo! Jesus, met them, saying—Joy to you! And, they, going forward, held his feet, and worshipped him.", "weymouth": "And then suddenly they saw Jesus coming to meet them. \"Peace be to you,\" He said. And they came and clasped His feet, bowing to the ground before Him.", "darby": "And as they went to bring his disciples word, behold also, Jesus met them, saying, Hail! And they coming up took him by the feet, and did him homage.", "twenty": "Suddenly Jesus met them. “Welcome!” he said. The women went up to him, and clasped his feet, bowing to the ground before him. Then Jesus said to them:", "acv": "And as they were going to tell his disciples, behold, Jesus also met them, saying, Hail. And having come, they held his feet and worshiped him.", "anderson": "And as they were going to tell his disciples, behold, Jesus met them, saying: Hail! And they came and laid hold of his feet, and worshiped him.", "haweis": "And as they were going to tell the disciples, then behold Jesus met them saying, Hail! And they came and held him by the feet, and worshipped him.", "noyes": "And lo! Jesus met them, saying, All hail! And they went up, and laid hold of his feet, and knelt down before him.", "webster": "And as they were going to tell his disciples, behold, Jesus met them, saying, All hail. And they came, and held him by the feet, and worshiped him.", "vulgate": "et ecce Iesus occurrit illis dicens havete illae autem accesserunt et tenuerunt pedes eius et adoraverunt eum;"}}, {"v": 10, "ref": "28:10", "o": "τότε λέγει αὐταῖς ὁ Ἰησοῦς· Μὴ φοβεῖσθε· ὑπάγετε ἀπαγγείλατε τοῖς ἀδελφοῖς μου ἵνα ἀπέλθωσιν εἰς τὴν Γαλιλαίαν, κἀκεῖ με ὄψονται.", "en": {"kjv": "Then said Jesus unto them, Be not afraid: go tell my brethren that they go into Galilee, and there shall they see me.", "web": "Then Jesus said to them, “Don’t be afraid. Go tell my brothers that they should go into Galilee, and there they will see me.”", "bsb": "“Do not be afraid,” said Jesus. “Go and tell My brothers to go to Galilee. There they will see Me.”", "asv": "Then saith Jesus unto them, Fear not: go tell my brethren that they depart into Galilee, and there shall they see me.", "ylt": "Then saith Jesus to them, `Fear ye not, go away, tell to my brethren that they may go away to Galilee, and there they shall see me.'", "tyndale": "The sayde Iesus vnto them: be not afrayde. Go and tell my brethren that they goo in to Galile and there shall they se me.", "dra": "Then Jesus said to them: Fear not. Go, tell my brethren that they go into Galilee. There they shall see me.", "bbe": "Then said Jesus to them, Have no fear: go and give word to my brothers to go into Galilee, and there they will see me.", "geneva": "Then said Iesus vnto them, Be not afraide. Goe, and tell my brethren, that they goe into Galile, and there shall they see me.", "wycliffe": "Thanne Jhesus seide to hem, Nyle ye drede; go ye, `telle ye to my britheren, that thei go in to Galile; there thei schulen se me.", "rotherham": "Then, Jesus saith unto them—Be not afraid! Go your way, bear tidings unto my brethren, that they may depart into Galilee; and, there, shall they themselves see me.", "weymouth": "Then He said, \"Dismiss all fear! Go and take word to my brethren to go into Galilee, and there they shall see me.\"", "darby": "Then Jesus says to them, Fear not; go, bring word to my brethren that they go into Galilee, and there they shall see me.", "twenty": "“Do not be afraid; go and tell my brothers to set out for Galilee, and they shall see me there.”", "acv": "Then Jesus says to them, Fear not. Go notify my brothers that they should depart into Galilee, and there they will see me.", "anderson": "Then Jesus said to them: Fear not; go, tell my brethren to go into Galilee, and there they shall see me.", "haweis": "Then saith Jesus to them, Be not affrighted: go, tell my disciples that they go into Galilee, there shall they see me.", "noyes": "Then Jesus saith to them, Be not afraid; go, tell my brethren to depart into Galilee, and there they shall see me.", "webster": "Then said Jesus to them, Be not afraid: go tell my brethren, that they go into Galilee, and there shall they see me.", "vulgate": "tunc ait illis Iesus nolite timere ite nuntiate fratribus meis ut eant in Galilaeam ibi me videbunt;"}}, {"v": 11, "ref": "28:11", "o": "Πορευομένων δὲ αὐτῶν ἰδού τινες τῆς κουστωδίας ἐλθόντες εἰς τὴν πόλιν ἀπήγγειλαν τοῖς ἀρχιερεῦσιν ἅπαντα τὰ γενόμενα.", "en": {"kjv": "Now when they were going, behold, some of the watch came into the city, and shewed unto the chief priests all the things that were done.", "web": "Now while they were going, behold, some of the guards came into the city, and told the chief priests all the things that had happened.", "bsb": "While the women were on their way, some of the guards went into the city and reported to the chief priests all that had happened.", "asv": "Now while they were going, behold, some of the guard came into the city, and told unto the chief priests all the things that were come to pass.", "ylt": "And while they are going on, lo, certain of the watch having come to the city, told to the chief priests all the things that happened,", "tyndale": "When they were gone: beholde some of the kepers came into the cyte and shewed vnto the hie prestes all the thinges that were hapened.", "dra": "Who when they were departed, behold, some of the guards came into the city and told the chief priests all things that had been done.", "bbe": "Now, while they were going, some of the watchmen came into the town and gave news to the chief priests of all the things which had taken place.", "geneva": "Nowe when they were gone, beholde, some of the watch came into the citie, and shewed vnto the hie Priestes all ye things that were done.", "wycliffe": "And whanne thei weren goon, lo! summe of the keperis camen in to the citee, and telden to the princis of prestis alle thingis that weren doon.", "rotherham": "Now as they were, going, lo! certain of the guard, went into the city and reported unto the High-priests all the things that had come to pass;", "weymouth": "While they went on this errand, some of the guards came into the city and reported to the High Priests every detail of what had happened.", "darby": "And as they went, behold, some of the watch went into the city, and brought word to the chief priests of all that had taken place.", "twenty": "While they were still on their way, some of the guard came into the city, and reported to the Chief Priests everything that had happened.", "acv": "Now while they were going, behold, some of the security having come into the city, reported to the chief priests all the things that happened.", "anderson": "While they were going, behold, some of the guard came into the city, and told the chief priests all things that were done.", "haweis": "And as they were going, some of the guards who were come into the city, had told the chief priests all things which had happened.", "noyes": "And as they were going, lo! some of the guard came into the city, and told the chief priests all that had taken place.", "webster": "Now when they were going, behold, some of the watch came into the city, and showed to the chief priests all the things that had been done.", "vulgate": "quae cum abissent ecce quidam de custodibus venerunt in civitatem et nuntiaverunt principibus sacerdotum omnia quae facta fuerant;"}}, {"v": 12, "ref": "28:12", "o": "καὶ συναχθέντες μετὰ τῶν πρεσβυτέρων συμβούλιόν τε λαβόντες ἀργύρια ἱκανὰ ἔδωκαν τοῖς στρατιώταις", "en": {"kjv": "And when they were assembled with the elders, and had taken counsel, they gave large money unto the soldiers,", "web": "When they were assembled with the elders, and had taken counsel, they gave a large amount of silver to the soldiers,", "bsb": "And after the chief priests had met with the elders and formed a plan, they gave the soldiers a large sum of money", "asv": "And when they were assembled with the elders, and had taken counsel, they gave much money unto the soldiers,", "ylt": "and having been gathered together with the elders, counsel also having taken, they gave much money to the soldiers,", "tyndale": "And they gaddered them to gedder with the elders and toke counsell and gave large money vnto the soudiers", "dra": "And they being assembled together with the ancients, taking counsel, gave a great sum of money to the soldiers,", "bbe": "And when they had come together with those in authority, and had made their decision, they gave much money to the watchmen, saying,", "geneva": "And they gathered them together with the Elders, and tooke counsell, and gaue large money vnto the souldiers,", "wycliffe": "And whanne thei weren gaderid togidere with the elder men, and hadden take her counseil, thei yauen to the kniytis miche monei, and seiden, Seie ye,", "rotherham": "and, being gathered together with the Elders and taking counsel, sufficient pieces of silver, gave they unto the soldiers,—", "weymouth": "So the latter held a conference with the Elders, and after consultation with them they heavily bribed the soldiers,", "darby": "And having assembled with the elders, and having taken counsel, they gave a large sum of money to the soldiers,", "twenty": "So they and the Councillors met and, after holding a consultation, gave a large sum of money to the soldiers,", "acv": "And after assembling with the elders, and having taken consultation, they gave many silver pieces to the soldiers, saying,", "anderson": "And when they came together with the elders, they held a consultation, and gave much money to the soldiers,", "haweis": "And being assembled with the elders, and having held a council, they gave a large sum of money to the soldiers,", "noyes": "And having assembled with the elders, and taken counsel together, they gave a large sum of money to the soldiers,", "webster": "And when they were assembled with the elders, and had taken counsel, they gave a large sum of money to the soldiers,", "vulgate": "et congregati cum senioribus consilio accepto pecuniam copiosam dederunt militibus;"}}, {"v": 13, "ref": "28:13", "o": "λέγοντες· Εἴπατε ὅτι Οἱ μαθηταὶ αὐτοῦ νυκτὸς ἐλθόντες ἔκλεψαν αὐτὸν ἡμῶν κοιμωμένων·", "en": {"kjv": "Saying, Say ye, His disciples came by night, and stole him away while we slept.", "web": "saying, “Say that his disciples came by night, and stole him away while we slept.", "bsb": "and instructed them: “You are to say, ‘His disciples came by night and stole Him away while we were asleep.’", "asv": "saying, Say ye, His disciples came by night, and stole him away while we slept.", "ylt": "saying, `Say ye, that his disciples having come by night, stole him--we being asleep;", "tyndale": "sayinge: Saye that his disciples came by nyght and stole him awaye whill ye slept.", "dra": "Saying: Say you, His disciples came by night and stole him away when we were asleep.", "bbe": "Say, His disciples came by night and took him away secretly while we were sleeping.", "geneva": "Saying, Say, His disciples came by night, and stole him away while we slept.", "wycliffe": "that hise disciplis camen bi nyyt, and han stolen hym, while ye slepten.", "rotherham": "saying—Say ye, His disciples, coming, by night, stole him, while we were sleeping;", "weymouth": "telling them to say, \"His disciples came during the night and stole his body while we were asleep.\"", "darby": "saying, Say that his disciples coming by night stole him [while] we [were] sleeping.", "twenty": "and told them to say that his disciples came in the night, and stole him while they were asleep;", "acv": "Say ye, His disciples, having come by night, stole him from us while we slept.", "anderson": "saying: Say that his disciples came by night and stole him away, while we were asleep.", "haweis": "saying, Report, that his disciples coming by night stole him away, while you were asleep.", "noyes": "saying, Say, His disciples came by night, and stole him away, while we slept.", "webster": "Saying, Say ye, His disciples came by night, and stole him [away] while we slept.", "vulgate": "dicentes dicite quia discipuli eius nocte venerunt et furati sunt eum nobis dormientibus;"}}, {"v": 14, "ref": "28:14", "o": "καὶ ἐὰν ἀκουσθῇ τοῦτο ⸀ἐπὶ τοῦ ἡγεμόνος, ἡμεῖς πείσομεν ⸀αὐτὸν καὶ ὑμᾶς ἀμερίμνους ποιήσομεν.", "en": {"kjv": "And if this come to the governor’s ears, we will persuade him, and secure you.", "web": "If this comes to the governor’s ears, we will persuade him and make you free of worry.”", "bsb": "If this report reaches the governor, we will satisfy him and keep you out of trouble.”", "asv": "And if this come to the governor’s ears, we will persuade him, and rid you of care.", "ylt": "and if this be heard by the governor, we will persuade him, and you keep free from anxiety.'", "tyndale": "And if this come to the rulers cares we wyll pease him and save you harmeles.", "dra": "And if the governor shall hear of this, we will persuade him and secure you.", "bbe": "And if this comes to the ruler's ears, we will see that he does not make you responsible.", "geneva": "And if this matter come before the gouernour to be heard, we will perswade him, and so vse the matter that you shall not neede to care.", "wycliffe": "And if this be herd of the iustice, we schulen counseile hym, and make you sikir.", "rotherham": "And, if this be reported unto the governor, we, will persuade him, and will make, you, free from care.", "weymouth": "\"And if this,\" they added, \"is reported to the Governor, we will satisfy him and screen you from punishment.\"", "darby": "And if this should come to the hearing of the governor, we will persuade him, and save you from all anxiety.", "twenty": "“And should this matter come before the Governor,” they added, “we will satisfy him, and see that you have nothing to fear.”", "acv": "And if this should be heard by the governor, we will persuade him, and will make you worry free.", "anderson": "And if this shall be heard in the presence of the governor, we will persuade him, and make you secure.", "haweis": "And if this comes to the governor’s ears, we will persuade him, and preserve you harmless.", "noyes": "And should the governor hear of this, we will persuade him, and make you secure.", "webster": "And if this shall come to the governor's ears, we will persuade him, and secure you.", "vulgate": "et si hoc auditum fuerit a praeside nos suadebimus ei et securos vos faciemus;"}}, {"v": 15, "ref": "28:15", "o": "οἱ δὲ λαβόντες ⸀τὰ ἀργύρια ἐποίησαν ὡς ἐδιδάχθησαν. Καὶ διεφημίσθη ὁ λόγος οὗτος παρὰ Ἰουδαίοις μέχρι τῆς σήμερον ⸀ἡμέρας.", "en": {"kjv": "So they took the money, and did as they were taught: and this saying is commonly reported among the Jews until this day.", "web": "So they took the money and did as they were told. This saying was spread abroad among the Jews, and continues until this day.", "bsb": "So the guards took the money and did as they were instructed. And this account has been circulated among the Jews to this very day.", "asv": "So they took the money, and did as they were taught: and this saying was spread abroad among the Jews, and continueth until this day.", "ylt": "And they, having received the money, did as they were taught, and this account was spread abroad among Jews till this day.", "tyndale": "And they toke the money and dyd as they were taught. And this sayinge is noysed amoge the Iewes vnto this daye.", "dra": "So they taking the money, did as they were taught: and this word was spread abroad among the Jews even unto this day.", "bbe": "So they took the money, and did as they had been ordered: and this account has been current among the Jews till the present time.", "geneva": "So they tooke the money, and did as they were taught: and this saying is noysed among the Iewes vnto this day.", "wycliffe": "And whanne the monei was takun, thei diden, as thei weren tauyt. And this word is pupplischid among the Jewis, til in to this day.", "rotherham": "And, they, taking the pieces of silver, did as they were instructed. And this account was spread abroad among the Jews…until this [very] day.", "weymouth": "So they took the money and did as they were instructed; and this story was noised about among the Jews, and is current to this day.", "darby": "And they took the money and did as they had been taught. And this report is current among the Jews until this day.", "twenty": "So the soldiers took the money, and did as they were instructed. And this story has been current among the Jews from that day to this.", "acv": "And having taken the silver pieces, they did as they were instructed. And this saying was spread abroad among the Jews until this day.", "anderson": "And they took the money, and did as they were taught. And their report of this matter is everywhere published among the Jews to this day.", "haweis": "So they took the money, and did as they were instructed. And this account is circulated among the Jews to this day.", "noyes": "So they took the money, and did as they were taught. And this story hath been commonly reported among the Jews to this day.", "webster": "So they took the money, and did as they were instructed: and this saying is commonly reported among the Jews until this day.", "vulgate": "at illi accepta pecunia fecerunt sicut erant docti et divulgatum est verbum istud apud Iudaeos usque in hodiernum diem;"}}, {"v": 16, "ref": "28:16", "o": "Οἱ δὲ ἕνδεκα μαθηταὶ ἐπορεύθησαν εἰς τὴν Γαλιλαίαν εἰς τὸ ὄρος οὗ ἐτάξατο αὐτοῖς ὁ Ἰησοῦς,", "en": {"kjv": "Then the eleven disciples went away into Galilee, into a mountain where Jesus had appointed them.", "web": "But the eleven disciples went into Galilee, to the mountain where Jesus had sent them.", "bsb": "Meanwhile, the eleven disciples went to Galilee, to the mountain Jesus had designated.", "asv": "But the eleven disciples went into Galilee, unto the mountain where Jesus had appointed them.", "ylt": "And the eleven disciples went to Galilee, to the mount where Jesus appointed them,", "tyndale": "Then the .xi. disciples went awaye into Galile in to a mountayne where Iesus had appoynted them.", "dra": "And the eleven disciples went into Galilee, unto the mountain where Jesus had appointed them.", "bbe": "But the eleven disciples went into Galilee, to the mountain where Jesus had given them orders to go.", "geneva": "Then ye eleuen disciples wet into Galile, into a mountaine, where Iesus had appointed the.", "wycliffe": "And the enleuen disciplis wenten in to Galilee, in to an hille, where Jhesus hadde ordeyned to hem.", "rotherham": "And, the eleven disciples, went into Galilee, unto the mountain which, Jesus, had appointed them;", "weymouth": "As for the eleven disciples, they proceeded into Galilee, to the hill where Jesus had arranged to meet them.", "darby": "But the eleven disciples went into Galilee to the mountain which Jesus had appointed them.", "twenty": "The eleven disciples went to Galilee, to the mountain where Jesus told them to meet him;", "acv": "But the eleven disciples went for Galilee to the mountain where Jesus arranged for them.", "anderson": "And the eleven disciples went away into Galilee, into the mountain, where Jesus had appointed to meet them.", "haweis": "Then the eleven disciples went into Galilee, to the mountain, where Jesus had ordered them.", "noyes": "And the eleven disciples went into Galilee, into the mountain, where Jesus had directed them.", "webster": "Then the eleven disciples went away into Galilee, to a mountain where Jesus had appointed them.", "vulgate": "undecim autem discipuli abierunt in Galilaeam in montem ubi constituerat illis Iesus;"}}, {"v": 17, "ref": "28:17", "o": "καὶ ἰδόντες αὐτὸν ⸀προσεκύνησαν, οἱ δὲ ἐδίστασαν.", "en": {"kjv": "And when they saw him, they worshipped him: but some doubted.", "web": "When they saw him, they bowed down to him, but some doubted.", "bsb": "When they saw Him, they worshiped Him, but some doubted.", "asv": "And when they saw him, they worshipped him; but some doubted.", "ylt": "and having seen him, they bowed to him, but some did waver.", "tyndale": "And when they sawe hym they worshipped him. But some of them douted.", "dra": "And seeing him they adored: but some doubted.", "bbe": "And when they saw him they gave him worship: but some were in doubt.", "geneva": "And when they sawe him, they worshipped him: but some douted.", "wycliffe": "And thei sayn hym, and worschipiden; but summe of hem doutiden.", "rotherham": "and, seeing him, they worshipped, but, some, doubted.", "weymouth": "There they saw Him and prostrated themselves before Him. Yet some doubted.", "darby": "And when they saw him, they did homage to him: but some doubted.", "twenty": "and, when they saw him, they bowed to the ground before him; although some felt doubtful.", "acv": "And when they saw him, they worshiped him, but men doubted.", "anderson": "And when they saw him, they worshiped him; but some doubted.", "haweis": "And when they saw him, they worshipped him. Still some doubted.", "noyes": "And when they saw him, they knelt down before him; but some doubted.", "webster": "And when they saw him, they worshiped him: but some doubted.", "vulgate": "et videntes eum adoraverunt quidam autem dubitaverunt;"}}, {"v": 18, "ref": "28:18", "o": "καὶ προσελθὼν ὁ Ἰησοῦς ἐλάλησεν αὐτοῖς λέγων· Ἐδόθη μοι πᾶσα ἐξουσία ἐν οὐρανῷ καὶ ἐπὶ ⸀τῆς γῆς·", "en": {"kjv": "And Jesus came and spake unto them, saying, All power is given unto me in heaven and in earth.", "web": "Jesus came to them and spoke to them, saying, “All authority has been given to me in heaven and on earth.", "bsb": "Then Jesus came to them and said, “All authority in heaven and on earth has been given to Me.", "asv": "And Jesus came to them and spake unto them, saying, All authority hath been given unto me in heaven and on earth.", "ylt": "And having come near, Jesus spake to them, saying, `Given to me was all authority in heaven and on earth;", "tyndale": "And Iesus came and spake vnto them sayinge: All power ys geve vnto me in heve and in erth.", "dra": "And Jesus coming, spoke to them, saying: All power is given to me in heaven and in earth.", "bbe": "And Jesus came to them and said, All authority has been given to me in heaven and on earth.", "geneva": "And Iesus came, and spake vnto them, saying, All power is giuen vnto me, in heauen, and in earth.", "wycliffe": "And Jhesus cam nyy, and spak to hem, and seide, Al power in heuene and in erthe is youun to me.", "rotherham": "And Jesus, coming near, spake unto them, saying—All authority, in heaven and on earth, hath been given unto me;", "weymouth": "Jesus however came near and said to them, \"All power in Heaven and over the earth has been given to me.", "darby": "And Jesus coming up spoke to them, saying, All power has been given me in heaven and upon earth.", "twenty": "Then Jesus came up, and spoke to them thus: “All authority in heaven and on the earth has been given to me.", "acv": "And Jesus having come, he spoke to them, saying, All authority in heaven and on earth was given to me.", "anderson": "And Jesus came and spoke to them, saying: All authority in heaven and on earth is given to me.", "haweis": "Then Jesus approaching, spake to them, saying, All power is given me in heaven and upon earth.", "noyes": "And Jesus came up and spoke to them, saying, All power was given to me in heaven and on earth.", "webster": "And Jesus came, and spoke to them, saying, All power is given to me in heaven and upon earth.", "vulgate": "et accedens Iesus locutus est eis dicens data est mihi omnis potestas in caelo et in terra;"}}, {"v": 19, "ref": "28:19", "o": "πορευθέντες ⸀οὖν μαθητεύσατε πάντα τὰ ἔθνη, ⸀βαπτίζοντες αὐτοὺς εἰς τὸ ὄνομα τοῦ πατρὸς καὶ τοῦ υἱοῦ καὶ τοῦ ἁγίου πνεύματος,", "en": {"kjv": "Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost:", "web": "Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit,", "bsb": "Therefore go and make disciples of all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Spirit,", "asv": "Go ye therefore, and make disciples of all the nations, baptizing them into the name of the Father and of the Son and of the Holy Spirit:", "ylt": "having gone, then, disciple all the nations, (baptizing them--to the name of the Father, and of the Son, and of the Holy Spirit,", "tyndale": "Go therfore and teache all nacions baptysinge them in the name of the father and the sonne and the holy goost:", "dra": "Going therefore, teach ye all nations: baptizing them in the name of the Father and of the Son and of the Holy Ghost.", "bbe": "Go then, and make disciples of all the nations, giving them baptism in the name of the Father and of the Son and of the Holy Spirit:", "geneva": "Go therefore, and teach all nations, baptizing them in the Name of the Father, and the Sonne, and the holy Ghost,", "wycliffe": "Therfor go ye, and teche alle folkis, baptisynge hem in the name of the Fadir, and of the Sone, and of the Hooli Goost;", "rotherham": "Go ye, therefore, and disciple all the nations, Immersing them into the name of the Father, and of the Son, and of the Holy Spirit,—", "weymouth": "Go therefore and make disciples of all the nations; baptize them into the name of the Father, and of the Son, and of the Holy Spirit;", "darby": "Go [therefore] and make disciples of all the nations, baptising them to the name of the Father, and of the Son, and of the Holy Spirit;", "twenty": "Therefore go and make disciples of all the nations, baptizing them into the Faith of the Father, the Son, and the Holy Spirit,", "acv": "After going, make ye disciples of all the nations, immersing them into the name of the Father and of the Son and of the Holy Spirit,", "anderson": "Go, therefore, make disciples of all nations, immersing them (the disciples) into the name of the Father, and of the Son, and of the Holy Spirit;", "haweis": "Go therefore, make disciples among all nations, baptising them in the name of the Father, and of the Son, and of the Holy Ghost:", "noyes": "Go, and make all nations my disciples, baptizing them into the name of the Father, and of the Son, and of the Holy Spirit;", "webster": "Go ye therefore and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Spirit.", "vulgate": "euntes ergo docete omnes gentes baptizantes eos in nomine Patris et Filii et Spiritus Sancti;"}}, {"v": 20, "ref": "28:20", "o": "διδάσκοντες αὐτοὺς τηρεῖν πάντα ὅσα ἐνετειλάμην ὑμῖν· καὶ ἰδοὺ ἐγὼ μεθ’ ὑμῶν εἰμι πάσας τὰς ἡμέρας ἕως τῆς συντελείας τοῦ ⸀αἰῶνος.", "en": {"kjv": "Teaching them to observe all things whatsoever I have commanded you: and, lo, I am with you alway, even unto the end of the world. Amen.", "web": "teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen.", "bsb": "and teaching them to obey all that I have commanded you. And surely I am with you always, even to the end of the age.”", "asv": "teaching them to observe all things whatsoever I commanded you: and lo, I am with you always, even unto the end of the world.", "ylt": "teaching them to observe all, whatever I did command you,) and lo, I am with you all the days--till the full end of the age.'", "tyndale": "Teachinge them to observe all thynges what soever I comcommaunded you. And lo I am with you all waye even vntyll the ende of the worlde.", "dra": "Teaching them to observe all things whatsoever I have commanded you. And behold I am with you all days, even to the consummation of the world.", "bbe": "Teaching them to keep all the rules which I have given you: and see, I am ever with you, even to the end of the world.", "geneva": "Teaching them to obserue all things, whatsoeuer I haue commanded you: and lo, I am with you alway, vntill the ende of the worlde, Amen.", "wycliffe": "techynge hem to kepe alle thingis, what euer thingis Y haue comaundid to you; and lo! Y am with you in alle daies, in to the ende of the world.", "rotherham": "Teaching them to observe all things whatsoever I myself have commanded you, And lo! I, am, with you, all the days, until the conclusion of the age.", "weymouth": "and teach them to obey every command which I have given you. And remember, I am with you always, day by day, until the Close of the Age.\"", "darby": "teaching them to observe all things whatsoever I have enjoined you. And behold, I am with you all the days, until the completion of the age.", "twenty": "and teaching them to lay to heart all the commands that I have given you; and, remember, I myself am with you every day until the close of the age.”", "acv": "teaching them to observe all things, as many as I commanded you. And lo, I am with you all the days, until the end of the age. Truly.", "anderson": "teaching them to observe all things whatever I have commanded you: and lo; I am with you all the days, even to the end of the age.", "haweis": "teaching them to observe all things whatsoever I have commanded you: and, lo! I am with you at all times even to the end of the world. Amen. \\p", "noyes": "teaching them to observe all things, whatever I have commanded you. And, lo! I am with you always, unto the end of the world.", "webster": "Teaching them to observe all things whatever I have commanded you: and lo, I am with you always, [even] to the end of the world. Amen.", "vulgate": "docentes eos servare omnia quaecumque mandavi vobis et ecce ego vobiscum sum omnibus diebus usque ad consummationem saeculi;"}}]}]};
window.BOOKS=[{"slug": "mark", "name": "Mark", "file": "Mark.html", "testament": "NT"}, {"slug": "matthew", "name": "Matthew", "file": "Matthew.html", "testament": "NT"}, {"slug": "luke", "name": "Luke", "file": "Luke.html", "testament": "NT"}, {"slug": "john", "name": "John", "file": "John.html", "testament": "NT"}, {"slug": "acts", "name": "Acts", "file": "Acts.html", "testament": "NT"}, {"slug": "romans", "name": "Romans", "file": "Romans.html", "testament": "NT"}, {"slug": "1corinthians", "name": "1 Corinthians", "file": "1Corinthians.html", "testament": "NT"}, {"slug": "philippians", "name": "Philippians", "file": "Philippians.html", "testament": "NT"}, {"slug": "colossians", "name": "Colossians", "file": "Colossians.html", "testament": "NT"}, {"slug": "philemon", "name": "Philemon", "file": "Philemon.html", "testament": "NT"}, {"slug": "hebrews", "name": "Hebrews", "file": "Hebrews.html", "testament": "NT"}, {"slug": "genesis", "name": "Genesis", "file": "Genesis.html", "testament": "OT"}, {"slug": "exodus", "name": "Exodus", "file": "Exodus.html", "testament": "OT"}, {"slug": "leviticus", "name": "Leviticus", "file": "Leviticus.html", "testament": "OT"}, {"slug": "numbers", "name": "Numbers", "file": "Numbers.html", "testament": "OT"}, {"slug": "deuteronomy", "name": "Deuteronomy", "file": "Deuteronomy.html", "testament": "OT"}, {"slug": "ruth", "name": "Ruth", "file": "Ruth.html", "testament": "OT"}, {"slug": "job", "name": "Job", "file": "Job.html", "testament": "OT"}, {"slug": "psalms", "name": "Psalms", "file": "Psalms.html", "testament": "OT"}, {"slug": "isaiah", "name": "Isaiah", "file": "Isaiah.html", "testament": "OT"}, {"slug": "ezekiel", "name": "Ezekiel", "file": "Ezekiel.html", "testament": "OT"}, {"slug": "daniel", "name": "Daniel", "file": "Daniel.html", "testament": "OT"}];
window.ANNOT={"1:22": [{"ref": "1:22", "title": "The virgin birth built on the Greek", "finding": "Matthew grounds the virgin birth in Isaiah 7:14 — but only in its Greek form, which renders Hebrew almah ('young woman') as parthenos ('virgin'). The doctrine rides on the Septuagint's word choice.", "category": "source-critical", "citation": "Matt 1:22-23 = Isa 7:14 LXX (παρθένος). — nt-citation-sources", "tier": "DEMONSTRABLE"}], "2:15": [{"ref": "2:15", "title": "“Out of Egypt I called my son”", "finding": "Matthew reads the flight to Egypt as fulfilling Hosea 11:1 — but in Hosea that line looks back on the Exodus and 'my son' is Israel, not a coming Messiah. Matthew re-aims Israel's story onto Jesus.", "category": "typology", "citation": "Matt 2:15 = Hos 11:1 (originally of Israel). — ot-nt-typology", "tier": "DEMONSTRABLE"}], "2:18": [{"ref": "2:18", "title": "Rachel weeping", "finding": "The slaughter of the infants is read through Jeremiah 31:15, 'Rachel weeping for her children' — a verse that in Jeremiah is about the exile, redirected by Matthew to Bethlehem.", "category": "ot-allusion", "citation": "Matt 2:17-18 = Jer 31:15. — ot-nt-typology", "tier": "STRONG-INFERENCE"}], "2:23": [{"ref": "2:23", "title": "“He shall be called a Nazarene” — a citation with no source", "finding": "Matthew says this fulfills 'what was spoken by the prophets' — but no such verse exists anywhere in the Old Testament. A phantom citation (perhaps a pun on nezer 'branch' or nazir).", "category": "source-critical", "citation": "Matt 2:23 — no OT source exists. — nt-citation-sources", "tier": "DEMONSTRABLE"}], "5:17": [{"ref": "5:17", "title": "“I came not to abolish the Law”", "finding": "Where Mark's Jesus sits loose to the Law, Matthew's insists 'not one iota' will pass from it — opening the first of five great discourses. Matthew rebuilds Mark into a Torah-keeping, five-book catechism.", "category": "composition", "citation": "Matt 5:17-20; the five-discourse structure. — matthew-origins", "tier": "STRONG-INFERENCE"}], "13:35": [{"ref": "13:35", "title": "Asaph's psalm, attributed to “Isaiah”", "finding": "Matthew quotes Psalm 78:2 (a psalm of Asaph) and, in an early text form, attributes it to 'Isaiah the prophet' — a misattribution scribes later corrected to the anonymous 'the prophet.'", "category": "source-critical", "citation": "Matt 13:35 = Ps 78:2 (variant 'Isaiah'). — nt-citation-sources", "tier": "STRONG-INFERENCE"}], "27:9": [{"ref": "27:9", "title": "Attributed to Jeremiah — but it's Zechariah", "finding": "'Then was fulfilled what was spoken by Jeremiah the prophet' — the thirty pieces of silver and the potter's field — but the words are Zechariah 11:12-13. Jeremiah supplies only the field-and-potter frame. The most famous NT misattribution alongside Mark 1:2.", "category": "source-critical", "citation": "Matt 27:9-10 attrib. Jeremiah, but = Zech 11:12-13. — nt-citation-sources", "tier": "DEMONSTRABLE"}]};